create table if not exists public.recipes (
  id text primary key,
  name text not null,
  category text not null default '',
  difficulty integer not null default 0,
  cooking_minutes integer not null default 30,
  description text not null default '',
  ingredients jsonb not null default '[]'::jsonb,
  steps jsonb not null default '[]'::jsonb,
  tags jsonb not null default '[]'::jsonb,
  image_url text,
  video_url text,
  nutrition jsonb,
  step_durations jsonb,
  updated_at timestamptz not null default now()
);

-- 老库幂等升级:新增列(已存在则无操作)
alter table public.recipes add column if not exists video_url text;
alter table public.recipes add column if not exists nutrition jsonb;
alter table public.recipes add column if not exists step_durations jsonb;

alter table public.recipes enable row level security;
-- 共享菜谱目录:匿名 + 已登录均可只读;无写策略(仅 service_role/迁移可写)
drop policy if exists "recipes_public_read" on public.recipes;
create policy "recipes_public_read" on public.recipes
  for select to anon, authenticated using (true);
grant select on public.recipes to anon, authenticated;

insert into public.recipes (id, name, category, difficulty, cooking_minutes, description, ingredients, steps, tags, image_url, video_url, nutrition, step_durations) values
  ('howtocook:aquatic/咖喱炒蟹', '咖喱炒蟹', '水产', 4, 30, '这是一道融合泰式风味的家常海鲜菜，浓郁咖喱包裹着爆满的蟹肉，带有蟹黄香气和椰浆的顺滑口感。螃蟹富含优质蛋白和多种微量元素，有助于补充体力。制作工序清晰，只需注意封煎蟹黄和最后关火翻炒酱汁，对有一定下厨经验的人比较友好，一般从备料到出锅约需 30 分钟。', '[{"name":"青蟹","quantity":1,"unit":"只"},{"name":"咖喱块","quantity":15,"unit":"克"},{"name":"洋葱","quantity":200,"unit":"克"},{"name":"椰浆","quantity":100,"unit":"ml"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"生粉","quantity":5,"unit":"克"},{"name":"大蒜","quantity":5,"unit":"瓣"}]'::jsonb, '["肉蟹掀盖后对半砍开，蟹钳用刀背轻轻拍裂，切口和蟹钳蘸一下生粉，不要太多。撒 5g 生粉到蟹盖中，盖住蟹黄，备用","洋葱切成洋葱碎，备用","大蒜切碎，备用","烧一壶开水，备用","起锅烧油，倒入约 20ml 食用油，等待 10 秒让油温升高","将螃蟹切口朝下，轻轻放入锅中，煎 20 秒，这一步主要是封住蟹黄，蟹肉。然后翻面，每面煎 10 秒。煎完将螃蟹取出备用","将螃蟹盖放入锅中，使用勺子舀起锅中热油泼到蟹盖中，煎封住蟹盖中的蟹黄，煎 20 秒后取出备用","不用刷锅，再倒入 10ml 食用油，大火让油温升高至轻微冒烟，将大蒜末，洋葱碎倒入，炒 10 秒钟","将咖喱块放入锅中炒化（10 秒），放入煎好的螃蟹，翻炒均匀","倒入开水 300ml，焖煮 3 分钟。","焖煮完后，倒入椰浆和蛋清，关火，关火后不断翻炒，一直到酱汁变浓稠。","出锅"]'::jsonb, '["水产","泰式","鲜香","浓郁","煎炒","下饭","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_aquatic_b1ab272049.jpg', 'https://www.bilibili.com/video/BV1c44y1k7ds', '{"energyKcal":750,"protein":24,"carbs":32,"fat":59}'::jsonb, '[null,null,null,null,10,20,20,10,10,180,null,null]'::jsonb),
  ('howtocook:aquatic/响油鳝丝', '响油鳝丝', '水产', 3, 40, '响油鳝丝是一道经典的江浙沪家常菜，鳝丝鲜嫩滑爽，蒜香浓郁，酱汁微甜，淋上热猪油后香气四溢，非常下饭。鳝鱼富含优质蛋白和 DHA，营养丰富。这道菜对刀工和火候有一定要求，难度适中，新手需要稍加练习。从备料到出锅，一般 大约 40 分钟就能端上餐桌。', '[{"name":"鳝丝","quantity":400,"unit":"克"},{"name":"大蒜","quantity":40,"unit":"克"},{"name":"姜末","quantity":20,"unit":"克"},{"name":"料酒","quantity":13,"unit":"克"},{"name":"生抽","quantity":3,"unit":"克"},{"name":"蚝油","quantity":2,"unit":"克"},{"name":"老抽","quantity":2,"unit":"克"},{"name":"食用盐","quantity":2,"unit":"克"},{"name":"白糖","quantity":6,"quantityMax":15,"unit":"克"},{"name":"胡椒粉","quantity":3.5,"quantityMax":8,"unit":"克"},{"name":"淀粉","quantity":10,"unit":"克"},{"name":"水","quantity":50,"unit":"克"},{"name":"蒜末","quantity":40,"unit":"克"},{"name":"葱花","quantity":15,"unit":"克"},{"name":"猪油","quantity":20,"unit":"克"},{"name":"香油","quantity":5,"unit":"克"}]'::jsonb, '["将鳝鱼切成三段后切成细丝","加入 0.5 g 胡椒粉、3 g 料酒搅拌均匀，再加入 5 g 香油腌制","热油滑锅","加入植物油，烧到 6 成热","加入一半蒜末和全部姜末，翻炒几下","加入鳝丝，中火爆炒 30 秒","边缘淋入 10 g 料酒，翻炒几下","加入生抽，炒匀","加入蚝油、老抽，翻炒几下","加入食用盐、白糖、3 g 胡椒粉，炒匀","淀粉和水混合为水淀粉，倒入锅中，收汁至浓稠","装盘，撒上蒜蓉、葱花","另起锅烧热，加入猪油，烧至七成热，浇在鳝丝上"]'::jsonb, '["水产","江浙沪","鲜香","微甜","爆炒","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_aquatic_6a870be542.jpg', 'https://www.bilibili.com/video/BV1RK421b7by', '{"energyKcal":1200,"protein":78,"carbs":54,"fat":72}'::jsonb, '[null,null,null,null,null,30,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:aquatic/小龙虾/小龙虾', '小龙虾', '水产', 4, 45, '这道菜麻辣鲜香，虾肉细嫩多汁，是经典的川湘风味下酒菜，在家自制干净又实惠。小龙虾富含优质蛋白和多种微量元素，但汤汁含油盐较多，适合偶尔享用。处理活虾和多种香料对新手有一定挑战，不过不去虾线可明显降低难度。从备料到出锅大约需要 45 分钟。', '[{"name":"小龙虾","quantity":2,"unit":"斤"},{"name":"油","quantity":70,"unit":"毫升"},{"name":"香叶","quantity":2,"unit":"片"},{"name":"八角","quantity":1,"unit":"个"},{"name":"桂皮","quantity":3,"unit":"克"},{"name":"青花椒","quantity":10,"unit":"克"},{"name":"花椒","quantity":10,"unit":"克"},{"name":"子弹头辣椒","quantity":5,"unit":"克"},{"name":"葱","quantity":1,"unit":"根"},{"name":"姜","quantity":30,"unit":"克"},{"name":"蒜","quantity":7,"unit":"瓣"},{"name":"郫县豆瓣","quantity":30,"unit":"克"},{"name":"黄豆酱","quantity":30,"unit":"克"},{"name":"啤酒","quantity":500,"unit":"毫升"},{"name":"生抽","quantity":30,"unit":"毫升"},{"name":"盐","quantity":10,"unit":"克"}]'::jsonb, '["小龙虾刷干净去虾线，葱切 2cm 葱段，姜蒜切末。","烧油，油微热, 下香叶、八角、桂皮、青花椒、花椒、子弹头辣椒。","香料出香气之后下锅葱姜蒜","葱姜蒜爆香后，加入郫县豆瓣、黄豆酱，炒出红油。","下小龙虾，翻炒至变色。","加入啤酒，等啤酒烧开后加入生抽，盐。","将小龙虾完全煮熟后出锅。"]'::jsonb, '["水产","麻辣","鲜香","川湘","下酒","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_aquatic_b6049d9abf.jpg', 'https://www.bilibili.com/video/BV15M4m1X7WR', '{"energyKcal":580,"protein":22.5,"carbs":14.5,"fat":37}'::jsonb, null),
  ('howtocook:aquatic/干煎阿根廷红虾/干煎阿根廷红虾', '干煎阿根廷红虾', '水产', 3, 20, '一道鲜美诱人的海鲜快手菜，煎制后的阿根廷红虾肉质白嫩，口感鲜甜浓郁，虾壳酥香。富含碘、磷和虾青素等微量元素，有助于增强免疫力、保护心脏并降低胆固醇。难度适中，需要掌握火候和翻面技巧，但步骤清晰，新手按操作来也能成功。预计 大约 20 分钟即可完成。', '[{"name":"阿根廷红虾（选用了速冻虾）","quantity":2,"quantityMax":3,"unit":"只"},{"name":"海盐（研磨装）","quantity":5,"unit":"克"},{"name":"黑胡椒（研磨装）","note":"适量"},{"name":"白葡萄酒","quantity":20,"unit":"ml"},{"name":"生抽","quantity":1,"unit":"ml"},{"name":"香菜","quantity":3,"unit":"片"},{"name":"柠檬","quantity":1,"unit":"片"},{"name":"洋葱","quantity":10,"unit":"克"},{"name":"生姜","quantity":10,"unit":"克"},{"name":"大蒜","quantity":10,"unit":"克"}]'::jsonb, '["阿根廷红虾解冻，最好是提前 1 天从速冻取出放到冷藏里自然解冻，能更好保持风味和口感。可买已经开背去虾线的，节省了不少时间","解冻好的红虾洗净擦干备用，注意这里一定要沥干水分，赶时间可以用厨房用纸吸干水分","生姜切片，洋葱切小方块，香菜洗干净后，叶茎分离，把香菜叶切碎，大蒜压碎切成小块碎末","大火热锅，热锅后倒入两调羹橄榄油，等油温升高后，放入生姜片，洋葱块和香菜茎煸炒","约 1 分钟后取出生姜，洋葱和香菜茎，弃用","调中大火，放入红虾开始煎，注意所有虾需要单面都完整接触平底锅，煎约 2 分钟，同时给每只虾刷上一层油","待底面虾壳有微微焦黄时翻面，并撒入大蒜碎末，轻微晃动平底锅使得受热均匀","约 1 分钟后添加 20ml 白葡萄酒","再煎 1 分钟后调中小火，均匀撒上一层盐和黑胡椒","给每只虾滴上一滴生抽","撒上香菜叶，装盘","切好柠檬片，摆放到盘边即可"]'::jsonb, '["水产","鲜香","干煎","快手","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_aquatic_91946c2214.jpg', 'https://www.bilibili.com/video/BV1Hx41147vj', '{"energyKcal":200,"protein":24,"carbs":4,"fat":9}'::jsonb, '[null,null,null,null,60,120,null,60,60,null,null,null]'::jsonb),
  ('howtocook:aquatic/微波葱姜黑鳕鱼', '微波葱姜黑鳕鱼', '水产', 3, 20, '微波做鱼，葱姜提鲜，热油一淋，香气四溢，是一道肉质细嫩、滋味咸鲜的家常蒸鱼菜，属于改良粤式做法。黑鳕鱼富含优质蛋白和欧米伽-3 脂肪酸，对心脑健康有益。操作不算复杂，但需掌握火候和油温，更适合有一定下厨经验的朋友。从备料到上桌大约只需二十分钟。', '[{"name":"黑鳕鱼（带皮）","quantity":450,"unit":"g"},{"name":"青葱（葱白）","quantity":25,"unit":"g"},{"name":"青葱（葱绿）","quantity":10,"unit":"g"},{"name":"姜","quantity":13,"unit":"g"},{"name":"料酒","quantity":5,"unit":"mL"},{"name":"酱油","quantity":25,"unit":"mL"},{"name":"芝麻油","quantity":2,"unit":"mL"},{"name":"花生油","quantity":50,"unit":"mL"}]'::jsonb, '["鱼片分别放入密封袋，鱼皮向下放在盘子中。","取葱白切丝 25g，姜去皮后切丝，10g，混合在一起后分成两半，分别放在袋内鱼片上。","每个袋子倒入 2.5mL 料酒。","封好密封袋，放入微波炉中，中火（800 瓦）微波至不透明且容易散开时（约 3.5-5 分钟），从袋中取出鱼片。","去除青葱和姜。","取酱油 25mL，芝麻油 2mL，混合均匀后平均淋在两片鱼片上。","取葱绿切细丝 10g，姜去皮后切丝 3g，混合后分成两份撒在鱼片上。","取花生油 50mL，在小锅中加热至 190℃。","将热油淋到放油葱绿的鱼片上，立刻上桌。"]'::jsonb, '["水产","鲜香","微波","粤式","家常","快手","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_aquatic_d31d57318c.jpg', 'https://www.bilibili.com/video/BV173411g7NN', '{"energyKcal":760,"protein":38.3,"carbs":2,"fat":66.6}'::jsonb, null),
  ('howtocook:aquatic/水煮鱼', '水煮鱼', '水产', 4, 120, '水煮鱼是一道麻辣鲜香、鱼肉嫩滑的经典川菜。巴沙鱼富含优质蛋白且脂肪含量低，搭配时令蔬菜营养均衡。做法中等难度，对新手有一定挑战，但按步骤操作也能成功。预计制作时长约 2 小时。', '[{"name":"巴沙鱼","quantity":500,"unit":"克"},{"name":"蔬菜（如土豆片、豆芽、花菜、生菜等）","quantity":300,"quantityMax":500,"unit":"克"},{"name":"红油豆瓣酱","quantity":40,"unit":"克"},{"name":"豆豉（可选）","quantity":10,"unit":"克"},{"name":"藤椒油","quantity":10,"unit":"ml"},{"name":"菜籽油","quantity":25,"unit":"ml"},{"name":"白胡椒粉","quantity":3,"unit":"克"},{"name":"蒜瓣","quantity":2,"unit":"瓣"},{"name":"盐","quantity":5,"unit":"克"},{"name":"糖","quantity":2,"unit":"克"},{"name":"热水","quantity":150,"unit":"ml"}]'::jsonb, '["准备：巴沙鱼若是从冷冻柜里取出，需要放室温自然解冻 5 小时再做切片处理。","切片：巴沙鱼撇成薄片，约 5cm 长，3cm 宽。","腌制：将切好片的巴沙鱼放入大不锈钢碗中","加入 30g 豆瓣酱，3g 盐，10ml 藤椒油，3g 白胡椒粉","用手抓匀后加入 5ml 菜籽油收尾封住口味","常温静置至少 30 分钟入味。","备菜：大蒜切成蒜末。以 300g 花菜，200g 生菜为例，将花菜与生菜洗净。","焯水与炒菜：花菜开水锅焯水备用；将生菜洗净晾干，炒熟备用（不用放油）。","炒豆瓣酱：热锅冷油（菜籽油 20ml），加入 10g 豆瓣酱，10g 豆豉（可选），加入蒜末，中火慢炒。","汆鱼片：加入 150ml 热水，水很快开后加入腌制好的鱼片，轻轻翻动让鱼片在水中散开，加入 2g 盐和 2g 糖调味（此时可根据个人口味调整盐的用量）。水再次沸腾后即可盛盘。","盛盘：先将熟的蔬菜盛至大碗中，然后将热的鱼片盛在蔬菜上面，浇上锅中剩余热汤即可！"]'::jsonb, '["水产","麻辣","鲜香","川菜","家常","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_aquatic_cbb36e85a9.jpg', 'https://www.bilibili.com/video/BV1Q7h2zLEGd', '{"energyKcal":950,"protein":70,"carbs":25,"fat":48}'::jsonb, '[18000,null,null,null,null,1800,null,null,null,null,null]'::jsonb),
  ('howtocook:aquatic/油焖大虾/油焖大虾', '油焖大虾', '水产', 4, 40, '这道鲁菜经典以咸甜交融的酱汁包裹整虾，成菜红亮油润，虾肉紧实弹嫩。虾本身富含优质蛋白与虾青素，脂肪含量低，是补充营养又不易增加负担的食材。制作时需要炼葱油、剪虾、焖烧、收汁，对火候和调味把握有一定要求，更适合有基础的厨友尝试，全程大约需要 40 分钟。', '[{"name":"黑虎虾/明虾","quantity":10,"unit":"只"},{"name":"花椒","quantity":5,"unit":"克"},{"name":"葱","quantity":50,"unit":"克"},{"name":"姜","quantity":20,"unit":"克"},{"name":"料酒","quantity":30,"unit":"克"},{"name":"水","quantity":2,"unit":"小碗"},{"name":"盐","quantity":3,"unit":"克"},{"name":"冰糖","quantity":10,"unit":"克"},{"name":"植物油","note":"适量"}]'::jsonb, '["剪虾枪到根上，虾须虾爪都剪掉，沙包挑掉，开背虾线挑出来，洗净备用","炸料油","油温三成热放花椒，油热离火，放葱姜（不要让油变色最好）葱稍微变黄沥油 （葱油弄多了可以留着作为拌面使用）。","下油，虾摆放整齐，两面变色后轻轻摁虾头","放姜米（姜切成细颗粒）","黄酒 30g","水两小碗","盐 3g","冰糖 10 克","大火烧开转小火盖盖子闷（中途不能再加汤水，不要开盖）","皮亮虾弯就可以起锅，虾摆盘","收汁（过滤后倒回锅里收浓，放葱油 ） 汤汁剩余 1/4 时。","浇汁","完成","油焖大虾-预览图-1","开吃✅"]'::jsonb, '["水产","鲁菜","咸甜","焖","家常","宴客","鲜香"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_aquatic_10314e540f.jpg', 'https://www.bilibili.com/video/BV1LS66BkEk3', '{"energyKcal":330,"protein":36,"carbs":10,"fat":19}'::jsonb, null),
  ('howtocook:aquatic/混合烤鱼/烤鱼', '烤鱼', '水产', 4, 60, '这道川味烤鱼麻辣鲜香，鱼肉外焦里嫩，配菜吸饱汤汁后格外下饭。草鱼富含优质蛋白，搭配多种蔬菜，营养均衡。做法看似复杂，但跟着步骤走其实不难，适合想挑战硬菜的新手。从备料到上桌大约需要一小时。', '[{"name":"草鱼","quantity":3,"unit":"斤"},{"name":"大葱","quantity":0.5,"unit":"根"},{"name":"食用油","quantity":20,"unit":"ml"},{"name":"料酒","quantity":10,"quantityMax":15,"unit":"ml"},{"name":"食用盐","quantity":5,"quantityMax":10,"unit":"克"},{"name":"白胡椒粉","quantity":5,"quantityMax":10,"unit":"克"},{"name":"桂皮","note":"一小片"},{"name":"八角","quantity":2,"unit":"个"},{"name":"大蒜","quantity":8,"unit":"个"},{"name":"香叶","quantity":2,"unit":"张"},{"name":"青花椒","note":"一小把"},{"name":"干辣椒段","quantity":10,"unit":"个"},{"name":"灯笼椒","quantity":4,"unit":"个"},{"name":"芹菜段","quantity":2,"unit":"根"},{"name":"洋葱","quantity":0.5,"unit":"个"},{"name":"千张","quantity":1,"unit":"张"},{"name":"绿豆芽","note":"适量"},{"name":"豆瓣酱","quantity":15,"quantityMax":20,"unit":"克"},{"name":"白糖","quantity":5,"unit":"克"},{"name":"生抽","quantity":5,"unit":"ml"},{"name":"孜然粉","note":"适量"},{"name":"熟花生米","note":"适量"},{"name":"白芝麻","note":"适量"},{"name":"葱花","note":"适量"},{"name":"香菜","note":"根据个人口味可放可不放"}]'::jsonb, '["草鱼（一般 3 斤 ）从背部切开，两面沿着鱼的背部往下划几刀，不要划到鱼肚皮，不然不易定型","可以用热水浇在鱼身上洗去粘液或者用刷子在流动水龙头下面不停的刷洗，直到摸着没有黏糊糊的手感。","把鱼放到容器中，加入料酒，10g 白胡椒粉，5g 食盐抹匀腌制二十分钟入味。","把半根大葱切成一块一块，大蒜粒中间切开，和八角香叶桂皮放在一个容器中","干辣椒段中间一分为二切开并和灯笼椒装在一个容器中","芹菜切小段","豆芽焯水","千张焯水切成丝","洋葱切成丝。","烤制鱼","家里有烤箱的可以在烤盘刷上底油，鱼皮朝下，直到烤制两面金黄，然后撒上孜然粉","如果没有烤箱，可以热锅热油，锅的两边撒上 2g 食盐，下入草鱼开始煎，刚下入的时候不要着急翻动，等一面定型后再翻面，煎制两面金黄，撒上孜然粉，出锅装在盘子里准备。","锅中撒上 20ml 食用油，等到油热后，把大葱大蒜八角香叶倒入炒香","加上一包火锅底料的一半和 15-20g 豆瓣酱，炒出红油","加入 5g 白糖，10g 食盐，5ml 生抽调味，倒入和食材齐平的清水煮开","依次下入芹菜段，豆芽，千张丝，不用煮熟，稍微烫一下后铺上洋葱丝，放上烤鱼","加入干辣椒，灯笼椒，青花椒","另一个锅烧油，油热后浇在刚加入的辣椒上面激发出香味","最后撒上熟花生米，葱花，白芝麻，香菜","煮 5-6 分钟，美味即成。"]'::jsonb, '["水产","麻辣","鲜香","下饭","川菜","煎烤","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_aquatic_ff10e072e4.jpg', 'https://www.bilibili.com/video/BV1uybYzYEav', '{"energyKcal":600,"protein":37,"carbs":8.5,"fat":42}'::jsonb, '[null,null,1200,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,300]'::jsonb),
  ('howtocook:aquatic/清蒸生蚝', '清蒸生蚝', '水产', 3, 20, '清蒸生蚝是一道原汁原味的沿海家常菜，蚝肉鲜嫩多汁，带着淡淡的海水咸香，蒜蓉与姜丝激发出清甜口感。生蚝富含优质蛋白和锌元素，能帮助提升免疫力。操作不算复杂，但掀开滚烫锅盖和处理蚝壳需要稍加小心，新手也能顺利完成。从刷洗到出锅，大约只需二十分钟。', '[{"name":"生蚝","quantity":6,"unit":"个"},{"name":"葱","quantity":3,"unit":"颗"},{"name":"蒜","quantity":6,"unit":"瓣"},{"name":"姜","quantity":1,"unit":"小块"},{"name":"酱油","quantity":1,"unit":"ml"}]'::jsonb, '["将生蚝用刷子刷干净（没有刷子用牙刷）。","蒸锅中放水，将蒸屉放上之后，将 6 个生蚝平铺在蒸屉,使用 50%功率，蒸 3 分钟。","用右手拿着湿抹布掀开烫锅盖，将每个生蚝的外壳掀开一半去掉，生蚝的凸面向下，平面向上，每个放 1 根姜丝,10g 蒜末放到生蚝上。","关上烫锅盖，100%功率蒸 3.5 分钟。","停火，用右手拿着抹布掀开烫锅盖，每个放 5ml 酱油。","盛盘。"]'::jsonb, '["水产","清蒸","海鲜","清淡","家常","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_aquatic_db5aa79fbd.jpg', 'https://www.bilibili.com/video/BV1644y1G7C9', '{"energyKcal":130,"protein":14,"carbs":8,"fat":5}'::jsonb, '[null,180,null,210,null,null]'::jsonb),
  ('howtocook:aquatic/清蒸鲈鱼/清蒸鲈鱼', '清蒸鲈鱼', '水产', 3, 30, '清蒸鲈鱼是一道粤式经典蒸菜，鱼肉细嫩爽滑，味道清淡鲜美，能最大程度保留鲈鱼的原汁原味。鲈鱼富含优质蛋白和 DHA，营养丰富且易于消化。这道菜操作简单，对新手非常友好，从备料到出锅大约只需三十分钟。', '[{"name":"鲈鱼","quantity":1,"unit":"条"},{"name":"香葱","quantity":3,"unit":"根"},{"name":"姜","quantity":1,"unit":"块"},{"name":"食用油","quantity":10,"quantityMax":15,"unit":"ml"},{"name":"蒸鱼豉油","quantity":10,"quantityMax":15,"unit":"ml"},{"name":"料酒","quantity":10,"quantityMax":15,"unit":"ml"},{"name":"食用盐","quantity":5,"quantityMax":10,"unit":"克"}]'::jsonb, '["姜切片切丝、香葱的葱白切段，葱绿切丝，切丝后放入冷水浸泡备用。","鲈鱼处理好后洗净，用厨房纸擦干，两面分别划几刀，用盐洗掉鱼身的粘液，并用 10g 盐抹遍鱼身的内外，腌制 10 分钟以上。","补充一个鲈鱼改刀和摆盘的方法，改刀后可以让鲈鱼立起来蒸，均匀受热，同时吃起来更加方便，无需翻面。","改刀","清蒸鲈鱼-预览图-2","鱼肚内塞上姜和葱白，鱼身也撒上姜和葱白，量为备用的一半。蒸鱼的碟子用筷子将鱼跟碟子隔开蒸","水烧热感觉到水温后放进入鱼","大火清蒸 10 分钟。","蒸好的鱼，用干净的盘子装起来并去除身上姜蒜","鱼身浇上 15ml 蒸鱼豉油","鱼身重新撒上姜和葱丝，锅内加上 10ml 食用油并烧热，将食用油淋至鱼身即可出菜"]'::jsonb, '["水产","清蒸","粤式","清淡","鲜嫩","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_aquatic_d3e8b64b85.jpg', 'https://www.bilibili.com/video/BV1oytPeiE8N', '{"energyKcal":370,"protein":46,"carbs":2,"fat":15}'::jsonb, null),
  ('howtocook:aquatic/白灼虾/白灼虾', '白灼虾', '水产', 2, 15, '白灼虾是一道粤式经典快手菜，虾肉鲜甜弹嫩，原汁原味。虾本身富含优质蛋白和多种矿物质，搭配蘸料开胃不油腻。做法简单容错率高，对新手非常友好，从备料到出锅大约只需 15 分钟。', '[{"name":"活虾","quantity":250,"unit":"克"},{"name":"洋葱","quantity":1,"unit":"头"},{"name":"姜","quantity":1,"unit":"块"},{"name":"蒜","quantity":5,"quantityMax":8,"unit":"瓣"},{"name":"葱","quantity":1,"unit":"根"},{"name":"食用油","quantity":10,"quantityMax":15,"unit":"ml"},{"name":"酱油","quantity":10,"quantityMax":15,"unit":"ml"},{"name":"料酒","quantity":20,"unit":"ml"},{"name":"芝麻","note":"一把"},{"name":"香醋","quantity":10,"unit":"ml"},{"name":"蚝油","quantity":10,"unit":"ml"}]'::jsonb, '["洋葱切小块，姜切片，平铺平底锅。","活虾冲洗一下（去除虾线、剪刀减掉虾腿虾须子都是可选操作），控水，铺在平底锅的洋葱、姜片之上。","锅内倒入料酒，盖上锅盖，中火 1 分钟，小火 5 分钟，关火 5 分钟。","和上一步并行操作，制作蘸料：","葱切成葱花、蒜切碎、倒入酱油、芝麻、香醋，搅拌之。","油烧热，淋入蘸料。","虾出锅，用干净的盘子装好。"]'::jsonb, '["水产","粤式","鲜香","快手","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_aquatic_0c3815d057.webp', 'https://www.bilibili.com/video/BV1eT4y157of', '{"energyKcal":260,"protein":32,"carbs":5,"fat":12}'::jsonb, '[null,null,660,null,null,null,null]'::jsonb),
  ('howtocook:aquatic/糖醋鲤鱼/糖醋鲤鱼', '糖醋鲤鱼', '水产', 4, 60, '糖醋鲤鱼是经典鲁菜，外酥里嫩、酸甜适口，鱼身炸至金黄浇上红亮糖醋汁，十分诱人。鱼肉富含优质蛋白和多种矿物质，易于消化吸收。这道菜对新手不太友好，难度中等偏上，需掌握改刀、挂糊和油炸火候。从备料到成菜大约需要 1 小时。', '[{"name":"鲤鱼","quantity":3,"unit":"斤"},{"name":"番茄酱","quantity":40,"unit":"克"},{"name":"白糖","quantity":20,"unit":"克"},{"name":"白醋","quantity":10,"unit":"克"},{"name":"淀粉","quantity":10,"unit":"克"},{"name":"盐","quantity":30,"unit":"克"},{"name":"葱","quantity":30,"unit":"克"},{"name":"姜","quantity":30,"unit":"克"},{"name":"料酒","quantity":25,"unit":"克"},{"name":"香菜","quantity":1,"unit":"颗"},{"name":"面粉","quantity":100,"unit":"克"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"清水","quantity":50,"unit":"克"},{"name":"食用油","quantity":1,"unit":"L"}]'::jsonb, '["将鱼清洗干净，确保无鱼鳞等异物","将鱼头朝左，鱼肚朝下，右手持刀。刀竖直切下 1cm，按紧鱼身往左片 3-4cm，再将鱼片中间轻轻划一刀","将鱼放进盆里，然后将大姜切片，大葱切段（随便切切就行了，主要是需要去腥味）","用吃奶的力气将大葱大姜里的汁水挤到盆中","加入 20g 盐，25g 料酒，然后给鲤鱼搓个澡，涂抹均匀","腌制","找个干净的盆，加入 100g 面粉、200g 淀粉、180g 水、5g 盐，用手将其搅拌均匀，面糊此时粘稠呈可拉丝状态，然后打入一个鸡蛋，再次搅匀","等待 30 分钟","将鱼放在案板上，用干毛巾将鱼身上的水擦干（这样可以更好的挂糊）","将盆冲洗干净，用干毛巾擦干","起锅烧油，加入约 1L 的油，将油温烧至 7 成热，约 200-240 度","捏起鱼的尾巴，将鱼头沉入锅底，用勺子往鱼的身上淋热油，待面糊成型后，将鱼慢慢放入锅中，拿锅铲轻轻铲起鱼的头部，然后垫上笊篱。防止底部炸糊。","准备一个盛鱼的盘子，放在锅的旁边。","用锅铲从鱼身处轻轻铲入，两个工具配合鱼翻个身。再炸两分钟，还是同样的方式（笊篱托着鱼头，锅铲托着鱼身，将鱼盛入盘中）","将锅中的油倒入擦干的盆中，放置一边，然后将锅刷干净","将 50g 清水、40g 番茄酱、20g 白糖、10g 白醋放入小碗中，搅拌均匀","再准备一个小碗加入 10g 淀粉、10g 水，搅拌成水淀粉","开大火将锅烧热，然后倒入之前准备的料汁，大火烧开，转小火","加入调好的水淀粉，边倒边搅拌，然后 20 秒后关火","将熬好的糖醋汁用勺子均匀地浇在鱼身上，可以加点香菜或葱花点缀，糖醋鲤鱼就做好了","糖醋鲤鱼-预览图-2"]'::jsonb, '["水产","酸甜","炸制","鲁菜","宴客","年夜饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_aquatic_b7c599d523.jpg', 'https://www.bilibili.com/video/BV1NKLZzbEEr', '{"energyKcal":550,"protein":34,"carbs":32,"fat":28}'::jsonb, null),
  ('howtocook:aquatic/红烧鱼', '红烧鱼', '水产', 4, 40, '红烧鱼是一道家常风味浓郁的经典菜，咸鲜微甜，鱼肉嫩滑入味，属于大众喜爱的中式烧菜。鱼肉富含优质蛋白和不饱和脂肪酸，营养易吸收。制作时需要处理生鱼和油煎，步骤稍多，对新手有一定挑战，但跟着菜谱操作也能成功。从备料到出锅，大约需要 40 分钟。', '[{"name":"姜","quantity":2,"quantityMax":3,"unit":"片"},{"name":"蒜瓣","quantity":3,"quantityMax":4,"unit":"个"},{"name":"干辣椒","quantity":2,"quantityMax":3,"unit":"个"},{"name":"油","quantity":30,"quantityMax":50,"unit":"ml"},{"name":"盐","quantity":10,"unit":"克"},{"name":"料酒","note":"适量"},{"name":"醋","quantity":5,"unit":"ml"},{"name":"酱油","quantity":5,"unit":"ml"},{"name":"白砂糖","quantity":10,"unit":"克"},{"name":"鱼","quantity":1,"unit":"条"},{"name":"蚝油","quantity":5,"unit":"克"},{"name":"葱","quantity":1,"quantityMax":2,"unit":"根"},{"name":"香菜","note":"依个人口味"},{"name":"小米椒","quantity":1,"quantityMax":2},{"name":"味精（鸡精）","quantity":5,"unit":"克"}]'::jsonb, '["姜蒜准备好，切碎","干辣椒切碎，和姜蒜一起","加入 30-50ml 油，等待锅热...","放入擦干水分的鱼（不想被热油溅一身的话），然后晃动锅，用热油煎鱼，注意这过程一定要小火","将鱼翻面，重复上面油煎过程","放入姜蒜辣椒，翻炒出香味","倒入料酒，稍微多一点，此过程注意安全，会起大量油烟","倒入醋（喜欢醋可以多放一点）","然后放入白砂糖，酱油（老抽)","加入冷水，以刚好淹没鱼身为宜，然后调成中火，盖上锅盖，大概 1 分钟后将鱼翻身，继续盖上锅盖","3-4 分钟后，加入盐、小米椒、蚝油（味精、鸡精等），然后继续盖上锅盖，后续继续要翻身","当锅内汤汁收汁到鱼的脊背线上的鱼鳍下面一点点的时候（或者汤汁不多的时候），转小火，加入香菜，葱花，然后盖上锅盖 20 秒，关火","起锅"]'::jsonb, '["水产","红烧","咸鲜","煎烧","家常","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_aquatic_3b596c1ffa.jpg', 'https://www.bilibili.com/video/BV1b9xrzmEij', '{"energyKcal":650,"protein":40,"carbs":12,"fat":28}'::jsonb, '[null,null,null,null,null,null,null,null,null,60,180,20,null]'::jsonb),
  ('howtocook:aquatic/红烧鱼头', '红烧鱼头', '水产', 4, 150, '红烧鱼头是一道经典的家常烧菜，鱼头胶质丰富，肉质滑嫩，汤汁咸鲜微辣，十分下饭。鱼头富含优质蛋白、卵磷脂和不饱和脂肪酸，对滋养皮肤和大脑有益。由于需要处理生鱼和剁骨，难度稍高，不建议完全零基础的新手独自操作，全程制作（含腌制）约需 2–2.5 小时。', '[{"name":"鱼头","quantity":1,"unit":"个"},{"name":"大葱","quantity":200,"unit":"克"},{"name":"姜","quantity":80,"unit":"克"},{"name":"大蒜","quantity":3,"quantityMax":4,"unit":"个"},{"name":"美人椒","quantity":0.25,"unit":"个"},{"name":"香菜","quantity":4,"unit":"棵"},{"name":"八角","quantity":2,"unit":"个"},{"name":"干辣椒","quantity":5,"unit":"个"},{"name":"油","quantity":30,"unit":"ml"},{"name":"盐（腌鱼用）","quantity":5,"unit":"克"},{"name":"盐（烧制用）","quantity":2,"unit":"克"},{"name":"生抽（腌鱼用）","quantity":10,"unit":"克"},{"name":"生抽（烧制用）","quantity":5,"unit":"克"},{"name":"料酒（腌鱼用）","quantity":10,"unit":"克"},{"name":"料酒（烧制用）","quantity":5,"unit":"克"},{"name":"鸡精","quantity":3,"unit":"克"},{"name":"老抽","quantity":3,"unit":"克"},{"name":"陈醋","quantity":3,"unit":"克"},{"name":"黑胡椒粉","quantity":2,"unit":"克"},{"name":"清水","quantity":500,"unit":"ml"}]'::jsonb, '["葱、姜、蒜、香菜、美人椒分别清洗干净。","干辣椒与八角稍微冲洗即可。","大葱切两半。后半段大葱（葱白处）切段，每段长度约 4cm。前半段（葱叶处）先切段，再将每段劈为四瓣。","姜切片，每片厚度约 3mm。","大蒜拍碎。","拿出两棵香菜去根，切为 1.5cm 香菜碎。","将美人椒切为厚度为 3mm 的辣椒圈。","干辣椒切四段。","注：下文所述的鱼身是购买鱼头时所附带的鱼肉。","将鱼头去鳞，清洗鱼头处未被清理干净的内脏。","剁去鱼鳍、清理鱼鳃。","将鱼头下巴与鱼身连接的地方剁开，鱼身剁块，鱼头剁成四/六瓣。","注：鱼的处理很难用文字完全表述，可以搜索鱼头处理相关视频。","将剁好的鱼头进行清洗，最好洗掉鱼块上滞留的血水。","将清洗好的鱼块放入盆中，加入 5g 盐、10g 生抽、10g 料酒。放入葱（前半段切碎的那个）、1/3 姜片。将其拌匀，静置 1-2 小时。","加入 30ml 油，等待锅热...","油热，将锅关至小火","如果不明白为何要这样做，请查看学习炒与煎中的翻炒辅料。","放入姜片，慢慢翻炒，以姜片中的大部分汁水被炒出，以金黄色为准。","放入葱段，翻炒至葱段略显发白。","放入蒜碎、八角、干辣椒，翻炒 5 秒。","将腌制好的鱼头倒入锅中，翻炒 2-3 分钟。","倒入 500ml 清水，加入 2g 盐、3g 鸡精、5g 生抽、3g 老抽、5g 料酒、2g 黑胡椒粉、3g 陈醋。","将两棵香菜放入锅中，盖上锅盖。","调至大火，将水烧开。","调至中火，慢焖入味。","当汤汁减少一半时，打开锅盖。","调至大火收汁，汤汁剩余 1/3 时，关火盛至小盆中。","注：将锅中的汤汁均匀淋到鱼头上，盛盘时可以将锅中煮的香菜放入小盆底部，这样能让成品菜好看又好吃。","将香菜放至已经盛出的鱼头上，把切好的美人椒圈放在香菜之上。","色香味俱全的红烧鱼头出炉！"]'::jsonb, '["水产","红烧","咸鲜","微辣","炖","下饭","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_aquatic_1e9c25294a.jpg', 'https://www.bilibili.com/video/BV1yXHpeHEcH', '{"energyKcal":620,"protein":42,"carbs":6,"fat":44}'::jsonb, '[null,null,null,null,null,null,null,null,null,null,null,null,null,null,3600,null,null,null,null,null,5,120,null,null,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:aquatic/红烧鲤鱼', '红烧鲤鱼', '水产', 4, 60, '红烧鲤鱼是一道家常鲁菜，鱼肉先炸后炖，外皮微韧，肉质鲜嫩，咸甜酱香中透着五花肉的醇厚，汤汁浓稠下饭。富含优质蛋白和钙、磷等矿物质，有助滋补。处理炸鱼和调味配比稍需耐心，但步骤清晰，新手跟着做也能完成。从备料到出锅预计 大约 1 小时。', '[{"name":"鲤鱼","quantity":2,"unit":"斤"},{"name":"五花肉","quantity":100,"unit":"克"},{"name":"大葱","quantity":200,"unit":"克"},{"name":"姜","quantity":80,"unit":"克"},{"name":"蒜瓣","quantity":3,"quantityMax":4,"unit":"个"},{"name":"干辣椒","quantity":2,"unit":"个"},{"name":"油","note":"适量"},{"name":"盐","quantity":5,"unit":"克"},{"name":"生抽","quantity":50,"unit":"ml"},{"name":"老抽","quantity":20,"unit":"ml"},{"name":"陈醋","quantity":50,"unit":"ml"},{"name":"蚝油","quantity":5,"unit":"ml"},{"name":"料酒","quantity":50,"unit":"ml"},{"name":"白糖","quantity":50,"unit":"克"}]'::jsonb, '["葱、姜、蒜、干辣椒分别清洗干净。","葱白处切段，每段长度约 4cm，再将每段劈为四瓣。","姜切片，每片厚度约 3mm。","一个大蒜拍碎切末，其余蒜切为二瓣。","干辣椒切四段。","五花肉切片，约 4cm4cm。","清洗鱼。","鱼背肉厚处拉几道斜口，方便入味","锅里多倒点油，烧至 7 成热（刚刚开始冒烟），下入鱼炸 1 分钟至鱼皮稍稍变硬捞出备用（注意不要一下锅就拨弄鱼，等炸一会再拨弄、翻面），炸鱼的油倒出，锅里留一点底油","将锅里底油烧热，下入五花肉，煸出香味。","放入干辣椒、葱、姜、蒜瓣，翻炒 1 分钟。","将炸好的鱼倒入锅中。","沿锅边倒入","50ml 料酒","50ml 陈醋","50ml 味极鲜","20ml 老抽调色","5ml 蚝油提鲜","5g 匙盐","50g 白糖","清水没过鱼面。","调至中火，将水烧开。","调至小火，慢焖入味。","15 分钟 后，打开锅盖，挑出锅里的葱、姜、蒜、干辣椒。","调至大火收汁，汤汁剩余 1/4 时，撒点蒜末，关火盛出。","红烧鲤鱼出锅！"]'::jsonb, '["水产","红烧","咸甜","酱香","下饭","鲁菜","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_aquatic_3f74310ccb.jpg', 'https://www.bilibili.com/video/BV1Pd6JYBEop', '{"energyKcal":420,"protein":34,"carbs":18,"fat":22}'::jsonb, null),
  ('howtocook:aquatic/肉蟹煲', '肉蟹煲', '水产', 4, 60, '这道菜酱香浓郁，蟹肉鲜甜微辣，土豆软糯、年糕 Q 弹，汤汁拌饭格外过瘾，属于一道适合聚餐的硬菜。它富含优质蛋白和多种微量元素，营养丰富。制作有一定难度，需处理活蟹、把控火候和调味比例，对新手略具挑战，预计全程约需 1 小时。', '[{"name":"肉蟹","quantity":500,"unit":"g"},{"name":"虾","quantity":200,"unit":"g"},{"name":"土豆","quantity":450,"unit":"g"},{"name":"年糕","quantity":200,"unit":"g"},{"name":"洋葱","quantity":100,"unit":"g"},{"name":"大蒜","quantity":20,"unit":"g"},{"name":"大蒜（放虾时追加）","quantity":10,"unit":"g"},{"name":"生姜","quantity":15,"unit":"g"},{"name":"干辣椒","quantity":5,"unit":"g"},{"name":"青椒","quantity":30,"unit":"g"},{"name":"红椒","quantity":30,"unit":"g"},{"name":"蚝油","quantity":20,"unit":"g"},{"name":"海鲜酱","quantity":15,"unit":"g"},{"name":"黄豆酱","quantity":15,"unit":"g"},{"name":"甜面酱","quantity":10,"unit":"g"},{"name":"番茄酱","quantity":10,"unit":"g"},{"name":"淀粉","quantity":40,"unit":"g"},{"name":"冰糖","quantity":10,"unit":"g"},{"name":"鸡精","quantity":3,"unit":"g"},{"name":"白胡椒粉","quantity":2,"unit":"g"},{"name":"白胡椒粉（放虾时追加）","quantity":1,"unit":"g"},{"name":"料酒","quantity":15,"unit":"ml"},{"name":"生抽","quantity":20,"unit":"ml"},{"name":"老抽","quantity":5,"unit":"ml"},{"name":"食用油","quantity":30,"quantityMax":50,"unit":"ml"},{"name":"食用油（放虾时追加）","quantity":10,"unit":"ml"},{"name":"食用油（油炸用）","quantity":500,"unit":"ml"},{"name":"啤酒","quantity":200,"unit":"ml"},{"name":"啤酒（放虾时追加）","quantity":50,"quantityMax":100,"unit":"ml"},{"name":"清水","quantity":800,"unit":"ml"},{"name":"清水（放虾时追加）","quantity":200,"unit":"ml"}]'::jsonb, '["土豆切块为各边均为 3 cm 的立方体，青/红椒切成边长 4 cm 的菱形片，洋葱切成 3 cm 宽的月牙瓣，年糕切成 1 cm 厚片","螃蟹切成 50-80 g 的块，裹薄淀粉，180 °C 油温炸 1 分钟捞出","锅中放油，蒜姜干辣椒爆香，放所有酱料 + 冰糖小火炒出红油，注意别糊底","加螃蟹、土豆、啤酒和清水，烧开转小火炖 12 分钟","放年糕和青红椒，开大火收汁到汤汁可以附着在物品表面，最后撒白胡椒粉"]'::jsonb, '["水产","酱香","微辣","炖煮","宴客","下饭","聚餐"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_aquatic_2dfadc3d4c.jpg', 'https://www.bilibili.com/video/BV1cs2BYPE9m', '{"energyKcal":580,"protein":25,"carbs":68,"fat":20}'::jsonb, null),
  ('howtocook:aquatic/芥末黄油罗氏虾/芥末黄油罗氏虾', '芥末黄油罗氏虾', '水产', 3, 30, '这道菜以黄油与芥末的奇妙搭配为亮点，虾肉紧实弹嫩，酱汁浓郁辛香，是一道新派海鲜菜肴。虾肉富含优质蛋白和多种微量元素，营养均衡。制作难度适中，只要提前备好料、控制火候，新手也能成功。从处理活虾到出锅，大约需要 30 分钟。', '[{"name":"罗氏虾","quantity":1,"unit":"斤"},{"name":"黄油","quantity":20,"unit":"克"},{"name":"芥末","quantity":15,"unit":"克"},{"name":"白糖","quantity":3,"unit":"克"},{"name":"生抽","quantity":30,"unit":"克"},{"name":"蚝油","quantity":30,"unit":"克"},{"name":"盐","quantity":3,"unit":"克"},{"name":"料酒、朗姆酒或啤酒","quantity":15,"quantityMax":30,"unit":"克"},{"name":"香菜","quantity":5,"unit":"条"},{"name":"蒜","quantity":5,"unit":"颗"}]'::jsonb, '["将罗氏虾剪掉头尾尖刺、触须和脚，剪刀把虾身开背，去除虾线。","提前搅拌好芥末酱汁：酱油、蚝油、芥末、盐、糖，搅拌均匀！","洗好香菜，切段备用。","罗氏虾沥掉水，锅中加入油，直接放入罗氏虾，中火，外表煎至金黄，捞出。","下入蒜蓉，大火，利用煎虾剩下的油继续煎炒蒜蓉，等到锅中白雾冒出，蒜蓉已经煎出香味，下虾和黄油，让虾充分吸收黄油香味","下入调好的酱汁，继续大火煮沸，翻炒虾，至酱汁收汁，加入酒（料酒、啤酒可以放 30g，朗姆酒味道浓郁放 15g 即可。）","在等酱汁稍微收汁，加入香菜翻炒两下，即可出锅。"]'::jsonb, '["水产","芥末鲜香","煎炒","新派海鲜","宴客","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_aquatic_5382968325.jpg', 'https://www.bilibili.com/video/BV1dx411z774', '{"energyKcal":520,"protein":48,"carbs":9,"fat":30}'::jsonb, null),
  ('howtocook:aquatic/葱油桂鱼/葱油桂鱼', '葱油桂鱼', '水产', 4, 45, '葱油桂鱼是一道葱香浓郁、鱼肉鲜嫩的家常蒸菜，属于中式清淡口味，适合各地人群。桂鱼富含优质蛋白和不饱和脂肪酸，经过精细去腥处理，保留了鱼肉的鲜美与营养。做法对新手十分友好，容错性高，只要按步骤操作，基本零失败。从备料到出锅，全程大约需要 45 分钟。', '[{"name":"桂鱼","quantity":500,"unit":"克"},{"name":"小葱","quantity":1,"unit":"根"},{"name":"小米辣","quantity":2,"unit":"个"},{"name":"姜","quantity":50,"unit":"克"},{"name":"料酒","quantity":25,"unit":"克"},{"name":"植物油","quantity":15,"unit":"克"},{"name":"盐","quantity":8,"unit":"克"},{"name":"蒸鱼豉油","quantity":10,"unit":"克"},{"name":"清水","quantity":5,"unit":"L"}]'::jsonb, '["去菜市场买已经处理好的鱼（自己处理的话最好不要内脏），将鱼身表面的所有鳞片刮干净","用厨房用纸将鱼肚子里的贴骨血和黑膜擦干净（帖骨血会影响口感，黑膜是鱼腥味的来源）","用菜刀在鱼身表面来回刮几次，将鱼身的黏液刮掉，进一步去除腥味，然后用清水将鱼内外冲洗干净","将鱼平放在砧板，使用厨房纸将鱼内外的水分擦干，然后鱼头朝左，尾朝右，从鱼鳃边开始，每隔 3cm 纵向划一刀，深度达到鱼的脊椎骨即可，另一面使用同样的处理方式","将鱼平放在盆中，确保盘中没有多余水分","取一块 50g 姜（鸡蛋大小），用削皮刀把表面的皮去除并洗干净，然后切成厚度为 3mm 的姜片","将小米辣洗干净、去蒂，切成厚度为 2mm 的小圆片（或切成 1mm 宽度的丝状）","将小葱洗干净，去除根须，切成 3cm 的小段，稍微粗一点的小葱，可以沿着小葱生长的方向沿中间劈开","加入 8g 盐，25g 料酒到盆中，带上一次性手套，然后对鱼进行全身按摩 1 分钟，确保鱼身每个部位都均匀涂抹了盐和料酒","按摩好鱼后，在鱼身的每一个刀口中塞入一片姜片，鱼肚子中放入 3 片姜片，腌制 10 分钟（建议不要腌制太久，否则鱼的鲜度降低）","在鱼腌制期间，在蒸锅中加入 5L 清水，烧开后，在蒸锅上放上蒸笼","鱼腌制好后，会析出水分，将多余水分和腌制用料酒、姜片倒掉，用清水冲洗干净鱼身和鱼肚，用厨房纸擦干鱼身和鱼肚","将鱼平放在蒸鱼盘中，重新在鱼身、鱼肚刀口处塞入姜片","然后将蒸鱼盘放入蒸笼中，盖上盖子，中火蒸 20 分钟","期间水蒸气会附着整个鱼和盘子上，凝结后形成鱼汤，出锅后千万不要倒掉这个汤，这个汤汁是鲜味精华","用防烫夹将蒸鱼盘夹出，在鱼身和鱼周围淋上 10g 蒸鱼豉油","然后在鱼身和周围均匀撒上小葱段和小米辣","在铁锅中倒入 15g 植物油，用中小火慢熬 5 分钟，不要用大火，否则油会挥发很快","将出锅后的热油均匀地慢慢地淋在鱼身上，鲜掉眉毛的葱油桂鱼就出炉啦！"]'::jsonb, '["水产","清蒸","葱香","家常","鲜香","清淡"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_aquatic_1bef5fe786.jpg', 'https://www.bilibili.com/video/BV1yAVazmEEc', '{"energyKcal":630,"protein":70,"carbs":2,"fat":18}'::jsonb, '[null,null,null,null,null,null,null,null,60,600,null,null,null,1200,null,null,null,300,null]'::jsonb),
  ('howtocook:aquatic/葱烧海参/葱烧海参', '葱烧海参', '水产', 3, 30, '这是一道经典的鲁菜家常烧制海味，以浓郁的葱香和软糯入味的海参为特色，汤汁稠亮咸鲜回甜。海参富含胶原蛋白与多种微量元素，对滋养身体很有益处。整体烹饪难度不高，但需提前花时间将干海参充分泡发，实际烧制过程约三十分钟即可完成，新手只要按步骤操作也容易成功。', '[{"name":"泡发好的海参","quantity":4,"unit":"个"},{"name":"大葱葱白","quantity":1,"unit":"根"},{"name":"食用油","quantity":20,"quantityMax":25,"unit":"ml"},{"name":"蚝油","quantity":20,"unit":"克"},{"name":"生抽","quantity":5,"unit":"克"},{"name":"白糖","quantity":2,"unit":"克"},{"name":"淀粉","quantity":2,"unit":"克"},{"name":"水","quantity":100,"unit":"ml"}]'::jsonb, '["葱白切成 1cm 的段，备用。","海参切成 1cm 的段，备用。","准备一个空碗，倒入 20g 蚝油， 10g 生抽， 2g 白糖，搅拌均匀。料汁","另一个空碗倒入淀粉，水，制备水淀粉，勾芡用。","热锅，锅内放入 20ml - 25ml 食用油。等待 10 秒让油温升高。","放入葱白，调小火，注意不要让葱白变焦。大概煎 3-5 分钟即可。葱白","用筷子夹出葱白，放入盘中备用。","倒入调好的料汁，炒香，等待 1 - 2 分钟 。","放入切好的海参，翻炒 1 分钟","加入 100 ml 的水， 中小火， 等待 5 分钟","等待锅中汤汁快干的时候，加入水淀粉，加入前面取出的葱白","在外观呈粘稠状态后关火，盛盘 葱烧海参-预览图-5"]'::jsonb, '["水产","鲁菜","烧制","咸鲜","宴客","海味"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_aquatic_4aa08f1f69.jpeg', 'https://www.bilibili.com/video/BV1j85b6jEZk', '{"energyKcal":380,"protein":30,"carbs":11,"fat":21}'::jsonb, '[null,null,null,null,10,null,null,null,60,300,null,null]'::jsonb),
  ('howtocook:aquatic/蒜蓉虾/蒜蓉虾', '蒜蓉虾', '水产', 2, 15, '这道广东传统名菜以鲜香嫩滑著称，虾肉清甜弹牙，蒜香浓郁扑鼻。海虾富含优质蛋白和钙、硒等微量元素，搭配蒜蓉有助杀菌开胃。做法十分简单，处理虾、铺酱、蒸制、淋油几步即成，新手也能轻松驾驭，全程约需 15 分钟。', '[{"name":"海虾","quantity":8,"unit":"只"},{"name":"蒜蓉酱","quantity":50,"unit":"克"},{"name":"食用油","quantity":20,"unit":"ml"},{"name":"生抽","quantity":5,"unit":"ml"}]'::jsonb, '["用刀从从虾头中间切开，切到距离虾尾 1 cm","将蒜蓉酱铺在虾身中间，放在盘子中","锅中倒入热水，将盘子放入锅中，大火蒸 3 分钟","烧热油，倒入虾盘中，倒入生抽"]'::jsonb, '["水产","鲜香","蒸制","粤式","快手","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_aquatic_3a496fcfc1.jpeg', 'https://www.bilibili.com/video/BV1s9YUzjEaa', '{"energyKcal":350,"protein":21,"carbs":5,"fat":28}'::jsonb, '[null,null,180,null]'::jsonb),
  ('howtocook:aquatic/蒜香黄油虾/蒜香黄油虾', '蒜香黄油虾', '水产', 2, 20, '蒜香黄油虾是一道经典的西式海鲜菜，虾肉鲜嫩弹牙，被浓郁的蒜香和黄油包裹，带有淡淡柠檬清香。虾肉富含优质蛋白，搭配黄油提供能量，适合快速补充营养。做法简单，只需几种常见食材，新手也能轻松上手，从备料到出锅大约二十分钟。', '[{"name":"大虾","quantity":8,"quantityMax":10,"unit":"只"},{"name":"无盐黄油","quantity":30,"unit":"克"},{"name":"大蒜","quantity":4,"unit":"瓣"},{"name":"白葡萄酒","quantity":15,"unit":"ml"},{"name":"柠檬","quantity":0.25,"unit":"个"},{"name":"橄榄油","quantity":10,"unit":"ml"}]'::jsonb, '["大虾去头去壳留尾，用牙签挑去虾线，洗净后用厨房纸吸干水分","大蒜切成蒜末，备用","中火加热平底锅，放入 10ml 橄榄油","油热后放入大虾，每面煎 1-1.5 分钟至变色，取出备用","同一锅中加入黄油，融化后放入蒜末，小火炒香（约 30 秒）","如使用白葡萄酒，此时加入并煮至酒精挥发（约 1 分钟）","将虾放回锅中，与蒜香黄油酱汁翻炒均匀（约 1 分钟）","挤入柠檬汁，翻炒均匀后立即关火","装盘，淋上锅中剩余酱汁"]'::jsonb, '["水产","蒜香","鲜香","西式","煎炒","快手","海鲜"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_aquatic_3995b2a218.jpg', 'https://www.bilibili.com/video/BV13k9BYTEdh', '{"energyKcal":450,"protein":30,"carbs":2,"fat":35}'::jsonb, '[null,null,null,90,30,60,60,null,null]'::jsonb),
  ('howtocook:aquatic/蛏抱蛋/蛏抱蛋', '蛏抱蛋', '水产', 3, 30, '蛏抱蛋是福建福州一带的传统家常菜，蛏肉裹着蛋液煎得外酥里嫩，带着洋葱和生抽的咸鲜香气。蛏子富含优质蛋白和锌、铁等微量元素，与鸡蛋搭配营养均衡。制作难度适中，需掌握煎炸火候但步骤不繁琐，预计 大约 30 分钟就能端上餐桌。', '[{"name":"蛏子","quantity":200,"unit":"g"},{"name":"鸡蛋","quantity":2,"unit":"个"},{"name":"食用油","quantity":100,"unit":"ml"},{"name":"洋葱","quantity":0.25,"unit":"个"},{"name":"淀粉","quantity":20,"unit":"g"},{"name":"生抽","quantity":5,"unit":"ml"},{"name":"鸡精","quantity":5,"unit":"ml"},{"name":"料酒","quantity":5,"unit":"ml"}]'::jsonb, '["烧开水，将蛏子放入水中，水煮 2 分钟后，捞上来去壳，放入大碗","往大碗中加入洋葱、生抽、料酒、鸡精、生粉后，充分搅拌","往大碗中打入 2 个 鸡蛋，继续搅拌","起锅烧油，倒入碗中蛏子，煎炸至单面金黄后，翻面继续煎炸"]'::jsonb, '["水产","鲜香","煎炸","闽菜","家常","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_aquatic_7e6e037bac.jpeg', 'https://www.bilibili.com/video/BV1dr4y1u7wE', '{"energyKcal":420,"protein":22,"carbs":24,"fat":28}'::jsonb, '[120,null,null,null]'::jsonb),
  ('howtocook:aquatic/酱炖蟹', '酱炖蟹', '水产', 3, 30, '这道菜是浙江平湖地区的秋日限定咸鲜风味，蟹黄绵润裹着酱香，蟹肉清甜，汤汁拌饭一绝。富含优质蛋白和微量元素。难度适中，适合有基础的新手，从准备到出锅大约 30 分钟。', '[{"name":"螃蟹（首选河蟹，次选梭子蟹）","quantity":500,"unit":"克"},{"name":"豆瓣酱","quantity":30,"quantityMax":50,"unit":"克"},{"name":"冰糖（可选）","quantity":0,"quantityMax":15,"unit":"克"},{"name":"老抽","quantity":15,"unit":"ml"},{"name":"菜油（未脱色的菜籽油，俗称“毛菜油”或“土菜油”，备选花生油）","quantity":20,"unit":"ml"},{"name":"番茄酱","quantity":15,"unit":"ml"},{"name":"料酒","quantity":5,"unit":"ml"},{"name":"老姜","quantity":10,"unit":"克"},{"name":"小葱","quantity":10,"unit":"克"},{"name":"鸡蛋（可选）","quantity":1,"unit":"个"},{"name":"猪肉末（可选）","quantity":50,"unit":"克"},{"name":"水","quantity":500,"unit":"mL"}]'::jsonb, '["把螃蟹刷洗干净，然后在砧板上对半劈开","锅里下菜油，放入姜末和豆瓣酱爆香，加入冰糖炒化，直到冒小气泡就盛出","在盘子里铺上一层酱，然后把切好的螃蟹切开面朝下，整齐排放在酱上","放点葱段和姜片，建议敲个鸡蛋或在盘底铺肉末","上锅蒸 10-12 分钟"]'::jsonb, '["水产","咸鲜","酱香","蒸","江浙","下饭","秋日限定"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_aquatic_e9c8dc3441.jpg', 'https://www.bilibili.com/video/BV1FD4y1o7w2', '{"energyKcal":550,"protein":54,"carbs":24,"fat":34}'::jsonb, '[null,null,null,null,600]'::jsonb),
  ('howtocook:aquatic/阳朔啤酒鱼/阳朔啤酒鱼', '阳朔啤酒鱼', '水产', 3, 30, '阳朔啤酒鱼是广西阳朔的地方名菜，选用漓江鲜鱼带鳞煎制，以啤酒代水焖煮，鱼鳞酥脆、鱼肉鲜嫩，啤酒香与番茄微酸交融，风味浓郁独特。鱼肉富含优质蛋白和矿物质，搭配番茄、辣椒，维生素丰富且开胃助食。制作难度中等，对新手稍具挑战，但跟着步骤操作也能成功，预计 30 分钟即可完成。', '[{"name":"剑骨鱼或鲤鱼","quantity":1,"unit":"条"},{"name":"漓泉啤酒","quantity":330,"unit":"ml"},{"name":"番茄","quantity":2,"unit":"个"},{"name":"青椒","quantity":2,"unit":"个"},{"name":"红椒","quantity":1,"unit":"个"},{"name":"大蒜","quantity":6,"unit":"瓣"},{"name":"生姜","quantity":1,"unit":"块"},{"name":"葱","quantity":2,"unit":"根"},{"name":"桂林辣椒酱","quantity":15,"unit":"克"},{"name":"料酒","quantity":15,"unit":"ml"},{"name":"生抽","quantity":15,"unit":"ml"},{"name":"老抽","quantity":5,"unit":"ml"},{"name":"白糖","quantity":5,"unit":"克"},{"name":"食盐","quantity":5,"unit":"克"},{"name":"食用油","quantity":30,"unit":"ml"}]'::jsonb, '["鱼处理好内脏，保留鱼鳞，清洗干净，从腹部剖开成两半（背部相连），用 15ml 料酒、姜片、食盐 3g 腌制 15 分钟","番茄切块，青椒红椒切块，大蒜拍碎，生姜切片，葱切段（葱白葱叶分开）","用姜片擦拭锅底，热锅后倒入 30ml 食用油，油热后放入鱼（鱼皮朝下），煎至两面金黄、鱼鳞酥脆，盛出备用","锅中留底油，放入葱白、姜片、蒜瓣爆香","加入 15g 桂林辣椒酱，炒出红油","放入番茄块，翻炒至番茄出汁变软","倒入整瓶啤酒，加入 15ml 生抽、5ml 老抽、5g 白糖、5g 食盐，搅拌均匀","放入煎好的鱼，大火烧开后转中小火，盖上锅盖焖煮 15-20 分钟","开盖，放入青椒红椒块，继续煮 3-5 分钟","大火收汁至汤汁浓稠，撒上葱叶段，出锅装盘"]'::jsonb, '["水产","广西名菜","煎焖","鲜香微辣","下饭","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_aquatic_60768bb8a8.png', 'https://www.bilibili.com/video/BV15V411e7MB', '{"energyKcal":520,"protein":55,"carbs":18,"fat":18}'::jsonb, '[900,null,null,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:aquatic/香煎翘嘴鱼/香煎翘嘴鱼', '香煎翘嘴鱼', '水产', 4, 30, '香煎翘嘴鱼是一道风味浓郁的家常河鲜，鱼身经腌晒后干香紧实，煎至外皮金黄酥脆，肉质细腻咸鲜，带着豆瓣与青椒的微辣回甜。鱼肉富含优质蛋白和不饱和脂肪酸，营养易吸收。制作需要提前腌晒两到四天，烹饪时间约半小时，煎鱼时需耐心控火，对新手稍有挑战，但成菜后香气扑鼻，格外下饭。', '[{"name":"翘嘴鱼","quantity":2,"unit":"斤"},{"name":"姜","quantity":20,"unit":"克"},{"name":"葱","quantity":50,"unit":"克"},{"name":"蒜","quantity":4,"unit":"个"},{"name":"青椒","note":"适量"},{"name":"香菜","note":"按个人口味"},{"name":"老抽","quantity":2,"unit":"ml"},{"name":"白糖","quantity":10,"unit":"克"},{"name":"豆瓣酱","note":"适量"},{"name":"料酒","quantity":100,"unit":"ml"},{"name":"生抽","quantity":4,"unit":"ml"},{"name":"盐","quantity":50,"unit":"克"},{"name":"食用油","quantity":100,"unit":"ml"},{"name":"干辣椒","quantity":4,"quantityMax":6,"unit":"个"},{"name":"热水","note":"适量"},{"name":"鸡精","note":"适量"},{"name":"十三香","note":"适量"},{"name":"陈醋","note":"适量"}]'::jsonb, '["鱼开背杀好（让卖鱼的杀好，千万不要剖腹杀鱼，切记是开背），清洗干净","鱼表面用盐涂抹均匀，倒入料酒约 80ml,姜末 20g，放入冰箱保鲜层进行腌制 1-2 天","取出腌制好的鱼，用绳挂起晾晒至半干（约 1-2 天，具体时间需结合气温与阳光）","食用前请将鱼用清水清洗，沥干水分（防止水遇油飞溅）","开大火将锅烧热，迅速改小火，锅中放油，尽量保持整个锅表面有油，将鱼沿锅边划入锅内（先煎鱼背面）","鱼入锅后（和翻面后），不要着急移动鱼的位置（此时容易破皮），煎约 30 秒后，尝试晃动锅","背面煎约 1 分钟后，翻面煎约 1-2 分钟，煎至两面金黄","等两面都煎好时，把鱼推向锅边一点，留点空间放入豆瓣酱炒香味，放入姜蒜，","炒出佐料香味后，加入料酒，生抽，老抽，倒入热水，水量和鱼平齐或者少点","此时改中大火，煮 5-10 分钟，后放入青椒断，白糖，鸡精，十三香，陈醋","改小火 2-5 分钟，放入葱，香菜，即可出锅"]'::jsonb, '["水产","香辣","煎","河鲜","下饭","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_aquatic_32676dd083.jpeg', 'https://www.bilibili.com/video/BV1dw411x7MV', '{"energyKcal":430,"protein":23,"carbs":6,"fat":32}'::jsonb, '[null,86400,86400,null,null,30,120,null,null,300,120]'::jsonb),
  ('howtocook:aquatic/鲤鱼炖白菜/鲤鱼炖白菜', '鲤鱼炖白菜', '水产', 3, 40, '鲤鱼炖白菜是一道鲜香浓郁的家常炖菜，鱼肉软嫩入味，白菜清甜吸汁，属于典型的北方风味。鲤鱼富含优质蛋白和不饱和脂肪酸，搭配白菜提供膳食纤维和维生素，营养均衡。制作过程需要煎鱼和炖煮，有一定难度但不算复杂，适合有基础烹饪经验的朋友尝试，从备料到出锅大约需要 40 分钟。', '[{"name":"食用油","quantity":10,"unit":"ml"},{"name":"姜","quantity":3,"unit":"片"},{"name":"蒜","quantity":3,"unit":"瓣"},{"name":"鲤鱼","quantity":1.2,"unit":"斤"},{"name":"娃娃菜（白菜心）","quantity":13,"unit":"片"},{"name":"盐","quantity":5,"quantityMax":8,"unit":"克"},{"name":"老抽","quantity":3,"unit":"ml"},{"name":"生抽","quantity":6,"unit":"ml"},{"name":"桂皮","quantity":1,"unit":"块"},{"name":"八角","quantity":3,"unit":"个"},{"name":"郫县豆瓣酱","quantity":20,"unit":"克"},{"name":"干辣椒","quantity":4,"quantityMax":6,"unit":"个"}]'::jsonb, '["鲤鱼清洗干净，改刀（在鱼身上多划几个伤口，方便入味）","娃娃菜清洗干净放入盘中备用","锅中加油，等油热放入“少盐” “姜” “蒜” “郫县豆瓣酱” “桂皮” “八角” 炒出香味","把鱼放锅里煎（3 分钟）每（30 秒）需要翻面","加入“水”（水量尽量和鱼平齐，可以少一点点） 放入 “生抽” “老抽” “娃娃菜”","大火炖 15-20 分钟，汤汁快干时添加 “盐” 即可出锅"]'::jsonb, '["水产","鲜香","炖菜","家常","下饭","北方风味"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_aquatic_c5f9a36624.jpeg', 'https://www.bilibili.com/video/BV1gG41117f7', '{"energyKcal":520,"protein":57,"carbs":11,"fat":25}'::jsonb, '[null,null,null,180,null,900]'::jsonb),
  ('howtocook:aquatic/鳊鱼炖豆腐/鳊鱼炖豆腐', '鳊鱼炖豆腐', '水产', 3, 40, '鳊鱼炖豆腐是一道家常红烧菜，鱼肉鲜嫩入味，豆腐饱吸汤汁，咸鲜微辣。鳊鱼富含优质蛋白和不饱和脂肪酸，豆腐则提供植物蛋白和钙质，搭配起来营养均衡。制作难度适中，煎鱼时稍需耐心防粘，整体步骤清晰，新手也能尝试。从备料到完成约需 40 分钟。', '[{"name":"鳊鱼","quantity":550,"unit":"克"},{"name":"老豆腐","quantity":400,"unit":"克"},{"name":"姜","quantity":5,"unit":"片"},{"name":"葱","quantity":0.5,"unit":"根"},{"name":"蒜","quantity":4,"unit":"个"},{"name":"老抽","quantity":2,"unit":"ml"},{"name":"桂皮","quantity":1,"unit":"块"},{"name":"冰糖","quantity":5,"unit":"块"},{"name":"干辣椒","quantity":4,"quantityMax":6,"unit":"个"},{"name":"料酒","quantity":5,"unit":"ml"},{"name":"生抽","quantity":4,"unit":"ml"},{"name":"盐","quantity":5,"quantityMax":8,"unit":"克"},{"name":"八角","quantity":1,"unit":"个"},{"name":"香叶","quantity":1,"quantityMax":3,"unit":"片"},{"name":"食用油","quantity":10,"unit":"ml"},{"name":"热水","quantity":400,"unit":"克"}]'::jsonb, '["鳊鱼改刀,放上姜片和料酒腌制 5-10 分钟","老豆腐切块后放入水中备用","锅中加油，可以放点盐在锅里，防止煎鱼的时候粘锅，把腌制的鱼用厨房纸擦干水分，把鱼放到锅中，两面都煎一下","等两面都煎好时，把鱼推向锅边一点，留点空间放入葱姜蒜，干辣椒，香叶，八角炒出味道","炒出佐料香味后，加入料酒，生抽，老抽，冰糖，桂皮，倒入热水，水量和鱼平齐或者少点","大火烧开后，放入老豆腐，豆腐贴在锅边，加入食盐，转小火","小火烧 10-15 分钟，然后大火收点汁，即可出锅"]'::jsonb, '["水产","红烧","家常","下饭","鲜香","微辣"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_aquatic_5991594c5d.jpg', 'https://www.bilibili.com/video/BV1tV4y187oV', '{"energyKcal":1230,"protein":150,"carbs":30,"fat":55}'::jsonb, '[300,null,null,null,null,null,600]'::jsonb),
  ('howtocook:aquatic/黄油煎虾/黄油煎虾', '黄油煎虾', '水产', 3, 60, '黄油煎虾是一道风味浓郁、虾肉鲜嫩弹牙的家常海鲜菜。鲜虾富含优质蛋白和钙、锌等矿物质，搭配黄油增添了奶香与能量。制作相对简单，只需耐心处理活虾，新手也能顺利上手，总耗时约一小时。', '[{"name":"鲜虾","quantity":300,"unit":"克"},{"name":"黄油","quantity":7,"unit":"克"},{"name":"黑胡椒粒","quantity":15,"unit":"ml"},{"name":"食用油","quantity":45,"unit":"ml"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"米酒","quantity":5,"unit":"ml"},{"name":"白糖","quantity":10,"unit":"ml"},{"name":"盐","quantity":2.5,"unit":"ml"}]'::jsonb, '["鲜虾摘除头部，顺带扯出虾线（这步处理不好可在下一步开背时取出虾线），使用剪刀剪开或菜刀片开虾背，沥干水分备用","调制酱汁：小碗放入上述量的全部生抽、米酒、白糖、盐搅匀备用","中大火热锅，热锅内放入食用油，等待 10 秒让油温升高","虾全部放入锅中，开始瓶磨黑胡椒，均匀地撒在虾上翻炒","虾变色后加入黄油，黄油完全融化后倒入调制酱汁，继续翻炒","大火翻炒 15 秒收汁即可装盘"]'::jsonb, '["水产","鲜香","奶香浓郁","煎炒","快手菜","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_aquatic_ee3b0d6358.jpg', 'https://www.bilibili.com/video/BV13k9BYTEdh', '{"energyKcal":710,"protein":61,"carbs":9,"fat":47}'::jsonb, '[null,null,10,null,null,15]'::jsonb),
  ('howtocook:breakfast/吐司果酱', '吐司果酱', '早餐', 1, 2, '这是一道极简快手早餐，烤至微脆的吐司夹入甜香果酱，外脆内软，方便随身携带，属于典型的便捷西式简餐。主要提供碳水化合物和糖分，能快速补充晨间能量。操作几乎零门槛，非常适合不擅烹饪的忙碌新手。从准备到完成只需大约 2 分钟，无需开火，也几乎不用清洗厨具。', '[{"name":"新鲜吐司","quantity":2,"unit":"片"},{"name":"果酱","note":"足够涂满一面吐司的量"}]'::jsonb, '["将吐司放入面包机","设置好档位,时间到了会自动弹出","两分钟后吐司加热完成弹出","先取出一片吐司,涂满果酱再盖上另一片吐司即可","用餐巾纸包一下可以边走边吃也可以吃完再出门"]'::jsonb, '["早餐","快手","西式","便携","甜香"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_84b958511a.jpg', 'https://www.bilibili.com/video/BV1u24y1T7Z2', '{"energyKcal":190,"protein":5.5,"carbs":38,"fat":1.5}'::jsonb, '[null,null,120,null,null]'::jsonb),
  ('howtocook:breakfast/太阳蛋', '太阳蛋', '早餐', 2, 5, '太阳蛋是一道用微波炉快速制成的家常早餐。口感嫩滑，蛋清凝固、蛋黄微溏，属于典型的快手菜。鸡蛋富含优质蛋白和多种维生素，易于消化吸收。做法非常简单，对新手友好。使用可控火候微波炉只需 3 分钟就能完成，不可控火候的也仅需几分钟反复加热。', '[{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"盐","quantity":1,"unit":"克"},{"name":"油","quantity":5,"unit":"ml"}]'::jsonb, '["准备一个小碗，倒入在上一步计算好的油，撒盐，搅拌均匀。倾斜碗使油沾在碗表面。","取出一个鸡蛋，打入小碗。","蛋黄表面戳孔。牙签戳 5 个或筷子戳 1 个。","放入微波炉，中火 3 分钟。","准备一个小碗，倒入在上一步计算好的油，撒盐，搅拌均匀。倾斜碗使油沾在碗表面。","取出一个鸡蛋，打入小碗。","蛋黄表面戳孔。牙签戳 5 个或筷子戳 1 个。","放入微波炉，1 分钟。","while（太阳蛋 否 大面积成固体状） 用微波炉打(30s);"]'::jsonb, '["早餐","快手","微波","嫩滑","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_c3c97ec823.jpg', 'https://www.bilibili.com/video/BV1WZsaeDEhs', '{"energyKcal":114,"protein":6.3,"carbs":0.6,"fat":9.4}'::jsonb, '[null,null,null,180,null,null,null,60,30]'::jsonb),
  ('howtocook:breakfast/完美水煮蛋', '完美水煮蛋', '早餐', 2, 35, '这是一道通过科学家研发的循环水煮法制成的鸡蛋，蛋黄绵密细腻，蛋白均匀凝固，口感层次分明。它保留了更多营养素，多酚含量比传统煮法高 23%，蛋白质丰富。制作难度较高，需精准控温并反复转移，预计制作时长约 35 分钟。', '[{"name":"新鲜鸡蛋（推荐 AA 级）","quantity":1,"unit":"个"},{"name":"100°C 沸水","quantity":1500,"unit":"ml"},{"name":"30°C 温水","quantity":1500,"unit":"ml"},{"name":"冰水","note":"适量"}]'::jsonb, '["准备两锅水： A 锅维持 100°C 沸水， B 锅维持 30°C 温水","用漏勺将鸡蛋放入 A 锅，启动定时器","精准每 2 分钟将鸡蛋转移至另一锅水","重复转移操作共 16 次（总时长 32 分钟）","最后一次转移后，在 B 锅静置 30 秒","立即放入冰水（ 0 摄氏度）终止加热（维持 30 秒）","剥壳时从钝端气室处开始，沿纵轴剥离蛋膜"]'::jsonb, '["早餐","清淡","鲜香","水煮","营养"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_68c490e487.jpg', 'https://www.bilibili.com/video/BV1v6421M77t', '{"energyKcal":70,"protein":6,"carbs":0.6,"fat":5}'::jsonb, '[null,null,120,1920,30,30,null]'::jsonb),
  ('howtocook:breakfast/微波炉蒸蛋', '微波炉蒸蛋', '早餐', 1, 10, '一道用微波炉快速制作的嫩滑蒸蛋，口感细腻如布丁，属于家常快手菜。富含优质蛋白，易于消化吸收，很适合作为早餐或轻食。制作非常简单，新手也能轻松上手，全程约 10 分钟即可完成。', '[{"name":"鸡蛋","quantity":2,"unit":"个"},{"name":"温水或高汤","quantity":100,"quantityMax":120,"unit":"ml"},{"name":"食盐","quantity":1,"unit":"克"},{"name":"生抽","quantity":2,"unit":"ml"},{"name":"香油","note":"几滴（出锅用）"}]'::jsonb, '["将鸡蛋打散，加入温水/高汤、盐、生抽，轻轻搅匀，尽量不要起泡。","将蛋液过筛倒入耐热碗中，表面若有气泡可用牙签轻戳。","覆盖保鲜膜并扎 8-10 个小孔，或使用微波炉专用盖（留缝隙）。","放入微波炉中加热：","700W：1 分 30 秒 → 视情况再加热 20-30 秒至表面刚凝。","600W：约 1 分 40 秒–2 分 10 秒。","800W：约 1 分 10 秒–1 分 40 秒。","加热完成后取出静置 1 分钟，让余温使中心完全熟化。","淋上香油，撒葱花即可食用。"]'::jsonb, '["早餐","快手","清淡","嫩滑"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_ec72dadc86.jpg', 'https://www.bilibili.com/video/BV1ZS4y1x7GZ', '{"energyKcal":150,"protein":12,"carbs":1,"fat":11}'::jsonb, '[null,null,null,null,90,null,null,60,null]'::jsonb),
  ('howtocook:breakfast/微波炉荷包蛋', '微波炉荷包蛋', '早餐', 1, 2, '微波炉荷包蛋是一道便捷的家常快手菜，蛋白嫩滑、蛋黄软糯，带有芝麻油的清香。鸡蛋富含优质蛋白质和卵磷脂。做法极其简单，新手也能轻松掌握，从准备到出锅仅需约 2 分钟。', '[{"name":"鸡蛋","quantity":2,"unit":"个"},{"name":"饮用水","quantity":35,"unit":"ml"},{"name":"芝麻油","quantity":3,"unit":"ml"},{"name":"盐","quantity":0.8,"unit":"g"}]'::jsonb, '["将鸡蛋打入小碗中，用筷子在所有鸡蛋黄上扎 2 个洞，避免加热弄脏微波炉","然后向碗内倒入常温饮用水","再向碗内倒入食用盐","最后加入芝麻油","将放好材料的碗放入微波炉中，高火加热 80 秒","到达设定时间后，使用抹布垫着手取出成品"]'::jsonb, '["早餐","快手早餐","清淡","微波","家常","佐餐"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_e281e0aadf.jpg', 'https://www.bilibili.com/video/BV1Lt411E7sF', '{"energyKcal":165,"protein":12,"carbs":1,"fat":13}'::jsonb, null),
  ('howtocook:breakfast/微波炉蛋糕', '微波炉蛋糕', '早餐', 1, 20, '微波炉版的快手蛋糕，口感松软香甜，是一道零基础也能轻松上手的家庭甜点。以鸡蛋、面粉为基础，搭配黄油提供能量和浓郁香气，糖分快速补充体力，加入坚果或水果还能增加膳食纤维和维生素。仅需准备少数材料，借助微波炉高火一分钟即可完成，从备料到品尝最快仅需 2 分钟，新手约 20 分钟即可搞定。', '[{"name":"鸡蛋","quantity":1,"unit":"只"},{"name":"黄油","note":"半个鸡蛋大小"},{"name":"面粉","quantity":15,"unit":"克"},{"name":"泡打粉","quantity":2.5,"unit":"克"},{"name":"白（红）糖","quantity":10,"unit":"克"},{"name":"盐","quantity":1,"unit":"克"},{"name":"巧克力","note":"适量"},{"name":"香蕉","note":"适量"},{"name":"咖啡粉","note":"适量"},{"name":"麦片","note":"适量"},{"name":"牛奶","note":"适量"},{"name":"坚果","note":"适量"},{"name":"饼干屑","note":"适量"}]'::jsonb, '["加入以下食材，注意不要超过容器的 3/4","挖半个鸡蛋大的黄油放进容器, 在微波炉加热 15 秒至融化","将巧克力/香蕉 融化/搅碎成 颗粒/糊状","打入一个鸡蛋并打散搅和","15g 白（红）糖（甜党可以多加些） （见附 4）","加入 1g 盐 (如果后续的口味食材含盐需自己斟酌)","加入 2.5g 泡打粉","加入 15g 面粉（筋度没太大影响）","加入任何喜欢的口味食材!（坚果与饼干等干食材不是现在放）","搅和至看不见干粉的稠酸奶状","加入可选的干燥食材（不包括冲泡粉）在顶端","夸赞一下自己🥰","微波炉（高火）加热 1分钟 （至蓬松蛋糕形态）","取出杯子（烫手啊啊啊啊↑）并拍朋友圈就可以吃了"]'::jsonb, '["早餐","香甜","微波炉","快手","甜点"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_673660ab27.jpg', 'https://www.bilibili.com/video/BV1QSMXzMExh', '{"energyKcal":330,"protein":8,"carbs":22,"fat":24}'::jsonb, '[null,15,null,null,null,null,null,null,null,null,null,null,60,null]'::jsonb),
  ('howtocook:breakfast/意式香肠北非蛋', '意式香肠北非蛋', '早餐', 3, 30, '意式香肠北非蛋是一道浓郁鲜香的地中海风味料理，溏心蛋卧在酸甜的番茄肉酱里，搭配脆面包蘸食，口感丰富。主要食材提供优质蛋白质，番茄、甜椒和洋葱带来维生素与膳食纤维。制作不难，只需注意焖蛋火候，全程约 30 分钟即可上桌。', '[{"name":"意式猪肉香肠 / 辣香肠(Chorizo) / 午餐肉","quantity":100,"quantityMax":150,"unit":"克"},{"name":"百味来拿坡里意面酱","quantity":1,"unit":"罐"},{"name":"鸡蛋","quantity":3,"quantityMax":4,"unit":"个"},{"name":"甜椒","quantity":0.5,"unit":"个"},{"name":"洋葱","quantity":0.5,"unit":"个"},{"name":"橄榄油","quantity":10,"quantityMax":15,"unit":"ml"},{"name":"帕马森干酪","note":"适量"},{"name":"新鲜欧芹","note":"适量"},{"name":"干辣椒碎","note":"适量"},{"name":"面包","note":"适量"},{"name":"水","quantity":15,"unit":"ml"}]'::jsonb, '["将意式猪肉香肠去肠衣备用；洋葱切小丁；甜椒切细丝。","在宽口平底锅中倒入 10ml - 15ml 橄榄油，中火加热。","放入处理好的香肠或午餐肉，翻炒至边缘金黄酥脆（如果使用生香肠，翻炒时用勺子将其捣碎变色）。","将洋葱丁和甜椒丝加入锅中与肉一起翻炒，持续翻炒 4 - 5 分钟，直到蔬菜变软，洋葱呈半透明状。","倒入百味来拿坡里意面酱，搅拌均匀。将火调至中低火，保持微沸炖煮 2 - 3 分钟。（如果酱汁看起来太稠，可以加入 15ml 水）。","用勺子的背面在锅内的酱汁中挖出 3 - 4 个小“坑”。","依次小心地将鸡蛋打入每个坑中。","盖上平底锅的盖子，利用蒸汽焖熟蛋白。等待 3 - 5 分钟。注意：请频繁检查状态。当蛋白变得不透明且凝固，但轻轻摇晃平底锅时蛋黄仍能晃动（溏心状态）时即可结束这一步。","关火。根据个人喜好撒上磨碎的帕马森干酪、新鲜欧芹或干辣椒碎。","将平底锅直接端上桌，配以硬壳面包蘸取蛋黄与酱汁食用。"]'::jsonb, '["早餐","鲜香","酸甜","煎焖","地中海","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_53c21bcf97.jpg', 'https://www.bilibili.com/video/BV1KLqoBFEmo', '{"energyKcal":580,"protein":24,"carbs":36,"fat":35}'::jsonb, '[null,null,null,240,120,null,null,180,null,null]'::jsonb),
  ('howtocook:breakfast/手抓饼', '手抓饼', '早餐', 2, 40, '手抓饼外酥里软，层次分明，是深受喜爱的家常面点。饼皮用半烫面制作，柔韧有嚼劲，搭配鸡蛋和蔬菜，营养均衡。做法对新手很友好，从和面到出锅大约只需 40 分钟，非常适合忙碌的早晨。', '[{"name":"普通面粉","quantity":200,"unit":"克"},{"name":"开水","quantity":100,"unit":"毫升"},{"name":"冷水","quantity":50,"unit":"毫升"},{"name":"食用油","quantity":15,"unit":"毫升"},{"name":"盐","quantity":3,"unit":"克"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"生菜","quantity":30,"unit":"克"},{"name":"火腿","quantity":30,"unit":"克"},{"name":"芝士片","quantity":1,"unit":"片"}]'::jsonb, '["面粉放入碗中，加入开水搅拌成絮状，再加入冷水揉成光滑面团，覆盖湿布静置 20 分钟。","面团分成每份约 100 克，搓圆，擀成薄片。","表面均匀涂抹食用油，撒上盐，卷成蜗牛状，松弛 10 分钟。","面团再次擀成薄饼，厚度均匀。","热锅中倒入油，小火煎至两面金黄起泡。","煎好的饼依次铺入煎蛋、生菜、火腿、芝士片等配料，卷起即可。"]'::jsonb, '["早餐","咸香","酥脆","煎炸","家常","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_e5170f09af.jpg', 'https://www.bilibili.com/video/BV1bN411Z77m', '{"energyKcal":960,"protein":35,"carbs":150,"fat":27}'::jsonb, '[1200,null,600,null,null,null]'::jsonb),
  ('howtocook:breakfast/桂圆红枣粥', '桂圆红枣粥', '早餐', 2, 70, '一道甜香软糯的中式传统粥品。以糯米、红枣和桂圆同煮，自带甘甜，暖身暖胃。有补血安神、健脑益智、补养心脾的食养效果。做法非常友好，新手也能轻松掌握，从准备到粥香满屋大约需要 70 分钟。', '[{"name":"糯米","quantity":100,"unit":"克"},{"name":"红枣","quantity":15,"unit":"颗"},{"name":"桂圆","quantity":15,"unit":"颗"}]'::jsonb, '["将桂圆肉扒出，用清水洗两次，放入碗中浸泡 10 分钟","红枣用清水洗两次，放入碗中浸泡 10 分钟","糯米放入电饭锅中，清水淘米两次后，加入 2000ml 水","将桂圆和红枣加入电饭锅","打开电饭锅煮饭模式，1 小时后粥成"]'::jsonb, '["早餐","甜香","煮","养生","快手","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_ff23cbc855.jpg', 'https://www.bilibili.com/video/BV1aE411E7Y5', '{"energyKcal":240,"protein":3.5,"carbs":58,"fat":0.5}'::jsonb, '[600,600,null,null,3600]'::jsonb),
  ('howtocook:breakfast/水煮玉米', '水煮玉米', '早餐', 2, 20, '水煮玉米是一道家常快手菜，口感清甜软糯。新鲜玉米带皮煮制，保留原香，加入盐和糖更能提味。它富含膳食纤维、维生素与碳水化合物，能为身体提供饱足感。做法极其简单，新手也能轻松上手，从准备到上桌只需大约 15 分钟。', '[{"name":"新鲜玉米","quantity":1,"unit":"个"},{"name":"水","note":"淹过玉米约半节指头"},{"name":"盐","quantity":2,"unit":"克"},{"name":"糖","note":"适量"}]'::jsonb, '["将新鲜玉米剥去外皮，剩部分玉米皮入锅","加入淹过玉米约半节指头的水，加盐和糖","水煮开之后转至小火，加盖继续煮 15-20 分钟，玉米煮久点没事。","煮熟后沥干水分，冷却后食用。"]'::jsonb, '["早餐","快手","家常","清甜","水煮"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_7b66f9aed3.jpg', 'https://www.bilibili.com/video/BV1AeMsz1EVp', '{"energyKcal":150,"protein":5,"carbs":33,"fat":1}'::jsonb, '[null,null,900,null]'::jsonb),
  ('howtocook:breakfast/温泉蛋/温泉蛋', '温泉蛋', '早餐', 3, 35, '温泉蛋源自日本，蛋白呈半流动凝乳状，蛋黄却温润凝固，口感滑嫩细腻，与溏心蛋恰好相反。鸡蛋富含优质蛋白、卵磷脂和多种维生素，营养十分全面。制作时需要借助温度计将水温控制在 70℃，虽然对温度稍有要求，但步骤简单，耐心等待约半小时便能完成。佐以昆布酱油和葱花，鲜香清爽，是一道轻松上手的小食。', '[{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"昆布酱油","note":"少量调味"},{"name":"香葱","note":"少量点缀"}]'::jsonb, '["在锅中盛装一定量自来水，确保水面没过约鸡蛋 3cm，水中插入温度计","开火或打开电磁炉，逐渐调整电磁炉功率或火苗大小，使得水温保持在 70 摄氏度","将鸡蛋放入锅中。鸡蛋不可互相堆叠，应皆在底部，并留有空间可以晃动","保持当前温度 25 分钟","准备一杯冰水","捞出鸡蛋，并立刻放入冰水中，等待 3 分钟","将鸡蛋打入小碗，完成制作"]'::jsonb, '["早餐","日式","清淡","嫩滑","慢煮","佐餐"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_5fece16614.jpg', 'https://www.bilibili.com/video/BV1KLWDeuEDa', '{"energyKcal":70,"protein":6,"carbs":1,"fat":5}'::jsonb, '[null,null,null,1500,null,180,null]'::jsonb),
  ('howtocook:breakfast/溏心蛋', '溏心蛋', '早餐', 3, 15, '这是一道用普通电锅就能轻松做出的家常蛋料理，蛋黄呈现流动的溏心状态，口感嫩滑香醇。每颗鸡蛋提供约 6 克优质蛋白质，尤其适合健身人群补充营养。制作过程简单明了，只要掌握好加热和静置的时间，新手也能快速上手，全程仅需 大约 15 分钟。', '[{"name":"鸡蛋","quantity":1,"unit":"颗"},{"name":"水","quantity":2,"unit":"公分"}]'::jsonb, '["将鸡蛋放入电锅中。鸡蛋不可互相堆叠，应皆在底部，并留有空间可以晃动","倒入淹过鸡蛋约 2 公分的冷水","开盖，使用最大功率加热至水滚起（大约 85 - 95 度，稍微滚动，不需完全沸腾）","关火，盖上盖子，让鸡蛋静置。","想要中央有流动的蛋黄，需静置 6 分钟","若想要完全煮熟的易碎蛋黄，需静置 10 分钟","沥干水分，用冷水冲洗鸡蛋约 1 分钟，即可去壳食用。"]'::jsonb, '["早餐","清淡","煮","快手","家常","嫩滑"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_3f4ca55b17.jpg', 'https://www.bilibili.com/video/BV1CFmdB2EKA', '{"energyKcal":78,"protein":6.2,"carbs":0.6,"fat":5.3}'::jsonb, '[null,null,null,null,360,600,60]'::jsonb),
  ('howtocook:breakfast/煎饺', '煎饺', '早餐', 2, 15, '煎饺是一道底部金黄酥脆、内馅鲜嫩多汁的家常面点，常见于北方餐桌。搭配速冻水饺制作，富含碳水化合物和蛋白质，简单快手。预估难度二星，对新手非常友好，总共约需 15 分钟就能端上桌。', '[{"name":"饺子（速冻水饺）","quantity":10,"quantityMax":15,"unit":"个"},{"name":"食用油","quantity":10,"quantityMax":15,"unit":"ml"},{"name":"清水","note":"适量"},{"name":"黑芝麻","note":"适量"},{"name":"葱花","note":"适量"}]'::jsonb, '["取出平底锅（不沾平底锅最佳）","加入 10ml - 15 ml 食用油","开火，放入饺子（尽量平均铺开，不宜堆叠）","立刻加入清水，水线没过饺子平均高度的 1/2","盖上锅盖（此时炉灶应该处于大火）","等待 8 - 10 分钟","当锅中水分仅剩 2mm 时， 转中火开始煎制","当水分全部蒸发后，摇晃平底锅使饺子受热均匀","放入黑芝麻和葱花再焖 10s","1 - 2 分钟夹出一个饺子观察底部，若出现金黄色脆皮立即取出"]'::jsonb, '["早餐","快手","家常","煎制","酥脆"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_143b7df77f.jpg', 'https://www.bilibili.com/video/BV1uh411L7tk', '{"energyKcal":640,"protein":20,"carbs":78,"fat":28}'::jsonb, '[null,null,null,null,null,null,null,null,10,null]'::jsonb),
  ('howtocook:breakfast/蒸水蛋', '蒸水蛋', '早餐', 2, 15, '这是一道以滑嫩如布丁的口感和清雅鲜美的风味见长的家常菜，南北通吃，北方常亲切地称其为“鸡蛋糕儿”。鸡蛋富含优质蛋白和卵磷脂，是日常补充营养的便捷之选。做法只需掌握蛋水比例和小火慢蒸的诀窍，对新手非常友好，从准备到出锅通常 大约 15 分钟就能完成。', '[{"name":"新鲜鸡蛋","quantity":2,"unit":"只"},{"name":"热水","quantity":260,"unit":"ml"},{"name":"盐","quantity":2,"unit":"克"}]'::jsonb, '["鸡蛋打入碗中，打散","取其他容器，倒入 1.5 倍（半个蛋壳为 0.5 倍水）于蛋液的温水（温度 20~30），将盐倒入水中化开","将盐水倒入鸡蛋液中，顺时针或逆时针单方向搅拌均匀，气泡之类的可以用舀出丢弃，过筛则口感更加。","使用锡纸包裹盛蛋液的碗（或用盘子盖住），置入提前带盖并加入大约 3cm 深度水的锅中","中火烧至水开，转最小的火继续蒸 4 分钟"]'::jsonb, '["早餐","清淡","蒸","快手","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_2f5cbe98a7.jpg', 'https://www.bilibili.com/video/BV1PqFrzuEEP', '{"energyKcal":143,"protein":12.6,"carbs":1.1,"fat":9.9}'::jsonb, '[null,null,null,null,240]'::jsonb),
  ('howtocook:breakfast/蒸花卷', '蒸花卷', '早餐', 2, 20, '这是一道北方传统面食，松软可口，带着淡淡麦香。使用冷冻花卷蒸制，能快速补充碳水化合物和膳食纤维。做法极其简单，烹饪新手也能轻松掌握，全程仅需半小时，是理想的快手早餐。', '[{"name":"冷冻花卷","quantity":5,"unit":"个"},{"name":"水","quantity":400,"unit":"ml"}]'::jsonb, '["从花卷的包装袋中取出 5 个花卷","把花卷平铺在碟子上，尽量不用重叠","往锅里倒入 400ml 水，把蒸架放里面，把装花卷的碟子放在蒸架上，盖上锅盖。","开大火加热，直至水沸腾。","转中火加热 15 分钟","开盖用手感受花卷的表面温度，如果不够热，就继续盖上盖子加热，否则就可以关火出锅。","碟子取出放凉至 50 度即可食用"]'::jsonb, '["早餐","蒸制","快手","家常","面食","北方"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_47a55b934c.jpg', 'https://www.bilibili.com/video/BV1n7411R7Je', '{"energyKcal":200,"protein":6}'::jsonb, '[null,null,null,null,900,null,null]'::jsonb),
  ('howtocook:breakfast/燕麦鸡蛋饼', '燕麦鸡蛋饼', '早餐', 2, 15, '燕麦鸡蛋饼是一道快手营养早餐，口感软嫩，带有燕麦的谷物香气与蛋奶的醇厚，属于家常简约风格。富含蛋白质、碳水化合物和膳食纤维，能为身体提供充足能量，尤其适合健身人士和工作日早晨。做法简单，对新手友好，从备料到出锅通常只需十几分钟。', '[{"name":"鸡蛋","quantity":2,"unit":"个"},{"name":"燕麦","quantity":50,"unit":"克"},{"name":"蔬菜","quantity":50,"unit":"克"},{"name":"牛奶","quantity":250,"unit":"ml"},{"name":"黄油","note":"适量"}]'::jsonb, '["将牛奶与干燕麦混合搅拌均匀至黏稠状。","将鸡蛋搅拌均匀至颜色单一程度。","将鸡蛋液倒入燕麦牛奶中继续搅拌至黏稠、均匀。","平底锅中加入一层黄油并覆盖均匀。","下入搅拌好的食材，并摊开至饼状。","小火加热两到三分钟。如想要加入蔬菜，可以在加热过程中加入碎菜叶。","翻面继续加热两分钟。","出锅，搭配剩下的牛奶作为早餐。"]'::jsonb, '["早餐","快手","煎制","清淡","健身"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_fa3a294646.jpg', 'https://www.bilibili.com/video/BV12V411g7TW', '{"energyKcal":570,"protein":28,"carbs":50,"fat":30}'::jsonb, '[null,null,null,null,null,null,120,null]'::jsonb),
  ('howtocook:breakfast/牛奶燕麦', '牛奶燕麦', '早餐', 1, 8, '一份高蛋白、高纤维的便捷营养早餐，将牛奶的滑润、燕麦的谷香与煎蛋的嫩脆巧妙结合，入口温热柔和、易于消化，饱腹感强。制作过程简单直接，对新手极为友好，全程约三分钟即可完成，搭配蔬果更添清爽。', '[{"name":"牛奶","quantity":280,"unit":"ml"},{"name":"燕麦","quantity":40,"unit":"克"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"水","quantity":200,"unit":"ml"},{"name":"椒盐","quantity":3,"unit":"克"}]'::jsonb, '["将牛奶倒入早餐杯（冷的即可）","准备好 200ml 水，如果是直饮水直接加入燕麦，否则请烧开后加入燕麦","水沸后 2 分钟，燕麦煮好","煮好的燕麦捞出倒入牛奶中（尽量不要将煮燕麦的水也倒入牛奶，影响口感）","将燕麦替换为快煮燕麦","将牛奶倒入装有快煮燕麦的容器中并搅拌","将混合物放入微波炉中","中等火力微波 4 分钟","热锅，锅内放一层底油，油热后煎鸡蛋，每面煎 20s，考虑调底味（3g 椒盐，可选）","关火，装盘"]'::jsonb, '["早餐","快手","营养","清淡","高蛋白","高纤维"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_e474319056.jpg', 'https://www.bilibili.com/video/BV1FD4y1q7ch', '{"energyKcal":400,"protein":20,"carbs":42,"fat":18}'::jsonb, '[null,null,120,null,null,null,null,240,20,null]'::jsonb),
  ('howtocook:breakfast/空气炸锅面包片', '空气炸锅面包片', '早餐', 1, 5, '空气炸锅面包片是一道极简快手的主食，外脆内软，麦香纯粹，特别适合减脂期食用。它富含膳食纤维和植物蛋白，能提供较长时间的饱腹感。做法毫无门槛，只需将面包片放入空气炸锅即可，对新手极其友好，从准备到完成仅需大约五分钟。', '[{"name":"面包片","quantity":2,"unit":"片"}]'::jsonb, '["取出两片面包片（建议使用粗粮面包片）","将面包片垂直放入空气炸锅","200°C 烘烤 5 分钟","取出即可使用"]'::jsonb, '["早餐","快手","清淡","减脂","酥脆","饱腹"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_ce19e75c5d.jpg', 'https://www.bilibili.com/video/BV1Qx4y1N7AB', '{"energyKcal":160,"protein":6,"carbs":28,"fat":2.5}'::jsonb, '[null,null,300,null]'::jsonb),
  ('howtocook:breakfast/美式炒蛋', '美式炒蛋', '早餐', 2, 20, '这是一道松软鲜嫩的美式家常蛋料理，加入牛奶后蛋花细密、口感绵润，富含优质蛋白和钙质。做法简单，对新手友好，从准备到出锅大约只需 20 分钟。', '[{"name":"鸡蛋","quantity":3,"unit":"个"},{"name":"全脂牛奶/奶油","quantity":10,"unit":"克"},{"name":"黄油","quantity":5,"unit":"克"},{"name":"盐","quantity":1,"unit":"克"}]'::jsonb, '["鸡蛋打入大碗中，加盐搅打至起泡，静置 15 分钟","黄油切小块入锅，倒入蛋液，开小火不断搅拌","黄油一融化，就快速翻动蛋液，将其打碎成细密状，在蛋液大体凝固前关火","加入牛奶搅拌 15 秒，至炒蛋湿润绵密，装盘"]'::jsonb, '["早餐","鲜香","炒","快手","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_db51d50174.jpg', 'https://www.bilibili.com/video/BV1n7411m7yF', '{"energyKcal":257,"protein":19.2,"carbs":2.6,"fat":18.7}'::jsonb, '[900,null,null,15]'::jsonb),
  ('howtocook:breakfast/苏格兰蛋/苏格兰蛋', '苏格兰蛋', '早餐', 3, 25, '这道简易版苏格兰蛋外层酥脆，内里糖心软嫩，融合了芝士的奶香和培根的烟熏风味，是一道源自英式做法的创意小吃。鸡蛋提供优质蛋白质，芝士补充钙质，搭配手抓饼皮能满足一餐的能量需求。制作过程不复杂，新手也能轻松上手，从准备到出锅大约只需 20 至 30 分钟。', '[{"name":"鸡蛋","quantity":50,"unit":"克"},{"name":"手抓饼","quantity":1,"quantityMax":2,"unit":"份"},{"name":"芝士片","quantity":1,"quantityMax":2,"unit":"片"},{"name":"培根片","quantity":1,"quantityMax":2,"unit":"片"}]'::jsonb, '["用冷水下锅水开 3 分钟后捞出","鸡蛋捞出，放入冰水中剥壳更快速也更完整","用芝士片包裹鸡蛋","培根片包裹鸡蛋","手抓饼两端切除以矩形包裹鸡蛋","油温 6 成下锅（油面波动，有青烟，筷子插入油中周围泛起气泡即是 6 成温度） 炸制金黄即可","空气炸锅 160 度 15 分钟","切开即可食用"]'::jsonb, '["早餐","鲜香","酥脆","煎炸","英式","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_breakfast_7e011cbd71.png', 'https://www.bilibili.com/video/BV14P411h7Rx', '{"energyKcal":450,"protein":22,"carbs":25,"fat":28}'::jsonb, '[180,null,null,null,null,null,900,null]'::jsonb),
  ('howtocook:breakfast/茶叶蛋', '茶叶蛋', '早餐', 3, 30, '这道传统小吃茶香浓郁，鲜香可口，富含优质蛋白质，是快捷的营养早餐之选。制作步骤清晰，难度适中，新手需要留意火候与香料配比，约 30 分钟即可完成，一次能做够 2-3 人食用，适合周末从容备好。', '[{"name":"鸡蛋","quantity":400,"unit":"克"},{"name":"八角","quantity":4,"unit":"克"},{"name":"香叶","quantity":0.5,"quantityMax":1,"unit":"克"},{"name":"桂皮","quantity":3,"unit":"克"},{"name":"茴香","quantity":5,"unit":"克"},{"name":"冰糖","quantity":15,"unit":"克"},{"name":"红茶","quantity":20,"unit":"克"},{"name":"生抽","quantity":15,"unit":"克"},{"name":"老抽","quantity":25,"unit":"克"},{"name":"食盐","quantity":3,"unit":"克"}]'::jsonb, '["用冷水将鸡蛋煮熟，大火大约 8 分钟（根据自家厨具决定）","鸡蛋捞出，过冷水","将鸡蛋互相碰撞，使每个鸡蛋产生裂缝","将鸡蛋下锅，放入八角，香叶，桂皮，茴香，冰糖，红茶，生抽，老抽，食盐","加水直至没过鸡蛋","大火煮开之后，转中小火煮 15 分钟"]'::jsonb, '["早餐","茶香","卤味","咸鲜","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_51cbb019c4.jpg', 'https://www.bilibili.com/video/BV1h2421F74u', '{"energyKcal":220,"protein":14,"carbs":2,"fat":14}'::jsonb, '[480,null,null,null,null,900]'::jsonb),
  ('howtocook:breakfast/蛋煎糍粑', '蛋煎糍粑', '早餐', 2, 10, '一道简单快手的小吃，外皮微酥，内里软糯，裹着蛋香与甜味，是南方家常风味。糍粑提供丰富碳水，鸡蛋补充蛋白质，热量较高但很顶饱。制作过程极其简单，新手也能轻松驾驭，全程仅需大约十 分钟。', '[{"name":"糍粑","quantity":2,"unit":"块"},{"name":"红糖或白糖","quantity":10,"quantityMax":15,"unit":"克"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"食用油","quantity":10,"quantityMax":15,"unit":"ml"},{"name":"食用盐","quantity":2,"unit":"克"}]'::jsonb, '["把糍粑切成长方形小块，便于后面煎","碗里打入一个鸡蛋并把鸡蛋搅碎，加入 2g 食用盐","将切好的小糍粑依此放入搅碎的鸡蛋里面，涂抹完糍粑双面为止","锅里倒入植物油 10ml ，把涂抹好的糍粑小块放进去小火慢慢煎软。","将剩下的鸡蛋液慢慢倒在糍粑表面","用筷子或者勺子为糍粑翻面，来回煎至金黄色后开吃"]'::jsonb, '["早餐","香甜","煎","南方","快手","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_9223c333b0.jpg', 'https://www.bilibili.com/video/BV1TT4y1D7Kv', '{"energyKcal":760,"protein":10.8,"carbs":73,"fat":18.4}'::jsonb, null),
  ('howtocook:breakfast/金枪鱼酱三明治', '金枪鱼酱三明治', '早餐', 1, 5, '这道西式早餐三明治以水浸金枪鱼拌入蛋黄酱和俄式酸黄瓜汁，咸鲜微酸，口感绵密，配上烤脆的吐司格外饱腹。富含优质蛋白和 Omega-3 等营养，能快速补充能量。制作非常简单，只需混合酱料、用轻食机加热，新手也能在 5 分钟里轻松搞定。', '[{"name":"水浸金枪鱼罐头","quantity":65,"unit":"克"},{"name":"方形吐司片","quantity":2,"unit":"片"},{"name":"蛋黄酱","quantity":50,"unit":"ml"},{"name":"俄式酸黄瓜汁","quantity":10,"quantityMax":15,"unit":"ml"},{"name":"芝士片（可选）","note":"适量"},{"name":"火腿片（可选）","note":"适量"}]'::jsonb, '["将金枪鱼、蛋黄酱、俄式酸黄瓜汁倒入碗中，用勺子搅拌，保证将金枪鱼块搅碎，酱整体呈糊状，并备用","将 1 片吐司放在轻食机上","将做好的金枪鱼酱涂抹到吐司上，建议 10-15ml","将另一片方形吐司片覆盖在上面，并按压轻食机，开机","待轻食机自动停止加热，即可装盘使用"]'::jsonb, '["早餐","咸鲜微酸","快手","西式","营养","简单"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_8d135e4afa.jpg', 'https://www.bilibili.com/video/BV1Sr4y1B7F8', '{"energyKcal":470,"protein":24,"carbs":28,"fat":27}'::jsonb, null),
  ('howtocook:breakfast/韩国麻药鸡蛋', '韩国麻药鸡蛋', '早餐', 1, 90, '一道甜辣浓郁的韩式溏心蛋小菜，酱汁挂满蛋白，入口嫩滑，回味微辛。鸡蛋提供优质蛋白与卵磷脂，营养饱腹。做法极为简单，新手也能轻松上手，从煮蛋到冷藏入味大约需要一个半小时。', '[{"name":"鸡蛋","quantity":5,"quantityMax":8,"unit":"个"},{"name":"韩式酱油（或生抽）","quantity":4,"unit":"汤匙"},{"name":"清水","quantity":4,"unit":"汤匙"},{"name":"日式味淋","quantity":2,"unit":"汤匙"},{"name":"白糖","quantity":2,"unit":"汤匙"},{"name":"芝麻油","quantity":5,"unit":"ml"},{"name":"青葱","quantity":15,"unit":"克"},{"name":"辣椒（小米辣或青红椒）","quantity":15,"unit":"克"}]'::jsonb, '["烧一锅开水，水沸腾后放入鸡蛋，煮 7 分钟（得到完美的溏心蛋状态）。","煮鸡蛋的期间调制酱汁：将 4 汤匙酱油、4 汤匙清水、2 汤匙味淋、2 汤匙白糖倒入小锅中。","加热酱汁至沸腾，煮开以挥发掉味淋中的酒精味，随后关火放凉备用。","将切好的辣椒圈加入放凉的酱汁中。","将煮好的鸡蛋捞出，放入冰水中冷却后剥去蛋壳。","将剥好的鸡蛋放入调好的酱汁中，表面淋上 5ml 芝麻油并撒上葱花。","放入冰箱冷藏等待 1 - 2 小时，让鸡蛋充分入味。"]'::jsonb, '["早餐","韩式","溏心蛋","甜辣","快手","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_0486f1af3d.jpg', 'https://www.bilibili.com/video/BV1hC411H74E', '{"energyKcal":110,"protein":6.5,"carbs":7,"fat":6}'::jsonb, '[420,null,null,null,null,null,null]'::jsonb),
  ('howtocook:breakfast/鸡蛋三明治', '鸡蛋三明治', '早餐', 2, 10, '这是一道简单快手的西式简餐，吐司夹着绵密的鸡蛋酱和咸香培根，口感软嫩又带着焦香。鸡蛋富含优质蛋白，搭配培根和黄油能快速补充能量。操作非常友好，厨房新手也能轻松驾驭，全程只需 大约 10 分钟即可完成。', '[{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"吐司","quantity":2,"unit":"片"},{"name":"培根","quantity":2,"unit":"片"},{"name":"黄油","quantity":10,"unit":"克"},{"name":"蛋黄酱","quantity":20,"unit":"克"},{"name":"盐","quantity":1,"unit":"克"},{"name":"黑胡椒","quantity":2,"unit":"克"}]'::jsonb, '["吐司切去四边，备用","鸡蛋煮熟，捣碎","混合鸡蛋、蛋黄酱、盐、黑胡椒","锅中加入黄油，煎熟培根","组装吐司，在两片吐司间加入制作好的鸡蛋酱及培根","四边形吐司切成三角形装盘"]'::jsonb, '["早餐","快手","西式","咸香","煎"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_breakfast_341728c386.jpg', 'https://www.bilibili.com/video/BV1t24y1C7VD', '{"energyKcal":500,"protein":18.5,"carbs":30,"fat":34}'::jsonb, null),
  ('howtocook:condiment/油泼辣子/油泼辣子', '油泼辣子', '酱料', 3, 10, '一道香辣扑鼻的陕西风味调味料，红油润泽，芝麻蒜香交织，入口辣而不燥、回味绵长。辣椒富含维生素 C 与辣椒素，能增进食欲、暖身驱寒。制作过程需掌握油温，对新手稍有挑战，但按部就班即可成功。全程约 10 分钟完成，是家常拌菜拌面的点睛之笔。', '[{"name":"蒜头","quantity":1,"unit":"个"},{"name":"干辣椒面","quantity":100,"unit":"克"},{"name":"盐","quantity":5,"unit":"克"},{"name":"熟白芝麻","quantity":15,"unit":"克"},{"name":"小米椒","quantity":1,"unit":"个"},{"name":"花生油","quantity":150,"unit":"毫升"},{"name":"五香粉","quantity":10,"unit":"克"},{"name":"草寇","quantity":1,"unit":"个"},{"name":"小葱","quantity":3,"quantityMax":5,"unit":"根"},{"name":"八角","quantity":1},{"name":"花椒","quantity":20,"quantityMax":50,"unit":"粒"},{"name":"香叶","quantity":2,"quantityMax":3,"unit":"片"},{"name":"白芷","quantity":2,"quantityMax":3,"unit":"片"},{"name":"姜片","note":"适量"},{"name":"糖","quantity":30,"unit":"克"},{"name":"白醋","quantity":5,"unit":"ml"},{"name":"味精","note":"适量"}]'::jsonb, '["拿出蒜头掰 2 个小蒜头去皮","拿出砧板剁碎小蒜头、小米椒","拿出碗倒入花生油","油热放入其他配料和小葱,等到香料变焦，捞出扔掉","拿出铁锅将碗内的油放入加热 2 分钟（菜籽油烧至冒烟）","此时是空碗","往空碗加入干辣椒面、白芝麻、蒜末、小米椒、盐、五香粉、草寇作为\"调料\"","关火将油温冷却至 210 摄氏度","将锅内热油倒入碗内并用勺子搅拌即可（可以在 165 摄氏度时加入同样\"调料\"的碗最后进行混合进行增辣）","倒入热油稍微搅拌后放入白醋，此时会重新沸腾。继续进行搅拌，白醋增香。","油泼辣子冷却到温热放白糖和味精，白糖可以是辣味柔和，不会那么的呛口"]'::jsonb, '["酱料","香辣","陕西风味","凉拌","快手","调味料"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_condiment_3642d273ae.jpg', 'https://www.bilibili.com/video/BV1Vaw9eBEnH', '{"energyKcal":110,"protein":0.5}'::jsonb, null),
  ('howtocook:condiment/油酥', '油酥', '酱料', 2, 3, '这是一道中式面点配料，常用于烙饼，能让成品层次分明、外酥里软。主要提供碳水化合物和脂肪，为身体补充能量。做法十分简单，新手友好，预计只需 3 分钟就能调好。', '[{"name":"面粉","note":"适量"},{"name":"油","quantity":10,"unit":"ml"},{"name":"盐","note":"适量"}]'::jsonb, '["面粉盛小碗里，加入盐","加入 200 度的热油","用筷子将其搅拌成无固状物体的糊状。"]'::jsonb, '["酱料","酥脆","面点","烙饼","家常","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_condiment_e44da61a7d.jpg', 'https://www.bilibili.com/video/BV1Zf4y1M7jJ', '{"energyKcal":270,"protein":5,"carbs":37,"fat":10}'::jsonb, null),
  ('howtocook:condiment/炸串酱料', '炸串酱料', '酱料', 2, 10, '这款万能炸串酱料香辣浓郁、鲜咸适口，属于街头风味风格。主要提供脂肪和香辛料带来的芳香物质，能增进食欲。制作非常简单，对新手毫无压力，全程只需大约 10 分钟即可完成。', '[{"name":"干辣椒面（粗细都准备）","quantity":60,"unit":"克"},{"name":"孜然粉","quantity":20,"unit":"克"},{"name":"胡椒粉","quantity":10,"unit":"克"},{"name":"五香粉","quantity":15,"unit":"克"},{"name":"花椒粉","quantity":15,"unit":"克"},{"name":"十三香","quantity":5,"unit":"克"},{"name":"麻辣鲜","quantity":5,"unit":"克"},{"name":"白芝麻","quantity":30,"unit":"克"},{"name":"食盐","quantity":20,"unit":"克"},{"name":"鸡精","quantity":8,"unit":"克"},{"name":"油","note":"以没过所有原材料为佳"},{"name":"香油","quantity":10,"unit":"ml"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"花椒油","quantity":10,"unit":"ml"},{"name":"蚝油","quantity":10,"unit":"ml"}]'::jsonb, '["所有原料在容器内混合，搅拌均匀。","锅里烧热油，油的用量以在容器内没过所有原材料为佳。","分三次淋入热油，每次 1/3，同时搅拌。","最后放入香油 10ml，生抽 10ml，花椒油 10ml，蚝油 10ml。"]'::jsonb, '["酱料","香辣","街头风味","快手","鲜香","万能"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_condiment_3794b71097.jpg', 'https://www.bilibili.com/video/BV1kL4y1N7DC', null, null),
  ('howtocook:condiment/简易版炒糖色', '简易版炒糖色', '酱料', 4, 10, '糖色是中餐红烧类菜肴上色的关键技法，火候到位时能带来红亮光泽与独特的焦香风味。主要成分为糖，提供能量，但更多是调和菜肴色泽与口味。这道简易版炒糖色对火候控制有一定要求，新手需多加练习才能避免发苦或发甜，整体制作约需十分钟。', '[{"name":"冰糖/白砂糖/绵白糖（任选其一）","quantity":50,"unit":"克"},{"name":"油","quantity":100,"unit":"ml"},{"name":"开水","quantity":500,"unit":"ml"}]'::jsonb, '["开火，并向锅中倒入 100ml 开水","再向锅中倒入 100ml 油，与第一步间隔越短越好，此时锅为大火中火都可以，着急的话可以大火","放入冰糖（如果冰糖过于耦合，可以提前敲碎，做到耦合度越低越好）","调整火力为中火","开始搅拌","要一直一直一直搅拌，变成棕褐色，此时转为小火","再变稀，变红茶色，再变成酱红色后起小泡泡，准备好执行下面的操作1or操作2","小泡泡会逐渐消失，之后会出现大泡泡，大泡泡出现时糖色完成","需要在此时快速进行下一步操作（无论哪种操作都一定要提前准备好并快速！否则火候过大糖色发苦），根据菜品派别以及个人口味作出选择","操作 1：可以直接加 400ml 开水降温","操作 2（进阶调味版）：在糖液变成枣红色并起密集小泡时，迅速加入提前备好的葱姜蒜、花椒等辅料进行翻炒。爆出香味后（约 5-10 秒内），必须立刻倒入 400ml 开水降温中止反应。（注：若后续菜谱需要翻炒肉类上色，请在此步先下入肉类翻炒，最后再加水。）"]'::jsonb, '["酱料","咸甜","焦香","炒制","家常","红烧上色"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_condiment_8fe90a4c95.jpg', 'https://www.bilibili.com/video/BV1No4y1A7iH', '{"energyKcal":1010,"protein":0,"carbs":50,"fat":90}'::jsonb, '[null,null,null,null,null,null,null,null,null,null,10]'::jsonb),
  ('howtocook:condiment/糖醋汁', '糖醋汁', '酱料', 2, 10, '这款调味汁酸甜可口，是中餐里糖醋菜肴的经典风味来源。调制简单、比例易记，新手也能轻松上手，从备料到完成约需 10 分钟。糖分能提供能量，醋香有助于开胃解腻，让家常菜瞬间变得有滋有味。', '[{"name":"清水","quantity":50,"unit":"ml"},{"name":"生抽","quantity":40,"unit":"ml"},{"name":"白糖","quantity":30,"unit":"g"},{"name":"白醋/米醋","quantity":20,"unit":"ml"},{"name":"料酒","quantity":10,"unit":"ml"}]'::jsonb, '["按照比例将各调料在小碗中搅拌均匀","按不同菜肴的方式处理完毕后，将配制好的糖醋汁倒入锅中","根据各菜肴的不同，烹制 5-10 分钟","大火收汁，可增加菜的浓度、香味和光泽"]'::jsonb, '["酱料","酸甜","调味","中餐","家常","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_condiment_2432f88fa4.jpg', 'https://www.bilibili.com/video/BV1N62EYHEnR', '{"energyKcal":155,"protein":4.5,"carbs":31,"fat":0}'::jsonb, '[null,null,300,null]'::jsonb),
  ('howtocook:condiment/草莓酱/草莓酱', '草莓酱', '酱料', 2, 120, '这是一道酸甜可口、果香浓郁的家常果酱，非常适合涂抹面包。草莓富含维生素 C，不过熬煮时糖分较高，可依口味调整。做法非常简单，新手也能轻松搞定，从准备到熬好大约需要两个小时。', '[{"name":"草莓","quantity":1200,"unit":"克"},{"name":"白砂糖","quantity":400,"unit":"克"}]'::jsonb, '["草莓洗净去叶","将草莓切碎放入合适的碗中","将白糖倒入碗中与草莓搅拌均匀","碗用保鲜膜覆盖静置 1 小时","将静置的草莓和糖的混合物倒入不粘锅中开大火烧开","烧开后转小火不断搅拌直至果酱呈粘稠状关火","待草莓酱冷却后装入准备好的密封罐中"]'::jsonb, '["酱料","酸甜","家常","自制","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_condiment_bdd079a7a5.jpeg', 'https://www.bilibili.com/video/BV1gi4y1N7Ba', '{"energyKcal":53,"protein":0.1,"carbs":13.5,"fat":0}'::jsonb, '[null,null,null,3600,null,null,null]'::jsonb),
  ('howtocook:condiment/葱油', '葱油', '酱料', 3, 30, '葱油是一道提香增鲜的家常调味油，带着浓郁的葱香和开洋的复合鲜味，用来拌馅、凉拌或热菜明油都很适合。主要提供油脂能量，葱姜等辛香料还含有植物活性成分，可辅助去腥开胃。做法简单，对新手友好，一般准备加熬制大约 30 分钟就能完成。', '[{"name":"油","quantity":200,"unit":"克"},{"name":"葱（大葱小葱都可以）","quantity":80,"unit":"克"},{"name":"姜","quantity":20,"unit":"克"},{"name":"洋葱","quantity":150,"unit":"克"},{"name":"料酒","quantity":10,"unit":"ml"},{"name":"开洋（可选）","quantity":50,"unit":"克"},{"name":"香菜（可选）","note":"适量"}]'::jsonb, '["开洋泡入 50 度温水中，加入 10ml 料酒去腥，泡 10 分钟后取出沥干水分","葱，香菜洗净，切成 5cm 长的段，擦干表面水份","洋葱切成丝，在锅里用热水煮 5 分钟，取出沥干水份","姜去皮，切成片","锅里倒入全部油，放入上述预处理好的材料，开中小火炸 20 分钟"]'::jsonb, '["酱料","葱香","鲜香","调味油","拌馅","拌面","热淋"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_condiment_5790bd6201.jpg', 'https://www.bilibili.com/video/BV1c54y127TP', '{"energyKcal":270,"protein":1,"carbs":0.5,"fat":30}'::jsonb, '[600,null,300,null,1200]'::jsonb),
  ('howtocook:condiment/蒜香酱油', '蒜香酱油', '酱料', 2, 5, '蒜香酱油是一道蒜香浓郁、咸鲜油润的家常蘸料，常用于白切鸡、饺子等菜肴的提味。大蒜和芝麻分别具有抗菌和补充不饱和脂肪酸的作用。做法极其简单，对新手非常友好，全程只需大约 5 分钟即可完成。', '[{"name":"蒜头","quantity":2,"unit":"瓣"},{"name":"白芝麻","quantity":5,"unit":"克"},{"name":"花生油","quantity":15,"unit":"ml"},{"name":"酱油","quantity":30,"unit":"ml"}]'::jsonb, '["拍碎蒜头","往蘸料碟中加入酱油","起锅，加入花生油，等到油温滚烫后加入拍好的蒜头，炸半分钟","半分钟后，关火，把热油倒入蘸料碟，用筷子搅拌即可"]'::jsonb, '["酱料","蒜香","咸鲜","炸","家常","蘸料"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_condiment_c30ac2c258.jpg', 'https://www.bilibili.com/video/BV1wK411h7jf', null, null),
  ('howtocook:condiment/蔗糖糖浆/蔗糖糖浆', '蔗糖糖浆', '酱料', 1, 5, '自制饮料糖浆，按 1：1 比例将白砂糖与水混合溶解，方便控制冷饮甜度，是调饮的基础配方。富含碳水化合物，能快速补充能量。做法极其简单，对新手非常友好，仅需几分钟即可完成，冷藏可保存一周。', '[{"name":"白砂糖","quantity":100,"unit":"克"},{"name":"水","quantity":100,"unit":"克"}]'::jsonb, '["将称好的白砂糖的饮用水于容器混匀","容器封盖放冰箱冷藏"]'::jsonb, '["酱料","甜味","调饮基础","快手","冷藏"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_condiment_2e5ad69bbf.jpg', 'https://www.bilibili.com/video/BV1Nm4y1x7gV', '{"energyKcal":400,"protein":0,"carbs":100,"fat":0}'::jsonb, null),
  ('howtocook:dessert/反沙芋头/反沙芋头', '反沙芋头', '甜品', 3, 20, '反沙芋头是一道外酥里糯、甜香可口的潮汕传统小吃，常作下午茶点。荔浦芋头富含膳食纤维、钾和多种维生素，能提供持久饱腹感。制作不难但需要掌握熬糖火候，适合稍有基础的初学者尝试，全程大约 20 分钟即可完成。', '[{"name":"荔浦芋头","quantity":200,"unit":"克"},{"name":"白砂糖或冰糖","quantity":30,"unit":"克"},{"name":"水","quantity":15,"unit":"克"},{"name":"葱","note":"适量"}]'::jsonb, '["芋头切长条（稍微大条一点，翻炒过程不容易烂）","加入可以没过芋头的油，等油温起来（插入筷子冒小泡即可）","放进芋头到油里，去炸到芋头浮起来，一般是微微泛黄并且可以用筷子很轻松戳洞","炸芋头的油放起来别浪费，后面炒菜啥的都能用","接下来关键的一步，把糖(30g)和水(15g)按照 2：1 比例，加热至不变色且冒小泡","倒入葱花和芋头，关火翻炒，此时等温度下来，糖就会有反沙的效果","装盘上桌！"]'::jsonb, '["甜品","潮汕","油炸","甜香","下午茶","点心"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_dessert_68448a8d44.jpg', 'https://www.bilibili.com/video/BV1f6xveXEhU', '{"energyKcal":430,"protein":3,"carbs":82,"fat":10}'::jsonb, null),
  ('howtocook:dessert/咖啡椰奶冻/咖啡椰奶冻', '咖啡椰奶冻', '甜品', 4, 60, '这款甜品融合了咖啡的醇厚与椰奶的清甜，口感像布丁般细腻滑嫩，层次丰富。淡奶油和椰汁提供了优质脂肪与植物营养，食用能带来满足感。做法非常友好，只需混合加热，无需复杂技巧，新手也能一次成功。不算冷藏的话，实际操作约需 1 小时，加上冷藏定型共 大约 4 小时即可享用。', '[{"name":"淡奶油","quantity":125,"unit":"ml"},{"name":"椰树牌椰汁","quantity":250,"unit":"ml"},{"name":"espresso 意式浓缩","quantity":35,"unit":"ml"},{"name":"椰子水","quantity":50,"unit":"ml"},{"name":"吉利丁","quantity":10,"unit":"克"},{"name":"糖","note":"适量"},{"name":"蓝莓","note":"适量"},{"name":"咖啡粉","note":"适量"}]'::jsonb, '["将定量淡奶油，椰树牌椰汁，espresso，椰子水混合备用。","将以上液体加热 1 分钟，温度达到 50-60 度即可。","（可选）如果格外嗜甜可以加额外的糖。","倒入吉利丁，搅拌至融化，煮 1 分钟。","（可选）过筛 （这一步可以让椰奶冻口感更佳顺畅）。","放入模具。","（可选）过滤掉表层的泡泡。这一步可以让椰奶冻口感更好，并且看着也会更棒。","放入冰箱冷藏区，等待 3 小时。"]'::jsonb, '["甜品","咖啡香","椰香","免烤","布丁口感","下午茶"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_dessert_48d7c2ae2c.png', 'https://www.bilibili.com/video/BV1UmKBzxE9X', null, null),
  ('howtocook:dessert/奥利奥冰淇淋/奥利奥冰淇淋', '奥利奥冰淇淋', '甜品', 3, 30, '奥利奥冰淇淋口感细腻，奶香与奥利奥的酥脆甜蜜相融，纯动物奶油令整体轻盈不腻。它主要提供能量，含有脂肪和碳水化合物，适合作为消暑小甜点。制作过程较为简单，只需处理饼干夹心和搅打奶油，新手稍加耐心也可完成，全程准备约需半小时，再冷冻 4 小时以上即可享用。', '[{"name":"淡奶油（推荐品牌 安佳动物淡奶油）","quantity":250,"unit":"毫升"},{"name":"原味奥利奥","quantity":6,"unit":"块"},{"name":"白砂糖","quantity":18,"unit":"克"}]'::jsonb, '["将奥利奥拧开后去除利利（夹心），备用","用筷子将奥奥剁碎，需要有一半奥奥变成粉状，另一半的奥奥最大长度小于 0.5 厘米，备用（某宝可搜“奥利奥饼干碎”，节省时间精力^-^）","将奶油全部倒置于深容器中，并加入准备好的糖","开始用电动打蛋器高速挡 搅打至 电动打蛋器提起后下方会出现悬挂住的奶油（ 0.5 厘米 - 1 厘米），而不是全部像液体一样滴下（部分滴下是正常现象）。","搅打完成后将奥奥放入奶油中，搅拌均匀直至底部有奥奥。","可选：将混合物倒入冰淇淋模具中","放置冰箱冷冻室（ -18 度） 4 小时以上可取出"]'::jsonb, '["甜品","奶香","香甜","冷冻","快手","下午茶"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_dessert_5c9a21e317.jpg', 'https://www.bilibili.com/video/BV1NB4y1U7H9', null, null),
  ('howtocook:dessert/戚风蛋糕/戚风蛋糕', '戚风蛋糕', '甜品', 5, 120, '这道烘焙入门甜品口感细腻绵软，拥有云朵般的轻盈质地，属于西点中的经典基础款。主要原料鸡蛋和牛奶提供了优质蛋白与钙质，营养丰富。制作过程对打发、翻拌及烘烤火候要求较高，具有一定挑战，但只要耐心按步骤操作，新手也能成功。从准备到出炉一般需要 1.5 至 2 小时。', '[{"name":"鸡蛋","quantity":3,"unit":"个"},{"name":"白糖","quantity":50,"unit":"克"},{"name":"牛奶（或水）","quantity":30,"unit":"克"},{"name":"食用油（或黄油）","quantity":25,"unit":"克"},{"name":"低筋面粉","quantity":50,"unit":"克"},{"name":"柠檬汁或白醋（可选）","note":"适量"}]'::jsonb, '["从冰箱中取出新鲜的鸡蛋","准备两个容器并擦干，分别盛放蛋清与蛋黄","对盛放蛋清的容器，可稍有水珠，但不能有任何油；盛放蛋黄的容器不能有水珠","打蛋，手工或利用分蛋器，将蛋清与蛋黄分离到两个容器中。","分离过程中蛋黄不能破碎，蛋清中不能混有任何蛋黄，否则会严重影响打发。（白色系带可进入蛋清，不影响）","（注意，不使用厨房机的情况下，盛放蛋清的容器也是打蛋的容器，为避免溢出，加入全部蛋清后不要超过容器的 1/8）","准备一个新的空碗，加入配方中全部的食用油和全部的牛奶","用打蛋器手动快速搅拌，直到油水完全融合，呈现乳白色悬浊液状态（完成乳化）","将配方中全部的低筋面粉过筛，加入上述乳化液中。用刮刀以”Z 字形”划拌至没有明显干粉即可（此时面糊可能会有些粗糙，属于正常现象）","将分离好的全部蛋黄加入碗中，继续用刮刀”Z 字形”划拌","此时面糊会变得非常细腻顺滑，且不易产生面筋。将其静置备用","准备好剩余 3/4 的白糖。分为三份，每份为总量的 1/4","蛋清中加入柠檬汁或白醋（可选）","打蛋器中速，打发蛋白至有粗大气泡的状态，加入第一份白糖","打蛋器高速，打发蛋白至气泡较细腻的状态，加入第二份白糖","打蛋器高速，打发蛋白至”湿性发泡”的状态，加入第三份白糖","打蛋器中低速，打发蛋白至”干性发泡”的状态","此时蛋白打发程度已符合要求","关于蛋白状态的判断可参考附件链接中的图片。）","打蛋器应尽量贴近容器底部，防止出现上面浮着的表层打发，底部仍然是液体的情况）","简单搅拌几下蛋黄液","用刮刀取 1/3 的蛋白霜，加入到蛋黄糊中","采用“翻拌”的手法，此手法是为了避免消泡","翻拌手法是","先用右手拿刮刀从搅拌盆中心插入面糊底部","向 8 点钟方向刮去直到碰到盆壁，顺势舀起面糊提到空中，然后再移回盆中心将面糊放入盆内","左手握住搅拌盆从 9 点钟方向转到 7 点钟方向，刚好旋转了 60 度，就完成了一次循环","速度大约是 1 秒钟两下","此方法出自《小岛老师的蛋糕教室》。用接地气的话说就是，像炒菜一样翻炒。","将 1/3 的蛋白霜与蛋黄液的混合液倒入剩余 2/3 的蛋白霜中，继续翻拌均匀","将蛋糕糊倒入模具，震荡几下避免大气泡","烘烤总时间：6 寸蛋糕 30-35 分钟，8 寸蛋糕 50 分钟。根据自己烤箱特性灵活调整，一般不超过 $\\pm 5$ 分钟。（最后几分钟时可在烤箱前观察）","以上管 150 摄氏度，下管 160 摄氏度预热烘烤，约 10 分钟可到达预定温度。","预热完成后，将模具放入烤箱下层","选择变温烘烤，分为两个阶段。","第一阶段烤箱设定温度为：上管 150 摄氏度，下管 160 摄氏度；","烘烤总时长的前 3/5 为第一阶段烘烤","第二阶段温度为：上管 160 摄氏度，下管 170 摄氏度；","烘烤总时长的后 2/5 为第二阶段烘烤。直接调整烤箱温度即可切换。","烤好后，出炉","此操作可能会烫手，注意用毛巾辅助","预热：空气炸锅设置 130°C 预热 5 分钟","入锅与遮盖：将装有蛋糕糊的模具放入炸锅。立刻在模具上方盖上一层锡纸（亮面朝上，哑光面接触食物），锡纸边缘捏紧，防止被热风吹开","第一阶段烘烤：设置 130°C，烘烤 35 分钟","第二阶段上色：打开炸锅，撤掉锡纸。将温度调高至 150°C，继续烘烤 10–15 分钟","判断熟透：蛋糕顶部膨胀且上色呈金黄色即可出锅。用牙签扎入中心，拔出后没有湿润面糊带出即代表已烤熟","出锅后的震热气与倒扣脱模操作，与烤箱版完全一致","（可选） 将模具从高处落下，震出其中的热气","模具倒扣 10 分钟，使蛋糕冷却","没有冷却的蛋糕立刻脱模会损伤蛋糕","此操作可能会烫手，注意用毛巾辅助","脱模，食用"]'::jsonb, '["甜品","香甜","烘焙","西点","下午茶","经典"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_dessert_207a1e71f7.jpg', 'https://www.bilibili.com/video/BV1bY4y1B7Tm', null, null),
  ('howtocook:dessert/提拉米苏/提拉米苏', '提拉米苏', '甜品', 4, 30, '这道意大利传统甜品无需烤箱，奶酪糊绵密轻盈，浸润咖啡液的手指饼干香醇柔软，属于入门级甜点。富含蛋白质和钙质，但糖分与热量较高，宜偶尔享用。操作简便，对烘焙新手十分友好，只需大约半 小时动手，再冷藏四小时即可成型品尝。', '[{"name":"马斯卡彭芝士","quantity":450,"unit":"克"},{"name":"手指饼干","quantity":1,"unit":"包"},{"name":"放凉浓缩咖啡","quantity":350,"unit":"ml"},{"name":"无菌鸡蛋","quantity":4,"unit":"个"},{"name":"白砂糖","quantity":50,"unit":"克"},{"name":"可可粉","quantity":10,"unit":"克"},{"name":"朗姆酒","quantity":35,"unit":"ml"}]'::jsonb, '["分离蛋黄蛋清","盛有蛋白的碗中加 10g 白砂糖湿性打发","盛有蛋黄的碗中将 40g 白砂糖分三次加入，搅拌至均匀","蛋黄中分三次加入马斯卡彭芝士，搅拌至均匀","蛋黄中最后加入朗姆酒，搅拌均匀","将打发好的蛋白分三次加入蛋黄芝士液中","手指饼干两面浸湿咖啡液，平铺入容器","两层芝士液两层饼干交替放入容器（这一步按照大家意愿及容器高度酌情处理）","放入冰箱冷藏四个小时（心急的小伙伴可以提早拿出来）","取出后在表面筛上可可粉，即可享用啦"]'::jsonb, '["甜品","免烤","意式","香甜","下午茶","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_dessert_c2c1beaea9.jpg', 'https://www.bilibili.com/video/BV1es4y1C79S', '{"energyKcal":559,"protein":10.8,"carbs":37.3,"fat":37.7}'::jsonb, '[null,null,null,null,null,null,null,null,14400,null]'::jsonb),
  ('howtocook:dessert/无厨师机蜂蜜面包/无厨师机蜂蜜面包', '无厨师机蜂蜜面包', '甜品', 5, 180, '这是一款无需厨师机的家常蜂蜜小面包，松软香甜，底部略带脆感，表面刷满蜂蜜水再撒上芝麻，透着朴实的甜香。主要用料为高筋面粉、牛奶、鸡蛋和黄油，提供充足的碳水化合物、蛋白质和钙质，作为早餐或加餐都很安心。做法简单，全程手揉，发酵时间灵活，甚至可以提前一晚放入冰箱冷藏，第二天再烘烤，对新手相当友好。制作耗时大约 3 小时，其中大部分是发面等待时间，实际动手并不费力。', '[{"name":"高筋面粉","quantity":400,"unit":"克"},{"name":"牛奶","quantity":200,"unit":"克"},{"name":"酵母","quantity":4,"unit":"克"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"白砂糖","quantity":70,"unit":"克"},{"name":"盐","quantity":2,"unit":"克"},{"name":"黄油","quantity":30,"unit":"克"},{"name":"蜂蜜","quantity":20,"unit":"克"},{"name":"水","quantity":20,"unit":"克"},{"name":"花生油","note":"适量"},{"name":"芝麻","note":"适量"}]'::jsonb, '["制作面团：将面粉，牛奶（建议加热到 40°，本人使用微波炉 15 - 20s），酵母，鸡蛋，面粉，糖和盐混合起来。","搅拌面团，将原料混合均匀成团。","加入黄油混合。","继续搅拌 + 手揉，均匀混合。","开始发面，使用保鲜膜覆盖容器，普通气温(10 - 20°)放置 1 - 2 小时，稍长时间对效果影响不大。","明显看到面团发酵变大（2 倍）即可开始切分面团, 此时面团应该不再十分黏手。","切分面团：理想状态每一份 60g（美观），可根据喜好适当调整大小。","将每一份小面团使用擀面杖擀成舌状后卷起, 再次醒面 10。","再次使用擀面杖擀成舌状后卷起, 从中间切开（一个变成两个）。","再次使用擀面杖擀成舌状后卷起, 从中间切开（两个变成四个）。（此步骤可以按照自己的时间多擀/卷几次, 把握一份的大小就行）","烤盘放入油纸并倒入花生油, （每份卷好的）底部蘸水 + 面粉后放入烤盘。","再次醒发（盖上保鲜膜）, 这一步可以放入冰箱, 第二天再烤。","刷上蛋液。","烤箱 180°(355°F), 18 - 20 分钟。","出炉后, 刷上蜂蜜水, 撒上芝麻。"]'::jsonb, '["甜品","香甜","烘焙","早餐","手揉","新手友好"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_dessert_1004bcf301.jpg', 'https://www.bilibili.com/video/BV1SY411J7GU', '{"energyKcal":195,"protein":5,"carbs":30,"fat":4}'::jsonb, null),
  ('howtocook:dessert/炸鲜奶/炸鲜奶', '炸鲜奶', '甜品', 3, 80, '炸鲜奶是一道外酥里嫩、香甜可口的经典甜点，属于家常小吃。富含蛋白质和钙质，营养较均衡。制作难度中等，新手也能上手，预计操作时长约 20 分钟，但需要提前 1 小时冷藏定型。', '[{"name":"牛奶","quantity":250,"unit":"克"},{"name":"玉米淀粉","quantity":30,"unit":"克"},{"name":"面包糠","quantity":100,"unit":"克"},{"name":"鸡蛋","quantity":2,"unit":"个"},{"name":"白糖","quantity":30,"unit":"克"}]'::jsonb, '["将牛奶倒入碗中","加入玉米淀粉和白糖，搅拌均匀","将模具刷上食用油","牛奶下锅，中火烧开","烧开后转小火，边煮边搅拌","牛奶变粘稠后出锅，倒入模具","将模具放冰箱冷却 1 小时","拿出，切成大小均匀的条，随后放入碗中","向碗中倒入一半的面包糠，奶糊裹上后取出，备用","在一个新碗中打入鸡蛋，搅匀，备用","将奶糊裹上蛋液和剩余的面包糠","锅中倒入足以覆盖奶糊的油，下锅","奶糊外观呈金黄状态后停火，摆盘"]'::jsonb, '["甜品","香甜","油炸","外酥里嫩","家常甜点","下午茶"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_dessert_a8547deb4c.jpg', 'https://www.bilibili.com/video/BV13P4y197Aq', '{"energyKcal":1380,"protein":35,"carbs":142,"fat":75}'::jsonb, '[null,null,null,null,null,null,3600,null,null,null,null,null,null]'::jsonb),
  ('howtocook:dessert/烤箱版巴斯克芝士蛋糕/烤箱版巴斯克芝士蛋糕', '烤箱版巴斯克芝士蛋糕', '甜品', 2, 30, '巴斯克芝士蛋糕是一道口感浓郁绵密、表面焦香内部湿润的甜品，属于西班牙巴斯克地区的经典风味。主要原料为奶油奶酪和鸡蛋，富含优质蛋白质和钙质。制作过程非常简单，新手也能轻松驾驭。从准备到出炉仅需约 30 分钟，但建议冷藏过夜后食用，总耗时约 8 小时以上。', '[{"name":"奶油奶酪","quantity":212,"unit":"克"},{"name":"白砂糖","quantity":60,"unit":"克"},{"name":"鸡蛋","quantity":2,"unit":"个"},{"name":"鸡蛋黄","quantity":1,"unit":"个"},{"name":"淡奶油","quantity":120,"unit":"克"},{"name":"低筋面粉","quantity":10,"unit":"克"}]'::jsonb, '["奶油奶酪软化，微波炉 10s + 10s。","奶油奶酪加入白砂糖，打蛋器打至顺滑。","加入 2 个全蛋 + 1 个蛋黄，搅拌均匀。","加入淡奶油，搅拌均匀。","加入低筋面粉，搅拌均匀。","烤箱 220°(425°F)，20 - 25 分钟（本人一般 20 或者 22 分钟）。","放凉之后放入冰箱，最好过夜。"]'::jsonb, '["甜品","香甜","烘烤","西式","快手","下午茶"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_dessert_c25f6f7e7d.jpg', 'https://www.bilibili.com/video/BV1h64y1f7jz', '{"energyKcal":269,"protein":5.3,"carbs":14,"fat":21.7}'::jsonb, '[20,null,null,null,null,1200,null]'::jsonb),
  ('howtocook:dessert/烤蛋挞/烤蛋挞', '烤蛋挞', '甜品', 4, 60, '烤蛋挞是一款经典的中式甜品，外皮酥脆、内馅嫩滑，奶香浓郁。富含蛋白质、钙质和多种维生素，能提供丰富能量。制作过程十分简单，新手也能轻松上手，而且半成品可冷冻保存，随吃随取。从准备到出炉，大约需要 1 小时。', '[{"name":"蛋挞皮","quantity":30,"unit":"只"},{"name":"鸡蛋","quantity":8,"unit":"个"},{"name":"牛奶","quantity":200,"unit":"毫升"},{"name":"淡奶油","quantity":450,"unit":"毫升"},{"name":"白砂糖","quantity":80,"quantityMax":100,"unit":"克"}]'::jsonb, '["将碗置于克数称上 称量 450 克 淡奶油（淡奶油密度在此处记为 1 ）","加入 80 克白砂糖 （甜度中等 可按个人口味增减 建议范围 60-100 克）","加入 200 克牛奶 （牛奶密度在此处记为 1 ）","取 8 个蛋黄加入 蛋清可留作他用","均匀搅拌所有材料直至白砂糖全部融化","使用网筛对搅拌完成的食材进行过滤 滤除鸡蛋黏膜 鸡蛋壳 未融化的白砂糖 结块的淡奶油","此时请将烤箱设置 220 摄氏度开始预热（约 10 分钟） 记得拿出烤盘","将蛋挞皮以 0.5 厘米的间隔均匀放置于烤盘中","将过滤完成的食材倒入蛋挞皮中 液面距离蛋挞皮上沿 0.5 厘米即可不宜过多","截止此步骤 半成品蛋挞的制作已经完成 可直接放入冰箱速冻 12 小时以上保存","将半成品蛋挞放入烤箱中进行烤制 温度为 200 摄氏度 时间为 25 分钟","烤制结束后即可食用"]'::jsonb, '["甜品","奶香","烘焙","新手","家常","冷冻保存","下午茶"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_dessert_45ccd66201.png', 'https://www.bilibili.com/video/BV1JU4y1a7H1', '{"energyKcal":160,"protein":2,"carbs":11,"fat":12}'::jsonb, '[null,null,null,null,null,null,600,null,null,43200,1500,null]'::jsonb),
  ('howtocook:dessert/玛格丽特饼干/玛格丽特饼干', '玛格丽特饼干', '甜品', 3, 45, '玛格丽特饼干口感酥松，黄油香气浓郁，是一款经典的西式小甜点。它主要由蛋黄、黄油和面粉制成，含有丰富的碳水化合物与脂肪，能快速补充能量。制作难度适中，从准备到出炉大约需要 45 分钟，新手也能轻松上手。', '[{"name":"熟蛋黄","quantity":1,"unit":"个"},{"name":"黄油","quantity":50,"unit":"克"},{"name":"白砂糖","quantity":20,"unit":"克"},{"name":"盐","quantity":1,"unit":"克"},{"name":"低筋面粉","quantity":50,"unit":"克"},{"name":"玉米淀粉","quantity":50,"unit":"克"}]'::jsonb, '["黄油隔热水融化、将蛋黄磨碎备用。","在融化的黄油中添加糖、盐、以及碾碎的鸡蛋黄，搅拌均匀","加入低筋面粉与玉米淀粉，揉成面团","将面团均匀分割成大约 8 克重的小面团，然后将它们搓成球状。","使用大拇指轻压在每个小面团上，以形成裂纹。","预热烤箱至 150℃，将小面团放入烤箱中，烘烤 20 分钟。","微微放凉即可食用"]'::jsonb, '["甜品","酥松","奶香","烘焙","西式甜点","下午茶"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_dessert_2dd6e18870.jpg', 'https://www.bilibili.com/video/BV17g4y1a7GD', '{"energyKcal":36,"protein":0.3,"carbs":4.3,"fat":1.9}'::jsonb, '[null,null,null,null,null,1200,null]'::jsonb),
  ('howtocook:dessert/红柚蛋糕/红柚蛋糕', '红柚蛋糕', '甜品', 3, 35, '红柚蛋糕是一道用空气炸锅就能轻松完成的清新甜点，融合了红柚果粒的微酸果香与蛋糕的松软口感，适合作为单人份下午茶。鸡蛋和面粉提供蛋白质与碳水，红柚富含维生素 C，带来简单的基础营养。制作难度中等，关键在于分次搅拌成无颗粒的淡黄色面糊，新手只要耐心按步骤操作就能成功。从备料到出锅大约需要 35 分钟，想吃现烤甜点时不会占用太多时间。', '[{"name":"鸡蛋","quantity":2,"unit":"个"},{"name":"红柚果肉","quantity":20,"unit":"克"},{"name":"面粉","quantity":80,"unit":"克"},{"name":"油","quantity":15,"unit":"ml"},{"name":"糖","quantity":15,"unit":"克"},{"name":"水","quantity":80,"unit":"ml"}]'::jsonb, '["锡纸盘里打入鸡蛋 2 个， 加入红柚果肉 20g","锡纸盘中倒入 15ml 油并摇晃锡纸盘时期均匀覆盖盘底","锡纸盘中放入 10g 糖， 以及 40g 面粉和 40ml 水","用筷子顺时针方向搅拌至淡黄色糊状","锡纸盘中放入 5g 糖， 以及 40g 面粉和 40ml 水","继续用筷子搅拌至淡黄色糊状","锡纸盘放入空气炸锅的烤篮上，用 180 摄氏度烤 15 分钟","打开空气炸锅，小心取出锡纸盘，用筷子或勺子将蛋糕翻面","继续 180 摄氏度烤 8 分钟","取出即可食用"]'::jsonb, '["甜品","酸甜","烘焙","空气炸锅","快手","下午茶"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_dessert_7ccfc8fe4d.jpg', 'https://www.bilibili.com/video/BV1D26FBpE2Z', '{"energyKcal":620,"protein":22,"carbs":74,"fat":26}'::jsonb, null),
  ('howtocook:dessert/胡萝卜甜糕', '胡萝卜甜糕', '甜品', 3, 45, '胡萝卜甜糕是印度家喻户晓的冬季甜品，胡萝卜丝与牛奶慢炖浓缩，融入酥油和坚果，口感绵密香甜、色泽金红。富含胡萝卜素、钙质和优质脂肪，暖身滋养。制作过程简单，但对新手需要些耐心，全程约需 45 分钟即可完成。', '[{"name":"胡萝卜","quantity":500,"unit":"克"},{"name":"全脂牛奶","quantity":500,"unit":"ml"},{"name":"糖","quantity":80,"unit":"克"},{"name":"酥油","quantity":40,"unit":"克"},{"name":"小豆蔻粉","quantity":3,"unit":"克"},{"name":"腰果","quantity":15,"unit":"克"},{"name":"杏仁","quantity":15,"unit":"克"},{"name":"葡萄干","quantity":15,"unit":"克"}]'::jsonb, '["将胡萝卜去皮，用刨丝器刨成细丝","在厚底锅中倒入酥油 20g（一半量），中火加热融化","放入胡萝卜丝，翻炒 3-5 分钟，直至胡萝卜丝变软且散发香味","倒入全脂牛奶 500ml，搅拌均匀","大火煮沸后转中小火，保持缓慢沸腾状态","持续翻搅 25-30 分钟，直至牛奶几乎完全被胡萝卜吸收蒸发（这是最关键的步骤，需要耐心且不断搅拌防止糊底）","当锅中几乎没有液体时，加入糖 80g，搅拌均匀","加糖后会重新出水，继续中小火翻炒 5-8 分钟，直至水分再次蒸发","加入剩余的酥油 20g 和小豆蔻粉 3g，翻炒 2 分钟","在另一个小锅中，用少量酥油将腰果、杏仁片和葡萄干分别炸至金黄（约 1 分钟），注意葡萄干会膨胀","将炸好的坚果和葡萄干的一半拌入胡萝卜甜糕中","盛盘，将剩余坚果和葡萄干撒在表面作为装饰"]'::jsonb, '["甜品","印度风味","香甜","慢炖","暖身","滋补"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_dessert_44ec3ddcb1.jpg', 'https://www.bilibili.com/video/BV17wYVzNEj9', null, null),
  ('howtocook:dessert/芋泥雪媚娘/芋泥雪媚娘', '芋泥雪媚娘', '甜品', 5, 120, '芋泥雪媚娘外皮软糯 Q 弹，内馅是细腻香甜的芋泥与轻盈奶油，口感层次丰富，是一道源自家常创意的中式甜品。芋头和紫薯提供膳食纤维与花青素，牛奶和淡奶油补充钙质，营养均衡。制作无需烤箱，步骤简单，对新手很友好，即使不擅烘焙也能轻松完成。从头到尾大约需要两小时，就能做出让孩子爱不释口的自制小点心。', '[{"name":"荔浦芋头","quantity":200,"unit":"克"},{"name":"紫薯粉","quantity":3,"unit":"克"},{"name":"牛奶","quantity":165,"unit":"克"},{"name":"糯米粉","quantity":50,"unit":"克"},{"name":"糯米粉","quantity":75,"unit":"克"},{"name":"玉米淀粉","quantity":22,"unit":"克"},{"name":"黄油","quantity":30,"unit":"克"},{"name":"淡奶油","quantity":145,"unit":"克"},{"name":"白砂糖","quantity":26,"unit":"克"}]'::jsonb, '["芋头切块，大火煮熟至软（40 分钟即可），全部放入料理机","向内加入 30g 牛奶，25g 淡奶油，将其打成泥状","再向内加入 3g 紫薯粉，18g 白砂糖，继续搅拌打成细腻芋泥","取出另一个碗，加入全部糯米粉 b，22g 玉米淀粉，135g 牛奶，50g 白砂糖，混匀并过筛一遍，保鲜膜盖上并扎小洞，中火蒸半个小时","在蒸的过程中，将糯米粉 a 放入平底锅小火翻炒至微微发黄（即炒熟），作为手粉备用","将中火蒸完半小时的糯米牛奶混合物（果冻状）趁热加入黄油 30g，将黄油揉至面团完全吸收，然后放冰箱冷藏一小时","取出另一只碗，加入 120g 淡奶油，8g 白砂糖，打发至有纹路，装进裱花袋备用","取出冷藏后的面团，搓揉 5 分钟，分成 30g 一个，均匀撒上 2g 手粉防粘，擀成圆形，先挤上 5g 裱花奶油，然后放上 30g 芋泥，最后将面饼像包包子一样包起来（可以减去多余的皮）","包好后再均匀撒 2g 手粉防粘","重复以上两步直至原材料用光"]'::jsonb, '["甜品","香甜","软糯","蒸制","免烤","下午茶"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_dessert_00eb2ca6b8.jpg', 'https://www.bilibili.com/video/BV1hk4y1u7cG', null, '[2400,null,null,1800,null,3600,null,300,null,null]'::jsonb),
  ('howtocook:dessert/英式司康/英式司康', '英式司康', '甜品', 3, 60, '英式司康是一款经典英式下午茶点心，外酥内软，蛋奶香气浓郁，搭配果酱或奶油食用风味更佳。它主要由面粉、黄油、鸡蛋和淡奶油制成，富含碳水化合物和蛋白质，能快速补充能量。制作过程较为简单，只要掌握基本揉面手法，新手也能胜任，从准备到出炉大约需要一小时。', '[{"name":"无盐黄油","quantity":40,"unit":"克"},{"name":"低筋面粉","quantity":180,"unit":"克"},{"name":"糖","quantity":30,"unit":"克"},{"name":"盐","quantity":1,"unit":"克"},{"name":"泡打粉","quantity":5,"unit":"克"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"淡奶油","quantity":45,"unit":"克"},{"name":"奶油奶酪","quantity":50,"unit":"克"}]'::jsonb, '["鸡蛋打散，称量出 30g 蛋液放入干净容器中，放入全量淡奶油和奶油奶酪混合均匀。如果奶酪太硬可以水浴加热至大约 40 度再混合。","将低筋面粉，盐，糖，泡打粉放入干净容器中混合均匀","黄油切成小块，放入上一步的混合物中，用手将黄油捏入混合物中，呈粗玉米粉质地","将第一步的蛋奶混合液倒入上一步得到的粉油混合物种，搅拌均接近。叠压成均匀面团","面团放到案板上，擀成 1.5cm 厚的面片，用刀或者模具分切成合适的形状","用刷子蘸取剩余的 20g 鸡蛋液，刷在司康表面","烤箱预热 180 度，烤制 27 分钟"]'::jsonb, '["甜品","香甜","烘焙","英式","下午茶","点心"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_dessert_dcef953f0c.png', 'https://www.bilibili.com/video/BV12K4y1N7B4', '{"energyKcal":190,"protein":5,"carbs":22,"fat":9}'::jsonb, '[null,null,null,null,null,null,1620]'::jsonb),
  ('howtocook:dessert/草莓冰淇淋/草莓冰淇淋', '草莓冰淇淋', '甜品', 2, 480, '这是一道不需要搅拌机就能轻松制作的家常草莓冰淇淋，果香浓郁、口感绵密。草莓富含维生素 C，搭配奶香四溢的炼乳和奶油，能提供能量和钙质。做法简单不考验厨艺，新手也能一次成功。全程制作耗时约八小时，其中大部分是冷冻时间，实际动手只需短短几十分钟。', '[{"name":"草莓","quantity":500,"unit":"克"},{"name":"白砂糖","quantity":45,"unit":"克"},{"name":"香草精","quantity":1,"unit":"克"},{"name":"食盐","quantity":1,"unit":"克"},{"name":"香草精","quantity":5,"unit":"克"},{"name":"重奶油","quantity":6,"unit":"克"},{"name":"食盐","quantity":1,"unit":"克"},{"name":"加糖炼乳","quantity":400,"unit":"克"}]'::jsonb, '["先做草莓糖浆。把草莓洗干净，去掉顶部叶子。将草莓切成 5mm 的小块。保留一半切碎的草莓，稍后折叠成冰淇淋。","将另一半切碎的草莓和糖一起放入酱汁锅中。用中火搅拌和烹饪，直到草莓释放液体并在锅中形成糖浆。","让草莓在糖浆中加热，不时搅拌，直到它们分解并变形，糖浆稍微变稠。","当糖浆保持分开 3秒钟 时，就已经准备好了。把糖浆从火上移开，加入香草和盐搅拌。将草莓糖浆放在一边冷却。","当糖浆冷却时，准备冰淇淋基料。在碗中加入甜炼乳、浓奶油、香草精和盐。使用手动搅拌器搅打混合物，直到它变得轻盈蓬松，并形成柔软的尖峰。","将保留的切碎的新鲜草莓折叠到冰淇淋底座中。将生过的冰淇淋底座转移到冷冻安全容器中。将冷却的草莓糖浆淋在冰淇淋上，然后轻轻地将其旋入混合物中。","盖上冰淇淋并冷冻 八小时 ，然后舀取和食用。"]'::jsonb, '["甜品","香甜","免烤","快手","家常","夏日"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_dessert_88d061b568.jpg', 'https://www.bilibili.com/video/BV1VS4y1b7eu', '{"energyKcal":260,"protein":4,"carbs":32,"fat":13}'::jsonb, '[null,null,null,3,null,null,28800]'::jsonb),
  ('howtocook:dessert/酸奶意式奶冻/酸奶意式奶冻', '酸奶意式奶冻', '甜品', 4, 300, '一道改良自意大利经典的甜品，融入原味酸奶后口感更为清爽顺滑，甜而不腻，适合作为餐后小点搭配水果或果酱。奶制品带来丰富的钙质和蛋白质，营养温和。制作步骤简单，只需加热搅拌和冷藏定型，新手也能顺利上手，从准备到冷藏完成大约需要 5 小时。', '[{"name":"淡奶油","quantity":200,"unit":"g"},{"name":"糖","quantity":40,"unit":"g"},{"name":"原味酸奶","quantity":250,"unit":"g"},{"name":"吉利丁片","quantity":6,"unit":"g"}]'::jsonb, '["吉利丁片剪成小片，泡入冷水中","淡奶油和糖放入锅中，加热至 60 度","关火，吉利丁从水中取出，控干水份，加入热淡奶油中，搅拌均匀","淡奶油降温至 40 度，加入原味酸奶，搅拌均匀","将上述步骤得到的混合物过两遍筛网","分装入合适的容器，放入冰箱冷藏 4 小时以上"]'::jsonb, '["甜品","酸甜","意式","免烤","快手","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_dessert_0e6edd30be.png', 'https://www.bilibili.com/video/BV1ah4y1j74o', '{"energyKcal":260,"protein":5.8,"carbs":14.4,"fat":19.3}'::jsonb, '[null,null,null,null,null,14400]'::jsonb),
  ('howtocook:dessert/雪花酥/雪花酥', '雪花酥', '甜品', 3, 30, '雪花酥是一道口感酥脆香甜、奶香浓郁的小甜点，属于简单快手的家常烘焙，也很适合装盒送礼。由于含有黄油、奶粉和混合坚果，能提供丰富的能量和蛋白质，不过热量较高，适合偶尔享用。制作难度适中，对新手有一定挑战，但只要注意火候和搅拌手法，一般只需 30 分钟就能完成。', '[{"name":"无盐黄油","quantity":20,"unit":"克"},{"name":"棉花糖","quantity":75,"unit":"克"},{"name":"全脂奶粉","quantity":40,"unit":"克"},{"name":"混合坚果","quantity":60,"unit":"克"},{"name":"饼干","quantity":75,"unit":"克"}]'::jsonb, '["饼干超过一元硬币大小先切成小块","无盐黄油加入锅中，小火加热至无盐黄油完全融化","棉花糖加入锅中，使用刮刀搅拌，直至棉花糖融化并与无盐黄油均匀融合","20g 奶粉加入锅中，使用刮刀搅拌，奶粉与黄油棉花糖混合物搅拌均匀后立即关火","准备好的所有混合坚果与饼干趁热加入锅中，使用刮刀搅拌","搅拌到温度下降到手可以接触的温度后，戴上一次塑料手套，在锅中搓揉或者双手拿起拉扯，让饼干混合坚果与棉花糖黄油奶粉混合物分散均匀。","将上述步骤混合物压入模具中，边角压实，擀面杖擀平，未满的一边用手尽量压成直边","室温放凉，完全冷却后脱模，按照模具纹路切块，或切成自己喜欢的大小，撒上剩余奶粉，尽量使雪花酥每面都沾上奶粉"]'::jsonb, '["甜品","奶香浓郁","酥脆香甜","快手","烘焙甜点","家常","送礼"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_dessert_06d2f114b6.jpg', 'https://www.bilibili.com/video/BV1ah411x7hx', '{"energyKcal":1300,"protein":25,"carbs":135,"fat":68}'::jsonb, null),
  ('howtocook:dessert/魔芋蛋糕/魔芋蛋糕', '魔芋蛋糕', '甜品', 4, 45, '魔芋蛋糕是一款低热量、无麸质的甜点，用赤藓糖醇代替白砂糖，口感轻盈湿润，带有可可香气，尤其适合减脂人群。它富含膳食纤维和蛋白质，饱腹感强。制作有一定难度，需要打发蛋白并注意翻拌手法，但整体耗时仅约半小时，算是快手健康的烘焙选择。', '[{"name":"鸡蛋","quantity":3,"unit":"个"},{"name":"赤藓糖醇","quantity":50,"unit":"克"},{"name":"可可粉","quantity":10,"unit":"克"},{"name":"魔芋粉","quantity":10,"unit":"克"},{"name":"塔塔粉","quantity":1,"unit":"克"}]'::jsonb, '["在准备蛋糕糊之前，可以开始预热烤箱至 350 ℉( 150 ℃)以节省时间","从冰箱中取出新鲜的鸡蛋","准备两个容器并擦干，分别盛放蛋清与蛋黄","对盛放蛋清的容器，可稍有水珠，但不能有任何油；盛放蛋黄的容器不能有水珠","打蛋，手工或利用分蛋器，将蛋清与蛋黄分离到两个容器中。","分离过程中蛋黄不能破碎，蛋清中不能混有任何蛋黄，否则会严重影响打发。（白色系带可进入蛋清，不影响）","（注意，不使用厨房机的情况下，盛放蛋清的容器也是打蛋的容器，为避免溢出，加入全部蛋清后不要超过容器的 1/8）","蛋清中加入 1g 塔塔粉","打蛋器高速，打发蛋白至粗大气泡的状态，加入 50g 赤藓糖醇","打蛋器中低速，打发蛋白至干性发泡的状态（提起打蛋器头，有短小直立的尖角；倒扣容器，蛋白可粘住容器不掉下来）","此时蛋白打发程度已符合要求","打蛋器应尽量贴近容器底部，防止出现上面浮着的表层打发，底部仍然是液体的情况）","把分离的蛋黄加入打发的蛋清中，打蛋器中低速搅拌均匀","蛋清中加入 10g 可可粉和 10g 魔芋粉，先用餐刀翻拌，这是由于如果直接用打蛋器搅拌会造成粉末飞溅","翻拌手法是","先用右手拿刮刀从搅拌盆中心插入面糊底部","向 8 点钟方向刮去直到碰到盆壁，顺势舀起面糊提到空中，然后再移回盆中心将面糊放入盆内","左手握住搅拌盆从 9 点钟方向转到 7 点钟方向，刚好旋转了 60 度，就完成了 1 次循环","速度大约是 1 秒钟 2 下","此方法出自《小岛老师的蛋糕教室》。用接地气的话说就是，像炒菜一样翻炒。","翻拌结束后，打蛋器低速搅拌均匀","模具铺好烘焙纸，贴合底部与内壁","将蛋糕糊倒入模具，然后用餐刀抹平，再然后震荡几下避免大气泡","烘烤 25 分钟","烤好后，戴好隔热手套取出","（可选） 将模具从高处落下，震出其中的热气","模具倒扣 10 分钟，使蛋糕冷却","没有冷却的蛋糕立刻脱模会损伤蛋糕","此操作可能会烫手，注意戴好隔热手套","脱模，餐刀切块食用"]'::jsonb, '["甜品","低卡","无麸质","可可味","烘焙","快手","减脂"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_dessert_8659256965.jpg', 'https://www.bilibili.com/video/BV1UT4y1m7Qc', '{"energyKcal":50,"protein":3,"carbs":10,"fat":2.5}'::jsonb, '[null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,1500,null,null,600,null,null,null]'::jsonb),
  ('howtocook:dessert/龟苓膏/龟苓膏', '龟苓膏', '甜品', 2, 130, '龟苓膏是一道广式传统甜品，口感嫩滑微苦回甘，常作为夏日消暑小食。龟苓膏能清热祛湿、滋阴养颜，是营养健康的一款点心。做法简单，新手也能轻松掌握，全程只需备料、搅拌和加热，冷藏等待约两小时后即可享用。', '[{"name":"龟苓膏粉","quantity":25,"unit":"克"},{"name":"冷水","quantity":120,"unit":"毫升"},{"name":"开水","quantity":500,"unit":"毫升"},{"name":"白砂糖","quantity":100,"unit":"克"}]'::jsonb, '["在锅中倒入龟苓膏粉 25 克与冷水 120 毫升，充分搅拌至无颗粒感。","在另一个容器中加入白砂糖 100 克，倒入沸水 500 毫升，搅拌至糖完全溶解。","将糖水缓慢倒入龟苓膏粉液中，立即搅拌均匀，避免结块。","将混合液体放入锅中，加热时保持中小火，并持续搅拌以防粘锅。","加热至液体变粘稠并开始冒小泡，即可关火。","快速将液体倒入模具中，自然冷却凝固。建议冷藏 1~2 小时后食用，口感更佳。"]'::jsonb, '["甜品","广式","消暑","嫩滑","微苦回甘","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_dessert_85f70fdf72.jpg', 'https://www.bilibili.com/video/BV1Sf4y1W7MP', '{"energyKcal":480,"protein":2,"carbs":122,"fat":0}'::jsonb, '[null,null,null,null,null,3600]'::jsonb),
  ('howtocook:drink/B52轰炸机', 'B52轰炸机', '饮品', 3, 5, '这款鸡尾酒口感层次分明，入口先是伏特加的烈，紧接着是咖啡奶油的回甘，点燃后饮用有独特的冰火体验，属于经典创意鸡尾酒。咖啡酒与百利甜酒提供了少量咖啡因和奶脂，但整体营养以酒精为主。制作需要练习分层倒酒和点火技巧，对新手稍有难度，整个过程大约只需 5 分钟。', '[{"name":"甘露咖啡酒","quantity":10,"unit":"ml"},{"name":"爱尔兰百利甜酒","quantity":10,"unit":"ml"},{"name":"蓝天原味伏特加","quantity":10,"unit":"ml"}]'::jsonb, '["在利口酒杯的最底层倒入甘露咖啡酒到 1/3 处。(10ml)","顺着吧勺缓缓倒入爱尔兰百利甜酒，也是 1/3 处 (10ml)。注意要慢，保证层次分明。（太快甜酒会和咖啡混合）","最后在上层倒入蓝天原味伏特加 （10ml)","用打火机热一下杯口","最后一步点火： 看到淡蓝色的小火苗了吗？"]'::jsonb, '["饮品","香甜","分层","点火","鸡尾酒","聚会"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_drink_B52_58e099a52f.jpg', 'https://www.bilibili.com/video/BV1sr4y1K7Ds', '{"energyKcal":95,"protein":0.3,"carbs":6,"fat":1.5}'::jsonb, null),
  ('howtocook:drink/Mojito莫吉托', 'Mojito莫吉托', '饮品', 3, 10, '这款鸡尾酒口感清爽酸甜，带有薄荷的清凉和朗姆酒的微醺，是经典的夏季饮品。酒精含量较低，佐以富含维生素 C 的青柠，能生津解渴、提神醒脑。制作十分简单，对新手友好，从备料到完成只需大约十 分钟。', '[{"name":"青柠","quantity":1,"unit":"块"},{"name":"薄荷叶","quantity":5,"unit":"株"},{"name":"糖浆","quantity":20,"unit":"ml"},{"name":"金色朗姆酒","quantity":45,"unit":"ml"},{"name":"蓝天原味伏特加","quantity":10,"unit":"ml"},{"name":"碎冰","note":"适量"},{"name":"冰镇苏打水","note":"适量"}]'::jsonb, '["将切成半块的青柠之一切成小块，放入海波杯，随后用研杵将其捣出汁；","用 3-4 珠薄荷叶沿着杯口涂抹，随后将其放入杯中；","加入 糖浆 20ml；","加入 金色朗姆酒 45ml；","将剩下的半块青柠压出汁水放入杯中；","轻轻搅拌，使砂糖/糖浆处于半融合状态；","将打碎的冰块放入杯中，直到占杯中 3/4；","加入冰镇苏打水直到刚好淹没碎冰；","旋转搅拌半分钟；","使用碎冰将海波杯补满；","将剩下的一株薄荷叶拍醒，插入碎冰，作装饰。"]'::jsonb, '["饮品","酸甜","清爽","调酒","快手","夏日"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_drink_Mojito_4f3587d083.jpg', 'https://www.bilibili.com/video/BV1jg4y187kB', null, '[null,null,null,null,null,null,null,null,30,null,null]'::jsonb),
  ('howtocook:drink/冬瓜茶', '冬瓜茶', '饮品', 2, 300, '冬瓜茶是一款清爽解暑的传统饮品，口感甘甜柔和，带有冬瓜特有的清香，冰镇后风味更佳。冬瓜本身低热量、富含水分，搭配冰糖熬制，能补充能量、生津止渴。制作不复杂，但对新手而言需要一些耐心，全程大约需要 4 到 5 小时。', '[{"name":"冬瓜","quantity":1000,"unit":"克"},{"name":"冰糖","quantity":300,"unit":"克"}]'::jsonb, '["准备冬瓜：将冬瓜去皮，去籽，切成小块（每块不超过 4cm）。","加入冰糖：冬瓜加入冰糖，搅拌均匀，盖上保鲜膜放冰箱冷藏 2 小时以上。","煮冬瓜： 此时冬瓜出了很多水, 倒入锅中 大火煮开，然后转中小火慢慢熬制 1~2 个小时，中途多搅拌防止糊锅。","过滤冬瓜茶：使用过滤网将煮好的冬瓜茶液过滤，取出冬瓜块，只保留茶液。","冷却：将冬瓜茶液放凉后，倒入干净的容器中，放入冰箱冷藏即可。","享用: 熬好的冬瓜茶液是浓缩汁，根据个人喜好添加水或其他饮品，冷热皆宜。"]'::jsonb, '["饮品","清爽","解暑","甘甜","熬制","冰镇"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_drink_bcfc951b87.jpg', 'https://www.bilibili.com/video/BV14s411n7pD', '{"energyKcal":130,"protein":0.5,"carbs":32,"fat":0}'::jsonb, '[null,7200,null,null,null,null]'::jsonb),
  ('howtocook:drink/冰粉/冰粉', '冰粉', '饮品', 2, 180, '石凉粉是河南信阳的传统小吃，口感爽滑如果冻，配以薄荷汁或柠檬汁清凉解暑，属于豫菜系。由冰粉籽手工揉搓而成，天然无添加，含有丰富的植物胶质。制作非常简单，对新手友好，全程约需 3 小时，其中 2.5 小时为静置凝固时间，几乎不占用人工。', '[{"name":"冰粉籽","quantity":200,"unit":"克"},{"name":"凉白开","quantity":2000,"unit":"克"},{"name":"薄荷汁","quantity":10,"unit":"ml"},{"name":"薄荷粉","quantity":10,"unit":"克"},{"name":"遇水发光冰块","note":"可选"}]'::jsonb, '["将凉白开倒入盆中；","将冰粉籽全部用纱布包起来，开口处打结","将包好的冰粉籽放入凉白开中，在凉白开中用力揉搓 6 分钟","然后将凉白开放置 2.5 小时，即可成型","随后将石凉粉用勺子装进准备好的一次性透明塑料杯中，加入 10ml 薄荷汁或者 10g 薄荷粉（柠檬汁、山楂汁、桑椹汁也可），再放入遇水发光冰块，用勺子慢慢搅拌均匀"]'::jsonb, '["饮品","豫菜","清凉","解暑","手工","夏日"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_drink_6f9fe0988f.jpg', 'https://www.bilibili.com/video/BV1CJ4m1u7Xm', '{"energyKcal":5,"protein":0,"carbs":1,"fat":0}'::jsonb, '[null,null,360,9000,null]'::jsonb),
  ('howtocook:drink/印度奶茶', '印度奶茶', '饮品', 2, 10, '印度奶茶是一道充满异域风情的家常饮品，以红茶、牛奶和多种香料现煮而成，口感浓郁顺滑，带有生姜、豆蔻、肉桂交织的辛香暖意。牛奶提供优质蛋白和钙质，香料则有助于暖身驱寒、促进消化。制作过程简单直观，对新手友好，从备料到入口只需大约 10 分钟。', '[{"name":"水","quantity":120,"unit":"ml"},{"name":"全脂牛奶","quantity":120,"unit":"ml"},{"name":"红茶（CTC 红茶最佳，或阿萨姆红茶）","quantity":8,"unit":"克"},{"name":"生姜","quantity":5,"unit":"克"},{"name":"小豆蔻（绿色）","quantity":2,"unit":"颗"},{"name":"肉桂棒","quantity":1,"unit":"小段"},{"name":"丁香","quantity":2,"unit":"颗"},{"name":"黑胡椒粒","quantity":2,"unit":"颗"},{"name":"糖","quantity":10,"quantityMax":15,"unit":"克"}]'::jsonb, '["将生姜拍碎（不用切太碎，拍开即可释放姜汁）","将小豆蔻用刀背拍开，露出里面的籽","将黑胡椒粒拍碎","在小奶锅中倒入 120ml 水","放入拍碎的生姜、小豆蔻、肉桂棒、丁香、黑胡椒粒","大火煮沸后转小火，煮 2 分钟，让香料的味道充分释出","加入红茶 8g，继续小火煮 2 分钟，直至茶汤颜色变深","倒入全脂牛奶 120ml","中火加热，注意观察，当奶茶开始冒泡上升时立即转小火（牛奶极易溢出）","小火煮 2-3 分钟，期间可以将锅提起倒回（反复提拉 3-4 次），使茶汤与牛奶充分融合","加入糖，搅拌溶解","关火","用滤网过滤到茶盏中，去除茶叶和香料残渣","趁热饮用"]'::jsonb, '["饮品","印度风味","辛香浓郁","煮制","快手","暖身"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_drink_c34b196519.jpg', 'https://www.bilibili.com/video/BV1PPmLYVE7e', null, null),
  ('howtocook:drink/可乐桶', '可乐桶', '饮品', 2, 5, '可乐桶是一款简单易调的休闲鸡尾酒，口感清爽甜润，可乐的气泡和柠檬汁很好地中和了威士忌的烈感，适合聚会场合。主要提供能量，柠檬补充维生素 C。整个调配过程只需 5 分钟即可完成，新手也能轻松上手。', '[{"name":"波旁威士忌","quantity":100,"unit":"毫升"},{"name":"可口可乐","quantity":500,"unit":"毫升"},{"name":"冰块","quantity":300,"unit":"克"},{"name":"柠檬","quantity":1,"unit":"个"}]'::jsonb, '["将柠檬对半切（刀方向垂直于柠檬的头尾连线），并从其中的一半中切取一片柠檬备用","再次将柠檬对半切，将得到的 4 角柠檬用压汁器压出柠檬汁置于容器中备用","将挤压过的柠檬置于容器中备用","选择一个杯子，建议使用容量在大约 1 升的大型玻璃杯或铁皮酒桶","将冰块和挤压过的柠檬入杯中（可根据个人喜好设计柠檬与冰块的摆放）","倒入 15 毫升柠檬汁（如果喜酸可以加多点或全加）","沿杯壁缓慢倒入可口可乐至距离杯口 3/4 处（控制可乐和威士忌的比例约在 5:1 ）","倒入威士忌直至满杯"]'::jsonb, '["饮品","清爽","甜润","快手","聚会","鸡尾酒"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_drink_ae9fc835ca.jpg', 'https://www.bilibili.com/video/BV1RN4y1T7SF', null, null),
  ('howtocook:drink/奇异果菠菜特调/奇异果菠菜特调', '奇异果菠菜特调', '饮品', 1, 10, '这是一道清爽健康的果蔬特饮，口感酸甜细腻，带有奇异果与苹果的天然果香，菠菜味清淡不抢。富含维生素 C 和膳食纤维，有助于促进消化。制作非常简单，新手也能一次成功，全程预计只需 10 分钟。', '[{"name":"奇异果","quantity":2,"unit":"个"},{"name":"苹果","quantity":0.5,"unit":"个"},{"name":"菠菜叶","quantity":4,"unit":"叶"},{"name":"饮用水","quantity":700,"unit":"ml"},{"name":"白砂糖","quantity":12,"unit":"克"}]'::jsonb, '["将猕猴桃切成两半，每半再分四份小块","将苹果切丁","将菠菜叶去梗，只留叶子部分","将菠菜切碎","一起倒入榨汁机搅拌杯","注水","加入白砂糖","启动搅拌机，搅拌约 4 个 15 秒（每 15 秒停下看状态）"]'::jsonb, '["饮品","酸甜","清爽","快手","健康","维C"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_drink_f3dca9ad16.jpg', 'https://www.bilibili.com/video/BV1454y1474R', null, '[null,null,null,null,null,null,null,60]'::jsonb),
  ('howtocook:drink/奶茶', '奶茶', '饮品', 2, 30, '这是一道用红茶和奶粉轻松调制的家常饮品，茶香与奶香交融，口感顺滑温暖。红茶中的茶多酚搭配牛奶的蛋白质和钙质，既能提神又补充日常营养。做法非常简单，新手也能一次成功，仅需大约半 小时就能喝上自制奶茶。', '[{"name":"袋泡红茶（推荐立顿黄牌精选红茶）","quantity":2,"unit":"包"},{"name":"全脂奶粉（或淡奶）","quantity":11,"quantityMax":12,"unit":"克"},{"name":"砂糖","quantity":5,"quantityMax":7,"unit":"克"},{"name":"沸水","quantity":180,"quantityMax":200,"unit":"ml"}]'::jsonb, '["取袋泡红茶 2 包放入杯中，加入 180-200mL 沸水。","等待 20 - 30 分钟。","称取 11-12g 奶粉和 5-7g 砂糖，分别加入前一步骤得到的液体中。","搅拌均匀即可饮用。"]'::jsonb, '["饮品","奶香","快手","自制","下午茶","暖胃"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_drink_f799f10138.jpg', 'https://www.bilibili.com/video/BV1s7411L7cq', '{"energyKcal":90,"protein":3,"carbs":12,"fat":3.2}'::jsonb, null),
  ('howtocook:drink/杨枝甘露', '杨枝甘露', '饮品', 2, 20, '这是一道改良版的经典港式甜品，用奇亚籽代替西谷米，口感滑嫩又带有籽粒的细微嚼劲，芒果的香甜与葡萄柚的微酸交织，椰奶增添浓郁。富含膳食纤维、维生素 C 和优质脂肪，清爽解暑。制作非常简单，新手也能轻松完成，从备料到享用只需约 20 分钟。', '[{"name":"奇亚籽","quantity":24,"unit":"g"},{"name":"牛奶","quantity":50,"unit":"ml"},{"name":"冰块","quantity":2,"unit":"小块"},{"name":"芒果","quantity":1,"unit":"粒"},{"name":"葡萄柚","quantity":0.5,"unit":"粒"},{"name":"椰奶","quantity":150,"unit":"ml"},{"name":"芒果干","note":"切丝，可选"},{"name":"柳橙干","note":"切丝，可选"}]'::jsonb, '["奇亚籽泡牛奶 10 分钟。","泡籽之时，把半粒芒果、葡萄柚去皮切丁，放入杯中。","半粒芒果切小块放入调理机加冰块、椰奶打成泥。","倒入杯中，放上点缀材料（如有）。","一边享用一边写代码！！"]'::jsonb, '["饮品","港式","酸甜","清爽","快手","解暑"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_drink_36f1603323.jpg', 'https://www.bilibili.com/video/BV1Xi4y1u7MT', '{"energyKcal":600,"protein":12,"carbs":58,"fat":38}'::jsonb, '[600,null,null,null,null]'::jsonb),
  ('howtocook:drink/柠檬水/柠檬水', '柠檬水', '饮品', 1, 5, '这道饮品以新鲜柠檬为主角，搭配果蜜调和，酸甜平衡，冰镇后更感清凉解暑。柠檬富含维生素 C，经常饮用有助于补充营养、提神美白。制作步骤极简，只需捶打、加料、摇晃，新手也能在三五分钟内完成。', '[{"name":"柠檬","quantity":40,"quantityMax":45,"unit":"克"},{"name":"果蜜","quantity":40,"quantityMax":45,"unit":"克"},{"name":"冰","note":"几块（可选）"}]'::jsonb, '["称 40~45 克柠檬，放入雪克杯中","雪克杯盖盖子锤大约 10 次","加入果蜜 40~45 克","补水","摇晃均匀","最后根据喜好加冰"]'::jsonb, '["饮品","酸甜","快手","清凉解暑","冷饮","维C"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_drink_200ee47824.jpg', 'https://www.bilibili.com/video/BV1QM4m1m7fP', '{"energyKcal":150,"protein":0.2,"carbs":40,"fat":0}'::jsonb, null),
  ('howtocook:drink/泰国手标红茶/泰国手标红茶', '泰国手标红茶', '饮品', 3, 260, '这是一道源自泰国街头的经典奶茶，茶香浓郁，口感绵密顺滑，炼乳与牛奶带来香甜奶味。茶奶结合可提供少量蛋白质和钙，但含糖量较高，适宜作为消暑解渴的饮品。制作步骤简单，但需反复过滤茶汤并等待长时间冷藏，整体耗时约 4 小时 20 分钟，对新手稍有耐心即可完成。', '[{"name":"水","quantity":600,"unit":"cc"},{"name":"茶粉","quantity":20,"unit":"g"},{"name":"炼乳","quantity":24,"unit":"g"},{"name":"白糖","quantity":24,"unit":"g"},{"name":"牛奶","quantity":18,"unit":"ml"},{"name":"冰块","quantity":6,"quantityMax":8,"unit":"颗"}]'::jsonb, '["600cc 水大火烧开","在过滤袋中装入 20g 茶粉，开水倒入过滤袋中，过滤 20 遍","使用克称量取 24g 炼乳、24g 白糖和 18ml 牛奶放入 1000ml 以上的水壶中","将过滤好的茶水倒入水壶中搅拌，直到白糖融化","将水壶放到冰箱 4 小时以上","喝前可以加 6-8 颗冰块"]'::jsonb, '["饮品","泰式奶茶","冷饮","香甜","街头风","消暑","奶茶"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_drink_bc992a5568.jpg', 'https://www.bilibili.com/video/BV1of4y1b7qd', '{"energyKcal":185,"protein":2.6,"carbs":38,"fat":2.7}'::jsonb, '[null,null,null,null,14400,null]'::jsonb),
  ('howtocook:drink/海边落日/海边落日', '海边落日', '饮品', 3, 15, '这款鸡尾酒色彩层次分明，底部红石榴糖浆似晚霞，中间橙汁透亮，上层蓝橙酒液如海水，整体呈现海边落日的意境，喝起来酸甜清爽，带朗姆酒香。橙汁和柠檬汁含少量维生素 C，酒精能帮助放松。调酒步骤不复杂，但倒液沿搅拌棒做出分层需要一点耐心，新手跟着做也能成功，准备加调制大约一刻钟搞定。', '[{"name":"红石榴糖浆","quantity":15,"unit":"ml"},{"name":"NFC 橙汁","quantity":35,"quantityMax":50,"unit":"ml"},{"name":"苏打水","quantity":50,"unit":"ml"},{"name":"白朗姆","quantity":30,"unit":"ml"},{"name":"蓝橙力娇酒","quantity":15,"unit":"ml"},{"name":"柠檬汁","quantity":15,"unit":"ml"},{"name":"冰块","note":"适量"},{"name":"柠檬","quantity":1,"unit":"片"}]'::jsonb, '["柠檬洗净切出一片","选择一个杯子，建议使用容量在 350~400 毫升的透明玻璃杯","放入大冰块，用搅拌棒搅拌冰杯","加入红石榴糖浆","让橙汁沿搅拌棒导入酒杯，到就被一半就行","轻轻搅拌半圈","倒入苏打水","拿出调酒杯，加入白朗姆 + 蓝橙力娇酒 + 柠檬汁 + 冰块。然后 shake，shake","轻轻倒入酒杯中","插上柠檬和吸管"]'::jsonb, '["饮品","酸甜","清爽","调酒","分层","夏日"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_drink_800a2093d5.jpg', 'https://www.bilibili.com/video/BV18nkgYtEmT', '{"energyKcal":150,"protein":0.5,"carbs":18,"fat":0.1}'::jsonb, null),
  ('howtocook:drink/牛油果拉西', '牛油果拉西', '饮品', 1, 5, '这是一款融合了印度传统酸奶饮品“拉西”的创新饮品，口感绵密顺滑、清甜不腻，特别适合作为早餐或午后提神饮品。牛油果富含单不饱和脂肪酸与膳食纤维，搭配酸奶的优质蛋白和益生菌，一杯便能提供持久饱腹感。制作极为简单，新手也能零失败，从备料到享用只需 大约 5 分钟。', '[{"name":"原味酸奶","quantity":120,"unit":"ml"},{"name":"牛油果","quantity":1,"unit":"个"},{"name":"蜂蜜","quantity":1,"unit":"汤匙"},{"name":"冷牛奶","quantity":60,"unit":"ml"},{"name":"小豆蔻粉","quantity":1,"unit":"撮"},{"name":"薄荷叶","note":"装饰用适量"},{"name":"坚果碎","quantity":5,"unit":"克"}]'::jsonb, '["将牛油果对半切开，去核，剥去外皮，将果肉切成小块备用。","在搅拌机中加入 120ml 原味酸奶、切好的牛油果块、1 汤匙蜂蜜以及 60ml 冷牛奶。","（可选）加入一小撮小豆蔻粉以增加独特风味。","启动搅拌机，搅拌大约 1 分钟直至液体变得完全顺滑和浓郁。","将打好的饮品倒入杯中。","（可选）在表面放上几片薄荷叶或撒上 5g 切碎的坚果作为装饰。"]'::jsonb, '["饮品","清甜","绵密","快手","早餐","印度风味"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_drink_4904ced668.jpg', 'https://www.bilibili.com/video/BV19Q4y1o7io', '{"energyKcal":360,"protein":10,"carbs":35,"fat":22}'::jsonb, '[null,null,null,60,null,null]'::jsonb),
  ('howtocook:drink/百香果橙子特调/百香果橙子特调', '百香果橙子特调', '饮品', 3, 30, '这是一道酸甜清爽的夏日饮品，融合了百香果的热带果香与橙子的鲜甜，搭配茉莉绿茶或苏打气泡水，口感层次分明，冰爽解腻。富含维生素 C，有助增强免疫力和滋润肌肤。包含腌制、泡茶、榨汁等步骤，操作略多但难度适中，新手也能尝试。需提前一天腌制百香果，总耗时约 24 小时，实际动手时间仅 大约 30 分钟。', '[{"name":"百香果","quantity":3,"unit":"个"},{"name":"橙子","quantity":1,"unit":"个"},{"name":"茉莉绿茶茶叶","quantity":3,"quantityMax":6,"unit":"克"},{"name":"白砂糖","quantity":30,"unit":"克"},{"name":"蜂蜜","quantity":10,"unit":"克"},{"name":"开水","quantity":150,"unit":"毫升"},{"name":"冰块","quantity":160,"unit":"克"},{"name":"苏打气泡水","note":"适量，与茉莉绿茶茶叶二选一"},{"name":"薄荷叶或其他绿叶","note":"可选，装饰用"}]'::jsonb, '["百香果腌制（因为量小不好配置，这里是两次的分量）","将三个百香果的果肉取出来（里面的汁也不能放过），置于容器中","称量 30 克白砂糖放入","称量 10 克蜂蜜放入（如果没有可以用 5 克白砂糖代替）","搅拌均匀","容器保鲜膜封口，放入冰箱中进行 12~24 小时的腌制","茉莉绿茶调配（推荐比例=>茶 : 水 : 冰 = 1~2 : 50 : 30）","称量 3~6 克茶叶置于容器，加入 150 毫升开水，泡 6 分钟","往泡好的绿茶中放入 90 克冰块冷却，可搅拌加速冷却","待冰块消失后，将茶叶过滤得到茉莉绿茶茶水约 240 毫升","橙子的处理（可在泡茶期间处理）","将橙子对半切（刀方向垂直于橙子的头尾连线），并从其中的一半中切取一片橙子备用","再次将橙子对半切，将得到的 4 角橙子用压汁器压出橙汁置于容器中备用","正式调配","选择一个杯子，建议使用容量在 350~400 毫升的透明玻璃杯","将 70 克冰块放置在杯底，并将所有橙汁倒入","将之前准备的一片橙子贴杯内壁放置","将一次分量的腌制百香果浇在冰上","缓慢注入茉莉绿茶直至满杯，便于分层","在液面放置好装饰用的绿叶（可选）"]'::jsonb, '["饮品","酸甜","清爽","冲泡","冰饮","夏日"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_drink_7b5080c215.jpg', 'https://www.bilibili.com/video/BV1YS4y1h7Sr', '{"energyKcal":250,"protein":2,"carbs":62,"fat":0.5}'::jsonb, '[null,null,null,null,null,43200,null,360,null,null,null,null,null,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:drink/砂糖椰子冰沙/砂糖椰子冰沙', '砂糖椰子冰沙', '饮品', 1, 600, '砂糖椰子冰沙是一道极具热带风情的快手冷饮，清甜的椰香融合粗粒黄糖的焦香，口感绵密冰爽。椰子水富含天然电解质与矿物质，能快速补充水分，咖啡调糖增添碳水能量。制作门槛极低，只要提前将椰汁冻硬，敲打成沙即可，对新手毫无压力。从冷冻到出品需提前准备 10 小时以上，但动手操作仅需几分钟，很适合作为悠闲的午后冰品。', '[{"name":"瓶装椰汁","quantity":500,"unit":"ml"},{"name":"咖啡调糖","quantity":10,"unit":"克"},{"name":"坚果碎(可选)","note":"适量"}]'::jsonb, '["500ml 瓶装椰汁倒掉 200ml，立刻拧紧瓶盖。","将这瓶椰汁放入冰箱冷冻区并冷冻 10 小时以上。","将这瓶椰汁取出，若确认瓶中椰汁已彻底冻结，则在墙角、椅背、桌角等坚硬表面上用力抽打。（请务必确认表面不会因此受到损伤）","当抽打到冻结椰汁变成冰沙状态，打开瓶盖倒出冰沙。","在冰沙表面均匀撒上咖啡调糖或坚果碎。","完成"]'::jsonb, '["饮品","快手","冷饮","清爽","下午茶","热带风味"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_drink_96f1554e11.jpg', 'https://www.bilibili.com/video/BV1fT421k7nb', '{"energyKcal":150,"protein":2,"carbs":36,"fat":2}'::jsonb, '[null,36000,null,null,null,null]'::jsonb),
  ('howtocook:drink/耙耙柑茶/耙耙柑茶', '耙耙柑茶', '饮品', 2, 15, '耙耙柑茶是一款融合了柑橘清甜与茉莉花香的果茶饮品，口感清爽回甘，属于创意调饮，不限于特定菜系。耙耙柑富含维生素 C 与膳食纤维，搭配绿茶饮用能带来清新提神的体验。做法非常简单，新手友好，从泡茶到搅拌全程仅需约 15 分钟即可完成。', '[{"name":"耙耙柑"},{"name":"茉莉绿茶"},{"name":"冰块","quantity":60,"unit":"克"},{"name":"蔗糖糖浆","quantity":10,"unit":"克"},{"name":"工具","note":"适量"}]'::jsonb, '["茉莉绿茶调配（推荐比例=>茶 : 水 : 冰 = 1~2 : 50 : 30）","称量 2~4 克茶叶置于容器，加入 100 毫升开水，泡 6 分钟","往泡好的绿茶中放入 60 克冰块冷却，可搅拌加速冷却","待冰块消失后，将茶叶过滤得到茉莉绿茶茶水约 160 毫升","正式调配","选择一个杯子，建议使用容量在大约 300 毫升的透明玻璃杯","取出耙耙柑的肉瓣，并将外皮剥去，取得果肉","取 130 克果肉和 130 毫升茉莉绿茶放入搅拌机中","倒入 10 克蔗糖糖浆（可选，如果喜甜可放）","封盖启动搅拌机，搅拌 20 秒后将搅拌产物倒入杯中","取一点果肉撕碎撒在液面上"]'::jsonb, '["饮品","清爽","果茶","快手","酸甜","新手友好"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_drink_1ab0919a82.jpg', 'https://www.bilibili.com/video/BV17YG1zrEC1', null, null),
  ('howtocook:drink/菠萝咖啡特调/菠萝咖啡特调', '菠萝咖啡特调', '饮品', 3, 10, '这道特调饮品融合了咖啡的醇香与菠萝的酸甜，气泡清爽、奶盖绵密，口感层次丰富。菠萝富含维生素 C 和膳食纤维，搭配咖啡能提神醒脑。制作难度中等，只需打发奶油并混合液体，全程约 10 分钟即可完成。', '[{"name":"咖啡液","quantity":30,"unit":"ml"},{"name":"菠萝汁","quantity":60,"unit":"ml"},{"name":"冰块","quantity":50,"unit":"克"},{"name":"苏打水","quantity":30,"unit":"ml"},{"name":"奶油","quantity":30,"unit":"ml"},{"name":"牛奶","quantity":10,"unit":"ml"},{"name":"糖","quantity":8,"unit":"克"},{"name":"海盐","quantity":0.5,"unit":"克"},{"name":"朗姆酒","quantity":5,"unit":"ml"}]'::jsonb, '["杯子里依次加入冰块，咖啡液，菠萝汁和苏打水","奶油加糖打发至湿性发泡，加入朗姆酒和牛奶均匀只有流动性","在第一部混合液上方倒入奶油","奶油顶面撒上海盐"]'::jsonb, '["饮品","酸甜","清爽","特调","快手","下午茶"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_drink_b84cc5f831.png', 'https://www.bilibili.com/video/BV1Xk4y1Y7Gi', null, null),
  ('howtocook:drink/酒酿醪糟/酒酿醪糟', '酒酿醪糟', '饮品', 4, 60, '这是一道传统中式发酵甜品，口感清甜微醺，带着淡淡的酒香。具有健脾开胃、促进消化的作用。制作过程简单有趣，虽然需要等待发酵，但动手操作并不复杂，非常适合作为发酵入门。预计制作总时长约 2 天，其中实际动手时间仅需 大约 1 小时。', '[{"name":"糯米","quantity":800,"unit":"克"},{"name":"安琪甜酒曲","quantity":8,"unit":"克"},{"name":"清水","quantity":720,"unit":"克"},{"name":"清水","quantity":600,"unit":"克"},{"name":"温水","quantity":20,"unit":"ml"},{"name":"桂花","note":"适量"},{"name":"清水","quantity":500,"unit":"ml"}]'::jsonb, '["将 800g 糯米淘洗干净放入电饭煲，加入 720g 清水选择蒸饭模式","蒸熟后将米饭倒出摊凉，使用干净的工具将其摊至 30°C （用温度计测量为宜，体感温热但不烫手）","将 8g 安琪甜酒曲用 20ml 温水（约 30°C）化开，均匀撒在糯米饭中，同时翻拌均匀","向糯米饭中加入 600g 清水帮助酒曲翻拌均匀。静置 2-3 分钟后发现糯米饭吸饱水分。这次加水可以让酒酿首次发酵便汤汁丰富","用擀面杖在糯米饭中央挖一个小洞（便于出酒）","将混合好的米饭装入干净容器中，轻轻压平表面，盖上盖子或保鲜膜密封好","放置于 28 ～ 32°C 环境下发酵 24 ～ 48 小时。发酵期间不可剧烈摇晃或移动","发酵成功标准为：中间凹槽有透明酒液渗出，整体略带酒香，无异味、不酸败","发酵结束后可立即冷藏保存（过程中可以加入桂花），每次食用用干净工具取出，可冷藏保存 7 ～ 10 天","可以继续二次发酵，加入 500ml 清水增加酒酿产量（800g 水以内即可）","酒酿会一直持续发酵。如果想停止发酵，可以上锅蒸 10 分钟杀菌，或放入冰箱冷藏","将 800g 糯米淘洗干净，倒入清水中浸泡 6 ～ 8 小时（冬季建议泡 8 ～ 10 小时），泡至米粒饱满","沥干糯米，放入蒸布中，隔水蒸 40 ～ 60 分钟。每 20 分钟打开锅盖翻动一次确保蒸熟均匀","蒸熟后将米饭倒出摊凉，加入酒曲，后续步骤同上","当然，酒酿老手可以随意尝试不同米搭配。可以替换 20%的糯米为小米、燕麦、黄米、血糯米等"]'::jsonb, '["饮品","清甜微醺","发酵","中式传统","健脾开胃","入门"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_drink_d20a2c0930.jpeg', 'https://www.bilibili.com/video/BV1CstpeAE3n', '{"energyKcal":220,"protein":4.6,"carbs":50,"fat":0.4}'::jsonb, '[null,null,null,120,null,null,86400,null,null,null,600,21600,2400,null,null]'::jsonb),
  ('howtocook:drink/酸梅汤（半成品加工）', '酸梅汤（半成品加工）', '饮品', 1, 5, '酸梅汤（半成品加工）是一道酸甜爽口的夏日消暑饮品，传统京味风格。酸梅汤本身有生津止渴、帮助消化的好处。做法极其简单，只需按顺序搅拌即可，对新手毫无难度，全程大约五分钟就能完成。', '[{"name":"饮用水","quantity":1177,"unit":"克"},{"name":"酸梅晶固体饮料","quantity":120,"unit":"克"},{"name":"方糖（可选）","quantity":9,"unit":"克"}]'::jsonb, '["取饮用水 1177 克。","放入酸梅晶固体饮料 60 克，使用汤匙顺时针搅拌 50 圈。","再放入剩下 60 克酸梅晶固体饮料，再次使用汤匙顺时针搅拌 50 圈。","放入 9 克的方糖，使用汤匙顺时针搅拌 100 圈。","放入北京二锅头酒 48 克，用汤匙顺时针搅拌 30 圈。"]'::jsonb, '["饮品","酸甜","京味","快手","消暑","搅拌"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_drink_e9e7b15d51.jpg', 'https://www.bilibili.com/video/BV1uh41177J5', '{"energyKcal":175,"protein":0,"carbs":32,"fat":0}'::jsonb, null),
  ('howtocook:drink/酸梅汤/酸梅汤', '酸梅汤', '饮品', 2, 360, '酸梅汤是一道酸甜可口、清凉解暑的传统饮品，冰镇后饮用尤为沁人心脾。配方中的乌梅、山楂、甘草等原料有助于生津止渴、消食开胃。做法简单，新手友好，只需浸泡、熬煮和冷藏即可。制作全程包括浸泡、两次煎煮和冷藏，大约需要 6 小时以上，建议提前准备。', '[{"name":"水","quantity":2,"unit":"升"},{"name":"乌枣","quantity":25,"unit":"克"},{"name":"乌梅","quantity":25,"unit":"克"},{"name":"山楂片（生）","quantity":30,"unit":"克"},{"name":"黄冰糖","quantity":100,"unit":"克"},{"name":"甘草","quantity":2,"unit":"克"},{"name":"陈皮","quantity":4,"unit":"克"},{"name":"红豆蔻","quantity":1,"unit":"克"},{"name":"干桂花","quantity":3,"unit":"克"}]'::jsonb, '["冲洗材料（干桂花和冰糖除外）， 1.5 升水常温浸泡两小时以上（干桂花和冰糖除外）","开中大火煮沸，盖盖，转小火煮 40 分钟，为头煎","将冰糖放入盆内，再将沥好用材的头汤趁热倒入，搅拌至冰糖融化。","药材重新装回锅内再 600 毫升的水，开大火煮沸，盖盖，转中火，再煮 20 分钟为二煎","最后将二煎和冰糖水趁热混合为成品。在成品 60-70℃加入干桂花（不要超过 80℃）加盖晾凉再放入冰箱冷藏 3 小时以上。","饮用时记得将干桂花沥出。如饮茶般细啜，冰凉振齿，酸醒人、甜适度，滋味丰满而悠长"]'::jsonb, '["饮品","酸甜","煮","解暑","冰镇","传统","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_drink_e6af72ea09.jpg', 'https://www.bilibili.com/video/BV1uh41177J5', null, null),
  ('howtocook:drink/金汤力/金汤力', '金汤力', '饮品', 2, 5, '这是一款经典的金酒鸡尾酒，口感清爽微苦，带有柠檬的明亮酸香与汤力水的细腻气泡，入口轻盈畅快。虽然主要提供水分和少量酒精带来的热量，新鲜柠檬汁能补充维生素 C，帮助提神。做法非常简单，新手也能轻松掌握，预计只需 5 分钟即可完成。', '[{"name":"金酒","quantity":30,"quantityMax":40,"unit":"毫升"},{"name":"汤力水气泡水","quantity":1,"unit":"罐"},{"name":"柠檬","quantity":1,"unit":"个"},{"name":"冰块","quantity":100,"unit":"克"},{"name":"新鲜绿叶","note":"适量（装饰用）"}]'::jsonb, '["将柠檬对半切（刀方向垂直于柠檬的头尾连线），并从其中的一半中切取一片柠檬备用","再次将柠檬对半切，将得到的 4 角柠檬用压汁器压出柠檬汁置于容器中备用","选择一个杯子，建议使用容量在 350~400 毫升的透明玻璃杯","将 100 克冰块放置在杯底","倒入 30~40 毫升金酒","倒入 15 毫升柠檬汁（如果喜酸可以加多点或全加）","用勺子搅拌均匀","将之前准备的一片柠檬放置好","缓慢沿杯壁注入汤力水直至满杯（不要倒在冰上，避免起泡流失）","用勺子轻轻上下提拉将液体搅拌均匀（不要旋转搅拌，避免起泡流失）","在液面放置好装饰用的绿叶（可选）"]'::jsonb, '["饮品","清爽","微苦","快手","鸡尾酒"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_drink_8249715208.jpg', 'https://www.bilibili.com/video/BV1dZ4y1x7yj', '{"energyKcal":210,"protein":0.1,"carbs":30,"fat":0}'::jsonb, null),
  ('howtocook:drink/金菲士/金菲士', '金菲士', '饮品', 2, 5, '经典金酒鸡尾酒，酸甜适口，气泡激爽。柠檬提供丰富维 C，搭配蔗糖糖浆平衡酸度。制作非常简单，新手只需 5 分钟即可调制完成，适合在家轻松享用。注意饮酒有害健康，请勿过量。', '[{"name":"金酒","quantity":30,"quantityMax":40,"unit":"毫升"},{"name":"苏打气泡水","quantity":1,"unit":"罐"},{"name":"柠檬","quantity":1,"unit":"个"},{"name":"蔗糖糖浆","quantity":30,"quantityMax":40,"unit":"克"},{"name":"冰块","quantity":100,"unit":"克"},{"name":"新鲜绿叶","note":"装饰用，适量"},{"name":"雪克瓶","note":"可选"}]'::jsonb, '["将柠檬对半切（刀方向垂直于柠檬的头尾连线），并从其中的一半中切取一片柠檬备用","再次将柠檬对半切，将得到的 4 角柠檬用压汁器压出柠檬汁置于容器中备用","选择一个杯子，建议使用容量在 350~400 毫升的透明玻璃杯","将 100 克冰块放置在杯底","倒入 30~40 毫升金酒","倒入 20 毫升柠檬汁（如果喜酸可以加多点或全加）","倒入 30~40 克蔗糖糖浆","用勺子搅拌均匀","将之前准备的一片柠檬放置好","缓慢沿杯壁注入苏打气泡水直至满杯（不要倒在冰上，避免起泡流失）","用勺子轻轻上下提拉将液体搅拌均匀（不要旋转搅拌，避免起泡流失）","在液面放置好装饰用的绿叶（可选）","将冰块、金酒、柠檬汁、蔗糖糖浆倒入雪克瓶，雪克均匀","将充分雪克的产物倒到杯子中（如果里面的冰太碎了，可以选择过滤其中的冰，重新往杯中补充冰块）"]'::jsonb, '["饮品","酸甜","清爽","气泡","快手","经典"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_drink_df45a37b8a.jpg', 'https://www.bilibili.com/video/BV1cZ4y1u7Wc', '{"energyKcal":240,"protein":0.1}'::jsonb, null),
  ('howtocook:drink/长岛冰茶', '长岛冰茶', '饮品', 2, 5, '长岛冰茶是一款口感酷似冰茶、入口柔和但酒精度颇高的经典鸡尾酒。它本身营养价值不高，偶尔小酌可放松身心，但切勿过量。做法非常简单，只需按比例混合四种基酒、甜酒和果汁，新手也能轻松调制。从准备到完成仅需 大约 5 分钟。', '[{"name":"金酒","quantity":15,"unit":"ml"},{"name":"龙舌兰酒","quantity":15,"unit":"ml"},{"name":"伏特加","quantity":15,"unit":"ml"},{"name":"白朗姆酒","quantity":15,"unit":"ml"},{"name":"橙味甜酒","quantity":15,"unit":"ml"},{"name":"柠檬","quantity":1,"unit":"个"},{"name":"柠檬汁","quantity":30,"unit":"ml"},{"name":"枫糖浆","quantity":20,"unit":"ml"},{"name":"可乐","quantity":75,"unit":"ml"},{"name":"冰块","quantity":100,"unit":"克"}]'::jsonb, '["柠檬对半切，挤出 30ml 柠檬汁至杯中；","依次向杯中加入：","15ml 金酒，","15ml 龙舌兰酒，","15ml 伏特加，","15ml 白朗姆酒，","15ml 橙味甜酒；","向杯中缓慢倒入 20ml 枫糖浆，边倒边搅拌；","向杯中加入 75ml 可乐；","向杯中加入冰块直至满杯；","轻轻搅拌 20 秒；","开始享用."]'::jsonb, '["饮品","鸡尾酒","微醺","快手","酸甜","经典"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_drink_d5c0be6982.jpg', 'https://www.bilibili.com/video/BV1Lb4y117Y5', '{"energyKcal":270,"protein":0,"carbs":28,"fat":0}'::jsonb, null),
  ('howtocook:meat_dish/农家一碗香/农家一碗香', '农家一碗香', '荤菜', 3, 17, '这是一道咸香下饭的湖南家常小炒，五花肉的油润、鸡蛋的嫩滑与青椒的清香彼此融合，口感层次丰富。猪肉与鸡蛋提供优质蛋白质，搭配青椒补充维生素 C，营养均衡。中等难度，需要注意煸炒火候和调味顺序，新手稍加练习也能做好。预计备菜 7 分钟，烹饪 10 分钟，总共约 17 分钟就能出锅。', '[{"name":"猪肉","quantity":250,"unit":"克"},{"name":"鸡蛋","note":"适量"},{"name":"青椒","quantity":3,"unit":"个"},{"name":"小米辣","quantity":1,"unit":"个"},{"name":"蒜片","quantity":2,"unit":"片"},{"name":"姜","quantity":2,"unit":"片"},{"name":"豆瓣酱","quantity":10,"unit":"克"},{"name":"酱油","quantity":15,"unit":"ml"},{"name":"白糖","quantity":5,"unit":"克"},{"name":"油","note":"适量"}]'::jsonb, '["备菜阶段：将猪肉切片，最好把肥瘦分开放。同时要把青椒和小米辣切成段，蒜片用刀背拍成末，姜切成丝。鸡蛋打到小碗中，用筷子打散。","备好菜，就可正式煮菜了。先将油倒入锅中，锅中开小火，油热后将蛋液倒入锅中，将鸡蛋炒散，炒至断生即可，放回小碗中备用。","将锅中继续加一点油，开小火，锅热后将之前切的肥猪肉倒入锅中逼出猪油。","肥肉出现金黄色的时候，加大火力到中火，将瘦肉一起放入锅中翻炒。","瘦肉全部炒至变色的时候加入备好的姜丝、蒜末和豆瓣酱翻炒均匀给猪肉上色。","放入青红椒、炒至断生的鸡蛋后加入酱油和白糖，继续将它们翻炒到青椒微微断生，保持青椒清脆口感。","出锅上菜！"]'::jsonb, '["荤菜","咸香","下饭","家常","炒","湖南"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_901dfda136.jpg', 'https://www.bilibili.com/video/BV1dwxCzcEtT', null, null),
  ('howtocook:meat_dish/冬瓜酿肉/冬瓜酿肉', '冬瓜酿肉', '荤菜', 4, 30, '冬瓜酿肉是一道荤素搭配的家常蒸菜，口感鲜嫩爽滑，肉馅的咸香与冬瓜的清甜相互融合，清爽不腻。猪肉末提供优质蛋白质和必需氨基酸，冬瓜则有助于清热利尿、补充水分。做法简单，即使是新手也能轻松上手，只需稍加练习卷肉技巧即可。从备料到出锅，大约需要 30 分钟。', '[{"name":"冬瓜","quantity":200,"unit":"克"},{"name":"猪肉末","quantity":300,"unit":"克"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"葱","quantity":20,"unit":"克"},{"name":"葱姜末","quantity":30,"unit":"克"},{"name":"胡椒粉","quantity":5,"unit":"克"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"淀粉","quantity":5,"unit":"克"},{"name":"盐","quantity":20,"unit":"克"},{"name":"水淀粉","quantity":25,"unit":"克"}]'::jsonb, '["冬瓜去皮，切成 25cm 长 3cm 厚的片","将切好的冬瓜放入碗中，放入 15g 盐，将冬瓜抹匀，放置 10 分钟","放置冬瓜的同时，换个碗放入肉末，葱姜末， 5g 盐，淀粉 5g，胡椒粉，生抽，胡椒粉","使用筷子在肉末中进行顺时针搅拌，搅拌到食材颜色没有明显对比（约 2 分钟）","将腌制好的冬瓜（会变软）使用清水洗三遍","拿出 1 片冬瓜片卷起来，并把肉塞进去","放入碟子中摆到碟子的边缘","打入 1 个鸡蛋到中间圆圈处","放入普通铁锅中水烧开后，蒸 15 分钟，盖上锅盖","开盖，取出蒸好的冬瓜酿肉","将冬瓜酿肉碟子的水倒入锅中，放入水淀粉，加入 50ml 清水倒入锅中烧开","淋到冬瓜酿肉上"]'::jsonb, '["荤菜","清蒸","家常","下饭","鲜香","荤素搭配"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_cbfcb46568.jpg', 'https://www.bilibili.com/video/BV1pq4y1t76H', '{"energyKcal":720,"protein":48}'::jsonb, '[null,600,null,120,null,null,null,null,900,null,null,null]'::jsonb),
  ('howtocook:meat_dish/冷吃兔', '冷吃兔', '荤菜', 4, 90, '这是一道经典的四川自贡盐帮菜，麻辣干香，兔肉紧实有嚼劲，入口先辣后鲜，回味悠长。兔肉高蛋白低脂肪，富含卵磷脂和多种氨基酸，营养丰富且易于消化。制作过程需处理多种香料并严格控制火候，对新手有一定挑战。从备料到炒制完成约需 1.5 小时，但放置一夜后风味更佳，值得提前准备。', '[{"name":"兔肉","note":"适量"},{"name":"盐","quantity":2,"unit":"克"},{"name":"味精","quantity":1,"unit":"克"},{"name":"蚝油","quantity":5,"unit":"克"},{"name":"料酒","quantity":10,"unit":"克"},{"name":"蒜","quantity":0.5,"unit":"头"},{"name":"姜","note":"与蒜量相同"},{"name":"小葱/大葱/洋葱","quantity":15,"unit":"克"},{"name":"干辣椒","note":"体积与兔肉相等"},{"name":"青花椒","note":"3斤兔肉配一整碗"},{"name":"八角","quantity":1,"unit":"粒"},{"name":"桂皮","note":"大拇指长短一块"},{"name":"香叶","quantity":5,"unit":"片"},{"name":"山奈","note":"黄豆大小一块"},{"name":"白蔻","quantity":2,"unit":"颗"},{"name":"小茴香","quantity":15,"unit":"克"},{"name":"白芝麻","quantity":25,"unit":"克"}]'::jsonb, '["蒜、姜扒皮并剁碎备用，八角、桂皮、香叶、山奈、白蔻、小茴香洗净备用。","干辣椒剪成 2 厘米的小段，洗净备用。","小葱/大葱/洋葱洗净，洋葱切成小块。","兔肉剁成 2 厘米的小块，加入盐、料酒、味精调味，腌制 15 分钟。","锅中倒油，油温 4 成热下小葱/大葱/洋葱，中小火煸炒出香味，待到小葱/大葱/洋葱微焦，将其捞出。","开大火升高油温，油温 8 成热时下入兔肉，炸制过程转中小火，炸至兔肉微微焦黄时捞出兔肉。","升高油温，倒入干辣椒、青花椒、八角、桂皮、香叶、山奈、白蔻、小茴香；转小火将辣椒段炸脆。","重新倒入兔肉，加入蚝油、翻炒几分钟。","关火，加入蒜、姜、白芝麻，翻炒均匀。","放置一夜更加入味。"]'::jsonb, '["荤菜","麻辣","干香","自贡盐帮","下酒","炸炒"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_ca34843c38.jpg', 'https://www.bilibili.com/video/BV13d4y1v7Cp', '{"energyKcal":300,"protein":35,"carbs":5,"fat":16}'::jsonb, '[null,null,null,900,null,null,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/凉拌鸡丝/凉拌鸡丝', '凉拌鸡丝', '荤菜', 3, 30, '一道少油低卡的家常凉菜，鸡丝嫩滑入味，麻油与香醋调和出微麻微酸的清爽口感，适合夏日解腻。鸡胸肉富含优质蛋白且脂肪含量低。做法简单，新手也能轻松上手，从备料到完成大约只需 30 分钟。', '[{"name":"鸡胸肉（常温冷冻均可）","quantity":200,"unit":"克"},{"name":"麻油（花椒油）","quantity":5,"unit":"毫升"},{"name":"生抽","quantity":4,"unit":"毫升"},{"name":"香醋","quantity":4,"unit":"毫升"},{"name":"白糖","quantity":3,"unit":"克"},{"name":"盐","quantity":2,"unit":"克"},{"name":"料酒","quantity":20,"unit":"毫升"},{"name":"姜","quantity":20,"unit":"克"},{"name":"凉白开水","note":"适量"}]'::jsonb, '["姜切片，备用","锅中倒入 4 升水","加入鸡胸肉、姜片","倒入 20 毫升料酒","开大火不盖盖将水烧开","水开后转中火，用勺子将浮沫捞出","继续煮 5-7 分钟，如果是非冷冻肉煮 5 分钟，冷冻肉煮 7 分钟","鸡胸肉大小会影响成熟时间，用筷子插入鸡胸肉，如果能轻松插入，代表鸡肉熟了。如果不熟需延长煮制时间","用凉白开水冲泡鸡胸肉，使鸡胸肉降至室温","顺着鸡胸肉纹理将鸡胸肉撕成细丝","准备一个碗","碗中加入准备好的麻油、生抽、香醋、白糖、盐","搅拌料汁，使糖和盐尽量溶化","将料汁倒入鸡丝中，搅拌均匀"]'::jsonb, '["荤菜","凉拌","微麻微酸","清爽","低卡","快手","夏日"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_9a77a8e8b2.jpg', 'https://www.bilibili.com/video/BV1Ga5QzWEW5', '{"energyKcal":370,"protein":62,"carbs":4,"fat":12}'::jsonb, null),
  ('howtocook:meat_dish/卤菜/卤菜', '卤菜', '荤菜', 3, 60, '这是一道经典中式卤味，肉质鲜嫩入味，香气浓郁，卤汁可反复使用、越陈越香，适合做凉菜、下酒或搭配主食。菜品富含优质蛋白和多种维生素，营养均衡。制作需要一点耐心，但步骤清晰，对新手比较友好。提前浸泡去血水、熬糖色和高压卤制约需 1 小时，再浸泡过夜让风味充分渗入，第二天取出切片即可享用。', '[{"name":"牛腱子（或其他肉类）","quantity":500,"unit":"克"},{"name":"卤料包","quantity":1,"unit":"包"},{"name":"黄豆酱","quantity":15,"unit":"ml"},{"name":"豆瓣酱","quantity":15,"unit":"ml"},{"name":"蚝油","quantity":15,"unit":"ml"},{"name":"南腐乳","quantity":15,"unit":"ml"},{"name":"洋葱","quantity":0.5,"unit":"个"},{"name":"生姜","quantity":30,"unit":"克"},{"name":"大蒜","quantity":40,"unit":"克"},{"name":"干辣椒","quantity":10,"unit":"克"},{"name":"生抽","quantity":120,"unit":"ml"},{"name":"老抽","quantity":60,"unit":"ml"},{"name":"盐","quantity":10,"quantityMax":15,"unit":"克"},{"name":"白糖","quantity":30,"unit":"克"},{"name":"啤酒","quantity":1,"unit":"罐"},{"name":"清水","note":"足量"},{"name":"热水","quantity":150,"unit":"ml"},{"name":"醋","quantity":10,"unit":"ml"},{"name":"糖","quantity":5,"unit":"ml"},{"name":"味精/鸡精","note":"适量"},{"name":"卤汤","quantity":15,"unit":"ml"},{"name":"蒜末","note":"适量"},{"name":"葱花","note":"适量"},{"name":"白芝麻","note":"适量"},{"name":"辣椒粉","note":"适量"},{"name":"小米辣","note":"依个人口味"},{"name":"芝麻油或藤椒油","note":"少量"},{"name":"植物油","note":"适量"},{"name":"黄瓜","note":"适量"},{"name":"木耳","note":"适量"},{"name":"油炸花生米","note":"适量"},{"name":"香菜","note":"适量"}]'::jsonb, '["牛腱子提前浸泡在冷水中 3 小时以上，去除血水","准备糖色：锅中加入 30g 白糖，小火加热至糖完全融化并呈现棕褐色，加入 150ml 热水，搅拌均匀备用","将洋葱切块，生姜和大蒜拍碎，干辣椒掰断备用","在锅中加入足量的水，放入卤料包、洋葱、生姜、大蒜、干辣椒，大火烧开","加入黄豆酱、豆瓣酱、蚝油和南腐乳各 15ml，搅拌均匀","倒入准备好的糖色，混合均匀","加入生抽 120ml 和老抽 60ml，搅拌均匀","加入 10-15g 盐调味","倒入 1 罐啤酒(330ml)，再次烧开","牛腱子放入锅中焯水 2-3 分钟，捞出并用热水冲洗干净表面的浮沫","将焯水后的牛腱子放入已烧开的卤水中，确保卤水没过所有肉类","盖上高压锅盖，上汽后继续烹饪 25-30 分钟","烹饪完成后，不要开盖保温，自然冷却并浸泡一晚上（这样会更入味）","将卤好的肉取出放入冰箱冷藏，使其成型","食用前取出切片，可直接食用或凉拌","卤水重复使用方法：每次卤完肉后，将卤水过滤，去除所有固体内容物，重新烧开杀菌，冷却后可冷藏或冷冻保存。使用时按原配方比例重新添加调味料。（加水量根据卤水使用情况而定）","卤水保存得当可以使用很长时间，且越老越香。","重要提示：如卤制素菜，必须另取一部分卤水，单独使用，并且卤制完素菜的卤水不可重复使用。","将蒜末、葱花、白芝麻、辣椒粉按 1:1:1:1 的比例混合，依个人口味加小米辣，热植物油中加入少量芝麻油或藤椒油，分次泼在调料上，再加入生抽、醋、蚝油各 10ml，5ml 糖，味精/鸡精，最后 15ml 卤汤混合均匀。","凉拌时可搭配拍黄瓜、木耳、油炸花生米、香菜等配菜。"]'::jsonb, '["荤菜","卤味","酱香","下酒","家常","凉拌"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_f77ab8ccd7.jpeg', 'https://www.bilibili.com/video/BV1ZA411E7KT', '{"energyKcal":380,"protein":25}'::jsonb, '[10800,null,null,null,null,null,null,null,null,150,null,1650,null,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/口水鸡/口水鸡', '口水鸡', '荤菜', 3, 90, '口水鸡是一道经典的四川凉菜，红油包裹的鸡肉冰爽 Q 弹、麻辣鲜香，夏季食用开胃解腻。鸡肉富含优质蛋白，搭配花生碎和香料，提供能量与风味。制作难度中等，需注意煮鸡火候和红油调味，适合有一定下厨经验的烹饪者。从备料、煮鸡、冷却到淋汁完成，预计耗时约 1.5 小时。', '[{"name":"鸡","quantity":500,"unit":"克"},{"name":"食用油","quantity":20,"unit":"ml"},{"name":"辣椒粉","quantity":20,"unit":"克"},{"name":"花椒","quantity":20,"unit":"克"},{"name":"花生","quantity":30,"unit":"克"},{"name":"小葱","quantity":50,"unit":"克"},{"name":"姜","quantity":20,"unit":"克"},{"name":"蒜","quantity":10,"unit":"克"},{"name":"白糖","quantity":5,"unit":"克"},{"name":"生抽","quantity":5,"unit":"ml"},{"name":"醋","quantity":5,"unit":"ml"},{"name":"味精","quantity":5,"unit":"克"},{"name":"花椒粉","quantity":5,"unit":"克"},{"name":"香菜","quantity":5,"unit":"克"},{"name":"盐","note":"适量"},{"name":"香油","note":"适量"}]'::jsonb, '["姜切片，1 颗小葱，15 颗花椒备用","鸡肉洗干净，放入锅中，清水没过鸡肉，放入姜片、小葱和花椒，开大火烧开。","大火烧开后，转中小火 20 分钟关火","取出鸡肉，放入冰水中，直至冰凉","取出鸡肉，切块摆盘子中，备用","小火把锅烧热，导入花生，烘烤至表皮爆裂。（注意随时翻动，不要糊了）","一颗葱切成段，蒜拍成末，花椒 15 颗，花生去皮切碎。","锅内导入油烧热后，放入葱段，花椒和一半蒜末，炒香","炒至油温 8 成热，关火，滤出热油","将热油倒入放辣椒粉的碗中，搅拌，并滤出红油","红油中放入剩余蒜末、生抽、醋、盐、味精、糖、香油、花椒粉。拌匀放凉","在鸡肉上撒上花生碎，把红油淋到切好的鸡肉上，撒上香菜。成盘"]'::jsonb, '["荤菜","麻辣","凉拌","川菜","下酒","开胃"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_0e09c90860.jpg', 'https://www.bilibili.com/video/BV1XKV66qEu5', '{"energyKcal":480,"protein":45,"carbs":6,"fat":28}'::jsonb, '[null,null,1200,null,null,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/可乐鸡翅', '可乐鸡翅', '荤菜', 3, 40, '可乐鸡翅色泽红亮、口感嫩滑，味道咸甜适口，是一道流行于家庭餐桌的创意菜肴。鸡翅富含优质蛋白质与脂肪，搭配可乐烹煮后肉质更为软烂。制作过程需要掌握煎制与收汁的火候，对新手有一定挑战，但跟随步骤仍可成功。从备料到完成大约耗时 40 分钟。', '[{"name":"鸡翅中","quantity":10,"quantityMax":12,"unit":"只"},{"name":"可乐","quantity":500,"unit":"ml"},{"name":"白糖","quantity":10,"unit":"克"},{"name":"生抽","quantity":15,"unit":"克"},{"name":"老抽","quantity":3,"unit":"克"},{"name":"盐","quantity":2,"unit":"克"},{"name":"生姜","quantity":2,"unit":"片"},{"name":"料酒","quantity":20,"unit":"毫升"},{"name":"小葱","note":"适量"}]'::jsonb, '["鸡翅入锅，倒入冷水淹没。放生姜 1 片和料酒 10 ～ 20 毫升。大火煮开（ 大约 2 分钟 ）后，撇去浮沫，沥出水分","这一步针对冰鲜鸡翅，刚买来的鸡翅直接改刀用生抽进行腌制即可。","捞出鸡翅，可用刀将两边各划上两口改刀。生抽约 10 克腌制鸡翅 10 分钟（生抽能完全包裹鸡翅表面入味就行）","锅重新小火起油，先将剩余姜片爆香，然后下入腌好的鸡翅。将鸡翅煎至金黄翻面（直到两面金黄），用炒菜勺子翻动一下鸡翅，与姜片一起翻炒 4～5 下（目的是防止鸡翅和姜片粘黏）。","鸡翅金黄，倒入可乐没过鸡翅，开大火将锅中可乐煮沸，然后撇去漂浮的黑色浮沫（包含血水）。此时加入葱结。","调味：加入食用盐 2 克，白糖 10 克，生抽 3 克调味（可以适当用老抽调底色，3 克）。","等到葱结变黄，和姜片一起捞出，转中火继续慢煮可乐鸡翅。","等到可乐呈现挂丝状态，关小火让汁牢牢挂在鸡翅上。出锅，装盘。"]'::jsonb, '["荤菜","咸甜","煎","炖煮","家常","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_7003252f46.jpg', 'https://www.bilibili.com/video/BV1z3F1zkExH', '{"energyKcal":735,"protein":55,"carbs":52,"fat":45}'::jsonb, '[120,null,600,null,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/台式卤肉饭/台式卤肉饭', '台式卤肉饭', '荤菜', 3, 90, '台式卤肉饭是一道浓香四溢的台湾家常料理，肉条软糯入味，酱汁琥珀般油亮，浇在热米饭上满口脂香。富含优质蛋白、胶原蛋白和碳水，能快速补充能量。做法对新手非常友好，只需备好食材、掌握火候，全程约 1.5 小时即可完成，其中动手操作仅需半小时，剩下的交给小火慢炖。', '[{"name":"红葱头","quantity":25,"unit":"克"},{"name":"带皮五花肉","quantity":500,"unit":"克"},{"name":"鸡蛋","quantity":4,"unit":"个"},{"name":"食用油","quantity":15,"unit":"ml"},{"name":"生抽酱油","quantity":75,"unit":"ml"},{"name":"米酒"},{"name":"大蒜","quantity":25,"unit":"克"},{"name":"香叶","quantity":2,"unit":"片"},{"name":"八角","quantity":1,"unit":"颗"},{"name":"冰糖","quantity":20,"unit":"克"},{"name":"白胡椒粉","quantity":6,"unit":"克"},{"name":"五香粉","quantity":6,"unit":"克"},{"name":"米饭","note":"适量"}]'::jsonb, '["带皮五花肉切成 $0.7cm（长）\\times 0.7cm（宽） \\times 2.5cm（高）$ 的细长条","红葱头、大蒜切末备用","鸡蛋煮熟剥壳，并用刀划破蛋白（便于入味），备用。","大火热锅，锅内放入 15 ml 食用油，让油滑满锅底即可。","放油的目的是防止五花肉刚下锅时粘锅。等待 5s 使油温稍微升高。","放入五花肉条，翻炒至肉色稍微变白，沿锅边淋入米酒 10ml 。继续翻炒至五花肉不再出油。","将切好的红葱头加入锅中，翻炒 1 分钟爆出油葱香味。","将切好的红葱头加入锅中，翻炒 30 秒。","把猪肉推到旁边，放入冰糖加热到融化冒泡变成焦糖，再把猪肉一起翻拌，让焦糖均匀附着。","加入生抽炒出香气。","呛入米酒 25 ml ，水加到淹过猪肉，加入白胡椒粉、五香粉、八角、香叶、水煮蛋，沸腾后转小火卤 1 小时。","注意: 不同酱油的咸淡不一，卤的时候务必试味道，太甜加酱油，太咸加点糖或水调整。","小火炖煮过程中，每隔 15 分钟 搅拌检查一次，防止粘锅。","如发现过干，则可加入 100ml 清水继续炖煮。","1 小时后，开大火收汁直到酱汁浓稠，呈现有光泽的琥珀色，即完成。","炖煮结束后，乘一碗米饭，将软烂的卤肉浇在米饭上，并加上卤蛋，开始享用。"]'::jsonb, '["荤菜","台式","家常","下饭","鲜香","炖煮"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_6ced04b8e0.jpg', 'https://www.bilibili.com/video/BV1vS4y117LQ', '{"energyKcal":820,"protein":20,"carbs":16,"fat":75}'::jsonb, '[null,null,null,null,5,null,60,30,null,null,3600,null,900,null,null,null]'::jsonb),
  ('howtocook:meat_dish/咕噜肉', '咕噜肉', '荤菜', 4, 40, '咕噜肉是一道经典粤式家常菜，酸甜开胃、外酥里嫩，菠萝的果香让肉块吃起来格外清爽解腻。猪肉提供优质蛋白质，青椒和菠萝则补充维生素与膳食纤维。这道菜的难点在于掌握炸肉的火候，对新手略有挑战，但只要按步骤操作便能成功。从腌制到出锅，全程大约需要 40 分钟，很适合为家人做一道下饭快菜。', '[{"name":"梅头猪肉","quantity":100,"unit":"克"},{"name":"青椒","quantity":25,"unit":"克"},{"name":"罐头菠萝片","quantity":75,"unit":"克"},{"name":"盐","quantity":0.25,"unit":"茶匙"},{"name":"茄汁","quantity":4,"unit":"汤匙"},{"name":"白醋","quantity":2,"unit":"茶匙"},{"name":"蒜蓉","quantity":1,"unit":"汤匙"},{"name":"生抽","quantity":0.5,"unit":"茶匙"},{"name":"生粉","quantity":2.5,"unit":"茶匙"},{"name":"白砂糖","quantity":2,"unit":"汤匙"},{"name":"水","quantity":200,"unit":"毫升"},{"name":"油","note":"适量"}]'::jsonb, '["将梅头猪肉（100 克）洗净，然后用厨房纸抹干水份，将猪肉切成比想要的成品小一圈的大小。","用盐（1/2 茶匙）腌制梅头猪肉 20 分钟。","将青椒（25 克）切碎。","将菠萝片（75 克）切件。","在碗中加入茄汁（4 汤匙）﹑白醋（2 茶匙）﹑蒜蓉（1 汤匙）﹑生抽（½ 茶匙）﹑生粉（2½ 茶匙）﹑白砂糖（2 汤匙）﹑盐（¼ 茶匙）和水（200 毫升），拌匀成酱汁。","将梅头猪肉粒沾上生粉（6 汤匙）。","加入油（500 毫升）中火加热。","将梅头猪肉粒放至锅里中火炸 5 分钟，然后盛起。","加入梅头猪肉粒，再大火翻炸 1 分钟。","加入油（1 茶匙）和酱汁，中火加热 3 分钟。","加入青椒和菠萝，大火加热 2 分钟。","将已炸好的梅头猪肉粒与酱汁拌匀即可。"]'::jsonb, '["荤菜","酸甜","粤式","家常","下饭","炸制"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_27ffddb969.jpg', 'https://www.bilibili.com/video/BV1de411J7XX', '{"energyKcal":590,"protein":20,"carbs":50,"fat":31}'::jsonb, '[null,1200,null,null,null,null,null,300,60,180,120,null]'::jsonb),
  ('howtocook:meat_dish/咖喱肥牛/咖喱肥牛', '咖喱肥牛', '荤菜', 4, 40, '咖喱肥牛是一道浓郁下饭的家常菜，咖喱的辛香与肥牛的脂香融合，搭配土豆、胡萝卜等蔬菜，口感绵软醇厚。富含蛋白质、维生素和钙质，荤素搭配均衡。做法简单，对新手友好，一般只需 40 分钟就能端上餐桌，很适合作为便当菜。', '[{"name":"香叶","quantity":1,"unit":"片"},{"name":"纯牛奶","quantity":50,"unit":"ml"},{"name":"洋葱","quantity":100,"unit":"克"},{"name":"胡萝卜","quantity":150,"unit":"克"},{"name":"土豆","quantity":200,"unit":"克"},{"name":"肥牛卷","quantity":300,"unit":"克"},{"name":"咖喱块","quantity":2,"unit":"块"},{"name":"食用油","quantity":10,"quantityMax":15,"unit":"ml"}]'::jsonb, '["洋葱切成条状、胡萝卜以及土豆切成块状，备用","烧一锅开水，水沸时将肥牛卷下锅，捞出血沫后放在一边沥水，备用","热锅，锅内放入 10ml - 15ml 食用油，等待 10 秒让油温升高","放入洋葱，翻炒至洋葱变软变透明","放入土豆以及胡萝卜翻炒 2 分钟","加入冷水至淹没所有食材即可","将香叶、咖喱块投入锅中，盖上锅盖，待水沸腾后将火调小然后等待直至土豆块以及胡萝卜块炖至软烂（可用筷子确认）","加入肥牛卷以及牛奶，盖上锅盖再小火煮 2-3 分钟即可出锅（用勺子搅拌食材，注意力度，避免肥牛卷破碎）"]'::jsonb, '["荤菜","浓郁下饭","炖菜","家常","快手","咖喱"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_0bd5c5ddfb.jpg', 'https://www.bilibili.com/video/BV1BQPfz4EQC', '{"energyKcal":670,"protein":30.5,"carbs":34.5,"fat":42.5}'::jsonb, '[null,null,10,null,120,null,null,150]'::jsonb),
  ('howtocook:meat_dish/商芝肉', '商芝肉', '荤菜', 5, 150, '商芝肉是陕西商县的传统风味菜，色泽红润，质地软嫩，肥而不腻，带有商芝独特的清香。猪肉提供优质蛋白和脂肪，蕨类蔬菜商芝则增添了膳食纤维和多种微量元素。这道菜工序繁琐，对刀工和火候均有要求，适合有一定烹饪基础的人挑战。从备料到成菜，全程大约需要 2.5 小时。', '[{"name":"带皮猪五花肉","quantity":500,"unit":"克"},{"name":"商芝","quantity":50,"unit":"克"},{"name":"葱","quantity":10,"unit":"克"},{"name":"姜","quantity":2,"unit":"克"},{"name":"八角","quantity":3,"unit":"个"},{"name":"蜂蜜","quantity":15,"unit":"克"},{"name":"醋","quantity":5,"unit":"克"},{"name":"料酒","quantity":15,"unit":"克"},{"name":"味精","quantity":1.5,"unit":"克"},{"name":"酱油","quantity":10,"unit":"克"},{"name":"摊鸡蛋皮","quantity":1,"unit":"张"},{"name":"精盐","quantity":1,"unit":"克"},{"name":"鸡汤","quantity":200,"unit":"克"},{"name":"芝麻油","quantity":10,"unit":"克"},{"name":"熟猪油","quantity":2000,"unit":"克"}]'::jsonb, '["将肉刮洗干净，入煮锅煮至六成熟（变色为白），捞出趁热用蜂蜜、醋涂抹肉皮。","炒锅内放入熟猪油，用旺火烧至八成熟（约 200 度，油表有大量青烟，油状平静），将肉块皮朝下投入，炸至呈金红色时，捞入凉肉煮锅（之前煮完的煮锅）中泡软，放在案板上，切成三寸(10 cm)长、两分(0.6 cm)厚的片，仍然皮朝下，整齐装入蒸碗内。","将 5 克大葱切成 2.4 cm 长的段，5 克切成 2.4 cm 长的斜形片。姜去皮洗净，1.5 克切成片，5 克切成末，摊的鸡蛋皮切成 2.4 cm 长的等腰三角形片。","商芝入沸水锅中煮软捞出，去除老茎、杂质，淘洗干净，切成 3 cm 长的段，放入碗中,加酱油（5 克）、精盐（1 克）、熟猪油（10 克）拌匀，盖在肉片上，另将鸡汤（100 克）放入一小碗中，加酱油（5 克）、精盐（0.5 克）、料酒（15 克）搅匀，浇入蒸碗，再放入姜片、葱段、八角上笼用旺火蒸约半小时后，转用小火继续蒸约一小时三十分钟，熟烂后取出，拣去姜、葱、八角，倒、过滤原汁，将肉扣入汤盘。","炒锅内，放入鸡汤（100 克），加入原汁，用旺火烧沸，下入姜末、葱片、味精后搅匀，投入摊鸡蛋皮，淋芝麻油，浇入汤盘即成。"]'::jsonb, '["荤菜","陕菜","蒸制","鲜香","宴客","传统"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_31c2c36953.jpg', 'https://www.bilibili.com/video/BV1NK4y1m7DB', '{"energyKcal":1850,"protein":35,"carbs":12,"fat":145}'::jsonb, '[null,null,null,7200,null]'::jsonb),
  ('howtocook:meat_dish/啤酒鸭/啤酒鸭', '啤酒鸭', '荤菜', 4, 60, '这是一道风味独特的家常菜肴，鸭肉鲜香软烂，透着淡淡啤酒清香，热而不浮、香而不腻。鸭肉富含蛋白质，啤酒去腥增香，搭配食用更有滋味。做法对新手友好，从备料到出锅大约需要 1 小时。', '[{"name":"鸭肉","quantity":0.5,"unit":"只"},{"name":"啤酒","quantity":800,"unit":"ml"},{"name":"生抽酱油","quantity":10,"quantityMax":15,"unit":"ml"},{"name":"老抽酱油","quantity":5,"quantityMax":10,"unit":"ml"},{"name":"姜","quantity":5,"unit":"片"},{"name":"蒜","quantity":12,"unit":"瓣"},{"name":"冰糖","quantity":10,"unit":"克"},{"name":"干辣椒","quantity":5,"unit":"个"},{"name":"料酒","quantity":30,"unit":"ml"},{"name":"盐","quantity":8,"unit":"克"},{"name":"鸡精","quantity":5,"unit":"克"},{"name":"丁香","quantity":4,"unit":"颗"},{"name":"八角","quantity":3,"unit":"个"},{"name":"香叶","quantity":3,"unit":"片"},{"name":"豆瓣酱","quantity":20,"unit":"克"}]'::jsonb, '["把鸭子切成 3 cm 小块，鸭肉冷水下锅，加姜片、料酒，焯一遍水，盛出沥干水分，备用。","炒锅烧热，放入约 100ml 食用油，大火待油烧开，鸭肉入锅翻炒至上色。","待鸭肉完全变色（肉眼可见泛白），将鸭肉拨到锅的一边，倒入豆瓣酱和糖，小火翻炒出香味和糖色。","加入丁香、八角、香叶、干辣椒、生抽、老抽、蒜，翻炒出香味。","倒入啤酒，没过鸭肉，加入盐、鸡精，然后中火将鸭子烧 30 分钟（牙口不好的话可以再多烧 5 分钟）。","出锅盛盘，上桌食用。"]'::jsonb, '["荤菜","鲜香","炖","川菜","家常","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_a11a95bdd7.jpg', 'https://www.bilibili.com/video/BV1iHnnzHEbS', '{"energyKcal":480,"protein":28,"carbs":10,"fat":32}'::jsonb, '[null,null,null,null,1800,null]'::jsonb),
  ('howtocook:meat_dish/回锅肉/回锅肉', '回锅肉', '荤菜', 4, 40, '回锅肉是四川传统名菜，以二刀肉或五花肉为主料，成菜色泽红亮，肥肉透明微卷、瘦肉干香不柴，口感肥而不腻，咸鲜微辣，带有蒜苗与豆瓣酱的复合香气。猪肉富含优质蛋白和必需脂肪酸，搭配青红椒、蒜苗可补充维生素。这道菜步骤稍多，包含煮、切、煸炒，对火候和刀工有一定要求，但按流程操作新手也能成功，预计全程耗时约 40 分钟。', '[{"name":"五花肉","quantity":0.5,"unit":"斤"},{"name":"小葱","quantity":2,"unit":"棵"},{"name":"生姜","quantity":10,"quantityMax":40,"unit":"克"},{"name":"青红椒","quantity":0,"quantityMax":30,"unit":"克"},{"name":"蒜苗","quantity":1,"unit":"把"},{"name":"料酒","quantity":5,"unit":"ml"},{"name":"豆瓣酱","quantity":10,"unit":"ml"},{"name":"生抽酱油","quantity":5,"unit":"ml"},{"name":"味精","quantity":5,"unit":"克"}]'::jsonb, '["锅烧热，用手将五花肉紧紧压在锅上炙皮","这一步是为了处理猪皮上的汗腺（或者买肉的时候让师傅烧一下皮，喜欢汗腺的可以无视）","用钢丝球把皮刷干净，至黑色部分碳化部分被完全去除，不刷干净会有苦味","将五花肉放入锅中，放入能淹没五花肉的冷水，放入生姜片、料酒和小葱（取 2 棵小葱打结）","开大火煮，水开后撇去浮沫，继续煮 15 分钟，煮至瘦肉部分可以用筷子轻松刺穿","青红椒切圈","蒜苗切段","生姜切小薄片","将 5ml 豆瓣酱和 5ml 生抽提前混合","将煮熟的五花肉捞出放入冷水晾凉","擦干五花肉的水，切成上肥下瘦的 2mm 的薄片（切厚了口感不好，而且很油）","锅烧热，放入一层底油滑锅","放入五花肉煸炒至肥肉透明，肉片微卷（欲称起灯盏窝），二刀肉效果最佳。","倒入豆瓣生抽混合物，5g 味精翻炒 15 秒","放入青红椒圈和小姜片，放入另 5ml 豆瓣酱翻炒 30 秒","放入蒜苗翻炒 60 秒","出锅","选用冰冻五花肉常量放置 0.5 小时 或者鲜五花肉放冰箱冷藏 1 个小时，切成 2-5 mm 薄片","开中火，辣椒放过锅中干煸 30-45 秒后取出","锅烧热，放入一层底油滑锅，放入姜片煸炒 15 秒","倒入五花肉，间隔 10 S 翻炒一次，待五花肉出现焦黄色（翻炒时间越久五花肉口感越硬）","倒入之前干煸过的辣椒、10ml 豆瓣酱，生抽调味，继续翻炒 60 秒","倒入切成段的蒜苗翻炒 10 秒","出锅"]'::jsonb, '["荤菜","川菜","家常","下饭","炒制","咸鲜"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_ad8b6bcb4b.jpeg', 'https://www.bilibili.com/video/BV14Qt8eZEdh', '{"energyKcal":1300,"protein":20,"carbs":5,"fat":128}'::jsonb, '[null,null,null,null,900,null,null,null,null,null,null,null,null,15,30,60,null,1800,30,15,10,60,10,null]'::jsonb),
  ('howtocook:meat_dish/土豆炖排骨/土豆炖排骨', '土豆炖排骨', '荤菜', 3, 90, '排骨软烂脱骨，土豆绵软入味，酱香浓郁微甜微辣，是一道典型的北方家常炖菜。富含蛋白质、钙质和碳水化合物，营养均衡。制作略有难度，需掌握炒糖色与火候，但步骤清晰，新手也能尝试，全程大约 1.5 小时。', '[{"name":"肋排","quantity":750,"unit":"克"},{"name":"土豆","quantity":300,"unit":"克"},{"name":"姜","quantity":30,"unit":"克"},{"name":"小葱","quantity":25,"unit":"克"},{"name":"料酒","quantity":25,"unit":"ml"},{"name":"白糖","quantity":10,"unit":"克"},{"name":"干辣椒","quantity":5,"unit":"克"},{"name":"八角","quantity":1,"unit":"克"},{"name":"花椒","quantity":1,"unit":"克"},{"name":"桂皮","quantity":1,"unit":"克"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"老抽","quantity":5,"unit":"ml"},{"name":"蚝油","quantity":5,"unit":"ml"},{"name":"黄豆酱","quantity":5,"unit":"克"},{"name":"盐","quantity":3,"unit":"克"},{"name":"食用油","quantity":20,"unit":"ml"},{"name":"开水","quantity":700,"unit":"ml"}]'::jsonb, '["处理土豆： 将 300g 土豆去皮，切成不规则的滚刀块 。切好后立刻泡入一盆清水中，隔绝氧气防止表面氧化发黑，备用。","处理葱姜： 将 30g 姜全部切成薄片（分成两份 15g）。将 25g 小葱处理好：15g 挽成一个葱结，剩余 10g 切成细小葱花备用。","封装酱汁碗（一键调用）： 拿一个小碗，依次加入 10ml 生抽、5ml 老抽、5ml 蚝油、5ml 黄豆酱，彻底搅拌均匀，放在灶台触手可及处备用。","封装香料碟（一键调用）： 拿一个小碟，放入 5g 干辣椒、1g 八角（约 1-2 颗）、1g 花椒（约 10 粒）、1g 桂皮（一小块），以及刚才切好的 15g 姜片，备用。","开启异步水程： 按下电热水壶开关，开始烧制 700ml 开水。（确保炒制完成时，开水刚好就绪）。","冷水焯水： 将 750g 肋排冷水下锅，加入 15g 葱结、15g 姜片、15ml 料酒。大火煮沸后，继续保持沸腾焯水 2 分钟，逼出内部血沫。","热洗冷防： 捞出排骨，必须用热水将排骨表面残留的浮沫清洗干净（遇冷水肉质会剧烈收缩变硬）。","绝对脱水（防爆防溅）： 洗净的排骨必须用厨房纸彻底吸干表面水分，装盘放在炒锅旁边备用（防止后续下入高温糖色时发生剧烈炸锅）。","炒制糖色： 热锅凉油，加入 20ml 食用油。将 10g 白糖倒入锅中，中小火不停搅拌。翻炒至白糖完全融化冒泡，并呈现红棕色的焦糖色 。","上色煎制： 迅速加入彻底脱水的 750g 排骨，转中大火翻炒。煎制约 2-3 分钟，至排骨两面微微金黄，且均匀裹满焦糖色。","一键爆香： 在锅中拨出一小块空地，直接倒入【香料碟】。利用锅底的热油爆香约 10 秒，激发出香料的脂溶性香气。","一键调味： 顺着热锅边缘淋入剩余的 10ml 料酒激发出锅气。紧接着直接倒入【酱汁碗】，翻炒约 30 秒，让酱料完全包裹排骨并炒出浓郁酱香。","加水长炖： 此时电热水壶已沸腾，直接加入 700ml 滚烫的开水（水量需没过排骨），大火烧开。随后盖上锅盖，转小火持续焖煮 40 分钟。","加入土豆： 40 分钟后打开锅盖，将泡在水里的 300g 土豆捞出沥干，下入锅中。重新盖上锅盖，继续小火焖煮 15-20 分钟，直到用筷子能轻松扎透土豆块。","调味收汁： 打开锅盖，加入 3g 盐（此时可尝一下汤汁，根据个人口味酌情微调）。转大火开始翻炒收汁，大约需要 3-5 分钟。直到汤汁变得浓稠，均匀地挂在排骨和土豆上即可关火。","点缀出锅： 盛盘出锅，在表面均匀撒上预处理好的 10g 葱花作为 UI 点缀即可。"]'::jsonb, '["荤菜","酱香","微辣","炖","北方","下饭","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_44f6fc1432.jpg', 'https://www.bilibili.com/video/BV19z4y1S7iE', '{"energyKcal":790,"protein":44,"carbs":22,"fat":57}'::jsonb, '[null,null,null,null,null,120,null,null,null,120,10,30,2400,900,180,null]'::jsonb),
  ('howtocook:meat_dish/奶酪培根通心粉/奶酪培根通心粉', '奶酪培根通心粉', '荤菜', 3, 60, '奶酪培根通心粉是经典美式家常菜，口感浓郁绵密，奶酪包裹弹牙通心粉，搭配香脆培根，咸香满足。富含蛋白质与钙质，但热量和脂肪较高，建议偶尔享用。制作需要一定耐心，掌握基础白酱和火候对新手略有挑战，整体难度中等。不烘烤时约 30 分钟即可上桌，若选择烘烤需额外预热和烤制，总时长约 1 小时。', '[{"name":"通心粉","quantity":100,"quantityMax":125,"unit":"克"},{"name":"奶酪","quantity":40,"quantityMax":55,"unit":"克"},{"name":"奶酪（烘烤用）","quantity":25,"unit":"克"},{"name":"肉类","quantity":100,"quantityMax":125,"unit":"克"},{"name":"洋葱","quantity":25,"quantityMax":40,"unit":"克"},{"name":"黄油","quantity":15,"unit":"克"},{"name":"面粉","quantity":10,"unit":"克"},{"name":"牛奶","quantity":125,"unit":"ml"},{"name":"大蒜","quantity":0.5,"unit":"瓣"}]'::jsonb, '["奶酪要磨成碎末","洋葱切成条状","通心粉用微咸的水煮 6 分钟","中火","锅中放入黄油，等待融化","加入洋葱","洋葱软化后加入大蒜","大蒜香味出来后，加入肉类，等待 5 秒","小火","分四次加入牛奶，每次搅拌 5 秒后再加下一次","加入面粉并充分搅拌","加入奶酪并搅拌均匀","将通心粉和奶酪搅拌","如果不打算烘烤，可以直接吃了","烘烤：","预热烤箱至 180°C","将额外的 50g 芝士铺在通心粉之上","等待烤箱预热至 180°C 后，将通心粉放入","烤至表面金黄,约 24 分钟"]'::jsonb, '["荤菜","奶香","咸香","焗烤","美式","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_923b4e570e.jpg', 'https://www.bilibili.com/video/BV1g94y1x7Ej', null, '[null,null,360,null,null,null,null,5,null,5,null,null,null,null,null,null,null,null,1440]'::jsonb),
  ('howtocook:meat_dish/姜炒鸡/姜炒鸡', '姜炒鸡', '荤菜', 3, 60, '姜炒鸡是湖南风味的下饭菜肴，鸡肉干香入味，姜香浓郁，辣而不燥。鸡肉富含优质蛋白，生姜有助于驱寒暖胃、促进食欲。做法简单，新手也能轻松掌握。从腌制到出锅大约需要 1 小时。', '[{"name":"鸡","quantity":0.5,"unit":"只"},{"name":"生姜","quantity":250,"unit":"克"},{"name":"啤酒","quantity":250,"unit":"ml"},{"name":"生抽","quantity":20,"unit":"ml"},{"name":"老抽","quantity":10,"unit":"ml"},{"name":"盐","quantity":3,"unit":"克"},{"name":"小米椒","quantity":0,"quantityMax":5,"unit":"个"},{"name":"美人辣","quantity":0,"quantityMax":5,"unit":"个"},{"name":"泡椒","quantity":5,"unit":"个"},{"name":"大蒜","quantity":3,"unit":"头"}]'::jsonb, '["鸡尽量剁成 1cm 的小块，洗净后滤干，再放生抽腌和料酒腌制 30 分钟","大先热锅到微微冒烟，放入食用油，等 5 秒","下入姜片后转中火炒 30 秒，","下入鸡块翻炒 3 分钟，炒干水分，炒出鸡油","放入各种剁碎的辣椒和大蒜子，加盐和老抽继续翻炒 30 秒","倒入啤酒，中小火焖 2 分钟","大火收汁盛盘"]'::jsonb, '["荤菜","湖南风味","下饭菜","香辣","炒","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_955959dbd3.jpg', 'https://www.bilibili.com/video/BV1c5411w7Du', '{"energyKcal":700,"protein":45,"carbs":15,"fat":45}'::jsonb, '[1800,5,30,180,30,120,null]'::jsonb),
  ('howtocook:meat_dish/姜葱捞鸡/姜葱捞鸡', '姜葱捞鸡', '荤菜', 3, 40, '姜葱捞鸡是一道粤式经典家常菜，鸡肉嫩滑多汁，葱姜香气浓郁，咸鲜适口，十分下饭。鸡腿肉提供优质蛋白质，搭配姜葱能温中散寒、促进食欲。整体操作以蒸制和手撕为主，步骤清晰，对新手来说比较容易上手。从备料到完成大约需要 40 分钟。', '[{"name":"鸡腿肉","quantity":4,"unit":"个"},{"name":"盐焗鸡粉","quantity":5,"unit":"克"},{"name":"姜","quantity":50,"unit":"克"},{"name":"葱","quantity":1,"unit":"根"},{"name":"盐","quantity":5,"unit":"克"},{"name":"糖","quantity":5,"unit":"克"},{"name":"油","quantity":35,"unit":"ml"}]'::jsonb, '["四个鸡腿清洗干净，放入碗中","碗中加入盐焗鸡粉和 5ml 油，搅拌均匀","让鸡腿静置腌制 15 分钟， 同时准备蒸锅并把水煮开","鸡腿腌制完成后， 放入水开后的蒸锅中，蒸制 20 分钟","将姜根据个人口味切成 1）姜蓉或 2）姜丝或 3）姜粒","将葱切成 0.5cm 小段","将葱姜放入蘸料碗，并加入盐和糖","将剩余的油倒入另一个锅中加热至六至七层热","将热油淋入葱姜碗中","鸡腿蒸好后将其撕碎成鸡丝，不需要特别细，大概 1cm 粗就可以","姜葱姜油淋在鸡丝上，搅拌均匀即可"]'::jsonb, '["荤菜","粤式","蒸制","手撕","咸鲜","下饭","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_0463bef7e8.jpg', 'https://www.bilibili.com/video/BV1F34y1J7WV', '{"energyKcal":1300,"protein":100,"carbs":15,"fat":80}'::jsonb, '[null,null,900,1200,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/孜然牛肉', '孜然牛肉', '荤菜', 3, 45, '孜然牛肉是一道香辣鲜嫩的家常小炒，浓郁的孜然风味与牛肉的软滑、青椒的清脆融合得恰到好处。牛肉富含优质蛋白和铁，搭配青椒还能补充维生素，营养均衡。制作需要一些刀工和火候把控，适合有一定下厨基础的爱好者尝试。算上腌肉和备菜，全程大约 45 分钟就能端上餐桌。', '[{"name":"牛柳或牛肩肉","quantity":250,"unit":"g"},{"name":"青椒","quantity":2,"unit":"颗"},{"name":"孜然","quantity":20,"unit":"g"},{"name":"小米椒","quantity":3,"unit":"颗"},{"name":"生抽酱油","quantity":20,"unit":"ml"},{"name":"淀粉","quantity":10,"unit":"g"},{"name":"油","quantity":15,"unit":"ml"},{"name":"盐","quantity":3,"unit":"g"},{"name":"葱","quantity":1,"unit":"根"}]'::jsonb, '["首先将小米椒切碎，和孜然粒一起放入捣药罐捣碎成颗粒，这样更入味。如果时间紧张可跳过捣碎步骤","青椒切头去籽（喜欢辣的可不去），切成丝。葱切段。","牛肉提前解冻，过一边水洗干净，晾干或用厨用纸吸干，将牛肉顺着纹理切成片","然后进行腌肉，加入生抽，淀粉，油，均匀搅拌，静止 30 分钟。腌肉方法也可参考学习腌","热锅下油，放入葱，爆出香味后放入腌好的牛肉煸炒","牛肉变色后均匀放入孜然辣椒颗粒并炒熟","然后下入青椒丝，断生后放盐","大🔥炒 1 分钟后关火再翻炒 30 秒保证受热均匀即可出锅"]'::jsonb, '["荤菜","香辣","家常","小炒","下饭","孜然"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_ff722e2419.jpg', 'https://www.bilibili.com/video/BV1pf4y1r7Ma', '{"energyKcal":525,"protein":54,"carbs":9,"fat":28}'::jsonb, '[null,null,null,1800,null,null,null,90]'::jsonb),
  ('howtocook:meat_dish/宫保鸡丁/宫保鸡丁', '宫保鸡丁', '荤菜', 4, 90, '这道川味名菜以糊辣荔枝味见长，小酸甜中透着干辣椒与花椒的香气，鸡丁嫩滑、花生酥脆，口感层次丰富。富含优质蛋白和不饱和脂肪酸，开胃下饭。做法分成简易和进阶两版，对新手比较友好，提前规划好腌制时间即可。从备料到出锅大约需要 1.5 小时。', '[{"name":"手枪腿（或者鸡胸脯肉）","quantity":1,"unit":"支"},{"name":"大葱","quantity":1,"unit":"根"},{"name":"姜片","quantity":10,"unit":"克"},{"name":"干辣椒","quantity":10,"unit":"克"},{"name":"二荆条","quantity":4,"unit":"支"},{"name":"熟花生","quantity":150,"unit":"克"},{"name":"生花生","note":"适量"},{"name":"花椒","quantity":5,"unit":"克"},{"name":"生抽酱油","quantity":10,"unit":"克"},{"name":"老抽酱油","quantity":5,"unit":"克"},{"name":"香醋","quantity":5,"unit":"克"},{"name":"白糖","quantity":2,"unit":"克"},{"name":"料酒","quantity":15,"unit":"克"},{"name":"盐","quantity":2,"unit":"克"},{"name":"鸡精","quantity":2,"unit":"克"},{"name":"淀粉","quantity":15,"unit":"克"},{"name":"淀粉（勾芡用）","quantity":10,"unit":"克"},{"name":"植物油","quantity":20,"unit":"克"},{"name":"芝麻油","quantity":10,"unit":"克"},{"name":"豆瓣酱","quantity":10,"unit":"克"},{"name":"莴笋","quantity":250,"unit":"克"},{"name":"油泼辣子","quantity":5,"unit":"克"},{"name":"开水","quantity":50,"unit":"克"},{"name":"清水","quantity":50,"unit":"克"}]'::jsonb, '["手枪腿用剪刀去骨，鸡肉面用刀背拍打一遍，切条后切至 1.5cm 见方肉丁；泡于清水 10 分钟，捞出控干备用（若是鸡胸脯肉，则可以直接进行切丁以及之后的动作）","取大葱葱绿与姜片 5g 于碗中，倒入 50g 开水备用；葱白切 1.5cm 圆粒备用；取花生放入微波炉高火 5 分钟焙干备用","鸡丁中加入盐 2g，老抽酱油 5g，料酒 15g，淀粉 15g 搅拌均匀，至微微发干；缓慢加入部分葱姜水，搅拌鸡丁至粘手；保鲜膜密封，放入冰箱腌制 1 小时","干辣椒切段；起锅，大火烧热转小火；放入干辣椒焙干至微微发糊，捞起备用；花椒焙干至有香味，捞起备用","转大火，倒入 20g 植物油，7 成热（竹筷子起泡）下入鸡丁，煎至上面开始发白，用锅铲翻面，煎 30s 后翻炒均匀","下入葱粒翻炒，加入余下葱姜水不够 100g 再加一点清水（务必是热水）；盖上锅盖，转中小火焖 2 分钟；","转大火，下入熟花生，干辣椒和花椒；加入鸡精 2g，香醋 5g，白糖 2g，翻炒均匀；","淀粉 10g 加 50g 清水调成水淀粉，加入锅中，翻炒均匀，收汁到自己想要的浓度","关火，淋入芝麻油 10g，即可出锅","莴笋去皮切至 1cm 见方的小块，备用；","二荆条切成 1cm 长段；","手枪腿用剪刀去骨，鸡肉面用刀背拍打一遍，切条后切至 1.5cm 见方肉丁；泡于清水 10 分钟，捞出控干备用（若是鸡胸脯肉，则可以直接进行切丁以及之后的动作）；","取大葱葱绿与姜片 5g 于碗中，倒入 50g 开水备用；葱白切 1.5cm 圆粒备用","鸡丁中加入盐 2g，老抽酱油 5g，料酒 15g，淀粉 15g 搅拌均匀，至微微发干；缓慢加入部分葱姜水，搅拌鸡丁至粘手；保鲜膜密封，放入冰箱腌制 1 小时","转中火，倒入 20g 植物油，放入生花生翻炒至其表面微微焦糊，捞起花生但是油留在锅内；","继续加热，7 成热（竹筷子起泡）下入鸡丁，放入豆瓣酱，翻炒大概 1 分钟；","加入备好的莴笋丁，继续翻炒 1 分钟；","下入葱粒翻炒，加入余下葱姜水不够 100g 再加一点清水（务必是热水）；加入二荆条段；盖上锅盖，转中小火焖 2 分钟；","转大火，下入先前捞起来备用的花生，花椒；加入鸡精 2g，香醋 5g，白糖 2g，翻炒均匀；","淀粉 10g 加 50g 清水调成水淀粉，加入锅中，翻炒均匀，收汁到自己想要的浓度","关火，淋入芝麻油 10g 与油泼辣子 5g 再翻炒 10s，即可出锅"]'::jsonb, '["荤菜","川菜","麻辣","酸甜","下饭","炒制","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_e6de330666.jpg', 'https://www.bilibili.com/video/BV1NMXTYKE6M', '{"energyKcal":500,"protein":23,"carbs":21,"fat":39}'::jsonb, '[600,300,3600,null,30,120,null,null,null,null,null,600,null,3600,60,60,60,120,null,null,10]'::jsonb),
  ('howtocook:meat_dish/小炒肉', '小炒肉', '荤菜', 3, 60, '小炒肉是一道香辣下饭的经典湘式家常菜，五花肉片焦香不腻，搭配鲜辣椒与豆豉、豆瓣酱炒出浓郁酱香。富含优质蛋白质和脂肪，辣椒能提供丰富的维生素 C，有助开胃暖身。制作难度中等，适合有一定基础的新手尝试，需注意肉片腌制和火候把控。从备料到出锅大约需要 1 小时，其中腌制 30 分钟，炒制过程约 15 分钟。', '[{"name":"五花肉","quantity":500,"unit":"g"},{"name":"朝天椒","quantity":4,"unit":"条"},{"name":"小米椒","quantity":4,"unit":"颗"},{"name":"豆豉","quantity":10,"unit":"g"},{"name":"豆瓣酱","quantity":10,"unit":"g"},{"name":"老抽","quantity":10,"unit":"ml"},{"name":"淀粉","quantity":10,"unit":"g"},{"name":"盐","quantity":1,"quantityMax":2,"unit":"g"},{"name":"葱","quantity":0.5,"quantityMax":1,"unit":"根"},{"name":"蒜","quantity":2,"unit":"瓣"},{"name":"食用油","quantity":15,"unit":"ml"}]'::jsonb, '["五花肉切片","把肉放入器皿内，加入淀粉、老抽、盐搅拌腌制半小时","葱切段","小米椒、朝天椒斜刀切好","热锅、倒油","油热后加入五花肉煸炒。炒至变色后盛出来","向锅中加蒜，煸出香味，加入豆豉，翻炒均匀","加入豆瓣酱翻炒均匀","加入炒好的五花肉继续的翻炒均匀","加入小米椒、朝天椒、葱段翻炒 40 秒","出锅。"]'::jsonb, '["荤菜","香辣","下饭","家常","湘式","小炒","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_50c18036df.jpg', 'https://www.bilibili.com/video/BV1UW4y1e7fB', '{"energyKcal":780,"protein":38,"carbs":12,"fat":62}'::jsonb, '[null,1800,null,null,null,null,null,null,null,40,null]'::jsonb),
  ('howtocook:meat_dish/小炒鸡肝/小炒鸡肝', '小炒鸡肝', '荤菜', 3, 40, '这道鸡肝小炒蒜香浓郁，口感嫩滑带点孜然的焦香，是一道家常风味小炒。鸡肝富含铁、维生素 A 和优质蛋白，有助补血明目。制作时需掌握焯水去腥的技巧，对新手略有挑战，从备料到出锅大约需要四十分钟。', '[{"name":"生鸡肝","quantity":5,"unit":"个"},{"name":"蒜苗","quantity":200,"unit":"克"},{"name":"大葱","quantity":150,"unit":"克"},{"name":"姜","quantity":120,"unit":"克"},{"name":"料酒","quantity":30,"unit":"ml"},{"name":"食用盐","quantity":5,"unit":"克"},{"name":"鸡精（味精）","quantity":5,"unit":"克"},{"name":"五香粉（十三香）","quantity":5,"unit":"克"},{"name":"胡椒粉","quantity":5,"unit":"克"},{"name":"烧烤料或孜然粉","quantity":10,"unit":"克"},{"name":"芝麻","quantity":5,"unit":"克"},{"name":"食用油","quantity":30,"unit":"ml"}]'::jsonb, '["鸡肝清洗，备用","蒜苗清洗，切段，备用","大葱清洗，取 100g 切段，取 50g 切片，备用","姜清晰，取 70g 切片， 取 50g 切丁，备用","第一步：焯水","清洗后的鸡肝放入锅内，加入凉水淹没鸡肝，并放入 100g 切段的大葱、70g 切片的姜和 30ml 料酒","开大火，待水沸腾调至中火并撇去浮沫后等待5-10分钟","关火，捞出过凉水并清洗干净","清洗干净后切片，备用","第二步：炒制","开中火。锅内加入 30ml 食用油，等待 10 秒使油升温","加入 50g 切片的大葱和 50g 切丁的姜，翻炒爆香","爆香后加入切片的鸡肝，翻炒至微微发黄","加入蒜苗，翻炒 30 秒，断生后调至为小火","加入调味料","食用盐 5g","鸡精（味精） 5g","五香粉（十三香） 5g","胡椒粉 5g","烧烤料或 10g （可选）","调至为大火，快速翻炒 30 秒防止糊锅，关火","盛出盘内，可以撒入 5g 芝麻作为装饰，如果不喜欢或者没有则可以不用添加。"]'::jsonb, '["荤菜","家常","蒜香","孜然","爆炒","下饭","补血"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_324bdf72ee.jpg', 'https://www.bilibili.com/video/BV1aR4y1M7Sd', '{"energyKcal":580,"protein":36,"carbs":22,"fat":34}'::jsonb, '[null,null,null,null,null,null,null,null,null,null,10,null,null,30,null,null,null,null,null,null,30,null]'::jsonb),
  ('howtocook:meat_dish/小炒黄牛肉/小炒黄牛肉', '小炒黄牛肉', '荤菜', 4, 60, '这道湘味小炒以大火爆炒逼出牛肉的嫩滑与椒香，口感鲜辣劲爽、芹菜脆嫩，极具湖南风味。牛里脊提供优质蛋白和易吸收的铁质，搭配芹菜增添膳食纤维，营养均衡。备料与烹饪步骤简单明了，全程旺火快炒，对新手十分友好，从切配到出锅大约一小时即可完成。', '[{"name":"牛里脊","quantity":400,"unit":"克"},{"name":"芹菜","quantity":200,"unit":"克"},{"name":"小米椒","quantity":30,"unit":"克"},{"name":"野山椒","quantity":30,"unit":"克"},{"name":"香菜","quantity":30,"unit":"克"},{"name":"食用油","quantity":15,"unit":"ml"},{"name":"酱油","quantity":6,"unit":"ml"}]'::jsonb, '["牛里脊切成不超过 3cm 宽，3mm 厚的薄片，倒入 6ml 酱油，用手抓匀备用","芹菜切成不超过 5cm 的小段，备用","小米椒切成丝状，备用","野山椒切成颗粒，备用","香菜切成成不超过 3cm 的小段，备用","热锅，锅内放入 15ml 食用油，大火等待 30 秒让油温升高","放入小米椒和野山椒爆香","放入牛里脊和芹菜，然后大火翻炒 1 分钟","关火，撒上香菜，盛盘"]'::jsonb, '["荤菜","湘菜","鲜辣","爆炒","下饭","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_47492b1cae.jpg', 'https://www.bilibili.com/video/BV1ri4y1S7E5', '{"energyKcal":360,"protein":41,"carbs":9,"fat":14}'::jsonb, '[null,null,null,null,null,30,null,60,null]'::jsonb),
  ('howtocook:meat_dish/小米辣炒肉', '小米辣炒肉', '荤菜', 3, 25, '小米辣炒肉香辣过瘾，是一道典型的西南风味下饭菜，猪肉的鲜嫩搭配小米辣的爽辣，令人食欲大开。猪肉富含蛋白质和脂肪，辣椒提供丰富的维生素 C，能够促进食欲。虽然需要掌握爆香和翻炒的火候，但步骤清晰，新手也能轻松上手，预计制作时长约 25 分钟。注意，这道菜辣味突出，不建议清淡饮食者尝试。', '[{"name":"小米辣","quantity":20,"unit":"个"},{"name":"花生油","quantity":20,"unit":"ml"},{"name":"五花肉/瘦肉","quantity":200,"unit":"克"},{"name":"盐","quantity":1,"quantityMax":2,"unit":"克"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"蚝油","quantity":10,"unit":"ml"},{"name":"大蒜","note":"适量"},{"name":"姜","note":"适量"},{"name":"豆瓣酱","quantity":10,"unit":"克"},{"name":"鸡精","quantity":10,"unit":"克"},{"name":"白糖","quantity":5,"unit":"克"}]'::jsonb, '["将小米辣洗净，斜刀切大一点","肉的话，想切丝切丝，想切片切片，倒入调料（生抽、蚝油、盐）腌制 5 分钟","热锅倒油，先把肉炒好盛起","姜蒜爆香，倒入豆瓣酱翻炒，到入切好的小米辣，再倒入瘦肉，翻炒一下，放点生抽、鸡精、盐、糖翻炒"]'::jsonb, '["荤菜","香辣","川菜","下饭菜","家常","炒制"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_9b29d53d57.jpg', 'https://www.bilibili.com/video/BV1RW4y1e7xS', '{"energyKcal":520,"protein":24}'::jsonb, '[null,300,null,null]'::jsonb),
  ('howtocook:meat_dish/小酥肉', '小酥肉', '荤菜', 3, 90, '小酥肉外酥里嫩，咸香中带着花椒的微麻，是川渝地区家家户户都会做的家常炸物。猪肉富含蛋白质和脂肪，油炸后热量较高，适合偶尔解馋。这道菜步骤稍多，需掌握初炸定型与复炸上色的火候，对新手略有挑战，预计从头到尾约 1 小时 30 分钟完成。', '[{"name":"去皮猪肉","quantity":500,"unit":"克"},{"name":"植物油","note":"适量"},{"name":"老姜","quantity":20,"unit":"克"},{"name":"小葱","quantity":15,"unit":"克"},{"name":"料酒","quantity":15,"unit":"克"},{"name":"盐","quantity":4,"unit":"克"},{"name":"十三香","quantity":2,"unit":"克"},{"name":"胡椒粉","quantity":3,"unit":"克"},{"name":"味精","quantity":5,"unit":"克"},{"name":"鸡精","quantity":5,"unit":"克"},{"name":"花椒碎","quantity":3,"unit":"克"},{"name":"花椒粒","quantity":3,"unit":"克"},{"name":"生抽","quantity":8,"unit":"克"},{"name":"鸡蛋","quantity":2,"unit":"个"},{"name":"面粉","quantity":30,"unit":"克"},{"name":"红薯淀粉","quantity":120,"unit":"克"}]'::jsonb, '["老姜切丝,小葱不用切。","根据计算公式倒入料酒、清水。","用手捏揉 5 分钟，使姜葱的味道充分溶解在水中。","将猪肉去皮洗净","切成长度 8~10 厘米，厚度 1.5 厘米的肉条。","根据上面的计算公式加入盐，十三香、胡椒粉、味精、鸡精、花椒碎、花椒粒、生抽。","倒入前面制作好的葱姜水","抓匀并且充分揉制 10 分钟，直至肉吸收所有水分并且变得粘手。","封上保鲜膜放冷藏室静置 30 分钟。","将面粉、红薯粉倒入腌制好的肉中，加入鸡蛋清。","充分揉制 15 分钟。","锅中倒入植物油，根据锅大小控制油量，油面高度 3 厘米以上。","大火将温加热至 150° 后，转小火保持温度。","将裹好粉的肉条用筷子夹入油锅中，捋成自己喜欢的形状，炸 3~5 分钟定型。目测颜色微黄，用锅铲翻动感受倒略微有些硬了就可以。具体时间受肉块大小、油温、裹粉程度影响。","捞出沥油。","将油温升至 180° 放入初炸好的肉条，炸至金黄色即可捞出。"]'::jsonb, '["荤菜","咸香","微麻","川渝","油炸","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_1d3be67ca4.jpg', 'https://www.bilibili.com/video/BV1Zj411F7B8', '{"energyKcal":1900,"protein":110}'::jsonb, '[null,null,300,null,null,null,null,600,1800,null,900,null,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/尖叫牛蛙/尖叫牛蛙', '尖叫牛蛙', '荤菜', 4, 45, '这道菜鲜辣开胃，蛙肉滑嫩弹牙，是一道典型的川味家常菜。牛蛙本身高蛋白、低脂肪，搭配泡姜泡椒等发酵食材，有助于促进食欲。做法相对直接，但油温控制和调味比例需要稍加留意，一般初学者也能在 1 到 2 小时内完成。', '[{"name":"牛蛙肉","quantity":800,"unit":"克"},{"name":"泡姜","quantity":20,"quantityMax":30,"unit":"克"},{"name":"泡椒","quantity":5,"quantityMax":10,"unit":"克"},{"name":"野山椒","quantity":10,"unit":"克"},{"name":"青红辣椒","quantity":20,"unit":"克"},{"name":"大蒜","quantity":30,"quantityMax":50,"unit":"克"},{"name":"豆瓣酱","quantity":20,"quantityMax":30,"unit":"克"},{"name":"盐巴","quantity":15,"unit":"克"},{"name":"胡椒粉","quantity":10,"unit":"克"},{"name":"生粉","quantity":30,"unit":"克"},{"name":"啤酒","quantity":400,"quantityMax":500,"unit":"ml"},{"name":"料酒","quantity":10,"unit":"ml"},{"name":"藤椒油","quantity":5,"quantityMax":10,"unit":"ml"},{"name":"猪油","quantity":20,"unit":"ml"},{"name":"食用油","quantity":200,"unit":"ml"},{"name":"葱花","quantity":5,"unit":"克"}]'::jsonb, '["牛蛙肉洗净后控干水分，加入 10 克以上的盐巴和 50ml 以上的啤酒，用手抓 5 分钟，去除牛蛙肉的腥味","然后对着清水冲洗，直至不再流出血水和杂质，控干水分，放到合适的器皿中，准备腌制","加入 5 克盐，30 克生粉，10ml 料酒，5 克胡椒粉，用手抓均匀，腌制 5-10 分钟","将泡姜 泡椒 野山椒 切丝或者片（根据自己刀工选择），青红辣椒切成圈圈 大蒜拨开即可","起锅烧热，加入 200ml 食用油（锅底比较平的可以再加 100ml）,烧至 6 成油温（有小气泡出现），将腌制好的牛蛙倒入，快速过油炸制，10 秒钟后捞出（不能超时太多，否则会导致蛙肉老柴）","捞出蛙肉后，控油，并将锅中的热油倒出到碗中，保留 30ml,加入 20ml 猪油（如果没有，则在锅中保留总共 50ml 食用油）","待油温 6 成热，加入泡姜、泡椒、野山椒、大蒜，超出香味，加入豆瓣酱 20 克，中火翻炒至出红油（时间控制在 30 秒），倒入 400ml 啤酒，","然后倒入炸过的牛蛙肉，用勺子推着翻，不要用力搅拌，加入 5 克胡椒粉，加入 5ml 藤椒油，中火慢焖 3 分钟","加大火力，大火收汁半分钟，加入青红辣椒圈，再煮 10 秒准备起锅","盛到盆里，撒上葱花，可以开动了！"]'::jsonb, '["荤菜","鲜辣","川味","下饭","家常","开胃"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_c7652ed75d.jpg', 'https://www.bilibili.com/video/BV13x4y1G7GM', '{"energyKcal":450,"protein":34,"carbs":14,"fat":20}'::jsonb, '[300,null,300,null,10,null,30,180,40,null]'::jsonb),
  ('howtocook:meat_dish/尖椒炒牛肉', '尖椒炒牛肉', '荤菜', 3, 60, '一道家常小炒，咸香微辣，牛肉滑嫩入味，尖椒清脆爽口。牛肉提供优质蛋白和铁，尖椒富含维生素 C，搭配起来营养均衡。虽然腌制需要一些耐心，但操作步骤明确，新手也能上手，难度适中。从备料到出锅大约需要 1 小时。', '[{"name":"牛肉","quantity":250,"unit":"g"},{"name":"葱","quantity":0.5,"unit":"根"},{"name":"姜","quantity":1,"unit":"个"},{"name":"蒜","note":"适量"},{"name":"尖椒","note":"适量"},{"name":"酱油","quantity":9,"unit":"ml"},{"name":"盐","quantity":3,"unit":"g"},{"name":"糖","quantity":1.5,"unit":"g"}]'::jsonb, '["蒜剁成蒜泥","葱切段","姜切成姜片","尖椒切成段","牛肉放入碗中","加姜、盐、酱油、糖进行腌制 30-40 分钟","腌制完姜可以去掉","冷油下锅，待油变热至偶有气泡","加入蒜泥","蒜泥变金黄后加入尖椒","待尖椒表皮微皱，加入腌制好的牛肉翻炒","翻炒变熟之前加入葱，继续翻炒","翻炒至牛肉变熟，关火出锅"]'::jsonb, '["荤菜","咸香","微辣","爆炒","家常","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_541c03ee8d.jpg', 'https://www.bilibili.com/video/BV1um4y127BX', '{"energyKcal":730,"protein":52,"carbs":6,"fat":15}'::jsonb, '[null,null,null,null,null,1800,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/山西过油肉', '山西过油肉', '荤菜', 4, 40, '过油肉是山西传统名菜，肉片滑嫩、蒜苔爽脆，咸鲜微酸，带着陈醋的醇香，属于典型的地方家常风味。猪里脊提供优质蛋白，搭配木耳、蒜苔和葱头，营养均衡。这道菜对火候和上浆技巧有一定要求，更适合有一定下厨基础的爱好者尝试。从备料到出锅，大约需要 40 分钟。', '[{"name":"猪里脊","quantity":150,"unit":"克"},{"name":"蒜苔","quantity":6,"unit":"根"},{"name":"盐","quantity":10,"unit":"克"},{"name":"生抽","quantity":20,"unit":"ml"},{"name":"葱姜蒜","quantity":50,"unit":"克"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"淀粉","quantity":10,"unit":"克"},{"name":"食用油","quantity":300,"unit":"ml"},{"name":"木耳","quantity":20,"unit":"克"},{"name":"葱头","quantity":100,"unit":"克"},{"name":"料酒","note":"适量"},{"name":"陈醋","quantity":10,"unit":"ml"},{"name":"花椒粉","note":"适量"},{"name":"鸡精","note":"适量"}]'::jsonb, '["木耳提前泡发好，如果着急可以用热水泡发。","猪里脊切片放入碗中，加 20ml 生抽、料酒、花椒粉，打入一个鸡蛋，拿自己的小手搅拌均匀，加入淀粉（建议红薯淀粉）拌匀，倒入 300ml 食用油封浆，腌制 15 分钟。","蒜苔切段大约 3cm，葱头切菱形块备用。","起锅烧油油要多一点，油温五成热，下入腌制好的肉片，将肉片打散，捞出控油备用。","将锅中多余油倒出，留 10ml 油炒菜，油温七成热","下入葱姜蒜爆香，先下蒜苔炒至断生，再下入木耳葱头，加入生抽，花椒粉，翻炒几下将之前炸好的肉片下入翻炒","加 10g 的盐，起锅前加 10ml 的醋和鸡精，起锅装盘。"]'::jsonb, '["荤菜","山西菜","家常","下饭","鲜香","滑炒","咸鲜微酸"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_2097e7c1b0.jpg', 'https://www.bilibili.com/video/BV1jf4y1e7vT', null, '[null,900,null,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/巴基斯坦牛肉咖喱/巴基斯坦牛肉咖喱', '巴基斯坦牛肉咖喱', '荤菜', 5, 150, '这道巴基斯坦风味咖喱牛肉香浓软糯，酸辣开胃，带着浓郁的香料气息。牛肉提供优质蛋白，搭配番茄和酸奶，营养均衡。做法不算繁琐，但慢炖需要一点耐心，很适合在闲暇的周末从容准备。从头到尾大约两个半小时，就能端出一锅温暖的异国美味。', '[{"name":"牛肉","quantity":1,"unit":"kg"},{"name":"番茄","quantity":4,"unit":"个"},{"name":"螺丝椒","quantity":2,"unit":"个"},{"name":"原味酸奶","quantity":1,"unit":"盒"},{"name":"Masala 粉（品牌可选 Shan）","quantity":50,"unit":"克"},{"name":"蒜粉","quantity":5,"unit":"克"},{"name":"姜粉","quantity":5,"unit":"克"},{"name":"油","note":"适量"},{"name":"水","quantity":250,"unit":"ml"}]'::jsonb, '["全部螺丝椒切成段状，备用","全部番茄打成番茄蓉，备用","牛肉切成 2cm 的小块，洗净备用","炒锅中倒入一层油（用来防止番茄蓉沸腾蒸发）","倒入番茄蓉，持续搅拌 2-3 分钟，等待它越变越红","加入 5g 蒜粉，5g 姜粉和 1 包 50g 的 Masala 粉，搅拌均匀","加入牛肉和螺丝椒段，搅拌均匀","加入 1 盒酸奶（为了让整个酱汁变得粘稠），搅拌均匀","将整锅材料转移到电饭煲/电炖锅，并加入 250 ml 的水，开启炖肉/慢炖档，设定时间 2-3 个小时","等待完成，开锅检查牛肉软糯，就可以吃了"]'::jsonb, '["荤菜","香辣","慢炖","巴基斯坦","下饭菜","周末"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_75750fe193.png', 'https://www.bilibili.com/video/BV1GY4y1z7TC', '{"energyKcal":580,"protein":42,"carbs":10,"fat":41}'::jsonb, null),
  ('howtocook:meat_dish/带把肘子', '带把肘子', '荤菜', 5, 210, '带把肘子是陕西大荔的传统名菜，因脚爪形似把柄而得名。成菜肘皮胶粘软糯，肉质酥烂不腻，蘸甜面酱佐葱段食用，咸香醇厚。富含胶原蛋白和优质蛋白质，滋补养颜。制作需去骨、定形、长时间蒸制，对新手有一定挑战，预计整个制作过程约需 3.5 小时。', '[{"name":"带脚、爪猪前肘","quantity":1250,"unit":"克"},{"name":"红豆腐乳","quantity":10,"unit":"克"},{"name":"甜面酱","quantity":150,"unit":"克"},{"name":"精盐","quantity":15,"unit":"克"},{"name":"红酱油","quantity":35,"unit":"克"},{"name":"白酱油","quantity":25,"unit":"克"},{"name":"料酒","quantity":25,"unit":"克"},{"name":"蒜片","quantity":50,"unit":"克"},{"name":"姜末","quantity":10,"unit":"克"},{"name":"八角","quantity":3,"unit":"个"},{"name":"桂皮","quantity":5,"unit":"克"},{"name":"葱","quantity":200,"unit":"克"}]'::jsonb, '["将肘子刮洗干净，肘头朝外、肘把（脚爪）朝里、肘皮朝下放在案板上。","用刀在正中由肘头向肘把沿着腿骨将皮剖开，剔去腿骨两边的肉（三面离肉），底部骨与肉相连，使骨头露出，然后将两节腿骨由中间用刀背（还是用斧头吧）砸断。","肘子放入煮锅煮至七成熟捞出（外观正常，内部淡红色），用干净抹布擦干水，趁热用红酱油涂抹肉皮。","取蒸锅一个，锅底放入八角、桂皮，先将肘把的关节处用手掰断，不伤外皮，再将肘皮朝下装进蒸锅内，装锅时根据肘子体型，将肘把贴住锅边窝着装进锅内，成为圆形。","撒入精盐，用消过毒的干净纱布盖在肉上，再将甜面酱（50 克）、葱（75 克）、红豆腐乳、红酱油、白酱油、姜、蒜等在纱布上抹开，用旺火蒸大约三小时（以蒸烂为准）。","蒸完取出，揭去纱布，扣入盘中，拣去八角，上桌时另带葱段和甜面酱小碟（或将甜面酱抹到肘面上，另带葱段小碟亦可）。"]'::jsonb, '["荤菜","咸香","蒸","陕西","大荔","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_966b13765e.jpg', 'https://www.bilibili.com/video/BV1NG4y1w7GM', '{"energyKcal":520,"protein":36}'::jsonb, '[null,null,null,null,10800,null]'::jsonb),
  ('howtocook:meat_dish/干煸仔鸡/干煸仔鸡', '干煸仔鸡', '荤菜', 4, 60, '这是一道源自北大食堂、甜辣风味的创新川菜，鸡肉先腌后炸，外酥里嫩，土豆香糯，青椒脆爽，裹满红亮的甜辣酱汁，咸甜微辣十分开胃。富含蛋白质、碳水化合物及维生素。制作涉及油炸和酱汁熬制，对新手稍有挑战，但按步骤操作即可成功，全程约需 1 小时。', '[{"name":"鸡腿肉","quantity":400,"unit":"g"},{"name":"土豆","quantity":200,"unit":"g"},{"name":"青椒","quantity":60,"unit":"g"},{"name":"蒜瓣","quantity":10,"unit":"g"},{"name":"盐","quantity":3,"unit":"g"},{"name":"鸡精","quantity":3,"unit":"g"},{"name":"胡椒粉","quantity":2,"unit":"g"},{"name":"生抽","quantity":5,"unit":"g"},{"name":"老抽","quantity":2,"unit":"g"},{"name":"料酒","quantity":5,"unit":"g"},{"name":"淀粉","quantity":20,"unit":"g"},{"name":"郫县红油豆瓣酱","quantity":40,"unit":"g"},{"name":"白糖","quantity":30,"unit":"g"},{"name":"花椒碎","quantity":2,"unit":"g"},{"name":"清水","quantity":40,"unit":"ml"},{"name":"食用油","quantity":5,"unit":"ml"}]'::jsonb, '["鸡腿去骨（如使用鸡腿排可忽略此步骤），鸡腿肉用刀背砸一砸，切成 2cm 的块。","鸡腿肉中加入盐、鸡精（可选）、胡椒粉、生抽、老抽、料酒，抓拌至粘手时加入淀粉拌匀，加入食用油防止粘连，腌制 30 分钟。","土豆去皮，切成 2cm 的块，沸水煮 5 分钟后捞出，控干水分，防止油炸时爆锅。","青椒去籽，切成 2cm 小片，放在笊篱中备用。","锅中加入宽油（根据锅的形状，能没过食材即可），油温烧至 180℃ 时，下入土豆块炸 3 分钟后捞出。","待油温再次升高到 180℃时，下入鸡块炸 2 分钟后捞出。","待油温再次升高到 180℃时，下入鸡块复炸 1 分钟后捞出。","待油温再次升高到 180℃时，下入土豆块复炸 1 分钟后，将锅中的油和土豆块经过笊篱过滤倒出，让笊篱上的青椒片断生。","锅中加入 5ml 食用油，小火煸炒蒜瓣至发黄，下入红油豆瓣酱煸炒出香，下入白糖炒融化，下入花椒碎，加 40ml 清水，不停搅拌至酱汁粘稠。","下入炸好的鸡块、土豆块、青椒片，搅拌均匀后出锅。"]'::jsonb, '["荤菜","甜辣","川菜","油炸","下饭","家常","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_b349e034b5.jpg', 'https://www.bilibili.com/video/BV1hV411q7Uu', '{"energyKcal":1050,"protein":80,"carbs":80,"fat":45}'::jsonb, '[null,1800,300,null,180,120,60,60,null,null]'::jsonb),
  ('howtocook:meat_dish/乡村啤酒鸭', '乡村啤酒鸭', '荤菜', 4, 60, '鸭肉与啤酒同炖，汤汁浓郁，肉质鲜香软烂，还带有一股淡淡的啤酒清香，是一道风味独特的家常菜。鸭肉本身滋补，富含蛋白质、B 族维生素和多种矿物质，搭配啤酒炖煮后更易入味。这道菜步骤虽稍多，但操作并不复杂，一般初学者只需 大约 1 小时即可完成。', '[{"name":"鸭肉","quantity":1,"unit":"kg"},{"name":"啤酒","quantity":1000,"unit":"ml"},{"name":"青椒","quantity":2,"unit":"条"},{"name":"红椒","quantity":1,"unit":"条"},{"name":"大蒜","quantity":4,"unit":"颗"},{"name":"生姜","quantity":3,"unit":"厘米"},{"name":"小米椒","quantity":3,"unit":"颗"},{"name":"蒜苗","quantity":2,"unit":"根"},{"name":"大葱","quantity":2,"unit":"根"},{"name":"草果","quantity":2,"unit":"颗"},{"name":"桂皮","quantity":4,"unit":"厘米"},{"name":"八角","quantity":3,"unit":"颗"},{"name":"香叶","quantity":3,"unit":"片"},{"name":"干辣椒","quantity":6,"unit":"条"},{"name":"料酒","quantity":20,"unit":"ml"},{"name":"花椒","quantity":30,"unit":"颗"},{"name":"花生油","quantity":60,"unit":"ml"},{"name":"盐","quantity":3,"unit":"克"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"老抽","quantity":5,"unit":"ml"}]'::jsonb, '["鸭肉清洗一遍放进锅中","加清水淹没鸭肉","加 20 ml 料酒","加备用的 1 根 大葱","加生姜 ,拍散的 2 厘米","开火烧滚","捞出浮沫","鸭肉捞出,清水洗干净备用","锅清洗感觉烧热,加 60ml 的花生油","油温到 60 度的时候,加一把花椒（ 30 颗）","加鸭肉翻炒 4 分钟","2 分钟后加入所有的香料","3 分钟的时候加入所有的料头（生姜,大蒜,小米辣）","加入 1000 ml 的啤酒","烧鸭肉 30 分钟","10 分钟的时候加 盐 （3 克） 生抽( 10 ml ) 老抽( 5 ml)","20 分钟 加入所有的辅料 （青椒和红椒段）","29 分钟加入 蒜苗段 和 大葱段","翻炒 1 分钟","出锅"]'::jsonb, '["荤菜","鲜香","炖煮","家常","下饭","微辣"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_bb269f5c3c.jpg', 'https://www.bilibili.com/video/BV1Ar421h7DC', '{"energyKcal":800,"protein":30,"carbs":11,"fat":60}'::jsonb, '[null,null,null,null,null,null,null,null,null,null,240,null,null,null,1800,null,null,null,60,null]'::jsonb),
  ('howtocook:meat_dish/广式萝卜牛腩/广式萝卜牛腩', '广式萝卜牛腩', '荤菜', 4, 150, '这是一道广式家常炖菜，牛腩软烂入味，萝卜吸饱汤汁后清甜浓郁，整体酱香回甘。富含优质蛋白和膳食纤维，开胃助消化。制作步骤稍多但难度适中，新手按部就班也能成功。预计从头到尾大约需要 2.5 小时完成。', '[{"name":"牛腩","quantity":500,"unit":"克"},{"name":"白萝卜","quantity":1,"unit":"根"},{"name":"姜片","quantity":8,"unit":"片"},{"name":"蒜瓣","quantity":5,"unit":"片"},{"name":"葱","note":"一把"},{"name":"八角","quantity":2,"unit":"片"},{"name":"桂皮","quantity":1,"unit":"小块"},{"name":"干辣椒","quantity":2,"unit":"个"},{"name":"香叶","quantity":2,"unit":"片"},{"name":"南乳","quantity":1,"unit":"块"},{"name":"柱侯酱","quantity":30,"unit":"克"},{"name":"蚝油","quantity":15,"unit":"克"},{"name":"酱油","quantity":15,"unit":"克"},{"name":"冰糖","quantity":10,"unit":"克"},{"name":"盐","quantity":5,"unit":"克"},{"name":"老抽","quantity":15,"unit":"克"}]'::jsonb, '["萝卜滚到切块备用","牛腩整块焯水，加入 2 片姜和一把葱结，等水开之后煮 5-10 分钟，然后捞出切件","将牛腩切块，切成自己喜欢的大小（牛腩焯过水，待会儿焖的时候基本不会缩水了，大块的会焖相对就一点的时间）","准备焖牛腩的酱料，将南乳、柱侯酱、酱油、蚝油、糖、盐按上面的量调和（冰糖刚刚没了换成了白糖）","热锅下油，将姜蒜爆香,放入牛腩，炒至干身,加入调好的酱料，炒香,如果喜欢色泽浓一点的可以加一点老抽润色一下","调料充分混合之后倒入热水","将牛腩换到汤锅中，放入桂皮、八角、香叶和干辣椒，焖大概 2 个小时","牛腩焖到半软之后加入白萝卜继续焖 30 分钟","等到萝卜焖软之后就完成,一锅浓香的萝卜牛腩就完成了"]'::jsonb, '["荤菜","广式","炖菜","酱香","下饭","家常","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_178a6d79f8.webp', 'https://www.bilibili.com/video/BV1FAycBjEkT', null, null),
  ('howtocook:meat_dish/徽派红烧肉/徽派红烧肉', '徽派红烧肉', '荤菜', 4, 45, '徽派红烧肉是一道色泽红亮、肥而不腻的经典徽式家常菜，口感软糯 Q 弹，咸甜交融。以五花肉为主料，富含优质蛋白质和脂肪，能提供充沛能量。烹制需掌握炒糖色与火候，稍有挑战，预估制作时长约 45 分钟。', '[{"name":"五花肉","quantity":300,"unit":"克"},{"name":"白砂糖","quantity":100,"unit":"克"},{"name":"食用油","quantity":200,"unit":"克"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"蚝油","quantity":5,"unit":"ml"},{"name":"老抽","quantity":5,"unit":"ml"},{"name":"姜片","quantity":2,"unit":"片"},{"name":"蒜头","quantity":3,"unit":"颗"},{"name":"料酒","quantity":100,"unit":"ml"},{"name":"葱","quantity":1,"unit":"根"},{"name":"五香粉","quantity":10,"unit":"克"},{"name":"盐","quantity":10,"unit":"克"}]'::jsonb, '["五花肉切块，每块 2-3 cm 大小","锅中加入 150 ml 食用油，倒入五花肉，煎炸 2 分钟 后，加入盐，翻炒五花肉，2 分钟 后出锅","锅中加入 50 ml 食用油，倒入白砂糖，翻炒到咖啡色","倒入五花肉，翻炒 30 S ，加入姜片、蒜头后翻炒 30 S","加入料酒，五香粉、葱，加入水没过五花肉，盖上锅盖煮 10 分钟","加入生抽、老抽、蚝油，中火煮 20 分钟","开锅，大火烧汁，端盘"]'::jsonb, '["荤菜","咸甜","红烧","徽式","下饭","家常菜"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_74eeebbc5f.jpeg', 'https://www.bilibili.com/video/BV1vfHfzYELM', null, '[null,240,null,60,600,1200,null]'::jsonb),
  ('howtocook:meat_dish/意式烤鸡', '意式烤鸡', '荤菜', 3, 50, '意式烤鸡是一道带有地中海风味的家常烤箱菜。鸡腿肉经过蒜香橄榄油腌制，烤后外皮微焦、内里鲜嫩多汁，搭配柠檬汁和欧芹，口感清爽不腻。鸡肉富含优质蛋白质，橄榄油提供不饱和脂肪酸，营养均衡。制作难度适中，需要提前预热烤箱，新手跟着步骤也能顺利完成，从腌制到出炉总计约五十分钟。', '[{"name":"鸡腿肉","quantity":1,"quantityMax":2,"unit":"个"},{"name":"盐","quantity":2,"unit":"克"},{"name":"黑胡椒","quantity":0.5,"unit":"克"},{"name":"橄榄油","quantity":5,"unit":"ml"},{"name":"蒜","quantity":1,"unit":"瓣"},{"name":"柠檬汁","quantity":5,"unit":"ml"},{"name":"欧芹","quantity":1,"unit":"根"}]'::jsonb, '["鸡腿肉涂上盐、黑胡椒、橄榄油和蒜末","放入预热至 180 度的烤箱中，烤 30-40 分钟或至熟","欧芹切成碎末备用","柠檬挤出汁备用","烤好的鸡肉取出，淋上柠檬汁","撒上欧芹碎即可"]'::jsonb, '["荤菜","意式","烤制","地中海","清爽","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_12974cc759.jpg', 'https://www.bilibili.com/video/BV1qZ4y1x7ux', '{"energyKcal":280,"protein":25}'::jsonb, '[null,1800,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/新疆大盘鸡/新疆大盘鸡', '新疆大盘鸡', '荤菜', 4, 60, '新疆大盘鸡是一道风味浓郁、色彩鲜艳的新疆家常菜，鸡肉鲜嫩不柴，土豆软糯吸汁，麻辣中带着微甜回甘。富含优质蛋白质和碳水化合物，搭配彩椒还能补充维生素 C。制作过程需要炒糖色和掌握收汁火候，对新手有一定挑战，但跟随步骤细心操作并不难，整体大约 1 小时可以完成。', '[{"name":"鸡肉（鸡腿肉最好）","quantity":1,"unit":"kg"},{"name":"土豆","quantity":750,"unit":"克"},{"name":"大葱","quantity":100,"unit":"克"},{"name":"菜椒（可选）","quantity":50,"unit":"克"},{"name":"甜椒（可选）","quantity":50,"unit":"克"},{"name":"白糖","quantity":20,"unit":"克"},{"name":"干线椒","quantity":5,"unit":"个"},{"name":"大蒜","quantity":4,"unit":"瓣"},{"name":"油","quantity":50,"unit":"克"},{"name":"盐","quantity":5,"unit":"克"},{"name":"生抽","quantity":7,"unit":"ml"},{"name":"蚝油","quantity":10,"unit":"克"},{"name":"料酒（可用啤酒代替）","quantity":100,"unit":"克"},{"name":"清水","quantity":1,"unit":"升"},{"name":"花椒","note":"适量"},{"name":"香叶","note":"适量"},{"name":"香果","note":"适量"}]'::jsonb, '["肉先剁好，块状，用清水+盐浸泡 5 分钟，去除血水，去腥，然后空干水","葱蒜辣椒土豆等洗干净，土豆削皮","葱白切长段，长度 4cm 一段，菜椒和线椒切块状","土豆切成滚刀土豆，即切一刀动滚动一下，一块土豆大概有 4cm4cm 大小即可","炒糖色：先将油加入锅中，然后将白砂糖放入，用锅铲来回搅拌，将糖炒化，然后炒出焦黄色，此时将空干水的鸡肉倒入锅中翻炒，进行上色","放入花椒，香叶，香果，干线椒等进行翻炒","放入 5g 盐，生抽 7ml，蚝油 10g ，料酒 100g，倒入 1 升清水，料酒可以用啤酒代替","调至中火，将水烧开，调制中小火慢炖入味","当水收至鸡肉即将露出时，将土豆放在锅表面：注意不要翻动土豆，就盖在表面，不然翻到下面容易粘锅，继续盖锅盖炖，炖一会后将大葱，菜椒和甜椒放入，继续炖。","炖到汁收的差不多时可以进行翻面，将土豆与汤汁相吸，最后关火盛出。"]'::jsonb, '["荤菜","麻辣","下饭","新疆","炖","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_9e330ef566.jpeg', 'https://www.bilibili.com/video/BV1kn4y1X72E', null, null),
  ('howtocook:meat_dish/无骨鸡爪/无骨鸡爪', '无骨鸡爪', '荤菜', 5, 495, '酸辣开胃、口感 Q 弹，是一道家常凉拌小吃。鸡爪富含胶原蛋白，对皮肤有益。去骨步骤繁琐费力，制作难度较高，不太适合新手尝试。全程耗时约 8 小时 15 分钟。', '[{"name":"鸡爪","quantity":1,"unit":"kg"},{"name":"姜","quantity":4,"unit":"片"},{"name":"料酒","quantity":65,"unit":"克"},{"name":"大葱","quantity":3,"unit":"段"},{"name":"大蒜","quantity":10,"unit":"瓣"},{"name":"小米辣","quantity":4,"quantityMax":12,"unit":"个"},{"name":"洋葱","quantity":0.5,"unit":"个"},{"name":"生抽","quantity":75,"unit":"克"},{"name":"蚝油","quantity":30,"unit":"克"},{"name":"黑醋（推荐陈醋）","quantity":50,"unit":"克"},{"name":"白糖","quantity":10,"unit":"克"},{"name":"盐","quantity":3,"unit":"克"},{"name":"花椒油","quantity":10,"unit":"ml"},{"name":"香菜","quantity":3,"unit":"颗"},{"name":"柠檬","quantity":2,"unit":"颗"}]'::jsonb, '["用剪刀 / 刀 把鸡爪上的指甲的部分全部剪掉 包括指甲下面的肉和骨头，让它一点指甲都不剩","用水把他们洗干净，放一边","把鸡爪放入大锅中，准备去腥味","大葱，料酒，姜 全放进去","加水没过鸡爪","大火煮开 中途可以把浮末捞起来","水开100度，沸腾后等 10 分钟","关火，捞出来，把水沥干，洗干净，放入盆里","放入冰箱，冷冻层 20 分钟","把全部放入不是冷冻层的冰箱，然后分批10个一批拿出来去骨","从手指（鸡爪的）最前端开始，每只手指都要用刀划开划到它的手背部分","再从手背部用刀分划开至整个手臂","把每只手指关节处都掰一掰按手指出声音时那种","按着它的手指最前端，往里推，每只手指都一样，先推到中间手掌手背部分","每只手指皮脱离后，从手掌开始往手臂部分推直到整个脱下来了","放入碗中，备用","小米辣 切均匀小颗","大蒜，洋葱，香菜切碎","柠檬对半切开，把柠檬汁挤入鸡爪的容器里","把全部调料倒入装鸡爪的容器，小米辣，大蒜，洋葱和香菜也放进去","抓拌均匀","放入冰箱一个晚上（6 个小时）","调配好后全部放入准备好的鸡爪"]'::jsonb, '["荤菜","酸辣","凉拌","开胃","下酒","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_077cca0e7c.jpg', 'https://www.bilibili.com/video/BV1jT41147Bu', '{"energyKcal":600,"protein":51,"carbs":10,"fat":40}'::jsonb, null),
  ('howtocook:meat_dish/杀猪菜', '杀猪菜', '荤菜', 4, 70, '这是一道源自东北的经典炖菜，酸爽鲜香、暖心暖胃。酸菜富含乳酸菌和膳食纤维，排骨提供优质蛋白与钙质，血肠则能补充铁元素。制作时需要耐心处理血肠以防煮爆，对厨房新手有一定挑战。从备料到出锅，预计耗时约一小时。', '[{"name":"血肠","quantity":200,"unit":"克"},{"name":"酸菜","quantity":500,"unit":"克"},{"name":"排骨","quantity":400,"unit":"克"},{"name":"料酒","quantity":10,"unit":"克"},{"name":"蒜瓣","quantity":5,"unit":"个"},{"name":"姜粉","quantity":5,"unit":"克"},{"name":"干辣椒","quantity":5,"unit":"个"},{"name":"香叶","quantity":2,"unit":"片"},{"name":"八角","quantity":1,"unit":"个"},{"name":"葱结","quantity":1,"unit":"个"},{"name":"香油","quantity":10,"unit":"克"},{"name":"菜籽油","quantity":10,"unit":"克"},{"name":"盐","quantity":5,"unit":"克"},{"name":"枸杞","note":"适量"},{"name":"辣椒油","quantity":5,"unit":"克"},{"name":"生抽","quantity":10,"unit":"克"},{"name":"蒜蓉","quantity":5,"unit":"克"},{"name":"香油","quantity":2,"unit":"克"}]'::jsonb, '["血肠用牙签多扎一些小孔，然后放水中小火煮十分钟，不要让水烧开，保持 80 度，否则血肠非常容易爆开。","煮好的血肠切块备用。","排骨放料酒焯水，控干水分备用。","锅内放入菜籽油，放蒜瓣，干辣椒，姜粉炒香。","放入排骨翻炒至表面金黄。","酸菜洗净拧干水分，放入锅中，加入香油翻炒，香油可以更好的去除酸味而且让酸菜更香，大火翻炒二分钟。","加入 600 毫升热水。","转入电压力锅，加香叶，八角，葱结，盐。","浓香模式压 40 分钟。","到时间后放气开盖。加入血肠和枸杞，盖上锅盖焖二分钟即可，血肠是熟的，不需再加热。","倒入盆中，按照上表调制蘸料，即可开吃。"]'::jsonb, '["荤菜","东北","炖菜","酸爽","鲜香","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_a330f66a3e.jpg', 'https://www.bilibili.com/video/BV1LX4y1M7vh', '{"energyKcal":620,"protein":28}'::jsonb, '[600,null,null,null,null,120,null,null,2400,120,null]'::jsonb),
  ('howtocook:meat_dish/枝竹羊腩煲/枝竹羊腩煲', '枝竹羊腩煲', '荤菜', 5, 150, '这是一道源自广东的传统煲仔菜，羊肉与腐竹在柱侯酱和腐乳的调和下，酱香浓郁，口感肥美而不腻口，暖身暖心，尤其适合寒冬食用。羊肉富含蛋白质和铁质，能温补气血，腐竹则提供优质植物蛋白，搭配起来营养均衡。虽然备料和炖煮步骤较多，但全程火候控制并不复杂，新手只需按部就班也能成功。预计从准备到出锅约需两个半小时。', '[{"name":"羊腩","quantity":500,"unit":"克"},{"name":"炸腐竹","quantity":30,"quantityMax":50,"unit":"克"},{"name":"柱侯酱","quantity":30,"unit":"克"},{"name":"腐乳","quantity":40,"unit":"克"},{"name":"南乳","quantity":35,"unit":"克"},{"name":"老抽","quantity":5,"unit":"ml"},{"name":"辣椒油","quantity":5,"unit":"ml"},{"name":"料酒","note":"适量"},{"name":"蚝油","note":"适量"},{"name":"清水","quantity":500,"unit":"ml"},{"name":"冰糖","quantity":20,"unit":"克"},{"name":"砂糖","quantity":10,"unit":"克"},{"name":"小葱","quantity":5,"unit":"根"},{"name":"姜片","quantity":6,"quantityMax":8,"unit":"片"},{"name":"香菇","quantity":7,"quantityMax":8,"unit":"个"},{"name":"洋葱","quantity":1,"unit":"个"},{"name":"红葱头","quantity":4,"quantityMax":5,"unit":"个"},{"name":"蒜瓣","quantity":7,"quantityMax":8,"unit":"瓣"},{"name":"香叶","quantity":1,"unit":"片"},{"name":"八角","quantity":4,"quantityMax":5,"unit":"个"},{"name":"桂皮","quantity":10,"unit":"克"},{"name":"配菜","note":"根据个人喜好添加"}]'::jsonb, '["准备工作: 香菇提前浸泡 2 - 3 小时至变软。腐竹提前浸泡 30 分钟至变软","准备酱汁 1: 南乳、柱侯酱、20g 腐乳、老抽放入同个小碗中搅拌均匀","准备酱汁 2: 20g 腐乳、砂糖、辣椒油放入同个小碗搅拌均匀","泡好的香菇去除根部","泡好的腐竹切成 5cm 的小段，挤干水分","洋葱去皮切丝。也可以用去皮红葱头进行替代，口味更佳。","小葱切成大约 5cm 的葱段","羊腩冷水下锅，放入 2 - 3 片姜片，倒入凉水，大火煮至水滚后关火","捞出羊腩，放入准备好的冷水盆中放凉，使其更有嚼劲","锅烧热后放入冷油，放入 4 - 5 片姜片、洋葱/红葱头、葱白段、7 - 8 瓣蒜瓣进行爆香","放入冷却好的羊腩，用筷子搅拌大约 2 - 5 分钟直至出现金黄色","放入调好的酱汁 1 ，翻炒大约 2 分钟至颜色均匀","倒入清水至刚好没过食材","放入香菇、冰糖、香叶、八角、桂皮","加盖转小火炖 90 分钟","开盖加入腐竹，加盖转中火煮 20 分钟","开盖加入酱汁 2 搅拌均匀","关火，出锅前加入葱绿段或香菜"]'::jsonb, '["荤菜","粤式","酱香","暖身","秋冬","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_61807b99fe.jpg', 'https://www.bilibili.com/video/BV1SJ411u7Mv', '{"energyKcal":410,"protein":27,"carbs":10,"fat":30}'::jsonb, '[null,null,null,null,null,null,null,null,null,null,null,120,null,null,5400,1200,null,null]'::jsonb),
  ('howtocook:meat_dish/柱候牛腩/柱候牛腩', '柱候牛腩', '荤菜', 4, 180, '这是一道经典广式风味菜肴，肉香浓郁，色泽红亮，带筋牛腩软烂入味，口感丰富。富含优质蛋白质和胶原蛋白，滋补暖身。虽需一定耐心，但使用高压锅能大幅缩短时间，对新手也较友好。普通炖煮约需 3 小时，用高压锅则约 1 小时即可完成。', '[{"name":"牛腩","quantity":500,"quantityMax":600,"unit":"克"},{"name":"姜","quantity":30,"unit":"克"},{"name":"蒜","quantity":0.5,"unit":"头"},{"name":"小米辣","quantity":1,"unit":"条"},{"name":"香叶","quantity":2,"unit":"片"},{"name":"花椒","quantity":0.5,"unit":"克"},{"name":"八角","quantity":2,"unit":"个"},{"name":"干辣椒","quantity":3,"unit":"个"},{"name":"丁香","quantity":3,"unit":"个"},{"name":"甘草","quantity":2,"unit":"片"},{"name":"南腐乳","quantity":2,"unit":"块"},{"name":"郫县豆瓣酱","quantity":15,"unit":"克"},{"name":"冰糖","quantity":10,"unit":"克"},{"name":"花雕酒","quantity":10,"unit":"克"},{"name":"白酒","quantity":20,"unit":"克"},{"name":"柱候酱","quantity":50,"unit":"克"},{"name":"叉烧酱","quantity":20,"unit":"克"},{"name":"蚝油","quantity":20,"unit":"克"},{"name":"老抽","quantity":5,"unit":"克"},{"name":"生抽","quantity":60,"unit":"克"}]'::jsonb, '["先把辅料备好：","碗 1：姜切成 1.5cm\\1.5cm 的小块，半头蒜剥好皮，如果有小米辣切成 1cm 小段","碗 2：放入 2 片香叶，0.5g 花椒，2 个八角，3 个干辣椒，3 个丁香， 2 片甘草","碗 3: 放入 2 块南乳","碗 4: 放入 15g 豆瓣酱","碗 5: 放入 10g 冰糖","碗 6：倒入花雕酒 10g 和白酒 10g","碗 7：加入 50g 柱候酱，20g 蚝油，20g 叉烧酱，5g 老抽，60g 生抽","牛肉不用切，直接冷水下锅，开大火焯水，水沸腾时将牛肉捞出","冲洗牛肉表面的杂质后，切成 4cm\\4cm\\4cm 的大块，控干水后放入碗中备用","大火，热锅下油，把碗 1（姜、蒜、小米辣）倒入锅中，炒香","中小火，倒入碗 2（香料），翻炒均匀，大概 30 秒","中小火，放入碗 3（南乳），用锅铲把南乳压碎","中小火，放入碗 4（豆瓣酱），翻炒均匀，大概 30 秒","中小火，放入碗 5（冰糖），炒至融化","中小火，下入牛腩，炒至牛肉上色","大火，沿锅边淋入碗 6（酒），快速翻炒，炒至牛肉表面略微焦褐","倒入碗 7（酱料），快速翻炒，留意底层汁水，炒至不停冒小气泡，汤汁略微浓稠","将锅内全部食材转移至另一个炖煮锅或高压锅，加水淹过食材","根据使用的锅来选择炖肉的时间：","a. 普通炖煮锅：小火炖煮 3 个小时","b. 高压锅：压 40 分钟","时间到后开盖调味，如果不够咸加盐或生抽（少量加，不断尝味道，直到合适），不够甜则同理加糖","调好味道后便可以把牛腩先捞出","如果要吃萝卜土豆，则削皮切成 2cm 厚片倒入锅中煮 10 - 15 分钟（或煮至想要吃的口感），如果是高压锅则在加压煮 5 分钟","煮好后捞出萝卜土豆和牛腩放一起","把汤汁过滤淋入碗中"]'::jsonb, '["荤菜","广式","酱香","炖","下饭","暖身","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_2ba53b046d.jpeg', 'https://www.bilibili.com/video/BV1Lt411x71y', '{"energyKcal":470,"protein":27,"carbs":13,"fat":30}'::jsonb, '[null,null,null,null,null,null,null,null,null,null,null,30,null,30,null,null,null,null,null,null,10800,2400,null,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/桂林十八酿/桂林十八酿', '桂林十八酿', '荤菜', 3, 90, '桂林传统酿菜系列，将调好味的猪肉、虾滑等馅料酿入青椒、苦瓜、田螺、茄子等十多种中空食材中，煎焖成菜，一菜一味，鲜香多汁，口感软嫩或弹牙，属于浓郁的地方家常风味。馅料提供优质蛋白质，搭配多种蔬菜，富含维生素与膳食纤维，营养较为均衡。制作步骤需要逐一填馅和掌控火候，稍需耐心，但操作逻辑简单，厨艺新手也能尝试，预计全部完成约需 1.5 小时。', '[{"name":"青椒","note":"适量"},{"name":"苦瓜","note":"适量"},{"name":"茄子","note":"适量"},{"name":"田螺","note":"适量"},{"name":"豆腐","note":"适量"},{"name":"香菇","note":"适量"},{"name":"南瓜花","note":"适量"},{"name":"柚子","note":"适量"},{"name":"笋","note":"适量"},{"name":"冬瓜","note":"适量"},{"name":"香芋","note":"适量"},{"name":"蒜","note":"适量"},{"name":"番茄","note":"适量"},{"name":"豆芽","note":"适量"},{"name":"蛋","note":"适量"},{"name":"香菌","note":"适量"},{"name":"猪肉馅","note":"适量"},{"name":"虾滑馅","note":"适量"},{"name":"鱼肉馅","note":"适量"},{"name":"混合馅","note":"适量"}]'::jsonb, '["青椒酿：青椒去籽挖空 → 塞入猪肉馅或虾滑 → 煎至虎皮色 → 酱汁焖煮","田螺酿：田螺焯水取肉 → 螺肉与猪肉剁碎混合 → 塞回螺壳 → 紫苏薄荷焖煮","猪肉馅：最基础通用的选择，肥瘦 3:7 口感最佳","虾滑馅：鲜甜弹牙，青椒酿里常用","螺肉猪肉混合馅：田螺酿的灵魂，螺肉与猪肉 1:1，加紫苏薄荷","混合馅：猪肉 + 虾滑混搭，鲜甜与油脂香兼得"]'::jsonb, '["荤菜","鲜香","煎焖","桂林风味","家常","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_6155253803.png', 'https://www.bilibili.com/video/BV1f142147mC', '{"energyKcal":340,"protein":18,"carbs":22,"fat":18}'::jsonb, null),
  ('howtocook:meat_dish/梅菜扣肉/梅菜扣肉', '梅菜扣肉', '荤菜', 4, 150, '这是一道客家传统名菜，成菜酱红油亮、汤汁黏稠，扣肉肥而不腻、软烂醇香。五花肉富含优质蛋白和脂肪酸，搭配梅干菜能提供膳食纤维。整体工序稍多，需要掌握煮、炸、蒸的火候，对新手有一定挑战。从备料到出锅，连同浸泡梅菜的时间在内，大约需要 2.5 小时。', '[{"name":"五花肉","quantity":200,"unit":"克"},{"name":"梅菜","quantity":30,"unit":"克"},{"name":"五香粉","quantity":2,"unit":"克"},{"name":"食用油","quantity":300,"unit":"ml"},{"name":"白砂糖","quantity":5,"unit":"克"},{"name":"老抽","quantity":30,"unit":"ml"},{"name":"生抽","quantity":20,"unit":"ml"},{"name":"小米椒","quantity":1,"unit":"个"},{"name":"蒜末","quantity":10,"unit":"克"},{"name":"食用盐","quantity":2,"unit":"克"},{"name":"鸡精","quantity":2,"unit":"克"}]'::jsonb, '["梅菜放到清水中，浸泡 1 小时","锅中倒入 50 ml 食用油，将整个五花肉猪皮朝下，放到锅中 1 分钟 ，取出挂掉猪皮 【可选】","锅中加入开水，放入五花肉，大火煮 20 分钟 （筷子可以插进五花肉），取出五花肉","在五花肉表面涂抹均匀老抽、五香粉、白砂糖，放置 15 分钟","起锅烧油，加入五花肉，中火油炸直至两面金黄色（3-5 分钟）","起锅烧油，倒入梅菜，加上小米椒、蒜蓉、鸡精、食用盐后翻炒，直至炒干梅干菜水分","五花肉切片（后端 0.5-1 cm）,放在大碗中，散上梅干菜","中火蒸 45 分钟","拿个盘子倒盖在五花肉大碗中，将五花肉倒在盘子中"]'::jsonb, '["荤菜","客家","蒸制","下饭菜","宴客","鲜香"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_9f4135bce3.jpeg', 'https://www.bilibili.com/video/BV1AfFJzyEDM', '{"energyKcal":1450,"protein":18,"carbs":12,"fat":155}'::jsonb, '[3600,60,1200,900,null,null,null,2700,null]'::jsonb),
  ('howtocook:meat_dish/椒盐排条', '椒盐排条', '荤菜', 4, 40, '椒盐排条是上海本帮菜里的经典家常菜，外酥里嫩，咸香适口。猪大排提供优质蛋白质和必需氨基酸，能补充体力。这道菜虽然步骤稍多，但跟着流程走并不难，新手也可以大胆尝试。从备料到出锅，大约需要 40 分钟。', '[{"name":"大排","quantity":4,"unit":"块"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"盐","quantity":1,"unit":"克"},{"name":"椒盐粉","quantity":10,"unit":"克"},{"name":"葱姜水","quantity":100,"unit":"ml"},{"name":"面粉","quantity":80,"unit":"克"},{"name":"淀粉","quantity":80,"unit":"克"},{"name":"吉士粉","quantity":2,"quantityMax":3,"unit":"克"},{"name":"水","quantity":10,"unit":"克"},{"name":"油","quantity":10,"unit":"克"}]'::jsonb, '["大排洗干净，剔骨，用刀面拍松，切成厚片，再改成粗条。","加入椒盐粉，搅匀，待到出胶质了分次加入葱姜水，放入冰箱腌制 20 分钟。","制作炸糊。放入 80 g 面粉，20 g 淀粉（注意是 20 g 淀粉，剩下 60 g 备用），2 - 3 g 吉士粉，盐 1 g。","打入一个鸡蛋，搅拌，再分次加入水 100 g ，再加 10 g 油，反复搅拌。直到炸糊完全调开，略粘稠即可。","取出剩余的 60 g 淀粉，取出排条，裹上一层淀粉，再裹上面糊。","锅中加入油，能没过食材即可，加热到大约 150 ℃ - 160 ℃ 。下入排条炸成浅金黄色后捞出。刚下入排条时可能会有粘连，不要动。待排条定型后可用筷子翻动，即可分开。","待油温再次升高到 150 ℃ - 160 ℃ 时，下入排条复炸至金黄色后捞出。","撒上椒盐粉，搅拌均匀后出锅。"]'::jsonb, '["荤菜","咸香","油炸","上海本帮","下酒","外酥里嫩"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_2014241522.jpg', 'https://www.bilibili.com/video/BV1wG411W7tn', '{"energyKcal":400,"protein":22,"carbs":28,"fat":18}'::jsonb, '[null,1200,null,null,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/水煮牛肉/水煮牛肉', '水煮牛肉', '荤菜', 3, 40, '水煮牛肉是川菜中的经典麻辣味型，口感滑嫩、汤汁红亮、香辣烫鲜。牛肉富含优质蛋白质和铁，搭配豆芽可补充膳食纤维。这道菜对新手来说不算太难，但需注意火候和泼油安全，整体制作约需四十分钟。', '[{"name":"牛肉","quantity":300,"unit":"克"},{"name":"豆芽","quantity":100,"unit":"克"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"香菜","quantity":5,"unit":"根"},{"name":"豆瓣酱","quantity":10,"unit":"克"},{"name":"料酒","quantity":10,"unit":"ml"},{"name":"淀粉","quantity":15,"unit":"克"},{"name":"干辣椒粉","quantity":5,"unit":"克"},{"name":"姜","quantity":20,"unit":"克"},{"name":"蒜","quantity":3,"unit":"瓣"},{"name":"红辣椒","quantity":1,"unit":"根"},{"name":"蚝油","quantity":8,"unit":"克"}]'::jsonb, '["牛肉洗干净切片。","加入 15g 姜丝，1 个鸡蛋，15g 淀粉，8g 蚝油，10ml 料酒搅拌均匀，腌制 15 分钟。","香菜洗干净切好。","锅里倒油，加入豆瓣酱，5g 姜丝，蒜片。","倒入开水，煮成红汤。","豆芽洗干净去掉尾须，放进开水里焯熟。","将豆芽铺入碗底。","将牛肉片一片一片的放进红汤中，煮熟以后捞出。","将牛肉铺在豆芽上，撒上香菜梗。","撒上香菜叶，辣椒粉，辣椒圈。","另起锅烧热油，将热油淋在菜上面，就完成了。"]'::jsonb, '["荤菜","麻辣","川菜","下饭","家常","滑嫩"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_cca01fbf19.jpg', 'https://www.bilibili.com/video/BV1BBHQesEzU', '{"energyKcal":850,"protein":72,"carbs":18,"fat":55}'::jsonb, '[null,900,null,null,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/水煮肉片', '水煮肉片', '荤菜', 5, 90, '水煮肉片是一道麻辣鲜香、肉片滑嫩、配菜爽脆的经典川菜，极其适合下饭。猪里脊提供优质蛋白质，搭配豆芽等蔬菜，营养均衡。做法稍显繁琐，尤其需要耐心腌制肉片和制作刀口辣椒，新手大约需要 1 至 2 小时完成。', '[{"name":"猪里脊肉","quantity":300,"unit":"克"},{"name":"食用盐","quantity":5,"unit":"克"},{"name":"胡椒粉","quantity":2,"unit":"克"},{"name":"生抽酱油","quantity":5,"unit":"克"},{"name":"料酒","quantity":3,"unit":"克"},{"name":"鸡蛋清","quantity":1,"unit":"个"},{"name":"土豆淀粉","quantity":7,"unit":"克"},{"name":"植物油","quantity":280,"unit":"克"},{"name":"绿豆芽","quantity":100,"unit":"克"},{"name":"凤尾","quantity":1,"unit":"根"},{"name":"芹菜","quantity":3,"unit":"根"},{"name":"蒜苗","quantity":2,"unit":"根"},{"name":"大蒜","quantity":20,"unit":"克"},{"name":"生姜","quantity":10,"unit":"克"},{"name":"红泡椒","quantity":20,"quantityMax":40,"unit":"克"},{"name":"青花椒","quantity":5,"unit":"克"},{"name":"干辣椒","quantity":20,"quantityMax":40,"unit":"克"},{"name":"红油豆瓣","quantity":5,"unit":"ml"},{"name":"鸡精","quantity":1.5,"unit":"克"},{"name":"白砂糖","quantity":1,"unit":"克"},{"name":"小葱","quantity":2,"unit":"根"},{"name":"菜籽油","quantity":200,"unit":"克"}]'::jsonb, '["里脊肉改刀成小块，再切成 2 毫米薄片（可根据自己的口感改进），放入碗中，加入清水清洗两遍来去除血水和杂质，捞出挤干水分备用。","碗中加入食用盐 1.5g，胡椒粉 1g，生抽酱油 5g，料酒 3g，然后朝着一个方向搅拌 2 分钟，使其入味。","另外准备一个碗，加入一个鸡蛋清，加入 7g 土豆淀粉，一个方向搅拌均匀，倒入肉中","再次一个方向搅拌均匀（肉表面就形成了润滑膜，这样会使肉更加鲜嫩）","最后再加入 30g 植物油轻轻搅拌（防止肉片粘连）。","绿豆芽 100g，凤尾 1 根（改刀成小条），芹菜 3 根切成小段，蒜苗 2 根拍散切成小段。","大蒜 20g 剁碎，生姜小块剁碎，红泡椒 20g 剁碎。","小米辣干辣椒 15g，青花椒 3g，锅内加入油滑锅，油稍许热了将多余的倒出备用留 50g 底油，下入干辣椒、花椒，开小火炒香，切记不要炒糊（颜色要变黑即可），倒出在菜板上剁细。","锅烧热，放入 100g 植物油烧至 6 成热，加入 2g 青花椒、干辣椒爆香，配菜下锅，加入 1g 食用盐，炒至断生，盛入碗中垫底备用。","锅洗干净，加入 150g 植物油烧至 6 成热，加入制作好的姜蒜红泡椒，爆香后加入豆瓣 10g，开小火把豆瓣爆香炒出红油即可。","加入 800 毫升清水（根据实际情况选择），大火烧开，转小火调味，加入食用盐 2.5g，鸡精 1.5g，1g 白砂糖提鲜，1g 胡椒粉，5g 水淀粉（根据实际情况选择）将汤汁收浓稠一点。","汤汁开后，开小火将腌制好的肉片分开依次下锅，然后开中火将肉片烫熟，用锅铲轻轻推动一下避免粘连，待汤汁烧开，肉片熟后捞出放入碗中配菜上，再将原汤倒入（不超过菜品）。","碗中均匀撒上刀口辣椒、蒜蓉和葱花。","锅洗干净，加入 200g 菜籽油，烧至 7 成热，然后一次性均匀泼在碗中肉片上（注意安全），美味完成。"]'::jsonb, '["荤菜","麻辣","川菜","下饭菜","水煮","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_ee424c097c.jpg', 'https://www.bilibili.com/video/BV1H9q8BEEB4', '{"energyKcal":580,"protein":15,"carbs":8,"fat":46}'::jsonb, '[null,120,null,null,null,null,null,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/洋葱炒猪肉', '洋葱炒猪肉', '荤菜', 3, 15, '这是一道家常风味小炒，咸中带甜，酱香浓郁，洋葱炒软后滋味温和，搭配嫩滑猪肉片非常下饭。猪肉提供优质蛋白质和 B 族维生素，洋葱含膳食纤维和多种抗氧化物，开胃助消化。操作简单，新手也能轻松上手，预计制作时长仅需 15 分钟。', '[{"name":"洋葱","quantity":1,"unit":"颗"},{"name":"猪肉片","quantity":250,"unit":"克"},{"name":"蒜头","quantity":3,"unit":"瓣"},{"name":"食用油","quantity":15,"unit":"ml"},{"name":"黑胡椒","quantity":1.25,"unit":"克"},{"name":"酱油","quantity":30,"unit":"ml"},{"name":"糖","quantity":15,"unit":"克"},{"name":"麻油","quantity":5,"unit":"ml"},{"name":"番茄酱","quantity":15,"unit":"ml"},{"name":"料酒","quantity":15,"unit":"ml"}]'::jsonb, '["洋葱切片，猪肉，蒜头拍碎，以及混合上述调味料备用","炒锅内倒入 1 大匙食用油（等待 10 秒让油温升高），倒入猪肉","炒至变色后下蒜头炒香盛起备用","原锅下洋葱翻炒 3~4 分钟后加入调味料炒匀","下刚盛起备用的猪肉翻炒至猪肉熟后","待猪肉熟后再翻炒 1、2 分钟即可起锅"]'::jsonb, '["荤菜","家常","下饭","快手","咸甜","酱香","炒"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_fe618fc8ee.jpg', 'https://www.bilibili.com/video/BV1bLZAYkEcQ', '{"energyKcal":700,"protein":55,"carbs":40,"fat":38}'::jsonb, '[null,10,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/淄博烧烤/淄博烧烤', '淄博烧烤', '荤菜', 4, 40, '这是一道山东淄博特色烧烤，小饼卷肉配大葱的吃法风味独特，肉香、酱香与葱香交融，口感层次丰富。五花肉富含优质蛋白质和脂肪，大葱提供膳食纤维，搭配小饼能快速补充能量。制作需要控制炭火火候和翻烤技巧，对新手稍具挑战，全程约 40 分钟即可完成。', '[{"name":"猪五花肉","quantity":200,"unit":"克"},{"name":"小薄饼","quantity":5,"unit":"张"},{"name":"大葱","quantity":1,"unit":"根"},{"name":"芝麻酱","quantity":20,"unit":"克"},{"name":"甜面酱","quantity":15,"unit":"克"},{"name":"芝麻盐","note":"适量"},{"name":"温水","quantity":10,"unit":"ml"}]'::jsonb, '["五花肉切成厚度不超过 2cm 长的块，并串成串。（五花肉可以预先腌制一下，味道更佳）","大葱切成 5cm 长的葱段，备用","芝麻酱加 10ml 温水调稀，与甜面酱混合均匀，备用（可以换成\"芝麻盐\"）","点燃炭火，等待炭火烧至通红无明火状态（约 15 分钟）","将五花肉串均匀摆在在烤网上，烤至底面焦黄出油后翻面","继续烤制约 2 - 3 分钟，至两面焦黄、边缘微焦后取下","取一张小薄面饼平铺，抹上 3 - 4g 混合酱料","放上烤好的肉片和 1 - 2 段大葱，卷起即可食用"]'::jsonb, '["荤菜","炭烤","鲁菜","鲜香","下酒","聚餐"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_c91532835d.jpg', 'https://www.bilibili.com/video/BV11P41197zR', '{"energyKcal":525,"protein":20,"carbs":32,"fat":31}'::jsonb, '[null,null,null,900,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/清蒸鳜鱼/清蒸鳜鱼', '清蒸鳜鱼', '荤菜', 3, 30, '清蒸鳜鱼肉质细嫩，鲜甜本味突出，是讲究原汁原味的家常河鲜做法。鳜鱼富含优质蛋白和多种微量元素，易于消化吸收。处理时需小心鱼鳍，但整体步骤不复杂，新手稍加注意也能胜任。从备料到出锅，大约只需半小时。', '[{"name":"鳜鱼","quantity":500,"unit":"克"},{"name":"大葱","quantity":1,"unit":"节"},{"name":"小葱","quantity":2,"unit":"根"},{"name":"生抽","quantity":30,"unit":"克"},{"name":"红辣椒","quantity":1,"unit":"颗"},{"name":"姜片","quantity":3,"unit":"片"},{"name":"食用油","quantity":20,"unit":"ml"}]'::jsonb, '["食材处理：","鳜鱼从腹部切开，去除鱼鳃和内脏，打去鱼鳞，用到在表皮上刮去粘液（这一步也可让热心摊主处理）","鳜鱼身上打上花刀，放姜片，有条件的可以放点猪油，装盘在下面垫一个筷子，便于蒸制时受热均匀","大葱划开后去除中间的芯，只保留外面两层","小葱划开备用","红椒去除辣椒籽和里层辣椒肉备用","将准备好的大葱、小葱、辣椒码在一起，切成丝泡在水里备用","炒制过程：","锅里加水，水量大一些，水热后放入鳜鱼，盖上锅盖，大火蒸制 8 - 10 分钟，蒸鱼四字窍门：汽大火足","蒸鱼过程，另起一个过热油，油需要烧到冒烟","蒸制结束后，倒掉蒸鱼的水，去除姜片，放上葱丝，浇上热油","在倒入生抽或蒸鱼豉油即可上桌"]'::jsonb, '["荤菜","清蒸","鲜香","清淡","河鲜","家常","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_4144963abb.jpg', 'https://www.bilibili.com/video/BV1Vx411o7Qj', '{"energyKcal":480,"protein":48,"carbs":4,"fat":26}'::jsonb, null),
  ('howtocook:meat_dish/湖南家常红烧肉/湖南家常红烧肉', '湖南家常红烧肉', '荤菜', 3, 60, '湖南家常红烧肉是一道湘味浓郁的家常菜，五花肉经慢炖后肥而不腻、入口软糯，咸香中带着微辣回甘。富含优质蛋白和脂肪，能为身体提供充足能量。制作需要一些耐心，对新手有一定挑战，但按步骤操作不难掌握，预计全程约 1 小时。', '[{"name":"带皮五花肉","quantity":500,"unit":"克"},{"name":"食用油","quantity":10,"unit":"克"},{"name":"冰糖","quantity":6,"unit":"颗"},{"name":"香叶","quantity":5,"unit":"片"},{"name":"姜","quantity":3,"unit":"片"},{"name":"桂皮","quantity":1,"unit":"小块"},{"name":"八角","quantity":3,"unit":"颗"},{"name":"料酒","quantity":20,"unit":"克"},{"name":"生抽","quantity":5,"unit":"克"},{"name":"老抽","quantity":2,"unit":"克"},{"name":"盐","quantity":2,"unit":"克"},{"name":"干小米椒","note":"根据个人情况"},{"name":"开水","note":"适量"}]'::jsonb, '["带皮五花肉洗净冷水下锅，加入姜片 2~3 片去腥味，煮到沸腾捞出冷水冲净白沫","五花肉切块，尺寸 1.5cm1.5cm 块状大小","热锅加入油，加入冰糖小火搅拌至焦糖色即可，加入切好的五花肉，中火翻炒上色","加入备好的姜片、八角、桂皮、生抽、老抽、料酒、干小米椒、盐，小火翻炒 1 分钟，加开水没过肉","加盖中火煮沸，转小火慢顿 30 分钟，慢炖期间，间隔 10 分钟搅拌一次防止粘锅","小火慢炖汤汁剩三分之一的时，调成中火收汁出锅。"]'::jsonb, '["荤菜","湘味","家常","红烧","下饭","咸香微辣"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_b8ea66d7fa.jpeg', 'https://www.bilibili.com/video/BV1vfHfzYELM', '{"energyKcal":760,"protein":12,"carbs":10,"fat":62}'::jsonb, '[null,null,null,60,1800,null]'::jsonb),
  ('howtocook:meat_dish/湘祁米夫鸭/湘祁米夫鸭', '湘祁米夫鸭', '荤菜', 4, 60, '湖南两祁地区传统特色菜，鸭肉煸炒后裹上混合米粉蒸制，口感软糯，咸香入味，回味悠长。鸭肉富含优质蛋白质和 B 族维生素，搭配米粉提供能量，营养均衡。制作需先煸炒再高压蒸制，稍有难度，适合有一定烹饪基础的朋友。从备料到出锅大约需要 1 小时，若选用老鸭需延长蒸制时间。', '[{"name":"鸭子","quantity":1000,"unit":"克"},{"name":"糯米粉","quantity":100,"unit":"克"},{"name":"粘米粉","quantity":300,"unit":"克"},{"name":"蒸肉粉","quantity":50,"unit":"克"},{"name":"细辣椒粉","quantity":50,"unit":"克"},{"name":"白胡椒粉","quantity":5,"unit":"克"},{"name":"五花肉","quantity":50,"unit":"克"},{"name":"姜蒜","quantity":20,"unit":"克"},{"name":"盐","quantity":10,"unit":"克"},{"name":"食用油","quantity":10,"unit":"克"},{"name":"开水","quantity":100,"unit":"克"},{"name":"葱花","note":"适量"}]'::jsonb, '["将糯米粉、粘米粉、蒸肉粉、细辣椒粉、5 克盐、白胡椒粉倒一起搅匀","鸭子让热心摊主剁成蒸煮块，姜切片，蒜子剥皮，五花肉切片即可","热锅凉油煸炒五花肉出油，再加食用油烧热，下入鸭子煸炒","鸭子煸炒到表皮焦变色，下入姜蒜和盐继续煸炒香味","关小火倒入米粉翻炒，鸭肉均匀裹满米粉子，加入开水，少量多次的加，边加边翻炒","翻炒鸭肉和米粉有湿感，铲出入碗中，高压锅放水蒸 20-25 分钟","出锅前撒点葱花即可享用了"]'::jsonb, '["荤菜","湖南","蒸菜","咸香","下饭","地方特色"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_420949124f.jpg', 'https://www.bilibili.com/video/BV1MG4y1B7np', '{"energyKcal":950,"protein":40,"carbs":90,"fat":45}'::jsonb, '[null,null,null,null,null,1200,null]'::jsonb),
  ('howtocook:meat_dish/澳门湿版免治牛肉饭/澳门湿版免治牛肉饭', '澳门湿版免治牛肉饭', '荤菜', 2, 30, '这是一道经典的澳门葡式风味快餐，牛肉碎嫩滑咸香，裹着浓郁酱汁和半熟蛋液，拌入米饭后口感油润诱人。牛肉末提供优质蛋白质，搭配鸡蛋和洋葱，营养均衡管饱。操作步骤简单易上手，特别适合新手尝试，从备料到出锅大约只需 30 分钟。', '[{"name":"牛肉末","quantity":200,"unit":"克"},{"name":"洋葱","quantity":0.5,"unit":"个"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"黄油","quantity":10,"unit":"克"},{"name":"小葱","quantity":5,"unit":"克"},{"name":"生抽","quantity":3,"unit":"汤匙"},{"name":"老抽","quantity":0.5,"unit":"汤匙"},{"name":"番茄酱","quantity":2,"unit":"汤匙"},{"name":"白糖","quantity":0.5,"unit":"汤匙"},{"name":"料酒","quantity":1,"unit":"汤匙"},{"name":"黑胡椒","quantity":2,"unit":"克"},{"name":"淀粉","quantity":1,"unit":"汤匙"},{"name":"清水","quantity":50,"unit":"ml"},{"name":"米饭","note":"适量"}]'::jsonb, '["将 200g 牛肉末放入碗中，加入 1 汤匙生抽、半汤匙白糖和 2g 黑胡椒，搅拌均匀，等待腌制 10 分钟。","将半个洋葱切成小丁，备用。","调制料汁：在碗中加入 2 汤匙生抽、2 汤匙番茄酱、1 汤匙料酒、1 汤匙淀粉、半汤匙老抽和 50ml 清水，搅拌均匀备用。","另起一锅，制作一个水波蛋或半熟煎蛋，备用。","热锅，放入 10g 黄油。待黄油融化后，放入洋葱丁，小火煎熟至散发香味。","加入腌制好的牛肉末，与洋葱一起翻炒至牛肉变色。","倒入调好的料汁，撒上 2g 黑胡椒，继续炒制直至汤汁变粘稠后关火。","将炒好的免治牛肉浇在热米饭上，放上提前准备好的水波蛋或半熟煎蛋。","（可选）表面撒上 5g 切好的小葱花作装饰。"]'::jsonb, '["荤菜","澳门风味","葡式","牛肉","快餐","拌饭","免治牛肉","新手友好"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_add14ccd38.jpg', 'https://www.bilibili.com/video/BV12j411F7cv', '{"energyKcal":705,"protein":37,"carbs":70,"fat":30}'::jsonb, '[600,null,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/烤鸡翅', '烤鸡翅', '荤菜', 3, 60, '腌制入味的鸡中翅经高温烘烤，外皮微焦、内里鲜嫩多汁，带有黑胡椒和酱油的咸香。富含优质蛋白质和胶原蛋白。难度适中，新手也能轻松上手，从准备到出炉大约需要 1 小时。还可按喜好添加蜂蜜或五香粉增添风味。', '[{"name":"鸡翅中","quantity":3,"quantityMax":4,"unit":"个"},{"name":"盐","quantity":2,"unit":"克"},{"name":"黑胡椒粉","quantity":1,"unit":"克"},{"name":"酱油","quantity":3,"unit":"ml"},{"name":"料酒","quantity":3,"unit":"ml"}]'::jsonb, '["鸡翅放入碗中","加盐、黑胡椒粉、酱油、料酒进行腌制 30-40 分钟","将烤箱预热至 200℃","将腌制好的鸡翅均匀地放在烤盘上","将烤盘放入烤箱中层，烤 15-20 分钟","取出烤盘，将鸡翅翻面，再烤 15-20 分钟，直到熟透"]'::jsonb, '["荤菜","咸香","烧烤","家常","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_9f80a2a4c9.jpg', 'https://www.bilibili.com/video/BV14b411g7Gm', '{"energyKcal":260,"protein":22,"carbs":3,"fat":18}'::jsonb, '[null,1800,null,null,900,900]'::jsonb),
  ('howtocook:meat_dish/煎烤羊排/煎烤羊排', '煎烤羊排', '荤菜', 4, 60, '一道外酥里嫩、香气浓郁的料理，先以香料炖煮再煎出金黄脆壳，风味浓郁不腻，是家常宴客两相宜的硬菜。羊肉富含优质蛋白和铁、锌等矿物质，有助于温补气血。做法步骤稍多，但只要按流程走，新手也能拿下；使用高压锅全程约 1 小时，普通锅约 1.5 小时。', '[{"name":"羊排","quantity":750,"unit":"克"},{"name":"桂皮","quantity":2,"unit":"克"},{"name":"花椒","quantity":5,"unit":"克"},{"name":"八角","quantity":1,"unit":"颗"},{"name":"白芷","quantity":6,"unit":"克"},{"name":"香叶","quantity":5,"unit":"片"},{"name":"盐","quantity":25,"unit":"克"},{"name":"料酒","quantity":10,"unit":"ml"},{"name":"辣椒粉","quantity":5,"unit":"克"},{"name":"孜然粒","quantity":2,"unit":"克"},{"name":"烧烤撒料","quantity":2,"unit":"克"},{"name":"孜然粉","quantity":2,"unit":"克"},{"name":"白芝麻","quantity":2,"unit":"克"},{"name":"糖","quantity":1,"unit":"克"}]'::jsonb, '["将羊排按照骨头分布，切成块状。","炒锅中加入冷水，放入全部羊排块，水沸腾后继续焯水 2 - 3 分钟，捞出备用。","将焯好水的羊排、桂皮、花椒、八角、白芷、香叶、料酒放入锅中（高压锅或普通锅）。","加入饮用水没过所有食材。如果使用高压锅，上汽后压 30 分钟。如果使用普通锅，炖煮 80 分钟。","将炖煮完成的羊排捞出，沥干水分，放入无油无水的炒锅 / 煎锅中。","中大火煎 6 - 7 分钟，直至羊排中的油脂被煎出，表面呈金黄酥脆状态。","锅中保留煎出的羊油，加入辣椒粉、孜然粒、烧烤撒料、孜然粉、白芝麻，翻炒均匀。","加入糖和盐（如果在炖煮步骤中未添加），翻炒均匀。","翻炒均匀后即可关火，盛盘。"]'::jsonb, '["荤菜","煎烤","香辣","外酥里嫩","家常","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_b9aba40f32.jpg', 'https://www.bilibili.com/video/BV1ov411z7eY', '{"energyKcal":580,"protein":42,"carbs":2,"fat":45}'::jsonb, null),
  ('howtocook:meat_dish/牛排/牛排', '牛排', '荤菜', 4, 25, '这是一道经典的西式煎牛排，焦香外壳包裹着鲜嫩多汁的肉心，搭配黄油、大蒜和香草，风味浓郁。富含优质蛋白质、油脂及铁、锌等矿物质。烹饪流程对新手较为友好，但掌握火候仍需一些练习，全程 15-30 分钟即可完成。', '[{"name":"牛排","quantity":450,"quantityMax":500,"unit":"克"},{"name":"橄榄油","quantity":10,"quantityMax":15,"unit":"ml"},{"name":"黄油","quantity":20,"quantityMax":25,"unit":"克"},{"name":"盐","quantity":5,"unit":"克"},{"name":"黑胡椒粉","quantity":2,"unit":"克"},{"name":"大蒜","quantity":1,"unit":"个"},{"name":"百里香","quantity":2,"unit":"克"},{"name":"迷迭香","note":"适量"},{"name":"预制牛排酱汁","note":"适量"},{"name":"口蘑","quantity":5,"quantityMax":10,"unit":"个"},{"name":"小土豆","quantity":5,"quantityMax":10,"unit":"个"},{"name":"小番茄","quantity":5,"quantityMax":10,"unit":"个"},{"name":"芦笋","note":"适量"}]'::jsonb, '["从冰箱中取出牛排解冻。","如果牛排处于冰冻状态，需提前一晚转移至冷藏室，并在烹饪前半小时放置在常温中。","请勿将牛排置于水中或加热解冻。","将小番茄，小土豆和口蘑洗净，对半切开备用。","将大蒜剥皮，留 5-8 个较大的蒜瓣，用刀背压扁备用。","牛排的预处理","对于肉眼牛排（见如何选择不同种类的牛排），使用厨房剪刀竖直插入到肉眼牛排中心的结缔组织，剪 1-2 刀。这是因为肉眼牛排的“肉眼”（即这块结缔组织）在高温下会剧烈收缩导致牛排变形，使得牛排无法均匀受热。","对于西冷牛排，如果您不喜欢西冷牛排边上的油脂，可以用刀慢慢将其剔除。","随后，使用厨房纸包裹牛排，将牛排上附着的水全部吸干，直至牛排放在案板上拿起后不留下明显水渍即可。","将炉灶打开高火（见附录对于火力大小的说明），同时锅中加入橄榄油，热锅 15-30 秒。","腌制牛排。将海盐和黑胡椒均匀的洒在牛排的全部表面并用手涂抹，揉搓，使得盐和胡椒颗粒尽量嵌入到肉中。注意，腌制完成后牛排需要立即下锅，不推荐提前腌制牛排。这是因为外表涂抹的盐会析出牛肉中的水分，影响烹饪的同时丧失风味。","热锅至油温 6-8 成（参见油温判断技巧），将牛排由近及远的缓慢放入锅中。","如果您使用了土豆作为配菜，可以将土豆放入碗中，然后放进微波炉加热 10 分钟，或者放入开水煮 3-5 分钟。","单面煎制 1.5 分钟（这个时间适用于 2-3cm 厚大约的牛排。如果您的牛排更薄，考虑将这个时间缩短为 1 分钟。如果您的牛排更厚，考虑将这个时间增加至 2-2.5 分钟。）","翻面，再煎制 1.5 分钟。","对于西冷牛排和菲力牛排，您需要使用筷子或者锅铲将牛排竖起来，煎它的侧面约 30 秒。","将炉灶切换至中火，随后按顺序快速加入黄油、大蒜、百里香。用锅铲推动黄油在锅中快速涂抹直至完全融化。将大蒜压在牛排下以增加风味。","将平底锅倾斜地放在灶上，使得油全部流到锅的一侧。","将香料和大蒜放置在牛排上，用汤匙舀起锅中的油，不断地淋在牛排上。这个过程持续 30 秒，随后将牛排翻面，再重复这个过程 30 秒。","您可以通过观察油淋在牛排表面时的状态来判断当前的火候。如果油淋在牛排上时冒泡并且油的颜色没有变成深褐色，则油温合适。","如果您的牛排没有擦干净或使用了不推荐的方式解冻，或者使用盐进行了提前腌制，这个时候锅中会出现大量水，导致牛排最后是被“煮熟”的，从而丧失风味。","如果牛排表面出现大量的油泡并且油的颜色变成深褐色，则说明油温过高，您需要将锅移开灶台，稍等片刻再继续淋油。","将牛排盛出放在案板上，用锡箔纸包裹，等待 5-10 分钟。这个过程（称为醒肉）的作用是利用牛排自身的温度继续加热，锁住水分。","将配菜（土豆，番茄，蘑菇）倒入锅中，开中火煎 5 分钟。","取出牛排，用刀切成宽度 1.5cm 宽度的肉条，此时您可以观察到牛肉的熟度。","取出配菜，装盘，淋上锅中剩余的油或者牛排酱汁（可选）"]'::jsonb, '["荤菜","西式","煎制","鲜香","宴客","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_4fff0bf7bb.jpg', 'https://www.bilibili.com/video/BV1dN4y1D7j8', '{"energyKcal":830,"protein":55,"carbs":35,"fat":70}'::jsonb, '[null,1800,null,null,null,null,null,null,null,null,null,null,null,90,90,30,null,null,60,null,null,null,null,300,null,null]'::jsonb),
  ('howtocook:meat_dish/猪皮冻/猪皮冻', '猪皮冻', '荤菜', 3, 1440, '猪皮冻是北方年夜饭常见的传统凉菜，晶莹剔透，口感滑嫩 Q 弹，特别适合下酒。猪皮富含胶原蛋白，有美容养颜的作用。这道菜难度稍高，需要耐心处理猪皮去腥和长时间熬煮，预计制作时长约 24 小时。', '[{"name":"猪皮","quantity":1,"unit":"kg"},{"name":"水","quantity":4,"unit":"kg"},{"name":"盐","quantity":13,"unit":"克"},{"name":"味精","quantity":10,"unit":"克"},{"name":"鸡精","quantity":15,"unit":"克"},{"name":"生抽","quantity":50,"unit":"ml"},{"name":"老抽","quantity":20,"unit":"ml"},{"name":"葱","quantity":10,"unit":"克"},{"name":"姜片","quantity":20,"unit":"克"},{"name":"姜","quantity":10,"unit":"克"},{"name":"大料","quantity":10,"unit":"克"},{"name":"花椒","quantity":5,"unit":"克"},{"name":"料酒","quantity":50,"unit":"ml"},{"name":"白醋","quantity":20,"unit":"克"},{"name":"白芷","note":"适量"},{"name":"桂皮","note":"适量"},{"name":"丁香","note":"适量"},{"name":"香叶","note":"适量"},{"name":"小茴香","note":"适量"}]'::jsonb, '["将猪皮，剁成不超过 10cm 小块，用清水浸泡 12 小时，然后冷水下锅，加入姜 10g、料酒 50ml 后，汆烫 5-10 分钟，捞出放入冷水中","将焯过水的猪皮，放到案板上，将里面的白肉部分全部剔除，然后再切成成不超过 3mm 的长条，放入盆中","加入白醋 20g，盐 5g，用力搓洗 3 分钟，再用清水洗净，这时的猪皮已经基本没什么腥味","锅内加入 4kg 水，放入猪皮，葱 10g，姜片 10g，八角 10g，花椒 5g，大火烧开后，小火煲煮 90 分钟至猪皮软烂","再加入盐 8g、味精 10g、鸡精 15g、生抽 50ml、老抽 20ml 调味后，倒入盘中，将葱姜，八角拣出，晾凉至果冻状","放冰箱冷藏即可，食用时，切成小块或者厚片"]'::jsonb, '["荤菜","咸鲜","炖煮","北方","下酒","年夜饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_04f8069805.jpg', 'https://www.bilibili.com/video/BV1Ru411D7ju', '{"energyKcal":110,"protein":10,"carbs":0,"fat":7}'::jsonb, '[43200,null,180,5400,null,null]'::jsonb),
  ('howtocook:meat_dish/猪肉烩酸菜', '猪肉烩酸菜', '荤菜', 5, 180, '猪肉烩酸菜是一道北方家常炖菜，酸香浓郁，五花肉软烂，排骨入味。主要提供蛋白质，酸菜也带来乳酸菌等有益成分。做法步骤清晰，新手也能按部就班完成，但需耐心慢炖，从头到尾大约需要 3 小时。', '[{"name":"猪五花肉或猪肉排骨","quantity":1500,"unit":"克"},{"name":"东北酸菜","quantity":1000,"unit":"克"},{"name":"大葱","quantity":1,"unit":"根"},{"name":"姜","quantity":100,"unit":"克"},{"name":"蒜","quantity":4,"unit":"瓣"},{"name":"盐","quantity":10,"unit":"克"},{"name":"生抽酱油","quantity":15,"unit":"克"},{"name":"五香粉","quantity":10,"unit":"克"},{"name":"料酒","quantity":20,"unit":"毫升"},{"name":"大料","quantity":2,"unit":"颗"}]'::jsonb, '["大葱切段；生姜 50 克切段， 50 克切末；大蒜切末，备用。","全部酸菜切丝，用水冲洗 2 ～ 3 遍备用。","排骨和五花肉入锅，倒入冷水淹没。放入全部葱段， 50 克生姜段和料酒 20 毫升。大火煮开后，等待 5 分钟。关火，将排骨和五花肉捞出，冷水冲洗掉浮沫，备用","煮好的五花肉切片或者切块，备用。","将之前的锅洗干净，并且擦干（不然加入油会崩出来）。","锅中加入油，开中火，放入姜蒜末爆香，放入五花肉和排骨。将五花肉和排骨煎至金黄，倒入 10 克五香粉和 15 克 生抽酱油，用铲子翻动 1 ～ 2 分钟。","将冲洗好的酸菜丝加入锅中，翻炒 3 分钟。","倒入纯净水至刚好没过食材，加入 2 颗大料，转大火，直到锅中水沸腾。转中火，盖锅盖焖煮。","等待 1.5 ～ 2 小时，直至五花肉软烂 （可以用筷子轻松扎穿）","掀开锅盖，开大火收汤，翻动锅中食材直至锅中剩余水分只覆盖锅底，转小火，准备调味。","调味：加入食用盐 10 克，搅拌均匀。","关火，出锅。"]'::jsonb, '["荤菜","酸香","炖菜","北方","家常","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_3095dc5354.jpg', 'https://www.bilibili.com/video/BV17341127kz', '{"energyKcal":620,"protein":28,"carbs":7,"fat":50}'::jsonb, '[null,null,300,null,null,null,180,null,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/甜辣烤全翅', '甜辣烤全翅', '荤菜', 3, 180, '这道甜辣烤全翅利用空气炸锅烹制，外皮微焦、内里多汁，甜中带辣的风味很受欢迎。鸡肉富含优质蛋白质，用空气炸代替油炸大幅减少了油脂，吃起来负担更轻。制作流程清晰明了，只需提前腌制并中途翻面一次，对新手也比较友好。从处理食材到出锅大约需要 3 个小时，大部分是静置腌制的时间，实际操作并不繁琐。', '[{"name":"鸡全翅","quantity":4,"unit":"个"},{"name":"生抽","quantity":45,"unit":"ml"},{"name":"老抽","quantity":15,"unit":"ml"},{"name":"蒜粉","quantity":10,"unit":"g"},{"name":"胡椒粉","quantity":5,"unit":"g"},{"name":"糖","quantity":10,"unit":"g"},{"name":"甜椒粉","quantity":10,"unit":"g"},{"name":"辣椒粉","quantity":5,"unit":"g"},{"name":"蚝油","quantity":15,"unit":"ml"},{"name":"水","quantity":20,"unit":"ml"},{"name":"油","quantity":10,"unit":"ml"}]'::jsonb, '["将 4 个新鲜鸡全翅取出，在翅中两根骨头之间用刀划开表皮，正反面各一刀","将 4 个鸡全翅放入碗中，加入生抽 45ml ， 老抽 15ml ， 蒜粉 10g ， 胡椒粉 5g ， 糖 10g ， 甜椒粉 10g ，辣椒粉 5g ， 蚝油 15ml ， 水 20ml 以及油 10ml","用勺子将酱汁均匀的抹在鸡全翅上，尤其是翅中的刀口处，大约花费 3 分钟","用保鲜膜盖住防油腌制中鸡全翅的碗，放入冰箱冷藏格静置 120 分钟","取出鸡全翅，锡纸盘中放入鸡全翅 4 个，将碗中残余酱料均匀倒在鸡全翅上","锡纸盘放入空气炸锅的烤篮上，用 200 摄氏度烤 25 分钟","打开空气炸锅，小心取出锡纸盘，将鸡全翅翻面","继续 200 摄氏度烤 25 分钟","取出即可食用"]'::jsonb, '["荤菜","甜辣","烤制","空气炸锅","下酒","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_3a0c0811f4.jpg', 'https://www.bilibili.com/video/BV1hm421K7zo', '{"energyKcal":420,"protein":30,"carbs":5,"fat":25}'::jsonb, '[null,null,180,7200,null,1500,null,1500,null]'::jsonb),
  ('howtocook:meat_dish/田螺酿/田螺酿', '田螺酿', '荤菜', 4, 40, '田螺酿是阳朔“十八酿”之首，螺肉韧而紧致、猪肉嫩滑，紫苏薄荷清香扑鼻，曾登上《舌尖上的中国 2》。富含蛋白质和多种微量元素，螺肉与猪肉搭配营养互补。这道菜步骤稍多，对新手有一定挑战，需提前半天让田螺吐沙，正式制作约 40 分钟，适合节假日全家一起动手。', '[{"name":"大田螺","quantity":20,"unit":"个"},{"name":"猪肉","quantity":250,"unit":"克"},{"name":"薄荷叶","quantity":10,"unit":"克"},{"name":"紫苏叶","quantity":10,"unit":"克"},{"name":"生姜","quantity":15,"unit":"克"},{"name":"葱","quantity":2,"unit":"根"},{"name":"桂林三花酒","quantity":15,"unit":"ml"},{"name":"生抽","quantity":30,"unit":"ml"},{"name":"食盐","quantity":5,"unit":"克"},{"name":"食用油","quantity":30,"unit":"ml"},{"name":"酸笋","quantity":50,"unit":"克"},{"name":"大蒜","quantity":5,"unit":"瓣"},{"name":"干辣椒","quantity":4,"unit":"个"},{"name":"蚝油","quantity":10,"unit":"ml"},{"name":"淀粉","quantity":10,"unit":"克"},{"name":"白胡椒粉","quantity":2,"unit":"克"}]'::jsonb, '["上午买回田螺，放入清水盆中，静置一下午吐沙","可在水中滴几滴香油（或者芥末~）加速吐沙","用刷子将田螺外壳刷洗干净（这一步可以时间久一些）","用老虎钳或菜刀剪去田螺尾部（约剪掉 1/3 到一半）","大锅烧水，水开后放入田螺焯烫 1-2 分钟（时间不可太久，螺肉会老）","捞出后用牙签挑出螺肉，去掉螺盖和黑色泥肠","螺壳用水冲洗干净，甩干水分备用","螺肉用盐抓洗干净，剁成碎粒（不要剁成泥，保留颗粒感才有嚼头）","猪肉剁成肉末","薄荷叶、紫苏叶切碎，姜切末，葱切葱花","将螺肉碎、猪肉末、薄荷碎、紫苏碎、姜末、葱花放入碗中","加入三花酒 15ml、生抽 15ml、食盐 3g","可选加入：蚝油 10ml、白胡椒粉 2g、淀粉 10g","朝一个方向搅拌至馅料粘稠上劲","图省事上面的所有东西直接放入打肉机直接打。","将馅料用筷子塞入田螺壳中，尽量塞满塞紧，但不要撑破螺壳","依次酿完所有田螺","热锅，倒入 30ml 食用油，可选放入酸笋和干辣椒炒出香味","倒入清水或高汤约 300ml，加生抽 15ml、食盐 2g，大火烧开","将酿好的田螺放入锅中，盖上锅盖，中小火焖煮 10 分钟","焖煮过程中不要频繁翻动，等肉馅六七成熟定型后再轻轻翻动","开盖，放入剩余的新鲜薄荷叶和紫苏叶，再焖 2-3 分钟","大火收汁至汤汁浓稠，即可出锅"]'::jsonb, '["荤菜","鲜香","酿菜","焖煮","桂菜","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_300069065c.jpeg', 'https://www.bilibili.com/video/BV1gK411P7xK', '{"energyKcal":350,"protein":26,"carbs":4,"fat":28}'::jsonb, '[null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,600,null,null,null]'::jsonb),
  ('howtocook:meat_dish/番茄红酱', '番茄红酱', '荤菜', 4, 60, '这款意式风味酱料香浓可口，蔬菜与牛肉的搭配带来丰富口感。它富含蛋白质和多种维生素，营养均衡。制作过程稍有繁琐，需要一些烹饪基础，例如炒出颗粒感的牛肉和控火慢煮。从备料到完成约需一小时，一次可多做一些冷冻保存，随取随用十分方便。', '[{"name":"碎牛肉","quantity":500,"unit":"克"},{"name":"蒜瓣","quantity":2,"unit":"个"},{"name":"胡萝卜","quantity":0.5,"unit":"根"},{"name":"芹菜","quantity":1,"unit":"根"},{"name":"洋葱","quantity":0.5,"unit":"个"},{"name":"橄榄油","quantity":10,"unit":"ml"},{"name":"糖","quantity":2,"unit":"克"},{"name":"食盐","quantity":10,"unit":"克"},{"name":"黑胡椒粉","quantity":5,"unit":"克"},{"name":"番茄酱","quantity":300,"unit":"克"},{"name":"牛奶","quantity":300,"unit":"ml"},{"name":"干罗勒或百里香（可选）","note":"适量"}]'::jsonb, '["将胡萝卜、芹菜、洋葱切碎，蒜瓣切片。","加入 10ml 橄榄油，热油下锅蔬菜，大火翻炒开始略微变色后盛出。","锅内加油 10ml，加蒜翻炒 10 秒，加入碎牛肉、糖、盐、胡椒粉和香料将牛肉炒脆（有颗粒感）。","加入炒好的蔬菜们和番茄酱继续翻炒，搅拌均匀。","分多次缓缓倒入牛奶，中小火煮 30 分钟，完成。"]'::jsonb, '["荤菜","意式","炖煮","酱香","佐餐","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_c1d8712d21.jpg', 'https://www.bilibili.com/video/BV1Za41177d9', '{"energyKcal":310,"protein":20.7,"carbs":14.6,"fat":18.8}'::jsonb, '[null,null,10,null,1800]'::jsonb),
  ('howtocook:meat_dish/瘦肉土豆片/瘦肉土豆片', '瘦肉土豆片', '荤菜', 3, 60, '一道快手家常小炒，肉片滑嫩，土豆片软韧入味，带有蒜苗清香，属于典型的家常菜风格。瘦肉富含优质蛋白质和铁质，土豆提供碳水化合物和膳食纤维，搭配均衡。制作流程简单明了，需注意刀工和火候，适合有一定基础的新手尝试。从备料到出锅，预计 大约 1 小时即可完成。', '[{"name":"纯瘦肉","quantity":200,"unit":"克"},{"name":"土豆","quantity":200,"unit":"克"},{"name":"蒜苗","quantity":2,"unit":"根"},{"name":"生粉","quantity":5,"unit":"克"},{"name":"生抽","quantity":10,"unit":"克"},{"name":"老抽","quantity":3,"unit":"克"},{"name":"食用盐","quantity":2,"unit":"克"},{"name":"食用油","quantity":10,"quantityMax":15,"unit":"ml"}]'::jsonb, '["土豆去皮、对半切开，再切成约 2mm 的薄片，备用","蒜苗洗净，切成约 1cm 的段，备用","瘦肉洗净切成约 2mm 的薄片，放入碗中，加入 5g 生粉、5g 生抽、3g 老抽腌制十分钟，备用","瘦肉腌制时，烧一锅开水，将土豆片放入锅中，焯水，约 5 分钟","热锅，锅内放入 10ml - 15ml 食用油。等待 10 秒让油温升高","放入瘦肉，翻炒至变色，倒入蒜苗一起炒，蒜苗炒约 20 秒","放入土豆，保持翻炒，加入 2g 食用盐、5g 生抽，","炒约 3 分钟，盛盘"]'::jsonb, '["荤菜","家常","快手","小炒","下饭","清香"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_0825a69d53.jpg', 'https://www.bilibili.com/video/BV1xTxieNEYe', '{"energyKcal":580,"protein":58,"carbs":41,"fat":18}'::jsonb, '[null,null,600,300,10,20,null,180]'::jsonb),
  ('howtocook:meat_dish/白菜猪肉炖粉条', '白菜猪肉炖粉条', '荤菜', 3, 45, '猪肉白菜炖粉条是东北地区经典的家常炖菜，汤汁浓郁咸鲜，五花肉软烂、粉条吸饱肉香后滑韧入味，白菜清甜解腻。整道菜荤素搭配均衡，能提供蛋白质、维生素和碳水化合物，营养饱腹。制作过程需要一些耐心，特别是粉条处理和炖煮火候，对新手有一定挑战，但按步骤操作不易失败，从头到尾大约需要 45 分钟即可上桌。', '[{"name":"五花肉","quantity":300,"unit":"克"},{"name":"大白菜","quantity":500,"unit":"克"},{"name":"土豆干粉条","quantity":50,"unit":"克"},{"name":"十三香","quantity":10,"unit":"克"},{"name":"鸡精","quantity":5,"unit":"克"},{"name":"食用盐","quantity":15,"unit":"克"},{"name":"老抽","quantity":5,"unit":"ml"},{"name":"生抽","quantity":5,"unit":"ml"}]'::jsonb, '["锅内烧水，水开后放入干粉条，煮 5 分钟后同水一起倒出容器中，盖上盖子继续浸泡泡 备用（第一步先做这个，期间可以进行以下步骤）","五花肉切 3mm 的肉片，备用","大白菜嫩叶与白菜帮子分开切成 2 份菜片，备用","热锅，锅内放入 10ml - 15ml 食用油。等待 10 秒让油温升高","放入五花肉，保持翻炒至肉变色","加入老抽，炒 1 分钟，给肉上色","加入白菜帮子，加入食用盐、生抽，炒一分钟（如果粘锅，烹入 10ml 水）","加水没过所有食材，加入鸡精 ，十三香，沸腾后，将火调小然后等待 20 分钟","粉条滤水切成小段放入碗中 备用","加入白菜嫩叶，炒匀后将粉条放在菜上方，加盖再煮 5 分钟","尝味、关火，收汁"]'::jsonb, '["荤菜","东北菜","家常炖菜","咸鲜","下饭","荤素搭配"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_b4e894c965.jpg', 'https://www.bilibili.com/video/BV1ty6KYBEYz', '{"energyKcal":600,"protein":15,"carbs":23,"fat":47}'::jsonb, '[300,null,null,10,null,60,60,1200,null,300,null]'::jsonb),
  ('howtocook:meat_dish/空气炸锅脆皮现腌炸鸡/空气炸锅脆皮现腌炸鸡', '空气炸锅脆皮现腌炸鸡', '荤菜', 4, 70, '空气炸锅炸鸡是一道先腌后炸的家常肉菜，外壳酥脆、内里多汁，调味可以按口味灵活切换。鸡翅富含优质蛋白和脂肪，适合作为正餐主菜或加餐。实操约 55-70 分钟（含一次裹粉；若选二次裹粉时约 70-90 分钟），如追求最佳效果，可冷藏腌制过夜（提前一天准备，第二天再炸）。', '[{"name":"鸡翅中","quantity":6,"unit":"个"},{"name":"生抽","quantity":15,"unit":"ml"},{"name":"蒜粉","quantity":13,"unit":"克"},{"name":"paprika（红甜椒粉）","quantity":10,"unit":"克"},{"name":"洋葱粉","quantity":5,"unit":"克"},{"name":"黑胡椒粉","quantity":5,"unit":"克"},{"name":"中筋面粉","quantity":60,"unit":"克"},{"name":"淀粉","quantity":30,"unit":"克"},{"name":"食用油","quantity":5,"unit":"ml"},{"name":"酸奶或牛奶","quantity":5,"unit":"ml"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"泡打粉","quantity":1,"unit":"克"}]'::jsonb, '["鸡翅中清洗后擦干水分，每个鸡翅两面各划 2 刀，方便入味。","调制腌料：生抽 15ml、蒜粉 8g、红甜椒粉 5g、洋葱粉 3g、黑胡椒粉 3g，牛奶或希腊酸奶 5ml（可选，让鸡肉更滑嫩）搅拌均匀。","将腌料和鸡翅中一起放到大 zip 保鲜袋里充分搅拌按摩，在冰箱里静置一晚。","裹粉：中筋面粉 60g、淀粉 30g、蒜粉 5g、红甜椒粉 5g、洋葱粉 2g、黑胡椒粉 2g、泡打粉 1g（可选，让外壳更酥脆）搅拌均匀。","裹浆（可选）：鸡蛋 1 个，牛奶或水 5ml，充分打散。","裹粉：将鸡翅中抖干水分，放入裹粉中轻轻按压，抖落多余的粉，一旁静置 10 分钟。","裹浆（可选）：如想要更饱满的外壳，可以再裹一层浆，然后重复裹粉步骤。","将裹粉静置后的鸡翅放入裹浆，然后轻轻抖落多余的浆。","再次放入裹粉，轻轻按压，抖落多余的粉。","一旁静置 20 分钟（如有条件可以更久一点，外壳更牢固不易脱落）。","空气炸锅预热到 180°C，预热 5 分钟。","炸篮内刷薄油，鸡皮面朝下，鸡翅上喷或者刷薄油。","设定空气炸锅 180°C，先炸 10 分钟。","打开炸篮翻面，在鸡翅表面补喷或者刷薄油，再以 180°C 炸 6 分钟。","观察鸡皮颜色，并用牙签扎一下最厚的部分，看是否有血水流出。","如需要再以 200°C 炸 1-2 分钟补脆上色（可迭代进行，先炸 1 分钟观察再决定是否继续）。"]'::jsonb, '["荤菜","酥脆","蒜香","空气炸","家常","主菜"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_32c05ae062.jpg', 'https://www.bilibili.com/video/BV1PT411a7yH', '{"energyKcal":880,"protein":46,"carbs":72,"fat":48}'::jsonb, '[null,null,null,null,null,600,null,null,null,1200,300,null,600,360,null,60]'::jsonb),
  ('howtocook:meat_dish/粉蒸肉', '粉蒸肉', '荤菜', 4, 90, '粉蒸肉是一道经典中式蒸菜，香味浓郁，口感软糯，属于广泛流传的家常风味。五花肉提供优质蛋白质和脂肪，搭配土豆等根茎蔬菜，营养均衡。此菜适合有一定烹饪经验的人士制作，从准备到完成大约需要 90 分钟。', '[{"name":"五花肉","quantity":250,"unit":"克"},{"name":"蒸肉米粉","quantity":50,"unit":"克"},{"name":"生抽","quantity":7.5,"unit":"ml"},{"name":"老抽","quantity":5,"unit":"ml"},{"name":"料酒","quantity":7.5,"unit":"ml"},{"name":"郫县豆瓣酱","quantity":5,"unit":"克"},{"name":"姜末","quantity":5,"unit":"克"},{"name":"蒜末","quantity":5,"unit":"克"},{"name":"白砂糖","quantity":2.5,"unit":"克"},{"name":"土豆或南瓜","quantity":150,"unit":"克"},{"name":"清水","quantity":1000,"unit":"ml"}]'::jsonb, '["将五花肉洗净，切成长约 5cm、宽约 3cm、厚度约 0.5cm 的肉片","将姜、蒜切成颗粒直径不大于 1mm 的细末","取一大碗，放入切好的五花肉、15ml 生抽、10ml 老抽、15ml 料酒、10g 郫县豆瓣酱、10g 姜末、10g 蒜末、5g 白砂糖","用筷子搅拌均匀后，盖上保鲜膜，室温(20°C - 25°C)静置腌制 30 分钟","腌制完成后，加入 100g 蒸肉米粉，继续翻拌 2 分钟，确保每片肉都均匀裹粉","土豆去皮，切片厚度控制在 0.8cm，片面积约为 5cm x 5cm，重量控制在 300g","在直径 20cm 的深碗底部铺满土豆片，尽量无重叠","将拌好粉的五花肉均匀铺在土豆片上，压实","蒸锅中加入 2000ml 清水，开火加热至水面持续冒泡(100°C)","将装好食材的碗放入蒸锅内，盖好锅盖","保持中火蒸 60 分钟（火力保持在可持续沸腾的程度，约 600W 热功率）","时间结束后，用筷子插入肉块中央，若能轻松穿透并无明显阻力，则表明蒸熟","若未达到此状态，则继续加热 10 - 15 分钟，直至肉质软烂，油脂渗出","取出盛盘，即可食用"]'::jsonb, '["荤菜","川菜","蒸制","软糯","下饭","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_095155824b.jpg', 'https://www.bilibili.com/video/BV1Ne411U7ji', null, null),
  ('howtocook:meat_dish/糖醋排骨/糖醋排骨', '糖醋排骨', '荤菜', 4, 45, '糖醋排骨是一道酸甜可口、外酥里嫩的传统名菜，广受欢迎。排骨富含优质蛋白和钙质，有较好的滋补效果。这道菜涉及焯水、油炸、炒糖色和收汁等多个步骤，对火候和调味有一定要求，不算特别适合新手，但按照优化后的流程操作成功率较高。预计制作时长为 大约 45 分钟。', '[{"name":"排骨","quantity":300,"unit":"g"},{"name":"白砂糖","quantity":30,"unit":"g"},{"name":"食用油","quantity":300,"quantityMax":350,"unit":"ml"},{"name":"生抽","quantity":5,"unit":"ml"},{"name":"蚝油","quantity":5,"unit":"ml"},{"name":"老抽","quantity":5,"unit":"ml"},{"name":"鸡精","quantity":2,"unit":"g"},{"name":"姜片","quantity":2,"unit":"片"},{"name":"芝麻","quantity":2,"unit":"g"},{"name":"番茄酱","quantity":10,"unit":"g"},{"name":"香醋","quantity":5,"unit":"ml"},{"name":"五香粉","quantity":0.5,"unit":"g"}]'::jsonb, '["排骨与姜片放入冷水中，大火加热至水沸腾、出现大量泡沫后转中火，待水持续沸腾时再转小火焯水 2–3 分钟，捞出备用。","用开水反复清洗排骨 2–3 遍，确保彻底去除血沫。","在锅中倒入足够量的食用油进行深炸（油量依据锅具大小而定，建议约 300 ml 供一般家庭使用），待油温升至约 170°C 后，下排骨炸制 3–5 分钟，直至表面略呈金黄色，捞出控油。","另取干净锅，置于小火上加热 50 ml 热水，加入白砂糖 30 g，轻轻搅拌直至糖完全溶解，并略呈淡黄色。此步骤的重点在于观察糖溶解情况，无需过分依赖颜色变化。","将炸好的排骨倒入炒制糖水的锅中，迅速翻炒 30 秒后，依次加入香醋 5 ml、生抽 5 ml、蚝油 5 ml、鸡精 2 g、番茄酱 10 g、五香粉 0.5 g，再次翻炒 30 秒，使调料均匀裹覆排骨，然后加入开水至刚好没过排骨。","用大火将锅中液体煮沸后，加入老抽 5 ml 进行上色，并快速收汁；若排骨块较大，可转小火焖煮 5–10 分钟以便更好地入味，切勿采用中火长时间炖煮 20 分钟，以免损伤口感。","起锅装盘，撒上芝麻 2 g，即可享用。"]'::jsonb, '["荤菜","酸甜","油炸","家常","下饭","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_9df6ca2127.jpeg', 'https://www.bilibili.com/video/BV1pBGMzkEon', null, '[120,null,180,null,30,300,null]'::jsonb),
  ('howtocook:meat_dish/糖醋里脊', '糖醋里脊', '荤菜', 4, 50, '糖醋里脊酸甜浓郁、外酥里嫩，是广受欢迎的家常风味，在多地域菜系中都很常见。猪里脊提供优质蛋白，但裹粉油炸和糖醋汁使整体热量偏高。制作时需要掌握腌制、复炸和调汁火候，对新手稍有挑战，建议提前备好料并一气呵成。从备料到出锅大约需要 45 分钟到 1 小时。', '[{"name":"里脊肉","quantity":500,"unit":"克"},{"name":"醋","quantity":10,"unit":"克"},{"name":"白糖","quantity":30,"unit":"克"},{"name":"淀粉","quantity":50,"unit":"克"},{"name":"鸡蛋","quantity":50,"unit":"克"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"料酒","quantity":20,"unit":"克"},{"name":"蚝油","quantity":10,"unit":"克"},{"name":"番茄酱","quantity":30,"unit":"ml"},{"name":"白胡椒粉","quantity":5,"unit":"克"},{"name":"食盐","quantity":10,"unit":"克"}]'::jsonb, '["腌肉：将猪里脊肉先切厚片，用刀背拍一拍，把肉拍松一点。切成一个手指头粗的条，加料酒，生抽，蚝油，食盐，白胡椒粉，一个鸡蛋，将肉用手抓匀，腌制 20 分钟以上。","调酱：番茄酱+10g 醋+30g 白糖+150ml 清水，搅拌至糖融化，备用。","裹粉：先把粉全部裹好再来炸，这样在炸的时候就不会手忙脚乱。准备一个大碗，里面放淀粉，把每一根肉条都满满裹上淀粉。","炸制：油温 160 摄氏度下里脊，可以拿一个干筷子放在油里面试一下，周围冒小泡就可以下锅。","炸到表面微黄可以捞出，全程中火。然后等油温升高到 200 摄氏度，把里脊倒进去重新炸一次，只需 40 秒，表皮就会很脆，马上捞出。","裹酱：另外拿一个锅，锅里放底油，把调好的酱汁倒进去，煮到冒泡，把炸好的里脊放进去，翻炒，让每一根都裹上酱汁。","下炸好的里脊肉翻炒，关火盛出。"]'::jsonb, '["荤菜","酸甜","煎炸","家常","宴客","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_fb548adc31.jpg', 'https://www.bilibili.com/video/BV1RT4QzXEyD', '{"energyKcal":360,"protein":28,"carbs":24,"fat":15}'::jsonb, '[1200,null,null,null,40,null,null]'::jsonb),
  ('howtocook:meat_dish/红烧猪蹄/红烧猪蹄', '红烧猪蹄', '荤菜', 4, 60, '红烧猪蹄是一道汤汁浓郁、肉质软糯的经典家常菜，咸香甜美，极为下饭。猪蹄富含胶原蛋白和蛋白质，营养丰富。这道菜对新手有一定挑战，但借助高压锅可以简化流程，有一定烹饪基础更易上手。从备料到完成大约需要 1 小时。', '[{"name":"猪蹄","quantity":2,"quantityMax":3,"unit":"根"},{"name":"香叶","quantity":2,"unit":"片"},{"name":"姜","quantity":5,"unit":"片"},{"name":"葱","quantity":0.5,"unit":"根"},{"name":"老抽","quantity":20,"unit":"ml"},{"name":"桂皮","quantity":1,"unit":"块"},{"name":"冰糖","quantity":7,"quantityMax":8,"unit":"粒"},{"name":"料酒","quantity":30,"unit":"ml"},{"name":"生抽","quantity":20,"unit":"ml"},{"name":"盐","quantity":8,"unit":"克"},{"name":"八角","quantity":4,"unit":"个"},{"name":"食用油","quantity":30,"unit":"ml"}]'::jsonb, '["冷水锅中放入热心摊主剁好的猪蹄，加入 20 ml 料酒与葱姜，煮 15 分钟去掉血腥","热锅冷油，倒入 30ml 食用油，放入 7-8 粒冰糖，开小火，熬成糖色，期间用锅铲把冰糖压碎，大概熬 2 分钟","熬成糖色后，放入焯过水的猪蹄，继续小火，翻炒猪蹄，直至所有猪蹄两面微黄","加入香叶 2 片、桂皮 1 块、八角 4 个、生抽 20 ml、老抽 20 ml、料酒 10 ml、姜 3 片、盐 8 克，转中火、继续翻炒 1 分钟","加入开水或者冷水，水需要没过猪蹄，盖上锅盖，大火烧开，烧开之后关火","把锅内的食材全部倒入高压锅中，高压锅中需要 15 分钟（如果同学没有高压锅，可放在锅中大火转小火熬制即可）","15 分钟之后，把高压锅的食材倒入炒锅中，开大火收汁，此时可用筷子尝下味道、淡的话可以加 2~3g 盐","大火收汁时长根据锅中的水来算，一般 30 秒即可，多留点也无碍、红烧猪蹄汤也是很下饭的"]'::jsonb, '["荤菜","咸香","软糯","红烧","下饭","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_9e934f7f83.jpg', 'https://www.bilibili.com/video/BV1zfq6YLEy5', '{"energyKcal":480,"protein":32,"carbs":14,"fat":32}'::jsonb, '[900,120,null,60,null,900,null,30]'::jsonb),
  ('howtocook:meat_dish/红烧肉/南派红烧肉', '南派红烧肉', '荤菜', 4, 90, '这道红烧肉成菜色泽红亮，肥肉入口即化、瘦肉酥烂不柴，咸中带甜，是典型的南方甜口风味。五花肉提供优质蛋白和丰富的胶原蛋白，香辛料还能去腥暖胃。制作虽需熬糖色与慢炖，但每一步都拆解得清晰易懂，新手跟着操作也能成功，全程约 1.5 小时即可端上桌。', '[{"name":"五花肉","quantity":1000,"unit":"g"},{"name":"油","quantity":100,"quantityMax":150,"unit":"ml"},{"name":"冰糖","quantity":50,"unit":"g"},{"name":"白砂糖","quantity":30,"unit":"g"},{"name":"老抽","quantity":15,"unit":"ml"},{"name":"料酒","quantity":30,"unit":"ml"},{"name":"香叶","quantity":4,"unit":"片"},{"name":"八角","quantity":3,"unit":"个"},{"name":"姜","quantity":6,"unit":"片"},{"name":"葱","quantity":30,"unit":"g"},{"name":"蒜","quantity":25,"unit":"g"},{"name":"盐","quantity":2,"quantityMax":3,"unit":"g"},{"name":"花椒","quantity":10,"unit":"g"},{"name":"凉水","note":"没过食材的量即可"},{"name":"开水","note":"没过食材的量即可"}]'::jsonb, '["猪五花肉先不切小块，切成能放入锅中的大块（约 5–6cm 宽）即可","生姜切片（每片厚度约 3mm ）","开水烧开","凉水自来水即可","小葱小葱白色的部分葱白切成小段（小葱最佳，大葱也可以）","蒜中间切开，不要拍扁，否则难以捞出以至最后收汁时影响味道","请将辅料分为两个\"预备包\"：","A包（去腥用）：2 片姜、2 段葱段。","B包（炖煮用）：剩下的 4 片姜、葱白、蒜瓣、花椒、八角、香叶，统一放入一个小碗中备用。","凉水锅中放入五花肉大块，加入 20ml 料酒 与 A包（2 片姜、2 段葱段），煮 15 分钟去掉血腥，捞出来后洗干净；","将焯过水的五花肉捞出，稍微放凉（不烫手即可），切成边长约 3cm × 3cm × 3cm 的正方体块（焯水后肉质收紧，此时切块比生肉时更容易且成品大小更均匀。3cm 切块最终成品约为 2.5cm，是最适宜入口且容易烧透的尺寸）","另起锅炒糖色，注意：在此菜谱中，请采用其中提到的\"操作 2\"来制作，即在糖液起密集小泡时，迅速将 B包（生姜、葱白、蒜、花椒、八角、香叶）倒入锅中爆香。","爆出香味后（约 5-10 秒内），先不要加开水，而是立刻将焯过水的五花肉倒入锅中大火翻炒，让肉块均匀裹上糖色并煸炒出油脂。待闻到肉香后，再倒入开水至没过全部肉，盖上锅盖，转中小火炖煮 50 分钟-60 分钟（高压锅则为 40 分钟）；","加入 10ml 料酒；","盖上锅盖煮至沸腾后，每隔 25 分钟打开盖子将浮在表面的油和沫捞出；","当水的高度减至肉最高的高度与锅底高度的 3/5 时，转中火，并捞出除肉和水以外的所有辅料，开始收汁；","打开锅盖，待汤汁快没有的时粘稠状出锅（切记不可收干）；"]'::jsonb, '["荤菜","南方风味","红烧","甜口","下饭","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_8adf6e8d89.jpg', 'https://www.bilibili.com/video/BV1PzhAzGEwT', '{"energyKcal":1200,"protein":15,"carbs":13,"fat":85}'::jsonb, null),
  ('howtocook:meat_dish/红烧肉/简易红烧肉', '简易红烧肉', '荤菜', 3, 90, '这道家常美味色泽红润油亮，口感软糯，肥而不腻，酱香浓郁，搭配米饭特别过瘾。五花肉提供优质蛋白质和必需脂肪酸，加上鹌鹑蛋或豆皮，营养更全面。做法对新手相当友好，从备料到出锅大约需要 1.5 小时。', '[{"name":"五花肉","quantity":3,"quantityMax":4,"unit":"斤"},{"name":"鹌鹑蛋或鸡蛋","quantity":0,"quantityMax":2,"unit":"个"},{"name":"豆皮","quantity":0,"quantityMax":80,"unit":"克"},{"name":"生姜","quantity":6,"unit":"片"},{"name":"冰糖","quantity":15,"unit":"克"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"老抽","quantity":15,"unit":"ml"},{"name":"料酒","quantity":5,"unit":"ml"},{"name":"香叶","quantity":3,"unit":"片"},{"name":"八角","quantity":2,"unit":"个"},{"name":"盐","quantity":2,"quantityMax":3,"unit":"克"},{"name":"水","quantity":600,"quantityMax":900,"unit":"ml"},{"name":"葱","note":"大葱葱白，适量"}]'::jsonb, '["猪五花肉切大块（约 4.5cm ，冷冻半小时至一小时更好切）","豆皮切 2cm 的宽度","生姜切片（每片厚度约 3mm ）","水烧开","鹌鹑蛋煮熟并用叉子/牙签扎孔（尽量多些好入味）","大葱大葱白色的部分葱白","冷水锅中放入切好的猪五花肉，加入料酒与葱姜，煮 15 分钟去掉血腥","锅中放入两片生姜提味","开中小火后直接加入五花肉，不需要放入食用油，每块五花肉六个面都煎一下，煎至出油即可","将煎出的油倒出备用，并将五花肉推至一边，加入 15g 冰糖，翻炒至冰糖融化；","融化后将五花肉与冰糖炒至融合上色，加入","生抽 10ml","老抽 15ml","料酒 5ml","翻炒至上色；","加入烧好的开水炖煮 40 分钟（刀工差的同学切的过大请自觉延长炖煮时间），并放入","生姜 2 片","香叶 3 片","八角 2 个","盖上锅盖煮至沸腾后，加入煮好扎好孔的鹌鹑蛋和豆皮，开中小火，等待 40 分钟。（中途可适当翻搅防止粘锅）；","打开锅盖，待汤汁快没有的时候开大火收汁（切记不可收干）；","加入 2-3g 盐，翻炒一下，就可以出锅了。"]'::jsonb, '["荤菜","家常","下饭","炖煮","酱香","软糯"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_ab3ceafa36.jpg', 'https://www.bilibili.com/video/BV1vfHfzYELM', null, '[null,null,null,null,null,null,900,null,null,null,null,null,null,null,null,2400,null,null,null,2400,null,null]'::jsonb),
  ('howtocook:meat_dish/红烧鸡翅', '红烧鸡翅', '荤菜', 3, 40, '红烧鸡翅是一道家常下饭菜，咸鲜带甜、色泽红亮，肉质嫩滑易脱骨。鸡翅富含优质蛋白质与胶原蛋白，营养好吸收。制作难度适中，新手按步骤操作也能顺利掌握，从备料到出锅大约需要 40 分钟。', '[{"name":"新鲜鸡翅","quantity":500,"unit":"克"},{"name":"姜片","quantity":10,"unit":"克"},{"name":"葱段","quantity":15,"unit":"克"},{"name":"大蒜","quantity":15,"unit":"克"},{"name":"香叶","quantity":1,"unit":"片"},{"name":"八角","quantity":1,"unit":"个"},{"name":"干辣椒","quantity":2,"unit":"个"},{"name":"冰糖","quantity":15,"unit":"克"},{"name":"黄酒或料酒","quantity":35,"unit":"ml"},{"name":"生抽","quantity":15,"unit":"ml"},{"name":"老抽","quantity":5,"unit":"ml"},{"name":"盐","quantity":3,"unit":"克"},{"name":"白糖","quantity":2,"unit":"克"},{"name":"胡椒粉","quantity":1,"unit":"克"},{"name":"白芝麻","quantity":3,"unit":"克"},{"name":"小葱花","quantity":5,"unit":"克"},{"name":"食用油","quantity":10,"quantityMax":15,"unit":"ml"}]'::jsonb, '["将鸡翅洗净。用刀在鸡翅厚处划三刀，背面扎一刀，便于入味。","如果鸡翅不新鲜，可在打完花刀之后用姜水泡 10-20 分钟。","将 10g 姜片（3-4 片）、15g 葱段（2-3 段）备好；3-4 瓣大蒜（约 15g）用刀拍散（无需剁碎）；1 片香叶、1 个八角、2 个干辣椒（可选）整理好备用。","起锅开火，锅中加入清水没过所有鸡翅，冷水下锅放入处理好的鸡翅，加入 20ml 黄酒或料酒、2 片姜片（约 5g），开大火烧至沸腾，沸腾后保持大火继续煮 2-3 分钟，撇去浮沫。","煮好后将鸡翅捞出，用温水清洗 2 遍，彻底去除血沫，控干水分备用。","另起锅，开火烧热后放入 10-15ml 食用油。","待油温至 5 成热，加入 15g 冰糖，开大火将冰糖熬至完全融化，冰糖融化变色后转小火，继续炒至冰糖呈枣红色，立即放入控干水分的鸡翅，快速翻炒 1-2 分钟，使每只鸡翅均匀裹上糖色。","加入准备好的 1 片香叶、1 个八角、2 个干辣椒（可选）、剩下的 2 片姜片（约 5g）、15g 葱段、拍散的大蒜，继续煸炒 30 秒至香料香味完全释放。","沿锅边淋入 15ml 料酒或黄酒，15ml 生抽，快速翻炒 10 秒。","加入温水（水温约 50-60℃），水量以稍微没过所有鸡翅为准。","加入 5ml 老抽、3g 盐、2g 白糖、1g 胡椒粉，用炒勺轻轻搅拌均匀。","盖上锅盖，开中火烧煮 7-8 分钟。","打开锅盖，用筷子将锅中的香叶、八角、姜片、葱段、大蒜捡出丢弃。","转大火，保持不断翻炒，将汤汁烧至粘稠状态（约 1-2 分钟）。","关火，将鸡翅盛入盘中，淋上锅中剩余的粘稠汤汁。","最后撒上 3g 白芝麻和 5g 小葱花，完成制作。"]'::jsonb, '["荤菜","家常","下饭菜","咸鲜","红烧","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_9c6a836c00.jpg', 'https://www.bilibili.com/video/BV1hP4y1V7ya', null, '[null,null,null,null,null,null,null,30,10,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/羊排焖面/羊排焖面', '羊排焖面', '荤菜', 4, 90, '羊排焖面是一道肉香浓郁、面条筋道的北方家常硬菜，羊排软烂，宽面吸足汤汁，每一口都满足。这道菜有肉有面有菜，一顿饭就能补齐人体所需的蛋白质、碳水和脂肪，营养全面。制作时需要先炖羊排再和面焖面，步骤稍多，更适合有一定下厨经验的朋友尝试，预计全程大约花费一个半小时。', '[{"name":"带皮羊排肉","quantity":500,"unit":"克"},{"name":"青椒","quantity":2,"unit":"个"},{"name":"甜椒","quantity":2,"unit":"个"},{"name":"大葱","note":"适量"},{"name":"花椒","note":"适量"},{"name":"干辣椒","note":"适量"},{"name":"生姜","quantity":4,"unit":"片"},{"name":"白砂糖","note":"适量"},{"name":"老抽","note":"适量"},{"name":"盐","note":"适量"},{"name":"食用油","note":"适量，多一点也没关系"}]'::jsonb, '["羊肉冷水下锅焯水，水开了之后把血沫撇掉，捞出羊肉。","切好生姜（ 4 片)，放入干辣椒与花椒在碗里备用。","在炒锅加入油。（多一点也没关系）","油热之后，放入白砂糖，给羊肉炒出焦糖色。","羊肉水份炒干之后，放入盐、老抽，以及备好的调味料。","加入清水没过羊肉，大火煮沸之后，让其继续煮 10 分钟，之后小火炖煮 30 分钟。","在此期间，可以和面。和面的量以及操作方法在附加内容里讲解 （注 1）。","放入青椒，甜椒，大葱，以及面皮进行翻炒。","翻炒均匀之后，即可出锅。"]'::jsonb, '["荤菜","鲜香","焖制","北方","家常","硬菜"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_5df08f763a.jpg', 'https://www.bilibili.com/video/BV1J44y1z7GS', '{"energyKcal":780,"protein":34.5,"carbs":48,"fat":22}'::jsonb, '[null,null,null,null,null,2400,null,null,null]'::jsonb),
  ('howtocook:meat_dish/老妈蹄花/老妈蹄花', '老妈蹄花', '荤菜', 4, 120, '老妈蹄花汤色奶白，猪蹄软烂脱骨，口感细腻，配上酸辣蘸汁十分开胃，是经典的川式家常菜。猪蹄富含胶原蛋白，白芸豆增添绵密口感，营养丰富。操作需要高压锅和提前浸泡，对新手有一定挑战，但按步骤来做不难掌握。含浸泡和压煮，全程大约需要 2 小时（不含提前一晚浸泡白芸豆的时间）。', '[{"name":"猪蹄","quantity":3,"unit":"根"},{"name":"葱","quantity":10,"unit":"克"},{"name":"姜","quantity":30,"unit":"克"},{"name":"料酒","note":"适量"},{"name":"生抽","quantity":25,"unit":"克"},{"name":"白芷","note":"适量"},{"name":"当归","quantity":2,"unit":"克"},{"name":"鸡精","quantity":2,"unit":"克"},{"name":"盐","note":"适量"},{"name":"蒜","quantity":8,"unit":"克"},{"name":"小米椒","note":"适量"},{"name":"白胡椒粉","quantity":5,"unit":"克"},{"name":"香醋","note":"适量"},{"name":"花椒油","note":"适量"},{"name":"油泼辣子","note":"适量"},{"name":"白芸豆","quantity":200,"unit":"克"}]'::jsonb, '["200g 白芸豆提前一晚清水浸泡备用","准备猪前蹄，买菜的时候让师傅从中间劈开，用喷火枪去除毛囊，拿回家清洗","冷水锅中加入猪蹄、大葱段、姜片、料酒，焯水十分钟，撇去浮沫，捞出洗干净备用","高压锅中放入猪蹄、当归、白芷、白胡椒粉、姜片，上汽后压三十分钟，放入白芸豆，再压十分钟，这个时候如果汤底是奶白色，那么恭喜是正确的（如果中途需要加水，只能加热水）","揭盖后加入盐、鸡精、葱花调味","调制灵魂汁子：放入葱、蒜、小米椒，白胡椒粉、生抽、香醋、油泼辣子、花椒油、猪蹄原汤","灵魂汁子，浇给"]'::jsonb, '["荤菜","川菜","炖","酸辣","家常","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_5331448601.jpg', 'https://www.bilibili.com/video/BV1q14y1J7Kv', '{"energyKcal":680,"protein":58,"carbs":38,"fat":36}'::jsonb, '[null,null,600,2400,null,null,null]'::jsonb),
  ('howtocook:meat_dish/老式锅包肉/老式锅包肉', '老式锅包肉', '荤菜', 4, 90, '锅包肉是东北经典名菜，起源于哈尔滨道台府，以白醋调出鲜明酸香，外壳酥脆、肉片滑嫩，酸甜爽口。猪肉提供优质蛋白质，搭配葱姜等蔬菜开胃解腻。这道菜需要掌握挂浆、油温和复炸技巧，烹饪难度中等偏上，新手需要耐心练习。从腌肉、调糊到炸制出锅，预计制作时长约 90 分钟。', '[{"name":"猪通脊肉","quantity":300,"unit":"克"},{"name":"大葱","quantity":50,"unit":"克"},{"name":"姜","quantity":30,"unit":"克"},{"name":"蒜","quantity":3,"quantityMax":4,"unit":"瓣"},{"name":"胡萝卜","quantity":10,"unit":"克"},{"name":"香菜","quantity":10,"unit":"克"},{"name":"白糖","quantity":65,"unit":"克"},{"name":"料酒","quantity":5,"unit":"ml"},{"name":"盐","quantity":5,"unit":"克"},{"name":"味精"},{"name":"土豆淀粉","quantity":170,"unit":"克"},{"name":"土豆淀粉","quantity":210,"unit":"克"},{"name":"中筋面粉","quantity":70,"unit":"克"},{"name":"小苏打","quantity":5,"unit":"克"},{"name":"小苏打","quantity":1,"unit":"克"},{"name":"白熟芝麻","quantity":5,"unit":"克"},{"name":"食用油","quantity":1000,"unit":"ml"},{"name":"白醋","quantity":55,"unit":"克"},{"name":"生抽","quantity":4,"unit":"克"},{"name":"玉米淀粉","quantity":1.5,"unit":"克"},{"name":"水","quantity":4,"unit":"克"},{"name":"清水","quantity":5,"unit":"ml"}]'::jsonb, '["处理猪肉：","将猪通脊肉切成厚度 8mm 的均匀肉片，去除白色筋膜。","用清水冲洗肉片，去除血水。","可选：加入小苏打 5g，抓匀，静置 5 分钟。","用清水冲洗 1-2 次，去除多余小苏打。","腌制肉片：","在肉片中加入盐 3g、料酒 5ml，拌匀，腌制 15 分钟。","挂浆：","方法一（推荐）：","将土豆淀粉 170g 加入过量清水，搅匀，静置 60 分钟，等待淀粉沉降分层。","倒出上层全部的的清水，保留底部淀粉浆（形如非牛顿流体）。","放入肉片，放入 5ml 清水，放入 3ml 食用油，搅拌均匀。","方法二：","将土豆淀粉 210g 和中筋面粉 70g 混合。","少量多次加入清水，搅拌至酸奶状，提起可拉丝，浆糊能在盆中堆积。","加入食用油 10ml，小苏打 1g，搅拌均匀。","将腌制好的肉片放入浆糊中，拌匀，使每片肉均匀裹上浆。","调制糖醋汁：","混合白糖 65g、白醋 55g、生抽 4g、盐 2g，搅拌均匀，备用。","可选：水 4g、玉米淀粉 1.5g，用于糖醋汁更加粘稠。","准备配菜：","大葱、姜、胡萝卜切丝，香菜切段，蒜切片。","炸制肉片：","第一次炸制：","锅中加入食用油，加热至 170℃（六成热）。","将肉片逐片放入油中，炸至表面定型，表面挂浆不粘筷子，肉上浮，颜色浅黄，约 30 秒（取决于肉片大小），捞出备用。","第二次炸制：","油温升至 200℃（七成热）。","将所有肉片放入油中，炸至外壳金黄酥脆，约 30 秒，捞出备用。","第三次炸制（可选）：","油温升至 220℃（八成热）。","将肉片快速复炸，直到能看到肉片黄里透红，约 30 秒（取决于油温维持能力），增强酥脆度，捞出沥油。","炒制：","锅中留 20ml 底油， 倒入调好的糖醋汁，大火加热至沸腾，熬至汤汁粘稠，约 30-60 秒。","可选：盛出 1/2 的糖醋汁，可以让后面翻炒更加方便","放入炸好的肉片、葱丝、蒜片、胡萝卜丝、香菜段，浇上前面盛出的糖醋汁，快速翻炒 3 次，使汤汁均匀裹在肉片上。","出锅装盘：","将锅包肉盛入盘中，撒上白熟芝麻（可无），即可上桌。"]'::jsonb, '["荤菜","东北","酸甜","酥脆","炸制","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_ea8b691621.jpg', 'https://www.bilibili.com/video/BV1ssiCBQEUe', '{"energyKcal":680,"protein":24,"carbs":78,"fat":28}'::jsonb, null),
  ('howtocook:meat_dish/肉饼炖蛋', '肉饼炖蛋', '荤菜', 3, 20, '肉饼炖蛋是一道咸鲜滑嫩的传统家常菜，肉饼吸饱了酱汁，鸡蛋卧在其中，口感软嫩又下饭。它富含优质蛋白质和多种氨基酸，能很好地补充体力。做法十分简单，对厨房新手非常友好，从备料到出锅大约只需要 20 分钟。', '[{"name":"猪肉末","quantity":300,"unit":"克"},{"name":"鸡蛋","quantity":2,"unit":"个"},{"name":"料酒","quantity":10,"unit":"ml"},{"name":"生抽","quantity":20,"unit":"ml"},{"name":"白胡椒粉","quantity":5,"unit":"克"},{"name":"芝麻香油","quantity":10,"quantityMax":15,"unit":"ml"}]'::jsonb, '["在碗中加入猪肉末、料酒、生抽、白胡椒粉、鸡蛋和芝麻香油，搅拌均匀。","将调好味的猪肉末铺在盘子里，肉末中间用勺子挖一个洞，往洞中打入 1 个鸡蛋。","锅中加水至 1/4 高度，水烧开后，将盘子放入锅中，盖上锅盖，蒸 15 分钟。"]'::jsonb, '["荤菜","咸鲜","蒸菜","家常","下饭","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_bfcaf0a892.jpg', 'https://www.bilibili.com/video/BV17u411M7p4', '{"energyKcal":960,"protein":72,"carbs":4,"fat":82}'::jsonb, '[null,null,900]'::jsonb),
  ('howtocook:meat_dish/腐乳肉', '腐乳肉', '荤菜', 5, 60, '这是一道经典的江南家常菜，五花肉与红腐乳同炖，色泽红亮如琥珀，肉质酥烂到入口即化，咸甜交织的酒香与豆香在舌尖层层展开。富含优质蛋白质和 B 族维生素，经慢火煨煮后更易消化。制作流程需要耐心把控火候和收汁，对新手来说有一定挑战，预计制作时长约 1 小时。', '[{"name":"带皮五花肉","quantity":400,"unit":"克"},{"name":"红腐乳","quantity":30,"unit":"克"},{"name":"腐乳汁","quantity":15,"unit":"ml"},{"name":"冰糖","quantity":25,"unit":"克"},{"name":"老抽","quantity":5,"unit":"ml"},{"name":"料酒","quantity":15,"unit":"ml"},{"name":"葱白","quantity":15,"unit":"克"},{"name":"葱花","quantity":5,"unit":"克"},{"name":"生姜","quantity":10,"unit":"克"},{"name":"清水","quantity":500,"unit":"ml"},{"name":"食用油","quantity":10,"unit":"ml"}]'::jsonb, '["五花肉切成长宽 2.5 cm 的小块","冷水放料酒姜片，五花肉放入开火慢慢加入到水沸腾后捞出","玫瑰腐乳块和腐乳汁碾成泥，加冰糖、老抽调成酱汁","热锅冷油爆香葱姜，下肉块煸到金黄","倒入腐乳酱炒匀加热水焖煮","小火慢炖 40 分钟","大火收汁，看到汤汁冒浓稠鱼眼泡时关火"]'::jsonb, '["荤菜","咸甜","炖煮","江南","下饭","宴客","家常菜"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_4b6c60e9bf.jpg', 'https://www.bilibili.com/video/BV1PzhAzGEwT', '{"energyKcal":1300,"protein":50,"carbs":30,"fat":120}'::jsonb, '[null,null,null,null,null,2400,null]'::jsonb),
  ('howtocook:meat_dish/芥末罗氏虾/芥末罗氏虾', '芥末罗氏虾', '荤菜', 3, 30, '这道菜鲜香微辣，芥末风味浓郁，虾肉紧实弹嫩，是一道快手家常海鲜菜。虾本身富含优质蛋白和钙，脂肪含量低，搭配芥末开胃解腻。中等难度，只要按步骤调制碗汁、控制火候，新手也能较快上手，全程约需 30 分钟。', '[{"name":"罗氏虾","quantity":250,"unit":"克"},{"name":"蒜","quantity":1,"quantityMax":2,"unit":"个"},{"name":"青芥末","quantity":20,"unit":"克"},{"name":"生粉","quantity":10,"unit":"克"},{"name":"生抽","quantity":30,"unit":"克"},{"name":"胡椒粉","quantity":5,"unit":"克"},{"name":"白糖","quantity":3,"unit":"克"},{"name":"蚝油","quantity":15,"unit":"克"},{"name":"盐","quantity":3,"unit":"克"},{"name":"小米辣","quantity":1,"quantityMax":2,"unit":"个"},{"name":"黄油","quantity":20,"unit":"克"},{"name":"食用油","quantity":80,"unit":"ml"}]'::jsonb, '["处理虾：","将虾从背部切开，去除虾线和沙袋，也可从腹部切开，炸出来会胀开，成菜比较漂亮","用清水洗干净，控干水分后可拍上生粉，也可不拍","蒜蓉及碗汁处理：","将 2 颗大蒜切成蒜末","准备碗汁，放入生抽、蚝油、白糖、胡椒粉、盐，依据个人口味挤入芥末，加清水稀释后加入生粉化开","炒制过程：","锅热倒入食用油，大概能覆盖锅底","放入控干水分的罗氏虾，慢慢煎制","虾油煎出来后（表现为锅中出现大量气泡），加入准备好的蒜蓉及小米辣","闻到蒜蓉的香味后，加入黄油","黄油融化后翻拌均匀，加入准备好的碗汁","盖锅盖焖煮 2 分钟汤汁浓稠后出锅"]'::jsonb, '["荤菜","鲜香微辣","煎炒","快手家常","海鲜","开胃解腻"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_1cbf720e45.jpg', 'https://www.bilibili.com/video/BV1hC4y1P7dv', '{"energyKcal":520,"protein":28,"carbs":15,"fat":22}'::jsonb, null),
  ('howtocook:meat_dish/茭白炒肉/茭白炒肉', '茭白炒肉', '荤菜', 3, 20, '茭白炒肉是一道家常快手菜，口感鲜嫩爽脆，咸鲜适口，属于典型的江南家常风味。茭白富含膳食纤维和多种维生素，搭配瘦肉提供优质蛋白，荤素搭配均衡营养。烹饪难度中等，新手稍加练习即可掌握，预计制作时长约 20 分钟。', '[{"name":"茭白","quantity":2,"unit":"根"},{"name":"瘦肉","quantity":100,"unit":"克"},{"name":"淀粉","quantity":15,"unit":"克"},{"name":"食用油","quantity":30,"unit":"ml"},{"name":"鸡精","quantity":5,"unit":"克"},{"name":"姜","quantity":1,"unit":"片"},{"name":"蒜","quantity":1,"unit":"个"},{"name":"料酒","quantity":5,"unit":"ml"},{"name":"盐","quantity":2,"unit":"克"}]'::jsonb, '["茭白切片，每片厚度 0.5 cm","瘦肉切条，厚度 0.3-0.5 cm，加入料酒、生粉、盐、水搅拌","姜切片、蒜头剁碎","起锅水烧开，放入茭白，水煮 60-90 S 后取出沥干","起锅，倒入 15 ml 油，倒入瘦肉，反复翻炒 60 S 取出","起锅，倒入 15 ml 油，倒入姜、蒜翻炒 30S，加入茭白继续翻炒 30 S","继续加入瘦肉翻炒 60 S，加入 20 ml 水，加入盐、鸡精后翻炒 60S 出锅"]'::jsonb, '["荤菜","咸鲜","炒制","家常","快手","江南"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_83f5232fc2.jpeg', 'https://www.bilibili.com/video/BV1KY4y1C72V', '{"energyKcal":508,"protein":23,"carbs":22,"fat":37}'::jsonb, '[null,null,null,60,60,60,120]'::jsonb),
  ('howtocook:meat_dish/荔枝肉/荔枝肉', '荔枝肉', '荤菜', 4, 45, '荔枝肉是一道酸甜酥香的福州传统闽菜，外焦里嫩的肉块裹着红亮的酱汁，搭配水果添入清爽果香。猪瘦肉富含优质蛋白质，凤梨含有膳食纤维和维生素，能帮助开胃解腻。制作过程需要切肉、挂糊和两次油炸，略有挑战但步骤明确，适合有一定下厨基础的美食爱好者尝试，大约 45 分钟就能端上餐桌。', '[{"name":"瘦肉","quantity":150,"unit":"克"},{"name":"凤梨","quantity":100,"unit":"克"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"食用油","quantity":500,"unit":"ml"},{"name":"白砂糖","quantity":5,"unit":"克"},{"name":"淀粉","quantity":100,"unit":"克"},{"name":"生抽","quantity":5,"unit":"ml"},{"name":"鸡精","quantity":5,"unit":"克"},{"name":"姜末","quantity":5,"unit":"克"},{"name":"芝麻","quantity":2,"unit":"克"},{"name":"番茄酱","quantity":20,"unit":"克"},{"name":"香醋","quantity":2,"unit":"ml"}]'::jsonb, '["瘦肉切块（每块 2-3 cm ），放入大碗中，加入鸡蛋 1 个 、生粉 50 g 、生抽 3 ml 、鸡精 2 g","充分搅拌,直至生粉包裹住瘦肉块（太稀则继续加生粉，太干则加水），然后加入 5 ml 油，在充分搅拌后备用","在准备一个碗，加入番茄酱、鸡精 3 g 、生抽 2 ml 、姜末、白砂糖、生粉 10 g \\香醋、凉水 200 ml ,充分搅拌后备用","切一个凤梨, 准备 6 个 （每个 1.5-2 cm）凤梨块","起锅烧油，倒入 500 ml 油，一直烧油直到听到油炸声","将瘦肉一个一个放入锅中（切记不可以整碗倒入），保证每个肉不要粘在一起","全部放入瘦肉后，每 30 S 用勺子来回两面翻转瘦肉块，直至瘦肉块表面金黄","取出瘦肉，一分钟后倒入油锅中继续炸，直至瘦肉块表面出现焦黄后，取出放入大碗备用","起锅，倒入汤汁，30 S 后倒入瘦肉块、凤梨块，充分翻炒后 出锅","摆上芝麻"]'::jsonb, '["荤菜","酸甜","油炸","闽菜","家常","下饭菜"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_4b45083b56.jpeg', 'https://www.bilibili.com/video/BV1U5411S7Sh', '{"energyKcal":900,"protein":35,"carbs":75,"fat":45}'::jsonb, '[null,null,null,null,null,null,30,60,30,null]'::jsonb),
  ('howtocook:meat_dish/荷兰豆炒腊肠/荷兰豆炒腊肠', '荷兰豆炒腊肠', '荤菜', 2, 15, '荷兰豆炒腊肠是一道清爽咸香的家常小炒，腊肠的油脂润着翠绿的荷兰豆，口感脆嫩不腻。荷兰豆富含优质蛋白质和多种维生素，有助于增强机体抗病能力。做法简单，几乎不需要刀工，初学者也能快速上手，从备料到出锅大约只需 15 分钟。', '[{"name":"荷兰豆","quantity":50,"unit":"个"},{"name":"腊肠","quantity":100,"unit":"克"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"食用油","quantity":10,"unit":"ml"}]'::jsonb, '["把荷兰豆去掉蒂，有时间的也可以同时把尾部去掉","买腊肠之前可以问老板是生的还是熟的，如果是生的，需要提前蒸一下，如果是熟的可以直接使用","把荷兰豆清洗一下，然后焯一下水，大概 45s，荷兰豆焯至变色即可，捞出过凉水备用","热锅，锅内放入大约 10ml 食用油。等待 10 秒让油温升高","放入腊肠，保持翻炒至腊肠微微卷边，注意这里一定要保持小火，小到不能小的那种，不然容易糊","放入荷兰豆，转为中大火，翻炒 30s 放入生抽，接着再翻炒 20-30s 即可"]'::jsonb, '["荤菜","咸香","炒","家常","快手","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_7eb6afb1bf.png', 'https://www.bilibili.com/video/BV148411t783', '{"energyKcal":630,"protein":19,"carbs":12,"fat":54}'::jsonb, '[null,null,45,10,null,null]'::jsonb),
  ('howtocook:meat_dish/萝卜炖羊排', '萝卜炖羊排', '荤菜', 4, 120, '这道汤菜清鲜不腻，羊肉软烂入味，萝卜饱吸汤汁后甘甜绵糯，是北方冬季常见的家常暖身菜。羊肉富含优质蛋白和铁，萝卜含有维生素与膳食纤维，两者搭配温补脾胃、驱寒助消化。虽然需经焯水去腥和两次炖煮，但步骤清晰易循，新手也能顺利上手。整体制作大约需要两小时，若用高压锅可缩短至大约一 小时。', '[{"name":"羊排","quantity":400,"unit":"g"},{"name":"白萝卜","quantity":1,"unit":"根"},{"name":"大葱","quantity":1,"unit":"根"},{"name":"花椒","quantity":10,"unit":"粒"},{"name":"白芷","note":"可选，适量"},{"name":"姜","quantity":10,"unit":"g"},{"name":"料酒或者黄酒","quantity":30,"quantityMax":40,"unit":"ml"},{"name":"食用盐","quantity":10,"unit":"g"},{"name":"冰糖","quantity":2,"quantityMax":4,"unit":"粒"},{"name":"水","quantity":1000,"unit":"ml"}]'::jsonb, '["萝卜去皮、滚刀切成 3-5cm 的大块，备用","羊排在购买时可以让卖家切好，因为家用刀一般难以切动，备用","羊肉冷水下锅，加入一半的料酒，一半的葱姜，煮 10 分钟去掉血腥，（可选）把焯的过程中出现的血沫子可以用勺子盛出来","另起一锅冷水，放入切好的白萝卜，放入一半的冰糖，等水开后煮 5 分钟去掉白萝卜的辣味","盛出来焯好的羊排，放入高压锅中，加水没过所有食材后再增加大约 300ml 的水","将剩余的葱姜料酒，花椒，冰糖，白芷（可选），盐放入锅中，盖锅等待上汽后计时，中火炖大约 15 分钟。","如没有高压锅，则放入普通锅中，炖大约 40 分钟到 1 小时。","关火，等待高压锅放气完毕，开盖，加入之前焯好的萝卜，调味，加入 3-10g 的食盐或者水，品尝汤的咸淡，","再开火，中火，高压锅上汽再炖 10 分钟，普通锅盖盖再炖 20 分钟","关火，盛盘"]'::jsonb, '["荤菜","鲜香","炖","北方","暖身","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_da2ed3380b.jpg', 'https://www.bilibili.com/video/BV1wc411z7Wk', '{"energyKcal":900,"protein":70,"carbs":10,"fat":60}'::jsonb, '[null,null,600,300,null,900,null,null,600,null]'::jsonb),
  ('howtocook:meat_dish/蒜苔炒肉末', '蒜苔炒肉末', '荤菜', 2, 10, '蒜苔炒肉末是北方家常菜，咸鲜脆嫩，蒜香浓郁。蒜苔富含膳食纤维和维生素，五花肉提供蛋白质，荤素搭配均衡。做法简单，备料轻松，新手也能快速上手。从切配到出锅大约只需 10 分钟。', '[{"name":"五花肉薄片","quantity":4,"unit":"片"},{"name":"蒜苔","quantity":1,"unit":"扎"},{"name":"蒜瓣","quantity":2,"unit":"瓣"},{"name":"生抽","quantity":15,"unit":"ml"},{"name":"食用油","quantity":10,"unit":"ml"},{"name":"食用盐","quantity":2,"unit":"克"}]'::jsonb, '["蒜苔切成 5cm 小段，备用","五花肉切成 5mm 5cm 丝状，备用","蒜瓣拍碎切成末，备用","热锅，锅内放入 10ml 食用油。等待 10 秒让油温升高","放入蒜末，中火翻炒 10 秒 将蒜末炒出香味","放入五花肉和 5ml 生抽，中火翻炒 30 秒 将肉炒熟并上色","将蒜苔放入锅内并加入 10ml 生抽，翻炒 30 秒","锅内加入 20g 水，中火翻炒 5 分钟 将蒜苔炒至稍稍变软","最后加入 2g 食盐，中火翻炒 30 秒，即可出锅装盘"]'::jsonb, '["荤菜","咸鲜","快炒","北方家常","下饭","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_c5c4af8e0f.jpg', 'https://www.bilibili.com/video/BV1124y1j7yw', '{"energyKcal":420,"protein":12,"carbs":10,"fat":38}'::jsonb, '[null,null,null,10,10,30,30,300,30]'::jsonb),
  ('howtocook:meat_dish/虎皮肘子', '虎皮肘子', '荤菜', 5, 150, '这道菜成品色泽红亮，肘皮呈现诱人的虎皮纹路，口感软烂入味，肥而不腻，瘦肉松软，属于传统中式宴客大菜。猪肘富含胶原蛋白和优质蛋白，经过长时间炖煮后更易吸收，对皮肤和关节有一定滋养效果。制作过程包含烧皮、油炸、炒糖色和高压炖煮等多个步骤，对新手来说挑战较大，建议有一定烹饪基础再尝试。从预处理到上桌，预计总耗时约 2.5 小时。', '[{"name":"猪前肘","quantity":1,"unit":"个"},{"name":"食用植物油","quantity":1,"unit":"桶"},{"name":"冰糖","quantity":5,"unit":"桶"},{"name":"盐","quantity":1,"quantityMax":2,"unit":"茶匙"},{"name":"老抽","quantity":1,"unit":"茶匙"},{"name":"生抽","quantity":1,"unit":"汤匙"},{"name":"白醋","quantity":1,"unit":"汤匙"},{"name":"香叶","quantity":3,"unit":"片"},{"name":"肉桂皮","quantity":2,"quantityMax":3,"unit":"克"},{"name":"豆蔻","quantity":3,"unit":"个"},{"name":"花椒","quantity":8,"quantityMax":12,"unit":"个"},{"name":"大料","quantity":2,"quantityMax":4,"unit":"个"},{"name":"淀粉","quantity":1,"unit":"汤匙"},{"name":"葱","quantity":2,"unit":"棵"},{"name":"姜","quantity":6,"unit":"克"},{"name":"蒜","quantity":6,"unit":"粒"},{"name":"水","quantity":100,"unit":"ml"},{"name":"料酒","quantity":2,"unit":"汤匙"}]'::jsonb, '["猪肘解冻后水泡 1 小时去除血水。","如有火焰喷枪，则使用火焰喷枪灼烧猪肘皮表面至棕黑色以去除猪毛，破坏汗腺。注意不要长时间炙烤同一个位置以避免烧焦，当猪肘皮几乎完全呈现棕黑色时则停止灼烧。","如无火焰喷枪，将铁锅烧至 200 以上，将猪肘直接放入锅内，用锅铲或筷子使猪肘皮充分接触铁锅表面，当猪肘皮与铁锅接触位置呈现出棕色时，更换位置继续烫猪肘皮，直到整个猪肘被充分烫过。注意再次过程中注意铁锅温度，不要使铁锅红热。","使用清洁球在水中刷洗猪肘，将其表面烧焦的部分去除。刷洗结束后，猪肘再次呈现出未被灼烧前的状态。","将猪肘置于铁锅中，加尽量多的冷水，具体视铁锅深度与猪肘大小而定，在保证可以拿得动铁锅及其内容物的情况下，能浸没猪肘 3/4 以上为最佳。","取 1 棵葱的葱白，分成 3 段，放入锅中。","取 3 粒蒜，分别用刀身拍扁，放入锅中。","取 3 克姜，放入锅中。","将 2 汤匙料酒加入锅中。","锅中水烧开后，等待五分钟，随后将猪肘取出，捡出锅中所有配料，更换容器保留所有肉汤备用。","向锅中加入冷油，以之前水量为参考，能浸没猪肘 3/5 以上为佳，开中火加热。","当油温达到五成时，转为小火，放入猪肘油炸。","在油炸过程中烹饪者应注意人身安全。","在油炸过程中，使用锅铲或其他耐高温厨具将锅中的油均匀淋到猪肘未被浸没的部分，如果条件允许应以 3 分钟的间隔翻转猪肘，使其油炸均匀。","油炸过程持续大约 20 分钟，当观察到猪肘皮已经全部呈现出浅棕色，而瘦肉部分已经微焦，则可捞出备用。","炸制完后的油可用于制作其他油炸类食物，但注意不要使用太多次。","炒糖色200ml 备用。","将猪肘加入高压锅内，加入所有肉汤、糖色、香叶、肉桂皮、豆蔻、花椒、大料、老抽、生抽、白醋。如果喜欢甜口，可以再额外加入 2-3 克冰糖。","取 1 棵葱的葱白，分成 3 段，放入锅中。","取 3 粒蒜，分别用刀身拍扁，放入锅中。","取 3 克姜，放入锅中。","盖上锅盖，加压炖煮 40 分钟。","在炖煮期间调制水淀粉。取碗 1 个，加入 1 汤匙淀粉，100ml 水，搅拌使其成为白色悬浊液","炖煮时间结束后，打开高压锅锅盖，捡出锅中所有的配料，只保留猪肘。","将高压锅中剩余的肉汤转移至铁锅内，猪肘转移至盘子或盆内","将铁锅置于灶台上，开大火。在收汁过程中可以用筷子头蘸取锅内汤汁判断咸淡，并根据口味添加盐。注意，汤汁多的时候味道会比汤汁少的时候味道更淡，加入盐时需要考虑这一点。","当肉汤沸腾时，注意观察剩余肉汤余量","当剩余肉汤少于原肉汤体积的 1/2 时，再次搅拌之前调制好的水淀粉，并加入一半","等待肉汤沸腾，加入剩下的一半","等待肉汤沸腾，沸腾后等待 1-2 分钟关火，此时锅内的肉汤呈红棕色粘稠状","用汤匙舀起肉汤均匀地淋在猪肘上，尽量使猪肘的每一处都淋到汤汁。如果在猪肘被完全淋到前汤汁已经用完则可直接上桌，否则剩余汤汁不需要再淋，可直接上桌。"]'::jsonb, '["荤菜","红烧","软糯","炸炖","宴客","传统"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_2a08224116.jpg', 'https://www.bilibili.com/video/BV181421X7EZ', '{"energyKcal":2350,"protein":168,"carbs":22,"fat":165}'::jsonb, '[3600,null,null,null,null,null,null,null,null,300,null,null,null,null,1200,null,null,null,null,null,null,2400,null,null,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/蚂蚁上树', '蚂蚁上树', '荤菜', 3, 20, '蚂蚁上树是一道经典的川味家常菜，咸香微辣，粉丝软滑吸汁，肉末细嫩鲜香。以红薯粉丝和肉末为主料，富含碳水化合物与蛋白质，能快速补充能量。制作难度中等，步骤清晰，对新手比较友好，全程约需 20 分钟即可完成。', '[{"name":"红薯粉丝","quantity":80,"unit":"克"},{"name":"猪肉末（或牛肉末）","quantity":150,"unit":"克"},{"name":"郫县豆瓣酱","quantity":15,"unit":"克"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"老抽","quantity":5,"unit":"ml"},{"name":"食用油","quantity":10,"unit":"ml"},{"name":"蒜末","quantity":10,"unit":"克"},{"name":"姜末","quantity":5,"unit":"克"},{"name":"小葱（可选）","note":"适量"},{"name":"清水","quantity":300,"unit":"ml"}]'::jsonb, '["红薯粉丝提前泡软，泡水时间为 20 分钟，备用","将蒜、姜分别剁碎，备用","锅烧热，加入 10ml 食用油，加入蒜末、姜末炒香","加入猪肉末翻炒至肉色发白且微微出油","加入郫县豆瓣酱，炒至红油析出","加入生抽和老抽，翻炒均匀","倒入 300ml 清水，煮沸","放入泡软沥干的粉丝，用筷子轻轻拨动防止粘连","中小火煮约 5 分钟，直至粉丝完全吸收汤汁、呈现微微收干状态","依据口味可撒入小葱末，关火装盘"]'::jsonb, '["荤菜","川味","咸香微辣","炒煮","下饭","快手","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_9f562b30af.jpg', 'https://www.bilibili.com/video/BV1J14y117ba', '{"energyKcal":760,"protein":27.2}'::jsonb, '[1200,null,null,null,null,null,null,null,300,null]'::jsonb),
  ('howtocook:meat_dish/血浆鸭/血浆鸭', '血浆鸭', '荤菜', 5, 120, '血浆鸭是一道湖南武冈传统名菜，鸭肉香酥脆嫩，浸透醋血后连姜和辣椒都变得甜净不辣。鸭肉与鸭血提供优质蛋白和铁质，适合补血养身。制作步骤较多，需要留意火候和翻炒，但跟着步骤操作，初学者也能在 大约 2 小时完成。', '[{"name":"鲜仔鸭肉","quantity":2000,"unit":"克"},{"name":"鲜鸭血","quantity":250,"unit":"ml"},{"name":"姜","quantity":6,"unit":"片"},{"name":"蒜仔","quantity":6,"unit":"瓣"},{"name":"香葱","quantity":2,"unit":"根"},{"name":"辣椒","quantity":1000,"unit":"克"},{"name":"小米辣（或朝天椒）","quantity":5,"quantityMax":8,"unit":"个"},{"name":"高度白酒","quantity":50,"unit":"ml"},{"name":"水","quantity":150,"unit":"ml"},{"name":"啤酒","quantity":200,"unit":"ml"},{"name":"米酒","quantity":200,"unit":"ml"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"料酒","quantity":30,"unit":"ml"},{"name":"盐","quantity":8,"unit":"克"},{"name":"鸡精","quantity":5,"unit":"克"},{"name":"食用油","quantity":100,"unit":"ml"},{"name":"开水","quantity":200,"unit":"ml"},{"name":"山胡椒油","quantity":3,"quantityMax":6,"unit":"滴"}]'::jsonb, '["鲜仔鸭肉切成约 3cm 小块，加料酒、姜片，去除血水。","炒锅烧热，放入约 100ml 食用油，大火待油烧开，放入腌制好的鲜鸭肉，不断翻炒。","待鸭肉完全变色（肉眼可见泛白），放入酒，再加入 200ml 开水，刚好淹没鸭肉即可，盖上锅盖中火煮 15 分钟。","水开之后，打开锅盖放入姜蒜，翻炒一遍，盖上锅盖持续加热 10 分钟。","打开锅盖放入辣椒，不断翻炒，待至肉眼可见辣椒炒软，放入鲜鸭血，此时需要不断翻炒，确保每块鸭肉和每片辣椒都有鸭血的浸润（此乃血浆鸭的精髓）。","翻炒至肉眼可见鸭血均为黑色，加入盐，鸡精，香葱，（喜欢食用山胡椒油的朋友也可以在此时放入 3-6 滴山胡椒油）再次翻炒一到二次即可。","出锅盛盘，上桌食用。"]'::jsonb, '["荤菜","湘菜","香辣","炒","下饭","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_e97c8421fc.jpg', 'https://www.bilibili.com/video/BV1W5411Q7iu', null, null),
  ('howtocook:meat_dish/西红柿土豆炖牛肉/西红柿土豆炖牛肉', '西红柿土豆炖牛肉', '荤菜', 4, 90, '一道家常炖菜，酸甜开胃，汤汁浓郁，牛肉软烂，土豆绵密。牛肉提供优质蛋白，西红柿富含番茄红素，搭配土豆和洋葱，营养均衡。操作简单，无需复杂技巧，新手也能轻松上手。从备菜到出锅大约需要 1 至 1.5 小时。', '[{"name":"牛肉","quantity":500,"quantityMax":700,"unit":"克"},{"name":"葱","quantity":1,"unit":"根"},{"name":"姜","quantity":4,"unit":"片"},{"name":"料酒","note":"炖煮和爆炒分两次加入"},{"name":"花椒","quantity":3,"unit":"克"},{"name":"八角","quantity":1,"unit":"个"},{"name":"香叶","quantity":2,"unit":"片"},{"name":"油","quantity":15,"unit":"ml"},{"name":"白糖/冰糖","note":"适量"},{"name":"生抽/酱油","quantity":15,"unit":"ml"},{"name":"老抽","note":"适量"},{"name":"黑胡椒粉（或白胡椒粉）","quantity":2,"unit":"克"},{"name":"土豆","quantity":2,"quantityMax":3,"unit":"个"},{"name":"西红柿","quantity":2,"quantityMax":3,"unit":"个"},{"name":"洋葱","quantity":1,"unit":"个"},{"name":"番茄膏/番茄酱","quantity":5,"quantityMax":10,"unit":"克"},{"name":"番茄罐头","note":"可选，替代番茄膏"},{"name":"盐","note":"适量"}]'::jsonb, '["备菜:","土豆去皮、切成 5cm 大块，备用","西红柿切十字花刀，开水烫后去皮，把中间的芯去掉，切 3cm 小块备用","葱切 4g 的葱花出来，剩下的掰成 5-8cm 大段","牛肉泡凉水半小时去血水，或凉水下锅煮至表面变白捞出，期间撇去浮末","洋葱切 0.5-1cm 小粒","制作","全程中火","凉水没过牛肉，放入高压锅，放入葱段，姜片，放入 20g 料酒，上汽压 20 分钟","取出牛肉后，切 5cm 大块，挑出姜，汤盛到一个大碗里一会炖煮用","倒油，油四到五成热以后下花椒八角香叶，出香味之后糊之前挑出不用","下入牛肉，葱姜，炒香，炒多久都无所谓，看着有点要糊可以舀 10ml 汤，此下同理","炒香后加入生抽 15ml，料酒 15ml，胡椒粉，5-10g 番茄膏番茄酱或一个番茄罐头，加入洋葱炒至透明","（可选）可以加一点点盐使洋葱出水不容易糊，不要加太多，后面再调味","加入西红柿炒至西红柿化开软烂，倒入剩下的汤","炖煮","中火开锅后，全程小火","出锅前 30-40 分钟 加土豆并调味","依据个人口味边尝边加糖盐，合适为止","筷子戳牛肉软烂后出锅！"]'::jsonb, '["荤菜","酸甜","炖","家常","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_0149dcfbad.png', 'https://www.bilibili.com/video/BV1sK411i758', '{"energyKcal":480,"protein":42,"carbs":35,"fat":22}'::jsonb, '[null,null,null,null,1800,null,null,null,1200,null,null,null,null,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/西红柿牛腩/西红柿牛腩', '西红柿牛腩', '荤菜', 5, 90, '西红柿牛腩汤汁浓厚酸甜可口，牛肉软绵醇香，是道开胃下饭的家常菜。富含蛋白质、维生素和番茄红素，营养均衡。对新手有一定挑战，需要掌握炖肉火候和番茄炒汁的技巧。一般初学者大约需要 90 分钟完成。', '[{"name":"西红柿","quantity":3,"quantityMax":4,"unit":"个"},{"name":"牛腩","quantity":500,"unit":"克"},{"name":"食用油","quantity":20,"quantityMax":30,"unit":"ml"},{"name":"水","quantity":2,"unit":"L"},{"name":"葱段","quantity":2,"unit":"段"},{"name":"姜片","quantity":2,"unit":"片"},{"name":"八角","quantity":3,"unit":"小片"},{"name":"料酒/黄酒","quantity":5,"quantityMax":10,"unit":"ml"},{"name":"葱花","quantity":10,"unit":"克"},{"name":"姜","quantity":10,"unit":"克"},{"name":"生抽","note":"适量"},{"name":"白胡椒粉","note":"适量"},{"name":"白糖","note":"适量"},{"name":"盐","note":"适量"}]'::jsonb, '["牛腩切条、切块成长宽高均 2cm ，冷水下锅，开锅煮制 2 分钟去除血水，捞出冲洗干净","另起锅 2L 水烧开，加入 2cm 两段葱段、两片姜片、八角、料/黄酒 5-10ml，放入焯好的牛肉，盖盖炖制（砂锅 1 小时，高压锅炖肉模式 45 分钟），筷子能轻松插透就证明炖好了","西红柿去皮：西红柿头部滑十字至腰线，筷子/刀叉从果蒂捅入，煤气灶小火，一边转动一边烤，及时拿下来查看，起皮后撕下来，切块。越小越好","撕皮小心烫，去皮后的西红柿特别滑，慢切注意安全","起锅烧油，油温 7 成热，葱、姜各 10g，番茄下锅，炒透炒出番茄红色，加入煮好的牛腩和原汤，原汤刚刚没过牛肉即可","根据个人口味放入盐、糖、生抽调味盖盖","开锅后大火继续炒制 3-5 分钟","待番茄汁呈中等粘稠程度后关火，散入葱花，盛盘"]'::jsonb, '["荤菜","酸甜","炖","家常","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_740749ed91.jpg', 'https://www.bilibili.com/video/BV1RN4y1r7dt', '{"energyKcal":680,"protein":52,"carbs":12,"fat":58}'::jsonb, '[120,3600,null,null,null,null,180,null]'::jsonb),
  ('howtocook:meat_dish/豆豉鲮鱼油麦菜/豆豉鲮鱼油麦菜', '豆豉鲮鱼油麦菜', '荤菜', 2, 15, '豆豉鲮鱼油麦菜是一道咸香下饭的快手家常小炒，源于粤式罐头菜肴，油麦菜清脆、鲮鱼酥香。荤素搭配，富含蛋白质和膳食纤维。做法简单，对新手十分友好，一般十五分钟即可完成。', '[{"name":"油麦菜","quantity":500,"unit":"g"},{"name":"甘竹牌鲮鱼罐头","quantity":1,"unit":"罐"},{"name":"蒜","quantity":4,"unit":"瓣"},{"name":"生抽","quantity":20,"unit":"g"},{"name":"白糖","quantity":3,"unit":"g"},{"name":"食用油","quantity":15,"unit":"ml"}]'::jsonb, '["食材处理：","油麦菜洗净后切段","鲮鱼罐头打开后，把鲮鱼主刺去除，切成小段后备用","大蒜切成末","炒制过程：","锅热倒入食用油，油热后加入洗净的油麦菜，炒到萎蔫出水后盛出备用，倒掉炒制出的水分","重新热锅后，加入鲮鱼罐头中的油，放入蒜末煸香","蒜末煸香后加入鲮鱼罐头中的豆豉，翻拌后加入切碎的鲮鱼块，再次翻拌","翻拌均匀后加入油麦菜，加入生抽和糖调味","调味加入后简单翻拌即可出锅装盘"]'::jsonb, '["荤菜","咸香","粤式","快炒","下饭","家常","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_dfc9c0c01c.jpg', 'https://www.bilibili.com/video/BV1ky4y1H7us', '{"energyKcal":450,"protein":20,"carbs":9,"fat":32}'::jsonb, null),
  ('howtocook:meat_dish/豉汁排骨', '豉汁排骨', '荤菜', 4, 60, '这是一道粤式茶楼里的人气蒸点，豉香醇厚，排骨滑嫩脱骨。排骨提供优质蛋白和钙质，发酵豆豉增添风味也更利吸收。做法需经过泡洗、腌制和控火蒸制，对新手稍有考验，但步骤清晰易上手，从备料到出锅大约只需 1 小时。剩余的汤汁用来拌饭或拌面格外鲜美。', '[{"name":"肋排","quantity":500,"unit":"g"},{"name":"阳江豆豉","quantity":15,"unit":"g"},{"name":"蒜蓉","quantity":10,"unit":"g"},{"name":"姜末","quantity":5,"unit":"g"},{"name":"生抽","quantity":15,"unit":"ml"},{"name":"老抽","quantity":3,"unit":"ml"},{"name":"蚝油","quantity":10,"unit":"g"},{"name":"白砂糖","quantity":5,"unit":"g"},{"name":"生粉","quantity":8,"unit":"g"},{"name":"食用油","quantity":20,"unit":"ml"},{"name":"清水","quantity":30,"unit":"ml"},{"name":"葱花","note":"适量"},{"name":"白芝麻","note":"适量"}]'::jsonb, '["将排骨用冷水浸泡 10 分钟泡去血水，换水重复 2 次，用厨房纸吸干","将豆豉放入水中浸泡 5 分钟","将所有食材混合（食用油放 10 ml），腌制 8-30 分钟","水开后上锅蒸 18 分钟","焖 2 分钟","锅中倒入 10 ml 热油，加热到 180-200 ℃","均匀撒上葱花和白芝麻，热油浇在撒料上"]'::jsonb, '["荤菜","粤式","蒸制","咸香","下饭","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_d0aae2339e.jpg', 'https://www.bilibili.com/video/BV1M74teJEm6', '{"energyKcal":1100,"protein":56,"carbs":19,"fat":80}'::jsonb, null),
  ('howtocook:meat_dish/豉汁蒸白鱔/豉汁蒸白鱔', '豉汁蒸白鱔', '荤菜', 3, 30, '豉汁蒸白鱔是一道粤式经典蒸菜，豆豉蒜蓉的酱香渗透进鱼肉，口感嫩滑鲜美。白鱔富含优质蛋白和多种不饱和脂肪酸，对身体有滋补作用。操作步骤清晰，但处理生鱼和掌握火候稍有挑战，适合有一定基础的厨友。从备料到上桌大约需要 30 分钟。', '[{"name":"白鳝","quantity":250,"unit":"克"},{"name":"豆豉","quantity":1,"unit":"汤匙"},{"name":"蒜头","quantity":2,"unit":"瓣"},{"name":"姜","quantity":3,"unit":"片"},{"name":"葱","quantity":1,"unit":"根"},{"name":"生抽","quantity":1.5,"unit":"汤匙"},{"name":"老抽","quantity":0.5,"unit":"茶匙"},{"name":"糖","quantity":0.5,"unit":"茶匙"},{"name":"麻油","quantity":0.5,"unit":"茶匙"},{"name":"生粉","quantity":1,"unit":"茶匙"},{"name":"水","quantity":1,"unit":"汤匙"},{"name":"红椒","quantity":10,"unit":"克"}]'::jsonb, '["检查与清洗白鱔：","购买时已请鱼贩去内脏、刮去黏液并切成约 5 厘米长的段。","回家后检查白鱔，冲洗干净，确保无残留黏液或杂质。","可选：用 3g 盐和 1 茶匙生粉轻搓白鱔段，腌制 5 分钟后冲洗干净，去腥并增加嫩滑口感。","准备酱汁：","在小碗中混合 1 汤匙豆豉、2 瓣蒜末、1.5 汤匙生抽、0.5 茶匙老抽、0.5 茶匙糖、0.5 茶匙麻油和 1 汤匙水，搅拌均匀。","若喜欢更浓郁的豉汁，可多加 0.5 汤匙豆豉。","摆盘：","将已切好的白鱔段平铺在耐热盘中，尽量不重叠。","将姜丝均匀撒在白鱔上。","将调好的豉汁均匀淋在白鱔上。","蒸制：","在蒸锅或电蒸炉中加入水 (500ml)，烧开。","将装有白鱔的盘子放入蒸锅，盖上锅盖。","用中大火蒸约 8-10 分钟 （视白鱔段大小调整时间），至白鱔熟透但不过老 （肉质变白，无血水）。","装饰与完成：","蒸好后取出，撒上葱丝和红椒丝 （可选） 作装饰。","可再淋热麻油提升香气。","趁热上桌，搭配白饭享用。"]'::jsonb, '["荤菜","粤式","清蒸","鲜香","下饭","家常","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_80aa5b3980.jpeg', 'https://www.bilibili.com/video/BV1SE411o7G8', '{"energyKcal":480,"protein":46,"carbs":4,"fat":30}'::jsonb, null),
  ('howtocook:meat_dish/贵州辣子鸡/贵州辣子鸡', '贵州辣子鸡', '荤菜', 4, 90, '贵州辣子鸡是贵州地区的经典家常菜，以糍粑辣椒和多种香料烹制而成，鸡肉香糯软烂，土豆绵密入味，整体风味香辣浓郁。鸡肉富含优质蛋白质，搭配土豆等配菜，营养均衡。这道菜步骤较多，对新手有一定挑战，但按部就班也能成功。从备料到出锅，预计需要 1.大约 5 小时。', '[{"name":"农村玉米鸡","quantity":4,"unit":"斤"},{"name":"土豆","quantity":2,"unit":"个"},{"name":"大蒜","quantity":2,"unit":"个"},{"name":"香叶","quantity":2,"unit":"片"},{"name":"姜","quantity":2,"unit":"个"},{"name":"老抽","quantity":20,"unit":"ml"},{"name":"花椒/麻椒","note":"适量"},{"name":"糍粑辣椒","quantity":500,"unit":"g"},{"name":"豆瓣酱","note":"适量"},{"name":"啤酒","quantity":0.5,"unit":"瓶"},{"name":"蒜苗","quantity":3,"unit":"根"},{"name":"酒糟","note":"适量"},{"name":"食用油","quantity":2,"unit":"斤"}]'::jsonb, '["在锅中加入和锅一半高度的油，将切成长条的土豆先炸至表面金黄然后捞出备用，等油温上至烤手时候将切好的鸡块放入锅中炸，并放入切好的生姜片和花椒","刚开始炸鸡的时候，油是浑浊的，因为鸡块里面有水的原因，等到油炸至清澈，鸡块就炸好了，然后捞出备用","现在锅里面的油可以捞三分之一出来，现在用不到这么多的油","将锅中剩余的油加热，加入糍粑辣椒，豆瓣酱，生姜片，炒出红油状，将炸好的鸡块翻炒均匀","等到鸡块都上色，加入老抽，倒入啤酒，啤酒一定要盖过鸡块，加上香叶盖上盖，闷十分钟，期间间隔翻炒","然后加入土豆条，大蒜（不用切，一颗一颗的最好），然后再闷 20 分钟","最后加入酒糟翻炒均匀再加入切好的蒜苗，就可以出锅了"]'::jsonb, '["荤菜","香辣","贵州风味","炸焖","下饭","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_1fb0748959.jpg', 'https://www.bilibili.com/video/BV1bLBmYQEZt', '{"energyKcal":750,"protein":40,"carbs":20,"fat":55}'::jsonb, null),
  ('howtocook:meat_dish/辣椒炒肉', '辣椒炒肉', '荤菜', 3, 30, '辣椒炒肉是一道湘味浓郁的家常菜，辣椒干香微焦，肉片滑嫩入味，咸鲜微辣十分下饭。猪肉富含优质蛋白质和 B 族维生素，青椒则提供丰富的维生素 C。这道菜需要掌握干煸和快炒的火候，适合有一定烹饪基础的朋友尝试。从备料到出锅，大约需要 30 分钟。', '[{"name":"青椒","quantity":3,"unit":"个"},{"name":"猪瘦肉","quantity":200,"unit":"克"},{"name":"盐","quantity":3,"unit":"克"},{"name":"生抽","quantity":3,"unit":"ml"},{"name":"蚝油","quantity":3,"unit":"ml"},{"name":"大蒜","quantity":5,"unit":"克"},{"name":"姜","quantity":5,"unit":"克"},{"name":"食用油","quantity":8,"unit":"ml"},{"name":"酱油","quantity":2,"unit":"ml"},{"name":"豆豉","quantity":3,"unit":"克"}]'::jsonb, '["将青椒洗净，去除青椒把以及青椒籽，再用滚刀手法切好备用。","大蒜用刀拍一下，再横切成蒜瓣，生姜切碎成姜末。","将猪瘦肉切成肉片（顺着猪肉的纹理切，即刀和肉的纹理呈水平线，出来的肉片，纹路呈“川”字）。","将切好的猪肉洗净，放入空碗，再加入计算好的生抽、蚝油、盐搅拌均匀，腌制 10 分钟。","热锅，不用倒油，把切好的青椒放入锅中，大火干煸至虎皮状后，再加 2g盐继续翻炒 1 分钟 后捞起。","不用洗锅，大火热锅，加入份数 8ml油，等待 30s，加入蒜瓣、姜末翻炒 15s。","加入腌制好的猪肉倒入锅内翻炒 2 分钟，再加入干煸过的青椒翻炒 1 分钟。","根据个人口味喜好加入豆豉，最后加入酱油，继续翻炒 30s。","出锅，盛盘。"]'::jsonb, '["荤菜","湘菜","咸鲜微辣","干煸","快炒","下饭","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_393b9bad32.jpg', 'https://www.bilibili.com/video/BV1uDdnYRETN', '{"energyKcal":410,"protein":41,"carbs":10.2,"fat":20}'::jsonb, '[null,null,null,600,60,45,180,30,null]'::jsonb),
  ('howtocook:meat_dish/酱排骨/酱排骨', '酱排骨', '荤菜', 4, 60, '酱排骨色泽酱红，肉质酥烂，骨香浓郁，汁浓味鲜，咸中带甜，是一道经典的家常菜。排骨富含优质蛋白质和钙质，营养均衡。制作涉及炒糖色和较长时间炖煮，对新手有一定挑战，但只要按步骤操作，也能顺利掌握。预计从备料到出锅约需 1 小时。', '[{"name":"排骨","quantity":300,"unit":"克"},{"name":"五香粉","quantity":20,"unit":"克"},{"name":"料酒","quantity":10,"unit":"ml"},{"name":"食用油","quantity":30,"unit":"ml"},{"name":"白砂糖","quantity":15,"unit":"克"},{"name":"老抽","quantity":10,"unit":"ml"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"蚝油","quantity":5,"unit":"ml"},{"name":"小米椒","quantity":1,"unit":"个"},{"name":"蒜","quantity":2,"unit":"粒"},{"name":"姜","quantity":2,"unit":"片"}]'::jsonb, '["起锅烧热水，放入排骨、姜片、料酒，煮开后用勺子舀去白色油沫，2-3 分钟后出锅","冷水清洗排骨，清洗 2-3 遍","小火起锅，加入食用油，加入白砂糖 ，轻轻搅拌到糖水变成黄色","倒入排骨翻炒 30 S 后，加入生抽、蚝油、五香粉、蒜、小米椒后翻炒 30 S 后，加入清水没过排骨","大火煮 30 分钟，加入老抽上色，再煮 10 分钟","起锅摆盘"]'::jsonb, '["荤菜","酱香","咸甜","炖","下饭","家常菜"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_cc25bf657d.jpeg', 'https://www.bilibili.com/video/BV1TAuEziEC8', '{"energyKcal":520,"protein":30,"carbs":18,"fat":34}'::jsonb, '[null,null,null,60,2400,null]'::jsonb),
  ('howtocook:meat_dish/酱牛肉/酱牛肉', '酱牛肉', '荤菜', 5, 600, '酱牛肉是一道北派家常冷荤，酱香浓郁，口感紧实不散，嚼劲十足。牛腱子肉富含优质蛋白和多种氨基酸，慢炖后更易消化吸收。制作过程不算复杂，但包含腌制、慢炖和长时间冷藏，对新手来说需要些耐心，从头到尾大约需要 10 小时。', '[{"name":"牛腱子肉","quantity":2000,"unit":"克"},{"name":"香叶","quantity":1,"unit":"片"},{"name":"姜","quantity":3,"unit":"片"},{"name":"葱","quantity":0.5,"unit":"根"},{"name":"老抽","quantity":15,"unit":"ml"},{"name":"桂皮","quantity":1,"unit":"块"},{"name":"冰糖","quantity":7,"quantityMax":8,"unit":"粒"},{"name":"花椒","quantity":15,"unit":"粒"},{"name":"料酒","quantity":30,"unit":"ml"},{"name":"生抽","quantity":15,"unit":"ml"},{"name":"盐","quantity":8,"unit":"克"},{"name":"八角","quantity":4,"unit":"个"},{"name":"黄豆酱","quantity":15,"unit":"ml"}]'::jsonb, '["牛腱子肉清洗干净，用清水浸泡 1 小时，去除血水","用牙签或者叉子在牛腱子肉表面扎孔，加料酒、花椒、姜片后，用保鲜膜紧密包裹容器，腌制 4-6 小时","牛腱子肉切成 8cm，不超过 10cm 的肉块","牛腱子肉放入锅中，加入冷水至水面没过牛肉，开锅至水沸腾开始计时，同时捞出浮沫。3 分钟后停火，捞出牛肉，用温水洗净","将洗净后的牛腱子肉放入砂锅或炖锅，加水没过牛腱子肉，开大火，放入除盐之外其他未使用的配料","水开之后，大火转为小火，持续加热 90 分钟，加盐","加盐后，继续小火 90 分钟（注：每 30 分钟确认水位线，要求至少达到牛肉面高度的 80%）","加热 180 分钟后，捞出牛腱子肉，捞出牛腱子肉，用保鲜膜紧密包裹，放入冰箱冷藏数小时","取出后沿牛肉纹路切片，上桌食用，其他牛腱子肉建议不切片冷藏"]'::jsonb, '["荤菜","酱香","冷荤","北派","慢炖","下酒","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_c5fd21fc14.jpg', 'https://www.bilibili.com/video/BV1VW41147Fh', null, null),
  ('howtocook:meat_dish/醉排骨/醉排骨', '醉排骨', '荤菜', 4, 40, '醉排骨是福州传统名菜，口感外酥里嫩，酸甜开胃，带着独特的鱼露鲜香。排骨富含蛋白质和钙质，营养解馋。这道菜需要掌握挂糊和复炸的技巧，更适合有一定下厨经验的朋友尝试，全程大约需要 40 分钟完成。', '[{"name":"排骨","quantity":200,"unit":"克"},{"name":"地瓜粉","quantity":30,"unit":"克"},{"name":"鸡蛋黄","quantity":1,"unit":"个"},{"name":"鱼露","quantity":5,"unit":"ml"},{"name":"蒜末","quantity":2,"unit":"粒"},{"name":"香醋","quantity":5,"unit":"ml"},{"name":"白砂糖","quantity":10,"unit":"克"},{"name":"番茄酱","quantity":5,"unit":"克"},{"name":"葱","quantity":1,"unit":"根"},{"name":"芝麻","quantity":5,"unit":"克"},{"name":"食用油","quantity":500,"unit":"ml"}]'::jsonb, '["排骨中加入 5 g 地瓜粉和水进行搅拌，清洗 2-3 遍后放入大碗备用","排骨中加入鱼露、地瓜粉、鸡蛋黄 充分搅拌","将排骨一个一个放入锅中（切记不可以整碗倒入），保证每个不要粘在一起","全部放入后，每 30 S 用勺子来回两面翻转瘦肉块，直至排骨表面金黄","取出排骨，一分钟后倒入油锅中继续炸，直至瘦肉块表面出现焦黄后，取出放入大碗备用","准备一个小碗，加入蒜末、香醋、白砂糖、鱼露、番茄酱、葱花、芝麻搅拌均匀，倒入 5 ml 热油","将汤汁浇灌入排骨，在充分搅拌后倒入盘中"]'::jsonb, '["荤菜","酸甜","鲜香","炸制","福州菜","宴客","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_287c1dc241.jpeg', 'https://www.bilibili.com/video/BV1iS4y1T7aU', '{"energyKcal":580,"protein":32,"carbs":18,"fat":35}'::jsonb, '[null,null,null,30,60,null,null]'::jsonb),
  ('howtocook:meat_dish/青椒土豆炒肉/青椒土豆炒肉', '青椒土豆炒肉', '荤菜', 3, 60, '青椒土豆炒肉是一道荤素搭配的家常小炒，口感鲜香脆嫩，酱香浓郁，特别下饭。土豆富含碳水化合物和维生素 C，青椒提供丰富的维生素 C 和膳食纤维，搭配猪肉的优质蛋白质，营养均衡。这道菜做法不复杂，对新手比较友好，从备料到出锅大约只需 1 小时。', '[{"name":"青椒","quantity":2,"unit":"个"},{"name":"土豆","quantity":2,"unit":"个"},{"name":"猪肉（五花肉）","quantity":200,"unit":"克"},{"name":"葱","quantity":1,"unit":"根"},{"name":"姜","quantity":1,"unit":"块"},{"name":"蒜","quantity":3,"unit":"瓣"},{"name":"盐","quantity":7,"unit":"克"},{"name":"酱油","quantity":6,"quantityMax":10,"unit":"ml"},{"name":"食用油","quantity":10,"quantityMax":15,"unit":"ml"},{"name":"土豆淀粉","quantity":5,"unit":"克"},{"name":"水","quantity":15,"unit":"克"}]'::jsonb, '["青椒去除根蒂切小块，土豆去皮切 2mm 薄片，猪肉切 4mm 薄片，葱横纵切 3mm 小段，姜蒜去皮拍散剁碎末；土豆淀粉加入约 15g 水搅拌均匀至水淀粉。","起锅烧油，加热至 7 成热放入猪肉片，缓缓翻滚炒至去肉红色，加入约 3ml 酱油，翻炒肉片均匀上色，放入约 2g 盐。","转 5 成油温，加入葱姜蒜炒 5 秒，然后加入土豆片，转 7 成油温均匀翻炒，加入加入约 5ml 酱油和 2g 盐，炒至土豆断生，表面轻微焦黄。","转 8 成油温加入青椒，大火煸炒出锅气（有白烟冒出），反复均匀翻炒 1 分钟上色，最后在锅周围倒入水淀粉转 4 成火勾芡。","在外观呈粘稠状态后关火，盛盘"]'::jsonb, '["荤菜","鲜香","家常","下饭","炒制","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_6531ead3bc.jpg', 'https://www.bilibili.com/video/BV1Mnd2BDEoJ', '{"energyKcal":780,"protein":25,"carbs":60,"fat":50}'::jsonb, '[null,null,5,60,null]'::jsonb),
  ('howtocook:meat_dish/青椒酿/青椒酿', '青椒酿', '荤菜', 3, 30, '这道广西经典家常菜以青椒包裹调好味的肉馅或虾滑，煎至表皮起皱呈虎皮色后焖煮入味，青椒清香与馅料鲜美交融，咸香微辣，十分下饭。猪肉和虾仁提供优质蛋白质，青椒富含维生素 C，营养均衡。制作需要一点耐心酿馅，但整体流程清晰，跟着步骤操作一般 30 分钟就能完成。', '[{"name":"青椒（尖椒，选笔直、肉厚）","quantity":8,"unit":"个"},{"name":"猪肉（前夹肉最佳）","quantity":250,"unit":"克"},{"name":"葱","quantity":2,"unit":"根"},{"name":"生姜","quantity":1,"unit":"小块"},{"name":"生抽","quantity":30,"unit":"ml"},{"name":"老抽","quantity":5,"unit":"ml"},{"name":"食盐","quantity":3,"unit":"克"},{"name":"食用油","quantity":30,"unit":"ml"},{"name":"清水","quantity":100,"unit":"ml"},{"name":"淀粉（可选）","quantity":10,"unit":"克"},{"name":"大蒜（可选）","quantity":4,"unit":"瓣"},{"name":"蚝油（可选）","quantity":10,"unit":"ml"},{"name":"料酒（可选）","quantity":10,"unit":"ml"},{"name":"鸡蛋（可选）","quantity":1,"unit":"个"},{"name":"白胡椒粉（可选）","quantity":2,"unit":"克"},{"name":"白糖（可选）","quantity":5,"unit":"克"},{"name":"虾仁（虾滑版）","quantity":250,"unit":"克"}]'::jsonb, '["猪肉洗净剁成肉馅（或用绞肉机），姜切末，葱切葱花","肉馅中加入姜末、葱花、生抽 15ml、老抽 5ml、食盐 3g，搅拌均匀","可选加入：料酒 10ml、蚝油 10ml、鸡蛋 1 个、淀粉 5g、白胡椒粉 2g、白糖 5g","朝一个方向搅拌肉馅至粘稠上劲，腌制 10 分钟","青椒洗净，去蒂，用筷子小心挖去内部的籽和白筋，保持青椒完整不破","可选在青椒内壁撒干淀粉约 5g，摇晃均匀，帮助肉馅粘附不脱落","将腌好的肉馅用筷子或裱花袋塞入青椒中，尽量填满但不要太紧以防撑破","全部酿好后备用","碗中加入生抽 15ml、老抽 5ml、清水 100ml，搅拌均匀","可选加入淀粉 5g，使汤汁更浓稠","热锅，倒入 30ml 食用油，油温五六成热时放入酿好的青椒（肉面朝下先煎）","中小火慢煎，翻面使青椒各面都煎至表皮起皱呈虎皮色，盛出备用","锅留底油，可选放入蒜末爆香","倒入调好的酱汁，烧开后放入煎好的青椒","转中小火，盖上锅盖焖煮 5-8 分钟，至汤汁浓稠、青椒变软","开盖大火收汁至汤汁油亮包裹青椒，即可出锅装盘","虾仁 250g 去虾线，用刀背拍成虾泥（保留一定颗粒感，口感更好，直接买成品虾滑得了，买那种三角形的裱花一样直接塞进去）","虾滑馅调味：姜末 5g、食盐 2g、淀粉 5g、生抽 10ml","可选加入：料酒 5ml、白胡椒粉 1g、蛋清半个","朝一个方向搅拌至虾滑上劲，腌制 10 分钟","后续酿入、煎制、焖煮步骤与猪肉版本一致","虾滑易熟，焖煮时间可缩短至 4-5 分钟"]'::jsonb, '["荤菜","咸香","微辣","下饭","煎焖","广西风味"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_fdb277f6f8.jpeg', 'https://www.bilibili.com/video/BV1wygCzBEJV', '{"energyKcal":800,"protein":50,"carbs":30,"fat":60}'::jsonb, '[null,null,null,600,null,null,null,null,null,null,null,null,null,null,300,null,null,null,null,600,null,240]'::jsonb),
  ('howtocook:meat_dish/香干肉丝', '香干肉丝', '荤菜', 3, 30, '香干肉丝是一道咸香下饭的家常小炒，肉丝嫩滑，香干柔韧，青椒爽脆。富含动物性与植物性双重蛋白质，搭配青椒补充维生素。难度适中，新手稍加练习即可掌握，预计制作时长约 30 分钟。', '[{"name":"猪里脊（肉丝）","quantity":100,"unit":"克"},{"name":"香干","quantity":75,"unit":"克"},{"name":"青椒","quantity":5,"unit":"个"},{"name":"盐","quantity":3,"unit":"克"},{"name":"生抽","quantity":5,"unit":"ml"},{"name":"淀粉","quantity":5,"unit":"克"},{"name":"大蒜","quantity":5,"unit":"克"},{"name":"鸡精","quantity":2,"unit":"克"}]'::jsonb, '["肉丝（没有肉丝，自己切）用生抽(3ml)，生粉混合均匀待用。","将青椒洗净，再用滚刀手法切好备用。","大蒜横切成片，香干切丝。","淀粉与水(10ml)混合，搅拌均匀。","干净锅 15ml 油，不用等油热就倒入肉丝慢慢划散，肉丝熟了，立马捞出，留油到锅里。","将蒜片和香干放入锅中，加入 2ml 生抽，翻炒均匀。","2-3 分钟，看火大小，将青椒丝放入锅中混合，翻炒。","1 分钟后，放入肉丝混合。","倒入淀粉与水的混合物勾芡，加入盐 3g，鸡精 2g，翻炒 2-3 分钟出锅。","成品。"]'::jsonb, '["荤菜","咸香","快炒","家常","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_181723c3a7.jpg', 'https://www.bilibili.com/video/BV1gP4y1S79p', '{"energyKcal":460,"protein":33,"carbs":18,"fat":29}'::jsonb, '[null,null,null,null,null,null,null,60,null,null]'::jsonb),
  ('howtocook:meat_dish/香干芹菜炒肉/香干芹菜炒肉', '香干芹菜炒肉', '荤菜', 3, 30, '香干芹菜炒肉是一道家常小炒，豆干柔韧、芹菜爽脆、猪肉嫩滑，咸鲜微辣。芹菜富含膳食纤维，豆干和猪肉提供优质植物蛋白与动物蛋白。做法简单，对新手友好，从备料到出锅大约只需 30 分钟。', '[{"name":"豆干","quantity":150,"unit":"克"},{"name":"香芹/芹菜","quantity":4,"unit":"根"},{"name":"猪肉","quantity":200,"unit":"克"},{"name":"大蒜","quantity":2,"unit":"瓣"},{"name":"辣椒","quantity":4,"unit":"个"},{"name":"花椒","quantity":6,"unit":"粒"},{"name":"盐","quantity":5,"unit":"克"},{"name":"鸡精","quantity":3,"unit":"克"},{"name":"老抽","quantity":8,"unit":"ml"},{"name":"蚝油","quantity":5,"unit":"ml"},{"name":"食用油","quantity":10,"quantityMax":15,"unit":"ml"}]'::jsonb, '["芹菜去叶切段、切成不超过 4cm 的条状，备用","香干切条，宽约小拇指，备用","蒜头切片或者剁成蒜泥都行，备用","辣椒切圈或者斜切成条都行，备用","热锅，锅内放入 10ml - 15ml 食用油。等待 10 秒让油温升高","放入花椒、大蒜爆香（可以吃姜的也可以额外放入一些姜片/姜丝）","加入猪肉炒至变色，再加入 8ml 老抽上色翻炒均匀（有豆瓣酱的，可以放入 3ml 豆瓣酱一起翻炒）","加入香干翻炒均匀（大约 2 分钟）","加入辣椒翻炒均匀（大约 1-2 分钟）","加入芹菜，放入 5g 盐翻炒 1 分钟","加入 3g 鸡精、5ml 蚝油翻炒均匀，即可出锅"]'::jsonb, '["荤菜","家常","下饭","快手","咸鲜","微辣","小炒"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_9371754843.jpg', 'https://www.bilibili.com/video/BV12A4y1X7UZ', '{"energyKcal":290,"protein":22,"carbs":6,"fat":20}'::jsonb, '[null,null,null,null,10,null,null,120,60,60,null]'::jsonb),
  ('howtocook:meat_dish/香煎五花肉/香煎五花肉', '香煎五花肉', '荤菜', 3, 30, '香煎五花肉是一道家常风味的快手荤菜，五花肉片煎得焦香微脆、肥而不腻，搭配脆爽的生菜叶和咸鲜豆瓣酱，入口酱香浓郁又解腻。猪肉富含优质蛋白质和脂肪，能快速补充能量，生菜则提供膳食纤维和维生素，营养更均衡。这道菜适合有一定下厨基础的朋友，新手只要注意火候和防溅油也能轻松上手，从备料到出锅大约半小时即可享用。', '[{"name":"五花肉条（推荐长宽高为20cm×6cm×5cm）"},{"name":"生菜","quantity":1,"unit":"朵"},{"name":"酱油","quantity":8,"unit":"克"},{"name":"盐","quantity":1,"unit":"克"},{"name":"味精","quantity":1,"unit":"克"},{"name":"料酒","quantity":10,"unit":"克"},{"name":"姜","quantity":2,"unit":"片"},{"name":"大蒜","quantity":2,"unit":"朵"},{"name":"食用油","quantity":5,"unit":"ml"},{"name":"豆瓣酱","note":"适量"}]'::jsonb, '["将五花肉条沿长边切片，每片厚 1mm-1.5mm，备用","将切好的五花肉放置碗中，依次加入 8g 酱油，1g 盐，1g 味精，10g 料酒，两片姜，两朵拍扁的大蒜腌制 10 分钟","将生菜叶直接用手扒下来，洗干净，备用","热锅，倒入 5ml 食用油。油轻微冒烟后下入五花肉。单面煎制焦黄色后翻面，另一边同理。","五花肉出锅后，装盘。","将豆瓣酱抹到菜叶上，卷着五花肉即可食用"]'::jsonb, '["荤菜","香煎","家常","快手","下饭","酱香"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_f3f75c7108.jpg', 'https://www.bilibili.com/video/BV1kgKgeBEBT', '{"energyKcal":680,"protein":22,"carbs":3,"fat":62}'::jsonb, '[null,600,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/香菇滑鸡/香菇滑鸡', '香菇滑鸡', '荤菜', 3, 60, '香菇滑鸡是一道以鸡腿肉和香菇为主料的家常菜，鸡腿肉经过煸炒和焖煮后口感滑嫩，搭配香菇独特的菌香，汤汁浓郁鲜美，属于老少皆宜的粤式风味。鸡肉富含优质蛋白质和多种氨基酸，香菇含有香菇多糖和膳食纤维，有助于增强免疫力和促进消化。这道菜需要一些刀工和火候控制，对新手有一定挑战，整体制作约需 1 小时。', '[{"name":"大鸡腿","quantity":2,"unit":"个"},{"name":"干香菇","quantity":5,"unit":"粒"},{"name":"姜","quantity":2,"unit":"片"},{"name":"葱","quantity":2,"unit":"颗"},{"name":"蒜","quantity":2,"unit":"瓣"},{"name":"温水","quantity":150,"unit":"ml"},{"name":"料酒","quantity":15,"unit":"ml"},{"name":"生抽","quantity":30,"unit":"ml"},{"name":"盐","quantity":1.5,"unit":"克"},{"name":"老抽","quantity":15,"unit":"ml"},{"name":"糖","quantity":15,"unit":"ml"},{"name":"香油","quantity":5,"unit":"ml"}]'::jsonb, '["温水泡发干香菇","姜切小块，葱切段，蒜对半切小粒","鸡腿去骨（不去骨也可，只是略影响程序员吃饭的效率而已），切成小块","泡发的香菇一分为四，香菇水留着备用","鸡腿肉焯水 1 分钟，去除血沫和杂质","鸡腿肉中加料酒 15ml、生抽 15ml、盐 1.5g、老抽 15ml，抓匀","油温 3 成，下入鸡腿肉煸炒，等鸡腿肉金黄后盛出备用","锅留底油，下入葱、姜、蒜炒香，香菇入锅，大火翻匀","等待 20 秒会有香菇香味从锅中飘出，此时下入煸炒过的鸡腿肉，下入香菇水（全部，本程序员认为的灵魂操作）、糖 15ml、生抽 30ml","转中火不盖盖，咕嘟 2 分钟收浓汤汁，淋入香油 5ml，撒上葱花后即可关火、装盘"]'::jsonb, '["荤菜","鲜香","粤式","家常","下饭","焖煮"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_7506ce4e04.jpg', 'https://www.bilibili.com/video/BV1554y1J7g4', '{"energyKcal":340,"protein":28.5}'::jsonb, '[null,null,null,null,60,null,null,null,20,120]'::jsonb),
  ('howtocook:meat_dish/香辣鸡爪煲/香辣鸡爪煲', '香辣鸡爪煲', '荤菜', 4, 45, '香辣浓郁、口感 Q 弹，是一道常见的家常下饭菜。鸡爪富含胶原蛋白，有助滋润皮肤、强健筋骨。制作需要先去趾甲，若用整只鸡爪还需去骨，对新手略有挑战，但耐心按步骤操作也能成功。从焯水到小火慢煮再翻炒入味，全程约需 45 分钟。', '[{"name":"鸡爪","quantity":1,"unit":"斤"},{"name":"葱","quantity":2,"unit":"根"},{"name":"姜","quantity":10,"unit":"克"},{"name":"蒜","quantity":10,"unit":"克"},{"name":"料酒","note":"适量"},{"name":"香叶","quantity":3,"unit":"片"},{"name":"八角","quantity":3,"unit":"个"},{"name":"生抽","note":"适量"},{"name":"老抽","note":"适量"},{"name":"小米椒","quantity":6,"unit":"个"},{"name":"辣椒面（可选）","note":"适量"},{"name":"蚝油","quantity":3,"unit":"克"},{"name":"五香粉","note":"适量"},{"name":"盐","note":"适量"},{"name":"鸡精","note":"适量"}]'::jsonb, '["给鸡爪剪去指甲。如果买的鸡爪只有脚掌部分，对半切开即可。 如果是整只鸡爪，需要去骨。清水洗干净。","鸡爪冷水下锅，葱姜料酒焯水，水开，撇去浮沫。","加入香叶、八角、生抽、老抽，盖盖小火慢煮三十分钟。","捞出鸡爪，留一碗鸡汤备用。","起锅烧油，用小火炒香姜末、蒜末、小米椒，能吃辣再放点辣椒面。加入生抽、老抽、蚝油、五香粉、盐，炒出酱香味。","放入鸡爪，放一点盐调味，翻炒一两分钟，再倒入鸡汤，边炒边搅动。","放入鸡精提鲜，撒入葱段搅拌均匀即可出锅。"]'::jsonb, '["荤菜","香辣","炖","下饭菜","家常","Q弹"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_f07ab86233.jpg', 'https://www.bilibili.com/video/BV13E411G7ey', '{"energyKcal":420,"protein":24,"carbs":5,"fat":30}'::jsonb, '[null,null,1800,null,null,null,null]'::jsonb),
  ('howtocook:meat_dish/鱼香肉丝', '鱼香肉丝', '荤菜', 4, 40, '鱼香肉丝是一道经典川菜，口味酸甜微辣，肉丝滑嫩，配以胡萝卜、青椒和木耳，口感丰富。富含蛋白质和多种维生素，荤素搭配，营养均衡。制作有一定难度，需要调好鱼香汁并掌握翻炒火候，新手建议严格按步骤操作。预计制作时长约 40 分钟（不含木耳泡发时间）。', '[{"name":"里脊肉","quantity":200,"unit":"克"},{"name":"胡萝卜","quantity":100,"unit":"克"},{"name":"青椒","quantity":100,"unit":"克"},{"name":"木耳（干）","quantity":5,"unit":"克"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"料酒","quantity":5,"unit":"ml"},{"name":"蛋清","quantity":1,"unit":"个"},{"name":"淀粉","quantity":10,"unit":"克"},{"name":"醋","quantity":15,"unit":"ml"},{"name":"白糖","quantity":10,"unit":"克"},{"name":"盐","quantity":5,"unit":"克"},{"name":"姜","quantity":20,"unit":"克"},{"name":"葱","quantity":20,"unit":"克"},{"name":"蒜","quantity":2,"unit":"瓣"},{"name":"豆瓣酱","quantity":15,"unit":"克"}]'::jsonb, '["制作腌料：将下列原料混合：","生抽 5ml","料酒 5ml","淀粉 5g","水 20ml","蛋清 1 个","制作香汁：将下列原料混合：","生抽 5ml","醋 15ml","白糖 10 克","盐 1 克","淀粉 5g","水 20ml","用腌料腌制里脊肉 15-30 分钟。注意将肉抓匀。","干木耳泡 4 个小时，洗净，切成小块。","青椒洗净，去蒂，切成丝。","胡萝卜洗净，切成丝，将胡萝卜丝焯水。","姜、蒜切沫。","葱切成 5mm 的小段。","将锅烧热，加入 15ml 油。","向锅内倒入准备好的腌肉，快速滑散至变白，盛出备用。","将锅烧热，加入 5ml 油。","倒入全部葱、姜、蒜、豆瓣酱。","倒入全部胡萝卜，翻炒 20s 后，放入青椒和木耳，翻炒 2 分钟。","倒入炒过的肉。快速翻炒均匀。注意不要炒超过 20 秒。","倒入香汁。快速翻炒均匀。注意不要炒超过 15 秒。","关火，盛盘。"]'::jsonb, '["荤菜","川菜","酸甜","微辣","下饭","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_7d457cc86f.jpg', 'https://www.bilibili.com/video/BV1zZAAerEJ3', '{"energyKcal":580,"protein":44,"carbs":38,"fat":26}'::jsonb, '[null,null,null,null,null,null,null,null,null,null,null,null,null,null,14400,null,null,null,null,null,null,null,null,null,140,20,15]'::jsonb),
  ('howtocook:meat_dish/鱼香茄子/鱼香茄子', '鱼香茄子', '荤菜', 3, 30, '鱼香茄子是一道经典的川味家常菜，酸甜微辣，茄子软糯吸汁，非常下饭。茄子富含膳食纤维和多种维生素，搭配肉末能补充蛋白质。制作难度中等，需要掌握炸茄子和调味技巧，新手稍加练习也能成功。从备料到出锅大约需要 30 分钟。', '[{"name":"茄子","quantity":2,"unit":"根"},{"name":"肉末","quantity":20,"unit":"克"},{"name":"盐","quantity":3,"quantityMax":5,"unit":"克"},{"name":"糖","quantity":5,"quantityMax":10,"unit":"克"},{"name":"味精","quantity":5,"unit":"克"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"老抽","quantity":5,"unit":"ml"},{"name":"醋","quantity":10,"unit":"ml"},{"name":"水淀粉","quantity":100,"unit":"ml"},{"name":"豆瓣酱","quantity":20,"quantityMax":30,"unit":"克"},{"name":"小葱","note":"适量"},{"name":"姜","note":"适量"},{"name":"蒜","note":"适量"},{"name":"小米辣","note":"适量"}]'::jsonb, '["将茄子切成条。","将肉切成肉沫，葱姜蒜切碎、小米椒切丁。","调鱼香汁：碗中放入盐、味精、糖、生抽、老抽、醋、水淀粉搅拌均匀。","锅中倒入 300ml 油，开小火（小火容易掌控），等油温七成热（小火大约 40 秒，有烟冒出）放入茄子炸两分钟，当茄子边缘微黄就捞出。多出的油可以盛出以后炒菜用。","锅中留 15-30ml 油，倒入肉沫炒至颜色变白就盛出来。","锅中倒入 15-30ml 油，放入豆瓣酱、葱白、姜、蒜炒香，然后倒入肉沫翻炒均匀。","加入 80-150ml 清水（水面预计茄子八成高度为准），倒入茄子、倒入料汁，爆炒入味收汁。最后放入葱翻炒均匀，就可以起锅了。"]'::jsonb, '["荤菜","川味","鱼香","酸甜微辣","家常","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_b55d7fda63.jpg', 'https://www.bilibili.com/video/BV1qwR6B1EYV', '{"energyKcal":450,"protein":8,"carbs":35,"fat":30}'::jsonb, '[null,null,null,160,null,null,null]'::jsonb),
  ('howtocook:meat_dish/麻婆豆腐/麻婆豆腐', '麻婆豆腐', '荤菜', 3, 40, '这道香辣滑嫩的豆腐菜以咸鸭蛋替代传统豆瓣酱，咸鲜中带着微麻微辣，格外开胃下饭。富含优质蛋白和钙、铁等多种微量元素。制作难度适中，对新手友好，全程约需 40 分钟。', '[{"name":"内脂豆腐","quantity":1,"unit":"盒"},{"name":"咸鸭蛋","quantity":1,"unit":"枚"},{"name":"五花肉","quantity":20,"quantityMax":30,"unit":"克"},{"name":"大蒜","quantity":2,"unit":"瓣"},{"name":"生姜","quantity":2,"unit":"片"},{"name":"小米椒","quantity":5,"unit":"根"},{"name":"香辣酱","quantity":5,"unit":"克"},{"name":"花椒","quantity":20,"unit":"颗"},{"name":"食盐","quantity":3,"unit":"克"},{"name":"酱油","quantity":10,"unit":"克"},{"name":"食用油","quantity":10,"quantityMax":15,"unit":"ml"}]'::jsonb, '["大蒜和生姜切碎，备用","小米辣切成辣椒圈，备用","五花肉切成肉糜（本来就是买的肉糜的跳过）","肉糜中加入一半的食盐和味极鲜酱油，搅拌均匀，备用","鸭蛋用菜刀竖着对半切开（注意安全），去除蛋黄（一定要去除，不然会腥），剩下的蛋白捣碎成大约 2 mm 2 mm 大小，不用太碎，备用","打开豆腐包装，用水果刀将在盒子中的豆腐划成大约 2.5 cm 3 cm 大小，备用","热锅，锅内放入 10ml - 15ml 食用油。等待 10 秒让油温升高","调成小火，放入大蒜、生姜、辣椒圈、花椒、咸鸭蛋、蒜蓉辣酱翻炒 20 秒，炒出香味","调成中火，放入肉糜，翻炒大约 1 分钟，肉炒变色","调成小火，放入豆腐，将剩下的食盐、味极鲜酱油酱油均匀的洒在豆腐上","从锅边倒入开水（不然豆腐容易破），没过豆腐即可","开大火，水沸腾后立马转入中火，等待大约 10 分钟","等到水只剩 1/5 并且豆腐表面已经入色，关火，盛盘"]'::jsonb, '["荤菜","香辣","咸鲜","微麻微辣","下饭","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_74d3804660.jpeg', 'https://www.bilibili.com/video/BV1md3NzzEnF', '{"energyKcal":600,"protein":29,"carbs":10,"fat":41}'::jsonb, '[null,null,null,null,null,null,10,20,60,null,null,600,null]'::jsonb),
  ('howtocook:meat_dish/麻辣香锅', '麻辣香锅', '荤菜', 3, 30, '一道麻辣浓郁的川味家常菜，汇集蔬菜、肉类和豆制品，口感香辣过瘾、层次丰富。荤素搭配提供了优质蛋白质和多种维生素，营养全面。操作步骤清晰，需要掌握焯水和翻炒火候，对新手有一定挑战，总制作时间约 30 分钟。', '[{"name":"青菜（油菜、油麦菜、菠菜）","quantity":455,"unit":"克"},{"name":"无骨肉（猪肉、牛肉、鸡肉、鱼丸、火腿肠）","quantity":430,"unit":"克"},{"name":"干豆腐","quantity":152,"unit":"克"},{"name":"北京麻辣方便面","quantity":1,"unit":"袋"},{"name":"干辣椒","quantity":5,"unit":"克"},{"name":"食用油","quantity":105,"unit":"克"}]'::jsonb, '["烧开一锅水（水量能没过第 2-4 步中的食材即可）。","在开水中放入青菜，焯 5 分钟后盛出备用。","在开水中放入无骨肉，焯 4 分钟后盛出备用。","在开水中放入北京麻辣方便面，煮 2 分钟后盛出备用。","倒出开水，擦干锅具，放入 105 克食用油，大火加热 30 秒。","放入麻辣香锅调料，翻炒 20 秒。","放入干辣椒，翻炒 10 秒。","放入焯过的青菜，改中火，翻炒 3 分钟。","放入焯过的无骨肉，翻炒 3 分钟。","放入煮过的北京麻辣方便面，用筷子翻动 1 分钟。","关火，出锅。"]'::jsonb, '["荤菜","麻辣","川味","炒","下饭","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_dbdd40221c.jpg', 'https://www.bilibili.com/video/BV1hMo5BYE7k', '{"energyKcal":1265,"protein":45,"carbs":44,"fat":80.5}'::jsonb, null),
  ('howtocook:meat_dish/黄油鸡', '黄油鸡', '荤菜', 4, 105, '这是一道源自印度的经典咖喱菜肴，以烤制后再炖煮的鸡腿肉搭配番茄、黄油和奶油制成的酱汁，口感醇厚丝滑，酸甜微辣，带有独特的香料复合香气。鸡肉、酸奶和腰果提供了丰富的蛋白质与健康脂肪，番茄和香料也带来一定的维生素与抗氧化物。制作有一定挑战，需要掌握火候和香料的平衡，加上腌制时间共约 1 小时 45 分钟方可完成。', '[{"name":"鸡腿肉（去骨）","quantity":500,"unit":"克"},{"name":"酸奶","quantity":80,"unit":"ml"},{"name":"生姜","quantity":10,"unit":"克"},{"name":"大蒜","quantity":4,"unit":"瓣"},{"name":"红辣椒粉","quantity":5,"unit":"克"},{"name":"姜黄粉","quantity":3,"unit":"克"},{"name":"盐","quantity":3,"unit":"克"},{"name":"柠檬汁","quantity":15,"unit":"ml"},{"name":"食用油","quantity":15,"unit":"ml"},{"name":"番茄","quantity":5,"unit":"个"},{"name":"洋葱","quantity":1,"unit":"个"},{"name":"腰果（用于增稠）","quantity":30,"unit":"克"},{"name":"生姜","quantity":10,"unit":"克"},{"name":"大蒜","quantity":4,"unit":"瓣"},{"name":"黄油","quantity":50,"unit":"克"},{"name":"淡奶油(Heavy Cream)","quantity":100,"unit":"ml"},{"name":"红辣椒粉","quantity":5,"unit":"克"},{"name":"香菜粉","quantity":5,"unit":"克"},{"name":"孜然粉","quantity":3,"unit":"克"},{"name":"印度综合香料粉(Garam Masala)","quantity":3,"unit":"克"},{"name":"小豆蔻粉","quantity":2,"unit":"克"},{"name":"干葫芦巴叶(Kasuri Methi)","quantity":3,"unit":"克"},{"name":"糖","quantity":10,"unit":"克"},{"name":"盐","quantity":5,"unit":"克"},{"name":"水","quantity":100,"unit":"ml"}]'::jsonb, '["在大碗中混合酸奶、生姜泥、大蒜泥、红辣椒粉、姜黄粉、盐、柠檬汁","放入鸡肉块，充分裹上腌料","盖保鲜膜，冷藏腌制至少 1 小时","在平底锅中倒入 15ml 食用油，大火加热","将腌好的鸡肉块放入锅中（不要倒入腌料汁）","大火煎至两面焦黄（每面约 3 分钟），鸡肉不需要完全煮熟","盛出备用","在锅中放入番茄块、洋葱块、腰果、生姜、大蒜和水 100ml","大火煮沸后转中火，煮 15 分钟，直至所有材料完全软烂","稍微冷却后，倒入搅拌机中打成细腻顺滑的泥状","用滤网过滤一遍，去除渣滓，得到顺滑的酱汁，备用","在炒锅中放入黄油 50g，中火加热融化","倒入过滤好的番茄酱汁","加入红辣椒粉 5g、香菜粉 5g、孜然粉 3g、盐 5g","翻炒 3-5 分钟，直至酱汁颜色变深且油花浮出","放入烤好的鸡肉块，翻拌均匀","加入糖 10g（平衡番茄的酸味），搅拌","倒入淡奶油 100ml，搅拌均匀","小火炖 10-12 分钟，使鸡肉完全熟透且吸收酱汁","加入印度综合香料粉 3g、小豆蔻粉 2g","撒入干葫芦巴叶 3g（用手搓碎后撒入）","搅拌均匀，关火","盛盘，可额外淋上少量淡奶油作为装饰"]'::jsonb, '["荤菜","印度风味","咖喱","香辣","醇厚","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_c92630e25e.jpg', 'https://www.bilibili.com/video/BV16C4y127jt', '{"energyKcal":440,"protein":28,"carbs":13,"fat":31.5}'::jsonb, null),
  ('howtocook:meat_dish/黄焖鸡', '黄焖鸡', '荤菜', 3, 40, '黄焖鸡是一道以鸡腿、香菇、青椒为主料的家常菜，汤汁浓郁，鸡肉滑嫩，咸鲜微甜，十分下饭。富含优质蛋白质和菌菇多糖等营养。炒糖色环节稍有挑战，但可用老抽替代，整体难度不高，新手也能顺利掌握。从备菜到出锅，大约需要 40 分钟。', '[{"name":"鸡腿","quantity":2,"unit":"只"},{"name":"香菇（干香菇最佳）","quantity":5,"unit":"朵"},{"name":"青椒","quantity":2,"unit":"个"},{"name":"生姜片","quantity":2,"unit":"片"},{"name":"干辣椒","quantity":5,"quantityMax":6,"unit":"个"},{"name":"盐","quantity":10,"unit":"克"},{"name":"料酒","quantity":10,"unit":"ml"},{"name":"白胡椒粉","quantity":5,"unit":"克"},{"name":"白糖","quantity":5,"unit":"克"},{"name":"酱油","quantity":5,"unit":"ml"},{"name":"味精","note":"适量"},{"name":"土豆（可选）","quantity":1,"unit":"个"}]'::jsonb, '["鸡腿洗净，剁成4cm大小的块","生姜切片、干辣椒切成小圈","香菇切片，青椒切成细长的马蹄状，若为干香菇，洗净灰尘后泡一晚上并留香菇水备用","若有土豆，切为与鸡肉大小类似的滚刀块","炒糖色：锅里倒入底油，冷油时放入白糖（有一定难度，新手可跳至鸡肉炒制并使用老抽替代）","小火慢慢加热，待油温逐渐升高，白糖开始融化并变成较深的棕色（期间要不断搅拌，防止糊锅）","迅速倒入鸡块，转大火，快速翻炒！烹入料酒，继续翻炒片刻","将生姜片和干辣椒倒入","放入酱油，炒匀","倒入香菇水或清水，以能淹住鸡肉为准","倒入香菇片，白胡椒粉，盐，土豆","翻炒均匀后，盖上锅盖焖煮，转中小火15——20分钟，有条件可以转至砂锅","待鸡肉软烂，汤汁浓稠后（汤汁不要收的太干），最后放入青椒","放入味精，兜炒均匀后，关火！青椒基本断生即可，不要炒时间久了"]'::jsonb, '["荤菜","咸鲜","微甜","焖煮","家常","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_6a18de5eee.jpg', 'https://www.bilibili.com/video/BV1qcXPYVE5c', '{"energyKcal":380,"protein":28,"carbs":18,"fat":18}'::jsonb, '[null,null,null,null,null,null,null,null,null,null,null,900,null,null]'::jsonb),
  ('howtocook:meat_dish/黄瓜炒肉', '黄瓜炒肉', '荤菜', 3, 25, '这是一道清爽脆嫩的家常快手菜，咸鲜适口，带有蒜香与微辣。富含蛋白质和多种维生素，有助于清热补水。对新手比较友好，只要注意火候就能成功，预计制作时长约 25 分钟。', '[{"name":"黄瓜","quantity":100,"unit":"克"},{"name":"猪瘦肉","quantity":50,"unit":"克"},{"name":"食用油","quantity":50,"unit":"克"},{"name":"生抽","quantity":5,"unit":"克"},{"name":"盐","quantity":10,"unit":"克"},{"name":"蒜","quantity":2,"unit":"瓣"},{"name":"小米辣","quantity":1,"unit":"根"}]'::jsonb, '["将猪瘦肉切片，放入碗中，倒入食用油 10 克，生抽，搅拌均匀，腌制 10 分钟","将黄瓜切去 5 厘米的头尾，剩余部分斜着切成 0.5 厘米的薄片","将黄瓜倒入碗中，撒上盐 8 克，搅拌均匀，腌制 5 分钟","将蒜瓣去皮，压扁，切成蒜末备用","将小米辣去丁切分成均匀 0.5 厘米的段状","热锅，倒油 40 克，等油温到冒烟，放入蒜蓉小米辣翻炒 5 次","放入腌制好的猪瘦肉，翻炒至肉熟变色","放入黄瓜，加入盐 2 克，大火翻炒均匀半分钟，出锅","如果无法保证大火，可能会有点生。可以考虑增加到 50 秒。"]'::jsonb, '["荤菜","家常","快手","咸鲜","微辣","下饭","清爽"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_meat_dish_e980a46a14.jpg', 'https://www.bilibili.com/video/BV1SB4y1777w', '{"energyKcal":540,"protein":11,"carbs":5,"fat":53}'::jsonb, '[600,null,300,null,null,null,null,30,50]'::jsonb),
  ('howtocook:meat_dish/黑椒牛柳/黑椒牛柳', '黑椒牛柳', '荤菜', 4, 45, '黑椒牛柳是一道广受欢迎的家常小炒，黑椒风味浓郁，牛柳嫩滑，搭配甜脆的洋葱和彩椒，荤素均衡，口味老少咸宜。牛肉富含优质蛋白和铁，彩椒和洋葱能补充多种维生素。这道菜对新手十分友好，从备料到出锅，通常一小时以内就能完成。', '[{"name":"牛肉（里脊肉/牛排肉）","quantity":100,"unit":"克"},{"name":"洋葱","quantity":0.083,"unit":"个"},{"name":"菜椒（红/黄椒）","quantity":0.083,"unit":"个"},{"name":"淀粉","quantity":3,"unit":"克"},{"name":"黑胡椒（粉）","quantity":1,"unit":"克"},{"name":"黑椒（腌料）","note":"适量"},{"name":"盐","quantity":1,"unit":"克"},{"name":"花生油","quantity":10,"unit":"ml"}]'::jsonb, '["将牛肉切条，长度最好控制在 8 厘米以下，厚度约 5-10 毫米，宽度约 1 厘米（要求不严格）","利用腌料腌制牛肉，混合均匀后静置，用量与时间请参照商品说明，可以延长不能缩短。","如果使用液态腌料，可以在腌制结束前三分钟撒一层黑胡椒粉，然后再加入淀粉，再次混合均匀后静置 20 分钟。","开火，热锅，加入花生油。","当能看到锅里的油冒出一丝烟时，放入牛肉，翻炒。","开中火偏大，翻炒 2 分钟至牛肉外表变色（即不出现明显血色，有血色部分说明翻炒不到位）（此处应小心油滴溅射）。","放入洋葱和菜椒，翻炒 2 分钟。","加入盐，再次撒一份黑胡椒粉，翻炒 30 秒，搅拌均匀。","观察洋葱已经变软即可关火，出锅，盛盘。"]'::jsonb, '["荤菜","黑椒","家常","小炒","下饭","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_24038f5581.jpg', 'https://www.bilibili.com/video/BV1hV4y1q7LS', '{"energyKcal":220,"protein":22,"carbs":5,"fat":13}'::jsonb, '[null,null,1200,null,null,120,120,30,null]'::jsonb),
  ('howtocook:meat_dish/黔式腊肠娃娃菜/黔式腊肠娃娃菜', '黔式腊肠娃娃菜', '荤菜', 1, 15, '这道菜咸鲜可口，融合了黔式腊肠的醇香与娃娃菜的清甜，是西南菜系中少见的不辣风味，南北皆宜。娃娃菜富含维生素和膳食纤维，搭配腊肠的蛋白质与脂肪，营养均衡。制作过程极为简单，无需掌握火候和额外调味，从备料到出锅仅需 15 分钟，非常适合新手和忙碌的日常。', '[{"name":"黔式腊肠","quantity":200,"unit":"克"},{"name":"娃娃菜","quantity":300,"unit":"克"},{"name":"水","quantity":750,"unit":"ml"}]'::jsonb, '["锅内放入 750ml 水，开火加热至沸腾","放入腊肠，计时 13 分钟","放入娃娃菜，计时 2 分钟","关火，夹出腊肠及娃娃菜","娃娃菜切段、腊肠切片，装盘"]'::jsonb, '["荤菜","咸鲜","煮","黔式","快手","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_meat_dish_8c141c7b67.jpg', 'https://www.bilibili.com/video/BV1o94y1d736', '{"energyKcal":1050,"protein":45}'::jsonb, null),
  ('howtocook:semi-finished/凉皮', '凉皮', '半成品', 3, 40, '凉皮是一道源自陕西的家常小吃，口感筋道爽滑，酸辣开胃，带有浓郁的芝麻酱香。芝麻酱和面筋提供了丰富的植物蛋白与钙质，搭配清脆的黄瓜和绿豆芽，富含维生素和膳食纤维。整体操作难度中等，只需简单煮烫、切丝和调汁，一般初学者也能从容完成。从备料到上桌大约需要 40 分钟，非常适合夏日餐桌。', '[{"name":"凉皮","quantity":300,"unit":"克"},{"name":"面筋","note":"适量"},{"name":"盐","note":"根据个人口味酌量添加"},{"name":"鸡精","note":"分次加入"},{"name":"蚝油","note":"分次加入"},{"name":"生抽","note":"分次加入"},{"name":"老抽","note":"分次加入"},{"name":"香油","quantity":1,"unit":"克"},{"name":"香醋","note":"根据个人口味酌量添加"},{"name":"芝麻酱","quantity":30,"unit":"克"},{"name":"黄瓜","quantity":100,"unit":"克"},{"name":"大蒜","quantity":10,"unit":"克"},{"name":"绿豆芽","quantity":50,"unit":"克"}]'::jsonb, '["锅中加入 500ml 水。煮沸。","将绿豆芽放入锅中，大火煮 60 秒。豆芽捞出，过凉水，放入盘中备用。","黄瓜切丝放入盘中备用","将 10g 蒜瓣剥皮、放入蒜臼中加入 1g 盐。锤成蒜泥，加入 10g 自来水。放置备用。","注：超市购买来的凉皮表面一般会有食用油，可以使用自来水清洗。面筋同样。","注：清洗面筋之后，请用手将面筋中的大量水分挤出（不需过于用力）。","准备小碗，加入 3g 盐、2g 鸡精、5g 生抽、1g 老抽、1g 香油、2g 蚝油、香醋 5g、（盐、香醋均可根据个人口味酌量添加，以上数据只是大众口味）。","以上调料加入 25-35g 温水（据个人咸淡程度），使用筷子将其拌匀、溶解。静置一旁冷却。","注：以下计量均为一人份，如果有 n 人，请自觉将计量乘以 n","拿出小碗，将准备好的芝麻酱放入其中。","加入 4g 盐、3g 鸡精、5g 生抽、1g 老抽、3g 蚝油。","使用筷子将其调料与芝麻酱拌匀。","加入 10g 清水将其拌匀。","上一步骤重复 2、3 次（次数根据个人对芝麻酱的浓稠程度而定）。","拿出之前准备好的小盆，加入之前准备好的凉皮。","倒入盐水，使用筷子将其拌匀。随之盛入小碗（盐水一并倒入碗中）。","豆芽放置凉皮上、面筋随后放上。","将调配好的芝麻酱从面筋上方倒下。","撒上黄瓜丝。","如有喜爱可以加入辣椒油。","色香味俱全的家常凉皮出炉！"]'::jsonb, '["半成品","酸辣","凉拌","陕西风味","家常","开胃","夏日"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_semi-finished_a2e07be74f.jpg', 'https://www.bilibili.com/video/BV1Ri4y1y7AW', '{"energyKcal":590,"protein":32,"carbs":78,"fat":19}'::jsonb, '[null,60,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:semi-finished/半成品意面', '半成品意面', '半成品', 1, 2, '这是一道利用市售半成品快速完成的西式简餐，面条弹韧有嚼劲，搭配现成酱料风味浓郁。以碳水化合物为主，能迅速补充能量，并含有蛋白质。制作难度极低，新手也能零失误，从开火到装盘仅需约 2 分钟。', '[{"name":"半成品意大利面（推荐品牌圃美多）","quantity":520,"unit":"克"},{"name":"清水","quantity":50,"unit":"ml"}]'::jsonb, '["热锅","将 50 ml 清水倒入平底锅","将面条放入，炒 1 分钟","将酱料倒入，翻炒 1 分钟","装盘即可","将面条放入「可用于微波炉加热」的盘子中","将附带的酱料倒在面条上","倒入 50 ml 清水","700W 加热 2 分钟","取出拌匀即可"]'::jsonb, '["半成品","快手","家常","西式","意面","方便速食"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_semi-finished_856433fc77.jpg', 'https://www.bilibili.com/video/BV16T4y1g7y4', '{"energyKcal":420,"protein":16,"carbs":68,"fat":11}'::jsonb, '[null,null,60,60,null,null,null,null,120,null]'::jsonb),
  ('howtocook:semi-finished/懒人蛋挞/懒人蛋挞', '懒人蛋挞', '半成品', 3, 40, '这道甜品利用现成的蛋挞皮和蛋挞液，外皮酥香、内馅嫩滑，带有焦糖斑点，是经典粤式点心中最易上手的版本。主要成分鸡蛋和牛奶提供了优质蛋白质与钙质，适合作为家庭小点心。整个操作只需组装和烘烤，对完全零基础的新手也很友好，从预热烤箱到出炉约需 40 分钟。', '[{"name":"蛋挞皮","quantity":1,"unit":"个"},{"name":"蛋挞液","quantity":10,"unit":"ml"}]'::jsonb, '["烤箱 200 度，预热 10 分钟","在烤盘上放上蛋挞皮，蛋挞皮中倒入蛋挞液约 10ml，具体分量需要看蛋挞皮大小，通常倒入 4/5 即可","将烤盘放入烤箱内，上下火 190 度，烤 10 - 20 分。如果想快速烤出蛋挞液上的焦褐斑点，需要上火更高一些，通常是 200 - 210 度","蛋挞液烤出焦褐斑点，蛋挞皮完全蓬松冒油即可"]'::jsonb, '["半成品","香甜","烘焙","粤式","快手","新手友好"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_semi_finished_97294260dc.png', 'https://www.bilibili.com/video/BV18qeDzfEKQ', '{"energyKcal":160,"protein":3,"carbs":15,"fat":10}'::jsonb, '[600,null,null,null]'::jsonb),
  ('howtocook:semi-finished/炸薯条/炸薯条', '炸薯条', '半成品', 2, 25, '炸薯条外酥里软，金黄咸香，属于广受欢迎的快餐小食。土豆提供碳水化合物和膳食纤维，但油炸或空气炸制后热量较高。使用半成品薯条和空气炸锅，操作简单，新手也能轻松上手。从预热到出锅，大约需要 25 分钟。', '[{"name":"半成品薯条（推荐品牌麦肯）","quantity":400,"unit":"克"},{"name":"油","note":"适量"}]'::jsonb, '["开封大分量半成品薯条注意开口要小，可以有效减少长久储藏下薯条表面结霜。","插电，200℃预热 5 分钟。","预热的目的是为了确保放入食材的时候锅内温度已经处于烹饪所需温度。","注意，预热完再拿出薯条，不应等薯条软化后再炸制。","取出薯条放入空气炸锅，200℃20 分钟。","取出薯条的时候注意半成品薯条已经有油，所以要异步去做客户端内刀斯林的话需要使用夹持工具。","5~10 分钟时可以拿出锅体晃动使薯条受热均匀也防止粘连。","10 分钟~15 分钟时，拿出锅体，往已经干了的薯条表面喷 1 层面积为薯条表面积 2/3 的油。","喜欢脆薯条的，取出后拿着锅体跳舞让空气经过薯条表面后装盘；喜欢软薯条的直接装盘。配合蘸酱或浇上酱汁更佳。"]'::jsonb, '["半成品","快手","小食","咸香","空气炸锅"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_semi_finished_2a34e3570c.jpg', 'https://www.bilibili.com/video/BV1Q24y147nd', '{"energyKcal":1000,"protein":12}'::jsonb, null),
  ('howtocook:semi-finished/牛油火锅底料', '牛油火锅底料', '半成品', 5, 60, '这道重庆火锅底料以大量牛油为基底，糅合糍粑辣椒和多种香辛料，熬出的底料麻辣醇厚、香气浓烈，是涮烫毛肚、鸭肠等食材的灵魂。牛油和猪油提供了丰富能量，辣椒与花椒能温中散寒、促进食欲，但油脂含量较高，宜节制食用。制作过程需精准控制油温和翻炒火候，对新手有一定挑战，从备料到完成约需 1 小时。', '[{"name":"牛油","quantity":4500,"unit":"克"},{"name":"色拉油/菜籽油","quantity":1000,"unit":"ml"},{"name":"纯猪油","quantity":500,"unit":"克"},{"name":"豆瓣","quantity":1000,"unit":"克"},{"name":"糍粑辣椒","quantity":3000,"unit":"克"},{"name":"老姜","quantity":250,"unit":"克"},{"name":"大葱","quantity":100,"unit":"克"},{"name":"洋葱","quantity":100,"unit":"克"},{"name":"大蒜","quantity":200,"unit":"克"},{"name":"豆豉","quantity":10,"unit":"克"},{"name":"豆母子","quantity":140,"unit":"克"},{"name":"红花椒","quantity":150,"unit":"克"},{"name":"颗粒香料","quantity":100,"unit":"克"},{"name":"整形香料","quantity":150,"unit":"克"},{"name":"麦芽粉","quantity":12.5,"unit":"克"},{"name":"白酒","quantity":150,"unit":"ml"},{"name":"干辣椒面","quantity":15,"unit":"克"},{"name":"山奈","quantity":5,"unit":"克"},{"name":"八角","quantity":10,"unit":"克"},{"name":"草果","quantity":10,"unit":"克"},{"name":"肉桂","quantity":10,"unit":"克"},{"name":"丁香","quantity":5,"unit":"克"},{"name":"小茴香","quantity":10,"unit":"克"},{"name":"白芷","quantity":10,"unit":"克"},{"name":"荜拨","quantity":5,"unit":"克"},{"name":"香草","quantity":10,"unit":"克"},{"name":"香果","quantity":10,"unit":"克"},{"name":"山楂","quantity":10,"unit":"克"},{"name":"陈皮","quantity":5,"unit":"克"},{"name":"香茅","quantity":10,"unit":"克"},{"name":"砂仁","quantity":10,"unit":"克"},{"name":"白蔻","quantity":10,"unit":"克"},{"name":"香叶","quantity":10,"unit":"克"}]'::jsonb, '["锅置旺火（大火）放入牛油烧至 八成热(240±10°C) 时放入 老姜、大葱、洋葱、大蒜 (各100g)，炸干（吸尽异味（牛油腥味））后捞出扔掉。","放入 (色拉油 || 菜籽油)、纯猪油，等待锅中油温下降到 五成热(150±10°C) 时放入 糍粑辣椒 持续翻炒 5-8 分钟。","放入 豆瓣 炒散，转用 中小火 慢炒至料渣略发白翻砂（发出沙沙声）。","油在外观呈现樱桃红时放入 姜片(150g)、大蒜(100g) 炒香，大约 15 秒。","放入 豆鼓、豆母子 炒香，放入 红花椒、小茴香 炒香。","（老油） 此刻放入 颗粒香料","放入 麦芽粉 炒散，放入 白酒 炒散。","起锅装入容器中，静置于温度低的环境(10-20) 5 天后再使用效果最佳。","起锅装入容器中放入 干辣椒面 搅匀置放 24 小时，等待制作 老油。","将底料倒入锅中，加入 3/5 的开水用大火烧开 （底料:2/5 开水:3/5）。","烧开后表面会出现泡沫，将泡沫撇净。","转用 中小火 慢熬出味（约 25-30 分钟），过滤去渣。","等待容器中 油水分离 后，将表面的 油 撇净（将油打出来） 装入另外的容器。","将上一步所 撇 出来的 油 重新倒入 净锅 中，直至 炼干 油中水分起锅装入容器即为 火锅老油。"]'::jsonb, '["半成品","麻辣","炒制","重庆","重油","自制底料"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_semi-finished_e6bd25880f.jpg', 'https://www.bilibili.com/video/BV16kskerE95', '{"energyKcal":520,"protein":3,"carbs":4,"fat":55}'::jsonb, '[null,300,null,15,null,null,null,432000,86400,null,null,1500,null,null]'::jsonb),
  ('howtocook:semi-finished/空气炸锅羊排/空气炸锅羊排', '空气炸锅羊排', '半成品', 3, 40, '这道菜做法超级懒人，用空气炸锅能逼出多余油脂，成品外焦里嫩、蒜香浓郁，风味主要取决于羊排本身品质。羊肉富含优质蛋白和铁、锌等微量元素，有助于温补气血、增强体质。烹饪难度适中，新手也能轻松上手，实际动手操作仅需 10 分钟，算上腌制总时长约 40 分钟就能端上餐桌。', '[{"name":"羊排","quantity":1,"unit":"片"},{"name":"黑椒混合牛排调味料","quantity":5,"unit":"克"},{"name":"蒜蓉酱","quantity":20,"unit":"克"},{"name":"黄油","quantity":1,"unit":"小盒"},{"name":"烧烤料","quantity":20,"unit":"克"},{"name":"罗勒碎","note":"适量"}]'::jsonb, '["羊排放入碗中清水洗净血水","羊排用厨房纸吸干水分，双面抹上黑椒混合调味料、蒜蓉酱，静置腌制 20 分钟","锡纸碗放上烤架，羊排放在烤架上，撒上罗勒碎，黄油或烧烤料放在羊排上，空气炸锅 180° 10 分钟","羊排翻面，撒上罗勒碎，黄油（从锡纸碗里舀上来）或烧烤料放在羊排上，空气炸锅 180° 5 分钟（可以视个人喜好加一点时间，这里写的是不会焦的时间）"]'::jsonb, '["半成品","空气炸锅","蒜香","黑椒","快手","家常","懒人"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_semi_finished_db06431821.jpg', 'https://www.bilibili.com/video/BV1Zj411S7PS', '{"energyKcal":420,"protein":28,"carbs":4,"fat":32}'::jsonb, '[null,1200,600,300]'::jsonb),
  ('howtocook:semi-finished/空气炸锅鸡翅中/空气炸锅鸡翅中', '空气炸锅鸡翅中', '半成品', 2, 40, '这是一道方便省事的家常快手菜，鸡翅外焦里嫩，自带油脂香气，比快餐店的更对胃口。鸡翅中富含优质蛋白和脂肪，能量充足。对新手非常友好，实际操作只需几分钟，全程大约四十分钟就能吃上。', '[{"name":"鸡翅中","quantity":6,"unit":"个"},{"name":"罗勒碎","note":"适量"},{"name":"云南单山蘸水","note":"适量"}]'::jsonb, '["鸡翅从冰箱拿出来，鸡翼面朝下放入锡纸烤盘，撒上罗勒碎，盖上保鲜膜自然解冻 20 分钟","撒上罗勒碎，空气炸锅 200°C，10 分钟","翻面，撒上罗勒碎，空气炸锅 200°C，7 分钟"]'::jsonb, '["半成品","快手","家常","奥尔良","鲜香","下酒"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_semi_finished_e79eaa4851.jpg', 'https://www.bilibili.com/video/BV16JqaBJExp', '{"energyKcal":530,"protein":45,"carbs":2,"fat":37}'::jsonb, '[1200,600,420]'::jsonb),
  ('howtocook:semi-finished/速冻水饺', '速冻水饺', '半成品', 1, 15, '这是一道源自中国的家常面食，采用市售冻饺速成，皮薄馅丰，口感鲜香。佐以醋、姜、蒜等蘸料，滋味更添层次。作为一餐，它能提供充足的蛋白质与碳水，营养饱腹。制作毫无难点，新手也能轻松上手，前后仅需大约一 刻钟。', '[{"name":"速冻水饺","quantity":7,"quantityMax":10,"unit":"个"},{"name":"水","note":"适量"},{"name":"醋","note":"适量"},{"name":"姜","note":"适量"},{"name":"蒜","note":"适量"}]'::jsonb, '["中火，将水倒入锅中，静候水煮沸。","将饺子倒入锅中。","倒入锅前可以适当用水过一下。","倒入饺子后，可以用炒菜勺子或铲子搅水，但要注意不要铲到饺子上，以避免粘锅上撕破皮或互相粘连造成粘连处夹生。","频率不需要太高，平均每 30 秒摇 3 秒，饺子浮起后不需要再做此步。","饺子浮起及水再次煮沸后，用炒菜勺子盛起一个饺子观察，如果面皮有夹生可用炒菜勺子舀入 80ml 凉水，将水降温，然后继续煮至沸腾，此间重复此观察、搅拌操作，最多加两次水就能全熟。","所有饺子浮起后（下饺子后约 8 分钟）用铲子或漏勺把饺子铲入盘或碗中，装盘后即可食用。","吃完饺子后，等锅内水温降低，将水倒掉并用洗洁精及时刷锅，不然过段时间锅内煮过的面粉会在锅壁形成黏糊糊的物质。"]'::jsonb, '["半成品","快手","家常","鲜香","煮制","饱腹"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_semi-finished_a139a678ec.jpg', 'https://www.bilibili.com/video/BV13s4y1U7sk', '{"energyKcal":300,"protein":12,"carbs":40,"fat":10}'::jsonb, '[null,null,null,null,3,null,480,null]'::jsonb),
  ('howtocook:semi-finished/速冻汤圆/速冻汤圆', '速冻汤圆', '半成品', 1, 6, '速冻汤圆是一道快速方便的微波炉甜点，外皮软糯、内馅香甜，属于中式传统小吃。主要提供碳水化合物，能迅速补充能量。做法极易上手，新手也能轻松完成，从准备到出锅仅需大约 6 分钟。', '[{"name":"速冻汤圆","quantity":11,"unit":"个"}]'::jsonb, '["取出速冻汤圆，放入碗中。","倒入开水，直至浸没汤圆。","微波炉高火 4 分钟。","假如汤圆均已吸水膨胀，则已熟。","如果没熟，再加热 1 分钟。"]'::jsonb, '["半成品","快手","微波","软糯","香甜","中式"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_semi_finished_b3d2344e33.jpg', 'https://www.bilibili.com/video/BV12A411b7oM', '{"energyKcal":550,"protein":8,"carbs":90,"fat":16}'::jsonb, '[null,null,240,null,60]'::jsonb),
  ('howtocook:semi-finished/速冻馄饨', '速冻馄饨', '半成品', 2, 55, '速冻馄饨皮薄馅嫩，汤清味鲜，是一道便捷的家常面食。主要提供碳水化合物和蛋白质，便于快速补充能量。做法简单，对新手非常友好，使用电饭煲即可完成，从烧水到出锅大约需要 55 分钟。', '[{"name":"速冻馄饨","quantity":12,"quantityMax":20,"unit":"个"},{"name":"水","quantity":600,"unit":"ml"},{"name":"盐","note":"无调料包时按口味适量"},{"name":"鸡精","note":"无调料包时按口味适量"},{"name":"胡椒粉","note":"无调料包时按口味适量"},{"name":"香油","note":"无调料包时按口味适量"},{"name":"香菜","quantity":5,"quantityMax":8,"unit":"片"}]'::jsonb, '["将水倒入电饭煲中，按炖或煮的模式运行 35 分钟，此时揭开电饭煲应看到水为沸腾状态。","将速冻馄饨小心放入水中，注意不要烫伤。","放入电饭煲前可以适当用水过一下。","如果馄饨有调料包，此时可一并加入水中。","盖上电饭煲，按同样炖或煮的模式运行 20 分钟。","将所有馄饨连同能没过所有馄饨的水一同盛入碗中。","如果此前没有加入调料包，此时可按自身口味轻重加入盐、鸡精、胡椒粉、香油调味。","也可撒上 5~8 片香菜叶佐味（仅适用于对香菜味道不敏感的人）。"]'::jsonb, '["半成品","家常","清淡","面食","煮","新手友好"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_semi-finished_f56195c804.jpg', 'https://www.bilibili.com/video/BV1og411j7Ca', '{"energyKcal":350,"protein":12,"carbs":55,"fat":10}'::jsonb, '[2100,null,null,null,1200,null,null,null]'::jsonb),
  ('howtocook:soup/勾芡香菇汤/勾芡香菇汤', '勾芡香菇汤', '汤羹', 3, 25, '香菇勾芡汤汤浓味鲜，滑润适口，是一道快手的家常汤品。香菇含有丰富的氨基酸和多糖，有助于增强免疫力。制作过程需要一些基本的控火和勾芡技巧，但对新手依然友好。从备料到出锅，大约只需 25 分钟。', '[{"name":"鲜香菇","quantity":2,"unit":"朵"},{"name":"香葱","quantity":0.5,"unit":"根"},{"name":"食用油","quantity":10,"unit":"ml"},{"name":"食用盐","quantity":3,"unit":"克"},{"name":"鸡精","quantity":3,"unit":"克"},{"name":"生粉","quantity":10,"unit":"克"},{"name":"开水","quantity":350,"unit":"ml"}]'::jsonb, '["香菇切片（每片厚度 0.5-1 cm,厚点相对薄点更有嚼劲），放入大碗中，倒入 2g 食用盐 浸泡 15 分钟","生粉倒入小碗中，加入 50ml 水，搅拌生粉直至融化没有颗粒（即水淀粉）","倒掉碗中的盐水，适当去掉香菇本身的水分（方便下一步煎炸）【可选】","小火，倒入油，待油开始冒小泡（小火 30s ，看每个锅的功率），倒入香菇，每面煎 10s 【可选】","倒入开水 300ml ，调中火再煮 3-5 分钟","倒入水淀粉，适当搅拌锅中汤汁后，加入 3g 盐、3 g ，最后撒上葱花出锅"]'::jsonb, '["汤羹","鲜香","清淡","快手","家常","勾芡"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_soup_33abca977c.jpeg', 'https://www.bilibili.com/video/BV1WQ4y1y7b5', '{"energyKcal":141,"protein":2.1,"carbs":10.9,"fat":9.2}'::jsonb, '[900,null,null,50,null,null]'::jsonb),
  ('howtocook:soup/奶油蘑菇汤', '奶油蘑菇汤', '汤羹', 1, 30, '这是一道经典法式浓汤，口感丝滑绵密，菌香与奶香交融。蘑菇富含膳食纤维和微量元素，牛奶则提供优质蛋白与钙质。做法非常简单，新手也能轻松驾驭，从备料到完成大约需要 30 分钟。', '[{"name":"白蘑菇","quantity":200,"unit":"克"},{"name":"洋葱","quantity":50,"unit":"克"},{"name":"黄油","quantity":15,"unit":"克"},{"name":"面粉","quantity":10,"unit":"克"},{"name":"牛奶","quantity":200,"unit":"毫升"},{"name":"淡奶油","quantity":30,"unit":"毫升"},{"name":"清水","quantity":100,"unit":"毫升"},{"name":"盐","quantity":2,"unit":"克"},{"name":"黑胡椒碎","quantity":1,"unit":"克"}]'::jsonb, '["白蘑菇切片备用，洋葱切末备用。","平底锅中放入黄油，小火融化后加入洋葱炒至透明。","加入白蘑菇翻炒至出水变软，撒入面粉搅拌均匀。","加入牛奶和清水，搅拌均匀后小火煮沸，保持搅拌防止糊底。","转小火煮约 10 分钟，汤汁浓稠。","倒入淡奶油继续加热 1 分钟，加入盐和黑胡椒调味。","熄火后可用料理机打成细腻浓汤（可选）。"]'::jsonb, '["汤羹","法式","奶香","煮制","快手","家常","鲜香"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_soup_c9e6b1e541.jpg', 'https://www.bilibili.com/video/BV19q4y1x7i2', '{"energyKcal":431,"protein":15.4,"carbs":28.7,"fat":31.5}'::jsonb, '[null,null,null,null,600,60,null]'::jsonb),
  ('howtocook:soup/小米粥', '小米粥', '汤羹', 2, 35, '小米粥是一道北方常见的家常粥品，口感绵滑，米香浓郁，熬出的米油尤其养胃。它富含蛋白质、脂肪、碳水化合物和胡萝卜素，维生素 B1 含量在粮食中名列前茅，容易消化吸收。做法非常简单，新手也能轻松掌握，从烧水到出锅大约需要 30-35 分钟。', '[{"name":"小米","quantity":100,"unit":"克"},{"name":"水（山泉水最佳）","quantity":2000,"unit":"克"}]'::jsonb, '["小米 100 克，放入碗中，用水轻淘一遍（用手搅拌一下，将水倒掉，只是去掉外面的浮灰，不可搓洗！！！）","水烧开，务必烧开！！！","水烧开沸腾时，将小米倒入锅内。（很容易被忽视的一个很重要的环节）","搅拌使得小米不会粘连锅底，继续用大火熬 6-10 分钟，注意用中间穿插搅拌几次。","改中火、文火熬 15-20 分钟，锅盖要错开一条缝，千万不能让小米油溜掉哟，中间继续搅拌几次，不要糊锅底"]'::jsonb, '["汤羹","清淡","鲜香","熬煮","北方","早餐","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_soup_8b874c67da.jpg', 'https://www.bilibili.com/video/BV19Y4y1t7QR', '{"energyKcal":90,"protein":2.3,"carbs":18.8,"fat":0.9}'::jsonb, '[null,null,null,360,900]'::jsonb),
  ('howtocook:soup/排骨山药玉米汤/排骨山药玉米汤', '排骨山药玉米汤', '汤羹', 2, 60, '排骨山药玉米汤清甜醇厚，山药软糯、玉米回甘，融合了排骨的鲜香，属于老少皆宜的家常汤品。它富含蛋白质、膳食纤维和多种维生素，有健脾益胃、增强抵抗力的作用。做法简单，预处理和炖煮步骤清晰，新手也能轻松上手，全程大约需要 1 小时即可完成。', '[{"name":"排骨","quantity":500,"unit":"g"},{"name":"山药","quantity":1,"unit":"根"},{"name":"胡萝卜","quantity":1,"unit":"根"},{"name":"玉米","quantity":1,"unit":"根"},{"name":"生姜","quantity":20,"unit":"g"},{"name":"小葱","quantity":15,"unit":"g"},{"name":"料酒","quantity":15,"unit":"ml"},{"name":"食用油","quantity":10,"unit":"ml"},{"name":"饮用水","quantity":1500,"quantityMax":2000,"unit":"ml"},{"name":"食盐","quantity":6,"quantityMax":8,"unit":"g"}]'::jsonb, '["食材预处理：","将胡萝卜洗净去皮，切成大约 3cm 的滚刀块。","玉米洗净，剁成大约 4cm 的圆柱状小块。","山药去皮（建议佩戴手套，防止粘液导致皮肤过敏），切成大约 4cm 的长段，备用。","排骨焯水：","锅中加入足量冷水，放入洗净的排骨。","加入大约 10g 姜片、葱结和 15ml 料酒。","大火煮沸，沸腾后等待 3 分钟，期间用勺子撇去表面浮沫。","捞出排骨，用大约 40℃ 的温水洗净杂质，沥干备用。","翻炒排骨：","热锅，倒入 10ml 食用油，等待 10 秒让油温升高。","放入剩余大约 10g 姜片爆香。","放入全部准备好的排骨，保持中火翻炒大约 1 分钟，至排骨表面微焦。","炖煮过程：","在锅中一次性加入 1500ml - 2000ml 饮用水。","放入全部准备好的胡萝卜、玉米和山药。","大火烧开后转小火，盖上锅盖，慢炖 40 分钟。","调味与出锅：","加入 6g - 8g 食盐，用勺子搅拌均匀。","保持小火继续炖煮 2 分钟使盐分入味。","关火，根据个人喜好撒入小葱末，盛盘。"]'::jsonb, '["汤羹","清淡","炖","家常","滋补"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_soup_19b1974de9.jpg', 'https://www.bilibili.com/video/BV1r54y1F7yB', '{"energyKcal":280,"protein":18,"carbs":18,"fat":16}'::jsonb, '[null,null,null,null,null,null,null,180,null,null,10,null,60,null,null,null,2400,null,null,120,null]'::jsonb),
  ('howtocook:soup/排骨苦瓜汤/排骨苦瓜汤', '排骨苦瓜汤', '汤羹', 4, 180, '排骨苦瓜汤是一道汤色清亮、鲜美回甘的粤式家常汤品，排骨软烂、苦瓜清热解腻。富含蛋白质与维生素，虾皮还能补充钙质。处理过程需要焯水去腥、仔细去除苦瓜瓤，对新手有一定挑战，但借助电压力锅可大幅简化；传统慢炖需 2 至 4 小时，建议提前 4 小时准备，压力锅则只需约 1 小时。', '[{"name":"排骨","quantity":250,"quantityMax":500,"unit":"克"},{"name":"苦瓜","quantity":100,"quantityMax":200,"unit":"克"},{"name":"虾皮","quantity":5,"quantityMax":15,"unit":"克"},{"name":"生姜","quantity":5,"quantityMax":10,"unit":"克"}]'::jsonb, '["排骨洗净，切到约 4cm ±2cm 3 ± 2cm 的小块（如没有剁排骨的工具，可以求助摊主）","炒锅倒入冷水 700ml 和排骨一起加热至煮沸，关火捞出排骨","苦瓜中间切为两半，清除干净内部的种子和苦瓜瓤，切为 0.5 ± 0.3 cm 的苦瓜条，洗净","汤锅倒入水 1100ml 和排骨，大火","等待水沸腾后将苦瓜和虾皮下锅转小火，放等待 120~240 分钟（在 120 分钟之后可以捞出一块肉进行品尝，若肉可以较为轻松的从骨头上分离即可关火）","出锅时加盐和白胡椒，推荐量为每 250ml 0.3 到 0.6g 盐，0.1 到 0.5g 白胡椒","倒入 1000ml 水和排骨，虾皮和苦瓜","选择炖汤功能，进行烹饪（一般为加压烹饪 45 分钟）","出锅，和汤锅一样进行加盐和胡椒"]'::jsonb, '["汤羹","粤式","家常","鲜香","清热","炖汤","补钙"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_soup_d3399a62bc.jpg', 'https://www.bilibili.com/video/BV1Gb4y1S7ts', '{"energyKcal":300,"protein":20,"carbs":3,"fat":19}'::jsonb, '[null,null,null,null,7200,null,null,2700,null]'::jsonb),
  ('howtocook:soup/昂刺鱼豆腐汤/昂刺鱼豆腐汤', '昂刺鱼豆腐汤', '汤羹', 3, 40, '昂刺鱼豆腐汤是一道口感鲜嫩、汤白味浓的家常汤品，鱼肉刺少肉嫩，豆腐滑润，带有胡椒的微辛暖意，适合各个年龄层。鱼富含优质蛋白质，搭配豆腐能补充钙质，营养均衡好吸收。制作过程不算复杂，只要注意去腥和煎鱼防粘，一般初学者也可以上手，预计制作时长约 40 分钟。', '[{"name":"昂刺鱼或者沙光鱼","quantity":1,"unit":"条"},{"name":"豆腐","quantity":100,"unit":"克"},{"name":"香葱","quantity":1,"unit":"根"},{"name":"姜","quantity":1,"unit":"块"},{"name":"食用油","quantity":15,"unit":"ml"},{"name":"料酒","quantity":5,"unit":"ml"},{"name":"食用盐","quantity":10,"quantityMax":15,"unit":"克"},{"name":"胡椒粉","quantity":3,"quantityMax":5,"unit":"克"},{"name":"开水","quantity":1,"unit":"L"}]'::jsonb, '["鱼处理好后洗净，（特别注意肚内的血丝、不洗干净会有腥味），放入大碗中，倒入料酒、10g 姜片、5g 盐，腌制 15 分钟","豆腐切块，放入凉水浸泡 5 分钟，捞出备用","煎鱼前，先用生姜片擦一下锅防止粘锅，倒入油（油量为 15ml 鱼的条数 ），烧热后放入鱼煎 2~3 分钟，期间需要晃动一下鱼，防止粘底，且需要翻一次身","待鱼全部煎好之后，倒入开水、5ml 料酒、姜片，小火转至大火，盖上锅盖、大火煮 10 分钟（水要稍微多一些，后面会蒸发掉一些）","见汤变白后倒入准备好的豆腐，调中火再煮 5 分钟，加入 10g 盐、3g 胡椒粉调味，最后撒上葱花出锅"]'::jsonb, '["汤羹","鲜香","炖煮","家常","补钙","暖胃"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_soup_e06bfee79c.jpg', 'https://www.bilibili.com/video/BV1sD4y1678j', '{"energyKcal":350,"protein":26,"carbs":3,"fat":22}'::jsonb, '[900,300,null,600,300]'::jsonb),
  ('howtocook:soup/朱雀汤/朱雀汤', '朱雀汤', '汤羹', 1, 8, '朱雀汤是一道豫东地区的家常快手汤品，口感顺滑香甜，带着芝麻油的醇香。鸡蛋提供优质蛋白质，制作非常简单，只需烧水冲蛋几步就能完成，前后不到十分钟即可上桌，还有清热去火的效果。', '[{"name":"鸡蛋","quantity":1,"unit":"只"},{"name":"香油（芝麻油）","quantity":2,"unit":"ml"},{"name":"白糖","quantity":20,"unit":"克"},{"name":"水","quantity":500,"unit":"ml"}]'::jsonb, '["鸡蛋在碗中打散，再倒入香油。","水烧开后，在沸腾状态下快速倒入盛有鸡蛋的碗中。","放入白糖。"]'::jsonb, '["汤羹","豫东","快手","香甜","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_soup_99cfef7656.jpg', 'https://www.bilibili.com/video/BV1Xw4m1R79i', '{"energyKcal":169,"protein":6,"carbs":20,"fat":7}'::jsonb, null),
  ('howtocook:soup/玉米排骨汤/玉米排骨汤', '玉米排骨汤', '汤羹', 3, 90, '玉米排骨汤是一道鲜美清甜的家常汤品，排骨软烂，玉米和胡萝卜带来自然甜味。富含蛋白质、维生素和膳食纤维，营养均衡。做法简单，对新手友好，只需将排骨焯水煸香后慢炖约一小时即可完成。从备菜到出锅大约需要一个半小时。', '[{"name":"排骨","quantity":500,"quantityMax":800,"unit":"g"},{"name":"玉米","quantity":1,"unit":"根"},{"name":"胡萝卜","quantity":1,"unit":"根"},{"name":"大葱","quantity":0.5,"unit":"根"},{"name":"香葱","quantity":1,"unit":"根"},{"name":"生姜","note":"适量"},{"name":"食用油","quantity":10,"unit":"ml"},{"name":"醋","quantity":10,"unit":"ml"},{"name":"料酒","quantity":10,"unit":"ml"},{"name":"黑胡椒粉","quantity":4,"unit":"g"},{"name":"食用盐","quantity":10,"quantityMax":15,"unit":"g"},{"name":"开水","quantity":1000,"unit":"ml"}]'::jsonb, '["大葱切成 3-4cm 的大段，用刀背拍一下","玉米剁成小块","胡箩卜切成滚刀块","生姜去皮切大片","新鲜的排骨砍成小块","排骨凉水下锅，放入大葱、生姜、料酒开始焯水，大火烧开，撇去浮沫，捞出排骨，沥干水分","热锅凉油，切大片的生姜和排骨一起下锅煸炒，待排骨表面微微焦黄，放入醋（可加速肉质软烂），继续煸炒一分钟","冲入开水，一次给足，之后就不要再加了，大火烧开","先下入玉米，放入胡椒粉，盖盖小火炖二十分钟，然后放入胡萝卜，盖盖继续小火炖四十分钟","调味很简单，出锅前三分钟，除了盐什么都不用放，最后撒上一把小葱花即可"]'::jsonb, '["汤羹","鲜香","炖汤","家常","营养均衡"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_soup_db4f01f926.jpeg', 'https://www.bilibili.com/video/BV1JA4y1f7zk', '{"energyKcal":400,"protein":30,"carbs":13,"fat":25}'::jsonb, '[null,null,null,null,null,null,60,null,3600,180]'::jsonb),
  ('howtocook:soup/生汆丸子汤', '生汆丸子汤', '汤羹', 4, 60, '生汆丸子汤口感鲜嫩弹滑，是一道原汁原味的家常汤品。猪肉提供优质蛋白质，搭配木耳、黄花等食材，营养较为均衡。制作中需要自己剁肉并掌握挤丸子的火候，稍有些门槛，更适合有一定基础的厨艺爱好者。从备料到上桌大约需要 1 小时。', '[{"name":"前腿肉","note":"适量"},{"name":"盐","note":"适量"},{"name":"胡椒粉","note":"适量"},{"name":"葱姜花椒水","note":"适量"},{"name":"鸡蛋清","quantity":1,"unit":"个"},{"name":"土豆淀粉","quantity":40,"unit":"克"},{"name":"熟豆油","note":"适量"},{"name":"木耳","note":"适量"},{"name":"黄花","note":"适量"},{"name":"小香葱","note":"适量"},{"name":"粉丝","note":"适量"},{"name":"鸡粉","note":"适量"},{"name":"香油","quantity":3,"quantityMax":5,"unit":"滴"},{"name":"香菜","quantity":1,"unit":"颗"}]'::jsonb, '["肉改刀切开，肥瘦三七分","上刀剁一剁，用刀背砸一砸，把肉筋打开打松疏","剁一剁，砸一砸，剁成肉末，要想好吃得自己剁，机器打的太黏糊了","每斤肉，6 克盐，1 克胡椒粉","上手抓匀","葱姜花椒水分次加，边加边搅，用手揉匀，让肉吸饱水。每斤肉末 80 克葱姜花椒水","放入鸡蛋清，继续顺着一个方向搅","加入 40 克土豆淀粉，搅匀","加入熟豆油，这是为了保持其嫩滑弹的状态","起锅烧水，烧开，改小火，似开非开的样子","上手，挤丸子，","全部漂起来，用小火煮 1 分钟","粉丝放碗底","加木耳，黄花，小香葱并用盐、胡椒粉、鸡粉打底调味","连汤带丸子冲如碗中","淋 3-5 滴香油","加一小颗香菜"]'::jsonb, '["汤羹","鲜香","清淡","汆烫","家常","营养均衡"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_soup_309223f8ce.jpg', 'https://www.bilibili.com/video/BV1Ga411C7zg', null, null),
  ('howtocook:soup/番茄牛肉蛋花汤', '番茄牛肉蛋花汤', '汤羹', 3, 30, '番茄牛肉蛋花汤是一道酸甜开胃的家常汤品，口感鲜嫩顺滑。牛肉富含优质蛋白和铁，番茄提供番茄红素和维生素 C，鸡蛋则补充卵磷脂。做法简单，新手也能轻松掌握，通常大约半 小时就能端上餐桌。', '[{"name":"牛肉","quantity":150,"unit":"克"},{"name":"番茄","quantity":1,"unit":"个"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"葱","note":"适量"},{"name":"姜","note":"适量"},{"name":"蒜","note":"适量"},{"name":"盐","quantity":2,"unit":"克"},{"name":"胡椒粉","quantity":0.5,"unit":"克"}]'::jsonb, '["牛肉切成薄片","番茄切成小块","葱切成葱花","姜切成姜片","蒜剁成蒜泥","牛肉放入碗中","加盐、胡椒粉腌制 15-20 分钟","加水煮开","加入姜片和牛肉片，煮至牛肉变色","加入番茄块，煮至番茄变软","打散鸡蛋液，缓慢地倒入锅中，用筷子搅拌形成蛋花","加入盐和胡椒粉调味","最后加入葱花，即可出锅"]'::jsonb, '["汤羹","酸甜","鲜香","煮","家常","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_soup_ba61b4adc7.jpg', 'https://www.bilibili.com/video/BV17D4y1D7Pb', '{"energyKcal":280,"protein":38,"carbs":5,"fat":11}'::jsonb, null),
  ('howtocook:soup/皮蛋瘦肉粥', '皮蛋瘦肉粥', '汤羹', 3, 90, '皮蛋瘦肉粥是广东经典的家常粥品，粥底绵密顺滑，皮蛋的醇香与瘦肉的鲜嫩融合，口感温润鲜美。它富含碳水化合物和优质蛋白质，搭配蔬菜，营养较为均衡，易于消化吸收。这道粥步骤虽多，但操作直观，新手跟着流程也能顺利完成，预计制作时长约 1.5 小时，借助电饭锅的预约或保温功能，作为早餐尤为方便。', '[{"name":"饮用水","quantity":1,"unit":"升"},{"name":"皮蛋（松花蛋）","quantity":2,"unit":"颗"},{"name":"瘦肉","quantity":100,"unit":"克"},{"name":"大米","quantity":150,"unit":"ml"},{"name":"小葱","quantity":1,"unit":"棵"},{"name":"香菜","quantity":1,"unit":"棵"},{"name":"生菜","quantity":4,"unit":"叶"},{"name":"生姜","quantity":1,"unit":"拇指块"},{"name":"酱油","quantity":5,"unit":"ml"},{"name":"蚝油","quantity":5,"unit":"ml"},{"name":"盐","quantity":2,"unit":"克"},{"name":"胡椒粉","quantity":1,"unit":"克"},{"name":"食用油","quantity":10,"unit":"ml"}]'::jsonb, '["大米 - 洗净 - 放入电饭锅内胆 - 加入 1 升 饮用水","瘦肉 - 洗净 - 简易晾去水分 - 加入 10ml 食用油 - 揉搓均匀 - 放入电饭锅内胆","皮蛋 - 去壳 - 洗净 - 对半切开 - 分离蛋白蛋黄 - 蛋白简单切碎块 - 蛋黄揉碎 - 放入电饭锅内胆","生姜 - 洗净 - 削皮 - 去除枯黄枯黑无法食用部分 - 切丝 - 放入电饭锅内胆","小葱 - 洗净 - 去除根部 - 去除枯黄枯黑无法食用部分 - 切碎 - 放入小碗备用","香菜 - 洗净 - 去除根部 - 去除枯黄枯黑无法食用部分 - 切碎 - 放入小碗备用","生菜 - 洗净 - 去除根部 - 去除枯黄枯黑无法食用部分 - 切碎 - 放入小碗备用","酱油 + 蚝油 + 盐 + 胡椒粉 - 搅拌均匀 - 放入小碗备用","主料 - 使用电饭锅煮粥模式煮熟","配料 - 待主料煮熟后，生菜单独过一次热水，并与其余配料一同开盖加入主料中搅拌均匀","酱料 - 待主料煮熟后，与其余配料一同开盖加入主料中搅拌均匀"]'::jsonb, '["汤羹","粤式","家常","早餐","鲜香"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_soup_07a2f77a14.jpg', 'https://www.bilibili.com/video/BV1FV4y1c77K', null, null),
  ('howtocook:soup/米粥', '米粥', '汤羹', 2, 25, '白粥清淡绵软，是家常必备的暖胃主食，米香纯粹，老少皆宜。富含碳水化合物和少量蛋白质，易于消化吸收，有补脾、和胃、清肺的食养之效。操作简单，只需掌握好火候和水量，初学者也能轻松完成，全程约需 25 分钟。', '[{"name":"米","quantity":60,"quantityMax":110,"unit":"ml"},{"name":"水","note":"适量"},{"name":"植物油","note":"可选，适量"}]'::jsonb, '["（可选）将 Mo ml 的油与洗净的米混合，尽量确保完全混合，即每粒米上至少都沾上少量油","（可选）将 米-油混合物品冷藏保存，冷藏时间 Tc。","将米和水加入锅中。","开大火，加热到 T1。","在 T1 之前将火关小。如果忘记此步骤，水可能会漫出而熄灭火焰。非常危险！","加热到 Tr。在 Tr 时关闭火源。"]'::jsonb, '["汤羹","清淡","暖胃","早餐","家常","快手","米香"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_soup_5f7d644c54.jpg', 'https://www.bilibili.com/video/BV1Yb4y167or', '{"energyKcal":250,"protein":5,"carbs":58,"fat":2}'::jsonb, null),
  ('howtocook:soup/紫菜蛋花汤', '紫菜蛋花汤', '汤羹', 2, 20, '紫菜蛋花汤是一道清淡鲜美的家常汤品，属于中式简易汤菜。紫菜富含碘、钙和膳食纤维，鸡蛋提供优质蛋白质，二者搭配营养均衡。做法非常简单，对新手友好，从准备到出锅仅需约 20 分钟。', '[{"name":"紫菜","quantity":10,"unit":"克"},{"name":"鸡蛋","quantity":2,"unit":"个"},{"name":"水","quantity":1.5,"unit":"升"},{"name":"盐","quantity":2,"unit":"克"},{"name":"油","quantity":5,"unit":"ml"},{"name":"香油","note":"几滴"},{"name":"葱花","note":"适量"},{"name":"虾仁","note":"适量"}]'::jsonb, '["干紫菜用清水泡 15 分钟，捞起沥干水份备用。","热锅，倒入 1.5 升清水、5ml 油、2g 盐。待水开后放入紫菜。","紫菜烧开后 3 分钟，将打好的蛋液徐徐倒入锅内，30 秒既可起锅。","撒上葱花，转小火 20 秒。","关火，出锅前放入几滴香油，也有的会放入一点虾皮，味道也不错。"]'::jsonb, '["汤羹","清淡","鲜香","快手","家常","煮"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_soup_bb60a69364.jpg', 'https://www.bilibili.com/video/BV1ct4y1H7sh', null, null),
  ('howtocook:soup/罗宋汤', '罗宋汤', '汤羹', 4, 150, '一道源自俄罗斯甜菜汤、在上海改良的海派家常汤品，以番茄和牛肉为主调，口感酸甜浓郁、醇厚鲜美。富含优质蛋白、番茄红素及多种维生素，营养均衡。制作简单，对初学者友好，全程预计 2–3 小时即可完成。', '[{"name":"牛肉","quantity":250,"unit":"g"},{"name":"牛肉高汤","quantity":500,"unit":"mL"},{"name":"番茄罐头","quantity":2,"unit":"罐"},{"name":"番茄膏","quantity":5,"unit":"g"},{"name":"马铃薯","quantity":400,"unit":"g"},{"name":"洋葱","quantity":100,"unit":"g"},{"name":"胡萝卜","quantity":100,"unit":"g"},{"name":"欧芹","quantity":100,"unit":"g"},{"name":"包菜","quantity":200,"unit":"g"},{"name":"红肠","quantity":100,"quantityMax":200,"unit":"g"},{"name":"橄榄油","quantity":5,"unit":"mL"},{"name":"植物油","quantity":5,"unit":"mL"},{"name":"盐","quantity":18,"unit":"g"},{"name":"黑胡椒","quantity":3,"unit":"g"},{"name":"蔬菜高汤（欧芹、胡萝卜、洋葱三件套）","note":"适量"}]'::jsonb, '["洋葱、胡萝卜、欧芹切 1cm 见方小丁","红肠、马铃薯切 2cm 块","包菜去梗后，手撕至 2cm 片","牛肉撒盐 3 g 、黑胡椒 3 g 腌制 5 分钟","平底锅烧热，加入植物油","煎制牛肉，直至表面焦黄色（可以带生，千万别糊了），取出备用。","汤锅烧热，加入橄榄油、洋葱丁、胡萝卜丁、欧芹丁","炒至洋葱透明，加入番茄膏、番茄罐头","加入牛肉、马铃薯丁，翻炒均匀","加水没过食材，中火烹制 1 小时","开锅加入包菜丁、红肠丁，搅拌均匀","中火烹制半小时","开盖加入剩余 15 g 盐，混合均匀后盛盘"]'::jsonb, '["汤羹","酸甜","炖汤","海派","家常","牛肉","开胃"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_soup_70b24ac660.jpg', 'https://www.bilibili.com/video/BV1e44y1W79X', '{"energyKcal":380,"protein":20,"carbs":35,"fat":15}'::jsonb, '[null,null,null,300,null,null,null,null,null,3600,null,1800,null]'::jsonb),
  ('howtocook:soup/羊肉汤/羊肉汤', '羊肉汤', '汤羹', 3, 30, '羊肉汤是一道家常暖身汤品，汤色乳白，肉质鲜嫩，带有大葱和白胡椒的清香与微辛。富含蛋白质、钙、铁等营养成分，有温补脾胃、抵御寒冷的功效。制作步骤简单，新手也能轻松掌握，整个烹饪过程大约需要 30 分钟。', '[{"name":"羊肉（或羊杂）","quantity":300,"unit":"克"},{"name":"食用油","quantity":10,"unit":"ml"},{"name":"料酒","quantity":20,"unit":"ml"},{"name":"大葱","quantity":50,"unit":"克"},{"name":"常温水","quantity":1000,"unit":"ml"},{"name":"开水","quantity":1000,"unit":"ml"},{"name":"白胡椒粉","quantity":1,"unit":"克"},{"name":"食用盐","quantity":5,"unit":"克"},{"name":"孜然粉（可选）","quantity":1,"unit":"克"},{"name":"香菜（可选）","quantity":20,"unit":"克"}]'::jsonb, '["羊肉切成长 5cm 宽 0.5cm 的块","大葱切成小段","羊肉放入锅中，加入 1000ml 常温水，加入料酒、大葱","煮沸 2 分钟后，捞出羊肉，使用常温水洗净，沥干水分","热锅加入食用油，加入羊肉，翻炒 2 分钟至羊肉表面微黄","加入开水，开到大火档位","5 分钟后，加入白胡椒粉、盐，继续煮沸 5 分钟","出锅之后，加入香菜、孜然粉，搅拌均匀"]'::jsonb, '["汤羹","鲜香","微辛","炖汤","家常","暖身"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_soup_12d8a23bfe.jpg', 'https://www.bilibili.com/video/BV1Ap421Q7WW', null, null),
  ('howtocook:soup/腊八粥', '腊八粥', '汤羹', 4, 180, '腊八粥是一道传统节令甜粥，粥体粘稠软糯，融合了多种谷物、豆类和干果的复合香气。富含碳水化合物、矿物质和多种维生素，莲子还有养心安神之效，适合工作压力大的人食用。虽然食材种类多，但操作简单，耐心慢熬即可，对新手友好。除去浸泡等准备时间，熬煮约需 3 小时。', '[{"name":"饮用水","quantity":1,"unit":"L"},{"name":"大米","quantity":50,"unit":"克"},{"name":"糯米","quantity":50,"unit":"克"},{"name":"花生","quantity":25,"unit":"克"},{"name":"红豆","quantity":25,"unit":"克"},{"name":"红枣","quantity":25,"unit":"克"},{"name":"薏米","quantity":50,"unit":"克"},{"name":"黑米","quantity":50,"unit":"克"},{"name":"小米","quantity":50,"unit":"克"},{"name":"莲子","quantity":25,"unit":"克"},{"name":"绿豆","quantity":25,"unit":"克"},{"name":"黄豆","quantity":25,"unit":"克"},{"name":"豌豆","quantity":25,"unit":"克"},{"name":"红腰豆","quantity":25,"unit":"克"},{"name":"桂圆（去种龙眼干）","quantity":25,"unit":"克"},{"name":"栗子","quantity":25,"unit":"克"},{"name":"去壳核桃","quantity":25,"unit":"克"},{"name":"葡萄干","quantity":25,"unit":"克"},{"name":"冰糖（或白糖，调味用）","quantity":10,"quantityMax":25,"unit":"克"}]'::jsonb, '["提前洗净好绿豆、红豆、花生、黄豆、豌豆、红腰豆，并用干净的玻璃碗盛放好，注入 3/4 玻璃碗大小的饮用水，浸泡一夜（或最少 8 小时）。","提前洗净好大米、糯米、薏米、黑米、小米、莲子，并用干净的玻璃碗盛放好，注入 3/4 玻璃碗大小的饮用水，浸泡 3 小时。","将步骤 1 中准备好的盛有绿豆、红豆、花生、黄豆、豌豆、红腰豆的玻璃碗中的水分分离倒出，其余原料倒入粥锅中，加入 1 升饮用水（或漫过食材 1 拇指块），大火煮沸，煮沸后合上锅盖，小火煮 30 分钟。","将步骤 2 中准备好的盛有大米、糯米、薏米、黑米、小米、莲子的玻璃碗中的水分分离倒出，其余原料继续倒入粥锅中，合上锅盖，小火煮 60 分钟。","洗净好红枣、桂圆、栗子、核桃、葡萄干（其中红枣切成小片）、冰糖，倒入锅中，合上锅盖，小火煮 60 分钟。","确认煮出的粥粘稠后即可关火、盛盘、食用。"]'::jsonb, '["汤羹","香甜","炖煮","传统","早餐","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_soup_72d3e3d08f.jpg', 'https://www.bilibili.com/video/BV1bZ4y1S7Ra', '{"energyKcal":300,"protein":9}'::jsonb, '[28800,10800,1800,3600,3600,null]'::jsonb),
  ('howtocook:soup/菌菇炖乳鸽/菌菇炖乳鸽', '菌菇炖乳鸽', '汤羹', 4, 45, '菌菇炖乳鸽汤色清亮、肉质细嫩，菌香与鸽鲜交融，属于家常粤式炖汤。乳鸽富含优质蛋白和多种氨基酸，菌菇提供多糖与膳食纤维，温和滋补。整道菜需先将乳鸽焯水去腥，再与玉米、菌菇同炖，对火候和时间的把控略有一些要求，新手稍加注意也能驾驭。从备料到出锅，使用高压锅约需 45 分钟，瓦罐慢炖则需 1 小时出头。', '[{"name":"乳鸽","quantity":300,"unit":"克"},{"name":"菌菇","quantity":100,"unit":"克"},{"name":"玉米","quantity":200,"unit":"克"},{"name":"姜","quantity":30,"unit":"克"},{"name":"料酒","quantity":15,"unit":"ml"},{"name":"食用盐","quantity":10,"unit":"克"}]'::jsonb, '["冷水洗干净热心摊主处理好的乳鸽","冷水锅中放入洗干净的乳鸽，加入 15ml 料酒与姜，水煮开即可捞出乳鸽，要不然会丢失营养","把乳鸽放到高压缩或者瓦罐中、倒入的水要没过乳鸽，放入生姜 20 g，玉米 200 g、菌菇 100 g","时间到了，盛到碗中，加入 3~5g 盐 即可"]'::jsonb, '["汤羹","鲜香","清淡","炖","粤式","家常","滋补"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_soup_d7a167745a.jpg', 'https://www.bilibili.com/video/BV1yM4y1T7zw', '{"energyKcal":250,"protein":18,"carbs":12,"fat":12}'::jsonb, null),
  ('howtocook:soup/西红柿鸡蛋汤', '西红柿鸡蛋汤', '汤羹', 2, 15, '西红柿鸡蛋汤是一道酸甜开胃、口感滑嫩的家常汤品，做法极简，属于老少皆宜的大众菜肴。富含番茄红素、维生素 C 和优质蛋白质，营养均衡易吸收。对新手非常友好，快手省时，预计制作时长 大约 15 分钟。', '[{"name":"西红柿","quantity":1,"unit":"个"},{"name":"鸡蛋","quantity":1,"quantityMax":2,"unit":"个"},{"name":"香油","quantity":2,"unit":"滴"},{"name":"味素","quantity":5,"unit":"克"},{"name":"盐","quantity":15,"unit":"克"},{"name":"葱、姜、蒜","quantity":15,"unit":"克"}]'::jsonb, '["将西红柿洗净，切块。","葱姜蒜切碎。","鸡蛋打到碗中，用筷子（或打蛋器）搅拌均匀。","热锅，并放入 15 毫升的油，待能从油中看到冒出一丝烟时，放入葱姜蒜翻炒 30 秒。","放入西红柿翻炒 1 分钟。","倒入水，水的高度大约为锅内菜品高度的 1.2 倍，并放入盐。","待开锅后，将鸡蛋液放入，并用筷子将鸡蛋打散，放入味素和香油。","等待 30 秒，关火出锅。"]'::jsonb, '["汤羹","酸甜","快手","家常","开胃","汤品"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_soup_d79f8d9b1f.jpg', 'https://www.bilibili.com/video/BV1V34y1J7pi', '{"energyKcal":235,"protein":7,"carbs":6,"fat":20}'::jsonb, '[null,null,null,30,60,null,null,30]'::jsonb),
  ('howtocook:soup/金针菇汤', '金针菇汤', '汤羹', 2, 10, '这是一道清淡爽口的家常汤品，口味鲜美，属简易快手菜。金针菇含有丰富的氨基酸和膳食纤维，加鸡蛋还能补充优质蛋白。制作门槛极低，新手也能轻松驾驭，从备菜到出锅大约只需 10 分钟。', '[{"name":"金针菇","quantity":400,"quantityMax":500,"unit":"克"},{"name":"鸡蛋","note":"适量（如需要）"},{"name":"食盐","quantity":15,"unit":"克"},{"name":"味精","quantity":5,"unit":"克"}]'::jsonb, '["金针菇徒手掰散，越散越好不然容易藏牙，洗净备用。","用菜刀或者水果刀将上述金针菇段段切，可依据个人喜好，但长度不宜超过 5 cm。","将金针菇放入锅中，加水没过约食材总高度 1.1 倍，沸腾后等待 3 分钟。","加入味精和食盐并搅拌。","继续加热约 30 秒，关火装盘。"]'::jsonb, '["汤羹","清淡","快手","家常","鲜香"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_soup_2c03f4d3d9.jpg', 'https://www.bilibili.com/video/BV1Ja4y177vv', '{"energyKcal":165,"protein":10,"carbs":18,"fat":2}'::jsonb, '[null,null,180,null,30]'::jsonb),
  ('howtocook:soup/银耳莲子粥/银耳莲子粥', '银耳莲子粥', '汤羹', 4, 210, '银耳莲子粥清甜润滑，银耳软糯、莲子绵密，是常见的滋补粥品。富含天然胶质、膳食纤维及多种微量元素，有助养心安神。制作需经历浸泡和慢熬，对新手的耐心是个考验，全程大约需要 3.5 小时。', '[{"name":"银耳","quantity":60,"unit":"克"},{"name":"去心莲子","quantity":20,"unit":"克"},{"name":"红枣","quantity":6,"unit":"克"},{"name":"枸杞","quantity":5,"quantityMax":6,"unit":"克"},{"name":"冰糖","quantity":10,"quantityMax":20,"unit":"克"}]'::jsonb, '["把银耳、莲子用清水浸泡 2 个小时，红枣浸泡 10 - 20 分钟，枸杞洗净，备用","在锅中倒入 600ml 水，烧开后依次放入银耳、莲子、红枣","等待水再次烧开后，盖上锅盖，转至中火继续熬","熬到大约 1 小时后，放入 5g - 10g 冰糖和 5g - 6g 枸杞，转至小火熬","小火继续熬 30 分钟，此时银耳开始呈现粘稠状态","再次放入 5g - 10g 冰糖，用勺子搅拌 5 - 10 分钟","关火，用勺子盛出"]'::jsonb, '["汤羹","清甜","滋补","慢炖","家常","养生"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_soup_1850c8eed8.png', 'https://www.bilibili.com/video/BV197411T7EN', '{"energyKcal":160,"protein":5,"carbs":38,"fat":1}'::jsonb, '[7200,null,null,3600,1800,300,null]'::jsonb),
  ('howtocook:soup/陈皮排骨汤', '陈皮排骨汤', '汤羹', 4, 60, '一道清润滋补的广式炖汤，汤色清亮，入口甘醇，带有陈皮的独特清香。排骨提供优质蛋白，搭配西洋参、石斛等食材，能润肺健脾、生津止渴，适合经常熬夜的人群。制作难度中等，只需要将材料处理好放进炖盅，慢炖约两小时即可完成。', '[{"name":"排骨","quantity":4,"quantityMax":5,"unit":"块"},{"name":"陈皮","quantity":1,"unit":"瓣"},{"name":"西洋参","quantity":9,"unit":"片"},{"name":"石斛","quantity":6,"unit":"颗"},{"name":"玉竹","quantity":5,"unit":"片"},{"name":"麦冬","quantity":7,"unit":"个"},{"name":"食盐","quantity":5,"unit":"克"}]'::jsonb, '["排骨用热水过一边，去血水","陈皮、麦冬、玉竹、石斛和西洋参，冲洗干净即可","煲汤盅洗干净","打开煲汤盅，先放入排骨在底部，然后依次放入陈皮、麦冬、玉竹、石斛和西洋参","加入热水进煲汤盅，水不宜太满","煲汤容器加入水，炖煮 1.5 小时即可","加入食盐，趁热饮用"]'::jsonb, '["汤羹"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_soup_d5f399eff0.jpg', 'https://www.bilibili.com/video/BV1hf4y1k7cu', '{"energyKcal":260,"protein":19,"carbs":2,"fat":22}'::jsonb, '[null,null,null,null,null,5400,null]'::jsonb),
  ('howtocook:soup/陈皮排骨汤/陈皮排骨汤', '陈皮排骨汤', '汤羹', 3, 120, '这道汤品属于粤式老火靓汤，汤色清亮，入口甘润回香，带有陈皮的独特陈韵。排骨提供优质蛋白质和钙质，搭配陈皮、西洋参、石斛等食材，有助于理气健脾、滋阴润肺，适合长期熬夜或咽喉不适时饮用。整体操作不难，只需备好料、掌握炖煮时间，新手也能轻松完成。从备菜到出锅大约需要两小时。', '[{"name":"排骨","quantity":4,"quantityMax":5,"unit":"块"},{"name":"陈皮","quantity":1,"unit":"瓣"},{"name":"西洋参","quantity":9,"unit":"片"},{"name":"石斛","quantity":6,"unit":"颗"},{"name":"玉竹","quantity":5,"unit":"片"},{"name":"麦冬","quantity":7,"unit":"个"},{"name":"盐","quantity":5,"unit":"克"}]'::jsonb, '["排骨用热水过一边，去血水","陈皮、麦冬、玉竹、石斛和西洋参，冲洗干净即可","煲汤盅洗干净","打开煲汤盅，先放入排骨在底部，然后依次放入陈皮、麦冬、玉竹、石斛和西洋参","加入热水进煲汤盅，水不宜太满","煲汤容器加入水，炖煮 1.5 小时即可","加入食盐，趁热饮用"]'::jsonb, '["汤羹","粤式","炖汤","滋补","甘润","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_soup_fcf185db3e.jpg', 'https://www.bilibili.com/video/BV1ur421p7u5', null, null),
  ('howtocook:soup/黄瓜皮蛋汤', '黄瓜皮蛋汤', '汤羹', 2, 10, '黄瓜皮蛋汤是一道快手家常汤品，口味清淡，带着皮蛋与蒜瓣煸炒出的焦香，暖心暖胃且不油腻。黄瓜清热补水，皮蛋提供一定蛋白质，低脂少负担。做法几乎没有技术门槛，厨房新手也能轻松完成，从备料到出锅只需大约十 分钟。', '[{"name":"黄瓜","quantity":1,"unit":"根"},{"name":"皮蛋","quantity":2,"unit":"个"},{"name":"大蒜","quantity":2,"unit":"瓣"},{"name":"小葱","note":"适量"},{"name":"食用油（推荐猪油）","quantity":10,"quantityMax":15,"unit":"g"},{"name":"盐","quantity":2,"quantityMax":3,"unit":"g"},{"name":"鸡精（可选）","quantity":0.5,"quantityMax":1,"unit":"g"},{"name":"水","quantity":400,"quantityMax":500,"unit":"ml"}]'::jsonb, '["黄瓜洗净，切成 0.5-1.2 mm 厚的薄片","葱洗净切成末，蒜用刀拍几下去皮，对半切一下","皮蛋剥去壳，然后每个切成 6-8 份。锅里倒入油，放入切好的皮蛋和大蒜","小火炒至皮蛋和大蒜表面有些焦黄，加入水，转大火烧开","放入黄瓜片。水再次沸腾以后立马关火，放入盐、鸡精调味即可出锅","装入碗中，再撒上葱花即可"]'::jsonb, '["汤羹","清淡","鲜香","快手","家常","低脂"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_soup_9eb28fdbd5.jpg', 'https://www.bilibili.com/video/BV1JJ4m1T7kJ', '{"energyKcal":330,"protein":17.2}'::jsonb, null),
  ('howtocook:staple/中式馅饼/中式馅饼', '中式馅饼', '主食', 4, 55, '这道饼外皮微脆内里松软，馅料咸香，属于家常面食。富含碳水化合物和蛋白质，搭配胡萝卜和鸡蛋更添营养。制作难度中等，新手需掌握火候，但步骤明确易上手。从备料到完成大约需要 1 小时。', '[{"name":"面粉","quantity":200,"unit":"克"},{"name":"肉沫","quantity":50,"unit":"克"},{"name":"油","quantity":30,"unit":"ml"},{"name":"盐","quantity":3,"unit":"克"},{"name":"糖","quantity":5,"unit":"克"},{"name":"生粉","quantity":10,"unit":"克"},{"name":"酱油","quantity":5,"unit":"克"},{"name":"风味调料","quantity":3,"unit":"克"},{"name":"蒜头","quantity":2,"unit":"瓣"},{"name":"大葱","quantity":0.25,"unit":"根"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"胡萝卜","note":"适量"}]'::jsonb, '["取肉沫（解冻），加入 1/2 所有上述调料（油、盐、糖、酱油、风味调料）和全部的生粉，搅拌均匀，腌制 30 分钟。","将面粉加入碗中，加入鸡蛋，加入剩下 1/2 所有上述调料，加入相当于面粉 1/2 的水（使得面粉相对粘稠但可以流动），搅拌均匀。","蒜头切为蒜末。","大葱切段。","胡萝卜切末（作为馅料用，所以要求尽量细碎，可用乱刀）","热锅冷油，宽油起锅。","待油烧热后，放入蒜末爆香。","加入腌制的肉沫，翻炒，直至断生。","将胡萝卜末加入肉沫中一同翻炒，直至油被染为金黄色（这是为了萃取胡萝卜的风味）。","关火。冷却 2 分钟。","将炒好的肉沫倒入生面糊中，搅匀。","重新开火，平底锅铺底油。","调至小火，将面糊倒入锅中均匀铺满。保证厚度不要过高。可以端起锅，让面糊流过锅底来完成这一操作。","在饼的表面尚为液态时，撒上大葱段。","保持小火，直到底面凝固。","将饼翻面，继续小火煎烤，直至另一侧凝固。","之后，每一面再额外煎 20 秒。","关火出锅。"]'::jsonb, '["主食","咸香","煎烤","家常","面食","早餐"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_1aa8596b79.jpg', 'https://www.bilibili.com/video/BV1Fq4y1Q7eJ', '{"energyKcal":1250,"protein":34,"carbs":170,"fat":47}'::jsonb, '[1800,null,null,null,null,null,null,null,null,120,null,null,null,null,null,null,20,null]'::jsonb),
  ('howtocook:staple/凉粉/凉粉', '凉粉', '主食', 3, 210, '凉粉是一道源自四川的传统小吃，口感冰凉爽滑，酸辣开胃，很适合夏天消暑。主要原料是豌豆淀粉，富含碳水化合物，能为身体快速补充能量。制作过程不算复杂，但需要耐心搅煮和长时间冷藏定型，对新手来说难度适中。从煮制到完成大约需要 3-4 小时，其中大部分是等待冷藏的时间，动手操作只需大约半 小时。', '[{"name":"豌豆淀粉","quantity":100,"unit":"克"},{"name":"大蒜","quantity":3,"unit":"瓣"},{"name":"小米辣","quantity":3,"unit":"颗"},{"name":"辣椒粉","quantity":10,"unit":"克"},{"name":"酱油","quantity":10,"unit":"ml"},{"name":"醋","quantity":10,"unit":"ml"},{"name":"白糖","quantity":3,"unit":"ml"},{"name":"鸡精","quantity":3,"unit":"克"},{"name":"盐","quantity":3,"unit":"克"},{"name":"花生碎","quantity":5,"unit":"克"},{"name":"香菜","quantity":5,"unit":"克"}]'::jsonb, '["准备食材。","把豌豆淀粉和水各 100 克混合搅拌。","往锅中倒入 600g 水，大火煮开后转为小火。","倒入淀粉水，边倒边不断的搅拌，搅拌到浓稠且色泽均匀。","找一个容器，在容器中刷一层薄薄的食用油。","将煮好的淀粉倒入容器中冷藏 2-4 小时。","冷藏后取出，脱模，切条。","大蒜和小米辣剁成沫，放上 10g 辣椒粉，5g 花生碎，热油搅拌均匀。","再加入 10ml 酱油，10ml 醋，5g 白糖，3g 鸡精，3g 盐搅拌均匀。","将调味料倒在凉粉上，然后撒上香菜即可。"]'::jsonb, '["主食","川菜","酸辣","凉拌","解暑","传统小吃"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_ef59ff9806.jpg', 'https://www.bilibili.com/video/BV1xR4y1F7Ji', '{"energyKcal":380,"protein":3,"carbs":82,"fat":7}'::jsonb, null),
  ('howtocook:staple/利提巧卡', '利提巧卡', '主食', 5, 60, '利提巧卡是印度比哈尔邦的传统主食，由烤得金黄的麦球和烟熏风味的蔬菜泥组成，口感外脆内软，香气浓郁。烤鹰嘴豆粉馅料富含植物蛋白和膳食纤维，搭配茄子、番茄、土豆等蔬菜，营养丰富。制作需要和面、包馅、烤制以及处理蔬菜，步骤较多，对新手有一定挑战，全程大约需要 60 分钟完成。', '[{"name":"全麦面粉（Atta）","quantity":200,"unit":"克"},{"name":"烤鹰嘴豆粉（Sattu，可用炒熟的鹰嘴豆磨粉替代）","quantity":120,"unit":"克"},{"name":"茄子","quantity":1,"unit":"个"},{"name":"番茄","quantity":2,"unit":"个"},{"name":"土豆","quantity":2,"unit":"个"},{"name":"洋葱","quantity":1,"unit":"个"},{"name":"大蒜","quantity":4,"unit":"瓣"},{"name":"生姜","quantity":5,"unit":"克"},{"name":"青辣椒","quantity":2,"unit":"根"},{"name":"青辣椒","quantity":1,"unit":"根"},{"name":"柠檬汁","quantity":10,"unit":"ml"},{"name":"香菜","quantity":10,"unit":"克"},{"name":"香菜","quantity":10,"unit":"克"},{"name":"芥末油（Mustard oil，可用其他食用油替代）","quantity":15,"unit":"ml"},{"name":"芥末油（Mustard oil，可用其他食用油替代）","quantity":15,"unit":"ml"},{"name":"孜然籽","quantity":3,"unit":"克"},{"name":"印度黑盐（Kala Namak，可用普通盐替代）","quantity":3,"unit":"克"},{"name":"红辣椒粉","quantity":3,"unit":"克"},{"name":"芝麻","quantity":5,"unit":"克"},{"name":"酥油（Ghee）","quantity":30,"unit":"克"},{"name":"盐","quantity":3,"unit":"克"},{"name":"盐","quantity":4,"unit":"克"}]'::jsonb, '["在碗中混合烤鹰嘴豆粉 120g、切碎的洋葱、青辣椒、生姜","加入孜然籽 3g、芝麻 5g、红辣椒粉 3g、印度黑盐 3g、盐 3g","加入芥末油 15ml、柠檬汁 10ml、切碎的香菜叶","充分混合均匀，馅料应呈松散但可捏合的状态，备用","将全麦面粉 200g 放入大碗中","逐渐加入温水，边加边揉，揉成光滑柔软的面团","面团静置 15 分钟","将面团分成 8 个等大的小剂子","每个剂子用手压成一个直径约 8cm 的圆形面片（中间稍厚）","在面片中央放入约 15g 馅料","将面片四周收拢包住馅料，封口处捏紧，搓成圆球","烤箱预热至 200°C","将利提放在烤盘上，烤 25-30 分钟，期间翻面一次，直至表面金棕色且有裂纹","如果使用明火：将利提直接放在炭火或煤气灶小火上烤，不断翻转，直至均匀焦黄","烤好后趁热将每个利提表面涂上酥油，使其浸润吸收","将茄子、番茄、土豆放在明火上直接烤，或放入 200°C 烤箱烤 20-25 分钟，直至外皮焦黑、内部完全软烂","烤好后去皮，将茄子、番茄、土豆分别用叉子或手捣碎","将捣碎的蔬菜混合在一起","加入切碎的大蒜、青辣椒、盐 4g、芥末油 15ml","充分搅拌混合均匀","撒上香菜叶装饰","将利提摆盘，旁边放上巧卡蔬菜泥","趁热食用，用手掰开利提蘸巧卡"]'::jsonb, '["主食","印度主食","鲜香","香辣","烤制","包馅","传统"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_cd918e9009.jpg', 'https://www.bilibili.com/video/BV1gZ4y1G7Wo', '{"energyKcal":240,"protein":7.5,"carbs":34,"fat":9.5}'::jsonb, '[null,null,null,null,null,null,900,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:staple/印度烤饼', '印度烤饼', '主食', 3, 90, '这是一道印度风味的发酵烤饼，外表微焦酥脆，内部松软有嚼劲，是咖喱的绝佳搭档。富含碳水化合物和蛋白质，酸奶的加入也让面饼更易消化。制作稍有难度，需注意面团软硬和火候，但平底锅即可操作，提前 1 小时发酵，总耗时约 1.5 小时。', '[{"name":"中筋面粉","quantity":300,"unit":"克"},{"name":"酸奶","quantity":60,"unit":"ml"},{"name":"干酵母","quantity":3,"unit":"克"},{"name":"糖","quantity":10,"unit":"克"},{"name":"盐","quantity":5,"unit":"克"},{"name":"食用油","quantity":15,"unit":"ml"},{"name":"温水","quantity":100,"unit":"ml"},{"name":"酥油或黄油","quantity":30,"unit":"克"},{"name":"黑芝麻","quantity":5,"unit":"克"},{"name":"香菜叶","quantity":10,"unit":"克"},{"name":"大蒜","quantity":3,"unit":"瓣"}]'::jsonb, '["将干酵母 3g 和糖 10g 溶解在 100ml 温水中（水温约 40°C，不可过烫）","静置 5 分钟，直至表面冒出细泡沫（说明酵母已激活）","在大碗中放入中筋面粉 300g 和盐 5g，混合均匀","倒入酵母水、酸奶 60ml 和食用油 15ml","用手揉成光滑柔软的面团（面团应比普通面团稍软，微微粘手是正常的）","揉面 8-10 分钟","在面团表面涂 3ml 油防止干裂","用湿布或保鲜膜盖住碗口","放置在温暖处发酵 至少 1 小时，直至面团膨胀至约两倍大","将发酵好的面团取出，轻揉排气","分成 6 个等大的小剂子（每个约 80g）","取一个剂子，手上沾 3ml 面粉或油","用擀面杖擀成长椭圆形或泪滴形面饼，厚度约 4-5mm","如果制作蒜蓉烤饼：在面饼表面撒上切碎的大蒜和香菜叶，轻轻擀压使其嵌入面饼","可在面饼表面撒上芝麻","将平底锅（铸铁锅最佳）大火加热至非常烫（滴水立即蒸发的程度）","在面饼一面刷一层薄薄的水","将刷水一面朝下放入锅中","烤 1-2 分钟，直至底面出现金棕色斑点且面饼开始鼓泡","翻面，继续烤 1-2 分钟","如果有煤气灶：翻面后可用夹子夹起面饼，将其直接放在明火上烤 数秒钟，面饼会迅速鼓起","取出后立即在表面涂上酥油或黄油","烤箱预热至最高温度（通常 250°C）","将面饼放在烤盘上","烤 3-5 分钟，直至表面金黄且鼓起","取出后涂上酥油或黄油","趁热食用","适合搭配任何印度咖喱，如黄油鸡、红芸豆咖喱等"]'::jsonb, '["主食","印度","烤饼","发酵","佐咖喱","香酥","奶香"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_4757bdde93.jpg', 'https://www.bilibili.com/video/BV1SJ41127Nj', '{"energyKcal":280,"protein":7,"carbs":45,"fat":9}'::jsonb, '[null,300,null,null,null,null,null,null,3600,null,null,null,null,null,null,null,null,null,90,90,null,null,null,null,240,null,null,null]'::jsonb),
  ('howtocook:staple/印度焖饭', '印度焖饭', '主食', 5, 90, '印度焖饭是源自莫卧儿帝国时期的皇家料理，米粒细长、香料气息浓郁，鸡肉嫩滑、米饭粒粒分明，层次丰富。富含蛋白质和多种香料精华，能提振食欲。制作步骤较繁琐，对新手不太友好，全程约需 90 分钟（鸡肉需提前腌制 1 小时）。', '[{"name":"巴斯马蒂长粒香米（Basmati Rice）","quantity":300,"unit":"克"},{"name":"鸡腿肉（去骨，可用羊肉替代）","quantity":500,"unit":"克"},{"name":"酸奶","quantity":100,"unit":"ml"},{"name":"番茄","note":"适量"},{"name":"生姜（磨碎）","quantity":15,"unit":"克"},{"name":"大蒜（磨碎）","quantity":6,"unit":"瓣"},{"name":"青辣椒（切缝）","quantity":3,"unit":"根"},{"name":"香菜叶","quantity":20,"unit":"克"},{"name":"薄荷叶","quantity":20,"unit":"克"},{"name":"藏红花（Saffron，可用食用黄色素替代）","quantity":0.5,"unit":"克"},{"name":"温牛奶","quantity":30,"unit":"ml"},{"name":"酥油（Ghee）","quantity":30,"unit":"克"},{"name":"食用油","quantity":50,"unit":"ml"},{"name":"姜黄粉","quantity":3,"unit":"克"},{"name":"红辣椒粉","quantity":5,"unit":"克"},{"name":"印度综合香料粉（Garam Masala）","quantity":5,"unit":"克"},{"name":"盐（腌肉用）","quantity":5,"unit":"克"},{"name":"盐（煮米用）","quantity":10,"unit":"克"},{"name":"月桂叶","quantity":2,"unit":"片"},{"name":"肉桂棒（约5cm）","quantity":1,"unit":"根"},{"name":"小豆蔻","quantity":3,"unit":"颗"},{"name":"丁香","quantity":4,"unit":"颗"},{"name":"八角","quantity":1,"unit":"颗"},{"name":"柠檬汁","quantity":15,"unit":"ml"},{"name":"洋葱（切薄片）","quantity":3,"unit":"个"}]'::jsonb, '["在大碗中混合酸奶、磨碎的生姜和大蒜、红辣椒粉、姜黄粉、印度综合香料粉、盐、柠檬汁","放入鸡肉块，均匀裹上腌料","盖保鲜膜，冷藏腌制至少 1 小时（过夜更佳）","将藏红花 0.5g 放入 30ml 温牛奶中浸泡 15 分钟，备用","在锅中倒入 50ml 食用油，中火加热","放入洋葱薄片，翻炒至深金棕色且酥脆（约 12-15 分钟，需耐心）","捞出炸洋葱，用厨房纸吸油，备用","将浸泡好的巴斯马蒂香米沥干","在大锅中烧开 2000ml 水","加入月桂叶、小豆蔻、丁香、肉桂棒、八角和盐 10g","放入米饭，大火煮 5-6 分钟，直至米粒约七成熟（外部软、芯部仍有硬度）","立即沥干，丢弃全香料，备用","在厚底锅底部涂抹酥油 15g","第一层：将腌制好的鸡肉均匀铺在锅底","第二层：铺上一半的半熟米饭","撒上一半的炸洋葱、薄荷叶、香菜叶、青辣椒","第三层：铺上剩余的米饭","撒上剩余的炸洋葱、薄荷叶、香菜叶","将藏红花牛奶均匀淋在最上层米饭表面","放上剩余的酥油 15g（切小块散放）","密封锅盖：用面粉加水和成面团条，沿锅口边缘封住缝隙（传统方法），或用锡纸包裹锅口再盖锅盖","先用大火加热 3 分钟，直至锅内开始冒蒸汽","然后转最小火，焖 25-30 分钟","关火后不要开盖，再焖 5 分钟","开盖，用大铲子从底部轻轻翻拌，使各层混合均匀","盛盘，搭配酸奶(Raita)食用"]'::jsonb, '["主食","鲜香","焖饭","印度","浓郁","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_280d08a18d.jpg', 'https://www.bilibili.com/video/BV1ot41137oc', '{"energyKcal":700,"protein":30}'::jsonb, '[null,null,3600,900,null,900,null,null,null,null,360,null,null,null,null,null,null,null,null,null,null,180,1800,300,null,null]'::jsonb),
  ('howtocook:staple/可乐炒饭', '可乐炒饭', '主食', 3, 20, '这道菜以可乐替代糖调味，带来独特的焦香微甜风味，酱汁浓郁包裹粒粒米饭，属于创意家常炒饭。鸡蛋和火腿肠提供优质蛋白质与能量，搭配主食米饭，营养均衡管饱。操作步骤直观，适合新手尝试，一般 大约 20 分钟便可端上桌。', '[{"name":"米饭","quantity":200,"unit":"克"},{"name":"可乐","quantity":160,"unit":"ml"},{"name":"鸡蛋","quantity":3,"unit":"个"},{"name":"火腿肠","quantity":20,"quantityMax":100,"unit":"克"},{"name":"午餐肉","note":"适量（可选）"},{"name":"油","quantity":25,"unit":"ml"},{"name":"生抽","quantity":15,"unit":"ml"},{"name":"老抽","quantity":7.5,"unit":"ml"},{"name":"豆瓣酱","quantity":7.5,"unit":"ml"},{"name":"蚝油","quantity":5,"unit":"ml"},{"name":"葱花","quantity":5,"unit":"克"},{"name":"胡椒粉","quantity":1,"unit":"克"}]'::jsonb, '["将锅烧热后，加入 25 ml 油，放两个鸡蛋，煎至底部完全凝固","翻面，煎至两面完全凝固","关火，将鸡蛋取出，剪成 2-5 cm² 的小块后放回锅中（也可以直接用锅铲铲碎）","重新开火，倒入可乐、生抽、老抽、豆瓣酱、蚝油，搅拌均匀","加热到锅内液体剩 1/3，倒入米饭和火腿肠翻炒","翻炒均匀后，改小火，锅内食物中心挖一个洞，打入 1 个鸡蛋，盖上锅盖，焖 2 分钟","开盖翻炒至第三颗鸡蛋熟透，撒上葱花和胡椒粉，出锅"]'::jsonb, '["主食","焦香微甜","炒饭","快手","创意","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_a3bc6ac537.jpg', 'https://www.bilibili.com/video/BV1sV4y1E7K5', '{"energyKcal":900,"protein":34,"carbs":82,"fat":48}'::jsonb, '[null,null,null,null,null,120,null]'::jsonb),
  ('howtocook:staple/咸肉菜饭', '咸肉菜饭', '主食', 4, 60, '这是一道充满上海弄堂风情的家常主食，咸肉的醇香与青菜的清甜在猪油的点化下融进每一粒米饭，既有锅巴焦脆，又保留菜梗爽嫩，层次分明。青菜富含维生素和膳食纤维，咸肉提供蛋白质与能量，荤素搭配均衡。做法并不复杂，但需要掌握分次下菜叶的小技巧，对新手而言稍有挑战。从头备料到出锅，大约需要 1 小时。', '[{"name":"大米","quantity":300,"unit":"克"},{"name":"青菜","quantity":400,"unit":"克"},{"name":"咸肉","quantity":150,"unit":"克"},{"name":"冬笋","quantity":100,"unit":"克"},{"name":"猪油","quantity":15,"unit":"克"},{"name":"料酒","quantity":15,"unit":"ml"},{"name":"白糖","quantity":0,"quantityMax":3,"unit":"克"},{"name":"白胡椒粉","quantity":1,"unit":"克"},{"name":"水","quantity":310,"unit":"ml"}]'::jsonb, '["如果加入冬笋，切薄片后冷水下锅煮 10 分钟去涩味","咸肉切 1 cm 小丁","咸肉和冬笋冷锅下 10 g 猪油、料酒、白糖，中小火煸炒到透明冒泡","青菜切碎，菜梗和菜叶分开放，菜梗切成 0.5 cm 边长的正方形小块，菜叶切成长 2-3 cm，宽 1-1.5 cm 的长方形小块","菜梗下锅炒到翡翠色","米淘净后倒进电饭煲，加水","把炒好的咸肉和菜梗铺在米上","正常煮饭模式启动，最后 10 分钟开盖快速铺入菜叶","煮好后焖 5 分钟，再淋 5 g 猪油、白胡椒粉疯狂翻拌均匀"]'::jsonb, '["主食","上海风味","家常","咸鲜","焖饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_3b601e5a40.jpg', 'https://www.bilibili.com/video/BV11YfwYNEEK', '{"energyKcal":420,"protein":13,"carbs":62,"fat":11.5}'::jsonb, '[600,null,null,null,null,null,null,600,300]'::jsonb),
  ('howtocook:staple/基础牛奶面包/基础牛奶面包', '基础牛奶面包', '主食', 5, 200, '这款基础牛奶面包通过酵头预发酵简化了传统面包的制作，成品奶香浓郁，质地松软。富含碳水化合物和蛋白质，能为身体提供能量。难度适中，适合烘焙新手尝试，全程大约需要 200 分钟。', '[{"name":"高筋或中筋面粉（酵头用）","quantity":1,"unit":"cup"},{"name":"温水（约30℃）","quantity":1,"unit":"cup"},{"name":"干酵母","quantity":2,"unit":"g"},{"name":"盐","quantity":2,"unit":"g"},{"name":"高筋或中筋面粉（面团用）","quantity":2.5,"unit":"cup"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"糖或糖浆","quantity":0.125,"unit":"cup"},{"name":"牛奶或淡奶油或炼乳或奶粉","quantity":0.25,"unit":"cup"},{"name":"黄油或玉米油","quantity":0.125,"unit":"cup"},{"name":"谷朊粉（可选）","quantity":0.25,"quantityMax":0.5,"unit":"cup"},{"name":"香草精（可选）","quantity":3,"unit":"g"},{"name":"布","note":"适量"}]'::jsonb, '["首先，将酵母和 30℃ 的温水 用刮刀或厨具混合均匀，静置 5 分钟。之后与面粉混合，搅拌均匀。此时的酵头应该是特别粘稠的面糊。","用布盖上面糊，将面糊放置到温暖的地方进行发酵，时长为 45 ~ 60 分钟。","最终的面糊应该是表面有很多气泡的且体积明显增大。"]'::jsonb, '["主食","奶香","松软","烘焙","发酵","新手友好"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_c3077d480c.jpg', 'https://www.bilibili.com/video/BV1tp4y1e7DT', '{"energyKcal":250,"protein":8,"carbs":45,"fat":4.5}'::jsonb, '[300,null,null]'::jsonb),
  ('howtocook:staple/微波炉腊肠煲仔饭/微波炉腊肠煲仔饭', '微波炉腊肠煲仔饭', '主食', 2, 15, '这是一道简单快手的粤式风味主食，米饭吸足腊肠油脂后油润咸香，搭配脆嫩青菜和胡萝卜，口感层次丰富。富含碳水化合物、蛋白质和多种维生素，营养均衡。烹饪用微波炉操作，对新手十分友好，预计全程仅需 15 分钟即可享用。', '[{"name":"米","quantity":200,"unit":"ml"},{"name":"腊肠","quantity":1,"unit":"根"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"红萝卜","quantity":1,"unit":"个"},{"name":"盐","quantity":5,"unit":"克"},{"name":"油","quantity":15,"unit":"ml"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"香葱","quantity":1,"unit":"颗"},{"name":"青菜","note":"适量"},{"name":"水","quantity":400,"unit":"ml"}]'::jsonb, '["将米淘洗干净后倒入 饭碗 内，加入 400ml 的水，盖上盖","放入微波炉，高火，6 分钟，煮饭途中准备原料","切好腊肠","洗好青菜","切好红萝卜片","切好葱花","青菜碗 中放入青菜、红萝卜片，倒入 10 ml 油，放入 5 g 盐","小碗 中倒入 10 ml 生抽、5 ml 油","6 分钟后，用毛巾或隔热手套取出碗，可以看见米饭已经八分熟","在米饭上摆入切片的腊肠，继续高火 2 分钟","取出腊肠饭，放入 青菜碗，高火 4-5 分钟","在腊肠饭上摆好青菜，磕入鸡蛋，看个人喜好继续高火 40-60 秒","取出腊肠饭，此时已经基本完成。","将 小碗 放入，继续高火 30 秒","在腊肠饭上淋上叮热的生抽，撒上葱花即可","多余的青菜可以沾着酱油吃"]'::jsonb, '["主食","粤式","微波炉","快手","咸香","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_f3e030fe4e.png', 'https://www.bilibili.com/video/BV1syWDzZEjZ', null, '[null,360,null,null,null,null,null,null,360,120,240,40,null,30,null,null]'::jsonb),
  ('howtocook:staple/意式肉酱面/意式肉酱面', '意式肉酱面', '主食', 1, 15, '意式肉酱面是一道简单快手的家常西餐，酱汁浓郁、面条筋道，适合忙碌的日常。肉末和洋葱搭配成品意面酱，能快速补充蛋白质与碳水化合物，洋葱还含有膳食纤维。做法对初学者十分友好，全程只需简单切炒，熟练后 15 分钟就能端上桌，比方便面更满足。', '[{"name":"意大利面","quantity":180,"unit":"克"},{"name":"意大利面酱","quantity":300,"unit":"克"},{"name":"肉沫","quantity":80,"unit":"克"},{"name":"白洋葱","quantity":150,"unit":"克"},{"name":"食用油","quantity":10,"quantityMax":15,"unit":"ml"}]'::jsonb, '["锅中加水，烧开后放入意面（等待 6 - 12 分钟）","在烧水的时候可以进行下面这些步骤，但请注意煮面的时间","洋葱切成小丁","空锅中倒油，中火下入洋葱碎","时刻搅拌，注意不要让洋葱烧糊，直到洋葱变成半透明状","下入肉沫，继续搅拌（搅散），直到肉末变成棕色","加入意大利面酱，稍微搅拌一下即可","把煮好的意大利面沥干水分并倒入肉酱中搅拌均匀即可（或者直接把做好的肉酱倒在意面上也行）"]'::jsonb, '["主食","快手","家常","鲜香","西餐"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_8238de0621.jpg', 'https://www.bilibili.com/video/BV1rd4y1E7vs', '{"energyKcal":1150,"protein":45}'::jsonb, '[360,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:staple/手工水饺', '手工水饺', '主食', 5, 180, '手工水饺是一道中式经典主食，皮薄馅大、鲜美多汁，饱腹又可以根据个人口味随意调味。猪肉馅提供优质蛋白质和脂肪，搭配韭菜还能补充维生素与膳食纤维。这道菜品对新手来说难度较高，需要掌握和面、擀皮、调馅和煮饺的火候，预计制作时间约 3 小时。', '[{"name":"面粉","quantity":200,"unit":"克"},{"name":"冷水","quantity":150,"unit":"ml"},{"name":"芝麻香油","quantity":2,"quantityMax":3,"unit":"ml"},{"name":"瘦肉末","quantity":250,"unit":"克"},{"name":"肥肉末","quantity":20,"unit":"克"},{"name":"姜","quantity":3,"unit":"克"},{"name":"葱","quantity":15,"unit":"克"},{"name":"盐","quantity":3,"unit":"克"},{"name":"蚝油","quantity":2,"unit":"ml"},{"name":"香油","quantity":2,"unit":"ml"},{"name":"生抽","quantity":2,"unit":"ml"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"韭菜","note":"适量"}]'::jsonb, '["盆中加入所有面粉","加入芝麻香油","面粉中央挖小洞","分 4-5 次加入水，并搅和，当出现碎末状的稍微干燥面团时","取消加水，用手将面团压实","面团压实至可把盆周围的面粉纳入即可，此步骤为面光盆光","将面团置于桌上，盆倒扣于桌上，环境温度为 25 度，使面团醒发约 45 分钟","醒发完成后，将面团搓成条状，合成一团，再次搓成条，重复 3 次","擀成条状，切成 20 份均匀大小面团，并搓成直径约 3-3.5cm 的球状","压扁面团，在手上，桌上，擀面杖上，及面团上撒上面粉，此步骤防止面团发粘","用擀面杖将面团擀平，约 8cm 直径，厚约 2mm，中间略微比四周厚 1mm","猪肉去皮,保留部分肥肉,切成小块","菜刀（建议两把）将猪肉剁成肉沫,放入碗中","葱、姜切成末,放入肉碗中搅拌均匀","韭菜洗净,切短至 3mm 以下长度","韭菜和肉沫混合,加入蚝油、生抽、香油各 2ml,加入一个鸡蛋的蛋清,用手混合搅拌均匀","放置 30 分钟即可开始包饺子","左手上放面皮，放饺子馅一面尽量不要粘到面粉，防止无法合拢","右手用筷子夹约面皮 1/2 直径的馅","沿饺子皮圆周进行合拢，捏实，个人吃无需捏花，饺子皮不漏即可","使用可放下 20 只饺子的锅，或分批量煮","烧水，水约 3/4 锅的高度","大火烧开水后放入饺子，调至中火","第一次放入饺子，且水冒泡后，锅边加入 50ml 冷水（重复此步骤两次）","第三次水开后加入冷水 50ml，水开后调至小火等 60s 即可出锅"]'::jsonb, '["主食","家常","鲜香","面食","手工","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_e8c8636afc.jpg', 'https://www.bilibili.com/video/BV1LJ411C7sW', '{"energyKcal":660,"protein":41,"carbs":81,"fat":18}'::jsonb, '[null,null,null,null,null,null,2700,null,null,null,null,null,null,null,null,null,1800,null,null,null,null,null,null,null,60]'::jsonb),
  ('howtocook:staple/扬州炒饭/扬州炒饭', '扬州炒饭', '主食', 4, 60, '这是一道配料丰富的升级版炒饭，米饭粒粒分明，鸡蛋嫩滑，搭配虾仁、午餐肉和蔬菜丁，口感层次鲜明，属于淮扬菜系中的经典主食。富含优质蛋白、碳水化合物和多种维生素，营养均衡。步骤虽多但操作直观，对初级烹饪者也较为友好，只需耐心备料。预计制作时长约 1 小时。', '[{"name":"冷饭","quantity":500,"unit":"克"},{"name":"鸡蛋","quantity":2,"quantityMax":3,"unit":"个"},{"name":"冷冻去皮基围虾","quantity":10,"quantityMax":15,"unit":"只"},{"name":"午餐肉罐头","quantity":150,"unit":"克"},{"name":"青豆","quantity":30,"unit":"克"},{"name":"胡萝卜","quantity":30,"unit":"克"},{"name":"玉米粒","quantity":30,"unit":"克"},{"name":"葱","quantity":1,"unit":"根"},{"name":"油","quantity":30,"quantityMax":40,"unit":"ml"},{"name":"盐","quantity":12,"quantityMax":15,"unit":"克"}]'::jsonb, '["胡萝卜切丁 0.2cm0.2cm0.2cm，备用","午餐肉切丁 0.2cm0.2cm0.2cm，备用","葱分别取葱白和葱绿，各切成 0.25-0.5cm 的小段，分开备用","在碗中打入鸡蛋液，均匀搅拌，备用","将胡萝卜，青豆，玉米粒煮熟捞出，备用（水别倒）","将虾煮熟，捞出备用（水可以倒了）","热锅热油，可以参考学习炒与煎中的热锅双油","第二次倒油需使用 20-30ml 油，等到第二次凉油热了以后，缓慢倒入鸡蛋（控制碗到油直接的流注直径大约在 0.5cm）不要搅拌","鸡蛋凝固后立刻捞出，备用","将午餐肉，青豆，胡萝卜，玉米粒，虾倒入锅中翻炒 1-2 分钟，装盘备用","水冲一下锅，将杂物冲干净，保证锅内干净（可以有油但是不能有杂质）","热锅热油(10ml)，将葱白放入爆香","调至小火（如果油温过高可以关火 1-2 分钟），放入米饭，用铲子快速砸击米饭并翻炒，保证米饭均匀沾到油且粒粒分明","倒入鸡蛋，继续砸击，使鸡蛋碎开并与米饭充分混合","转大火，倒入其他所有备用配料，快速翻炒 1-2 分钟","撒入盐，并翻炒至充分混合","撒入葱绿，翻炒 1 分钟","关火，装盘"]'::jsonb, '["主食","鲜香","炒饭","家常","淮扬","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_afc7f19ab7.png', 'https://www.bilibili.com/video/BV1sU4y1B7MC', '{"energyKcal":1780,"protein":79,"carbs":158,"fat":87}'::jsonb, '[null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,null,60,null]'::jsonb),
  ('howtocook:staple/披萨饼皮/披萨饼皮', '披萨饼皮', '主食', 4, 720, '披萨饼皮采用低温隔夜发酵，成品饼底柔软又略带嚼劲，属于家常西式面点。主要提供碳水化合物和少量优质脂肪。制作流程简单，但需要耐心等待面团发酵，对新手也算友好。从准备到烘烤完成，算上隔夜冷藏时间大约需要 10-14 小时，适合提前一天备好。', '[{"name":"中筋面粉","quantity":500,"unit":"克"},{"name":"温水","quantity":350,"unit":"克"},{"name":"干酵母粉","quantity":5,"unit":"克"},{"name":"食用盐","quantity":3,"unit":"克"},{"name":"橄榄油","quantity":35,"unit":"克"},{"name":"白砂糖","quantity":3,"unit":"克"}]'::jsonb, '["用准备好的温水把酵母粉化开，稍微搅拌小就好，备用","取准备好的面粉，依次添加盐、橄榄油、白砂糖","准备混合水和面粉，边加水边搅拌直至水全部加完","搅拌至看不到干米粉为止","用差不多三倍大面团的容器装好，密封，冰箱冷藏（4 度） 等待 8~12 小时，一般晚上做第二天就可以用","观察面团醒发完毕 差不多是原始大小大约两倍算醒发完毕","取醒发好的面团，均匀分成四份，分别用保鲜膜盖好，备用","案板撒稍微多一点的干面粉，准备开始揉面","因为是比较湿的面团，所以粘上干面粉后才没那么粘手，不用揉太多次，面团表面稍微光滑一点就可以了","用手拉扯，或者擀面杖擀平，也不一定非得擀圆，只要厚度均匀，烤箱放得进去就好","铺好油纸，放上饼皮，依照个人口味，把准备好的食材放上去，撒上芝士碎","水果烤箱上 180 度，下 220 度，16 分钟即可","肉蔬菜烤箱上 200 度，下 230 度，18 分钟即可","挤上沙拉酱或者其他自己喜欢的酱即可享用~"]'::jsonb, '["主食","西式","烘烤","隔夜发酵","家常","新手友好"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_c284143305.jpeg', 'https://www.bilibili.com/video/BV17D4y1k7Vb', '{"energyKcal":530,"protein":15,"carbs":96,"fat":11}'::jsonb, '[null,null,null,null,36000,null,null,null,null,null,null,960,1080,null]'::jsonb),
  ('howtocook:staple/日式咖喱饭/日式咖喱饭', '日式咖喱饭', '主食', 4, 60, '日式咖喱饭是一道浓郁醇厚的家常和风料理，以咖喱块调味，搭配土豆、胡萝卜、洋葱和肉类，口感顺滑绵密、辛香微甜。它富含蛋白质、碳水与多种维生素，能为身体提供充足能量。做法整体不算复杂，但需要掌握火候与搅拌技巧，适合稍有下厨经验的朋友尝试。从备料到出锅约需 1 小时，冷藏后风味更佳。', '[{"name":"咖喱块（推荐好侍）","quantity":115,"unit":"克"},{"name":"土豆","quantity":2,"unit":"个"},{"name":"胡萝卜","quantity":1,"unit":"根"},{"name":"洋葱","quantity":2,"unit":"个"},{"name":"肉（猪肉/鸡肉/牛肉均可）","quantity":2,"unit":"斤"},{"name":"蒜头","quantity":2,"quantityMax":3,"unit":"瓣"},{"name":"花椰菜（清水煮开）","note":"适量"},{"name":"培根（即食）","note":"适量"},{"name":"煎蛋/太阳蛋","note":"适量"}]'::jsonb, '["胡萝卜去头尾，去皮，滚刀切","洋葱剥去外层去芯，切成月牙状","土豆去皮、切大块","肉切块状","剥蒜拍平切碎","咖喱块切碎，增加接触面积加速溶解","热油锅放入蒜和肉，快速翻炒至肉表面变白","加入胡萝卜，快速翻炒至均匀受热","加入洋葱，快速翻炒至洋葱变透明状","加入土豆，保持翻炒至土豆变软（可以用筷子确认）","加水没过所有食材，沸腾后等待 15 分钟","关火，加咖喱并搅拌","等待咖喱融化后再开火，缓慢搅拌 10 分钟，防止糊锅","在外观呈粘稠状态关火结束制作","微波炉：单人份高火 2-3 分钟","锅：需额外加 50ml 水，加热时保持搅拌"]'::jsonb, '["主食","日式","浓郁","家常","下饭","炖煮"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_c2eee4e19e.jpg', 'https://www.bilibili.com/video/BV1tp4y1t7YG', '{"energyKcal":520,"protein":32,"carbs":38,"fat":28}'::jsonb, null),
  ('howtocook:staple/日式肥牛丼饭/日式肥牛丼饭', '日式肥牛丼饭', '主食', 4, 30, '一道经典的日式家常盖饭，肥牛片与白洋葱在咸甜酱汁中炖煮入味，肉质软嫩，洋葱甜润，汁香浓郁。牛肉提供优质蛋白和血红素铁，洋葱富含膳食纤维与多种抗氧化物。制作不算复杂，新手只要跟着步骤操作也能轻松完成，炒煮过程约需 30 分钟。', '[{"name":"洋葱","quantity":1,"unit":"个"},{"name":"肥牛","quantity":250,"unit":"克"},{"name":"葱","quantity":1,"quantityMax":2,"unit":"根"},{"name":"白芝麻","quantity":5,"unit":"克"},{"name":"味淋","quantity":40,"unit":"克"},{"name":"料酒","quantity":30,"unit":"克"},{"name":"温泉蛋","note":"适量"},{"name":"出汁","note":"适量"},{"name":"米","quantity":1,"unit":"杯"},{"name":"酱油","quantity":30,"unit":"克"},{"name":"蚝油","quantity":20,"unit":"克"},{"name":"糖","quantity":5,"unit":"克"},{"name":"老抽","quantity":5,"unit":"克"},{"name":"水","quantity":250,"unit":"克"}]'::jsonb, '["洋葱剥去外层去芯，切成月牙状","葱洗净切成 0.5cm 的小段","热锅直接放入白芝麻，前后晃动锅体使芝麻均匀受热至略呈金黄色","肥牛焯水 1 分钟后捞出","将 40g 味淋（或 30g 料酒），30g 酱油，20g 耗油，5g 糖，5g 老抽（可选，用于调色），在碗中搅拌混合成调料（该步骤可直接将碗放在电子秤上进行）","热油锅放入洋葱，快速翻炒至洋葱变透明状","关小火，加入 250g 水（或出汁），开回大火加热等待 3 分钟","加入牛肉和调料","不断翻动所有食材 10 分钟，防止食材粘锅","关火","盛装肥牛丼至米饭上（注意要把汁水淋一些在饭上）","撒上葱花和白芝麻，制作完成。","微波炉：单人份高火 2-3 分钟","锅：需额外加 50ml 水，加热时需不断翻动"]'::jsonb, '["主食","日式","咸甜","炖煮","下饭","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_1b3f1450db.png', 'https://www.bilibili.com/video/BV1UM4y1u7Wa', '{"energyKcal":720,"protein":32,"carbs":82,"fat":24}'::jsonb, '[null,null,null,60,null,null,180,null,600,null,null,null,null,null]'::jsonb),
  ('howtocook:staple/汤面', '汤面', '主食', 2, 30, '汤面是一道自由搭配的家常主食，汤汁清爽，面条软滑，兼容各种荤素食材，味道可鲜可淡。它富含碳水化合物和优质蛋白质，搭配蔬菜还能补充维生素与膳食纤维，营养均衡又饱腹。做法非常简单，无需厨艺基础，新手也能轻松驾驭。从准备食材到出锅，一般约需 30 分钟。', '[{"name":"面食材料","quantity":70,"quantityMax":230,"unit":"克"},{"name":"冷水","quantity":200,"quantityMax":400,"unit":"ml"},{"name":"菜类材料","note":"体积大约和面类相当"},{"name":"盐","note":"适量"},{"name":"胡椒粉","note":"适量"},{"name":"香油","note":"适量"}]'::jsonb, '["先将菜类材料切成边长不超过 4cm 的块状，便于煮熟","如有生肉，则先放入冷水中，盖上锅盖，煮沸腾，先捞出上层血沫，再关火，捞出半熟的肉备用","先大火将水加热至沸腾，后调至中火","将较难煮熟的食材放入锅中（比如半熟肉类、香菇类、等最先放入锅中）。为保证煮熟，可在沸腾后计时 10 分钟，特别难熟的大块食材可追加 5 分钟。","将面食放入锅中，适当搅拌确保面和汤充分接触，使液面保持轻微沸腾，煮 5 分钟。加入面后液面易产生白色泡沫，可适当抬起锅盖通气或者撤下锅盖。","将易于煮熟的食材如青菜类放入锅中，适当搅拌以充分浸没，煮 2-5 分钟","关火，随后加入盐、胡椒粉、香油等自己喜欢的调味料，适当搅拌即可出锅食用"]'::jsonb, '["主食","清淡","家常","快手","自由搭配","营养均衡"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_07a24bb37a.jpg', 'https://www.bilibili.com/video/BV1vv411L7CU', '{"energyKcal":380,"protein":14,"carbs":75,"fat":5}'::jsonb, '[null,null,null,600,300,null,null]'::jsonb),
  ('howtocook:staple/河南蒸面条/河南蒸面条', '河南蒸面条', '主食', 4, 40, '河南蒸面条是源自河南的家常小吃，面条先蒸后炒再蒸，油润入味，口感劲道爽滑。五花肉和蒜薹提供丰富的蛋白质和膳食纤维，搭配主食带来均衡营养。制作步骤稍多一些，但对新手而言只要按顺序操作就能成功。从备料到出锅，总共约需 40 分钟。', '[{"name":"挂面（推荐圆的）","quantity":300,"unit":"克"},{"name":"五花肉","quantity":350,"unit":"克"},{"name":"蒜薹","quantity":150,"unit":"克"},{"name":"葱","quantity":10,"unit":"克"},{"name":"姜","quantity":5,"unit":"克"},{"name":"蒜","quantity":10,"unit":"克"},{"name":"料酒","quantity":5,"unit":"ml"},{"name":"盐","quantity":2,"unit":"克"},{"name":"鸡精","quantity":2,"unit":"克"},{"name":"十三香","quantity":1,"unit":"克"},{"name":"生抽","quantity":15,"unit":"ml"},{"name":"老抽","quantity":10,"unit":"ml"},{"name":"蚝油","quantity":5,"unit":"ml"},{"name":"食用油","quantity":10,"quantityMax":15,"unit":"ml"},{"name":"麻油","quantity":5,"unit":"ml"},{"name":"蒸篦子","note":"适量"}]'::jsonb, '["起锅加 7 成水，水开，上蒸篦子","将挂面，均匀铺开放置，淋 5ml 油并抹匀，蒸 15 分钟","将挂面和蒸篦子取出，放置一边，并倒掉锅中的水","五花肉，切成 2mm 厚度的肉片","蒜薹，切成 3cm 段","葱，切成 0.2cm 薄片","姜，切成 1mm x 1mm x 3cm 的细丝","蒜，放在砧板上拍碎，切成 1mm 的粒度","起锅，烧干水分，加 3ml 食用油","手持锅柄，摇晃锅，使食用油充分挂满锅的 2/3","中火，加入肉片，翻炒 1 分钟","加入葱姜蒜，料酒，继续翻炒 1 分钟","将蒜薹段，放入锅中，翻炒 1 分钟","开始调味，加入老抽、生抽、蚝油、盐、鸡精、十三香，翻炒 1 分钟","加入 500ML 水，没过蔬菜，炖煮 1 分钟","将蒸好的挂面放入，不断搅拌 3 分钟，待挂面全部均匀上色，关火","将搅拌好的挂面和菜，全部倒入额外的盆中","起锅，加冷水 7 成，放上蒸篦子，将拌好的面条和菜，均匀的铺在上面","水开后，大火烧 15 分钟，出锅","淋上 10g 的麻油，即可食用"]'::jsonb, '["主食","河南风味","家常","鲜香","蒸炒","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_ab9a32b213.png', 'https://www.bilibili.com/video/BV19W411P785', '{"energyKcal":970,"protein":27,"carbs":74,"fat":59}'::jsonb, '[null,900,null,null,null,null,null,null,null,null,60,60,60,60,60,180,null,null,900,null]'::jsonb),
  ('howtocook:staple/火腿饭团/火腿饭团', '火腿饭团', '主食', 4, 60, '一道简单快手的日式风味饭团，咸香火腿搭配沙拉酱与海苔，口感丰富饱腹。富含碳水化合物、蛋白质和维生素，能快速补充能量。制作难度极低，新手也能轻松上手，从煮饭到完成大约只需 1 小时。', '[{"name":"火腿","quantity":100,"unit":"克"},{"name":"米饭","quantity":125,"unit":"克"},{"name":"水","quantity":90,"unit":"ml"},{"name":"冷冻青豆","quantity":30,"unit":"克"},{"name":"冷冻玉米粒","quantity":30,"unit":"克"},{"name":"海苔碎","quantity":10,"unit":"克"},{"name":"沙拉酱","quantity":20,"unit":"克"},{"name":"食用油","quantity":10,"quantityMax":15,"unit":"ml"}]'::jsonb, '["将米饭和水放到电饭锅里，点击米饭模式，等待完成","冷冻玉米粒和青豆放到锅里，加水没过所有食材，沸腾后静待 2 分钟后，捞出。","火腿切成 1cm 的方块","与此同时，加入 10ml 食用油，加入火腿翻炒至火腿上色","将米饭，火腿，海苔碎，青豆，玉米粒，沙拉酱放入碗中，混合均匀即可","装盘（如果有的话）"]'::jsonb, '["主食","日式","快手","家常","咸香","饭团"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_f81fe785c5.png', 'https://www.bilibili.com/video/BV1F6MszrEy6', '{"energyKcal":900,"protein":29}'::jsonb, '[null,120,null,null,null,null]'::jsonb),
  ('howtocook:staple/炒凉粉/炒凉粉', '炒凉粉', '主食', 3, 15, '炒凉粉是一道山西、陕西地区的特色小吃，入口滑嫩，咸香微辣，带着蒜香和酱香。凉粉主要由淀粉制成，能提供丰富的碳水化合物，快速补充能量。烹饪难度适中，适合有一定基础的新手尝试，全程制作大约需要 15 分钟。', '[{"name":"凉粉","quantity":500,"unit":"克"},{"name":"玉米油","quantity":10,"unit":"ml"},{"name":"大蒜","quantity":10,"unit":"克"},{"name":"香葱","quantity":15,"unit":"克"},{"name":"豆瓣酱","quantity":15,"unit":"克"},{"name":"生抽","quantity":20,"unit":"ml"},{"name":"老抽","quantity":10,"unit":"ml"},{"name":"食盐","quantity":5,"unit":"克"},{"name":"十三香","quantity":5,"unit":"克"},{"name":"中粗辣椒面","quantity":15,"unit":"克"},{"name":"矿泉水","quantity":20,"unit":"ml"}]'::jsonb, '["凉粉改刀切麻将块大小","开小火，起锅烧油，锅烧微热后，下入蒜末爆香后加入豆瓣酱炒出红油","将凉粉块下入锅中，翻炒 10 秒","加入生抽提味，老抽上色，翻炒均匀后加入辣椒面继续翻炒均匀","加入食盐、十三香继续翻炒 10 秒","加入准备好的矿泉水，再次翻炒 10 秒，待汤汁浓稠后，关火出锅装盘","撒上葱花即可完成"]'::jsonb, '["主食","咸香微辣","炒制","晋陕风味","家常小吃","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_0558608774.jpg', 'https://www.bilibili.com/video/BV1984y1m7cX', '{"energyKcal":320,"protein":3,"carbs":52,"fat":10}'::jsonb, '[null,null,10,null,10,10,null]'::jsonb),
  ('howtocook:staple/炒年糕', '炒年糕', '主食', 3, 30, '这是一道闽南风味的主食，年糕软糯弹牙，带着葱油的焦香，家常又饱腹。以米粉制成的年糕提供充足碳水化合物，搭配鸡蛋和青菜能补充蛋白质与维生素，营养均衡。做法简单，对新手友好，从准备到出锅大约需要 30 分钟。', '[{"name":"年糕/白粿","quantity":250,"unit":"g"},{"name":"小葱","quantity":2,"unit":"根"},{"name":"食用油","quantity":50,"unit":"ml"},{"name":"酱油","quantity":15,"unit":"ml"},{"name":"盐","quantity":1,"quantityMax":2,"unit":"g"},{"name":"鸡蛋","note":"适量"},{"name":"青菜","note":"适量"}]'::jsonb, '["锅中加水烧开，煮熟年糕，碗中加水确保年糕不会粘连，捞起年糕备用。","小葱切葱花（将葱白和葱叶分开），青菜切小段备用。","（可选） 制作炒蛋，见西红柿炒蛋。","热锅，加入 30ml 食用油。","将葱白倒入锅中，直至大部分葱白变成焦黄色且发出香味，倒出葱油备用。","重新热锅，加入 20ml 食用油。","加入所有辅料（鸡蛋，青菜等），翻炒均匀。","将年糕的水倒掉，向锅中加入年糕。","加入酱油和盐，翻炒均匀。","关火，加入葱油，翻炒均匀，乘盘。"]'::jsonb, '["主食","闽南风味","炒","家常","快手","鲜香"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_d0fa392da5.jpg', 'https://www.bilibili.com/video/BV164411R77G', '{"energyKcal":1050,"protein":15,"carbs":115,"fat":56}'::jsonb, null),
  ('howtocook:staple/炒意大利面/炒意大利面', '炒意大利面', '主食', 3, 30, '这道炒意大利面软糯爽口，搭配肥牛和酱料，酱香浓郁，是带有西式风味的家常主食。富含碳水化合物与蛋白质，能快速补充能量。做法简单，新手也能轻松掌握，全程大约需要 30 分钟。', '[{"name":"意大利面","quantity":50,"unit":"克"},{"name":"肥牛片","quantity":5,"unit":"片"},{"name":"番茄酱","quantity":10,"unit":"克"},{"name":"黑胡椒酱","note":"选其一即可"},{"name":"菜籽油","quantity":5,"unit":"ml"},{"name":"水","quantity":250,"unit":"克"},{"name":"食盐","quantity":2,"unit":"克"}]'::jsonb, '["加入 250 克水 / 人","待水烧开，下入面条，中火煮 15 - 20 分钟（这个面通常比较硬，捞起来之前最好尝一下，中心如果有一点硬，需要继续煮）","捞出面条，盛入盘中备用","热锅倒入食用油，待油温中热，下入面条翻炒一分钟（如果太干，加入少量水）","放入 10 克番茄酱、肥牛、加入 2g 食盐，继续翻炒一分钟","起锅"]'::jsonb, '["主食","酱香","西式风味","炒","快手","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_393a3a01c7.jpg', 'https://www.bilibili.com/video/BV13W411C7hu', '{"energyKcal":330,"protein":13,"carbs":39,"fat":14}'::jsonb, '[null,null,null,60,60,null]'::jsonb),
  ('howtocook:staple/炒方便面/炒方便面', '炒方便面', '主食', 2, 15, '这道炒方便面口感 Q 弹筋道，咸香入味，是一道改良自传统煮面的家常快手主食。搭配鸡蛋和火腿肠，丰富了蛋白质和能量来源。做法简单，只需注意冷水冲面保持口感，新手也能轻松完成，全程大约 15 分钟即可出锅。', '[{"name":"方便面","quantity":1,"unit":"包"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"火腿肠","quantity":1,"unit":"个"},{"name":"食用油","quantity":10,"quantityMax":18,"unit":"ml"},{"name":"水","quantity":1200,"unit":"ml"}]'::jsonb, '["将火腿肠撕开包装，切成宽度 1cm 的小块。","向煮锅中加入 1200 ml 水，实际以没过面饼为准。完全煮沸，不要在未沸腾时加面。","加入方便面面饼，煮 45 秒。煮的过程中将其挑动，把面条打散。","面条打散后立刻关火。不要煮熟！","从锅中舀出 80ml 热面汤备用。","将面汤和面分离。用凉水冲一下面条。","沥干面条上的水分。不要长时间将面泡在水中。","准备一个小碗，将方便面的调料包挤进去。","挤进去所有菜包","挤进去所有酱包","挤进去 50% - 80% 的粉包。（全部粉包都挤进去会很咸）","将上一步的 80ml 热面汤全部倒入小碗，搅匀，得到调料碗。","取出计算好的数量的鸡蛋，打入一个小碗。不要加盐！（鸡蛋最终会混合锅里食材的盐味）","热锅 20s，加入份数 8ml 油。","加入刚刚准备好的一碗鸡蛋。翻炒大约 20s 至鸡蛋形成固态即可。","将煎鸡蛋取出暂存。不需要洗锅。但一般锅内不会残余太多油。","重新热锅 20s，向锅内加入油：份数 10ml。","加入第一步处理的火腿肠。翻炒 10 秒。","加入第二步的面。翻炒 30 秒。","加入第三步的调料碗。翻炒 30 秒。","加入第四步的煎鸡蛋。翻炒 30 秒。","关火盛盘即可。"]'::jsonb, '["主食","咸香","快手","家常","炒"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_dbc8a2560c.png', 'https://www.bilibili.com/video/BV1rTwBezEHq', '{"energyKcal":700,"protein":18,"carbs":55,"fat":40}'::jsonb, '[null,null,45,null,null,null,null,null,null,null,null,null,null,20,20,null,20,10,30,30,30,null]'::jsonb),
  ('howtocook:staple/炒河粉', '炒河粉', '主食', 4, 30, '炒河粉是一道流行于广东地区的经典小吃，讲究镬气十足、干香爽滑，河粉软韧透亮，搭配肉丝、豆芽和黄瓜丝，口感层次丰富。主要提供碳水化合物和蛋白质，蔬菜的加入也补充了维生素与膳食纤维。按本菜谱操作难度适中，即便新手只要备齐材料也能尝试，整个制作过程约需 30 分钟即可端上餐桌。', '[{"name":"炒河粉","quantity":250,"unit":"g"},{"name":"猪肉/牛肉","note":"适量"},{"name":"盐","quantity":10,"unit":"g"},{"name":"味精","quantity":2,"unit":"g"},{"name":"老抽","quantity":10,"unit":"ml"},{"name":"生抽","quantity":15,"unit":"ml"},{"name":"孜然粉","quantity":3,"unit":"g"},{"name":"河粉料","quantity":20,"unit":"g"},{"name":"胡椒粉","note":"适量"},{"name":"黄瓜","quantity":30,"unit":"g"},{"name":"面筋块","quantity":30,"unit":"g"},{"name":"绿豆芽","quantity":30,"unit":"g"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"蒜瓣","quantity":2,"unit":"个"},{"name":"小葱","quantity":1,"unit":"根"},{"name":"淀粉","note":"适量"},{"name":"食用油","quantity":20,"unit":"g"}]'::jsonb, '["小葱切碎（葱白和葱叶分开）、蒜瓣拍碎，丢案板上备用。","打碎鸡蛋，捞一点蛋清到一只碗中，剩下的丢入另一只碗中备用。","将绿豆芽放入锅中，大火煮 60 秒。豆芽捞出，过凉水，放入盘中备用。","黄瓜切丝放入盘中备用，可和豆芽丢一起。","处理面筋，单独丢一个盘中。","肉切细条状，加入淀粉与刚刚碗中的鸡蛋清、胡椒粉，顺时针拌匀。","注：超市购买来的凉皮表面一般会有食用油，可以使用自来水清洗。面筋同样。","注：清洗面筋之后，请用手将面筋中的大量水分挤出（不需过于用力）。","加入食用油，锅热倒出。","倒入处理好的肉，翻炒均匀至变色，倒入碗中备用。","趁锅热，加入 20g 食用油（高血压人群可降低用量），倒入葱白、蒜爆炒出香。","加入河粉，淋入老抽提色，翻炒均匀后再加入河粉炒料，继续翻炒。","河粉即将透明时，放入炒制好的肉丝与面筋，并加入生抽提鲜，简单翻炒两次。","加入豆芽与黄瓜丝，翻炒至河粉完全透明。","关火！","撒入葱叶点缀，把锅端起。","倒入盘中，开始干饭。"]'::jsonb, '["主食","鲜香","炒制","粤式","快手","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_3a437e50d6.jpg', 'https://www.bilibili.com/video/BV1z44y1G7av', null, null),
  ('howtocook:staple/炒馍', '炒馍', '主食', 3, 15, '炒馍是一道咸香酥脆的家常面食，属于北方风味。馒头丁炒至金黄，外脆里软，孜然与五香粉的加入让风味更加浓郁。可搭配鸡蛋提供蛋白质，搭配小葱增添清香，营养均衡。制作难度适中，新手也能很快上手，预计 大约 15 分钟即可出锅享用。', '[{"name":"馒头","quantity":2,"unit":"个"},{"name":"盐","quantity":3,"unit":"g"},{"name":"油","quantity":20,"unit":"ml"},{"name":"孜然粉","quantity":3,"unit":"g"},{"name":"辣椒粉","quantity":3,"unit":"g"},{"name":"五香粉","quantity":3,"unit":"g"},{"name":"小葱","quantity":2,"unit":"棵"},{"name":"鸡蛋","quantity":2,"unit":"个"},{"name":"胡椒粉","note":"适量"}]'::jsonb, '["将馒头切成小块或小片。","选有鸡蛋的话将鸡蛋打进碗里，打散（可加盐和五香粉各 1g 或不加，等炒的过程中加）。","鸡蛋浇在馒头上，拌匀，鸡蛋不宜过多。","大火热锅，倒入食用油（不锈钢锅怕伤锅的话可以先倒油，烧至油热也可也可）","将馍丁放进去翻炒，翻炒均匀。","将火调小，炒至馍丁呈金黄色。","放入盐，胡椒粉，五香粉。","最后将葱花放入一起翻炒几下。","关火出锅。"]'::jsonb, '["主食","咸香","炒","北方风味","快手","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_8ecb64c0e7.jpg', 'https://www.bilibili.com/video/BV1M5411A7B2', '{"energyKcal":540,"protein":19}'::jsonb, null),
  ('howtocook:staple/炸酱面', '炸酱面', '主食', 3, 30, '炸酱面是一道酱香浓郁、面条劲道的传统北京家常面食，搭配清爽菜码，咸甜适口。主要营养来自瘦肉蛋白质和蔬菜维生素，能为人体提供充足能量。做法对新手友好，预计制作时长约 30 分钟，熟练掌握后可通过备菜与炒酱并行进一步缩短时间。', '[{"name":"肉丁/肉末","quantity":150,"unit":"克"},{"name":"挂面","quantity":150,"unit":"克"},{"name":"普通面条","quantity":250,"unit":"克"},{"name":"葱","quantity":15,"unit":"克"},{"name":"蒜","note":"适量"},{"name":"菜码","quantity":35,"unit":"克"},{"name":"食用油","quantity":10,"unit":"克"},{"name":"豆瓣酱","quantity":20,"unit":"克"},{"name":"甜面酱","quantity":20,"unit":"克"}]'::jsonb, '["菜码切丝备用。","葱切碎。油锅烧热，下葱和肉，炒至肉完全熟透（无红色）","下豆瓣酱和甜面酱，继续炒至微微粘稠。盛出，得到炸酱。","取大碗，加凉水备用。","煮面条至断生（无白芯），盛入第 4 步装有凉水的碗中。","立即控水捞出，盛入干净的碗中。","取第 3 步炸酱，倒入碗中，拌匀。然后取第 1 步菜码，倒入碗中，拌匀。"]'::jsonb, '["主食","酱香","咸甜","炒酱","北京","家常","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_e1cdb4587c.jpg', 'https://www.bilibili.com/video/BV1Gi421a7di', '{"energyKcal":920,"protein":48,"carbs":115,"fat":29}'::jsonb, null),
  ('howtocook:staple/烙饼/烙饼', '烙饼', '主食', 4, 60, '这道家常烙饼层次分明，外皮酥脆内里柔软，带着油酥的焦香，是北方餐桌上常见的主食。主要提供碳水化合物和能量，适合搭配菜肴一起食用。制作需要一点手法，尤其卷酥和擀饼环节，但跟着步骤操作并不难，新手也能掌握。从和面到烙好，大约需要 1 个小时。', '[{"name":"面粉","quantity":400,"unit":"克"},{"name":"热水","quantity":130,"unit":"ml"},{"name":"冷水","quantity":130,"unit":"ml"},{"name":"油","note":"适量"},{"name":"电饼铛","note":"适量"}]'::jsonb, '["将 400g 面粉倒入盆中，一半用凉水和面，一半用热水和面，搅拌成面絮，用手揉成团。用保鲜膜封起来，醒面 40 分钟","离醒面完成时间还有 10 分钟时，请查看小技巧中的油酥做法（热油酥效果更好）","醒好的面不用揉，稍微摁一下，用一横刀一竖刀将其分成四份。","搓圆，擀开，擀成与电饼铛大小差不多的饼，取 1/4 的油酥，将饼表面涂抹均匀","沿饼的半径切开，从外圈将其卷成圆锥形，然后将圆锥尾部捏好，防止油酥外漏。","按压面饼圆锥尖的地方，将其压扁，然后再次擀成与电饼铛大小差不多的面饼（厚度约为 3mm）","将电饼铛预热，涂上凉油（热锅凉油），将擀好的饼放入电饼铛中，将饼的上方也刷点油，涂抹均匀（锁住水分），盖上盖子","大火烙一分钟，打开盖子，将饼翻个面再烙一分钟","重复以上动作，完成饼的烙制"]'::jsonb, '["主食","烙制","北方","家常主食","外酥里嫩","层次分明"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_38749374e8.jpg', 'https://www.bilibili.com/video/BV1PN4y1a7K3', '{"energyKcal":410,"protein":10,"carbs":76,"fat":6}'::jsonb, '[2400,null,null,null,null,null,null,120,null]'::jsonb),
  ('howtocook:staple/烧饼/芝麻烧饼', '芝麻烧饼', '主食', 3, 40, '芝麻烧饼是北方家喻户晓的面点，外皮沾满芝麻酥香可口，内层层次分明、松软适口。面粉提供充足的碳水化合物，芝麻含有丰富的钙和不饱和脂肪酸。制作过程虽然包含揉面、做油酥等步骤，但操作并不复杂，初学者也能跟着做出来。从备料到出锅大约需要 40 分钟。', '[{"name":"面粉","quantity":300,"unit":"克"},{"name":"面粉","quantity":30,"unit":"克"},{"name":"酵母粉","quantity":3,"unit":"克"},{"name":"白糖","quantity":3,"unit":"克"},{"name":"温水（40℃）","quantity":180,"unit":"克"},{"name":"食用油","quantity":20,"unit":"克"},{"name":"食用油","quantity":20,"unit":"克"},{"name":"十三香","quantity":4,"unit":"克"},{"name":"盐","quantity":2,"unit":"克"},{"name":"白芝麻","note":"适量"}]'::jsonb, '["面团：300 克面粉，3 克酵母粉，3 克白糖，180 克温水，20 克食用油，醒面 10 分钟","油酥：小碗放 30 克面粉，2 克盐，4 克十三香，20 克食用油，拌匀后，静置","做饼：面擀成长方形，抹上调好的油酥，从一头卷起，切成 7 个面剂子，对折，用虎口收拢即可，先沾水再沾白芝麻，擀成小圆饼","烙饼：将电饼铛预热，倒入凉油（锅底铺满油），将擀好的饼放入电饼铛中，将饼的上方也刷点油，涂抹均匀盖上盖子，选大饼档,听到叮的一声出锅即可"]'::jsonb, '["主食","香酥","烙制","北方","家常","面点"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_80a2becbd8.jpg', 'https://www.bilibili.com/video/BV1YA411e7Aa', null, '[600,null,null,null]'::jsonb),
  ('howtocook:staple/热干面', '热干面', '主食', 3, 15, '热干面是武汉最具代表性的小吃之一，属于鄂菜系。碱水面条筋道爽滑，裹满浓稠的芝麻酱，搭配酸豆角、萝卜干和肉末，咸香微辣，滋味醇厚。主要提供碳水化合物和蛋白质，芝麻酱也富含钙质。制作简单快捷，新手也能轻松上手，从煮面到拌好大约只需十几分钟。', '[{"name":"热干面特有的碱水面","quantity":250,"unit":"克"},{"name":"小葱","quantity":10,"unit":"克"},{"name":"酸豆角","quantity":20,"unit":"克"},{"name":"肉末","quantity":30,"unit":"克"},{"name":"蒜水","quantity":30,"unit":"ml"},{"name":"肉汤汁","quantity":30,"unit":"ml"},{"name":"萝卜干","quantity":50,"unit":"克"},{"name":"芝麻酱","quantity":40,"unit":"ml"},{"name":"辣椒油","quantity":0,"quantityMax":10,"unit":"ml"},{"name":"胡椒粉","quantity":0,"quantityMax":10,"unit":"克"},{"name":"酱油","quantity":5,"unit":"ml"},{"name":"食盐","quantity":3,"unit":"克"},{"name":"鸡精","quantity":0,"quantityMax":3,"unit":"克"}]'::jsonb, '["水煮沸，并加入碱水面，焯烫 25 秒钟捞起","撒上食盐、鸡精和胡椒粉","芝麻酱用 90ml 水稀释，搅匀，然后加入","加入 5ml 酱油，加入 30ml 肉汤汁和蒜水","加入萝卜干，肉末，酸豆角，葱花","拌均匀后开吃"]'::jsonb, '["主食","武汉","小吃","拌面","快手","咸香微辣","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_5eef68f6ee.jpg', 'https://www.bilibili.com/video/BV1yK411H7kr', '{"energyKcal":650,"protein":20,"carbs":70,"fat":28}'::jsonb, '[25,null,null,null,null,null]'::jsonb),
  ('howtocook:staple/煮泡面加蛋', '煮泡面加蛋', '主食', 1, 10, '煮泡面加蛋是一道便捷的快手主食，口感顺滑，汤味浓郁，适合随时填饱肚子。主要提供碳水化合物和蛋白质，能快速补充能量。做法极其简单，只需烧水、煮面、打入鸡蛋煮熟，新手也能轻松掌握，全程大约 10 分钟即可完成。', '[{"name":"泡面","quantity":1,"unit":"包"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"水","quantity":550,"quantityMax":1000,"unit":"ml"}]'::jsonb, '["先将水加热至沸腾（火候不做严格要求，使用热水会更快）","将取出的面饼放入锅中","将泡面里附带的佐料放入锅中","取出筷子轻微拨动泡面，使佐料充分溶解，面饼充分浸泡受热","盖上锅盖等待约 1 分钟至锅内水再次沸腾","去壳鸡蛋，加入锅中","等待约 3 至 4 分钟，即可"]'::jsonb, '["主食","快手","家常","煮","鲜香","饱腹"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_3672bf71ca.jpg', 'https://www.bilibili.com/video/BV1Br4y1M7oE', '{"energyKcal":380,"protein":14}'::jsonb, '[null,null,null,null,60,null,240]'::jsonb),
  ('howtocook:staple/照烧鸡腿饭', '照烧鸡腿饭', '主食', 4, 30, '照烧鸡腿饭是一道甜咸适口的下饭菜，鸡腿煎得焦香后融入浓郁酱汁，口感嫩滑入味。鸡腿肉富含优质蛋白，搭配西兰花和胡萝卜能补充膳食纤维与维生素。制作稍需一点去骨技巧，但整体不复杂，新手跟着步骤也能成功。从备料到出锅，大约 30 分钟就能端上餐桌。', '[{"name":"鸡腿","quantity":500,"unit":"g"},{"name":"料酒","quantity":15,"unit":"ml"},{"name":"生抽","quantity":30,"unit":"ml"},{"name":"蜂蜜","quantity":15,"unit":"ml"},{"name":"黑椒碎","quantity":5,"unit":"g"},{"name":"黑椒粉","quantity":5,"unit":"g"},{"name":"盐","quantity":2.5,"unit":"g"},{"name":"西兰花","quantity":50,"unit":"g"},{"name":"胡萝卜","quantity":50,"unit":"g"},{"name":"老抽","quantity":12,"unit":"ml"},{"name":"大蒜","quantity":10,"unit":"g"},{"name":"生姜","quantity":10,"unit":"g"},{"name":"食用油","quantity":15,"quantityMax":25,"unit":"ml"},{"name":"清水","quantity":30,"unit":"ml"},{"name":"米饭","quantity":300,"quantityMax":400,"unit":"g"}]'::jsonb, '["取一只鸡腿，鸡皮朝下放在砧板上","用刀尖沿着鸡腿骨头的轮廓轻轻划开，从一端到另一端","用手指或刀背慢慢推开鸡肉，让骨头暴露出来。如果遇到筋膜，用刀尖切断","当鸡肉完全分离后，握住骨头一端，轻轻扭转并拔出","重复上述步骤将所有鸡腿去骨","去骨鸡腿加入黑胡椒粉、黑胡椒碎、盐、姜片腌制 5 分钟","碗里加入料酒、生抽、蜂蜜、老抽清水拌匀","蔬菜焯水 1-2 分钟煮熟捞起","热锅放油 15 ml 放入拍碎的大蒜爆香","放入鸡腿中小火煎至两面金黄，如果感觉锅中太干，补 5-10 ml 油","加入调好的酱汁，盖好盖子中小火（在燃气灶上使用小火）焖 5-10 分钟熟透，酱汁浓稠起泡即可","切件，和蔬菜一起摆在饭面，淋入煎鸡腿的酱汁就可以慢慢享用啦"]'::jsonb, '["主食","甜咸","煎焖","日式","下饭","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_c7f7bad177.jpg', 'https://www.bilibili.com/video/BV1eT4y1o7Yv', '{"energyKcal":799,"protein":51.3,"carbs":65.3,"fat":34.2}'::jsonb, '[null,null,null,null,null,300,null,null,null,null,null,null]'::jsonb),
  ('howtocook:staple/蒸卤面', '蒸卤面', '主食', 4, 60, '这是一道豫南地区经典的家常面食，荤素搭配，面条吸足汤汁，口感软韧，咸香入味。五花肉提供优质蛋白质和脂肪，芹菜富含膳食纤维。做法简单易学，新手也能从容上手，整体制作约需一小时。', '[{"name":"五花肉","quantity":350,"unit":"克"},{"name":"鲜面条","quantity":500,"unit":"克"},{"name":"芹菜","quantity":2,"unit":"根"},{"name":"大葱","quantity":10,"unit":"厘米"},{"name":"姜","quantity":20,"unit":"克"},{"name":"大蒜","quantity":5,"unit":"瓣"},{"name":"青椒","quantity":2,"unit":"个"},{"name":"干红椒","quantity":3,"unit":"个"},{"name":"花椒","quantity":20,"unit":"粒"},{"name":"盐","quantity":10,"unit":"克"},{"name":"五香粉","quantity":5,"unit":"克"},{"name":"生抽","quantity":15,"unit":"ml"},{"name":"老抽","quantity":10,"unit":"ml"},{"name":"食用油（花生油最佳）","note":"适量"},{"name":"料酒","note":"适量"}]'::jsonb, '["猪肉去皮，切成 2 cm 6 cm 0.5 cm 薄片备用","芹菜去叶，去掉根部 2cm，然后从中对半切开，切成 2cm 段备用","大蒜去皮切粒备用，葱切 0.2cm 薄片备用，姜切细丝备用","炒锅烧热至冒烟后，倒入 3ml 食用油滑锅后倒出底油","重新加入食用油，加入肉片，葱姜蒜，干红椒，炒 1 分钟，注意不停匀速翻炒","加入料酒，生抽，老抽，再翻炒 1 分钟","续入 500ml 热水。盖上锅盖炖煮 3 分钟","将芹菜，青椒倒入锅中，加入盐，五香粉调味，盖上锅盖继续炖煮煮 3 分钟 后关火","蒸锅加入 1000ml 水，烧开上汽后，将面条摊平在笼屉上放入锅中，蒸 15 分钟","面条蒸熟后取出，用筷子和无情铁手扒拉散开在案板上，室温冷却","将面条放入菜锅中搅拌，搅拌方式为一手持筷，一手持锅铲将菜翻至面条上面，以面条以全部均匀上色为搅拌完成标准","将搅拌后的面条再次放在整屉上，再次蒸 10 分钟 关火"]'::jsonb, '["主食","咸香","蒸制","豫南","家常","荤素搭配"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_a970159ab8.jpg', 'https://www.bilibili.com/video/BV1r2wczoEwu', '{"energyKcal":1100,"protein":32,"carbs":95,"fat":55}'::jsonb, '[null,null,null,null,60,60,180,180,900,null,null,600]'::jsonb),
  ('howtocook:staple/猪油拌饭', '猪油拌饭', '主食', 1, 5, '这是一道充满南方家常气息的简单拌饭，米粒被融化的猪油包裹，透着酱油的咸鲜和葱花的清香，是许多孩子食欲不振时的安心之选。主要提供快速碳水与脂肪能量，但胆固醇较高，不宜常吃。制作毫无门槛，哪怕完全不会做饭也能轻松完成，煮好的米饭只要几分钟就能拌出一碗香喷喷的主食。', '[{"name":"米饭（推荐用粳米）","quantity":200,"unit":"克"},{"name":"猪油","quantity":15,"unit":"克"},{"name":"生抽（推荐用李锦记或海天）","quantity":5,"unit":"ml"},{"name":"老抽","quantity":2,"unit":"ml"},{"name":"蚝油（可选）","quantity":8,"unit":"克"},{"name":"葱花（可选）","quantity":0,"quantityMax":12,"unit":"克"},{"name":"猪油渣（可选）","quantity":5,"unit":"克"}]'::jsonb, '["碗底铺猪油","加入米饭","淋上酱油与蚝油","撒上葱花和猪油渣","搅拌均匀"]'::jsonb, '["主食","咸鲜","拌饭","快手","家常","南方","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_35d12ee227.jpg', 'https://www.bilibili.com/video/BV17ZtCz6Exh', '{"energyKcal":440,"protein":7,"carbs":56,"fat":17}'::jsonb, null),
  ('howtocook:staple/电饭煲三文鱼炊饭/电饭煲三文鱼炊饭', '电饭煲三文鱼炊饭', '主食', 2, 45, '这是一道融合日式炊饭做法的家常料理，米饭吸饱牛油和三文鱼的香气，口感浓郁鲜香。三文鱼提供优质蛋白和不饱和脂肪酸，搭配菌菇更添膳食纤维。操作极其简单，只需用电饭煲一键完成，从备料到出锅大约 45 分钟，非常适合新手尝试。', '[{"name":"米","quantity":50,"unit":"g"},{"name":"三文鱼","quantity":300,"unit":"g"},{"name":"有盐牛油","quantity":1,"unit":"汤匙"},{"name":"水","note":"适量"},{"name":"粟米（可选）","note":"适量"},{"name":"金菇（可选）","note":"适量"},{"name":"冬菇（可选）","note":"适量"}]'::jsonb, '["三文鱼去鳞，去骨","金菇、冬菇切碎","洗米三次","把三文鱼、米、牛油放入电饭煲","想口感浓厚一点，可以加多一汤匙牛油","根据电饭煲的刻度放水","把电饭煲調較至煲飯模式，等待大約 30 - 45 分鐘"]'::jsonb, '["主食","鲜香","电饭煲","家常","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_74ac5e4288.webp', 'https://www.bilibili.com/video/BV111bbzjE1h', '{"energyKcal":900,"protein":64,"carbs":39,"fat":50}'::jsonb, null),
  ('howtocook:staple/空气炸锅照烧鸡饭/空气炸锅照烧鸡饭', '空气炸锅照烧鸡饭', '主食', 4, 60, '这道日式照烧风味的鸡肉饭，甜咸酱汁浓郁，表层烘烤得略微焦脆，内里软嫩多汁，搭配米饭非常下饭。鸡肉和鸡蛋提供丰富的优质蛋白，不过酱油和糖的用量较多，更适合偶尔改善口味。做法简单，只需混合原料交给空气炸锅，新手也能轻松搞定，从准备到出锅大约需要 1 小时。', '[{"name":"鸡肉","quantity":900,"unit":"g"},{"name":"酱油","quantity":100,"quantityMax":125,"unit":"ml"},{"name":"糖","quantity":60,"quantityMax":65,"unit":"g"},{"name":"白醋","quantity":30,"quantityMax":35,"unit":"ml"},{"name":"丽滋饼干","quantity":16,"unit":"个"},{"name":"鸡蛋","quantity":2,"unit":"个"},{"name":"米饭","note":"适量"}]'::jsonb, '["将酱油、糖和醋混合在一起,搅匀料汁备用","另一个碗中加入鸡肉、鸡蛋、1/2 料汁和压碎的丽滋饼干。搅拌均匀","空气炸锅用箔纸碗铺底，加入肉饼混合物，将剩余的料汁均匀的倒在上面","350°F(177°C) 炸40 分钟。最好在米饭上食用","在外观呈金黄酥脆后出锅，切块盛盘"]'::jsonb, '["主食","甜咸","空气炸锅","日式","下饭","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_b8d81b8742.jpg', 'https://www.bilibili.com/video/BV1gd4y1T7Lp', '{"energyKcal":670,"protein":60,"carbs":68,"fat":18}'::jsonb, '[null,null,null,2400,null]'::jsonb),
  ('howtocook:staple/米饭/煮锅蒸米饭', '煮锅蒸米饭', '主食', 2, 25, '这是一道朴实无华的家常主食，用普通煮锅就能做出软糯适口的米饭。白米饭主要提供碳水化合物，为身体快速补充能量。做法极为简单，新手只需全程关注火候即可轻松掌握，从下米到出锅大约需要 25 分钟。', '[{"name":"北方大米","quantity":100,"quantityMax":200,"unit":"ml"},{"name":"水","note":"适量"}]'::jsonb, '["清洗大米","将米和水加入煮锅","大火煮至水沸腾","搅拌底部防止粘黏","盖上锅盖，转小火加热 10-15 分钟（根据对软糯程度的喜好），中途切勿打开锅盖","关火，静置 5 分钟","Enjoy :)"]'::jsonb, '["主食","清淡","软糯","煮","家常","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_5fc5aedb37.jpeg', 'https://www.bilibili.com/video/BV1L3411B7Mx', '{"energyKcal":280,"protein":5.6,"carbs":62,"fat":0.8}'::jsonb, '[null,null,null,null,600,300,null]'::jsonb),
  ('howtocook:staple/米饭/电饭煲蒸米饭', '电饭煲蒸米饭', '主食', 1, 40, '一道家喻户晓的基础主食，米香纯粹、口感软糯，因水量调节可偏硬或偏润。富含碳水化合物，能快速补充能量，适合搭配各类菜肴。操作极其简单，新手也能轻松上手，从洗米到焖好大约需要四十分钟。', '[{"name":"江南米或北方大米","quantity":100,"quantityMax":200,"unit":"ml"},{"name":"水","note":"适量"}]'::jsonb, '["清洗米","将米和水一起加入电饭煲中。","连接电饭煲电源，进入加热模式。等待大约 30 分钟。","待电饭煲自动进入保温模式后。","将米在电饭煲中闷 10-15 分钟。","盛出米。"]'::jsonb, '["主食","清淡","快手","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_9f5f37d569.jpg', 'https://www.bilibili.com/video/BV1tN411i7dY', '{"energyKcal":200,"protein":4,"carbs":44,"fat":0.5}'::jsonb, '[null,null,1800,null,600,null]'::jsonb),
  ('howtocook:staple/红芸豆拌饭', '红芸豆拌饭', '主食', 3, 45, '这道北印度家常菜是旁遮普邦和德里地区的传统美食，番茄洋葱汤汁浓郁辛香，炖煮后红芸豆软糯入味，与热米饭拌食温暖饱腹。豆子富含蛋白质、膳食纤维和多种微量元素，营养均衡。做法简单，初学者也能轻松上手，全程制作约 40 分钟，但干豆需提前浸泡 8 小时。浓郁的家常滋味，有妈妈的味道。', '[{"name":"干红芸豆","quantity":200,"unit":"克"},{"name":"洋葱","quantity":2,"unit":"个"},{"name":"番茄","quantity":3,"unit":"个"},{"name":"番茄酱","quantity":30,"unit":"ml"},{"name":"生姜","quantity":10,"unit":"克"},{"name":"大蒜","quantity":4,"unit":"瓣"},{"name":"青辣椒","quantity":1,"unit":"根"},{"name":"食用油或酥油","quantity":30,"unit":"ml"},{"name":"月桂叶","quantity":2,"unit":"片"},{"name":"姜黄粉","quantity":3,"unit":"克"},{"name":"红辣椒粉","quantity":5,"unit":"克"},{"name":"香菜粉","quantity":5,"unit":"克"},{"name":"孜然粉","quantity":3,"unit":"克"},{"name":"印度综合香料粉","quantity":3,"unit":"克"},{"name":"盐","quantity":6,"unit":"克"},{"name":"水","quantity":600,"unit":"ml"},{"name":"香菜叶","quantity":15,"unit":"克"},{"name":"大米","quantity":200,"unit":"克"},{"name":"水","quantity":400,"unit":"ml"}]'::jsonb, '["将干红芸豆用清水浸泡至少 8 小时（过夜），浸泡后体积会膨胀约两倍","将浸泡好的红芸豆沥干","使用高压锅：放入红芸豆和 600ml 水，盖好锅盖，大火上气后转中火，压 15-20 分钟，直至豆子用手指可轻松压碎","使用普通锅：放入红芸豆和足量水，大火煮沸后转中火，煮 60-90 分钟，直至豆子完全软烂","煮好后保留煮豆汤水，备用","在炒锅中倒入 30ml 食用油，中火加热","放入月桂叶 2 片，炸至散出香味（约 10 秒）","放入切碎的洋葱，翻炒至金棕色（约 6-8 分钟）","加入磨碎的生姜和大蒜，翻炒 1 分钟","加入切碎的番茄，翻炒至番茄完全软烂出油（约 5 分钟）","加入姜黄粉 3g、红辣椒粉 5g、香菜粉 5g、孜然粉 3g、盐 6g","翻炒 2 分钟，使香料与番茄融合","将煮好的红芸豆连同汤水一起倒入锅中","加入青辣椒，搅拌均匀","大火煮沸后转小火，炖 15-20 分钟","期间用铲子背面压碎一部分豆子，使汤汁变得浓稠","加入印度综合香料粉 3g，搅拌均匀","关火，撒上香菜叶","将大米淘洗干净","放入电饭锅，加入 400ml 水","正常蒸煮即可","将米饭盛入盘中","将红芸豆咖喱浇在米饭上或旁边","可搭配洋葱沙拉和柠檬角"]'::jsonb, '["主食","北印度","炖菜","辛香","下饭","家常","咖喱"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_2582117da9.jpg', 'https://www.bilibili.com/video/BV1cv4y1q7LN', '{"energyKcal":580,"protein":22}'::jsonb, null),
  ('howtocook:staple/老友猪肉粉/老友猪肉粉', '老友猪肉粉', '主食', 3, 40, '老友猪肉粉酸辣鲜香，米粉爽滑，带着豆豉与酸笋特有的浓郁风味，是典型的南宁家常味。猪肉提供优质蛋白质，米粉则快速补充碳水能量。整体制作中等难度，需注意提前泡发米粉，熟练后大约四十分钟就能端上桌。', '[{"name":"米粉","quantity":250,"unit":"克"},{"name":"猪肉","quantity":50,"unit":"克"},{"name":"酸笋","quantity":50,"unit":"克"},{"name":"剁椒","quantity":15,"unit":"克"},{"name":"豆豉","quantity":30,"unit":"克"},{"name":"大蒜","quantity":10,"unit":"克"},{"name":"料酒","quantity":10,"quantityMax":20,"unit":"ml"},{"name":"生抽","quantity":15,"unit":"ml"},{"name":"白糖","quantity":5,"unit":"克"},{"name":"米醋","quantity":5,"unit":"ml"},{"name":"盐","quantity":5,"unit":"ml"},{"name":"油","quantity":15,"unit":"ml"},{"name":"生粉","quantity":15,"unit":"ml"},{"name":"胡椒粉","quantity":10,"unit":"ml"}]'::jsonb, '["全部猪肉用料酒、盐、生抽、生粉、胡椒粉倒在一个碗里调味,备用","热锅不放油,下全部酸笋把水份炒干，炒干的酸笋中间留点空间","放入 10ml - 15ml 食用油与全部大蒜、 剁椒、 豆豉到炒干的酸笋中间到炒干的酸笋中间,全部推到中间炒出香味","放入全部调味好的猪肉,持续放入 10ml 生抽炒一分钟","放入 5ml 米醋、 10ml 生抽、450ml 清水一起煮开","水煮开后,放入温水泡好的米粉,继续煮 3 分钟就可以盛盘"]'::jsonb, '["主食","酸辣","煮制","南宁风味","家常","米粉"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_3986d7384c.jpg', 'https://www.bilibili.com/video/BV1pJ411p7x1', '{"energyKcal":1200,"protein":35,"carbs":215,"fat":22}'::jsonb, '[null,null,null,60,null,180]'::jsonb),
  ('howtocook:staple/老干妈拌面', '老干妈拌面', '主食', 1, 10, '一道香辣开胃的家常快手面食，面条筋道裹满老干妈的豆豉辣香，酱油提鲜，简单却滋味十足。作为主食能快速补充碳水化合物和能量，辣椒素还有助促进食欲。制作毫无门槛，新手也能轻松驾驭，从烧水到出锅只需大约十 分钟。', '[{"name":"水","quantity":1,"unit":"升"},{"name":"面","quantity":120,"unit":"克"},{"name":"老干妈","quantity":15,"unit":"ml"},{"name":"酱油","quantity":5,"unit":"ml"}]'::jsonb, '["将水倒入锅中并煮沸","将面均匀放入锅中","在煮的过程注意搅拌，避免面粘成一坨","当用筷子挑起一根面且该面能自然地从筷子上滑落时再等 30 秒关火","将面夹入碗中","按照上面的计量放入老干妈和酱油","用筷子将碗里的面、老干妈、酱油拌均匀","吃"]'::jsonb, '["主食","香辣","拌面","快手","家常","开胃"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_fd8d028044.jpg', 'https://www.bilibili.com/video/BV1C44y187PE', '{"energyKcal":450,"protein":15,"carbs":86,"fat":11}'::jsonb, null),
  ('howtocook:staple/肉蛋盖饭', '肉蛋盖饭', '主食', 3, 15, '这道菜酱香浓郁、咸甜适口，肉馅焦香、鸡蛋嫩滑，盖在热米饭上十分满足，属于家常快手料理。富含优质蛋白质和必需氨基酸，能快速补充能量。做法简单直观，新手也能轻松上手，从备料到出锅大约只需十五分钟。', '[{"name":"米饭","quantity":240,"unit":"g"},{"name":"鸡蛋","quantity":4,"unit":"个"},{"name":"肉馅","quantity":300,"unit":"g"},{"name":"老抽","quantity":10,"unit":"ml"},{"name":"生抽","quantity":25,"unit":"ml"},{"name":"醋","quantity":20,"unit":"ml"},{"name":"红葱油","quantity":10,"unit":"g"},{"name":"葱","quantity":10,"unit":"g"},{"name":"油","quantity":30,"unit":"ml"},{"name":"糖","quantity":15,"unit":"g"}]'::jsonb, '["煮好米饭，通常使用买米赠送的量杯，一杯米 240g","锅中放油 30ml","放入肉馅，调中火煎至两面微焦","将鸡蛋打入锅中，不要打散，盖上锅盖","调一个碗汁，碗中放入计算中的对应数量的老抽，生抽，醋，糖，红葱油，搅拌均匀","打开锅盖，将碗汁倒入锅中，等待三分钟","关火，将肉蛋盖到米饭上","安全检查，开始食用盖饭"]'::jsonb, '["主食","酱香","咸甜","快手","下饭","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_aeb55137ca.jpg', 'https://www.bilibili.com/video/BV1Jf4y1X7k9', '{"energyKcal":1150,"protein":55,"carbs":75,"fat":70}'::jsonb, '[null,null,null,null,null,180,null,null]'::jsonb),
  ('howtocook:staple/茄子肉煎饼/茄子肉煎饼', '茄子肉煎饼', '主食', 3, 30, '这道家常煎饼融合了腊肉的咸香与茄子的软糯，外皮酥脆、内里绵润，是一道充满乡土风味的米粉主食。它富含碳水化合物和优质蛋白质，茄子还能提供膳食纤维和维生素，荤素搭配营养均衡。制作难度中等，需要掌握面糊稠度和煎制火候，但初学者跟着步骤操作也能成功。从备料到出锅大约需要 30 分钟。', '[{"name":"米粉","quantity":250,"unit":"克"},{"name":"面粉","quantity":50,"unit":"克"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"熟腊肉","quantity":100,"unit":"克"},{"name":"茄子","quantity":1,"unit":"根"},{"name":"食用油","quantity":10,"quantityMax":15,"unit":"ml"},{"name":"食盐","quantity":1,"quantityMax":2,"unit":"克"}]'::jsonb, '["将茄子去皮后切成片，将腊肉切成片，备用","依次向盆中加入 250g 米粉（大米研磨成的粉）、50g 面粉和 1 个鸡蛋","边用筷子搅拌，边加入清水（清水用于调节粘稠度），使米粉、面粉、鸡蛋混合成面糊,当面糊能够附着在茄片、肉片上而不掉落时停止加水，而后将所有茄片和肉片放入面糊中，用面糊充分包裹","平底锅加入食用油10-30ml，开小火","用筷子或勺子把裹了面糊的茄片、肉片放入锅中，先煎至两面金黄，再煎3-6分钟（煎的过程中，食用油会变少，可再添加食用油）","撒盐，翻炒均匀，起锅装盘"]'::jsonb, '["主食","咸香","煎制","家常","乡土风味","营养均衡"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_407c6e48d0.jpg', 'https://www.bilibili.com/video/BV1KW411c79P', '{"energyKcal":560,"protein":15,"carbs":74,"fat":18}'::jsonb, null),
  ('howtocook:staple/葱油拌面', '葱油拌面', '主食', 2, 30, '葱油拌面是一道经典的上海家常面点，以独特的葱油香味著称，做法简单快捷。富含碳水化合物和脂肪，能快速补充能量。一般初学者只需 20 分钟即可完成，非常适合作为日常快手晚餐。', '[{"name":"干面条","quantity":80,"unit":"克"},{"name":"小葱","quantity":100,"unit":"克"},{"name":"生抽","quantity":60,"unit":"ml"},{"name":"老抽","quantity":20,"unit":"ml"},{"name":"白糖","quantity":15,"unit":"克"},{"name":"食用油","quantity":100,"unit":"ml"}]'::jsonb, '["将 小葱 洗净，切成长段（约 5-7 cm）。葱白和葱绿可以分开。","锅中加入 100 ml 食用油，中火烧热。先放入葱白段，煸炒至微黄。","加入葱绿段，转小火，继续煸炒。","保持小火，耐心煸炒约 15-20 分钟，直至葱段变得焦黄酥脆。","将焦黄的葱段捞出（葱油保留在锅中）。","在锅中的葱油中，加入 60 ml 生抽，20 ml 老抽，15 g 白糖。小火加热并搅拌，约 1 分钟，至糖溶解，酱汁混合均匀。立即关火。将制作好的葱油酱汁倒入容器中，放凉后密封保存。","取 80 g 干面条。","锅中加入 1000 ml 饮用水，大火烧开。","放入 面条，根据面条包装说明，煮至熟透（通常 3-8 分钟，以包装说明为准）。","将 煮好的 面条 捞出，沥干水分，放入碗中。","在装有 面条 的碗中，加入 15 ml 之前做好的 葱油酱汁。","可以加入之前炸好的葱段（可选）。","用 筷子 快速搅拌均匀，即可食用。"]'::jsonb, '["主食","上海","鲜香","快手","家常","拌面"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_396dbe6087.jpg', 'https://www.bilibili.com/video/BV1TgbGzKEiQ', '{"energyKcal":410,"protein":11,"carbs":60,"fat":16}'::jsonb, '[null,null,null,null,null,60,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:staple/蛋包饭', '蛋包饭', '主食', 3, 25, '以嫩滑蛋皮包裹茄汁炒饭，口感丰富，酸甜开胃，是一道经典的日式家庭料理。富含蛋白质、碳水和多种维生素，营养均衡。包裹蛋皮需要一点技巧，但整体难度适中，新手也可尝试，从准备到完成约需 25 分钟。', '[{"name":"鸡蛋","quantity":2,"unit":"个"},{"name":"洋葱","quantity":30,"unit":"克"},{"name":"胡萝卜","quantity":30,"unit":"克"},{"name":"玉米粒、青豆（可选）","quantity":30,"unit":"克"},{"name":"火腿肠或鸡胸肉","quantity":50,"unit":"克"},{"name":"米饭","quantity":200,"unit":"克"},{"name":"番茄酱","quantity":20,"unit":"ml"},{"name":"食用油","quantity":15,"unit":"ml"},{"name":"牛奶（可选）","quantity":10,"unit":"ml"}]'::jsonb, '["洋葱、胡萝卜、火腿肠或鸡胸肉切成小丁，备用","热锅，锅中倒入 10ml 食用油，等待 10 秒加热","先放入洋葱丁翻炒 1 分钟，出香味后加入胡萝卜、玉米粒、青豆继续翻炒 2 分钟","加入火腿肠或鸡胸肉丁，炒至变色","加入米饭炒散后，加入番茄酱 20ml，翻炒均匀，炒饭完成，盛出备用","鸡蛋打散，加入 10ml 牛奶搅匀","锅中放入 5ml 食用油，倒入蛋液，轻晃锅底让蛋液均匀铺满锅面","用小火加热，待蛋液表面半熟状态时，将炒饭放入蛋液中央","用铲子将蛋皮折叠包住米饭，形成椭圆形状","用锅铲轻轻推至盘中，整理外形，可在表面挤上少量番茄酱装饰"]'::jsonb, '["主食","酸甜","炒制","快手","家常","日式","开胃"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_168ceaad4c.jpg', 'https://www.bilibili.com/video/BV1Y7411377f', '{"energyKcal":650,"protein":28,"carbs":73,"fat":28}'::jsonb, '[null,10,180,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:staple/蛋炒饭', '蛋炒饭', '主食', 3, 25, '一道家常蛋炒饭，金黄的蛋丝裹着粒粒分明的米饭，搭配火腿、胡萝卜和黄瓜，口感丰富，咸香适口。鸡蛋提供优质蛋白，胡萝卜增添维生素，碳水化合物带来充足能量。制作步骤稍多，但新手按流程操作也能成功，全程大约需要 25 分钟。', '[{"name":"冷饭","quantity":500,"unit":"ml"},{"name":"鸡蛋"},{"name":"火腿","quantity":2,"unit":"个"},{"name":"黄瓜","quantity":30,"unit":"克"},{"name":"胡萝卜","quantity":30,"unit":"克"},{"name":"油","quantity":12,"unit":"ml"},{"name":"盐","quantity":4,"quantityMax":6,"unit":"克"},{"name":"胡椒粉","quantity":8,"unit":"克"},{"name":"香葱","quantity":1,"unit":"颗"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"灯影牛肉丝/午餐肉/腊肠/卤肉等熟肉（备选）","note":"适量"}]'::jsonb, '["米饭提前用铲子铲成小块","火腿肠、胡萝卜、黄瓜等根据需求切片或者块状","如果家里有熟肉 准备好味道更佳","将蛋白，蛋黄分开，分别打入一个大碗里，各自搅匀。注意，不要在这一步加盐。","大火热锅，待锅里冒烟放入食用油，放入蛋白，待主体凝固后盛出备用。","如果油够，则直接放入蛋黄，如果油不够则放入食用油并等其升温到大火热锅","待主体凝固后，将火调至中小火，倒入火腿肠、熟肉，胡萝卜、黄瓜等备料、翻炒 10 秒钟（到爆香）","重新倒入蛋白，翻炒 5s 钟，迅速倒入米饭大火翻炒，为的就是每一粒饭都裹上鸡蛋。","翻炒过程中将米饭的块状捣碎、这一步过程会比较长、待米饭全部捣碎再翻炒均匀即可","调至小火、加盐、胡椒粉、生抽","进一步翻炒均匀，能看到一些米饭在锅里有“跳起来”的时候其实就已经差不多了","最后倒入香葱再翻炒 10s","关火、盛入碗中"]'::jsonb, '["主食","咸香","家常","快手","炒","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_6dbff3bcad.jpg', 'https://www.bilibili.com/video/BV1Dg4y1t7An', null, null),
  ('howtocook:staple/螺蛳粉', '螺蛳粉', '主食', 1, 10, '螺蛳粉是广西柳州的特色小吃，汤鲜味浓，酸辣爽口，米粉软滑筋道。口味上融合了螺蛳汤的鲜美、酸笋的独特发酵风味和辣椒油的刺激，层次分明。作为主食，米粉提供充足碳水化合物，螺蛳肉包和配料带来一定蛋白质，酸笋则有助于开胃促消化。这道菜所需操作简单，只需按顺序煮熟米粉和调味即可，对新手非常友好。从烧水到出锅，最快约十分钟就能端上餐桌，适合快手解决一餐。', '[{"name":"袋装螺蛳粉","quantity":1,"unit":"包"},{"name":"水","quantity":1,"unit":"L"},{"name":"米粉","note":"适量"},{"name":"螺蛳肉包","note":"适量"},{"name":"汤料包","note":"适量"},{"name":"酸笋包","note":"适量"},{"name":"花生包","note":"适量"},{"name":"豆皮包","note":"适量"},{"name":"木耳包","note":"适量"},{"name":"醋包","note":"适量"},{"name":"辣椒油","note":"适量"}]'::jsonb, '["锅中加水，将水烧开","下米粉，煮 3-5 分钟，期间用筷子搅拌，防止米粉粘在一起","下汤料包，按个人口味添加","下一部分配料包，如木耳，花生，螺蛳（这部分配料需要煮一会才入味）","下调味包，按个人口味添加","搅拌后捞出，放入碗中","下剩下的配料包，如酸笋，豆皮（这部分配料不适合被汤泡太久）","享用美食"]'::jsonb, '["主食","酸辣","鲜香","快手","广西风味","汤粉"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_25c54c4cea.jpg', 'https://www.bilibili.com/video/BV1FK4y1n7Gb', '{"energyKcal":600,"protein":10,"carbs":90,"fat":20}'::jsonb, null),
  ('howtocook:staple/西红柿鸡蛋挂面/西红柿鸡蛋挂面', '西红柿鸡蛋挂面', '主食', 2, 20, '西红柿鸡蛋挂面是一道家常快手面食，酸甜咸鲜，汤汁浓郁，面条劲道，属于融入北方风味的日常主食。鸡蛋提供优质蛋白，西红柿富含番茄红素和维生素，搭配碳水主食，营养均衡。操作简单，步骤清晰，对新手友好，从备料到完成大约只需 20 分钟。', '[{"name":"挂面","quantity":50,"quantityMax":100,"unit":"克"},{"name":"西红柿","quantity":1,"unit":"个"},{"name":"鸡蛋","quantity":1,"quantityMax":2,"unit":"个"},{"name":"盐","quantity":5,"unit":"克"},{"name":"葱","note":"适量"},{"name":"蒜","note":"适量"},{"name":"青椒","note":"适量"},{"name":"食用油","quantity":20,"unit":"克"},{"name":"酱油","quantity":5,"quantityMax":8,"unit":"克"},{"name":"蚝油","quantity":5,"unit":"克"},{"name":"鸡精","quantity":3,"unit":"克"},{"name":"白砂糖","quantity":2,"unit":"克"},{"name":"香油","quantity":5,"unit":"克"},{"name":"白醋","quantity":2,"unit":"克"},{"name":"清水","note":"适量"}]'::jsonb, '["小葱洗净并切成葱花","西红柿切块儿，如果不太会切建议先百度一下~","青椒切成菱形块","生鸡蛋打入一个小碗并打散，如果鸡蛋有点腥味可以加 2g 白醋去腥","起锅烧热，倒入 15~20g 食用油，鸡蛋炒嫩滑就得多一点油，同时为后面煸炒西红柿留一些底油","待油温到七成热时（手掌隔大概 10cm，能感觉到热），倒入蛋液快速划散","鸡蛋滑到凝固后，一点不会有蛋液了后倒入小碗备用，此处留一些底油","锅中留底油后先加入葱白、蒜末炒香","加入西红柿块、青椒，待西红柿炒出一点汁水","此时速速加入 5g 酱油和 2g 白砂糖","翻炒十几秒后加入一碗清水（刚刚好即将没过西红柿即可）","煮沸后加入炒好的鸡蛋，加入蚝油 5g 或者 2g 鸡精用于提鲜","中小火收汁，期间要搅拌防止粘锅，收汁到下图后加一点葱花（剩下的葱绿部分）和香油（不加也可以），臊子制作完成","可以不用洗锅，直接加清水 500ml","煮沸加入挂面，挂面煮软后加入 100ml 清水","再次煮沸后，若面条飘起来了，再加入 100ml 清水","煮沸后看面条两侧是否呈透明状，透明状则熟了","捞面到臊子碗中，拌面即可啦~"]'::jsonb, '["主食","家常","快手","酸甜","面食","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_cd767a11cc.jpg', 'https://www.bilibili.com/video/BV1w14y1c7vF', '{"energyKcal":630,"protein":21,"carbs":66,"fat":34}'::jsonb, null),
  ('howtocook:staple/豆角焖面/豆角焖面', '豆角焖面', '主食', 3, 30, '豆角焖面是一道北方家常面食，面条吸饱汤汁，口感软韧咸香，带着豆角的清爽和肉片的油润。五花肉提供蛋白质和脂肪，豆角富含膳食纤维和维生素，荤素搭配均衡。整体操作不难，但需要留意火候和加汤时机，适合有一定下厨经验的朋友尝试，一般约 30 分钟就能端上桌。', '[{"name":"鲜面条","quantity":300,"unit":"克"},{"name":"五花肉","quantity":100,"unit":"克"},{"name":"豆角","quantity":150,"unit":"克"},{"name":"食用油","quantity":10,"quantityMax":18,"unit":"ml"},{"name":"盐","quantity":2,"unit":"克"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"老抽","quantity":5,"unit":"ml"},{"name":"耗油","quantity":5,"unit":"克"},{"name":"十三香","quantity":1,"unit":"克"},{"name":"鸡精","quantity":2,"unit":"克"},{"name":"味精","quantity":1,"unit":"克"},{"name":"葱","quantity":10,"unit":"克"},{"name":"姜","quantity":5,"unit":"克"},{"name":"蒜头","quantity":10,"unit":"克"},{"name":"热水","quantity":150,"unit":"ml"}]'::jsonb, '["将豆角切成 5cm - 6cm 的小段。","将葱切成 1cm - 2cm 小段。","将姜切成 1mm x 1mm x 3cm 的长条","将蒜放在砧板上拍碎，切成 1mm 的粒度。","将五花肉切成 2mm 厚度的肉片。","首先将锅烧热，烧去锅内全部水汽，手放过内距离锅底 10cm 处，感觉明显有些许烤手。","加入上述定量的食用油，手持锅柄，离灶 5cm 处，摇晃锅，使食用油充分挂满锅的三分之二（自下而上）。","放入全部的姜和全部的葱段，翻炒爆香 5 秒（注意！此时有油飞溅的危险，建议带上手套或做好防护措施）。","放入全部的肉片，放入以后不着急饭锅，静置 5 秒后，再翻炒，使所有的肉都裹满食用油。","不断翻炒肉片，待到全部肉片都已经变色，沿锅边均匀淋如准备好的生抽，翻炒均匀。","依次加入准备好的盐、老抽、耗油、十三香、鸡精以及全部准备好的豆角，翻炒 2 分钟。","加入准备好的热水。","水开使用勺子舀出锅内 2 分之一菜汤（注意！不要将菜舀出）。","将所有面条平铺在菜的上方。","盖上锅盖，中火焖 5 分钟。","打开锅盖，将舀出的菜汤使用勺子，以每次一勺的量，均匀撒在面条上。","盖上锅盖，中火焖 3 分钟。","打开锅盖，将所有的蒜、味精均匀撒入。","使用筷子不断翻炒，将菜与肉均匀搅拌。","关火"]'::jsonb, '["主食","北方家常","焖面","咸香","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_20513891ef.jpg', 'https://www.bilibili.com/video/BV1QZ421T75P', null, '[null,null,null,null,null,null,null,5,5,null,120,null,null,null,300,null,180,null,null,null]'::jsonb),
  ('howtocook:staple/酱拌荞麦面/酱拌荞麦面', '酱拌荞麦面', '主食', 2, 20, '酱拌荞麦面酸甜可口、清凉爽滑，是一道简单快手的家常凉拌面。荞麦面富含膳食纤维和蛋白质，搭配黄瓜、胡萝卜增添清爽口感与维生素，营养均衡。只需煮面、切菜、拌入老干妈，几步搞定，对新手非常友好，一般约 20 分钟便可完成。冷藏后食用风味更佳。', '[{"name":"荞麦面","quantity":100,"unit":"g"},{"name":"黄瓜","quantity":0.5,"unit":"根"},{"name":"红萝卜","quantity":0.5,"unit":"根"},{"name":"老干妈","quantity":20,"unit":"ml"}]'::jsonb, '["荞麦面下冷水煮熟，8-10 分钟 后捞出沥干备用","黄瓜、萝卜 切成小条","将荞麦面、黄瓜、萝卜放入盘子，放上老干妈，搅拌"]'::jsonb, '["主食","凉拌","快手","家常","酸甜","微辣","清爽"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_84c8c12b6e.jpeg', 'https://www.bilibili.com/video/BV1Z64y1X78m', '{"energyKcal":477,"protein":15.7,"carbs":79.4,"fat":13.3}'::jsonb, '[480,null,null]'::jsonb),
  ('howtocook:staple/酸辣蕨根粉', '酸辣蕨根粉', '主食', 2, 10, '酸辣蕨根粉口感爽滑筋道，酸辣开胃，是一道家常凉菜，也可当作主食享用。蕨根粉富含淀粉和膳食纤维，能为身体提供能量。这道菜做法格外简单，对新手非常友好，从准备到完成只需 10 分钟。', '[{"name":"蕨根粉","note":"适量"},{"name":"油泼辣子","note":"适量"},{"name":"酱油","note":"适量"},{"name":"香醋","note":"适量"},{"name":"小米辣","note":"适量"},{"name":"蒜","note":"适量"},{"name":"葱","note":"适量"},{"name":"盐","quantity":2,"quantityMax":5,"unit":"克"},{"name":"糖","quantity":2,"unit":"克"}]'::jsonb, '["锅中加入约为深度 3/5 的水，烧开","水沸腾后加入蕨根粉，中小火煮 8 分钟","出锅","根据配比，加入酱油、醋、油泼辣子","用筷子蘸取，尝一口","如果觉得此时酱油味稍浓，加入准备好的盐","如果觉得此时不够鲜，加入准备好的糖","充分搅拌至大部分颗粒状调料溶解","取一个碗","加入上一步调制的酱料","将蕨根粉过冷水后放入酱料中","充分搅拌","将准备的葱、蒜、小米辣切碎后撒在粉上","完成啦(｡･∀･)ﾉﾞ"]'::jsonb, '["主食","酸辣","凉拌","快手","家常","开胃"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_3a741a6fa0.jpg', 'https://www.bilibili.com/video/BV1aW411N7JW', '{"energyKcal":300,"protein":5,"carbs":50,"fat":9}'::jsonb, '[null,480,null,null,null,null,null,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:staple/醪糟小汤圆', '醪糟小汤圆', '主食', 2, 15, '醪糟小汤圆是一道香甜软糯的传统中式甜品，酒酿的微酸与糯米的绵滑交融，暖胃又舒心。它富含碳水化合物和少量 B 族维生素，能快速补充能量，也有助促进血液循环。做法毫无门槛，对新手特别友好，从烧水到出锅只需约 15 分钟，是一碗随时都能轻松完成的家常甜汤。', '[{"name":"水","quantity":300,"unit":"毫升"},{"name":"小汤圆","quantity":250,"unit":"克"},{"name":"醪糟","quantity":50,"unit":"克"},{"name":"枸杞","quantity":5,"unit":"颗"},{"name":"白糖","note":"适量"}]'::jsonb, '["将水倒入锅中并煮沸","放入小汤圆煮 8 分钟","放入醪糟和枸杞再煮 2 分钟","盛入碗中根据个人口味加入白糖并搅拌均匀","吃"]'::jsonb, '["主食","香甜","软糯","煮","快手","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_f1d81328d3.jpg', 'https://www.bilibili.com/video/BV1pM4y1u7V6', '{"energyKcal":910,"protein":19,"carbs":217,"fat":2}'::jsonb, '[null,480,120,null,null]'::jsonb),
  ('howtocook:staple/陕西油泼面/陕西油泼面', '陕西油泼面', '主食', 2, 30, '这道西北传统面食以筋道的扯面和热油泼出的香辣风味著称，是陕西家喻户晓的日常主食。面条富含碳水化合物，搭配青菜和豆芽，能快速补充能量，膳食搭配合理。整个流程简单明了，对新手十分友好，从备料到出锅大约只需 30 分钟。', '[{"name":"鲜面条（扯面尤佳）","quantity":3,"quantityMax":4,"unit":"根"},{"name":"盐","quantity":2,"unit":"克"},{"name":"葱","quantity":1,"unit":"根"},{"name":"蒜","quantity":3,"unit":"瓣"},{"name":"干辣椒面（或秦椒面）","quantity":15,"unit":"克"},{"name":"食用油","quantity":50,"unit":"ml"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"香醋","quantity":5,"unit":"ml"},{"name":"青菜","quantity":50,"unit":"克"},{"name":"豆芽","quantity":50,"unit":"克"},{"name":"花椒","note":"适量"},{"name":"八角","note":"适量"},{"name":"桂皮","note":"适量"},{"name":"香叶","note":"适量"},{"name":"芝麻","note":"适量"}]'::jsonb, '["扯面的话, 用擀面杖（没有擀面杖,用手也行）上下两边轻压, 两手拽住左侧和右侧两端,轻轻拉开","葱切成葱花，蒜切成蒜末备用","青菜洗净，豆芽洗净备用（如使用）","锅中加入足量清水，大火烧开后加入 1g 盐","放入面条，用筷子轻轻搅动防止粘连，煮至面条浮起后再煮 1-2 分钟","在煮面的最后 1 分钟，放入青菜和豆芽焯水","将煮好的面条和青菜、豆芽捞出，沥干水分后放入碗中","在面条上依次加入生抽、香醋、葱花、蒜末和干辣椒面, 也可放点芝麻","炒锅中倒入食用油，同时放入花椒、八角、桂皮、香叶（如使用），小火炸出香味后捞出香料","待油温升至七成热（微微冒烟）时，迅速均匀地泼在碗中的干辣椒面上，听到“滋啦”声即可","用筷子将所有调料和面条充分拌匀即可食用"]'::jsonb, '["主食","陕西","面食","香辣","快手","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_059f9207d2.png', 'https://www.bilibili.com/video/BV1RPh9zMEJ7', '{"energyKcal":800,"protein":12,"carbs":60,"fat":50}'::jsonb, '[null,null,null,null,90,60,null,null,null,null,null]'::jsonb),
  ('howtocook:staple/韩式拌饭/韩式拌饭', '韩式拌饭', '主食', 3, 45, '韩式拌饭是一道色彩缤纷、口感丰富的韩国家常料理，甜辣酱汁包裹着米饭、蔬菜、牛肉和溏心蛋，拌匀后一口满足。多种蔬菜提供维生素和膳食纤维，牛肉和鸡蛋补充优质蛋白，营养均衡。制作简单但备菜步骤稍多，新手也能从容完成，从准备到上桌大约需要 45 分钟。', '[{"name":"米饭","quantity":1,"unit":"碗"},{"name":"鸡蛋","quantity":1,"unit":"颗"},{"name":"牛肉卷","quantity":6,"unit":"卷"},{"name":"豆芽","quantity":80,"unit":"克"},{"name":"蘑菇","quantity":50,"unit":"克"},{"name":"胡萝卜","quantity":0.25,"unit":"根"},{"name":"西葫芦","quantity":50,"unit":"克"},{"name":"韩式辣酱","quantity":25,"unit":"ml"},{"name":"雪碧","quantity":20,"unit":"ml"},{"name":"芝麻","quantity":10,"unit":"克"},{"name":"芝麻油","quantity":20,"unit":"ml"},{"name":"生抽","quantity":15,"unit":"ml"},{"name":"盐","note":"适量"}]'::jsonb, '["蔬菜清洗 切丝 放锅中翻炒 食材变软 便可称出","煮水 等沸腾时 焯牛肉卷 只需煮熟 大概三分钟即可捞出","煎溏心蛋","将米饭放在一个碗里 然后倒扣在大碗","将准备好的蔬菜和肉卷依次绕圈放在米饭上面 将煎蛋放中间","备酱汁","10ml 韩式辣酱（甜辣口）+ 5ml 生抽 + 两瓶盖雪碧（减肥的话 可以放无糖雪碧）+ 10g 芝麻 + 5ml 芝麻油","搅拌上述酱汁，可以再加生抽和盐","将备好的酱汁倒在摆好盘的碗中"]'::jsonb, '["主食","韩式","甜辣","家常","下饭","拌制"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_45264ee9b7.png', 'https://www.bilibili.com/video/BV194411X7PE', '{"energyKcal":700,"protein":33,"carbs":55,"fat":42}'::jsonb, '[null,180,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:staple/韭菜盒子', '韭菜盒子', '主食', 3, 150, '韭菜盒子是一道传统中式面点，外皮金黄酥脆，内馅鲜香多汁。韭菜搭配虾仁和鸡蛋，富含维生素与优质蛋白质。做法简单，对新手也很友好，从和面到出锅大约需要 2.5 小时。', '[{"name":"韭菜","quantity":500,"unit":"克"},{"name":"虾仁","quantity":100,"unit":"克"},{"name":"鸡蛋","quantity":3,"unit":"枚"},{"name":"香油","quantity":10,"unit":"ml"},{"name":"盐","quantity":5,"unit":"克"},{"name":"面粉","quantity":250,"unit":"克"}]'::jsonb, '["将面粉放入大碗中，加入水，搅拌成光滑的面团，静置 30 分钟。","韭菜洗净切碎，加入打散的鸡蛋、5g 盐，搅拌均匀。","将面团分成小剂子，擀成薄圆饼，包入韭菜、虾仁、鸡蛋液。","热锅，加入食用油，放入包好的韭菜盒子，煎至两面金黄，约 3-4 分钟。","盛盘，稍凉后即可享用。"]'::jsonb, '["主食","鲜香","煎制","家常","中式面点"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_36af3fd704.jpg', 'https://www.bilibili.com/video/BV1Jz411q7UA', '{"energyKcal":390,"protein":18.5,"carbs":52,"fat":9}'::jsonb, '[1800,null,null,180,null]'::jsonb),
  ('howtocook:staple/鲜肉烧卖', '鲜肉烧卖', '主食', 4, 60, '这是一道江南风味的精致点心，皮薄如纸，馅料饱满多汁，咬开时肉香、笋鲜与皮冻融化后的汤汁交融，咸中带甜，口感软嫩弹牙。猪肉和虾仁提供优质蛋白质，冬笋与香菇增添膳食纤维和微量元素，低脂版本进一步减少了饱和脂肪。虽然包制手法需要一点耐心，但整体步骤清晰，新手多加练习也能掌握，从拌馅到出锅大约需要一小时。', '[{"name":"烧卖皮","quantity":240,"quantityMax":465,"unit":"g"},{"name":"猪肉末（肥瘦3:7）","quantity":300,"unit":"g"},{"name":"猪里脊肉或猪前腿肉（低脂版本）","quantity":280,"unit":"g"},{"name":"生姜末","quantity":5,"quantityMax":10,"unit":"g"},{"name":"葱末（只用绿色部分）","quantity":10,"quantityMax":20,"unit":"g"},{"name":"生抽","quantity":15,"unit":"mL"},{"name":"料酒","quantity":10,"unit":"mL"},{"name":"盐","quantity":3,"quantityMax":5,"unit":"g"},{"name":"糖（可选）","quantity":2,"quantityMax":3,"unit":"g"},{"name":"白胡椒粉（可选）","quantity":2,"unit":"g"},{"name":"芝麻油","quantity":5,"unit":"mL"},{"name":"高汤","quantity":30,"unit":"mL"},{"name":"浓汤宝","quantity":6,"unit":"g"},{"name":"冬笋（可选）","quantity":50,"unit":"g"},{"name":"皮冻（可选但推荐）","quantity":100,"unit":"g"},{"name":"香菇（可选）","quantity":75,"unit":"g"},{"name":"干香菇（泡发，可选）","quantity":30,"unit":"g"},{"name":"虾仁（可选）","quantity":100,"quantityMax":200,"unit":"g"},{"name":"复配食品增稠剂（低脂版本）","quantity":1.2,"unit":"g"},{"name":"玉米淀粉（低脂版本）","quantity":2,"unit":"g"},{"name":"猪油（或鸡油）（低脂版本）","quantity":15,"unit":"g"}]'::jsonb, '["（低脂版本）取 10 mL 冷水，加入复配食品增稠剂，调成糊糊","（低脂版本）加入 25 mL 开水，搅拌至半透明凝胶","（低脂版本）冷却后混入 280 g 纯瘦肉糜 + 15 g 融化猪油（或鸡油）","将猪肉末与生姜末、葱末混合，加入酱油、料酒、盐、糖、白胡椒粉，顺一个方向搅拌上劲","如果使用浓汤宝，取浓汤宝块加入 15 mL 热水混合，搅拌至乳浊液完全分散，再加入 15 mL 常温水","慢慢加入水或高汤，继续搅拌，直到馅料吸收水分，变得粘稠，如果觉得肉馅太稠，补 5 mL 水继续搅拌","加入可选配料（冬笋、皮冻、香菇），最后淋上芝麻油，拌匀。冷藏 30 分钟，让味道融合","取一张烧卖皮，放上约 20-25 g 馅料（别太贪心，否则包不住）","用虎口轻轻收拢皮子边缘，形成“花瓶”状，顶部留开口","用手指轻轻压实底部，确保站立稳定","如果要加虾仁，在顶部加一颗虾仁","重复包烧卖的步骤，直到包好","放在蒸笼里，间隔开，避免粘连","大火蒸 8-10 分钟即可"]'::jsonb, '["主食","江南风味","咸鲜","蒸制","宴客点心","皮薄馅大","低脂可选"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_690984a5bd.jpg', 'https://www.bilibili.com/video/BV1K7411E7jM', '{"energyKcal":530,"protein":27,"carbs":57,"fat":21}'::jsonb, '[null,null,null,null,null,null,1800,null,null,null,null,null,null,540]'::jsonb),
  ('howtocook:staple/鲣鱼海苔玉米饭/鲣鱼海苔玉米饭', '鲣鱼海苔玉米饭', '主食', 2, 40, '这是一道鲜香味美的日式简餐，米饭粒粒分明，融合了鲣鱼的咸鲜、海苔的酥香与玉米的甜脆。鲣鱼富含优质蛋白和 DHA，搭配海苔的矿物质和玉米的膳食纤维，营养均衡。做法非常简单，新手也能轻松完成，实际动手仅需 5 分钟，加上煮饭总共约 40 分钟即可享用。', '[{"name":"米饭","note":"适量"},{"name":"玉米粒","quantity":80,"unit":"克"},{"name":"鲣鱼海苔碎","quantity":20,"unit":"克"}]'::jsonb, '["盛好米饭，放入玉米粒拌好","放入鲣鱼海苔碎"]'::jsonb, '["主食","日式","快手","鲜香","家常","简餐"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_staple_1462181a67.jpg', 'https://www.bilibili.com/video/BV1kh411W7RT', '{"energyKcal":305,"protein":15,"carbs":56,"fat":3}'::jsonb, null),
  ('howtocook:staple/鹰嘴豆炸饼', '鹰嘴豆炸饼', '主食', 4, 50, '鹰嘴豆咖喱配油炸面饼是北印度经典街头小吃，松软的炸饼搭配香料浓郁的鹰嘴豆，口感层次丰富，酸辣咸香。鹰嘴豆富含植物蛋白和膳食纤维，饱腹又营养。制作步骤稍多，但跟着流程走并不难，适合有一定基础的家常烹饪。约 50 分钟即可完成（鹰嘴豆需提前浸泡 8 小时）。', '[{"name":"干鹰嘴豆","quantity":200,"unit":"克"},{"name":"洋葱","quantity":2,"unit":"个"},{"name":"番茄","quantity":3,"unit":"个"},{"name":"生姜","quantity":10,"unit":"克"},{"name":"大蒜","quantity":4,"unit":"瓣"},{"name":"青辣椒","quantity":2,"unit":"根"},{"name":"食用油（炒咖喱用）","quantity":30,"unit":"ml"},{"name":"红茶包（用于鹰嘴豆上色）","quantity":1,"unit":"个"},{"name":"姜黄粉","quantity":3,"unit":"克"},{"name":"红辣椒粉","quantity":5,"unit":"克"},{"name":"香菜粉","quantity":8,"unit":"克"},{"name":"孜然粉","quantity":5,"unit":"克"},{"name":"盐（咖喱用）","quantity":6,"unit":"克"},{"name":"印度综合香料粉","quantity":5,"unit":"克"},{"name":"石榴粉","quantity":3,"unit":"克"},{"name":"柠檬汁","quantity":15,"unit":"ml"},{"name":"水","quantity":500,"unit":"ml"},{"name":"中筋面粉","quantity":250,"unit":"克"},{"name":"酸奶","quantity":60,"unit":"ml"},{"name":"食用油（和面用）","quantity":15,"unit":"ml"},{"name":"小苏打","quantity":2,"unit":"克"},{"name":"盐（面团用）","quantity":3,"unit":"克"},{"name":"温水","quantity":60,"unit":"ml"},{"name":"食用油（炸饼用）","quantity":500,"unit":"ml"},{"name":"香菜","note":"适量"},{"name":"柠檬角","note":"适量"}]'::jsonb, '["将干鹰嘴豆用清水浸泡过夜（至少 8 小时），浸泡后体积会膨胀至约两倍","将浸泡好的鹰嘴豆沥干水分","放入锅中，加入 500ml 水和 1 个红茶包（用于上色）","大火煮沸后转中火，煮 25-30 分钟，直至鹰嘴豆用手指可以轻松压碎","取出红茶包，保留煮豆的汤水，备用","在炒锅中倒入 30ml 食用油，中火加热","放入切碎的洋葱，翻炒至金棕色（约 6-8 分钟）","加入磨碎的生姜和大蒜，翻炒 1 分钟","加入切碎的番茄，翻炒至番茄完全软烂出油（约 5 分钟）","加入姜黄粉 3g、红辣椒粉 5g、香菜粉 8g、孜然粉 5g、盐 6g","翻炒 2 分钟，使香料充分释放香味","将煮好的鹰嘴豆连同汤水一起倒入锅中","加入青辣椒，搅拌均匀","大火煮沸后转小火，炖 15-20 分钟，期间可用铲子背面压碎一些鹰嘴豆使汤汁变稠","加入印度综合香料粉 5g 和石榴粉 3g（或柠檬汁 15ml）","搅拌均匀后关火，备用","在大碗中混合中筋面粉 250g、小苏打 2g、盐 3g","加入酸奶 60ml 和食用油 15ml","逐渐加入温水，边加边揉，揉成光滑柔软的面团（面团应比普通面团稍软）","用湿布盖住面团，静置 30 分钟","将面团分成 8 个等大的小剂子","取一个剂子，手上沾少量油，擀成直径约 15cm、厚度约 3mm 的圆形面饼","在深锅中倒入 500ml 食用油，中大火加热至油温约 180°C","将面饼轻轻滑入热油中，用漏勺轻轻按压面饼使其膨胀鼓起","炸 1-2 分钟，翻面炸至两面金黄","捞出，用厨房纸吸去多余油分","将鹰嘴豆咖喱重新加热","炸饼趁热上桌，搭配鹰嘴豆咖喱食用","可搭配切片洋葱、青辣椒和柠檬角"]'::jsonb, '["主食","北印","街头小吃","酸辣咸香","油炸","饱腹"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_e71a230d5d.jpg', 'https://www.bilibili.com/video/BV1ps4y14715', '{"energyKcal":350,"protein":9,"carbs":33,"fat":20}'::jsonb, '[28800,null,null,1500,null,null,360,60,300,null,120,null,null,900,null,null,null,null,null,1800,null,null,null,null,60,null,null,null,null]'::jsonb),
  ('howtocook:staple/麻油拌面', '麻油拌面', '主食', 1, 10, '麻油香气浓郁，搭配老抽与胡椒粉简单调味，咸香适口，是一道省时省钱的家常拌面。面条提供充足碳水化合物，麻油含有不饱和脂肪酸与维生素 E，能为身体补充能量。制作毫无难度，厨房新手也能轻松上手，从煮水到拌好只需大约十分钟。', '[{"name":"水","quantity":1,"unit":"升"},{"name":"快熟面","quantity":1,"unit":"块"},{"name":"麻油","quantity":15,"unit":"ml"},{"name":"老抽","quantity":10,"unit":"克"},{"name":"盐","quantity":30,"unit":"克"},{"name":"胡椒粉","quantity":10,"unit":"克"},{"name":"生抽","quantity":5,"unit":"克"}]'::jsonb, '["将水倒入锅中并煮沸 （喜欢吃 q 弹面的同学，可在水里加入 30 克盐，用盐水煮出来的面会比较 q 弹）","将快熟面放入锅中 3 分钟（也可参考当下品牌快熟面的烹饪时间）","当面开始散了可以开始搅拌，让面受热均匀","将水滤干把面倒入碗中","按照上面的计量放入麻油，老抽，胡椒粉，生抽（可选）","筷子搅拌均匀","一道简单即省钱的懒人麻油拌面就完成啦"]'::jsonb, '["主食","咸香","拌","快手","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_9e87b779d4.jpg', 'https://www.bilibili.com/video/BV1Hx411q7zQ', '{"energyKcal":530,"protein":9,"carbs":52,"fat":32}'::jsonb, '[null,180,null,null,null,null,null]'::jsonb),
  ('howtocook:staple/麻辣减脂荞麦面', '麻辣减脂荞麦面', '主食', 2, 20, '麻辣汤底融合了火锅底料与花生酱、牛奶，口感浓郁顺滑，带有鲜明麻辣风味。搭配高纤维荞麦面与新鲜蔬菜，低卡饱腹，适合减脂期享用。做法毫无难度，无需厨艺基础，全程约 20 分钟即可端锅开吃。', '[{"name":"半干荞麦面","quantity":100,"unit":"克"},{"name":"娃娃菜","quantity":8,"unit":"片"},{"name":"生菜","quantity":6,"unit":"片"},{"name":"花生酱","quantity":15,"unit":"克"},{"name":"全脂牛奶","quantity":150,"unit":"ml"},{"name":"生抽","quantity":6,"unit":"ml"},{"name":"辣椒油","quantity":10,"unit":"ml"},{"name":"醋","quantity":20,"unit":"ml"},{"name":"花椒油","quantity":10,"unit":"ml"},{"name":"水","quantity":500,"unit":"ml"}]'::jsonb, '["娃娃菜、生菜洗好，备用","锅内倒入 500ml 水，开大火，将荞麦面和娃娃菜放进去，等待水沸腾","水沸腾后，转小火，加入火锅底料、花生酱、牛奶、生抽、辣椒油，水开后煮 5 分钟","加入生菜，再煮 2 分钟","加入醋、花椒油，关火，直接端着小锅开吃。"]'::jsonb, '["主食","麻辣","鲜香","快手","减脂","低卡","煮面"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_staple_b6aee6e084.jpg', 'https://www.bilibili.com/video/BV1P5411W7ad', '{"energyKcal":720,"protein":22,"carbs":74,"fat":32}'::jsonb, '[null,null,300,120,null]'::jsonb),
  ('howtocook:vegetable_dish/上汤娃娃菜/上汤娃娃菜', '上汤娃娃菜', '素菜', 3, 20, '这道上汤娃娃菜清甜鲜美，口感软嫩，属于家常素菜，尤其适合减肥期间食用。娃娃菜富含维生素和膳食纤维，低脂低热量，搭配皮蛋和午餐肉增添风味又不会过多增加负担。制作难度适中，新手也能尝试，从备菜到出锅大约只需 20 分钟。', '[{"name":"娃娃菜","quantity":700,"unit":"克"},{"name":"金针菇","quantity":10,"unit":"克"},{"name":"皮蛋","quantity":1,"unit":"个"},{"name":"午餐肉（火腿肠）","note":"适量"},{"name":"葱","quantity":3,"unit":"克"},{"name":"姜","quantity":10,"unit":"克"},{"name":"蒜","quantity":10,"unit":"克"},{"name":"盐","note":"适量"},{"name":"糖","note":"适量"},{"name":"淀粉","note":"适量"}]'::jsonb, '["娃娃菜洗净, 竖着切开切成段。","葱 3g 切 小段。蒜 10g 切片。姜 10g 切小片。","皮蛋切成丁, 火腿肠或者午餐肉切成丁（1cm 大小的丁）","金针菇洗净撕开","烧热水娃娃菜放进去十秒钟出一下水捞出。","热锅凉油, 加热锅倒入油过一遍就倒出来, 重新倒入一点油。","调至小火加入葱姜蒜，煎炒出香味即可。","加入适 300g 清水（水量没过娃娃菜即可）, 放入娃娃菜, 金针菇, 午餐肉","加入调味料蚝油、糖、盐、味精烧开。","煮 3 分钟, 煮开后开始装盘, 盛出娃娃菜后皮蛋放在上面把汤汁浇上去就可以了","上汤娃娃菜"]'::jsonb, '["素菜","清淡","家常","快手","炖煮","低脂","鲜美"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_d65cdcb9ba.png', 'https://www.bilibili.com/video/BV18e4y1D7M3', null, null),
  ('howtocook:vegetable_dish/乾隆白菜/乾隆白菜', '乾隆白菜', '素菜', 2, 10, '乾隆白菜是一道经典的北京风味凉菜，以手撕白菜心拌上浓稠芝麻酱汁，口感酸甜爽脆、醇厚开胃。白菜富含维生素和膳食纤维，芝麻酱则带来优质脂肪与钙质，清爽解腻又营养。全程不炒不煮，调酱拌匀即可，对新手十分友好，一般仅需 10 分钟便能端上餐桌。', '[{"name":"大白菜嫩叶","quantity":300,"unit":"克"},{"name":"芝麻酱","quantity":30,"unit":"克"},{"name":"陈醋","quantity":45,"unit":"ml"},{"name":"白糖","quantity":5,"unit":"克"},{"name":"香油","quantity":5,"unit":"ml"},{"name":"食盐","quantity":1,"unit":"克"},{"name":"熟白芝麻","quantity":3,"unit":"克"}]'::jsonb, '["大白菜只取内部嫩叶（黄色部分），去除菜帮，用手撕成半个巴掌大的块，不要用刀切（手撕截面粗糙更易挂酱）","将撕好的白菜叶冲洗干净，充分控干水分，水分残留会导致酱汁无法挂附","碗中加入 30g 芝麻酱，先加入 45ml 陈醋，沿同一方向搅拌，将麻酱慢慢稀释开，直至成细线状滴落为止（切勿来回搅拌，会导致芝麻酱\"走油\"）","向麻酱汁中加入 5g 白糖，搅拌均匀；再加入 1g 食盐，搅拌均匀；最后加入 5ml 香油，搅拌均匀（各调料需分次加入并分别搅拌，边加边感受稀稠度）","将调好的麻酱汁均匀淋在白菜叶上，用手轻轻抓拌，使每片菜叶都裹上酱汁","撒上熟白芝麻，装盘即可食用；若时间充裕，可静置 5 分钟待其入味后再食用"]'::jsonb, '["素菜","北京风味","酸甜","凉菜","开胃","快手","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_a1c133b004.jpg', 'https://www.bilibili.com/video/BV1ch41147Tq', '{"energyKcal":350,"protein":10.6,"carbs":31,"fat":23}'::jsonb, '[null,null,null,null,null,300]'::jsonb),
  ('howtocook:vegetable_dish/凉拌木耳/凉拌木耳', '凉拌木耳', '素菜', 2, 55, '凉拌木耳，由于发放物资中有很多干货，木耳是较为健康的食物。且凉拌木耳的烹饪方式也相对简单。', '[{"name":"干木耳","quantity":20,"unit":"克"},{"name":"湿木耳","quantity":120,"unit":"克"},{"name":"蒜瓣","quantity":2,"quantityMax":3,"unit":"个"},{"name":"小米辣","quantity":2,"unit":"个"},{"name":"盐","quantity":2,"unit":"克"},{"name":"糖","quantity":5,"quantityMax":10,"unit":"克"},{"name":"生抽","quantity":15,"unit":"ml"},{"name":"醋","quantity":15,"unit":"ml"},{"name":"香油","quantity":5,"unit":"ml"},{"name":"芥末","quantity":2,"unit":"cm"}]'::jsonb, '["泡发干木耳, 水量约为 400ml, 泡发约 45 分钟。 （湿木耳跳过此步骤）","将泡发好的木耳, 进行去根处理（如图 4, 5, 6）, 并彻底洗净。","起锅烧水，水开后放入木耳, 大火煮 1.5-2 分钟。","将蒜瓣、小米辣切碎放入碗中 （可选取中大碗）, 并依次加入盐、糖、生抽、醋、香油、芥末, 用量如上。","木耳盛出后沥水, 放入上一步碗中。","搅拌充分，端盘。"]'::jsonb, '["素菜","凉拌","快手","酸辣","开胃","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_463498a9e2.jpg', 'https://www.bilibili.com/video/BV1KM4y1e7WD', '{"energyKcal":120,"protein":3,"carbs":18,"fat":5}'::jsonb, '[2700,null,null,null,null,null]'::jsonb),
  ('howtocook:vegetable_dish/凉拌油麦菜', '凉拌油麦菜', '素菜', 1, 15, '一道清爽解腻的家常凉菜，芝麻酱的醇厚包裹着油麦菜的脆嫩，酸甜咸香交织，非常开胃。油麦菜富含维生素和膳食纤维，芝麻酱则补充钙与健康脂肪，营养均衡。做法毫无难度，切一切、拌一拌就行，从准备到上桌只需十几分钟，特别适合新手和忙碌时快速成菜。', '[{"name":"油麦菜","quantity":1,"unit":"颗"},{"name":"醋","quantity":15,"unit":"ml"},{"name":"酱油","quantity":5,"unit":"ml"},{"name":"芝麻酱","quantity":10,"unit":"ml"},{"name":"香油","quantity":5,"unit":"ml"},{"name":"白糖","quantity":5,"unit":"克"},{"name":"蚝油","quantity":10,"unit":"ml"},{"name":"蒜","quantity":2,"unit":"头"},{"name":"盐","note":"适量"}]'::jsonb, '["蒜拍碎切末","醋，酱油，芝麻酱，香油，糖，蚝油，蒜末放到碗里搅拌均匀","油麦菜切段，每段不超过 4cm","油麦菜放到一个大点的盆里,倒入上述碗中酱料,充分搅拌均匀."]'::jsonb, '["素菜","清爽","凉拌","快手","家常","开胃"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_5b4d09fdc2.jpg', 'https://www.bilibili.com/video/BV1VF411V7Wh', '{"energyKcal":260,"protein":10.7,"carbs":35.3,"fat":11.2}'::jsonb, null),
  ('howtocook:vegetable_dish/凉拌莴笋/凉拌莴笋', '凉拌莴笋', '素菜', 2, 20, '一道清脆爽口的家常凉拌小菜，莴笋经过腌制后格外脆嫩，带着微微辣意，十分开胃。富含维生素与膳食纤维，热量不高。做法简单，对新手很友好，从备料到上桌大约二十分钟，冰镇后风味更佳。', '[{"name":"莴笋","quantity":1,"unit":"根"},{"name":"萝卜","quantity":0.25,"unit":"根"},{"name":"小米辣","quantity":2,"unit":"个"},{"name":"姜","quantity":1,"unit":"片"},{"name":"蒜头","quantity":2,"unit":"粒"},{"name":"盐","quantity":5,"unit":"g"},{"name":"食用油","quantity":25,"unit":"ml"}]'::jsonb, '["莴笋削皮，切小条。萝卜切条，一起放入大碗，加入盐搅拌，放置 10 分钟","放置后的莴笋用水清洗 1-2 遍","起锅烧水，放入莴笋，水煮 1 分钟 捞出，沥干水分，放入大碗","起锅烧油，放入姜片、蒜粒、小米椒煸炒 30-45 S ，倒入莴笋中","搅拌充分，端盘"]'::jsonb, '["素菜","清爽","微辣","凉拌","快手","家常","开胃"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_16697b48ae.jpeg', 'https://www.bilibili.com/video/BV1eWoEYbEof', '{"energyKcal":130,"protein":2,"carbs":8,"fat":9}'::jsonb, '[600,null,60,null,null]'::jsonb),
  ('howtocook:vegetable_dish/凉拌豆腐', '凉拌豆腐', '素菜', 2, 10, '这道凉菜清爽可口，富含植物蛋白和钙质，低脂健康，制作简单快捷，一般初学者只需要 10 分钟即可完成。', '[{"name":"豆腐","quantity":250,"unit":"g"},{"name":"小葱","quantity":10,"unit":"g"},{"name":"大蒜","quantity":2,"quantityMax":3,"unit":"瓣"},{"name":"生抽","quantity":15,"unit":"ml"},{"name":"香油","quantity":5,"unit":"ml"},{"name":"醋","quantity":5,"unit":"ml"},{"name":"白糖","quantity":2,"unit":"g"},{"name":"辣椒油","quantity":5,"unit":"ml"}]'::jsonb, '["将 豆腐 切成 2 cm 见方的小块，备用。","锅中加入 500 ml 饮用水，大火烧开。","放入 豆腐 块，煮 1-2 分钟，以去除豆腥味并使豆腐口感更紧实。","将 煮好的 豆腐 块捞出，沥干水分，放入碗中，备用。","将 小葱 洗净，切成葱花，备用。","将 大蒜 去皮，切成蒜末，备用。","在一个干净的小碗中，加入 15 ml 生抽，5 ml 香油，5 ml 醋（可选），2 g 白糖（可选）。","加入切好的 大蒜末。","搅拌均匀，使 白糖 充分溶解，酱汁混合均匀。","将制作好的酱汁均匀淋在 豆腐 块上。","撒上切好的 小葱花。","根据个人喜好，淋上 5 ml 辣椒油（可选）。","用 筷子 或勺子轻轻拌匀，即可食用。"]'::jsonb, '["素菜","清爽","快手","凉拌","家常","低脂"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_33b7e7ecbd.jpg', 'https://www.bilibili.com/video/BV1BZ4y1p7H6', '{"energyKcal":304,"protein":21.6,"carbs":10.9,"fat":21.2}'::jsonb, '[null,null,90,null,null,null,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:vegetable_dish/凉拌金针菇', '凉拌金针菇', '素菜', 2, 10, '凉拌金针菇是一道简单快捷的家常开胃凉菜，口感脆嫩爽滑，咸鲜微酸。金针菇富含膳食纤维和多种维生素，热量较低。制作全程只需焯烫和调味，对新手非常友好，忙碌时也能快速准备。从备菜到完成大约只需 10 分钟。', '[{"name":"金针菇","quantity":150,"unit":"g"},{"name":"小葱","quantity":5,"unit":"g"},{"name":"大蒜","quantity":2,"unit":"瓣"},{"name":"生抽","quantity":15,"unit":"ml"},{"name":"醋","quantity":10,"unit":"ml"},{"name":"白糖","quantity":3,"unit":"g"},{"name":"香油","quantity":5,"unit":"ml"},{"name":"辣椒油","quantity":5,"unit":"ml"}]'::jsonb, '["将 金针菇 根部切除，用清水冲洗干净，备用。","将 小葱 洗净，切成葱花，备用。","将 大蒜 去皮，切成蒜末，备用。","锅中加入 1000 ml 饮用水，大火烧开。","放入 金针菇，煮 1-2 分钟，至金针菇变软。","将 煮好的 金针菇 捞出，沥干水分，放入一个较大的碗中，备用。","在另一个干净的小碗中，加入 15 ml 生抽，10 ml 醋，3 g 白糖（可选），5 ml 香油（可选）。","加入切好的 大蒜末。","搅拌均匀，使 白糖 充分溶解，酱汁混合均匀。","将制作好的酱汁均匀淋在 金针菇 上。","撒上切好的 小葱花。","根据个人喜好，淋上 5 ml 辣椒油（可选）。","用 筷子 轻轻拌匀，即可食用。"]'::jsonb, '["素菜","凉拌","家常","快手","开胃","清爽","咸鲜"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_de2b2681f6.jpg', 'https://www.bilibili.com/video/BV1G34y1E7Mx', '{"energyKcal":165,"protein":6,"carbs":18,"fat":10}'::jsonb, '[null,null,null,null,60,null,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:vegetable_dish/凉拌黄瓜', '凉拌黄瓜', '素菜', 1, 20, '这是一道清爽开胃的家常凉菜，口感脆嫩，酸香适口。黄瓜富含水分和维生素，有助于清热解暑、美容养颜。做法非常简单，对新手友好，只需拍碎、调味、腌制 15 分钟，全程约 20 分钟即可完成。', '[{"name":"黄瓜","quantity":200,"unit":"克"},{"name":"醋"},{"name":"酱油"},{"name":"蒜","quantity":3,"unit":"瓣"},{"name":"白糖","quantity":5,"unit":"克"},{"name":"盐"},{"name":"蚝油","quantity":5,"unit":"ml"},{"name":"香油"}]'::jsonb, '["用菜刀将黄瓜拍扁，再剁成长 3 厘米的碎块","将碎黄瓜装入碗中","将蒜拍碎切成碎末","将碗中放入 5 克白糖，搅拌均匀腌制 15 分钟（用糖腌制更好吃，且成色更好不会蔫）","将醋，酱油，盐，蚝油和蒜依次倒入碗中搅拌均匀","将香油倒入碗中并均匀搅拌"]'::jsonb, '["素菜","清爽","凉拌","快手","家常","开胃"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_c23f64013f.jpg', 'https://www.bilibili.com/video/BV1RV41167WV', '{"energyKcal":95,"protein":2.2,"carbs":8.5,"fat":3.5}'::jsonb, '[null,null,null,900,null,null]'::jsonb),
  ('howtocook:vegetable_dish/包菜炒鸡蛋粉丝/包菜炒鸡蛋粉丝', '包菜炒鸡蛋粉丝', '素菜', 3, 80, '包菜炒鸡蛋粉丝是一道咸鲜可口的家常快手菜，脆甜的包菜丝与软韧的粉丝、嫩滑的鸡蛋相互融合，口感层次丰富。包菜富含维生素和膳食纤维，鸡蛋提供优质蛋白质，胡萝卜增添营养，荤素搭配均衡。制作时需要提前浸泡粉丝，整体流程稍多但操作并不复杂，对新手有一定挑战性。从备料到出锅，大约需要 1 小时 20 分钟。', '[{"name":"包菜","quantity":0.5,"unit":"颗"},{"name":"鸡蛋","quantity":2,"unit":"个"},{"name":"粉丝","quantity":1,"unit":"把"},{"name":"胡萝卜","quantity":0.5,"unit":"根"},{"name":"菜籽油","quantity":20,"unit":"ml"},{"name":"盐","quantity":2,"unit":"克"},{"name":"生抽","quantity":15,"unit":"ml"},{"name":"老抽","quantity":10,"unit":"ml"},{"name":"蚝油","quantity":10,"unit":"ml"},{"name":"葱","quantity":0.5,"unit":"根"},{"name":"蒜","quantity":2,"unit":"瓣"},{"name":"干辣椒","quantity":5,"unit":"根"}]'::jsonb, '["胡萝卜、包菜切丝备用","粉丝先用冷水浸泡 1 小时，然后将粉丝放入锅中，加入开水烧至粉丝烫软捞出备用","鸡蛋打入碗中，加入盐后搅拌 15 秒","葱、蒜、辣椒切成小粒备用","起锅烧油，倒入鸡蛋，打散炒熟盛出","再倒入油，放入葱、蒜、干辣椒翻炒 8 秒","下胡萝卜、包菜丝儿翻炒 30 秒","放入粉丝","放调料，生抽 15 ml，老抽 10 ml，蚝油 10 ml，盐 2 克","放入之前炒好的鸡蛋，翻炒约 15 秒","出锅摆盘"]'::jsonb, '["素菜","咸鲜","快炒","家常","下饭","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_1e3b18db61.jpg', 'https://www.bilibili.com/video/BV1QV411G7GU', '{"energyKcal":620,"protein":21,"carbs":70,"fat":30}'::jsonb, '[null,3600,15,null,null,8,30,null,null,15,null]'::jsonb),
  ('howtocook:vegetable_dish/印度土豆花菜', '印度土豆花菜', '素菜', 3, 25, '这道印度家常素菜以干香金黄、香料浓郁为特点，土豆绵软、花菜略带焦边，属于北印度风味。土豆和花菜富含膳食纤维与维生素 C，营养均衡。做法简单，对新手友好，从准备到出锅约需 25 分钟。', '[{"name":"土豆","quantity":2,"unit":"个"},{"name":"花菜","quantity":1,"unit":"个"},{"name":"洋葱","quantity":1,"unit":"个"},{"name":"番茄","quantity":1,"unit":"个"},{"name":"生姜","quantity":8,"unit":"克"},{"name":"大蒜","quantity":3,"unit":"瓣"},{"name":"青辣椒","quantity":1,"unit":"根"},{"name":"香菜","quantity":15,"unit":"克"},{"name":"食用油","quantity":30,"unit":"ml"},{"name":"孜然籽","quantity":3,"unit":"克"},{"name":"姜黄粉","quantity":3,"unit":"克"},{"name":"红辣椒粉","quantity":3,"unit":"克"},{"name":"香菜粉","quantity":5,"unit":"克"},{"name":"印度综合香料粉（Garam Masala）","quantity":3,"unit":"克"},{"name":"盐","quantity":5,"unit":"克"}]'::jsonb, '["将土豆去皮切成约 2cm 的块状","将花菜掰成均匀的小朵，大朵可用刀切小","在炒锅中倒入 30ml 食用油，中火加热","油热后放入孜然籽 3g，炸至孜然籽变深色且散发香味（约 10 秒，注意不要炸糊）","放入切碎的洋葱，翻炒至洋葱变透明微黄（约 3-4 分钟）","加入生姜、大蒜和青辣椒，翻炒 1 分钟","加入切碎的番茄，翻炒至番茄软烂（约 2-3 分钟）","加入姜黄粉 3g、红辣椒粉 3g、香菜粉 5g、盐 5g","翻炒 1 分钟，使香料与蔬菜融合","放入土豆块，翻炒 2 分钟使土豆表面裹上香料","放入花菜朵，轻轻翻拌均匀","盖上锅盖，转中小火，焖 12-15 分钟，期间每 3-4 分钟打开翻炒一次防止粘锅","当土豆用筷子可轻松戳透、花菜略有焦边时，撒入印度综合香料粉 3g","翻炒 1 分钟","关火，撒上香菜叶，盛盘"]'::jsonb, '["素菜","北印度","香辣","焖炒","家常","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_fc042d1c74.jpg', 'https://www.bilibili.com/video/BV1aR4y1M7Sd', '{"energyKcal":320,"protein":7,"carbs":41,"fat":16}'::jsonb, '[null,null,null,10,210,60,150,null,60,120,null,810,null,60,null]'::jsonb),
  ('howtocook:vegetable_dish/印度葫芦丸子', '印度葫芦丸子', '素菜', 4, 40, '这道北印度素菜将葫芦擦丝与鹰嘴豆粉团成丸子，油炸后浸入番茄洋葱咖喱，外酥内软、酱汁浓郁香辛。瓠瓜清润、鹰嘴豆粉提供植物蛋白与膳食纤维，是一道饱腹又均衡的素食。制作涉及油炸和熬酱，步骤稍多但按序操作不难掌握，全程大约需要 40 分钟。', '[{"name":"瓠瓜（葫芦）","quantity":1,"unit":"根"},{"name":"鹰嘴豆粉","quantity":80,"unit":"克"},{"name":"盐","quantity":3,"unit":"克"},{"name":"红辣椒粉","quantity":3,"unit":"克"},{"name":"香菜粉","quantity":3,"unit":"克"},{"name":"食用油","quantity":500,"unit":"ml"},{"name":"洋葱","quantity":2,"unit":"个"},{"name":"番茄","quantity":3,"unit":"个"},{"name":"生姜","quantity":10,"unit":"克"},{"name":"大蒜","quantity":4,"unit":"瓣"},{"name":"青辣椒","quantity":1,"unit":"根"},{"name":"食用油","quantity":30,"unit":"ml"},{"name":"姜黄粉","quantity":3,"unit":"克"},{"name":"红辣椒粉","quantity":5,"unit":"克"},{"name":"香菜粉","quantity":5,"unit":"克"},{"name":"孜然粉","quantity":3,"unit":"克"},{"name":"印度综合香料粉","quantity":3,"unit":"克"},{"name":"盐","quantity":5,"unit":"克"},{"name":"水","quantity":200,"unit":"ml"},{"name":"香菜","quantity":10,"unit":"克"}]'::jsonb, '["将瓠瓜去皮，用刨丝器刨成细丝","用手将瓠瓜丝中的水分挤干，尽量挤干，否则丸子炸不成型","在挤干水分的瓠瓜丝中加入鹰嘴豆粉 80g、盐 3g、红辣椒粉 3g、香菜粉 3g","用手充分混合均匀，揉成不粘手的面团状","将混合物搓成直径约 3cm 的小丸子，备用","在深锅中倒入 500ml 食用油，中火加热至油温约 170°C（放入一小块面团，能快速浮起且冒泡即可）","将丸子分批放入油中，炸 4-5 分钟，直至表面金黄酥脆","炸好的丸子用厨房纸吸去多余油分，备用","在炒锅中倒入 30ml 食用油，中火加热 10 秒","放入切碎的洋葱，翻炒至洋葱变成金棕色（约 5-7 分钟）","加入磨碎的生姜和大蒜，翻炒 1 分钟至香味散出","加入切碎的番茄，翻炒至番茄完全软烂出油（约 5 分钟）","加入姜黄粉 3g、红辣椒粉 5g、香菜粉 5g、孜然粉 3g、盐 5g","翻炒 2 分钟，使香料与番茄充分融合","加入 200ml 水，搅拌均匀，煮沸后转小火炖 5 分钟","将炸好的丸子轻轻放入酱汁中，小火炖 3-5 分钟，使丸子吸收酱汁","撒上印度综合香料粉 3g 和切碎的青辣椒","关火，撒上香菜叶装饰，盛盘"]'::jsonb, '["素菜","北印度","香辣","咖喱","素食","宴客"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_be188f5815.jpg', 'https://www.bilibili.com/video/BV1CB4y1T7CM', '{"energyKcal":300,"protein":6,"carbs":18,"fat":20}'::jsonb, '[null,null,null,null,null,null,null,null,10,null,60,300,null,120,300,null,null,null]'::jsonb),
  ('howtocook:vegetable_dish/地三鲜/地三鲜', '地三鲜', '素菜', 3, 40, '地三鲜是东北经典家常菜，茄子软糯、土豆绵香、尖椒清脆，酱香咸鲜十分下饭。食材搭配可提供丰富的维生素与膳食纤维，土豆还带来满足的碳水能量。这道菜需要油炸和快速翻炒，有一定技巧要求，新手需稍加练习，制作全程约需 40 分钟。', '[{"name":"茄子","quantity":200,"unit":"克"},{"name":"土豆","quantity":150,"unit":"克"},{"name":"尖椒","quantity":3,"quantityMax":4,"unit":"个"},{"name":"葱","quantity":5,"unit":"克"},{"name":"姜","quantity":5,"unit":"克"},{"name":"蒜","quantity":15,"unit":"克"},{"name":"豆瓣酱","quantity":15,"unit":"ml"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"糖","quantity":10,"unit":"克"},{"name":"淀粉","quantity":8,"unit":"克"}]'::jsonb, '["土豆、茄子、尖椒洗净。","土豆去皮。","茄子、土豆均切成 15g 的不规则的小块。","尖椒用手顺着纹路撕即可，撕成比土豆、茄子略大 25%的块。","尽可能除去青椒表面的水分，避免后续炸的时候炸水。考虑使用厨房纸或风干半小时。","葱切 0.5cm 小段，共取 5g。蒜剁碎成蒜蓉取 15g，分成两份，各 7.5g。姜切沫取 5g。","拿一个空碗，放入生抽 10ml、糖 10g、淀粉 8g，加入 80ml 清水，彻底搅拌均匀，作为调料碗，备用。","热锅，加入 150ml 油。","加入土豆，煎炸大约 3-4 分钟，以显示金黄色、筷子能轻松扎透为准。","捞出土豆，留下油。","加入茄子，煎炸大约 2-3 分钟，待其到大约 7 分熟，以茄子变软、边缘微焦且吐出多余油脂为准。","捞出茄子，留下油。（也可能没有残余的油了）","如果锅内已经没有流动的油，可以考虑补充 15ml 油。","加入尖椒块，煎炸大约 15 秒，边缘稍微起虎皮后，立刻捞出。倒出锅里的油。","重新热锅，重新加入 15ml 新底油。","放入葱 5g，姜 5g，蒜 7.5g。中小火爆香。","放入豆瓣酱 15ml。转小火，炒出红油和酱香味。","倒入调料碗。立刻转大火，高速搅拌避免糊锅！大约 10 秒后汤汁就会开始冒泡并变得黏稠。","立刻放入之前准备好的全部土豆、茄子和尖椒。","翻炒 20 秒，让浓稠的酱汁均匀挂在食材上。","关火，撒入 7.5g 蒜。翻拌均匀，盛盘。"]'::jsonb, '["素菜","东北","家常","下饭","酱香","煎炒"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_cd3758802b.jpg', 'https://www.bilibili.com/video/BV1pr421K7Fq', '{"energyKcal":580,"protein":8,"carbs":62,"fat":36}'::jsonb, '[null,null,null,null,1800,null,null,null,210,null,150,null,null,15,null,null,null,10,null,20,null]'::jsonb),
  ('howtocook:vegetable_dish/家常日本豆腐', '家常日本豆腐', '素菜', 3, 30, '家常日本豆腐是一道外酥里嫩的家常快手菜，金黄脆壳包裹着柔滑的玉子豆腐，搭配青椒、胡萝卜等时蔬，可调成咸鲜或酸甜风味，脆嫩咸香。日本豆腐以鸡蛋为主要原料，富含优质蛋白，加上木耳和蔬菜，营养均衡。需要一点煎豆腐的技巧，难度适中，新手也能尝试，全程大约 30 分钟即可上桌。', '[{"name":"日本豆腐","quantity":300,"unit":"克"},{"name":"青椒","quantity":120,"unit":"克"},{"name":"胡萝卜","quantity":50,"unit":"克"},{"name":"火腿肠","quantity":50,"unit":"克"},{"name":"黑木耳","quantity":30,"unit":"克"},{"name":"生粉","quantity":80,"unit":"克"},{"name":"洋葱","quantity":30,"unit":"克"},{"name":"蒜","quantity":10,"unit":"克"},{"name":"油","quantity":160,"quantityMax":165,"unit":"ml"},{"name":"生抽","quantity":8,"unit":"ml"},{"name":"蚝油","quantity":15,"unit":"ml"},{"name":"盐","quantity":2,"unit":"克"},{"name":"鸡精","quantity":3,"unit":"克"},{"name":"白砂糖","quantity":10,"unit":"克"},{"name":"番茄酱","quantity":15,"unit":"ml"}]'::jsonb, '["胡萝卜切片，尖椒切薄块，葱蒜碎切好","把买好的日本豆腐打开袋子切好，切成大概 1 cm 厚的圆柱体","生粉放到平盘中，准备给豆腐裹面","轻轻把豆腐放到面粉上，上下两面和周边都裹上面粉，注意不要包裹的太厚","在平底锅里放 150 ml 油，油能没过豆腐一大半即可，看边缘颜色变成金黄，翻面煎就可以了","两边都煎好的时候捞出来放在干净的盘里备用","在炒锅中倒入 10-15 ml 油，放入葱蒜，爆香后放入青椒、胡萝卜、火腿肠、黑木耳","加入蚝油、生抽、盐、鸡精、白砂糖、番茄酱","轻轻翻炒至颜色均匀"]'::jsonb, '["素菜","煎炒","咸鲜","酸甜","快手","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_c7aeccd7fa.jpg', 'https://www.bilibili.com/video/BV1tV4y187oV', '{"energyKcal":480,"protein":12,"carbs":32,"fat":38}'::jsonb, null),
  ('howtocook:vegetable_dish/小炒藕丁/小炒藕丁', '小炒藕丁', '素菜', 3, 20, '小炒藕丁是一道快手家常素菜，藕丁脆嫩爽口，咸鲜中带着微微辣意，非常下饭。莲藕富含膳食纤维和维生素，有助于清热润燥。制作简单，只要注意藕丁焯水和调味，厨房新手也能轻松完成。全程大约 20 分钟就能端上餐桌。', '[{"name":"大葱","quantity":1,"unit":"段"},{"name":"小米辣","quantity":1,"quantityMax":2,"unit":"根"},{"name":"莲藕","quantity":1,"unit":"段"},{"name":"生抽","quantity":30,"unit":"ml"},{"name":"老抽","quantity":15,"unit":"ml"},{"name":"蚝油","quantity":15,"unit":"ml"},{"name":"食用油","quantity":10,"quantityMax":15,"unit":"ml"}]'::jsonb, '["大葱、小米辣切小段，备用","莲藕去皮，切成不超过 3cm 的小块，放入水中备用（防止氧化发黑）","取炒锅，锅内放入 500ml 凉水，煮沸","将藕丁下入沸水中，焯水 2 分钟后，取出放入盘中备用","将锅中水倒掉后，将锅加热干燥，加入 10-15 ml 食用油","待油温升高后，下入葱花，小米辣爆香","将处理好的藕丁下入锅中，大火翻炒","加入生抽、老抽、耗油","翻炒 2 分钟即可出锅"]'::jsonb, '["素菜","咸鲜","微辣","快炒","家常","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_ec7ed74479.jpg', 'https://www.bilibili.com/video/BV1rK4y1R7cH', '{"energyKcal":300,"protein":7,"carbs":42,"fat":12}'::jsonb, '[null,null,null,120,null,null,null,null,120]'::jsonb),
  ('howtocook:vegetable_dish/干锅花菜/干锅花菜', '干锅花菜', '素菜', 3, 40, '干锅花菜是一道湘味家常菜，口感脆嫩干香，五花肉焦香四溢，带着微微辣意。花菜富含维生素 C 和膳食纤维，搭配五花肉补充蛋白质与能量。制作难度适中，只需注意焯水后充分沥干并把五花肉煸出油脂，适合有一定基础的烹饪新手。从准备到出锅大约需要 40 分钟。', '[{"name":"花菜","quantity":400,"unit":"克"},{"name":"五花肉","quantity":100,"unit":"克"},{"name":"辣椒","quantity":1,"quantityMax":2,"unit":"根"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"白糖","quantity":5,"unit":"克"},{"name":"蒜","quantity":3,"quantityMax":4,"unit":"个"},{"name":"盐","quantity":2,"unit":"克"},{"name":"油","quantity":10,"unit":"ml"}]'::jsonb, '["花菜朵朝下，没入淡盐水中浸泡 20 分钟。然后洗净用小刀拆成小朵","入开水锅中焯水 1 分钟，捞出立即用冷水冲淋至完全凉透，沥水备用","五花肉切成薄片，大蒜白色切下用刀背拍扁，小红辣椒切成段","锅烧热放油，油热下大葱白爆香","下五花肉片入锅，用中火煸炒至表面全部变色，继续煸炒一会儿，把肥肉部分的油份逼出一部分","倒入红辣椒段和花菜，翻炒几下","加入 10 ml 生抽","再加入 5 g 白糖，转大火不断翻炒 1 分钟","把大蒜叶部分切成段，放入锅中，翻炒几下后，关火盖上盖子焖 1 分钟即可"]'::jsonb, '["素菜","湘味","干锅","家常","下饭","干香"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_7f9aa481ba.jpg', 'https://www.bilibili.com/video/BV1hipUzaEHH', '{"energyKcal":740,"protein":19,"carbs":26,"fat":63}'::jsonb, '[1200,60,null,null,null,null,null,60,60]'::jsonb),
  ('howtocook:vegetable_dish/手撕包菜/手撕包菜', '手撕包菜', '素菜', 3, 20, '手撕包菜是一道酸辣脆爽的经典湘菜，成菜包菜脆嫩入味，五花肉干香不腻，开胃下饭。包菜富含维生素 C 和膳食纤维，搭配五花肉能提供蛋白质和能量。制作时需要掌握大火快炒的火候，对新手稍有挑战，但按步骤操作也能成功。从备料到出锅大约 20 分钟。', '[{"name":"包菜","quantity":1,"unit":"颗"},{"name":"五花肉","quantity":200,"unit":"克"},{"name":"小米辣","quantity":2,"unit":"根"},{"name":"食用油","quantity":60,"unit":"ml"},{"name":"料酒","quantity":5,"unit":"ml"},{"name":"生抽","quantity":5,"unit":"ml"},{"name":"香醋","quantity":5,"unit":"ml"},{"name":"鸡精","quantity":2,"unit":"克"},{"name":"姜","quantity":2,"unit":"片"},{"name":"蒜头","quantity":2,"unit":"粒"},{"name":"蒜苗","quantity":0.5,"unit":"根"},{"name":"盐","quantity":5,"unit":"克"}]'::jsonb, '["包菜对半切开，去掉中间白色部分【参见图一】","手撕包菜，碗中放入 2 g 盐，清洗包菜并沥干备用【参见图二】","姜片、蒜头、小米辣、蒜苗处理后备用【参见图三】","五花肉切片，清水清洗后备用","锅中加入 30 ml 食用油，倒入包菜翻炒，大火翻炒 1 分钟 后，加入 3 g 盐 ，继续翻炒 2 分钟 后取出备用","锅中加入 30 ml 食用油，倒入五花肉，大火翻炒 1 分钟","倒入姜片等材料，翻炒 1 分钟","倒入包菜翻炒后，加入 香醋、料酒、鸡精、料酒，大火继续翻炒，2 分钟 后出锅"]'::jsonb, '["素菜","酸辣","炒","湘菜","下饭","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_d66783f4c4.jpeg', 'https://www.bilibili.com/video/BV1mAGjzBEaZ', '{"energyKcal":1400,"protein":25,"carbs":25,"fat":120}'::jsonb, '[null,null,null,null,180,60,60,120]'::jsonb),
  ('howtocook:vegetable_dish/拔丝土豆/拔丝土豆', '拔丝土豆', '素菜', 3, 30, '拔丝土豆是一道经典的鲁菜，成菜色泽金黄、糖丝细长，外脆里糯、香甜可口。土豆富含碳水化合物和维生素 C，能快速补充能量。这道菜有一定难度，新手需注意熬糖火候，避免翻沙或焦苦。从备料到出锅，预计制作时长约 30 分钟。', '[{"name":"土豆","quantity":2,"unit":"个"},{"name":"食用油","quantity":300,"unit":"ml"},{"name":"淀粉","quantity":30,"unit":"克"},{"name":"白砂糖","quantity":120,"unit":"克"},{"name":"水","quantity":100,"unit":"ml"},{"name":"芝麻","quantity":5,"unit":"克"}]'::jsonb, '["土豆去皮，切均匀的小块。放入淀粉（不加水）搅拌，使得淀粉覆盖土豆表面","起锅烧油，放入土豆块，缓缓翻滚煎炸 5-7 分钟 ，直至筷子可以插进土豆","取出土豆，放入大碗备用","锅中加入水、白砂糖，沿着一个方向慢慢搅动白砂糖，直到白砂糖颜色变成褐色","重新倒入土豆，翻炒 30 S 后 出锅","土豆盛盘，散上芝麻"]'::jsonb, '["素菜","鲁菜","拔丝","甜香","煎炸","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_540c4aa099.jpeg', 'https://www.bilibili.com/video/BV1W541187Un', null, null),
  ('howtocook:vegetable_dish/松仁玉米', '松仁玉米', '素菜', 2, 15, '松仁玉米是一道口感清甜脆嫩的家常快手菜，松仁香酥、玉米甜润，属于广受欢迎的北方家常风味。玉米和松仁搭配，能提供丰富的膳食纤维、不饱和脂肪酸和多种维生素，营养均衡。做法简单，新手也能轻松驾驭，从备料到出锅一般只需大约十五 分钟。', '[{"name":"玉米粒","quantity":200,"unit":"克"},{"name":"熟松子仁","quantity":30,"unit":"克"},{"name":"胡萝卜","quantity":50,"unit":"克"},{"name":"食用油","quantity":15,"unit":"ml"},{"name":"白砂糖","quantity":10,"unit":"克"},{"name":"盐","quantity":1,"unit":"克"},{"name":"淀粉","quantity":5,"unit":"克"},{"name":"水","quantity":20,"unit":"ml"}]'::jsonb, '["玉米粒和胡萝卜丁提前焯水 1 分钟，捞出沥干备用","热锅凉油，放入胡萝卜丁略炒，再加入玉米粒翻炒","加入白砂糖和盐，炒匀","混合水与淀粉成水淀粉，倒入锅中快速翻炒使汤汁略稠","加入熟松仁翻炒均匀","出锅装盘"]'::jsonb, '["素菜","清淡","快手","家常","北方风味","炒"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_94767f2dea.jpg', 'https://www.bilibili.com/video/BV1o4UUYbEi3', '{"energyKcal":545,"protein":9.5,"carbs":54,"fat":34.5}'::jsonb, '[60,null,null,null,null,null]'::jsonb),
  ('howtocook:vegetable_dish/椒盐玉米/椒盐玉米', '椒盐玉米', '素菜', 3, 30, '一道外酥里嫩、咸香扑鼻的风味小食，有着川菜馆里常见的干香口感，咬开是玉米自带的清甜。玉米提供丰富的碳水化合物与膳食纤维，搭配芝麻还能补充优质脂肪和维生素 E。这道菜步骤略多但操作简单，需要一点耐心抖水裹粉，对新手比较友好。从解冻到出锅大约需要 30 分钟。', '[{"name":"玉米粒","quantity":350,"unit":"克"},{"name":"淀粉","quantity":40,"quantityMax":70,"unit":"克"},{"name":"椒盐","quantity":10,"unit":"克"},{"name":"芝麻粒","quantity":10,"unit":"克"},{"name":"油","note":"适量"},{"name":"塑料簸箕","quantity":2,"unit":"个"}]'::jsonb, '["玉米粒都是剥好的，直接解冻即可，温水泡 15 分钟或者灶上开水煮 5 分钟。","拿出一个簸箕，将其假设为 BoxA，垫上吸油纸，倒进解冻好的玉米粒。","shaking shaking shaking! - 直到吸油纸全部变湿为止。","拿出第二个簸箕 BoxB，垫上吸油纸，将 BoxA 的玉米粒全部倒入 BoxB 中。","shaking shaking shaking! - 直到吸油纸全部变湿为止。","重复上述操作多次，直到玉米表面没有明显可见的水滴但保持湿润的状态。","倒入大量淀粉，能够完全盖住玉米粒。","shaking shaking shaking! - 直到淀粉裹住了玉米粒","开灶 - 放锅 - 倒入油 尽量铺满锅底 但不要太多。","油热 8 成，倒入裹上了淀粉的玉米粒。","中火先煎 30s，不要翻炒，不然淀粉会掉。","轻微翻炒 3 分钟即可出锅。","最重要的一步：撒上 3g 椒盐，撒上芝麻粒！","香喷喷的”椒盐玉米“就做好了"]'::jsonb, '["素菜","咸香","香酥","川菜","家常","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_1c5aec3ef4.jpeg', 'https://www.bilibili.com/video/BV1zj41167rn', '{"energyKcal":750,"protein":13,"carbs":114,"fat":29}'::jsonb, '[900,null,null,null,null,null,null,null,null,null,30,180,null,null]'::jsonb),
  ('howtocook:vegetable_dish/榄菜肉末四季豆/榄菜肉末四季豆', '榄菜肉末四季豆', '素菜', 3, 30, '榄菜肉末四季豆是潮汕风味浓厚的家常小炒，口感咸香脆嫩，十分下饭。四季豆富含膳食纤维与维生素，搭配肉末能提供优质蛋白，橄榄菜则带来独特的鲜咸风味。这道菜步骤清晰，新手也能较快上手，只需注意将四季豆彻底炒熟。从备料到出锅，大约三十分钟即可完成。', '[{"name":"四季豆","quantity":220,"unit":"克"},{"name":"五花肉","quantity":100,"unit":"克"},{"name":"橄榄菜","quantity":20,"unit":"克"},{"name":"大蒜","quantity":10,"unit":"克"},{"name":"小米辣","quantity":10,"unit":"克"}]'::jsonb, '["将四季豆洗净，并把筋撕干净，然后切成大小均匀的颗粒备用。","将大蒜拍碎剁成蒜末备用。","将小米辣切成大小均匀的颗粒备用。","将五花肉去皮，然后剁成肉末备用。","将锅烧热，然后加入 20ml 油滑锅，锅滑好之后将热油倒出，然后加入 10ml 冷油，这就是传说中热锅冷油，这么做主要是防止肉末粘锅。","如果家里没有晾油瓶的话，也可以不用滑锅，放入油之后，直接加入肉末开始煸炒，小火煸炒两分钟，炒出猪油。","肉末炒香之后加入蒜末，橄榄菜和小米辣，炒出香味。","加入四季豆开中火煸炒，四季豆至少要炒 5 分钟，一定要保证四季豆熟透，否则可能会食物中毒。","四季豆炒熟后加入 2ml 酱油从锅边淋入，然后加入 2g 盐、1g 鸡精、1g 胡椒粉和 0.5g 糖。","将调料翻炒均匀。","出锅，装盘。"]'::jsonb, '["素菜","咸香","潮汕","下饭","小炒"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_3972041935.jpg', 'https://www.bilibili.com/video/BV1AP411C7fE', '{"energyKcal":540,"protein":16,"carbs":18,"fat":47}'::jsonb, '[null,null,null,null,null,120,null,300,null,null,null]'::jsonb),
  ('howtocook:vegetable_dish/水油焖蔬菜', '水油焖蔬菜', '素菜', 2, 10, '水油焖蔬菜是一道简单快手的家常佐餐，通过沸水加几滴油和调料，让叶菜口感软嫩、色泽油亮，既清爽又带有淡淡油香。这种做法有助于提高脂溶性维生素的吸收率，比生吃蔬菜更有营养价值。烹饪难度低，对新手非常友好，从洗菜到出锅一般只需 10 分钟。', '[{"name":"叶菜类蔬菜","quantity":300,"quantityMax":500,"unit":"克"},{"name":"食用油","quantity":2,"unit":"ml"},{"name":"盐","quantity":3,"unit":"克"},{"name":"蚝油","quantity":3,"unit":"ml"}]'::jsonb, '["洗净蔬菜","锅中加入 150ml 水，并烧开。（水不需要能完全没过蔬菜）","加入 3g 盐","（可选）加入 3ml 蚝油","加入 2ml 食用油","下菜， 翻拌一下，然后盖上锅盖焖 1 分钟","盛盘"]'::jsonb, '["素菜","清淡","焖制","快手","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_c6fb813e06.jpg', 'https://www.bilibili.com/video/BV15T411D7pA', '{"energyKcal":110,"protein":10,"carbs":14,"fat":3}'::jsonb, '[null,null,null,null,null,60,null]'::jsonb),
  ('howtocook:vegetable_dish/油醋爆蛋', '油醋爆蛋', '素菜', 2, 15, '这是一道湘味十足的家常快手下饭菜，酸辣鲜香，鸡蛋焦香蓬松裹满浓郁汤汁，十分开胃。鸡蛋提供优质蛋白质和卵磷脂，搭配香醋更有助于促进食欲。做法极其简单，新手友好，从准备到出锅仅需大约十分钟。', '[{"name":"鸡蛋","quantity":4,"unit":"个"},{"name":"小米辣","quantity":10,"unit":"g"},{"name":"食用油","quantity":35,"quantityMax":50,"unit":"ml"},{"name":"小葱","quantity":10,"unit":"g"},{"name":"蒜","quantity":5,"unit":"g"},{"name":"香醋","quantity":15,"unit":"ml"},{"name":"生抽","quantity":10,"quantityMax":15,"unit":"ml"},{"name":"蚝油","quantity":10,"unit":"g"},{"name":"白糖","quantity":0,"quantityMax":5,"unit":"g"}]'::jsonb, '["鸡蛋不需打散，直接打入碗中备用","香葱切 3cm 长小段即可","蒜瓣和小米辣放入打蒜器，打成沫","将香醋、生抽、蚝油、白糖、水加入小碗，搅拌均匀作为糖醋料汁","油热倒入鸡蛋，等鸡蛋凝固之后铲成大块，倒入蒜沫、小米辣沫、倒入糖醋料汁","大火收汁、快出锅时加入葱段即可"]'::jsonb, '["素菜","酸辣","快手","下饭","家常","湘味"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_9107f0d09d.jpg', 'https://www.bilibili.com/video/BV16C4y127jt', '{"energyKcal":630,"protein":24.5,"carbs":9,"fat":59}'::jsonb, null),
  ('howtocook:vegetable_dish/洋葱炒鸡蛋/洋葱炒鸡蛋', '洋葱炒鸡蛋', '素菜', 2, 5, '洋葱炒鸡蛋是一道咸香适口、葱香浓郁的家常菜肴，鸡蛋嫩滑，洋葱清甜，属于国民下饭菜。鸡蛋富含优质蛋白质和多种维生素，洋葱含有膳食纤维和抗氧化物质，是一道营养均衡的快手菜。这道菜操作极其简单，对新手非常友好，从备料到出锅只需约 5 分钟。', '[{"name":"鸡蛋","quantity":2,"unit":"个"},{"name":"洋葱","quantity":50,"unit":"g"},{"name":"食用油","quantity":50,"unit":"ml"},{"name":"盐","quantity":2,"unit":"g"},{"name":"葱","quantity":0.5,"unit":"根"},{"name":"料酒","quantity":2,"unit":"ml"}]'::jsonb, '["鸡蛋打入大碗中，加入洋葱片、盐后搅拌 60 S","起锅烧油，倒入鸡蛋，一面煎炸 30-45 S ，翻面继续翻炒，反复 2-3 分钟 后散上料酒出锅","鸡蛋装盘，散上葱花"]'::jsonb, '["素菜","咸香","家常","快手","下饭菜","炒"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_1c5ccf176e.jpeg', 'https://www.bilibili.com/video/BV1Dp4y1k7Mu', null, null),
  ('howtocook:vegetable_dish/清炒花菜', '清炒花菜', '素菜', 2, 15, '一道常见的家常素菜，口感脆嫩爽口。富含维生素 C 和膳食纤维。做法简单快捷，一般初学者仅需 15 分钟即可完成。', '[{"name":"花菜","quantity":300,"unit":"g"},{"name":"大蒜","quantity":2,"quantityMax":3,"unit":"瓣"},{"name":"盐","quantity":3,"unit":"g"},{"name":"食用油","quantity":15,"unit":"ml"},{"name":"饮用水","quantity":50,"unit":"ml"}]'::jsonb, '["将 花菜 洗净，用刀或手掰成小朵，粗茎部分可以切片，备用。","将 大蒜 去皮，切成蒜片，备用。","锅中加入 1000 ml 饮用水，大火烧开。","放入 花菜 朵，煮 2-3 分钟，至花菜颜色变浅，口感稍微软化。","将 煮好的 花菜 捞出，沥干水分，备用。","热锅，加入 15 ml 食用油，大火烧热。","放入 蒜片，快速煸炒出香味。","放入 焯好水的 花菜 朵，转中大火，快速翻炒约 2 分钟，使花菜均匀受热。","加入 3 g 盐，继续翻炒均匀。","沿锅边淋入 50 ml 饮用水，盖上锅盖，焖 1 分钟，帮助花菜完全熟透入味。","开盖，快速翻炒均匀，即可出锅。"]'::jsonb, '["素菜","清淡","清炒","家常","快手","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_564a86813e.jpg', 'https://www.bilibili.com/video/BV1u14y1e7g9', '{"energyKcal":200,"protein":6,"carbs":15,"fat":14}'::jsonb, '[null,null,null,120,null,null,null,120,null,60,null]'::jsonb),
  ('howtocook:vegetable_dish/清蒸南瓜', '清蒸南瓜', '素菜', 1, 20, '一道原汁原味的家常蒸菜，最大程度保留南瓜的天然甜味与营养，口感软糯香甜，既可当甜点也可作主食。南瓜富含β-胡萝卜素和膳食纤维，有益视力与肠胃健康。制作极其简单，新手也能轻松搞定，从切配到出锅仅需 15-20 分钟。', '[{"name":"南瓜","quantity":300,"unit":"g"},{"name":"饮用水","quantity":1000,"unit":"ml"}]'::jsonb, '["将 南瓜 外皮洗净，去除瓜瓤和籽。","将 南瓜 切成厚度大约 2 cm 的片，备用。","在 蒸锅 的锅中加入 1000 ml 饮用水。","将切好的 南瓜 片均匀摆放在盘中。","待蒸锅中的水烧开后，将装有 南瓜 的盘子放入蒸锅中。","盖上锅盖，保持大火蒸 15-20 分钟，直至南瓜变软，可以用筷子轻松穿透。","关火，小心取出盘子。"]'::jsonb, '["素菜","清淡","蒸菜","快手","家常","素食"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_66b9e64907.jpg', 'https://www.bilibili.com/video/BV1pE411Y7gh', '{"energyKcal":78,"protein":3,"carbs":19.5,"fat":0.3}'::jsonb, '[null,null,null,null,null,900,null]'::jsonb),
  ('howtocook:vegetable_dish/炒滑蛋/炒滑蛋', '炒滑蛋', '素菜', 1, 5, '炒滑蛋是一道口感嫩滑、蛋香浓郁的经典家常菜，带有淡淡的奶香。鸡蛋富含优质蛋白质和多种维生素，营养丰富，易于吸收。做法非常友好，新手也能轻松掌握，从备料到出锅只需约 5 分钟，是忙碌时快速补充能量的理想选择。', '[{"name":"鸡蛋","quantity":4,"unit":"颗"},{"name":"牛奶","quantity":30,"unit":"ml"},{"name":"食用油","quantity":10,"unit":"ml"}]'::jsonb, '["鸡蛋加入牛奶以及 5ml 食用油搅拌均匀，备用","大火烧热平底锅约 30s, 加入 5ml 食用油","烧 30s 转小火, 并且放入搅拌好的鸡蛋","在锅中静置 5 秒后，用锅铲将蛋液从边缘缓慢推向中间","翻炒至鸡蛋大致凝固后关火，装盘"]'::jsonb, '["素菜","鲜香","嫩滑","快手","家常","早餐"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_15256ed1ea.jpg', 'https://www.bilibili.com/video/BV1G1421S7E6', '{"energyKcal":380,"protein":25,"carbs":2,"fat":30}'::jsonb, '[null,30,30,5,null]'::jsonb),
  ('howtocook:vegetable_dish/炒茄子', '炒茄子', '素菜', 3, 20, '这道家常炒茄子软嫩入味，酱香浓郁，加八角后风味更足。茄子富含膳食纤维、维生素 P 和钾元素，有助于保护心血管。做法简单，对新手友好，全程大火快炒，从备料到出锅大约二十分钟即可完成。', '[{"name":"茄子","quantity":1.8,"unit":"个"},{"name":"八角（可选）","quantity":1,"unit":"个"},{"name":"虾皮（可选）","quantity":0.5,"unit":"把"},{"name":"香葱（可选）","quantity":2,"unit":"颗"},{"name":"肉末（可选）","quantity":50,"unit":"克"},{"name":"酱油","quantity":40,"unit":"ml"},{"name":"糖（可选）","quantity":5,"unit":"克"},{"name":"醋（可选）","quantity":10,"unit":"ml"},{"name":"菜籽油或花生油","note":"适量"}]'::jsonb, '["将茄子洗净，一刀分为两段（竖切）。每段的茄子切菱形块，将切好的茄子放入碗中待命。","将香葱洗净，并切成葱花放到案板上待命。","切好八角，放到案板上待命。","如果打算放肉末，先用 10 ml（如果是纯瘦肉，用 15 ml）油中火炒至变色（约 1 分钟），然后盛出备用。","开火热锅，直至锅内没有水。","往锅内倒食用油，没过锅底的两倍（油可以多加，但不可少加）。","热油约 6 成熟，放入八角、虾皮、香葱这三种可选性材料。","如果没有八角等可选材料，热油至 9 成熟。","待锅内的油到 9 成熟，将碗中的茄子倒入锅内用锅铲进行翻炒。","翻炒约 40 秒，将锅铲悬空，与锅平行，把酱油倒入锅铲内。一人约 2.5 锅铲（酱油可以少加，但不可多加，会咸）。","茄子炒到半软时（约 1 分钟后），放回预炒的肉末，快速搅拌均匀。","如果打算加入糖和醋，加入糖和醋。","继续进行翻炒。","等到锅内所有茄子变色且变软时捞出。"]'::jsonb, '["素菜","家常","快手","下饭","鲜香","大火快炒"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_2fa6b77bd9.jpg', 'https://www.bilibili.com/video/BV1HF411j7iB', '{"energyKcal":680,"protein":15,"carbs":30,"fat":55}'::jsonb, '[null,null,null,60,null,null,null,null,null,40,60,null,null,null]'::jsonb),
  ('howtocook:vegetable_dish/炒青菜', '炒青菜', '素菜', 2, 10, '这是一道清爽可口的家常素菜，口感脆嫩、咸鲜回甘。青菜富含维生素与膳食纤维，有助于促进消化。做法非常简单，零基础也能轻松驾驭，从备菜到出锅大约只需 10 分钟。', '[{"name":"青菜","quantity":100,"unit":"克"},{"name":"蒜瓣","quantity":2,"unit":"粒"},{"name":"食用油","quantity":10,"quantityMax":15,"unit":"ml"},{"name":"食盐","quantity":2,"unit":"克"},{"name":"饮用水","quantity":70,"unit":"ml"},{"name":"白糖","quantity":5,"unit":"克"}]'::jsonb, '["青菜掰成小瓣，用清水洗净，备用。","将蒜瓣剁碎，备用","中火或大火热锅后，锅内放入 10-15ml 食用油。再等待 30 秒让油温升高。","将准备好的青菜倒入锅中，翻炒至青菜变软（约 1 分钟）。","放入剁碎的蒜瓣","倒入计算好的清水，水位应当完全浸润或即将没过青菜，加入食盐 （2g 份数），继续翻炒约 1 分钟。","最后加入白糖小火加热 2 分钟，加热时盖上锅盖。","盛盘。"]'::jsonb, '["素菜","清淡","鲜香","家常","快手","清炒"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_850d413b3f.jpg', 'https://www.bilibili.com/video/BV1of4y1B7gs', '{"energyKcal":140,"protein":2.2}'::jsonb, '[null,null,30,60,null,60,120,null]'::jsonb),
  ('howtocook:vegetable_dish/烤茄子/烤茄子', '烤茄子', '素菜', 3, 30, '烤茄子香气浓郁、外焦里嫩，孜然和蒜蓉的辛香完美融入软糯的茄肉，是街头烧烤风味在家轻松复刻的菜品。茄子富含维生素 P 和花青素，有助于保护心血管、抗氧化。做法需要用到烤箱，但步骤清晰，新手也能在大约半 小时完成，很适合作为家庭聚餐的快手下饭菜。', '[{"name":"茄子","quantity":1,"unit":"个"},{"name":"食用油","quantity":20,"quantityMax":30,"unit":"毫升"},{"name":"酱油（生抽）","quantity":4,"quantityMax":6,"unit":"克"},{"name":"小米椒","quantity":1,"unit":"个"},{"name":"蒜蓉","quantity":3,"quantityMax":4,"unit":"瓣"},{"name":"孜然","quantity":1,"quantityMax":3,"unit":"克"},{"name":"食用盐","quantity":0.5,"quantityMax":2,"unit":"克"}]'::jsonb, '["将酱油、孜然、食用盐、蒜蓉和切碎的小米椒置于碗中，均匀搅拌备用","茄子洗净，用纸巾擦干表面的水分","用叉子在茄子的一侧扎 4-8 下","使用 15-25ml 的食用油涂满茄子表面","将烤箱温度设置为 200℃ （打开烤箱风扇 大火），预热 2 分钟","将茄子放入烤箱中层或者上层，烤制 12-15 分钟 （茄子表面有褶皱，且能按压 0.3-0.5cm 的深度即可）","取出茄子，用刀茄子上竖着划一个口子。口子居中，上下距 1-1.5cm","用小刀或者叉子伸入口子，竖着切割茄子内部","将口子微微掰开，倒入第一步准备的酱料","再次将茄子放入烤箱，将烤箱温度设置为 200℃ ，烤制 4-7 分钟","取出，关闭烤箱电源"]'::jsonb, '["素菜","蒜香","孜然","烤制","快手","家常","下饭菜"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_44afe6e31c.jpg', 'https://www.bilibili.com/video/BV1Ff4y1P7ng', '{"energyKcal":280,"protein":3.5,"carbs":16,"fat":22}'::jsonb, '[null,null,null,null,120,720,null,null,null,240,null]'::jsonb),
  ('howtocook:vegetable_dish/白灼菜心/白灼菜心', '白灼菜心', '素菜', 2, 15, '这道经典粤菜采用白灼技法，沸水快焯保留菜心的清甜与脆嫩，根茎尤为爽口，味道清淡鲜美。富含维生素 C 和膳食纤维，低脂低热量，适合追求健康饮食的人群。做法非常简单，预估难度仅两星，一般初学者只需 15 分钟即可完成，是快速补充绿叶蔬菜的理想选择。', '[{"name":"新鲜菜心","quantity":250,"unit":"克"},{"name":"生抽","quantity":5,"unit":"克"},{"name":"蚝油","quantity":5,"unit":"克"},{"name":"盐","quantity":5,"unit":"克"},{"name":"大蒜","quantity":4,"quantityMax":5,"unit":"瓣"},{"name":"小米辣","quantity":1,"quantityMax":2,"unit":"根"},{"name":"食用油","quantity":10,"unit":"克"}]'::jsonb, '["菜心洗净，去除根部比较硬或老的地方。此处还用刀刮了刮菜心根茎部分，刮掉外面那层比较硬的，菜心内部更可口，但要注意根茎白灼时长，时间太长的话根茎不脆了","大蒜切成蒜末，有洋葱顺便加了点洋葱","调制灵魂料汁：生抽 5g 吧、蚝油 5g，加 3g 糖和 100g 清水半碗成一碗汁儿","一锅 500ml 清水加 5g 盐和 10g 食用油烧开","将菜心根茎在沸水中烫 1 分钟，直到根茎颜色变成深绿。再将整个菜心放到锅中烫熟 1 分钟，捞起来码入盘中","开另一小锅将兑好的料汁倒入，小火烧开，放入一半的蒜末，一点点姜丝和小米椒碎。在制作时加了一点点洋葱碎和大蒜，先在锅底倒油，五成热后倒入蒜末、洋葱，稍稍爆香后再加入料汁，加入小米辣煮开","料汁稍微收汁，煮沸后稍等十来秒吧，后直接浇在菜心上，不要特别多，但蒜末还是很给力的不要少蒜"]'::jsonb, '["素菜","粤菜","白灼","清淡","快手","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_e8cb377dc5.jpg', 'https://www.bilibili.com/video/BV1LE41157Xb', '{"energyKcal":150,"protein":4,"carbs":9,"fat":10}'::jsonb, '[null,null,null,null,120,null,null]'::jsonb),
  ('howtocook:vegetable_dish/皮蛋豆腐', '皮蛋豆腐', '素菜', 1, 5, '皮蛋豆腐是一道清爽开胃的凉拌家常菜，松花蛋 Q 弹滑嫩，嫩豆腐入口即化，咸香微酸的口味特别下饭。豆腐富含优质植物蛋白和钙，皮蛋则提供铁、维生素 A 等营养素，搭配食用易于消化吸收。制作过程几乎零门槛，新手也能轻松完成，从备料到上桌仅需 大约 5 分钟。', '[{"name":"皮蛋","quantity":2,"unit":"个"},{"name":"内酯豆腐","quantity":1,"unit":"盒"},{"name":"生抽","quantity":15,"unit":"ml"},{"name":"白砂糖","quantity":2.5,"unit":"克"},{"name":"醋（推荐镇江香醋）","quantity":15,"unit":"ml"},{"name":"香油（可选）","quantity":15,"unit":"ml"},{"name":"辣椒油（可选）","quantity":10,"unit":"ml"},{"name":"花生碎（可选）","quantity":10,"unit":"克"},{"name":"葱花（可选）","quantity":15,"unit":"克"},{"name":"香菜（可选）","quantity":1,"unit":"株"}]'::jsonb, '["先把皮蛋剥壳，切成四瓣。","嫩豆腐切块或者切片放中间。","将生抽、白砂糖、醋、香油、辣椒油调成酱汁，淋上去。","最后可选撒上花生碎、葱花、香菜。"]'::jsonb, '["素菜","凉拌","快手","家常","清爽","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_63141cfeef.jpg', 'https://www.bilibili.com/video/BV1PZ421T7Pw', '{"energyKcal":620,"protein":30,"carbs":15,"fat":45}'::jsonb, null),
  ('howtocook:vegetable_dish/糖拌西红柿/糖拌西红柿', '糖拌西红柿', '素菜', 2, 15, '这是一道适合夏季的家常凉菜，酸甜爽口，制作简便。西红柿富含维生素 C，开胃解腻。新手也能轻松完成，整个过程（包含冷藏）约 15 分钟即可上桌。', '[{"name":"西红柿","quantity":2,"unit":"个"},{"name":"白砂糖","quantity":20,"unit":"克"}]'::jsonb, '["用刀将西红柿皮米字型划开","用筷子插入西红柿的菊花，在燃气上转动烤 10 秒（或用开水冲 30 秒），直到西红柿皮卷边","把西红柿的衣服脱光","再西红柿大卸八块（沿纹路切可以更多的留汁水），去掉头部根蒂部，备用","全部切好后，将西红柿在盘子中均匀码一层","撒上白糖，重复上面一步直到全部西红柿放完","放入冰箱冷藏 10 分钟","一盘糖拌西红柿就好了，营养美味，酸甜爽口，夏日解暑又解腻"]'::jsonb, '["素菜","酸甜","凉拌","家常","快手","解暑"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_ac27219904.jpg', 'https://www.bilibili.com/video/BV1564y1t7mX', '{"energyKcal":130,"protein":4,"carbs":32,"fat":0}'::jsonb, '[null,10,null,null,null,null,600,null]'::jsonb),
  ('howtocook:vegetable_dish/红烧冬瓜/红烧冬瓜', '红烧冬瓜', '素菜', 3, 25, '红烧冬瓜是一道色泽红亮、香鲜味美的家常素菜，口感软糯入味，属于大众喜爱的中式烧菜。冬瓜本身富含水分、膳食纤维和维生素 C，具有清热解暑、利尿消肿的作用，搭配简单的调味料，营养又好消化。这道菜对初学者比较友好，操作步骤清晰，只需掌握好火候和调味，预计制作时长约 25 分钟。', '[{"name":"冬瓜","quantity":300,"unit":"g"},{"name":"食用油","quantity":50,"unit":"ml"},{"name":"料酒","quantity":2,"unit":"ml"},{"name":"淀粉","quantity":10,"unit":"g"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"老抽","quantity":15,"unit":"ml"},{"name":"鸡精","quantity":3,"unit":"g"},{"name":"香葱","quantity":0.5,"unit":"根"},{"name":"姜末","quantity":1,"unit":"粒"},{"name":"蚝油","quantity":15,"unit":"ml"}]'::jsonb, '["冬瓜去皮，切 边长不超过 2cm 小块","起锅烧油，放入冬瓜，缓缓翻滚煎炸 2 分钟 ，直至冬瓜表面泛金黄色","取出冬瓜，放入大碗备用","利用锅中的剩余油，依次放入姜末、生抽、蚝油，翻炒 15 S","重新倒入冬瓜，翻炒 30 S 后，加入开水，水要没过冬瓜表面，大火煮 10 分钟","加入老抽上色，继续煮，直至冬瓜软糯（筷子可以轻松插近冬瓜）","加入鸡精、料酒、香葱翻炒后 30 S， 取出冬瓜到大碗中","锅中剩余汤汁保留，倒入水淀粉，煮开后汤汁浇灌在冬瓜表面"]'::jsonb, '["素菜","红烧","咸鲜","家常","快手","软糯"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_2c030740d6.jpeg', 'https://www.bilibili.com/video/BV1fG411T7GQ', null, null),
  ('howtocook:vegetable_dish/红烧茄子', '红烧茄子', '素菜', 4, 45, '红烧茄子是一道咸香浓郁的家常下饭菜，软糯的茄块吸饱汤汁，搭配柿子椒和番茄，酸辣适口。茄子富含膳食纤维和维生素 P，炸过的茄块香而不腻。制作需要挂糊油炸并慢烧入味，步骤略多但对新手仍可尝试，专注细节就能成功。从备料到出锅大约需要 45 分钟。', '[{"name":"大蒜","quantity":3,"unit":"瓣"},{"name":"大葱","quantity":0.5,"unit":"颗"},{"name":"青辣椒","quantity":0.5,"unit":"个"},{"name":"洋葱","quantity":0.3,"unit":"个"},{"name":"西红柿","quantity":1,"unit":"个"},{"name":"青茄子","quantity":0.7,"unit":"个"},{"name":"盐","note":"适量"},{"name":"酱油","note":"适量"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"面粉","quantity":150,"unit":"克"},{"name":"淀粉","note":"适量"}]'::jsonb, '["青茄子、青辣椒、西红柿、洋葱、大葱洗净。","大葱切 5 毫米宽的葱花，大蒜扒皮并拍碎，西红柿切 6 立方厘米的块，青辣椒、洋葱切 5g 的块。","茄子切菱形块（先切 2 公分厚的片，然后再把片切成 2 公分的条，最后斜刀切块儿...）。","将面粉倒入盆中，依次加入少量水，搅拌均匀，呈粘稠糊状。","加入淀粉，加入 30 克水，搅拌均匀。","将鸡蛋打到盆中，加入（面粉 / 20）克的盐，搅拌均匀。","将茄块倒入面糊中，搅拌使茄块的每一面都能沾上面糊。","开大火，热锅，加入 500 毫升的油，当能看到锅里的油冒出一丝烟时，调至小火，将茄块用筷子夹入到油锅，待所有的茄块下锅之后，调至中火，直到茄块变金黄色时捞出，将油倒出。","加入（份数 5）g 的油，放入大蒜、葱花，翻炒 15 秒，放入青辣椒块翻炒 30 秒，放入西红柿翻炒 30 秒。","放入炸好的茄块，加水面高度为锅内食材的 0.8 倍。","放入酱油和（份数 3）g 的盐。","等待，直到汤汁呈粘稠状（水位大概为剩余食材高度的 0.2-0.3 倍），开盖，盛出菜，关火。"]'::jsonb, '["素菜","咸香","红烧","家常","下饭菜","油炸"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_a679274106.jpg', 'https://www.bilibili.com/video/BV1ot4y1S7Hf', '{"energyKcal":780,"protein":13,"carbs":75,"fat":43}'::jsonb, '[null,null,null,null,null,null,null,null,75,null,null,null]'::jsonb),
  ('howtocook:vegetable_dish/素炒豆角', '素炒豆角', '素菜', 2, 20, '这是一道酱香浓郁的家常小炒，豆角软嫩入味，鲜辣下饭。富含膳食纤维和多种维生素，有助于促进消化。做法简单，新手也能轻松上手，从备菜到出锅大约 20 分钟。', '[{"name":"豆角","quantity":250,"unit":"克"},{"name":"小米椒","quantity":2,"unit":"个"},{"name":"葱","quantity":3,"unit":"圈"},{"name":"蒜","quantity":2,"unit":"颗"},{"name":"生抽","quantity":6,"unit":"ml"},{"name":"老抽","quantity":2,"unit":"ml"},{"name":"耗油","quantity":6,"unit":"ml"},{"name":"盐","quantity":6,"unit":"克"},{"name":"油","quantity":10,"quantityMax":15,"unit":"ml"},{"name":"水","quantity":150,"unit":"ml"}]'::jsonb, '["葱切花，蒜切沫，备用。","生抽、老抽、耗油、盐混合调料汁，备用。","小米椒切圈，备用。","豆角去筋，45° 斜切4-10cm小段，备用。","起锅烧油(10ml - 15ml)，冒烟后放入葱、小米椒，翻炒至闻到香味；","加入豆角，翻炒30s,","加入料汁，开大火翻炒2分钟","倒入 150ml 水","转中小火，盖上锅盖焖制 8-10 分钟","加入蒜切沫，出锅。"]'::jsonb, '["素菜","鲜香","素炒","下饭","快手","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_38c48ba3f1.jpg', 'https://www.bilibili.com/video/BV1mp4y1a7jy', '{"energyKcal":200,"protein":6,"carbs":16,"fat":13}'::jsonb, '[null,null,null,null,null,30,120,null,480,null]'::jsonb),
  ('howtocook:vegetable_dish/脆皮豆腐', '脆皮豆腐', '素菜', 3, 30, '脆皮豆腐外酥里嫩，酱汁咸甜适口，是一道快手下饭菜。豆腐富含植物蛋白和钙质，鸡蛋提供优质蛋白，营养搭配均衡。制作需要耐心煎出金黄脆皮，但步骤清晰，初学者也能掌握，全程大约需要 30 分钟。', '[{"name":"老豆腐","quantity":1,"unit":"块"},{"name":"鸡蛋","quantity":2,"unit":"只"},{"name":"生抽","quantity":20,"unit":"克"},{"name":"老抽","quantity":5,"unit":"克"},{"name":"蚝油","quantity":10,"unit":"克"},{"name":"白糖","quantity":10,"unit":"克"},{"name":"玉米淀粉","quantity":50,"unit":"克"},{"name":"食用油","quantity":18,"unit":"ml"}]'::jsonb, '["鸡蛋搅拌形成蛋液放置备用","配置酱料 （20 g 生抽+10 g 蚝油+5 g 老抽+10 g 白糖+10 g 玉米淀粉+200 ml 清水）","老豆腐切片 （个人建议，仅供参考 人 5 片，厚度 1.2 cm）","玉米淀粉倒入盘中，将老豆腐片粘上淀粉后，粘上蛋液，放置一旁","热锅，锅内放入 18ml 食用油。等待 10 秒让油温升高","将粘上蛋液的老豆腐片均匀放入锅中，铺好锅底，小火煎至金黄翻面","待两面煎至金黄后，倒入酱料，让每块豆腐都沐浴在酱料中，大火 3 分钟至酱汁浓稠","关火"]'::jsonb, '["素菜","咸甜","煎","家常","下饭","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_e06abcb03d.jpg', 'https://www.bilibili.com/video/BV11wuTzqErh', '{"energyKcal":782,"protein":38,"carbs":66,"fat":42}'::jsonb, '[null,null,null,null,10,null,180,null]'::jsonb),
  ('howtocook:vegetable_dish/芹菜拌茶树菇/芹菜拌茶树菇', '芹菜拌茶树菇', '素菜', 2, 30, '这是一道清爽脆嫩的凉拌菜，芹菜脆嫩与茶树菇的嚼劲相得益彰，口感层次丰富。富含多种维生素和矿物质，营养又开胃。做法非常简单，新手也能轻松掌握，从备菜到完成只需约 30 分钟。', '[{"name":"闽星茶树菇","quantity":1,"unit":"瓶"},{"name":"芹菜","quantity":250,"quantityMax":300,"unit":"克"},{"name":"香油","quantity":5,"unit":"ml"},{"name":"蚝油","quantity":7,"unit":"ml"},{"name":"味极鲜","quantity":3,"unit":"ml"},{"name":"食用盐","quantity":2,"unit":"克"}]'::jsonb, '["（如果是芹菜苗这一步略过）用热水壶烧一壶热水,备用","新鲜的芹菜苗或者芹菜摘去黄叶清洗,备用","（如果是芹菜苗这一步略过）将芹菜摘去叶子单独放一个盆中,将芹菜茎用刀划成 2-3 毫米宽的芹菜条备用,这一步的目的是让芹菜断生的更快更均匀,吃起来更脆更爽口","芹菜苗切成 4cm 的芹菜段,备用","（如果是芹菜苗这一步略过）起锅开火,将热水壶的开水倒入锅中待水起泡沸腾","（如果是芹菜苗这一步略过）将切好的芹菜条放入锅中焯水,大约 20 秒放入芹菜叶,5 秒后关火全部捞出过凉水,备用","将盆中焯好的芹菜或者芹菜苗撒上准备好的食盐,香油,耗油和味极鲜搅拌均匀","将茶树菇倒入盆中搅拌均匀","装盘","开吃"]'::jsonb, '["素菜","凉拌","清淡","快手","开胃","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_d9f944a4d9.jpg', 'https://www.bilibili.com/video/BV1Q7411Y7BX', '{"energyKcal":165,"protein":6,"carbs":12,"fat":5}'::jsonb, '[null,null,null,null,null,25,null,null,null,null]'::jsonb),
  ('howtocook:vegetable_dish/茄子炖土豆', '茄子炖土豆', '素菜', 3, 45, '茄子炖土豆是一道东北家常炖菜，口感绵软咸香，带着辣椒的微辣和蒜香，十分下饭。茄子富含花青素和膳食纤维，土豆提供碳水化合物和维生素 C，加上猪肉的蛋白质，营养均衡又饱腹。这道菜操作流程简单，但需要掌握翻炒和收汁的火候，对新手有一定挑战，预估难度中等。从备料到出锅大约需要 45 分钟。', '[{"name":"茄子","quantity":1,"unit":"个"},{"name":"土豆","quantity":1,"unit":"个"},{"name":"肉","quantity":180,"unit":"克"},{"name":"青辣椒","quantity":50,"unit":"克"},{"name":"酱油","quantity":15,"unit":"毫升"},{"name":"盐","quantity":5,"unit":"克"},{"name":"蒜","quantity":3,"unit":"瓣"},{"name":"食用油","quantity":13,"unit":"毫升"},{"name":"水","note":"适量"}]'::jsonb, '["将茄子、土豆、辣椒洗净，蒜扒皮并拍碎。","将茄子、土豆切成约 6 立方厘米的块，辣椒切成 5 克的小块，肉切成 3 厘米的丝。","开火，热锅，加入份数 13 毫升的油。","当能看到锅里的油冒出一丝烟时，放入辣椒。","煸出辣椒香气后，立刻放入肉，用铲子翻炒 30 秒。","放入土豆，翻炒 30 秒。","放入茄子，翻炒 30 秒。","放入酱油和盐，继续翻炒 5 分钟。","加入水，水面高度为锅内食材高度的 0.9 倍，并盖上锅盖。","等待，直到锅内水的高度剩余食材高度的 0.1 倍时，开盖，放入蒜，搅拌均匀，关火。"]'::jsonb, '["素菜","东北","家常","炖菜","咸香","下饭","微辣"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_ed805fdade.jpg', 'https://www.bilibili.com/video/BV135411w7C2', '{"energyKcal":600,"protein":30,"carbs":35,"fat":35}'::jsonb, '[null,null,null,null,30,30,30,300,null,null]'::jsonb),
  ('howtocook:vegetable_dish/莴笋叶煎饼/莴笋叶煎饼', '莴笋叶煎饼', '素菜', 2, 10, '莴笋叶煎饼是一道简单快手的家常小吃，口感外酥里嫩，带有莴笋叶的清香味。莴笋叶富含维生素和膳食纤维，搭配鸡蛋补充优质蛋白，营养均衡。制作过程无需复杂技巧，只需搅拌并煎制两面，新手也很容易上手，预计从备料到出锅仅需 大约 10 分钟。', '[{"name":"莴笋叶","quantity":50,"unit":"克"},{"name":"鸡蛋","quantity":2,"unit":"个"},{"name":"食用油","quantity":30,"unit":"ml"},{"name":"生抽","quantity":5,"unit":"ml"},{"name":"淀粉","quantity":15,"unit":"克"},{"name":"鸡精","quantity":2,"unit":"克"}]'::jsonb, '["莴笋叶剁碎，加入鸡蛋、生粉、生抽、鸡精搅拌均匀备用","起锅烧油，倒入莴笋叶浆汁，均匀平铺在锅面上","第一面炸 120 S 后，翻面再炸 60 S 后出锅"]'::jsonb, '["素菜","快手","家常","煎制","清淡","营养"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_fe80fff522.jpeg', 'https://www.bilibili.com/video/BV14J411w7ok', '{"energyKcal":480,"protein":13.5,"carbs":18,"fat":40}'::jsonb, '[null,null,180]'::jsonb),
  ('howtocook:vegetable_dish/菠菜炒鸡蛋/菠菜炒鸡蛋', '菠菜炒鸡蛋', '素菜', 2, 15, '菠菜炒鸡蛋是一道清淡爽口的家常快手菜，菠菜软嫩、鸡蛋鲜香，属于南北皆宜的大众风味。菠菜富含铁、叶酸和维生素，鸡蛋提供优质蛋白与卵磷脂，搭配食用有助于补血养气、增强体质。整道菜操作简单，非常适合烹饪新手，从备料到出锅大约只需 15 分钟。', '[{"name":"菠菜","quantity":350,"unit":"克"},{"name":"鸡蛋","quantity":2,"unit":"个"},{"name":"食用油","quantity":15,"unit":"ml"},{"name":"食用盐","quantity":5,"unit":"克"}]'::jsonb, '["菠菜去根，洗净，放在篮子里，焯水","将鸡蛋打入碗中，搅匀","热锅，加入 10ml 油","油热后，倒入鸡蛋液，中火翻炒 15 秒，先煎成蛋饼，然后再用锅铲切成小块","关火，将鸡蛋块 盛到盘子中，不要洗锅","重新开火，倒入 5ml 油，油热后，放入菠菜，大火 翻炒 15 秒后，倒入鸡蛋块，翻炒均匀","加入 5g 盐、100ml 饮用水，大火 翻炒 10 秒","关火，盛盘"]'::jsonb, '["素菜","清淡","鲜香","快手","家常","炒"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_6eefa164db.jpg', 'https://www.bilibili.com/video/BV1rC4y1s7mF', null, null),
  ('howtocook:vegetable_dish/葱煎豆腐', '葱煎豆腐', '素菜', 3, 30, '外焦里嫩，葱香浓郁，咸鲜微辣，是一道家常风味。豆腐富含植物蛋白和钙质，搭配青椒和葱段，营养均衡。制作难度适中，煎豆腐时需掌握小火慢煎，新手按步骤耐心操作也能做好，全程约 30 分钟。', '[{"name":"白豆腐","note":"适量"},{"name":"葱","quantity":2,"unit":"根"},{"name":"青辣椒","quantity":1.5,"unit":"只"},{"name":"盐","quantity":3,"unit":"克"},{"name":"鸡精","quantity":1.5,"unit":"克"},{"name":"油","quantity":9,"unit":"ml"},{"name":"水","quantity":10,"unit":"ml"}]'::jsonb, '["豆腐洗净。切约 5 mm 厚度，置于碟中。","葱洗净，除去根部，切成葱花，备用。","辣椒洗净，切开，去籽，切成 1cm 1cm 状，备用、","热锅，加入份数 9ml 油。","油入锅后，使其均匀布于锅底，均匀放入豆腐，小火煎至金黄翻面。","待两面金黄，盛入碟中备用。","补油至覆盖锅底，倒入辣椒大火翻炒，并铲碾 3 分钟。","倒入豆腐，翻炒，加入盐与鸡精，中火翻炒 1 分钟后倒入 10 ML 水，大火收汁。","出锅前撒上之前计算好的葱花，起锅盛盘。"]'::jsonb, '["素菜","咸鲜微辣","香煎","家常","下饭","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_81f7671f75.jpg', 'https://www.bilibili.com/video/BV1fd2EYgESd', '{"energyKcal":210,"protein":13,"carbs":5,"fat":16}'::jsonb, null),
  ('howtocook:vegetable_dish/蒜蓉空心菜/蒜蓉空心菜', '蒜蓉空心菜', '素菜', 2, 15, '蒜蓉空心菜是一道清脆爽口、蒜香浓郁的家常快手菜，属于典型的川式小炒风味。空心菜富含膳食纤维、维生素和钙质，有助于促进肠道蠕动。做法非常简单，对新手十分友好，从备料到出锅大约只需 15 分钟。', '[{"name":"空心菜","quantity":250,"unit":"g"},{"name":"蒜末","quantity":0.5,"unit":"个"},{"name":"食用油","quantity":45,"unit":"ml"},{"name":"盐","quantity":2,"unit":"g"},{"name":"白糖","quantity":3,"unit":"g"},{"name":"生抽","quantity":8,"unit":"ml"}]'::jsonb, '["空心菜洗净，去掉烂叶或者老梗，均匀切成 2 段或者 3 段（防止过长不好炒）","锅里先倒少量油，烧至微微冒烟，此时拿起锅将国内的热油向四周浸润，让油均匀覆盖锅底，然后再倒入剩余的油(热锅凉油法)。","放入蒜末，小火炒 10 到 15 秒煸香","尽快均匀地放入空心菜，开大火，左手拿铲子，右手拿筷子，配合将空心菜不停翻动，直至软化变绿。","接着不需使用筷子，而是使用铲子快速翻炒已软化的空心菜 15 - 20 秒，使之受热更均匀，撒入盐 2 g ，白糖 3 g，生抽 8 ml。","继续大火翻炒 10 秒，即可出锅。"]'::jsonb, '["素菜","蒜香","清淡","川式","快手","家常","炒"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish___1_2111f29e0f.jpg', 'https://www.bilibili.com/video/BV15F411f7cG', '{"energyKcal":510,"protein":9.5,"carbs":23,"fat":46}'::jsonb, '[null,null,13,null,18,10]'::jsonb),
  ('howtocook:vegetable_dish/蒜蓉西兰花', '蒜蓉西兰花', '素菜', 2, 15, '这道家常蔬菜以蒜香浓郁、调味简单见长，西兰花焯水后软嫩或微脆，清淡鲜美。富含维生素 C、膳食纤维和多种抗氧化物质，是营养均衡的快手素菜。制作过程不难，新手也能轻松掌握，从备料到出锅一般约 15 分钟即可完成。', '[{"name":"西兰花","quantity":200,"unit":"克"},{"name":"大蒜","quantity":3,"quantityMax":4,"unit":"瓣"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"蚝油","quantity":5,"unit":"ml"},{"name":"白糖","quantity":2,"unit":"克"}]'::jsonb, '["将 西兰花 切成小朵，清洗干净。","将 大蒜 去皮，切成蒜末，备用。","锅中加入 1000 ml 饮用水，大火烧开。","放入 西兰花，保持大火 煮 2-3 分钟，至 西兰花 颜色变翠绿，口感变软。","将 煮好的 西兰花 捞出，沥干水分，摆入盘中，备用。","热锅，加入 10 ml 食用油。油温升高后，放入 大蒜末，小火煸炒出香味。","加入 10 ml 生抽，5 ml 蚝油，2 g 白糖，加入 30 ml 饮用水。","将锅中汤汁烧开。","将烧好的蒜蓉汁 均匀淋在盘中的 西兰花 上。"]'::jsonb, '["素菜","蒜香","清淡","快手","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_aa5533ecbe.jpg', 'https://www.bilibili.com/video/BV1K3411J7cj', '{"energyKcal":180,"protein":8,"carbs":22,"fat":11}'::jsonb, '[null,null,null,120,null,null,null,null,null]'::jsonb),
  ('howtocook:vegetable_dish/蒲烧茄子', '蒲烧茄子', '素菜', 3, 30, '蒲烧茄子是一道咸甜交织、口感软糯的家常菜，借鉴日式蒲烧风味却用中式煎烧手法烹制。茄子富含膳食纤维和多种维生素，有助于清热活血。难度适中，对新手稍需耐心，预计制作时长约 30 分钟。', '[{"name":"茄子","quantity":1,"unit":"个"},{"name":"蒲烧汁","quantity":1,"unit":"份"},{"name":"蜂蜜","quantity":20,"unit":"ml"},{"name":"白糖","quantity":15,"unit":"ml"},{"name":"生抽","quantity":40,"unit":"ml"},{"name":"老抽","quantity":10,"unit":"ml"},{"name":"料酒","quantity":20,"unit":"ml"},{"name":"水","quantity":100,"unit":"ml"}]'::jsonb, '["茄子削皮、横着切成两段","蒸 5 分钟","纵向切开，不要切断，在两边切面各划 2~3 刀至可以摊平","煎至两面金黄","往茄子上浇蒲烧汁至没过 1/2 茄子高度","煎至背面上色，翻面","同时收汁，若无法收汁可以加入水淀粉（生粉和水的比例在 1:4 到 1:10 根据收汁情况而定）","把剩下的蒲烧汁浇在茄子上","出锅，一份茄子烧蒲烧汁就烧好了"]'::jsonb, '["素菜","咸甜","煎烧","家常","下饭","软糯"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_f54e373f11.jpg', 'https://www.bilibili.com/video/BV1wh411471y', '{"energyKcal":380,"protein":3,"carbs":48,"fat":16}'::jsonb, '[null,300,null,null,null,null,null,null,null]'::jsonb),
  ('howtocook:vegetable_dish/虎皮青椒/虎皮青椒', '虎皮青椒', '素菜', 3, 15, '虎皮青椒是一道家常小菜，外皮微焦起皱，口感软嫩带脆，咸鲜中透着酸甜，十分开胃下饭。青椒富含维生素 C 和膳食纤维，有助于增强免疫力、促进消化。制作过程简单明了，只需掌握按压和火候，对新手也比较友好，一般约 15 分钟就能完成。', '[{"name":"青椒","quantity":5,"unit":"个"},{"name":"大蒜","quantity":2,"quantityMax":3,"unit":"瓣"},{"name":"油","quantity":20,"unit":"ml"},{"name":"白糖","quantity":15,"unit":"克"},{"name":"生抽","quantity":15,"unit":"ml"},{"name":"香醋","quantity":15,"unit":"ml"},{"name":"盐","quantity":4,"unit":"克"}]'::jsonb, '["去掉青椒蒂，用自来水冲洗干净。","青椒切长片，平均一个青椒纵向切成 3-4 片即可。","大蒜去皮，切成碎末，体积在 2mm x 2mm x 2mm 即可。","调料 1：拿一个小碗倒入 20ml 油，将大蒜末放入其中。","调料 2：白糖、生抽、醋、盐全部倒入砵（碗）等容器，搅拌。","将 调料 1 倒入锅中，开火加热 5 成放入青椒，青椒片不要叠在一起，单独成片放置锅中。","用锅铲不停的按压青椒，合适的时候翻面。","翻炒约 2 分钟，待青椒表皮出现褶皱时，倒入 调料 2。","加大火候继续翻炒 30s 后即可出锅盛入盘中。"]'::jsonb, '["素菜","家常","下饭","快手","鲜香","酸甜","煎炒"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_77f40e3507.jpg', 'https://www.bilibili.com/video/BV11F41187tw', '{"energyKcal":340,"protein":4,"carbs":30,"fat":20}'::jsonb, '[null,null,null,null,null,null,null,120,30]'::jsonb),
  ('howtocook:vegetable_dish/蚝油三鲜菇/蚝油三鲜菇', '蚝油三鲜菇', '素菜', 3, 15, '蚝油三鲜菇是一道鲜美滑嫩的家常快手菜，菌菇吸饱蚝油酱汁，口感软滑有嚼劲，带着微微辣意，清爽不腻。富含植物蛋白、膳食纤维和多种维生素，搭配西蓝花营养均衡。制作简单，新手也能轻松掌握，从备料到出锅仅需 大约 15 分钟。', '[{"name":"香菇","quantity":2,"unit":"朵"},{"name":"蟹味菇","quantity":30,"unit":"g"},{"name":"白玉菇","quantity":30,"unit":"g"},{"name":"小米辣","quantity":1,"unit":"根"},{"name":"菜椒","quantity":0.5,"unit":"颗"},{"name":"食用油","quantity":10,"unit":"ml"},{"name":"盐","quantity":5,"unit":"g"},{"name":"料酒","quantity":2,"unit":"ml"},{"name":"淀粉","quantity":10,"unit":"g"},{"name":"生抽","quantity":10,"unit":"ml"},{"name":"鸡精","quantity":3,"unit":"g"},{"name":"香葱","quantity":0.5,"unit":"根"},{"name":"姜末","quantity":1,"unit":"粒"},{"name":"蚝油","quantity":5,"unit":"ml"},{"name":"西蓝花","quantity":100,"unit":"g"},{"name":"开水","quantity":350,"unit":"ml"}]'::jsonb, '["蟹味菇、白玉菇 去掉根部泥土，掰散菌朵","香菇切片（每片厚度 0.5-1 cm，厚点相对薄点更有嚼劲）","生粉倒入小碗中，加入 50ml 水，搅拌生粉直至融化没有颗粒（即水淀粉）备用","水开，放入西蓝花，清水煮 3 分钟，放入碗中备用","洗锅烧开水，加入 5 g 食用盐，倒入蟹味菇、白玉菇、香菇，水煮 1 分钟","1 分钟后，捞出沥干水分","起锅烧油，待油开始冒小泡，放入姜末、小米辣、菜椒 煸炒 30 S","倒入三鲜菇，然后依次倒入生抽、蚝油、鸡精，翻炒均匀后，倒入水淀粉","中火烧干汁，加入料酒、葱花 出锅","摆上西蓝花"]'::jsonb, '["素菜","鲜香","微辣","快手","家常","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_eff2ee4cc6.jpeg', 'https://www.bilibili.com/video/BV11L411c7MB', '{"energyKcal":200,"protein":7,"carbs":22,"fat":10}'::jsonb, '[null,null,null,180,60,null,30,null,null,null]'::jsonb),
  ('howtocook:vegetable_dish/蚝油生菜', '蚝油生菜', '素菜', 2, 15, '蚝油生菜是一道爽口鲜香的家常菜，脆嫩的生菜淋上蒜香蚝油汁，咸中带甜，属于粤菜和川菜馆都很常见的快手素菜。富含维生素和膳食纤维，有助于促进消化。做法对新手非常友好，从洗菜到出锅大约只需 15 分钟即可完成。', '[{"name":"生菜","quantity":1,"unit":"棵"},{"name":"蚝油","quantity":6,"quantityMax":8,"unit":"ml"},{"name":"大蒜","quantity":4,"quantityMax":5,"unit":"瓣"},{"name":"生抽","quantity":6,"unit":"ml"},{"name":"盐","quantity":0.5,"unit":"克"},{"name":"白糖","quantity":1,"unit":"克"},{"name":"食用油","quantity":5,"quantityMax":8,"unit":"ml"}]'::jsonb, '["生菜洗净并去掉烂菜叶。","热锅，先放 1 L 清水（凉），然后在锅内放入 2 ml - 3 ml 食用油和 0.5 g 盐，等待锅中的水煮沸。","水沸后，放入生菜，将每一片生菜叶都焯水 10 s。","捞出生菜，控干水份，摆盘 。","调汁：将生抽 10 ml 、蚝油 6-8 ml 、盐 0.5 g 、 白糖 1 g 放入碗中调匀，并加入 10-15 ml 清水（凉）搅拌均匀。","再开火，热锅，放入食用油 5-8 ml，油热放入蒜泥。","等待有蒜香飘出，倒入调好的汁，煮沸即可，立马关火。","将锅中的汤汁均匀地浇在生菜上。"]'::jsonb, '["素菜","鲜香","咸甜","快手","粤菜","家常菜","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_9eb513cb25.jpg', 'https://www.bilibili.com/video/BV1M44y187u6', '{"energyKcal":90,"protein":2.5,"carbs":5,"fat":7}'::jsonb, '[null,null,10,null,null,null,null,null]'::jsonb),
  ('howtocook:vegetable_dish/西红柿炒鸡蛋', '西红柿炒鸡蛋', '素菜', 2, 15, '一道酸甜开胃的家常菜肴，嫩滑的鸡蛋裹着软烂多汁的西红柿，是中国家庭餐桌上的经典味道。鸡蛋提供优质蛋白质，西红柿富含维生素 C 和番茄红素，营养均衡好吸收。步骤简单，原材料易得，特别适合厨房新手入门，从头备菜到盛盘出锅大约只需 15 分钟。', '[{"name":"西红柿","quantity":1,"unit":"个"},{"name":"鸡蛋","quantity":1.5,"unit":"个"},{"name":"食用油","quantity":4,"unit":"ml"},{"name":"盐","quantity":1.5,"quantityMax":2,"unit":"克"},{"name":"糖（可选）","quantity":0,"quantityMax":2,"unit":"克"},{"name":"葱花（可选）","quantity":0,"quantityMax":10,"unit":"克"},{"name":"醋","quantity":1,"unit":"ml"},{"name":"番茄酱","quantity":10,"unit":"ml"},{"name":"清水","quantity":50,"unit":"ml"}]'::jsonb, '["西红柿洗净","可选：去掉西红柿的外表皮","开水烫表皮，然后将西红柿放入冷水，剥去外皮","西红柿去蒂，切成边长不超过 4cm 的小块，即为 西红柿块","将鸡蛋打入碗中，加入 1g 份数 的盐，搅匀，即为 鸡蛋液","可以考虑向鸡蛋中加入 1ml 醋，这可以去除腥味，令鸡蛋更蓬松","热锅，加入食用油","油热后，倒入 鸡蛋液。翻炒至鸡蛋结为固体且颜色微微发黄，即为 半熟鸡蛋","关火。将 半熟鸡蛋 盛盘，重新开火","注意：不要洗锅","加入 西红柿块，锅铲拍打并翻炒 20 秒，或至西红柿软烂","向锅中加入 半熟鸡蛋，翻炒均匀","可以考虑加入 10ml 番茄酱和 50ml 清水，增加汤汁","可以额外加入一些其它熟肉和材料","加入剩余的盐、糖（可选，如果倾向于甜味版本）、葱花（可选），翻炒均匀","关火，盛盘"]'::jsonb, '["素菜","酸甜","炒","家常","快手","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_89ac8dfb02.jpg', 'https://www.bilibili.com/video/BV1SW4y1f7Tc', '{"energyKcal":180,"protein":10,"carbs":7,"fat":12}'::jsonb, '[null,null,null,null,null,null,null,null,null,null,20,null,null,null,null,null]'::jsonb),
  ('howtocook:vegetable_dish/西红柿豆腐汤羹/西红柿豆腐汤羹', '西红柿豆腐汤羹', '素菜', 2, 15, '一道清淡鲜美的家常汤羹，酸甜开胃，口感嫩滑。西红柿富含维生素 C 和番茄红素，搭配鸡蛋与豆腐，能补充优质蛋白，营养均衡易吸收。做法简单，只需切配翻炒和煮制，新手也能轻松掌握，从准备到出锅大约 15 分钟即可完成。', '[{"name":"西红柿","quantity":1,"unit":"个"},{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"豆腐","quantity":100,"unit":"克"},{"name":"食用油","quantity":5,"unit":"ml"},{"name":"盐","quantity":2,"unit":"克"},{"name":"淀粉","quantity":5,"unit":"克"},{"name":"鸡精","quantity":2,"unit":"克"},{"name":"香葱","quantity":0.5,"unit":"根"},{"name":"姜","quantity":1,"unit":"片"},{"name":"开水","quantity":350,"unit":"ml"}]'::jsonb, '["西红柿切成小丁、鸡蛋打入碗中搅拌、豆腐切块备用","起锅烧油，放入姜片 5 S 后倒入入西红柿翻炒 30 S","锅中加入开水，汤水烧开，60 S 后到入鸡蛋液、豆腐块","汤水重新烧开后，加入水淀粉，沿一个方向搅拌 2 圈","加入鸡精、盐、香葱，30 S 后起锅"]'::jsonb, '["素菜","清淡","酸甜","家常","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_3322b90373.jpeg', 'https://www.bilibili.com/video/BV1td4y1q7XW', null, null),
  ('howtocook:vegetable_dish/西葫芦炒鸡蛋/西葫芦炒鸡蛋', '西葫芦炒鸡蛋', '素菜', 2, 15, '西葫芦炒鸡蛋是一道清爽可口的家常快手菜，西葫芦软嫩多汁、鸡蛋鲜香松软，加入西红柿后更添酸甜风味，十分下饭。鸡蛋提供优质蛋白质和卵磷脂，西葫芦含有丰富的维生素 C 和膳食纤维，搭配食用营养均衡。制作过程简单，对新手非常友好，从备料到出锅一般初学者只需 15 分钟即可完成。', '[{"name":"西葫芦","quantity":500,"unit":"克"},{"name":"鸡蛋","quantity":3,"unit":"个"},{"name":"西红柿","quantity":100,"unit":"克"},{"name":"食用油","quantity":10,"quantityMax":20,"unit":"ml"},{"name":"食用盐","quantity":6,"unit":"克"}]'::jsonb, '["西红柿洗净，切成小块，备用","西葫芦洗净，切成边长约为 4cm 的菱形，备用","打三个鸡蛋到碗里，打散搅匀，备用","热锅，锅内放入 5ml - 10ml 食用油","倒入鸡蛋，保持翻炒至鸡蛋成固体，用锅铲分成小块后盛到碗里，备用","锅内放入 5ml - 10ml 食用油，倒入西红柿，炒至变软","倒入西葫芦一起翻炒均匀，放入 6g 食用盐，将火调小然后等待 4 - 5 分钟","倒入备用的鸡蛋，中火翻炒 15 秒","关火，盛盘"]'::jsonb, '["素菜","清淡","炒","家常","快手","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_56a764e9a9.jpeg', 'https://www.bilibili.com/video/BV1qb411u7e9', null, '[null,null,null,null,null,null,270,15,null]'::jsonb),
  ('howtocook:vegetable_dish/话梅煮毛豆/话梅煮毛豆', '话梅煮毛豆', '素菜', 2, 40, '话梅煮毛豆是一道酸甜开胃的家常小菜，口感清爽软糯，带有梅子的自然果香。毛豆富含植物蛋白和膳食纤维，有助于补充能量、促进消化。做法非常简单，新手也能轻松上手，全程只需 35 到 45 分钟即可完成。', '[{"name":"毛豆","quantity":300,"unit":"g"},{"name":"话梅","quantity":6,"unit":"颗"},{"name":"食用盐","quantity":2,"unit":"g"}]'::jsonb, '["清水加入食用盐，毛豆浸泡 15 分钟","加入开水，倒入毛豆、话梅，水煮 20-30 分钟","起锅开吃"]'::jsonb, '["素菜","酸甜","煮","家常","开胃","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_a4f2529e65.jpeg', 'https://www.bilibili.com/video/BV1BV41177Tj', null, null),
  ('howtocook:vegetable_dish/酸辣土豆丝', '酸辣土豆丝', '素菜', 2, 20, '酸辣开胃的经典家常菜，口感脆爽，色泽鲜亮，属于大众喜爱的快手小炒。土豆提供碳水化合物和钾元素，辣椒富含维生素 C，有助于增进食欲。操作步骤简单明了，对新手十分友好，从备料到出锅大约只需 20 分钟。', '[{"name":"土豆","quantity":240,"unit":"克"},{"name":"大蒜","quantity":4,"unit":"瓣"},{"name":"青椒","quantity":0.5,"unit":"个"},{"name":"红椒","quantity":0.5,"unit":"个"},{"name":"干辣椒","quantity":3,"unit":"个"},{"name":"葱","quantity":1,"unit":"根"},{"name":"生抽","quantity":5,"unit":"ml"},{"name":"陈醋","quantity":10,"unit":"ml"},{"name":"盐","quantity":2,"unit":"克"},{"name":"食用油","quantity":10,"quantityMax":15,"unit":"ml"}]'::jsonb, '["土豆去皮、切丝（或用刨丝器）。","切好的土豆丝用清水清洗，去除多余的淀粉，然后对土豆丝焯水 10 秒。沥干，备用。","葱切成葱花；大蒜拍碎切成蒜末（分为两等份备用）；干辣椒切小段；青红椒切丝。","热锅，小火热油，下入一半的葱花（葱白部分）、一半的蒜末和干辣椒爆香。","加入青红椒翻炒几下，加入土豆丝翻炒至变色。","加 5ml 生抽，10ml 陈醋，倒入剩下的一半蒜末和 2g 盐快速翻炒均匀。","出锅前撒上剩余的葱花，翻匀即可装盘。"]'::jsonb, '["素菜","酸辣","炒","家常","快手","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_ec085c0038.jpg', 'https://www.bilibili.com/video/BV1BHZmYjENX', null, null),
  ('howtocook:vegetable_dish/金针菇日本豆腐煲', '金针菇日本豆腐煲', '素菜', 2, 30, '金针菇日本豆腐煲是一道酱香浓郁的家常下饭菜，豆腐外焦里嫩，金针菇爽滑入味。金针菇富含氨基酸和膳食纤维，日本豆腐提供优质蛋白，营养开胃。这道菜步骤简单，新手也能轻松掌握，从备菜到出锅大约需要 30 分钟。', '[{"name":"金针菇","quantity":1,"quantityMax":2,"unit":"把"},{"name":"日本豆腐（玉子豆腐）","quantity":2,"unit":"袋"},{"name":"小米椒","quantity":3,"quantityMax":5,"unit":"根"},{"name":"蒜","quantity":2,"quantityMax":3,"unit":"瓣"},{"name":"生抽","quantity":15,"unit":"ml"},{"name":"蚝油","quantity":5,"unit":"ml"},{"name":"老抽","quantity":3,"unit":"ml"},{"name":"糖","quantity":3,"unit":"克"},{"name":"食用油","quantity":10,"quantityMax":15,"unit":"ml"},{"name":"盐","note":"适量"},{"name":"水","quantity":100,"unit":"ml"}]'::jsonb, '["豆腐切片，小火煎到两面金黄出锅备用。","切蒜成蒜末；将生抽，蚝油，老抽，糖，100ml 水调汁备用。","热锅放油，油热放小米椒、蒜末爆香，先放金针菇，炒软，把煎好的豆腐平铺在金针菇上，倒入#2 配好的料汁，焖 5 分钟，大火收汁。"]'::jsonb, '["素菜","酱香","家常","下饭","煎焖"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_90bbd60df2.jpg', 'https://www.bilibili.com/video/BV1VZ4y1H75g', '{"energyKcal":480,"protein":27,"carbs":22,"fat":30}'::jsonb, '[null,null,300]'::jsonb),
  ('howtocook:vegetable_dish/金钱蛋', '金钱蛋', '素菜', 3, 30, '金钱蛋是一道外焦里嫩、咸香微辣的湘味家常菜，煎至金黄的蛋片形似铜钱，寓意吉祥。鸡蛋与青红椒搭配，富含优质蛋白质和多种维生素，营养均衡。制作难度中等，新手稍加练习也能掌握，全程约需 30 分钟即可完成下饭菜。', '[{"name":"鸡蛋","quantity":5,"unit":"个"},{"name":"线椒","quantity":15,"unit":"克"},{"name":"小米辣","quantity":6,"quantityMax":15,"unit":"克"},{"name":"豆瓣酱","quantity":15,"unit":"ml"},{"name":"蒜","quantity":10,"unit":"克"},{"name":"小葱","quantity":3,"unit":"克"},{"name":"玉米淀粉","quantity":40,"unit":"克"},{"name":"食用油","quantity":20,"quantityMax":35,"unit":"ml"},{"name":"生抽","quantity":15,"unit":"ml"},{"name":"蚝油","quantity":15,"unit":"ml"},{"name":"糖","quantity":5,"unit":"克"}]'::jsonb, '["鸡蛋冷水下锅，大火煮开转小火煮 8 分钟","用自来水冲凉，方便剥皮","蒜切沫（粒径不大于 1 mm），线椒和小米辣切小粒（约 2-3 mm）","每个熟鸡蛋沿短轴切成体积类似的 4 份","如果打算沾淀粉，每片鸡蛋粘上淀粉，抖掉多余的淀粉","锅内放入 25 ml 油（如果不沾淀粉，放 20 ml），放入熟鸡蛋片","煎至微焦黄后，补 10 ml 油（如果不沾淀粉，补 10 ml），翻面","第二面微黄后，加入线椒、小米辣、蒜末煎制约一分钟，翻面","接着加豆瓣酱煎制约几十秒，翻面","生抽、耗油、糖调成汁，轻轻颠锅后即可出锅"]'::jsonb, '["素菜","咸香","微辣","煎","湘味","下饭"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_847777fc07.jpg', 'https://www.bilibili.com/video/BV1zY4LzFEbv', null, null),
  ('howtocook:vegetable_dish/陕北熬豆角', '陕北熬豆角', '素菜', 2, 30, '这是一道西北农家风味的炖菜，豆角绵软、土豆沙糯、番茄汤汁浓郁，酸香开胃。富含膳食纤维、维生素和碳水化合物，营养均衡。做法极其简单，食材用量可随喜好调整，几乎没有失败的可能，对新手特别友好。从备料到出锅，大约只需 30 分钟。', '[{"name":"豆角","quantity":300,"unit":"g"},{"name":"土豆","quantity":1,"unit":"个"},{"name":"西红柿","quantity":1,"unit":"个"},{"name":"螺丝椒","quantity":2,"unit":"个"},{"name":"盐","quantity":6,"unit":"g"},{"name":"生抽","quantity":6,"unit":"ml"},{"name":"五香粉","quantity":3,"unit":"g"},{"name":"蚝油","quantity":6,"unit":"ml"},{"name":"葱","quantity":3,"unit":"圈"},{"name":"姜","quantity":2,"unit":"g"},{"name":"蒜","quantity":2,"unit":"颗"},{"name":"香菜碎","note":"根据口味"},{"name":"油","quantity":10,"quantityMax":15,"unit":"ml"}]'::jsonb, '["葱切花，蒜切沫，姜切丝，备用。","豆角去筋，切2-10cm小段，备用。","土豆去皮，切1cm³小块，备用。","西红柿去皮，切1cm³小块，备用。","辣椒去仔，切0.15cm 宽条，备用。","起锅烧油(10ml - 15ml)，冒烟后放入葱姜蒜，翻炒至闻到葱姜蒜香味；","加入豆角，翻炒至变色（青绿色变为翠绿色）；","加入土豆块，翻炒 30s；","加入热水（水面刚刚漫过菜），盖上锅盖熬至土豆变软（可以用筷子确认）；","加入西红柿块，加入盐，生抽，蚝油，五香粉，辣椒，熬至西红柿成汁（注意搅拌，防止糊锅）；","加入香菜碎，出锅。"]'::jsonb, '["素菜","家常","下饭","炖菜","西北","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_f715af09f5.jpg', 'https://www.bilibili.com/video/BV16d4y137Pb', '{"energyKcal":361,"protein":10.7,"carbs":54.4,"fat":13.1}'::jsonb, '[null,null,null,null,null,null,null,30,null,null,null]'::jsonb),
  ('howtocook:vegetable_dish/雷椒皮蛋', '雷椒皮蛋', '素菜', 2, 15, '雷椒皮蛋是一道卖相朴实但风味十足的家常凉菜，青椒的焦香与皮蛋的醇滑交融，酸辣开胃，尤其适合夏日佐餐。皮蛋富含蛋白质和矿物质，青椒提供丰富的维生素 C，大蒜则有助增进食欲。整道菜操作简单，新手也能轻松驾驭，从备料到完成大约只需 15 分钟。', '[{"name":"皮蛋","quantity":2,"unit":"个"},{"name":"青椒","quantity":4,"unit":"根"},{"name":"葱","quantity":10,"unit":"cm"},{"name":"蒜","quantity":3,"quantityMax":4,"unit":"瓣"},{"name":"小米辣","quantity":3,"quantityMax":4,"unit":"颗"},{"name":"食用油","quantity":10,"quantityMax":20,"unit":"ml"},{"name":"生抽","quantity":15,"quantityMax":20,"unit":"ml"},{"name":"陈醋","quantity":15,"quantityMax":20,"unit":"ml"},{"name":"白糖","quantity":6,"quantityMax":10,"unit":"g"},{"name":"香油","quantity":5,"quantityMax":7,"unit":"ml"}]'::jsonb, '["青椒清洗，去除根部，侧面切开，去除内部的子后在案板压平，备用（一定要去除青椒子，否则会在锅里炸开）","葱切成半厘米小段，备用","蒜去皮，切成碎末，备用","皮蛋去皮，备用","小米辣，切成 5-10mm 的小段，备用","热锅，锅内放入 10ml - 20ml 食用油","放入全部青椒，改小火保持锅子温度，煎至青椒变软（可以用筷子试一下，插入即透即可）","关火，将皮蛋和青椒放入小铁盆中","方法 1： 有擀面杖且砸东西不会吵到邻居：用擀面杖的一头在小盆中砸击皮蛋和青椒，至皮蛋与青椒混合（选项）","方法 2：将青椒用手撕开，撕成大约半厘米的条状，用叉子将皮蛋压碎（选项）","小米辣","倒入生抽，陈醋，白糖，香油，以及其他未使用的备用食材","均匀搅拌"]'::jsonb, '["素菜","酸辣","凉拌","开胃","家常","快手"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_b9790771e1.jpg', 'https://www.bilibili.com/video/BV1DJ4m1T72z', '{"energyKcal":500,"protein":16,"carbs":17,"fat":38}'::jsonb, null),
  ('howtocook:vegetable_dish/鸡蛋火腿炒黄瓜', '鸡蛋火腿炒黄瓜', '素菜', 2, 10, '这是一道清爽快手的家常小炒，咸鲜适口，黄瓜脆嫩、鸡蛋软滑、火腿增香，属于大众化的中式家常菜。鸡蛋提供优质蛋白，黄瓜富含维生素和水分，火腿补充风味，整体营养均衡。烹饪步骤简单明了，难度很低，对厨房新手非常友好。从备菜到出锅，全程只需约 10 分钟。', '[{"name":"黄瓜","quantity":1,"unit":"根"},{"name":"鸡蛋","quantity":2,"unit":"个"},{"name":"火腿肠","quantity":1,"unit":"根"},{"name":"红尖椒","quantity":1,"unit":"个"},{"name":"食用油","quantity":10,"unit":"ml"},{"name":"生抽","quantity":3,"unit":"ml"},{"name":"盐","quantity":2,"unit":"克"}]'::jsonb, '["黄瓜洗净，切半圆形片，备用","火腿切半圆形片，备用","红尖椒（可选）切碎，备用","将鸡蛋打入碗中，搅匀，即为 鸡蛋液","热锅里倒 5ml 食用油","油热后转小火，倒入打散的鸡蛋液，用筷子划散，翻炒至鸡蛋结为固体且颜色微微发黄，即为 半熟鸡蛋，盛出备用","不用洗锅，往锅内倒入 5ml 食用油，倒入黄瓜片大火翻炒 1 分钟","把 半熟鸡蛋 倒入锅中，调入 2g 盐、3ml 生抽，立刻倒入火腿片和辣椒碎（可选）翻炒均匀","关火，盛盘"]'::jsonb, '["素菜","清爽","咸鲜","小炒","快手","家常"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_75a7952593.jpg', 'https://www.bilibili.com/video/BV1Zj96BGEx6', null, null),
  ('howtocook:vegetable_dish/鸡蛋羹/微波炉鸡蛋羹', '微波炉鸡蛋羹', '素菜', 2, 10, '微波炉鸡蛋羹是一道简单快手的家常蒸蛋，口感嫩滑细腻，尤其适合作为夜宵或快速加餐。鸡蛋富含优质蛋白质和多种维生素，能为身体提供必要营养，虾皮还补充了钙质。这道菜对新手非常友好，无需掌握火候技巧，从打蛋调味到出炉，全程仅需约 10 分钟即可完成。', '[{"name":"鸡蛋","quantity":2,"unit":"个"},{"name":"水","quantity":200,"unit":"ml"},{"name":"盐","quantity":3,"unit":"克"},{"name":"虾皮","quantity":10,"unit":"个"},{"name":"葱","quantity":5,"unit":"克"},{"name":"芝麻油（香油）","quantity":1,"unit":"ml"},{"name":"酱油","note":"适量"}]'::jsonb, '["将鸡蛋打入可使用微波炉加热的陶瓷碗中，使用筷子将其打散。","加入水和盐，搅拌均匀。","将虾皮放入碗中，搅拌均匀，保证所有虾皮不会堆积在一起。","葱切碎至边长 0.6±3mm 状，放入碗中搅拌均匀。","将此碗及内容物放入微波炉中，容器表面覆盖保鲜膜或以可微波瓷盘加盖（注意：不得密封，必须留有涨缩量）加热 2 分钟(500W)。","小心地取下保鲜膜或其他覆盖物，然后继续加热 2 分钟。","若微波炉不带旋转式加热盘，将碗缓慢的水平旋转 180 度，以确保内容物加热均匀。","放入芝麻油。","小心地从微波炉中拿出碗（真的很烫）。","如果选择放入酱油，则确保酱油在鸡蛋羹表面流动后能以最薄的形式沾满鸡蛋羹表面即可。","开心的享受鸡蛋羹"]'::jsonb, '["素菜","快手","家常","嫩滑","夜宵","微波"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_3ca27608e0.jpg', 'https://www.bilibili.com/video/BV19W4y167Sd', '{"energyKcal":155,"protein":13,"carbs":1,"fat":11}'::jsonb, '[null,null,null,null,120,120,null,null,null,null,null]'::jsonb),
  ('howtocook:vegetable_dish/鸡蛋羹/蒸箱鸡蛋羹', '蒸箱鸡蛋羹', '素菜', 3, 15, '这是一道利用蒸箱快速制作的嫩滑家常蛋羹，口感可调，水少则弹、水多则嫩。富含优质蛋白质和多种营养素，易于消化吸收。难度适中，新手稍加注意即可掌握，从准备到出锅大约只需 15 分钟。', '[{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"食用盐","quantity":1,"unit":"克"},{"name":"食用油","quantity":5,"unit":"ml"},{"name":"生抽（味极鲜，可选）","quantity":6,"unit":"ml"}]'::jsonb, '["一个鸡蛋放入碗中打散","向碗中加入鸡蛋体积 1.0-1.5 倍 60 度纯净水，并且搅拌均匀","正确范围内水越少弹，水越多越嫩","注意：超出范围后，水越少会口感变得太弹，水越多会变得太稀","加入食用盐 1g","盐起到了重要的增加底味和凝固作用","加入食用油 5ml","过滤蛋液，去掉蛋液中的浮沫（可选，不过滤蒸出来的蛋会有气泡导致不好看）","确认蒸箱的水源已经补充至足够（若不确定，可把水槽补满）","将已经完全搅拌均匀的鸡蛋液碗放入蒸箱","调节至100摄氏度蒸 10 分钟","打开蒸箱 （注意：蒸箱在开启时会有蒸气瞬间喷出，注意缓慢开启）","出锅（可加入生抽调味）","享用"]'::jsonb, '["素菜","蒸","快手","家常","嫩滑","清淡"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_f04fdc96c5.jpg', 'https://www.bilibili.com/video/BV1eX4y1C74e', '{"energyKcal":120,"protein":7.5,"carbs":1,"fat":9.8}'::jsonb, '[null,null,null,null,null,null,null,null,null,null,600,null,null,null]'::jsonb),
  ('howtocook:vegetable_dish/鸡蛋羹/鸡蛋羹', '鸡蛋羹', '素菜', 2, 15, '这道菜是一道简单快手的家常蒸菜，口感嫩滑如果冻，咸鲜适口，常作为早餐或配餐出现在各地餐桌。鸡蛋提供优质蛋白质和卵磷脂，易于消化吸收。对新手十分友好，只需简单几步就能蒸出平整细腻的蛋羹，全程大约需要 15 分钟。', '[{"name":"鸡蛋","quantity":2,"unit":"个"},{"name":"食用盐","quantity":3,"unit":"克"},{"name":"香油（或芝麻油）","quantity":2,"quantityMax":4,"unit":"ml"},{"name":"生抽（或味极鲜）","quantity":8,"unit":"ml"},{"name":"白醋（或料酒）","quantity":2,"unit":"ml"},{"name":"藤椒油","note":"适量"}]'::jsonb, '["两个鸡蛋放入碗中打散","加入食用盐 3g","盐起到了重要的增加底味和凝固作用","加入 2ml 白醋，去除鸡蛋的腥味（可选）","加入米醋也行，但米醋的颜色会使鸡蛋微微发黑","还可以加入料酒，同样具有去腥的作用，且没有醋的酸味","向碗中加入鸡蛋体积 1-1.5 倍的 70 度纯净水，并且搅拌均匀","1 倍的水鸡蛋更弹，1.5 倍的水鸡蛋更嫩","过滤蛋液，去掉蛋液中的浮沫（可选，不过滤蒸出来的蛋会有气泡导致不好看）","向任意一口锅中加入 300-500ml 清水，水烧开后，放入盛有鸡蛋液的碗","蒸碗要盖上一个盖子，倒扣一个有凹槽的铁碟子，或者使用保鲜膜来减少水汽进入，这是为了避免其变成蜂窝状","蒸煮步骤（二选一）","开中火蒸10 分钟, 10 分钟之后关火再闷上5 分钟。","开大火蒸5 分钟，要保持锅中水一直处于沸腾状态，否则要延长时间。每隔2 分钟开盖一次释放水蒸气，开盖过晚蛋羹容易变成蜂窝状；开盖太早/频繁蒸的时间需要久一些。","如何判断已经熟了？","晃动碗，蛋羹不再处于液体状态，拥有类似果冻的 Q 弹状态即可出锅。","出锅","加入香油和生抽即可享用","也可用藤椒油代替香油，增加麻爽口感"]'::jsonb, '["素菜","蒸菜","快手","家常","早餐","鲜香"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/howtocook_vegetable_dish_c0e00da0af.jpg', 'https://www.bilibili.com/video/BV1PqFrzuEEP', '{"energyKcal":180,"protein":13,"carbs":2,"fat":13}'::jsonb, null),
  ('howtocook:vegetable_dish/鸡蛋花/鸡蛋花', '鸡蛋花', '素菜', 1, 5, '一道简单易做的家常食疗汤饮，有甜咸两种风味，口感柔滑嫩爽，属于民间润喉小方。富含优质蛋白质和卵磷脂，易于消化吸收，可缓解喉咙干痒不适。制作极简单，初学者看一遍就能上手，从烧水到完成大约只需 5 分钟。', '[{"name":"鸡蛋","quantity":1,"unit":"个"},{"name":"沸水","quantity":100,"quantityMax":150,"unit":"ml"},{"name":"白糖","quantity":5,"quantityMax":10,"unit":"克"},{"name":"食盐","quantity":1,"quantityMax":2,"unit":"克"}]'::jsonb, '["将鸡蛋打入碗中。","使用筷子或搅拌器，顺着一个方向搅打蛋液，直至蛋清与蛋黄完全混合均匀，颜色一致。（此过程约需 1 - 2 分钟）","将糖或盐等调味料加入蛋液中，略微搅匀。","准备刚烧开的、100 ℃ 的沸水。","一边用筷子快速搅拌碗中的蛋液，一边将沸水以细流状冲入蛋液中。确保沸水与蛋液充分混合。","持续搅拌片刻，直至蛋液被完全烫熟，形成均匀的淡黄色蛋花。"]'::jsonb, '["素菜","甜咸两味","快手","家常","润喉","汤饮"]'::jsonb, 'https://nkugeupizmphbeicykpj.supabase.co/storage/v1/object/public/recipe-images/web_vegetable_dish_d28cc43961.jpg', 'https://www.bilibili.com/video/BV1NF3bzKEKH', '{"energyKcal":100,"protein":6,"carbs":8,"fat":5}'::jsonb, '[null,90,null,null,null,null]'::jsonb)
