create table if not exists public.recipe_i18n (
  recipe_id text not null references public.recipes(id) on delete cascade,
  lang text not null,
  name text not null,
  category text not null default '',
  description text not null default '',
  ingredients jsonb not null default '[]'::jsonb,
  steps jsonb not null default '[]'::jsonb,
  tags jsonb not null default '[]'::jsonb,
  updated_at timestamptz not null default now(),
  primary key (recipe_id, lang),
  constraint recipe_i18n_lang_check check (lang in ('en', 'ja', 'fr'))
);

alter table public.recipe_i18n enable row level security;
drop policy if exists "recipe_i18n_public_read" on public.recipe_i18n;
create policy "recipe_i18n_public_read" on public.recipe_i18n
  for select to anon, authenticated using (true);
grant select on public.recipe_i18n to anon, authenticated;

with seed (recipe_id, lang, name, category, description, ingredients, steps, tags) as (values
  ('howtocook:aquatic/咖喱炒蟹', 'en', 'Curry Fried Crab', 'Seafood', 'This is a home-style seafood dish with Thai flavors. Rich curry coats the full crab meat, with the aroma of crab roe and the smooth texture of coconut milk. Crab is rich in high-quality protein and various trace elements, helping to replenish energy. The steps are clear; just pay attention to sealing the crab roe and stir-frying the sauce off the heat at the end. Suitable for those with some cooking experience. It takes about 30 minutes from prep to serving.', '[{"name":"mud crab","unit":"whole"},{"name":"curry cubes","unit":"g"},{"name":"onion","unit":"g"},{"name":"coconut milk","unit":"ml"},{"name":"egg","unit":"piece"},{"name":"cornstarch","unit":"g"},{"name":"garlic","unit":"clove"}]'::jsonb, '["Open the crab by lifting the lid, cut it in half. Lightly crack the claws with the back of a knife. Dip the cut surfaces and claws in some cornstarch, not too much. Sprinkle 5g cornstarch into the crab lid to cover the roe, set aside.","Finely chop the onion, set aside.","Finely chop the garlic, set aside.","Boil a pot of water, set aside.","Heat oil in a pan, add about 20ml cooking oil, wait 10 seconds for the oil to heat up.","Place the crab cut-side down into the pan gently, fry for 20 seconds (this seals the roe and meat). Then flip, fry each side for 10 seconds. Remove crab and set aside.","Put the crab lid in the pan, use a spoon to ladle hot oil over the lid to seal the roe inside, fry for 20 seconds, then remove and set aside.","Without cleaning the pan, add another 10ml oil. Heat on high until lightly smoking, then add minced garlic and chopped onion, stir-fry for 10 seconds.","Add curry cubes and stir until melted (10 seconds), then add the fried crab and stir to coat evenly.","Pour in 300ml boiling water, cover and simmer for 3 minutes.","After simmering, add coconut milk and egg white, turn off the heat. Keep stirring until the sauce thickens.","Serve."]'::jsonb, '["Seafood","Thai","Savory","Rich","Stir-fry","Rice companion","Party"]'::jsonb),
  ('howtocook:aquatic/响油鳝丝', 'en', 'Sizzling Eel Shreds', 'Seafood', 'Sizzling Eel Shreds is a classic home-style dish from Jiangsu, Zhejiang, and Shanghai. The eel shreds are tender and smooth, with rich garlic flavor and a slightly sweet sauce. Drizzling hot lard over it releases an irresistible aroma, making it a perfect accompaniment to rice. Eel is rich in high-quality protein and DHA, offering great nutrition. This dish requires some knife skills and heat control, so it''s moderately challenging. Beginners may need a bit of practice. From prep to serving, it usually takes about 40 minutes.', '[{"name":"Eel shreds","unit":"g"},{"name":"Garlic","unit":"g"},{"name":"Minced ginger","unit":"g"},{"name":"Cooking wine","unit":"g"},{"name":"Light soy sauce","unit":"g"},{"name":"Oyster sauce","unit":"g"},{"name":"Dark soy sauce","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Sugar","unit":"g"},{"name":"White pepper","unit":"g"},{"name":"Starch","unit":"g"},{"name":"Water","unit":"g"},{"name":"Minced garlic","unit":"g"},{"name":"Chopped green onions","unit":"g"},{"name":"Lard","unit":"g"},{"name":"Sesame oil","unit":"g"}]'::jsonb, '["Cut the eel into three sections, then shred into thin strips.","Add 0.5 g white pepper, 3 g cooking wine, mix well. Then add 5 g sesame oil and marinate.","Heat oil and coat the wok.","Add vegetable oil and heat to 60% (medium-high heat).","Add half the minced garlic and all the minced ginger, stir-fry a few times.","Add the eel shreds, stir-fry over medium-high heat for 30 seconds.","Drizzle 10 g cooking wine along the edge, stir-fry a few times.","Add light soy sauce, stir well.","Add oyster sauce and dark soy sauce, stir-fry a few times.","Add salt, sugar, and 3 g white pepper, stir well.","Mix starch with water to make a slurry, pour into the wok, and cook until the sauce thickens.","Plate and sprinkle with minced garlic and chopped green onions.","Heat another wok with lard until 70% hot, then pour it over the eel shreds."]'::jsonb, '["Seafood","Jiangsu-Zhejiang-Shanghai","Savory","Slightly Sweet","Stir-fry","Rice Companion"]'::jsonb),
  ('howtocook:aquatic/小龙虾/小龙虾', 'en', 'Crayfish', 'Seafood', 'This dish is spicy and fragrant, with tender and juicy meat. It is a classic Sichuan-Hunan style appetizer for drinks. Making it at home is clean and economical. Crayfish is rich in high-quality protein and various trace elements, but the broth contains a lot of oil and salt, so it is suitable for occasional enjoyment. Handling live shrimp and a variety of spices is somewhat challenging for beginners, but skipping the deveining step can significantly reduce difficulty. From preparation to serving, it takes about 45 minutes.', '[{"name":"Crayfish","unit":"pound"},{"name":"Oil","unit":"ml"},{"name":"Bay leaves","unit":"pieces"},{"name":"Star anise","unit":"pieces"},{"name":"Cinnamon","unit":"grams"},{"name":"Sichuan green peppercorns","unit":"grams"},{"name":"Sichuan peppercorns","unit":"grams"},{"name":"Bullet chili peppers","unit":"grams"},{"name":"Green onion","unit":"stalks"},{"name":"Ginger","unit":"grams"},{"name":"Garlic","unit":"cloves"},{"name":"Pixian bean paste","unit":"grams"},{"name":"Yellow soybean paste","unit":"grams"},{"name":"Beer","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Salt","unit":"grams"}]'::jsonb, '["Wash the crayfish and remove the vein (devein). Cut green onions into 2cm sections, mince ginger and garlic.","Heat oil until slightly warm, then add bay leaves, star anise, cinnamon, Sichuan green peppercorns, Sichuan peppercorns, and bullet chili peppers.","Once the spices are fragrant, add the green onions, ginger, and garlic.","After the aromatics are fragrant, add Pixian bean paste and yellow soybean paste, stir-fry until red oil appears.","Add the crayfish and stir-fry until they change color.","Add beer, and after it comes to a boil, add light soy sauce and salt.","Cook until the crayfish are fully cooked, then remove from heat."]'::jsonb, '["Seafood","Spicy","Savory","Sichuan-Hunan","Appetizer for drinks","Home-style"]'::jsonb),
  ('howtocook:aquatic/干煎阿根廷红虾/干煎阿根廷红虾', 'en', 'Pan-fried Argentine Red Shrimp', 'Seafood', 'A delicious and tempting quick seafood dish. After pan-frying, the Argentine red shrimp has tender white meat, sweet and rich flavor, and crispy shells. Rich in trace elements like iodine, phosphorus, and astaxanthin, it helps boost immunity, protect the heart, and lower cholesterol. Moderate difficulty; requires mastering heat and flipping techniques, but steps are clear so beginners can succeed. Takes about 20 minutes to complete.', '[{"name":"Argentine red shrimp (frozen used)","unit":"pieces"},{"name":"Sea salt (ground)","unit":"grams"},{"name":"Black pepper (ground)","note":"to taste"},{"name":"White wine","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Cilantro","unit":"leaves"},{"name":"Lemon","unit":"slices"},{"name":"Onion","unit":"grams"},{"name":"Ginger","unit":"grams"},{"name":"Garlic","unit":"grams"}]'::jsonb, '["Thaw the Argentine red shrimp, preferably by transferring from freezer to fridge a day in advance for natural thawing to better preserve flavor and texture. You can buy ones that are already butterflied and deveined to save time.","Wash the thawed red shrimp, pat dry, and set aside. Make sure to drain well; if in a rush, use paper towels to absorb moisture.","Slice ginger, dice onion into small cubes. Wash cilantro, separate leaves from stems, chop cilantro leaves. Crush garlic and mince into small pieces.","Heat the pan over high heat. Add 2 tablespoons of olive oil. When oil is hot, add ginger slices, onion cubes, and cilantro stems; stir-fry.","After about 1 minute, remove ginger, onion, and cilantro stems; discard.","Adjust to medium-high heat. Place the red shrimp in the pan, making sure each shrimp''s one side fully contacts the pan. Fry for about 2 minutes, while brushing each shrimp with a layer of oil.","When the bottom shell is slightly browned, flip the shrimp. Sprinkle garlic mince, and gently shake the pan to distribute heat evenly.","After about 1 minute, add 20ml of white wine.","Fry for another minute, then reduce to medium-low heat. Sprinkle a layer of salt and black pepper evenly.","Add a drop of light soy sauce to each shrimp.","Sprinkle cilantro leaves and plate.","Slice lemon into wedges and arrange on the side of the plate."]'::jsonb, '["Seafood","Savory","Pan-fried","Quick","Home-style"]'::jsonb),
  ('howtocook:aquatic/微波葱姜黑鳕鱼', 'en', 'Microwave Black Cod with Scallion and Ginger', 'Seafood', 'Microwave cooking for fish, scallion and ginger enhance freshness, hot oil drizzle makes it fragrant. This is a home-style steamed fish dish with tender meat and savory flavor, a modified Cantonese method. Black cod is rich in high-quality protein and omega-3 fatty acids, beneficial for heart and brain health. The operation is not complicated, but requires control of heat and oil temperature, better for those with some cooking experience. It takes about 20 minutes from preparation to table.', '[{"name":"Black Cod (with skin)","unit":"g"},{"name":"Scallion (white part)","unit":"g"},{"name":"Scallion (green part)","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Cooking Wine","unit":"mL"},{"name":"Soy Sauce","unit":"mL"},{"name":"Sesame Oil","unit":"mL"},{"name":"Peanut Oil","unit":"mL"}]'::jsonb, '["Place each fish fillet into a separate sealed bag, skin side down on a plate.","Take 25g scallion (white part), cut into strips. Peel and cut 10g ginger into strips. Mix together, then divide into two halves, and place each half on the fish fillet in each bag.","Pour 2.5mL cooking wine into each bag.","Seal the bags, place in microwave, and microwave on medium (800W) until opaque and easily flaked (about 3.5-5 minutes). Remove the fish fillets from the bags.","Discard the scallion and ginger.","Mix 25mL soy sauce and 2mL sesame oil, then drizzle evenly over the two fish fillets.","Take 10g scallion (green part), cut into fine strips. Peel and cut 3g ginger into strips. Mix together, divide into two portions, and sprinkle over the fish fillets.","Heat 50mL peanut oil in a small saucepan to 190°C.","Drizzle the hot oil over the fish fillets topped with scallion greens. Serve immediately."]'::jsonb, '["Seafood","Fresh and Fragrant","Microwave","Cantonese","Home-style","Quick","Banquet"]'::jsonb),
  ('howtocook:aquatic/水煮鱼', 'en', 'Sichuan Boiled Fish (Shui Zhu Yu)', 'Seafood', 'Sichuan boiled fish is a classic Sichuan dish known for its spicy and numbing flavor and tender fish slices. Basa fish is rich in high-quality protein and low in fat, making it a balanced meal when paired with seasonal vegetables. The difficulty is moderate, challenging for beginners, but following the steps carefully will lead to success. Estimated cooking time: about 2 hours.', '[{"name":"basa fish","unit":"g"},{"name":"Vegetables (e.g., potato slices, bean sprouts, cauliflower, lettuce, etc.)","unit":"g"},{"name":"red oil chili bean paste","unit":"g"},{"name":"fermented black beans (optional)","unit":"g"},{"name":"green Sichuan pepper oil","unit":"ml"},{"name":"rapeseed oil","unit":"ml"},{"name":"white pepper powder","unit":"g"},{"name":"garlic cloves","unit":"cloves"},{"name":"salt","unit":"g"},{"name":"sugar","unit":"g"},{"name":"hot water","unit":"ml"}]'::jsonb, '["Prep: If the basa fish is frozen, let it thaw at room temperature for 5 hours before slicing.","Slice: Slice the basa fish into thin pieces, about 5 cm long and 3 cm wide.","Marinate: Place the sliced fish in a large stainless steel bowl.","Add 30g chili bean paste, 3g salt, 10ml green Sichuan pepper oil, and 3g white pepper powder.","Mix well with your hands, then add 5ml rapeseed oil to seal in the flavors.","Let it marinate at room temperature for at least 30 minutes.","Prep vegetables: Mince the garlic cloves. For example, use 300g cauliflower and 200g lettuce. Wash the cauliflower and lettuce.","Blanch and stir-fry: Blanch the cauliflower in boiling water and set aside. Wash the lettuce, drain, and stir-fry until cooked (no oil needed).","Fry the chili bean paste: Heat the wok with cold oil (20ml rapeseed oil), add 10g chili bean paste, 10g fermented black beans (optional), and the minced garlic. Stir-fry over medium heat.","Quick-boil the fish slices: Add 150ml hot water. Once it boils quickly, add the marinated fish slices. Gently stir to separate the slices. Add 2g salt and 2g sugar to season (adjust salt to taste). When the water boils again, remove from heat.","Plate: First, place the cooked vegetables in a large bowl. Then, place the hot fish slices on top of the vegetables. Pour the remaining hot broth from the wok over everything. Serve immediately!"]'::jsonb, '["Seafood","Spicy Numbing","Savory","Sichuan Cuisine","Home-style","Goes well with rice"]'::jsonb),
  ('howtocook:aquatic/油焖大虾/油焖大虾', 'en', 'Oil-Braised Prawns', 'Seafood', 'This classic Shandong dish wraps whole prawns in a sweet and savory sauce, resulting in bright red, glossy prawns with firm and tender meat. Prawns are rich in high-quality protein and astaxanthin, low in fat, making them a nutritious ingredient that won''t burden the body. The cooking process requires making scallion oil, trimming prawns, braising, and reducing the sauce, demanding a good grasp of heat and seasoning. It''s better for experienced cooks. The whole process takes about 40 minutes.', '[{"name":"Black tiger shrimp / Prawn","unit":"piece"},{"name":"Sichuan peppercorns","unit":"g"},{"name":"Scallion","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Cooking wine","unit":"g"},{"name":"Water","unit":"small bowl"},{"name":"Salt","unit":"g"},{"name":"Rock sugar","unit":"g"},{"name":"Vegetable oil","note":"as needed"}]'::jsonb, '["Cut the prawn''s spear to the root, trim the antennae and legs, remove the sand sac, butterfly the back and remove the vein, wash and set aside.","Fry the flavored oil.","When the oil reaches 30% heat, add Sichuan peppercorns. Once the oil is hot, remove from heat, add scallions and ginger (best not to let the oil discolor). When the scallions turn slightly yellow, drain the oil (if you have extra scallion oil, you can save it for noodles).","Add oil to the pan, arrange the prawns neatly. Once both sides change color, gently press the prawn heads.","Add minced ginger (finely diced ginger).","30g cooking wine.","Two small bowls of water.","3g salt.","10g rock sugar.","Bring to a boil over high heat, then turn to low heat, cover and braise (do not add any more liquid during cooking, do not uncover).","When the shell is glossy and the prawns are curled, remove from the pan and arrange on a plate.","Reduce the sauce (strain it back into the pan and thicken, add scallion oil) until about 1/4 of the liquid remains.","Pour the sauce over the prawns.","Done.","Oil-Braised Prawns - Preview Image 1","Start eating ✅"]'::jsonb, '["Seafood","Shandong cuisine","Sweet and savory","Braising","Home-style","Banquet","Fresh and fragrant"]'::jsonb),
  ('howtocook:aquatic/混合烤鱼/烤鱼', 'en', 'Grilled Fish', 'Seafood', 'This Sichuan-style grilled fish is spicy and numbing, with crispy skin and tender meat. The vegetables soak up the broth, making it extra flavorful with rice. Grass carp is rich in high-quality protein, and the mix of vegetables provides balanced nutrition. The process may look complicated, but following the steps makes it manageable—perfect for beginners wanting a challenge. From prep to table takes about an hour.', '[{"name":"Grass carp","unit":"jin"},{"name":"Scallion","unit":"stalk"},{"name":"Cooking oil","unit":"ml"},{"name":"Cooking wine","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"White pepper","unit":"g"},{"name":"Cinnamon","note":"small piece"},{"name":"Star anise","unit":"piece"},{"name":"Garlic","unit":"cloves"},{"name":"Bay leaves","unit":"pieces"},{"name":"Green Sichuan peppercorns","note":"small handful"},{"name":"Dried chili segments","unit":"pieces"},{"name":"Lantern chilies","unit":"pieces"},{"name":"Celery","unit":"stalk"},{"name":"Onion","unit":"piece"},{"name":"Tofu skin sheets","unit":"pieces"},{"name":"Mung bean sprouts","note":"as needed"},{"name":"Doubanjiang","unit":"g"},{"name":"Sugar","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Cumin powder","note":"to taste"},{"name":"Roasted peanuts","note":"to taste"},{"name":"White sesame seeds","note":"to taste"},{"name":"Chopped scallions","note":"to taste"},{"name":"Cilantro","note":"optional"}]'::jsonb, '["Cut the grass carp (about 3 jin) open from the back. Score both sides along the back, but don''t cut through the belly, or it won''t hold its shape.","You can rinse the fish with hot water to remove slime, or scrub it under running water with a brush until it''s no longer sticky.","Place the fish in a container. Add cooking wine, 10g white pepper, and 5g salt. Rub evenly and marinate for 20 minutes.","Cut half a stalk of scallion into chunks. Halve the garlic cloves crosswise. Put the scallion, garlic, star anise, bay leaves, and cinnamon together in one bowl.","Split the dried chili segments in half and place them in a bowl with the lantern chilies.","Cut the celery into small sections.","Blanch the bean sprouts.","Blanch the tofu skin sheets and cut into shreds.","Slice the onion into strips.","Prepare to cook the fish.","If you have an oven, brush the baking tray with oil, place the fish skin side down, and roast until both sides are golden. Then sprinkle with cumin powder.","If you don''t have an oven, heat oil in a pan. Sprinkle 2g salt on both sides of the pan, add the grass carp, and fry without moving until the first side sets. Flip and fry until golden on both sides. Sprinkle with cumin powder and remove to a plate.","Add 20ml cooking oil to the pan. Once hot, stir-fry the scallion, garlic, star anise, and bay leaves until fragrant.","Add half a packet of hot pot base and 15-20g doubanjiang (fermented broad bean paste). Stir-fry until the oil turns red.","Add 5g sugar, 10g salt, and 5ml light soy sauce. Pour in enough water to just cover the ingredients and bring to a boil.","Add the celery, bean sprouts, and tofu skin shreds in order. Don''t cook them through; just blanch briefly. Then lay the onion strips on top and place the grilled fish on them.","Add the dried chili segments, lantern chilies, and green Sichuan peppercorns.","Heat oil in another pan. When hot, pour it over the chilies just added to release their aroma.","Finally, sprinkle with roasted peanuts, chopped scallions, white sesame seeds, and cilantro.","Cook for 5-6 minutes and it''s ready to serve."]'::jsonb, '["Seafood","Spicy","Numbing","Flavorful","Rice companion","Sichuan cuisine","Pan-fry & roast","Entertaining"]'::jsonb),
  ('howtocook:aquatic/清蒸生蚝', 'en', 'Steamed Oysters', 'Seafood', 'Steamed oysters are a coastal home-style dish that preserves the original flavor. The oyster meat is tender and juicy with a hint of sea saltiness. Minced garlic and shredded ginger bring out a refreshing sweetness. Oysters are rich in high-quality protein and zinc, which can help boost immunity. The process is not complicated, but opening the hot lid and handling the oyster shells require some care, and beginners can easily do it. From washing to serving, it takes about twenty minutes.', '[{"name":"Oysters","unit":"piece"},{"name":"Scallion","unit":"piece"},{"name":"Garlic","unit":"clove"},{"name":"Ginger","unit":"small piece"},{"name":"Soy sauce","unit":"ml"}]'::jsonb, '["Scrub the oysters clean with a brush (or a toothbrush if no brush).","Add water to the steamer, place the steamer rack, then arrange 6 oysters flat on the rack. Steam at 50% power for 3 minutes.","Use a wet cloth in your right hand to open the hot lid. For each oyster, open half of the shell and remove it, placing the oyster with the curved side down and flat side up. Put 1 shred of ginger and 10g minced garlic on each oyster.","Close the hot lid and steam at 100% power for 3.5 minutes.","Turn off the heat. Use a cloth in your right hand to open the hot lid. Add 5ml soy sauce to each oyster.","Plate and serve."]'::jsonb, '["Seafood","Steamed","Shellfish","Light","Home-style","Quick"]'::jsonb),
  ('howtocook:aquatic/清蒸鲈鱼/清蒸鲈鱼', 'en', 'Steamed Sea Bass', 'Seafood', 'Steamed sea bass is a classic Cantonese steamed dish. The fish meat is tender and smooth, light and fresh, retaining the original flavor of the sea bass to the greatest extent. Sea bass is rich in high-quality protein and DHA, nutritious and easy to digest. This dish is simple to prepare and very beginner-friendly, taking about 30 minutes from prep to serving.', '[{"name":"Sea bass","unit":"whole"},{"name":"Scallions","unit":"stalk"},{"name":"Ginger","unit":"piece"},{"name":"Cooking oil","unit":"ml"},{"name":"Steamed fish soy sauce","unit":"ml"},{"name":"Cooking wine","unit":"ml"},{"name":"Salt","unit":"g"}]'::jsonb, '["Slice the ginger into pieces and then into thin strips. Cut the white parts of the scallions into sections, and slice the green parts into thin strips. Soak the scallion strips in cold water and set aside.","After cleaning the sea bass, pat dry with paper towels. Make a few cuts on both sides. Rub the fish with salt to remove the slime, then rub 10g of salt all over the inside and outside of the fish. Marinate for at least 10 minutes.","Here''s a tip for cutting and plating the sea bass: after scoring, the fish can stand upright while steaming, ensuring even heating and making it easier to eat without flipping.","Score the fish","清蒸鲈鱼-预览图-2","Stuff the fish belly with ginger and scallion whites, and also sprinkle some on top. Use half of the prepared amount. Place chopsticks under the fish in the steaming plate to lift it off the bottom.","Heat the water until it''s warm to the touch, then place the fish in the steamer.","Steam over high heat for 10 minutes.","Transfer the steamed fish to a clean plate and remove the ginger and scallions from the fish.","Drizzle 15ml of steamed fish soy sauce over the fish.","Sprinkle fresh ginger and scallion strips on the fish. Heat 10ml of cooking oil in a pan until hot, then pour the hot oil over the fish. Serve."]'::jsonb, '["Seafood","Steamed","Cantonese","Light","Tender","Home-style"]'::jsonb),
  ('howtocook:aquatic/白灼虾/白灼虾', 'en', 'Boiled Shrimp', 'Seafood', 'Boiled shrimp is a classic quick Cantonese dish. The shrimp meat is sweet, bouncy, and tender, preserving its original flavor. Shrimp is rich in high-quality protein and various minerals. Paired with dipping sauce, it''s appetizing and not greasy. The method is simple and forgiving, very beginner-friendly. From prep to serving, it takes only about 15 minutes.', '[{"name":"Live shrimp","unit":"g"},{"name":"Onion","unit":"head"},{"name":"Ginger","unit":"piece"},{"name":"Garlic","unit":"clove"},{"name":"Scallion","unit":"stalk"},{"name":"Cooking oil","unit":"ml"},{"name":"Soy sauce","unit":"ml"},{"name":"Cooking wine","unit":"ml"},{"name":"Sesame","note":"a handful"},{"name":"Vinegar","unit":"ml"},{"name":"Oyster sauce","unit":"ml"}]'::jsonb, '["Cut the onion into small pieces, slice the ginger, and spread them evenly in a flat-bottomed pan.","Rinse the live shrimp (optional: devein, snip off legs and antennae), drain, and lay them on top of the onion and ginger in the pan.","Pour in cooking wine, cover the lid. Cook on medium heat for 1 minute, then low heat for 5 minutes. Turn off the heat and let sit for 5 minutes.","Concurrently with the previous step, prepare the dipping sauce:","Chop the scallion into small pieces, mince the garlic, then add soy sauce, sesame, and vinegar. Stir to combine.","Heat the oil until hot, then pour it over the dipping sauce.","Remove the shrimp from the pan and plate on a clean dish."]'::jsonb, '["Seafood","Cantonese","Savory","Quick","Homestyle"]'::jsonb),
  ('howtocook:aquatic/糖醋鲤鱼/糖醋鲤鱼', 'en', 'Sweet and Sour Carp', 'Seafood', 'Sweet and Sour Carp is a classic Shandong dish, crispy on the outside and tender on the inside, with a perfect balance of sour and sweet. The fish is deep-fried until golden and then topped with a bright red sweet and sour sauce, making it very appetizing. The fish is rich in high-quality protein and various minerals, easy to digest and absorb. This dish is not very beginner-friendly; it''s medium to high difficulty, requiring mastery of cutting techniques, battering, and frying temperature. From prep to serving, it takes about 1 hour.', '[{"name":"Carp","unit":"lb"},{"name":"Ketchup","unit":"g"},{"name":"White sugar","unit":"g"},{"name":"White vinegar","unit":"g"},{"name":"Cornstarch","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Scallion","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Cooking wine","unit":"g"},{"name":"Cilantro","unit":"bunch"},{"name":"All-purpose flour","unit":"g"},{"name":"Egg","unit":"piece"},{"name":"Water","unit":"g"},{"name":"Cooking oil","unit":"L"}]'::jsonb, '["Clean the fish thoroughly, ensuring no scales or foreign matter.","Place the fish with head to the left, belly down, and hold the knife in your right hand. Cut vertically 1 cm deep, then while holding the fish firmly, slice horizontally to the left 3-4 cm. Then lightly score the middle of the fish slice.","Put the fish in a basin. Slice the ginger into thick slices and cut the scallion into sections (just roughly chop, mainly for removing fishy smell).","Squeeze the juice from the scallion and ginger into the basin with all your might.","Add 20g salt and 25g cooking wine, then give the carp a bath by rubbing evenly.","Marinate.","In a clean basin, add 100g flour, 200g cornstarch, 180g water, and 5g salt. Mix evenly by hand until the batter is thick and can be pulled into strings. Then crack in one egg and mix again until smooth.","Wait 30 minutes.","Place the fish on a cutting board and dry the body with a dry towel (this helps the batter adhere better).","Rinse the basin clean and dry with a dry towel.","Heat oil in a wok, add about 1L of oil, and heat to 70% hot, about 200-240°C.","Hold the fish by the tail and lower the head into the oil. Use a ladle to pour hot oil over the fish''s body. Once the batter sets, slowly lower the whole fish into the oil. Gently lift the head with a spatula and place a strainer underneath to prevent the bottom from burning.","Prepare a plate for the fish and place it next to the wok.","Gently slide the spatula under the fish''s body and flip it over with the help of another tool. Fry for another two minutes. Then, using the same method (strainer supporting the head, spatula supporting the body), lift the fish onto the plate.","Pour the oil from the wok into a dry basin and set aside. Clean the wok thoroughly.","In a small bowl, mix 50g water, 40g ketchup, 20g white sugar, and 10g white vinegar until well combined.","In another small bowl, mix 10g cornstarch and 10g water to make a slurry.","Heat the wok over high heat, then pour in the sauce mixture. Bring to a boil over high heat, then reduce to low heat.","Add the cornstarch slurry, stirring constantly. After 20 seconds, turn off the heat.","Pour the sweet and sour sauce evenly over the fish using a ladle. Garnish with a little cilantro or chopped scallion. Sweet and Sour Carp is ready.","Sweet and Sour Carp - Preview Image 2"]'::jsonb, '["Seafood","Sweet and Sour","Deep-fried","Shandong Cuisine","Entertaining","New Year''s Eve Dinner"]'::jsonb),
  ('howtocook:aquatic/红烧鱼', 'en', 'Braised Fish', 'Seafood', 'Braised fish is a classic home-style dish with rich flavors, savory with a hint of sweetness, tender and flavorful fish meat. It is a popular Chinese braised dish. Fish is rich in high-quality protein and unsaturated fatty acids, easy to absorb. The process involves handling raw fish and pan-frying, with several steps, which may be challenging for beginners, but following the recipe can still succeed. From prep to serving, it takes about 40 minutes.', '[{"name":"Ginger","unit":"slices"},{"name":"Garlic cloves","unit":"cloves"},{"name":"Dried chili peppers","unit":"pieces"},{"name":"Oil","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Cooking wine","note":"to taste"},{"name":"Vinegar","unit":"ml"},{"name":"Soy sauce","unit":"ml"},{"name":"White sugar","unit":"g"},{"name":"Fish","unit":"piece"},{"name":"Oyster sauce","unit":"g"},{"name":"Green onions","unit":"stalks"},{"name":"Cilantro","note":"to taste"},{"name":"Small chili peppers"},{"name":"MSG (chicken powder)","unit":"g"}]'::jsonb, '["Prepare ginger and garlic, chop finely","Chop dried chili peppers, combine with ginger and garlic","Add 30-50ml oil, wait for the pan to heat up...","Place the dried fish (to avoid oil splatters), then shake the pan to fry the fish in hot oil, ensure to use low heat","Flip the fish, repeat the frying process","Add ginger, garlic, and chili, stir-fry until fragrant","Pour in cooking wine, a bit more, be careful as it will create a lot of smoke","Pour in vinegar (add more if you like vinegar)","Then add white sugar and soy sauce (dark soy sauce)","Add cold water, just enough to submerge the fish, then turn to medium heat, cover the lid, after about 1 minute flip the fish, continue covering","After 3-4 minutes, add salt, small chili peppers, oyster sauce (or MSG, chicken powder), then continue covering, flip again later","When the sauce has reduced to just below the fin on the fish''s back (or when there''s not much sauce left), turn to low heat, add cilantro and chopped green onions, then cover for 20 seconds, turn off heat","Serve"]'::jsonb, '["Seafood","Braised","Savory","Pan-fried","Home-style","Rice companion"]'::jsonb),
  ('howtocook:aquatic/红烧鱼头', 'en', 'Braised Fish Head', 'Seafood', 'Braised fish head is a classic home-cooked dish. The fish head is rich in collagen, with tender and smooth meat. The sauce is savory with a slight spiciness, perfect with rice. Fish head is rich in high-quality protein, lecithin, and unsaturated fatty acids, beneficial for skin and brain health. Since it involves handling raw fish and chopping bones, it is slightly challenging and not recommended for absolute beginners. The whole process (including marinating) takes about 2–2.5 hours.', '[{"name":"Fish Head","unit":"piece"},{"name":"Scallion","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Garlic","unit":"head"},{"name":"Fairy Pepper","unit":"piece"},{"name":"Cilantro","unit":"stalk"},{"name":"Star Anise","unit":"piece"},{"name":"Dried Chili","unit":"piece"},{"name":"Oil","unit":"ml"},{"name":"Salt (for marinating)","unit":"g"},{"name":"Salt (for cooking)","unit":"g"},{"name":"Light Soy Sauce (for marinating)","unit":"g"},{"name":"Light Soy Sauce (for cooking)","unit":"g"},{"name":"Cooking Wine (for marinating)","unit":"g"},{"name":"Cooking Wine (for cooking)","unit":"g"},{"name":"Chicken Bouillon","unit":"g"},{"name":"Dark Soy Sauce","unit":"g"},{"name":"Aged Vinegar","unit":"g"},{"name":"Black Pepper","unit":"g"},{"name":"Water","unit":"ml"}]'::jsonb, '["Wash scallions, ginger, garlic, cilantro, and fairy peppers separately.","Rinse dried chilies and star anise briefly.","Cut the scallion in half. For the back half (white part), cut into sections about 4 cm each. For the front half (green part), first cut into sections, then split each section into four pieces.","Slice ginger into pieces about 3 mm thick.","Crush the garlic cloves.","Take two cilantro stalks, remove the roots, and cut into 1.5 cm pieces.","Slice fairy peppers into rings about 3 mm thick.","Cut dried chilies into four sections each.","Note: The fish body mentioned below refers to the meat attached to the fish head when purchased.","Scale the fish head and clean any remaining internal organs from the head area.","Chop off the fins and clean out the gills.","Separate the lower jaw from the body, chop the body into pieces, and cut the head into four or six pieces.","Note: Handling the fish is hard to describe fully in text; search for fish head preparation videos.","Rinse the chopped fish pieces, ideally washing off any blood residue.","Place the cleaned fish pieces in a bowl. Add 5g salt, 10g light soy sauce, 10g cooking wine. Add the chopped green part of the scallion and 1/3 of the ginger slices. Mix well and let sit for 1–2 hours.","Add 30ml oil and wait for the pot to heat...","When the oil is hot, turn the heat to low.","If you don''t understand why, please refer to the section on stir-frying aromatics in ''Learning to Stir-fry and Pan-fry''.","Add ginger slices and stir-fry slowly until most of the ginger juice is released and they turn golden brown.","Add scallion sections and stir-fry until they become slightly white.","Add crushed garlic, star anise, and dried chilies; stir-fry for 5 seconds.","Pour the marinated fish head into the pot and stir-fry for 2–3 minutes.","Add 500ml water, then 2g salt, 3g chicken bouillon, 5g light soy sauce, 3g dark soy sauce, 5g cooking wine, 2g black pepper, and 3g aged vinegar.","Add the two cilantro stalks into the pot and cover with a lid.","Turn to high heat and bring the water to a boil.","Turn to medium heat and let it simmer slowly to infuse flavors.","When the liquid has reduced by half, uncover the pot.","Turn to high heat to reduce the sauce. When about 1/3 of the liquid remains, turn off the heat and transfer to a small bowl.","Note: Evenly pour the sauce in the pot over the fish head. When serving, you can place the cooked cilantro at the bottom of the bowl for a better presentation and taste.","Place cilantro on top of the fish head, then arrange the fairy pepper rings over the cilantro.","Your aromatic and flavorful braised fish head is ready!"]'::jsonb, '["Seafood","Braised","Savory","Slightly Spicy","Stewed","Goes with Rice","Home-style"]'::jsonb),
  ('howtocook:aquatic/红烧鲤鱼', 'en', 'Braised Carp', 'Seafood', 'Braised carp is a homestyle Shandong dish. The fish is first fried then braised, with a slightly chewy skin and tender flesh. The savory-sweet sauce carries the rich flavor of pork belly, and the thick gravy is perfect over rice. Rich in high-quality protein and minerals like calcium and phosphorus, it''s nourishing. Frying the fish and balancing the seasonings require a bit of patience, but the steps are clear, even beginners can follow. From prep to finish, it takes about 1 hour.', '[{"name":"carp","unit":"jin"},{"name":"pork belly","unit":"g"},{"name":"scallions","unit":"g"},{"name":"ginger","unit":"g"},{"name":"garlic cloves","unit":"pieces"},{"name":"dried chili peppers","unit":"pieces"},{"name":"oil","note":"as needed"},{"name":"salt","unit":"g"},{"name":"light soy sauce","unit":"ml"},{"name":"dark soy sauce","unit":"ml"},{"name":"aged vinegar","unit":"ml"},{"name":"oyster sauce","unit":"ml"},{"name":"cooking wine","unit":"ml"},{"name":"sugar","unit":"g"}]'::jsonb, '["Wash the scallions, ginger, garlic, and dried chili peppers separately.","Cut the white part of the scallions into segments about 4 cm long, then split each segment into four strips.","Slice the ginger into pieces about 3 mm thick.","Smash and mince one garlic clove, cut the remaining cloves in half.","Cut the dried chili peppers into four pieces each.","Slice the pork belly into pieces about 4 cm by 4 cm.","Clean the fish.","Make several diagonal slits on the thick part of the fish''s back to help it absorb flavors.","Pour enough oil into the pan, heat to 70% hot (just starting to smoke), then fry the fish for 1 minute until the skin firms up slightly. Remove and set aside (do not disturb the fish immediately; wait a bit before turning). Pour out the frying oil, leaving a little base oil in the pan.","Heat the remaining oil in the pan, add the pork belly, and stir-fry until fragrant.","Add the dried chili peppers, scallions, ginger, and garlic cloves, and stir-fry for 1 minute.","Place the fried fish back into the pan.","Pour along the edge of the pan:","50 ml cooking wine","50 ml aged vinegar","50 ml premium light soy sauce","20 ml dark soy sauce for color","5 ml oyster sauce for umami","5 g salt","50 g sugar","Add water until it just covers the fish.","Turn the heat to medium and bring to a boil.","Reduce to low heat and simmer gently to infuse flavors.","After 15 minutes, uncover the pot, and pick out the scallions, ginger, garlic, and dried chili peppers.","Turn the heat to high to reduce the sauce. When about 1/4 of the sauce remains, sprinkle some minced garlic, turn off the heat, and serve.","Braised carp is ready!"]'::jsonb, '["Fish","Braised","Salty-sweet","Soy sauce aroma","Goes well with rice","Shandong cuisine","Home-style"]'::jsonb),
  ('howtocook:aquatic/肉蟹煲', 'en', 'Meat Crab Pot', 'Seafood', 'This dish has a rich sauce flavor, with sweet and slightly spicy crab meat, soft and sticky potatoes, chewy rice cakes, and the sauce is especially satisfying when mixed with rice. It''s a hearty dish suitable for gatherings. It is rich in high-quality protein and various trace elements, nutritious. It is moderately difficult to make, requiring handling live crabs, controlling heat and seasoning ratios, somewhat challenging for beginners, and takes about 1 hour in total.', '[{"name":"meat crab","unit":"g"},{"name":"shrimp","unit":"g"},{"name":"potato","unit":"g"},{"name":"rice cake","unit":"g"},{"name":"onion","unit":"g"},{"name":"garlic","unit":"g"},{"name":"garlic (additional for shrimp)","unit":"g"},{"name":"ginger","unit":"g"},{"name":"dried chili","unit":"g"},{"name":"green bell pepper","unit":"g"},{"name":"red bell pepper","unit":"g"},{"name":"oyster sauce","unit":"g"},{"name":"hoisin sauce","unit":"g"},{"name":"fermented soybean paste","unit":"g"},{"name":"sweet bean sauce","unit":"g"},{"name":"ketchup","unit":"g"},{"name":"cornstarch","unit":"g"},{"name":"rock sugar","unit":"g"},{"name":"chicken bouillon","unit":"g"},{"name":"white pepper powder","unit":"g"},{"name":"white pepper powder (additional for shrimp)","unit":"g"},{"name":"cooking wine","unit":"ml"},{"name":"light soy sauce","unit":"ml"},{"name":"dark soy sauce","unit":"ml"},{"name":"cooking oil","unit":"ml"},{"name":"cooking oil (additional for shrimp)","unit":"ml"},{"name":"cooking oil (for deep-frying)","unit":"ml"},{"name":"beer","unit":"ml"},{"name":"beer (additional for shrimp)","unit":"ml"},{"name":"water","unit":"ml"},{"name":"water (additional for shrimp)","unit":"ml"}]'::jsonb, '["Cut potatoes into 3 cm cubes, green and red bell peppers into 4 cm diamond-shaped slices, onions into 3 cm wide crescent moons, and rice cakes into 1 cm thick slices.","Cut crabs into 50-80 g pieces, coat lightly with starch, deep-fry at 180°C for 1 minute, then remove.","Heat oil in a wok, sauté garlic, ginger, and dried chili until fragrant. Add all sauces and rock sugar, stir-fry over low heat until red oil appears, being careful not to burn.","Add crabs, potatoes, beer, and water. Bring to a boil, then simmer for 12 minutes.","Add rice cakes and green/red bell peppers. Turn up the heat to reduce the sauce until it coats the ingredients. Finally, sprinkle white pepper powder."]'::jsonb, '["Seafood","Sauce-rich","Slightly spicy","Braising","Banquet","Rice dish","Gathering"]'::jsonb),
  ('howtocook:aquatic/芥末黄油罗氏虾/芥末黄油罗氏虾', 'en', 'Wasabi Butter Prawns', 'Seafood', 'This dish features the wonderful pairing of butter and wasabi. The prawn meat is firm and bouncy, with a rich and spicy sauce. It''s a modern seafood dish. Prawns are rich in high-quality protein and various trace elements, making it nutritious. The difficulty is moderate; with proper preparation and heat control, even beginners can succeed. From preparing live prawns to serving, it takes about 30 minutes.', '[{"name":"Prawns (Giant River Prawns)","unit":"lb"},{"name":"Butter","unit":"g"},{"name":"Wasabi","unit":"g"},{"name":"Sugar","unit":"g"},{"name":"Light Soy Sauce","unit":"g"},{"name":"Oyster Sauce","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Cooking Wine, Rum or Beer","unit":"g"},{"name":"Cilantro","unit":"stalks"},{"name":"Garlic","unit":"cloves"}]'::jsonb, '["Cut off the sharp spikes, antennae, and legs of the prawns. Use scissors to butterfly the backs and remove the digestive tracts.","Mix the wasabi sauce in advance: soy sauce, oyster sauce, wasabi, salt, sugar. Stir well!","Wash the cilantro and cut into sections. Set aside.","Drain the prawns. Add oil to the pan, place the prawns in, and cook over medium heat until the surface turns golden. Remove.","Add minced garlic, turn to high heat, and stir-fry in the remaining oil. When white smoke appears and the garlic is fragrant, add back the prawns and butter. Let the prawns fully absorb the butter aroma.","Add the prepared sauce, continue boiling over high heat, and stir-fry the prawns until the sauce thickens. Add wine (30g of cooking wine or beer, or 15g of rum for a stronger flavor).","When the sauce is slightly reduced, add cilantro, stir-fry a couple of times, and serve."]'::jsonb, '["Seafood","Wasabi Fragrant","Pan-fried","Modern Seafood","Party","Quick"]'::jsonb),
  ('howtocook:aquatic/葱油桂鱼/葱油桂鱼', 'en', 'Steamed Mandarin Fish with Scallion Oil', 'Seafood', 'Steamed Mandarin Fish with Scallion Oil is a home-style steamed dish with rich scallion aroma and tender fish. It belongs to light Chinese flavors and suits all palates. Mandarin fish is rich in high-quality protein and unsaturated fatty acids. Through careful deodorization, it retains the fish''s freshness and nutrition. The recipe is beginner-friendly and tolerant of mistakes; as long as you follow the steps, it''s basically foolproof. From prep to serving, it takes about 45 minutes in total.', '[{"name":"mandarin fish","unit":"g","note":""},{"name":"scallions","unit":"stalks","note":""},{"name":"bird''s eye chilies","unit":"pieces","note":""},{"name":"ginger","unit":"g","note":""},{"name":"cooking wine","unit":"g","note":""},{"name":"vegetable oil","unit":"g","note":""},{"name":"salt","unit":"g","note":""},{"name":"steamed fish soy sauce","unit":"g","note":""},{"name":"water","unit":"L","note":""}]'::jsonb, '["Buy a pre-cleaned fish from the market (if cleaning yourself, remove the innards). Scrape off all scales from the fish skin.","Use a paper towel to wipe away the blood and black membrane inside the belly (blood affects texture; black membrane is the source of fishy smell).","Scrape the fish skin back and forth with a knife to remove the slime, further removing fishy smell. Then rinse the fish inside and out with water.","Place the fish flat on a cutting board. Pat dry inside and out with paper towels. With the head on the left and tail on the right, make vertical cuts every 3 cm starting from the gill, cutting down to the backbone. Repeat on the other side.","Place the fish flat in a basin, ensuring there is no excess water in the basin.","Take 50g of ginger (about the size of an egg). Peel the skin with a peeler and wash it. Slice into 3 mm thick slices.","Wash the bird''s eye chilies, remove the stems, and cut into 2 mm thick rounds (or 1 mm wide strips).","Wash the scallions, remove the roots, and cut into 3 cm pieces. For thicker scallions, split them lengthwise down the middle.","Add 8g salt and 25g cooking wine to the basin. Put on disposable gloves and massage the fish all over for 1 minute, ensuring every part is evenly coated with salt and wine.","After massaging, insert one ginger slice into each cut on the fish, and put 3 ginger slices inside the belly. Marinate for 10 minutes (don''t marinate too long, or the fish will lose freshness).","While the fish marinates, add 5L of water to a steamer pot. Bring to a boil, then place a steamer basket on top.","After marinating, liquid will be released. Discard the excess liquid, along with the used cooking wine and ginger slices. Rinse the fish body and belly with water, then pat dry with paper towels.","Place the fish flat on a steaming plate. Insert ginger slices into the cuts and belly again.","Put the steaming plate into the steamer basket. Cover and steam over medium heat for 20 minutes.","During steaming, steam will condense on the fish and plate, forming fish broth. After taking it out, do not discard this broth; it is the essence of umami.","Use heat-resistant tongs to remove the plate. Drizzle 10g of steamed fish soy sauce over the fish and around it.","Evenly sprinkle the scallion pieces and bird''s eye chilies over the fish and around it.","Pour 15g of vegetable oil into an iron pan. Heat over medium-low heat for 5 minutes. Do not use high heat, or the oil will evaporate quickly.","Slowly and evenly pour the hot oil over the fish. The umami-packed steamed mandarin fish with scallion oil is ready!"]'::jsonb, '["Seafood","Steamed","Scallion","Home-style","Umami","Light"]'::jsonb),
  ('howtocook:aquatic/葱烧海参/葱烧海参', 'en', 'Braised Sea Cucumber with Scallion', 'Seafood', 'This is a classic Shandong home-style braised seafood dish, featuring rich scallion aroma and soft, flavorful sea cucumber. The sauce is thick, savory, and slightly sweet. Sea cucumber is rich in collagen and trace elements, beneficial for nourishing the body. The overall cooking difficulty is low, but requires time to fully rehydrate dried sea cucumber beforehand. The actual braising process takes about 30 minutes. Beginners can succeed easily by following the steps.', '[{"name":"Rehydrated sea cucumber","unit":"pieces"},{"name":"Scallion whites (large scallion)","unit":"stalks"},{"name":"Cooking oil","unit":"ml"},{"name":"Oyster sauce","unit":"g"},{"name":"Light soy sauce","unit":"g"},{"name":"Sugar","unit":"g"},{"name":"Starch","unit":"g"},{"name":"Water","unit":"ml"}]'::jsonb, '["Cut the scallion whites into 1 cm sections. Set aside.","Cut the sea cucumber into 1 cm sections. Set aside.","Prepare a small bowl. Mix 20g oyster sauce, 10g light soy sauce, and 2g sugar. Sauce.","In another bowl, mix starch and water to make a slurry for thickening.","Heat the pan. Add 20-25 ml cooking oil. Wait 10 seconds for oil to heat.","Add scallion whites. Reduce heat to low. Be careful not to burn them. Fry for about 3-5 minutes. Scallion whites.","Remove scallion whites with chopsticks and place on a plate. Set aside.","Pour in the prepared sauce. Stir-fry until fragrant, about 1-2 minutes.","Add the cut sea cucumber. Stir-fry for 1 minute.","Add 100 ml water. Cook over medium-low heat for 5 minutes.","When the sauce is almost dry, add the starch slurry and the reserved scallion whites.","When the sauce becomes thick and sticky, turn off the heat. Plate and serve. Preview image."]'::jsonb, '["Seafood","Shandong Cuisine","Braising","Savory","Banquet","Sea Delicacy"]'::jsonb),
  ('howtocook:aquatic/蒜蓉虾/蒜蓉虾', 'en', 'Garlic Shrimp', 'Seafood', 'This classic Cantonese dish is known for its fresh, fragrant, tender, and smooth texture. The shrimp are sweet and bouncy, with a strong aroma of garlic. Sea shrimp are rich in high-quality protein, calcium, selenium, and other trace elements. Paired with garlic sauce, it helps kill bacteria and stimulate appetite. The method is very simple: prepare the shrimp, spread the sauce, steam, and drizzle with hot oil. Even a beginner can easily master it. The whole process takes about 15 minutes.', '[{"name":"Sea shrimp","unit":"pieces"},{"name":"Garlic sauce","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Light soy sauce","unit":"ml"}]'::jsonb, '["Cut from the middle of the shrimp head to 1 cm from the tail","Spread the garlic sauce in the middle of the shrimp body and place on a plate","Pour hot water into a pot, put the plate in the pot, and steam over high heat for 3 minutes","Heat oil until hot, pour over the shrimp on the plate, then add light soy sauce"]'::jsonb, '["Seafood","Savory","Steamed","Cantonese","Quick","Rice Companion"]'::jsonb),
  ('howtocook:aquatic/蒜香黄油虾/蒜香黄油虾', 'en', 'Garlic Butter Shrimp', 'Seafood', 'Garlic Butter Shrimp is a classic Western seafood dish. The shrimp is tender and bouncy, coated in rich garlic and butter with a hint of lemon. Shrimp is high in quality protein, and the butter provides energy, making it a quick nutritional boost. The recipe is simple, requiring only a few common ingredients. Even beginners can easily make it, from prep to plate in about twenty minutes.', '[{"name":"Large shrimp","unit":"pieces"},{"name":"Unsalted butter","unit":"g"},{"name":"Garlic","unit":"cloves"},{"name":"White wine","unit":"ml"},{"name":"Lemon","unit":"piece"},{"name":"Olive oil","unit":"ml"}]'::jsonb, '["Remove the heads and shells from the shrimp, leaving the tails on. Use a toothpick to devein, rinse, and pat dry with paper towels.","Mince the garlic and set aside.","Heat a frying pan over medium heat and add 10 ml olive oil.","When the oil is hot, add the shrimp and sear for 1-1.5 minutes per side until pink. Remove and set aside.","In the same pan, add the butter. Once melted, add the minced garlic and sauté over low heat until fragrant (about 30 seconds).","If using white wine, add it now and cook until the alcohol evaporates (about 1 minute).","Return the shrimp to the pan and toss to coat evenly with the garlic butter sauce (about 1 minute).","Squeeze in lemon juice, toss to combine, and immediately turn off the heat.","Plate and drizzle with remaining sauce from the pan."]'::jsonb, '["Seafood","Garlic","Savoury","Western","Pan-fried","Quick","Seafood"]'::jsonb),
  ('howtocook:aquatic/蛏抱蛋/蛏抱蛋', 'en', 'Razor Clams with Egg', 'Seafood', 'Razor clams with egg is a traditional home-style dish from Fuzhou, Fujian. The clam meat is coated in egg and pan-fried until crispy outside and tender inside, with the savory aroma of onion and light soy sauce. Razor clams are rich in high-quality protein, zinc, iron, and other trace elements, making them a balanced match with eggs. The difficulty is moderate; you need to control the frying heat, but the steps are not complicated. It takes about 30 minutes to serve.', '[{"name":"razor clams","unit":"g"},{"name":"eggs","unit":"piece"},{"name":"cooking oil","unit":"ml"},{"name":"onion","unit":"piece"},{"name":"cornstarch","unit":"g"},{"name":"light soy sauce","unit":"ml"},{"name":"chicken bouillon","unit":"ml"},{"name":"cooking wine","unit":"ml"}]'::jsonb, '["Bring water to a boil, add clams, cook for 2 minutes, then remove and shell them. Place in a large bowl.","Add onion, light soy sauce, cooking wine, chicken bouillon, and cornstarch to the bowl. Stir well.","Crack 2 eggs into the bowl and continue stirring.","Heat oil in a pan, pour in the clam mixture. Fry until one side is golden, then flip and continue frying."]'::jsonb, '["Seafood","Savory","Pan-fried","Fujian Cuisine","Home-style","Goes well with rice"]'::jsonb),
  ('howtocook:aquatic/酱炖蟹', 'en', 'Braised Crab with Sauce', 'Seafood', 'This dish is a limited autumn flavor from Pinghu area of Zhejiang, with a savory and salty taste. The crab roe is rich and smooth with sauce fragrance, the crab meat is sweet, and the sauce is perfect for mixing with rice. Rich in high-quality protein and trace elements. Moderate difficulty, suitable for beginners with some experience. Preparation to finish takes about 30 minutes.', '[{"name":"Crab (preferably river crab, alternatively swimming crab)","unit":"g"},{"name":"Bean paste","unit":"g"},{"name":"Rock sugar (optional)","unit":"g"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Vegetable oil (unrefined rapeseed oil, commonly called ''crude rapeseed oil'' or ''local rapeseed oil'', alternative: peanut oil)","unit":"ml"},{"name":"Ketchup","unit":"ml"},{"name":"Cooking wine","unit":"ml"},{"name":"Old ginger","unit":"g"},{"name":"Scallion","unit":"g"},{"name":"Egg (optional)","unit":"piece"},{"name":"Minced pork (optional)","unit":"g"},{"name":"Water","unit":"ml"}]'::jsonb, '["Scrub the crabs clean, then split them in half on a cutting board.","Add vegetable oil to the pot, stir-fry minced ginger and bean paste until fragrant, add rock sugar and stir until dissolved, until small bubbles appear, then remove from heat.","Spread a layer of sauce on a plate, then place the cut crabs face down neatly on the sauce.","Add some scallion sections and ginger slices. It is recommended to crack an egg or spread minced meat on the bottom of the plate.","Steam for 10-12 minutes."]'::jsonb, '["Seafood","Savory","Sauce","Steamed","Jiangzhe","Rice-pairing","Autumn limited"]'::jsonb),
  ('howtocook:aquatic/阳朔啤酒鱼/阳朔啤酒鱼', 'en', 'Yangshuo Beer Fish', 'Seafood', 'Yangshuo Beer Fish is a famous local dish from Yangshuo, Guangxi. It uses fresh fish from the Lijiang River, fried with scales on, then braised with beer instead of water. The scales are crispy, the flesh tender. The aroma of beer blends with the slight acidity of tomatoes, creating a rich and unique flavor. The fish is rich in high-quality protein and minerals. Paired with tomatoes and peppers, it is packed with vitamins and whets the appetite. Moderate difficulty; a bit challenging for beginners but doable by following the steps. It takes about 30 minutes to finish.', '[{"name":"Swordbone fish or carp","unit":"piece"},{"name":"Liquan beer","unit":"ml"},{"name":"Tomato","unit":"piece"},{"name":"Green pepper","unit":"piece"},{"name":"Red pepper","unit":"piece"},{"name":"Garlic","unit":"clove"},{"name":"Ginger","unit":"piece"},{"name":"Scallion","unit":"stalk"},{"name":"Guilin chili sauce","unit":"g"},{"name":"Cooking wine","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Sugar","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Cooking oil","unit":"ml"}]'::jsonb, '["Clean the fish, remove innards but keep scales. Rinse clean. Butterfly the fish from the belly (keeping the back connected). Marinate with 15ml cooking wine, ginger slices, and 3g salt for 15 minutes.","Cut tomato into chunks, green and red peppers into chunks. Smash garlic cloves, slice ginger, cut scallion into sections (separate white and green parts).","Rub the bottom of the pan with ginger slices. Heat the pan and add 30ml cooking oil. When oil is hot, place the fish in (skin side down). Fry until both sides are golden and scales are crispy. Remove and set aside.","Leave a little oil in the pan. Add scallion whites, ginger slices, and garlic cloves. Stir-fry until fragrant.","Add 15g Guilin chili sauce. Stir-fry until red oil releases.","Add tomato chunks. Stir-fry until tomatoes release juice and soften.","Pour in a whole bottle of beer. Add 15ml light soy sauce, 5ml dark soy sauce, 5g sugar, and 5g salt. Stir to combine.","Place the fried fish into the pan. Bring to a boil over high heat, then reduce to medium-low heat. Cover and simmer for 15-20 minutes.","Uncover, add green and red pepper chunks. Continue cooking for 3-5 minutes.","Increase heat to reduce the sauce until thickened. Sprinkle with scallion greens. Serve on a plate."]'::jsonb, '["Seafood","Guangxi Specialty","Pan-fried and braised","Savory and slightly spicy","Goes with rice","Banquet dish"]'::jsonb),
  ('howtocook:aquatic/香煎翘嘴鱼/香煎翘嘴鱼', 'en', 'Pan-Fried Topmouth Culter', 'Seafood', 'Pan-fried topmouth culter is a flavorful home-style river fish dish. The fish is salted and dried for a couple of days, then pan-fried until the skin is golden and crispy. The meat is tender and savory, with a hint of spicy sweetness from broad bean paste and green peppers. Rich in protein and healthy fats, it''s nutritious and easy to digest. Preparation requires 2-4 days for salting and drying, and cooking takes about half an hour. Frying needs patience with heat control, a bit challenging for beginners, but the result is aromatic and goes perfectly with rice.', '[{"name":"Topmouth culter","unit":"lb","note":""},{"name":"Ginger","unit":"g","note":""},{"name":"Scallion","unit":"g","note":""},{"name":"Garlic","unit":"clove","note":""},{"name":"Green pepper","unit":"","note":"to taste"},{"name":"Cilantro","unit":"","note":"to personal taste"},{"name":"Dark soy sauce","unit":"ml","note":""},{"name":"Sugar","unit":"g","note":""},{"name":"Broad bean paste","unit":"","note":"to taste"},{"name":"Cooking wine","unit":"ml","note":""},{"name":"Light soy sauce","unit":"ml","note":""},{"name":"Salt","unit":"g","note":""},{"name":"Cooking oil","unit":"ml","note":""},{"name":"Dried chili","unit":"piece","note":""},{"name":"Hot water","unit":"","note":"to taste"},{"name":"Chicken bouillon","unit":"","note":"to taste"},{"name":"Thirteen-spice powder","unit":"","note":"to taste"},{"name":"Aged vinegar","unit":"","note":"to taste"}]'::jsonb, '["Have the fish killed and cleaned by making a cut along the back (ask the fishmonger to do it; never cut the belly open), then wash thoroughly.","Rub salt evenly over the fish surface. Add about 80ml cooking wine and 20g minced ginger. Place in the refrigerator for 1-2 days to marinate.","Remove the marinated fish, hang it up with string to air-dry until half-dry (about 1-2 days, depending on temperature and sunlight).","Before cooking, rinse the fish with clean water and drain well (to prevent oil splatter).","Heat the wok over high heat, then quickly reduce to low heat. Add oil, making sure to coat the entire surface. Slide the fish into the wok along the edge (fry the back side first).","After placing the fish in the wok (and after flipping), do not move the fish immediately (the skin might break). After about 30 seconds, try shaking the wok.","Fry the back side for about 1 minute, then flip and fry the other side for about 1-2 minutes, until both sides are golden.","When both sides are cooked, push the fish to the side of the wok, leaving space to stir-fry the broad bean paste until fragrant, then add ginger and garlic.","After the aromatics are fragrant, add cooking wine, light soy sauce, dark soy sauce, and hot water. The water level should be level with the fish or slightly less.","Turn to medium-high heat and cook for 5-10 minutes. Then add green pepper segments, sugar, chicken bouillon, thirteen-spice powder, and aged vinegar.","Turn to low heat for 2-5 minutes, add spring onions and cilantro, then serve."]'::jsonb, '["Fish","Spicy","Pan-Fried","River Fish","Goes Well with Rice","Home-style"]'::jsonb),
  ('howtocook:aquatic/鲤鱼炖白菜/鲤鱼炖白菜', 'en', 'Braised Carp with Napa Cabbage', 'Seafood', 'Braised carp with napa cabbage is a fragrant and rich home-style stew. The fish is tender and flavorful, while the cabbage is sweet and absorbs the sauce. It''s a typical northern Chinese dish. Carp is rich in high-quality protein and unsaturated fatty acids, paired with cabbage for dietary fiber and vitamins, offering balanced nutrition. The process requires frying and simmering; moderately difficult but not too complex, suitable for cooks with some experience. From prep to serving takes about 40 minutes.', '[{"name":"Cooking oil","unit":"ml"},{"name":"Ginger","unit":"slice"},{"name":"Garlic","unit":"clove"},{"name":"Carp","unit":"jin"},{"name":"Baby cabbage (cabbage heart)","unit":"piece"},{"name":"Salt","unit":"g"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Cinnamon stick","unit":"piece"},{"name":"Star anise","unit":"piece"},{"name":"Pixian bean paste","unit":"g"},{"name":"Dried chili pepper","unit":"piece"}]'::jsonb, '["Clean the carp and make slashes on both sides (cut a few deep slits for better flavor absorption).","Wash the baby cabbage and set aside on a plate.","Heat oil in a pot. When hot, add a little salt, ginger, garlic, Pixian bean paste, cinnamon stick, and star anise. Stir-fry until fragrant.","Place the fish in the pot and fry for 3 minutes, flipping every 30 seconds.","Add water (enough to nearly cover the fish, slightly less is fine). Add light soy sauce, dark soy sauce, and the baby cabbage.","Simmer over high heat for 15-20 minutes. When the sauce is almost dried up, add salt to taste. Remove from heat and serve."]'::jsonb, '["Seafood","Savory","Stew","Home-style","Rice companion","Northern flavor"]'::jsonb),
  ('howtocook:aquatic/鳊鱼炖豆腐/鳊鱼炖豆腐', 'en', 'Braised Bream with Tofu', 'Seafood', 'Braised Bream with Tofu is a home-style red-cooked dish. The fish is tender and flavorful, the tofu soaks up the sauce, with a savory, slightly spicy taste. Bream is rich in high-quality protein and unsaturated fatty acids, while tofu provides plant protein and calcium, making a balanced meal. The cooking difficulty is moderate; frying the fish requires some patience to prevent sticking, but the steps are clear and beginners can try. It takes about 40 minutes from preparation to completion.', '[{"name":"bream","unit":"g"},{"name":"old tofu","unit":"g"},{"name":"ginger","unit":"slices"},{"name":"scallion","unit":"stalk"},{"name":"garlic","unit":"clove"},{"name":"dark soy sauce","unit":"ml"},{"name":"cinnamon","unit":"piece"},{"name":"rock sugar","unit":"piece"},{"name":"dried chili","unit":"piece"},{"name":"cooking wine","unit":"ml"},{"name":"light soy sauce","unit":"ml"},{"name":"salt","unit":"g"},{"name":"star anise","unit":"piece"},{"name":"bay leaf","unit":"leaf"},{"name":"cooking oil","unit":"ml"},{"name":"hot water","unit":"g"}]'::jsonb, '["Score the bream, top with ginger slices and cooking wine, and marinate for 5-10 minutes.","Cut the old tofu into pieces and set aside in water.","Add oil to the pan; you can add a little salt to prevent sticking. Pat the marinated fish dry with paper towels, place it in the pan, and fry both sides.","When both sides are browned, push the fish to the side, leaving space to add scallions, ginger, garlic, dried chili, bay leaves, and star anise; stir-fry until fragrant.","After the aromatics are fragrant, add cooking wine, light soy sauce, dark soy sauce, rock sugar, and cinnamon. Pour in hot water until just level with the fish or slightly less.","Bring to a boil over high heat, then add the old tofu, placing it around the edges. Add salt, then reduce to low heat.","Simmer on low heat for 10-15 minutes, then increase heat to reduce the sauce slightly. Serve."]'::jsonb, '["Seafood","Red-cooked","Home-style","Rice-friendly","Savory","Slightly spicy"]'::jsonb),
  ('howtocook:aquatic/黄油煎虾/黄油煎虾', 'en', 'Pan-fried Shrimp with Butter', 'Seafood', 'Pan-fried Shrimp with Butter is a home-style seafood dish with rich flavor, tender and springy shrimp meat. Fresh shrimp are rich in high-quality protein and minerals like calcium and zinc, paired with butter for added creaminess and energy. It''s relatively simple to make, just need patience in handling live shrimp; even beginners can master it, taking about an hour in total.', '[{"name":"Fresh shrimp","unit":"g"},{"name":"Butter","unit":"g"},{"name":"Black peppercorns","unit":"ml"},{"name":"Cooking oil","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Rice wine","unit":"ml"},{"name":"Sugar","unit":"ml"},{"name":"Salt","unit":"ml"}]'::jsonb, '["Remove the heads from the fresh shrimp, pulling out the vein along the way (if not done well, you can remove it when butterflying the shrimp in the next step). Use scissors to cut or a knife to slit open the back of the shrimp. Drain and set aside.","Prepare the sauce: In a small bowl, combine all of the light soy sauce, rice wine, sugar, and salt as listed above. Stir well and set aside.","Heat the pan over medium-high heat. Add cooking oil into the hot pan and wait for 10 seconds for the oil to heat up.","Add all the shrimp to the pan. Start grinding black pepper from the bottle, sprinkle evenly over the shrimp, and stir-fry.","Once the shrimp change color, add the butter. When the butter has completely melted, pour in the prepared sauce. Continue stir-frying.","Stir-fry over high heat for 15 seconds to reduce the sauce, then serve."]'::jsonb, '["Seafood","Savory","Rich buttery","Pan-frying","Quick dish","Rice companion"]'::jsonb),
  ('howtocook:breakfast/吐司果酱', 'en', 'Toast with Jam', 'Breakfast', 'This is an extremely simple and quick breakfast. Toast lightly crispy, then sandwich with sweet jam. Crispy outside, soft inside, easy to carry. A typical convenient Western-style light meal. Mainly provides carbohydrates and sugar, quickly replenishing morning energy. Almost zero skill required, perfect for busy beginners who are not good at cooking. From start to finish takes about 2 minutes, no need to turn on the stove, and almost no dishes to wash.', '[{"name":"Fresh toast","unit":"slice"},{"name":"Jam","note":"Enough to spread on one side of toast"}]'::jsonb, '["Put the toast into the toaster.","Set the browning level; it will pop up automatically when done.","After two minutes, the toast is done and pops up.","Take out one slice of toast, spread with jam, then cover with the other slice.","Wrap it in a napkin so you can eat it on the go or eat it before leaving."]'::jsonb, '["Breakfast","Quick","Western","Portable","Sweet"]'::jsonb),
  ('howtocook:breakfast/太阳蛋', 'en', 'Sunny Egg', 'Breakfast', 'Sunny Egg is a quick homemade breakfast made in the microwave. The texture is tender and smooth, with the egg white set and the yolk slightly runny – a typical quick dish. Eggs are rich in high-quality protein and various vitamins, easy to digest and absorb. The method is very simple and beginner-friendly. With a controllable microwave, it takes only 3 minutes; with a non-controllable one, just a few minutes of repeated heating.', '[{"name":"egg","unit":"piece"},{"name":"salt","unit":"g"},{"name":"oil","unit":"ml"}]'::jsonb, '["Prepare a small bowl, pour in the oil that was calculated in the previous step, sprinkle salt, and stir well. Tilt the bowl to coat the surface with oil.","Take out one egg and crack it into the small bowl.","Poke holes in the yolk surface. Poke 5 holes with a toothpick or 1 hole with a chopstick.","Place in the microwave and microwave on medium heat for 3 minutes.","Prepare a small bowl, pour in the oil that was calculated in the previous step, sprinkle salt, and stir well. Tilt the bowl to coat the surface with oil.","Take out one egg and crack it into the small bowl.","Poke holes in the yolk surface. Poke 5 holes with a toothpick or 1 hole with a chopstick.","Place in the microwave and microwave for 1 minute.","while (the sunny egg is not largely solidified) microwave for 30 seconds;"]'::jsonb, '["Breakfast","Quick","Microwave","Tender","Home-style"]'::jsonb),
  ('howtocook:breakfast/完美水煮蛋', 'en', 'Perfect Boiled Eggs', 'Breakfast', 'This is an egg made using a cyclic water boiling method developed by scientists. The yolk is dense and delicate, the white is evenly solidified, and the texture is layered. It retains more nutrients, with polyphenol content 23% higher than traditional boiling methods, and rich in protein. The difficulty is high, requiring precise temperature control and repeated transfers. Estimated cooking time is about 35 minutes.', '[{"name":"Fresh eggs (Grade AA recommended)","unit":"pieces"},{"name":"100°C boiling water","unit":"ml"},{"name":"30°C warm water","unit":"ml"},{"name":"Ice water","note":"as needed"}]'::jsonb, '["Prepare two pots of water: Pot A maintains 100°C boiling water, Pot B maintains 30°C warm water.","Use a slotted spoon to put the eggs into Pot A, start the timer.","Precisely every 2 minutes, transfer the eggs to the other pot of water.","Repeat the transfer operation a total of 16 times (total time 32 minutes).","After the last transfer, let sit in Pot B for 30 seconds.","Immediately place in ice water (0°C) to stop heating (hold for 30 seconds).","When peeling, start from the blunt end (air cell) and peel the membrane along the longitudinal axis."]'::jsonb, '["Breakfast","Light","Savory","Boiled","Nutritious"]'::jsonb),
  ('howtocook:breakfast/微波炉蒸蛋', 'en', 'Microwave Steamed Eggs', 'Breakfast', 'A quick steamed egg dish made in the microwave, tender and smooth like pudding. It''s a home-style fast dish. Rich in high-quality protein, easy to digest and absorb, suitable for breakfast or light meal. Very simple to make, even beginners can handle it. Takes about 10 minutes in total.', '[{"name":"Eggs","unit":"piece"},{"name":"Warm water or broth","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Sesame oil","note":"a few drops (for finishing)"}]'::jsonb, '["Beat the eggs, add warm water or broth, salt, and light soy sauce. Stir gently to avoid bubbles.","Strain the egg mixture into a heatproof bowl. If there are bubbles on the surface, poke them with a toothpick.","Cover with plastic wrap and poke 8-10 small holes, or use a microwave-safe lid (leave a gap).","Place in the microwave and heat:","700W: 1 min 30 sec → then heat for 20-30 sec more if needed until the surface just sets.","600W: about 1 min 40 sec to 2 min 10 sec.","800W: about 1 min 10 sec to 1 min 40 sec.","After heating, let it sit for 1 minute to allow residual heat to fully cook the center.","Drizzle with sesame oil and sprinkle chopped green onions before serving."]'::jsonb, '["Breakfast","Quick","Light","Silky"]'::jsonb),
  ('howtocook:breakfast/微波炉荷包蛋', 'en', 'Microwave Poached Egg', 'Breakfast', 'Microwave poached egg is a quick and easy home-cooked dish. The egg white is tender and smooth, the yolk is soft and sticky, with the fragrance of sesame oil. Eggs are rich in high-quality protein and lecithin. The method is extremely simple, even beginners can master it easily, taking only about 2 minutes from preparation to serving.', '[{"name":"Egg","unit":"piece"},{"name":"Drinking water","unit":"ml"},{"name":"Sesame oil","unit":"ml"},{"name":"Salt","unit":"g"}]'::jsonb, '["Crack the egg into a small bowl, use chopsticks to poke 2 holes in each egg yolk to avoid messing up the microwave when heating.","Then pour room temperature drinking water into the bowl.","Then add salt to the bowl.","Finally add sesame oil.","Place the bowl with ingredients into the microwave and heat on high for 80 seconds.","After the set time, use a cloth to pad your hands and take out the finished product."]'::jsonb, '["Breakfast","Quick Breakfast","Light","Microwave","Home-style","Side Dish"]'::jsonb),
  ('howtocook:breakfast/微波炉蛋糕', 'en', 'Microwave Cake', 'Breakfast', 'A quick microwave cake, soft and sweet, a family dessert that even beginners can easily make. Based on eggs and flour, with butter for energy and rich aroma, sugar for quick energy boost, adding nuts or fruits for fiber and vitamins. Only a few ingredients needed, finished in one minute on high microwave power, from prep to taste in as little as 2 minutes, about 20 minutes for a beginner.', '[{"name":"egg","unit":"piece"},{"name":"butter","note":"size of half an egg"},{"name":"flour","unit":"g"},{"name":"baking powder","unit":"g"},{"name":"white (or brown) sugar","unit":"g"},{"name":"salt","unit":"g"},{"name":"chocolate","note":"to taste"},{"name":"banana","note":"to taste"},{"name":"coffee powder","note":"to taste"},{"name":"cereal","note":"to taste"},{"name":"milk","note":"to taste"},{"name":"nuts","note":"to taste"},{"name":"cookie crumbs","note":"to taste"}]'::jsonb, '["Add the following ingredients, making sure not to exceed 3/4 of the container","Scoop butter the size of half an egg into the container, microwave for 15 seconds until melted","Mash/melt chocolate/banana into small pieces/paste","Crack an egg and beat it well","15g white (or brown) sugar (add more if you have a sweet tooth) (see note 4)","Add 1g salt (if later flavor ingredients contain salt, adjust accordingly)","Add 2.5g baking powder","Add 15g flour (gluten content doesn''t matter much)","Add any flavor ingredients you like! (Do not add dry ingredients like nuts and cookies now)","Mix until no dry powder remains, resembling thick yogurt","Add optional dry ingredients (excluding instant powders) on top","Praise yourself 🥰","Microwave on high for 1 minute (until fluffy cake form)","Take out the cup (it''s hot!!! 😱) and take a photo for social media, then eat"]'::jsonb, '["Breakfast","Sweet","Microwave","Quick","Dessert"]'::jsonb),
  ('howtocook:breakfast/意式香肠北非蛋', 'en', 'Italian Sausage Shakshuka', 'Breakfast', 'Italian Sausage Shakshuka is a rich and fragrant Mediterranean-style dish. Soft-boiled eggs sit in a sweet and sour tomato meat sauce, served with crusty bread for dipping. The main ingredients provide high-quality protein, while tomatoes, bell peppers, and onions bring vitamins and fiber. It''s easy to make, just pay attention to the heat when steaming the eggs. It takes about 30 minutes from start to finish.', '[{"name":"Italian pork sausage / Chorizo / Luncheon meat","unit":"g"},{"name":"Barilla Napoli pasta sauce","unit":"can"},{"name":"Egg","unit":"pieces"},{"name":"Bell pepper","unit":"pieces"},{"name":"Onion","unit":"pieces"},{"name":"Olive oil","unit":"ml"},{"name":"Parmesan cheese","note":"to taste"},{"name":"Fresh parsley","note":"to taste"},{"name":"Dried chili flakes","note":"to taste"},{"name":"Bread","note":"to taste"},{"name":"Water","unit":"ml"}]'::jsonb, '["Remove the casing from the Italian pork sausage and set aside; dice the onion; julienne the bell pepper.","Pour 10-15ml olive oil into a wide skillet and heat over medium heat.","Add the prepared sausage or luncheon meat and stir-fry until golden brown and crispy on the edges (if using raw sausage, break it up with a spoon as it cooks).","Add the diced onion and julienned bell pepper to the pan and cook with the meat, stirring for 4-5 minutes until the vegetables soften and the onion becomes translucent.","Pour in the Barilla Napoli pasta sauce and stir well. Reduce heat to medium-low and let it simmer gently for 2-3 minutes (if the sauce is too thick, add 15ml water).","Using the back of a spoon, make 3-4 small wells in the sauce.","Carefully crack an egg into each well.","Cover the skillet and let the egg whites steam until set. Wait 3-5 minutes. Note: Check frequently. When the egg whites are opaque and set but the yolks still jiggle when the pan is gently shaken (soft-boiled state), it''s done.","Turn off the heat. Sprinkle with grated Parmesan cheese, fresh parsley, or dried chili flakes to taste.","Serve the skillet directly at the table with crusty bread for dipping into the yolks and sauce."]'::jsonb, '["Breakfast","Savory","Sweet and Sour","Pan-steamed","Mediterranean","Quick"]'::jsonb),
  ('howtocook:breakfast/手抓饼', 'en', 'Hand-Grasp Pancake', 'Breakfast', 'Hand-Grasp Pancake is crispy outside and soft inside, with distinct layers. It is a beloved home-style pastry. The dough is made with the half-boiled water method, making it elastic and chewy. Paired with eggs and vegetables, it is nutritionally balanced. The recipe is beginner-friendly, taking only about 40 minutes from mixing to serving, perfect for busy mornings.', '[{"name":"all-purpose flour","unit":"g"},{"name":"boiling water","unit":"ml"},{"name":"cold water","unit":"ml"},{"name":"cooking oil","unit":"ml"},{"name":"salt","unit":"g"},{"name":"eggs","unit":"piece"},{"name":"lettuce","unit":"g"},{"name":"ham","unit":"g"},{"name":"cheese slices","unit":"slice"}]'::jsonb, '["Put flour in a bowl, add boiling water and stir into flocculent, then add cold water and knead into a smooth dough. Cover with a damp cloth and let rest for 20 minutes.","Divide the dough into portions of about 100 grams each, roll into balls, and roll out into thin sheets.","Evenly brush with cooking oil, sprinkle with salt, roll into a snail shape, and let rest for 10 minutes.","Roll the dough again into a thin pancake with even thickness.","Heat oil in a pan, fry over low heat until both sides are golden and bubbly.","On the cooked pancake, layer fried egg, lettuce, ham, cheese slice, and other toppings, then roll up."]'::jsonb, '["Breakfast","Savory","Crispy","Pan-fried","Home-style","Quick"]'::jsonb),
  ('howtocook:breakfast/桂圆红枣粥', 'en', 'Longan and Red Date Congee', 'Breakfast', 'A sweet, soft, and sticky traditional Chinese congee. Made by cooking glutinous rice with red dates and longan, it is naturally sweet and warms the body and stomach. It has nourishing effects such as enriching the blood, calming the mind, improving brain function, and tonifying the heart and spleen. The method is very friendly, even beginners can easily master it. It takes about 70 minutes from preparation to the aroma filling the house.', '[{"name":"Glutinous rice","unit":"g"},{"name":"Red dates","unit":"pieces"},{"name":"Longan","unit":"pieces"}]'::jsonb, '["Remove the longan pulp, rinse twice with water, and soak in a bowl for 10 minutes","Rinse the red dates twice with water and soak in a bowl for 10 minutes","Put the glutinous rice in a rice cooker, rinse twice, then add 2000 ml of water","Add the longan and red dates to the rice cooker","Turn on the rice cooker''s cooking mode; the congee will be ready in 1 hour"]'::jsonb, '["Breakfast","Sweet","Boiled","Nourishing","Quick","Home-style"]'::jsonb),
  ('howtocook:breakfast/水煮玉米', 'en', 'Boiled Corn', 'Breakfast', 'Boiled corn is a quick and easy home-cooked dish, with a sweet and soft texture. Fresh corn is cooked with the husk on to retain its original aroma, and adding salt and sugar enhances the flavor. It is rich in dietary fiber, vitamins, and carbohydrates, providing a sense of fullness. The method is extremely simple, even beginners can easily master it. From preparation to serving, it takes only about 15 minutes.', '[{"name":"Fresh corn","unit":"ear"},{"name":"Water","note":"Covers corn by half a finger"},{"name":"Salt","unit":"gram"},{"name":"Sugar","note":"to taste"}]'::jsonb, '["Peel off the outer husks of the fresh corn, leaving some husks on, and put into the pot.","Add water until it covers the corn by about half a finger''s depth, then add salt and sugar.","After the water boils, reduce to low heat, cover, and continue cooking for 15-20 minutes. It''s fine to cook the corn a bit longer.","After cooking, drain the water and let it cool before eating."]'::jsonb, '["Breakfast","Quick","Home-style","Sweet","Boiled"]'::jsonb),
  ('howtocook:breakfast/温泉蛋/温泉蛋', 'en', 'Onsen Tamago', 'Breakfast', 'Onsen Tamago originated in Japan. The egg white is semi-liquid and curd-like, while the yolk is warm and solid, giving a smooth and delicate texture—the exact opposite of a soft-boiled egg. Eggs are rich in high-quality protein, lecithin, and various vitamins, offering comprehensive nutrition. To make it, you need a thermometer to keep the water at 70°C. Although it requires attention to temperature, the steps are simple; after patiently waiting about half an hour, it''s done. Serve with kombu soy sauce and chopped scallions for a fresh and savory flavor. It''s an easy-to-make snack.', '[{"name":"Egg","unit":"piece"},{"name":"Kombu soy sauce","note":"a small amount for seasoning"},{"name":"Scallion","note":"a small amount for garnish"}]'::jsonb, '["Fill a pot with enough tap water so that the water level is about 3 cm above the eggs. Insert a thermometer into the water.","Turn on the heat (gas or induction) and gradually adjust the power or flame to keep the water temperature at 70°C.","Gently place the eggs into the pot. Do not stack them; they should all sit on the bottom with some space to move around.","Maintain the temperature for 25 minutes.","Prepare a bowl of ice water.","Remove the eggs and immediately transfer them to the ice water. Let them sit for 3 minutes.","Crack the egg into a small bowl. Done."]'::jsonb, '["Breakfast","Japanese","Light","Silky","Slow-cooked","Side dish"]'::jsonb),
  ('howtocook:breakfast/溏心蛋', 'en', 'Soft-Boiled Egg', 'Breakfast', 'This is a home-style egg dish that can be easily made using a regular electric pot. The yolk is in a runny, soft-boiled state, tender and smooth. Each egg provides about 6 grams of high-quality protein, especially suitable for fitness enthusiasts to supplement nutrition. The process is simple and clear; as long as you master the heating and resting times, beginners can quickly get the hang of it. The entire process takes only about 15 minutes.', '[{"name":"Eggs","unit":"pieces"},{"name":"Water","unit":"cm"}]'::jsonb, '["Place the eggs in the electric pot. Do not stack the eggs; they should all be on the bottom with space to shake.","Pour in cold water until the eggs are submerged by about 2 cm.","Open the lid, heat at maximum power until the water comes to a rolling boil (about 85-95°C, slightly bubbling, not fully boiling).","Turn off the heat, cover the lid, and let the eggs rest.","For a runny yolk in the center, let rest for 6 minutes.","For a fully cooked, crumbly yolk, let rest for 10 minutes.","Drain the water, rinse the eggs with cold water for about 1 minute, then peel and serve."]'::jsonb, '["Breakfast","Light","Boiled","Quick","Home-style","Tender and smooth"]'::jsonb),
  ('howtocook:breakfast/煎饺', 'en', 'Pan-Fried Dumplings', 'Breakfast', 'Pan-fried dumplings are a home-style pastry with a golden crispy bottom and tender, juicy filling, commonly found on northern Chinese tables. Made with frozen dumplings, they are rich in carbohydrates and protein, simple and quick. Estimated difficulty is two stars, very beginner-friendly, and takes about 15 minutes to serve.', '[{"name":"Dumplings (frozen)","unit":"piece"},{"name":"Cooking oil","unit":"ml"},{"name":"Water","note":"as needed"},{"name":"Black sesame seeds","note":"as needed"},{"name":"Chopped green onions","note":"as needed"}]'::jsonb, '["Take out a frying pan (non-stick is best)","Add 10ml - 15ml cooking oil","Turn on the heat, place dumplings (spread them out as evenly as possible, avoid stacking)","Immediately add water until it reaches halfway up the dumplings","Cover with a lid (the stove should be on high heat)","Wait for 8 - 10 minutes","When only about 2mm of water remains, reduce to medium heat and start pan-frying","When all water has evaporated, shake the pan to heat the dumplings evenly","Add black sesame seeds and chopped green onions, then cover and let steam for 10 seconds","After 1 - 2 minutes, take out one dumpling to check the bottom; if golden and crispy, remove immediately"]'::jsonb, '["Breakfast","Quick","Home-style","Pan-Fried","Crispy"]'::jsonb),
  ('howtocook:breakfast/蒸水蛋', 'en', 'Steamed Egg Custard', 'Breakfast', 'This is a home-cooked dish known for its smooth, pudding-like texture and elegant, delicious flavor. It is enjoyed across China, and in the north it is affectionately called ''egg cake''. Eggs are rich in high-quality protein and lecithin, making them a convenient choice for daily nutrition. The key is to master the egg-to-water ratio and slow steaming over low heat. It''s very beginner-friendly and takes about 15 minutes from preparation to serving.', '[{"name":"Fresh eggs","unit":"pieces"},{"name":"Warm water","unit":"ml"},{"name":"Salt","unit":"grams"}]'::jsonb, '["Crack eggs into a bowl and beat.","In another container, pour in warm water (20-30°C) 1.5 times the volume of the egg liquid (half an eggshell is 0.5 times water), and dissolve the salt in the water.","Pour the salted water into the egg mixture, stir evenly in one direction (clockwise or counterclockwise). Skim off any bubbles and discard, or strain for a smoother texture.","Cover the bowl with aluminum foil (or a plate), and place it into a pot with a lid that has about 3cm depth of water pre-added.","Bring to a boil over medium heat, then reduce to the lowest heat and steam for another 4 minutes."]'::jsonb, '["Breakfast","Light","Steamed","Quick","Homestyle"]'::jsonb),
  ('howtocook:breakfast/蒸花卷', 'en', 'Steamed Scallion Rolls', 'Breakfast', 'This is a traditional northern Chinese flour-based food, soft and delicious, with a light wheat aroma. Using frozen scallion rolls to steam, it can quickly provide carbohydrates and dietary fiber. The method is extremely simple, even beginners can master it easily, and the whole process only takes half an hour, making it an ideal quick breakfast.', '[{"name":"Frozen scallion rolls","unit":"piece"},{"name":"Water","unit":"ml"}]'::jsonb, '["Take out 5 scallion rolls from the packaging bag.","Arrange the rolls flat on a plate, try not to overlap.","Pour 400ml water into the pot, place the steaming rack inside, put the plate with rolls on the rack, and cover with lid.","Turn to high heat until water boils.","Reduce to medium heat and steam for 15 minutes.","Open the lid and feel the surface temperature of the rolls with your hand. If not hot enough, continue to cover and heat; otherwise, turn off the heat and remove.","Take out the plate and let it cool to 50°C before serving."]'::jsonb, '["Breakfast","Steamed","Quick","Home-style","Flour-based","Northern"]'::jsonb),
  ('howtocook:breakfast/燕麦鸡蛋饼', 'en', 'Oat Egg Pancake', 'Breakfast', 'A quick and nutritious breakfast. Soft, with the grain aroma of oats and the richness of eggs and milk. A simple home-style dish. Rich in protein, carbs, and fiber, it provides energy. Great for fitness enthusiasts and weekday mornings. Easy to make, beginner-friendly; from prep to plate takes about ten minutes.', '[{"name":"Egg","unit":"piece"},{"name":"Oats","unit":"g"},{"name":"Vegetables","unit":"g"},{"name":"Milk","unit":"ml"},{"name":"Butter","note":"to taste"}]'::jsonb, '["Mix milk and dry oats until thick and sticky.","Beat eggs until uniform in color.","Pour the egg mixture into the oat milk and stir until thick and even.","Add a layer of butter to a non-stick pan and spread evenly.","Pour in the batter and spread into a pancake shape.","Cook over low heat for 2-3 minutes. If adding vegetables, sprinkle chopped greens during cooking.","Flip and cook for another 2 minutes.","Serve with the remaining milk as breakfast."]'::jsonb, '["Breakfast","Quick","Pan-fried","Light","Fitness"]'::jsonb),
  ('howtocook:breakfast/牛奶燕麦', 'en', 'Milk Oatmeal', 'Breakfast', 'A quick, nutritious breakfast high in protein and fiber, combining the smoothness of milk, the graininess of oatmeal, and the crispy tenderness of a fried egg. Warm, soft, and easy to digest, it keeps you full. The process is simple and beginner-friendly, taking about three minutes. Pair with fruits or vegetables for a fresher taste.', '[{"name":"Milk","unit":"ml"},{"name":"Oatmeal","unit":"g"},{"name":"Egg","unit":"piece"},{"name":"Water","unit":"ml"},{"name":"Pepper salt","unit":"g"}]'::jsonb, '["Pour milk into a breakfast cup (cold is fine)","Prepare 200ml water. If it''s drinking water, add oatmeal directly; otherwise, bring to a boil then add oatmeal","Cook for 2 minutes after water boils, oatmeal is done","Scoop out the cooked oatmeal and add to the milk (try not to pour in the oatmeal water, as it affects texture)","Replace oatmeal with quick-cook oatmeal","Pour milk into the container with quick-cook oatmeal and stir","Place the mixture in a microwave","Microwave on medium power for 4 minutes","Heat a pan, add a thin layer of oil. When oil is hot, fry the egg, 20 seconds per side. Consider seasoning (3g pepper salt, optional)","Turn off the heat and plate"]'::jsonb, '["Breakfast","Quick","Nutritious","Light","High protein","High fiber"]'::jsonb),
  ('howtocook:breakfast/空气炸锅面包片', 'en', 'Air Fryer Bread Slices', 'Breakfast', 'Air fryer bread slices are an extremely simple and quick staple food, crispy on the outside and soft on the inside, with pure wheat flavor. They are especially suitable for weight loss periods. Rich in dietary fiber and plant protein, they provide a longer feeling of fullness. The method requires no skill; just put the bread slices in the air fryer. Very beginner-friendly, from preparation to completion takes only about five minutes.', '[{"name":"Bread slices","unit":"slice"}]'::jsonb, '["Take out two slices of bread (preferably whole grain bread slices)","Place the bread slices vertically into the air fryer","Bake at 200°C for 5 minutes","Remove and serve"]'::jsonb, '["Breakfast","Quick","Light","Weight Loss","Crispy","Filling"]'::jsonb),
  ('howtocook:breakfast/美式炒蛋', 'en', 'American-style Scrambled Eggs', 'Breakfast', 'This is a soft and fluffy American home-style egg dish. Adding milk makes the curds fine and the texture moist, rich in high-quality protein and calcium. The method is simple and beginner-friendly, taking about 20 minutes from prep to serving.', '[{"name":"Eggs","unit":"pieces"},{"name":"Whole milk/cream","unit":"grams"},{"name":"Butter","unit":"grams"},{"name":"Salt","unit":"grams"}]'::jsonb, '["Crack eggs into a large bowl, add salt and whisk until foamy. Let rest for 15 minutes.","Cut butter into small pieces and add to pan. Pour in egg mixture and cook over low heat, stirring constantly.","As soon as the butter melts, quickly stir and break the eggs into fine curds. Turn off the heat just before the eggs are fully set.","Add milk and stir for 15 seconds until the scrambled eggs are moist and creamy. Serve on a plate."]'::jsonb, '["Breakfast","Savory","Scrambled","Quick","Home-style"]'::jsonb),
  ('howtocook:breakfast/苏格兰蛋/苏格兰蛋', 'en', 'Scottish Eggs', 'Breakfast', 'This simplified Scottish egg has a crispy outer layer and a soft, runny yolk inside, combining the milky aroma of cheese and the smoky flavor of bacon. It is a creative snack derived from British cuisine. Eggs provide high-quality protein, cheese supplies calcium, and paired with the hand-grabbed flatbread crust, it meets the energy needs of a meal. The cooking process is not complicated, and beginners can easily master it. From preparation to serving, it takes only about 20 to 30 minutes.', '[{"name":"Eggs","unit":"grams"},{"name":"Hand-grabbed flatbread","unit":"piece"},{"name":"Cheese slices","unit":"slices"},{"name":"Bacon slices","unit":"slices"}]'::jsonb, '["Put eggs in cold water, bring to a boil, and cook for 3 minutes. Then remove.","Remove the eggs and place them in ice water for easier and more complete peeling.","Wrap each egg with a slice of cheese.","Wrap each egg with a slice of bacon.","Cut off both ends of the hand-grabbed flatbread and wrap the egg in a rectangular shape.","Heat oil to about 60% (when the surface shimmers, wisps of smoke appear, and bubbles form around a chopstick inserted). Fry until golden brown.","Air fry at 160°C for 15 minutes.","Cut open and serve."]'::jsonb, '["Breakfast","Savory","Crispy","Fried","British-style","Quick"]'::jsonb),
  ('howtocook:breakfast/茶叶蛋', 'en', 'Tea Eggs', 'Breakfast', 'This traditional snack is rich in tea aroma, savory and delicious, packed with high-quality protein, making it a quick and nutritious breakfast choice. The steps are clear, moderate difficulty. Beginners should pay attention to heat control and spice ratios. It takes about 30 minutes to complete, serving 2-3 people, perfect for a relaxed weekend preparation.', '[{"name":"Eggs","unit":"g"},{"name":"Star Anise","unit":"g"},{"name":"Bay Leaves","unit":"g"},{"name":"Cinnamon Stick","unit":"g"},{"name":"Fennel Seeds","unit":"g"},{"name":"Rock Sugar","unit":"g"},{"name":"Black Tea","unit":"g"},{"name":"Light Soy Sauce","unit":"g"},{"name":"Dark Soy Sauce","unit":"g"},{"name":"Salt","unit":"g"}]'::jsonb, '["Boil the eggs in cold water over high heat for about 8 minutes (adjust based on your stove).","Remove the eggs and rinse with cold water.","Tap the eggs against each other to crack the shells evenly.","Put the eggs back in the pot, add star anise, bay leaves, cinnamon, fennel seeds, rock sugar, black tea, light soy sauce, dark soy sauce, and salt.","Add water until the eggs are fully submerged.","Bring to a boil over high heat, then reduce to medium-low heat and simmer for 15 minutes."]'::jsonb, '["Breakfast","Tea Aroma","Marinated","Savory","Quick"]'::jsonb),
  ('howtocook:breakfast/蛋煎糍粑', 'en', 'Egg-fried Glutinous Rice Cake', 'Breakfast', 'A quick and easy snack, slightly crispy on the outside, soft and sticky inside, wrapped in egg aroma and sweetness. It''s a Southern home-style flavor. Glutinous rice cakes provide rich carbs, eggs add protein, high in calories but very filling. The process is extremely simple, even beginners can handle it, and it takes only about ten minutes.', '[{"name":"Glutinous rice cake","unit":"piece"},{"name":"Brown sugar or white sugar","unit":"g"},{"name":"Egg","unit":"piece"},{"name":"Cooking oil","unit":"ml"},{"name":"Salt","unit":"g"}]'::jsonb, '["Cut the glutinous rice cake into small rectangular pieces for easier frying.","Crack an egg into a bowl and beat it, add 2g of salt.","Dip each piece of glutinous rice cake into the beaten egg, coating both sides.","Pour 10ml of vegetable oil into the pan, place the coated pieces in, and fry over low heat until soft.","Slowly pour the remaining egg mixture over the surface of the rice cakes.","Flip the rice cakes with chopsticks or a spoon, fry until golden brown on both sides, then serve."]'::jsonb, '["Breakfast","Sweet","Pan-fry","Southern","Quick","Home-style"]'::jsonb),
  ('howtocook:breakfast/金枪鱼酱三明治', 'en', 'Tuna Salad Sandwich', 'Breakfast', 'This Western-style breakfast sandwich combines water-packed tuna with mayonnaise and Russian pickled cucumber juice, offering a savory, slightly tangy flavor and creamy texture. Paired with crispy toast, it''s especially filling. Rich in high-quality protein and omega-3s, it provides a quick energy boost. The preparation is simple: just mix the sauce and heat it with a sandwich press. Even beginners can make it in 5 minutes.', '[{"name":"Canned tuna in water","unit":"g"},{"name":"Square bread slices","unit":"slice"},{"name":"Mayonnaise","unit":"ml"},{"name":"Russian pickled cucumber juice","unit":"ml"},{"name":"Cheese slice (optional)","note":"to taste"},{"name":"Ham slice (optional)","note":"to taste"}]'::jsonb, '["Pour the tuna, mayonnaise, and Russian pickled cucumber juice into a bowl. Stir with a spoon, ensuring the tuna chunks are broken up and the mixture becomes a paste. Set aside.","Place 1 slice of bread on the sandwich press.","Spread the prepared tuna mixture onto the bread. Suggested amount: 10-15 ml.","Cover with another square bread slice, press the sandwich press, and turn it on.","When the sandwich press automatically stops heating, remove and serve."]'::jsonb, '["Breakfast","Savory and tangy","Quick","Western-style","Nutritious","Simple"]'::jsonb),
  ('howtocook:breakfast/韩国麻药鸡蛋', 'en', 'Korean Marinated Eggs', 'Breakfast', 'A sweet and spicy Korean soft-boiled egg side dish, with sauce coating the whites, smooth and tender, with a slight spicy aftertaste. Eggs provide high-quality protein and lecithin, nutritious and filling. The recipe is extremely simple, even beginners can easily master it. From boiling to marinating in the fridge, it takes about an hour and a half.', '[{"name":"Eggs","unit":"piece","note":""},{"name":"Korean soy sauce (or light soy sauce)","unit":"tablespoon","note":""},{"name":"Water","unit":"tablespoon","note":""},{"name":"Mirin","unit":"tablespoon","note":""},{"name":"Sugar","unit":"tablespoon","note":""},{"name":"Sesame oil","unit":"ml","note":""},{"name":"Green onion","unit":"g","note":""},{"name":"Chili pepper (bird''s eye chili or green/red pepper)","unit":"g","note":""}]'::jsonb, '["Bring a pot of water to a boil. Once boiling, add the eggs and cook for 7 minutes (for perfect soft-boiled eggs).","While the eggs are cooking, prepare the sauce: add 4 tablespoons soy sauce, 4 tablespoons water, 2 tablespoons mirin, and 2 tablespoons sugar to a small pot.","Heat the sauce until boiling, cook to evaporate the alcohol from the mirin, then turn off the heat and let it cool.","Add the sliced chili peppers into the cooled sauce.","Remove the boiled eggs, cool in ice water, then peel the shells.","Place the peeled eggs into the prepared sauce, drizzle 5ml sesame oil on top, and sprinkle with chopped green onions.","Refrigerate for 1-2 hours to allow the eggs to absorb the flavors."]'::jsonb, '["Breakfast","Korean","Soft-boiled egg","Sweet and spicy","Quick","Rice companion"]'::jsonb),
  ('howtocook:breakfast/鸡蛋三明治', 'en', 'Egg Sandwich', 'Breakfast', 'A simple and quick Western-style light meal. Soft bread slices hold creamy egg salad and savory bacon, tender yet crispy. Eggs provide high-quality protein, and bacon and butter quickly replenish energy. Very beginner-friendly, easy even for new cooks, taking only about 10 minutes.', '[{"name":"Egg","unit":"piece"},{"name":"Bread","unit":"slice"},{"name":"Bacon","unit":"slice"},{"name":"Butter","unit":"g"},{"name":"Mayonnaise","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Black pepper","unit":"g"}]'::jsonb, '["Trim the crusts off the bread slices and set aside.","Hard-boil the eggs, then mash them.","Mix the eggs, mayonnaise, salt, and black pepper.","Melt butter in a pan and fry the bacon until cooked.","Assemble the sandwich: place the egg mixture and bacon between two bread slices.","Cut the sandwich diagonally into triangles and serve."]'::jsonb, '["Breakfast","Quick","Western-style","Savory","Pan-fried"]'::jsonb),
  ('howtocook:condiment/油泼辣子/油泼辣子', 'en', 'Oil-Splashed Chili Oil', 'Sauces', 'A fragrant and spicy Shaanxi-style condiment, with glossy red oil, intertwined aromas of sesame and garlic. It tastes spicy but not harsh, with a lingering aftertaste. Chili peppers are rich in vitamin C and capsaicin, which can stimulate appetite and warm the body. The process requires controlling oil temperature, a bit challenging for beginners, but step by step can succeed. Takes about 10 minutes in total, a finishing touch for home-style cold dishes and noodles.', '[{"name":"Garlic","unit":"clove"},{"name":"Dried chili flakes","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Toasted white sesame seeds","unit":"g"},{"name":"Bird''s eye chili","unit":"piece"},{"name":"Peanut oil","unit":"ml"},{"name":"Five-spice powder","unit":"g"},{"name":"Caoguo","unit":"piece"},{"name":"Scallion","unit":"piece"},{"name":"Star anise"},{"name":"Sichuan peppercorns","unit":"piece"},{"name":"Bay leaf","unit":"piece"},{"name":"Baizhi","unit":"piece"},{"name":"Ginger slices","note":"to taste"},{"name":"Sugar","unit":"g"},{"name":"White vinegar","unit":"ml"},{"name":"MSG","note":"to taste"}]'::jsonb, '["Take out the garlic head, break off 2 small garlic cloves, and peel them.","Take out the cutting board and chop the small garlic cloves and bird''s eye chilies.","Take out a bowl and pour in peanut oil.","Once the oil is hot, add the other aromatics and scallion. When the aromatics turn brown, remove and discard.","Take out an iron wok, pour the oil from the bowl into the wok, and heat for 2 minutes (the rapeseed oil should heat until smoking).","Now the bowl is empty.","Add dried chili flakes, toasted white sesame seeds, chopped garlic, bird''s eye chilies, salt, five-spice powder, and caoguo to the empty bowl as the ''seasoning''.","Turn off the heat and let the oil cool to 210°C.","Pour the hot oil from the wok into the bowl and stir with a spoon. (For extra heat, you can also add the same ''seasoning'' to another bowl at 165°C and mix at the end.)","After pouring the oil and stirring briefly, add white vinegar; it will re-boil. Continue stirring. The vinegar enhances the aroma.","Let the chili oil cool until warm, then add sugar and MSG. The sugar softens the spiciness, making it less harsh."]'::jsonb, '["Condiment","Spicy","Shaanxi Style","Cold Dish","Quick","Seasoning"]'::jsonb),
  ('howtocook:condiment/油酥', 'en', 'Oil Pastry', 'Sauces', 'This is a Chinese pastry ingredient, often used for making flatbreads. It gives the final product distinct layers, crispy outside and soft inside. It mainly provides carbohydrates and fats for energy. The method is very simple and beginner-friendly, expected to take only 3 minutes to prepare.', '[{"name":"flour","unit":"","note":"as needed"},{"name":"oil","unit":"ml","note":""},{"name":"salt","unit":"","note":"as needed"}]'::jsonb, '["Put flour in a small bowl, add salt.","Add hot oil at 200°C.","Stir with chopsticks until it becomes a smooth paste with no lumps."]'::jsonb, '["Sauce","Crispy","Pastry","Flatbread","Home-style","Quick"]'::jsonb),
  ('howtocook:condiment/炸串酱料', 'en', 'Fried Skewer Sauce', 'Sauces', 'This versatile fried skewer sauce is spicy, rich, savory, and slightly salty, with a street-food style. It mainly provides fat and spices that bring aromatic compounds, stimulating appetite. Very easy to make, no pressure for beginners, only about 10 minutes total.', '[{"name":"Dried chili powder (both fine and coarse)","unit":"grams"},{"name":"Cumin powder","unit":"grams"},{"name":"Pepper powder","unit":"grams"},{"name":"Five-spice powder","unit":"grams"},{"name":"Sichuan pepper powder","unit":"grams"},{"name":"Thirteen-spice powder","unit":"grams"},{"name":"Mala seasoning","unit":"grams"},{"name":"White sesame seeds","unit":"grams"},{"name":"Salt","unit":"grams"},{"name":"Chicken bouillon","unit":"grams"},{"name":"Oil","unit":"","note":"enough to submerge all ingredients"},{"name":"Sesame oil","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Sichuan pepper oil","unit":"ml"},{"name":"Oyster sauce","unit":"ml"}]'::jsonb, '["Mix all ingredients in a container.","Heat oil in a pan, enough to submerge all ingredients in the container.","Pour hot oil in three batches, 1/3 each time, while stirring.","Finally add 10ml sesame oil, 10ml light soy sauce, 10ml Sichuan pepper oil, 10ml oyster sauce."]'::jsonb, '["Sauce","Spicy","Street food style","Quick","Savory","Versatile"]'::jsonb),
  ('howtocook:condiment/简易版炒糖色', 'en', 'Simple Caramel Color', 'Sauces', 'Caramel color is a key technique for coloring red-braised dishes in Chinese cuisine. When the heat is right, it imparts a glossy red sheen and a unique caramelized aroma. The main ingredient is sugar, which provides energy, but more importantly, it harmonizes the color and flavor of the dish. This simple version of caramel color requires some heat control; beginners may need practice to avoid bitterness or excessive sweetness. The entire process takes about ten minutes.', '[{"name":"Rock sugar / White sugar / Caster sugar (choose any one)","unit":"g"},{"name":"Oil","unit":"ml"},{"name":"Boiling water","unit":"ml"}]'::jsonb, '["Turn on the heat and pour 100ml of boiling water into the pot.","Then pour 100ml of oil into the pot, with as short an interval as possible from the first step. At this point, the heat can be high or medium; if in a hurry, high heat is fine.","Add rock sugar (if the rock sugar is too clumped, break it up in advance, the less clumped the better).","Adjust the heat to medium.","Start stirring.","Keep stirring continuously until it turns brownish-black, then reduce to low heat.","It will thin out, turn tea-red, then sauce-red, and small bubbles will appear. Prepare to perform operation 1 or operation 2 below.","The small bubbles will gradually disappear, then large bubbles will appear. When the large bubbles appear, the caramel color is ready.","At this point, you must quickly proceed to the next step (regardless of which operation, be prepared in advance and act fast! Otherwise, the heat will be too high and the caramel will become bitter). Choose based on the dish style and personal taste.","Operation 1: Directly add 400ml of boiling water to cool it down.","Operation 2 (advanced seasoning version): When the sugar liquid turns jujube-red and dense small bubbles appear, quickly add pre-prepared aromatics such as scallion, ginger, garlic, and Sichuan peppercorns, and stir-fry. After the aroma releases (within about 5-10 seconds), immediately pour in 400ml of boiling water to stop the reaction. (Note: If the subsequent recipe requires stir-frying meat for coloring, add the meat and stir-fry first before adding water.)"]'::jsonb, '["Sauce","Salty-sweet","Caramelized","Stir-fry","Home-style","Red-braise coloring"]'::jsonb),
  ('howtocook:condiment/糖醋汁', 'en', 'Sweet and Sour Sauce', 'Sauces', 'This sauce is sweet and sour, and is the classic flavor base for Chinese sweet and sour dishes. It''s simple to mix with easy-to-remember proportions, even beginners can handle it. From prep to finish, it takes about 10 minutes. The sugar provides energy, and the vinegar aroma helps stimulate appetite and cut grease, instantly adding flavor to home-style dishes.', '[{"name":"Water","unit":"ml"},{"name":"Light Soy Sauce","unit":"ml"},{"name":"White Sugar","unit":"g"},{"name":"White Vinegar/Rice Vinegar","unit":"ml"},{"name":"Cooking Wine","unit":"ml"}]'::jsonb, '["Mix all seasonings in a small bowl according to the proportions.","After handling according to the specific dish, pour the prepared sweet and sour sauce into the pan.","Cook for 5-10 minutes depending on the dish.","Reduce the sauce over high heat to thicken, enhance aroma, and add gloss."]'::jsonb, '["Sauce","Sweet and Sour","Seasoning","Chinese","Home-style","Quick"]'::jsonb),
  ('howtocook:condiment/草莓酱/草莓酱', 'en', 'Strawberry Jam', 'Sauces', 'This is a sweet and sour, fruity homemade jam, perfect for spreading on bread. Strawberries are rich in vitamin C, but the sugar content is high during cooking - adjust to taste. The method is very simple, even beginners can easily make it. It takes about two hours from preparation to completion.', '[{"name":"Strawberries","unit":"g"},{"name":"White sugar","unit":"g"}]'::jsonb, '["Wash strawberries and remove stems","Chop the strawberries and place in a suitable bowl","Pour white sugar into the bowl and mix well with the strawberries","Cover the bowl with plastic wrap and let sit for 1 hour","Pour the strawberry-sugar mixture into a non-stick pan and bring to a boil over high heat","After boiling, reduce heat to low and stir continuously until the jam thickens, then turn off the heat","Let the strawberry jam cool, then transfer to a prepared sealed jar"]'::jsonb, '["Jam","Sweet & Sour","Home-style","Homemade","Quick"]'::jsonb),
  ('howtocook:condiment/葱油', 'en', 'Scallion Oil', 'Sauces', 'Scallion oil is a home-style seasoning oil that adds fragrance and umami. It carries a rich scallion aroma and the complex savory flavor of dried shrimp. Suitable for mixing into fillings, cold dishes, or as a finishing oil for hot dishes. It mainly provides energy from oil, and the scallion, ginger, and other aromatics contain plant active compounds that help remove fishy smells and stimulate appetite. Simple to make, beginner-friendly, generally about 30 minutes including prep and cooking.', '[{"name":"Oil","unit":"g"},{"name":"Scallion (green onion or spring onion)","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Onion","unit":"g"},{"name":"Cooking wine","unit":"ml"},{"name":"Dried shrimp (optional)","unit":"g"},{"name":"Cilantro (optional)","unit":"g","note":"to taste"}]'::jsonb, '["Soak dried shrimp in 50°C warm water, add 10ml cooking wine to remove fishy smell, soak for 10 minutes then remove and drain.","Wash scallions and cilantro, cut into 5cm long sections, wipe dry surface moisture.","Cut onion into strips, boil in hot water for 5 minutes, remove and drain.","Peel ginger, slice.","Pour all oil into pot, add all pre-treated ingredients, fry over medium-low heat for 20 minutes."]'::jsonb, '["Sauce","Scallion aroma","Savory","Seasoning oil","Filling mixing","Noodle mixing","Hot drizzle"]'::jsonb),
  ('howtocook:condiment/蒜香酱油', 'en', 'Garlic Soy Sauce', 'Sauces', 'Garlic Soy Sauce is a home-style dipping sauce with rich garlic flavor, savory and oily. It is commonly used to enhance the taste of dishes like white cut chicken and dumplings. Garlic and sesame seeds have antibacterial effects and provide unsaturated fatty acids respectively. The method is extremely simple, very beginner-friendly, and takes only about 5 minutes in total.', '[{"name":"garlic","unit":"clove"},{"name":"white sesame seeds","unit":"g"},{"name":"peanut oil","unit":"ml"},{"name":"soy sauce","unit":"ml"}]'::jsonb, '["Crush the garlic","Add soy sauce to the dipping dish","Heat the wok, add peanut oil. When the oil is hot, add the crushed garlic and fry for half a minute.","After half a minute, turn off the heat, pour the hot oil into the dipping dish, and stir with chopsticks."]'::jsonb, '["Sauce","Garlic","Savory","Fried","Home-style","Dipping"]'::jsonb),
  ('howtocook:condiment/蔗糖糖浆/蔗糖糖浆', 'en', 'Sucrose Syrup', 'Sauces', 'Homemade beverage syrup, mix white sugar and water in a 1:1 ratio to dissolve, easy to control sweetness of cold drinks, a basic recipe for mixing drinks. Rich in carbohydrates, quickly replenishes energy. Extremely simple, very beginner-friendly, only takes a few minutes, can be refrigerated for a week.', '[{"name":"White sugar","unit":"g"},{"name":"Water","unit":"g"}]'::jsonb, '["Mix the weighed white sugar and drinking water in a container","Cover the container and refrigerate"]'::jsonb, '["sauce","sweet","mixology base","quick","refrigerated"]'::jsonb),
  ('howtocook:dessert/反沙芋头/反沙芋头', 'en', 'Sugar-Coated Taro', 'Desserts', 'Sugar-coated taro is a traditional Chaoshan snack with a crispy exterior and soft, sweet interior, often enjoyed as an afternoon tea treat. Lipu taro is rich in dietary fiber, potassium, and various vitamins, providing long-lasting satiety. It''s not difficult to make but requires mastering the sugar syrup temperature; suitable for beginners with some basic skills, taking about 20 minutes in total.', '[{"name":"Lipu taro","unit":"g"},{"name":"White sugar or rock sugar","unit":"g"},{"name":"Water","unit":"g"},{"name":"Scallion","note":"to taste"}]'::jsonb, '["Cut the taro into thick strips (slightly larger so they don''t break during stir-frying).","Add enough oil to submerge the taro. Heat the oil until it''s hot (insert chopsticks and bubbles form).","Add the taro strips to the oil and fry until they float, usually when they turn slightly golden and a chopstick can easily pierce through.","Save the oil used for frying; it can be reused for stir-frying other dishes.","Next is the crucial step: combine sugar (30g) and water (15g) in a 2:1 ratio. Heat until it bubbles without changing color.","Add the chopped scallions and taro, then turn off the heat and stir-fry. As the temperature drops, the sugar will crystallize into a frosted coating.","Plate and serve!"]'::jsonb, '["Dessert","Chaoshan","Deep-fried","Sweet and fragrant","Afternoon tea","Snack"]'::jsonb),
  ('howtocook:dessert/咖啡椰奶冻/咖啡椰奶冻', 'en', 'Coffee Coconut Milk Pudding', 'Desserts', 'This dessert combines the richness of coffee with the sweetness of coconut milk, with a texture as smooth and tender as pudding, rich in layers. Whipping cream and coconut juice provide high-quality fat and plant nutrition, bringing satisfaction. The method is very friendly: just mix and heat, no complicated techniques needed, beginners can succeed at first try. Excluding refrigeration, actual operation takes about 1 hour, plus refrigeration to set, about 4 hours in total to enjoy.', '[{"name":"Whipping cream","unit":"ml"},{"name":"Coconut juice","unit":"ml"},{"name":"Espresso","unit":"ml"},{"name":"Coconut water","unit":"ml"},{"name":"Gelatin","unit":"g"},{"name":"Sugar","note":"to taste"},{"name":"Blueberries","note":"to taste"},{"name":"Coffee powder","note":"to taste"}]'::jsonb, '["Mix the measured whipping cream, coconut juice, espresso, and coconut water together and set aside.","Heat the above liquid for 1 minute to reach a temperature of 50-60°C.","(Optional) Add extra sugar if you have a sweet tooth.","Add gelatin, stir until dissolved, and cook for 1 minute.","(Optional) Strain (this step makes the coconut milk pudding smoother in texture).","Pour into molds.","(Optional) Remove surface bubbles. This step improves the texture and appearance of the coconut milk pudding.","Place in the refrigerator and wait for 3 hours."]'::jsonb, '["Dessert","Coffee aroma","Coconut aroma","No-bake","Pudding texture","Afternoon tea"]'::jsonb),
  ('howtocook:dessert/奥利奥冰淇淋/奥利奥冰淇淋', 'en', 'Oreo Ice Cream', 'Desserts', 'The Oreo ice cream has a delicate texture, blending the milky flavor with the crunchy sweetness of Oreos. The pure animal cream makes it light and not greasy. It mainly provides energy, contains fat and carbohydrates, and is suitable as a refreshing small dessert. The preparation is relatively simple; you only need to handle the cookie filling and whip the cream. Even beginners with a bit of patience can do it. The entire preparation takes about half an hour, then freeze for at least 4 hours before enjoying.', '[{"name":"Heavy cream (recommended brand: Anchor animal cream)","unit":"ml"},{"name":"Original Oreo cookies","unit":"pieces"},{"name":"White granulated sugar","unit":"grams"}]'::jsonb, '["Twist open the Oreos and remove the cream filling, set aside.","Use chopsticks to crush the Oreo cookies. Half of the cookies should become powder, and the other half should be in pieces less than 0.5 cm. Set aside. (You can search for ''Oreo cookie crumbs'' on Taobao to save time and effort ^-^)","Pour all the cream into a deep container and add the prepared sugar.","Start whipping with an electric hand mixer on high speed until when you lift the mixer, the cream holds a peak (0.5 cm to 1 cm) and doesn''t drip completely like liquid (some dripping is normal).","After whipping, add the crushed Oreos into the cream and mix well until you see Oreos at the bottom.","Optional: Pour the mixture into ice cream molds.","Place in the freezer (-18°C) for at least 4 hours before removing."]'::jsonb, '["Dessert","Milky","Sweet","Frozen","Quick","Afternoon Tea"]'::jsonb),
  ('howtocook:dessert/戚风蛋糕/戚风蛋糕', 'en', 'Chiffon Cake', 'Desserts', 'This beginner-friendly dessert has a delicate, soft texture and a cloud-like lightness, making it a classic in Western baking. The main ingredients, eggs and milk, provide high-quality protein and calcium. The process requires careful whipping, folding, and baking, which can be challenging, but with patience and following the steps, even a novice can succeed. From prep to finish, it typically takes 1.5 to 2 hours.', '[{"name":"Egg","unit":"piece"},{"name":"White sugar","unit":"gram"},{"name":"Milk (or water)","unit":"gram"},{"name":"Cooking oil (or butter)","unit":"gram"},{"name":"Cake flour","unit":"gram"},{"name":"Lemon juice or white vinegar (optional)","note":"to taste"}]'::jsonb, '["Take fresh eggs out of the refrigerator.","Prepare two bowls and dry them; one for egg whites, one for yolks.","The bowl for egg whites can have a few drops of water, but no oil; the bowl for yolks must be dry.","Crack the eggs, using your hands or an egg separator, to separate whites and yolks into the two bowls.","During separation, the yolks must not break, and no yolk should get into the whites, otherwise it will severely affect whipping. (The white chalaza can go into the whites; it won''t affect.)","(Note: If not using a stand mixer, the bowl for egg whites is also the whipping bowl. To avoid overflow, after adding all the whites, the volume should not exceed 1/8 of the bowl.)","Prepare a new empty bowl. Add all the oil and all the milk from the recipe.","Whisk quickly by hand until the oil and milk are fully combined, forming a milky white emulsion (emulsification complete).","Sift all the cake flour from the recipe into the emulsion. Use a spatula to stir in a zigzag pattern until no visible dry flour remains (the batter may be a bit lumpy; that''s normal).","Add all the separated egg yolks to the bowl. Continue stirring in a zigzag pattern with the spatula.","The batter will become very smooth and silky, and gluten development is minimized. Set aside.","Prepare the remaining 3/4 of the sugar. Divide into three portions, each 1/4 of the total.","Add lemon juice or white vinegar to the egg whites (optional).","With the mixer on medium speed, whip the egg whites until large bubbles form. Add the first portion of sugar.","Increase to high speed, whip until the bubbles are finer. Add the second portion of sugar.","Continue on high speed until soft peaks form. Add the third portion of sugar.","Reduce to medium-low speed and whip until stiff peaks form.","The egg whites are now ready.","(For reference on the egg white state, see the picture in the attached link.)","(Keep the beaters close to the bottom of the bowl to prevent the top from being whipped while the bottom is still liquid.)","Give the yolk batter a few quick stirs.","Using a spatula, take 1/3 of the meringue and add it to the yolk batter.","Use the folding technique to avoid deflating the meringue.","The folding technique is:","With your right hand, insert the spatula from the center of the bowl to the bottom.","Scrape towards the 8 o''clock position until you hit the side of the bowl, then lift the spatula up and bring it back to the center, dropping the batter back.","With your left hand, turn the bowl from the 9 o''clock position to the 7 o''clock position (a 60-degree rotation) to complete one cycle.","The speed is about two strokes per second.","This method is from ''Chef Koyama''s Cake Classroom''. In simple terms, it''s like stir-frying.","Pour the mixture of 1/3 meringue and yolk batter into the remaining 2/3 meringue. Continue folding until evenly combined.","Pour the batter into the pan. Tap the pan a few times to release large air bubbles.","Total baking time: 30–35 minutes for a 6-inch cake, 50 minutes for an 8-inch cake. Adjust based on your oven, generally within ±5 minutes. (Watch the cake in the last few minutes.)","Preheat the oven with top heating at 150°C and bottom heating at 160°C; it takes about 10 minutes to reach the temperature.","Once preheated, place the pan on the lower rack.","Choose variable temperature baking, divided into two stages.","First stage: set top heating to 150°C, bottom heating to 160°C.","Bake for the first 3/5 of the total time.","Second stage: set top heating to 160°C, bottom heating to 170°C.","Bake for the remaining 2/5 of the total time. Simply adjust the oven temperature to switch.","When done, remove from the oven.","Be careful, it may be hot. Use a towel for protection.","Preheat the air fryer to 130°C for 5 minutes.","Place the pan with batter into the air fryer. Immediately cover the pan with aluminum foil (shiny side up, matte side touching food), and seal the edges to prevent it from blowing off.","First stage: set to 130°C and bake for 35 minutes.","Second stage for browning: open the air fryer, remove the foil. Increase temperature to 150°C and bake for another 10–15 minutes.","Check for doneness: the cake should be puffed and golden brown on top. Insert a toothpick into the center; if it comes out clean, it''s done.","After removing, the process of tapping out hot air and inverting to cool is exactly the same as for the oven version.","(Optional) Drop the pan from a height to release hot air.","Invert the pan and let it cool for 10 minutes.","Do not remove the cake from the pan while it''s still warm, as it may be damaged.","Be careful, it may be hot. Use a towel for protection.","Unmold and serve."]'::jsonb, '["Dessert","Sweet","Baking","Pastry","Afternoon tea","Classic"]'::jsonb),
  ('howtocook:dessert/提拉米苏/提拉米苏', 'en', 'Tiramisu', 'Desserts', 'This classic Italian dessert requires no oven. The mascarpone cream is smooth and light, and the ladyfingers soaked in coffee are rich and soft. It is an entry-level dessert. Rich in protein and calcium, but high in sugar and calories, best enjoyed occasionally. Simple to make, very beginner-friendly. It takes about half an hour of hands-on time, then refrigerate for four hours to set.', '[{"name":"Mascarpone cheese","unit":"g"},{"name":"Ladyfingers","unit":"pack"},{"name":"Cooled espresso","unit":"ml"},{"name":"Pasteurized eggs","unit":"piece"},{"name":"White sugar","unit":"g"},{"name":"Cocoa powder","unit":"g"},{"name":"Rum","unit":"ml"}]'::jsonb, '["Separate egg yolks from whites","Add 10g sugar to the egg whites and whip until soft peaks form","Gradually add 40g sugar to the egg yolks in three additions, stirring until smooth","Gradually add mascarpone cheese to the egg yolks in three additions, stirring until smooth","Finally add rum to the egg yolk mixture and stir to combine","Fold the whipped egg whites into the egg yolk-mascarpone mixture in three additions","Quickly dip both sides of each ladyfinger in coffee and arrange in a single layer in a dish","Alternate layers of mascarpone cream and ladyfingers (adjust according to your dish and preference)","Refrigerate for at least 4 hours (or less if you''re impatient)","Remove from fridge, dust with cocoa powder, and serve"]'::jsonb, '["Dessert","No-bake","Italian","Sweet","Tea time","Party"]'::jsonb),
  ('howtocook:dessert/无厨师机蜂蜜面包/无厨师机蜂蜜面包', 'en', 'No-Mixer Honey Bread', 'Desserts', 'This is a home-style small honey bread that requires no stand mixer. It''s soft and sweet, with a slightly crispy bottom. The surface is brushed with honey water and sprinkled with sesame seeds, giving off a rustic sweet fragrance. Main ingredients are bread flour, milk, eggs, and butter, providing plenty of carbs, protein, and calcium. It''s reassuring as breakfast or a snack. The method is simple, all hand-kneaded, with flexible fermentation time. You can even refrigerate the dough overnight and bake the next day, very beginner-friendly. Total time about 3 hours, most of which is waiting for the dough to rise; actual hands-on work is not laborious.', '[{"name":"bread flour","unit":"g"},{"name":"milk","unit":"g"},{"name":"yeast","unit":"g"},{"name":"egg","unit":"piece"},{"name":"white sugar","unit":"g"},{"name":"salt","unit":"g"},{"name":"butter","unit":"g"},{"name":"honey","unit":"g"},{"name":"water","unit":"g"},{"name":"peanut oil","note":"as needed"},{"name":"sesame seeds","note":"as needed"}]'::jsonb, '["Make the dough: Mix together the flour, milk (recommend heating to 40°C, I use microwave 15-20s), yeast, egg, sugar, and salt.","Mix the dough until the ingredients are well combined into a ball.","Add the butter and mix.","Continue mixing and hand-knead until evenly combined.","Start proofing: cover the bowl with plastic wrap, let it sit at room temperature (10-20°C) for 1-2 hours. A little longer won''t hurt the result.","When the dough has visibly doubled in size, it''s time to divide the dough. At this point, the dough should no longer be very sticky.","Divide the dough: ideally each piece is 60g (for looks), but you can adjust the size to your liking.","Roll each small piece with a rolling pin into a tongue shape, then roll it up. Rest again for 10 minutes.","Again roll out into a tongue shape with rolling pin and roll up. Cut in half from the middle (one becomes two).","Again roll out into a tongue shape and roll up, then cut in half (two become four). (You can repeat the rolling and cutting a few times depending on your time, just aim to control the size of each piece.)","Line a baking pan with parchment paper and pour in peanut oil. Dip the bottom of each rolled piece in water and then in flour, then place in the pan.","Proof again (cover with plastic wrap). At this step, you can put it in the fridge and bake the next day.","Brush with egg wash.","Bake at 180°C (355°F) for 18-20 minutes.","After taking out of the oven, brush with honey water and sprinkle with sesame seeds."]'::jsonb, '["Dessert","Sweet","Baking","Breakfast","Hand-kneaded","Beginner-friendly"]'::jsonb),
  ('howtocook:dessert/炸鲜奶/炸鲜奶', 'en', 'Fried Milk Custard', 'Desserts', 'Fried Milk Custard is a classic dessert with a crispy exterior and creamy interior, sweet and delicious. It''s a home-style snack. Rich in protein and calcium, with balanced nutrition. Medium difficulty, beginners can try. Preparation time about 20 minutes, but requires 1 hour refrigeration to set.', '[{"name":"Milk","unit":"克"},{"name":"Cornstarch","unit":"克"},{"name":"Breadcrumbs","unit":"克"},{"name":"Egg","unit":"个"},{"name":"White sugar","unit":"克"}]'::jsonb, '["Pour the milk into a bowl.","Add cornstarch and sugar, stir until well combined.","Brush the mold with cooking oil.","Pour the milk mixture into the pot, bring to a boil over medium heat.","After boiling, reduce to low heat, stirring constantly.","When the milk thickens, remove from heat and pour into the mold.","Place the mold in the refrigerator to cool for 1 hour.","Take it out, cut into evenly sized strips, then place in a bowl.","Pour half of the breadcrumbs into the bowl, coat the milk strips, then remove and set aside.","In a new bowl, beat the eggs and mix well, set aside.","Coat the milk strips with egg wash and the remaining breadcrumbs.","Pour enough oil into the pot to cover the strips, then fry them.","When the strips turn golden, turn off the heat and plate."]'::jsonb, '["Dessert","Sweet","Fried","Crispy outside and tender inside","Home-style dessert","Afternoon tea"]'::jsonb),
  ('howtocook:dessert/烤箱版巴斯克芝士蛋糕/烤箱版巴斯克芝士蛋糕', 'en', 'Oven-Baked Basque Cheesecake', 'Desserts', 'Basque cheesecake is a dessert with a rich, dense texture, caramelized on the outside and moist inside. It''s a classic from the Basque region of Spain. Main ingredients are cream cheese and eggs, rich in high-quality protein and calcium. The process is very simple, even beginners can easily handle it. From prep to out of the oven takes about 30 minutes, but it''s recommended to chill overnight before serving, total time about 8+ hours.', '[{"name":"Cream cheese","unit":"g"},{"name":"Granulated sugar","unit":"g"},{"name":"Eggs","unit":"pieces"},{"name":"Egg yolk","unit":"pieces"},{"name":"Heavy cream","unit":"g"},{"name":"Cake flour","unit":"g"}]'::jsonb, '["Soften cream cheese in microwave: 10s + 10s.","Add sugar to cream cheese and beat with mixer until smooth.","Add 2 whole eggs and 1 egg yolk, mix well.","Add heavy cream, mix well.","Add cake flour, mix well.","Bake at 220°C (425°F) for 20-25 minutes (I usually do 20 or 22 minutes).","Let cool, then refrigerate, preferably overnight."]'::jsonb, '["Dessert","Sweet","Baked","Western-style","Quick","Afternoon tea"]'::jsonb),
  ('howtocook:dessert/烤蛋挞/烤蛋挞', 'en', 'Baked Egg Tarts', 'Desserts', 'Baked egg tarts are a classic Chinese dessert with a crispy crust and silky smooth filling, rich in milky flavor. They are rich in protein, calcium, and various vitamins, providing ample energy. The preparation is very simple, even beginners can easily master it, and the semi-finished product can be frozen for later use. From preparation to serving, it takes about 1 hour.', '[{"name":"Egg tart shells","unit":"pieces"},{"name":"Eggs","unit":"pieces"},{"name":"Milk","unit":"ml"},{"name":"Whipping cream","unit":"ml"},{"name":"White sugar","unit":"g"}]'::jsonb, '["Place a bowl on a kitchen scale and weigh 450g of whipping cream (the density of whipping cream is taken as 1 here).","Add 80g of white sugar (medium sweetness, adjust to taste; recommended range 60-100g).","Add 200g of milk (the density of milk is taken as 1 here).","Take 8 egg yolks and add them; the egg whites can be saved for other uses.","Stir all ingredients evenly until the white sugar is completely dissolved.","Strain the mixed ingredients through a sieve to remove egg membranes, eggshell bits, undissolved sugar, and lumps of whipping cream.","Now preheat the oven to 220°C (about 10 minutes) and remember to take out the baking tray.","Place the tart shells evenly on the baking tray with a 0.5 cm gap between them.","Pour the strained mixture into the tart shells, filling until the liquid is 0.5 cm below the rim; do not overfill.","At this point, the semi-finished egg tarts are complete. They can be directly frozen for at least 12 hours for storage.","Place the semi-finished egg tarts in the oven and bake at 200°C for 25 minutes.","Once baked, they are ready to serve."]'::jsonb, '["Dessert","Milky","Baking","Beginner","Home-style","Freezer-friendly","Afternoon tea"]'::jsonb),
  ('howtocook:dessert/玛格丽特饼干/玛格丽特饼干', 'en', 'Margaret Cookies', 'Desserts', 'Margaret Cookies are crumbly and rich in butter aroma, a classic Western-style small dessert. They are mainly made from egg yolks, butter, and flour, rich in carbohydrates and fats, providing quick energy. The difficulty is moderate, taking about 45 minutes from preparation to finish, and even beginners can easily make them.', '[{"name":"hard-boiled egg yolk","unit":"piece"},{"name":"butter","unit":"g"},{"name":"granulated sugar","unit":"g"},{"name":"salt","unit":"g"},{"name":"cake flour","unit":"g"},{"name":"cornstarch","unit":"g"}]'::jsonb, '["Melt butter over hot water; mash the egg yolks and set aside.","Add sugar, salt, and mashed egg yolks to the melted butter; mix well.","Add cake flour and cornstarch; knead into a dough.","Divide the dough evenly into small pieces about 8 grams each, and roll into balls.","Use your thumb to lightly press each ball to create cracks.","Preheat oven to 150°C, place the balls in the oven, and bake for 20 minutes.","Let cool slightly before serving."]'::jsonb, '["Dessert","Crumbly","Buttery","Baking","Western-style pastry","Afternoon tea"]'::jsonb),
  ('howtocook:dessert/红柚蛋糕/红柚蛋糕', 'en', 'Red Pomelo Cake', 'Desserts', 'Red Pomelo Cake is a refreshing dessert that can be easily made with an air fryer, combining the tart fruity flavor of red pomelo pulp with the soft texture of cake, perfect for a single serving afternoon tea. Eggs and flour provide protein and carbs, while red pomelo is rich in vitamin C, offering simple basic nutrition. The difficulty is medium, and the key is to stir gradually into a smooth light yellow batter. Beginners can succeed if they patiently follow the steps. From preparation to serving takes about 35 minutes, not too much time when you crave a freshly baked dessert.', '[{"name":"Eggs","unit":"piece"},{"name":"Red pomelo pulp","unit":"g"},{"name":"Flour","unit":"g"},{"name":"Oil","unit":"ml"},{"name":"Sugar","unit":"g"},{"name":"Water","unit":"ml"}]'::jsonb, '["Crack 2 eggs into a foil pan, add 20g red pomelo pulp","Pour 15ml oil into the foil pan and shake to evenly cover the bottom","Add 10g sugar, 40g flour, and 40ml water to the foil pan","Stir clockwise with chopsticks until a light yellow batter forms","Add 5g sugar, 40g flour, and 40ml water to the foil pan","Continue stirring with chopsticks until a light yellow batter forms","Place the foil pan in the air fryer basket and bake at 180°C for 15 minutes","Open the air fryer, carefully remove the foil pan, and flip the cake with chopsticks or a spoon","Continue baking at 180°C for 8 minutes","Remove and enjoy"]'::jsonb, '["Dessert","Sweet and Sour","Baking","Air Fryer","Quick","Afternoon Tea"]'::jsonb),
  ('howtocook:dessert/胡萝卜甜糕', 'en', 'Carrot Halwa', 'Desserts', 'Carrot Halwa is a well-known winter dessert in India. Shredded carrots are slow-cooked with milk until thickened, then enriched with ghee and nuts. The texture is dense and sweet, with a golden-red color. Rich in beta-carotene, calcium, and healthy fats, it is warming and nourishing. The process is simple but requires patience for beginners; it takes about 45 minutes to complete.', '[{"name":"Carrots","unit":"g"},{"name":"Whole milk","unit":"ml"},{"name":"Sugar","unit":"g"},{"name":"Ghee","unit":"g"},{"name":"Ground cardamom","unit":"g"},{"name":"Cashews","unit":"g"},{"name":"Almonds","unit":"g"},{"name":"Raisins","unit":"g"}]'::jsonb, '["Peel the carrots and grate them into fine shreds using a grater.","In a heavy-bottomed pan, add 20g of ghee (half the amount) and heat over medium heat until melted.","Add the shredded carrots and stir-fry for 3-5 minutes until softened and fragrant.","Pour in 500ml of whole milk and stir well.","Bring to a boil over high heat, then reduce to medium-low heat and maintain a gentle simmer.","Continue stirring for 25-30 minutes until the milk is almost completely absorbed and evaporated by the carrots (this is the most critical step; patience and constant stirring are needed to prevent burning).","When there is almost no liquid left in the pan, add 80g of sugar and stir well.","The mixture will release water after adding sugar; continue to stir over medium-low heat for 5-8 minutes until the liquid evaporates again.","Add the remaining 20g of ghee and 3g of ground cardamom, and stir-fry for 2 minutes.","In another small pan, fry the cashews, almond slices, and raisins separately in a little ghee until golden (about 1 minute each); note that the raisins will puff up.","Mix half of the fried nuts and raisins into the carrot halwa.","Transfer to a serving dish and sprinkle the remaining nuts and raisins on top as decoration."]'::jsonb, '["Dessert","Indian style","Sweet","Slow-cooked","Warming","Nourishing"]'::jsonb),
  ('howtocook:dessert/芋泥雪媚娘/芋泥雪媚娘', 'en', 'Taro Mochi', 'Desserts', 'Taro Mochi has a soft and chewy outer skin, with a delicate sweet taro paste and light cream filling, creating rich layers of texture. This is a Chinese dessert inspired by home cooking. Taro and purple sweet potato provide dietary fiber and anthocyanins, while milk and cream add calcium. No oven required, simple steps, beginner-friendly. Takes about two hours from start to finish.', '[{"name":"Taro","unit":"g"},{"name":"Purple sweet potato powder","unit":"g"},{"name":"Milk","unit":"g"},{"name":"Glutinous rice flour","unit":"g"},{"name":"Glutinous rice flour","unit":"g"},{"name":"Corn starch","unit":"g"},{"name":"Butter","unit":"g"},{"name":"Heavy cream","unit":"g"},{"name":"White sugar","unit":"g"}]'::jsonb, '["Cut taro into chunks, boil on high heat until soft (about 40 minutes), then put all into a blender.","Add 30g milk, 25g heavy cream, and blend into a puree.","Then add 3g purple sweet potato powder, 18g white sugar, and continue blending until smooth taro paste.","Get another bowl, add all glutinous rice flour b, 22g corn starch, 135g milk, 50g white sugar, mix well and sift once. Cover with plastic wrap, poke small holes, and steam over medium heat for 30 minutes.","While steaming, put glutinous rice flour a into a pan and stir-fry over low heat until slightly yellow (cooked), set aside as hand flour.","Take the steamed glutinous rice and milk mixture (jelly-like) out, immediately add 30g butter, knead until butter is fully absorbed, then refrigerate for one hour.","Take another bowl, add 120g heavy cream, 8g white sugar, whip until peaks form, put into a piping bag and set aside.","Take out the chilled dough, knead for 5 minutes, divide into 30g portions. Evenly dust with 2g hand flour to prevent sticking. Roll into circles. First pipe 5g whipped cream, then place 30g taro paste, then wrap the dough like a bun (trim excess dough if needed).","After wrapping, evenly dust with 2g hand flour to prevent sticking.","Repeat the last two steps until all ingredients are used."]'::jsonb, '["Dessert","Sweet","Soft and chewy","Steamed","No-bake","Afternoon tea"]'::jsonb),
  ('howtocook:dessert/英式司康/英式司康', 'en', 'English Scones', 'Desserts', 'English scones are a classic afternoon tea treat, crispy on the outside and soft inside, with rich egg and milk aroma. They taste even better with jam or cream. Made mainly from flour, butter, eggs, and cream, they are rich in carbohydrates and protein, providing quick energy. The process is simple; with basic kneading techniques, even beginners can succeed. It takes about an hour from preparation to baking.', '[{"name":"Unsalted butter","unit":"g"},{"name":"Cake flour","unit":"g"},{"name":"Sugar","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Baking powder","unit":"g"},{"name":"Eggs","unit":"piece"},{"name":"Heavy cream","unit":"g"},{"name":"Cream cheese","unit":"g"}]'::jsonb, '["Beat the eggs and measure out 30g of egg liquid into a clean bowl. Add the full amount of heavy cream and cream cheese; mix well. If the cheese is too hard, heat it in a water bath to about 40°C before mixing.","Place the cake flour, salt, sugar, and baking powder in a clean bowl; mix well.","Cut the butter into small pieces and add to the previous mixture. Rub the butter into the mixture with your hands until it resembles coarse cornmeal.","Pour the egg-milk mixture from step 1 into the flour-butter mixture. Stir until combined. Press and fold to form a uniform dough.","Place the dough on a work surface and roll out to 1.5cm thickness. Cut into desired shapes with a knife or cutter.","Dip a brush into the remaining 20g of egg liquid and brush onto the surface of the scones.","Preheat the oven to 180°C and bake for 27 minutes."]'::jsonb, '["Dessert","Sweet","Baking","English","Afternoon Tea","Pastry"]'::jsonb),
  ('howtocook:dessert/草莓冰淇淋/草莓冰淇淋', 'en', 'Strawberry Ice Cream', 'Desserts', 'This is an easy homemade strawberry ice cream that requires no ice cream maker. It''s fruity, rich, and creamy. Strawberries are packed with vitamin C, and the sweetened condensed milk and cream provide energy and calcium. The recipe is simple and foolproof, perfect for beginners. Total time is about 8 hours, mostly freezing, with only a few tens of minutes of hands-on work.', '[{"name":"Strawberries","unit":"g"},{"name":"White sugar","unit":"g"},{"name":"Vanilla extract","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Vanilla extract","unit":"g"},{"name":"Heavy cream","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Sweetened condensed milk","unit":"g"}]'::jsonb, '["First make the strawberry syrup. Wash the strawberries and remove the green tops. Cut the strawberries into 5mm small pieces. Reserve half of the chopped strawberries to fold into the ice cream later.","Place the other half of the chopped strawberries and sugar into a saucepan. Stir and cook over medium heat until the strawberries release liquid and form a syrup in the pan.","Let the strawberries heat in the syrup, stirring occasionally, until they break down and deform, and the syrup thickens slightly.","When the syrup holds its shape for 3 seconds, it''s ready. Remove the syrup from the heat, stir in vanilla and salt. Set the strawberry syrup aside to cool.","While the syrup cools, prepare the ice cream base. In a bowl, combine sweetened condensed milk, heavy cream, vanilla extract, and salt. Use a hand mixer to whip the mixture until it becomes light and fluffy, and forms soft peaks.","Fold the reserved chopped fresh strawberries into the ice cream base. Transfer the whipped ice cream base to a freezer-safe container. Drizzle the cooled strawberry syrup over the ice cream, then gently swirl it into the mixture.","Cover the ice cream and freeze for eight hours, then scoop and serve."]'::jsonb, '["Dessert","Sweet","No-bake","Quick","Homestyle","Summer"]'::jsonb),
  ('howtocook:dessert/酸奶意式奶冻/酸奶意式奶冻', 'en', 'Yogurt Panna Cotta', 'Desserts', 'A twist on the classic Italian dessert, adding plain yogurt for a lighter, smoother texture—sweet but not cloying. Perfect as a post-meal treat with fruit or jam. Dairy provides calcium and protein, making it a gentle yet nutritious choice. Simple steps: just heat, stir, and chill. Even beginners can master it. From prep to serving, about 5 hours.', '[{"name":"heavy cream","unit":"g"},{"name":"sugar","unit":"g"},{"name":"plain yogurt","unit":"g"},{"name":"gelatin sheets","unit":"g"}]'::jsonb, '["Cut gelatin sheets into small pieces, soak in cold water","Place heavy cream and sugar in a pot, heat to 60°C","Turn off heat. Remove gelatin from water, squeeze dry, add to hot cream, stir until dissolved","Cool cream to 40°C, add plain yogurt, mix well","Strain the mixture through a sieve twice","Pour into serving containers, refrigerate for at least 4 hours"]'::jsonb, '["Dessert","Sweet and Tangy","Italian","No-Bake","Quick","Party"]'::jsonb),
  ('howtocook:dessert/雪花酥/雪花酥', 'en', 'Snowflake Crisp', 'Desserts', 'Snowflake Crisp is a small dessert with a crispy, sweet, and rich milky flavor. It is a simple and quick home-baked treat, also suitable for gift boxes. Since it contains butter, milk powder, and mixed nuts, it provides ample energy and protein, though it is high in calories, so enjoy in moderation. The difficulty is moderate, somewhat challenging for beginners, but with attention to heat and stirring technique, it can be completed in about 30 minutes.', '[{"name":"Unsalted butter","unit":"g"},{"name":"Marshmallows","unit":"g"},{"name":"Whole milk powder","unit":"g"},{"name":"Mixed nuts","unit":"g"},{"name":"Cookies","unit":"g"}]'::jsonb, '["If cookies are larger than a one-yuan coin, cut them into small pieces first.","Add unsalted butter to the pan, heat over low heat until fully melted.","Add marshmallows to the pan, stir with a spatula until melted and evenly combined with the butter.","Add 20g milk powder to the pan, stir with a spatula until combined, then immediately turn off the heat.","Add all prepared mixed nuts and cookies while hot, stir with a spatula.","After stirring until cool enough to touch, put on disposable plastic gloves, knead or pull the mixture in the pan to evenly distribute cookies and nuts with the marshmallow-butter-milk powder mixture.","Press the mixture into a mold, compact the corners, roll flat with a rolling pin, and press the unfilled side into a straight edge by hand.","Let cool at room temperature. Once completely cooled, unmold, cut into pieces along the mold lines or to desired size, sprinkle with remaining milk powder, making sure to coat all sides of the snowflake crisp."]'::jsonb, '["Dessert","Rich milky flavor","Crispy and sweet","Quick","Baked dessert","Home-style","Gift"]'::jsonb),
  ('howtocook:dessert/魔芋蛋糕/魔芋蛋糕', 'en', 'Konjac Cake', 'Desserts', 'Konjac cake is a low-calorie, gluten-free dessert. It uses erythritol instead of white sugar, with a light and moist texture, cocoa aroma, especially suitable for weight loss. It is rich in dietary fiber and protein, giving a strong feeling of fullness. It is somewhat difficult to make, requiring whipping egg whites and careful folding, but it takes only about half an hour, making it a quick and healthy baking option.', '[{"name":"Egg","unit":"piece"},{"name":"Erythritol","unit":"gram"},{"name":"Cocoa powder","unit":"gram"},{"name":"Konjac flour","unit":"gram"},{"name":"Cream of tartar","unit":"gram"}]'::jsonb, '["Before preparing the batter, preheat the oven to 350°F (150°C) to save time","Take fresh eggs out of the refrigerator","Prepare two dry containers, one for egg whites and one for yolks","The container for egg whites can have a little water but no oil; the container for yolks must be dry","Crack the eggs, manually or using an egg separator, to separate whites and yolks into the two containers.","During separation, yolks must not break, and no yolk should get into the whites, otherwise it will affect whipping. (White chalaza can go into whites, it''s fine)","(Note: if not using a stand mixer, the container for egg whites is also the mixing bowl; to avoid overflow, the egg whites should not exceed 1/8 of the container''s volume)","Add 1g cream of tartar to the egg whites","Beat on high speed until frothy with large bubbles, then add 50g erythritol","Beat on medium-low speed until stiff peaks form (when lifting the whisk, short upright peaks form; bowl can be inverted without whites falling)","At this point the egg whites are properly whipped","Keep the beaters close to the bottom of the bowl to avoid having the top whipped but bottom still liquid)","Add the separated yolks to the whipped egg whites, mix on medium-low speed until evenly combined","Add 10g cocoa powder and 10g konjac flour to the egg white mixture. First fold with a knife because using a mixer would cause powder to fly","The folding technique is:","First, insert a spatula into the center of the bowl all the way to the bottom","Scrape towards the 8 o''clock direction until hitting the bowl wall, then lift the spatula up, bring it back to the center, and drop the batter back","With your left hand, turn the bowl from 9 o''clock to 7 o''clock, a 60-degree rotation, completing one cycle","Speed about 2 strokes per second","This method is from ''Small Island Teacher''s Cake Classroom''. In simple terms, stir like you''re stir-frying.","After folding, use a mixer on low speed to mix evenly","Line the mold with parchment paper, fitting the bottom and sides","Pour the batter into the mold, smooth the top with a knife, then tap the mold a few times to remove large air bubbles","Bake for 25 minutes","Once baked, use oven mitts to remove from the oven","(Optional) Drop the mold from a height to release steam","Invert the mold for 10 minutes to cool the cake","Removing the cake before cooling will damage it","This step may be hot, be sure to wear oven mitts","Unmold and slice with a knife to serve"]'::jsonb, '["Dessert","Low Calorie","Gluten-Free","Cocoa","Baking","Quick","Weight Loss"]'::jsonb),
  ('howtocook:dessert/龟苓膏/龟苓膏', 'en', 'Guilinggao', 'Desserts', 'Guilinggao is a traditional Cantonese dessert with a smooth, jelly-like texture, slightly bitter with a sweet aftertaste. Often enjoyed as a summer treat, it helps clear heat, remove dampness, nourish yin, and beautify the skin. This healthy snack is easy to make—even beginners can master it. Just prepare ingredients, mix, heat, and chill for about two hours before serving.', '[{"name":"Guilinggao powder","unit":"g"},{"name":"Cold water","unit":"ml"},{"name":"Boiling water","unit":"ml"},{"name":"Granulated sugar","unit":"g"}]'::jsonb, '["In a pot, mix 25 g of guilinggao powder with 120 ml of cold water until no lumps remain.","In another container, add 100 g of granulated sugar and pour in 500 ml of boiling water, stirring until the sugar is completely dissolved.","Slowly pour the sugar water into the guilinggao powder mixture, stirring immediately to prevent clumps.","Place the combined liquid on the stove over medium-low heat, stirring continuously to avoid sticking.","Heat until the liquid thickens and small bubbles start to appear, then turn off the heat.","Quickly pour the liquid into molds and let it cool naturally to set. For best texture, refrigerate for 1–2 hours before serving."]'::jsonb, '["Dessert","Cantonese","Summer","Smooth","Bitter-sweet","Quick"]'::jsonb),
  ('howtocook:drink/B52轰炸机', 'en', 'B52 Bomber', 'Drinks', 'This cocktail has distinct layers. First, the kick of vodka, then the sweet aftertaste of coffee cream. When lit, it offers a unique ice-and-fire experience. A classic creative cocktail. Kahlúa and Baileys provide a little caffeine and cream, but the nutrition is mainly alcohol. Making it requires practice in layering and lighting. A bit challenging for beginners, but the whole process takes only about 5 minutes.', '[{"name":"Kahlúa","unit":"ml"},{"name":"Baileys Irish Cream","unit":"ml"},{"name":"Skyy Original Vodka","unit":"ml"}]'::jsonb, '["Pour Kahlúa into the bottom of a liqueur glass to 1/3 full. (10ml)","Slowly pour Baileys Irish Cream along the back of a spoon to also 1/3 full (10ml). Go slow to keep the layers distinct. (Too fast and the Baileys will mix with the coffee liqueur.)","Finally, pour Skyy Original Vodka on top (10ml).","Warm the rim of the glass with a lighter.","Last step: light it. See the small blue flame?"]'::jsonb, '["Beverage","Sweet","Layered","Flamed","Cocktail","Party"]'::jsonb),
  ('howtocook:drink/Mojito莫吉托', 'en', 'Mojito', 'Drinks', 'This cocktail has a refreshing sweet and sour taste, with the coolness of mint and the slight buzz of rum. It is a classic summer drink. Low in alcohol, paired with vitamin C-rich lime, it can quench thirst and refresh the mind. Very easy to make, beginner-friendly, from prep to finish takes about ten minutes.', '[{"name":"Lime","unit":"piece"},{"name":"Mint leaves","unit":"sprig"},{"name":"Simple syrup","unit":"ml"},{"name":"Golden rum","unit":"ml"},{"name":"Blue Sky Original Vodka","unit":"ml"},{"name":"Crushed ice","note":"as needed"},{"name":"Chilled soda water","note":"as needed"}]'::jsonb, '["Cut one of the halved limes into small pieces, place into a highball glass, then muddle with a muddler to extract juice;","Rub 3-4 mint sprigs along the rim of the glass, then place them into the glass;","Add 20ml simple syrup;","Add 45ml golden rum;","Squeeze the remaining half lime into the glass;","Stir gently to partially dissolve the sugar/syrup;","Fill the glass with crushed ice until it reaches 3/4 full;","Add chilled soda water until it just covers the crushed ice;","Stir with a swirling motion for half a minute;","Top up the highball glass with crushed ice;","Slap the remaining mint sprig to release aroma, insert into the crushed ice as garnish."]'::jsonb, '["Drinks","Sweet and Sour","Refreshing","Cocktail","Quick","Summer"]'::jsonb),
  ('howtocook:drink/冬瓜茶', 'en', 'Winter Melon Tea', 'Drinks', 'Winter melon tea is a traditional refreshing and heat-relieving drink. It tastes sweet and mild, with a unique fragrance of winter melon, and tastes even better when chilled. Winter melon itself is low in calories and rich in water. When boiled with rock sugar, it replenishes energy and promotes hydration. The process is not complicated but requires some patience for beginners. It takes about 4 to 5 hours in total.', '[{"name":"Winter melon","unit":"g"},{"name":"Rock sugar","unit":"g"}]'::jsonb, '["Prepare the winter melon: Peel the winter melon, remove the seeds, and cut into small pieces (each piece no larger than 4 cm).","Add rock sugar: Add rock sugar to the winter melon, mix well, cover with plastic wrap, and refrigerate for at least 2 hours.","Cook the winter melon: At this point the winter melon has released a lot of water. Pour it into a pot, bring to a boil over high heat, then reduce to medium-low heat and simmer slowly for 1 to 2 hours, stirring frequently to prevent sticking.","Strain the winter melon tea: Use a strainer to filter the cooked winter melon liquid, remove the winter melon pieces, and keep only the tea liquid.","Cool: Let the winter melon tea liquid cool down, then pour into a clean container and refrigerate.","Enjoy: The cooked winter melon tea liquid is a concentrate. Dilute with water or other beverages according to personal preference. It can be served cold or hot."]'::jsonb, '["Beverage","Refreshing","Heat-relieving","Sweet","Simmered","Chilled"]'::jsonb),
  ('howtocook:drink/冰粉/冰粉', 'en', 'Ice Jelly', 'Drinks', 'Ice Jelly is a traditional snack from Xinyang, Henan. It has a smooth, jelly-like texture and is served with mint juice or lemon juice to cool down and relieve summer heat. It belongs to Henan cuisine. Made by hand-rubbing ice jelly seeds, it is natural and additive-free, rich in plant colloids. The preparation is very simple and beginner-friendly. The whole process takes about 3 hours, of which 2.5 hours is setting time, requiring almost no hands-on work.', '[{"name":"Ice jelly seeds","unit":"grams"},{"name":"Cooled boiled water","unit":"grams"},{"name":"Mint juice","unit":"ml"},{"name":"Mint powder","unit":"grams"},{"name":"Water-glow ice cubes","note":"optional"}]'::jsonb, '["Pour the cooled boiled water into a basin.","Wrap all the ice jelly seeds in a cheesecloth and tie the opening.","Put the wrapped ice jelly seeds into the cooled boiled water and vigorously knead for 6 minutes.","Then let the cooled boiled water sit for 2.5 hours to set.","Then scoop the ice jelly into prepared disposable clear plastic cups, add 10ml mint juice or 10g mint powder (lemon juice, hawthorn juice, mulberry juice also work), add water-glow ice cubes, and slowly stir with a spoon."]'::jsonb, '["Beverage","Henan Cuisine","Cooling","Heat Relief","Handmade","Summer"]'::jsonb),
  ('howtocook:drink/印度奶茶', 'en', 'Indian Milk Tea', 'Drinks', 'Indian milk tea is a home-style drink full of exotic flavor, freshly brewed with black tea, milk, and a variety of spices. It has a rich and smooth taste, with a warm spiciness from ginger, cardamom, and cinnamon. The milk provides high-quality protein and calcium, while the spices help warm the body, ward off cold, and promote digestion. The process is simple and intuitive, friendly for beginners, taking about 10 minutes from preparation to serving.', '[{"name":"Water","unit":"ml"},{"name":"Whole milk","unit":"ml"},{"name":"Black tea (CTC tea is best, or Assam black tea)","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Green cardamom","unit":"pods"},{"name":"Cinnamon stick","unit":"small stick"},{"name":"Cloves","unit":"cloves"},{"name":"Black peppercorns","unit":"peppercorns"},{"name":"Sugar","unit":"g"}]'::jsonb, '["Smash the ginger (no need to chop too finely, just smash to release the juice)","Crack the green cardamom pods with the back of a knife to expose the seeds","Crush the black peppercorns","Pour 120ml water into a small saucepan","Add the smashed ginger, cracked cardamom, cinnamon stick, cloves, and crushed black peppercorns","Bring to a boil over high heat, then reduce to low heat and cook for 2 minutes to let the spices release their flavors","Add 8g black tea and continue to cook over low heat for 2 minutes until the tea darkens","Pour in 120ml whole milk","Heat over medium heat, watching carefully. When the milk tea starts to foam and rise, immediately reduce to low heat (milk can easily boil over)","Simmer for 2-3 minutes, occasionally lifting the saucepan and pouring the tea back (repeat 3-4 times) to fully blend the tea and milk","Add sugar and stir to dissolve","Turn off the heat","Strain the tea into a cup through a fine mesh sieve to remove the tea leaves and spice residues","Serve hot"]'::jsonb, '["Drink","Indian flavor","Spicy and aromatic","Boiled","Quick","Warming"]'::jsonb),
  ('howtocook:drink/可乐桶', 'en', 'Cola Bucket', 'Drinks', 'Cola Bucket is a simple and easy-to-mix casual cocktail with a refreshing and sweet taste. The bubbles of cola and lemon juice nicely balance the harshness of whiskey, making it suitable for parties. It mainly provides energy, and lemon adds vitamin C. The whole mixing process takes only 5 minutes, and beginners can easily master it.', '[{"name":"Bourbon whiskey","unit":"ml"},{"name":"Coca-Cola","unit":"ml"},{"name":"Ice cubes","unit":"g"},{"name":"Lemon","unit":"piece"}]'::jsonb, '["Cut the lemon in half (knife perpendicular to the line connecting the stem and tip), then cut a slice from one half and set aside.","Cut the lemon in half again, then use a lemon squeezer to juice the four lemon wedges into a container and set aside.","Place the squeezed lemon wedges into a container and set aside.","Choose a cup, preferably a large glass or tin bucket with a capacity of about 1 liter.","Add ice cubes and the squeezed lemon wedges into the cup (you can arrange the lemon and ice cubes according to personal preference).","Pour in 15 ml of lemon juice (if you like it sour, you can add more or all of it).","Slowly pour Coca-Cola along the cup wall until it reaches 3/4 from the rim (control the ratio of cola to whiskey at about 5:1).","Pour whiskey until the cup is full."]'::jsonb, '["Beverage","Refreshing","Sweet","Quick","Party","Cocktail"]'::jsonb),
  ('howtocook:drink/奇异果菠菜特调/奇异果菠菜特调', 'en', 'Kiwifruit Spinach Special Drink', 'Drinks', 'This is a refreshing and healthy fruit and vegetable drink, with a sweet and sour smooth texture, natural fruity aroma of kiwifruit and apple, and a light spinach flavor that doesn''t overpower. Rich in vitamin C and dietary fiber, it helps promote digestion. It''s very simple to make, even beginners can succeed on the first try, and it takes only about 10 minutes.', '[{"name":"Kiwifruit","unit":"piece"},{"name":"Apple","unit":"piece"},{"name":"Spinach leaves","unit":"leaf"},{"name":"Drinking water","unit":"ml"},{"name":"White sugar","unit":"g"}]'::jsonb, '["Cut the kiwifruit in half, then each half into four small pieces","Dice the apple","Remove the stems from the spinach leaves, keeping only the leaves","Chop the spinach","Pour them all into the blender cup","Add water","Add white sugar","Start the blender and blend for about four 15-second intervals (stop every 15 seconds to check the consistency)"]'::jsonb, '["Drinks","Sweet and Sour","Refreshing","Quick","Healthy","Vitamin C"]'::jsonb),
  ('howtocook:drink/奶茶', 'en', 'Milk Tea', 'Drinks', 'This is a home-style drink easily made with black tea and milk powder, blending tea aroma and milky flavor, smooth and warm. The polyphenols in black tea combined with the protein and calcium in milk can both refresh and supplement daily nutrition. The method is very simple, beginners can succeed on the first try, and it takes only about half an hour to enjoy homemade milk tea.', '[{"name":"Black tea bag (recommend Lipton Yellow Label Black Tea)","unit":"bag"},{"name":"Whole milk powder (or evaporated milk)","unit":"g"},{"name":"Granulated sugar","unit":"g"},{"name":"Boiling water","unit":"ml"}]'::jsonb, '["Place 2 tea bags in a cup and add 180-200mL boiling water.","Wait for 20-30 minutes.","Weigh 11-12g milk powder and 5-7g granulated sugar, and add them separately to the liquid from the previous step.","Stir well and serve."]'::jsonb, '["Beverage","Milky","Quick","Homemade","Afternoon Tea","Warming Stomach"]'::jsonb),
  ('howtocook:drink/杨枝甘露', 'en', 'Mango Pomelo Chia Seed Dessert', 'Drinks', 'This is a modified version of the classic Hong Kong dessert, using chia seeds instead of sago. The texture is smooth and tender with a subtle crunch from the seeds. The sweetness of mango and the slight tartness of pomelo intertwine, while coconut milk adds richness. Rich in dietary fiber, vitamin C, and healthy fats, it''s refreshing and perfect for cooling down. Very easy to make, even beginners can do it. From prep to serving, it takes about 20 minutes.', '[{"name":"Chia seeds","unit":"g"},{"name":"Milk","unit":"ml"},{"name":"Ice cubes","unit":"small cubes"},{"name":"Mango","unit":"piece"},{"name":"Pomelo","unit":"piece"},{"name":"Coconut milk","unit":"ml"},{"name":"Dried mango","note":"shredded, optional"},{"name":"Dried orange","note":"shredded, optional"}]'::jsonb, '["Soak chia seeds in milk for 10 minutes.","While the seeds are soaking, peel and dice half a mango and the pomelo, place in a cup.","Cut the other half mango into small pieces, put in a blender with ice cubes and coconut milk, blend into a puree.","Pour into the cup, add garnishes (if any).","Enjoy while writing code!!"]'::jsonb, '["Beverage","Hong Kong style","Sweet and sour","Refreshing","Quick","Cooling"]'::jsonb),
  ('howtocook:drink/柠檬水/柠檬水', 'en', 'Lemonade', 'Drinks', 'This drink features fresh lemon as the main ingredient, paired with fruit syrup to balance sweet and sour. It''s refreshing and cool when iced. Lemons are rich in vitamin C, and regular consumption helps replenish nutrients, refresh, and whiten. The steps are minimal: just pound, add ingredients, and shake. Even beginners can finish in 3-5 minutes.', '[{"name":"Lemon","unit":"grams"},{"name":"Fruit syrup","unit":"grams"},{"name":"Ice","note":"a few cubes (optional)"}]'::jsonb, '["Weigh 40~45 grams of lemon and put into a shaker","Cover the shaker and pound about 10 times","Add 40~45 grams of fruit syrup","Top up with water","Shake well","Finally, add ice to taste"]'::jsonb, '["Beverage","Sweet and Sour","Quick","Refreshing","Cold Drink","Vitamin C"]'::jsonb),
  ('howtocook:drink/泰国手标红茶/泰国手标红茶', 'en', 'Thai Hand-Pick Tea', 'Drinks', 'This is a classic milk tea from the streets of Thailand. Rich tea aroma, smooth and silky texture, sweet milky flavor from condensed milk and fresh milk. The combination provides a small amount of protein and calcium, but is high in sugar. Suitable as a refreshing drink to beat the heat. The steps are simple, but require repeated filtering and a long refrigeration time. Total time about 4 hours 20 minutes. Patience required for beginners.', '[{"name":"water","unit":"cc"},{"name":"tea powder","unit":"g"},{"name":"condensed milk","unit":"g"},{"name":"white sugar","unit":"g"},{"name":"milk","unit":"ml"},{"name":"ice cubes","unit":"cubes"}]'::jsonb, '["Bring 600cc of water to a rolling boil over high heat.","Put 20g of tea powder in a filter bag, pour the boiling water into the filter bag, and filter 20 times.","Using a scale, measure 24g of condensed milk, 24g of white sugar, and 18ml of milk, and put them into a kettle or pitcher of at least 1000ml capacity.","Pour the filtered tea into the pitcher and stir until the sugar dissolves.","Place the pitcher in the refrigerator for at least 4 hours.","Add 6-8 ice cubes before serving."]'::jsonb, '["Drinks","Thai Milk Tea","Cold Drink","Sweet","Street Style","Refreshing","Milk Tea"]'::jsonb),
  ('howtocook:drink/海边落日/海边落日', 'en', 'Seaside Sunset', 'Drinks', 'This cocktail has distinct layers of color: the grenadine at the bottom resembles sunset clouds, the orange juice in the middle is translucent, and the blue curaçao on top looks like seawater, creating the imagery of a seaside sunset. It tastes sweet and sour, refreshing, with a hint of rum. Orange juice and lemon juice contain a small amount of vitamin C, and the alcohol helps you relax. The mixing steps are not complicated, but pouring the liquid along the stirring rod to create layers requires a bit of patience. Even beginners can succeed by following along. Preparation and mixing take about 15 minutes.', '[{"name":"grenadine syrup","unit":"ml"},{"name":"NFC orange juice","unit":"ml"},{"name":"soda water","unit":"ml"},{"name":"white rum","unit":"ml"},{"name":"blue curaçao","unit":"ml"},{"name":"lemon juice","unit":"ml"},{"name":"ice","note":"as needed"},{"name":"lemon","unit":"slice"}]'::jsonb, '["Wash the lemon and cut a slice","Choose a glass, preferably a clear glass with a capacity of 350–400 ml","Add large ice cubes and stir the glass with a stirring rod to chill","Add grenadine syrup","Pour orange juice along the stirring rod into the glass until it is half full","Gently stir half a turn","Pour in soda water","Take a mixing glass, add white rum + blue curaçao + lemon juice + ice. Then shake, shake","Gently pour into the glass","Garnish with lemon slice and straw"]'::jsonb, '["Drinks","Sweet and Sour","Refreshing","Cocktail","Layered","Summer"]'::jsonb),
  ('howtocook:drink/牛油果拉西', 'en', 'Avocado Lassi', 'Drinks', 'An innovative twist on the traditional Indian yogurt drink Lassi, this beverage is creamy, smooth, refreshingly sweet without being cloying, making it perfect as a breakfast or afternoon pick-me-up. Avocados are rich in monounsaturated fatty acids and dietary fiber, while the yogurt provides high-quality protein and probiotics, offering long-lasting satiety in one glass. Extremely easy to make, even beginners can succeed with zero failures—only about 5 minutes from preparation to enjoyment.', '[{"name":"plain yogurt","unit":"ml"},{"name":"avocado","unit":"piece"},{"name":"honey","unit":"tablespoon"},{"name":"cold milk","unit":"ml"},{"name":"cardamom powder","unit":"pinch"},{"name":"mint leaves","note":"for garnish, as needed"},{"name":"crushed nuts","unit":"g"}]'::jsonb, '["Cut the avocado in half, remove the pit, peel off the skin, and cut the flesh into small pieces. Set aside.","Add 120ml plain yogurt, the avocado pieces, 1 tablespoon honey, and 60ml cold milk to a blender.","(Optional) Add a pinch of cardamom powder for a unique flavor.","Blend for about 1 minute until the mixture is completely smooth and creamy.","Pour the drink into a glass.","(Optional) Garnish with a few mint leaves or sprinkle 5g of chopped nuts on top."]'::jsonb, '["Beverage","Sweet","Creamy","Quick","Breakfast","Indian Flavor"]'::jsonb),
  ('howtocook:drink/百香果橙子特调/百香果橙子特调', 'en', 'Passion Fruit and Orange Special Drink', 'Drinks', 'This is a sweet and sour refreshing summer drink that combines the tropical aroma of passion fruit with the sweetness of oranges. Paired with jasmine green tea or soda water, the layers of flavor are distinct, icy and refreshing. Rich in vitamin C, it helps boost immunity and moisturize the skin. Steps include marinating, brewing tea, and juicing. There are a few steps but moderate difficulty, beginners can try. Need to marinate passion fruit one day in advance, total time about 24 hours, actual hands-on time about 30 minutes.', '[{"name":"Passion fruit","unit":"pieces"},{"name":"Orange","unit":"pieces"},{"name":"Jasmine green tea leaves","unit":"grams"},{"name":"White sugar","unit":"grams"},{"name":"Honey","unit":"grams"},{"name":"Boiling water","unit":"ml"},{"name":"Ice cubes","unit":"grams"},{"name":"Soda water","note":"to taste, alternative to jasmine green tea"},{"name":"Mint leaves or other greens","note":"optional, for decoration"}]'::jsonb, '["Marinate the passion fruit (this makes two servings because small amounts are hard to handle)","Scoop out the pulp of three passion fruits (including the juice) and place in a container","Weigh out 30 grams of white sugar and add","Weigh out 10 grams of honey and add (if none, substitute with 5 grams of white sugar)","Stir well","Cover the container with plastic wrap and refrigerate for 12–24 hours to marinate","Prepare jasmine green tea (recommended ratio => tea : water : ice = 1–2 : 50 : 30)","Weigh 3–6 grams of tea leaves into a container, add 150 ml boiling water, steep for 6 minutes","Add 90 grams of ice cubes to the brewed tea to cool, stir to speed up cooling","Once the ice has melted, strain out the tea leaves to obtain about 240 ml of jasmine green tea","Handle the orange (can be done while the tea is steeping)","Cut the orange in half (cut perpendicular to the line between stem and blossom end), then slice one thin round from one half and set aside","Cut the orange halves again to get four wedges, use a juicer to squeeze the juice into a container and set aside","Final assembly","Choose a cup, preferably a transparent glass with a capacity of 350–400 ml","Place 70 grams of ice cubes at the bottom, then pour all the orange juice over them","Place the previously prepared orange slice against the inner wall of the cup","Pour one serving of the marinated passion fruit over the ice","Slowly pour the jasmine green tea until the cup is full, to create layers","Place a decorative green leaf on the surface (optional)"]'::jsonb, '["Drinks","Sweet and sour","Refreshing","Brewed","Iced drink","Summer"]'::jsonb),
  ('howtocook:drink/砂糖椰子冰沙/砂糖椰子冰沙', 'en', 'Sugar Coconut Ice Slush', 'Drinks', 'Sugar Coconut Ice Slush is a quick tropical cold drink, with the sweet coconut aroma blended with the caramelized fragrance of coarse brown sugar, offering a smooth and icy texture. Coconut water is rich in natural electrolytes and minerals, quickly replenishing hydration, while coffee sugar adds carbohydrate energy. It''s extremely easy to make: just freeze the coconut water solid and smash it into slush—no stress for beginners. It requires more than 10 hours of freezing in advance, but the actual prep takes only a few minutes, making it a perfect afternoon ice treat.', '[{"name":"Bottled coconut water","unit":"ml"},{"name":"Coffee sugar","unit":"grams"},{"name":"Crushed nuts (optional)","note":"to taste"}]'::jsonb, '["Pour out 200ml from a 500ml bottle of coconut water, then tighten the cap immediately.","Place the bottle in the freezer and freeze for at least 10 hours.","Take out the bottle. Once confirmed that the coconut water is completely frozen, forcefully hit it against a hard surface like a wall corner, chair back, or table edge. (Make sure the surface won''t be damaged.)","When the frozen coconut water turns into slush, open the cap and pour out the slush.","Evenly sprinkle coffee sugar or crushed nuts on top of the slush.","Done."]'::jsonb, '["Beverage","Quick","Cold Drink","Refreshing","Afternoon Tea","Tropical Flavor"]'::jsonb),
  ('howtocook:drink/耙耙柑茶/耙耙柑茶', 'en', 'Pomelo Tea', 'Drinks', 'Pomelo Tea is a fruit tea drink that combines the sweetness of pomelo with the fragrance of jasmine. It tastes refreshing and sweet, a creative beverage not limited to any specific cuisine. Pomelo is rich in vitamin C and dietary fiber, and when paired with green tea, it offers a clean and invigorating experience. The recipe is very simple, beginner-friendly, and takes only about 15 minutes from steeping to blending.', '[{"name":"Pomelo"},{"name":"Jasmine green tea"},{"name":"Ice cubes","unit":"g"},{"name":"Cane syrup","unit":"g"},{"name":"Tool","note":"as needed"}]'::jsonb, '["Prepare jasmine green tea (recommended ratio: tea : water : ice = 1~2 : 50 : 30)","Weigh 2~4 g of tea leaves into a container, add 100 ml of boiling water, steep for 6 minutes","Add 60 g of ice cubes to the brewed tea to cool, stir to speed cooling","Once ice has melted, strain out the tea leaves to obtain about 160 ml of jasmine green tea","Formal preparation","Choose a cup, preferably a transparent glass with a capacity of about 300 ml","Remove the flesh segments from the pomelo and peel off the outer skin to get the pulp","Place 130 g of pulp and 130 ml of jasmine green tea into a blender","Add 10 g of cane syrup (optional, if you prefer it sweeter)","Cover and blend for 20 seconds, then pour the mixture into the cup","Take a little pulp, tear it into small pieces, and scatter on the surface"]'::jsonb, '["Drink","Refreshing","Fruit tea","Quick","Sweet-sour","Beginner-friendly"]'::jsonb),
  ('howtocook:drink/菠萝咖啡特调/菠萝咖啡特调', 'en', 'Pineapple Coffee Special', 'Drinks', 'This special drink combines the rich aroma of coffee with the sweet and sour taste of pineapple. The bubbles are refreshing, the cream topping is smooth, and the layers of flavor are rich. Pineapple is rich in vitamin C and dietary fiber, and when paired with coffee, it can help refresh and energize. The difficulty level is moderate; just whip the cream and mix the liquids. It takes about 10 minutes in total to complete.', '[{"name":"Brewed coffee","unit":"ml"},{"name":"Pineapple juice","unit":"ml"},{"name":"Ice cubes","unit":"g"},{"name":"Soda water","unit":"ml"},{"name":"Cream","unit":"ml"},{"name":"Milk","unit":"ml"},{"name":"Sugar","unit":"g"},{"name":"Sea salt","unit":"g"},{"name":"Rum","unit":"ml"}]'::jsonb, '["Add ice, coffee, pineapple juice, and soda water to a glass in that order.","Whip the cream with sugar until soft peaks form. Add rum and milk, mixing until smooth and pourable.","Pour the cream over the mixture from step 1.","Sprinkle sea salt on top of the cream."]'::jsonb, '["Drinks","Sweet and Sour","Refreshing","Special","Quick","Afternoon Tea"]'::jsonb),
  ('howtocook:drink/酒酿醪糟/酒酿醪糟', 'en', 'Fermented Sweet Rice (Jiuniang)', 'Drinks', 'This is a traditional Chinese fermented dessert with a sweet, slightly intoxicating flavor and a light wine aroma. It helps strengthen the spleen and promote digestion. The process is simple and fun, though it requires fermentation time; actual hands-on work is only about 1 hour. Total preparation time is about 2 days.', '[{"name":"Glutinous rice","unit":"grams"},{"name":"Angel sweet rice yeast","unit":"grams"},{"name":"Water","unit":"grams"},{"name":"Water","unit":"grams"},{"name":"Warm water","unit":"ml"},{"name":"Osmanthus flowers","note":"to taste"},{"name":"Water","unit":"ml"}]'::jsonb, '["Wash 800g glutinous rice clean and put it in a rice cooker. Add 720g water and select the steam/cook mode.","After cooking, turn out the rice and spread it to cool. Use clean tools to cool it to 30°C (use a thermometer if possible; it should feel warm but not hot to the touch).","Dissolve 8g Angel sweet rice yeast in 20ml warm water (about 30°C). Sprinkle evenly over the glutinous rice and mix well.","Add 600g water to the rice to help mix the yeast evenly. Let sit for 2-3 minutes until the rice absorbs the water. This addition ensures the fermented rice will have plenty of liquid during the first fermentation.","Use a rolling pin to make a small well in the center of the rice (to allow the wine to collect).","Transfer the mixed rice into a clean container, gently press the surface flat, and seal tightly with a lid or plastic wrap.","Place in an environment at 28-32°C for 24-48 hours. Do not shake or move it during fermentation.","Signs of successful fermentation: clear wine seeps into the center well, the whole batch has a light wine aroma, no off-odors, no sourness.","After fermentation, refrigerate immediately (you can add osmanthus flowers during this step). Use clean utensils each time when serving. It can be refrigerated for 7-10 days.","For a second fermentation, add 500ml water to increase the yield (up to 800g water total).","The fermentation will continue. To stop it, steam for 10 minutes to sterilize, or refrigerate.","Wash 800g glutinous rice clean, soak in water for 6-8 hours (8-10 hours in winter) until grains are plump.","Drain the rice, place in a steaming cloth, and steam over water for 40-60 minutes. Every 20 minutes, open the lid and stir to ensure even cooking.","After steaming, turn out the rice and cool it. Add the yeast, then follow the same steps as above.","Of course, experienced makers can experiment with different grains. You can replace 20% of the glutinous rice with millet, oats, yellow rice, black glutinous rice, etc."]'::jsonb, '["Beverage","Sweet and lightly intoxicating","Fermented","Traditional Chinese","Appetizing and digestive","Beginner-friendly"]'::jsonb),
  ('howtocook:drink/酸梅汤（半成品加工）', 'en', 'Sour Plum Drink (Using Premix)', 'Drinks', 'Sour Plum Drink (Using Premix) is a sweet and sour, refreshing summer drink with traditional Beijing flavor. It helps quench thirst and aid digestion. The method is extremely simple—just stir in order. It''s easy for beginners and takes about five minutes.', '[{"name":"Drinking water","unit":"grams"},{"name":"Sour plum crystal solid drink","unit":"grams"},{"name":"Sugar cubes (optional)","unit":"grams"}]'::jsonb, '["Take 1177 grams of drinking water.","Add 60 grams of sour plum crystal solid drink, and stir clockwise with a spoon for 50 circles.","Add the remaining 60 grams of sour plum crystal solid drink, and stir clockwise with a spoon for another 50 circles.","Add 9 grams of sugar cubes, and stir clockwise with a spoon for 100 circles.","Add 48 grams of Beijing Erguotou liquor, and stir clockwise with a spoon for 30 circles."]'::jsonb, '["Beverage","Sweet and Sour","Beijing Flavor","Quick","Summer Refreshment","Stirring"]'::jsonb),
  ('howtocook:drink/酸梅汤/酸梅汤', 'en', 'Sour Plum Drink', 'Drinks', 'Sour Plum Drink is a traditional beverage that is sweet and sour, refreshing and cooling. It is especially invigorating when served chilled. The ingredients like dark plum, hawthorn, and licorice help stimulate salivation, quench thirst, aid digestion, and whet the appetite. The method is simple and beginner-friendly: just soak, boil, and chill. The whole process includes soaking, two rounds of boiling, and chilling, taking about 6 hours or more. It is recommended to prepare in advance.', '[{"name":"Water","unit":"liter"},{"name":"Smoked jujube","unit":"g"},{"name":"Smoked plum","unit":"g"},{"name":"Hawthorn slices (raw)","unit":"g"},{"name":"Yellow rock sugar","unit":"g"},{"name":"Licorice","unit":"g"},{"name":"Dried tangerine peel","unit":"g"},{"name":"Red cardamom","unit":"g"},{"name":"Dried osmanthus","unit":"g"}]'::jsonb, '["Rinse the ingredients (except dried osmanthus and rock sugar). Soak in 1.5 liters of water at room temperature for over 2 hours (except dried osmanthus and rock sugar).","Bring to a boil over medium-high heat. Cover, reduce to low heat, and simmer for 40 minutes. This is the first decoction.","Place rock sugar in a bowl. Strain the first decoction and pour the hot liquid over the sugar. Stir until the sugar dissolves.","Put the herbs back into the pot and add 600 ml of water. Bring to a boil over high heat. Cover, reduce to medium heat, and simmer for 20 minutes. This is the second decoction.","Finally, combine the second decoction with the rock sugar water while hot. When the mixture cools to 60-70°C, add dried osmanthus (do not exceed 80°C). Cover and let cool to room temperature, then refrigerate for at least 3 hours.","Strain out the dried osmanthus before serving. Sip slowly like tea. The drink is icy cold, with a pleasant sourness that awakens the palate, balanced sweetness, and a rich, lingering aftertaste."]'::jsonb, '["Beverages","Sweet and Sour","Boiled","Cooling","Iced","Traditional","Home-style"]'::jsonb),
  ('howtocook:drink/金汤力/金汤力', 'en', 'Gin and Tonic', 'Drinks', 'This is a classic gin cocktail. It tastes refreshing and slightly bitter, with the bright sourness of lemon and the fine bubbles of tonic water, making it light and invigorating. Although it mainly provides hydration and a bit of calories from alcohol, fresh lemon juice supplements vitamin C and helps refresh. The method is very simple, even a beginner can master it easily, and it takes only about 5 minutes to complete.', '[{"name":"Gin","unit":"ml"},{"name":"Tonic water","unit":"can"},{"name":"Lemon","unit":"piece"},{"name":"Ice","unit":"g"},{"name":"Fresh green leaves","note":"as needed (for garnish)"}]'::jsonb, '["Cut the lemon in half (with the knife perpendicular to the line connecting the lemon''s ends), then cut one slice from one half and set aside.","Cut the lemon halves in half again, then juice the lemon quarters using a citrus press into a container and set aside.","Choose a glass, preferably a clear glass with a capacity of 350-400 ml.","Place 100 g of ice at the bottom of the glass.","Pour in 30-40 ml of gin.","Pour in 15 ml of lemon juice (add more or all if you like it sour).","Stir well with a spoon.","Place the prepared lemon slice in the glass.","Slowly pour tonic water along the side of the glass until full (do not pour over the ice to avoid losing carbonation).","Gently lift and lower the spoon to mix the liquid (do not stir in circles to avoid losing carbonation).","Place a decorative green leaf on the surface (optional)."]'::jsonb, '["Beverage","Refreshing","Slightly Bitter","Quick","Cocktail"]'::jsonb),
  ('howtocook:drink/金菲士/金菲士', 'en', 'Gin Fizz', 'Drinks', 'A classic gin cocktail, sweet and sour with a refreshing fizz. Lemon provides rich vitamin C, balanced by cane sugar syrup. Very easy to make; even a beginner can whip it up in 5 minutes at home. Note: alcohol is harmful to health, drink in moderation.', '[{"name":"Gin","unit":"ml"},{"name":"Soda water","unit":"can"},{"name":"Lemon","unit":"piece"},{"name":"Cane sugar syrup","unit":"g"},{"name":"Ice cubes","unit":"g"},{"name":"Fresh green leaves","note":"for decoration, as needed"},{"name":"Shaker","note":"optional"}]'::jsonb, '["Cut the lemon in half (knife perpendicular to the line between the lemon''s ends), and cut one slice from one half for later use","Cut the remaining half in half again, then use a juicer to squeeze the juice from the 4 lemon wedges and set aside","Choose a glass, preferably a clear glass with a capacity of 350–400 ml","Place 100 g of ice cubes at the bottom of the glass","Pour in 30–40 ml of gin","Pour in 20 ml of lemon juice (add more if you like it sour, or use all of it)","Pour in 30–40 g of cane sugar syrup","Stir well with a spoon","Place the reserved lemon slice in the glass","Slowly pour soda water along the inner wall of the glass until full (do not pour over the ice to avoid losing fizz)","Use a spoon to gently lift and lower the liquid to stir evenly (do not stir in a circular motion to avoid losing fizz)","Place decorative green leaves on the surface (optional)","Pour the ice, gin, lemon juice, and cane sugar syrup into a shaker and shake well","Pour the shaken mixture into the glass (if the ice is too crushed, you may strain it out and add fresh ice)"]'::jsonb, '["Drink","Sweet-sour","Refreshing","Fizzy","Quick","Classic"]'::jsonb),
  ('howtocook:drink/长岛冰茶', 'en', 'Long Island Iced Tea', 'Drinks', 'Long Island Iced Tea is a classic cocktail that tastes like iced tea, with a smooth entry but high alcohol content. It''s not particularly nutritious, but an occasional drink can help you relax—just don''t overdo it. The recipe is very simple: just mix four base spirits, a liqueur, and juice in the right proportions. Even a beginner can make it easily. It takes about 5 minutes from prep to finish.', '[{"name":"Gin","unit":"ml"},{"name":"Tequila","unit":"ml"},{"name":"Vodka","unit":"ml"},{"name":"White rum","unit":"ml"},{"name":"Orange liqueur","unit":"ml"},{"name":"Lemon","unit":"piece"},{"name":"Lemon juice","unit":"ml"},{"name":"Maple syrup","unit":"ml"},{"name":"Cola","unit":"ml"},{"name":"Ice","unit":"g"}]'::jsonb, '["Cut the lemon in half and squeeze 30ml lemon juice into the glass.","Add to the glass in order:","15ml gin,","15ml tequila,","15ml vodka,","15ml white rum,","15ml orange liqueur;","Slowly pour 20ml maple syrup into the glass, stirring as you pour;","Add 75ml cola to the glass;","Add ice until the glass is full;","Gently stir for 20 seconds;","Enjoy."]'::jsonb, '["Drinks","Cocktail","Tipsy","Quick","Sweet and Sour","Classic"]'::jsonb),
  ('howtocook:meat_dish/农家一碗香/农家一碗香', 'en', 'Farmhouse One-Pot Stir-Fry', 'Meat Dishes', 'This is a savory and rice-friendly Hunan home-style stir-fry. The richness of fatty pork, the tenderness of egg, and the fragrance of green peppers blend together, creating layers of texture. Pork and egg provide high-quality protein, paired with green peppers for vitamin C, making it a balanced dish. Medium difficulty; pay attention to the heat when rendering fat and the order of seasoning. Beginners can master it with a little practice. Prep time: about 7 minutes, cooking time: about 10 minutes, total about 17 minutes.', '[{"name":"Pork","unit":"grams"},{"name":"Egg","note":"to taste"},{"name":"Green pepper","unit":"pieces"},{"name":"Bird''s eye chili","unit":"pieces"},{"name":"Garlic","unit":"slices"},{"name":"Ginger","unit":"slices"},{"name":"Doubanjiang (chili bean paste)","unit":"grams"},{"name":"Light soy sauce","unit":"ml"},{"name":"Sugar","unit":"grams"},{"name":"Oil","note":"to taste"}]'::jsonb, '["Preparation: Slice the pork, preferably separating the fatty and lean parts. Cut the green pepper and bird''s eye chili into sections. Smash the garlic cloves with the flat of the knife to make minced garlic. Shred the ginger. Crack the egg into a small bowl and beat with chopsticks.","Once prepared, start cooking. Add oil to a pan over low heat. When hot, pour in the beaten egg and stir-fry until just set. Transfer back to the small bowl and set aside.","Add a little more oil to the pan over low heat. Once hot, add the fatty pork slices and render the lard.","When the fat turns golden, increase the heat to medium, add the lean pork, and stir-fry.","When the lean meat changes color, add the shredded ginger, minced garlic, and doubanjiang (chili bean paste). Stir-fry evenly to coat the pork.","Add the green pepper and bird''s eye chili, and the cooked egg. Add light soy sauce and sugar. Continue stir-frying until the peppers are just tender but still crisp.","Serve!"]'::jsonb, '["Meat","Savory","Goes well with rice","Home-style","Stir-fry","Hunan"]'::jsonb),
  ('howtocook:meat_dish/冬瓜酿肉/冬瓜酿肉', 'en', 'Steamed Winter Melon Stuffed with Meat', 'Meat Dishes', 'Steamed winter melon stuffed with meat is a home-style dish that combines meat and vegetables. It is tender and smooth, with the savory meat filling complementing the sweet winter melon, refreshing and not greasy. Pork mince provides high-quality protein and essential amino acids, while winter melon helps clear heat, promote urination, and replenish water. The recipe is simple, even beginners can easily master it with a little practice on rolling the meat. From preparation to serving, it takes about 30 minutes.', '[{"name":"Winter melon","unit":"g"},{"name":"Pork mince","unit":"g"},{"name":"Egg","unit":"piece"},{"name":"Scallion","unit":"g"},{"name":"Minced scallion and ginger","unit":"g"},{"name":"Pepper","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Starch","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Water starch","unit":"g"}]'::jsonb, '["Peel the winter melon and cut into slices 25 cm long and 3 cm thick.","Place the sliced winter melon in a bowl, add 15g salt, rub it evenly, and let sit for 10 minutes.","While the winter melon sits, in another bowl combine the minced pork, minced scallion and ginger, 5g salt, 5g starch, pepper, light soy sauce, and pepper.","Using chopsticks, stir the meat mixture clockwise until the ingredients are evenly mixed (about 2 minutes).","Rinse the marinated winter melon (which will have softened) with clean water three times.","Take one slice of winter melon, roll it up, and stuff the meat filling inside.","Arrange the rolls on a plate, placing them around the edge.","Crack 1 egg into the center circle of the plate.","Place the plate in a regular iron steamer over boiling water, cover, and steam for 15 minutes.","Remove the lid and take out the steamed winter melon stuffed with meat.","Pour the liquid from the plate into a saucepan, add water starch and 50ml of water, bring to a boil.","Pour the sauce over the stuffed winter melon."]'::jsonb, '["Meat dish","Steamed","Home-style","Goes well with rice","Savory","Meat-vegetable combo"]'::jsonb),
  ('howtocook:meat_dish/冷吃兔', 'en', 'Cold Rabbit (Leng Chi Tu)', 'Meat Dishes', 'This is a classic Sichuan Zigong salt-gang dish. It''s spicy, numbing, and dry-fried, with firm and chewy rabbit meat that delivers an initial kick of heat followed by a savory finish. Rabbit is high in protein, low in fat, rich in lecithin and various amino acids, nutritious and easy to digest. The process involves handling multiple spices and strict heat control, which can be challenging for beginners. From prep to completion takes about 1.5 hours, but the flavor improves after resting overnight, making it worth preparing in advance.', '[{"name":"Rabbit meat","note":"as needed"},{"name":"Salt","unit":"g"},{"name":"MSG (or chicken powder)","unit":"g"},{"name":"Oyster sauce","unit":"g"},{"name":"Cooking wine","unit":"g"},{"name":"Garlic","unit":"head"},{"name":"Ginger","note":"same amount as garlic"},{"name":"Scallions/spring onions/onion","unit":"g"},{"name":"Dried chilies","note":"volume equal to rabbit meat"},{"name":"Green Sichuan peppercorns","note":"1 full bowl for 3 jin rabbit meat"},{"name":"Star anise","unit":"piece"},{"name":"Cinnamon stick","note":"a piece the size of a thumb"},{"name":"Bay leaves","unit":"piece"},{"name":"Sand ginger","note":"a piece the size of a soybean"},{"name":"White cardamom","unit":"piece"},{"name":"Cumin seeds","unit":"g"},{"name":"White sesame seeds","unit":"g"}]'::jsonb, '["Peel and mince garlic and ginger; set aside. Wash star anise, cinnamon stick, bay leaves, sand ginger, white cardamom, and cumin seeds; set aside.","Cut dried chilies into 2 cm sections, wash, and set aside.","Wash scallions/spring onions/onion; cut onion into small pieces.","Chop rabbit meat into 2 cm pieces. Add salt, cooking wine, and MSG (or chicken powder). Marinate for 15 minutes.","Heat oil in a wok. When oil reaches 40% hot (around 140°C), add scallions/spring onions/onion. Stir-fry over medium-low heat until fragrant and slightly charred, then remove them.","Turn up the heat to high. When oil reaches 80% hot (around 240°C), add rabbit meat. Reduce heat to medium-low and fry until the rabbit turns slightly golden brown, then remove.","Increase oil temperature again. Add dried chilies, green Sichuan peppercorns, star anise, cinnamon, bay leaves, sand ginger, white cardamom, and cumin seeds. Turn to low heat and fry until the chilies become crispy.","Return the rabbit meat to the wok. Add oyster sauce and stir-fry for a few minutes.","Turn off the heat. Add minced garlic, ginger, and white sesame seeds. Stir well to combine.","Let it rest overnight for better flavor."]'::jsonb, '["Meat dish","Spicy and numbing","Dry-fried","Zigong salt gang","Snack with alcohol","Fried and stir-fried"]'::jsonb),
  ('howtocook:meat_dish/凉拌鸡丝/凉拌鸡丝', 'en', 'Cold Shredded Chicken', 'Meat Dishes', 'A home-style cold dish with low oil and calories. The shredded chicken is tender and flavorful. The combination of Sichuan peppercorn oil and black vinegar creates a slightly numbing and sour refreshing taste, perfect for summer to relieve greasiness. Chicken breast is rich in high-quality protein and low in fat. The recipe is simple, even beginners can easily master it. It takes about 30 minutes from preparation to completion.', '[{"name":"Chicken breast (fresh or frozen)","unit":"g"},{"name":"Sichuan peppercorn oil","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Black vinegar","unit":"ml"},{"name":"Sugar","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Cooking wine","unit":"ml"},{"name":"Ginger","unit":"g"},{"name":"Cooled boiled water","note":"as needed"}]'::jsonb, '["Slice ginger, set aside.","Pour 4 liters of water into a pot.","Add chicken breast and ginger slices.","Pour in 20 ml of cooking wine.","Turn to high heat and bring to a boil without covering.","After boiling, reduce to medium heat and skim off the foam with a spoon.","Continue cooking for 5-7 minutes; cook for 5 minutes if fresh, 7 minutes if frozen.","The size of the chicken breast affects cooking time. Insert a chopstick into the chicken; if it goes in easily, the chicken is done. If not, extend cooking time.","Rinse the chicken breast with cooled boiled water to bring it to room temperature.","Shred the chicken breast into thin strips along the grain.","Prepare a bowl.","Add the prepared Sichuan peppercorn oil, light soy sauce, black vinegar, sugar, and salt to the bowl.","Stir the sauce until the sugar and salt are mostly dissolved.","Pour the sauce over the shredded chicken and mix well."]'::jsonb, '["Meat Dish","Cold Dish","Slightly Numbing and Sour","Refreshing","Low Calorie","Quick","Summer"]'::jsonb),
  ('howtocook:meat_dish/卤菜/卤菜', 'en', 'Braised Meat', 'Meat Dishes', 'This is a classic Chinese braised dish. The meat is tender and flavorful with a rich aroma. The marinade can be reused and becomes more fragrant over time. It is suitable as a cold dish, appetizer with alcohol, or paired with staples. The dish is rich in high-quality protein and various vitamins, with balanced nutrition. It requires a bit of patience, but the steps are clear and beginner-friendly. Pre-soaking to remove blood, preparing caramel color, and pressure cooking take about 1 hour, followed by overnight soaking for full flavor. Take out and slice the next day to enjoy.', '[{"name":"beef shank (or other meat)","unit":"g"},{"name":"spice pack","unit":"pack"},{"name":"soybean paste","unit":"ml"},{"name":"bean paste","unit":"ml"},{"name":"oyster sauce","unit":"ml"},{"name":"fermented bean curd","unit":"ml"},{"name":"onion","unit":"piece"},{"name":"ginger","unit":"g"},{"name":"garlic","unit":"g"},{"name":"dried chili peppers","unit":"g"},{"name":"light soy sauce","unit":"ml"},{"name":"dark soy sauce","unit":"ml"},{"name":"salt","unit":"g"},{"name":"sugar","unit":"g"},{"name":"beer","unit":"can"},{"name":"water","note":"enough"},{"name":"hot water","unit":"ml"},{"name":"vinegar","unit":"ml"},{"name":"sugar","unit":"ml"},{"name":"MSG/chicken essence","note":"to taste"},{"name":"braising liquid","unit":"ml"},{"name":"minced garlic","note":"to taste"},{"name":"chopped green onion","note":"to taste"},{"name":"white sesame seeds","note":"to taste"},{"name":"chili powder","note":"to taste"},{"name":"bird''s eye chili","note":"according to preference"},{"name":"sesame oil or Sichuan pepper oil","note":"a little"},{"name":"vegetable oil","note":"to taste"},{"name":"cucumber","note":"to taste"},{"name":"wood ear mushrooms","note":"to taste"},{"name":"fried peanuts","note":"to taste"},{"name":"cilantro","note":"to taste"}]'::jsonb, '["Soak the beef shank in cold water for more than 3 hours to remove blood.","Prepare caramel color: Add 30g sugar to a pan, heat on low until sugar melts and turns dark brown, add 150ml hot water, stir well, and set aside.","Cut the onion into chunks, crush the ginger and garlic, break the dried chili peppers into pieces, and set aside.","Add enough water to a pot, add the spice pack, onion, ginger, garlic, and dried chili peppers, bring to a boil over high heat.","Add 15ml each of soybean paste, bean paste, oyster sauce, and fermented bean curd, stir well.","Pour in the prepared caramel color and mix well.","Add 120ml light soy sauce and 60ml dark soy sauce, stir well.","Add 10-15g salt to season.","Pour in 1 can of beer (330ml) and bring to a boil again.","Blanch the beef shank in boiling water for 2-3 minutes, remove and rinse off any scum with hot water.","Place the blanched beef shank into the boiling marinade, ensuring the marinade covers all meat.","Cover with the pressure cooker lid, cook for 25-30 minutes after it starts steaming.","After cooking, do not open the lid; let it cool naturally and soak overnight (this will enhance the flavor).","Remove the braised meat and refrigerate to set.","Before serving, take out and slice; can be eaten directly or served cold with dressing.","How to reuse the marinade: After braising, strain the marinade, discard all solids, bring to a boil again to sterilize, cool, and store in refrigerator or freezer. When using, add seasonings according to the original ratio. (Add water based on the marinade''s condition.)","If stored properly, the marinade can be used for a long time and becomes more aromatic with age.","Important note: When braising vegetables, use a separate portion of the marinade and do not reuse it after braising vegetables.","Mix minced garlic, chopped green onion, white sesame seeds, and chili powder in a 1:1:1:1 ratio. Add bird''s eye chili according to preference. Heat vegetable oil with a little sesame oil or Sichuan pepper oil, pour it over the seasonings in batches. Then add 10ml each of light soy sauce, vinegar, and oyster sauce, 5ml sugar, MSG/chicken essence, and finally 15ml braising liquid. Mix well.","When serving cold, pair with smashed cucumber, wood ear mushrooms, fried peanuts, cilantro, etc."]'::jsonb, '["Meat Dish","Braised","Soy-sauce aroma","Goes with alcohol","Home-style","Cold dish"]'::jsonb),
  ('howtocook:meat_dish/口水鸡/口水鸡', 'en', 'Mouthwatering Chicken', 'Meat Dishes', 'Mouthwatering Chicken is a classic Sichuan cold dish. The chicken, coated in chili oil, is icy, bouncy, numbing, spicy, and aromatic. It''s appetizing and refreshing in summer. Chicken is rich in high-quality protein, paired with crushed peanuts and spices for energy and flavor. Medium difficulty; pay attention to the cooking time of the chicken and the seasoning of the chili oil. Suitable for cooks with some experience. From preparation, boiling, cooling to pouring the sauce, it takes about 1.5 hours.', '[{"name":"Chicken","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Chili powder","unit":"g"},{"name":"Sichuan peppercorns","unit":"g"},{"name":"Peanuts","unit":"g"},{"name":"Scallion","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Garlic","unit":"g"},{"name":"Sugar","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Vinegar","unit":"ml"},{"name":"MSG","unit":"g"},{"name":"Sichuan pepper powder","unit":"g"},{"name":"Cilantro","unit":"g"},{"name":"Salt","note":"to taste"},{"name":"Sesame oil","note":"to taste"}]'::jsonb, '["Slice ginger, set aside 1 scallion, and 15 Sichuan peppercorns.","Wash the chicken, place it in a pot, add enough water to cover the chicken, add ginger slices, scallion, and Sichuan peppercorns. Bring to a boil over high heat.","After boiling, reduce to medium-low heat and cook for 20 minutes, then turn off the heat.","Remove the chicken and place it in ice water until completely chilled.","Take out the chicken, cut into pieces, and arrange on a plate. Set aside.","Heat the pan over low heat, add peanuts, and roast until the skins crack. (Keep stirring to avoid burning.)","Cut one scallion into sections, mince the garlic, take 15 Sichuan peppercorns, peel and chop the peanuts.","Heat oil in the pan, add scallion sections, Sichuan peppercorns, and half of the minced garlic. Stir-fry until fragrant.","When the oil is about 80% hot, turn off the heat and strain out the hot oil.","Pour the hot oil into a bowl with chili powder, stir, then strain to obtain the chili oil.","Add the remaining minced garlic, light soy sauce, vinegar, salt, MSG, sugar, sesame oil, and Sichuan pepper powder to the chili oil. Mix well and let cool.","Sprinkle chopped peanuts over the chicken, pour the chili oil over the chicken, and garnish with cilantro. Serve."]'::jsonb, '["Meat Dish","Numbing and Spicy","Cold Dish","Sichuan Cuisine","Goes with Alcohol","Appetizing"]'::jsonb),
  ('howtocook:meat_dish/可乐鸡翅', 'en', 'Cola Chicken Wings', 'Meat Dishes', 'These cola chicken wings are shiny red, tender, and have a savory-sweet taste. They''re a creative dish loved by families. Chicken wings are packed with protein and fat, and simmering them with cola makes the meat super tender. Cooking them requires a good handle on frying and reducing the sauce—a bit challenging for newbies, but just follow the steps and you''ll nail it. It takes about 40 minutes from start to finish.', '[{"name":"Chicken wings","unit":"pieces"},{"name":"Cola","unit":"ml"},{"name":"Sugar","unit":"g"},{"name":"Light soy sauce","unit":"g"},{"name":"Dark soy sauce","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Ginger","unit":"slices"},{"name":"Cooking wine","unit":"ml"},{"name":"Scallions","note":"to taste"}]'::jsonb, '["Put chicken wings in a pot, add cold water to cover. Add 1 slice of ginger and 10-20 ml of cooking wine. Bring to a boil over high heat (about 2 minutes), skim off the foam, then drain.","This step is for fresh chicken wings. For freshly bought wings, simply score them and marinate with light soy sauce.","Remove the chicken wings, score each side twice with a knife. Marinate with about 10 g light soy sauce for 10 minutes (enough to coat the surface).","Heat oil in the pan over low heat again, first sauté the remaining ginger slices until fragrant, then add the marinated chicken wings. Pan-fry until golden, then flip (until both sides are golden). Stir the wings and ginger with a spatula 4-5 times (to prevent sticking).","When wings are golden, pour in cola to cover them. Bring to a boil over high heat, then skim off the black foam (including blood). Add the scallion knot.","Seasoning: Add 2 g salt, 10 g sugar, 3 g light soy sauce (you can add 3 g dark soy sauce for color).","When the scallion knot turns yellow, remove it along with the ginger slices. Turn to medium heat and continue simmering the cola chicken wings.","When the cola reduces to a syrupy consistency, turn to low heat to let the sauce cling to the wings. Remove from heat and plate."]'::jsonb, '["Meat Dish","Salty-Sweet","Pan-fry","Braise","Home-style","Rice Companion"]'::jsonb),
  ('howtocook:meat_dish/台式卤肉饭/台式卤肉饭', 'en', 'Taiwanese Braised Pork Rice', 'Meat Dishes', 'Taiwanese braised pork rice is a fragrant Taiwanese home-cooked dish. The meat strips are tender and flavorful, the sauce is amber and glossy, poured over hot rice for a mouthful of savory fat. Rich in high-quality protein, collagen, and carbs, it quickly replenishes energy. The recipe is very beginner-friendly. Just prepare the ingredients and master the heat. It takes about 1.5 hours total, with only half an hour of hands-on work; the rest is slow simmering.', '[{"name":"Shallots","unit":"g"},{"name":"Pork belly with skin","unit":"g"},{"name":"Eggs","unit":"piece"},{"name":"Cooking oil","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Rice wine"},{"name":"Garlic","unit":"g"},{"name":"Bay leaves","unit":"piece"},{"name":"Star anise","unit":"piece"},{"name":"Rock sugar","unit":"g"},{"name":"White pepper powder","unit":"g"},{"name":"Five-spice powder","unit":"g"},{"name":"Rice","note":"to taste"}]'::jsonb, '["Cut the pork belly with skin into thin strips of $0.7cm (length) \\times 0.7cm (width) \\times 2.5cm (height)$.","Mince shallots and garlic; set aside.","Boil eggs until hard, peel, and score the whites with a knife (for better flavor absorption); set aside.","Heat the wok over high heat, add 15 ml cooking oil, and swirl to coat the bottom.","The oil prevents the pork belly from sticking when first added. Wait 5 seconds for the oil to heat slightly.","Add the pork belly strips and stir-fry until the meat turns slightly white. Drizzle 10 ml rice wine along the wok edge. Continue stir-frying until the pork stops releasing fat.","Add the minced shallots to the wok and stir-fry for 1 minute until fragrant.","Add the minced shallots to the wok and stir-fry for 30 seconds.","Push the pork to the side, add rock sugar, and heat until melted and bubbly into caramel. Then mix with the pork to coat evenly.","Add light soy sauce and stir-fry until fragrant.","Splash in 25 ml rice wine, then add water until it covers the pork. Add white pepper powder, five-spice powder, star anise, bay leaves, and boiled eggs. Bring to a boil, then reduce to low heat and braise for 1 hour.","Note: Different soy sauces vary in saltiness. Taste the sauce while braising; add more soy sauce if too sweet, or a bit of sugar or water if too salty.","During simmering, stir and check every 15 minutes to prevent sticking.","If it becomes too dry, add 100 ml water and continue simmering.","After 1 hour, increase heat to high to reduce the sauce until thick and glossy amber, then done.","After braising, serve a bowl of rice, ladle the tender braised pork over the rice, add the braised egg, and enjoy."]'::jsonb, '["Meat Dish","Taiwanese","Home-cooked","Goes great with rice","Savory","Braising"]'::jsonb),
  ('howtocook:meat_dish/咕噜肉', 'en', 'Sweet and Sour Pork', 'Meat Dishes', 'Sweet and Sour Pork is a classic Cantonese home-style dish. It''s sweet and sour, appetizing, crispy on the outside and tender on the inside. The fruity aroma of pineapple makes the pork refreshing and cuts through the richness. Pork provides high-quality protein, while green pepper and pineapple add vitamins and dietary fiber. The tricky part is controlling the frying temperature, which is a bit challenging for beginners, but following the steps will ensure success. From marinating to serving, it takes about 40 minutes, making it a great quick dish to serve with rice for the family.', '[{"name":"Pork shoulder","unit":"g"},{"name":"Green pepper","unit":"g"},{"name":"Canned pineapple slices","unit":"g"},{"name":"Salt","unit":"teaspoon"},{"name":"Ketchup","unit":"tablespoon"},{"name":"White vinegar","unit":"teaspoon"},{"name":"Minced garlic","unit":"tablespoon"},{"name":"Light soy sauce","unit":"teaspoon"},{"name":"Cornstarch","unit":"teaspoon"},{"name":"White sugar","unit":"tablespoon"},{"name":"Water","unit":"ml"},{"name":"Oil","note":"as needed"}]'::jsonb, '["Wash the pork shoulder (100g), then pat dry with paper towels. Cut the pork into pieces slightly smaller than the desired final size.","Marinate the pork shoulder with salt (1/2 tsp) for 20 minutes.","Chop the green pepper (25g).","Cut the canned pineapple slices (75g) into pieces.","In a bowl, combine ketchup (4 tbsp), white vinegar (2 tsp), minced garlic (1 tbsp), light soy sauce (½ tsp), cornstarch (2½ tsp), white sugar (2 tbsp), salt (¼ tsp), and water (200 ml). Mix well to make the sauce.","Coat the pork pieces with cornstarch (6 tbsp).","Add oil (500 ml) and heat over medium heat.","Fry the pork pieces in the oil over medium heat for 5 minutes, then remove and set aside.","Add the pork pieces back, then fry over high heat for 1 minute, turning as needed.","Add oil (1 tsp) and the sauce, heat over medium heat for 3 minutes.","Add the green pepper and pineapple, heat over high heat for 2 minutes.","Toss the fried pork pieces with the sauce until well coated. Serve."]'::jsonb, '["Meat Dish","Sweet and Sour","Cantonese","Home-style","Goes with rice","Deep-fried"]'::jsonb),
  ('howtocook:meat_dish/咖喱肥牛/咖喱肥牛', 'en', 'Curry Beef Rolls', 'Meat Dishes', 'Curry Beef Rolls is a rich and savory home-cooked dish that goes well with rice. The spicy aroma of curry combines with the fatty fragrance of beef rolls, paired with potatoes, carrots, and other vegetables, resulting in a soft and hearty texture. Rich in protein, vitamins, and calcium, it offers a balanced mix of meat and vegetables. The recipe is simple and beginner-friendly, typically taking only 40 minutes to serve, making it great for lunchboxes.', '[{"name":"Bay leaves","unit":"piece"},{"name":"Milk","unit":"ml"},{"name":"Onion","unit":"g"},{"name":"Carrot","unit":"g"},{"name":"Potato","unit":"g"},{"name":"Beef rolls","unit":"g"},{"name":"Curry blocks","unit":"block"},{"name":"Cooking oil","unit":"ml"}]'::jsonb, '["Cut the onion into strips, and the carrots and potatoes into chunks. Set aside.","Bring a pot of water to a boil. Add the beef rolls, skim off the foam, then drain and set aside.","Heat the pan, add 10-15ml of cooking oil, and wait 10 seconds for the oil to heat up.","Add the onion and stir-fry until soft and translucent.","Add the potatoes and carrots, and stir-fry for 2 minutes.","Add cold water until all ingredients are just submerged.","Add the bay leaves and curry blocks to the pot, cover with a lid. Once the water boils, reduce the heat and simmer until the potatoes and carrots are tender (check with chopsticks).","Add the beef rolls and milk, cover, and simmer on low heat for 2-3 minutes. Serve. Stir gently with a spoon to avoid breaking the beef rolls."]'::jsonb, '["Meat Dish","Rich and Savory with Rice","Stew","Home-style","Quick","Curry"]'::jsonb),
  ('howtocook:meat_dish/商芝肉', 'en', 'Shangzhi Pork', 'Meat Dishes', 'Shangzhi Pork is a traditional dish from Shangxian County, Shaanxi. It features a reddish color, tender texture, rich but not greasy, with the unique fragrance of shangzhi (a type of fern). Pork provides high-quality protein and fat, while the fern vegetable shangzhi adds dietary fiber and various trace elements. This dish has elaborate steps and requires knife skills and heat control, suitable for those with some cooking experience. From preparation to serving, it takes about 2.5 hours.', '[{"name":"Pork belly with skin","unit":"g"},{"name":"Shangzhi (fern)","unit":"g"},{"name":"Scallion","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Star anise","unit":"piece"},{"name":"Honey","unit":"g"},{"name":"Vinegar","unit":"g"},{"name":"Cooking wine","unit":"g"},{"name":"MSG","unit":"g"},{"name":"Soy sauce","unit":"g"},{"name":"Egg crepe","unit":"sheet"},{"name":"Salt","unit":"g"},{"name":"Chicken broth","unit":"g"},{"name":"Sesame oil","unit":"g"},{"name":"Lard","unit":"g"}]'::jsonb, '["Scrape and wash the pork clean, put it in a pot and boil until six-tenths done (turns white). Remove while hot and brush the skin with honey and vinegar.","Put lard in a wok and heat over high heat to 80% hot (about 200°C, oil surface is calm with much blue smoke). Add the pork skin-side down and fry until golden red. Remove and soak in the pot with cold meat broth (the previous boiling pot) until soft. Place on a cutting board and slice into 10 cm long, 0.6 cm thick pieces. Still skin-side down, arrange neatly in a steaming bowl.","Cut 5g scallion into 2.4 cm segments, and another 5g into 2.4 cm diagonal slices. Peel and wash ginger: cut 1.5g into slices, mince 5g. Cut the egg crepe into isosceles triangles with 2.4 cm sides.","Put shangzhi into boiling water and cook until soft, remove, discard tough stems and impurities, wash, cut into 3 cm segments. Place in a bowl, add 5g soy sauce, 1g salt, 10g lard, mix well, and spread over the pork slices. In a small bowl, combine 100g chicken broth, 5g soy sauce, 0.5g salt, 15g cooking wine, stir, and pour into the steaming bowl. Add ginger slices, scallion segments, and star anise. Steam over high heat for about half an hour, then turn to low heat and continue steaming for about 1.5 hours until tender. Remove, discard ginger, scallion, and star anise. Pour out and strain the original juice. Invert the pork onto a soup plate.","In a wok, add 100g chicken broth and the strained juice. Bring to a boil over high heat. Add ginger mince, scallion slices, and MSG, stir well. Add the egg crepe pieces, drizzle with sesame oil, and pour over the pork in the soup plate. Serve."]'::jsonb, '["Meat Dish","Shaanxi Cuisine","Steamed","Savory","Banquet","Traditional"]'::jsonb),
  ('howtocook:meat_dish/啤酒鸭/啤酒鸭', 'en', 'Beer-Braised Duck', 'Meat Dishes', 'This is a unique home-style dish. The duck meat is tender and savory, with a subtle aroma of beer—warming but not greasy. Duck is rich in protein, and beer helps remove any gamey smell while enhancing flavor. It''s beginner-friendly, taking about 1 hour from prep to serving.', '[{"name":"Duck","unit":"whole"},{"name":"Beer","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Ginger","unit":"slice"},{"name":"Garlic","unit":"clove"},{"name":"Rock sugar","unit":"g"},{"name":"Dried chili peppers","unit":"piece"},{"name":"Cooking wine","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Chicken bouillon","unit":"g"},{"name":"Cloves","unit":"piece"},{"name":"Star anise","unit":"piece"},{"name":"Bay leaves","unit":"piece"},{"name":"Doubanjiang (fermented broad bean paste)","unit":"g"}]'::jsonb, '["Cut the duck into 3 cm pieces. Blanch the duck in cold water with ginger slices and cooking wine. Drain and set aside.","Heat the wok with about 100ml cooking oil over high heat. Add the duck and stir-fry until browned.","When the duck is fully changed color (pale), push it to one side. Add doubanjiang and sugar, stir-fry on low heat until fragrant and caramelized.","Add cloves, star anise, bay leaves, dried chili peppers, light soy sauce, dark soy sauce, garlic. Stir-fry until fragrant.","Pour in the beer to cover the duck. Add salt and chicken bouillon. Cook over medium heat for 30 minutes (if you prefer softer meat, cook for an additional 5 minutes).","Serve on a plate and enjoy."]'::jsonb, '["Meat Dish","Savory","Braise","Sichuan Cuisine","Home-style","Goes with rice"]'::jsonb),
  ('howtocook:meat_dish/回锅肉/回锅肉', 'en', 'Twice-Cooked Pork', 'Meat Dishes', 'Twice-Cooked Pork is a classic Sichuan dish, using pork belly or rear leg meat. The finished dish is red and bright, with translucent and slightly curled fat, dry and fragrant lean meat, rich but not greasy, savory with a hint of spiciness, carrying the complex aroma of garlic sprouts and broad bean paste. Pork is rich in high-quality protein and essential fatty acids, and with green and red peppers and garlic sprouts, it provides vitamins. This dish has many steps—boiling, slicing, stir-frying—requiring some control over heat and knife skills, but beginners can succeed if they follow the process. The total time is about 40 minutes.', '[{"name":"pork belly","unit":"lb","note":""},{"name":"scallions","unit":"stalks","note":""},{"name":"ginger","unit":"g","note":""},{"name":"green and red peppers","unit":"g","note":""},{"name":"garlic sprouts","unit":"bunch","note":""},{"name":"cooking wine","unit":"ml","note":""},{"name":"broad bean paste","unit":"ml","note":""},{"name":"light soy sauce","unit":"ml","note":""},{"name":"MSG","unit":"g","note":""}]'::jsonb, '["Heat the pan, press the pork belly firmly against the pan with your hand to sear the skin.","This step is to treat the sweat glands on the skin (or ask the butcher to burn the skin; ignore if you like the glands).","Scrub the skin clean with a steel wool, removing all carbonized black parts; otherwise, it will be bitter.","Put the pork belly in a pot, add enough cold water to cover it, then add ginger slices, cooking wine, and scallions (tie 2 scallions into a knot).","Bring to a boil over high heat, skim off the foam, and continue to boil for 15 minutes, until the lean part can be easily pierced with chopsticks.","Cut green and red peppers into rings.","Cut garlic sprouts into sections.","Slice ginger into small thin pieces.","Mix 5ml broad bean paste and 5ml light soy sauce in advance.","Remove the cooked pork belly and cool it in cold water.","Dry the pork belly, then slice it into 2mm thin slices with fat on top and lean on bottom (thicker slices will have poor texture and be greasy).","Heat the pan, add a thin layer of oil to coat the pan.","Stir-fry the pork belly slices until the fat turns translucent and the slices are slightly curled (like lamp holders; rear leg meat works best).","Add the broad bean paste-soy sauce mixture and 5g MSG, stir-fry for 15 seconds.","Add green and red pepper rings and small ginger slices, then add another 5ml broad bean paste, stir-fry for 30 seconds.","Add garlic sprouts and stir-fry for 60 seconds.","Plate and serve.","If using frozen pork belly, thaw for 0.5 hour; if fresh, refrigerate for 1 hour, then slice into 2-5mm thin slices.","Over medium heat, dry-fry the peppers in the pan for 30-45 seconds, then remove them.","Heat the pan, add a thin layer of oil to coat, then add ginger slices and stir-fry for 15 seconds.","Add the pork belly slices, stir-fry every 10 seconds, until they turn golden brown (the longer you stir-fry, the firmer the texture).","Add the previously dry-fried peppers, 10ml broad bean paste, and light soy sauce to season, continue stir-frying for 60 seconds.","Add the cut garlic sprouts and stir-fry for 10 seconds.","Plate and serve."]'::jsonb, '["Meat Dish","Sichuan Cuisine","Home-style","Rice Companion","Stir-fry","Savory and Slightly Spicy"]'::jsonb),
  ('howtocook:meat_dish/土豆炖排骨/土豆炖排骨', 'en', 'Braised Pork Ribs with Potatoes', 'Meat Dishes', 'The ribs are tender and fall off the bone, the potatoes are soft and flavorful, with a rich savory sauce that is slightly sweet and spicy. It is a typical northern home-style braised dish. Rich in protein, calcium, and carbohydrates, nutritionally balanced. Preparation is somewhat challenging, requiring mastery of caramelizing sugar and heat control, but the steps are clear and beginners can try it. The whole process takes about 1.5 hours.', '[{"name":"Pork Ribs","unit":"g"},{"name":"Potatoes","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Scallions","unit":"g"},{"name":"Cooking Wine","unit":"ml"},{"name":"White Sugar","unit":"g"},{"name":"Dried Chilies","unit":"g"},{"name":"Star Anise","unit":"g"},{"name":"Sichuan Peppercorns","unit":"g"},{"name":"Cinnamon Stick","unit":"g"},{"name":"Light Soy Sauce","unit":"ml"},{"name":"Dark Soy Sauce","unit":"ml"},{"name":"Oyster Sauce","unit":"ml"},{"name":"Soybean Paste","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Cooking Oil","unit":"ml"},{"name":"Boiling Water","unit":"ml"}]'::jsonb, '["Prepare potatoes: Peel 300g potatoes and cut into irregular rolling cuts. Immediately soak in a bowl of water to prevent oxidation and blackening. Set aside.","Prepare ginger and scallions: Slice 30g ginger into thin slices (divide into two portions of 15g each). Prepare 25g scallions: tie 15g into a knot, finely chop the remaining 10g. Set aside.","Prepare sauce bowl (one-click use): In a small bowl, add 10ml light soy sauce, 5ml dark soy sauce, 5ml oyster sauce, 5ml soybean paste. Stir thoroughly. Place within easy reach.","Prepare spice dish (one-click use): In a small dish, place 5g dried chilies, 1g star anise (about 1-2 pieces), 1g Sichuan peppercorns (about 10), 1g cinnamon stick (a small piece), and the 15g ginger slices set aside earlier. Set aside.","Start water boiling: Press the electric kettle to boil 700ml water. (Ensure the water is ready when needed.)","Cold water blanching: Place 750g pork ribs in cold water. Add 15g scallion knot, 15g ginger slices, 15ml cooking wine. Bring to a boil over high heat, then continue boiling for 2 minutes to draw out blood foam.","Hot rinse, cold prevent: Drain the ribs. Rinse off any remaining foam with hot water (cold water will cause the meat to shrink and harden).","Thoroughly dry (prevent splatter): Pat the ribs completely dry with paper towels. Place on a plate near the wok (to prevent oil splatter when adding to hot caramel).","Caramelize sugar: Heat oil in wok over medium-low heat, add 20ml cooking oil. Add 10g white sugar and stir constantly. Cook until sugar completely melts, bubbles, and turns a reddish-brown caramel color.","Color and sear: Quickly add the dried 750g ribs and turn to medium-high heat. Stir-fry for 2-3 minutes until ribs are lightly golden and evenly coated with caramel.","One-click aromatics: Clear a small space in the wok, add the spice dish directly. Stir-fry in the hot oil for about 10 seconds to release fragrance.","One-click seasoning: Drizzle the remaining 10ml cooking wine along the edge of the wok to create wok hei. Then pour in the sauce bowl. Stir-fry for about 30 seconds until ribs are fully coated and fragrant.","Add water and braise: Add 700ml boiling water (enough to submerge ribs). Bring to a boil over high heat. Cover, reduce to low heat, and simmer for 40 minutes.","Add potatoes: After 40 minutes, uncover. Drain the 300g potatoes from water and add to the pot. Re-cover and simmer for another 15-20 minutes until potatoes are easily pierced with a chopstick.","Season and reduce sauce: Uncover, add 3g salt (taste and adjust if needed). Turn to high heat and stir-fry to reduce sauce for 3-5 minutes until thickened and coats the ribs and potatoes. Turn off heat.","Garnish and serve: Plate the dish and sprinkle the reserved 10g chopped scallions on top as garnish."]'::jsonb, '["Meat Dish","Savory Sauce","Mildly Spicy","Braised","Northern","Rice Companion","Home-style"]'::jsonb),
  ('howtocook:meat_dish/奶酪培根通心粉/奶酪培根通心粉', 'en', 'Cheese Bacon Macaroni', 'Meat Dishes', 'Cheese Bacon Macaroni is a classic American home-style dish. Rich and creamy cheese coats the chewy macaroni, paired with crispy bacon, savory and satisfying. Rich in protein and calcium, but high in calories and fat, so it''s recommended to enjoy occasionally. Making it requires some patience; mastering the basic white sauce and heat control can be a bit challenging for beginners, overall difficulty is medium. Without baking, it can be served in about 30 minutes. If baking, additional preheating and baking time is needed, total about 1 hour.', '[{"name":"macaroni","unit":"g"},{"name":"cheese","unit":"g"},{"name":"cheese (for baking)","unit":"g"},{"name":"meat","unit":"g"},{"name":"onion","unit":"g"},{"name":"butter","unit":"g"},{"name":"flour","unit":"g"},{"name":"milk","unit":"ml"},{"name":"garlic","unit":"clove"}]'::jsonb, '["Grate the cheese into fine crumbs.","Cut the onion into strips.","Cook the macaroni in slightly salted water for 6 minutes.","Medium heat.","Put butter in the pan and wait until melted.","Add the onion.","When the onion softens, add the garlic.","After the garlic aroma comes out, add the meat and wait 5 seconds.","Low heat.","Add milk in four batches, stirring for 5 seconds after each addition.","Add flour and stir thoroughly.","Add cheese and stir until well combined.","Mix the macaroni with the cheese sauce.","If not baking, you can eat it directly.","Baking:","Preheat oven to 180°C.","Spread the additional 50g cheese on top of the macaroni.","After the oven preheats to 180°C, put in the macaroni.","Bake until golden brown on top, about 24 minutes."]'::jsonb, '["meat dish","creamy","savory","baked","American","home-style"]'::jsonb),
  ('howtocook:meat_dish/姜炒鸡/姜炒鸡', 'en', 'Stir-fried Chicken with Ginger', 'Meat Dishes', 'Stir-fried Chicken with Ginger is a Hunan-style rice-wrecking dish. The chicken is dry-fried and flavorful, with rich ginger aroma, spicy but not greasy. Chicken is high in quality protein, and ginger helps dispel cold, warm the stomach, and stimulate appetite. The recipe is simple, even beginners can master it easily. From marinating to serving, it takes about 1 hour.', '[{"name":"Chicken","unit":"whole"},{"name":"Ginger","unit":"g"},{"name":"Beer","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Bird''s eye chilies","unit":"piece"},{"name":"Beauty peppers","unit":"piece"},{"name":"Pickled chilies","unit":"piece"},{"name":"Garlic","unit":"head"}]'::jsonb, '["Cut the chicken into 1cm pieces as much as possible, wash and drain, then marinate with light soy sauce and cooking wine for 30 minutes.","First heat the wok over high heat until it just starts to smoke, add cooking oil, wait 5 seconds.","Add ginger slices, turn to medium heat and stir-fry for 30 seconds.","Add the chicken pieces and stir-fry for 3 minutes, until the moisture is dry and the chicken oil is released.","Add the chopped chilies and garlic cloves, add salt and dark soy sauce, continue stir-frying for 30 seconds.","Pour in beer, simmer over medium-low heat for 2 minutes.","Increase heat to high to reduce the sauce, then serve."]'::jsonb, '["Meat Dish","Hunan Style","Rice-Wrecking","Spicy","Stir-fry","Home-style"]'::jsonb),
  ('howtocook:meat_dish/姜葱捞鸡/姜葱捞鸡', 'en', 'Ginger and Scallion Chicken', 'Meat Dishes', 'Ginger and Scallion Chicken is a classic Cantonese home-cooked dish. The chicken is tender and juicy, with a rich aroma of scallion and ginger. It is savory and goes well with rice. Chicken thighs provide high-quality protein, and the combination with ginger and scallion warms the stomach and stimulates appetite. The cooking methods are mainly steaming and hand-shredding. The steps are clear and easy for beginners. It takes about 40 minutes from preparation to completion.', '[{"name":"Chicken thighs","unit":"pieces"},{"name":"Salt-baked chicken powder","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Scallions","unit":"stalks"},{"name":"Salt","unit":"g"},{"name":"Sugar","unit":"g"},{"name":"Oil","unit":"ml"}]'::jsonb, '["Wash four chicken thighs clean and place them in a bowl.","Add salt-baked chicken powder and 5ml oil to the bowl, mix well.","Let the chicken thighs marinate for 15 minutes. Meanwhile, prepare a steamer and bring water to a boil.","After marinating, place the chicken thighs in the steamer and steam for 20 minutes.","Cut the ginger according to personal preference into 1) ginger paste, 2) ginger shreds, or 3) ginger pieces.","Cut the scallions into 0.5 cm pieces.","Put the scallions and ginger into a dipping bowl, and add salt and sugar.","Pour the remaining oil into another pot and heat until 60-70% hot.","Pour the hot oil over the scallions and ginger in the bowl.","After steaming, shred the chicken thighs into strips, not too thin, about 1 cm thick.","Pour the ginger-scallion oil over the shredded chicken and mix well."]'::jsonb, '["Meat Dish","Cantonese","Steamed","Hand-shredded","Savory","Goes well with rice","Quick"]'::jsonb),
  ('howtocook:meat_dish/孜然牛肉', 'en', 'Cumin Beef', 'Meat Dishes', 'Cumin Beef is a spicy and tender home-style stir-fry. The rich cumin flavor perfectly combines with the softness of beef and the crispness of green peppers. Beef is rich in high-quality protein and iron, paired with green peppers to supplement vitamins, making it nutritionally balanced. Preparation requires some knife skills and heat control, suitable for enthusiasts with basic cooking experience. Including marinating and prepping, it takes about 45 minutes from start to table.', '[{"name":"Beef tenderloin or chuck","unit":"g"},{"name":"Green pepper","unit":"piece"},{"name":"Cumin","unit":"g"},{"name":"Bird''s eye chili","unit":"piece"},{"name":"Light soy sauce","unit":"ml"},{"name":"Starch","unit":"g"},{"name":"Oil","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Scallion","unit":"stalk"}]'::jsonb, '["First, chop the bird''s eye chilies and put them together with cumin seeds into a mortar, pound into granules for better flavor. If short on time, you can skip the pounding step.","Cut off the head and remove seeds of the green pepper (keep seeds if you like it spicy), then shred. Cut the scallion into sections.","Thaw the beef in advance, rinse with water, and pat dry with kitchen paper. Cut the beef into slices along the grain.","Then marinate the beef: add light soy sauce, starch, and oil, mix well, and let it sit for 30 minutes. You can also refer to learn marinating methods.","Heat oil in a wok, add scallion, stir-fry until fragrant, then add the marinated beef and stir-fry.","When the beef changes color, evenly add the cumin and chili granules and stir-fry until cooked through.","Then add the shredded green pepper, stir-fry until just cooked, then add salt.","Stir-fry over high heat for 1 minute, then turn off the heat and continue stirring for 30 seconds to ensure even heat, then serve."]'::jsonb, '["Meat Dish","Spicy","Home-style","Stir-fry","Rice-friendly","Cumin"]'::jsonb),
  ('howtocook:meat_dish/宫保鸡丁/宫保鸡丁', 'en', 'Kung Pao Chicken', 'Meat Dishes', 'This iconic Sichuan dish features a numbing-spicy and tangy flavor profile, with a hint of sweetness and sourness. The aroma of dried chilies and Sichuan peppercorns permeates the tender chicken cubes and crispy peanuts, creating a rich texture. It is rich in high-quality protein and unsaturated fats, making it an appetizing dish that pairs well with rice. The recipe includes both a simple and an advanced version, friendly for beginners. Just plan ahead for the marinating time. From preparation to serving, it takes about 1.5 hours.', '[{"name":"Chicken leg (or chicken breast)","unit":"piece"},{"name":"Scallion","unit":"stalk"},{"name":"Ginger slices","unit":"g"},{"name":"Dried chilies","unit":"g"},{"name":"Erjingtiao chilies","unit":"piece"},{"name":"Cooked peanuts","unit":"g"},{"name":"Raw peanuts","note":"to taste"},{"name":"Sichuan peppercorns","unit":"g"},{"name":"Light soy sauce","unit":"g"},{"name":"Dark soy sauce","unit":"g"},{"name":"Zhenjiang vinegar","unit":"g"},{"name":"Sugar","unit":"g"},{"name":"Cooking wine","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Chicken bouillon","unit":"g"},{"name":"Starch","unit":"g"},{"name":"Starch (for slurry)","unit":"g"},{"name":"Vegetable oil","unit":"g"},{"name":"Sesame oil","unit":"g"},{"name":"Doubanjiang (fermented broad bean paste)","unit":"g"},{"name":"Asparagus lettuce","unit":"g"},{"name":"Chili oil","unit":"g"},{"name":"Boiling water","unit":"g"},{"name":"Water","unit":"g"}]'::jsonb, '["Debone the chicken leg using scissors, pound the meat side with the back of a knife, then cut into strips and dice into 1.5 cm cubes. Soak in clean water for 10 minutes, then drain and set aside (if using chicken breast, dice directly and proceed).","Put the green part of the scallion and 5g ginger slices in a bowl, pour in 50g boiling water and set aside. Cut the white part of the scallion into 1.5 cm rounds. Roast the peanuts in a microwave on high for 5 minutes until dry, set aside.","Add 2g salt, 5g dark soy sauce, 15g cooking wine, and 15g starch to the chicken cubes. Mix until slightly dry. Slowly add some of the scallion-ginger water, stirring until the chicken becomes sticky. Cover with plastic wrap and marinate in the refrigerator for 1 hour.","Cut dried chilies into segments. Heat the wok over high heat, then reduce to low. Dry-roast the dried chilies until slightly charred, then remove and set aside. Roast the Sichuan peppercorns until fragrant, then remove and set aside.","Turn to high heat, add 20g vegetable oil. When the oil is 70% hot (bubbles form around chopsticks), add the chicken cubes. Fry until the tops turn white, then flip with a spatula. Fry for 30 seconds, then stir-fry evenly.","Add the scallion rounds and stir-fry. Add the remaining scallion-ginger water, and if it''s less than 100g, add a bit more hot water (must be hot). Cover the wok, reduce to medium-low heat, and braise for 2 minutes.","Turn to high heat. Add the cooked peanuts, dried chilies, and Sichuan peppercorns. Add 2g chicken bouillon, 5g Zhenjiang vinegar, and 2g sugar. Stir-fry evenly.","Mix 10g starch with 50g water to make a slurry. Add to the wok and stir-fry evenly. Thicken to desired consistency.","Turn off the heat, drizzle with 10g sesame oil, and serve immediately.","Peel the asparagus lettuce and dice into 1 cm cubes. Set aside.","Cut the Erjingtiao chilies into 1 cm long segments.","Debone the chicken leg using scissors, pound the meat side with the back of a knife, then cut into strips and dice into 1.5 cm cubes. Soak in clean water for 10 minutes, then drain and set aside (if using chicken breast, dice directly and proceed).","Put the green part of the scallion and 5g ginger slices in a bowl, pour in 50g boiling water and set aside. Cut the white part of the scallion into 1.5 cm rounds.","Add 2g salt, 5g dark soy sauce, 15g cooking wine, and 15g starch to the chicken cubes. Mix until slightly dry. Slowly add some of the scallion-ginger water, stirring until the chicken becomes sticky. Cover with plastic wrap and marinate in the refrigerator for 1 hour.","Turn to medium heat, add 20g vegetable oil. Add raw peanuts and stir-fry until the surface is slightly scorched. Remove the peanuts but leave the oil in the wok.","Continue heating until the oil is 70% hot (bubbles form around chopsticks). Add the chicken cubes and doubanjiang (fermented broad bean paste). Stir-fry for about 1 minute.","Add the prepared asparagus lettuce cubes and continue stir-frying for 1 minute.","Add the scallion rounds and stir-fry. Add the remaining scallion-ginger water, and if it''s less than 100g, add a bit more hot water (must be hot). Add the Erjingtiao chili segments. Cover the wok, reduce to medium-low heat, and braise for 2 minutes.","Turn to high heat. Add the reserved peanuts and Sichuan peppercorns. Add 2g chicken bouillon, 5g Zhenjiang vinegar, and 2g sugar. Stir-fry evenly.","Mix 10g starch with 50g water to make a slurry. Add to the wok and stir-fry evenly. Thicken to desired consistency.","Turn off the heat, drizzle with 10g sesame oil and 5g chili oil, then stir-fry for another 10 seconds. Serve."]'::jsonb, '["Meat Dish","Sichuan","Numbing-Spicy","Sweet and Sour","Rice Companion","Stir-fry","Home-style"]'::jsonb),
  ('howtocook:meat_dish/小炒肉', 'en', 'Stir-fried Pork Belly', 'Meat Dishes', 'Stir-fried Pork Belly is a classic spicy and appetizing Hunan home-style dish. The pork belly slices are crispy and not greasy, stir-fried with fresh chili peppers, fermented black beans, and bean paste to create a rich sauce. Rich in high-quality protein and fat, chili peppers provide plenty of vitamin C, which helps stimulate appetite and warm the body. The difficulty level is moderate, suitable for beginners with some basic skills. Pay attention to marinating the meat and controlling the heat. From preparation to serving takes about 1 hour, including 30 minutes of marinating and about 15 minutes of cooking.', '[{"name":"Pork belly","unit":"g"},{"name":"Bird''s eye chili peppers","unit":"pieces"},{"name":"Red chili peppers","unit":"pieces"},{"name":"Fermented black beans","unit":"g"},{"name":"Bean paste","unit":"g"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Starch","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Scallions","unit":"stalk"},{"name":"Garlic","unit":"clove"},{"name":"Cooking oil","unit":"ml"}]'::jsonb, '["Slice the pork belly.","Place the meat in a bowl, add starch, dark soy sauce, and salt. Mix and marinate for 30 minutes.","Cut the scallions into sections.","Slice the red chili peppers and bird''s eye chili peppers diagonally.","Heat the wok and add oil.","Once the oil is hot, add the pork belly and stir-fry. Stir-fry until it changes color, then remove from the wok.","Add garlic to the wok, stir-fry until fragrant, then add fermented black beans and stir-fry evenly.","Add bean paste and stir-fry evenly.","Add the previously stir-fried pork belly and continue to stir-fry evenly.","Add the red chili peppers, bird''s eye chili peppers, and scallion sections. Stir-fry for 40 seconds.","Serve."]'::jsonb, '["Meat Dish","Spicy","Rice Pairing","Home-style","Hunan Style","Stir-fry","Quick"]'::jsonb),
  ('howtocook:meat_dish/小炒鸡肝/小炒鸡肝', 'en', 'Stir-Fried Chicken Liver', 'Meat Dishes', 'This stir-fried chicken liver dish has a rich garlic aroma, tender and smooth texture with a hint of cumin''s smoky flavor. It''s a home-style stir-fry. Chicken liver is rich in iron, vitamin A, and high-quality protein, which helps nourish blood and improve eyesight. The technique of blanching to remove the gamey smell is essential, which may be slightly challenging for beginners. From preparation to serving, it takes about 40 minutes.', '[{"name":"Raw chicken liver","unit":"piece"},{"name":"Garlic sprouts","unit":"gram"},{"name":"Scallions","unit":"gram"},{"name":"Ginger","unit":"gram"},{"name":"Cooking wine","unit":"ml"},{"name":"Salt","unit":"gram"},{"name":"Chicken bouillon (MSG)","unit":"gram"},{"name":"Five-spice powder (thirteen-spice)","unit":"gram"},{"name":"Ground pepper","unit":"gram"},{"name":"Barbecue seasoning or cumin powder","unit":"gram"},{"name":"Sesame seeds","unit":"gram"},{"name":"Cooking oil","unit":"ml"}]'::jsonb, '["Wash the chicken livers and set aside.","Wash the garlic sprouts, cut into sections, and set aside.","Wash the scallions, take 100g and cut into sections, take 50g and slice, set aside.","Wash the ginger, take 70g and slice, take 50g and dice, set aside.","Step 1: Blanch","Put the cleaned chicken livers in a pot, add cold water to cover, and add 100g of scallion sections, 70g of sliced ginger, and 30ml of cooking wine.","Turn to high heat, when the water boils, reduce to medium heat and skim off any foam, then wait 5-10 minutes.","Turn off the heat, take out the livers, rinse under cold water and clean thoroughly.","Slice the cleaned livers and set aside.","Step 2: Stir-fry","Turn to medium heat. Add 30ml of cooking oil to the pot, wait 10 seconds for the oil to heat up.","Add the 50g of sliced scallions and 50g of diced ginger, stir-fry until fragrant.","After releasing fragrance, add the sliced chicken livers, stir-fry until slightly golden.","Add the garlic sprouts, stir-fry for 30 seconds, then reduce to low heat once they are slightly cooked.","Add seasonings.","5g salt","5g chicken bouillon (MSG)","5g five-spice powder (or thirteen-spice)","5g ground pepper","10g barbecue seasoning or cumin powder (optional)","Turn to high heat, quickly stir-fry for 30 seconds to prevent sticking, then turn off the heat.","Transfer to a plate. Optionally sprinkle 5g of sesame seeds as garnish. If you don''t like or don''t have, you can skip."]'::jsonb, '["Meat Dish","Home-style","Garlic Aroma","Cumin","Stir-fry","Goes with rice","Blood-nourishing"]'::jsonb),
  ('howtocook:meat_dish/小炒黄牛肉/小炒黄牛肉', 'en', 'Stir-Fried Beef', 'Meat Dishes', 'This Hunan-style stir-fry uses high heat to bring out the tenderness of the beef and the aroma of chili peppers, resulting in a spicy and refreshing taste with crisp celery, embodying the essence of Hunan cuisine. Beef tenderloin provides high-quality protein and easily absorbable iron, while celery adds dietary fiber for a balanced meal. The preparation and cooking steps are straightforward, with quick stir-frying over high heat throughout, making it beginner-friendly. From cutting to serving, it takes about one hour.', '[{"name":"Beef tenderloin","unit":"g"},{"name":"Celery","unit":"g"},{"name":"Red chili pepper","unit":"g"},{"name":"Pickled chili pepper","unit":"g"},{"name":"Cilantro","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Soy sauce","unit":"ml"}]'::jsonb, '["Slice the beef tenderloin into pieces no wider than 3 cm and no thicker than 3 mm. Pour in 6 ml of soy sauce and mix well with your hands. Set aside.","Cut the celery into segments no longer than 5 cm. Set aside.","Slice the red chili peppers into strips. Set aside.","Cut the pickled chili peppers into small pieces. Set aside.","Cut the cilantro into segments no longer than 3 cm. Set aside.","Heat the wok, add 15 ml of cooking oil, and wait for 30 seconds over high heat until the oil is hot.","Add the red chili peppers and pickled chili peppers and stir-fry until fragrant.","Add the beef and celery, then stir-fry over high heat for 1 minute.","Turn off the heat, sprinkle with cilantro, and serve."]'::jsonb, '["Meat Dish","Hunan Cuisine","Spicy","Stir-Fry","Goes with Rice","Home-style"]'::jsonb),
  ('howtocook:meat_dish/小米辣炒肉', 'en', 'Stir-fried Pork with Thai Chili Peppers', 'Meat Dishes', 'Stir-fried pork with Thai chili peppers is spicy and satisfying, a classic Southwestern Chinese dish. The tender pork paired with the fiery kick of Thai peppers whets the appetite. Pork is rich in protein and fat, while chili peppers provide plenty of vitamin C, helping to stimulate appetite. Although you need to master the heat for stir-frying, the steps are clear and even beginners can easily handle it. The total cooking time is about 25 minutes. Note: This dish is intensely spicy; it''s not recommended for those who prefer light flavors.', '[{"name":"Thai chili peppers","unit":"pieces"},{"name":"Peanut oil","unit":"ml"},{"name":"Pork belly/lean pork","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Oyster sauce","unit":"ml"},{"name":"Garlic","note":"to taste"},{"name":"Ginger","note":"to taste"},{"name":"Doubanjiang (chili bean paste)","unit":"g"},{"name":"Chicken bouillon","unit":"g"},{"name":"Sugar","unit":"g"}]'::jsonb, '["Wash the Thai chili peppers and cut them diagonally into larger pieces.","For the meat, cut into shreds or slices as you like. Add the seasonings (light soy sauce, oyster sauce, salt) and marinate for 5 minutes.","Heat oil in a wok, stir-fry the meat first, then remove and set aside.","Sauté ginger and garlic until fragrant, add doubanjiang (chili bean paste) and stir-fry, then add the sliced Thai peppers. Return the lean meat, stir-fry briefly, then add a bit of light soy sauce, chicken bouillon, salt, and sugar, and stir-fry."]'::jsonb, '["meat dish","spicy","Sichuan cuisine","rice dish","home-style","stir-fry"]'::jsonb),
  ('howtocook:meat_dish/小酥肉', 'en', 'Crispy Fried Pork Strips (Xiao Su Rou)', 'Meat Dishes', 'Crispy on the outside and tender on the inside, with a savory flavor and a slight numbing sensation from Sichuan pepper. It is a home-style fried dish commonly made in the Sichuan and Chongqing region. Pork is rich in protein and fat, and after deep-frying, it is relatively high in calories, suitable for occasional indulgence. This dish has quite a few steps; mastering the heat for the initial frying to set the shape and the second frying for color can be a bit challenging for beginners. It takes about 1 hour and 30 minutes from start to finish.', '[{"name":"Skinless pork","unit":"g"},{"name":"Vegetable oil","unit":"","note":"as needed"},{"name":"Old ginger","unit":"g"},{"name":"Scallions","unit":"g"},{"name":"Cooking wine","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Thirteen-spice powder","unit":"g"},{"name":"Pepper powder","unit":"g"},{"name":"MSG","unit":"g"},{"name":"Chicken powder","unit":"g"},{"name":"Crushed Sichuan pepper","unit":"g"},{"name":"Whole Sichuan pepper","unit":"g"},{"name":"Light soy sauce","unit":"g"},{"name":"Egg","unit":"piece(s)"},{"name":"Flour","unit":"g"},{"name":"Sweet potato starch","unit":"g"}]'::jsonb, '["Slice old ginger into thin strips; do not cut the scallions.","According to the calculation formula, pour in cooking wine and water.","Knead with hands for 5 minutes to fully dissolve the flavor of ginger and scallion into the water.","Remove skin from pork and wash clean.","Cut into strips about 8–10 cm long and 1.5 cm thick.","According to the calculation formula above, add salt, thirteen-spice powder, pepper powder, MSG, chicken powder, crushed Sichuan pepper, whole Sichuan pepper, and light soy sauce.","Pour in the previously prepared ginger-scallion water.","Mix thoroughly and knead for 10 minutes until the meat absorbs all the liquid and becomes sticky.","Cover with plastic wrap and rest in the refrigerator for 30 minutes.","Add flour and sweet potato starch to the marinated meat, then add egg whites.","Knead thoroughly for 15 minutes.","Pour vegetable oil into the pot; control the amount based on pot size; oil depth should be at least 3 cm.","Heat over high heat to 150°C, then turn to low heat to maintain temperature.","Use chopsticks to place the coated meat strips into the oil, shaping them as desired; fry for 3–5 minutes to set. Look for a light golden color and a slightly firm feel when turning with a spatula. Exact time depends on meat size, oil temperature, and coating thickness.","Remove and drain oil.","Raise oil temperature to 180°C, add the first-fried strips, and fry until golden brown, then remove."]'::jsonb, '["Meat Dish","Savory","Slightly Numbing","Sichuan/Chongqing","Fried","Home-style"]'::jsonb),
  ('howtocook:meat_dish/尖叫牛蛙/尖叫牛蛙', 'en', 'Screaming Bullfrog', 'Meat Dishes', 'This dish is spicy and appetizing, with tender and springy frog meat. It''s a classic Sichuan home-style dish. Bullfrog is high in protein and low in fat, paired with pickled ginger, pickled peppers and other fermented ingredients to boost appetite. The method is straightforward, but oil temperature and seasoning ratios need some attention. Beginners can usually finish it in 1 to 2 hours.', '[{"name":"bullfrog meat","unit":"g"},{"name":"pickled ginger","unit":"g"},{"name":"pickled peppers","unit":"g"},{"name":"wild mountain peppers","unit":"g"},{"name":"green and red chilies","unit":"g"},{"name":"garlic","unit":"g"},{"name":"doubanjiang","unit":"g"},{"name":"salt","unit":"g"},{"name":"white pepper","unit":"g"},{"name":"cornstarch","unit":"g"},{"name":"beer","unit":"ml"},{"name":"cooking wine","unit":"ml"},{"name":"Sichuan pepper oil","unit":"ml"},{"name":"lard","unit":"ml"},{"name":"cooking oil","unit":"ml"},{"name":"chopped scallions","unit":"g"}]'::jsonb, '["Clean the bullfrog meat and drain well. Add 10g or more of salt and 50ml or more of beer. Knead with hands for 5 minutes to remove the gamey smell.","Then rinse under running water until no blood or impurities remain. Drain well and place in a suitable container for marinating.","Add 5g salt, 30g cornstarch, 10ml cooking wine, and 5g pepper. Mix evenly with hands. Marinate for 5-10 minutes.","Shred or slice pickled ginger, pickled peppers, and wild mountain peppers (depending on knife skills). Cut green and red chilies into rings. Peel garlic cloves.","Heat the wok, add 200ml cooking oil (add extra 100ml if using a flat-bottom pan). Heat to 60% (small bubbles appear). Add the marinated bullfrog and quickly deep-fry for 10 seconds. Remove immediately (do not over-fry or the meat will become tough).","Remove the frog meat, drain oil. Pour out the hot oil from the wok into a bowl, leaving 30ml. Add 20ml lard (if not available, keep a total of 50ml cooking oil in the wok).","When oil is 60% hot, add pickled ginger, pickled peppers, wild mountain peppers, and garlic. Stir-fry until fragrant. Add 20g doubanjiang. Stir-fry over medium heat until red oil appears (about 30 seconds). Pour in 400ml beer.","Then add the deep-fried bullfrog meat. Gently push with a spoon to mix, do not stir vigorously. Add 5g pepper and 5ml Sichuan pepper oil. Simmer over medium heat for 3 minutes.","Increase heat to high and reduce sauce for 30 seconds. Add green and red chili rings. Cook for 10 more seconds, then prepare to plate.","Transfer to a bowl, sprinkle with chopped scallions, and serve!"]'::jsonb, '["Meat Dish","Spicy","Sichuan Style","Goes with Rice","Home-style","Appetizing"]'::jsonb),
  ('howtocook:meat_dish/尖椒炒牛肉', 'en', 'Stir-fried Beef with Hot Peppers', 'Meat Dishes', 'A home-style stir-fry, savory and slightly spicy. The beef is tender and flavorful, while the hot peppers are crisp and refreshing. Beef provides high-quality protein and iron, and hot peppers are rich in vitamin C, making a balanced dish. Although marinating requires patience, the steps are clear, suitable for beginners, with moderate difficulty. From prep to finish, it takes about 1 hour.', '[{"name":"Beef","unit":"g"},{"name":"Scallions","unit":"stalk"},{"name":"Ginger","unit":"piece"},{"name":"Garlic","note":"to taste"},{"name":"Hot peppers","note":"to taste"},{"name":"Soy sauce","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Sugar","unit":"g"}]'::jsonb, '["Mince garlic into paste","Cut scallions into sections","Slice ginger into slices","Cut hot peppers into sections","Place beef in a bowl","Add ginger, salt, soy sauce, and sugar; marinate for 30-40 minutes","After marinating, remove the ginger","Add cold oil to the pan, heat until bubbles appear occasionally","Add minced garlic","When garlic turns golden, add hot peppers","When the pepper skin wrinkles slightly, add marinated beef and stir-fry","Before the beef is fully cooked, add scallions and continue stir-frying","Stir-fry until beef is cooked through, then turn off heat and serve"]'::jsonb, '["Meat Dish","Savory","Slightly Spicy","Stir-fry","Home-style","Rice Companion"]'::jsonb),
  ('howtocook:meat_dish/山西过油肉', 'en', 'Shanxi Fried Sliced Pork', 'Meat Dishes', 'Shanxi Fried Sliced Pork is a traditional famous dish of Shanxi. The pork slices are tender, garlic sprouts are crisp, savory with a hint of sourness, carrying the rich aroma of aged vinegar. It is a typical local home-style flavor. Pork tenderloin provides high-quality protein, paired with wood ear mushrooms, garlic sprouts, and onions for balanced nutrition. This dish requires some skill in heat control and battering, making it more suitable for enthusiasts with some cooking experience. From preparation to serving, it takes about 40 minutes.', '[{"name":"pork tenderloin","unit":"g"},{"name":"garlic sprouts","unit":"piece"},{"name":"salt","unit":"g"},{"name":"light soy sauce","unit":"ml"},{"name":"scallion, ginger, garlic","unit":"g"},{"name":"egg","unit":"piece"},{"name":"starch","unit":"g"},{"name":"cooking oil","unit":"ml"},{"name":"wood ear mushrooms","unit":"g"},{"name":"onion","unit":"g"},{"name":"cooking wine","note":"to taste"},{"name":"aged vinegar","unit":"ml"},{"name":"ground Sichuan pepper","note":"to taste"},{"name":"chicken bouillon","note":"to taste"}]'::jsonb, '["Soak the wood ear mushrooms in advance; if in a hurry, use hot water to speed up.","Slice the pork tenderloin and put into a bowl. Add 20ml light soy sauce, cooking wine, ground Sichuan pepper, crack in one egg, mix well with your hand. Add starch (sweet potato starch recommended) and mix well. Pour in 300ml cooking oil to seal the batter, and marinate for 15 minutes.","Cut garlic sprouts into sections about 3cm long. Cut onion into diamond-shaped pieces and set aside.","Heat a wok with more oil. When oil reaches 50% heat (about 150°C), add the marinated pork slices. Quickly separate them, then remove and drain oil.","Pour out excess oil from the wok, leaving 10ml for stir-frying. Heat oil to 70% heat (about 210°C).","Add chopped scallion, ginger, and garlic to sizzle. First add garlic sprouts and stir-fry until just cooked, then add wood ear mushrooms and onion. Add light soy sauce and ground Sichuan pepper. Stir a few times, then add the previously fried pork slices and stir-fry.","Add 10g salt. Just before removing from heat, add 10ml vinegar and chicken bouillon. Remove and plate."]'::jsonb, '["Meat Dish","Shanxi Cuisine","Home-style","Rice Appetizer","Savory","Stir-fry","Salty-savory with slight sourness"]'::jsonb),
  ('howtocook:meat_dish/巴基斯坦牛肉咖喱/巴基斯坦牛肉咖喱', 'en', 'Pakistani Beef Curry', 'Meat Dishes', 'This Pakistani-style beef curry is rich and tender, with a sour and spicy kick and a strong aroma of spices. Beef provides high-quality protein, paired with tomatoes and yogurt for balanced nutrition. The method is not too complicated, but slow cooking requires some patience, making it perfect for a leisurely weekend. From start to finish, it takes about two and a half hours to serve up a warm pot of exotic deliciousness.', '[{"name":"Beef","unit":"kg"},{"name":"Tomato","unit":"piece"},{"name":"Screw chili","unit":"piece"},{"name":"Plain yogurt","unit":"box"},{"name":"Masala powder (brand optional: Shan)","unit":"g"},{"name":"Garlic powder","unit":"g"},{"name":"Ginger powder","unit":"g"},{"name":"Oil","note":"as needed"},{"name":"Water","unit":"ml"}]'::jsonb, '["Cut all screw chilies into sections and set aside.","Blend all tomatoes into a puree and set aside.","Cut the beef into 2cm cubes and wash clean.","Pour a layer of oil into the wok (to prevent the tomato puree from boiling and evaporating).","Pour in the tomato puree and stir continuously for 2-3 minutes, waiting for it to turn a deeper red.","Add 5g garlic powder, 5g ginger powder, and 1 packet (50g) of Masala powder, and mix well.","Add the beef and screw chili sections, and stir to combine.","Add 1 box of yogurt (to make the sauce thick), and stir well.","Transfer everything to a rice cooker or slow cooker, add 250 ml of water, and set to stew/slow cook mode for 2-3 hours.","Wait until done, then open the lid and check that the beef is tender. It''s ready to eat."]'::jsonb, '["Meat Dish","Spicy","Slow Cooked","Pakistani","Rice Pairing","Weekend"]'::jsonb),
  ('howtocook:meat_dish/带把肘子', 'en', 'Braised Pork Hock with Handle', 'Meat Dishes', 'Braised Pork Hock with Handle is a traditional famous dish from Dali, Shaanxi. It is named because the claw resembles a handle. The finished dish has sticky and soft skin, tender and non-greasy meat. It is eaten with sweet bean sauce and scallion segments, savory and mellow. Rich in collagen and high-quality protein, nourishing and beautifying. It requires deboning, shaping, and long steaming, which is somewhat challenging for beginners. The entire process takes about 3.5 hours.', '[{"name":"Pork front hock with foot and claw","unit":"g"},{"name":"Fermented red bean curd","unit":"g"},{"name":"Sweet bean sauce","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Dark soy sauce","unit":"g"},{"name":"Light soy sauce","unit":"g"},{"name":"Cooking wine","unit":"g"},{"name":"Garlic slices","unit":"g"},{"name":"Minced ginger","unit":"g"},{"name":"Star anise","unit":"pieces"},{"name":"Cinnamon","unit":"g"},{"name":"Scallion","unit":"g"}]'::jsonb, '["Scrape and clean the pork hock. Place it on the cutting board with the top end outward, the handle (claw) inward, and the skin side down.","Using a knife, cut the skin open along the leg bone from the top end to the handle. Remove the meat on both sides of the leg bone (meat separated on three sides), leaving the bone attached at the bottom to expose the bone. Then smash the two sections of the leg bone in the middle with the back of the knife (or use a cleaver).","Put the hock in a pot and boil until 70% cooked (normal appearance, interior light red). Remove, wipe dry with a clean cloth, and while hot, brush the skin with dark soy sauce.","Prepare a steamer. Place star anise and cinnamon on the bottom. First, break the joint of the handle by hand without damaging the skin. Then place the hock skin side down into the steamer. Depending on the size, nestle the handle against the edge of the steamer to form a round shape.","Sprinkle with salt. Cover the meat with sterilized clean gauze. Then spread sweet bean sauce (50g), scallion (75g), fermented red bean curd, dark soy sauce, light soy sauce, ginger, and garlic onto the gauze. Steam over high heat for about three hours (until thoroughly tender).","After steaming, remove and uncover the gauze. Invert onto a plate. Discard the star anise. Serve with scallion segments and a small dish of sweet bean sauce on the side (or spread the sauce on the hock and serve scallion segments separately)."]'::jsonb, '["Meat Dish","Savory","Steamed","Shaanxi","Dali","Banquet"]'::jsonb),
  ('howtocook:meat_dish/干煸仔鸡/干煸仔鸡', 'en', 'Dry-Fried Chicken', 'Meat Dishes', 'An innovative Sichuan dish with a sweet-spicy flavor, originating from Peking University''s cafeteria. The chicken is marinated then fried, crispy outside and tender inside. Potatoes are soft and sticky, green peppers are crisp, all coated in a bright red sweet-spicy sauce. Salty-sweet with a hint of spice, it''s very appetizing. Rich in protein, carbohydrates, and vitamins. Involves deep-frying and sauce reduction, slightly challenging for beginners, but following steps will ensure success. Takes about 1 hour in total.', '[{"name":"Chicken thigh meat","unit":"g"},{"name":"Potato","unit":"g"},{"name":"Green pepper","unit":"g"},{"name":"Garlic cloves","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Chicken bouillon","unit":"g"},{"name":"White pepper","unit":"g"},{"name":"Light soy sauce","unit":"g"},{"name":"Dark soy sauce","unit":"g"},{"name":"Cooking wine","unit":"g"},{"name":"Cornstarch","unit":"g"},{"name":"Pixian red oil chili bean paste","unit":"g"},{"name":"Sugar","unit":"g"},{"name":"Ground Sichuan peppercorns","unit":"g"},{"name":"Water","unit":"ml"},{"name":"Cooking oil","unit":"ml"}]'::jsonb, '["Debone chicken thighs (skip if using boneless thigh fillets). Tenderize the meat with the back of a knife, then cut into 2cm cubes.","Add salt, chicken bouillon (optional), white pepper, light soy sauce, dark soy sauce, and cooking wine to the chicken. Mix until sticky, then add cornstarch and mix. Add cooking oil to prevent sticking. Marinate for 30 minutes.","Peel potatoes, cut into 2cm cubes. Boil in water for 5 minutes, then drain well to avoid splattering when frying.","Remove seeds from green peppers, cut into 2cm pieces, set aside in a colander.","Add enough oil to a wok (enough to submerge ingredients). Heat oil to 180°C, then fry potato cubes for 3 minutes. Remove.","Reheat oil to 180°C, then fry chicken cubes for 2 minutes. Remove.","Reheat oil to 180°C, then fry chicken cubes again for 1 minute. Remove.","Reheat oil to 180°C, then fry potato cubes again for 1 minute. Pour the oil and potatoes through a colander to drain, letting the green peppers on the colander wilt slightly from the hot oil.","Add 5ml cooking oil to the wok. Stir-fry garlic cloves over low heat until golden. Add Sichuan chili bean paste (red oil) and stir-fry until fragrant. Add sugar and stir until melted. Add ground Sichuan peppercorns. Add 40ml water, stirring constantly until the sauce thickens.","Add the fried chicken, potatoes, and green peppers. Toss to coat evenly with the sauce. Remove from heat and serve."]'::jsonb, '["Meat Dish","Sweet-Spicy","Sichuan","Deep-Fried","Rice Companion","Home-style","Party Dish"]'::jsonb),
  ('howtocook:meat_dish/乡村啤酒鸭', 'en', 'Country Beer Duck', 'Meat Dishes', 'Duck meat is braised with beer, resulting in a rich broth and tender, flavorful meat with a hint of beer aroma. It''s a unique home-style dish. Duck is nutritious, rich in protein, B vitamins, and various minerals. Braising with beer enhances its flavor. Although the steps are many, it''s not complicated, and beginners can finish in about 1 hour.', '[{"name":"Duck","unit":"kg"},{"name":"Beer","unit":"ml"},{"name":"Green bell pepper","unit":"stalks"},{"name":"Red bell pepper","unit":"stalks"},{"name":"Garlic","unit":"cloves"},{"name":"Ginger","unit":"cm"},{"name":"Bird''s eye chili","unit":"pieces"},{"name":"Garlic sprout","unit":"stalks"},{"name":"Scallion","unit":"stalks"},{"name":"Tsaoko","unit":"pieces"},{"name":"Cinnamon stick","unit":"cm"},{"name":"Star anise","unit":"pieces"},{"name":"Bay leaf","unit":"leaves"},{"name":"Dried chili","unit":"pieces"},{"name":"Cooking wine","unit":"ml"},{"name":"Sichuan peppercorn","unit":"pieces"},{"name":"Peanut oil","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"}]'::jsonb, '["Wash duck meat and put into pot","Add water to cover duck","Add 20 ml cooking wine","Add 1 reserved scallion","Add 2 cm ginger, smashed","Bring to a boil over high heat","Skim off foam","Remove duck, rinse clean with water and set aside","Clean pot and heat over high heat, add 60 ml peanut oil","When oil reaches 60°C, add a handful of Sichuan peppercorns (30 pieces)","Add duck and stir-fry for 4 minutes","After 2 minutes, add all spices","At 3 minutes, add all aromatics (ginger, garlic, bird''s eye chili)","Add 1000 ml beer","Braise duck for 30 minutes","At 10 minutes, add salt (3 g), light soy sauce (10 ml), dark soy sauce (5 ml)","At 20 minutes, add all side ingredients (green and red pepper segments)","At 29 minutes, add garlic sprout segments and scallion segments","Stir-fry for 1 minute","Serve"]'::jsonb, '["Meat Dish","Savory","Braising","Home-style","Rice-friendly","Mildly Spicy"]'::jsonb),
  ('howtocook:meat_dish/广式萝卜牛腩/广式萝卜牛腩', 'en', 'Cantonese Radish Beef Brisket', 'Meat Dishes', 'This is a Cantonese home-style stew. The beef brisket is tender and flavorful, and the radish absorbs the broth, becoming sweet and rich. The overall taste is savory with a hint of sweetness. Rich in high-quality protein and dietary fiber, it appetizing and aids digestion. The steps are a bit many but moderate difficulty; even beginners can succeed by following the order. It takes about 2.5 hours from start to finish.', '[{"name":"beef brisket","unit":"g"},{"name":"white radish","unit":"root"},{"name":"ginger slices","unit":"slices"},{"name":"garlic cloves","unit":"cloves"},{"name":"scallions","note":"a bunch"},{"name":"star anise","unit":"pieces"},{"name":"cinnamon stick","unit":"small piece"},{"name":"dried chili peppers","unit":"pieces"},{"name":"bay leaves","unit":"leaves"},{"name":"fermented red bean curd","unit":"pieces"},{"name":"hoisin sauce","unit":"g"},{"name":"oyster sauce","unit":"g"},{"name":"soy sauce","unit":"g"},{"name":"rock sugar","unit":"g"},{"name":"salt","unit":"g"},{"name":"dark soy sauce","unit":"g"}]'::jsonb, '["Roll-cut the radish into chunks and set aside.","Blanch the whole brisket with 2 slices of ginger and a bunch of scallion knots. After the water boils, cook for 5-10 minutes, then remove and cut into pieces.","Cut the brisket into pieces of your preferred size (the brisket has been blanched, so it won''t shrink much during stewing; larger pieces will take a bit longer to stew).","Prepare the sauce for stewing: mix the fermented red bean curd, hoisin sauce, soy sauce, oyster sauce, sugar, and salt according to the amounts above (I ran out of rock sugar so I used granulated sugar instead).","Heat oil in a wok, stir-fry ginger and garlic until fragrant. Add the brisket and stir-fry until dry. Add the prepared sauce and stir-fry until aromatic. If you prefer a darker color, you can add a bit of dark soy sauce to enhance the color.","After the seasonings are well mixed, pour in hot water.","Transfer the brisket to a soup pot, add cinnamon stick, star anise, bay leaves, and dried chili peppers. Stew for about 2 hours.","When the brisket is half-tender, add the white radish and continue stewing for 30 minutes.","Once the radish is tender, it''s done. A pot of fragrant radish beef brisket is ready."]'::jsonb, '["Meat Dish","Cantonese","Stew","Savory","Rice-Goer","Home-style","Entertaining"]'::jsonb),
  ('howtocook:meat_dish/徽派红烧肉/徽派红烧肉', 'en', 'Anhui-Style Braised Pork Belly', 'Meat Dishes', 'Anhui-Style Braised Pork Belly is a classic home-style dish with a bright red color, fatty but not greasy, with a soft, sticky, and chewy texture, blending salty and sweet flavors. Made with pork belly, it is rich in high-quality protein and fat, providing ample energy. Cooking requires mastering caramel coloring and heat control, which is somewhat challenging. Estimated cooking time: about 45 minutes.', '[{"name":"Pork belly","unit":"g"},{"name":"White sugar","unit":"g"},{"name":"Cooking oil","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Oyster sauce","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Ginger slices","unit":"slices"},{"name":"Garlic cloves","unit":"cloves"},{"name":"Cooking wine","unit":"ml"},{"name":"Scallion","unit":"stalk"},{"name":"Five-spice powder","unit":"g"},{"name":"Salt","unit":"g"}]'::jsonb, '["Cut pork belly into 2-3 cm cubes.","Add 150 ml cooking oil to the pot, add pork belly, fry for 2 minutes, then add salt, stir-fry for 2 minutes, then remove from pot.","Add 50 ml cooking oil to the pot, add white sugar, stir-fry until caramel colored.","Add pork belly, stir-fry for 30 seconds, add ginger slices and garlic cloves, stir-fry for 30 seconds.","Add cooking wine, five-spice powder, scallion, add water to cover pork belly, cover and cook for 10 minutes.","Add light soy sauce, dark soy sauce, oyster sauce, cook over medium heat for 20 minutes.","Uncover, reduce sauce over high heat, and serve."]'::jsonb, '["Meat Dish","Salty-sweet","Braised","Anhui-style","Rice companion","Home-style"]'::jsonb),
  ('howtocook:meat_dish/意式烤鸡', 'en', 'Italian Roasted Chicken', 'Meat Dishes', 'Italian Roasted Chicken is a home-style oven dish with Mediterranean flavors. Chicken thighs are marinated with garlic and olive oil, then roasted until the skin is slightly charred and the inside is tender and juicy. Served with lemon juice and parsley, it tastes light and not greasy. Chicken is rich in high-quality protein, and olive oil provides unsaturated fatty acids, making it nutritionally balanced. The difficulty is moderate; you need to preheat the oven in advance. Beginners can follow the steps successfully. The total time from marinating to serving is about 50 minutes.', '[{"name":"chicken thighs","unit":"piece"},{"name":"salt","unit":"g"},{"name":"black pepper","unit":"g"},{"name":"olive oil","unit":"ml"},{"name":"garlic","unit":"clove"},{"name":"lemon juice","unit":"ml"},{"name":"parsley","unit":"stalk"}]'::jsonb, '["Coat chicken thighs with salt, black pepper, olive oil and minced garlic.","Place in a preheated oven at 180°C and bake for 30-40 minutes or until cooked through.","Chop parsley into small pieces and set aside.","Squeeze lemon juice and set aside.","Remove the cooked chicken and drizzle with lemon juice.","Sprinkle with chopped parsley and serve."]'::jsonb, '["Meat Dish","Italian","Roasted","Mediterranean","Light","Home-style"]'::jsonb),
  ('howtocook:meat_dish/新疆大盘鸡/新疆大盘鸡', 'en', 'Xinjiang Big Plate Chicken', 'Meat Dishes', 'Xinjiang Big Plate Chicken is a flavorful and colorful Xinjiang home-style dish. The chicken is tender and not dry, the potatoes are soft and absorb the sauce, with a spicy and numbing taste that carries a hint of sweetness and a pleasant aftertaste. It is rich in high-quality protein and carbohydrates, and with bell peppers it also provides vitamin C. The cooking process requires caramelizing sugar and controlling the sauce reduction, which may be a bit challenging for beginners, but it''s not difficult if you follow the steps carefully. It takes about 1 hour in total.', '[{"name":"Chicken (preferably drumsticks)","unit":"kg"},{"name":"Potatoes","unit":"g"},{"name":"Green onions","unit":"g"},{"name":"Bell peppers (optional)","unit":"g"},{"name":"Sweet peppers (optional)","unit":"g"},{"name":"White sugar","unit":"g"},{"name":"Dried chili peppers","unit":"pieces"},{"name":"Garlic","unit":"cloves"},{"name":"Oil","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Oyster sauce","unit":"g"},{"name":"Cooking wine (or beer)","unit":"g"},{"name":"Water","unit":"L"},{"name":"Sichuan peppercorns","note":"to taste"},{"name":"Bay leaves","note":"to taste"},{"name":"Cardamom","note":"to taste"}]'::jsonb, '["Chop the meat into chunks. Soak in water with salt for 5 minutes to remove blood and odor, then drain.","Wash the green onions, garlic, peppers, and potatoes. Peel the potatoes.","Cut the white part of the green onions into 4cm long sections. Cut the bell peppers and long peppers into chunks.","Cut the potatoes into rolling cuts (roll-cut), meaning cut and rotate the potato. Each piece should be about 4cm by 4cm.","Caramelize sugar: Add oil to the pot, then add white sugar. Stir constantly with a spatula until the sugar melts and turns a caramel color. Then add the drained chicken and stir-fry to coat with color.","Add Sichuan peppercorns, bay leaves, cardamom, and dried chili peppers. Stir-fry.","Add 5g salt, 7ml light soy sauce, 10g oyster sauce, 100g cooking wine (or beer), and 1 liter of water.","Turn to medium heat and bring to a boil. Then reduce to medium-low heat and simmer to infuse flavors.","When the liquid reduces until the chicken is almost exposed, place the potatoes on top of the chicken. Do not stir, just cover them on the surface to prevent sticking. Continue to simmer covered. After a while, add the green onions, bell peppers, and sweet peppers, and continue simmering.","When the sauce is nearly reduced, you can stir to let the potatoes absorb the sauce. Finally, turn off the heat and serve."]'::jsonb, '["Meat Dish","Spicy and Numbing","Rice Companion","Xinjiang","Stewed","Home-style"]'::jsonb),
  ('howtocook:meat_dish/无骨鸡爪/无骨鸡爪', 'en', 'Boneless Chicken Feet', 'Meat Dishes', 'Sour and spicy, appetizing, with a Q-elastic texture. It is a home-style cold dish. Chicken feet are rich in collagen, beneficial for the skin. The deboning process is tedious and labor-intensive, making it relatively difficult and not suitable for beginners. Total time about 8 hours 15 minutes.', '[{"name":"chicken feet","unit":"kg"},{"name":"ginger","unit":"slices"},{"name":"cooking wine","unit":"grams"},{"name":"scallion","unit":"pieces"},{"name":"garlic","unit":"cloves"},{"name":"bird''s eye chili","unit":"pieces"},{"name":"onion","unit":"piece"},{"name":"light soy sauce","unit":"grams"},{"name":"oyster sauce","unit":"grams"},{"name":"black vinegar (preferably aged vinegar)","unit":"grams"},{"name":"white sugar","unit":"grams"},{"name":"salt","unit":"grams"},{"name":"Sichuan pepper oil","unit":"ml"},{"name":"cilantro","unit":"bunches"},{"name":"lemon","unit":"pieces"}]'::jsonb, '["Use scissors/knife to cut off all the nails from the chicken feet, including the flesh and bone under the nail, leaving no nails at all","Wash them clean and set aside","Put chicken feet into a large pot, prepare to remove fishy smell","Add scallion, cooking wine, and ginger all in","Add water to cover the chicken feet","Boil over high heat; skim off any foam that rises","After water reaches 100°C and boils, wait 10 minutes","Turn off heat, take out, drain water, rinse clean, put into a bowl","Put in the freezer compartment of the fridge for 20 minutes","Put all into the refrigerator (not freezer), then take out 10 pieces at a time to debone","Starting from the tips of the chicken toes, use a knife to slit each toe all the way to the back of the foot","Then from the back of the foot, slit all the way down to the whole arm","Bend each toe joint until you hear a popping sound","Press the tip of each toe and push inward; same for every toe, first push to the middle palm and back part","After each toe''s skin comes off, push from the palm toward the arm part until the whole bone comes off","Place in a bowl and set aside","Cut bird''s eye chilies into uniform small pieces","Mince garlic, onion, and cilantro","Cut lemon in half and squeeze lemon juice into the container with chicken feet","Pour all seasonings into the container with chicken feet; also add bird''s eye chilies, garlic, onion, and cilantro","Mix evenly by hand","Refrigerate overnight (6 hours)","After mixing, pour all over the prepared chicken feet"]'::jsonb, '["Meat Dish","Sour and Spicy","Cold Dish","Appetizing","Goes with Alcohol","Home-style"]'::jsonb),
  ('howtocook:meat_dish/杀猪菜', 'en', 'Pork and Sauerkraut Stew', 'Meat Dishes', 'This is a classic stew from Northeast China. It is sour, refreshing, savory, and warms the heart and stomach. The sauerkraut is rich in lactic acid bacteria and dietary fiber, the ribs provide high-quality protein and calcium, and the blood sausage supplies iron. Care is needed when handling the blood sausage to prevent it from bursting during cooking, which can be a challenge for beginners. From prep to serving, it takes about an hour.', '[{"name":"Blood sausage","unit":"grams"},{"name":"Sauerkraut","unit":"grams"},{"name":"Pork ribs","unit":"grams"},{"name":"Cooking wine","unit":"grams"},{"name":"Garlic cloves","unit":"count"},{"name":"Ginger powder","unit":"grams"},{"name":"Dried chili peppers","unit":"count"},{"name":"Bay leaves","unit":"leaves"},{"name":"Star anise","unit":"count"},{"name":"Scallion knot","unit":"count"},{"name":"Sesame oil","unit":"grams"},{"name":"Rapeseed oil","unit":"grams"},{"name":"Salt","unit":"grams"},{"name":"Goji berries","note":"to taste"},{"name":"Chili oil","unit":"grams"},{"name":"Light soy sauce","unit":"grams"},{"name":"Garlic paste","unit":"grams"},{"name":"Sesame oil","unit":"grams"}]'::jsonb, '["Use a toothpick to poke many small holes in the blood sausage. Then gently boil it in water over low heat for ten minutes. Do not let the water boil; keep it at 80°C, otherwise the blood sausage will easily burst.","Cut the cooked blood sausage into pieces and set aside.","Blanch the ribs with cooking wine, then drain and set aside.","Add rapeseed oil to the pot, then add garlic cloves, dried chili peppers, and ginger powder. Stir until fragrant.","Add the ribs and stir-fry until the surface turns golden brown.","Wash the sauerkraut and squeeze out excess water. Add it to the pot along with sesame oil and stir-fry over high heat for two minutes. The sesame oil helps remove the sourness and enhances the fragrance.","Add 600 ml of hot water.","Transfer to an electric pressure cooker. Add bay leaves, star anise, a scallion knot, and salt.","Pressure cook on the ''rich flavor'' mode for 40 minutes.","After the time is up, release the pressure and open the lid. Add the blood sausage and goji berries, cover, and let it sit for two minutes. The blood sausage is already cooked, so no further heating is needed.","Pour into a bowl. Prepare the dipping sauce according to the table above, and enjoy."]'::jsonb, '["Meat Dish","Northeast China","Stew","Sour and Refreshing","Savory","Goes well with rice"]'::jsonb),
  ('howtocook:meat_dish/枝竹羊腩煲/枝竹羊腩煲', 'en', 'Braised Lamb Brisket with Bean Curd Sticks', 'Meat Dishes', 'This is a traditional claypot dish from Guangdong. The lamb and bean curd sticks are harmonized with zhuhou sauce and fermented bean curd, resulting in a rich sauce flavor, luscious yet not greasy, warming both body and soul, especially suitable for cold winter. Lamb is rich in protein and iron, can warm and nourish qi and blood, while bean curd sticks provide high-quality plant protein, making a balanced combination. Although there are many preparation and stewing steps, the heat control throughout is not complicated; beginners can succeed by following the steps. It takes about two and a half hours from prep to serving.', '[{"name":"lamb brisket","unit":"g"},{"name":"fried bean curd sticks","unit":"g"},{"name":"zhuhou sauce","unit":"g"},{"name":"fermented bean curd","unit":"g"},{"name":"fermented red bean curd","unit":"g"},{"name":"dark soy sauce","unit":"ml"},{"name":"chili oil","unit":"ml"},{"name":"cooking wine","note":"to taste"},{"name":"oyster sauce","note":"to taste"},{"name":"water","unit":"ml"},{"name":"rock sugar","unit":"g"},{"name":"sugar","unit":"g"},{"name":"scallions","unit":"stalks"},{"name":"ginger slices","unit":"slices"},{"name":"shiitake mushrooms","unit":"pieces"},{"name":"onion","unit":"piece"},{"name":"shallots","unit":"pieces"},{"name":"garlic cloves","unit":"cloves"},{"name":"bay leaves","unit":"pieces"},{"name":"star anise","unit":"pieces"},{"name":"cinnamon","unit":"g"},{"name":"side vegetables","note":"Add according to personal preference"}]'::jsonb, '["Prep: Soak shiitake mushrooms for 2-3 hours until soft. Soak bean curd sticks for 30 minutes until soft.","Prepare sauce 1: Mix fermented red bean curd, zhuhou sauce, 20g fermented bean curd, and dark soy sauce in a small bowl.","Prepare sauce 2: Mix 20g fermented bean curd, sugar, and chili oil in a small bowl.","Remove the stems from the soaked mushrooms.","Cut the soaked bean curd sticks into 5cm sections, squeeze out excess water.","Peel and slice the onion. You can also use peeled shallots for better flavor.","Cut scallions into about 5cm sections.","Put lamb brisket in a pot with cold water, add 2-3 slices of ginger, bring to a boil over high heat, then turn off.","Remove the lamb and place it in a basin of cold water to cool, making it more chewy.","Heat the pot, add cold oil, then stir-fry 4-5 slices of ginger, onion/shallots, white parts of scallions, and 7-8 garlic cloves until fragrant.","Add the cooled lamb, stir with chopsticks for about 2-5 minutes until golden brown.","Add prepared sauce 1, stir-fry for about 2 minutes until evenly colored.","Pour in enough water to just cover the ingredients.","Add mushrooms, rock sugar, bay leaves, star anise, and cinnamon.","Cover, reduce to low heat, and simmer for 90 minutes.","Uncover, add bean curd sticks, cover, and cook over medium heat for 20 minutes.","Uncover, add sauce 2, and stir well.","Turn off heat, add green parts of scallions or cilantro before serving."]'::jsonb, '["Meat Dish","Cantonese","Saucy","Warming","Fall/Winter","Home-style"]'::jsonb),
  ('howtocook:meat_dish/柱候牛腩/柱候牛腩', 'en', 'Chu Hou Beef Brisket', 'Meat Dishes', 'This is a classic Cantonese-style dish. The meat is richly aromatic, bright red in color, and the tendon-in brisket is tender and flavorful with a rich texture. It is high in quality protein and collagen, nourishing and warming. Although it requires some patience, using a pressure cooker significantly shortens the time, making it beginner-friendly. Regular simmering takes about 3 hours, while a pressure cooker takes about 1 hour.', '[{"name":"beef brisket","unit":"g"},{"name":"ginger","unit":"g"},{"name":"garlic","unit":"head"},{"name":"bird''s eye chili","unit":"piece"},{"name":"bay leaves","unit":"slice"},{"name":"Sichuan peppercorns","unit":"g"},{"name":"star anise","unit":"piece"},{"name":"dried chili","unit":"piece"},{"name":"cloves","unit":"piece"},{"name":"licorice","unit":"slice"},{"name":"fermented red bean curd","unit":"piece"},{"name":"Pixian doubanjiang","unit":"g"},{"name":"rock sugar","unit":"g"},{"name":"Huadiao wine","unit":"g"},{"name":"baijiu","unit":"g"},{"name":"Chu Hou paste","unit":"g"},{"name":"char siu sauce","unit":"g"},{"name":"oyster sauce","unit":"g"},{"name":"dark soy sauce","unit":"g"},{"name":"light soy sauce","unit":"g"}]'::jsonb, '["First, prepare the aromatics and sauces:","Bowl 1: Dice ginger into 1.5cm x 1.5cm cubes, peel half a head of garlic, if using bird''s eye chili, cut into 1cm sections","Bowl 2: Add 2 bay leaves, 0.5g Sichuan peppercorns, 2 star anise, 3 dried chilies, 3 cloves, 2 slices licorice","Bowl 3: Add 2 pieces fermented red bean curd","Bowl 4: Add 15g Pixian doubanjiang","Bowl 5: Add 10g rock sugar","Bowl 6: Add 10g Huadiao wine and 10g baijiu","Bowl 7: Add 50g Chu Hou paste, 20g oyster sauce, 20g char siu sauce, 5g dark soy sauce, 60g light soy sauce","Do not cut the beef. Place it directly into a pot of cold water, bring to a boil over high heat. Once boiling, remove the beef.","Rinse off any impurities from the beef, then cut into 4cm cubes. Drain and set aside in a bowl.","Over high heat, heat oil in a wok, add Bowl 1 (ginger, garlic, bird''s eye chili) and stir-fry until fragrant.","Reduce to medium-low heat, add Bowl 2 (spices), stir-fry for about 30 seconds.","Over medium-low heat, add Bowl 3 (fermented red bean curd) and mash it with a spatula.","Over medium-low heat, add Bowl 4 (doubanjiang), stir-fry for about 30 seconds.","Over medium-low heat, add Bowl 5 (rock sugar), stir until melted.","Over medium-low heat, add the beef brisket, stir-fry until the beef is colored.","Increase to high heat, pour Bowl 6 (wine) along the edge of the wok, stir-fry quickly until the beef surface is slightly browned.","Add Bowl 7 (sauce mixture), stir-fry quickly, watch the bottom, cook until small bubbles appear and the sauce thickens slightly.","Transfer all contents to another pot or a pressure cooker. Add water to cover the ingredients.","Choose the cooking time based on the pot used:","a. Regular pot: Simmer on low heat for 3 hours.","b. Pressure cooker: Cook under pressure for 40 minutes.","After the time is up, open the lid and season. If not salty enough, add salt or light soy sauce (add a little at a time, taste until right). If not sweet enough, add sugar similarly.","Once seasoned, remove the beef brisket from the pot.","If adding radish and potato, peel and cut into 2cm thick slices, add to the pot and cook for 10-15 minutes (or until desired tenderness). If using a pressure cooker, cook under pressure for 5 minutes.","Once cooked, remove the radish and potato along with the beef brisket, place together.","Strain the sauce and pour over the meat and vegetables."]'::jsonb, '["Meat Dish","Cantonese","Savory Sauce","Braise","Goes Well with Rice","Warming","Home-style"]'::jsonb),
  ('howtocook:meat_dish/桂林十八酿/桂林十八酿', 'en', 'Guilin Eighteen Stuffed Delicacies', 'Meat Dishes', 'A traditional Guilin series of stuffed dishes. Seasoned pork, shrimp paste, and other fillings are stuffed into more than a dozen hollow ingredients such as green peppers, bitter melon, snails, and eggplants, then pan-fried and braised. Each dish has its unique flavor, savory and juicy, with a soft, tender, or chewy texture. It''s a rich local home-style flavor. The fillings provide high-quality protein, paired with various vegetables, rich in vitamins and dietary fiber, making for a balanced nutrition. The steps require stuffing each ingredient one by one and controlling the heat, requiring a bit of patience, but the logic is simple, so even beginners can try. It takes about 1.5 hours total.', '[{"name":"green peppers","note":"to taste"},{"name":"bitter melon","note":"to taste"},{"name":"eggplant","note":"to taste"},{"name":"snails","note":"to taste"},{"name":"tofu","note":"to taste"},{"name":"shiitake mushrooms","note":"to taste"},{"name":"pumpkin flowers","note":"to taste"},{"name":"pomelo","note":"to taste"},{"name":"bamboo shoots","note":"to taste"},{"name":"winter melon","note":"to taste"},{"name":"taro","note":"to taste"},{"name":"garlic","note":"to taste"},{"name":"tomato","note":"to taste"},{"name":"bean sprouts","note":"to taste"},{"name":"eggs","note":"to taste"},{"name":"fragrant mushrooms","note":"to taste"},{"name":"pork filling","note":"to taste"},{"name":"shrimp paste","note":"to taste"},{"name":"fish paste","note":"to taste"},{"name":"mixed filling","note":"to taste"}]'::jsonb, '["Stuffed green peppers: Remove seeds and hollow out green peppers → stuff with pork filling or shrimp paste → pan-fry until tiger-skin color → braise in sauce","Stuffed snails: Blanch snails and remove meat → mince snail meat with pork → stuff back into shells → braise with perilla and mint","Pork filling: The most basic and common choice, with 30% fat and 70% lean for the best texture","Shrimp paste filling: Sweet and bouncy, often used in stuffed green peppers","Snail and pork mixed filling: The soul of stuffed snails, snail meat to pork ratio 1:1, add perilla and mint","Mixed filling: Pork and shrimp paste combined, offering both sweetness and richness"]'::jsonb, '["Meat Dish","Savory","Pan-fried and Braised","Guilin Style","Home-style","Banquet"]'::jsonb),
  ('howtocook:meat_dish/梅菜扣肉/梅菜扣肉', 'en', 'Steamed Pork Belly with Preserved Mustard Greens', 'Meat Dishes', 'This is a traditional Hakka dish. The finished dish has a glossy red-brown sauce, thick gravy, and the pork belly is fatty but not greasy, tender and fragrant. Pork belly is rich in high-quality protein and fatty acids, and paired with preserved mustard greens provides dietary fiber. The process is somewhat lengthy, requiring mastery of boiling, frying, and steaming times, which can be challenging for beginners. From preparation to serving, including the time to soak the preserved mustard greens, it takes about 2.5 hours.', '[{"name":"pork belly","unit":"g"},{"name":"preserved mustard greens","unit":"g"},{"name":"five-spice powder","unit":"g"},{"name":"cooking oil","unit":"ml"},{"name":"white sugar","unit":"g"},{"name":"dark soy sauce","unit":"ml"},{"name":"light soy sauce","unit":"ml"},{"name":"bird''s eye chilies","unit":"pieces"},{"name":"minced garlic","unit":"g"},{"name":"table salt","unit":"g"},{"name":"chicken bouillon","unit":"g"}]'::jsonb, '["Soak the preserved mustard greens in clean water for 1 hour.","Pour 50 ml cooking oil into a wok. Place the whole pork belly skin-side down and cook for 1 minute. Remove and scrape off the skin [optional].","Add boiling water to a pot, put in the pork belly, and boil over high heat for 20 minutes (until a chopstick can pierce through). Remove the pork belly.","Evenly rub the pork belly with dark soy sauce, five-spice powder, and white sugar. Let it sit for 15 minutes.","Heat oil in a wok, add the pork belly, and deep-fry over medium heat until both sides are golden brown (3-5 minutes).","Heat oil in a wok, add the preserved mustard greens, along with chopped bird''s eye chilies, minced garlic, chicken bouillon, and table salt. Stir-fry until the greens are dry.","Slice the pork belly (0.5-1 cm thick), place in a large bowl, and scatter the preserved mustard greens on top.","Steam over medium heat for 45 minutes.","Invert a plate over the large bowl, then flip the bowl to transfer the pork belly onto the plate."]'::jsonb, '["Meat Dish","Hakka","Steamed","Rice Dish","Banquet","Savory"]'::jsonb),
  ('howtocook:meat_dish/椒盐排条', 'en', 'Salt and Pepper Pork Strips', 'Meat Dishes', 'Salt and Pepper Pork Strips is a classic home-style dish in Shanghai cuisine, crispy on the outside and tender on the inside, with a savory and aromatic flavor. Pork chops provide high-quality protein and essential amino acids to replenish energy. Although this dish has several steps, it''s not difficult to follow the process, and beginners can confidently give it a try. From prep to serving, it takes about 40 minutes.', '[{"name":"Pork chops","unit":"piece"},{"name":"Egg","unit":"piece"},{"name":"Salt","unit":"g"},{"name":"Salt and pepper powder","unit":"g"},{"name":"Scallion-ginger water","unit":"ml"},{"name":"Flour","unit":"g"},{"name":"Starch","unit":"g"},{"name":"Custard powder","unit":"g"},{"name":"Water","unit":"g"},{"name":"Oil","unit":"g"}]'::jsonb, '["Wash the pork chops, debone, pound with the flat side of a knife to loosen, cut into thick slices, then into thick strips.","Add salt and pepper powder, mix well. When it becomes sticky, gradually add scallion-ginger water. Refrigerate for 20 minutes to marinate.","Prepare the batter. Mix 80 g flour, 20 g starch (note: 20 g starch, reserve the remaining 60 g), 2-3 g custard powder, and 1 g salt.","Beat in one egg, stir, then gradually add 100 g water, then add 10 g oil. Mix repeatedly until the batter is smooth and slightly thick.","Take the remaining 60 g starch, coat the pork strips with starch, then coat with batter.","Add oil to the pot to submerge the ingredients, heat to about 150°C - 160°C. Fry the pork strips until light golden, then remove. They may stick together when first added; do not disturb. Once set, use chopsticks to turn and separate.","When the oil temperature rises again to 150°C - 160°C, refry the strips until golden brown, then remove.","Sprinkle with salt and pepper powder, stir well, and serve."]'::jsonb, '["Meat Dish","Savory","Fried","Shanghai cuisine","Pair with alcohol","Crispy outside, tender inside"]'::jsonb),
  ('howtocook:meat_dish/水煮牛肉/水煮牛肉', 'en', 'Sichuan Boiled Beef', 'Meat Dishes', 'Sichuan Boiled Beef is a classic spicy and numbing Sichuan dish, with tender and smooth beef, bright red soup, and a hot, spicy, and fresh flavor. Beef is rich in high-quality protein and iron, and pairing it with bean sprouts adds dietary fiber. This dish is not too difficult for beginners, but pay attention to heat control and safety when pouring hot oil. The total preparation time is about 40 minutes.', '[{"name":"Beef","unit":"g"},{"name":"Bean Sprouts","unit":"g"},{"name":"Egg","unit":"piece"},{"name":"Cilantro","unit":"stalk"},{"name":"Broad Bean Paste","unit":"g"},{"name":"Cooking Wine","unit":"ml"},{"name":"Starch","unit":"g"},{"name":"Dried Chili Powder","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Garlic","unit":"clove"},{"name":"Red Chili","unit":"piece"},{"name":"Oyster Sauce","unit":"g"}]'::jsonb, '["Wash and slice the beef.","Add 15g shredded ginger, 1 egg, 15g starch, 8g oyster sauce, and 10ml cooking wine. Mix well and marinate for 15 minutes.","Wash and chop the cilantro.","Pour oil into a pot, add broad bean paste, 5g shredded ginger, and sliced garlic.","Pour in boiling water and cook into a red broth.","Wash the bean sprouts and remove the tails. Blanch them in boiling water until cooked.","Spread the bean sprouts at the bottom of a bowl.","Add the beef slices one by one into the red broth. Once cooked, remove them.","Place the beef on top of the bean sprouts, and sprinkle with cilantro stems.","Sprinkle with cilantro leaves, chili powder, and chili rings.","Heat oil in another pan, then pour the hot oil over the dish. It''s done."]'::jsonb, '["Meat Dish","Spicy and Numbing","Sichuan","Goes Well with Rice","Home-style","Tender and Smooth"]'::jsonb),
  ('howtocook:meat_dish/水煮肉片', 'en', '水煮肉片 (Boiled Sliced Pork in Chili Sauce)', 'Meat Dishes', '水煮肉片 is a classic Sichuan dish with spicy and numbing flavor, tender sliced meat, and crunchy vegetables. It''s excellent with rice. Pork tenderloin provides high-quality protein, combined with bean sprouts and other vegetables for balanced nutrition. The preparation process is a bit elaborate, especially the marination of the meat and making the knife-cut chilies. Beginners may need about 1 to 2 hours.', '[{"name":"Pork tenderloin","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Ground white pepper","unit":"g"},{"name":"Light soy sauce","unit":"g"},{"name":"Cooking wine","unit":"g"},{"name":"Egg white","unit":"piece"},{"name":"Potato starch","unit":"g"},{"name":"Vegetable oil","unit":"g"},{"name":"Mung bean sprouts","unit":"g"},{"name":"Lettuce","unit":"piece"},{"name":"Celery","unit":"stalk"},{"name":"Garlic sprouts","unit":"stalk"},{"name":"Garlic","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Pickled red chilies","unit":"g"},{"name":"Green Sichuan peppercorns","unit":"g"},{"name":"Dried chilies","unit":"g"},{"name":"Red oil doubanjiang","unit":"ml"},{"name":"Chicken powder","unit":"g"},{"name":"White sugar","unit":"g"},{"name":"Scallion","unit":"stalk"},{"name":"Rapeseed oil","unit":"g"}]'::jsonb, '["Cut the tenderloin into small pieces, then slice into 2mm thin slices (adjust thickness to preference). Place in a bowl, wash with water twice to remove blood and impurities, drain and squeeze dry.","Add 1.5g salt, 1g white pepper, 5g light soy sauce, 3g cooking wine to the bowl. Stir in one direction for 2 minutes to season.","In another bowl, mix one egg white with 7g potato starch, stir evenly in one direction, then pour into the meat.","Stir again in one direction until the meat surface forms a smooth coating, making the meat more tender.","Finally, add 30g vegetable oil and gently mix (to prevent the slices from sticking).","100g mung bean sprouts, 1 lettuce (cut into strips), 3 celery stalks cut into segments, 2 garlic sprouts crushed and cut into segments.","20g garlic minced, small piece of ginger minced, 20g pickled red chilies minced.","15g dried small chili peppers, 3g green Sichuan peppercorns. Heat oil in a wok, swirl to coat, pour out excess leaving 50g oil. Add dried chilies and peppercorns, stir-fry on low heat until fragrant and the color turns dark (be careful not to burn). Transfer to a cutting board and chop finely.","Heat the wok, add 100g vegetable oil to 60% heat. Add 2g green Sichuan peppercorns and dried chilies for aroma. Add the vegetables, 1g salt, stir-fry until just cooked. Transfer to a bowl as a base.","Clean the wok, add 150g vegetable oil to 60% heat. Add the prepared ginger, garlic, and pickled chilies, stir until fragrant. Add 10g doubanjiang (red oil chili bean paste), stir-fry on low heat until the oil turns red.","Add 800ml water (adjust as needed). Bring to a boil over high heat, then reduce to low heat. Season with 2.5g salt, 1.5g chicken powder, 1g sugar for freshness, 1g white pepper, 5g water starch slurry (adjust as needed) to thicken the soup slightly.","When the soup is boiling, turn to low heat and slide the marinated meat slices one by one into the soup. Then turn to medium heat to cook the meat slices. Gently push with a spatula to prevent sticking. When the soup boils again and the meat is cooked, remove the meat and place on top of the vegetables in the bowl. Pour the soup over (not exceeding the ingredients).","Evenly sprinkle the chopped dried chili mixture, minced garlic, and chopped scallions on top.","Clean the wok, add 200g rapeseed oil, heat to 70% heat (smoking). Then pour the hot oil evenly over the meat in the bowl (be careful of safety). Ready to serve."]'::jsonb, '["Meat Dish","Spicy and Numbing","Sichuan","Rice Dish","Boiled","Banquet"]'::jsonb),
  ('howtocook:meat_dish/洋葱炒猪肉', 'en', 'Stir-fried Pork with Onion', 'Meat Dishes', 'This is a home-style stir-fry with a savory-sweet flavor and rich soy sauce aroma. Once the onion is stir-fried until soft, its taste becomes mild, pairing perfectly with tender pork slices to make a great rice dish. Pork provides high-quality protein and B vitamins, while onion offers dietary fiber and various antioxidants, stimulating appetite and aiding digestion. Simple to make, even beginners can master it, and it takes only about 15 minutes.', '[{"name":"onion","unit":"piece"},{"name":"pork slices","unit":"g"},{"name":"garlic","unit":"clove"},{"name":"cooking oil","unit":"ml"},{"name":"black pepper","unit":"g"},{"name":"soy sauce","unit":"ml"},{"name":"sugar","unit":"g"},{"name":"sesame oil","unit":"ml"},{"name":"ketchup","unit":"ml"},{"name":"cooking wine","unit":"ml"}]'::jsonb, '["Slice the onion, slice the pork, crush the garlic, and mix the above seasonings; set aside.","Pour 1 tablespoon of cooking oil into the wok (wait 10 seconds for the oil to heat up), then add the pork.","Stir-fry until the pork changes color, then add the garlic and stir until fragrant, then remove and set aside.","In the same wok, add the onion and stir-fry for 3–4 minutes, then add the seasonings and stir well.","Add the reserved pork and stir-fry until the pork is cooked through.","Once the pork is cooked, stir-fry for another 1–2 minutes, then serve."]'::jsonb, '["meat dish","home-style","rice dish","quick","savory-sweet","soy sauce aroma","stir-fry"]'::jsonb),
  ('howtocook:meat_dish/淄博烧烤/淄博烧烤', 'en', 'Zibo BBQ', 'Meat Dishes', 'This is a specialty barbecue from Zibo, Shandong. The unique way of wrapping meat in small pancakes with scallions offers a rich blend of meaty, savory, and onion flavors with layered textures. Pork belly is rich in high-quality protein and fat, scallions provide dietary fiber, and the small pancakes quickly replenish energy. Cooking requires control of charcoal heat and flipping skills, which may be slightly challenging for beginners. The whole process takes about 40 minutes.', '[{"name":"Pork belly","unit":"g"},{"name":"Small thin pancakes","unit":"pieces"},{"name":"Scallions","unit":"stalks"},{"name":"Sesame paste","unit":"g"},{"name":"Sweet bean sauce","unit":"g"},{"name":"Sesame salt","note":"to taste"},{"name":"Warm water","unit":"ml"}]'::jsonb, '["Cut the pork belly into chunks no thicker than 2cm, and thread them onto skewers. (Pre-marinate the pork belly for better flavor if desired.)","Cut the scallions into 5cm sections and set aside.","Thin the sesame paste with 10ml warm water, then mix evenly with sweet bean sauce and set aside. (Can substitute with ''sesame salt''.)","Light the charcoal and wait until it is red-hot with no visible flame (about 15 minutes).","Place the pork skewers evenly on the grill. Grill until the bottom side is golden and starting to render fat, then flip.","Continue grilling for about 2-3 minutes until both sides are golden and the edges are slightly charred, then remove.","Take a small thin pancake, lay it flat, and spread about 3-4g of the mixed sauce on it.","Place the grilled meat pieces and 1-2 sections of scallion on top, then roll up and serve."]'::jsonb, '["Meat Dish","Charcoal Grill","Lu Cuisine","Savory","Snack with Drinks","Gathering"]'::jsonb),
  ('howtocook:meat_dish/清蒸鳜鱼/清蒸鳜鱼', 'en', 'Steamed Mandarin Fish', 'Meat Dishes', 'Steamed mandarin fish has tender flesh and a prominent natural sweetness. It is a homestyle freshwater fish dish that emphasizes original flavors. Mandarin fish is rich in high-quality protein and various trace elements, easy to digest and absorb. Be careful with the fins when handling, but the overall steps are not complicated; even beginners can manage with a little attention. From prep to serving, it takes about half an hour.', '[{"name":"mandarin fish","unit":"grams"},{"name":"large scallion","unit":"stalk"},{"name":"spring onion","unit":"stalk"},{"name":"light soy sauce","unit":"grams"},{"name":"red chili pepper","unit":"piece"},{"name":"ginger slices","unit":"slice"},{"name":"cooking oil","unit":"milliliters"}]'::jsonb, '["Ingredient preparation:","Cut open the mandarin fish from the belly, remove gills and innards, scale it, and scrape off the slime from the skin with a knife (you can also ask the fishmonger to do this).","Score the fish on both sides, place ginger slices on top (optional: add a little lard). Put the fish on a plate with chopsticks underneath to allow even heat distribution.","Split the large scallion and remove the core, keeping only the outer two layers.","Split the spring onion and set aside.","Remove the seeds and inner flesh of the red chili pepper, set aside.","Stack the prepared large scallion, spring onion, and chili together, cut into thin strips, and soak in water for later use.","Cooking process:","Add water to the pot (enough volume). When the water is hot, place the fish in, cover, and steam over high heat for 8-10 minutes. The four-character tip for steaming fish: ''Steam high, heat sufficient''.","While steaming, heat oil in another wok until it smokes.","After steaming, discard the water from the plate, remove the ginger slices, top with the shredded scallions, and pour the hot oil over.","Then drizzle with light soy sauce or steamed fish soy sauce, and serve."]'::jsonb, '["Meat Dish","Steamed","Savory","Light","Freshwater Fish","Home-style","Banquet"]'::jsonb),
  ('howtocook:meat_dish/湖南家常红烧肉/湖南家常红烧肉', 'en', 'Hunan Home-style Braised Pork Belly', 'Meat Dishes', 'Hunan home-style braised pork belly is a richly flavored home-style dish. After slow simmering, the pork belly becomes tender but not greasy, soft and glutinous, with a savory and slightly spicy taste that lingers with a hint of sweetness. Rich in high-quality protein and fat, it provides ample energy. The cooking requires some patience and is moderately challenging for beginners, but following the steps makes it easy to master. The entire process takes about 1 hour.', '[{"name":"pork belly with skin","unit":"grams"},{"name":"cooking oil","unit":"grams"},{"name":"rock sugar","unit":"pieces"},{"name":"bay leaves","unit":"pieces"},{"name":"ginger","unit":"slices"},{"name":"cinnamon","unit":"small pieces"},{"name":"star anise","unit":"pieces"},{"name":"cooking wine","unit":"grams"},{"name":"light soy sauce","unit":"grams"},{"name":"dark soy sauce","unit":"grams"},{"name":"salt","unit":"grams"},{"name":"dried millet peppers","note":"to taste"},{"name":"boiling water","note":"as needed"}]'::jsonb, '["Rinse the pork belly with skin on, place in a pot with cold water, add 2-3 slices of ginger to remove the gamey smell, bring to a boil, then remove and rinse under cold water to clean off the white foam.","Cut the pork belly into 1.5cm x 1.5cm cubes.","Heat oil in a wok, add rock sugar and stir over low heat until caramelized, then add the cubed pork belly and stir-fry over medium heat until color changes.","Add prepared ginger slices, star anise, cinnamon, light soy sauce, dark soy sauce, cooking wine, dried millet peppers, and salt. Stir-fry over low heat for 1 minute, then add boiling water to just cover the meat.","Cover and bring to a boil over medium heat, then reduce to low heat and simmer for 30 minutes. During simmering, stir every 10 minutes to prevent sticking.","When the liquid has reduced to one-third, turn to medium heat to reduce the sauce until thickened. Then remove from heat and serve."]'::jsonb, '["Meat Dish","Hunan Flavor","Home-style","Braised","Rice Companion","Savory and Slightly Spicy"]'::jsonb),
  ('howtocook:meat_dish/湘祁米夫鸭/湘祁米夫鸭', 'en', 'Xiangqi Rice Flour Duck', 'Meat Dishes', 'A traditional specialty from the Two Qi areas of Hunan. The duck is stir-fried and then coated with mixed rice flour and steamed. The texture is soft and sticky, savory and fragrant, with a long-lasting aftertaste. Duck meat is rich in high-quality protein and B vitamins, combined with rice flour to provide energy, balanced nutrition. The process requires stir-frying first then pressure steaming, which is slightly challenging, suitable for friends with some cooking experience. From preparation to serving takes about 1 hour; if using an old duck, extend the steaming time.', '[{"name":"Duck","unit":"grams"},{"name":"Glutinous rice flour","unit":"grams"},{"name":"Rice flour","unit":"grams"},{"name":"Steamed meat powder","unit":"grams"},{"name":"Fine chili powder","unit":"grams"},{"name":"White pepper powder","unit":"grams"},{"name":"Pork belly","unit":"grams"},{"name":"Ginger and garlic","unit":"grams"},{"name":"Salt","unit":"grams"},{"name":"Cooking oil","unit":"grams"},{"name":"Boiling water","unit":"grams"},{"name":"Chopped green onions","unit":"","note":"to taste"}]'::jsonb, '["Mix glutinous rice flour, rice flour, steamed meat powder, fine chili powder, 5 grams salt, and white pepper powder together evenly.","Have the friendly vendor chop the duck into steaming pieces, slice the ginger, peel the garlic cloves, and slice the pork belly.","Heat the wok with cold oil, stir-fry the pork belly to render fat, then add more cooking oil and heat, add the duck and stir-fry.","Stir-fry the duck until the skin turns brown and crispy, then add ginger, garlic, and salt, continue stir-frying until fragrant.","Turn to low heat, pour in the rice flour mixture and stir-fry, coating the duck evenly. Add boiling water little by little while stirring.","Stir-fry until the duck and rice flour feel moist, then transfer to a bowl. Place in a pressure cooker with water and steam for 20-25 minutes.","Before serving, sprinkle some chopped green onions on top. Enjoy!"]'::jsonb, '["Meat Dish","Hunan","Steamed Dish","Savory","Goes Well with Rice","Local Specialty"]'::jsonb),
  ('howtocook:meat_dish/澳门湿版免治牛肉饭/澳门湿版免治牛肉饭', 'en', 'Macau Wet-Style Minced Beef Rice', 'Meat Dishes', 'This is a classic Macau Portuguese-style fast food. The minced beef is tender and savory, wrapped in a rich sauce and runny egg yolk, then mixed with rice for an oily and enticing taste. The minced beef provides high-quality protein, paired with eggs and onions for balanced nutrition. The steps are simple and easy to follow, perfect for beginners, taking about 30 minutes from prep to plate.', '[{"name":"minced beef","unit":"g","note":""},{"name":"onion","unit":"piece","note":""},{"name":"egg","unit":"piece","note":""},{"name":"butter","unit":"g","note":""},{"name":"green onion","unit":"g","note":""},{"name":"light soy sauce","unit":"tablespoon","note":""},{"name":"dark soy sauce","unit":"tablespoon","note":""},{"name":"ketchup","unit":"tablespoon","note":""},{"name":"sugar","unit":"tablespoon","note":""},{"name":"cooking wine","unit":"tablespoon","note":""},{"name":"black pepper","unit":"g","note":""},{"name":"starch","unit":"tablespoon","note":""},{"name":"water","unit":"ml","note":""},{"name":"steamed rice","unit":"","note":"as needed"}]'::jsonb, '["Put 200g minced beef into a bowl, add 1 tablespoon light soy sauce, half tablespoon sugar, and 2g black pepper, mix well, and let marinate for 10 minutes.","Dice half an onion into small pieces and set aside.","Prepare the sauce: In a bowl, combine 2 tablespoons light soy sauce, 2 tablespoons ketchup, 1 tablespoon cooking wine, 1 tablespoon starch, half tablespoon dark soy sauce, and 50ml water, stir well and set aside.","In another pan, make a poached egg or a sunny-side-up egg, set aside.","Heat the pan, add 10g butter. Once melted, add the diced onion and cook over low heat until fragrant and translucent.","Add the marinated minced beef and stir-fry with the onion until the beef changes color.","Pour in the prepared sauce, add 2g black pepper, and continue to stir-fry until the sauce thickens, then turn off the heat.","Serve the cooked minced beef over hot steamed rice, and top with the prepared poached or sunny-side-up egg.","(Optional) Garnish with 5g chopped green onion."]'::jsonb, '["Meat Dish","Macau-style","Portuguese-style","Beef","Fast Food","Rice Bowl","Minced Beef","Beginner-friendly"]'::jsonb),
  ('howtocook:meat_dish/烤鸡翅', 'en', 'Baked Chicken Wings', 'Meat Dishes', 'Marinated chicken wings are baked at high heat, resulting in slightly charred skin and tender, juicy meat with the savory flavor of black pepper and soy sauce. Rich in high-quality protein and collagen. Moderate difficulty, even beginners can easily handle it. It takes about 1 hour from preparation to serving. You can also add honey or five-spice powder to enhance the flavor according to your preference.', '[{"name":"Chicken mid-joint wings","unit":"pieces"},{"name":"Salt","unit":"g"},{"name":"Black pepper","unit":"g"},{"name":"Soy sauce","unit":"ml"},{"name":"Cooking wine","unit":"ml"}]'::jsonb, '["Place chicken wings in a bowl","Add salt, black pepper, soy sauce, and cooking wine. Marinate for 30-40 minutes.","Preheat oven to 200°C.","Arrange the marinated chicken wings evenly on a baking sheet.","Place the baking sheet on the middle rack and bake for 15-20 minutes.","Remove the baking sheet, flip the chicken wings, and bake for another 15-20 minutes until fully cooked."]'::jsonb, '["Meat Dish","Savory","BBQ","Home-style","Entertaining"]'::jsonb),
  ('howtocook:meat_dish/煎烤羊排/煎烤羊排', 'en', 'Pan-Fried Lamb Chops', 'Meat Dishes', 'A dish with a crispy exterior and tender interior, rich in aroma. First braised with spices, then pan-fried to a golden crust. Rich but not greasy, perfect for family meals or entertaining guests. Lamb is rich in high-quality protein, iron, and zinc, helping to warm and nourish the body. The steps are a bit many, but follow the process and even beginners can succeed; using a pressure cooker takes about 1 hour total, a regular pot about 1.5 hours.', '[{"name":"Lamb chops","unit":"g"},{"name":"Cinnamon","unit":"g"},{"name":"Sichuan peppercorns","unit":"g"},{"name":"Star anise","unit":"piece(s)"},{"name":"Angelica dahurica","unit":"g"},{"name":"Bay leaves","unit":"slice(s)"},{"name":"Salt","unit":"g"},{"name":"Cooking wine","unit":"ml"},{"name":"Chili powder","unit":"g"},{"name":"Cumin seeds","unit":"g"},{"name":"BBQ seasoning","unit":"g"},{"name":"Ground cumin","unit":"g"},{"name":"White sesame seeds","unit":"g"},{"name":"Sugar","unit":"g"}]'::jsonb, '["Cut the lamb chops into pieces along the bone.","Add cold water to a wok, put all lamb chops in. After the water boils, continue blanching for 2-3 minutes, then remove and set aside.","Put the blanched lamb chops, cinnamon, Sichuan peppercorns, star anise, Angelica dahurica, bay leaves, and cooking wine into a pot (pressure cooker or regular pot).","Add drinking water to cover all ingredients. If using a pressure cooker, cook for 30 minutes after pressure is reached. If using a regular pot, simmer for 80 minutes.","Remove the cooked lamb chops, drain well, and place them into an oil-free and water-free wok or frying pan.","Pan-fry over medium-high heat for 6-7 minutes until the fat renders out and the surface turns golden and crispy.","Keep the rendered lamb fat in the pan, add chili powder, cumin seeds, BBQ seasoning, ground cumin, and white sesame seeds, and stir-fry until well combined.","Add sugar and salt (if not added during braising), and stir-fry evenly.","After stir-frying evenly, turn off the heat and plate."]'::jsonb, '["Meat Dish","Pan-Fry/Roast","Spicy","Crispy Outside Tender Inside","Home Cooking","Entertaining"]'::jsonb),
  ('howtocook:meat_dish/牛排/牛排', 'en', 'Steak', 'Meat Dishes', 'This is a classic Western-style pan-seared steak, with a crispy exterior enclosing a tender and juicy interior, paired with butter, garlic, and herbs for rich flavor. Rich in high-quality protein, fats, and minerals like iron and zinc. The cooking process is beginner-friendly, but mastering the heat still requires some practice. It takes 15-30 minutes in total.', '[{"name":"Steak","unit":"grams"},{"name":"Olive oil","unit":"ml"},{"name":"Butter","unit":"grams"},{"name":"Salt","unit":"grams"},{"name":"Black pepper","unit":"grams"},{"name":"Garlic","unit":"cloves"},{"name":"Thyme","unit":"grams"},{"name":"Rosemary","note":"appropriate amount"},{"name":"Pre-made steak sauce","note":"appropriate amount"},{"name":"Mushrooms","unit":"pieces"},{"name":"Baby potatoes","unit":"pieces"},{"name":"Cherry tomatoes","unit":"pieces"},{"name":"Asparagus","note":"appropriate amount"}]'::jsonb, '["Take the steak out of the refrigerator to thaw.","If the steak is frozen, transfer it to the refrigerator the night before and bring it to room temperature half an hour before cooking.","Do not thaw the steak in water or by heating.","Wash the cherry tomatoes, baby potatoes, and mushrooms, then cut them in half and set aside.","Peel the garlic, keep 5-8 larger cloves, and flatten them with the side of a knife. Set aside.","Preparing the steak.","For ribeye steak (see How to Choose Different Cuts of Steak), use kitchen scissors to vertically cut into the connective tissue at the center of the ribeye, making 1-2 cuts. This is because the ''eye'' of the ribeye (the connective tissue) contracts sharply at high heat, causing the steak to deform and heat unevenly.","For sirloin steak, if you dislike the fat along the edge, you can trim it off slowly with a knife.","Then, wrap the steak in paper towels and pat it dry until no obvious moisture remains when you lift the steak from the cutting board.","Turn the stove to high heat (see appendix for heat level descriptions), and add olive oil to the pan. Heat the pan for 15-30 seconds.","Season the steak. Sprinkle sea salt and black pepper evenly over the entire surface of the steak, rubbing and massaging to embed the salt and pepper into the meat. Note: The steak must be cooked immediately after seasoning; it is not recommended to season in advance, as the salt will draw out moisture, affecting cooking and losing flavor.","Heat the oil to 60-80% hot (see oil temperature tips), then slowly place the steak into the pan, starting from the near side and moving away.","If you are using potatoes as a side dish, place them in a bowl and microwave for 10 minutes, or boil in water for 3-5 minutes.","Sear one side for 1.5 minutes (this timing is for a steak about 2-3 cm thick. If your steak is thinner, reduce to 1 minute. If thicker, increase to 2-2.5 minutes.)","Flip and sear the other side for 1.5 minutes.","For sirloin and filet mignon, use chopsticks or a spatula to stand the steak on its side and sear the edges for about 30 seconds.","Reduce the heat to medium, then quickly add butter, garlic, and thyme in order. Use a spatula to push the butter around the pan until fully melted. Place the garlic under the steak to enhance flavor.","Tilt the pan so the oil pools to one side.","Place the herbs and garlic on top of the steak, and use a spoon to continuously baste the steak with the oil from the pan. Do this for 30 seconds, then flip the steak and repeat for another 30 seconds.","You can gauge the heat by observing the oil when basting. If the oil bubbles on the steak and doesn''t turn dark brown, the temperature is right.","If your steak wasn''t properly dried or was thawed incorrectly, or if you seasoned it in advance, a lot of water will come out in the pan, resulting in the steak being ''boiled'' and losing flavor.","If large oil bubbles appear on the steak surface and the oil turns dark brown, the oil is too hot. Remove the pan from the stove for a moment before continuing to baste.","Remove the steak to a cutting board, wrap it in aluminum foil, and let it rest for 5-10 minutes. This process (called resting) allows the steak''s own heat to continue cooking and lock in moisture.","Add the side dishes (potatoes, tomatoes, mushrooms) to the pan and sauté over medium heat for 5 minutes.","Take out the steak and cut it into strips about 1.5 cm wide. You can now observe the doneness of the beef.","Remove the side dishes, plate them, and drizzle with the remaining oil from the pan or steak sauce (optional)."]'::jsonb, '["Meat Dish","Western-style","Pan-seared","Savory","Party","Quick"]'::jsonb),
  ('howtocook:meat_dish/猪皮冻/猪皮冻', 'en', 'Pork Skin Jelly', 'Meat Dishes', 'Pork skin jelly is a traditional cold dish commonly seen in northern Chinese New Year''s Eve dinner. It is crystal clear, smooth and chewy, perfect for drinking. Pork skin is rich in collagen and has beautifying effects. This dish is a bit difficult; it requires patience to remove the gamey smell and long simmering. Estimated preparation time is about 24 hours.', '[{"name":"Pork skin","unit":"kg"},{"name":"Water","unit":"kg"},{"name":"Salt","unit":"g"},{"name":"MSG","unit":"g"},{"name":"Chicken bouillon","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Scallion","unit":"g"},{"name":"Ginger slices","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Star anise","unit":"g"},{"name":"Sichuan pepper","unit":"g"},{"name":"Cooking wine","unit":"ml"},{"name":"White vinegar","unit":"g"},{"name":"Angelica dahurica","note":"to taste"},{"name":"Cinnamon","note":"to taste"},{"name":"Cloves","note":"to taste"},{"name":"Bay leaves","note":"to taste"},{"name":"Cumin seeds","note":"to taste"}]'::jsonb, '["Cut the pork skin into pieces no larger than 10 cm. Soak in clean water for 12 hours. Then put in cold water, add 10g ginger and 50ml cooking wine, blanch for 5-10 minutes. Remove and put into cold water.","Place the blanched pork skin on a cutting board. Remove all the white fat layer, then cut into strips no thicker than 3 mm. Put in a bowl.","Add 20g white vinegar and 5g salt. Rub vigorously for 3 minutes, then rinse with clean water. The pork skin should now have almost no gamey smell.","Add 4kg water to the pot. Put in the pork skin, 10g scallion, 10g ginger slices, 10g star anise, and 5g Sichuan pepper. Bring to a boil over high heat, then simmer over low heat for 90 minutes until the pork skin is soft and tender.","Add 8g salt, 10g MSG, 15g chicken bouillon, 50ml light soy sauce, and 20ml dark soy sauce to season. Pour into a plate. Remove the scallion, ginger, and star anise. Let cool until it becomes jelly-like.","Refrigerate. When serving, cut into small pieces or thick slices."]'::jsonb, '["Meat Dish","Salty and Savory","Braising","Northern","Goes with Alcohol","New Year''s Eve Dinner"]'::jsonb),
  ('howtocook:meat_dish/猪肉烩酸菜', 'en', 'Pork Braised with Sauerkraut', 'Meat Dishes', 'Pork braised with sauerkraut is a Northern Chinese home-style stew, with rich sour aroma, tender pork belly, and flavorful ribs. It mainly provides protein, and the sauerkraut also brings beneficial components like lactic acid bacteria. The steps are clear and easy for beginners to follow, but requires patient slow cooking, taking about 3 hours from start to finish.', '[{"name":"Pork belly or pork ribs","unit":"克"},{"name":"Northeastern sauerkraut","unit":"克"},{"name":"Scallion","unit":"根"},{"name":"Ginger","unit":"克"},{"name":"Garlic","unit":"瓣"},{"name":"Salt","unit":"克"},{"name":"Light soy sauce","unit":"克"},{"name":"Five-spice powder","unit":"克"},{"name":"Cooking wine","unit":"毫升"},{"name":"Star anise","unit":"颗"}]'::jsonb, '["Cut the scallions into sections; cut 50g of ginger into sections and 50g into minced ginger; mince the garlic; set aside.","Shred all the sauerkraut, rinse with water 2 to 3 times, and set aside.","Put the ribs and pork belly into a pot, pour in cold water to submerge. Add all the scallion sections, 50g ginger sections, and 20ml cooking wine. Bring to a boil over high heat, then wait 5 minutes. Turn off the heat, remove the ribs and pork belly, rinse with cold water to remove scum, and set aside.","Slice or chunk the cooked pork belly, and set aside.","Wash the previous pot clean and dry it (otherwise the oil will splatter when added).","Add oil to the pot over medium heat, sauté the minced ginger and garlic until fragrant, then add the pork belly and ribs. Fry until golden, then add 10g five-spice powder and 15g light soy sauce, stirring with a spatula for 1-2 minutes.","Add the rinsed sauerkraut shreds to the pot and stir-fry for 3 minutes.","Pour in purified water until the ingredients are just submerged, add 2 star anise, turn to high heat until the water boils. Then reduce to medium heat, cover, and simmer.","Wait 1.5 to 2 hours until the pork belly is tender (can be easily pierced with chopsticks).","Remove the lid, turn to high heat to reduce the sauce, stirring the ingredients until only a thin layer of liquid covers the bottom, then turn to low heat, ready to season.","Seasoning: add 10g of salt, stir well.","Turn off the heat and serve."]'::jsonb, '["Meat Dish","Sour and Aromatic","Stew","Northern","Home-style","Appetizing with Rice"]'::jsonb),
  ('howtocook:meat_dish/甜辣烤全翅', 'en', 'Sweet and Spicy Roasted Whole Chicken Wings', 'Meat Dishes', 'These sweet and spicy roasted whole chicken wings are cooked in an air fryer, with a slightly crispy exterior and juicy interior. The sweet and spicy flavor is very popular. Chicken is rich in high-quality protein, and air frying instead of deep frying greatly reduces oil, making it lighter to eat. The process is clear and straightforward—just marinate in advance and flip once halfway. It''s friendly for beginners. From preparation to serving takes about 3 hours, mostly waiting time for marinating, so it''s not complicated.', '[{"name":"Whole chicken wings","unit":"pieces"},{"name":"Light soy sauce","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Garlic powder","unit":"g"},{"name":"White pepper powder","unit":"g"},{"name":"Sugar","unit":"g"},{"name":"Sweet paprika","unit":"g"},{"name":"Chili powder","unit":"g"},{"name":"Oyster sauce","unit":"ml"},{"name":"Water","unit":"ml"},{"name":"Oil","unit":"ml"}]'::jsonb, '["Take 4 fresh whole chicken wings and cut the skin between the two bones of the wingette with a knife, one cut on each side.","Place the 4 whole chicken wings in a bowl. Add 45 ml light soy sauce, 15 ml dark soy sauce, 10 g garlic powder, 5 g white pepper powder, 10 g sugar, 10 g sweet paprika, 5 g chili powder, 15 ml oyster sauce, 20 ml water, and 10 ml oil.","Use a spoon to evenly spread the sauce over the chicken wings, especially into the cuts on the wingettes, for about 3 minutes.","Cover the bowl with plastic wrap to prevent splattering while marinating, and place it in the refrigerator for 120 minutes.","Remove the chicken wings. Place 4 chicken wings in a foil tray and pour the remaining sauce from the bowl evenly over them.","Place the foil tray on the air fryer basket. Roast at 200°C for 25 minutes.","Open the air fryer, carefully remove the foil tray, and flip the chicken wings.","Continue roasting at 200°C for 25 minutes.","Remove and serve."]'::jsonb, '["Meat","Sweet and Spicy","Roasted","Air Fryer","Goes Well with Drinks","Home-style"]'::jsonb),
  ('howtocook:meat_dish/田螺酿/田螺酿', 'en', 'Stuffed River Snails', 'Meat Dishes', 'Stuffed river snails are the top of Yangshuo''s ''Eighteen Stuffed Dishes''. The snail meat is chewy and firm, the pork is tender and smooth, and the aroma of perilla and mint is refreshing. It was featured on ''A Bite of China 2''. Rich in protein and trace elements, the combination of snail and pork provides complementary nutrition. This dish has many steps and is a challenge for beginners. Snails need to be purged for half a day in advance. Actual cooking takes about 40 minutes. Suitable for family gatherings on holidays.', '[{"name":"Large river snails","unit":"pieces"},{"name":"Pork","unit":"g"},{"name":"Mint leaves","unit":"g"},{"name":"Perilla leaves","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Scallion","unit":"stalk"},{"name":"Guilin Sanhua liquor","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Pickled bamboo shoots","unit":"g"},{"name":"Garlic","unit":"cloves"},{"name":"Dried chili peppers","unit":"pieces"},{"name":"Oyster sauce","unit":"ml"},{"name":"Starch","unit":"g"},{"name":"White pepper powder","unit":"g"}]'::jsonb, '["Buy snails in the morning, put them in a basin of water, and let them sit for the afternoon to purge sand.","You can add a few drops of sesame oil (or wasabi~) to the water to speed up purging.","Scrub the snail shells clean with a brush (this step can take some time).","Use pliers or a cleaver to cut off the tail of the snail (about 1/3 to half).","Bring a large pot of water to a boil, blanch the snails for 1-2 minutes (do not overdo it, or the meat will become tough).","Remove and use a toothpick to pick out the snail meat, discard the operculum and the black mud intestine.","Rinse the snail shells clean and shake off water; set aside.","Wash the snail meat with salt, then chop into small pieces (do not mash; keep a grainy texture for chewiness).","Mince the pork.","Finely chop mint leaves and perilla leaves, mince ginger, and slice scallion into rings.","Put the chopped snail meat, minced pork, chopped mint and perilla, minced ginger, and scallion in a bowl.","Add 15ml Sanhua liquor, 15ml light soy sauce, 3g salt.","Optional: add 10ml oyster sauce, 2g white pepper powder, 10g starch.","Stir in one direction until the filling is sticky and firm.","For convenience, you can put all the above ingredients directly into a meat grinder and grind.","Use chopsticks to stuff the filling into the snail shells, filling them as tightly as possible without breaking the shell.","Repeat until all snails are stuffed.","Heat the wok, pour in 30ml cooking oil. Optionally add pickled bamboo shoots and dried chili peppers and stir-fry until fragrant.","Pour in about 300ml water or broth, add 15ml light soy sauce and 2g salt. Bring to a boil over high heat.","Put the stuffed snails into the pot, cover, and simmer over medium-low heat for 10 minutes.","Do not stir frequently during simmering; wait until the filling is about 60-70% cooked and set before gently stirring.","Uncover, add the remaining fresh mint and perilla leaves, and simmer for another 2-3 minutes.","Increase heat to reduce the sauce until thickened, then remove from heat and serve."]'::jsonb, '["Meat Dish","Savory","Stuffed Dish","Braising","Guangxi Cuisine","Banquet"]'::jsonb),
  ('howtocook:meat_dish/番茄红酱', 'en', 'Tomato Red Sauce', 'Meat Dishes', 'This Italian-style sauce is rich and delicious, with a combination of vegetables and beef that provides a rich texture. It is high in protein and various vitamins, nutritionally balanced. The cooking process is a bit involved and requires some basic cooking skills, such as browning the beef until granular and controlling the heat for slow simmering. From prep to finish, it takes about an hour. You can make a larger batch and freeze it for later use, which is very convenient.', '[{"name":"ground beef","unit":"g"},{"name":"garlic cloves","unit":"clove"},{"name":"carrot","unit":"piece"},{"name":"celery","unit":"stalk"},{"name":"onion","unit":"piece"},{"name":"olive oil","unit":"ml"},{"name":"sugar","unit":"g"},{"name":"salt","unit":"g"},{"name":"black pepper","unit":"g"},{"name":"tomato paste","unit":"g"},{"name":"milk","unit":"ml"},{"name":"dried basil or thyme (optional)","note":"to taste"}]'::jsonb, '["Finely chop the carrots, celery, and onion; slice the garlic cloves.","Add 10ml olive oil, heat the oil and add the vegetables. Stir-fry over high heat until they start to change color, then remove from the pan.","Add another 10ml oil to the pan, add garlic and stir-fry for 10 seconds. Add the ground beef, sugar, salt, pepper, and spices. Fry until the beef is crispy (with a granular texture).","Add the cooked vegetables and tomato paste, continue to stir-fry, and mix well.","Slowly pour in the milk in batches, and cook over medium-low heat for 30 minutes. Done."]'::jsonb, '["Meat Dish","Italian","Stewed","Savory Sauce","Side Dish","Home-style"]'::jsonb),
  ('howtocook:meat_dish/瘦肉土豆片/瘦肉土豆片', 'en', 'Lean Pork and Potato Slices', 'Meat Dishes', 'A quick home-style stir-fry, with tender pork slices and soft yet chewy potato slices infused with the fragrance of garlic sprouts, typical of home cooking. Lean pork provides high-quality protein and iron, while potatoes supply carbohydrates and dietary fiber, making a balanced dish. The process is simple, requiring attention to knife skills and heat control, suitable for beginners with some experience. From preparation to serving, it takes about 1 hour.', '[{"name":"Lean pork","unit":"g"},{"name":"Potato","unit":"g"},{"name":"Garlic sprout","unit":"stalk"},{"name":"Cornstarch","unit":"g"},{"name":"Light soy sauce","unit":"g"},{"name":"Dark soy sauce","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Cooking oil","unit":"ml"}]'::jsonb, '["Peel the potatoes, cut in half, then slice into about 2mm thin pieces; set aside.","Wash the garlic sprouts and cut into about 1cm sections; set aside.","Wash the lean pork and slice into about 2mm thin pieces. Place in a bowl, add 5g cornstarch, 5g light soy sauce, and 3g dark soy sauce. Marinate for ten minutes; set aside.","While the pork is marinating, bring a pot of water to a boil. Add the potato slices and blanch for about 5 minutes.","Heat the wok and add 10ml-15ml cooking oil. Wait 10 seconds for the oil to heat up.","Add the marinated pork, stir-fry until it changes color. Then add the garlic sprouts and stir-fry together for about 20 seconds.","Add the potato slices, keep stir-frying. Add 2g salt and 5g light soy sauce.","Stir-fry for about 3 minutes, then plate."]'::jsonb, '["Meat Dish","Home-style","Quick","Stir-fry","Rice Accompaniment","Fragrant"]'::jsonb),
  ('howtocook:meat_dish/白菜猪肉炖粉条', 'en', 'Cabbage and Pork Braised with Vermicelli', 'Meat Dishes', 'Pork, cabbage and vermicelli braised is a classic home-style stew from Northeast China. The broth is rich and savory, the pork belly is tender, the vermicelli absorbs the meat flavor and becomes smooth and chewy, and the cabbage is sweet and refreshing. The dish is balanced with meat and vegetables, providing protein, vitamins and carbohydrates, nutritious and filling. The cooking process requires some patience, especially handling the vermicelli and controlling the heat, which may be challenging for beginners, but following the steps makes it hard to fail. From start to finish, it takes about 45 minutes to serve.', '[{"name":"Pork belly","unit":"g"},{"name":"Chinese cabbage","unit":"g"},{"name":"Dried potato vermicelli","unit":"g"},{"name":"Thirteen-spice","unit":"g"},{"name":"Chicken bouillon","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Light soy sauce","unit":"ml"}]'::jsonb, '["Bring water to a boil in a pot. Add dried vermicelli and cook for 5 minutes. Pour out together with water into a container, cover and continue to soak. Set aside. (Do this first; proceed with the following steps during soaking)","Slice pork belly into 3mm thick pieces. Set aside.","Separate cabbage leaves from the stalks. Cut into two portions of slices. Set aside.","Heat the wok, add 10-15ml cooking oil. Wait 10 seconds for the oil to heat up.","Add pork belly and stir-fry until the meat changes color.","Add dark soy sauce and stir-fry for 1 minute to color the meat.","Add cabbage stalks, salt, and light soy sauce. Stir-fry for 1 minute (if sticking, add 10ml water).","Add water to submerge all ingredients. Add chicken bouillon and thirteen-spice. Bring to a boil, then reduce heat and simmer for 20 minutes.","Drain the vermicelli, cut into short sections, and place in a bowl. Set aside.","Add cabbage leaves, stir well. Place vermicelli on top of the vegetables, cover and cook for another 5 minutes.","Taste, turn off heat, and reduce sauce."]'::jsonb, '["Meat Dish","Northeastern Cuisine","Home-style Stew","Savory","Rice Companion","Meat-Vegetable Balance"]'::jsonb),
  ('howtocook:meat_dish/空气炸锅脆皮现腌炸鸡/空气炸锅脆皮现腌炸鸡', 'en', 'Air Fryer Crispy Marinated Fried Chicken', 'Meat Dishes', 'Air fryer fried chicken is a home-cooked meat dish that is first marinated and then fried. The crust is crispy and the inside is juicy. The seasoning can be adjusted according to taste. Chicken wings are rich in high-quality protein and fat, making them suitable as a main dish or snack. Actual cooking time is about 55-70 minutes (including one coating; if choosing double coating, about 70-90 minutes). For best results, you can refrigerate and marinate overnight (prepare the day before and fry the next day).', '[{"name":"chicken wing mid-joints","unit":"pieces"},{"name":"light soy sauce","unit":"ml"},{"name":"garlic powder","unit":"g"},{"name":"paprika","unit":"g"},{"name":"onion powder","unit":"g"},{"name":"black pepper","unit":"g"},{"name":"all-purpose flour","unit":"g"},{"name":"starch","unit":"g"},{"name":"cooking oil","unit":"ml"},{"name":"yogurt or milk","unit":"ml"},{"name":"egg","unit":"piece"},{"name":"baking powder","unit":"g"}]'::jsonb, '["After washing the chicken wings, pat them dry. Make 2 cuts on each side of each wing to allow flavor to penetrate.","Prepare marinade: mix 15ml light soy sauce, 8g garlic powder, 5g paprika, 3g onion powder, 3g black pepper, and 5ml milk or Greek yogurt (optional, for tenderness). Stir well.","Place the marinade and chicken wings in a large zip-lock bag, massage thoroughly, and let sit in the refrigerator overnight.","Coating powder: mix 60g all-purpose flour, 30g starch, 5g garlic powder, 5g paprika, 2g onion powder, 2g black pepper, and 1g baking powder (optional, for extra crispiness). Stir well.","Batter (optional): beat 1 egg with 5ml milk or water until well combined.","Coating: shake off excess moisture from the chicken wings, place them in the coating powder, press gently, shake off excess powder, and let rest for 10 minutes.","Batter (optional): For a thicker coating, dip in batter, then repeat the coating step.","Dip the rested coated chicken wings into the batter, then gently shake off excess.","Place back into the coating powder, press gently, and shake off excess.","Let rest for 20 minutes (longer if possible, for a more stable crust).","Preheat the air fryer to 180°C for 5 minutes.","Brush the basket with a thin layer of oil. Place the chicken wings skin-side down, and spray or brush a thin layer of oil on top.","Set air fryer to 180°C and cook for 10 minutes.","Open the basket, flip the wings, spray or brush with more oil, then cook at 180°C for another 6 minutes.","Check the color of the skin and poke the thickest part with a toothpick to see if any blood comes out.","If needed, cook at 200°C for 1-2 minutes to crisp and brown (you can do this in increments, cooking 1 minute at a time and checking)."]'::jsonb, '["Meat Dish","Crispy","Garlic","Air Fried","Home-style","Main Course"]'::jsonb),
  ('howtocook:meat_dish/粉蒸肉', 'en', 'Steamed Pork with Rice Flour', 'Meat Dishes', 'Steamed Pork with Rice Flour is a classic Chinese steamed dish, rich in aroma and soft in texture, widely popular as home-style cuisine. Pork belly provides high-quality protein and fat, paired with root vegetables like potatoes for balanced nutrition. This dish is suitable for those with some cooking experience, taking about 90 minutes from preparation to completion.', '[{"name":"pork belly","unit":"g"},{"name":"steamed pork rice flour","unit":"g"},{"name":"light soy sauce","unit":"ml"},{"name":"dark soy sauce","unit":"ml"},{"name":"cooking wine","unit":"ml"},{"name":"Pixian doubanjiang (broad bean paste)","unit":"g"},{"name":"minced ginger","unit":"g"},{"name":"minced garlic","unit":"g"},{"name":"white sugar","unit":"g"},{"name":"potato or pumpkin","unit":"g"},{"name":"water","unit":"ml"}]'::jsonb, '["Wash the pork belly and cut into slices about 5cm long, 3cm wide, and 0.5cm thick.","Finely mince ginger and garlic into particles no larger than 1mm in diameter.","In a large bowl, combine the sliced pork belly, 15ml light soy sauce, 10ml dark soy sauce, 15ml cooking wine, 10g Pixian doubanjiang (broad bean paste), 10g minced ginger, 10g minced garlic, and 5g white sugar.","Stir well with chopsticks, cover with plastic wrap, and marinate at room temperature (20°C-25°C) for 30 minutes.","After marinating, add 100g steamed pork rice flour and continue stirring for 2 minutes until each slice is evenly coated.","Peel potato and slice into pieces about 0.8cm thick, each piece roughly 5cm x 5cm, total weight 300g.","Line the bottom of a 20cm diameter deep bowl with potato slices, minimizing overlap.","Evenly arrange the coated pork slices on top of the potatoes, pressing down firmly.","Add 2000ml water to a steamer, heat until it boils steadily (100°C).","Place the bowl into the steamer, cover with lid.","Steam over medium heat for 60 minutes (keep water boiling steadily, about 600W heat power).","After time, insert a chopstick into the center of a meat piece; if it goes through easily without resistance, it''s done.","If not, continue steaming for another 10-15 minutes until meat is tender and fat has rendered.","Remove from steamer, plate, and serve."]'::jsonb, '["meat dish","Sichuan cuisine","steamed","soft and sticky","rice companion","home-style"]'::jsonb),
  ('howtocook:meat_dish/糖醋排骨/糖醋排骨', 'en', 'Sweet and Sour Pork Ribs', 'Meat Dishes', 'Sweet and Sour Pork Ribs is a classic dish known for its tangy and sweet flavor, crispy exterior, and tender interior. It is widely loved. Pork ribs are rich in high-quality protein and calcium, providing good nourishment. The dish involves multiple steps such as blanching, deep-frying, caramelizing sugar, and reducing sauce, requiring some skill in heat control and seasoning. It may not be for beginners, but following this optimized process ensures a high success rate. Estimated cooking time: about 45 minutes.', '[{"name":"pork ribs","unit":"g"},{"name":"white sugar","unit":"g"},{"name":"cooking oil","unit":"ml"},{"name":"light soy sauce","unit":"ml"},{"name":"oyster sauce","unit":"ml"},{"name":"dark soy sauce","unit":"ml"},{"name":"chicken bouillon","unit":"g"},{"name":"ginger slices","unit":"slices"},{"name":"sesame seeds","unit":"g"},{"name":"ketchup","unit":"g"},{"name":"rice vinegar","unit":"ml"},{"name":"five-spice powder","unit":"g"}]'::jsonb, '["Put the ribs and ginger slices in cold water. Heat over high heat until the water boils and a lot of foam appears, then reduce to medium heat. When the water is continuously boiling, reduce to low heat and blanch for 2–3 minutes. Remove and set aside.","Rinse the ribs repeatedly with boiling water 2-3 times to thoroughly remove blood foam.","Pour enough cooking oil into the pot for deep-frying (amount depends on pot size; for a typical household, about 300 ml is recommended). Heat the oil to about 170°C, then add the ribs and fry for 3–5 minutes until the surface is lightly golden. Remove and drain oil.","Take another clean pot, heat 50 ml hot water over low heat, add 30 g white sugar, and gently stir until the sugar is completely dissolved and turns slightly pale yellow. The key is to observe the sugar dissolving; do not rely too much on color change.","Pour the fried ribs into the pot with the sugar syrup. Stir-fry quickly for 30 seconds, then add in order: 5 ml rice vinegar, 5 ml light soy sauce, 5 ml oyster sauce, 2 g chicken bouillon, 10 g ketchup, 0.5 g five-spice powder. Stir-fry for another 30 seconds to evenly coat the ribs. Then add boiling water just enough to cover the ribs.","Bring the liquid in the pot to a boil over high heat, then add 5 ml dark soy sauce for color and quickly reduce the sauce. If the ribs are large, you can turn to low heat and simmer for 5–10 minutes to allow better flavor absorption. Do not use medium heat for a long simmer of 20 minutes, as it will harm the texture.","Transfer to a plate, sprinkle with 2 g sesame seeds, and serve."]'::jsonb, '["Meat Dish","Sweet and Sour","Deep-Fried","Home-Style","Goes with Rice","Banquet"]'::jsonb),
  ('howtocook:meat_dish/糖醋里脊', 'en', 'Sweet and Sour Pork Tenderloin', 'Meat Dishes', 'Sweet and sour pork tenderloin with a rich sweet and tangy flavor, crispy outside and tender inside, is a beloved home-style dish common in many regional cuisines. Pork tenderloin provides high-quality protein, but the coating and frying plus the sugar-vinegar sauce make it relatively high in calories. The key is mastering marination, double-frying, and sauce preparation—a bit challenging for beginners. It''s recommended to prep all ingredients in advance and cook continuously. From prep to serving, it takes about 45 minutes to 1 hour.', '[{"name":"pork tenderloin","unit":"g"},{"name":"vinegar","unit":"g"},{"name":"white sugar","unit":"g"},{"name":"cornstarch","unit":"g"},{"name":"egg","unit":"g"},{"name":"light soy sauce","unit":"ml"},{"name":"cooking wine","unit":"g"},{"name":"oyster sauce","unit":"g"},{"name":"ketchup","unit":"ml"},{"name":"white pepper powder","unit":"g"},{"name":"salt","unit":"g"}]'::jsonb, '["Marinate the meat: First slice the pork tenderloin into thick pieces, then use the back of a knife to pound it a bit to loosen the meat. Cut into finger-thick strips. Add cooking wine, light soy sauce, oyster sauce, salt, white pepper powder, and one egg. Mix well with your hands and marinate for at least 20 minutes.","Prepare the sauce: Mix ketchup, 10g vinegar, 30g white sugar, and 150ml water. Stir until the sugar dissolves. Set aside.","Coat with starch: It''s better to coat all the strips first before frying, so you won''t be in a rush. Prepare a large bowl with cornstarch, and coat each meat strip thoroughly with cornstarch.","Frying: Heat oil to 160°C and add the pork strips. You can test with a dry chopstick – if small bubbles form around it, the oil is ready. Fry over medium heat.","Fry until the surface turns light yellow, then remove. Maintain medium heat throughout. Then, heat the oil to 200°C and deep-fry the strips again for only 40 seconds until the skin becomes crispy. Remove immediately.","Coat with sauce: In a separate pan, add a little oil, pour in the prepared sauce, and bring to a boil. Add the fried pork strips and stir-fry until each piece is evenly coated with the sauce.","Put the fried pork strips in and stir-fry. Turn off the heat and plate."]'::jsonb, '["Meat Dish","Sweet and Sour","Pan-fried","Home-style","For Guests","Goes Well with Rice"]'::jsonb),
  ('howtocook:meat_dish/红烧猪蹄/红烧猪蹄', 'en', 'Braised Pork Trotters', 'Meat Dishes', 'Braised pork trotters is a classic home-cooked dish with rich sauce and tender, glutinous meat. It is savory, sweet, and extremely appetizing. Pork trotters are rich in collagen and protein, making them nutritious. This dish is somewhat challenging for beginners, but using a pressure cooker simplifies the process; it''s easier for those with some cooking experience. From preparation to completion takes about 1 hour.', '[{"name":"pork trotters","unit":"piece"},{"name":"bay leaves","unit":"piece"},{"name":"ginger","unit":"slice"},{"name":"scallion","unit":"stalk"},{"name":"dark soy sauce","unit":"ml"},{"name":"cinnamon stick","unit":"stick"},{"name":"rock sugar","unit":"piece"},{"name":"cooking wine","unit":"ml"},{"name":"light soy sauce","unit":"ml"},{"name":"salt","unit":"g"},{"name":"star anise","unit":"piece"},{"name":"cooking oil","unit":"ml"}]'::jsonb, '["Put the chopped pork trotters (kindly done by the vendor) into a pot of cold water, add 20 ml cooking wine and scallion and ginger, boil for 15 minutes to remove the bloodiness.","Heat the wok with cold oil, pour in 30 ml cooking oil, add 7-8 rock sugar pieces, cook on low heat until caramelized, using a spatula to crush the rock sugar, about 2 minutes.","Once caramelized, add the blanched pork trotters, continue on low heat, stir-fry until all trotters are lightly browned on both sides.","Add 2 bay leaves, 1 cinnamon stick, 4 star anise, 20 ml light soy sauce, 20 ml dark soy sauce, 10 ml cooking wine, 3 slices ginger, 8 g salt, turn to medium heat, continue stir-frying for 1 minute.","Add boiling water or cold water, enough to cover the trotters, cover the lid, bring to a boil over high heat, then turn off the heat.","Pour all the contents from the wok into a pressure cooker, pressure cook for 15 minutes (if you don''t have a pressure cooker, you can simmer in the wok over low heat after boiling).","After 15 minutes, pour the pressure cooker contents back into the wok, turn to high heat to reduce the sauce. At this point, you can taste with chopsticks; if bland, add 2-3 g salt.","The time for reducing sauce over high heat depends on the amount of liquid; usually 30 seconds is enough. It''s fine to leave a bit more sauce; the braised trotter sauce is also great with rice."]'::jsonb, '["Meat Dish","Savory and Aromatic","Glutinous","Braised","Appetizing","Home-style"]'::jsonb),
  ('howtocook:meat_dish/红烧肉/南派红烧肉', 'en', 'Southern-Style Red-Braised Pork Belly', 'Meat Dishes', 'This red-braised pork belly dish has a bright red color, melt-in-your-mouth fat, tender and not dry lean meat, with a savory-sweet taste—a classic southern sweet flavor. Pork belly provides high-quality protein and rich collagen, while spices help remove any gamey taste and warm the stomach. Although it requires caramelizing sugar and slow simmering, each step is broken down clearly and easy to follow, so even beginners can succeed. It takes about 1.5 hours from start to table.', '[{"name":"Pork belly","unit":"g"},{"name":"Oil","unit":"ml"},{"name":"Rock sugar","unit":"g"},{"name":"White sugar","unit":"g"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Cooking wine","unit":"ml"},{"name":"Bay leaves","unit":"leaf"},{"name":"Star anise","unit":"piece"},{"name":"Ginger","unit":"slice"},{"name":"Scallions","unit":"g"},{"name":"Garlic","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Sichuan peppercorns","unit":"g"},{"name":"Cold water","note":"enough to cover ingredients"},{"name":"Boiling water","note":"enough to cover ingredients"}]'::jsonb, '["Do not cut the pork belly into small pieces yet; cut into large chunks that can fit in the pot (about 5–6 cm wide).","Slice ginger (each slice about 3 mm thick).","Bring water to a boil.","Use tap water for cold water.","Cut the white parts of scallions into small sections (preferably scallions, but green onions are also fine).","Cut garlic in half lengthwise, do not smash, otherwise it will be hard to remove and affect the flavor during final reduction.","Divide the aromatics into two ''prep packs'':","Pack A (for removing odor): 2 slices ginger, 2 scallion sections.","Pack B (for simmering): remaining 4 slices ginger, scallion whites, garlic cloves, Sichuan peppercorns, star anise, bay leaves, all placed in a small bowl for later use.","Place the large pork belly chunks in a pot with cold water, add 20 ml cooking wine and Pack A (2 slices ginger, 2 scallion sections), bring to a boil and cook for 15 minutes to remove bloodiness. Remove and rinse clean.","Remove the blanched pork belly, let cool slightly (until not too hot to handle). Cut into cubes of about 3 cm x 3 cm x 3 cm (after blanching, the meat tightens, making it easier to cut than raw meat, and the cubes are more uniform. The final size after cooking will be about 2.5 cm, ideal for eating and cooking through).","In a separate pot, caramelize sugar. Note: In this recipe, use ''Method 2'' mentioned: when the sugar syrup forms dense small bubbles, quickly add Pack B (ginger, scallion whites, garlic, Sichuan peppercorns, star anise, bay leaves) to the pot and stir-fry until fragrant.","After the aromatics become fragrant (within 5-10 seconds), do not add boiling water yet. Immediately add the blanched pork belly and stir-fry over high heat to evenly coat the meat with caramelized sugar and render fat. When you smell the meat fragrance, pour in boiling water until the meat is fully submerged, cover the pot, reduce heat to medium-low, and simmer for 50-60 minutes (40 minutes if using a pressure cooker).","Add 10 ml cooking wine.","After covering and bringing to a boil, every 25 minutes open the lid and skim off any oil and foam floating on the surface.","When the liquid level reduces to three-fifths of the height of the meat and the pot bottom, turn to medium heat, remove all aromatics except the meat and liquid, and start reducing the sauce.","Open the lid, and when the sauce is nearly gone and thick, remove from heat (be careful not to dry it out completely)."]'::jsonb, '["Meat Dish","Southern-Style","Red-Braised","Sweet","Rice Accompaniment","Home-style"]'::jsonb),
  ('howtocook:meat_dish/红烧肉/简易红烧肉', 'en', 'Easy Braised Pork Belly', 'Meat Dishes', 'This home-style dish has a glossy red-brown color, tender and soft texture, rich sauce without being greasy, and a deep soy flavor. It''s especially satisfying with rice. Pork belly provides high-quality protein and essential fatty acids, and adding quail eggs or tofu skin makes it more nutritious. The method is quite beginner-friendly, taking about 1.5 hours from prep to serving.', '[{"name":"Pork belly","unit":"lb"},{"name":"Quail eggs or chicken eggs","unit":"pieces"},{"name":"Tofu skin","unit":"g"},{"name":"Ginger","unit":"slices"},{"name":"Rock sugar","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Cooking wine","unit":"ml"},{"name":"Bay leaves","unit":"leaves"},{"name":"Star anise","unit":"pieces"},{"name":"Salt","unit":"g"},{"name":"Water","unit":"ml"},{"name":"Scallion","note":"white part only, to taste"}]'::jsonb, '["Cut pork belly into large chunks (about 4.5 cm; freezing for half an hour to an hour makes cutting easier)","Cut tofu skin into 2 cm wide strips","Slice ginger (about 3 mm thick per slice)","Bring water to a boil","Boil quail eggs and poke holes with a fork or toothpick (as many as possible for better flavor)","Scallion, white part only","Place the cut pork belly in a pot of cold water, add cooking wine, scallion, and ginger, boil for 15 minutes to remove bloodiness","Put two slices of ginger in the pot for flavor","Over medium-low heat, directly add the pork belly without oil. Sear all six sides of each piece until oil renders.","Pour out the rendered oil and set aside. Push the pork belly to one side, add 15g rock sugar, and stir-fry until the sugar melts.","Once melted, stir-fry the pork belly with the sugar until evenly coated, then add","10ml light soy sauce","15ml dark soy sauce","5ml cooking wine","Stir-fry until well colored.","Add boiling water and braise for 40 minutes (if your knife skills are poor and chunks are too large, extend the time accordingly). Then add","2 slices ginger","3 bay leaves","2 star anise","Cover and bring to a boil, then add the boiled and poked quail eggs and tofu skin. Reduce to medium-low heat and simmer for 40 minutes (stir occasionally to prevent sticking).","Uncover the pot, and when the sauce is almost gone, increase heat to reduce the sauce (do not reduce completely).","Add 2-3g salt, stir once, and serve."]'::jsonb, '["Meat Dish","Home-style","Rice Companion","Braising","Savory Soy","Tender"]'::jsonb),
  ('howtocook:meat_dish/红烧鸡翅', 'en', 'Braised Chicken Wings', 'Meat Dishes', 'Braised chicken wings is a homestyle dish that goes well with rice. It is savory with a hint of sweetness, glossy red in color, and the meat is tender and falls off the bone easily. Chicken wings are rich in high-quality protein and collagen, making them nutritious and easy to absorb. The difficulty is moderate; beginners can follow the steps and master it. From prep to serving, it takes about 40 minutes.', '[{"name":"Fresh chicken wings","unit":"g"},{"name":"Ginger slices","unit":"g"},{"name":"Scallion sections","unit":"g"},{"name":"Garlic","unit":"g"},{"name":"Bay leaf","unit":"piece(s)"},{"name":"Star anise","unit":"piece(s)"},{"name":"Dried chili peppers","unit":"piece(s)"},{"name":"Rock sugar","unit":"g"},{"name":"Huangjiu or cooking wine","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"White sugar","unit":"g"},{"name":"White pepper","unit":"g"},{"name":"White sesame seeds","unit":"g"},{"name":"Chopped scallions","unit":"g"},{"name":"Cooking oil","unit":"ml"}]'::jsonb, '["Wash the chicken wings. Use a knife to make three slits on the thick part of each wing and one slit on the back to help the flavor penetrate.","If the chicken wings are not fresh, soak them in ginger water for 10-20 minutes after scoring.","Prepare 10g ginger slices (3-4 slices), 15g scallion sections (2-3 sections); smash 3-4 garlic cloves (about 15g) with the flat side of a knife (do not mince); set aside 1 bay leaf, 1 star anise, and 2 dried chili peppers (optional).","Heat a pot and add enough cold water to submerge all the chicken wings. Place the chicken wings in the pot, add 20ml huangjiu or cooking wine, and 2 slices of ginger (about 5g). Bring to a boil over high heat, then continue boiling for 2-3 minutes, skimming off any foam.","After boiling, remove the chicken wings and rinse them twice with warm water to completely remove any blood foam. Drain well.","Heat another pot over high heat and add 10-15ml cooking oil.","When the oil reaches about 50% hot, add 15g rock sugar. Cook over high heat until the sugar melts completely. When the sugar melts and changes color, turn to low heat and continue stirring until the sugar turns date-red. Immediately add the drained chicken wings and stir-fry quickly for 1-2 minutes, coating each wing evenly with the caramel.","Add the prepared 1 bay leaf, 1 star anise, 2 dried chili peppers (optional), the remaining 2 ginger slices (about 5g), 15g scallion sections, and smashed garlic. Continue stir-frying for 30 seconds until the aromatics are fully fragrant.","Pour 15ml cooking wine or huangjiu along the edge of the pan, then 15ml light soy sauce. Stir-fry quickly for 10 seconds.","Add warm water (about 50-60°C) until it just barely covers the chicken wings.","Add 5ml dark soy sauce, 3g salt, 2g white sugar, and 1g white pepper. Gently stir to combine.","Cover the pot and cook over medium heat for 7-8 minutes.","Remove the lid. Use chopsticks to pick out and discard the bay leaf, star anise, ginger slices, scallion sections, and garlic from the pot.","Turn to high heat and keep stirring constantly until the sauce thickens (about 1-2 minutes).","Turn off the heat. Transfer the chicken wings to a plate and pour the remaining thickened sauce over them.","Finally, sprinkle 3g white sesame seeds and 5g chopped scallions on top. Done."]'::jsonb, '["Meat Dish","Home-style","Rice Dish","Savory","Braised","Party Dish"]'::jsonb),
  ('howtocook:meat_dish/羊排焖面/羊排焖面', 'en', 'Lamb Rib Braised Noodles', 'Meat Dishes', 'Lamb rib braised noodles is a hearty Northern home-style dish with rich meat flavor and chewy noodles. The lamb ribs are tender, and the wide noodles absorb the savory broth, making every bite satisfying. This dish combines meat, noodles, and vegetables, providing a complete meal with protein, carbs, and fats. It requires braising the lamb first, then preparing the dough and braising the noodles - a bit more steps, suitable for experienced cooks. Estimated time: about 1.5 hours.', '[{"name":"Lamb ribs with skin","unit":"g"},{"name":"Green pepper","unit":"piece"},{"name":"Bell pepper","unit":"piece"},{"name":"Scallion","note":"to taste"},{"name":"Sichuan peppercorn","note":"to taste"},{"name":"Dried chili","note":"to taste"},{"name":"Ginger","unit":"slice"},{"name":"White sugar","note":"to taste"},{"name":"Dark soy sauce","note":"to taste"},{"name":"Salt","note":"to taste"},{"name":"Cooking oil","note":"to taste, a bit more is fine"}]'::jsonb, '["Place lamb in cold water and blanch. When water boils, skim off the foam, then remove the lamb.","Slice ginger (4 slices). Set aside dried chilies and Sichuan peppercorns in a bowl.","Add oil to a wok. (A bit more is fine.)","Once oil is hot, add sugar and stir-fry lamb until caramelized.","After the lamb''s moisture is evaporated, add salt, dark soy sauce, and the prepared seasonings.","Add enough water to cover lamb. Bring to a boil over high heat, let it boil for 10 minutes, then simmer on low heat for 30 minutes.","Meanwhile, prepare the dough. The amount and method are explained in the additional notes (Note 1).","Add green pepper, bell pepper, scallions, and the noodle sheets; stir-fry.","After stirring evenly, remove from heat and serve."]'::jsonb, '["Meat Dish","Savory","Braised","Northern","Home-style","Hearty"]'::jsonb),
  ('howtocook:meat_dish/老妈蹄花/老妈蹄花', 'en', 'Mom''s Pig Trotters', 'Meat Dishes', 'Mom''s Pig Trotters soup is milky white, the trotters are tender and fall off the bone, with a delicate texture. Paired with a sour and spicy dipping sauce, it is very appetizing. This is a classic Sichuan home-style dish. Pig trotters are rich in collagen, and white kidney beans add a creamy texture, making it nutritious. The preparation requires a pressure cooker and pre-soaking, which can be a bit challenging for beginners, but it''s easy to follow the steps. Including soaking and pressure cooking, the whole process takes about 2 hours (excluding overnight soaking of white kidney beans).', '[{"name":"Pig trotters","unit":"piece"},{"name":"Scallions","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Cooking wine","note":"to taste"},{"name":"Light soy sauce","unit":"g"},{"name":"Dahurian angelica","note":"to taste"},{"name":"Angelica","unit":"g"},{"name":"Chicken bouillon","unit":"g"},{"name":"Salt","note":"to taste"},{"name":"Garlic","unit":"g"},{"name":"Small red chili peppers","note":"to taste"},{"name":"White pepper powder","unit":"g"},{"name":"Fragrant vinegar","note":"to taste"},{"name":"Sichuan pepper oil","note":"to taste"},{"name":"Chili oil","note":"to taste"},{"name":"White kidney beans","unit":"g"}]'::jsonb, '["Soak 200g white kidney beans in water overnight in advance and set aside.","Prepare pig front trotters. When buying, ask the butcher to split them in half. Use a blowtorch to remove hair follicles, then wash them at home.","In a cold water pot, add pig trotters, scallion segments, ginger slices, and cooking wine. Blanch for 10 minutes, skim off foam, remove and wash clean, set aside.","In a pressure cooker, add pig trotters, angelica, dahurian angelica, white pepper powder, and ginger slices. After steam comes up, cook for 30 minutes. Add white kidney beans, then cook for another 10 minutes. At this point, if the broth is milky white, congratulations, it''s correct (if you need to add water midway, only add hot water).","After removing the lid, add salt, chicken bouillon, and chopped scallions to season.","Prepare the soul dipping sauce: Add scallions, garlic, small red chili peppers, white pepper powder, light soy sauce, fragrant vinegar, chili oil, Sichuan pepper oil, and the original pig trotter broth.","Soul dipping sauce, pour it over."]'::jsonb, '["Meat Dish","Sichuan","Stew","Sour and Spicy","Homestyle","Banquet"]'::jsonb),
  ('howtocook:meat_dish/老式锅包肉/老式锅包肉', 'en', 'Old-Style Guo Bao Rou', 'Meat Dishes', 'Guo Bao Rou is a classic dish from Northeast China, originating from the Daotai Mansion in Harbin. It features a bright sour aroma from white vinegar, a crispy shell, tender meat slices, and a sweet and sour taste. Pork provides high-quality protein, paired with scallions, ginger and other vegetables to stimulate appetite and cut the grease. This dish requires skills in battering, oil temperature control, and double frying. Cooking difficulty is above average; beginners need patience to practice. From marinating, making batter to frying and plating, estimated preparation time is about 90 minutes.', '[{"name":"Pork loin","unit":"g"},{"name":"Scallion","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Garlic","unit":"cloves"},{"name":"Carrot","unit":"g"},{"name":"Cilantro","unit":"g"},{"name":"White sugar","unit":"g"},{"name":"Cooking wine","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"MSG","unit":""},{"name":"Potato starch","unit":"g"},{"name":"Potato starch","unit":"g"},{"name":"All-purpose flour","unit":"g"},{"name":"Baking soda","unit":"g"},{"name":"Baking soda","unit":"g"},{"name":"White sesame seeds","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"White vinegar","unit":"g"},{"name":"Light soy sauce","unit":"g"},{"name":"Corn starch","unit":"g"},{"name":"Water","unit":"g"},{"name":"Water","unit":"ml"}]'::jsonb, '["Prepare pork:","Slice the pork loin into uniform pieces 8mm thick, removing white sinew.","Rinse the meat slices with clean water to remove blood.","Optional: Add 5g baking soda, mix well, and let sit for 5 minutes.","Rinse 1-2 times with clean water to remove excess baking soda.","Marinate the meat slices:","Add 3g salt and 5ml cooking wine to the meat, mix well, and marinate for 15 minutes.","Make the batter:","Method 1 (recommended):","Add 170g potato starch to an excess of water, stir, and let sit for 60 minutes until the starch settles.","Pour off all the clear water on top, retaining the starch paste at the bottom (like a non-Newtonian fluid).","Add the meat slices, 5ml water, and 3ml cooking oil, and mix well.","Method 2:","Mix 210g potato starch and 70g all-purpose flour.","Add water little by little, stirring until the batter is like yogurt, can be lifted into a thread, and piles up in the bowl.","Add 10ml cooking oil and 1g baking soda, and mix well.","Add the marinated meat slices to the batter and mix so each piece is evenly coated.","Prepare the sweet and sour sauce:","Mix 65g white sugar, 55g white vinegar, 4g light soy sauce, and 2g salt, stirring until dissolved. Set aside.","Optional: 4g water and 1.5g cornstarch to thicken the sauce further.","Prepare the garnishes:","Shred scallions, ginger, and carrot; cut cilantro into sections; slice garlic.","Fry the meat slices:","First fry:","Add cooking oil to a wok and heat to 170°C (350°F).","Fry the meat slices one by one until the surface sets, the batter no longer sticks to chopsticks, the meat floats, and turns light yellow, about 30 seconds (depending on size). Remove and set aside.","Second fry:","Raise oil temperature to 200°C (390°F).","Fry all meat slices again until golden and crispy, about 30 seconds. Remove and set aside.","Third fry (optional):","Raise oil temperature to 220°C (430°F).","Quickly re-fry the meat slices until they look yellow with a hint of red, about 30 seconds (depending on oil temperature retention), to enhance crispiness. Remove and drain oil.","Stir-fry:","Leave 20ml oil in the wok, pour in the prepared sweet and sour sauce, and bring to a boil over high heat. Cook until thickened, about 30-60 seconds.","Optional: Remove half of the sauce to make stirring easier later.","Add the fried meat slices, shredded scallions, garlic slices, shredded carrot, and cilantro. Pour the reserved sauce over everything, and quickly stir-fry 3 times to coat evenly.","Plate:","Transfer the Guo Bao Rou to a plate, sprinkle with white sesame seeds (optional), and serve."]'::jsonb, '["Meat Dish","Northeast","Sweet and Sour","Crispy","Deep-fried","Entertaining"]'::jsonb),
  ('howtocook:meat_dish/肉饼炖蛋', 'en', 'Steamed Minced Pork with Egg', 'Meat Dishes', 'Steamed minced pork with egg is a traditional home-style dish with savory and tender flavors. The pork patty absorbs the sauce, and the egg sits on top, creating a soft and juicy texture that pairs well with rice. It is rich in high-quality protein and various amino acids, helping to replenish energy. The recipe is very simple, beginner-friendly, and takes only about 20 minutes from preparation to serving.', '[{"name":"Minced pork","unit":"g"},{"name":"Egg","unit":"piece"},{"name":"Cooking wine","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"White pepper powder","unit":"g"},{"name":"Sesame oil","unit":"ml"}]'::jsonb, '["In a bowl, combine minced pork, cooking wine, light soy sauce, white pepper powder, egg, and sesame oil. Mix well.","Spread the seasoned minced pork on a plate. Use a spoon to make a well in the center, then crack an egg into the well.","Add water to the pot to about 1/4 height. Bring the water to a boil, then place the plate in the pot, cover, and steam for 15 minutes."]'::jsonb, '["Meat dish","Savory","Steamed","Home-style","Goes with rice","Quick"]'::jsonb),
  ('howtocook:meat_dish/腐乳肉', 'en', 'Red Fermented Bean Curd Pork', 'Meat Dishes', 'This is a classic home-style dish from the Jiangnan region. Pork belly is braised with red fermented bean curd, resulting in a bright red, amber-like color. The meat is so tender it melts in your mouth, with layers of savory and sweet flavors mingling with the aroma of wine and beans. Rich in high-quality protein and B vitamins, it becomes easier to digest after slow simmering. The cooking process requires patience to control the heat and reduce the sauce, which can be a challenge for beginners. Estimated cooking time: about 1 hour.', '[{"name":"pork belly with skin","unit":"g"},{"name":"red fermented bean curd","unit":"g"},{"name":"fermented bean curd liquid","unit":"ml"},{"name":"rock sugar","unit":"g"},{"name":"dark soy sauce","unit":"ml"},{"name":"cooking wine","unit":"ml"},{"name":"scallion white parts","unit":"g"},{"name":"chopped scallions","unit":"g"},{"name":"ginger","unit":"g"},{"name":"water","unit":"ml"},{"name":"cooking oil","unit":"ml"}]'::jsonb, '["Cut the pork belly into small cubes of 2.5 cm on each side.","Place the pork belly in cold water with cooking wine and ginger slices, then bring to a boil over heat. Remove the pork when the water boils.","Mash the red fermented bean curd cubes and its liquid into a paste. Add rock sugar and dark soy sauce to make the sauce.","Heat oil in a wok, sauté scallions and ginger until fragrant, then add the pork cubes and stir-fry until golden brown.","Pour in the fermented bean curd sauce, stir well, then add hot water and simmer covered.","Simmer over low heat for 40 minutes.","Increase heat to reduce the sauce until it thickens and large bubbles appear, then turn off the heat."]'::jsonb, '["Meat Dish","Savory-Sweet","Braising","Jiangnan","Rice Companion","Party Dish","Home-style"]'::jsonb),
  ('howtocook:meat_dish/芥末罗氏虾/芥末罗氏虾', 'en', 'Wasabi Prawns', 'Meat Dishes', 'This dish is savory with a slight kick, rich in wasabi flavor. The prawn meat is firm and bouncy. It''s a quick home-style seafood dish. Prawns are rich in high-quality protein and calcium, low in fat, and paired with wasabi to stimulate appetite and cut richness. Moderate difficulty; as long as you prepare the sauce mixture and control the heat, beginners can quickly get the hang of it. It takes about 30 minutes in total.', '[{"name":"Giant river prawns","unit":"g"},{"name":"Garlic","unit":"cloves"},{"name":"Wasabi","unit":"g"},{"name":"Cornstarch","unit":"g"},{"name":"Light soy sauce","unit":"g"},{"name":"White pepper","unit":"g"},{"name":"Sugar","unit":"g"},{"name":"Oyster sauce","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Bird''s eye chilies","unit":"pieces"},{"name":"Butter","unit":"g"},{"name":"Cooking oil","unit":"ml"}]'::jsonb, '["Prepare the prawns:","Cut the prawns along the back, remove the vein and sand sac. Alternatively, cut from the belly; when fried, they will open up and look nicer.","Rinse clean with water. After draining, you can dust with cornstarch or skip.","Prepare garlic and sauce mixture:","Finely chop 2 garlic cloves.","Prepare the sauce: mix light soy sauce, oyster sauce, sugar, white pepper, and salt. Squeeze in wasabi to taste. Add water to dilute, then add cornstarch and stir to dissolve.","Cooking process:","Heat oil in a wok, enough to coat the bottom.","Add the drained prawns and pan-fry slowly.","When the prawn oil is released (indicated by lots of bubbles), add the prepared garlic and bird''s eye chilies.","Once you smell the garlic fragrance, add butter.","After the butter melts, stir well, then add the prepared sauce.","Cover and simmer for 2 minutes until the sauce thickens. Serve."]'::jsonb, '["Meat Dish","Savory and slightly spicy","Pan-fry","Quick home-style","Seafood","Appetizing and refreshing"]'::jsonb),
  ('howtocook:meat_dish/茭白炒肉/茭白炒肉', 'en', 'Stir-fried Water Bamboo Shoots with Pork', 'Meat Dishes', 'Stir-fried water bamboo shoots with pork is a quick home-style dish, fresh, tender, and crispy, with a savory taste. It''s a typical Jiangnan home-style flavor. Water bamboo shoots are rich in dietary fiber and vitamins, paired with lean pork for quality protein, balancing nutrition. Medium difficulty, easy for beginners with a bit of practice. Estimated cooking time: about 20 minutes.', '[{"name":"water bamboo shoots","unit":"stalks"},{"name":"lean pork","unit":"g"},{"name":"cornstarch","unit":"g"},{"name":"cooking oil","unit":"ml"},{"name":"chicken powder","unit":"g"},{"name":"ginger","unit":"slices"},{"name":"garlic","unit":"cloves"},{"name":"cooking wine","unit":"ml"},{"name":"salt","unit":"g"}]'::jsonb, '["Slice water bamboo shoots to 0.5 cm thickness each.","Cut lean pork into strips, 0.3-0.5 cm thick, mix with cooking wine, cornstarch, salt, and water.","Slice ginger, mince garlic.","Bring water to a boil in a pot, add water bamboo shoots, blanch for 60-90 seconds, then remove and drain.","Heat 15 ml oil in a wok, add pork strips, stir-fry for 60 seconds, then remove.","Heat 15 ml oil in the wok, add ginger and garlic, stir-fry for 30 seconds, add water bamboo shoots, stir-fry for another 30 seconds.","Add pork back, stir-fry for 60 seconds, add 20 ml water, add salt and chicken powder, stir-fry for 60 seconds, then serve."]'::jsonb, '["Meat Dish","Savory","Stir-fry","Home-style","Quick","Jiangnan"]'::jsonb),
  ('howtocook:meat_dish/荔枝肉/荔枝肉', 'en', 'Lychee Pork', 'Meat Dishes', 'Lychee Pork is a traditional Fujian dish with sweet and sour flavor, crispy outside and tender inside. The pork pieces are coated in a glossy sauce, paired with fruit to add a refreshing fruity aroma. Pork tenderloin is rich in high-quality protein, and pineapple provides dietary fiber and vitamins, helping to stimulate appetite and cut through the richness. The cooking process involves cutting the meat, coating it in batter, and double-frying, which is a bit challenging but steps are clear. Suitable for home cooks with some experience, about 45 minutes to serve.', '[{"name":"Lean meat","unit":"g"},{"name":"Pineapple","unit":"g"},{"name":"Egg","unit":"piece"},{"name":"Cooking oil","unit":"ml"},{"name":"White sugar","unit":"g"},{"name":"Cornstarch","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Chicken bouillon","unit":"g"},{"name":"Minced ginger","unit":"g"},{"name":"Sesame seeds","unit":"g"},{"name":"Ketchup","unit":"g"},{"name":"Vinegar","unit":"ml"}]'::jsonb, '["Cut the lean meat into pieces (2-3 cm each). Place in a large bowl. Add 1 egg, 50g cornstarch, 3ml light soy sauce, 2g chicken bouillon.","Stir well until the cornstarch coats the meat. If too thin, add more cornstarch; if too dry, add water. Then add 5ml oil, stir well, and set aside.","In another bowl, combine ketchup, 3g chicken bouillon, 2ml light soy sauce, minced ginger, white sugar, 10g cornstarch, vinegar, and 200ml cold water. Stir well and set aside.","Cut one pineapple, prepare 6 pieces (each 1.5-2 cm).","Heat oil in a wok. Pour in 500ml oil. Heat until you hear the frying sound.","Add the meat pieces one by one into the oil (do not pour all at once). Make sure they don''t stick together.","After all meat is added, flip the pieces every 30 seconds with a spatula until the surface turns golden.","Remove the meat. After one minute, fry again until the surface becomes crispy and golden. Remove and set aside in a large bowl.","Leave the wok, pour in the sauce. After 30 seconds, add the meat and pineapple pieces. Stir-fry well, then remove from heat.","Sprinkle with sesame seeds."]'::jsonb, '["Meat Dish","Sweet and Sour","Fried","Fujian Cuisine","Home-style","Rice Dish"]'::jsonb),
  ('howtocook:meat_dish/荷兰豆炒腊肠/荷兰豆炒腊肠', 'en', 'Stir-fried Snow Peas with Chinese Sausage', 'Meat Dishes', 'Stir-fried snow peas with Chinese sausage is a refreshing and savory home-style dish. The fat from the sausage coats the green snow peas, giving a crisp and tender texture without being greasy. Snow peas are rich in high-quality protein and various vitamins, helping to boost the body''s disease resistance. The cooking method is simple, requiring almost no knife skills, and even beginners can quickly master it. It takes about 15 minutes from preparation to serving.', '[{"name":"Snow peas","unit":"piece"},{"name":"Chinese sausage","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Cooking oil","unit":"ml"}]'::jsonb, '["Remove the stems from the snow peas; if you have time, you can also remove the tips.","Before buying the Chinese sausage, ask the seller if it is raw or cooked. If raw, steam it in advance; if cooked, it can be used directly.","Rinse the snow peas, then blanch them for about 45 seconds until they change color. Remove and drain, then rinse with cold water and set aside.","Heat the wok and add about 10ml of cooking oil. Wait 10 seconds for the oil to heat up.","Add the Chinese sausage and stir-fry until it slightly curls at the edges. Keep the heat very low to prevent burning.","Add the snow peas, turn the heat to medium-high, stir-fry for 30 seconds, then add light soy sauce. Stir-fry for another 20-30 seconds and serve."]'::jsonb, '["meat dish","savory","stir-fry","home-style","quick","rice companion"]'::jsonb),
  ('howtocook:meat_dish/萝卜炖羊排', 'en', 'Braised Lamb Ribs with Radish', 'Meat Dishes', 'This soup is light yet flavorful, with tender lamb and sweet, soft radish that absorbs the broth—a common winter warmer in northern China. Lamb provides high-quality protein and iron, while radish offers vitamins and fiber; together they warm the spleen and stomach, dispel cold, and aid digestion. Although it requires blanching and two rounds of simmering, the steps are clear and easy to follow for beginners. Total prep takes about two hours, or about one hour with a pressure cooker.', '[{"name":"Lamb ribs","unit":"g"},{"name":"White radish","unit":"piece"},{"name":"Scallion","unit":"stalk"},{"name":"Sichuan peppercorns","unit":"pieces"},{"name":"Angelica","note":"optional, to taste"},{"name":"Ginger","unit":"g"},{"name":"Cooking wine or Shaoxing wine","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Rock sugar","unit":"pieces"},{"name":"Water","unit":"ml"}]'::jsonb, '["Peel the radish and cut into 3-5cm chunks using a rolling cut (oblique), set aside.","Ask the butcher to cut the lamb ribs when buying, as household knives are usually not strong enough; set aside.","Place lamb in cold water, add half the cooking wine and half the scallion and ginger, boil for 10 minutes to remove bloodiness. (Optional) Skim off any foam that appears during blanching.","In another pot with cold water, add the cut radish and half the rock sugar, bring to a boil and cook for 5 minutes to remove radish''s spiciness.","Remove the blanched lamb ribs and place in a pressure cooker. Add water to cover all ingredients, then add about 300ml more water.","Add the remaining scallion, ginger, cooking wine, Sichuan peppercorns, rock sugar, angelica (optional), and salt. Cover, wait for steam, then cook on medium heat for about 15 minutes.","If using a regular pot, simmer for about 40 minutes to 1 hour.","Turn off heat, wait for pressure to release completely, open lid. Add the blanched radish, adjust seasoning, add 3-10g salt or water to taste.","Turn heat back on to medium. For pressure cooker, cook for another 10 minutes after steaming; for regular pot, cover and simmer for another 20 minutes.","Turn off heat, serve."]'::jsonb, '["Meat Dish","Savory","Stew","Northern","Warming","Home-style"]'::jsonb),
  ('howtocook:meat_dish/蒜苔炒肉末', 'en', 'Stir-fried Garlic Scapes with Minced Pork', 'Meat Dishes', 'Stir-fried garlic scapes with minced pork is a northern Chinese home-style dish. It is savory, fresh, crispy, and tender with a rich garlic aroma. Garlic scapes are rich in dietary fiber and vitamins, while pork belly provides protein, making a balanced meat-and-vegetable combination. The recipe is simple, ingredients are easy to prepare, and even beginners can quickly master it. From cutting to serving, it takes only about 10 minutes.', '[{"name":"Pork belly slices","unit":"slices"},{"name":"Garlic scapes","unit":"bunch"},{"name":"Garlic cloves","unit":"cloves"},{"name":"Light soy sauce","unit":"ml"},{"name":"Cooking oil","unit":"ml"},{"name":"Salt","unit":"g"}]'::jsonb, '["Cut garlic scapes into 5cm sections, set aside.","Cut pork belly into 5mm x 5cm strips, set aside.","Smash and mince garlic cloves, set aside.","Heat the wok, add 10ml cooking oil. Wait 10 seconds for the oil to heat up.","Add minced garlic, stir-fry over medium heat for 10 seconds until fragrant.","Add pork belly and 5ml light soy sauce, stir-fry over medium heat for 30 seconds until cooked and colored.","Add garlic scapes to the wok along with 10ml light soy sauce, stir-fry for 30 seconds.","Add 20g water to the wok, stir-fry over medium heat for 5 minutes until garlic scapes are slightly softened.","Finally, add 2g salt, stir-fry over medium heat for 30 seconds, then serve."]'::jsonb, '["Meat Dish","Savory","Quick Stir-fry","Northern Home-style","Goes with Rice","Quick"]'::jsonb),
  ('howtocook:meat_dish/虎皮肘子', 'en', 'Tiger Skin Pork Elbow', 'Meat Dishes', 'This dish is a classic Chinese banquet staple, with a glossy red color, attractive tiger-like skin pattern, and tender, flavorful meat that is rich but not greasy. The lean meat is soft and loose. Pork elbow is rich in collagen and high-quality protein, which becomes more absorbable after long braising, benefiting skin and joints. The process involves scorching, deep-frying, caramelizing, and pressure-cooking—quite challenging for beginners, so some cooking experience is recommended. Total time from prep to table is about 2.5 hours.', '[{"name":"Pork front elbow","unit":"piece"},{"name":"Vegetable oil","unit":"bottle"},{"name":"Rock sugar","unit":"bottle"},{"name":"Salt","unit":"teaspoon"},{"name":"Dark soy sauce","unit":"teaspoon"},{"name":"Light soy sauce","unit":"tablespoon"},{"name":"White vinegar","unit":"tablespoon"},{"name":"Bay leaves","unit":"piece"},{"name":"Cinnamon stick","unit":"gram"},{"name":"Cardamom","unit":"piece"},{"name":"Sichuan peppercorns","unit":"piece"},{"name":"Star anise","unit":"piece"},{"name":"Cornstarch","unit":"tablespoon"},{"name":"Scallion","unit":"bunch"},{"name":"Ginger","unit":"gram"},{"name":"Garlic","unit":"clove"},{"name":"Water","unit":"ml"},{"name":"Cooking wine","unit":"tablespoon"}]'::jsonb, '["Thaw the pork elbow and soak in water for 1 hour to remove blood.","If you have a flame torch, burn the skin of the pork elbow until it turns dark brown to remove hair and destroy sweat glands. Do not burn one spot too long to avoid charring. Stop when the skin is almost completely dark brown.","If no flame torch, heat a dry wok to above 200°C, place the pork elbow directly in the wok, and use a spatula or chopsticks to press the skin against the hot surface. When the contact area turns brown, reposition and continue until the entire skin is treated. Be careful not to let the wok get red-hot.","Use a scrubber under running water to clean the pork elbow, removing the burnt parts. After scrubbing, the skin should look as it did before scorching.","Place the pork elbow in a wok and add as much cold water as possible, depending on wok depth and elbow size. Ideally, the water should cover at least 3/4 of the elbow, as long as you can lift the wok and its contents.","Take the white part of 1 scallion, cut into 3 sections, and add to the wok.","Take 3 garlic cloves, smash each with the side of a knife, and add to the wok.","Add 3 grams of ginger to the wok.","Add 2 tablespoons of cooking wine to the wok.","Bring the water to a boil, wait 5 minutes, then remove the pork elbow and discard all aromatics from the wok. Reserve the broth in a separate container.","Add cold oil to the wok, enough to submerge about 3/5 of the elbow (use the previous water amount as reference). Heat over medium heat.","When the oil reaches 50% hot (about 150°C), reduce to low heat and add the pork elbow for deep-frying.","During deep-frying, be cautious for safety.","Use a spatula or other heat-resistant utensil to ladle hot oil over the parts of the elbow not submerged. If possible, flip the elbow every 3 minutes for even frying.","Deep-fry for about 20 minutes, until the skin is uniformly light brown and the lean meat edges are slightly charred. Remove and set aside.","The used oil can be reused for other frying, but not too many times.","Prepare 200 ml of caramelized sugar (for coloring) and set aside.","Add the pork elbow to a pressure cooker. Pour in all the reserved broth, caramelized sugar, bay leaves, cinnamon stick, cardamom, Sichuan peppercorns, star anise, dark soy sauce, light soy sauce, and white vinegar. If you prefer a sweeter taste, add 2-3 grams of rock sugar.","Take the white part of 1 scallion, cut into 3 sections, and add to the pressure cooker.","Take 3 garlic cloves, smash with the side of a knife, and add to the pressure cooker.","Add 3 grams of ginger to the pressure cooker.","Close the lid and pressure cook for 40 minutes.","While cooking, make a cornstarch slurry: In a bowl, mix 1 tablespoon of cornstarch with 100 ml of water until it forms a white suspension.","After pressure cooking, open the lid and discard all aromatics, leaving only the pork elbow.","Transfer the remaining broth from the pressure cooker to a wok, and move the pork elbow to a plate or basin.","Place the wok over high heat to reduce the sauce. Dip a chopstick tip into the sauce to taste saltiness, and add salt as needed. Note that the sauce will taste less salty when more liquid is present, so adjust accordingly.","When the sauce boils, keep an eye on the remaining volume.","When the remaining broth is less than half of the original volume, stir the cornstarch slurry again and add half of it to the wok.","Wait for the sauce to boil again, then add the remaining slurry.","Let the sauce boil, then wait 1-2 minutes and turn off the heat. The sauce should now be thick and reddish-brown.","Ladle the sauce evenly over the pork elbow, trying to cover every part. If you run out of sauce before covering completely, serve as is; otherwise, serve with remaining sauce on the side."]'::jsonb, '["Meat Dish","Braised","Soft and Sticky","Fried and Braised","Banquet","Traditional"]'::jsonb),
  ('howtocook:meat_dish/蚂蚁上树', 'en', 'Ants Climbing a Tree', 'Meat Dishes', 'Ants Climbing a Tree is a classic Sichuan home-style dish, savory and slightly spicy, with soft and slippery vermicelli that soaks up the sauce, and tender minced meat that is delicious. Made mainly from sweet potato vermicelli and minced pork, it is rich in carbohydrates and protein, providing a quick energy boost. The difficulty is moderate, the steps are clear, and it is beginner-friendly, taking about 20 minutes in total.', '[{"name":"Sweet potato vermicelli","unit":"g"},{"name":"Minced pork (or beef)","unit":"g"},{"name":"Pixian broad bean paste","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Cooking oil","unit":"ml"},{"name":"Minced garlic","unit":"g"},{"name":"Minced ginger","unit":"g"},{"name":"Green onion (optional)","note":"to taste"},{"name":"Water","unit":"ml"}]'::jsonb, '["Soak sweet potato vermicelli in advance for 20 minutes until soft, set aside","Finely chop garlic and ginger, set aside","Heat a wok, add 10ml cooking oil, add minced garlic and ginger, stir-fry until fragrant","Add minced pork, stir-fry until the meat turns white and slightly releases oil","Add Pixian broad bean paste, stir-fry until red oil appears","Add light soy sauce and dark soy sauce, stir well","Pour in 300ml water, bring to a boil","Add the soaked and drained vermicelli, gently stir with chopsticks to prevent sticking","Cook over medium-low heat for about 5 minutes, until the vermicelli fully absorbs the sauce and becomes slightly dry","Optionally sprinkle with chopped green onions, turn off the heat and serve"]'::jsonb, '["Meat Dish","Sichuan Style","Savory and Slightly Spicy","Stir-fry and Boil","Goes with Rice","Quick","Home-style"]'::jsonb),
  ('howtocook:meat_dish/血浆鸭/血浆鸭', 'en', 'Blood Duck', 'Meat Dishes', 'Blood Duck is a traditional famous dish from Wugang, Hunan. The duck meat is crispy and tender, and after being soaked in vinegar blood, even the ginger and chili become sweet and not spicy. Duck meat and blood provide high-quality protein and iron, suitable for nourishing blood and body. There are many steps, requiring attention to heat and stirring, but following the steps, beginners can finish in about 2 hours.', '[{"name":"Fresh young duck meat","unit":"g"},{"name":"Fresh duck blood","unit":"ml"},{"name":"Ginger","unit":"slices"},{"name":"Garlic cloves","unit":"cloves"},{"name":"Scallions","unit":"stalks"},{"name":"Chili peppers","unit":"g"},{"name":"Thai bird''s eye chili (or facing-heaven chili)","unit":"pieces"},{"name":"High-proof baijiu","unit":"ml"},{"name":"Water","unit":"ml"},{"name":"Beer","unit":"ml"},{"name":"Rice wine","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Cooking wine","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Chicken bouillon","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Boiling water","unit":"ml"},{"name":"Wild pepper oil","unit":"drops"}]'::jsonb, '["Cut fresh young duck meat into about 3cm pieces, add cooking wine and ginger slices to remove blood.","Heat a wok, add about 100ml cooking oil, heat on high until oil is hot, add the marinated duck meat and stir constantly.","When the duck meat has completely changed color (visibly white), add the liquor, then add 200ml boiling water, just enough to cover the duck meat, cover and cook on medium heat for 15 minutes.","After the water boils, uncover, add ginger and garlic, stir once, cover and continue heating for 10 minutes.","Uncover, add chili, stir constantly until the chili becomes soft, then add fresh duck blood. Stir constantly to ensure every piece of duck and chili is coated with blood (this is the essence of Blood Duck).","Stir until the duck blood turns black, add salt, chicken bouillon, and scallions. (If you like, you can also add 3-6 drops of wild pepper oil at this point.) Stir once or twice more.","Remove from heat, plate, and serve."]'::jsonb, '["Meat Dish","Hunan Cuisine","Spicy","Stir-fry","Rice Companion","Banquet"]'::jsonb),
  ('howtocook:meat_dish/西红柿土豆炖牛肉/西红柿土豆炖牛肉', 'en', 'Tomato and Potato Braised Beef', 'Meat Dishes', 'A home-style braised dish, sweet and sour appetizing, rich broth, tender beef, soft potatoes. Beef provides high-quality protein, tomatoes are rich in lycopene, combined with potatoes and onions for balanced nutrition. Simple operation, no complex skills needed, beginners can easily master. From prep to serving takes about 1 to 1.5 hours.', '[{"name":"Beef","unit":"g"},{"name":"Scallion","unit":"stalk"},{"name":"Ginger","unit":"slices"},{"name":"Cooking wine","note":"Add in two batches: for braising and stir-frying"},{"name":"Sichuan peppercorns","unit":"g"},{"name":"Star anise","unit":"pieces"},{"name":"Bay leaves","unit":"pieces"},{"name":"Oil","unit":"ml"},{"name":"White sugar/rock sugar","note":"to taste"},{"name":"Light soy sauce","unit":"ml"},{"name":"Dark soy sauce","note":"to taste"},{"name":"Black pepper (or white pepper)","unit":"g"},{"name":"Potatoes","unit":"pieces"},{"name":"Tomatoes","unit":"pieces"},{"name":"Onion","unit":"pieces"},{"name":"Tomato paste/ketchup","unit":"g"},{"name":"Canned tomatoes","note":"optional, substitute for tomato paste"},{"name":"Salt","note":"to taste"}]'::jsonb, '["Prep:","Peel potatoes, cut into 5cm chunks, set aside.","Score tomatoes with a cross, blanch in boiling water to remove skin, remove cores, cut into 3cm small pieces, set aside.","Slice 4g of scallion into chopped scallions, break the rest into 5-8cm sections.","Soak beef in cold water for half an hour to remove blood, or put beef in cold water and boil until surface turns white, then remove; skim off foam during boiling.","Dice onion into 0.5-1cm small pieces.","Cooking","Keep medium heat throughout.","Cover beef with cold water in a pressure cooker, add scallion sections, ginger slices, and 20g cooking wine. Pressure cook for 20 minutes after steam builds up.","Remove beef, cut into 5cm chunks, discard ginger, and pour the broth into a large bowl for later use.","Add oil; when oil is 40-50% hot, add Sichuan peppercorns, star anise, and bay leaves. Once fragrant (before they burn), remove and discard.","Add beef, scallion, and ginger; stir-fry until fragrant. It doesn''t matter how long; if it looks like it''s about to burn, add 10ml of the reserved broth. Same for the following steps.","After fragrant, add 15ml light soy sauce, 15ml cooking wine, pepper, 5-10g tomato paste/ketchup or one canned tomato, and diced onion; stir-fry until onion is translucent.","(Optional) Add a pinch of salt to help onion release water and prevent burning; don''t add too much, adjust seasoning later.","Add tomatoes and stir-fry until they break down and become soft; pour in the remaining broth.","Simmering","After bringing to a boil over medium heat, reduce to low heat and simmer.","30-40 minutes before finishing, add potatoes and season.","Adjust sugar and salt to taste, adding gradually and tasting.","When beef is tender enough to be pierced with chopsticks, remove from heat!"]'::jsonb, '["Meat Dish","Sweet and Sour","Braise","Home-style","Rice Dish"]'::jsonb),
  ('howtocook:meat_dish/西红柿牛腩/西红柿牛腩', 'en', 'Tomato Beef Brisket', 'Meat Dishes', 'Tomato beef brisket has a thick, tangy and sweet broth, the beef is tender and fragrant—a comforting home-cooked dish that whets the appetite. Rich in protein, vitamins, and lycopene, it''s nutritionally balanced. A bit challenging for beginners, requiring skills in simmering meat and stir-frying tomato sauce. Typically takes about 90 minutes for a novice.', '[{"name":"Tomatoes","unit":"piece(s)"},{"name":"Beef brisket","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Water","unit":"L"},{"name":"Scallion segments","unit":"segment(s)"},{"name":"Ginger slices","unit":"slice(s)"},{"name":"Star anise","unit":"small piece(s)"},{"name":"Cooking wine / Huangjiu","unit":"ml"},{"name":"Chopped scallions","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Light soy sauce","note":"to taste"},{"name":"White pepper powder","note":"to taste"},{"name":"Sugar","note":"to taste"},{"name":"Salt","note":"to taste"}]'::jsonb, '["Cut the beef brisket into strips, then into cubes about 2cm on each side. Place in cold water, bring to a boil, and cook for 2 minutes to remove blood. Drain and rinse clean.","In another pot, bring 2L of water to a boil. Add two 2cm scallion segments, two slices of ginger, star anise, and 5-10ml of cooking wine or Huangjiu. Add the blanched beef, cover, and simmer (1 hour in a clay pot, or 45 minutes on the stew setting of a pressure cooker). It''s done when a chopstick can easily pierce the meat.","Peel the tomatoes: Score a cross on the top of each tomato down to the middle. Insert a chopstick or fork from the stem end, roast over low heat on a gas stove, turning constantly. Check frequently, peel off the skin when it blisters. Then cut into pieces, as small as possible.","Be careful not to burn yourself when peeling. The peeled tomatoes are very slippery, so cut slowly and safely.","Heat oil in a wok until 70% hot. Add 10g each of scallion and ginger. Add the tomatoes and stir-fry until they break down and turn red. Add the cooked beef and its broth, just enough to barely cover the beef.","Season with salt, sugar, and light soy sauce to taste. Cover with a lid.","After it comes to a boil, continue cooking on high heat for 3-5 minutes.","When the tomato sauce reaches a medium thick consistency, turn off the heat. Sprinkle with chopped scallions and serve."]'::jsonb, '["Meat Dish","Sweet and Sour","Stew","Home-style","Goes with rice"]'::jsonb),
  ('howtocook:meat_dish/豆豉鲮鱼油麦菜/豆豉鲮鱼油麦菜', 'en', 'Stir-fried Celtuce with Dace in Black Bean Sauce', 'Meat Dishes', 'Stir-fried celtuce with dace in black bean sauce is a savory and flavorful quick home-style stir-fry, originating from Cantonese canned dishes. The celtuce is crisp, and the dace is crispy and aromatic. It combines meat and vegetables, rich in protein and dietary fiber. The method is simple and beginner-friendly, usually completed in 15 minutes.', '[{"name":"celtuce","unit":"g"},{"name":"Ganzhu brand dace in black bean sauce (canned)","unit":"can"},{"name":"garlic","unit":"clove"},{"name":"light soy sauce","unit":"g"},{"name":"white sugar","unit":"g"},{"name":"cooking oil","unit":"ml"}]'::jsonb, '["Ingredient preparation:","Wash celtuce and cut into sections.","Open the dace can, remove the main bones from the dace, cut into small pieces, and set aside.","Mince the garlic.","Stir-frying process:","Heat the wok, add cooking oil. When oil is hot, add the washed celtuce, stir-fry until wilted and water releases. Remove and set aside, discard the released liquid.","Reheat the wok, add the oil from the dace can, add minced garlic and stir until fragrant.","After the garlic is fragrant, add the black beans from the dace can, stir, then add the chopped dace pieces, stir again.","Once well mixed, add the celtuce, add light soy sauce and sugar to season.","After adding the seasoning, briefly stir-fry, then remove from wok and plate."]'::jsonb, '["Meat Dish","Savory and Flavorful","Cantonese","Quick Stir-fry","Rice Companion","Home-style","Quick"]'::jsonb),
  ('howtocook:meat_dish/豉汁排骨', 'en', 'Steamed Spare Ribs with Black Bean Sauce', 'Meat Dishes', 'A popular steamed dim sum from Cantonese teahouses, with rich fermented black bean aroma and tender, fall-off-the-bone ribs. Ribs provide high-quality protein and calcium, while fermented black beans add flavor and aid absorption. The process involves soaking, marinating, and precise steaming—a bit challenging for beginners, but clear steps make it easy to follow. From prep to serving, it takes about 1 hour. The leftover sauce is especially delicious over rice or noodles.', '[{"name":"Pork ribs","unit":"g"},{"name":"Yangjiang fermented black beans","unit":"g"},{"name":"Minced garlic","unit":"g"},{"name":"Minced ginger","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Oyster sauce","unit":"g"},{"name":"White sugar","unit":"g"},{"name":"Cornstarch","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Water","unit":"ml"},{"name":"Scallions","note":"to taste"},{"name":"White sesame seeds","note":"to taste"}]'::jsonb, '["Soak the ribs in cold water for 10 minutes to remove blood, change water and repeat twice, then pat dry with paper towels.","Soak the fermented black beans in water for 5 minutes.","Mix all ingredients (reserve 10 ml of cooking oil), marinate for 8-30 minutes.","Steam over boiling water for 18 minutes.","Let rest for 2 minutes.","Heat 10 ml of oil in a pan to 180-200°C.","Evenly sprinkle with scallions and white sesame seeds, then pour hot oil over the toppings."]'::jsonb, '["Meat Dish","Cantonese","Steamed","Savory","Goes well with rice","Suitable for guests"]'::jsonb),
  ('howtocook:meat_dish/豉汁蒸白鱔/豉汁蒸白鱔', 'en', 'Steamed Eel with Black Bean Sauce', 'Meat Dishes', 'Steamed eel with black bean sauce is a classic Cantonese steamed dish. The savory aroma of black bean and garlic penetrates the fish, giving it a tender and delicious texture. Eel is rich in high-quality protein and various unsaturated fatty acids, nourishing the body. The steps are clear, but handling raw fish and controlling the heat pose a slight challenge, suitable for cooks with some experience. It takes about 30 minutes from preparation to serving.', '[{"name":"eel","unit":"g"},{"name":"black beans (fermented)","unit":"tablespoon"},{"name":"garlic","unit":"cloves"},{"name":"ginger","unit":"slices"},{"name":"scallion","unit":"stalks"},{"name":"light soy sauce","unit":"tablespoon"},{"name":"dark soy sauce","unit":"teaspoon"},{"name":"sugar","unit":"teaspoon"},{"name":"sesame oil","unit":"teaspoon"},{"name":"cornstarch","unit":"teaspoon"},{"name":"water","unit":"tablespoon"},{"name":"red chili","unit":"g"}]'::jsonb, '["Check and clean the eel:","When buying, ask the fishmonger to gut, remove slime, and cut into about 5 cm sections.","Check the eel at home, rinse thoroughly to ensure no residual slime or impurities.","Optional: Gently rub the eel pieces with 3g salt and 1 teaspoon cornstarch, marinate for 5 minutes, then rinse clean to remove fishy smell and enhance tenderness.","Prepare the sauce:","In a small bowl, mix 1 tablespoon black beans, 2 cloves minced garlic, 1.5 tablespoons light soy sauce, 0.5 teaspoon dark soy sauce, 0.5 teaspoon sugar, 0.5 teaspoon sesame oil, and 1 tablespoon water. Stir well.","If you prefer a richer black bean sauce, add an extra 0.5 tablespoon of black beans.","Arrange on plate:","Place the eel pieces flat in a heatproof dish, overlapping as little as possible.","Evenly sprinkle ginger strips over the eel.","Evenly pour the prepared black bean sauce over the eel.","Steam:","Add water (500ml) to a steamer or electric steamer and bring to a boil.","Place the dish with eel into the steamer, cover with lid.","Steam over medium-high heat for about 8-10 minutes (adjust time based on eel piece size) until the eel is cooked through but not overdone (flesh turns white, no blood).","Garnish and finish:","Remove from steamer, sprinkle with scallion strips and red chili strips (optional) for garnish.","You may drizzle hot sesame oil on top to enhance aroma.","Serve hot with steamed rice."]'::jsonb, '["Meat Dish","Cantonese","Steamed","Savory","Rice Companion","Home-style","Banquet"]'::jsonb),
  ('howtocook:meat_dish/贵州辣子鸡/贵州辣子鸡', 'en', 'Guizhou Spicy Chicken', 'Meat Dishes', 'Guizhou Spicy Chicken is a classic home-cooked dish from the Guizhou region, made with Ciba chili and various spices. The chicken is tender and sticky, the potatoes are soft and flavorful, and the overall taste is spicy and rich. Chicken is high in quality protein, paired with potatoes and other ingredients, making it a balanced meal. This dish has many steps, posing a challenge for beginners, but it can be done step by step. From preparation to serving, it takes about 1.5 hours.', '[{"name":"Free-range corn-fed chicken","unit":"lb"},{"name":"Potatoes","unit":"individual"},{"name":"Garlic","unit":"head"},{"name":"Bay leaves","unit":"leaf"},{"name":"Ginger","unit":"piece"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Sichuan pepper / numbing pepper","note":"to taste"},{"name":"Ciba chili (pounded chili)","unit":"g"},{"name":"Doubanjiang (fermented broad bean paste)","note":"to taste"},{"name":"Beer","unit":"bottle"},{"name":"Garlic sprouts","unit":"stalk"},{"name":"Fermented rice wine","note":"to taste"},{"name":"Cooking oil","unit":"lb"}]'::jsonb, '["Add oil to the pot until it reaches half the height of the pot. First fry the potato strips until golden brown, then remove and set aside. When the oil is hot enough to feel warm on your hand, add the chicken pieces to the pot and fry, along with sliced ginger and Sichuan pepper.","At the beginning of frying the chicken, the oil will be cloudy due to the water in the chicken. When the oil becomes clear, the chicken is done. Remove and set aside.","Now you can scoop out one-third of the oil from the pot; you won''t need that much oil for now.","Heat the remaining oil in the pot, add Ciba chili, Doubanjiang, and sliced ginger. Stir-fry until the oil turns red. Add the fried chicken pieces and stir-fry evenly.","When the chicken is evenly colored, add dark soy sauce and pour in beer. The beer must cover the chicken. Add bay leaves, cover, and simmer for 10 minutes, stirring occasionally.","Then add the potato strips and garlic (whole cloves, not chopped). Simmer for another 20 minutes.","Finally, add fermented rice wine and stir well, then add chopped garlic sprouts. Remove from heat and serve."]'::jsonb, '["Meat Dish","Spicy","Guizhou Flavor","Fried and Braised","Rice Dish","Entertaining"]'::jsonb),
  ('howtocook:meat_dish/辣椒炒肉', 'en', 'Stir-fried Pork with Green Peppers', 'Meat Dishes', 'Stir-fried pork with green peppers is a home-style dish with rich Hunan flavor. The peppers are dry-fried until slightly charred, and the pork slices are tender and flavorful. It''s salty, savory, and mildly spicy, making it a great accompaniment to rice. Pork is rich in high-quality protein and B vitamins, while green peppers provide abundant vitamin C. This dish requires mastery of dry-frying and quick-stirring techniques, suitable for those with some cooking experience. From preparation to serving, it takes about 30 minutes.', '[{"name":"Green peppers","unit":"piece"},{"name":"Lean pork","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Oyster sauce","unit":"ml"},{"name":"Garlic","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Fermented black beans","unit":"g"}]'::jsonb, '["Wash the green peppers, remove the stems and seeds, then cut into bite-sized pieces using a rolling cut (cut on the bias, turning the pepper as you go).","Smash the garlic cloves with the side of a knife, then slice crosswise into pieces. Finely chop the ginger into mince.","Slice the pork into pieces along the grain (i.e., the knife should be parallel to the meat fibers, resulting in slices with the grain in a ''川'' shape).","Rinse the sliced pork, place in a bowl, then add the measured light soy sauce, oyster sauce, and salt. Mix well and marinate for 10 minutes.","Heat the wok without oil, add the cut green peppers. Dry-fry over high heat until they develop a ''tiger skin'' appearance (blistered and slightly charred). Then add 2g salt and stir-fry for another minute. Remove and set aside.","Without cleaning the wok, heat it over high heat, add 8ml oil. After 30 seconds, add the garlic and ginger, stir-fry for 15 seconds.","Add the marinated pork to the wok, stir-fry for 2 minutes, then add the dry-fried green peppers and stir-fry for another minute.","Add fermented black beans (douchi) to taste, then add dark soy sauce. Continue stir-frying for 30 seconds.","Remove from heat and plate."]'::jsonb, '["Meat Dish","Hunan Cuisine","Salty, Savory, Mildly Spicy","Dry-fried","Quick Stir-fry","Goes well with rice","Home-style"]'::jsonb),
  ('howtocook:meat_dish/酱排骨/酱排骨', 'en', 'Braised Pork Ribs', 'Meat Dishes', 'Braised pork ribs are glossy red, tender and flavorful, with a rich bone aroma and a savory-sweet sauce. This classic home-cooked dish is rich in high-quality protein and calcium, offering balanced nutrition. The process involves caramelizing sugar and a longer simmer, which may be challenging for beginners, but following the steps carefully will yield good results. Preparation to serving takes about 1 hour.', '[{"name":"pork ribs","unit":"grams"},{"name":"five-spice powder","unit":"grams"},{"name":"cooking wine","unit":"ml"},{"name":"cooking oil","unit":"ml"},{"name":"white sugar","unit":"grams"},{"name":"dark soy sauce","unit":"ml"},{"name":"light soy sauce","unit":"ml"},{"name":"oyster sauce","unit":"ml"},{"name":"bird''s eye chilies","unit":"pieces"},{"name":"garlic","unit":"cloves"},{"name":"ginger","unit":"slices"}]'::jsonb, '["Bring a pot of water to a boil, add ribs, ginger slices, and cooking wine. After boiling, skim off the white foam with a spoon. Remove ribs after 2-3 minutes.","Rinse ribs under cold water, washing 2-3 times.","Heat a small amount of oil in a pan over low heat. Add white sugar and stir gently until the sugar melts and turns yellow.","Add ribs and stir-fry for 30 seconds. Then add light soy sauce, oyster sauce, five-spice powder, garlic, and bird''s eye chilies. Stir-fry for another 30 seconds. Add enough water to cover the ribs.","Boil over high heat for 30 minutes. Add dark soy sauce for color, then cook for another 10 minutes.","Plate and serve."]'::jsonb, '["Meat Dish","Savory-Sweet","Braised","Rice Companion","Home Cooking"]'::jsonb),
  ('howtocook:meat_dish/酱牛肉/酱牛肉', 'en', 'Soy-Marinated Beef', 'Meat Dishes', 'Soy-marinated beef is a Northern-style home-style cold dish, rich in sauce aroma, firm and not loose in texture, chewy. Beef shank is rich in high-quality protein and various amino acids, and after slow cooking, it''s easier to digest. The process is not too complicated, but includes marinating, slow cooking, and long refrigeration; it requires some patience for beginners, taking about 10 hours from start to finish.', '[{"name":"beef shank","unit":"grams"},{"name":"bay leaves","unit":"pieces"},{"name":"ginger","unit":"slices"},{"name":"scallion","unit":"stalks"},{"name":"dark soy sauce","unit":"ml"},{"name":"cinnamon stick","unit":"piece"},{"name":"rock sugar","unit":"pieces"},{"name":"Sichuan peppercorns","unit":"pieces"},{"name":"cooking wine","unit":"ml"},{"name":"light soy sauce","unit":"ml"},{"name":"salt","unit":"grams"},{"name":"star anise","unit":"pieces"},{"name":"soybean paste","unit":"ml"}]'::jsonb, '["Clean the beef shank, soak in water for 1 hour to remove blood.","Use a toothpick or fork to poke holes on the surface of the beef shank, add cooking wine, Sichuan peppercorns, and ginger slices, then tightly wrap the container with plastic wrap and marinate for 4-6 hours.","Cut the beef shank into pieces of 8 cm, not exceeding 10 cm.","Put the beef shank in a pot, add cold water until just covered. Bring to a boil, start timing, and skim off the foam. After 3 minutes, turn off the heat, remove the beef, and wash with warm water.","Place the washed beef shank in a clay pot or stew pot, add water to cover the beef, turn on high heat, and add all other unused ingredients except salt.","After the water boils, reduce heat to low and cook for 90 minutes, then add salt.","After adding salt, continue on low heat for another 90 minutes (note: check the water level every 30 minutes, ensuring it reaches at least 80% of the beef''s height).","After a total of 180 minutes of cooking, remove the beef shank, remove the beef shank, tightly wrap with plastic wrap, and refrigerate for several hours.","After taking it out, slice against the grain and serve. It is recommended to store the remaining beef shank unsliced in the refrigerator."]'::jsonb, '["Meat Dish","Sauce Aroma","Cold Dish","Northern Style","Slow Simmer","Goes with Drinks","Banquet Dish"]'::jsonb),
  ('howtocook:meat_dish/醉排骨/醉排骨', 'en', 'Drunken Spare Ribs', 'Meat Dishes', 'Drunken Spare Ribs is a traditional Fuzhou dish with a crispy outside and tender inside, sweet and sour, and a unique fish sauce aroma. The ribs are rich in protein and calcium, making them nutritious and satisfying. This dish requires skills in battering and double frying, so it''s better for those with some cooking experience. It takes about 40 minutes in total.', '[{"name":"spare ribs","unit":"gram"},{"name":"sweet potato starch","unit":"gram"},{"name":"egg yolk","unit":"piece"},{"name":"fish sauce","unit":"ml"},{"name":"minced garlic","unit":"clove"},{"name":"black vinegar","unit":"ml"},{"name":"white sugar","unit":"gram"},{"name":"ketchup","unit":"gram"},{"name":"scallion","unit":"stalk"},{"name":"sesame seeds","unit":"gram"},{"name":"cooking oil","unit":"ml"}]'::jsonb, '["Add 5 g sweet potato starch and water to the ribs, stir, rinse 2-3 times, and put in a large bowl for later use.","Add fish sauce, sweet potato starch, and egg yolk to the ribs and stir well.","Place the ribs one by one into the pot (do not pour them all in at once), making sure they don''t stick together.","After all are in, flip the meat pieces every 30 seconds with a spatula until the ribs are golden brown on the surface.","Remove the ribs, and after one minute, put them back into the oil to continue frying until the surface turns dark golden. Remove and set aside in a large bowl.","Prepare a small bowl, add minced garlic, black vinegar, white sugar, fish sauce, ketchup, chopped scallions, and sesame seeds, stir well, then pour in 5 ml hot oil.","Pour the sauce over the ribs, stir thoroughly, and transfer to a serving plate."]'::jsonb, '["Meat Dish","Sweet and Sour","Savory","Deep-fried","Fuzhou Cuisine","Entertaining","Rice Companion"]'::jsonb),
  ('howtocook:meat_dish/青椒土豆炒肉/青椒土豆炒肉', 'en', 'Green Pepper, Potato, and Pork Stir-fry', 'Meat Dishes', 'Green Pepper, Potato, and Pork Stir-fry is a home-style stir-fry that combines meat and vegetables. It tastes fresh, crispy, and tender, with a rich soy sauce flavor that goes well with rice. Potatoes are rich in carbohydrates and vitamin C, green peppers provide plenty of vitamin C and dietary fiber, and pork adds high-quality protein for a balanced meal. This dish is not complicated to make and is beginner-friendly, taking about 1 hour from prep to serving.', '[{"name":"Green pepper","unit":"piece"},{"name":"Potato","unit":"piece"},{"name":"Pork (pork belly)","unit":"g"},{"name":"Scallion","unit":"stalk"},{"name":"Ginger","unit":"piece"},{"name":"Garlic","unit":"clove"},{"name":"Salt","unit":"g"},{"name":"Soy sauce","unit":"ml"},{"name":"Cooking oil","unit":"ml"},{"name":"Potato starch","unit":"g"},{"name":"Water","unit":"g"}]'::jsonb, '["Remove the stems and cut the green pepper into small pieces, peel and slice the potato into 2mm thick slices, slice the pork into 4mm thick slices, cut the scallion into 3mm small sections crosswise and lengthwise, peel and smash the ginger and garlic and chop into fine mince; mix potato starch with about 15g water to form a slurry.","Heat oil in a wok until 70% hot, add the pork slices and gently stir-fry until no longer red, add about 3ml soy sauce and stir-fry until the meat is evenly colored, then add about 2g salt.","Lower the oil temperature to 50% hot, add scallion, ginger, and garlic and stir-fry for 5 seconds, then add the potato slices, increase heat to 70% hot and stir-fry evenly, add about 5ml soy sauce and 2g salt, stir-fry until the potatoes are just cooked through and slightly golden on the surface.","Increase heat to 80% hot, add the green pepper, stir-fry over high heat until you smell the aroma (white smoke appears), stir-fry evenly for 1 minute to color, then pour the starch slurry around the edges of the wok and reduce heat to 40% hot to thicken.","Turn off the heat when the sauce appears thick and glossy, then transfer to a serving plate."]'::jsonb, '["Meat Dish","Savory","Home-style","Goes well with rice","Stir-fry","Quick"]'::jsonb),
  ('howtocook:meat_dish/青椒酿/青椒酿', 'en', 'Stuffed Green Peppers', 'Meat Dishes', 'This classic Guangxi home-style dish features green peppers stuffed with seasoned meat or shrimp paste. The peppers are pan-fried until the skin wrinkles and develops a tiger-skin pattern, then braised to infuse flavors. The fresh aroma of green peppers blends with the savory filling, creating a salty, slightly spicy taste that pairs perfectly with rice. Both pork and shrimp provide high-quality protein, while green peppers are rich in vitamin C, offering a balanced nutrition. It takes a bit of patience to stuff the peppers, but the process is straightforward, and you can finish it in about 30 minutes.', '[{"name":"Green peppers (pointed peppers, choose straight and thick-fleshed)","unit":"piece"},{"name":"Pork (front shoulder meat is best)","unit":"g"},{"name":"Green onion","unit":"stalk"},{"name":"Ginger","unit":"small piece"},{"name":"Light soy sauce","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Water","unit":"ml"},{"name":"Starch (optional)","unit":"g"},{"name":"Garlic (optional)","unit":"clove"},{"name":"Oyster sauce (optional)","unit":"ml"},{"name":"Cooking wine (optional)","unit":"ml"},{"name":"Egg (optional)","unit":"piece"},{"name":"White pepper (optional)","unit":"g"},{"name":"Sugar (optional)","unit":"g"},{"name":"Shrimp (for shrimp paste version)","unit":"g"}]'::jsonb, '["Wash the pork and chop into minced meat (or use a meat grinder). Mince the ginger, and chop the green onion into scallions.","Add minced ginger, scallions, 15ml light soy sauce, 5ml dark soy sauce, and 3g salt to the minced meat. Mix well.","Optional: Add 10ml cooking wine, 10ml oyster sauce, 1 egg, 5g starch, 2g white pepper, and 5g sugar.","Stir the meat filling in one direction until it becomes sticky and firm. Marinate for 10 minutes.","Wash the green peppers, remove the stems, and carefully use chopsticks to remove the seeds and white pith, keeping the peppers intact.","Optional: Sprinkle about 5g of dry starch inside the peppers and shake evenly to help the filling adhere.","Use chopsticks or a piping bag to stuff the marinated meat filling into the peppers. Fill as much as possible but not too tightly to avoid splitting.","Set aside all stuffed peppers.","In a bowl, mix 15ml light soy sauce, 5ml dark soy sauce, and 100ml water. Stir well.","Optional: Add 5g starch to thicken the sauce.","Heat a pan and add 30ml cooking oil. When the oil is about 50-60% hot, place the stuffed peppers in the pan (meat side down first).","Fry over medium-low heat, turning to cook all sides until the skin wrinkles and develops a tiger-skin pattern. Remove and set aside.","Leave a little oil in the pan. Optional: add minced garlic and sauté until fragrant.","Pour in the prepared sauce. Bring to a boil, then add the fried peppers.","Reduce to medium-low heat, cover, and simmer for 5-8 minutes until the sauce thickens and the peppers soften.","Uncover, increase heat to high, and reduce the sauce until it glazes the peppers. Remove from heat and plate.","Devein 250g shrimp, then use the back of a knife to pound into a paste (keep some texture for better mouthfeel; alternatively, buy ready-made shrimp paste and directly stuff it using a piping bag).","Season the shrimp paste: 5g minced ginger, 2g salt, 5g starch, 10ml light soy sauce.","Optional: Add 5ml cooking wine, 1g white pepper, and half an egg white.","Stir in one direction until the shrimp paste becomes firm. Marinate for 10 minutes.","The subsequent steps of stuffing, frying, and braising are the same as the pork version.","Shrimp paste cooks quickly, so reduce the braising time to 4-5 minutes."]'::jsonb, '["Meat Dish","Savory","Slightly Spicy","Rice Companion","Pan-fried and Braised","Guangxi Style"]'::jsonb),
  ('howtocook:meat_dish/香干肉丝', 'en', 'Stir-fried Shredded Pork with Smoked Tofu', 'Meat Dishes', 'Shredded pork with smoked tofu is a savory, home-style stir-fry that pairs well with rice. The pork is tender, the smoked tofu is chewy, and the green peppers are crisp. It provides both animal and plant proteins, with green peppers adding vitamins. Moderate difficulty, achievable for beginners with some practice. Preparation time: about 30 minutes.', '[{"name":"Pork tenderloin (shredded)","unit":"g"},{"name":"Smoked tofu","unit":"g"},{"name":"Green pepper","unit":"piece"},{"name":"Salt","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Cornstarch","unit":"g"},{"name":"Garlic","unit":"g"},{"name":"Chicken bouillon","unit":"g"}]'::jsonb, '["Mix shredded pork (if not pre-cut, cut yourself) with light soy sauce (3ml) and cornstarch until well combined. Set aside.","Wash the green pepper, then cut into strips using a rolling cut technique. Set aside.","Slice the garlic crosswise into thin slices. Shred the smoked tofu.","Mix cornstarch with water (10ml) until smooth.","In a clean pan, heat 15ml oil. Add the shredded pork before the oil is hot, gently separate it with a spatula. Once the pork is cooked, immediately remove it, leaving the oil in the pan.","Add the garlic slices and shredded smoked tofu to the pan. Add 2ml light soy sauce and stir-fry evenly.","Depending on the heat, after 2-3 minutes, add the green pepper strips and stir-fry together.","After 1 minute, add the cooked pork back in and mix well.","Pour in the cornstarch-water mixture to thicken. Add 3g salt and 2g chicken bouillon. Stir-fry for 2-3 minutes, then serve.","Finished product."]'::jsonb, '["Meat Dish","Savory","Stir-fry","Home-style","Rice-pairing"]'::jsonb),
  ('howtocook:meat_dish/香干芹菜炒肉/香干芹菜炒肉', 'en', 'Stir-fried Pork with Dried Tofu and Celery', 'Meat Dishes', 'Stir-fried Pork with Dried Tofu and Celery is a home-style stir-fry. The dried tofu is chewy, the celery is crisp, and the pork is tender, with a savory and slightly spicy flavor. Celery is rich in dietary fiber, while dried tofu and pork provide high-quality plant and animal protein. The method is simple and beginner-friendly. From prep to serving, it takes about 30 minutes.', '[{"name":"Dried tofu","unit":"g"},{"name":"Celery","unit":"stalks"},{"name":"Pork","unit":"g"},{"name":"Garlic","unit":"cloves"},{"name":"Chili","unit":"pieces"},{"name":"Sichuan peppercorn","unit":"grains"},{"name":"Salt","unit":"g"},{"name":"Chicken bouillon","unit":"g"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Oyster sauce","unit":"ml"},{"name":"Cooking oil","unit":"ml"}]'::jsonb, '["Remove leaves from celery, cut into segments, then cut into strips no longer than 4 cm. Set aside.","Cut dried tofu into strips about the width of your pinky finger. Set aside.","Slice garlic or mince it. Set aside.","Cut chili into rings or slice diagonally. Set aside.","Heat the wok, add 10-15 ml cooking oil. Wait 10 seconds for the oil to heat up.","Add Sichuan peppercorns and garlic and stir-fry until fragrant (if you eat ginger, you can also add some ginger slices or shreds).","Add pork and stir-fry until it changes color, then add 8 ml dark soy sauce for color and stir well (if you have chili bean paste, add 3 ml and stir-fry together).","Add dried tofu and stir-fry evenly (about 2 minutes).","Add chili and stir-fry evenly (about 1-2 minutes).","Add celery, add 5 g salt and stir-fry for 1 minute.","Add 3 g chicken bouillon, 5 ml oyster sauce, and stir well. Then serve."]'::jsonb, '["Meat Dish","Home-style","Rice companion","Quick","Savory","Slightly spicy","Stir-fry"]'::jsonb),
  ('howtocook:meat_dish/香煎五花肉/香煎五花肉', 'en', 'Pan-Fried Pork Belly', 'Meat Dishes', 'Pan-fried pork belly is a quick home-style meat dish. The pork belly slices are fried until crispy and fragrant, fatty but not greasy. Paired with crisp lettuce leaves and savory broad bean paste, it''s rich in sauce flavor and refreshing. Pork is rich in high-quality protein and fat, quickly replenishing energy, while lettuce provides dietary fiber and vitamins for a more balanced nutrition. This dish is suitable for those with some basic cooking experience; beginners can also handle it easily by paying attention to heat and preventing oil splatter. From preparation to serving, it takes about half an hour.', '[{"name":"Pork belly strip (recommended dimensions: 20cm × 6cm × 5cm)"},{"name":"Lettuce","unit":"head"},{"name":"Soy sauce","unit":"gram"},{"name":"Salt","unit":"gram"},{"name":"MSG","unit":"gram"},{"name":"Cooking wine","unit":"gram"},{"name":"Ginger","unit":"slice"},{"name":"Garlic","unit":"head"},{"name":"Cooking oil","unit":"ml"},{"name":"Broad bean paste","note":"to taste"}]'::jsonb, '["Slice the pork belly strip lengthwise into pieces about 1mm-1.5mm thick, set aside.","Place the sliced pork belly in a bowl, add 8g soy sauce, 1g salt, 1g MSG, 10g cooking wine, 2 slices of ginger, and 2 smashed heads of garlic, marinate for 10 minutes.","Tear off the lettuce leaves by hand, wash them, and set aside.","Heat the pan, pour in 5ml cooking oil. Once the oil is slightly smoking, add the pork belly. Fry one side until golden brown, then flip and fry the other side the same way.","Remove the pork belly from the pan and plate it.","Spread the broad bean paste on the lettuce leaves, wrap the pork belly, and enjoy."]'::jsonb, '["Meat Dish","Pan-Fried","Home-style","Quick","Rice Companion","Savory Sauce"]'::jsonb),
  ('howtocook:meat_dish/香菇滑鸡/香菇滑鸡', 'en', 'Braised Chicken with Shiitake Mushrooms', 'Meat Dishes', 'Braised Chicken with Shiitake Mushrooms is a home-style dish primarily made with chicken thighs and shiitake mushrooms. The chicken thighs are stir-fried and then braised, resulting in a tender and smooth texture. Combined with the unique aroma of shiitake mushrooms, the broth is rich and savory. It is a Cantonese-style dish suitable for all ages. Chicken is rich in high-quality protein and various amino acids, while shiitake mushrooms contain lentinan and dietary fiber, which help boost immunity and promote digestion. This dish requires some knife skills and heat control, posing a challenge for beginners, and takes about 1 hour to prepare.', '[{"name":"Large chicken thigh","unit":"piece"},{"name":"Dried shiitake mushroom","unit":"piece"},{"name":"Ginger","unit":"slice"},{"name":"Scallion","unit":"stalk"},{"name":"Garlic","unit":"clove"},{"name":"Warm water","unit":"ml"},{"name":"Cooking wine","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Sugar","unit":"ml"},{"name":"Sesame oil","unit":"ml"}]'::jsonb, '["Soak dried shiitake mushrooms in warm water.","Cut ginger into small pieces, cut scallions into sections, cut garlic cloves in half and then into small pieces.","Debone chicken thighs (optional, but it slightly affects the efficiency of programmers eating). Cut into small pieces.","Cut each rehydrated mushroom into four pieces. Reserve the mushroom soaking water.","Blanch chicken thigh pieces in boiling water for 1 minute to remove blood foam and impurities.","Add 15ml cooking wine, 15ml light soy sauce, 1.5g salt, and 15ml dark soy sauce to the chicken. Mix well.","Heat oil to 30% hot. Add chicken and stir-fry until golden brown. Remove and set aside.","Leave a little oil in the wok. Add scallions, ginger, and garlic and stir-fry until fragrant. Add mushrooms and stir-fry over high heat to combine.","After about 20 seconds, when the mushroom aroma wafts out, add the stir-fried chicken, all of the mushroom soaking water (this is the soul of the dish, according to this programmer), 15ml sugar, and 30ml light soy sauce.","Reduce to medium heat, do not cover, and simmer for 2 minutes to reduce the sauce. Drizzle with 5ml sesame oil, sprinkle with chopped scallions, then turn off the heat and plate."]'::jsonb, '["Meat","Savory","Cantonese","Home-style","Rice Companion","Braising"]'::jsonb),
  ('howtocook:meat_dish/香辣鸡爪煲/香辣鸡爪煲', 'en', 'Spicy Chicken Feet Pot', 'Meat Dishes', 'Spicy, rich flavor, and chewy texture. It''s a common home-style dish that goes well with rice. Chicken feet are rich in collagen, which helps nourish skin and strengthen bones. You need to remove the toenails first. If using whole chicken feet, you also need to debone them. It''s a bit challenging for beginners, but with patience and following the steps, you can succeed. From blanching to slow simmering and then stir-frying to infuse flavor, the whole process takes about 45 minutes.', '[{"name":"Chicken feet","unit":"pound"},{"name":"Scallion","unit":"stalk"},{"name":"Ginger","unit":"gram"},{"name":"Garlic","unit":"gram"},{"name":"Cooking wine","note":"to taste"},{"name":"Bay leaves","unit":"piece"},{"name":"Star anise","unit":"piece"},{"name":"Light soy sauce","note":"to taste"},{"name":"Dark soy sauce","note":"to taste"},{"name":"Bird''s eye chilies","unit":"piece"},{"name":"Chili flakes (optional)","note":"to taste"},{"name":"Oyster sauce","unit":"gram"},{"name":"Five-spice powder","note":"to taste"},{"name":"Salt","note":"to taste"},{"name":"Chicken bouillon","note":"to taste"}]'::jsonb, '["Cut off the toenails of the chicken feet. If you bought only the paw part, cut them in half. If using whole chicken feet, you need to debone them. Rinse clean with water.","Place chicken feet in a pot with cold water, add scallion, ginger, and cooking wine to blanch. Bring to a boil, skim off the foam.","Add bay leaves, star anise, light soy sauce, and dark soy sauce. Cover and simmer on low heat for 30 minutes.","Remove the chicken feet, reserve a bowl of the chicken broth.","Heat oil in a wok, stir-fry minced ginger, minced garlic, and bird''s eye chilies on low heat until fragrant. Add more chili flakes if you can handle the heat. Add light soy sauce, dark soy sauce, oyster sauce, five-spice powder, and salt, stir-fry until the sauce is aromatic.","Add the chicken feet, season with a little salt, stir-fry for 1-2 minutes, then pour in the chicken broth, stirring constantly.","Add chicken bouillon to enhance flavor, sprinkle with scallion segments, stir well, and then remove from heat."]'::jsonb, '["Meat Dish","Spicy","Braise","Rice Dish","Home-style","Chewy"]'::jsonb),
  ('howtocook:meat_dish/鱼香肉丝', 'en', 'Fish-Fragrant Shredded Pork', 'Meat Dishes', 'Fish-Fragrant Shredded Pork is a classic Sichuan dish with a sweet, sour, and mildly spicy flavor. The pork is tender and smooth, accompanied by carrots, green peppers, and wood ear mushrooms, offering a rich texture. It''s rich in protein and various vitamins, with a balanced mix of meat and vegetables. The preparation is somewhat challenging, requiring a well-balanced fish-fragrant sauce and proper stir-frying technique. Beginners are advised to follow the steps strictly. The estimated preparation time is about 40 minutes (excluding time for soaking wood ear mushrooms).', '[{"name":"pork tenderloin","unit":"g"},{"name":"carrot","unit":"g"},{"name":"green pepper","unit":"g"},{"name":"dried wood ear mushroom","unit":"g"},{"name":"light soy sauce","unit":"ml"},{"name":"cooking wine","unit":"ml"},{"name":"egg white","unit":"piece"},{"name":"starch","unit":"g"},{"name":"vinegar","unit":"ml"},{"name":"sugar","unit":"g"},{"name":"salt","unit":"g"},{"name":"ginger","unit":"g"},{"name":"scallion","unit":"g"},{"name":"garlic","unit":"clove"},{"name":"doubanjiang (chili bean paste)","unit":"g"}]'::jsonb, '["Make the marinade: Mix the following ingredients:","Light soy sauce 5ml","Cooking wine 5ml","Starch 5g","Water 20ml","Egg white 1 piece","Make the sauce: Mix the following ingredients:","Light soy sauce 5ml","Vinegar 15ml","Sugar 10g","Salt 1g","Starch 5g","Water 20ml","Marinate the pork tenderloin with the marinade for 15-30 minutes. Make sure to mix well.","Soak dried wood ear mushrooms for 4 hours, wash, and cut into small pieces.","Wash green peppers, remove stems, and shred.","Wash carrots, shred, and blanch the carrot shreds.","Mince ginger and garlic.","Cut scallions into 5mm sections.","Heat the wok, add 15ml oil.","Add the marinated pork to the wok, quickly stir-fry until it turns white, then remove and set aside.","Heat the wok again, add 5ml oil.","Add all the scallions, ginger, garlic, and doubanjiang (chili bean paste).","Add all the carrots, stir-fry for 20 seconds, then add green peppers and wood ear mushrooms, stir-fry for 2 minutes.","Add the cooked pork. Quickly stir-fry until well combined. Do not stir-fry for more than 20 seconds.","Pour in the sauce. Quickly stir-fry until well combined. Do not stir-fry for more than 15 seconds.","Turn off the heat and plate."]'::jsonb, '["Meat Dish","Sichuan Cuisine","Sweet and Sour","Mildly Spicy","Great with Rice","Home-style"]'::jsonb),
  ('howtocook:meat_dish/鱼香茄子/鱼香茄子', 'en', 'Fish-Fragrant Eggplant', 'Meat Dishes', 'Fish-fragrant eggplant is a classic Sichuan home-style dish, sweet, sour and mildly spicy, with soft and tender eggplant that absorbs the sauce, making it a great accompaniment to rice. Eggplant is rich in dietary fiber and vitamins, and the ground meat adds protein. The difficulty is moderate; you need to master frying eggplant and seasoning techniques, but with a bit of practice, beginners can succeed. From prep to serving takes about 30 minutes.', '[{"name":"Eggplant","unit":"piece"},{"name":"Ground meat","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Sugar","unit":"g"},{"name":"MSG","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Vinegar","unit":"ml"},{"name":"Water starch","unit":"ml"},{"name":"Chili bean paste","unit":"g"},{"name":"Green onion","note":"to taste"},{"name":"Ginger","note":"to taste"},{"name":"Garlic","note":"to taste"},{"name":"Small chili peppers","note":"to taste"}]'::jsonb, '["Cut the eggplant into strips.","Chop the meat into mince; chop green onion, ginger, and garlic; dice the small chilies.","Make the fish-fragrant sauce: In a bowl, combine salt, MSG, sugar, light soy sauce, dark soy sauce, vinegar, and water starch, and stir well.","Pour 300ml oil into the wok, heat on low (low heat is easier to control). When the oil is 70% hot (about 40 seconds on low, when smoke appears), fry the eggplant for two minutes until the edges turn slightly yellow, then remove. The excess oil can be saved for later cooking.","Leave 15-30ml oil in the wok, stir-fry the ground meat until it turns white, then remove.","Pour 15-30ml oil into the wok, add chili bean paste, white parts of green onion, ginger, and garlic, stir-fry until fragrant, then add the ground meat and stir-fry evenly.","Add 80-150ml water (enough to come about 80% up the eggplant), add the eggplant and the sauce, stir-fry vigorously to let the flavors meld and reduce the sauce. Finally, add the green onion, stir-fry evenly, and serve."]'::jsonb, '["Meat dish","Sichuan flavor","Fish-fragrant","Sweet-sour and mildly spicy","Home-style","Rice companion"]'::jsonb),
  ('howtocook:meat_dish/麻婆豆腐/麻婆豆腐', 'en', 'Mapo Tofu', 'Meat Dishes', 'This spicy and silky tofu dish replaces traditional doubanjiang with salted duck egg, offering a salty-savory flavor with a hint of numbing and spicy notes—perfect to whet the appetite. Rich in high-quality protein, calcium, iron, and other trace elements. Moderate difficulty, beginner-friendly, takes about 40 minutes in total.', '[{"name":"Silken tofu","unit":"box"},{"name":"Salted duck egg","unit":"piece"},{"name":"Pork belly","unit":"g"},{"name":"Garlic","unit":"cloves"},{"name":"Ginger","unit":"slices"},{"name":"Bird''s eye chili","unit":"piece"},{"name":"Garlic chili sauce","unit":"g"},{"name":"Sichuan peppercorns","unit":"pieces"},{"name":"Salt","unit":"g"},{"name":"Light soy sauce","unit":"g"},{"name":"Cooking oil","unit":"ml"}]'::jsonb, '["Mince garlic and ginger; set aside.","Cut bird''s eye chilies into rings; set aside.","Finely chop the pork belly into ground pork (skip if already ground).","Add half the salt and light soy sauce to the ground pork; mix well; set aside.","Split the salted duck egg vertically with a knife (be careful), remove the yolk (must remove, otherwise it will be fishy), then mash the egg white into pieces about 2 mm x 2 mm—no need to be too fine; set aside.","Open the tofu package, use a fruit knife to cut the tofu in the box into pieces about 2.5 cm x 3 cm; set aside.","Heat the wok, add 10-15 ml cooking oil. Wait 10 seconds for the oil to heat up.","Reduce to low heat, add garlic, ginger, chili rings, Sichuan peppercorns, salted duck egg, and garlic chili sauce; stir-fry for 20 seconds until fragrant.","Increase to medium heat, add ground pork, stir-fry for about 1 minute until the meat changes color.","Reduce to low heat, add tofu, sprinkle the remaining salt and light soy sauce evenly over the tofu.","Pour boiling water from the side of the wok (otherwise the tofu may break), just enough to submerge the tofu.","Turn to high heat, once the water boils, immediately reduce to medium heat; simmer for about 10 minutes.","When the liquid reduces to 1/5 and the tofu surface has taken on color, turn off the heat and plate."]'::jsonb, '["Meat dish","Spicy","Salty-savory","Slightly numbing and spicy","Rice companion","Home-style"]'::jsonb),
  ('howtocook:meat_dish/麻辣香锅', 'en', 'Mala Spicy Pot', 'Meat Dishes', 'A spicy and rich Sichuan home-style dish, combining vegetables, meat, and tofu products. The taste is numbing and spicy with rich layers. The combination of meat and vegetables provides high-quality protein and various vitamins, making it nutritious. The steps are clear; need to master blanching and stir-frying heat; it''s somewhat challenging for beginners. Total preparation time is about 30 minutes.', '[{"name":"Greens (bok choy, lettuce, spinach)","unit":"g"},{"name":"Boneless meat (pork, beef, chicken, fish balls, ham sausage)","unit":"g"},{"name":"Dried tofu","unit":"g"},{"name":"Beijing Mala instant noodles","unit":"packet"},{"name":"Dried chili peppers","unit":"g"},{"name":"Cooking oil","unit":"g"}]'::jsonb, '["Bring a pot of water to a boil (enough water to submerge the ingredients in steps 2-4).","Add the greens to the boiling water, blanch for 5 minutes, then remove and set aside.","Add the boneless meat to the boiling water, blanch for 4 minutes, then remove and set aside.","Add the Beijing Mala instant noodles to the boiling water, cook for 2 minutes, then remove and set aside.","Discard the boiling water, dry the pot, add 105 grams of cooking oil, and heat over high heat for 30 seconds.","Add the Mala Xiang Guo seasoning, stir-fry for 20 seconds.","Add the dried chili peppers, stir-fry for 10 seconds.","Add the blanched greens, reduce to medium heat, and stir-fry for 3 minutes.","Add the blanched boneless meat, stir-fry for 3 minutes.","Add the cooked Beijing Mala instant noodles, toss with chopsticks for 1 minute.","Turn off the heat, serve."]'::jsonb, '["Meat Dish","Spicy","Sichuan","Stir-fry","Rice Companion","Homestyle"]'::jsonb),
  ('howtocook:meat_dish/黄油鸡', 'en', 'Butter Chicken', 'Meat Dishes', 'This is a classic Indian curry dish, featuring grilled then simmered chicken thighs in a sauce made with tomatoes, butter, and cream. The texture is rich and silky, with a sweet, sour, and mildly spicy flavor, and a unique blend of spices. Chicken, yogurt, and cashews provide ample protein and healthy fats, while tomatoes and spices offer vitamins and antioxidants. It''s somewhat challenging to make, requiring control of heat and balance of spices. Including marinating time, it takes about 1 hour 45 minutes to complete.', '[{"name":"Chicken thighs (boneless)","unit":"g","note":""},{"name":"Yogurt","unit":"ml","note":""},{"name":"Ginger","unit":"g","note":""},{"name":"Garlic","unit":"clove","note":""},{"name":"Red chili powder","unit":"g","note":""},{"name":"Turmeric powder","unit":"g","note":""},{"name":"Salt","unit":"g","note":""},{"name":"Lemon juice","unit":"ml","note":""},{"name":"Cooking oil","unit":"ml","note":""},{"name":"Tomato","unit":"piece","note":""},{"name":"Onion","unit":"piece","note":""},{"name":"Cashew nuts (for thickening)","unit":"g","note":""},{"name":"Ginger","unit":"g","note":""},{"name":"Garlic","unit":"clove","note":""},{"name":"Butter","unit":"g","note":""},{"name":"Heavy cream","unit":"ml","note":""},{"name":"Red chili powder","unit":"g","note":""},{"name":"Coriander powder","unit":"g","note":""},{"name":"Cumin powder","unit":"g","note":""},{"name":"Garam masala","unit":"g","note":""},{"name":"Cardamom powder","unit":"g","note":""},{"name":"Dried fenugreek leaves (Kasuri Methi)","unit":"g","note":""},{"name":"Sugar","unit":"g","note":""},{"name":"Salt","unit":"g","note":""},{"name":"Water","unit":"ml","note":""}]'::jsonb, '["In a large bowl, mix together yogurt, ginger paste, garlic paste, red chili powder, turmeric powder, salt, and lemon juice.","Add chicken pieces and coat thoroughly with the marinade.","Cover with plastic wrap and refrigerate for at least 1 hour.","Heat 15ml of cooking oil in a pan over high heat.","Place the marinated chicken pieces into the pan (do not pour in the marinade).","Sear over high heat until both sides are browned (about 3 minutes per side); the chicken does not need to be fully cooked.","Remove and set aside.","Add tomato chunks, onion chunks, cashews, ginger, garlic, and 100ml of water to the pan.","Bring to a boil over high heat, then reduce to medium heat and cook for 15 minutes until all ingredients are completely soft.","Let cool slightly, then transfer to a blender and blend into a smooth puree.","Strain through a fine mesh sieve to remove solids, yielding a smooth sauce. Set aside.","In a wok or pan, melt 50g of butter over medium heat.","Pour in the strained tomato sauce.","Add 5g red chili powder, 5g coriander powder, 3g cumin powder, and 5g salt.","Stir-fry for 3-5 minutes until the sauce darkens and oil separates.","Add the seared chicken pieces and toss to coat evenly.","Add 10g sugar (to balance the acidity of the tomatoes) and stir.","Pour in 100ml heavy cream and mix well.","Simmer over low heat for 10-12 minutes until the chicken is fully cooked and has absorbed the sauce.","Add 3g garam masala and 2g cardamom powder.","Sprinkle in 3g dried fenugreek leaves (crush them between your palms before adding).","Stir to combine, then turn off the heat.","Serve on a plate, optionally drizzling a little extra cream on top for decoration."]'::jsonb, '["Meat Dish","Indian Flavor","Curry","Spicy","Rich","Entertaining"]'::jsonb),
  ('howtocook:meat_dish/黄焖鸡', 'en', 'Braised Chicken', 'Meat Dishes', 'Braised Chicken is a home-style dish featuring chicken thighs, mushrooms, and green peppers. The broth is rich, the chicken is tender, with a savory and slightly sweet flavor that goes great with rice. It is nutritious, providing high-quality protein and mushroom polysaccharides. The caramelizing sugar step can be a bit challenging, but you can substitute with dark soy sauce. Overall, it''s not difficult and beginners can handle it. It takes about 40 minutes from prep to serving.', '[{"name":"chicken thigh","unit":"piece"},{"name":"shiitake mushrooms (dried preferred)","unit":"piece"},{"name":"green pepper","unit":"piece"},{"name":"ginger slices","unit":"slice"},{"name":"dried chili peppers","unit":"piece"},{"name":"salt","unit":"gram"},{"name":"cooking wine","unit":"ml"},{"name":"white pepper","unit":"gram"},{"name":"sugar","unit":"gram"},{"name":"soy sauce","unit":"ml"},{"name":"MSG","note":"to taste"},{"name":"potato (optional)","unit":"piece"}]'::jsonb, '["Wash the chicken thighs and chop them into 4 cm pieces.","Slice the ginger and cut the dried chili peppers into small rings.","Slice the mushrooms. Cut the green peppers into long, thin horse-hoof shapes. If using dried mushrooms, rinse off dust, soak overnight, and reserve the mushroom soaking liquid.","If using potatoes, cut them into rolling cut chunks similar in size to the chicken.","Caramelize the sugar: Pour oil into the wok, add sugar to the cold oil (this is somewhat challenging; beginners can skip to stir-frying the chicken and substitute with dark soy sauce).","Heat slowly over low heat. As the oil temperature rises, the sugar will melt and turn a deep brown (stir constantly to prevent burning).","Quickly add the chicken pieces, turn up the heat, and stir-fry fast! Splash in the cooking wine and continue stir-frying for a moment.","Add the ginger slices and dried chili peppers.","Add the soy sauce and stir well.","Pour in the mushroom soaking liquid or water, just enough to cover the chicken.","Add the mushroom slices, white pepper, salt, and potatoes.","Stir everything together, then cover and simmer over medium-low heat for 15–20 minutes. If possible, transfer to a clay pot.","When the chicken is tender and the sauce has thickened (don''t reduce the sauce too much), finally add the green peppers.","Add MSG, toss to combine, then turn off the heat! The green peppers should be just cooked through—don''t overcook."]'::jsonb, '["Meat Dish","Savory","Slightly Sweet","Braising","Home-style","Goes Well with Rice"]'::jsonb),
  ('howtocook:meat_dish/黄瓜炒肉', 'en', 'Cucumber Stir-fry with Pork', 'Meat Dishes', 'This is a refreshing, crisp, and tender home-style quick dish. It is savory and slightly spicy with garlic aroma. Rich in protein and various vitamins, it helps cool and hydrate. It''s friendly for beginners; just pay attention to the heat and you''ll succeed. Estimated cooking time: about 25 minutes.', '[{"name":"Cucumber","unit":"g"},{"name":"Lean pork","unit":"g"},{"name":"Cooking oil","unit":"g"},{"name":"Light soy sauce","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Garlic","unit":"clove"},{"name":"Bird''s eye chili","unit":"piece"}]'::jsonb, '["Slice the lean pork into pieces, place in a bowl, add 10g cooking oil and light soy sauce, mix well, and marinate for 10 minutes.","Cut off the 5cm ends of the cucumber, and slice the rest diagonally into 0.5cm thin slices.","Put the cucumber slices into a bowl, sprinkle with 8g salt, mix well, and marinate for 5 minutes.","Peel the garlic cloves, flatten them, and mince into garlic paste; set aside.","Remove the stems from the bird''s eye chilies and cut into even 0.5cm sections.","Heat the wok, add 40g oil, wait until the oil smokes, then add the minced garlic and bird''s eye chilies and stir-fry 5 times.","Add the marinated lean pork and stir-fry until the meat is cooked and changes color.","Add the cucumber, add 2g salt, stir-fry over high heat evenly for half a minute, then remove from wok.","If you can''t guarantee high heat, it might be a bit undercooked. Consider extending to 50 seconds."]'::jsonb, '["Meat Dish","Home-style","Quick","Savory","Slightly Spicy","Rice Companion","Refreshing"]'::jsonb),
  ('howtocook:meat_dish/黑椒牛柳/黑椒牛柳', 'en', 'Black Pepper Beef', 'Meat Dishes', 'Black Pepper Beef is a popular home-style stir-fry. It features a rich black pepper flavor, tender beef slices, and sweet crunchy onions and bell peppers, balancing meat and vegetables. The taste appeals to all ages. Beef is rich in high-quality protein and iron, while bell peppers and onions provide various vitamins. This dish is very beginner-friendly; from prep to serving, it usually takes under an hour.', '[{"name":"Beef (tenderloin/steak)","unit":"g"},{"name":"Onion","unit":"piece"},{"name":"Bell pepper (red/yellow)","unit":"piece"},{"name":"Starch","unit":"g"},{"name":"Black pepper (ground)","unit":"g"},{"name":"Black pepper (marinade)","note":"to taste"},{"name":"Salt","unit":"g"},{"name":"Peanut oil","unit":"ml"}]'::jsonb, '["Cut the beef into strips, preferably no longer than 8 cm, about 5-10 mm thick, and about 1 cm wide (not strict).","Marinate the beef with the marinade. Mix well and let it sit. Refer to the product instructions for the amount and time. You can extend the marinating time but not shorten it.","If using a liquid marinade, sprinkle a layer of black pepper three minutes before the end of marinating, then add starch, mix well again, and let sit for 20 minutes.","Turn on the heat and heat the pan. Add peanut oil.","When you see a faint smoke rising from the oil, add the beef and stir-fry.","Stir-fry over medium-high heat for 2 minutes until the beef surface changes color (no obvious redness; any red spots indicate insufficient stir-frying). Be careful of oil splatter.","Add the onion and bell peppers, and stir-fry for 2 minutes.","Add salt, sprinkle another portion of black pepper, and stir-fry for 30 seconds until well combined.","Once the onion has softened, turn off the heat, remove from the pan, and plate."]'::jsonb, '["Meat Dish","Black Pepper","Home-style","Stir-fry","Rice Dish","Quick"]'::jsonb),
  ('howtocook:meat_dish/黔式腊肠娃娃菜/黔式腊肠娃娃菜', 'en', 'Guizhou-Style Sausage with Baby Cabbage', 'Meat Dishes', 'This dish is savory and delicious, blending the rich aroma of Guizhou-style sausage with the sweetness of baby cabbage. It is a rare non-spicy flavor in Southwestern cuisine, suitable for all tastes. Baby cabbage is rich in vitamins and dietary fiber, paired with the protein and fat of sausage for balanced nutrition. The cooking process is extremely simple, requiring no mastery of heat or extra seasoning. It takes only 15 minutes from prep to serving, making it perfect for beginners and busy days.', '[{"name":"Guizhou-style sausage","unit":"g"},{"name":"baby cabbage","unit":"g"},{"name":"water","unit":"ml"}]'::jsonb, '["Add 750ml water to the pot and heat until boiling.","Add the sausage, set a timer for 13 minutes.","Add the baby cabbage, set a timer for 2 minutes.","Turn off the heat, remove the sausage and baby cabbage.","Cut the baby cabbage into segments and slice the sausage; arrange on a plate."]'::jsonb, '["meat dish","savory","boiled","Guizhou-style","quick","home-style"]'::jsonb),
  ('howtocook:semi-finished/凉皮', 'en', 'Liangpi', 'Semi-prepared', 'Liangpi is a homestyle snack originating from Shaanxi. It has a chewy and smooth texture, sour and spicy flavor that whets the appetite, and a rich sesame paste aroma. The sesame paste and gluten provide plant protein and calcium, while the crisp cucumber and bean sprouts add vitamins and dietary fiber. The difficulty is moderate; it requires simple blanching, shredding, and sauce mixing, so beginners can manage it. From prep to table takes about 40 minutes, perfect for summer meals.', '[{"name":"Liangpi","unit":"g"},{"name":"Gluten","note":"to taste"},{"name":"Salt","note":"to taste"},{"name":"Chicken bouillon","note":"add in batches"},{"name":"Oyster sauce","note":"add in batches"},{"name":"Light soy sauce","note":"add in batches"},{"name":"Dark soy sauce","note":"add in batches"},{"name":"Sesame oil","unit":"g"},{"name":"Zhenjiang vinegar","note":"to taste"},{"name":"Sesame paste","unit":"g"},{"name":"Cucumber","unit":"g"},{"name":"Garlic","unit":"g"},{"name":"Bean sprouts","unit":"g"}]'::jsonb, '["Add 500ml water to a pot. Bring to a boil.","Put the bean sprouts into the pot and cook over high heat for 60 seconds. Remove the bean sprouts, rinse under cold water, and set aside on a plate.","Shred the cucumber and set aside on a plate.","Peel 10g garlic cloves, put them in a mortar with 1g salt. Pound into garlic paste, add 10g tap water. Set aside.","Note: Store-bought liangpi usually has cooking oil on the surface; you can rinse with tap water. Same for gluten.","Note: After washing the gluten, squeeze out excess water by hand (no need to be too forceful).","Prepare a small bowl, add 3g salt, 2g chicken bouillon, 5g light soy sauce, 1g dark soy sauce, 1g sesame oil, 2g oyster sauce, 5g Zhenjiang vinegar (salt and vinegar can be adjusted to taste; these amounts are for average taste).","Add 25-35g warm water (depending on desired saltiness) to the above seasonings, stir with chopsticks to dissolve. Set aside to cool.","Note: The following measurements are for one serving. For n people, multiply accordingly.","Take out a small bowl and put the prepared sesame paste in it.","Add 4g salt, 3g chicken bouillon, 5g light soy sauce, 1g dark soy sauce, 3g oyster sauce.","Use chopsticks to mix the seasonings with the sesame paste.","Add 10g water and mix well.","Repeat the previous step 2-3 times (depending on desired thickness of sesame paste).","Take out the previously prepared basin and add the prepared liangpi.","Pour in the salted water mixture, mix with chopsticks. Then transfer to a small bowl (including the liquid).","Place bean sprouts on top of the liangpi, then add the gluten.","Pour the prepared sesame paste over the gluten.","Sprinkle shredded cucumber on top.","Add chili oil if desired.","Your flavorful homestyle liangpi is ready!"]'::jsonb, '["Semi-prepared","Sour-Spicy","Cold Mix","Shaanxi Style","Homestyle","Appetizing","Summer"]'::jsonb),
  ('howtocook:semi-finished/半成品意面', 'en', 'Semi-finished Pasta', 'Semi-prepared', 'Using store-bought semi-finished ingredients, this Western-style quick meal features springy, chewy pasta paired with a rich, ready-made sauce. It''s primarily carbohydrates for quick energy, with some protein. Extremely easy, even beginners can''t go wrong—from stove to plate in about 2 minutes.', '[{"name":"Semi-finished pasta (recommended brand: Pulmuone)","unit":"g"},{"name":"Water","unit":"ml"}]'::jsonb, '["Heat the pan.","Pour 50 ml of water into the pan.","Add the pasta and stir-fry for 1 minute.","Pour in the sauce and stir-fry for 1 minute.","Plate and serve.","Place the pasta in a microwave-safe dish.","Pour the included sauce over the pasta.","Add 50 ml of water.","Microwave at 700W for 2 minutes.","Remove, stir, and serve."]'::jsonb, '["Convenience","Quick","Home-style","Western","Pasta","Instant"]'::jsonb),
  ('howtocook:semi-finished/懒人蛋挞/懒人蛋挞', 'en', 'Lazy Egg Tarts', 'Semi-prepared', 'This dessert uses ready-made tart shells and egg tart mixture. The crust is flaky and fragrant, the filling is silky smooth with caramel spots. It''s the easiest version of classic Cantonese dim sum. The main ingredients, eggs and milk, provide high-quality protein and calcium, making it suitable as a family snack. The whole process only requires assembly and baking, and is friendly even for absolute beginners. From preheating the oven to finishing takes about 40 minutes.', '[{"name":"Egg tart shells","unit":"piece"},{"name":"Egg tart mixture","unit":"ml"}]'::jsonb, '["Preheat oven to 200°C for 10 minutes.","Place the tart shells on a baking tray. Pour about 10ml of egg tart mixture into each shell, adjusting based on shell size; usually fill up to 4/5 full.","Put the baking tray into the oven, bake at 190°C with both top and bottom heat for 10-20 minutes. To quickly get caramelized spots on the filling, increase the top heat to 200-210°C.","Done when the filling has caramelized spots and the tart shells are fully puffed and oily."]'::jsonb, '["Semi-finished","Sweet","Baking","Cantonese","Quick","Beginner-friendly"]'::jsonb),
  ('howtocook:semi-finished/炸薯条/炸薯条', 'en', 'French Fries', 'Semi-prepared', 'French fries are crispy on the outside and soft on the inside, golden and savory, a popular fast food snack. Potatoes provide carbohydrates and dietary fiber, but frying or air frying makes them high in calories. Using semi-finished fries and an air fryer makes the process simple, even for beginners. From preheating to serving, it takes about 25 minutes.', '[{"name":"Semi-finished fries (recommended brand McCain)","unit":"grams"},{"name":"Oil","note":"as needed"}]'::jsonb, '["When opening a large package of semi-finished fries, make a small opening to effectively reduce frost on the fries during long-term storage.","Plug in, preheat at 200°C for 5 minutes.","The purpose of preheating is to ensure the temperature inside the basket is at the required cooking temperature when you add the food.","Note: take out the fries only after preheating; do not let them soften before frying.","Place the fries in the air fryer, cook at 200°C for 20 minutes.","When taking out the fries, note that semi-finished fries already have oil, so use tongs or a suitable tool to avoid contact.","At 5–10 minutes, shake the basket to ensure even heating and prevent sticking.","At 10–15 minutes, take out the basket and spray a layer of oil covering about 2/3 of the surface area of the fries.","For crispy fries, after removing, shake the basket to let air pass over the fries, then plate; for soft fries, plate directly. Best served with dipping sauce or drizzled with sauce."]'::jsonb, '["Semi-finished","Quick","Snack","Savory","Air Fryer"]'::jsonb),
  ('howtocook:semi-finished/牛油火锅底料', 'en', 'Beef Tallow Hot Pot Base', 'Semi-prepared', 'This Chongqing hot pot base uses a large amount of beef tallow as the base, combined with Ciba chili and various spices. The resulting base is spicy, rich, and intensely aromatic, making it the soul for blanching tripe, duck intestines, and other ingredients. Beef tallow and lard provide rich energy; chili and Sichuan pepper warm the body, dispel cold, and stimulate appetite. However, it is high in fat, so consume in moderation. The process requires precise control of oil temperature and stir-frying heat, which is challenging for beginners. From prep to completion, it takes about 1 hour.', '[{"name":"Beef tallow","unit":"g"},{"name":"Salad oil/rapeseed oil","unit":"ml"},{"name":"Pure lard","unit":"g"},{"name":"Doubanjiang","unit":"g"},{"name":"Ciba chili","unit":"g"},{"name":"Old ginger","unit":"g"},{"name":"Scallions","unit":"g"},{"name":"Onion","unit":"g"},{"name":"Garlic","unit":"g"},{"name":"Fermented black beans","unit":"g"},{"name":"Doumuzi","unit":"g"},{"name":"Red Sichuan pepper","unit":"g"},{"name":"Whole spices","unit":"g"},{"name":"Shaped spices","unit":"g"},{"name":"Malt powder","unit":"g"},{"name":"Baijiu","unit":"ml"},{"name":"Dried chili flakes","unit":"g"},{"name":"Kaempferia galanga","unit":"g"},{"name":"Star anise","unit":"g"},{"name":"Tsaoko","unit":"g"},{"name":"Cinnamon","unit":"g"},{"name":"Cloves","unit":"g"},{"name":"Cumin","unit":"g"},{"name":"Angelica dahurica","unit":"g"},{"name":"Long pepper","unit":"g"},{"name":"Vanilla","unit":"g"},{"name":"Nutmeg","unit":"g"},{"name":"Hawthorn","unit":"g"},{"name":"Dried tangerine peel","unit":"g"},{"name":"Lemongrass","unit":"g"},{"name":"Amomum villosum","unit":"g"},{"name":"White cardamom","unit":"g"},{"name":"Bay leaves","unit":"g"}]'::jsonb, '["Place the pot over high heat, add beef tallow and heat to 80% hot (240±10°C). Add 100g each of old ginger, scallions, onion, and garlic. Fry until dry (to absorb the gamey smell of beef tallow), then remove and discard.","Add (salad oil or vegetable oil) and pure lard. Wait until the oil temperature drops to 50% hot (150±10°C), then add Ciba chili and stir-fry continuously for 5-8 minutes.","Add doubanjiang (fermented broad bean paste) and stir to break it up. Switch to medium-low heat and slowly stir-fry until the residue turns slightly white and sandy (making a rustling sound).","When the oil turns cherry red in appearance, add 150g sliced ginger and 100g garlic, stir-fry until fragrant, about 15 seconds.","Add fermented black beans and dòumǔzi (fermented soybean paste) and stir-fry until fragrant. Add red Sichuan pepper and cumin, stir-fry until fragrant.","(For aged oil) At this point, add the whole spices.","Add malt powder and stir to combine, then add baijiu (Chinese liquor) and stir to combine.","Remove from pot and place in a container. Let it sit in a low-temperature environment (10-20°C) for 5 days for best results before use.","Remove from pot and place in a container. Add dried chili flakes and stir to combine. Let it sit for 24 hours, waiting to make aged oil.","Pour the base into a pot, add 3/5 boiling water, and bring to a boil over high heat (base: 2/5, boiling water: 3/5).","After boiling, foam will appear on the surface. Skim off the foam.","Switch to medium-low heat and simmer to extract flavor (about 25-30 minutes), then strain out the solids.","After the oil and water separate in the container, skim off the oil on top (scoop out the oil) and place into another container.","Pour the skimmed oil back into a clean pot and heat until the moisture in the oil is evaporated. Remove from pot and place into a container. This is the aged hot pot oil."]'::jsonb, '["Semi-finished","Spicy and numbing","Stir-fried","Chongqing","Heavy oil","Homemade base"]'::jsonb),
  ('howtocook:semi-finished/空气炸锅羊排/空气炸锅羊排', 'en', 'Air Fryer Lamb Chops', 'Semi-prepared', 'This dish is super lazy-friendly. The air fryer renders excess fat, giving a crispy exterior and tender interior with rich garlic flavor. The taste mainly depends on the quality of the lamb chops. Lamb is rich in high-quality protein and trace elements like iron and zinc, which help warm and nourish the body and boost immunity. The cooking difficulty is moderate; beginners can easily handle it. The actual hands-on time is only 10 minutes, and including marinating, you can serve it in about 40 minutes.', '[{"name":"Lamb chops","unit":"pieces"},{"name":"Black pepper mixed steak seasoning","unit":"grams"},{"name":"Garlic sauce","unit":"grams"},{"name":"Butter","unit":"small box"},{"name":"Barbecue seasoning","unit":"grams"},{"name":"Dried basil","note":"to taste"}]'::jsonb, '["Place lamb chops in a bowl and rinse with water to remove blood.","Pat lamb chops dry with paper towels. Spread black pepper mixed seasoning and garlic sauce on both sides. Let marinate for 20 minutes.","Place a foil bowl on the rack, put lamb chops on the rack, sprinkle with dried basil, place butter or barbecue seasoning on top. Air fry at 180°C for 10 minutes.","Flip lamb chops, sprinkle with dried basil, add butter (scoop from the foil bowl) or barbecue seasoning on top. Air fry at 180°C for 5 minutes (you can add a bit more time if desired; this is the time to avoid burning)."]'::jsonb, '["Semi-finished","Air fryer","Garlic","Black pepper","Quick","Home-style","Lazy"]'::jsonb),
  ('howtocook:semi-finished/空气炸锅鸡翅中/空气炸锅鸡翅中', 'en', 'Air Fryer Chicken Wings (Middle Section)', 'Semi-prepared', 'This is a convenient and easy home-style quick dish. The chicken wings are crispy on the outside and tender on the inside, with their own fatty aroma, more satisfying than fast food. Chicken wings are rich in high-quality protein and fat, providing ample energy. Very friendly for beginners; actual preparation takes just a few minutes, and the whole process takes about 40 minutes to serve.', '[{"name":"Chicken wings (middle section)","unit":"piece"},{"name":"Dried basil","note":"to taste"},{"name":"Yunnan Single Mountain Dipping Spice","note":"to taste"}]'::jsonb, '["Take chicken wings out of the fridge, place them skin side down in a foil-lined baking pan, sprinkle with dried basil, cover with plastic wrap, and let thaw naturally for 20 minutes.","Sprinkle with dried basil, air fry at 200°C for 10 minutes.","Flip, sprinkle with dried basil, air fry at 200°C for 7 minutes."]'::jsonb, '["Semi-finished","Quick","Home-style","Orleans","Savory","Pairing with alcohol"]'::jsonb),
  ('howtocook:semi-finished/速冻水饺', 'en', 'Frozen Dumplings', 'Semi-prepared', 'This is a home-style noodle dish from China, made quickly with store-bought frozen dumplings. Thin-skinned and generously filled, they offer a savory and fresh taste. Paired with dipping sauces like vinegar, ginger, and garlic, the flavors gain extra depth. As a meal, it provides ample protein and carbs, making it nutritious and filling. No difficulties in preparation, even beginners can handle it, and it takes only about 15 minutes from start to finish.', '[{"name":"Frozen dumplings","unit":"pieces"},{"name":"Water","note":"to taste"},{"name":"Vinegar","note":"to taste"},{"name":"Ginger","note":"to taste"},{"name":"Garlic","note":"to taste"}]'::jsonb, '["Over medium heat, pour water into a pot and wait for it to boil.","Pour the dumplings into the pot.","Before pouring, you can briefly rinse the dumplings with water if desired.","After adding the dumplings, stir the water with a spatula or ladle, but be careful not to hit the dumplings to avoid tearing the wrappers on the pot or sticking together, which can cause undercooked areas where they stick.","Stirring frequency doesn''t need to be high; average 3 seconds of stirring every 30 seconds. Once the dumplings float, this step is no longer needed.","After the dumplings float and the water boils again, scoop up one dumpling with a ladle to check. If the wrapper is undercooked, ladle in 80ml of cold water to lower the temperature, then continue cooking until boiling again. Repeat this checking and stirring process; at most two additions of water will cook them through.","Once all dumplings have floated (about 8 minutes after adding them), use a spatula or slotted spoon to transfer the dumplings to a plate or bowl. Serve immediately.","After eating, wait for the pot water to cool, then pour out the water and wash the pot promptly with dish soap; otherwise, the cooked flour from the dumplings will form a sticky residue on the pot walls."]'::jsonb, '["Semi-prepared","Quick","Home-style","Savory","Boiled","Filling"]'::jsonb),
  ('howtocook:semi-finished/速冻汤圆/速冻汤圆', 'en', 'Frozen Tangyuan', 'Semi-prepared', 'Frozen tangyuan is a quick and convenient microwave dessert with soft and chewy skin and sweet filling. It is a traditional Chinese snack. It mainly provides carbohydrates and can quickly replenish energy. The method is very easy, even beginners can do it easily. From preparation to serving takes about 6 minutes.', '[{"name":"frozen tangyuan","unit":"piece"}]'::jsonb, '["Take out the frozen tangyuan and put them in a bowl.","Pour boiling water until the tangyuan are submerged.","Microwave on high for 4 minutes.","If the tangyuan have all absorbed water and expanded, they are cooked.","If not cooked, heat for another 1 minute."]'::jsonb, '["semi-finished","quick","microwave","soft and chewy","sweet","Chinese"]'::jsonb),
  ('howtocook:semi-finished/速冻馄饨', 'en', 'Frozen Wontons', 'Semi-prepared', 'Frozen wontons have thin skins and juicy filling, with a clear and flavorful broth. They''re a quick and easy home-style noodle dish that provides carbs and protein for a fast energy boost. The cooking method is simple and beginner-friendly—just use a rice cooker. From boiling water to serving, it takes about 55 minutes.', '[{"name":"Frozen wontons","unit":"pieces"},{"name":"Water","unit":"ml"},{"name":"Salt","note":"Add to taste if no seasoning packet"},{"name":"Chicken bouillon","note":"Add to taste if no seasoning packet"},{"name":"White pepper","note":"Add to taste if no seasoning packet"},{"name":"Sesame oil","note":"Add to taste if no seasoning packet"},{"name":"Cilantro","unit":"leaves"}]'::jsonb, '["Pour water into the rice cooker, set it to simmer or cook mode for 35 minutes. At this point, when you open the lid, the water should be boiling.","Carefully place the frozen wontons into the water, being careful not to burn yourself.","Before adding to the rice cooker, you can briefly rinse them with water.","If the wontons come with a seasoning packet, add it to the water at this point.","Close the lid, set to the same simmer or cook mode for 20 minutes.","Ladle all the wontons into a bowl, along with enough water to cover them.","If you didn''t add the seasoning packet earlier, now you can add salt, chicken bouillon, white pepper, and sesame oil to taste.","You can also garnish with 5–8 cilantro leaves (only for those who are not sensitive to the taste of cilantro)."]'::jsonb, '["Semi-prepared","Home-style","Light","Noodle dish","Boiled","Beginner-friendly"]'::jsonb),
  ('howtocook:soup/勾芡香菇汤/勾芡香菇汤', 'en', 'Thickened Mushroom Soup', 'Soups', 'Thickened mushroom soup is rich in flavor, smooth and pleasant, a quick home-style soup. Mushrooms are rich in amino acids and polysaccharides, which help boost immunity. The process requires some basic heat control and thickening skills, but is still beginner-friendly. From prep to finish, it takes about 25 minutes.', '[{"name":"Fresh mushrooms","unit":"piece"},{"name":"Scallion","unit":"stalk"},{"name":"Cooking oil","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Chicken bouillon","unit":"g"},{"name":"Cornstarch","unit":"g"},{"name":"Boiling water","unit":"ml"}]'::jsonb, '["Slice the mushrooms (each slice 0.5-1 cm thick; thicker slices have more chew), place in a large bowl, add 2g salt, and soak for 15 minutes.","Put cornstarch in a small bowl, add 50ml water, stir until dissolved and no lumps (i.e., cornstarch slurry).","Discard the salted water from the bowl, and squeeze out excess moisture from the mushrooms (to facilitate frying) [Optional].","Heat oil over low heat until small bubbles appear (about 30s on low, depending on your stove), add mushrooms, fry each side for 10s [Optional].","Add 300ml boiling water, increase to medium heat, and cook for another 3-5 minutes.","Pour in the cornstarch slurry, stir the soup briefly, then add 3g salt and 3g chicken bouillon, and finally sprinkle with chopped green onions before serving."]'::jsonb, '["Soup","Savory","Light","Quick","Home-style","Thickened"]'::jsonb),
  ('howtocook:soup/奶油蘑菇汤', 'en', 'Creamy Mushroom Soup', 'Soups', 'This is a classic French creamy soup with a silky smooth texture, blending the flavors of mushrooms and milk. Mushrooms are rich in dietary fiber and trace elements, while milk provides high-quality protein and calcium. The recipe is very simple, perfect for beginners, and takes about 30 minutes from prep to finish.', '[{"name":"White mushrooms","unit":"g"},{"name":"Onion","unit":"g"},{"name":"Butter","unit":"g"},{"name":"Flour","unit":"g"},{"name":"Milk","unit":"ml"},{"name":"Heavy cream","unit":"ml"},{"name":"Water","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Black pepper","unit":"g"}]'::jsonb, '["Slice the white mushrooms and set aside. Mince the onion and set aside.","Place butter in a frying pan, melt over low heat, then add the onion and cook until translucent.","Add the white mushrooms and stir-fry until they release water and soften. Sprinkle in the flour and stir well.","Add the milk and water, stir well, then bring to a boil over low heat, stirring constantly to prevent sticking.","Reduce to low heat and cook for about 10 minutes until the soup thickens.","Pour in the heavy cream and heat for another minute. Season with salt and black pepper.","Turn off the heat. Optionally, use a blender to puree into a smooth soup."]'::jsonb, '["Soup","French","Creamy","Simmering","Quick","Home-style","Savory"]'::jsonb),
  ('howtocook:soup/小米粥', 'en', 'Millet Congee', 'Soups', 'Millet congee is a common home-style porridge in northern China. It has a smooth texture and rich grain aroma, and the millet oil that forms on top is especially nourishing for the stomach. It is rich in protein, fat, carbohydrates, and carotene, with vitamin B1 content among the highest in grains. It is easy to digest and absorb. The method is very simple, even beginners can easily master it. From boiling water to serving, it takes about 30-35 minutes.', '[{"name":"Millet","unit":"grams"},{"name":"Water (spring water is best)","unit":"grams"}]'::jsonb, '["100 grams of millet, put in a bowl, gently rinse once with water (stir with your hand, pour off the water, just to remove surface dust, do not rub!!!)","Boil the water, make sure it''s boiling!!!","When the water is boiling vigorously, pour the millet into the pot. (A very important step that is easily overlooked.)","Stir so the millet doesn''t stick to the bottom, continue boiling over high heat for 6-10 minutes, stirring occasionally in between.","Reduce to medium-low heat and simmer for 15-20 minutes. Leave the lid slightly ajar to prevent the millet oil from escaping. Stir a few more times to prevent sticking to the bottom."]'::jsonb, '["Soup","Light","Savory","Simmering","Northern","Breakfast","Home-style"]'::jsonb),
  ('howtocook:soup/排骨山药玉米汤/排骨山药玉米汤', 'en', 'Spare Ribs, Chinese Yam and Corn Soup', 'Soups', 'This spare ribs, yam, and corn soup is sweet and rich, with soft yam and sweet corn infused with the savory flavor of ribs. It''s a family-friendly soup for all ages, rich in protein, dietary fiber, and vitamins, beneficial for the spleen and stomach, and boosts immunity. The method is simple, with clear prep and simmering steps, easy for beginners. It takes about 1 hour.', '[{"name":"Spare ribs","unit":"g"},{"name":"Chinese yam","unit":"piece"},{"name":"Carrot","unit":"piece"},{"name":"Corn","unit":"ear"},{"name":"Ginger","unit":"g"},{"name":"Scallions","unit":"g"},{"name":"Cooking wine","unit":"ml"},{"name":"Cooking oil","unit":"ml"},{"name":"Drinking water","unit":"ml"},{"name":"Salt","unit":"g"}]'::jsonb, '["Ingredient prep:","Wash and peel the carrot, then cut into rolling cuts about 3 cm.","Wash the corn, chop into small cylindrical pieces about 4 cm.","Peel the Chinese yam (wear gloves to avoid skin irritation from the mucilage), cut into long sections about 4 cm, and set aside.","Blanch the spareribs:","Add enough cold water to a pot, then add the rinsed spareribs.","Add about 10g ginger slices, a scallion knot, and 15ml cooking wine.","Bring to a boil over high heat. Once boiling, wait for 3 minutes, skimming off any foam with a spoon.","Remove the spareribs, rinse with warm water (about 40°C) to remove impurities, drain, and set aside.","Stir-fry the spareribs:","Heat a wok, pour in 10ml cooking oil, wait 10 seconds for the oil to heat up.","Add the remaining ginger slices (about 10g) and stir-fry until fragrant.","Add all the prepared spareribs, stir-fry over medium heat for about 1 minute until the surface is lightly browned.","Simmering process:","Add 1500ml to 2000ml of drinking water all at once.","Add all the prepared carrot, corn, and Chinese yam.","Bring to a boil over high heat, then reduce to low heat, cover, and simmer for 40 minutes.","Seasoning and serving:","Add 6g to 8g salt, stir well with a spoon.","Keep on low heat and simmer for another 2 minutes to let the salt infuse.","Turn off the heat, sprinkle with chopped scallions to taste, and serve."]'::jsonb, '["Soup","Light","Simmered","Home-style","Nourishing"]'::jsonb),
  ('howtocook:soup/排骨苦瓜汤/排骨苦瓜汤', 'en', 'Pork Rib and Bitter Melon Soup', 'Soups', 'Pork rib and bitter melon soup is a clear, savory, and slightly sweet Cantonese home-style soup. The ribs are tender, and the bitter melon clears heat and cuts grease. Rich in protein and vitamins, the dried shrimp also add calcium. The process requires blanching to remove odor and carefully removing the bitter melon pith, which can be challenging for beginners, but an electric pressure cooker simplifies it greatly. Traditional simmering takes 2 to 4 hours, so plan ahead 4 hours; with a pressure cooker, it takes about 1 hour.', '[{"name":"Pork ribs","unit":"g"},{"name":"Bitter melon","unit":"g"},{"name":"Dried shrimp","unit":"g"},{"name":"Ginger","unit":"g"}]'::jsonb, '["Wash the ribs, cut into small pieces about 4cm ±2cm by 3±2cm (if you don''t have a cleaver, ask the butcher).","In a wok, add 700ml cold water and the ribs, heat to boiling, then turn off heat and drain the ribs.","Cut the bitter melon in half lengthwise, thoroughly remove the seeds and white pith, then slice into 0.5±0.3 cm strips, and wash.","In a soup pot, add 1100ml water and the ribs, bring to a boil over high heat.","Once boiling, add the bitter melon and dried shrimp, reduce to low heat, and simmer for 120–240 minutes (after 120 minutes, you can test a piece of meat; if it separates easily from the bone, it''s done).","When done, add salt and white pepper. Recommended amount: 0.3 to 0.6g salt and 0.1 to 0.5g white pepper per 250ml of soup.","Pour 1000ml water, ribs, dried shrimp, and bitter melon into the pressure cooker.","Select the soup function and cook (usually pressure cook for 45 minutes).","When done, season with salt and pepper as with the stovetop method."]'::jsonb, '["Soup","Cantonese","Home-style","Savory","Cooling","Stewed soup","Calcium-rich"]'::jsonb),
  ('howtocook:soup/昂刺鱼豆腐汤/昂刺鱼豆腐汤', 'en', 'Yellow Catfish and Tofu Soup', 'Soups', 'Yellow catfish and tofu soup is a tender, milky and flavorful home-style soup. The fish has few bones and tender meat, the tofu is smooth, with a slight warmth from pepper, suitable for all ages. The fish is rich in high-quality protein, and paired with tofu it provides calcium, making it nutritious and easy to absorb. The cooking process is not complicated; just pay attention to removing the fishy smell and prevent sticking when frying. Beginners can handle it. Estimated cooking time: about 40 minutes.', '[{"name":"Yellow catfish or sand goby","unit":"piece"},{"name":"Tofu","unit":"g"},{"name":"Scallion","unit":"stalk"},{"name":"Ginger","unit":"piece"},{"name":"Cooking oil","unit":"ml"},{"name":"Cooking wine","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Pepper","unit":"g"},{"name":"Boiling water","unit":"L"}]'::jsonb, '["After cleaning the fish, (especially the blood inside the belly; if not cleaned, it will have a fishy smell), place in a large bowl, add cooking wine, 10g ginger slices, and 5g salt. Marinate for 15 minutes.","Cut the tofu into pieces, soak in cold water for 5 minutes, then drain and set aside.","Before frying the fish, rub the pan with ginger slices to prevent sticking. Pour in oil (15ml per piece of fish), heat until hot, then add the fish and fry for 2-3 minutes, shaking the pan occasionally to prevent sticking, and flip once.","After all the fish is fried, pour in boiling water, 5ml cooking wine, and ginger slices. Switch from low to high heat, cover the pot, and boil on high heat for 10 minutes (add enough water as some will evaporate).","Once the soup turns white, add the prepared tofu, reduce to medium heat and cook for another 5 minutes. Add 10g salt and 3g pepper to season. Finally, sprinkle with chopped green onions and serve."]'::jsonb, '["Soup","Savory","Stew","Home-style","Calcium-rich","Warming"]'::jsonb),
  ('howtocook:soup/朱雀汤/朱雀汤', 'en', 'Zhuque Soup', 'Soups', 'Zhuque Soup is a quick home-cook soup from eastern Henan, with a smooth and sweet taste and the rich aroma of sesame oil. Eggs provide high-quality protein. It''s very simple to make—just boil water and pour it over the eggs—and can be ready in under ten minutes. It also helps clear heat and reduce internal heat.', '[{"name":"Eggs","unit":"pieces"},{"name":"Sesame oil","unit":"ml"},{"name":"Sugar","unit":"grams"},{"name":"Water","unit":"ml"}]'::jsonb, '["Beat the eggs in a bowl, then add sesame oil.","Bring water to a boil, then quickly pour it into the bowl with the eggs while it''s still boiling.","Add sugar."]'::jsonb, '["Soup","Eastern Henan","Quick","Sweet","Home-cook"]'::jsonb),
  ('howtocook:soup/玉米排骨汤/玉米排骨汤', 'en', 'Corn and Pork Rib Soup', 'Soups', 'Corn and pork rib soup is a delicious and sweet home-style soup. The ribs are tender, and the corn and carrots bring natural sweetness. It is rich in protein, vitamins, and dietary fiber, with balanced nutrition. Simple to make, beginner-friendly. Just blanch and sauté the ribs, then simmer for about an hour. From prep to finish, it takes about an hour and a half.', '[{"name":"Pork ribs","unit":"g"},{"name":"Corn","unit":"ear"},{"name":"Carrot","unit":"piece"},{"name":"Scallion","unit":"stalk"},{"name":"Spring onion","unit":"stalk"},{"name":"Ginger","note":"to taste"},{"name":"Cooking oil","unit":"ml"},{"name":"Vinegar","unit":"ml"},{"name":"Cooking wine","unit":"ml"},{"name":"Black pepper","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Boiling water","unit":"ml"}]'::jsonb, '["Cut the scallions into 3-4 cm sections, and pound them with the flat side of the knife.","Chop the corn into small pieces.","Cut the carrot into rolling-cut chunks.","Peel the ginger and cut into large slices.","Chop the fresh ribs into small pieces.","Put the ribs in a pot with cold water, add scallions, ginger, and cooking wine to blanch. Bring to a boil over high heat, skim off the foam, then remove the ribs and drain.","Heat the pan with cold oil, add the sliced ginger and ribs, and stir-fry. When the ribs are slightly golden, add vinegar (to help tenderize the meat) and stir-fry for another minute.","Pour in boiling water all at once (enough for the whole process, do not add more later). Bring to a boil over high heat.","First add the corn and black pepper, cover and simmer over low heat for 20 minutes. Then add the carrots, cover and continue simmering over low heat for 40 minutes.","Seasoning is simple: three minutes before serving, add nothing but salt. Finally, sprinkle with a handful of chopped scallions."]'::jsonb, '["Soup","Savory","Stewed Soup","Home-style","Balanced Nutrition"]'::jsonb),
  ('howtocook:soup/生汆丸子汤', 'en', 'Fresh Poached Meatball Soup', 'Soups', 'Fresh Poached Meatball Soup has a tender and springy texture, making it a home-style soup with authentic flavor. Pork provides high-quality protein, and with ingredients like wood ear mushrooms and daylily buds, it is nutritionally balanced. The process requires hand-chopping the meat and mastering the heat for shaping the meatballs, which is somewhat challenging and more suitable for cooks with some experience. It takes about 1 hour from preparation to serving.', '[{"name":"pork front leg","note":"to taste"},{"name":"salt","note":"to taste"},{"name":"pepper","note":"to taste"},{"name":"scallion-ginger-Sichuan peppercorn water","note":"to taste"},{"name":"egg white","unit":"piece"},{"name":"potato starch","unit":"g"},{"name":"cooked soybean oil","note":"to taste"},{"name":"wood ear mushroom","note":"to taste"},{"name":"daylily bud","note":"to taste"},{"name":"scallion","note":"to taste"},{"name":"vermicelli","note":"to taste"},{"name":"chicken bouillon powder","note":"to taste"},{"name":"sesame oil","unit":"drop"},{"name":"cilantro","unit":"piece"}]'::jsonb, '["Cut the meat, separating fat and lean in a 3:7 ratio.","Chop with the knife, pound with the back of the knife to break and loosen the meat fibers.","Chop and pound until minced. For best flavor, chop by hand; machine-ground meat is too sticky.","Per 500g meat, 6g salt, 1g pepper.","Mix well with your hands.","Add the scallion-ginger-Sichuan peppercorn water in batches, stirring and kneading to let the meat absorb the water. Per 500g minced meat, 80g of the water.","Add egg whites and continue stirring in one direction.","Add 40g potato starch and mix well.","Add cooked soybean oil to maintain a tender and springy texture.","Bring water to a boil in a pot, then reduce to low heat, keeping it at a gentle simmer.","Using your hand, squeeze out meatballs.","Once they all float, cook on low heat for 1 minute.","Place vermicelli at the bottom of the bowl.","Add wood ear mushrooms, daylily buds, and chopped scallions. Season with salt, pepper, and chicken bouillon powder.","Pour the soup and meatballs into the bowl.","Drizzle 3-5 drops of sesame oil.","Add a small cilantro sprig."]'::jsonb, '["Soup","Savory","Light","Poached","Home-style","Balanced Nutrition"]'::jsonb),
  ('howtocook:soup/番茄牛肉蛋花汤', 'en', 'Tomato Beef Egg Drop Soup', 'Soups', 'Tomato Beef Egg Drop Soup is a sweet and sour appetizing home-style soup with a tender and smooth texture. Beef is rich in high-quality protein and iron, tomatoes provide lycopene and vitamin C, and eggs supplement lecithin. The method is simple, even beginners can master it easily, and it can be served in about half an hour.', '[{"name":"beef","unit":"grams"},{"name":"tomato","unit":"whole"},{"name":"egg","unit":"whole"},{"name":"scallion","note":"to taste"},{"name":"ginger","note":"to taste"},{"name":"garlic","note":"to taste"},{"name":"salt","unit":"grams"},{"name":"pepper","unit":"grams"}]'::jsonb, '["Slice the beef thinly","Cut the tomatoes into small pieces","Chop the scallion into small pieces","Slice the ginger","Mince the garlic","Place the beef in a bowl","Add salt and pepper, marinate for 15-20 minutes","Bring water to a boil","Add ginger slices and beef slices, cook until beef changes color","Add tomato pieces, cook until tomatoes soften","Beat the eggs, slowly pour into the pot, stir with chopsticks to form egg flowers","Add salt and pepper to taste","Finally add scallion pieces, then serve"]'::jsonb, '["Soup","Sweet and Sour","Savory","Boil","Home-style","Quick"]'::jsonb),
  ('howtocook:soup/皮蛋瘦肉粥', 'en', 'Century Egg and Lean Pork Congee', 'Soups', 'Century egg and lean pork congee is a classic Cantonese home-style porridge. The base is smooth and silky, with the rich flavor of century egg blending with the tenderness of lean pork, creating a warm and delicious taste. It is rich in carbohydrates and high-quality protein, and when paired with vegetables, it offers balanced nutrition and is easy to digest. Although there are many steps, the process is straightforward, and even beginners can follow along. The estimated cooking time is about 1.5 hours. Using the rice cooker''s timer or keep-warm function makes it especially convenient as a breakfast option.', '[{"name":"Drinking water","unit":"liter"},{"name":"Century egg (preserved egg)","unit":"piece"},{"name":"Lean pork","unit":"gram"},{"name":"Rice","unit":"ml"},{"name":"Scallion","unit":"stalk"},{"name":"Cilantro","unit":"stalk"},{"name":"Lettuce","unit":"leaf"},{"name":"Ginger","unit":"thumb-sized piece"},{"name":"Soy sauce","unit":"ml"},{"name":"Oyster sauce","unit":"ml"},{"name":"Salt","unit":"gram"},{"name":"White pepper powder","unit":"gram"},{"name":"Cooking oil","unit":"ml"}]'::jsonb, '["Rice - wash - place into rice cooker inner pot - add 1 liter drinking water","Lean pork - wash - lightly pat dry - add 10 ml cooking oil - rub evenly - place into rice cooker inner pot","Century egg - remove shell - wash - cut in half - separate egg white and yolk - roughly chop egg white - crumble egg yolk - place into rice cooker inner pot","Ginger - wash - peel - remove any yellow or black inedible parts - julienne - place into rice cooker inner pot","Scallion - wash - remove root - remove any yellow or black inedible parts - chop finely - place into small bowl and set aside","Cilantro - wash - remove root - remove any yellow or black inedible parts - chop finely - place into small bowl and set aside","Lettuce - wash - remove root - remove any yellow or black inedible parts - chop finely - place into small bowl and set aside","Soy sauce + oyster sauce + salt + white pepper powder - mix well - place into small bowl and set aside","Main ingredients - cook using rice cooker''s porridge mode until done","Toppings - after main ingredients are cooked, blanch the lettuce in hot water separately, then open the lid and add together with the remaining toppings (scallion, cilantro) to the main ingredients, stirring well","Sauce - after main ingredients are cooked, open the lid and add the sauce together with the other toppings, stirring well"]'::jsonb, '["Soup","Cantonese","Home-style","Breakfast","Savory"]'::jsonb),
  ('howtocook:soup/米粥', 'en', 'Rice Porridge', 'Soups', 'Plain porridge is light and soft, a warm stomach-soothing staple for home cooking. The pure rice aroma is suitable for all ages. Rich in carbohydrates and a small amount of protein, it is easy to digest and absorb, with health benefits for the spleen, stomach, and lungs. Simple to make, just control the heat and water amount; even beginners can do it easily. Total time about 25 minutes.', '[{"name":"Rice","unit":"ml"},{"name":"Water","note":"as needed"},{"name":"Vegetable oil","note":"optional, as needed"}]'::jsonb, '["(Optional) Mix Mo ml of oil with the washed rice, ensuring each grain is lightly coated.","(Optional) Refrigerate the rice-oil mixture for Tc.","Add rice and water to the pot.","Turn heat to high and heat to T1.","Before T1, reduce the heat. If you forget, water may overflow and extinguish the flame. Very dangerous!","Heat to Tr. Turn off the heat at Tr."]'::jsonb, '["Soup","Light","Stomach-warming","Breakfast","Home-style","Quick","Rice aroma"]'::jsonb),
  ('howtocook:soup/紫菜蛋花汤', 'en', 'Seaweed Egg Drop Soup', 'Soups', 'Seaweed egg drop soup is a light and delicious home-style soup, a simple Chinese soup dish. Seaweed is rich in iodine, calcium, and dietary fiber, while eggs provide high-quality protein, making a balanced combination. The method is very simple and beginner-friendly, taking only about 20 minutes from prep to serving.', '[{"name":"dried seaweed","unit":"g"},{"name":"egg","unit":""},{"name":"water","unit":"L"},{"name":"salt","unit":"g"},{"name":"oil","unit":"ml"},{"name":"sesame oil","note":"a few drops"},{"name":"scallions","note":"to taste"},{"name":"shrimp","note":"to taste"}]'::jsonb, '["Soak dried seaweed in water for 15 minutes, then drain and set aside.","Heat the pot, add 1.5 L water, 5 ml oil, and 2 g salt. Bring to a boil, then add the seaweed.","After the seaweed boils for 3 minutes, slowly pour in the beaten eggs and cook for 30 seconds before removing from heat.","Sprinkle with scallions and turn to low heat for 20 seconds.","Turn off the heat, add a few drops of sesame oil before serving. Some also add a bit of dried shrimp for extra flavor."]'::jsonb, '["Soup","Light","Savory","Quick","Home-style","Boiled"]'::jsonb),
  ('howtocook:soup/罗宋汤', 'en', 'Borscht', 'Soups', 'A home-style soup that originated from Russian beet soup, adapted in Shanghai. It features tomato and beef as main flavors, with a sweet and sour, rich, and savory taste. Rich in high-quality protein, lycopene, and various vitamins, nutritionally balanced. Simple to make, beginner-friendly, takes about 2-3 hours total.', '[{"name":"beef","unit":"g"},{"name":"beef broth","unit":"mL"},{"name":"canned tomatoes","unit":"can"},{"name":"tomato paste","unit":"g"},{"name":"potato","unit":"g"},{"name":"onion","unit":"g"},{"name":"carrot","unit":"g"},{"name":"parsley","unit":"g"},{"name":"cabbage","unit":"g"},{"name":"red sausage","unit":"g"},{"name":"olive oil","unit":"mL"},{"name":"vegetable oil","unit":"mL"},{"name":"salt","unit":"g"},{"name":"black pepper","unit":"g"},{"name":"vegetable stock (parsley, carrot, onion trio)","note":"to taste"}]'::jsonb, '["Dice onion, carrot, and parsley into 1cm cubes.","Cut red sausage and potato into 2cm chunks.","Remove the core from cabbage, then tear into 2cm pieces.","Season beef with 3g salt and 3g black pepper, marinate for 5 minutes.","Heat a frying pan and add vegetable oil.","Sear beef until browned on all sides (can be rare inside, be careful not to burn), then set aside.","Heat a soup pot, add olive oil, diced onion, carrot, and parsley.","Cook until onion is translucent, then add tomato paste and canned tomatoes.","Add beef and potato chunks, stir to combine.","Add water to cover ingredients, cook over medium heat for 1 hour.","Uncover, add cabbage and red sausage, stir well.","Cook uncovered over medium heat for 30 minutes.","Remove from heat, add remaining 15g salt, mix well, and serve."]'::jsonb, '["Soup","Sweet and Sour","Stew","Shanghai-style","Home-style","Beef","Appetizing"]'::jsonb),
  ('howtocook:soup/羊肉汤/羊肉汤', 'en', 'Lamb Soup', 'Soups', 'Lamb soup is a home-style warming soup, with milky white broth, tender meat, and the fresh aroma and slight spiciness of scallions and white pepper. Rich in protein, calcium, iron and other nutrients, it warms the spleen and stomach and helps ward off cold. The steps are simple, even beginners can master it easily, and the whole cooking process takes about 30 minutes.', '[{"name":"Lamb (or lamb offal)","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Cooking wine","unit":"ml"},{"name":"Scallion","unit":"g"},{"name":"Room temperature water","unit":"ml"},{"name":"Boiling water","unit":"ml"},{"name":"White pepper powder","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Cumin powder (optional)","unit":"g"},{"name":"Cilantro (optional)","unit":"g"}]'::jsonb, '["Cut lamb into pieces 5cm long and 0.5cm wide","Cut scallions into small sections","Put lamb in pot, add 1000ml room temperature water, add cooking wine and scallions","After boiling for 2 minutes, remove lamb, rinse with room temperature water, and drain","Heat oil in pot, add lamb, stir-fry for 2 minutes until lamb surface turns slightly yellow","Add boiling water, turn to high heat","After 5 minutes, add white pepper powder and salt, continue boiling for 5 minutes","After removing from heat, add cilantro and cumin powder, stir well"]'::jsonb, '["Soup","Savory","Slightly Spicy","Stewed Soup","Home-style","Warming"]'::jsonb),
  ('howtocook:soup/腊八粥', 'en', 'Laba Porridge', 'Soups', 'Laba porridge is a traditional festive sweet porridge with a thick and sticky texture, blending the complex aromas of various grains, beans, and dried fruits. Rich in carbohydrates, minerals, and vitamins, lotus seeds also help calm the mind and promote sleep, making it suitable for those under work stress. Although it contains many ingredients, the steps are simple—just slow simmer patiently, beginner-friendly. Excluding soaking prep time, cooking takes about 3 hours.', '[{"name":"Drinking water","unit":"L"},{"name":"Rice","unit":"g"},{"name":"Glutinous rice","unit":"g"},{"name":"Peanuts","unit":"g"},{"name":"Red beans","unit":"g"},{"name":"Red dates","unit":"g"},{"name":"Coix seeds","unit":"g"},{"name":"Black rice","unit":"g"},{"name":"Millet","unit":"g"},{"name":"Lotus seeds","unit":"g"},{"name":"Mung beans","unit":"g"},{"name":"Soybeans","unit":"g"},{"name":"Peas","unit":"g"},{"name":"Kidney beans","unit":"g"},{"name":"Longan (dried, pitted)","unit":"g"},{"name":"Chestnuts","unit":"g"},{"name":"Shelled walnuts","unit":"g"},{"name":"Raisins","unit":"g"},{"name":"Rock sugar (or white sugar, for seasoning)","unit":"g"}]'::jsonb, '["Wash the mung beans, red beans, peanuts, soybeans, peas, and kidney beans. Place them in a clean glass bowl and add enough drinking water to fill 3/4 of the bowl. Soak overnight (or at least 8 hours).","Wash the rice, glutinous rice, coix seeds, black rice, millet, and lotus seeds. Place them in a clean glass bowl and add enough drinking water to fill 3/4 of the bowl. Soak for 3 hours.","Drain the soaking water from the bowl in step 1 (with mung beans, red beans, peanuts, soybeans, peas, kidney beans). Transfer the drained ingredients to a porridge pot. Add 1 liter of drinking water (or enough to submerge the ingredients by one thumb''s width). Bring to a boil over high heat, then cover and simmer over low heat for 30 minutes.","Drain the soaking water from the bowl in step 2 (with rice, glutinous rice, coix seeds, black rice, millet, lotus seeds). Add the drained ingredients to the pot. Cover and simmer over low heat for 60 minutes.","Wash the red dates, longan, chestnuts, walnuts, and raisins (cut the red dates into small pieces). Add them along with rock sugar to the pot. Cover and simmer over low heat for 60 minutes.","Once the porridge becomes thick and sticky, turn off the heat. Serve in bowls and enjoy."]'::jsonb, '["Porridge","Sweet","Simmered","Traditional","Breakfast","Home-style"]'::jsonb),
  ('howtocook:soup/菌菇炖乳鸽/菌菇炖乳鸽', 'en', 'Mushroom and Squab Stew', 'Soups', 'Mushroom and squab stew has a clear broth, tender meat, and a harmonious blend of mushroom aroma and squab freshness. It is a home-style Cantonese stew. Squab is rich in high-quality protein and various amino acids, while mushrooms provide polysaccharides and dietary fiber, making it gently nourishing. The dish requires blanching the squab to remove gaminess, then simmering with corn and mushrooms. It demands some attention to heat and timing, but beginners can manage with care. From preparation to serving, it takes about 45 minutes using a pressure cooker or just over 1 hour with a clay pot.', '[{"name":"Squab","unit":"g"},{"name":"Mushrooms","unit":"g"},{"name":"Corn","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Cooking wine","unit":"ml"},{"name":"Salt","unit":"g"}]'::jsonb, '["Rinse the squab that the helpful stallholder has prepared under cold water.","Place the cleaned squab in a pot of cold water, add 15ml cooking wine and ginger. Bring to a boil, then remove the squab immediately to avoid nutrient loss.","Put the squab into a pressure cooker or clay pot. Add enough water to cover the squab. Add 20g ginger, 200g corn, and 100g mushrooms.","When done, ladle into a bowl and add 3-5g salt."]'::jsonb, '["Soup","Savory","Light","Stew","Cantonese-style","Home-style","Nourishing"]'::jsonb),
  ('howtocook:soup/西红柿鸡蛋汤', 'en', 'Tomato Egg Drop Soup', 'Soups', 'Tomato Egg Drop Soup is a sweet and sour, appetizing, and smooth home-style soup. It is extremely simple to make and suitable for all ages. Rich in lycopene, vitamin C, and high-quality protein, it is nutritious and easy to absorb. Very beginner-friendly, quick and time-saving, estimated cooking time about 15 minutes.', '[{"name":"Tomato","unit":"pieces"},{"name":"Egg","unit":"pieces"},{"name":"Sesame oil","unit":"drops"},{"name":"MSG","unit":"grams"},{"name":"Salt","unit":"grams"},{"name":"Green onion, ginger, garlic","unit":"grams"}]'::jsonb, '["Wash the tomatoes and cut into pieces.","Chop the green onion, ginger, and garlic.","Crack the eggs into a bowl and beat well with chopsticks (or a whisk).","Heat the pan and add 15 ml of oil. When a wisp of smoke rises from the oil, add the green onion, ginger, and garlic, and stir-fry for 30 seconds.","Add the tomatoes and stir-fry for 1 minute.","Pour in water, about 1.2 times the height of the ingredients in the pan, and add salt.","When the soup boils, pour in the beaten eggs and use chopsticks to stir the eggs into ribbons. Add MSG and sesame oil.","Wait 30 seconds, then turn off the heat and serve."]'::jsonb, '["Soup","Sweet and Sour","Quick","Home-style","Appetizing","Soup Dish"]'::jsonb),
  ('howtocook:soup/金针菇汤', 'en', 'Enoki Mushroom Soup', 'Soups', 'This is a light and refreshing home-style soup that is delicious and easy to make. Enoki mushrooms are rich in amino acids and dietary fiber, and adding eggs provides high-quality protein. The recipe is very simple, even beginners can easily handle it. It takes about 10 minutes from prep to serving.', '[{"name":"Enoki mushrooms","unit":"grams"},{"name":"Egg","note":"to taste (optional)"},{"name":"Salt","unit":"grams"},{"name":"MSG","unit":"grams"}]'::jsonb, '["Tear the enoki mushrooms apart by hand, the more separated the better, otherwise they can hide in the teeth. Rinse and set aside.","Using a kitchen knife or fruit knife, cut the enoki mushrooms into sections. Adjust to personal preference, but the length should not exceed 5 cm.","Put the enoki mushrooms into a pot, add water until it is about 1.1 times the total height of the ingredients. After boiling, wait for 3 minutes.","Add MSG and salt, then stir.","Continue heating for about 30 seconds, then turn off the heat and serve."]'::jsonb, '["Soup","Light","Quick","Home-style","Savory"]'::jsonb),
  ('howtocook:soup/银耳莲子粥/银耳莲子粥', 'en', 'Tremella and Lotus Seed Porridge', 'Soups', 'Tremella and lotus seed porridge is sweet, smooth, with soft and sticky tremella and dense lotus seeds. It is a common nourishing congee. Rich in natural colloid, dietary fiber, and various trace elements, it helps to calm the mind and nourish the heart. The preparation requires soaking and slow simmering, testing a beginner''s patience, and takes about 3.5 hours in total.', '[{"name":"Tremella","unit":"g"},{"name":"Lotus Seeds (hearts removed)","unit":"g"},{"name":"Red Dates","unit":"g"},{"name":"Goji Berries","unit":"g"},{"name":"Rock Sugar","unit":"g"}]'::jsonb, '["Soak the tremella and lotus seeds in water for 2 hours, soak the red dates for 10-20 minutes, wash the goji berries, and set aside.","Pour 600ml water into a pot, bring to a boil, then add the tremella, lotus seeds, and red dates in order.","Wait for the water to boil again, cover with lid, and switch to medium heat to continue simmering.","After simmering for about 1 hour, add 5g-10g rock sugar and 5g-6g goji berries, then switch to low heat.","Continue simmering on low heat for 30 minutes; the tremella will start to become sticky.","Add another 5g-10g rock sugar, stir with a spoon for 5-10 minutes.","Turn off the heat and ladle out."]'::jsonb, '["Soup","Sweet","Nourishing","Slow-cooked","Home-style","Health"]'::jsonb),
  ('howtocook:soup/陈皮排骨汤', 'en', 'Tangerine Peel Pork Rib Soup', 'Soups', 'A clear and nourishing Cantonese slow-cooked soup with a bright broth, sweet taste, and unique fragrance of tangerine peel. Pork ribs provide quality protein, combined with American ginseng, dendrobium, and other ingredients to moisten the lungs, strengthen the spleen, promote fluid production, and quench thirst. Suitable for those who often stay up late. Medium difficulty; simply prepare the ingredients, place them in a stewing pot, and simmer for about two hours.', '[{"name":"pork ribs","unit":"piece"},{"name":"tangerine peel","unit":"piece"},{"name":"American ginseng","unit":"slice"},{"name":"dendrobium","unit":"piece"},{"name":"Solomon''s seal","unit":"slice"},{"name":"dwarf lilyturf","unit":"piece"},{"name":"salt","unit":"gram"}]'::jsonb, '["Blanch the pork ribs in hot water to remove blood","Rinse tangerine peel, dwarf lilyturf, Solomon''s seal, dendrobium, and American ginseng","Clean the stewing pot","Open the stewing pot, put the pork ribs at the bottom, then add tangerine peel, dwarf lilyturf, Solomon''s seal, dendrobium, and American ginseng in order","Add hot water to the stewing pot, not too full","Add water to the steaming container, then stew for 1.5 hours","Add salt, serve hot"]'::jsonb, '["Soup"]'::jsonb),
  ('howtocook:soup/陈皮排骨汤/陈皮排骨汤', 'en', 'Tangerine Peel Pork Rib Soup', 'Soups', 'This soup is a classic Cantonese slow-cooked soup. The broth is clear, sweet, and aromatic with the unique aged fragrance of tangerine peel. Pork ribs provide high-quality protein and calcium. Combined with tangerine peel, American ginseng, dendrobium, and other ingredients, it helps regulate qi, strengthen the spleen, nourish yin, and moisten the lungs. It is suitable for those who stay up late or have throat discomfort. The process is not difficult; just prepare the ingredients and control the cooking time. Even beginners can do it easily. From prep to serving, it takes about two hours.', '[{"name":"pork ribs","unit":"piece"},{"name":"tangerine peel","unit":"segment"},{"name":"American ginseng","unit":"slice"},{"name":"dendrobium","unit":"piece"},{"name":"polygonatum","unit":"slice"},{"name":"ophiopogon","unit":"piece"},{"name":"salt","unit":"g"}]'::jsonb, '["Blanch the pork ribs in hot water to remove blood.","Rinse the tangerine peel, ophiopogon, polygonatum, dendrobium, and American ginseng.","Clean the soup pot.","Open the soup pot, place the ribs at the bottom, then add the tangerine peel, ophiopogon, polygonatum, dendrobium, and American ginseng in order.","Add hot water to the soup pot, not too full.","Add water to the cooking vessel and simmer for 1.5 hours.","Add salt and serve hot."]'::jsonb, '["Soup","Cantonese","Stewed Soup","Nourishing","Sweet and Moist","Home-style"]'::jsonb),
  ('howtocook:soup/黄瓜皮蛋汤', 'en', 'Cucumber and Century Egg Soup', 'Soups', 'Cucumber and century egg soup is a quick home-style soup. It is light in flavor, with the aromatic scent of century eggs and garlic cloves stir-fried until slightly charred. It warms the heart and stomach without being greasy. Cucumber is cooling and hydrating, while century eggs provide some protein, making it low-fat and light. The method requires almost no skill, even a novice can easily make it. From prep to serving, it takes only about ten minutes.', '[{"name":"Cucumber","unit":"piece"},{"name":"Century egg","unit":"piece"},{"name":"Garlic","unit":"clove"},{"name":"Scallion","note":"to taste"},{"name":"Cooking oil (lard recommended)","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Chicken bouillon (optional)","unit":"g"},{"name":"Water","unit":"ml"}]'::jsonb, '["Wash the cucumber, slice into thin rounds about 0.5-1.2 mm thick.","Wash and mince the scallion. Smash the garlic cloves with a knife, peel, and cut in half.","Peel the century eggs, cut each into 6-8 pieces. Pour oil into the pot, add the cut century eggs and garlic.","Stir-fry over low heat until the surface of century eggs and garlic is slightly browned. Add water, turn to high heat and bring to a boil.","Add the cucumber slices. As soon as the water boils again, turn off the heat immediately. Season with salt and chicken bouillon (optional), then serve.","Pour into a bowl and sprinkle with scallions."]'::jsonb, '["Soup","Light","Savory","Quick","Home-style","Low-fat"]'::jsonb),
  ('howtocook:staple/中式馅饼/中式馅饼', 'en', 'Chinese-style Pie', 'Staples', 'This pancake has a slightly crispy exterior and a soft interior, with a savory filling. It''s a home-style flour-based dish. Rich in carbohydrates and protein, with the addition of carrot and egg for extra nutrition. Medium difficulty; beginners need to master the heat, but the steps are clear and easy to follow. It takes about 1 hour from preparation to completion.', '[{"name":"flour","unit":"grams"},{"name":"minced meat","unit":"grams"},{"name":"oil","unit":"ml"},{"name":"salt","unit":"grams"},{"name":"sugar","unit":"grams"},{"name":"cornstarch","unit":"grams"},{"name":"soy sauce","unit":"grams"},{"name":"flavor seasoning","unit":"grams"},{"name":"garlic","unit":"cloves"},{"name":"scallion","unit":"stalks"},{"name":"egg","unit":"piece"},{"name":"carrot","note":"to taste"}]'::jsonb, '["Take the minced meat (thawed), add half of all the above seasonings (oil, salt, sugar, soy sauce, flavor seasoning) and all of the cornstarch, mix well, and marinate for 30 minutes.","Add the flour to a bowl, add the egg, add the remaining half of all the above seasonings, add water equivalent to half the amount of flour (so the batter is relatively thick but still pourable), and mix well.","Mince the garlic.","Cut the scallion into sections.","Finely dice the carrot (for the filling, so it should be as fine as possible, you can use a chopping motion).","Heat the pan with cold oil, use a generous amount of oil.","When the oil is hot, add the minced garlic and stir-fry until fragrant.","Add the marinated minced meat, stir-fry until no longer pink.","Add the diced carrot to the meat and stir-fry together until the oil turns golden (this is to extract the carrot''s flavor).","Turn off the heat. Let cool for 2 minutes.","Pour the stir-fried meat into the raw batter and mix well.","Turn on the heat again, coat the bottom of a non-stick pan with oil.","Reduce to low heat, pour the batter into the pan and spread evenly. Make sure it''s not too thick. You can tilt the pan to let the batter flow across the bottom.","While the surface of the pancake is still liquid, sprinkle the scallion sections on top.","Keep on low heat until the bottom is set.","Flip the pancake and continue to cook on low heat until the other side is set.","Then, cook each side for an additional 20 seconds.","Turn off the heat and serve."]'::jsonb, '["Main Course","Savory","Pan-fried","Home-style","Flour-based","Breakfast"]'::jsonb),
  ('howtocook:staple/凉粉/凉粉', 'en', 'Liangfen (Bean Jelly)', 'Staples', 'Liangfen is a traditional snack originating from Sichuan. It has a cool, smooth texture and a sour-spicy flavor that whets the appetite, making it perfect for summer. The main ingredient is pea starch, which is rich in carbohydrates and provides a quick energy boost. The process is not complicated, but requires patience in stirring and a long time for refrigeration to set, making it moderately challenging for beginners. From cooking to completion, it takes about 3-4 hours, most of which is waiting for refrigeration; the hands-on time is only about half an hour.', '[{"name":"Pea Starch","unit":"g"},{"name":"Garlic","unit":"cloves"},{"name":"Bird''s Eye Chili","unit":"pieces"},{"name":"Chili Powder","unit":"g"},{"name":"Soy Sauce","unit":"ml"},{"name":"Vinegar","unit":"ml"},{"name":"Sugar","unit":"ml"},{"name":"Chicken Bouillon","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Crushed Peanuts","unit":"g"},{"name":"Cilantro","unit":"g"}]'::jsonb, '["Prepare the ingredients.","Mix 100g of pea starch and 100g of water together.","Pour 600g of water into a pot, bring to a boil over high heat, then reduce to low heat.","Pour in the starch water while continuously stirring until it becomes thick and evenly colored.","Find a container and brush a thin layer of cooking oil on it.","Pour the cooked starch into the container and refrigerate for 2-4 hours.","After refrigeration, remove, unmold, and cut into strips.","Mince garlic and bird''s eye chili, add 10g chili powder, 5g crushed peanuts, and stir with hot oil.","Then add 10ml soy sauce, 10ml vinegar, 5ml sugar, 3g chicken bouillon, 3g salt, and stir well.","Pour the seasoning over the liangfen, then sprinkle with cilantro and serve."]'::jsonb, '["Main Course","Sichuan Cuisine","Sour and Spicy","Cold Dish","Summer Relief","Traditional Snack"]'::jsonb),
  ('howtocook:staple/利提巧卡', 'en', 'Litti Chokha', 'Staples', 'Litti Chokha is a traditional staple from Bihar, India, consisting of golden-brown wheat balls and smoky vegetable mash. The texture is crispy outside and soft inside, with a rich aroma. The roasted chickpea flour filling is packed with plant protein and dietary fiber, paired with vegetables like eggplant, tomato, and potato, making it nutritious. The process involves kneading dough, stuffing, baking, and preparing the vegetables. It has several steps and is somewhat challenging for beginners, taking about 60 minutes in total.', '[{"name":"Whole wheat flour (Atta)","unit":"g"},{"name":"Roasted chickpea flour (Sattu, can substitute with roasted gram flour)","unit":"g"},{"name":"Eggplant","unit":"piece"},{"name":"Tomato","unit":"piece"},{"name":"Potato","unit":"piece"},{"name":"Onion","unit":"piece"},{"name":"Garlic","unit":"clove"},{"name":"Ginger","unit":"g"},{"name":"Green chili","unit":"piece"},{"name":"Green chili","unit":"piece"},{"name":"Lemon juice","unit":"ml"},{"name":"Cilantro","unit":"g"},{"name":"Cilantro","unit":"g"},{"name":"Mustard oil (can substitute with other cooking oil)","unit":"ml"},{"name":"Mustard oil (can substitute with other cooking oil)","unit":"ml"},{"name":"Cumin seeds","unit":"g"},{"name":"Black salt (Kala Namak, can substitute with regular salt)","unit":"g"},{"name":"Red chili powder","unit":"g"},{"name":"Sesame seeds","unit":"g"},{"name":"Ghee","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Salt","unit":"g"}]'::jsonb, '["In a bowl, mix 120g roasted chickpea flour, chopped onion, green chilies, and ginger.","Add 3g cumin seeds, 5g sesame seeds, 3g red chili powder, 3g black salt, and 3g salt.","Add 15ml mustard oil, 10ml lemon juice, and chopped cilantro leaves.","Mix thoroughly until the filling is loose but can be shaped into a ball; set aside.","Place 200g whole wheat flour in a large bowl.","Gradually add warm water while kneading to form a smooth, soft dough.","Let the dough rest for 15 minutes.","Divide the dough into 8 equal portions.","Press each portion into a round disc about 8cm in diameter, slightly thicker in the center.","Place about 15g of filling in the center of each disc.","Bring the edges together to enclose the filling, pinch to seal, and roll into a ball.","Preheat the oven to 200°C.","Place the littis on a baking sheet and bake for 25-30 minutes, turning once, until golden brown and cracked.","If using an open flame: place the littis directly over charcoal or a low gas flame, turning constantly, until evenly charred.","While still hot, brush each litti with ghee so it absorbs.","Roast the eggplant, tomato, and potato directly over an open flame, or in a 200°C oven for 20-25 minutes, until the skins are charred and the insides are completely soft.","Peel the roasted vegetables, then mash the eggplant, tomato, and potato separately with a fork or by hand.","Mix the mashed vegetables together.","Add chopped garlic, green chilies, 4g salt, and 15ml mustard oil.","Stir until well combined.","Garnish with cilantro leaves.","Arrange the littis on a plate with the chokha (vegetable mash) on the side.","Serve hot, breaking the litti with your hands and dipping it into the chokha."]'::jsonb, '["Main Dish","Indian Main Dish","Savory","Spicy","Baked","Stuffed","Traditional"]'::jsonb),
  ('howtocook:staple/印度烤饼', 'en', 'Indian Flatbread', 'Staples', 'This is an Indian-style fermented flatbread, slightly charred and crispy on the outside, soft and chewy inside, perfect with curries. Rich in carbs and protein, yogurt makes it easy to digest. Moderately difficult, need to watch dough consistency and heat, but can be made with a skillet. Allow 1 hour for proofing, total about 1.5 hours.', '[{"name":"All-purpose flour","unit":"g"},{"name":"Yogurt","unit":"ml"},{"name":"Dry yeast","unit":"g"},{"name":"Sugar","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Warm water","unit":"ml"},{"name":"Ghee or butter","unit":"g"},{"name":"Black sesame seeds","unit":"g"},{"name":"Cilantro leaves","unit":"g"},{"name":"Garlic","unit":"cloves"}]'::jsonb, '["Dissolve 3g dry yeast and 10g sugar in 100ml warm water (about 40°C, not too hot).","Let stand for 5 minutes until frothy on surface (yeast is activated).","In a large bowl, mix 300g all-purpose flour and 5g salt evenly.","Add the yeast water, 60ml yogurt, and 15ml cooking oil.","Knead into a smooth, soft dough (slightly softer than usual, a little sticky is normal).","Knead for 8-10 minutes.","Brush 3ml oil on dough surface to prevent drying.","Cover bowl with a damp cloth or plastic wrap.","Place in a warm spot to rise for at least 1 hour until doubled in size.","Remove dough, gently knead to release air.","Divide into 6 equal pieces (about 80g each).","Take one piece, dust hands with 3ml flour or oil.","Roll into a long oval or teardrop shape, about 4-5mm thick.","If making garlic naan: sprinkle chopped garlic and cilantro on top, gently roll to embed.","Optionally sprinkle sesame seeds on top.","Heat a skillet (cast iron best) over high heat until very hot (water droplets evaporate instantly).","Brush one side of the flatbread with a thin layer of water.","Place water-side down into the skillet.","Cook for 1-2 minutes until bottom has golden brown spots and bread starts to puff.","Flip and cook another 1-2 minutes.","If you have a gas stove: after flipping, use tongs to hold the bread directly over an open flame for a few seconds; it will puff up quickly.","Remove and immediately brush with ghee or butter.","Preheat oven to highest temperature (usually 250°C).","Place flatbread on a baking sheet.","Bake for 3-5 minutes until golden and puffed.","Remove and brush with ghee or butter.","Serve hot.","Pairs well with any Indian curry like butter chicken or red kidney bean curry."]'::jsonb, '["Staple","Indian","Flatbread","Fermented","Curry companion","Crispy","Milky"]'::jsonb),
  ('howtocook:staple/印度焖饭', 'en', 'Indian Biryani', 'Staples', 'Indian Biryani is a royal dish originating from the Mughal Empire period. The rice grains are long and slender, with rich spices; the chicken is tender, the rice is distinct, and the layers are rich. Rich in protein and various spice essences, it can stimulate appetite. The preparation steps are relatively complicated and not friendly to beginners. The whole process takes about 90 minutes (chicken needs to be marinated for 1 hour in advance).', '[{"name":"Basmati rice (long grain)","unit":"g"},{"name":"Chicken thighs (boneless, can substitute with lamb)","unit":"g"},{"name":"Yogurt","unit":"ml"},{"name":"Tomato","note":"to taste"},{"name":"Ginger (grated)","unit":"g"},{"name":"Garlic (grated)","unit":"clove"},{"name":"Green chilies (slit)","unit":"piece"},{"name":"Cilantro leaves","unit":"g"},{"name":"Mint leaves","unit":"g"},{"name":"Saffron (can substitute with yellow food coloring)","unit":"g"},{"name":"Warm milk","unit":"ml"},{"name":"Ghee","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Turmeric powder","unit":"g"},{"name":"Red chili powder","unit":"g"},{"name":"Garam masala","unit":"g"},{"name":"Salt (for marinating)","unit":"g"},{"name":"Salt (for cooking rice)","unit":"g"},{"name":"Bay leaves","unit":"piece"},{"name":"Cinnamon stick (about 5cm)","unit":"piece"},{"name":"Cardamom pods","unit":"piece"},{"name":"Cloves","unit":"piece"},{"name":"Star anise","unit":"piece"},{"name":"Lemon juice","unit":"ml"},{"name":"Onion (thinly sliced)","unit":"piece"}]'::jsonb, '["In a large bowl, mix yogurt, grated ginger and garlic, red chili powder, turmeric powder, garam masala, salt, and lemon juice","Add chicken pieces and coat evenly with the marinade","Cover with plastic wrap and refrigerate to marinate for at least 1 hour (overnight is better)","Soak 0.5g saffron in 30ml warm milk for 15 minutes; set aside","Pour 50ml cooking oil into a pot and heat over medium heat","Add onion slices and fry until deep golden brown and crispy (about 12-15 minutes, be patient)","Remove fried onions with a slotted spoon and drain on paper towels; set aside","Drain the soaked Basmati rice","Bring 2000ml water to a boil in a large pot","Add bay leaves, cardamom, cloves, cinnamon stick, star anise, and 10g salt","Add rice and cook over high heat for 5-6 minutes until about 70% done (soft outside with a firm center)","Drain immediately, discard whole spices, and set aside","Grease the bottom of a heavy-bottomed pot with 15g ghee","Layer 1: Spread the marinated chicken evenly on the bottom of the pot","Layer 2: Spread half of the parboiled rice over the chicken","Sprinkle half of the fried onions, mint leaves, cilantro leaves, and green chilies","Layer 3: Spread the remaining rice on top","Sprinkle the remaining fried onions, mint leaves, and cilantro leaves","Evenly drizzle the saffron milk over the top layer of rice","Place the remaining 15g ghee (cut into small pieces and scattered) on top","Seal the lid: Mix flour with water to form a dough strip and seal the edge of the pot (traditional method), or wrap the pot mouth with aluminum foil and then cover with the lid","First, heat over high heat for 3 minutes until steam begins to escape","Then reduce to the lowest heat and cook for 25-30 minutes","Turn off the heat and let it rest without opening the lid for another 5 minutes","Remove the lid, gently fluff the rice from the bottom with a large spoon to mix the layers evenly","Serve, accompanied by yogurt (Raita)"]'::jsonb, '["Main Course","Savory","Biryani","Indian","Rich","Entertaining"]'::jsonb),
  ('howtocook:staple/可乐炒饭', 'en', 'Cola Fried Rice', 'Staples', 'This dish uses cola as a substitute for sugar, giving it a unique caramelized and slightly sweet flavor. The rich sauce coats every grain of rice, making it a creative home-style fried rice. Eggs and ham sausage provide high-quality protein and energy, balanced with the staple rice for a filling meal. The steps are straightforward, suitable for beginners, and it can be on the table in about 20 minutes.', '[{"name":"Rice","unit":"g"},{"name":"Cola","unit":"ml"},{"name":"Eggs","unit":"whole"},{"name":"Ham sausage","unit":"g"},{"name":"Luncheon meat","note":"to taste (optional)"},{"name":"Oil","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Chili bean paste","unit":"ml"},{"name":"Oyster sauce","unit":"ml"},{"name":"Chopped green onions","unit":"g"},{"name":"White pepper","unit":"g"}]'::jsonb, '["Heat the pan, add 25 ml oil, crack two eggs, and fry until the bottom is completely set.","Flip and fry until both sides are completely set.","Turn off the heat, remove the eggs, cut into 2-5 cm² pieces, and return to the pan (or break them up directly with a spatula).","Turn the heat back on, add cola, light soy sauce, dark soy sauce, chili bean paste, and oyster sauce, stir to combine.","Heat until the liquid reduces to 1/3, then add the rice and ham sausage, stirring well.","After stirring evenly, reduce to low heat, make a well in the center of the rice, crack in one egg, cover, and steam for 2 minutes.","Uncover and stir-fry until the third egg is cooked through, sprinkle with chopped green onions and white pepper, and serve."]'::jsonb, '["Main Course","Caramelized & Sweet","Fried Rice","Quick","Creative","Home-style"]'::jsonb),
  ('howtocook:staple/咸肉菜饭', 'en', 'Salted Pork and Vegetable Rice', 'Staples', 'This is a home-style staple full of Shanghai alleyway charm. The richness of salted pork and the sweetness of greens are melted into every grain of rice with the help of lard. It offers both crispy rice crust and tender-crisp vegetable stems, with distinct layers. Greens are rich in vitamins and dietary fiber, while salted pork provides protein and energy—a balanced mix of meat and vegetables. The method is not complicated, but requires the trick of adding leaves in batches, which is a bit challenging for beginners. From prep to serving, it takes about 1 hour.', '[{"name":"Rice","unit":"g"},{"name":"Greens","unit":"g"},{"name":"Salted pork","unit":"g"},{"name":"Winter bamboo shoots","unit":"g"},{"name":"Lard","unit":"g"},{"name":"Cooking wine","unit":"ml"},{"name":"Sugar","unit":"g"},{"name":"White pepper","unit":"g"},{"name":"Water","unit":"ml"}]'::jsonb, '["If adding winter bamboo shoots, slice thinly and boil in cold water for 10 minutes to remove astringency.","Cut salted pork into 1 cm cubes.","Place salted pork and winter bamboo shoots in a cold pan with 10 g lard, cooking wine, and sugar. Stir-fry over medium-low heat until translucent and bubbling.","Chop the greens, separating stems and leaves. Cut stems into 0.5 cm square pieces, and leaves into 2-3 cm long by 1-1.5 cm wide rectangular pieces.","Stir-fry the stems until emerald green.","Rinse the rice and put it in the rice cooker, add water.","Spread the cooked pork and stems over the rice.","Start the normal cooking cycle. In the last 10 minutes, quickly open the lid and layer the leaves on top.","After cooking, let it rest for 5 minutes, then drizzle with 5 g lard and white pepper, and mix vigorously."]'::jsonb, '["Main Dish","Shanghai Style","Home-style","Savory","Braised Rice"]'::jsonb),
  ('howtocook:staple/基础牛奶面包/基础牛奶面包', 'en', 'Basic Milk Bread', 'Staples', 'This basic milk bread simplifies traditional bread-making with a pre-fermented starter. The result is rich in milk flavor and soft in texture. Rich in carbohydrates and protein, it provides energy for the body. Moderate difficulty, suitable for baking beginners, takes about 200 minutes in total.', '[{"name":"Bread flour or all-purpose flour (for starter)","unit":"cup","note":""},{"name":"Warm water (about 30°C)","unit":"cup","note":""},{"name":"Dry yeast","unit":"g","note":""},{"name":"Salt","unit":"g","note":""},{"name":"Bread flour or all-purpose flour (for dough)","unit":"cup","note":""},{"name":"Egg","unit":"piece","note":""},{"name":"Sugar or syrup","unit":"cup","note":""},{"name":"Milk, light cream, condensed milk, or milk powder","unit":"cup","note":""},{"name":"Butter or corn oil","unit":"cup","note":""},{"name":"Vital wheat gluten (optional)","unit":"cup","note":""},{"name":"Vanilla extract (optional)","unit":"g","note":""},{"name":"Cloth","unit":"","note":"as needed"}]'::jsonb, '["First, mix the yeast and warm water (30°C) evenly using a spatula or kitchen utensil, and let stand for 5 minutes. Then mix with flour and stir until well combined. The starter should be a very sticky batter at this point.","Cover the batter with a cloth and place it in a warm place to ferment for 45 to 60 minutes.","The final batter should have many bubbles on the surface and have visibly increased in volume."]'::jsonb, '["Staple","Milk flavor","Soft","Baking","Fermentation","Beginner-friendly"]'::jsonb),
  ('howtocook:staple/微波炉腊肠煲仔饭/微波炉腊肠煲仔饭', 'en', 'Microwave Sausage Claypot Rice', 'Staples', 'This is a simple and quick Cantonese-style staple. The rice absorbs the fat from the sausage, becoming rich and savory. Paired with crisp vegetables and carrots, it offers a rich texture. Rich in carbohydrates, protein, and various vitamins, it''s nutritionally balanced. Cooked in the microwave, it''s very beginner-friendly, and it''s estimated to be ready in just 15 minutes.', '[{"name":"rice","unit":"ml"},{"name":"sausage","unit":"piece"},{"name":"egg","unit":"piece"},{"name":"carrot","unit":"piece"},{"name":"salt","unit":"gram"},{"name":"oil","unit":"ml"},{"name":"light soy sauce","unit":"ml"},{"name":"green onion","unit":"stalk"},{"name":"greens","note":"to taste"},{"name":"water","unit":"ml"}]'::jsonb, '["Wash the rice and put it in a bowl. Add 400ml of water and cover with a lid.","Microwave on high for 6 minutes. While cooking, prepare the ingredients.","Slice the sausage.","Wash the greens.","Slice the carrot.","Chop the green onion.","Put the greens and carrot slices in a vegetable bowl. Add 10ml oil and 5g salt.","In a small bowl, mix 10ml light soy sauce and 5ml oil.","After 6 minutes, remove the bowl with a towel or heat-resistant gloves. The rice should be about 80% cooked.","Arrange the sliced sausage on top of the rice, then microwave on high for another 2 minutes.","Remove the sausage rice bowl. Put the vegetable bowl in the microwave and cook on high for 4-5 minutes.","Arrange the cooked vegetables on the sausage rice. Crack an egg on top. Depending on preference, microwave on high for 40-60 seconds.","Remove the sausage rice. It is basically ready.","Put the small bowl with soy sauce mixture in and microwave on high for 30 seconds.","Drizzle the heated soy sauce mixture over the rice and sprinkle with chopped green onions.","Extra vegetables can be dipped in soy sauce."]'::jsonb, '["Staple","Cantonese","Microwave","Quick","Savory","Home-style"]'::jsonb),
  ('howtocook:staple/意式肉酱面/意式肉酱面', 'en', 'Spaghetti Bolognese', 'Staples', 'Spaghetti Bolognese is a simple and quick home-style Western dish with rich sauce and chewy noodles, perfect for busy days. Minced meat and onion paired with ready-made pasta sauce provide a fast boost of protein and carbs, and the onion adds dietary fiber. The recipe is very beginner-friendly; just basic chopping and stir-frying, and once you''re used to it, you can serve it in 15 minutes—more satisfying than instant noodles.', '[{"name":"Spaghetti","unit":"g"},{"name":"Pasta sauce","unit":"g"},{"name":"Minced meat","unit":"g"},{"name":"White onion","unit":"g"},{"name":"Cooking oil","unit":"ml"}]'::jsonb, '["Add water to a pot, bring to a boil, then add the spaghetti (wait 6-12 minutes)","While the water is boiling, you can do the following steps, but keep track of the pasta cooking time","Dice the white onion","Heat oil in an empty pot, add the diced onion over medium heat","Stir constantly to prevent burning, until the onion becomes translucent","Add the minced meat, continue stirring (break it apart) until the meat turns brown","Add the pasta sauce, stir briefly","Drain the cooked spaghetti and mix it with the meat sauce (or simply pour the meat sauce over the spaghetti)"]'::jsonb, '["Staple","Quick","Home-style","Savory","Western"]'::jsonb),
  ('howtocook:staple/手工水饺', 'en', 'Handmade Dumplings', 'Staples', 'Handmade dumplings are a classic Chinese staple food, with thin wrappers and generous filling, savory and juicy. They are filling and can be seasoned according to personal taste. The pork filling provides high-quality protein and fat, and paired with chives, it also adds vitamins and dietary fiber. This dish is challenging for beginners, requiring skills in kneading dough, rolling wrappers, preparing filling, and cooking dumplings. Estimated preparation time is about 3 hours.', '[{"name":"flour","unit":"grams"},{"name":"cold water","unit":"ml"},{"name":"toasted sesame oil","unit":"ml"},{"name":"lean ground pork","unit":"grams"},{"name":"fat ground pork","unit":"grams"},{"name":"ginger","unit":"grams"},{"name":"green onion","unit":"grams"},{"name":"salt","unit":"grams"},{"name":"oyster sauce","unit":"ml"},{"name":"sesame oil","unit":"ml"},{"name":"light soy sauce","unit":"ml"},{"name":"egg","unit":"piece"},{"name":"chives","note":"to taste"}]'::jsonb, '["Add all the flour to a bowl","Add sesame oil","Make a small well in the center of the flour","Add water in 4-5 batches, stirring, until the mixture becomes crumbly and slightly dry","Stop adding water, press the dough together with your hands","Press the dough until it incorporates all the flour from the bowl; the bowl should be clean","Place the dough on the table, cover with the bowl upside down, at 25°C, let it rest for about 45 minutes","After resting, roll the dough into a log, gather it into a ball, and roll again; repeat 3 times","Roll into a log, cut into 20 equal pieces, and roll each into a ball about 3-3.5 cm in diameter","Flatten each ball, dust hands, table, rolling pin, and dough with flour to prevent sticking","Roll out each piece into a circle about 8 cm in diameter and 2 mm thick, with the center slightly thicker than the edges by about 1 mm","Remove skin from pork, keep some fat, cut into small pieces","Use a cleaver (preferably two) to chop the pork into mince, put in a bowl","Finely chop green onions and ginger, add to the bowl and mix well","Wash chives, cut into pieces shorter than 3 mm","Mix chives with the minced pork, add 2 ml each of oyster sauce, light soy sauce, and sesame oil, add the egg white from one egg, mix well with your hands","Let it sit for 30 minutes, then start wrapping dumplings","Place a wrapper on your left hand; avoid getting flour on the side where the filling goes, to prevent sealing issues","With chopsticks in your right hand, take about half the diameter of the wrapper worth of filling","Seal along the edge of the wrapper, pinch firmly; for personal consumption, no decorative pleats needed, just ensure it''s sealed","Use a pot that can hold 20 dumplings, or cook in batches","Boil water, filling the pot to about 3/4 full","Bring water to a boil over high heat, add dumplings, then reduce to medium heat","After adding dumplings and water bubbles, add 50 ml cold water along the edge (repeat this step twice)","After the third boil, add 50 ml cold water, bring to a boil again, then reduce to low heat and wait 60 seconds before removing"]'::jsonb, '["Staple","Home-style","Savory","Noodle/Pastry","Handmade","Banquet"]'::jsonb),
  ('howtocook:staple/扬州炒饭/扬州炒饭', 'en', 'Yangzhou Fried Rice', 'Staples', 'This is an upgraded fried rice with rich ingredients. The rice grains are distinct, the eggs are tender, paired with shrimp, luncheon meat, and vegetable dices, creating distinct layers of texture. It is a classic staple of Huaiyang cuisine. Rich in high-quality protein, carbohydrates, and various vitamins, it is nutritionally balanced. Although there are many steps, the operations are intuitive and friendly for beginners, requiring only patient preparation. Estimated cooking time is about 1 hour.', '[{"name":"Cold rice","unit":"g"},{"name":"Egg","unit":"piece(s)"},{"name":"Frozen peeled shrimp","unit":"pieces"},{"name":"Canned luncheon meat","unit":"g"},{"name":"Green peas","unit":"g"},{"name":"Carrot","unit":"g"},{"name":"Corn kernels","unit":"g"},{"name":"Scallion","unit":"stalk"},{"name":"Oil","unit":"ml"},{"name":"Salt","unit":"g"}]'::jsonb, '["Cut carrot into 0.2 cm cubes, set aside.","Cut luncheon meat into 0.2 cm cubes, set aside.","Separate scallion white and green parts, cut each into 0.25-0.5 cm pieces, set aside separately.","Crack eggs into a bowl, beat evenly, set aside.","Boil carrot, green peas, and corn kernels until cooked, drain and set aside (do not discard the water).","Boil shrimp until cooked, drain and set aside (water can be discarded).","Heat the wok and oil, refer to ''hot wok, cold oil'' technique from stir-frying and pan-frying.","Add 20-30 ml oil for the second pour. When the oil is hot, slowly pour in the egg (control the stream diameter from bowl to oil to about 0.5 cm). Do not stir.","Once the egg sets, immediately remove and set aside.","Add luncheon meat, green peas, carrot, corn kernels, and shrimp to the wok and stir-fry for 1-2 minutes. Transfer to a plate and set aside.","Rinse the wok with water to clean off any residues, ensuring the wok is clean (oil may remain but no impurities).","Heat the wok and add 10 ml oil. Add scallion white and sauté until fragrant.","Reduce to low heat (if oil is too hot, turn off heat for 1-2 minutes). Add rice, quickly chop and stir-fry with a spatula, ensuring each grain is coated with oil and separated.","Add the cooked egg, continue chopping to break the egg into small pieces and mix thoroughly with the rice.","Turn up to high heat, add all other reserved ingredients, and quickly stir-fry for 1-2 minutes.","Sprinkle in salt and stir-fry until evenly mixed.","Sprinkle in scallion green and stir-fry for 1 minute.","Turn off heat and plate."]'::jsonb, '["Main Dish","Savory","Fried Rice","Home-style","Huaiyang","Quick"]'::jsonb),
  ('howtocook:staple/披萨饼皮/披萨饼皮', 'en', 'Pizza Dough', 'Staples', 'Pizza dough uses low-temperature overnight fermentation, resulting in a soft yet slightly chewy crust. It''s a home-style Western pastry. Mainly provides carbohydrates and a small amount of healthy fats. The process is simple but requires patience for dough fermentation, and is beginner-friendly. From preparation to baking, including overnight refrigeration, it takes about 10-14 hours, so it''s suitable to prepare a day in advance.', '[{"name":"all-purpose flour","unit":"grams"},{"name":"warm water","unit":"grams"},{"name":"dry yeast","unit":"grams"},{"name":"salt","unit":"grams"},{"name":"olive oil","unit":"grams"},{"name":"white sugar","unit":"grams"}]'::jsonb, '["Dissolve the yeast in the prepared warm water, stir a little, and set aside.","Take the prepared flour, add salt, olive oil, and sugar in order.","Prepare to mix water and flour, add water while stirring until all water is added.","Stir until no dry flour is visible.","Put it in a container about three times the size of the dough, seal, and refrigerate at 4°C for 8-12 hours. Usually make it at night and use it the next day.","Observe that the dough has finished proofing; it should be about twice its original size.","Take the proofed dough, divide evenly into four portions, cover each with plastic wrap, and set aside.","Sprinkle a little more flour on the work surface, ready to knead.","Since the dough is quite wet, coating it with flour will make it less sticky. Don''t knead too much; just until the surface is slightly smooth.","Stretch by hand or roll out with a rolling pin; it doesn''t have to be perfectly round, just even thickness and fit in the oven.","Line with parchment paper, place the crust, add your preferred toppings, and sprinkle shredded cheese.","For fruit pizza, bake at top 180°C, bottom 220°C for 16 minutes.","For meat and vegetable pizza, bake at top 200°C, bottom 230°C for 18 minutes.","Drizzle with mayonnaise or your favorite sauce and enjoy~"]'::jsonb, '["Main Dish","Western","Baking","Overnight Fermentation","Home-style","Beginner-friendly"]'::jsonb),
  ('howtocook:staple/日式咖喱饭/日式咖喱饭', 'en', 'Japanese Curry Rice', 'Staples', 'Japanese curry rice is a rich and hearty home-style Japanese dish, seasoned with curry roux, paired with potatoes, carrots, onions, and meat, smooth and creamy, mildly spicy and sweet. It is rich in protein, carbohydrates, and various vitamins, providing ample energy. The cooking process is not too complicated, but requires control of heat and stirring skills, suitable for those with some cooking experience. From preparation to serving takes about 1 hour, and it tastes even better after refrigeration.', '[{"name":"Curry roux (recommended: House)","unit":"grams"},{"name":"Potato","unit":"pieces"},{"name":"Carrot","unit":"pieces"},{"name":"Onion","unit":"pieces"},{"name":"Meat (pork/chicken/beef optional)","unit":"pound"},{"name":"Garlic","unit":"cloves"},{"name":"Broccoli (blanched in water)","unit":"to taste"},{"name":"Bacon (ready-to-eat)","unit":"to taste"},{"name":"Fried egg / sunny-side up egg","unit":"to taste"}]'::jsonb, '["Cut off both ends of carrots, peel, and cut into rolling chunks","Peel the outer layer of onion, remove core, and cut into crescent shapes","Peel potatoes and cut into large chunks","Cut meat into chunks","Peel garlic, flatten, and mince","Chop curry roux to increase surface area for faster dissolving","Heat oil in pan, add garlic and meat, stir-fry quickly until meat surface turns white","Add carrots, stir-fry quickly until evenly heated","Add onions, stir-fry quickly until onions become translucent","Add potatoes, continue stir-frying until potatoes soften (test with chopsticks)","Add water to cover all ingredients, wait 15 minutes after boiling","Turn off heat, add curry roux and stir","Wait for curry to melt, then turn on heat again, stir slowly for 10 minutes to prevent burning","Turn off heat when the appearance becomes thick and sticky, finish","Microwave: high heat for 2-3 minutes per serving","Stovetop: add extra 50ml water, keep stirring while heating"]'::jsonb, '["Main Course","Japanese","Rich","Home-style","Rice companion","Stewing"]'::jsonb),
  ('howtocook:staple/日式肥牛丼饭/日式肥牛丼饭', 'en', 'Japanese Beef Rice Bowl', 'Staples', 'A classic Japanese home-style rice bowl, beef slices and white onion simmered in a savory-sweet sauce, tender meat, sweet onion, rich flavor. Beef provides high-quality protein and heme iron, onion is rich in dietary fiber and various antioxidants. Not complicated to make, even beginners can easily follow the steps, cooking process takes about 30 minutes.', '[{"name":"onion","unit":"piece"},{"name":"beef slices (for hot pot)","unit":"gram"},{"name":"green onion","unit":"stalk"},{"name":"white sesame seeds","unit":"gram"},{"name":"mirin","unit":"gram"},{"name":"cooking wine","unit":"gram"},{"name":"onsen tamago (soft-cooked egg)","note":"as needed"},{"name":"dashi","note":"as needed"},{"name":"rice","unit":"cup"},{"name":"soy sauce","unit":"gram"},{"name":"oyster sauce","unit":"gram"},{"name":"sugar","unit":"gram"},{"name":"dark soy sauce","unit":"gram"},{"name":"water","unit":"gram"}]'::jsonb, '["Peel the onion, remove the core, and cut into crescent-shaped slices.","Wash the green onions and cut into 0.5cm pieces.","Heat a pan and add white sesame seeds directly, shake the pan back and forth to evenly heat until lightly golden.","Blanch the beef slices in boiling water for 1 minute, then remove.","Mix 40g mirin (or 30g cooking wine), 30g soy sauce, 20g oyster sauce, 5g sugar, and 5g dark soy sauce (optional, for color) in a bowl to make the seasoning. (You can place the bowl on a kitchen scale for this step.)","Heat oil in a pan, add the onion, and stir-fry quickly until translucent.","Turn to low heat, add 250g water (or dashi), then return to high heat and wait for 3 minutes.","Add the beef and seasoning.","Continuously stir all ingredients for 10 minutes to prevent sticking.","Turn off the heat.","Serve the beef bowl over rice (make sure to drizzle some sauce over the rice).","Sprinkle with chopped green onions and white sesame seeds. Done.","Microwave: high heat for 2-3 minutes for a single serving.","Stovetop: add an extra 50ml water and stir continuously while heating."]'::jsonb, '["Main Dish","Japanese","Savory-sweet","Simmered","Goes well with rice","Home-style"]'::jsonb),
  ('howtocook:staple/汤面', 'en', 'Soup Noodles', 'Staples', 'Soup noodles are a freely customizable home-style staple. The broth is light and refreshing, the noodles are soft and smooth, and it can accommodate various meat and vegetable ingredients, with a flavor that can be savory or mild. It is rich in carbohydrates and high-quality protein, and with vegetables it adds vitamins and dietary fiber, making it nutritious and filling. The preparation is very simple, requiring no culinary skills, and even beginners can easily handle it. From preparing ingredients to serving, it usually takes about 30 minutes.', '[{"name":"Noodles","unit":"grams"},{"name":"Cold water","unit":"ml"},{"name":"Vegetables","note":"about the same volume as the noodles"},{"name":"Salt","note":"to taste"},{"name":"Pepper","note":"to taste"},{"name":"Sesame oil","note":"to taste"}]'::jsonb, '["First, cut the vegetable ingredients into pieces no larger than 4 cm on each side, to ensure even cooking.","If using raw meat, place it in cold water, cover with lid, bring to a boil. Skim off the scum that rises to the surface, then turn off the heat. Remove the partially cooked meat and set aside.","First, heat the water over high heat until boiling, then reduce to medium heat.","Add ingredients that take longer to cook (like partially cooked meat, mushrooms, etc.) into the pot first. To ensure they are cooked through, set a timer for 10 minutes after boiling resumes; add another 5 minutes for particularly large or tough pieces.","Add the noodles to the pot, stirring gently to ensure they are well submerged in the broth. Keep the liquid at a gentle boil and cook for 5 minutes. After adding noodles, white foam may appear; you can lift the lid slightly to release steam or remove the lid.","Add quick-cooking ingredients like leafy greens to the pot, stirring to submerge them. Cook for 2-5 minutes.","Turn off the heat. Add seasonings like salt, pepper, and sesame oil to taste. Stir well, then serve."]'::jsonb, '["Main Dish","Light","Home-style","Quick","Customizable","Nutritious and Balanced"]'::jsonb),
  ('howtocook:staple/河南蒸面条/河南蒸面条', 'en', 'Henan Steamed Noodles', 'Staples', 'Henan Steamed Noodles is a homestyle snack from Henan. The noodles are steamed, then stir-fried, and steamed again, resulting in a rich, flavorful, and chewy texture. Pork belly and garlic scapes provide protein and fiber, balanced with the staple. The steps are a bit many, but if followed in order, even beginners can succeed. From prep to finish takes about 40 minutes.', '[{"name":"Dried noodles (round recommended)","unit":"g","note":""},{"name":"Pork belly","unit":"g","note":""},{"name":"Garlic scapes","unit":"g","note":""},{"name":"Scallions","unit":"g","note":""},{"name":"Ginger","unit":"g","note":""},{"name":"Garlic","unit":"g","note":""},{"name":"Cooking wine","unit":"ml","note":""},{"name":"Salt","unit":"g","note":""},{"name":"Chicken bouillon","unit":"g","note":""},{"name":"Thirteen spice","unit":"g","note":""},{"name":"Light soy sauce","unit":"ml","note":""},{"name":"Dark soy sauce","unit":"ml","note":""},{"name":"Oyster sauce","unit":"ml","note":""},{"name":"Cooking oil","unit":"ml","note":""},{"name":"Sesame oil","unit":"ml","note":""},{"name":"Steamer basket","unit":"","note":"as needed"}]'::jsonb, '["Add water to a wok until 70% full, bring to a boil, and place a steamer basket on top.","Evenly spread the dried noodles in the basket, drizzle with 5ml oil and rub to coat. Steam for 15 minutes.","Remove the noodles and steamer basket, set aside, and discard the water in the wok.","Slice the pork belly into 2mm thick pieces.","Cut garlic scapes into 3cm segments.","Slice scallions into 0.2cm thin rounds.","Cut ginger into 1mm x 1mm x 3cm fine strips.","Smash garlic on a cutting board, then chop into 1mm pieces.","Heat the wok until dry, then add 3ml cooking oil.","Hold the handle and swirl the wok, coating 2/3 of the surface with oil.","Over medium heat, add the pork slices and stir-fry for 1 minute.","Add scallions, ginger, garlic, and cooking wine. Continue stir-frying for 1 minute.","Add the garlic scapes and stir-fry for 1 minute.","Season with dark soy sauce, light soy sauce, oyster sauce, salt, chicken bouillon, and thirteen spice. Stir-fry for 1 minute.","Add 500ml water, just enough to submerge the vegetables. Simmer for 1 minute.","Add the steamed noodles, stirring constantly for 3 minutes until evenly colored. Turn off the heat.","Transfer the noodle-vegetable mixture to a separate basin.","Add cold water to the wok until 70% full, place the steamer basket, and spread the mixture evenly on top.","Once the water boils, steam over high heat for 15 minutes. Remove from heat.","Drizzle with 10g sesame oil and serve."]'::jsonb, '["Main Course","Henan Flavor","Homestyle","Savory","Steamed & Stir-fried","Rice Companion"]'::jsonb),
  ('howtocook:staple/火腿饭团/火腿饭团', 'en', 'Ham Rice Balls', 'Staples', 'A simple and quick Japanese-style rice ball, savory ham paired with mayonnaise and seaweed, rich in taste and satisfying. Rich in carbohydrates, protein, and vitamins, it quickly replenishes energy. Extremely low difficulty, even beginners can easily make it. From cooking rice to finishing, it takes about 1 hour.', '[{"name":"ham","unit":"g"},{"name":"rice","unit":"g"},{"name":"water","unit":"ml"},{"name":"frozen green peas","unit":"g"},{"name":"frozen corn kernels","unit":"g"},{"name":"shredded seaweed","unit":"g"},{"name":"mayonnaise","unit":"g"},{"name":"cooking oil","unit":"ml"}]'::jsonb, '["Put the rice and water into the rice cooker, press the rice mode, and wait for it to finish.","Put frozen corn kernels and green peas into a pot, add water to cover all ingredients, bring to a boil, wait 2 minutes, then drain.","Cut the ham into 1cm cubes.","Meanwhile, add 10ml of cooking oil, stir-fry the ham until browned.","Put rice, ham, shredded seaweed, green peas, corn kernels, and mayonnaise into a bowl, mix well.","Plate (if available)."]'::jsonb, '["Main Dish","Japanese","Quick","Home-style","Savory","Rice Balls"]'::jsonb),
  ('howtocook:staple/炒凉粉/炒凉粉', 'en', 'Stir-fried Bean Jelly', 'Staples', 'Stir-fried bean jelly is a specialty snack from the Shanxi and Shaanxi regions. It is smooth and tender, savory with a slight spiciness, and carries the aroma of garlic and sauce. Bean jelly is mainly made from starch, providing rich carbohydrates for quick energy. The cooking difficulty is moderate, suitable for beginners with some basic skills. The whole process takes about 15 minutes.', '[{"name":"bean jelly","unit":"g"},{"name":"corn oil","unit":"ml"},{"name":"garlic","unit":"g"},{"name":"scallions","unit":"g"},{"name":"broad bean paste","unit":"g"},{"name":"light soy sauce","unit":"ml"},{"name":"dark soy sauce","unit":"ml"},{"name":"salt","unit":"g"},{"name":"thirteen-spice powder","unit":"g"},{"name":"medium-coarse chili flakes","unit":"g"},{"name":"mineral water","unit":"ml"}]'::jsonb, '["Cut the bean jelly into mahjong-sized cubes.","Turn the heat to low, heat oil in a wok. When the wok is slightly hot, add minced garlic and stir-fry until fragrant, then add broad bean paste and stir-fry until red oil appears.","Add the bean jelly cubes to the wok and stir-fry for 10 seconds.","Add light soy sauce for flavor and dark soy sauce for color, stir-fry evenly, then add chili flakes and continue stir-frying until well combined.","Add salt and thirteen-spice powder and stir-fry for another 10 seconds.","Add the prepared mineral water, stir-fry again for 10 seconds. When the sauce thickens, turn off the heat and transfer to a plate.","Sprinkle with chopped scallions and serve."]'::jsonb, '["Staple","Savory and slightly spicy","Stir-fried","Shanxi-Shaanxi style","Home-style snack","Quick"]'::jsonb),
  ('howtocook:staple/炒年糕', 'en', 'Stir-fried Rice Cakes', 'Staples', 'This is a staple dish in the Minnan style. The rice cakes are soft, chewy, and infused with the rich aroma of scallion oil. It''s homestyle and filling. Made from rice flour, the rice cakes provide plenty of carbohydrates, while the eggs and greens add protein and vitamins for balanced nutrition. The recipe is simple, beginner-friendly, and takes about 30 minutes from prep to plate.', '[{"name":"Rice cakes","unit":"g"},{"name":"Scallions","unit":"stalk"},{"name":"Cooking oil","unit":"ml"},{"name":"Soy sauce","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Eggs","note":"to taste"},{"name":"Greens","note":"to taste"}]'::jsonb, '["Bring water to a boil in a pot, cook the rice cakes until done. Place them in a bowl with water to prevent sticking, then drain and set aside.","Slice the scallions into pieces (separate the white parts from the green parts). Cut the greens into small sections and set aside.","(Optional) Make scrambled eggs, refer to the recipe for Tomato and Egg Stir-fry.","Heat the wok, add 30ml cooking oil.","Add the white parts of the scallions to the wok, cook until most of them turn golden brown and fragrant. Pour out the scallion oil and set aside.","Reheat the wok, add 20ml cooking oil.","Add all the side ingredients (eggs, greens, etc.) and stir-fry until well combined.","Drain the water from the rice cakes, then add them to the wok.","Add soy sauce and salt, stir-fry until evenly coated.","Turn off the heat, add the scallion oil, stir-fry to combine, and transfer to a serving plate."]'::jsonb, '["Main Course","Minnan Style","Stir-fry","Homestyle","Quick","Savory"]'::jsonb),
  ('howtocook:staple/炒意大利面/炒意大利面', 'en', 'Stir-fried Spaghetti', 'Staples', 'This stir-fried spaghetti is soft and tasty, paired with beef slices and sauce, rich in sauce aroma, a home-style staple with Western flavor. Rich in carbs and protein, quickly replenishes energy. Easy to make, even beginners can master it, takes about 30 minutes total.', '[{"name":"spaghetti","unit":"g"},{"name":"beef slices","unit":"slice"},{"name":"ketchup","unit":"g"},{"name":"black pepper sauce","note":"choose one"},{"name":"rapeseed oil","unit":"ml"},{"name":"water","unit":"g"},{"name":"salt","unit":"g"}]'::jsonb, '["Add 250g water per person","Bring water to a boil, add spaghetti, cook over medium heat for 15-20 minutes (this spaghetti is usually hard, best to taste before taking out; if the center is a bit hard, continue cooking)","Remove spaghetti, place on plate for later use","Heat oil in pan, when the oil is medium hot, add spaghetti and stir-fry for one minute (if too dry, add a little water)","Add 10g ketchup, beef slices, add 2g salt, continue stir-frying for one minute","Remove from pan"]'::jsonb, '["main dish","sauce-rich","Western-style","stir-fried","quick","home-style"]'::jsonb),
  ('howtocook:staple/炒方便面/炒方便面', 'en', 'Stir-Fried Instant Noodles', 'Staples', 'This stir-fried instant noodle dish has a chewy, springy texture and a savory flavor. It''s a quick and easy staple adapted from traditional boiled noodles. With eggs and ham sausage, it provides protein and energy. Simple to make, just rinse noodles with cold water to keep the texture. Perfect for beginners, ready in about 15 minutes.', '[{"name":"instant noodles","unit":"pack"},{"name":"egg","unit":"piece"},{"name":"ham sausage","unit":"piece"},{"name":"cooking oil","unit":"ml"},{"name":"water","unit":"ml"}]'::jsonb, '["Remove the ham sausage from its packaging and cut into 1cm wide pieces.","Add 1200ml water to a pot, enough to submerge the noodle cake. Bring to a full boil; do not add noodles before boiling.","Add the instant noodle cake and boil for 45 seconds. Gently stir to separate the noodles.","Turn off the heat immediately once noodles are separated. Do not overcook!","Scoop out 80ml of the hot noodle water and set aside.","Drain the noodles and rinse with cold water.","Drain the noodles thoroughly. Do not soak in water for long.","Prepare a small bowl and squeeze in the seasoning packet from the instant noodles.","Add all the vegetable packet.","Add all the sauce packet.","Add 50% to 80% of the powder packet. (Using the whole packet will make it too salty.)","Pour the reserved 80ml hot noodle water into the bowl and stir well to make the sauce.","Take the required number of eggs and crack them into a small bowl. Do not add salt! (The eggs will absorb salt from other ingredients later.)","Heat the pan for 20 seconds, then add 8ml of oil.","Add the beaten eggs and scramble for about 20 seconds until set.","Remove the scrambled eggs and set aside. No need to wash the pan; there won''t be much oil left.","Reheat the pan for 20 seconds and add 10ml of oil.","Add the ham sausage pieces from step 1 and stir-fry for 10 seconds.","Add the noodles from step 2 and stir-fry for 30 seconds.","Add the sauce from step 3 and stir-fry for 30 seconds.","Add the scrambled eggs from step 4 and stir-fry for 30 seconds.","Turn off the heat and serve."]'::jsonb, '["Main Course","Savory","Quick","Home-style","Stir-fry"]'::jsonb),
  ('howtocook:staple/炒河粉', 'en', 'Stir-Fried Rice Noodles', 'Staples', 'Stir-fried rice noodles is a classic snack popular in the Guangdong region. It emphasizes wok hei (breath of the wok), dry and fragrant, with smooth and chewy noodles. Paired with shredded meat, bean sprouts, and cucumber strips, it offers a rich texture. It mainly provides carbohydrates and protein, and the vegetables add vitamins and fiber. This recipe is moderately difficult; even beginners can try it with all ingredients ready. The whole process takes about 30 minutes to serve.', '[{"name":"Stir-fried rice noodles (dry)","unit":"g"},{"name":"Pork or beef","note":"to taste"},{"name":"Salt","unit":"g"},{"name":"MSG","unit":"g"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Cumin powder","unit":"g"},{"name":"Rice noodle seasoning mix","unit":"g"},{"name":"Ground pepper","note":"to taste"},{"name":"Cucumber","unit":"g"},{"name":"Gluten (kaofu) cubes","unit":"g"},{"name":"Mung bean sprouts","unit":"g"},{"name":"Egg","unit":"piece"},{"name":"Garlic","unit":"cloves"},{"name":"Scallion","unit":"stalk"},{"name":"Starch","note":"to taste"},{"name":"Cooking oil","unit":"g"}]'::jsonb, '["Finely chop the scallions (separate white and green parts), and crush the garlic cloves. Set aside on the cutting board.","Crack the egg. Transfer a little egg white to a small bowl, and put the rest into another bowl. Set aside.","Place the mung bean sprouts in a pot and boil for 60 seconds. Remove the sprouts, rinse under cold water, and put them in a plate. Set aside.","Cut the cucumber into strips and put them in a plate. They can be mixed with the bean sprouts.","Handle the gluten. Place it in a separate plate.","Cut the meat into thin strips. Add starch, the egg white from the small bowl, and ground pepper. Stir clockwise to mix well.","Note: The ready-made liangpi (cold skin noodles) from the supermarket usually have cooking oil on the surface. You can rinse them with tap water. Do the same for the gluten.","Note: After rinsing the gluten, squeeze out the excess water with your hands (no need to squeeze too hard).","Add cooking oil. Heat the wok, then pour out the oil.","Add the prepared meat. Stir-fry until it changes color. Transfer to a bowl and set aside.","While the wok is still hot, add 20g cooking oil (reduce for those with high blood pressure). Add the white parts of scallions and garlic. Stir-fry until fragrant.","Add the rice noodles. Drizzle with dark soy sauce for color. Stir-fry evenly, then add the rice noodle seasoning. Continue stir-frying.","When the noodles are almost translucent, add the cooked shredded meat and gluten. Add light soy sauce for freshness. Stir-fry a couple of times.","Add the bean sprouts and cucumber strips. Stir-fry until the noodles are fully translucent.","Turn off the heat!","Sprinkle the green parts of scallions on top. Lift the wok.","Transfer to a plate. Start eating!"]'::jsonb, '["Main Dish","Savory","Stir-fry","Cantonese","Quick","Goes with rice"]'::jsonb),
  ('howtocook:staple/炒馍', 'en', 'Stir-fried Steamed Bun', 'Staples', 'Stir-fried steamed bun is a salty, crispy home-style flour dish, typical of northern Chinese cuisine. The bun cubes are fried until golden, crispy on the outside and soft inside. The addition of cumin and five-spice powder enhances the flavor. It can be paired with eggs for protein and scallions for freshness, making it a balanced meal. The difficulty is moderate, and even beginners can quickly master it. It takes about 15 minutes from start to serving.', '[{"name":"steamed bun","unit":"piece"},{"name":"salt","unit":"g"},{"name":"oil","unit":"ml"},{"name":"cumin powder","unit":"g"},{"name":"chili powder","unit":"g"},{"name":"five-spice powder","unit":"g"},{"name":"scallion","unit":"stalk"},{"name":"egg","unit":"piece"},{"name":"pepper","note":"to taste"}]'::jsonb, '["Cut the steamed bun into small cubes or slices.","If using eggs, crack the eggs into a bowl and beat them (you can add 1g salt and 1g five-spice powder now, or add them later during stir-frying).","Pour the eggs over the bun pieces and mix well. Do not use too much egg.","Heat the pan over high heat, then add cooking oil. (If you''re worried about damaging a stainless steel pan, you can add the oil first and heat until hot.)","Add the bun pieces and stir-fry, mixing evenly.","Reduce the heat to low and stir-fry until the bun pieces turn golden brown.","Add salt, pepper, and five-spice powder.","Finally, add the chopped scallions and stir-fry a few times.","Turn off the heat and serve."]'::jsonb, '["staple","salty","stir-fry","northern style","quick","home-style"]'::jsonb),
  ('howtocook:staple/炸酱面', 'en', 'Zhajiangmian (Fried Sauce Noodles)', 'Staples', 'Zhajiangmian is a traditional Beijing home-style noodle dish with rich sauce and chewy noodles, paired with refreshing vegetable toppings, balancing salty and sweet. The main nutrition comes from protein in lean meat and vitamins from vegetables, providing sufficient energy. It''s beginner-friendly, taking about 30 minutes. With practice, you can shorten time by preparing toppings and stir-frying sauce in parallel.', '[{"name":"Diced meat / minced meat","unit":"g"},{"name":"Dried noodles","unit":"g"},{"name":"Regular noodles","unit":"g"},{"name":"Green onion","unit":"g"},{"name":"Garlic","note":"to taste"},{"name":"Vegetable toppings","unit":"g"},{"name":"Cooking oil","unit":"g"},{"name":"Bean paste (doubanjiang)","unit":"g"},{"name":"Sweet bean paste (tianmianjiang)","unit":"g"}]'::jsonb, '["Cut the vegetable toppings into shreds and set aside.","Chop the green onion. Heat oil in a pan, add green onion and meat, stir-fry until meat is fully cooked (no pink).","Add bean paste and sweet bean paste, continue to stir-fry until slightly thickened. Remove from heat to get the fried sauce.","Take a large bowl, add cold water and set aside.","Cook noodles until just done (no white core), then transfer to the bowl with cold water from step 4.","Immediately drain and transfer to a clean bowl.","Take the fried sauce from step 3, pour into the bowl, and mix well. Then take the vegetable toppings from step 1, add to the bowl, and mix well."]'::jsonb, '["Main Dish","Sauce Aroma","Salty-Sweet","Stir-Fried Sauce","Beijing","Home-Style","Quick"]'::jsonb),
  ('howtocook:staple/烙饼/烙饼', 'en', 'Pan-fried Flatbread', 'Staples', 'This home-style flatbread has distinct layers, crispy on the outside and soft inside, with the savory aroma of oil pastry. It is a common staple on northern Chinese tables. It mainly provides carbohydrates and energy, suitable to accompany dishes. Making it requires some technique, especially the rolling of the pastry and the process of rolling out the dough, but following the steps is not difficult, and beginners can master it. From mixing the dough to finishing the flatbread, it takes about 1 hour.', '[{"name":"flour","unit":"g"},{"name":"hot water","unit":"ml"},{"name":"cold water","unit":"ml"},{"name":"oil","note":"as needed"},{"name":"electric pan","note":"as needed"}]'::jsonb, '["Pour 400g flour into a bowl. Use cold water for half and hot water for the other half to form dough. Stir into flocculent, then knead into a ball by hand. Cover with plastic wrap and let rest for 40 minutes.","10 minutes before the resting time is up, check the tips for making oil pastry (hot oil pastry works better).","Do not knead the rested dough. Press it slightly and divide it into four portions with one horizontal and one vertical cut.","Roll each portion into a ball, then roll out into a circle roughly the size of your electric pan. Take 1/4 of the oil pastry and spread it evenly over the surface.","Cut along one radius of the circle, then roll from the outer edge into a cone shape. Pinch the tip closed to prevent the oil pastry from leaking.","Press down on the tip of the cone to flatten it, then roll out again into a circle similar in size to the electric pan (about 3mm thick).","Preheat the electric pan, brush with cold oil (hot pan, cold oil). Place the rolled flatbread in the pan, brush the top with oil to seal in moisture, cover with lid.","Cook on high heat for one minute, open lid, flip the flatbread, and cook for another minute.","Repeat the above process to finish cooking all flatbreads."]'::jsonb, '["Staple","Pan-fried","Northern","Home-style Staple","Crispy outside & soft inside","Distinct layers"]'::jsonb),
  ('howtocook:staple/烧饼/芝麻烧饼', 'en', 'Sesame Flatbread', 'Staples', 'Sesame flatbread is a well-known pastry in northern China. The crust is covered with sesame seeds, crisp and fragrant, while the inside is layered and soft. Flour provides ample carbohydrates, and sesame seeds are rich in calcium and unsaturated fats. The process involves kneading dough and making oil pastry, but it''s not complicated—even beginners can follow. From preparation to serving takes about 40 minutes.', '[{"name":"Flour","unit":"g"},{"name":"Flour","unit":"g"},{"name":"Yeast","unit":"g"},{"name":"Sugar","unit":"g"},{"name":"Warm water (40°C)","unit":"g"},{"name":"Cooking oil","unit":"g"},{"name":"Cooking oil","unit":"g"},{"name":"Five-spice powder","unit":"g"},{"name":"Salt","unit":"g"},{"name":"White sesame seeds","note":"as needed"}]'::jsonb, '["Dough: 300g flour, 3g yeast, 3g sugar, 180g warm water, 20g cooking oil, rest for 10 minutes","Oil pastry: In a small bowl, combine 30g flour, 2g salt, 4g five-spice powder, 20g cooking oil, mix well, and set aside","Shape the flatbread: Roll the dough into a rectangle, spread the oil pastry on top, roll it up from one end, cut into 7 pieces, fold each in half, seal with your thumb and index finger, dip in water then white sesame seeds, roll into small rounds","Cook the flatbread: Preheat the electric griddle, pour in cold oil (cover the bottom with oil), place the rolled flatbreads in, brush some oil on top, spread evenly, cover, select the large bread setting, and remove when you hear the ding sound"]'::jsonb, '["Staple","Crispy","Griddled","Northern Chinese","Home-style","Pastry"]'::jsonb),
  ('howtocook:staple/热干面', 'en', 'Hot Dry Noodles', 'Staples', 'Hot Dry Noodles is one of the most representative snacks of Wuhan, belonging to Hubei cuisine. The alkaline noodles are chewy and smooth, coated with thick sesame paste, paired with pickled beans, dried radish, and minced meat, salty and slightly spicy, with a rich flavor. It mainly provides carbohydrates and protein, and the sesame paste is also rich in calcium. Simple and quick to make, even beginners can easily master it, taking about ten minutes from boiling to mixing.', '[{"name":"Alkaline noodles for Hot Dry Noodles","unit":"g"},{"name":"Green onion","unit":"g"},{"name":"Pickled beans","unit":"g"},{"name":"Minced meat","unit":"g"},{"name":"Garlic water","unit":"ml"},{"name":"Meat broth","unit":"ml"},{"name":"Dried radish","unit":"g"},{"name":"Sesame paste","unit":"ml"},{"name":"Chili oil","unit":"ml"},{"name":"Pepper","unit":"g"},{"name":"Soy sauce","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Chicken powder","unit":"g"}]'::jsonb, '["Boil water, add the alkaline noodles, blanch for 25 seconds and remove","Sprinkle with salt, chicken powder, and pepper","Dilute sesame paste with 90ml water, stir well, then add","Add 5ml soy sauce, add 30ml meat broth and garlic water","Add dried radish, minced meat, pickled beans, chopped green onions","Mix well and enjoy"]'::jsonb, '["Staple","Wuhan","Snack","Mixed Noodles","Quick","Salty and slightly spicy","Home-style"]'::jsonb),
  ('howtocook:staple/煮泡面加蛋', 'en', 'Instant Noodles with Egg', 'Staples', 'Instant noodles with egg is a quick and convenient staple dish. The texture is smooth and the soup is rich, perfect for filling your stomach anytime. It mainly provides carbohydrates and protein, quickly replenishing energy. The method is extremely simple: just boil water, cook the noodles, and crack in an egg. Even beginners can master it easily, and it takes about 10 minutes from start to finish.', '[{"name":"instant noodles","unit":"packet"},{"name":"egg","unit":"piece"},{"name":"water","unit":"ml"}]'::jsonb, '["First, heat the water until boiling (no strict requirement for heat level; using hot water is faster)","Put the removed noodle cake into the pot","Add the seasoning packets from the instant noodles into the pot","Use chopsticks to gently stir the noodles, allowing the seasoning to fully dissolve and the noodle cake to be evenly soaked and heated","Cover with lid and wait about 1 minute until the water boils again","Crack the egg and add it to the pot","Wait about 3 to 4 minutes, then it''s ready"]'::jsonb, '["Staple","Quick","Home-style","Boiled","Savory","Filling"]'::jsonb),
  ('howtocook:staple/照烧鸡腿饭', 'en', 'Teriyaki Chicken Leg Rice', 'Staples', 'Teriyaki Chicken Leg Rice is a savory and sweet dish that goes well with rice. The chicken legs are pan-fried until crispy and then simmered in a rich sauce, resulting in tender and flavorful meat. Chicken leg meat is rich in high-quality protein, and paired with broccoli and carrots, it provides dietary fiber and vitamins. It requires some deboning skills, but overall it''s not complicated; beginners can follow the steps and succeed. From preparation to serving, it takes about 30 minutes.', '[{"name":"Chicken thigh","unit":"g"},{"name":"Cooking wine","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Honey","unit":"ml"},{"name":"Crushed black pepper","unit":"g"},{"name":"Ground black pepper","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Broccoli","unit":"g"},{"name":"Carrot","unit":"g"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Garlic","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Water","unit":"ml"},{"name":"Rice","unit":"g"}]'::jsonb, '["Take one chicken leg, place skin-side down on a cutting board.","Using the tip of a knife, carefully cut along the outline of the bone from one end to the other.","Use your fingers or the back of a knife to slowly push the meat away to expose the bone. If you encounter connective tissue, cut it with the knife tip.","When the meat is fully separated, hold one end of the bone, twist gently, and pull it out.","Repeat the above steps to debone all chicken legs.","Add ground black pepper, crushed black pepper, salt, and ginger slices to the deboned chicken legs. Marinate for 5 minutes.","In a bowl, mix cooking wine, light soy sauce, honey, dark soy sauce, and water.","Blanch the vegetables in boiling water for 1-2 minutes until cooked, then remove.","Heat a pan, add 15 ml oil, and sauté crushed garlic until fragrant.","Add the chicken legs and pan-fry over medium-low heat until golden on both sides. If the pan seems too dry, add 5-10 ml oil.","Pour in the prepared sauce, cover, and simmer over medium-low heat (low heat on a gas stove) for 5-10 minutes until cooked through and the sauce thickens and bubbles.","Slice the chicken, arrange with vegetables over rice, drizzle with the pan sauce, and enjoy slowly."]'::jsonb, '["Main Dish","Sweet and Salty","Pan-fry and Simmer","Japanese-style","Goes with Rice","Quick"]'::jsonb),
  ('howtocook:staple/蒸卤面', 'en', 'Steamed Noodles with Braised Sauce', 'Staples', 'This is a classic home-style noodle dish from southern Henan. It combines meat and vegetables, with noodles absorbing the rich sauce, resulting in a chewy and savory flavor. Pork belly provides high-quality protein and fat, while celery is rich in dietary fiber. The method is simple and easy to learn, even for beginners. The entire preparation takes about an hour.', '[{"name":"pork belly","unit":"g"},{"name":"fresh noodles","unit":"g"},{"name":"celery","unit":"stalk"},{"name":"scallion","unit":"cm"},{"name":"ginger","unit":"g"},{"name":"garlic","unit":"clove"},{"name":"green bell pepper","unit":"piece"},{"name":"dried red chili pepper","unit":"piece"},{"name":"Sichuan peppercorns","unit":"grain"},{"name":"salt","unit":"g"},{"name":"five-spice powder","unit":"g"},{"name":"light soy sauce","unit":"ml"},{"name":"dark soy sauce","unit":"ml"},{"name":"cooking oil (peanut oil preferred)","note":"to taste"},{"name":"cooking wine","note":"to taste"}]'::jsonb, '["Remove skin from pork belly and slice into 2 cm by 6 cm by 0.5 cm pieces. Set aside.","Remove leaves from celery, cut off 2 cm from the root, then halve lengthwise and cut into 2 cm segments. Set aside.","Peel garlic and cut into small pieces. Slice scallion into 0.2 cm thin rounds. Cut ginger into thin strips. Set aside.","Heat a wok until smoking. Add 3 ml cooking oil to coat the wok, then discard the oil.","Add cooking oil again. Add the pork slices, scallion, ginger, garlic, and dried red chili peppers. Stir-fry for 1 minute, stirring constantly and evenly.","Add cooking wine, light soy sauce, and dark soy sauce. Stir-fry for another 1 minute.","Add 500 ml hot water. Cover and simmer for 3 minutes.","Add celery and green bell pepper to the wok. Season with salt and five-spice powder. Cover and continue simmering for 3 minutes, then turn off the heat.","Add 1000 ml water to a steamer. Bring to a boil. Spread the noodles evenly on a steamer tray and place into the steamer. Steam for 15 minutes.","Remove the steamed noodles. Use chopsticks and your hands to separate them on a cutting board. Let cool to room temperature.","Add the noodles to the wok with the vegetables. Mix by holding chopsticks in one hand and a spatula in the other, lifting the vegetables over the noodles until all noodles are evenly coated with sauce.","Place the mixed noodles back on the steamer tray. Steam again for 10 minutes, then turn off heat."]'::jsonb, '["Main Course","Savory","Steamed","Southern Henan","Home-style","Meat and Vegetable Combo"]'::jsonb),
  ('howtocook:staple/猪油拌饭', 'en', 'Lard Rice', 'Staples', 'This is a simple rice dish full of southern home-style flavor. The rice grains are coated in melted lard, with the savory saltiness of soy sauce and the fragrance of scallions. It''s a comforting choice for children with poor appetite. It mainly provides quick carbs and fat energy, but is high in cholesterol, so not for frequent consumption. There''s no threshold for making it; even someone who can''t cook can easily make it. Just a few minutes with cooked rice yields a fragrant bowl of staple food.', '[{"name":"Rice (japonica recommended)","unit":"g"},{"name":"Lard","unit":"g"},{"name":"Light soy sauce (Lee Kum Kee or Haitian recommended)","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Oyster sauce (optional)","unit":"g"},{"name":"Scallions (optional)","unit":"g"},{"name":"Lard cracklings (optional)","unit":"g"}]'::jsonb, '["Spread lard at the bottom of a bowl","Add rice","Drizzle soy sauce and oyster sauce","Sprinkle scallions and lard cracklings","Mix well"]'::jsonb, '["Staple","Savory","Mixed rice","Quick","Homestyle","Southern","Goes with rice"]'::jsonb),
  ('howtocook:staple/电饭煲三文鱼炊饭/电饭煲三文鱼炊饭', 'en', 'Salmon Rice in Rice Cooker', 'Staples', 'This is a home-style dish that combines the Japanese cooking method of takikomi gohan. The rice soaks up the aroma of butter and salmon, resulting in a rich and savory flavor. Salmon provides high-quality protein and unsaturated fatty acids, and the addition of mushrooms adds dietary fiber. The operation is extremely simple, just one click on the rice cooker. From preparation to serving, it takes about 45 minutes, making it perfect for beginners.', '[{"name":"Rice","unit":"g"},{"name":"Salmon","unit":"g"},{"name":"Salted butter","unit":"tablespoon"},{"name":"Water","note":"to taste"},{"name":"Corn (optional)","note":"to taste"},{"name":"Enoki mushrooms (optional)","note":"to taste"},{"name":"Shiitake mushrooms (optional)","note":"to taste"}]'::jsonb, '["Remove scales and bones from salmon","Finely chop enoki mushrooms and shiitake mushrooms","Rinse rice three times","Put salmon, rice, and butter into the rice cooker","For a richer taste, add one more tablespoon of butter","Add water according to the rice cooker''s markings","Set the rice cooker to cook rice mode and wait about 30-45 minutes"]'::jsonb, '["Main","Savory","Rice Cooker","Home-style","Quick"]'::jsonb),
  ('howtocook:staple/空气炸锅照烧鸡饭/空气炸锅照烧鸡饭', 'en', 'Air Fryer Teriyaki Chicken Rice', 'Staples', 'This Japanese-style teriyaki chicken rice has a rich sweet and savory sauce, with a slightly crispy surface and tender, juicy inside. It goes great with rice. Chicken and eggs provide high-quality protein, but the sauce uses quite a bit of soy sauce and sugar, so it''s better for occasional indulgence. The method is simple: just mix the ingredients and let the air fryer do the work. Even beginners can handle it easily. It takes about 1 hour from prep to finish.', '[{"name":"chicken","unit":"g"},{"name":"soy sauce","unit":"ml"},{"name":"sugar","unit":"g"},{"name":"white vinegar","unit":"ml"},{"name":"Ritz crackers","unit":"pieces"},{"name":"egg","unit":"pieces"},{"name":"rice","note":"as needed"}]'::jsonb, '["Mix the soy sauce, sugar, and vinegar together, stir well to make the sauce and set aside.","In another bowl, add the chicken, egg, 1/2 of the sauce, and crushed Ritz crackers. Stir to combine.","Line the air fryer basket with a foil bowl, add the meat mixture, and pour the remaining sauce evenly over the top.","Air fry at 350°F (177°C) for 40 minutes. Best served over rice.","When golden and crispy, remove from the air fryer, cut into pieces, and serve on a plate."]'::jsonb, '["Main Dish","Sweet and Savory","Air Fryer","Japanese","Goes Well with Rice","Home-style"]'::jsonb),
  ('howtocook:staple/米饭/煮锅蒸米饭', 'en', 'Pot-Steamed Rice', 'Staples', 'This is a humble home-style staple. With an ordinary pot, you can make soft and fluffy rice. White rice mainly provides carbohydrates, quickly replenishing energy. The method is extremely simple; beginners only need to pay attention to the heat throughout. From adding rice to serving takes about 25 minutes.', '[{"name":"Northern rice","unit":"ml"},{"name":"water","note":"as needed"}]'::jsonb, '["Rinse the rice","Add rice and water to the pot","Bring to a boil over high heat","Stir the bottom to prevent sticking","Cover, reduce heat to low, and cook for 10-15 minutes (depending on desired softness). Do not open the lid during cooking.","Turn off heat and let it rest for 5 minutes","Enjoy :)"]'::jsonb, '["Staple","Light","Soft and Fluffy","Boil","Home-style","Quick"]'::jsonb),
  ('howtocook:staple/米饭/电饭煲蒸米饭', 'en', 'Rice Cooker Steamed Rice', 'Staples', 'A staple base dish known in every household, with pure rice fragrance and soft, sticky texture. The amount of water can make it firmer or more moist. Rich in carbohydrates, quickly replenishes energy, and pairs well with various dishes. Extremely simple to make, even beginners can easily master it. It takes about 40 minutes from washing rice to steaming.', '[{"name":"Jiangnan rice or northern rice","unit":"ml"},{"name":"Water","note":"as needed"}]'::jsonb, '["Wash the rice.","Add the rice and water together into the rice cooker.","Plug in the rice cooker and set to cooking mode. Wait about 30 minutes.","Wait until the rice cooker automatically switches to keep-warm mode.","Let the rice sit in the cooker for 10-15 minutes.","Scoop out the rice."]'::jsonb, '["Staple","Light","Quick","Homestyle"]'::jsonb),
  ('howtocook:staple/红芸豆拌饭', 'en', 'Red Kidney Bean Rice Bowl', 'Staples', 'This North Indian homestyle dish is a traditional favorite from Punjab and Delhi. The tomato-onion gravy is rich and aromatic, and the red kidney beans become tender and flavorful after simmering. Mixed with hot rice, it''s a warm and filling meal. The beans are packed with protein, dietary fiber, and various micronutrients, offering balanced nutrition. The recipe is simple and beginner-friendly, taking about 40 minutes to cook, but the dried beans need to be soaked for 8 hours ahead. It''s a comforting home-cooked flavor, just like mom''s.', '[{"name":"dried red kidney beans","unit":"g"},{"name":"onion","unit":"piece"},{"name":"tomato","unit":"piece"},{"name":"tomato paste","unit":"ml"},{"name":"ginger","unit":"g"},{"name":"garlic","unit":"clove"},{"name":"green chili","unit":"piece"},{"name":"vegetable oil or ghee","unit":"ml"},{"name":"bay leaf","unit":"leaf"},{"name":"turmeric powder","unit":"g"},{"name":"red chili powder","unit":"g"},{"name":"coriander powder","unit":"g"},{"name":"cumin powder","unit":"g"},{"name":"garam masala","unit":"g"},{"name":"salt","unit":"g"},{"name":"water","unit":"ml"},{"name":"fresh cilantro leaves","unit":"g"},{"name":"rice","unit":"g"},{"name":"water","unit":"ml"}]'::jsonb, '["Soak dried red kidney beans in water for at least 8 hours (overnight); they will double in volume.","Drain the soaked red kidney beans.","Using a pressure cooker: Add the red kidney beans and 600ml water, close the lid, bring to high pressure over high heat then reduce to medium heat, cook for 15-20 minutes until beans can be easily crushed with fingers.","Using a regular pot: Add the red kidney beans and enough water, bring to a boil over high heat then reduce to medium heat, cook for 60-90 minutes until beans are completely soft.","After cooking, reserve the bean cooking liquid and set aside.","In a frying pan, heat 30ml vegetable oil or ghee over medium heat.","Add 2 bay leaves and fry until fragrant (about 10 seconds).","Add chopped onion and sauté until golden brown (about 6-8 minutes).","Add grated ginger and garlic, sauté for 1 minute.","Add chopped tomatoes and sauté until completely soft and oil separates (about 5 minutes).","Add 3g turmeric powder, 5g red chili powder, 5g coriander powder, 3g cumin powder, and 6g salt.","Sauté for 2 minutes to blend the spices with the tomatoes.","Pour the cooked kidney beans along with their cooking liquid into the pan.","Add green chili and mix well.","Bring to a boil over high heat, then reduce to low heat and simmer for 15-20 minutes.","During simmering, mash some of the beans with the back of a spatula to thicken the gravy.","Add 3g garam masala and stir well.","Turn off the heat and sprinkle fresh cilantro leaves.","Wash the rice thoroughly.","Place the rice in a rice cooker and add 400ml water.","Cook as usual.","Scoop the cooked rice onto a plate.","Spoon the red kidney bean curry over or alongside the rice.","Serve with onion salad and lemon wedges."]'::jsonb, '["Main Course","North Indian","Stew","Spicy","Rice Dish","Homestyle","Curry"]'::jsonb),
  ('howtocook:staple/老友猪肉粉/老友猪肉粉', 'en', 'Old Friend Pork Rice Noodles', 'Staples', 'Old Friend Pork Rice Noodles are sour, spicy, fresh, and aromatic. The noodles are smooth and slippery, with the rich flavors of fermented black beans and sour bamboo shoots, a typical Nanning home-cooked taste. Pork provides high-quality protein, while rice noodles quickly replenish carbs. Overall difficulty is moderate; be sure to soak the rice noodles in advance. Once you get the hang of it, it takes about forty minutes to serve.', '[{"name":"rice noodles","unit":"g"},{"name":"pork","unit":"g"},{"name":"sour bamboo shoots","unit":"g"},{"name":"chopped chili","unit":"g"},{"name":"fermented black beans","unit":"g"},{"name":"garlic","unit":"g"},{"name":"cooking wine","unit":"ml"},{"name":"light soy sauce","unit":"ml"},{"name":"sugar","unit":"g"},{"name":"rice vinegar","unit":"ml"},{"name":"salt","unit":"ml"},{"name":"oil","unit":"ml"},{"name":"cornstarch","unit":"ml"},{"name":"pepper","unit":"ml"}]'::jsonb, '["Season all the pork with cooking wine, salt, light soy sauce, cornstarch, and pepper in a bowl; set aside.","Heat the wok without oil, add all the sour bamboo shoots and stir-fry until dry. Make a little space in the middle of the dried bamboo shoots.","Add 10-15 ml cooking oil, all the garlic, chopped chili, and fermented black beans into the center of the dried bamboo shoots. Push everything to the center and stir-fry until fragrant.","Add all the seasoned pork, then add 10 ml light soy sauce and stir-fry for one minute.","Add 5 ml rice vinegar, 10 ml light soy sauce, and 450 ml water. Bring to a boil.","After boiling, add the rice noodles that have been soaked in warm water, and cook for another 3 minutes. Then serve."]'::jsonb, '["Main Course","Sour and Spicy","Boiled","Nanning Style","Home-style","Rice Noodles"]'::jsonb),
  ('howtocook:staple/老干妈拌面', 'en', 'Laoganma Noodles', 'Staples', 'A spicy and appetizing home-style quick noodle dish. The chewy noodles are coated with the fermented bean chili flavor of Laoganma, with soy sauce enhancing the umami. Simple yet full of flavor. As a staple, it quickly replenishes carbohydrates and energy, and capsaicin helps stimulate appetite. No cooking skills required, easy for beginners. From boiling water to serving takes only about 10 minutes.', '[{"name":"Water","unit":"L"},{"name":"Noodles","unit":"g"},{"name":"Laoganma","unit":"ml"},{"name":"Soy sauce","unit":"ml"}]'::jsonb, '["Pour water into a pot and bring to a boil.","Evenly add noodles to the pot.","Stir occasionally during cooking to prevent noodles from clumping.","When you can pick up a noodle with chopsticks and it naturally slides off, wait another 30 seconds then turn off the heat.","Transfer noodles to a bowl.","Add Laoganma and soy sauce according to the measurements above.","Mix the noodles, Laoganma, and soy sauce evenly with chopsticks.","Enjoy."]'::jsonb, '["Staple","Spicy","Noodles","Quick","Homestyle","Appetizing"]'::jsonb),
  ('howtocook:staple/肉蛋盖饭', 'en', 'Meat and Egg Rice Bowl', 'Staples', 'This dish is rich in sauce aroma, savory and sweet, with lightly charred ground meat and tender eggs, satisfying on hot rice. It''s a home-style quick dish. Rich in high-quality protein and essential amino acids, it quickly replenishes energy. The method is simple and straightforward, even beginners can easily handle it. From prep to serving, it takes about fifteen minutes.', '[{"name":"rice","unit":"g"},{"name":"eggs","unit":"piece"},{"name":"ground meat","unit":"g"},{"name":"dark soy sauce","unit":"ml"},{"name":"light soy sauce","unit":"ml"},{"name":"vinegar","unit":"ml"},{"name":"red onion oil","unit":"g"},{"name":"scallion","unit":"g"},{"name":"oil","unit":"ml"},{"name":"sugar","unit":"g"}]'::jsonb, '["Cook the rice. Typically use the measuring cup that came with the rice, one cup of rice is 240g.","Add 30ml oil to the pan.","Add the ground meat, cook over medium heat until both sides are lightly browned.","Crack the eggs into the pan, do not scramble, cover the pan.","Prepare a sauce: in a bowl, add the corresponding amounts of dark soy sauce, light soy sauce, vinegar, sugar, and red onion oil, stir to combine.","Uncover the pan, pour the sauce in, wait for three minutes.","Turn off the heat, spoon the meat and eggs over the rice.","Safety check, then start eating."]'::jsonb, '["Main Dish","Savory Sauce","Savory and Sweet","Quick","Goes with Rice","Home-Style"]'::jsonb),
  ('howtocook:staple/茄子肉煎饼/茄子肉煎饼', 'en', 'Eggplant and Preserved Meat Pancake', 'Staples', 'This home-style pancake combines the savory flavor of preserved meat with the soft texture of eggplant. It has a crispy outer layer and a tender interior, making it a rustic rice flour main dish. Rich in carbohydrates and high-quality protein, eggplant also provides dietary fiber and vitamins, offering a balanced mix of meat and vegetables. The difficulty is moderate; you need to control the batter consistency and frying heat, but beginners can succeed by following the steps. It takes about 30 minutes from preparation to serving.', '[{"name":"Rice flour","unit":"g"},{"name":"Wheat flour","unit":"g"},{"name":"Egg","unit":"piece"},{"name":"Cooked preserved meat","unit":"g"},{"name":"Eggplant","unit":"piece"},{"name":"Cooking oil","unit":"ml"},{"name":"Salt","unit":"g"}]'::jsonb, '["Peel the eggplant and slice it. Slice the preserved meat. Set aside.","Add 250g rice flour (ground from rice), 50g wheat flour, and 1 egg to a bowl in order.","While stirring with chopsticks, add water (to adjust consistency) to mix the rice flour, wheat flour, and egg into a batter. Stop adding water when the batter can coat the eggplant and meat slices without dripping. Then put all slices into the batter and coat them thoroughly.","Add 10-30ml cooking oil to a flat-bottomed pan over low heat.","Use chopsticks or a spoon to place the battered slices into the pan. Fry until golden on both sides, then cook for another 3-6 minutes (add more oil if needed during frying).","Sprinkle with salt, stir-fry evenly, then remove from heat and plate."]'::jsonb, '["Main Dish","Savory","Pan-fried","Home-style","Rustic","Balanced Nutrition"]'::jsonb),
  ('howtocook:staple/葱油拌面', 'en', 'Scallion Oil Noodles', 'Staples', 'Scallion oil noodles is a classic Shanghai home-style noodle dish, known for its unique scallion oil aroma. It''s simple and quick to make, rich in carbohydrates and fats, providing a quick energy boost. Beginners can finish it in about 20 minutes, making it an ideal quick weekday dinner.', '[{"name":"dried noodles","unit":"g"},{"name":"scallions","unit":"g"},{"name":"light soy sauce","unit":"ml"},{"name":"dark soy sauce","unit":"ml"},{"name":"sugar","unit":"g"},{"name":"cooking oil","unit":"ml"}]'::jsonb, '["Wash the scallions and cut into long sections (about 5-7 cm). The white and green parts can be separated.","Add 100 ml cooking oil to the pan and heat over medium heat. First add the white parts of the scallions and stir-fry until slightly yellow.","Add the green parts of the scallions, turn to low heat, and continue stir-frying.","Keep on low heat and patiently stir-fry for about 15-20 minutes until the scallion sections become crispy and dark golden.","Remove the crispy scallions (keep the oil in the pan).","To the scallion oil in the pan, add 60 ml light soy sauce, 20 ml dark soy sauce, and 15 g sugar. Heat over low heat and stir for about 1 minute until the sugar dissolves and the sauce is well combined. Immediately turn off the heat. Pour the prepared scallion oil sauce into a container, let cool, and seal for storage.","Take 80 g dried noodles.","Add 1000 ml water to the pan and bring to a boil over high heat.","Add the noodles and cook according to the package instructions until done (usually 3-8 minutes, follow package instructions).","Remove the cooked noodles, drain well, and place in a bowl.","Add 15 ml of the prepared scallion oil sauce to the bowl with the noodles.","You can add the previously fried scallion sections (optional).","Mix quickly and evenly with chopsticks, and serve."]'::jsonb, '["Main Course","Shanghai","Savory","Quick","Home-style","Noodles"]'::jsonb),
  ('howtocook:staple/蛋包饭', 'en', 'Omurice (Egg-Wrapped Rice)', 'Staples', 'Tender egg wrap filled with ketchup-flavored fried rice. Rich flavor, sweet and sour, appetizing. A classic Japanese home-style dish. Rich in protein, carbs, and vitamins, nutritionally balanced. Wrapping the egg requires some skill, but overall moderate difficulty, suitable for beginners. Takes about 25 minutes from prep to finish.', '[{"name":"Eggs","unit":"piece"},{"name":"Onion","unit":"gram"},{"name":"Carrot","unit":"gram"},{"name":"Corn kernels and green peas (optional)","unit":"gram"},{"name":"Ham sausage or chicken breast","unit":"gram"},{"name":"Cooked rice","unit":"gram"},{"name":"Ketchup","unit":"ml"},{"name":"Cooking oil","unit":"ml"},{"name":"Milk (optional)","unit":"ml"}]'::jsonb, '["Dice the onion, carrot, and ham sausage or chicken breast into small cubes; set aside.","Heat a pan, add 10ml cooking oil, wait 10 seconds to heat.","First stir-fry the diced onion for 1 minute, then add carrot, corn kernels, and green peas (if using) and stir-fry for another 2 minutes.","Add the ham sausage or chicken breast cubes, stir-fry until color changes.","Add the rice and stir-fry to break up clumps, then add 20ml ketchup, stir well. The fried rice is done; remove and set aside.","Beat the eggs, add 10ml milk and mix well.","Add 5ml cooking oil to the pan, pour in the egg mixture, gently tilt the pan to spread evenly.","Heat on low heat. When the egg surface is half-cooked, place the fried rice in the center of the egg.","Use a spatula to fold the egg over the rice to form an oval shape.","Gently slide onto a plate, shape it, and optionally drizzle a little ketchup on top for decoration."]'::jsonb, '["Main Course","Sweet and Sour","Stir-Fry","Quick","Home-style","Japanese","Appetizing"]'::jsonb),
  ('howtocook:staple/蛋炒饭', 'en', 'Egg Fried Rice', 'Staples', 'A home-style egg fried rice, with golden egg threads wrapping each grain of rice, paired with ham, carrot, and cucumber. Rich texture, savory and tasty. Eggs provide quality protein, carrots add vitamins, and carbohydrates supply energy. The steps are a bit many, but beginners can succeed by following the process. It takes about 25 minutes in total.', '[{"name":"Cold rice","unit":"ml"},{"name":"Egg"},{"name":"Ham","unit":"piece"},{"name":"Cucumber","unit":"g"},{"name":"Carrot","unit":"g"},{"name":"Oil","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Pepper","unit":"g"},{"name":"Spring onion","unit":"stalk"},{"name":"Light soy sauce","unit":"ml"},{"name":"Shredded beef jerky/luncheon meat/Chinese sausage/braised meat, etc. (optional)","note":"to taste"}]'::jsonb, '["Break cold rice into small pieces with a spatula beforehand.","Slice or dice ham, carrot, cucumber, etc. as desired.","If you have cooked meat at home, prepare it for better flavor.","Separate egg whites and yolks into two large bowls, beat each separately. Note: do not add salt at this step.","Heat the wok over high heat. When it starts to smoke, add cooking oil. Add egg whites, wait until mostly set, then remove and set aside.","If there''s enough oil, add egg yolks directly. If not, add more oil and heat over high heat again.","When the yolks are mostly set, reduce heat to medium-low. Add ham, cooked meat, carrot, cucumber, etc. Stir-fry for 10 seconds until fragrant.","Add back the egg whites, stir-fry for 5 seconds, then quickly add rice and stir-fry over high heat, making sure each grain is coated with egg.","During stir-frying, break up any clumps of rice. This step may take a while. Once all rice is broken up and evenly mixed, it''s done.","Reduce heat to low. Add salt, pepper, and light soy sauce.","Continue stir-frying evenly. When you see some rice grains ''jumping'' in the wok, it''s almost ready.","Finally, add chopped green onions and stir-fry for another 10 seconds.","Turn off heat and transfer to a bowl."]'::jsonb, '["Main Dish","Savory","Home-style","Quick","Stir-fry","Goes with rice"]'::jsonb),
  ('howtocook:staple/螺蛳粉', 'en', 'Snail Noodles', 'Staples', 'Snail Noodles is a specialty snack from Liuzhou, Guangxi. The soup is savory and rich, with a sour and spicy kick. The rice noodles are soft, smooth, and chewy. The flavor combines the umami of snail soup, the unique fermented aroma of sour bamboo shoots, and the heat of chili oil, creating distinct layers. As a staple, the rice noodles provide ample carbohydrates, while the snail meat packet and toppings add protein. The sour bamboo shoots help stimulate appetite and aid digestion. This dish is simple to prepare: just cook the noodles and seasonings in order. It''s very beginner-friendly. From boiling water to serving, it takes about ten minutes, perfect for a quick meal.', '[{"name":"Packaged snail noodles","unit":"packet","note":""},{"name":"Water","unit":"L","note":""},{"name":"Rice noodles","unit":"","note":"to taste"},{"name":"Snail meat packet","unit":"","note":"to taste"},{"name":"Soup base packet","unit":"","note":"to taste"},{"name":"Sour bamboo shoot packet","unit":"","note":"to taste"},{"name":"Peanut packet","unit":"","note":"to taste"},{"name":"Tofu skin packet","unit":"","note":"to taste"},{"name":"Wood ear mushroom packet","unit":"","note":"to taste"},{"name":"Vinegar packet","unit":"","note":"to taste"},{"name":"Chili oil","unit":"","note":"to taste"}]'::jsonb, '["Add water to a pot and bring to a boil.","Add the rice noodles and cook for 3-5 minutes, stirring occasionally with chopsticks to prevent sticking.","Add the soup base packet, adjusting to taste.","Add some of the topping packets, such as wood ear mushrooms, peanuts, and snails (these need to cook for a while to infuse flavor).","Add the seasoning packet, adjusting to taste.","Stir, then remove and place in a bowl.","Add the remaining topping packets, such as sour bamboo shoots and tofu skin (these should not be soaked in soup for too long).","Enjoy your meal."]'::jsonb, '["Main Course","Sour & Spicy","Savory","Quick","Guangxi Style","Soup Noodles"]'::jsonb),
  ('howtocook:staple/西红柿鸡蛋挂面/西红柿鸡蛋挂面', 'en', 'Tomato Egg Noodle Soup', 'Staples', 'Tomato Egg Noodle Soup is a quick and easy home-style noodle dish. It has a sweet and sour, savory flavor with rich broth and chewy noodles. It''s a daily staple with northern Chinese influences. Eggs provide high-quality protein, tomatoes are rich in lycopene and vitamins, and together with carbs, it''s a balanced meal. Simple steps, beginner-friendly, takes about 20 minutes from prep to finish.', '[{"name":"Dried noodles","unit":"g"},{"name":"Tomatoes","unit":"pieces"},{"name":"Eggs","unit":"pieces"},{"name":"Salt","unit":"g"},{"name":"Scallions","note":"to taste"},{"name":"Garlic","note":"to taste"},{"name":"Green pepper","note":"to taste"},{"name":"Cooking oil","unit":"g"},{"name":"Soy sauce","unit":"g"},{"name":"Oyster sauce","unit":"g"},{"name":"Chicken bouillon","unit":"g"},{"name":"Sugar","unit":"g"},{"name":"Sesame oil","unit":"g"},{"name":"White vinegar","unit":"g"},{"name":"Water","note":"as needed"}]'::jsonb, '["Wash and finely chop the scallions.","Cut the tomatoes into chunks. If you''re not confident, you can look it up online first~","Cut the green pepper into diamond-shaped pieces.","Crack the eggs into a small bowl and beat them. If the eggs have a slight smell, add 2g of white vinegar to remove the odor.","Heat the wok over high heat, add 15-20g of cooking oil. Use a bit more oil for tender scrambled eggs, and leave some in the pan for later sautéing tomatoes.","When the oil is about 70% hot (you can feel the heat when your palm is about 10cm above), pour in the beaten eggs and quickly stir to scramble.","Once the eggs are fully set (no liquid egg remains), transfer them to a small bowl, leaving some oil in the pan.","With the remaining oil, add the white parts of the scallions and minced garlic, and stir-fry until fragrant.","Add the tomato chunks and green pepper pieces, and stir until the tomatoes release some juice.","Quickly add 5g of soy sauce and 2g of sugar.","Stir-fry for about ten seconds, then add a bowl of water (just enough to barely cover the tomatoes).","After boiling, add the scrambled eggs and 5g of oyster sauce (or 2g of chicken bouillon) to enhance the flavor.","Simmer over medium-low heat to reduce the sauce, stirring occasionally to prevent sticking. When the sauce has thickened, add some chopped scallion greens and a drizzle of sesame oil (optional). The topping is ready.","You can skip washing the pan; directly add 500ml of water.","Bring to a boil, add the dried noodles. When the noodles soften, add 100ml of cold water.","After it boils again, if the noodles float, add another 100ml of cold water.","After boiling, check if the noodles look translucent on the edges; if so, they are cooked.","Lift the noodles into the bowl with the topping, mix well, and enjoy~"]'::jsonb, '["Main Course","Home-style","Quick","Sweet and Sour","Noodles","Appetizing"]'::jsonb),
  ('howtocook:staple/豆角焖面/豆角焖面', 'en', 'Green Bean Braised Noodles with Pork Belly', 'Staples', 'Green bean braised noodles is a Northern Chinese home-style noodle dish. The noodles soak up the savory broth, becoming soft and chewy with a rich flavor, complemented by the freshness of green beans and the oiliness of pork belly. Pork belly provides protein and fat, while green beans are rich in dietary fiber and vitamins, making a balanced meal. The process is not difficult but requires attention to heat and timing for adding broth. Suitable for cooks with some experience, it takes about 30 minutes to serve.', '[{"name":"Fresh noodles","unit":"g"},{"name":"Pork belly","unit":"g"},{"name":"Green beans","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Oyster sauce","unit":"g"},{"name":"Thirteen-spice powder","unit":"g"},{"name":"Chicken bouillon powder","unit":"g"},{"name":"MSG","unit":"g"},{"name":"Scallions","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Garlic","unit":"g"},{"name":"Hot water","unit":"ml"}]'::jsonb, '["Cut the green beans into 5-6 cm segments.","Cut the scallions into 1-2 cm pieces.","Cut the ginger into 1mm x 1mm x 3cm strips.","Crush the garlic cloves on a cutting board, then mince to 1mm granules.","Slice the pork belly into 2mm thick slices.","First, heat the wok until all moisture evaporates; hold your hand 10 cm above the wok bottom, you should feel a noticeable heat.","Add the specified amount of cooking oil, hold the wok handle 5 cm above the stove, and swirl the wok to coat 2/3 of the wok surface (from bottom up).","Add all the ginger and scallion pieces, stir-fry for 5 seconds to release fragrance (Note: oil may splatter, wear gloves or protect yourself).","Add all the pork slices; do not stir immediately. Let them sit for 5 seconds, then stir-fry until all slices are coated with oil.","Keep stir-frying until all pork slices change color, then drizzle the prepared light soy sauce along the wok edge and stir well.","Add in order: salt, dark soy sauce, oyster sauce, thirteen-spice powder, chicken bouillon powder, and all the green beans. Stir-fry for 2 minutes.","Add the prepared hot water.","When the water boils, use a spoon to scoop out half of the broth (be careful not to scoop out the vegetables).","Lay all the fresh noodles evenly on top of the vegetables.","Cover with a lid and simmer over medium heat for 5 minutes.","Remove the lid, and use a spoon to drizzle the reserved broth over the noodles, one spoonful at a time, evenly.","Cover again and simmer over medium heat for 3 minutes.","Remove the lid, and evenly sprinkle all the minced garlic and MSG over the dish.","Use chopsticks to toss and stir everything together until well mixed.","Turn off the heat."]'::jsonb, '["Main Course","Northern Home-style","Braised Noodles","Savory","Quick"]'::jsonb),
  ('howtocook:staple/酱拌荞麦面/酱拌荞麦面', 'en', 'Buckwheat Noodles with Sauce', 'Staples', 'Buckwheat noodles with sauce are sweet, sour, refreshing, and smooth. This is a simple and quick home-style cold noodle dish. Buckwheat noodles are rich in dietary fiber and protein, paired with cucumber and carrot for a refreshing texture and vitamins, making it nutritionally balanced. Just boil the noodles, cut the vegetables, and mix with Lao Gan Ma—easy steps that are very beginner-friendly, taking about 20 minutes. It tastes even better after chilling.', '[{"name":"buckwheat noodles","unit":"g"},{"name":"cucumber","unit":"piece"},{"name":"carrot","unit":"piece"},{"name":"Lao Gan Ma","unit":"ml"}]'::jsonb, '["Cook buckwheat noodles in cold water until done, about 8-10 minutes, then drain and set aside.","Cut cucumber and carrot into small strips.","Place buckwheat noodles, cucumber, and carrot in a plate, add Lao Gan Ma, and mix."]'::jsonb, '["Main Course","Cold Dish","Quick","Home-style","Sweet and Sour","Mildly Spicy","Refreshing"]'::jsonb),
  ('howtocook:staple/酸辣蕨根粉', 'en', 'Hot and Sour Fern Root Noodles', 'Staples', 'Hot and sour fern root noodles are smooth and chewy, with a tangy and spicy flavor that whets the appetite. They are a home-style cold dish and can also be enjoyed as a main course. Fern root powder is rich in starch and dietary fiber, providing energy for the body. This dish is extremely simple to make and very beginner-friendly, taking only 10 minutes from prep to finish.', '[{"name":"Fern root noodles","note":"as needed"},{"name":"Chili oil","note":"as needed"},{"name":"Soy sauce","note":"as needed"},{"name":"Vinegar","note":"as needed"},{"name":"Bird''s eye chili peppers","note":"as needed"},{"name":"Garlic","note":"as needed"},{"name":"Scallions","note":"as needed"},{"name":"Salt","unit":"gram"},{"name":"Sugar","unit":"gram"}]'::jsonb, '["Fill a pot with water to about 3/5 of its depth and bring to a boil.","Once the water is boiling, add the fern root noodles and cook over medium-low heat for 8 minutes.","Remove from heat and drain.","According to the ratio, add soy sauce, vinegar, and chili oil.","Dip a chopstick and taste a bit.","If the soy sauce flavor is too strong, add the prepared salt.","If it''s not savory enough, add the prepared sugar.","Stir well until most of the granular seasonings dissolve.","Take a bowl.","Add the sauce prepared in the previous step.","Rinse the fern root noodles under cold water, then add them to the sauce.","Stir well.","Chop the prepared scallions, garlic, and bird''s eye chili peppers and sprinkle over the noodles.","Done! (｡･∀･)ﾉﾞ"]'::jsonb, '["Main Course","Hot and Sour","Cold Dish","Quick","Home-style","Appetizing"]'::jsonb),
  ('howtocook:staple/醪糟小汤圆', 'en', 'Small Tangyuan in Fermented Rice Wine', 'Staples', 'Small tangyuan in fermented rice wine is a traditional Chinese dessert that is sweet, soft, and glutinous. The slight acidity of the fermented rice blends with the smoothness of the glutinous rice, warming the stomach and comforting the heart. It is rich in carbohydrates and contains a small amount of B vitamins, quickly replenishing energy and helping to promote blood circulation. The method is easy, especially friendly for beginners. From boiling water to serving, it takes only about 15 minutes. It''s a home-style sweet soup that can be easily made anytime.', '[{"name":"Water","unit":"milliliters"},{"name":"Small glutinous rice balls","unit":"grams"},{"name":"Fermented rice","unit":"grams"},{"name":"Goji berries","unit":"pieces"},{"name":"White sugar","note":"to taste"}]'::jsonb, '["Pour water into a pot and bring to a boil.","Add the small glutinous rice balls and cook for 8 minutes.","Add the fermented rice and goji berries, then cook for another 2 minutes.","Ladle into a bowl, add sugar to taste and stir well.","Enjoy."]'::jsonb, '["Staple","Sweet","Soft and glutinous","Boiled","Quick","Home-style"]'::jsonb),
  ('howtocook:staple/陕西油泼面/陕西油泼面', 'en', 'Shaanxi Oil-Splashed Noodles', 'Staples', 'This traditional Northwestern noodle dish is famous for its chewy hand-pulled noodles and the spicy aroma from splashing hot oil. It is a well-known daily staple in Shaanxi. The noodles are rich in carbohydrates, and with greens and bean sprouts, they quickly replenish energy with a balanced diet. The whole process is straightforward and beginner-friendly, taking about 30 minutes from prep to serving.', '[{"name":"Fresh noodles (hand-pulled preferably)","unit":"piece"},{"name":"Salt","unit":"g"},{"name":"Green onion","unit":"piece"},{"name":"Garlic","unit":"clove"},{"name":"Dried chili flakes (or Qin pepper powder)","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Black vinegar","unit":"ml"},{"name":"Greens","unit":"g"},{"name":"Bean sprouts","unit":"g"},{"name":"Sichuan peppercorns","note":"to taste"},{"name":"Star anise","note":"to taste"},{"name":"Cinnamon stick","note":"to taste"},{"name":"Bay leaves","note":"to taste"},{"name":"Sesame seeds","note":"to taste"}]'::jsonb, '["For hand-pulled noodles, use a rolling pin (or your hands if you don''t have one) to lightly press the dough from top to bottom, then hold the left and right ends and gently pull apart.","Finely chop the green onion, mince the garlic, and set aside.","Wash the greens and bean sprouts, and set aside (if using).","Add enough water to a pot, bring to a boil over high heat, then add 1g salt.","Add the noodles, gently stir with chopsticks to prevent sticking, and cook until they float, then cook for 1-2 more minutes.","In the last minute of cooking, blanch the greens and bean sprouts.","Remove the cooked noodles, greens, and bean sprouts, drain well, and place in a bowl.","On top of the noodles, add light soy sauce, black vinegar, chopped green onion, minced garlic, and dried chili flakes. You can also add some sesame seeds.","Pour cooking oil into a wok, add Sichuan peppercorns, star anise, cinnamon, and bay leaves (if using). Fry over low heat until fragrant, then remove the spices.","When the oil reaches about 70% hot (starting to smoke slightly), quickly and evenly pour it over the chili flakes in the bowl. You should hear a sizzling sound.","Use chopsticks to thoroughly mix all the seasonings with the noodles, and serve."]'::jsonb, '["Staple","Shaanxi","Noodles","Spicy","Quick","Home-style"]'::jsonb),
  ('howtocook:staple/韩式拌饭/韩式拌饭', 'en', 'Korean Bibimbap', 'Staples', 'Korean bibimbap is a colorful and flavorful Korean home-style dish, with sweet and spicy sauce coating rice, vegetables, beef, and a sunny-side-up egg. Mix it all together for a satisfying bite. The variety of vegetables provides vitamins and dietary fiber, while beef and eggs supply high-quality protein, making it nutritionally balanced. It''s simple to make, though the prep steps are a bit many. Even beginners can handle it with ease. It takes about 45 minutes from prep to serving.', '[{"name":"Rice","unit":"bowl"},{"name":"Egg","unit":"piece"},{"name":"Beef rolls","unit":"roll"},{"name":"Bean sprouts","unit":"g"},{"name":"Mushrooms","unit":"g"},{"name":"Carrot","unit":"piece"},{"name":"Zucchini","unit":"g"},{"name":"Korean chili paste","unit":"ml"},{"name":"Sprite","unit":"ml"},{"name":"Sesame seeds","unit":"g"},{"name":"Sesame oil","unit":"ml"},{"name":"Soy sauce","unit":"ml"},{"name":"Salt","note":"to taste"}]'::jsonb, '["Wash vegetables, cut into strips, stir-fry in a pan until softened, then set aside.","Boil water, when it boils, blanch the beef rolls until cooked through, about three minutes, then remove.","Fry a sunny-side-up egg.","Place rice in a bowl and then invert onto a large bowl.","Arrange the prepared vegetables and beef rolls in a circle on top of the rice, and place the fried egg in the center.","Prepare the sauce.","10ml Korean chili paste (sweet and spicy) + 5ml soy sauce + two bottle caps of Sprite (use Sprite Zero if dieting) + 10g sesame seeds + 5ml sesame oil.","Stir the above sauce, you can add more soy sauce and salt to taste.","Pour the prepared sauce over the arranged bowl."]'::jsonb, '["Main Course","Korean","Sweet and Spicy","Home-style","Goes with Rice","Mixed"]'::jsonb),
  ('howtocook:staple/韭菜盒子', 'en', 'Chive Boxes', 'Staples', 'Chive boxes are a traditional Chinese pastry, with a golden and crispy outer crust and a savory, juicy filling. Chives paired with shrimp and eggs are rich in vitamins and high-quality protein. The recipe is simple and beginner-friendly, taking about 2.5 hours from kneading to serving.', '[{"name":"Chives","unit":"g"},{"name":"Shrimp (peeled)","unit":"g"},{"name":"Eggs","unit":"pieces"},{"name":"Sesame oil","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Flour","unit":"g"}]'::jsonb, '["Place the flour in a large bowl, add water, and mix into a smooth dough. Let it rest for 30 minutes.","Wash and chop the chives, add beaten eggs and 5g salt, mix well.","Divide the dough into small pieces, roll into thin rounds, and wrap with chive, shrimp, and egg mixture.","Heat a pan, add cooking oil, place the wrapped chive boxes, and fry until both sides are golden, about 3-4 minutes.","Transfer to a plate, let cool slightly, and enjoy."]'::jsonb, '["Staple","Savory","Pan-fried","Home-style","Chinese pastry"]'::jsonb),
  ('howtocook:staple/鲜肉烧卖', 'en', 'Pork Siu Mai', 'Staples', 'This is a delicate Jiangnan-style dim sum with paper-thin wrappers and juicy, generous filling. When bitten into, the flavors of meat, bamboo shoots, and melted skin jelly combine in a savory-sweet broth, with a tender and springy texture. Pork and shrimp provide high-quality protein, while winter bamboo shoots and shiitake mushrooms add dietary fiber and trace elements. The low-fat version further reduces saturated fat. Although wrapping requires some patience, the steps are clear and beginners can master it with practice. From mixing the filling to serving takes about an hour.', '[{"name":"Siu Mai wrappers","unit":"g"},{"name":"Ground pork (70% lean, 30% fat)","unit":"g"},{"name":"Pork tenderloin or front leg (for low-fat version)","unit":"g"},{"name":"Minced ginger","unit":"g"},{"name":"Minced scallion (green parts only)","unit":"g"},{"name":"Light soy sauce","unit":"mL"},{"name":"Cooking wine","unit":"mL"},{"name":"Salt","unit":"g"},{"name":"Sugar (optional)","unit":"g"},{"name":"White pepper (optional)","unit":"g"},{"name":"Sesame oil","unit":"mL"},{"name":"Broth","unit":"mL"},{"name":"Bouillon cube","unit":"g"},{"name":"Winter bamboo shoots (optional)","unit":"g"},{"name":"Skin jelly (optional but recommended)","unit":"g"},{"name":"Shiitake mushrooms (optional)","unit":"g"},{"name":"Dried shiitake mushrooms (rehydrated, optional)","unit":"g"},{"name":"Shrimp (optional)","unit":"g"},{"name":"Composite food thickener (for low-fat version)","unit":"g"},{"name":"Cornstarch (for low-fat version)","unit":"g"},{"name":"Lard (or chicken fat) (for low-fat version)","unit":"g"}]'::jsonb, '["(Low-fat version) Take 10 mL cold water, add composite food thickener, and mix into a paste.","(Low-fat version) Add 25 mL boiling water, stir until a translucent gel forms.","(Low-fat version) After cooling, mix in 280 g lean ground meat + 15 g melted lard (or chicken fat).","Mix ground pork with minced ginger and scallion. Add light soy sauce, cooking wine, salt, sugar, and white pepper. Stir in one direction until the mixture becomes sticky.","If using bouillon cube, dissolve it in 15 mL hot water, stir until the emulsion is fully dispersed, then add 15 mL room-temperature water.","Gradually add water or broth while stirring until the filling absorbs liquid and becomes thick. If too thick, add 5 mL more water and continue stirring.","Add optional ingredients (bamboo shoots, skin jelly, mushrooms). Finally, drizzle with sesame oil and mix well. Refrigerate for 30 minutes to let flavors meld.","Take one siu mai wrapper and place about 20-25 g of filling (don''t overfill, or it won''t close).","Gently gather the wrapper edges with your thumb and index finger to form a ''vase'' shape, leaving an opening at the top.","Gently press the bottom to ensure it stands stable.","If using shrimp, add one shrimp on top.","Repeat the wrapping steps until all are done.","Place in steamer basket, spaced apart to avoid sticking.","Steam over high heat for 8-10 minutes."]'::jsonb, '["Main Dish","Jiangnan-style","Savory","Steamed","Party snack","Thin wrapper, generous filling","Low-fat option"]'::jsonb),
  ('howtocook:staple/鲣鱼海苔玉米饭/鲣鱼海苔玉米饭', 'en', 'Bonito Flakes, Seaweed, and Corn Rice', 'Staples', 'This is a savory and delicious Japanese quick meal. The rice grains are distinct, blending the salty umami of bonito flakes, the crispy aroma of seaweed, and the sweet crunch of corn. Bonito flakes are rich in high-quality protein and DHA, paired with the minerals in seaweed and dietary fiber in corn, offering balanced nutrition. The method is very simple, easily completed by beginners. Actual hands-on time is only 5 minutes, plus cooking rice, about 40 minutes total to enjoy.', '[{"name":"Rice","note":"appropriate amount"},{"name":"Corn kernels","unit":"g"},{"name":"Bonito flakes and seaweed sprinkles","unit":"g"}]'::jsonb, '["Scoop the rice, add corn kernels, and mix well.","Add bonito flakes and seaweed sprinkle."]'::jsonb, '["Main Course","Japanese","Quick","Savory","Home-style","Simple Meal"]'::jsonb),
  ('howtocook:staple/鹰嘴豆炸饼', 'en', 'Chickpea Curry with Fried Flatbread', 'Staples', 'Chickpea curry with fried flatbread is a classic North Indian street snack. The soft fried bread paired with spiced chickpeas offers rich textures and sour, spicy, salty flavors. Chickpeas are high in plant protein and dietary fiber, making it filling and nutritious. The steps are a bit many, but following the process is not difficult, suitable for home cooking with some basic skills. About 50 minutes to complete (chickpeas need to be soaked for 8 hours in advance).', '[{"name":"Dried chickpeas","unit":"g"},{"name":"Onion","unit":"piece"},{"name":"Tomato","unit":"piece"},{"name":"Ginger","unit":"g"},{"name":"Garlic","unit":"clove"},{"name":"Green chili","unit":"stalk"},{"name":"Cooking oil (for curry)","unit":"ml"},{"name":"Black tea bag (for coloring chickpeas)","unit":"piece"},{"name":"Turmeric powder","unit":"g"},{"name":"Red chili powder","unit":"g"},{"name":"Coriander powder","unit":"g"},{"name":"Cumin powder","unit":"g"},{"name":"Salt (for curry)","unit":"g"},{"name":"Garam masala","unit":"g"},{"name":"Pomegranate powder","unit":"g"},{"name":"Lemon juice","unit":"ml"},{"name":"Water","unit":"ml"},{"name":"All-purpose flour","unit":"g"},{"name":"Yogurt","unit":"ml"},{"name":"Cooking oil (for dough)","unit":"ml"},{"name":"Baking soda","unit":"g"},{"name":"Salt (for dough)","unit":"g"},{"name":"Warm water","unit":"ml"},{"name":"Cooking oil (for frying)","unit":"ml"},{"name":"Cilantro","note":"to taste"},{"name":"Lemon wedges","note":"to taste"}]'::jsonb, '["Soak the dried chickpeas in water overnight (at least 8 hours); the volume will roughly double after soaking.","Drain the soaked chickpeas.","Put them in a pot, add 500ml water and 1 black tea bag (for coloring).","Bring to a boil over high heat, then reduce to medium heat and cook for 25-30 minutes, until the chickpeas can be easily crushed with fingers.","Remove the tea bag and reserve the cooking liquid; set aside.","In a wok, heat 30ml cooking oil over medium heat.","Add the chopped onion and sauté until golden brown (about 6-8 minutes).","Add the grated ginger and garlic, stir-fry for 1 minute.","Add the chopped tomato and stir-fry until the tomato is completely soft and oil separates (about 5 minutes).","Add 3g turmeric powder, 5g red chili powder, 8g coriander powder, 5g cumin powder, and 6g salt.","Stir-fry for 2 minutes to let the spices release their fragrance.","Pour the cooked chickpeas along with the reserved cooking liquid into the wok.","Add the green chili and stir well.","Bring to a boil over high heat, then reduce to low heat and simmer for 15-20 minutes, occasionally crushing some chickpeas with the back of a spoon to thicken the gravy.","Add 5g garam masala and 3g pomegranate powder (or 15ml lemon juice).","Stir well, then turn off the heat and set aside.","In a large bowl, mix 250g all-purpose flour, 2g baking soda, and 3g salt.","Add 60ml yogurt and 15ml cooking oil.","Gradually add warm water while kneading to form a smooth, soft dough (the dough should be slightly softer than regular dough).","Cover the dough with a damp cloth and let it rest for 30 minutes.","Divide the dough into 8 equal portions.","Take one portion, lightly oil your hands, and roll it into a circle about 15cm in diameter and 3mm thick.","In a deep pot, heat 500ml cooking oil over medium-high heat until it reaches about 180°C.","Gently slide the flatbread into the hot oil and use a slotted spoon to gently press it down so it puffs up.","Fry for 1-2 minutes, then turn over and fry until both sides are golden brown.","Remove and drain on paper towels to absorb excess oil.","Reheat the chickpea curry.","Serve the fried flatbread hot with the chickpea curry.","It can be accompanied by sliced onions, green chilies, and lemon wedges."]'::jsonb, '["Main Dish","North Indian","Street Snack","Sour Spicy Salty","Fried","Filling"]'::jsonb),
  ('howtocook:staple/麻油拌面', 'en', 'Sesame Oil Noodles', 'Staples', 'Rich aroma of sesame oil, simply seasoned with dark soy sauce and white pepper, savory and satisfying. A time-saving and budget-friendly homemade noodle dish. Noodles provide ample carbohydrates, sesame oil contains unsaturated fatty acids and vitamin E, replenishing energy. Super easy to make, even beginners can handle it. From boiling water to mixing, it takes only about ten minutes.', '[{"name":"Water","unit":"liter"},{"name":"Instant noodles","unit":"piece"},{"name":"Sesame oil","unit":"ml"},{"name":"Dark soy sauce","unit":"g"},{"name":"Salt","unit":"g"},{"name":"White pepper","unit":"g"},{"name":"Light soy sauce","unit":"g"}]'::jsonb, '["Pour water into a pot and bring to a boil (If you like chewy noodles, add 30g salt to the water; noodles boiled in salted water will be more chewy).","Add the instant noodles to the pot and cook for 3 minutes (or follow the cooking time on the package).","When the noodles start to loosen, stir to ensure even heating.","Drain the noodles and transfer to a bowl.","Add sesame oil, dark soy sauce, white pepper, and light soy sauce (optional) according to the measurements above.","Stir well with chopsticks.","A simple and budget-friendly lazy sesame oil noodle is done!"]'::jsonb, '["Staple","Savory","Mixed","Quick","Homestyle"]'::jsonb),
  ('howtocook:staple/麻辣减脂荞麦面', 'en', 'Spicy Weight-Loss Buckwheat Noodles', 'Staples', 'The spicy and numbing broth combines hot pot base with peanut butter and milk, creating a rich and smooth texture with bold Sichuan flavors. Paired with high-fiber buckwheat noodles and fresh vegetables, it''s low-calorie and filling, perfect for a weight-loss diet. The method is foolproof, no cooking skills required, and the whole process takes about 20 minutes from start to eating straight from the pot.', '[{"name":"Semi-dried buckwheat noodles","unit":"g"},{"name":"Baby bok choy","unit":"pieces"},{"name":"Lettuce","unit":"pieces"},{"name":"Peanut butter","unit":"g"},{"name":"Whole milk","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Chili oil","unit":"ml"},{"name":"Vinegar","unit":"ml"},{"name":"Sichuan peppercorn oil","unit":"ml"},{"name":"Water","unit":"ml"}]'::jsonb, '["Wash the baby bok choy and lettuce, set aside.","Pour 500ml water into the pot, turn to high heat, add the buckwheat noodles and baby bok choy, wait for the water to boil.","After the water boils, reduce to low heat, add the hot pot base, peanut butter, milk, light soy sauce, and chili oil. Once it boils again, cook for 5 minutes.","Add the lettuce, cook for another 2 minutes.","Add vinegar and Sichuan peppercorn oil, turn off the heat, and eat directly from the pot."]'::jsonb, '["Main Dish","Spicy and Numbing","Savory","Quick","Weight Loss","Low Calorie","Noodle Soup"]'::jsonb),
  ('howtocook:vegetable_dish/上汤娃娃菜/上汤娃娃菜', 'en', 'Baby Cabbage in Broth', 'Vegetarian', 'This baby cabbage in broth is sweet, fresh, and tender. It''s a home-style vegetable dish, especially suitable during dieting. Baby cabbage is rich in vitamins and dietary fiber, low in fat and calories. Combined with century eggs and luncheon meat, it adds flavor without too much burden. The difficulty is moderate; beginners can try it. From prep to serving takes about 20 minutes.', '[{"name":"Baby Cabbage","unit":"g"},{"name":"Enoki Mushrooms","unit":"g"},{"name":"Century Eggs","unit":"piece"},{"name":"Luncheon Meat (Ham Sausage)","note":"to taste"},{"name":"Scallions","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Garlic","unit":"g"},{"name":"Salt","note":"to taste"},{"name":"Sugar","note":"to taste"},{"name":"Starch","note":"to taste"}]'::jsonb, '["Wash the baby cabbage, cut vertically into sections.","Cut 3g scallions into small segments. Slice 10g garlic. Slice 10g ginger into small pieces.","Dice the century eggs, dice the ham sausage or luncheon meat into 1cm cubes.","Wash and shred the enoki mushrooms.","Boil water, blanch the baby cabbage for ten seconds, then remove.","Heat the pan with cold oil, swirl to coat, then pour out, and add a little fresh oil.","Reduce to low heat, add scallions, ginger, garlic, and stir-fry until fragrant.","Add about 300g water (enough to submerge the baby cabbage), then add baby cabbage, enoki mushrooms, and luncheon meat.","Add seasonings: oyster sauce, sugar, salt, MSG, and bring to a boil.","Cook for 3 minutes. After boiling, plate: arrange baby cabbage, top with century eggs, and pour the broth over.","Baby Cabbage in Broth"]'::jsonb, '["Vegetable Dish","Light","Home-style","Quick","Braising","Low-fat","Savory"]'::jsonb),
  ('howtocook:vegetable_dish/乾隆白菜/乾隆白菜', 'en', 'Qianlong Cabbage', 'Vegetarian', 'Qianlong Cabbage is a classic Beijing-style cold dish. Hand-torn cabbage hearts are coated in a thick sesame paste dressing, resulting in a sweet, sour, crisp, and refreshing flavor that is rich and appetizing. Cabbage is rich in vitamins and dietary fiber, while sesame paste provides quality fats and calcium. No cooking or stir-frying is required—just mix the dressing and toss. It''s beginner-friendly and can be served in about 10 minutes.', '[{"name":"Tender Napa cabbage leaves","unit":"grams"},{"name":"Sesame paste","unit":"grams"},{"name":"Black vinegar","unit":"ml"},{"name":"White sugar","unit":"grams"},{"name":"Sesame oil","unit":"ml"},{"name":"Salt","unit":"grams"},{"name":"Toasted white sesame seeds","unit":"grams"}]'::jsonb, '["Take only the inner tender leaves (yellow part) of the Napa cabbage, discard the stems, and tear into palm-sized pieces by hand. Do not use a knife (the rough torn surface holds the sauce better).","Rinse the torn cabbage leaves thoroughly and drain well. Any residual water will prevent the sauce from adhering.","In a bowl, add 30g sesame paste. First add 45ml black vinegar. Stir in one direction to gradually thin the paste until it drips in a thin stream (do not stir back and forth, as it may cause the sesame paste to separate oil).","Add 5g white sugar to the sesame paste dressing and stir well. Then add 1g salt and stir well. Finally, add 5ml sesame oil and stir well (add each seasoning separately and stir each time, checking the consistency as you go).","Evenly pour the prepared dressing over the cabbage leaves. Gently toss with your hands to coat every leaf.","Sprinkle with toasted white sesame seeds, plate, and serve. If time allows, let it rest for 5 minutes to allow flavors to meld."]'::jsonb, '["Vegetarian Dish","Beijing-style","Sweet and Sour","Cold Dish","Appetizing","Quick","Home-Style"]'::jsonb),
  ('howtocook:vegetable_dish/凉拌木耳/凉拌木耳', 'en', 'Cold Mixed Wood Ear Mushrooms', 'Vegetarian', 'Cold Mixed Wood Ear Mushrooms: Since the distributed supplies include many dried goods, wood ear mushrooms are a relatively healthy food. Also, the cooking method for cold mixed wood ear mushrooms is relatively simple.', '[{"name":"Dried wood ear mushrooms","unit":"g"},{"name":"Fresh wood ear mushrooms","unit":"g"},{"name":"Garlic cloves","unit":"cloves"},{"name":"Xiaomi chili peppers","unit":"pieces"},{"name":"Salt","unit":"g"},{"name":"Sugar","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Vinegar","unit":"ml"},{"name":"Sesame oil","unit":"ml"},{"name":"Wasabi","unit":"cm"}]'::jsonb, '["Soak dried wood ear mushrooms in about 400ml water for about 45 minutes. (Skip this step if using fresh wood ear mushrooms.)","Remove the roots from the soaked wood ear mushrooms (as shown in pictures 4, 5, 6), and wash thoroughly.","Bring water to a boil in a pot, add the wood ear mushrooms, and cook on high heat for 1.5-2 minutes.","Mince the garlic cloves and Xiaomi chili peppers, put them in a bowl (medium or large), then add salt, sugar, light soy sauce, vinegar, sesame oil, and wasabi in order, using the amounts listed above.","Remove the wood ear mushrooms, drain well, and add them to the bowl from the previous step.","Mix thoroughly and serve on a plate."]'::jsonb, '["Vegetarian Dish","Cold Dish","Quick","Sour and Spicy","Appetizing","Home-style"]'::jsonb),
  ('howtocook:vegetable_dish/凉拌油麦菜', 'en', 'Cold Mixed Celtuce', 'Vegetarian', 'A refreshing and non-greasy home-style cold dish. The rich sesame paste coats the crispy and tender celtuce, blending sweet, sour, salty, and aromatic flavors, making it very appetizing. Celtuce is rich in vitamins and dietary fiber, while sesame paste provides calcium and healthy fats, offering balanced nutrition. The method is effortless: just cut and mix. From preparation to serving, it takes only about ten minutes, making it especially suitable for beginners or quick meals on busy days.', '[{"name":"celtuce","unit":"head"},{"name":"vinegar","unit":"ml"},{"name":"soy sauce","unit":"ml"},{"name":"sesame paste","unit":"ml"},{"name":"sesame oil","unit":"ml"},{"name":"sugar","unit":"g"},{"name":"oyster sauce","unit":"ml"},{"name":"garlic","unit":"head"},{"name":"salt","note":"to taste"}]'::jsonb, '["Smash garlic cloves and mince them.","Put vinegar, soy sauce, sesame paste, sesame oil, sugar, oyster sauce, and minced garlic into a bowl and stir well.","Cut celtuce into sections, each no longer than 4 cm.","Put the celtuce into a larger bowl, pour in the sauce from the bowl, and mix thoroughly."]'::jsonb, '["Vegetarian","Refreshing","Cold Mixed","Quick","Homestyle","Appetizing"]'::jsonb),
  ('howtocook:vegetable_dish/凉拌莴笋/凉拌莴笋', 'en', 'Cold Mixed Celtuce', 'Vegetarian', 'A crisp and refreshing cold mixed appetizer. After salting, the celtuce becomes extra tender and crunchy, with a slight spiciness that is very appetizing. Rich in vitamins and dietary fiber, low in calories. Simple to make, beginner-friendly. From prep to table in about 20 minutes; tastes even better chilled.', '[{"name":"Celtuce","unit":"piece"},{"name":"Radish","unit":"piece"},{"name":"Small red chili","unit":"piece"},{"name":"Ginger","unit":"slice"},{"name":"Garlic","unit":"clove"},{"name":"Salt","unit":"g"},{"name":"Cooking oil","unit":"ml"}]'::jsonb, '["Peel the celtuce and cut into small strips. Cut the radish into strips, put both in a large bowl, add salt, mix, and let sit for 10 minutes.","Rinse the celtuce with water 1-2 times.","Bring water to a boil in a pot, add celtuce, blanch for 1 minute, then drain and put into a large bowl.","Heat oil in a pan, add ginger slices, garlic cloves, and small red chilies, stir-fry for 30-45 seconds, then pour over the celtuce.","Mix well and serve on a plate."]'::jsonb, '["Vegetarian","Refreshing","Mildly spicy","Cold mixed","Quick","Home-style","Appetizing"]'::jsonb),
  ('howtocook:vegetable_dish/凉拌豆腐', 'en', 'Cold Tofu Salad', 'Vegetarian', 'This cold dish is refreshing and delicious, rich in plant protein and calcium, low-fat and healthy. It''s quick and easy to make, and beginners can finish it in 10 minutes.', '[{"name":"tofu","unit":"g"},{"name":"scallion","unit":"g"},{"name":"garlic","unit":"cloves"},{"name":"light soy sauce","unit":"ml"},{"name":"sesame oil","unit":"ml"},{"name":"vinegar","unit":"ml"},{"name":"sugar","unit":"g"},{"name":"chili oil","unit":"ml"}]'::jsonb, '["Cut the tofu into 2 cm cubes and set aside.","Add 500 ml drinking water to a pot and bring to a boil over high heat.","Put the tofu cubes in and cook for 1-2 minutes to remove the beany flavor and make the tofu firmer.","Remove the cooked tofu cubes, drain excess water, and place in a bowl.","Wash the scallions and cut into chopped scallions.","Peel the garlic and mince it.","In a clean small bowl, add 15 ml light soy sauce, 5 ml sesame oil, 5 ml vinegar (optional), 2 g sugar (optional).","Add the minced garlic.","Stir well until the sugar is fully dissolved and the sauce is well combined.","Pour the prepared sauce evenly over the tofu cubes.","Sprinkle the chopped scallions on top.","Drizzle 5 ml chili oil (optional) according to personal preference.","Gently mix with chopsticks or a spoon and serve."]'::jsonb, '["Vegetarian","Refreshing","Quick","Cold","Home-style","Low-fat"]'::jsonb),
  ('howtocook:vegetable_dish/凉拌金针菇', 'en', 'Cold Mixed Enoki Mushrooms', 'Vegetarian', 'Cold mixed enoki mushrooms is a simple and quick home-style appetizer salad, with a crisp, tender, and smooth texture, savory with a hint of sourness. Enoki mushrooms are rich in dietary fiber and various vitamins, and low in calories. The entire process only requires blanching and seasoning, very beginner-friendly, and can be prepared quickly even when busy. From prep to finish, it takes about 10 minutes.', '[{"name":"enoki mushrooms","unit":"g"},{"name":"scallions","unit":"g"},{"name":"garlic","unit":"clove"},{"name":"soy sauce","unit":"ml"},{"name":"vinegar","unit":"ml"},{"name":"sugar","unit":"g"},{"name":"sesame oil","unit":"ml"},{"name":"chili oil","unit":"ml"}]'::jsonb, '["Cut off the roots of the enoki mushrooms, rinse thoroughly under clean water, and set aside.","Wash the scallions, then cut into chopped scallions, and set aside.","Peel the garlic cloves, then mince into garlic paste, and set aside.","Add 1000 ml of drinking water to a pot, and bring to a boil over high heat.","Add the enoki mushrooms, and cook for 1-2 minutes until they become soft.","Remove the cooked enoki mushrooms, drain well, and place in a large bowl. Set aside.","In another clean small bowl, add 15 ml soy sauce, 10 ml vinegar, 3 g sugar (optional), and 5 ml sesame oil (optional).","Add the minced garlic.","Stir well until the sugar is fully dissolved and the sauce is evenly mixed.","Evenly pour the prepared sauce over the enoki mushrooms.","Sprinkle the chopped scallions on top.","According to personal preference, drizzle with 5 ml chili oil (optional).","Gently toss with chopsticks until well combined, then serve."]'::jsonb, '["Vegetarian dish","Cold mixed","Home-style","Quick","Appetizing","Refreshing","Savory"]'::jsonb),
  ('howtocook:vegetable_dish/凉拌黄瓜', 'en', 'Cucumber Salad', 'Vegetarian', 'This is a refreshing and appetizing home-style cold dish with a crisp texture and a tangy, savory flavor. Cucumbers are rich in water and vitamins, helping to clear heat and relieve summer heat, as well as beautifying the skin. The recipe is very simple, beginner-friendly: just crush, season, and marinate for 15 minutes. The whole process takes about 20 minutes.', '[{"name":"Cucumber","unit":"g"},{"name":"Vinegar"},{"name":"Soy sauce"},{"name":"Garlic","unit":"cloves"},{"name":"Sugar","unit":"g"},{"name":"Salt"},{"name":"Oyster sauce","unit":"ml"},{"name":"Sesame oil"}]'::jsonb, '["Using a kitchen knife, smash the cucumber flat, then chop into 3 cm pieces.","Place the chopped cucumber into a bowl.","Smash the garlic and chop into fine pieces.","Add 5 grams of sugar to the bowl, mix well, and marinate for 15 minutes (marinating with sugar makes it tastier and keeps the color fresh, preventing wilting).","Add vinegar, soy sauce, salt, oyster sauce, and garlic to the bowl in order, and mix well.","Pour sesame oil into the bowl and stir evenly."]'::jsonb, '["Vegetarian","Refreshing","Cold Dish","Quick","Home-style","Appetizing"]'::jsonb),
  ('howtocook:vegetable_dish/包菜炒鸡蛋粉丝/包菜炒鸡蛋粉丝', 'en', 'Stir-fried Cabbage with Eggs and Vermicelli', 'Vegetarian', 'Cabbage stir-fried with eggs and vermicelli is a savory and delicious home-style quick dish. The crispy sweet cabbage shreds, soft and chewy vermicelli, and tender scrambled eggs blend together, creating rich layers of texture. Cabbage is rich in vitamins and dietary fiber, eggs provide high-quality protein, and carrots add nutrition, making a balanced combination of vegetables and protein. Preparation requires soaking vermicelli in advance; the overall process has several steps but is not complicated, offering some challenge for beginners. From prep to serving, it takes about 1 hour and 20 minutes.', '[{"name":"Cabbage","unit":"head"},{"name":"Eggs","unit":"piece"},{"name":"Vermicelli","unit":"bundle"},{"name":"Carrot","unit":"piece"},{"name":"Rapeseed oil","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Oyster sauce","unit":"ml"},{"name":"Scallion","unit":"stalk"},{"name":"Garlic","unit":"clove"},{"name":"Dried chili","unit":"piece"}]'::jsonb, '["Shred carrots and cabbage; set aside.","First soak vermicelli in cold water for 1 hour, then put vermicelli in a pot, add boiling water, cook until softened, then drain and set aside.","Crack eggs into a bowl, add salt, and stir for 15 seconds.","Finely chop scallions, garlic, and dried chili peppers; set aside.","Heat oil in a wok, pour in eggs, scramble until cooked, then remove and set aside.","Add more oil, then add scallions, garlic, and dried chili peppers; stir-fry for 8 seconds.","Add shredded carrots and cabbage; stir-fry for 30 seconds.","Add the vermicelli.","Add seasonings: light soy sauce 15 ml, dark soy sauce 10 ml, oyster sauce 10 ml, salt 2 g.","Add the previously scrambled eggs; stir-fry for about 15 seconds.","Serve and plate."]'::jsonb, '["Vegetarian","Savory","Quick Stir-fry","Home-style","Goes well with rice","Quick"]'::jsonb),
  ('howtocook:vegetable_dish/印度土豆花菜', 'en', 'Indian Potato Cauliflower', 'Vegetarian', 'This Indian home-style vegetarian dish features dry, golden, and aromatic spices, with tender potatoes and slightly charred cauliflower edges, typical of North Indian cuisine. Potatoes and cauliflower are rich in dietary fiber and vitamin C, making it a balanced dish. Simple to make, beginner-friendly, takes about 25 minutes from prep to serving.', '[{"name":"potato","unit":"piece"},{"name":"cauliflower","unit":"piece"},{"name":"onion","unit":"piece"},{"name":"tomato","unit":"piece"},{"name":"ginger","unit":"g"},{"name":"garlic","unit":"clove"},{"name":"green chili","unit":"piece"},{"name":"coriander leaves","unit":"g"},{"name":"cooking oil","unit":"ml"},{"name":"cumin seeds","unit":"g"},{"name":"turmeric powder","unit":"g"},{"name":"red chili powder","unit":"g"},{"name":"coriander powder","unit":"g"},{"name":"garam masala","unit":"g"},{"name":"salt","unit":"g"}]'::jsonb, '["Peel the potatoes and cut into about 2 cm cubes.","Break the cauliflower into uniform small florets; cut large ones smaller with a knife.","Pour 30 ml cooking oil into a wok and heat over medium heat.","When the oil is hot, add 3 g cumin seeds and fry until they darken and become fragrant (about 10 seconds; be careful not to burn).","Add the chopped onion and stir-fry until translucent and slightly golden (about 3-4 minutes).","Add ginger, garlic, and green chili, and stir-fry for 1 minute.","Add the chopped tomato and stir-fry until soft and mushy (about 2-3 minutes).","Add 3 g turmeric powder, 3 g red chili powder, 5 g coriander powder, and 5 g salt.","Stir-fry for 1 minute to combine the spices with the vegetables.","Add the potato cubes and stir-fry for 2 minutes to coat them with spices.","Add the cauliflower florets and gently toss to combine.","Cover the wok, reduce heat to medium-low, and simmer for 12-15 minutes, opening and stirring every 3-4 minutes to prevent sticking.","When the potatoes can be easily pierced with a chopstick and the cauliflower has slight charred edges, sprinkle in 3 g garam masala.","Stir-fry for 1 minute.","Turn off the heat, garnish with coriander leaves, and serve."]'::jsonb, '["Vegetarian","North Indian","Spicy","Braised and stir-fried","Home-style","Rice companion"]'::jsonb),
  ('howtocook:vegetable_dish/印度葫芦丸子', 'en', 'Indian Bottle Gourd Kofta', 'Vegetarian', 'This North Indian vegetarian dish grates bottle gourd and mixes it with chickpea flour to form dumplings, which are deep-fried and then simmered in a tomato-onion curry. Crispy on the outside and soft inside, the rich and spicy sauce is flavorful. Bottle gourd is refreshing, and chickpea flour provides plant protein and dietary fiber, making it a filling and balanced vegetarian meal. The preparation involves frying and making the sauce; the steps are a bit many but easy to follow in order. The whole process takes about 40 minutes.', '[{"name":"Bottle gourd","unit":"piece"},{"name":"Chickpea flour","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Red chili powder","unit":"g"},{"name":"Coriander powder","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Onion","unit":"piece"},{"name":"Tomato","unit":"piece"},{"name":"Ginger","unit":"g"},{"name":"Garlic","unit":"clove"},{"name":"Green chili","unit":"piece"},{"name":"Cooking oil","unit":"ml"},{"name":"Turmeric powder","unit":"g"},{"name":"Red chili powder","unit":"g"},{"name":"Coriander powder","unit":"g"},{"name":"Cumin powder","unit":"g"},{"name":"Garam masala","unit":"g"},{"name":"Salt","unit":"g"},{"name":"Water","unit":"ml"},{"name":"Coriander leaves","unit":"g"}]'::jsonb, '["Peel the bottle gourd and grate it into fine shreds using a grater.","Squeeze out the water from the grated bottle gourd with your hands, as dry as possible, otherwise the dumplings won''t hold shape when fried.","Add 80g chickpea flour, 3g salt, 3g red chili powder, and 3g coriander powder to the squeezed bottle gourd.","Mix thoroughly with your hands and knead into a dough that doesn''t stick to your hands.","Roll the mixture into small balls about 3 cm in diameter, and set aside.","Pour 500ml cooking oil into a deep pot and heat over medium heat to about 170°C (test with a small piece of dough; it should quickly float and bubble).","Fry the balls in batches for 4-5 minutes until golden brown and crispy.","Drain the fried balls on paper towels to remove excess oil, and set aside.","Pour 30ml cooking oil into a wok or pan and heat over medium heat for 10 seconds.","Add chopped onion and stir-fry until golden brown (about 5-7 minutes).","Add grated ginger and garlic, and stir-fry for 1 minute until fragrant.","Add chopped tomatoes and stir-fry until fully softened and oil separates (about 5 minutes).","Add 3g turmeric powder, 5g red chili powder, 5g coriander powder, 3g cumin powder, and 5g salt.","Stir-fry for 2 minutes to blend the spices with the tomatoes.","Add 200ml water, stir well, bring to a boil, then reduce heat and simmer for 5 minutes.","Gently place the fried balls into the sauce and simmer on low heat for 3-5 minutes to let them absorb the sauce.","Sprinkle 3g garam masala and chopped green chilies.","Turn off the heat, garnish with coriander leaves, and serve."]'::jsonb, '["Vegetarian dish","North Indian","Spicy","Curry","Vegetarian","Entertaining"]'::jsonb),
  ('howtocook:vegetable_dish/地三鲜/地三鲜', 'en', 'Three Delicacies from the Earth', 'Vegetarian', 'Three Delicacies from the Earth is a classic home-style dish from Northeast China. The eggplant is soft and sticky, the potato is fluffy and fragrant, and the green pepper is crisp. The savory sauce with a hint of saltiness makes it a great accompaniment to rice. The combination of ingredients provides rich vitamins and dietary fiber, and the potato offers satisfying carbohydrate energy. This dish requires deep-frying and quick stir-frying, which demands some skill. Beginners may need a bit of practice. The entire process takes about 40 minutes.', '[{"name":"Eggplant","unit":"g"},{"name":"Potato","unit":"g"},{"name":"Green pepper","unit":"piece"},{"name":"Scallion","unit":"g"},{"name":"Ginger","unit":"g"},{"name":"Garlic","unit":"g"},{"name":"Broad bean paste","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Sugar","unit":"g"},{"name":"Cornstarch","unit":"g"}]'::jsonb, '["Wash the potato, eggplant, and green pepper.","Peel the potato.","Cut the eggplant and potato into irregular pieces of about 15g each.","Tear the green pepper along the grain into pieces about 25% larger than the potato and eggplant pieces.","Remove as much moisture from the green pepper surface as possible to avoid splattering during frying. Consider using a kitchen towel or air-drying for half an hour.","Cut the scallion into 0.5cm sections, totaling 5g. Mince the garlic into a paste, taking 15g, and divide into two portions of 7.5g each. Grate the ginger to make 5g.","In an empty bowl, combine 10ml light soy sauce, 10g sugar, 8g cornstarch, and 80ml water. Stir thoroughly to make the sauce mixture. Set aside.","Heat the wok and add 150ml oil.","Add the potato pieces and fry for about 3-4 minutes until golden brown and easily pierced with a chopstick.","Remove the potato pieces, leaving the oil in the wok.","Add the eggplant pieces and fry for about 2-3 minutes until they are about 70% done, soft, edges slightly charred, and excess oil rendered out.","Remove the eggplant pieces, leaving the oil (there may be little oil left).","If there is no flowing oil left in the wok, consider adding 15ml oil.","Add the green pepper pieces and fry for about 15 seconds until the edges start to blister, then remove immediately. Pour out the oil from the wok.","Reheat the wok and add 15ml fresh oil.","Add 5g scallion, 5g ginger, and 7.5g garlic. Stir-fry over medium-low heat until fragrant.","Add 15ml broad bean paste. Turn to low heat and stir-fry until the oil turns red and the paste is aromatic.","Pour in the sauce mixture. Immediately turn to high heat and stir rapidly to prevent burning. After about 10 seconds, the sauce will start to bubble and thicken.","Immediately add all the prepared potato, eggplant, and green pepper.","Stir-fry for 20 seconds to evenly coat the ingredients with the thick sauce.","Turn off the heat, sprinkle in 7.5g garlic. Toss to combine, then plate."]'::jsonb, '["Vegetarian","Northeast China","Home-style","Goes well with rice","Savory sauce","Pan-fried and stir-fried"]'::jsonb),
  ('howtocook:vegetable_dish/家常日本豆腐', 'en', 'Homestyle Japanese Tofu', 'Vegetarian', 'Homestyle Japanese Tofu is a quick and easy home-cooked dish with a crispy outside and tender inside. Golden crust wraps silky egg tofu, paired with green pepper, carrot, and other vegetables. It can be seasoned with savory or sweet and sour flavors, crispy and tender. Japanese tofu is mainly made from eggs, rich in high-quality protein, plus wood ear mushrooms and vegetables for balanced nutrition. It requires a bit of pan-frying skill, moderate difficulty, but beginners can try. It takes about 30 minutes to serve.', '[{"name":"Japanese tofu","unit":"克"},{"name":"Green pepper","unit":"克"},{"name":"Carrot","unit":"克"},{"name":"Ham sausage","unit":"克"},{"name":"Black wood ear mushrooms","unit":"克"},{"name":"Cornstarch","unit":"克"},{"name":"Onion","unit":"克"},{"name":"Garlic","unit":"克"},{"name":"Oil","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Oyster sauce","unit":"ml"},{"name":"Salt","unit":"克"},{"name":"Chicken bouillon","unit":"克"},{"name":"White sugar","unit":"克"},{"name":"Ketchup","unit":"ml"}]'::jsonb, '["Slice the carrot, cut the green pepper into thin pieces, mince the green onion and garlic.","Open the packaged Japanese tofu, cut into cylinders about 1 cm thick.","Put cornstarch in a flat plate, ready to coat the tofu.","Gently place the tofu on the cornstarch, coat both sides and edges, being careful not to coat too thickly.","Add 150 ml oil to a flat pan, enough to submerge most of the tofu. When the edges turn golden, flip and fry the other side.","When both sides are fried, remove and set aside on a clean plate.","Pour 10-15 ml oil into a wok, add green onion and garlic, stir-fry until fragrant, then add green pepper, carrot, ham sausage, and black wood ear mushrooms.","Add oyster sauce, light soy sauce, salt, chicken bouillon, white sugar, and ketchup.","Gently stir-fry until the colors are evenly distributed."]'::jsonb, '["Vegetarian","Pan-fried","Savory","Sweet and Sour","Quick","Rice-friendly"]'::jsonb),
  ('howtocook:vegetable_dish/小炒藕丁/小炒藕丁', 'en', 'Stir-fried Diced Lotus Root', 'Vegetarian', 'Stir-fried Diced Lotus Root is a quick home-style vegetarian dish. The lotus root cubes are crispy and tender, with a savory and slightly spicy flavor that goes great with rice. Lotus root is rich in dietary fiber and vitamins, helping to clear heat and moisten dryness. It''s easy to make; just pay attention to blanching the lotus root cubes and seasoning. Even a kitchen novice can do it. It takes about 20 minutes from start to finish.', '[{"name":"Scallion","unit":"segment"},{"name":"Millet pepper","unit":"piece"},{"name":"Lotus root","unit":"piece"},{"name":"Light soy sauce","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Oyster sauce","unit":"ml"},{"name":"Cooking oil","unit":"ml"}]'::jsonb, '["Cut the scallion and millet pepper into small sections and set aside.","Peel the lotus root and cut into pieces no larger than 3 cm. Place in water to prevent oxidation (darkening).","Take a wok, add 500 ml of cold water, and bring to a boil.","Blanch the lotus root cubes in the boiling water for 2 minutes, then remove and place in a plate, set aside.","Pour out the water from the wok, heat the wok until dry, then add 10-15 ml of cooking oil.","When the oil is hot, add the scallion sections and millet pepper, stir-fry until fragrant.","Add the blanched lotus root cubes and stir-fry over high heat.","Add light soy sauce, dark soy sauce, and oyster sauce.","Stir-fry for 2 minutes, then serve."]'::jsonb, '["Vegetarian","Savory","Slightly Spicy","Quick Stir-fry","Home-style","Goes with Rice"]'::jsonb),
  ('howtocook:vegetable_dish/干锅花菜/干锅花菜', 'en', 'Dry Pot Cauliflower', 'Vegetarian', 'Dry Pot Cauliflower is a Hunan-style home-cooking dish. The cauliflower is tender and crisp, and the pork belly is rich and fragrant, with a slight spiciness. Cauliflower is rich in vitamin C and dietary fiber, while pork belly provides protein and energy. The cooking difficulty is moderate. Just make sure to drain the cauliflower thoroughly after blanching and render the fat from the pork belly. Suitable for beginners with some cooking experience. It takes about 40 minutes from preparation to serving.', '[{"name":"cauliflower","unit":"g"},{"name":"pork belly","unit":"g"},{"name":"red chili pepper","unit":"pieces"},{"name":"light soy sauce","unit":"ml"},{"name":"sugar","unit":"g"},{"name":"garlic","unit":"cloves"},{"name":"salt","unit":"g"},{"name":"oil","unit":"ml"}]'::jsonb, '["Submerge cauliflower florets stem-side down in lightly salted water for 20 minutes. Then rinse and break into small florets with a small knife.","Blanch in boiling water for 1 minute, remove and immediately rinse under cold water until completely cooled. Drain and set aside.","Slice pork belly thinly. Cut off the white part of garlic and smash with the flat side of a knife. Cut small red chili peppers into sections.","Heat oil in a wok over high heat. Add the white parts of scallion and stir-fry until fragrant.","Add pork belly slices and stir-fry over medium heat until the surface changes color. Continue stir-frying for a while to render some fat from the fatty parts.","Add red chili pepper sections and cauliflower. Stir-fry a few times.","Add 10 ml light soy sauce.","Then add 5 g sugar, turn to high heat and stir-fry continuously for 1 minute.","Cut the garlic leaves into sections, add to the wok. Stir-fry a few times, then turn off the heat, cover and let sit for 1 minute. Serve."]'::jsonb, '["Vegetable Dish","Hunan-style","Dry Pot","Home-style","Rice-appetizing","Dry-fragrant"]'::jsonb),
  ('howtocook:vegetable_dish/手撕包菜/手撕包菜', 'en', 'Hand-Torn Cabbage', 'Vegetarian', 'Hand-Torn Cabbage is a classic Hunan dish with a sour, spicy, and crispy taste. The cabbage is tender and flavorful, and the pork belly is dry-fried without being greasy. It''s a great appetizer that goes well with rice. Cabbage is high in vitamin C and fiber, and the pork belly provides protein and energy. The key is to stir-fry over high heat quickly. It might be a bit challenging for new cooks, but following the steps will ensure success. It takes about 20 minutes from prep to serving.', '[{"name":"Cabbage","unit":"head"},{"name":"Pork belly","unit":"g"},{"name":"Small chili pepper","unit":"piece"},{"name":"Cooking oil","unit":"ml"},{"name":"Cooking wine","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Black vinegar","unit":"ml"},{"name":"Chicken bouillon","unit":"g"},{"name":"Ginger","unit":"slice"},{"name":"Garlic","unit":"clove"},{"name":"Garlic sprout","unit":"piece"},{"name":"Salt","unit":"g"}]'::jsonb, '["Cut the cabbage in half, remove the white core in the middle 【see Figure 1】","Tear the cabbage into pieces by hand, put 2 g salt in a bowl, wash the cabbage and drain, set aside 【see Figure 2】","Prepare ginger slices, garlic cloves, small chili peppers, and garlic sprouts, set aside 【see Figure 3】","Slice the pork belly, wash with clean water, set aside","Add 30 ml cooking oil to the wok, add the cabbage and stir-fry over high heat for 1 minute, then add 3 g salt, continue stir-frying for 2 minutes, remove and set aside","Add 30 ml cooking oil to the wok, add the pork belly, stir-fry over high heat for 1 minute","Add the ginger slices and other ingredients, stir-fry for 1 minute","Add the cabbage and stir-fry, then add vinegar, cooking wine, chicken bouillon, cooking wine, continue stir-frying over high heat, remove from heat after 2 minutes"]'::jsonb, '["Vegetable Dish","Sour and Spicy","Stir-fry","Hunan Cuisine","Appetizing","Homestyle"]'::jsonb),
  ('howtocook:vegetable_dish/拔丝土豆/拔丝土豆', 'en', 'Candied Potatoes', 'Vegetarian', 'Candied Potatoes is a classic Shandong dish. The finished dish is golden, with long sugar threads, crispy outside and chewy inside, sweet and tasty. Potatoes are rich in carbs and vitamin C, giving a quick energy boost. This dish is a bit tricky; beginners should watch the sugar syrup temperature to avoid seizing or scorching. Prep to plate takes about 30 minutes.', '[{"name":"Potato","unit":"piece","note":""},{"name":"Cooking oil","unit":"ml","note":""},{"name":"Starch","unit":"g","note":""},{"name":"White sugar","unit":"g","note":""},{"name":"Water","unit":"ml","note":""},{"name":"Sesame seeds","unit":"g","note":""}]'::jsonb, '["Peel potatoes and cut into even small pieces. Add starch (without water) and toss to coat the potato surface.","Heat oil in a wok, add potato pieces, and gently fry and tumble for 5-7 minutes until a chopstick can pierce through.","Remove potatoes and set aside in a large bowl.","Add water and white sugar to the wok, stirring slowly in one direction until the sugar turns brown.","Pour the potatoes back in, stir-fry for 30 seconds, then remove from heat.","Transfer potatoes to a plate and sprinkle with sesame seeds."]'::jsonb, '["Vegetarian","Shandong","Candied","Sweet","Deep-fried","Home-style"]'::jsonb),
  ('howtocook:vegetable_dish/松仁玉米', 'en', 'Pine Nut Corn', 'Vegetarian', 'Pine Nut Corn is a quick and easy home-style dish with a sweet and crisp texture. The pine nuts are fragrant and crunchy, while the corn is sweet and juicy. It''s a beloved Northern Chinese home-style flavor. The combination of corn and pine nuts provides rich dietary fiber, unsaturated fatty acids, and various vitamins, making it nutritious and balanced. The method is simple, even beginners can handle it easily. It takes only about fifteen minutes from preparation to serving.', '[{"name":"Corn kernels","unit":"grams"},{"name":"Cooked pine nuts","unit":"grams"},{"name":"Carrot","unit":"grams"},{"name":"Cooking oil","unit":"ml"},{"name":"White sugar","unit":"grams"},{"name":"Salt","unit":"grams"},{"name":"Cornstarch","unit":"grams"},{"name":"Water","unit":"ml"}]'::jsonb, '["Blanch corn kernels and carrot cubes for 1 minute, then drain and set aside.","Heat oil in a pan, add carrot cubes and stir-fry briefly, then add corn kernels and stir-fry.","Add white sugar and salt, stir well.","Mix water and starch to make a slurry, pour into the pan and stir-fry quickly to slightly thicken the sauce.","Add cooked pine nuts and stir-fry evenly.","Transfer to a plate and serve."]'::jsonb, '["Vegetarian Dish","Light","Quick","Home-style","Northern Chinese Flavor","Stir-fry"]'::jsonb),
  ('howtocook:vegetable_dish/椒盐玉米/椒盐玉米', 'en', 'Pepper Salt Corn', 'Vegetarian', 'A flavorful snack with crispy outside and tender inside, salty and fragrant, with the dry-fragrant texture common in Sichuan restaurants. When bitten, the corn''s natural sweetness emerges. Corn provides abundant carbohydrates and dietary fiber, and with sesame seeds, it also adds high-quality fats and vitamin E. This dish has a few more steps but is simple to make, requiring patience to shake off water and coat with starch. It''s beginner-friendly. From thawing to serving takes about 30 minutes.', '[{"name":"Corn kernels","unit":"g"},{"name":"Starch","unit":"g"},{"name":"Pepper salt","unit":"g"},{"name":"Sesame seeds","unit":"g"},{"name":"Oil","note":"as needed"},{"name":"Plastic colander","unit":"piece"}]'::jsonb, '["Corn kernels are already shelled, just thaw them directly. Soak in warm water for 15 minutes or boil in hot water for 5 minutes.","Take out a colander, consider it as Box A, line with oil-absorbing paper, and pour in the thawed corn kernels.","shaking shaking shaking! - until the oil-absorbing paper is completely wet.","Take out a second colander Box B, line with oil-absorbing paper, and pour all the corn from Box A into Box B.","shaking shaking shaking! - until the oil-absorbing paper is completely wet.","Repeat the above operations multiple times until there are no visible water droplets on the corn surface but it remains moist.","Pour in a large amount of starch, enough to completely cover the corn kernels.","shaking shaking shaking! - until the starch coats the corn kernels.","Turn on the stove - place the pan - pour in oil, try to cover the bottom but not too much.","Oil at 80% heat, pour in the starch-coated corn kernels.","Fry on medium heat first for 30 seconds, do not stir, otherwise the starch will fall off.","Lightly stir-fry for 3 minutes, then remove from the pan.","The most important step: sprinkle 3g pepper salt, sprinkle sesame seeds!","Fragrant pepper salt corn is ready!"]'::jsonb, '["Vegetarian","Salty and fragrant","Crispy","Sichuan","Home-style","Quick"]'::jsonb),
  ('howtocook:vegetable_dish/榄菜肉末四季豆/榄菜肉末四季豆', 'en', 'Green Beans with Minced Pork and Olive Vegetables', 'Vegetarian', 'Green beans with minced pork and olive vegetables is a home-style stir-fry with strong Chaoshan flavor. It is salty, fragrant, crisp, and tender, making it a great appetizer. Green beans are rich in dietary fiber and vitamins, paired with minced pork for quality protein, while olive vegetables bring a unique savory flavor. The recipe steps are clear, and even beginners can quickly master it. Just ensure the green beans are thoroughly cooked. From preparation to serving, it takes about thirty minutes.', '[{"name":"green beans","unit":"grams"},{"name":"pork belly","unit":"grams"},{"name":"olive vegetables","unit":"grams"},{"name":"garlic","unit":"grams"},{"name":"bird''s eye chili","unit":"grams"}]'::jsonb, '["Wash the green beans, remove the strings, and cut into evenly sized pieces. Set aside.","Smash the garlic and chop into mince. Set aside.","Cut the bird''s eye chilies into evenly sized pieces. Set aside.","Remove the skin from the pork belly and mince it. Set aside.","Heat the wok, then add 20ml oil to coat the wok. After coating, pour out the hot oil, then add 10ml cold oil. This is the hot-wok-cold-oil technique, mainly to prevent the minced pork from sticking.","If you don''t have a grease container at home, you can skip the oil coating step. Add oil directly, then put in the minced pork and stir-fry over low heat for two minutes until the pork fat renders.","Once the minced pork is fragrant, add the garlic, olive vegetables, and bird''s eye chilies. Stir-fry until aromatic.","Add the green beans and stir-fry over medium heat for at least 5 minutes. Make sure the green beans are thoroughly cooked, otherwise they may cause food poisoning.","Once the green beans are cooked, drizzle 2ml of soy sauce along the side of the wok. Then add 2g salt, 1g chicken bouillon, 1g white pepper, and 0.5g sugar.","Stir-fry everything evenly to combine the seasonings.","Remove from heat and plate."]'::jsonb, '["Vegetable Dish","Salty and fragrant","Chaoshan","Rice accompaniment","Stir-fry"]'::jsonb),
  ('howtocook:vegetable_dish/水油焖蔬菜', 'en', 'Water-Oil Braised Greens', 'Vegetarian', 'Water-oil braised greens is a simple and quick home-style side dish. By adding a few drops of oil and seasonings to boiling water, the leafy greens become tender and glossy, refreshing yet with a light oily aroma. This method helps improve the absorption of fat-soluble vitamins, making it more nutritious than eating raw vegetables. The cooking difficulty is low, very beginner-friendly, and it generally takes only 10 minutes from washing to serving.', '[{"name":"Leafy greens","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Oyster sauce","unit":"ml"}]'::jsonb, '["Wash the greens","Add 150ml water to the pot and bring to a boil. (The water does not need to completely submerge the greens.)","Add 3g salt","(Optional) Add 3ml oyster sauce","Add 2ml cooking oil","Add the greens, toss briefly, then cover and simmer for 1 minute","Plate and serve"]'::jsonb, '["Vegetarian","Light","Braised","Quick","Home-style"]'::jsonb),
  ('howtocook:vegetable_dish/油醋爆蛋', 'en', 'Oil and Vinegar Scrambled Eggs', 'Vegetarian', 'This is a home-style quick dish full of Hunan flavor. Sour, spicy, fresh, and aromatic. The eggs are fluffy and golden, coated in a rich sauce that''s very appetizing. Eggs provide high-quality protein and lecithin, and the rice vinegar helps stimulate appetite. The method is extremely simple and beginner-friendly, taking only about ten minutes from prep to serving.', '[{"name":"egg","unit":"piece"},{"name":"bird''s eye chili","unit":"g"},{"name":"cooking oil","unit":"ml"},{"name":"scallion","unit":"g"},{"name":"garlic","unit":"g"},{"name":"rice vinegar","unit":"ml"},{"name":"light soy sauce","unit":"ml"},{"name":"oyster sauce","unit":"g"},{"name":"sugar","unit":"g"}]'::jsonb, '["Do not beat the eggs; crack them directly into a bowl and set aside.","Cut scallions into 3 cm sections.","Put garlic cloves and bird''s eye chilies into a garlic press and mince.","Add rice vinegar, light soy sauce, oyster sauce, sugar, and water to a small bowl, stir well to make the sweet and sour sauce.","Heat oil, pour in the eggs. Once set, break into large pieces with a spatula. Add minced garlic and chilies, then pour in the sweet and sour sauce.","Reduce the sauce over high heat. Just before serving, add the scallion sections."]'::jsonb, '["vegetarian","sour and spicy","quick","rice bowl","home-style","Hunan flavor"]'::jsonb),
  ('howtocook:vegetable_dish/洋葱炒鸡蛋/洋葱炒鸡蛋', 'en', 'Scrambled Eggs with Onion', 'Vegetarian', 'Scrambled Eggs with Onion is a savory and fragrant home-style dish with tender eggs and sweet onion. It''s a classic Chinese comfort food. Eggs are rich in high-quality protein and vitamins, while onions provide dietary fiber and antioxidants, making this a nutritious and quick dish. The preparation is extremely simple and beginner-friendly, taking only about 5 minutes from start to finish.', '[{"name":"Eggs","unit":"piece"},{"name":"Onion","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Scallion","unit":"stalk"},{"name":"Cooking wine","unit":"ml"}]'::jsonb, '["Crack eggs into a large bowl, add sliced onion and salt, then stir for 60 seconds.","Heat oil in a pan, pour in the eggs. Fry one side for 30-45 seconds, flip and continue to stir-fry. Repeat for 2-3 minutes, then sprinkle in cooking wine and remove from heat.","Plate the eggs and garnish with chopped green onions."]'::jsonb, '["Vegetarian","Savory","Home-style","Quick","Rice companion","Stir-fry"]'::jsonb),
  ('howtocook:vegetable_dish/清炒花菜', 'en', 'Stir-fried Cauliflower', 'Vegetarian', 'A common home-style vegetable dish, crisp and refreshing. Rich in vitamin C and dietary fiber. Simple and quick to make, a beginner can finish in just 15 minutes.', '[{"name":"cauliflower","unit":"g"},{"name":"garlic","unit":"clove"},{"name":"salt","unit":"g"},{"name":"cooking oil","unit":"ml"},{"name":"drinking water","unit":"ml"}]'::jsonb, '["Wash the cauliflower, cut or break into small florets, slice the thick stems, and set aside.","Peel the garlic and slice into pieces, set aside.","Add 1000 ml drinking water to the pot and bring to a boil over high heat.","Add the cauliflower florets, cook for 2-3 minutes until the color lightens and they become slightly tender.","Remove the cooked cauliflower, drain well, and set aside.","Heat the wok, add 15 ml cooking oil, and heat over high heat.","Add the garlic slices and stir-fry quickly until fragrant.","Add the blanched cauliflower florets, turn to medium-high heat, and stir-fry quickly for about 2 minutes to heat evenly.","Add 3 g salt and continue to stir-fry evenly.","Pour 50 ml drinking water along the edge of the wok, cover with lid, and simmer for 1 minute to help the cauliflower cook through and absorb flavor.","Uncover, stir-fry quickly and evenly, then serve."]'::jsonb, '["Vegetable dish","Light","Stir-fried","Home-style","Quick","Goes well with rice"]'::jsonb),
  ('howtocook:vegetable_dish/清蒸南瓜', 'en', 'Steamed Pumpkin', 'Vegetarian', 'A simple home-style steamed dish that retains the natural sweetness and nutrition of pumpkin. The texture is soft, sweet, and fragrant. It can be served as a dessert or a main course. Pumpkin is rich in beta-carotene and dietary fiber, benefiting vision and digestive health. Extremely easy to make; even beginners can handle it. From prep to serving, it only takes 15-20 minutes.', '[{"name":"Pumpkin","unit":"g"},{"name":"Drinking water","unit":"ml"}]'::jsonb, '["Wash the outside of the pumpkin and remove the pulp and seeds.","Cut the pumpkin into slices about 2 cm thick. Set aside.","Add 1000 ml of drinking water to the steamer pot.","Arrange the sliced pumpkin evenly on a plate.","Once the water in the steamer boils, place the plate with pumpkin into the steamer.","Cover the lid and steam over high heat for 15-20 minutes, until the pumpkin is soft and can be easily pierced with chopsticks.","Turn off the heat and carefully remove the plate."]'::jsonb, '["Vegetarian dish","Light","Steamed","Quick","Home-style","Vegan"]'::jsonb),
  ('howtocook:vegetable_dish/炒滑蛋/炒滑蛋', 'en', 'Silky Scrambled Eggs', 'Vegetarian', 'Silky scrambled eggs is a classic home-cooked dish with a tender, smooth texture and rich egg aroma, with a hint of milkiness. Eggs are rich in high-quality protein and various vitamins, nutritious and easy to absorb. The method is very friendly, even beginners can master it easily. From prep to serving takes only about 5 minutes, making it an ideal choice for a quick energy boost when busy.', '[{"name":"eggs","unit":"piece"},{"name":"milk","unit":"ml"},{"name":"cooking oil","unit":"ml"}]'::jsonb, '["Add milk and 5ml cooking oil to the eggs, mix well, and set aside.","Heat a non-stick pan over high heat for about 30 seconds, then add 5ml cooking oil.","After 30 seconds, reduce heat to low and pour in the egg mixture.","Let it sit for 5 seconds, then slowly push the egg mixture from the edges toward the center using a spatula.","Stir-fry until the eggs are mostly set, then turn off the heat and plate."]'::jsonb, '["vegetarian","savory","silky","quick","home-style","breakfast"]'::jsonb),
  ('howtocook:vegetable_dish/炒茄子', 'en', 'Stir-fried Eggplant', 'Vegetarian', 'This home-style stir-fried eggplant is tender and flavorful, with a rich sauce. Adding star anise enhances the flavor. Eggplant is rich in dietary fiber, vitamin P, and potassium, which help protect the cardiovascular system. The recipe is simple and beginner-friendly. Cook over high heat throughout; from prep to finish takes about 20 minutes.', '[{"name":"Eggplant","unit":"piece"},{"name":"Star anise (optional)","unit":"piece"},{"name":"Dried shrimp (optional)","unit":"handful"},{"name":"Scallion (optional)","unit":"piece"},{"name":"Ground meat (optional)","unit":"grams"},{"name":"Soy sauce","unit":"ml"},{"name":"Sugar (optional)","unit":"grams"},{"name":"Vinegar (optional)","unit":"ml"},{"name":"Rapeseed or peanut oil","note":"as needed"}]'::jsonb, '["Wash the eggplant, cut it into two sections lengthwise (vertical cut). Cut each section into diamond-shaped pieces. Place the cut eggplant in a bowl and set aside.","Wash the scallions, cut into chopped scallions, and place on the cutting board to set aside.","Cut the star anise and set aside on the cutting board.","If you plan to add ground meat, first stir-fry it over medium heat with 10 ml (if lean meat, use 15 ml) of oil until it changes color (about 1 minute), then set aside.","Heat the pan over high heat until there is no water in the pan.","Add cooking oil to the pan, enough to cover the bottom twice over (you can add more oil, but not less).","When the oil is about 60% hot, add the optional star anise, dried shrimp, and scallions.","If you do not have the optional ingredients like star anise, heat the oil until 90% hot.","When the oil in the pan is 90% hot, pour the eggplant from the bowl into the pan and stir-fry with a spatula.","After stir-frying for about 40 seconds, hold the spatula horizontally, parallel to the pan, and pour soy sauce onto the spatula. About 2.5 spatulafuls per person (you can add less soy sauce, but not more, as it will be salty).","When the eggplant becomes half-soft (about 1 minute later), add back the pre-fried ground meat and stir quickly to combine.","If you plan to add sugar and vinegar, add them.","Continue stir-frying.","When all the eggplant has changed color and become soft, remove from the pan."]'::jsonb, '["Vegetarian","Home-style","Quick","Rice Companion","Savory","High-heat Stir-fry"]'::jsonb),
  ('howtocook:vegetable_dish/炒青菜', 'en', 'Stir-fried Greens', 'Vegetarian', 'This is a refreshing and delicious home-style vegetable dish, with a crisp and tender texture, savory and slightly sweet. Greens are rich in vitamins and dietary fiber, which aid digestion. The method is very simple, even beginners can easily handle it, from prep to serving takes only about 10 minutes.', '[{"name":"Greens","unit":"grams"},{"name":"Garlic cloves","unit":"cloves"},{"name":"Cooking oil","unit":"ml"},{"name":"Salt","unit":"grams"},{"name":"Drinking water","unit":"ml"},{"name":"Sugar","unit":"grams"}]'::jsonb, '["Break the greens into small pieces, wash them in clean water, and set aside.","Mince the garlic cloves and set aside.","Heat the wok over medium-high or high heat, then add 10-15ml of cooking oil. Wait 30 seconds for the oil to heat up.","Pour the prepared greens into the wok and stir-fry until they soften (about 1 minute).","Add the minced garlic cloves.","Pour in the measured clean water, the water level should fully cover or just about cover the greens. Add salt (2g portions), and continue stir-frying for about 1 minute.","Finally, add sugar, reduce heat to low, cover with lid, and heat for 2 minutes.","Transfer to a plate."]'::jsonb, '["Vegetable dish","Light","Savory","Home-style","Quick","Stir-fried"]'::jsonb),
  ('howtocook:vegetable_dish/烤茄子/烤茄子', 'en', 'Roasted Eggplant', 'Vegetarian', 'Roasted eggplant is fragrant with a crispy outside and tender inside. The spicy aroma of cumin and minced garlic perfectly blends into the soft and sticky eggplant flesh. This dish brings street barbecue flavor easily at home. Eggplant is rich in vitamin P and anthocyanins, which help protect cardiovascular health and provide antioxidant benefits. The recipe requires an oven, but the steps are clear and beginners can finish it in about half an hour. It''s a perfect quick and tasty dish for family gatherings.', '[{"name":"Eggplant","unit":"piece"},{"name":"Cooking oil","unit":"ml"},{"name":"Soy sauce (light)","unit":"g"},{"name":"Bird''s eye chili","unit":"piece"},{"name":"Garlic cloves","unit":"clove"},{"name":"Cumin","unit":"g"},{"name":"Salt","unit":"g"}]'::jsonb, '["Place the soy sauce, cumin, salt, minced garlic, and chopped bird''s eye chili in a bowl, mix evenly and set aside.","Wash the eggplant and dry its surface with a paper towel.","Use a fork to poke 4-8 holes on one side of the eggplant.","Use 15-25ml of cooking oil to coat the entire surface of the eggplant.","Preheat the oven to 200°C (with fan on high heat), preheat for 2 minutes.","Place the eggplant on the middle or upper rack, roast for 12-15 minutes (until the eggplant skin wrinkles and you can press it down 0.3-0.5cm).","Remove the eggplant and use a knife to make a vertical slit in the center, leaving 1-1.5cm at both ends.","Insert a small knife or fork into the slit and cut the inside of the eggplant vertically.","Gently open the slit and pour in the sauce prepared in step 1.","Return the eggplant to the oven, set temperature to 200°C, and roast for 4-7 minutes.","Remove and turn off the oven."]'::jsonb, '["Vegetarian Dish","Garlicky","Cumin","Roasted","Quick","Home-style","Rice Companion"]'::jsonb),
  ('howtocook:vegetable_dish/白灼菜心/白灼菜心', 'en', 'Blanched Choy Sum', 'Vegetarian', 'This classic Cantonese dish uses the blanching technique—quickly boiling in water to retain the sweetness and crunch of choy sum, with particularly crisp stems. It is light and delicious, rich in vitamin C and dietary fiber, low in fat and calories, making it ideal for health-conscious diners. The method is very simple, with an estimated difficulty of only two stars; beginners can finish in just 15 minutes. It''s an excellent choice for a quick green vegetable fix.', '[{"name":"fresh choy sum","unit":"g"},{"name":"light soy sauce","unit":"g"},{"name":"oyster sauce","unit":"g"},{"name":"salt","unit":"g"},{"name":"garlic","unit":"cloves"},{"name":"bird''s eye chili","unit":"piece"},{"name":"cooking oil","unit":"g"}]'::jsonb, '["Wash the choy sum, remove the tougher or older parts of the roots. Use a knife to scrape the stems, removing the tough outer layer so the inner part is more tender. But note the blanching time for stems—if too long, they won''t be crisp.","Mince the garlic into small pieces. If you have onion, add a bit of chopped onion as well.","Prepare the soul sauce: 5g light soy sauce, 5g oyster sauce, add 3g sugar and 100g water (half a bowl to a full bowl of sauce).","Bring 500ml water to a boil with 5g salt and 10g cooking oil.","Blanch the choy sum stems in the boiling water for 1 minute, until they turn dark green. Then put the whole choy sum in the pot and cook for another 1 minute. Remove and arrange on a plate.","In another small pot, pour in the prepared sauce. Bring to a simmer over low heat. Add half the minced garlic, a little shredded ginger, and minced bird''s eye chili. While cooking, add a little chopped onion and garlic. First, pour oil into the pot, heat to 50% hot, then add the garlic and onion. Slightly fragrant, then add the sauce and bird''s eye chili. Bring to a boil.","Reduce the sauce slightly—after boiling, wait about ten seconds. Then pour directly over the choy sum. Don''t use too much sauce, but be generous with the garlic—don''t skimp."]'::jsonb, '["Vegetarian","Cantonese","Blanched","Light","Quick","Home-style"]'::jsonb),
  ('howtocook:vegetable_dish/皮蛋豆腐', 'en', 'Century Egg Tofu', 'Vegetarian', 'Century Egg Tofu is a refreshing and appetizing cold vegetarian dish. The century eggs are springy and smooth, while the silken tofu melts in your mouth. The savory and slightly sour flavor goes great with rice. Tofu is rich in plant protein and calcium, while century eggs provide iron, vitamin A, and other nutrients. Together, they are easy to digest. The process is almost zero-effort, even beginners can do it; from prep to serving takes only about 5 minutes.', '[{"name":"century egg","unit":"piece"},{"name":"silken tofu","unit":"box"},{"name":"light soy sauce","unit":"ml"},{"name":"white sugar","unit":"g"},{"name":"vinegar (recommend Zhenjiang vinegar)","unit":"ml"},{"name":"sesame oil (optional)","unit":"ml"},{"name":"chili oil (optional)","unit":"ml"},{"name":"crushed peanuts (optional)","unit":"g"},{"name":"chopped scallions (optional)","unit":"g"},{"name":"cilantro (optional)","unit":"stalks"}]'::jsonb, '["First, peel the century eggs and cut each into quarters.","Cut the silken tofu into pieces or slices and place in the middle.","Mix light soy sauce, white sugar, vinegar, sesame oil, and chili oil into a dressing, then pour over.","Finally, optionally sprinkle with crushed peanuts, chopped scallions, and cilantro."]'::jsonb, '["Vegetarian","Cold Dish","Quick","Home-style","Refreshing","Rice Companion"]'::jsonb),
  ('howtocook:vegetable_dish/糖拌西红柿/糖拌西红柿', 'en', 'Tomato Salad with Sugar', 'Vegetarian', 'This is a home-style cold dish suitable for summer. It''s sweet and sour, refreshing, and easy to make. Tomatoes are rich in vitamin C, appetizing and refreshing. Beginners can easily do it. The whole process (including refrigeration) takes about 15 minutes to serve.', '[{"name":"Tomato","unit":"piece"},{"name":"White sugar","unit":"gram"}]'::jsonb, '["Use a knife to score the tomato skin in a cross pattern.","Insert a chopstick into the bottom of the tomato, rotate over a gas flame for 10 seconds (or pour boiling water over it for 30 seconds) until the skin curls.","Peel off the skin completely.","Cut the tomato into eight pieces (cut along the lines to retain more juice), remove the stem and core, and set aside.","After all are cut, arrange a layer of tomatoes evenly on a plate.","Sprinkle with sugar, repeat the previous step until all tomatoes are placed.","Refrigerate for 10 minutes.","A plate of tomato salad with sugar is ready. Nutritious, delicious, sweet and sour, perfect for cooling down and refreshing in summer."]'::jsonb, '["Vegetarian","Sweet and sour","Cold dish","Home-style","Quick","Cooling"]'::jsonb),
  ('howtocook:vegetable_dish/红烧冬瓜/红烧冬瓜', 'en', 'Braised Winter Melon', 'Vegetarian', 'Braised Winter Melon is a home-style vegetarian dish with bright red color, savory and delicious taste, soft and glutinous texture that absorbs flavors well. It is a popular Chinese braised dish. Winter melon is rich in water, dietary fiber, and vitamin C. It has the effects of clearing heat, relieving summer heat, diuresis, and reducing swelling. With simple seasonings, it is nutritious and easy to digest. This dish is beginner-friendly with clear steps; just master the heat and seasoning. Estimated cooking time: about 25 minutes.', '[{"name":"Winter melon","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Cooking wine","unit":"ml"},{"name":"Starch","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Chicken bouillon","unit":"g"},{"name":"Scallion","unit":"stalk"},{"name":"Minced ginger","unit":"piece"},{"name":"Oyster sauce","unit":"ml"}]'::jsonb, '["Peel the winter melon, cut into small pieces no larger than 2cm per side.","Heat oil in a pan, add winter melon, gently fry and toss for 2 minutes until the surface turns golden.","Remove the winter melon, set aside in a large bowl.","Using the remaining oil in the pan, add minced ginger, light soy sauce, and oyster sauce in order, stir-fry for 15 seconds.","Return the winter melon to the pan, stir-fry for 30 seconds, then add boiling water to cover the winter melon, cook on high heat for 10 minutes.","Add dark soy sauce for color, continue cooking until the winter melon is soft and tender (a chopstick can easily pierce through it).","Add chicken bouillon, cooking wine, and scallions, stir-fry for 30 seconds, then remove the winter melon to a large bowl.","Keep the remaining sauce in the pan, add water starch, bring to a boil, then pour the sauce over the winter melon."]'::jsonb, '["Vegetarian","Braised","Savory","Home-style","Quick","Soft and tender"]'::jsonb),
  ('howtocook:vegetable_dish/红烧茄子', 'en', 'Braised Eggplant', 'Vegetarian', 'Braised eggplant is a savory and rich home-style dish that goes great with rice. The soft eggplant pieces soak up the sauce, paired with bell peppers and tomatoes for a tangy and slightly spicy flavor. Eggplant is rich in dietary fiber and vitamin P, and the fried pieces are fragrant without being greasy. The process involves coating and deep-frying, then slow-braising to infuse flavor. There are quite a few steps, but beginners can try it if they pay attention to details. From prep to serving takes about 45 minutes.', '[{"name":"garlic","unit":"clove"},{"name":"scallion","unit":"stalk"},{"name":"green chili pepper","unit":"piece"},{"name":"onion","unit":"piece"},{"name":"tomato","unit":"piece"},{"name":"green eggplant","unit":"piece"},{"name":"salt","note":"to taste"},{"name":"soy sauce","note":"to taste"},{"name":"egg","unit":"piece"},{"name":"flour","unit":"gram"},{"name":"starch","note":"to taste"}]'::jsonb, '["Wash the green eggplants, green chili peppers, tomatoes, onion, and scallions.","Cut the scallion into 5 mm wide rings. Peel and crush the garlic. Cut the tomato into 6 cm³ cubes. Cut the green chili peppers and onion into 5 g pieces.","Cut the eggplant into diamond-shaped pieces (first cut into 2 cm thick slices, then cut the slices into 2 cm strips, then cut diagonally into pieces...).","Pour the flour into a bowl. Gradually add a small amount of water, stirring until it forms a thick batter.","Add the starch and 30 g of water, stir until well combined.","Crack the egg into the bowl, add (flour/20) grams of salt, and stir until smooth.","Pour the eggplant pieces into the batter, stirring to coat each piece evenly.","Heat the wok over high heat, add 500 ml of oil. When the oil starts to shimmer (a wisp of smoke), reduce to low heat. Use chopsticks to carefully place the eggplant pieces into the oil. Once all pieces are in, turn to medium heat. Fry until golden brown, then remove and drain the oil.","Add (servings 5) g of oil, add the garlic and scallion, stir-fry for 15 seconds. Add the green chili pepper pieces and stir-fry for 30 seconds. Add the tomato and stir-fry for 30 seconds.","Add the fried eggplant pieces. Add water until it reaches 0.8 times the height of the ingredients in the wok.","Add soy sauce and (servings 3) g of salt.","Wait until the sauce thickens (the water level is about 0.2-0.3 times the height of the remaining ingredients). Remove the lid, plate the dish, and turn off the heat."]'::jsonb, '["Vegetarian Dish","Savory","Braised","Home-style","Goes with Rice","Deep-fried"]'::jsonb),
  ('howtocook:vegetable_dish/素炒豆角', 'en', 'Stir-fried Green Beans', 'Vegetarian', 'This is a home-style stir-fry with rich savory sauce. The green beans are tender and flavorful, with a hint of spiciness that pairs well with rice. Rich in dietary fiber and various vitamins, it aids digestion. Simple to make, even beginners can handle it easily. From prep to finish, it takes about 20 minutes.', '[{"name":"Green beans","unit":"g"},{"name":"Chili peppers","unit":"piece"},{"name":"Spring onion","unit":"ring"},{"name":"Garlic","unit":"clove"},{"name":"Light soy sauce","unit":"ml"},{"name":"Dark soy sauce","unit":"ml"},{"name":"Oyster sauce","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Oil","unit":"ml"},{"name":"Water","unit":"ml"}]'::jsonb, '["Chop the spring onion into rings and mince the garlic. Set aside.","Mix light soy sauce, dark soy sauce, oyster sauce, and salt to make the seasoning sauce. Set aside.","Slice the chili peppers into rings. Set aside.","Remove the strings from the green beans, cut diagonally at a 45° angle into 4-10 cm pieces. Set aside.","Heat oil (10-15 ml) in a wok until smoking, then add the spring onion and chili peppers. Stir-fry until fragrant.","Add the green beans and stir-fry for 30 seconds.","Add the seasoning sauce and stir-fry over high heat for 2 minutes.","Pour in 150 ml of water.","Reduce to medium-low heat, cover, and simmer for 8-10 minutes.","Add the minced garlic, then remove from heat and serve."]'::jsonb, '["Vegetarian","Savory","Stir-fried","Pairs well with rice","Quick","Home-style"]'::jsonb),
  ('howtocook:vegetable_dish/脆皮豆腐', 'en', 'Crispy Tofu', 'Vegetarian', 'Crispy tofu is crispy on the outside and tender on the inside, with a savory-sweet sauce that makes it a quick and satisfying dish. Tofu is rich in plant-based protein and calcium, while eggs provide high-quality protein, creating a balanced nutritional profile. Making it requires patience to achieve a golden crust, but the steps are clear and easy for beginners to follow. The entire process takes about 30 minutes.', '[{"name":"Firm tofu","unit":"block"},{"name":"Egg","unit":"piece"},{"name":"Light soy sauce","unit":"gram"},{"name":"Dark soy sauce","unit":"gram"},{"name":"Oyster sauce","unit":"gram"},{"name":"Sugar","unit":"gram"},{"name":"Cornstarch","unit":"gram"},{"name":"Cooking oil","unit":"ml"}]'::jsonb, '["Beat the eggs to form an egg wash and set aside.","Prepare the sauce: (20 g light soy sauce + 10 g oyster sauce + 5 g dark soy sauce + 10 g sugar + 10 g cornstarch + 200 ml water)","Slice the old tofu (personal suggestion, for reference: 5 slices per person, thickness 1.2 cm)","Pour cornstarch into a plate. Coat the tofu slices with cornstarch, then with egg wash, and set aside.","Heat the pan, add 18 ml cooking oil. Wait 10 seconds for the oil to heat up.","Place the egg-washed tofu slices evenly in the pan, covering the bottom. Fry over low heat until golden brown, then flip.","After both sides are golden, pour in the sauce, ensuring each piece is coated. Cook over high heat for 3 minutes until the sauce thickens.","Turn off the heat."]'::jsonb, '["Vegetarian","Savory-sweet","Pan-fried","Home-style","Rice companion","Quick"]'::jsonb),
  ('howtocook:vegetable_dish/芹菜拌茶树菇/芹菜拌茶树菇', 'en', 'Celery with Tea Tree Mushroom Salad', 'Vegetarian', 'This is a refreshing and crisp cold dish. The crunchiness of celery complements the chewy texture of tea tree mushrooms, creating a rich mouthfeel. It is rich in various vitamins and minerals, nutritious and appetizing. The recipe is very simple, even beginners can master it easily. From prep to finish, it takes only about 30 minutes.', '[{"name":"Minxing Tea Tree Mushroom","unit":"bottle"},{"name":"Celery","unit":"grams"},{"name":"Sesame oil","unit":"ml"},{"name":"Oyster sauce","unit":"ml"},{"name":"Premium light soy sauce","unit":"ml"},{"name":"Salt","unit":"grams"}]'::jsonb, '["(Skip if using celery sprouts) Boil a kettle of hot water and set aside.","Remove yellow leaves from fresh celery sprouts or celery, wash, and set aside.","(Skip if using celery sprouts) Remove the leaves from the celery and place them in a separate bowl. Cut the celery stalks into strips about 2-3 mm wide and set aside. This step is to ensure the celery blanches faster and more evenly, resulting in a crisper texture.","Cut celery sprouts into 4 cm segments and set aside.","(Skip if using celery sprouts) Place a pot on the stove, pour the hot water from the kettle into the pot, and bring to a boil.","(Skip if using celery sprouts) Add the celery strips to the pot and blanch for about 20 seconds. Then add the celery leaves, and after 5 seconds, turn off the heat. Remove everything and rinse under cold water. Set aside.","Sprinkle the blanched celery or celery sprouts with the prepared salt, sesame oil, oyster sauce, and premium light soy sauce. Mix well.","Add the tea tree mushrooms to the bowl and mix well.","Arrange on a plate.","Enjoy!"]'::jsonb, '["Vegetarian","Cold Dish","Light","Quick","Appetizing","Home-style"]'::jsonb),
  ('howtocook:vegetable_dish/茄子炖土豆', 'en', 'Braised Eggplant with Potatoes', 'Vegetarian', 'Braised Eggplant with Potatoes is a home-style stew from Northeast China. It has a soft and savory flavor, with a slight spiciness from chili and garlic aroma, making it a great dish to go with rice. Eggplant is rich in anthocyanins and dietary fiber, potatoes provide carbohydrates and vitamin C, and pork adds protein, making it nutritionally balanced and filling. The cooking process is simple but requires control of stir-frying and reducing the sauce, which may be a bit challenging for beginners. Estimated difficulty: medium. It takes about 45 minutes from preparation to serving.', '[{"name":"Eggplant","unit":"piece"},{"name":"Potato","unit":"piece"},{"name":"Meat","unit":"gram"},{"name":"Green chili pepper","unit":"gram"},{"name":"Soy sauce","unit":"ml"},{"name":"Salt","unit":"gram"},{"name":"Garlic","unit":"clove"},{"name":"Cooking oil","unit":"ml"},{"name":"Water","note":"as needed"}]'::jsonb, '["Wash the eggplant, potatoes, and chili peppers. Peel and crush the garlic.","Cut the eggplant and potatoes into cubes of about 6 cubic centimeters. Cut the chili peppers into small pieces of 5 grams. Cut the meat into shreds of 3 centimeters.","Turn on the heat, heat the wok, and add 13 ml of oil.","When you see a wisp of smoke from the oil in the wok, add the chili peppers.","After sautéing until fragrant, immediately add the meat and stir-fry with a spatula for 30 seconds.","Add the potatoes and stir-fry for 30 seconds.","Add the eggplant and stir-fry for 30 seconds.","Add soy sauce and salt, and continue stir-frying for 5 minutes.","Add water until the water level is 0.9 times the height of the ingredients in the wok, and cover with a lid.","Wait until the water level is 0.1 times the height of the ingredients, then uncover, add the garlic, stir well, and turn off the heat."]'::jsonb, '["Vegetable Dish","Northeast China","Home-style","Stew","Savory","Goes with rice","Slightly spicy"]'::jsonb),
  ('howtocook:vegetable_dish/莴笋叶煎饼/莴笋叶煎饼', 'en', 'Lettuce Leaf Pancake', 'Vegetarian', 'A simple and quick home-style snack, crispy outside and tender inside, with the refreshing flavor of lettuce leaves. Lettuce leaves are rich in vitamins and fiber, paired with eggs for protein. No complicated skills – just mix and fry both sides. Ready in about 10 minutes.', '[{"name":"Lettuce leaf","unit":"g"},{"name":"Egg","unit":"piece"},{"name":"Cooking oil","unit":"ml"},{"name":"Soy sauce","unit":"ml"},{"name":"Starch","unit":"g"},{"name":"Chicken bouillon","unit":"g"}]'::jsonb, '["Chop the lettuce leaves, add eggs, starch, soy sauce, chicken bouillon, and mix well. Set aside.","Heat oil in a pan, pour in the lettuce leaf mixture, and spread evenly over the pan surface.","Fry the first side for 120 seconds, then flip and fry the other side for 60 seconds. Remove from pan."]'::jsonb, '["Vegetarian","Quick","Home-style","Pan-fried","Light","Nutritious"]'::jsonb),
  ('howtocook:vegetable_dish/菠菜炒鸡蛋/菠菜炒鸡蛋', 'en', 'Spinach and Egg Stir-fry', 'Vegetarian', 'Spinach and egg stir-fry is a light and refreshing home-style quick dish. The spinach is tender, and the eggs are savory. It''s a popular flavor suitable for both northern and southern tastes. Spinach is rich in iron, folic acid, and vitamins, while eggs provide high-quality protein and lecithin. Eating them together helps nourish blood, boost energy, and strengthen the body. The whole dish is simple to make, perfect for cooking beginners. It takes only about 15 minutes from prep to serving.', '[{"name":"Spinach","unit":"gram"},{"name":"Egg","unit":"piece"},{"name":"Cooking oil","unit":"ml"},{"name":"Salt","unit":"gram"}]'::jsonb, '["Trim the roots of the spinach, wash it, place it in a colander, and blanch in boiling water.","Crack the eggs into a bowl and beat until smooth.","Heat the wok, then add 10ml oil.","When the oil is hot, pour in the egg mixture. Stir-fry over medium heat for 15 seconds, first cooking into an omelet, then break into small pieces with a spatula.","Turn off the heat, transfer the egg pieces to a plate. Do not wash the wok.","Reheat the wok, add 5ml oil. When hot, add the spinach and stir-fry over high heat for 15 seconds. Then add the egg pieces and stir-fry until well combined.","Add 5g salt and 100ml drinking water. Stir-fry over high heat for 10 seconds.","Turn off the heat and transfer to a plate."]'::jsonb, '["Vegetarian","Light","Savory","Quick","Home-style","Stir-fry"]'::jsonb),
  ('howtocook:vegetable_dish/葱煎豆腐', 'en', 'Scallion Pan-Fried Tofu', 'Vegetarian', 'Crispy on the outside, tender inside, rich scallion aroma, savory with a hint of spiciness, a home-style dish. Tofu is rich in plant protein and calcium, paired with green peppers and scallions, nutritionally balanced. Moderate difficulty, requires slow frying over low heat. Beginners can succeed with patience, about 30 minutes total.', '[{"name":"White tofu","note":"to taste"},{"name":"Scallion","unit":"stalk"},{"name":"Green chili","unit":"piece"},{"name":"Salt","unit":"g"},{"name":"Chicken bouillon","unit":"g"},{"name":"Oil","unit":"ml"},{"name":"Water","unit":"ml"}]'::jsonb, '["Wash the tofu. Cut into slices about 5 mm thick, place on a plate.","Wash the scallions, remove roots, cut into chopped scallions, set aside.","Wash the peppers, cut open, remove seeds, cut into 1 cm pieces, set aside.","Heat the pan, add 9 ml of oil.","After the oil is in the pan, spread it evenly over the bottom, place tofu pieces evenly, fry over low heat until golden brown, then flip.","When both sides are golden, transfer to a plate and set aside.","Add more oil to cover the bottom of the pan, add the peppers, stir-fry over high heat, and press them with a spatula for 3 minutes.","Add the tofu back, stir-fry, add salt and chicken bouillon, stir-fry over medium heat for 1 minute, then add 10 ml water, and reduce the sauce over high heat.","Before removing from heat, sprinkle with the prepared chopped scallions, then serve on a plate."]'::jsonb, '["Vegetarian","Savory with hint of spice","Pan-fried","Home-style","Pairs well with rice","Quick"]'::jsonb),
  ('howtocook:vegetable_dish/蒜蓉空心菜/蒜蓉空心菜', 'en', 'Garlic Water Spinach', 'Vegetarian', 'Garlic water spinach is a crisp, refreshing, and garlicky home-style quick dish, typical of Sichuan-style stir-fry. Water spinach is rich in dietary fiber, vitamins, and calcium, which helps promote intestinal motility. The method is very simple and friendly to beginners, from preparation to serving takes about 15 minutes.', '[{"name":"water spinach","unit":"g"},{"name":"minced garlic","unit":"cloves"},{"name":"cooking oil","unit":"ml"},{"name":"salt","unit":"g"},{"name":"sugar","unit":"g"},{"name":"light soy sauce","unit":"ml"}]'::jsonb, '["Wash water spinach, remove bad leaves or tough stems, cut into 2 or 3 equal segments (to prevent them from being too long to stir-fry).","First, pour a small amount of oil into the pan, heat until it''s just smoking. Then, tilt the pan to spread the hot oil evenly over the bottom, then pour in the remaining oil (hot pan, cold oil method).","Add minced garlic, stir-fry over low heat for 10-15 seconds until fragrant.","Quickly and evenly add water spinach, turn the heat to high. Use a spatula in your left hand and chopsticks in your right, stirring constantly until the leaves soften and turn green.","Then, without using chopsticks, use a spatula to quickly stir-fry the softened water spinach for 15-20 seconds for even heating. Sprinkle in 2g salt, 3g sugar, and 8ml light soy sauce.","Continue stir-frying over high heat for 10 seconds, then serve."]'::jsonb, '["Vegetarian","Garlicky","Light","Sichuan-style","Quick","Home-style","Stir-fry"]'::jsonb),
  ('howtocook:vegetable_dish/蒜蓉西兰花', 'en', 'Garlic Broccoli', 'Vegetarian', 'This home-style vegetable dish is known for its rich garlic flavor and simple seasoning. After blanching, the broccoli is tender or slightly crisp, light and delicious. Rich in vitamin C, dietary fiber, and various antioxidants, it''s a quick and nutritious vegetable dish. The process is easy, even beginners can master it, from prep to finish in about 15 minutes.', '[{"name":"broccoli","unit":"grams"},{"name":"garlic","unit":"cloves"},{"name":"light soy sauce","unit":"ml"},{"name":"oyster sauce","unit":"ml"},{"name":"sugar","unit":"grams"}]'::jsonb, '["Cut the broccoli into small florets and wash thoroughly.","Peel the garlic and mince it; set aside.","Add 1000 ml of drinking water to a pot and bring to a boil over high heat.","Add the broccoli and blanch for 2-3 minutes over high heat until it turns bright green and becomes tender.","Remove the broccoli, drain well, and arrange on a plate; set aside.","Heat a pan and add 10 ml of cooking oil. Once hot, add the minced garlic and stir-fry over low heat until fragrant.","Add 10 ml of light soy sauce, 5 ml of oyster sauce, 2 g of sugar, and 30 ml of drinking water.","Bring the sauce to a boil.","Evenly pour the cooked garlic sauce over the broccoli on the plate."]'::jsonb, '["Vegetarian","Garlic","Light","Quick","Home-style"]'::jsonb),
  ('howtocook:vegetable_dish/蒲烧茄子', 'en', 'Unagi-Style Eggplant', 'Vegetarian', 'Unagi-style eggplant is a home-style dish with a sweet-salty flavor and soft, sticky texture. It draws inspiration from Japanese unagi cooking but uses Chinese pan-frying and braising techniques. Eggplant is rich in dietary fiber and various vitamins, helping to clear heat and promote blood circulation. The difficulty is moderate; beginners need a bit of patience. Estimated cooking time: about 30 minutes.', '[{"name":"eggplant","unit":"piece"},{"name":"unagi sauce","unit":"portion"},{"name":"honey","unit":"ml"},{"name":"white sugar","unit":"ml"},{"name":"light soy sauce","unit":"ml"},{"name":"dark soy sauce","unit":"ml"},{"name":"cooking wine","unit":"ml"},{"name":"water","unit":"ml"}]'::jsonb, '["Peel the eggplant, cut it horizontally into two sections.","Steam for 5 minutes.","Cut lengthwise without cutting through, then make 2-3 slashes on each cut side so it can be flattened.","Pan-fry until both sides are golden brown.","Pour the unagi sauce over the eggplant until it reaches half the height of the eggplant.","Fry until the bottom side is colored, then flip.","Meanwhile, reduce the sauce. If it doesn''t thicken, add a cornstarch slurry (cornstarch to water ratio between 1:4 and 1:10 depending on the sauce consistency).","Pour the remaining unagi sauce over the eggplant.","Remove from the pan. A serving of eggplant braised in unagi sauce is ready."]'::jsonb, '["vegetarian","sweet-salty","pan-fried","home-style","rice companion","soft and sticky"]'::jsonb),
  ('howtocook:vegetable_dish/虎皮青椒/虎皮青椒', 'en', 'Tiger Skin Green Peppers', 'Vegetarian', 'Tiger Skin Green Peppers is a home-style side dish. The skin is slightly charred and wrinkled, with a tender yet crisp texture. It''s savory with a hint of sweet and sour, very appetizing and goes well with rice. Green peppers are rich in vitamin C and dietary fiber, which help boost immunity and aid digestion. The cooking process is simple and straightforward; you just need to master pressing and heat control. It''s beginner-friendly and takes about 15 minutes to complete.', '[{"name":"Green peppers","unit":"piece"},{"name":"Garlic","unit":"cloves"},{"name":"Oil","unit":"ml"},{"name":"Sugar","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Aged vinegar","unit":"ml"},{"name":"Salt","unit":"g"}]'::jsonb, '["Remove the stems of the green peppers and rinse thoroughly under tap water.","Cut the peppers into long slices; one pepper can be cut lengthwise into 3-4 slices.","Peel the garlic and mince into pieces about 2mm x 2mm x 2mm in size.","Sauce 1: Take a small bowl, pour in 20ml oil, and add the minced garlic.","Sauce 2: Put sugar, soy sauce, vinegar, and salt all into a bowl (or similar container) and stir.","Pour Sauce 1 into the pan, heat to medium heat, then add the pepper slices. Do not overlap; place each slice separately in the pan.","Constantly press the peppers with a spatula, flipping at the right time.","Stir-fry for about 2 minutes. When the pepper skin becomes wrinkled, pour in Sauce 2.","Increase heat and continue stir-frying for 30 seconds, then serve on a plate."]'::jsonb, '["Vegetarian dish","Home-style","Goes well with rice","Quick","Savory and aromatic","Sweet and sour","Pan-fried and stir-fried"]'::jsonb),
  ('howtocook:vegetable_dish/蚝油三鲜菇/蚝油三鲜菇', 'en', 'Oyster Sauce Mixed Mushrooms', 'Vegetarian', 'Oyster Sauce Mixed Mushrooms is a delicious, tender, and quick home-style dish. The mushrooms soak up the oyster sauce, resulting in a soft yet chewy texture with a slight spiciness, refreshing and not greasy. Rich in plant protein, dietary fiber, and various vitamins, paired with broccoli for balanced nutrition. Simple to make, even beginners can master it easily. From prep to finish, it takes about 15 minutes.', '[{"name":"shiitake mushrooms","unit":"piece"},{"name":"shimeji mushrooms","unit":"g"},{"name":"white beech mushrooms","unit":"g"},{"name":"Thai chili peppers","unit":"piece"},{"name":"bell pepper","unit":"piece"},{"name":"cooking oil","unit":"ml"},{"name":"salt","unit":"g"},{"name":"cooking wine","unit":"ml"},{"name":"cornstarch","unit":"g"},{"name":"light soy sauce","unit":"ml"},{"name":"chicken bouillon","unit":"g"},{"name":"green onions","unit":"piece"},{"name":"minced ginger","unit":"piece"},{"name":"oyster sauce","unit":"ml"},{"name":"broccoli","unit":"g"},{"name":"boiling water","unit":"ml"}]'::jsonb, '["Remove the root ends of the shimeji and white beech mushrooms, then break apart the clusters.","Slice the shiitake mushrooms (each slice 0.5-1 cm thick; thicker slices have more chewiness).","Pour cornstarch into a small bowl, add 50ml water, and stir until dissolved and no lumps remain (this is the slurry). Set aside.","Bring water to a boil, add broccoli, boil for 3 minutes, then transfer to a bowl and set aside.","Clean the pot, bring fresh water to a boil, add 5g salt, then add the shimeji, white beech, and shiitake mushrooms. Boil for 1 minute.","After 1 minute, drain the mushrooms well.","Heat oil in a pan. When small bubbles appear, add ginger, Thai chili, and bell pepper. Stir-fry for 30 seconds.","Add the three mushrooms, then add light soy sauce, oyster sauce, and chicken bouillon. Stir-fry evenly, then add the slurry.","Cook over medium heat until the sauce thickens. Add cooking wine and chopped green onions, then remove from heat.","Arrange the broccoli around the dish."]'::jsonb, '["vegetarian","savory","slightly spicy","quick","home-style","goes with rice"]'::jsonb),
  ('howtocook:vegetable_dish/蚝油生菜', 'en', 'Oyster Sauce Lettuce', 'Vegetarian', 'Oyster Sauce Lettuce is a refreshing and savory home-cooked dish. Crisp lettuce is drizzled with a garlicky oyster sauce, savory with a hint of sweetness. It''s a quick vegetarian dish commonly found in both Cantonese and Sichuan restaurants. Rich in vitamins and dietary fiber, it aids digestion. The recipe is very beginner-friendly, taking only about 15 minutes from washing to serving.', '[{"name":"Lettuce","unit":"head"},{"name":"Oyster sauce","unit":"ml"},{"name":"Garlic","unit":"clove"},{"name":"Light soy sauce","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Sugar","unit":"g"},{"name":"Cooking oil","unit":"ml"}]'::jsonb, '["Wash the lettuce and remove any spoiled leaves.","Heat the pan, add 1 L cold water, then add 2-3 ml cooking oil and 0.5 g salt. Wait for the water to boil.","Once boiling, add the lettuce and blanch each leaf for 10 seconds.","Remove the lettuce, drain, and arrange on a plate.","Make the sauce: Mix 10 ml light soy sauce, 6-8 ml oyster sauce, 0.5 g salt, and 1 g sugar in a bowl. Add 10-15 ml cold water and stir well.","Reheat the pan over fire, add 5-8 ml cooking oil. When hot, add minced garlic.","Wait for the garlic aroma, then pour in the prepared sauce. Bring to a boil and immediately turn off the heat.","Pour the sauce evenly over the lettuce."]'::jsonb, '["Vegetarian","Savory","Sweet-salty","Quick","Cantonese","Home-style","Rice companion"]'::jsonb),
  ('howtocook:vegetable_dish/西红柿炒鸡蛋', 'en', 'Scrambled Eggs with Tomatoes', 'Vegetarian', 'A sweet and sour home-style dish that is appetizing. Tender scrambled eggs wrapped around soft, juicy tomatoes—a classic flavor on Chinese family tables. Eggs provide high-quality protein, while tomatoes are rich in vitamin C and lycopene, making it nutritious and easy to absorb. Simple steps and easily available ingredients, especially suitable for beginners. From prep to serving, it takes about 15 minutes.', '[{"name":"Tomatoes","unit":"piece"},{"name":"Eggs","unit":"piece"},{"name":"Cooking oil","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Sugar (optional)","unit":"g"},{"name":"Chopped scallions (optional)","unit":"g"},{"name":"Vinegar","unit":"ml"},{"name":"Tomato paste","unit":"ml"},{"name":"Water","unit":"ml"}]'::jsonb, '["Wash the tomatoes","Optional: Remove the tomato skin","Blanch the tomatoes in boiling water, then transfer to cold water and peel off the skin","Remove the stem and cut into small pieces no larger than 4 cm on each side; these are the tomato pieces","Crack the eggs into a bowl, add 1g salt, and beat well; this is the egg mixture","You may consider adding 1ml vinegar to the eggs; this removes any fishy smell and makes the eggs fluffier","Heat the wok and add cooking oil","When the oil is hot, pour in the egg mixture. Stir-fry until the eggs are set and slightly golden; these are the half-cooked eggs","Turn off the heat. Transfer the half-cooked eggs to a plate, then turn the heat back on","Note: Do not wash the wok","Add the tomato pieces, press and stir-fry with a spatula for 20 seconds, or until the tomatoes are soft","Add the half-cooked eggs back to the wok and stir-fry evenly","You may consider adding 10ml tomato paste and 50ml water for more sauce","You can also add some other cooked meat and ingredients","Add the remaining salt, sugar (optional, if you prefer a sweet version), and chopped scallions (optional), and stir-fry evenly","Turn off the heat and serve"]'::jsonb, '["Vegetarian Dish","Sweet and Sour","Stir-fry","Home-style","Quick","Rice Companion"]'::jsonb),
  ('howtocook:vegetable_dish/西红柿豆腐汤羹/西红柿豆腐汤羹', 'en', 'Tomato and Tofu Soup', 'Vegetarian', 'A light and delicious home-style soup, sweet and sour, appetizing, with a smooth texture. Tomatoes are rich in vitamin C and lycopene, paired with eggs and tofu, providing high-quality protein, balanced nutrition and easy absorption. Simple to make, just chop, stir-fry and boil, even beginners can master it easily, from preparation to serving in about 15 minutes.', '[{"name":"Tomato","unit":"pcs"},{"name":"Egg","unit":"pcs"},{"name":"Tofu","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Starch","unit":"g"},{"name":"Chicken bouillon","unit":"g"},{"name":"Scallion","unit":"stalk"},{"name":"Ginger","unit":"slice"},{"name":"Boiling water","unit":"ml"}]'::jsonb, '["Cut tomatoes into small cubes, beat eggs in a bowl, cut tofu into cubes and set aside.","Heat oil in a pot, add ginger slices, after 5 seconds add tomatoes and stir-fry for 30 seconds.","Add boiling water to the pot, bring to a boil, after 60 seconds add beaten eggs and tofu cubes.","After the soup boils again, add water starch, stir in one direction for 2 circles.","Add chicken bouillon, salt, and scallions, after 30 seconds remove from heat."]'::jsonb, '["Vegetarian","Light","Sweet and Sour","Home-style","Quick"]'::jsonb),
  ('howtocook:vegetable_dish/西葫芦炒鸡蛋/西葫芦炒鸡蛋', 'en', 'Stir-fried Zucchini with Eggs', 'Vegetarian', 'Stir-fried Zucchini with Eggs is a refreshing and delicious home-style quick dish. The zucchini is tender and juicy, the eggs are fluffy and savory, and adding tomatoes brings a sweet and sour flavor that pairs perfectly with rice. Eggs provide high-quality protein and lecithin, while zucchini is rich in vitamin C and dietary fiber, making the combination nutritionally balanced. The cooking process is simple and beginner-friendly; from prep to serving, it usually takes only 15 minutes for novices.', '[{"name":"Zucchini","unit":"g"},{"name":"Egg","unit":"piece"},{"name":"Tomato","unit":"g"},{"name":"Cooking oil","unit":"ml"},{"name":"Salt","unit":"g"}]'::jsonb, '["Wash the tomatoes, cut into small pieces, and set aside.","Wash the zucchini, cut into diamond shapes about 4cm on each side, and set aside.","Crack three eggs into a bowl, beat until well mixed, and set aside.","Heat the pan and add 5ml - 10ml of cooking oil.","Pour in the eggs, keep stirring until the eggs are set, break into small pieces with a spatula, then transfer to a bowl and set aside.","Add 5ml - 10ml of cooking oil to the pan, pour in the tomatoes, and stir-fry until soft.","Add the zucchini and stir-fry together. Add 6g of salt, reduce the heat to low, and wait 4 - 5 minutes.","Add the reserved eggs, stir-fry over medium heat for 15 seconds.","Turn off the heat and serve."]'::jsonb, '["Vegetarian","Light","Stir-fry","Home-style","Quick","Goes well with rice"]'::jsonb),
  ('howtocook:vegetable_dish/话梅煮毛豆/话梅煮毛豆', 'en', 'Plum-Boiled Edamame', 'Vegetarian', 'Plum-boiled edamame is a sweet and sour appetizing home-style side dish. The texture is refreshing, soft, and sticky, with the natural fruity aroma of plums. Edamame is rich in plant protein and dietary fiber, which helps replenish energy and promote digestion. The recipe is very simple, even beginners can easily master it. It takes only 35 to 45 minutes to complete.', '[{"name":"edamame","unit":"g"},{"name":"preserved plum","unit":"piece"},{"name":"salt","unit":"g"}]'::jsonb, '["Add salt to water, soak edamame for 15 minutes","Add boiling water, add edamame and plums, boil for 20-30 minutes","Remove from heat and enjoy"]'::jsonb, '["vegetarian dish","sweet and sour","boiled","home-style","appetizing","quick"]'::jsonb),
  ('howtocook:vegetable_dish/酸辣土豆丝', 'en', 'Sour and Spicy Shredded Potatoes', 'Vegetarian', 'A classic home-cooked dish with a sour and spicy flavor that whets the appetite. The texture is crisp and refreshing, and the color is bright. It''s a popular quick stir-fry. Potatoes provide carbohydrates and potassium, while chili peppers are rich in vitamin C, helping to stimulate appetite. The steps are simple and clear, friendly for beginners, taking about 20 minutes from prep to serving.', '[{"name":"Potatoes","unit":"g"},{"name":"Garlic","unit":"cloves"},{"name":"Green bell pepper","unit":"piece"},{"name":"Red bell pepper","unit":"piece"},{"name":"Dried chilies","unit":"pieces"},{"name":"Scallion","unit":"stalks"},{"name":"Light soy sauce","unit":"ml"},{"name":"Aged vinegar","unit":"ml"},{"name":"Salt","unit":"g"},{"name":"Cooking oil","unit":"ml"}]'::jsonb, '["Peel the potatoes and cut into shreds (or use a grater).","Wash the shredded potatoes in clean water to remove excess starch, then blanch them in boiling water for 10 seconds. Drain and set aside.","Chop the scallion into small pieces; mince the garlic (divide into two equal portions for later); cut dried chilies into small sections; shred the green and red bell peppers.","Heat a wok over low heat, add oil, then stir-fry half of the scallion (the white part), half of the garlic, and the dried chilies until fragrant.","Add the shredded green and red peppers and stir-fry a few times, then add the shredded potatoes and stir-fry until they change color.","Add 5ml light soy sauce, 10ml aged vinegar, pour in the remaining half of the minced garlic and 2g salt, and quickly stir-fry until well combined.","Before serving, sprinkle the remaining scallion over the dish, toss well, and plate."]'::jsonb, '["Vegetarian","Sour and Spicy","Stir-fry","Home-style","Quick","Rice-friendly"]'::jsonb),
  ('howtocook:vegetable_dish/金针菇日本豆腐煲', 'en', 'Enoki Mushroom and Japanese Tofu Pot', 'Vegetarian', 'Enoki Mushroom and Japanese Tofu Pot is a home-style dish with rich savory sauce. The tofu is crispy outside and tender inside, while the enoki mushrooms are smooth and flavorful. Enoki mushrooms are rich in amino acids and dietary fiber, and Japanese tofu provides high-quality protein, making it nutritious and appetizing. The steps are simple, easy for beginners, and takes about 30 minutes from preparation to serving.', '[{"name":"enoki mushrooms","unit":"bunch"},{"name":"Japanese tofu (egg tofu)","unit":"pack"},{"name":"chili pepper","unit":"piece"},{"name":"garlic","unit":"clove"},{"name":"light soy sauce","unit":"ml"},{"name":"oyster sauce","unit":"ml"},{"name":"dark soy sauce","unit":"ml"},{"name":"sugar","unit":"g"},{"name":"cooking oil","unit":"ml"},{"name":"salt","note":"to taste"},{"name":"water","unit":"ml"}]'::jsonb, '["Slice the tofu, pan-fry over low heat until both sides are golden brown, then remove and set aside.","Mince the garlic; mix light soy sauce, oyster sauce, dark soy sauce, sugar, and 100ml water to make the sauce.","Heat oil in a pot, add chopped chili peppers and minced garlic, stir-fry until fragrant. Add enoki mushrooms first and cook until soft. Place the fried tofu on top of the mushrooms, pour in the sauce from step 2, cover and simmer for 5 minutes, then reduce the sauce over high heat."]'::jsonb, '["Vegetarian Dish","Savory Sauce","Home-style","Rice Companion","Pan-fry and Braise"]'::jsonb),
  ('howtocook:vegetable_dish/金钱蛋', 'en', 'Golden Coin Eggs', 'Vegetarian', 'Golden Coin Eggs is a home-style Hunan dish with crispy exterior and tender interior, savory and slightly spicy. The golden fried egg slices resemble copper coins, symbolizing good fortune. Eggs paired with green and red peppers provide high-quality protein and various vitamins, offering balanced nutrition. The difficulty is moderate; beginners can master it with a bit of practice. It takes about 30 minutes to complete this rice-pairing dish.', '[{"name":"Eggs","unit":"piece"},{"name":"Line peppers","unit":"gram"},{"name":"Bird''s eye chilies","unit":"gram"},{"name":"Doubanjiang","unit":"ml"},{"name":"Garlic","unit":"gram"},{"name":"Scallions","unit":"gram"},{"name":"Cornstarch","unit":"gram"},{"name":"Cooking oil","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Oyster sauce","unit":"ml"},{"name":"Sugar","unit":"gram"}]'::jsonb, '["Put eggs in cold water, bring to a boil over high heat, then reduce to low heat and cook for 8 minutes","Rinse under tap water to cool, making them easy to peel","Mince garlic (particle size no more than 1 mm), dice line peppers and bird''s eye chilies into small pieces (about 2-3 mm)","Cut each cooked egg along the short axis into 4 roughly equal pieces","If using starch, coat each egg slice with starch, then shake off excess","Add 25 ml oil to the pan (20 ml if not using starch), add the egg slices","After frying until slightly golden, add another 10 ml of oil (if not using starch, add 10 ml), and flip","When the second side is golden, add line peppers, bird''s eye chilies, and minced garlic; fry for about one minute, then flip","Then add doubanjiang (chili bean paste) and fry for about a few tens of seconds, then flip","Mix light soy sauce, oyster sauce, and sugar into a sauce. Gently toss the pan, then serve"]'::jsonb, '["Vegetarian Dish","Savory","Slightly Spicy","Pan-fried","Hunan Style","Rice-pairing"]'::jsonb),
  ('howtocook:vegetable_dish/陕北熬豆角', 'en', 'Northern Shaanxi Braised Green Beans', 'Vegetarian', 'This is a rustic farm-style stew from Northwest China. The green beans are soft, the potatoes are creamy, and the tomato sauce is rich and tangy, making it appetizing. It''s rich in dietary fiber, vitamins, and carbohydrates, offering balanced nutrition. The method is extremely simple, ingredient amounts can be adjusted to taste, and it''s almost foolproof—very beginner-friendly. From prep to serving, it takes about 30 minutes.', '[{"name":"Green beans","unit":"g"},{"name":"Potato","unit":"piece"},{"name":"Tomato","unit":"piece"},{"name":"Screw pepper","unit":"piece"},{"name":"Salt","unit":"g"},{"name":"Light soy sauce","unit":"ml"},{"name":"Five-spice powder","unit":"g"},{"name":"Oyster sauce","unit":"ml"},{"name":"Scallion","unit":"ring"},{"name":"Ginger","unit":"g"},{"name":"Garlic","unit":"clove"},{"name":"Chopped cilantro","note":"to taste"},{"name":"Oil","unit":"ml"}]'::jsonb, '["Chop scallion into rings, mince garlic, shred ginger, and set aside.","Remove strings from green beans, cut into 2-10 cm sections, and set aside.","Peel potato, cut into 1 cm cubes, and set aside.","Peel tomato, cut into 1 cm cubes, and set aside.","Remove seeds from pepper, cut into 0.15 cm wide strips, and set aside.","Heat oil (10-15 ml) in a wok until smoking, add scallion, ginger, and garlic, stir-fry until fragrant.","Add green beans, stir-fry until color changes (from light green to bright green).","Add potato cubes, stir-fry for 30 seconds.","Add hot water (just enough to cover the ingredients), cover and braise until potatoes are soft (check with chopsticks).","Add tomato cubes, salt, light soy sauce, oyster sauce, five-spice powder, and pepper. Braise until tomatoes break down into sauce (stir occasionally to prevent sticking).","Add chopped cilantro, then remove from heat and serve."]'::jsonb, '["Vegetarian","Home-style","Rice Companion","Stew","Northwest","Quick"]'::jsonb),
  ('howtocook:vegetable_dish/雷椒皮蛋', 'en', 'Smashed Century Egg with Green Peppers', 'Vegetarian', 'Smashed Century Egg with Green Peppers is a humble-looking but flavorful home-style cold dish. The charred aroma of green peppers blends with the smooth richness of century eggs, creating a tangy and spicy appetizer, perfect for summer meals. Century eggs are rich in protein and minerals, green peppers provide abundant vitamin C, and garlic helps stimulate appetite. The whole dish is simple to make, easy for beginners, and takes about 15 minutes from prep to finish.', '[{"name":"century egg","unit":"piece"},{"name":"green pepper","unit":"piece"},{"name":"scallion","unit":"cm"},{"name":"garlic","unit":"clove"},{"name":"Thai chili","unit":"piece"},{"name":"cooking oil","unit":"ml"},{"name":"light soy sauce","unit":"ml"},{"name":"aged vinegar","unit":"ml"},{"name":"sugar","unit":"g"},{"name":"sesame oil","unit":"ml"}]'::jsonb, '["Wash the green peppers, remove the stems, cut them open lengthwise, remove the seeds, and flatten them on the cutting board. Set aside. (Be sure to remove the seeds, or they will pop in the pan.)","Cut the scallion into 0.5 cm pieces. Set aside.","Peel the garlic and mince finely. Set aside.","Peel the century eggs. Set aside.","Cut the Thai chilies into 5-10 mm pieces. Set aside.","Heat the pan and add 10-20 ml of cooking oil.","Add all the green peppers. Reduce the heat to low and fry until the peppers are soft. (Test with a chopstick – it should pierce through easily.)","Turn off the heat. Transfer the century eggs and green peppers to a small metal bowl.","Method 1: If you have a rolling pin and smashing things won''t disturb the neighbors, use one end of the rolling pin to smash the century eggs and green peppers in the bowl until they are combined. (Optional)","Method 2: Tear the green peppers by hand into strips about 0.5 cm wide, and use a fork to mash the century eggs. (Optional)","Add the Thai chilies.","Add light soy sauce, aged vinegar, sugar, sesame oil, and any other reserved ingredients not yet used.","Stir evenly."]'::jsonb, '["Cold Dish","Spicy and Sour","Cold Tossed","Appetizing","Home-style","Quick"]'::jsonb),
  ('howtocook:vegetable_dish/鸡蛋火腿炒黄瓜', 'en', 'Stir-fried Cucumber with Egg and Ham', 'Vegetarian', 'This is a refreshing and quick home-style stir-fry, salty and savory, with crisp cucumber, soft scrambled eggs, and flavorful ham. It''s a popular Chinese home-cooked dish. Eggs provide high-quality protein, cucumbers are rich in vitamins and water, and ham adds flavor, making it nutritionally balanced. The cooking steps are simple and straightforward, very low difficulty, and friendly for kitchen beginners. From prep to plating, it takes only about 10 minutes.', '[{"name":"Cucumber","unit":"piece"},{"name":"Egg","unit":"piece"},{"name":"Ham sausage","unit":"piece"},{"name":"Red chili pepper","unit":"piece"},{"name":"Cooking oil","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"Salt","unit":"g"}]'::jsonb, '["Wash the cucumber, cut into half-round slices, set aside.","Cut the ham into half-round slices, set aside.","Finely chop the red chili pepper (optional), set aside.","Crack the eggs into a bowl, beat well, this is the egg mixture.","Pour 5ml cooking oil into a hot pan.","When the oil is hot, reduce to low heat, pour in the beaten eggs, stir with chopsticks to scramble until the eggs are set and slightly golden, this is the half-cooked eggs. Remove and set aside.","Without washing the pan, pour 5ml cooking oil into the pan, add cucumber slices and stir-fry over high heat for 1 minute.","Add the half-cooked eggs to the pan, season with 2g salt and 3ml light soy sauce, immediately add ham slices and chopped chili (optional), stir-fry evenly.","Turn off the heat, plate."]'::jsonb, '["Vegetable dish","Light","Savory","Stir-fry","Quick","Home-style"]'::jsonb),
  ('howtocook:vegetable_dish/鸡蛋羹/微波炉鸡蛋羹', 'en', 'Microwave Steamed Egg Custard', 'Vegetarian', 'Microwave steamed egg custard is a simple and quick home-style steamed egg dish with a tender and smooth texture, especially suitable as a late-night snack or quick meal. Eggs are rich in high-quality protein and various vitamins, providing essential nutrients for the body, and the dried shrimp adds calcium. This dish is very beginner-friendly, requiring no mastery of heat control; from beating the eggs to serving, it only takes about 10 minutes.', '[{"name":"Eggs","unit":"pieces"},{"name":"Water","unit":"ml"},{"name":"Salt","unit":"grams"},{"name":"Dried shrimp","unit":"pieces"},{"name":"Scallions","unit":"grams"},{"name":"Sesame oil","unit":"ml"},{"name":"Soy sauce","note":"to taste"}]'::jsonb, '["Crack the eggs into a microwave-safe ceramic bowl and beat them with chopsticks.","Add water and salt, and stir well.","Add the dried shrimp into the bowl and stir evenly, making sure the shrimp are not clumped together.","Finely chop the scallions into pieces about 0.6 to 3 mm in size, then add to the bowl and stir well.","Place the bowl and its contents into the microwave, cover the surface with plastic wrap or a microwave-safe ceramic lid (note: do not seal; must leave room for expansion), and heat for 2 minutes (500W).","Carefully remove the plastic wrap or other cover, then continue heating for 2 minutes.","If the microwave does not have a rotating turntable, slowly rotate the bowl horizontally by 180 degrees to ensure even heating.","Add sesame oil.","Carefully remove the bowl from the microwave (it''s really hot).","If you choose to add soy sauce, make sure it flows over the surface of the egg custard and then coats it in a thin layer.","Enjoy the egg custard happily."]'::jsonb, '["Vegetarian","Quick","Home-style","Tender and smooth","Late-night snack","Microwave"]'::jsonb),
  ('howtocook:vegetable_dish/鸡蛋羹/蒸箱鸡蛋羹', 'en', 'Steamed Egg Custard', 'Vegetarian', 'This is a tender and smooth home-style egg custard quickly made using a steamer. The texture can be adjusted: less water makes it firmer, more water makes it tenderer. Rich in high-quality protein and various nutrients, easy to digest and absorb. Moderate difficulty, beginners can master it with a little care. From preparation to serving, it takes only about 15 minutes.', '[{"name":"Egg","unit":"piece"},{"name":"Salt","unit":"gram"},{"name":"Cooking oil","unit":"ml"},{"name":"Light soy sauce (optional)","unit":"ml"}]'::jsonb, '["Beat one egg in a bowl until smooth.","Add purified water at 60°C, 1.0 to 1.5 times the volume of the egg, and stir well.","Within the correct range, less water gives a firmer texture, more water gives a tenderer texture.","Note: Outside the range, too little water makes it too firm, too much water makes it too thin.","Add 1g of salt.","Salt plays an important role in enhancing the base flavor and coagulating.","Add 5ml of cooking oil.","Strain the egg mixture to remove foam (optional; without straining, the steamed custard may have bubbles and look less appealing).","Make sure the steamer''s water supply is sufficient (if unsure, fill the water tank).","Place the bowl with the fully stirred egg mixture into the steamer.","Set to 100°C and steam for 10 minutes.","Open the steamer (Note: When opening the steamer, steam will burst out instantly; open slowly and carefully).","Remove from steamer (can add light soy sauce for seasoning).","Enjoy!"]'::jsonb, '["Vegetarian Dish","Steam","Quick","Home-style","Tender and Smooth","Light"]'::jsonb),
  ('howtocook:vegetable_dish/鸡蛋羹/鸡蛋羹', 'en', 'Egg Custard', 'Vegetarian', 'This dish is a simple and quick home-style steamed dish, with a tender texture like jelly, savory and suitable. It often appears on tables as breakfast or a side dish. Eggs provide high-quality protein and lecithin, easy to digest and absorb. Very beginner-friendly, just a few steps to steam a smooth and delicate egg custard, the whole process takes about 15 minutes.', '[{"name":"Egg","unit":"piece"},{"name":"Salt","unit":"g"},{"name":"Sesame oil","unit":"ml"},{"name":"Light soy sauce","unit":"ml"},{"name":"White vinegar (or cooking wine)","unit":"ml"},{"name":"Sichuan pepper oil","note":"to taste"}]'::jsonb, '["Crack two eggs into a bowl and beat them.","Add 3g of salt.","Salt plays an important role in adding flavor and helping coagulation.","Add 2ml of white vinegar to remove the eggy smell (optional).","Rice vinegar also works, but it may give the eggs a slightly darker color.","You can also add cooking wine, which also removes the smell without the acidity of vinegar.","Add purified water at 70°C, about 1-1.5 times the volume of the eggs, and stir well.","With 1x water, the egg is firmer; with 1.5x water, it is more tender.","Strain the egg mixture to remove foam (optional; if not strained, the custard may have bubbles and look less appealing).","Add 300-500ml of water to a pot, bring to a boil, then place the bowl with the egg mixture inside.","Cover the bowl with a lid, invert a grooved metal plate over it, or use plastic wrap to prevent steam from dripping in, to avoid a honeycomb texture.","Steaming steps (choose one):","Steam over medium heat for 10 minutes, then turn off the heat and let it rest for 5 minutes.","Steam over high heat for 5 minutes, keeping the water boiling; otherwise, extend the time. Open the lid every 2 minutes to release steam. Opening too late may cause honeycomb texture; opening too early or too often requires longer steaming.","How to tell if it''s done?","Shake the bowl; if the custard is no longer liquid and has a jelly-like wobble, it is ready.","Remove from the pot.","Add sesame oil and light soy sauce, and enjoy.","Alternatively, replace sesame oil with Sichuan pepper oil for a numbing sensation."]'::jsonb, '["Vegetarian","Steamed","Quick","Home-style","Breakfast","Savory"]'::jsonb),
  ('howtocook:vegetable_dish/鸡蛋花/鸡蛋花', 'en', 'Egg Flower Soup', 'Vegetarian', 'A simple home-style therapeutic soup drink with both sweet and savory flavors. The texture is smooth and tender. It''s a folk remedy for soothing the throat. Rich in high-quality protein and lecithin, easy to digest and absorb, it can relieve dry and itchy throat discomfort. Extremely simple to make; beginners can pick it up after one look. It takes only about 5 minutes from boiling water to completion.', '[{"name":"Eggs","unit":"piece"},{"name":"Boiling water","unit":"ml"},{"name":"White sugar","unit":"g"},{"name":"Table salt","unit":"g"}]'::jsonb, '["Crack the eggs into a bowl.","Using chopsticks or a whisk, beat the eggs in one direction until the whites and yolks are fully combined and the color is uniform. (This takes about 1-2 minutes.)","Add sugar or salt and other seasonings to the egg mixture, and stir lightly.","Prepare freshly boiled water at 100°C.","While quickly stirring the egg mixture in the bowl with chopsticks, pour the boiling water in a thin stream into the egg mixture. Ensure the boiling water is fully mixed with the egg mixture.","Continue stirring for a moment until the egg mixture is completely cooked by the hot water, forming uniform pale yellow egg flowers."]'::jsonb, '["Vegetarian Dish","Sweet and Savory","Quick","Home-style","Throat-soothing","Soup Drink"]'::jsonb),
  ('howtocook:aquatic/咖喱炒蟹', 'ja', 'カレー炒め蟹', '魚介', 'タイ風の味わいを取り入れた家庭的な海鮮料理です。濃厚なカレーがたっぷりの蟹の身に絡み、蟹みその香りとココナッツミルクの滑らかな口当たりが特徴。蟹は高品質のタンパク質や各種ミネラルが豊富で、体力回復に役立ちます。調理手順は明確で、蟹みそを封じるための焼きと最後のソース炒めに注意すれば、中級者にも扱いやすく、準備から盛り付けまで約30分です。', '[{"name":"蟹","unit":"匹"},{"name":"カレールウ","unit":"g"},{"name":"玉ねぎ","unit":"g"},{"name":"ココナッツミルク","unit":"ml"},{"name":"卵","unit":"個"},{"name":"片栗粉","unit":"g"},{"name":"にんにく","unit":"かけ"}]'::jsonb, '["肉蟹の蓋を開け、半分に切る。蟹のハサミは包丁の背で軽く叩いて割る。切り口とハサミに片栗粉をまぶす（多すぎないように）。蟹の蓋に片栗粉5gをふりかけ、蟹みそを覆う。取っておく。","玉ねぎはみじん切りにする。取っておく。","にんにくはみじん切りにする。取っておく。","やかんでお湯を沸かしておく。","鍋に油を熱し、サラダ油約20mlを入れ、10秒待って油温を上げる。","蟹の切り口を下にして鍋にそっと入れ、20秒焼く（これで蟹みそと身を封じる）。その後裏返し、各面10秒ずつ焼く。焼き終わったら蟹を取り出して取っておく。","蟹の蓋を鍋に入れ、スプーンで鍋の熱油をすくって蓋の中にかけ、蓋の中の蟹みそを封じるように20秒焼く。その後取り出して取っておく。","鍋を洗わずに、さらにサラダ油10mlを加え、強火で油が少し煙が出るまで熱し、にんにくみじん切りと玉ねぎみじん切りを入れて10秒炒める。","カレールウを鍋に入れて溶かす（10秒）。焼いた蟹を加え、全体を炒め合わせる。","沸騰したお湯300mlを注ぎ、蓋をして3分煮込む。","煮込んだら、ココナッツミルクと卵白を加え、火を止める。火を止めた後、絶えず炒めながら、ソースがとろみがつくまで続ける。","皿に盛る。"]'::jsonb, '["水産","タイ風","香ばしい","濃厚","炒め","ご飯が進む","おもてなし"]'::jsonb),
  ('howtocook:aquatic/响油鳝丝', 'ja', '油かけうなぎの細切り', '魚介', '油かけうなぎの細切りは、江浙滬地方の定番家庭料理です。うなぎの細切りは柔らかく滑らかで、にんにくの香りが豊かで、たれはほんのり甘く、熱したラードをかけると香りが広がり、ご飯が進みます。うなぎは良質のたんぱく質とDHAが豊富で栄養価が高いです。この料理は包丁さばきと火加減にある程度の技術が必要で、難易度は中程度、初心者は少し練習が必要です。準備から仕上げまで、通常約40分で食卓に出せます。', '[{"name":"うなぎの細切り","unit":"g"},{"name":"にんにく","unit":"g"},{"name":"しょうがのみじん切り","unit":"g"},{"name":"料理酒","unit":"g"},{"name":"薄口醤油","unit":"g"},{"name":"オイスターソース","unit":"g"},{"name":"濃口醤油","unit":"g"},{"name":"食塩","unit":"g"},{"name":"白糖","unit":"g"},{"name":"こしょう","unit":"g"},{"name":"片栗粉","unit":"g"},{"name":"水","unit":"g"},{"name":"にんにくのみじん切り","unit":"g"},{"name":"ねぎのみじん切り","unit":"g"},{"name":"ラード","unit":"g"},{"name":"ごま油","unit":"g"}]'::jsonb, '["うなぎを三つに切り、細切りにする","0.5gのこしょう、3gの料理酒を加えてよく混ぜ、さらに5gのごま油を加えて下味をつける","油を熱して鍋になじませる","植物油を加え、6割の熱さまで加熱する","にんにくのみじん切りの半分としょうがのみじん切り全部を加え、数回炒める","うなぎの細切りを加え、中火で30秒炒める","縁から10gの料理酒を回し入れ、数回炒める","薄口醤油を加え、よく炒める","オイスターソースと濃口醤油を加え、数回炒める","食塩、白糖、3gのこしょうを加え、よく炒める","片栗粉と水を混ぜて水溶き片栗粉を作り、鍋に加えてとろみがつくまで煮詰める","皿に盛り、にんにくのみじん切りとねぎのみじん切りを散らす","別の鍋を熱し、ラードを加えて7割の熱さまで加熱し、うなぎの細切りの上にかける"]'::jsonb, '["水産","江浙滬","新鮮で香ばしい","ほのかに甘い","強火で炒める","ご飯が進む"]'::jsonb),
  ('howtocook:aquatic/小龙虾/小龙虾', 'ja', 'ザリガニの麻辣炒め', '魚介', 'この料理は麻辣で香り高く、エビの身は柔らかくジューシーで、四川・湖南風味の定番の酒の肴です。家庭で作れば清潔で経済的。ザリガニは良質なたんぱく質や様々な微量元素が豊富ですが、スープには油分や塩分が多いので、たまに楽しむのに適しています。活きのザリガニの処理や多くの香辛料は初心者には少し難しいですが、背わたを取らなければ難易度がぐっと下がります。準備から完成まで約45分かかります。', '[{"name":"ザリガニ","unit":"斤"},{"name":"油","unit":"ml"},{"name":"ローリエ","unit":"枚"},{"name":"八角","unit":"個"},{"name":"桂皮（シナモン）","unit":"g"},{"name":"青花椒（グリーンホアジャオ）","unit":"g"},{"name":"花椒（ホアジャオ）","unit":"g"},{"name":"弾頭唐辛子","unit":"g"},{"name":"長ネギ","unit":"本"},{"name":"生姜","unit":"g"},{"name":"ニンニク","unit":"片"},{"name":"トウバンジャン（豆板醤）","unit":"g"},{"name":"テンメンジャン（甜麺醤）","unit":"g"},{"name":"ビール","unit":"ml"},{"name":"薄口醤油","unit":"ml"},{"name":"塩","unit":"g"}]'::jsonb, '["ザリガニをきれいに洗って背わたを取り、長ネギは2cmの長さに切り、生姜とニンニクはみじん切りにする。","油を熱し、油が少し温まったら、ローリエ、八角、桂皮、青花椒、花椒、弾頭唐辛子を加える。","香りが立ったら、長ネギ、生姜、ニンニクを加える。","長ネギ、生姜、ニンニクの香りが立ったら、トウバンジャンとテンメンジャンを加えて、赤い油が出るまで炒める。","ザリガニを加え、色が変わるまで炒める。","ビールを加え、沸騰したら薄口醤油と塩を加える。","ザリガニに完全に火が通ったら、火を止める。"]'::jsonb, '["水産","麻辣","うま味","四川・湖南","酒の肴","家庭料理"]'::jsonb),
  ('howtocook:aquatic/干煎阿根廷红虾/干煎阿根廷红虾', 'ja', 'アルゼンチン赤エビの乾煎り', '魚介', '美味しく魅力的な海鮮の時短料理です。焼き上げたアルゼンチン赤エビは身が白く柔らかく、味は甘く濃厚で、殻はサクサク。ヨウ素、リン、アスタキサンチンなどの微量元素が豊富で、免疫力向上、心臓保護、コレステロール低下に役立ちます。難易度は中程度で、火加減と裏返しのコツが必要ですが、手順は明確なので初心者でも成功できます。約20分で完成します。', '[{"name":"アルゼンチン赤エビ（冷凍エビ使用）","unit":"尾"},{"name":"海塩（粒）","unit":"g"},{"name":"黒胡椒（挽き）","unit":"g","note":"適量"},{"name":"白ワイン","unit":"ml"},{"name":"薄口醤油","unit":"ml"},{"name":"パクチー","unit":"枚"},{"name":"レモン","unit":"枚"},{"name":"玉ねぎ","unit":"g"},{"name":"生姜","unit":"g"},{"name":"にんにく","unit":"g"}]'::jsonb, '["アルゼンチン赤エビを解凍します。できれば前日冷凍庫から冷蔵庫に移して自然解凍すると、風味と食感がより良くなります。背開きして背ワタを取ってあるものを買うと、時間が節約できます。","解凍したエビを洗って水気を拭き取ります。ここでしっかり水気を切ることが重要です。急ぐ場合はキッチンペーパーで水分を吸い取ります。","生姜は薄切り、玉ねぎは小さな角切り、パクチーは洗って葉と茎を分け、葉はみじん切り、にんにくは潰して細かく刻みます。","強火で鍋を熱し、温まったらオリーブオイル大さじ2を入れ、油が熱くなったら生姜の薄切り、玉ねぎの角切り、パクチーの茎を加えて炒めます。","約1分後に生姜、玉ねぎ、パクチーの茎を取り出して捨てます。","中強火にしてエビを入れ、すべてのエビの片面がフライパンにしっかり触れるようにして約2分焼きます。同時に各エビに油を塗ります。","底面の殻がうっすら焦げ色になったら裏返し、にんにくのみじん切りを振り入れ、フライパンを軽く揺らして均一に熱を通します。","約1分後、白ワイン20mlを加えます。","さらに1分焼いたら中弱火にし、均一に塩と黒胡椒を振ります。","各エビに醤油を一滴ずつ垂らします。","パクチーの葉を散らして盛り付けます。","レモンをスライスして皿の脇に添えます。"]'::jsonb, '["水産物","香ばしい","乾煎り","時短","家庭料理"]'::jsonb),
  ('howtocook:aquatic/微波葱姜黑鳕鱼', 'ja', 'レンジ葱生姜黒鱈', '魚介', '電子レンジで魚を調理し、ねぎと生姜で旨味を引き出し、熱い油をかけることで香りが広がります。肉質は柔らかく、味は塩味と旨味が効いた家庭的な蒸し魚料理で、広東風をアレンジしたものです。黒鱈は良質なタンパク質とオメガ3脂肪酸が豊富で、心臓や脳の健康に良いです。操作は複雑ではありませんが、火加減と油の温度管理が必要で、ある程度料理経験のある方に向いています。準備から食卓まで約20分でできます。', '[{"name":"ギンダラ（皮付き）","unit":"g"},{"name":"葱（白い部分）","unit":"g"},{"name":"葱（緑の部分）","unit":"g"},{"name":"生姜","unit":"g"},{"name":"料理酒","unit":"mL"},{"name":"醤油","unit":"mL"},{"name":"ごま油","unit":"mL"},{"name":"ピーナッツ油","unit":"mL"}]'::jsonb, '["魚の切り身をそれぞれ密閉袋に入れ、皮を下にして皿に置きます。","葱の白い部分25gを千切りにし、生姜の皮をむいて10gを千切りにし、混ぜ合わせて半分ずつに分け、それぞれの袋の魚の上に置きます。","各袋に料理酒2.5mLを注ぎます。","密閉袋を閉じ、電子レンジに入れ、中火（800W）で魚が白く不透明になりほぐれやすくなるまで（約3.5〜5分）加熱し、袋から取り出します。","葱と生姜を取り除きます。","醤油25mL、ごま油2mLを混ぜ合わせ、均等に2枚の魚の切り身にかけます。","葱の緑の部分10gを細い千切りにし、生姜の皮をむいて3gを千切りにし、混ぜ合わせて2つに分けて魚の上に散らします。","ピーナッツ油50mLを小さな鍋で190℃に加熱します。","熱した油を葱の緑をのせた魚の切り身にかけ、すぐにテーブルに出します。"]'::jsonb, '["海鮮","風味豊か","レンジ","広東風","家庭料理","時短","おもてなし"]'::jsonb),
  ('howtocook:aquatic/水煮鱼', 'ja', '水煮魚', '魚介', '水煮魚は、麻辣で香り豊か、魚肉が柔らかい定番の四川料理です。バサは良質なタンパク質が豊富で脂肪分が低く、旬の野菜と組み合わせることで栄養バランスが良いです。作り方は中級程度で初心者には少し難しいですが、手順通りに進めば成功します。調理時間は約2時間です。', '[{"name":"バサ","unit":"g"},{"name":"野菜（ジャガイモ、もやし、カリフラワー、レタスなど）","unit":"g"},{"name":"赤油豆板醤","unit":"g"},{"name":"豆豉（オプション）","unit":"g"},{"name":"花椒油","unit":"ml"},{"name":"菜種油","unit":"ml"},{"name":"白胡椒","unit":"g"},{"name":"ニンニク","unit":"片"},{"name":"塩","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"熱湯","unit":"ml"}]'::jsonb, '["準備：バサが冷凍庫から出した場合は、室温で5時間自然解凍してからスライスします。","スライス：バサを薄切りにします。長さ約5cm、幅約3cm。","下味：スライスしたバサを大きなステンレスボウルに入れます。","豆板醤30g、塩3g、花椒油10ml、白胡椒3gを加えます。","手でよく混ぜ合わせ、最後に菜種油5mlを加えて味を閉じます。","室温で少なくとも30分置いて味を染み込ませます。","野菜の準備：ニンニクをみじん切りにします。例として、カリフラワー300g、レタス200gを使います。カリフラワーとレタスを洗います。","湯通しと炒め：カリフラワーを熱湯でさっと茹でておきます。レタスは洗って水気を切り、油を引かずに炒めておきます。","豆板醤を炒める：鍋を熱して油（菜種油20ml）を引き、豆板醤10g、豆豉（オプション）10g、ニンニクのみじん切りを加え、中火でゆっくり炒めます。","魚のスライスを茹でる：熱湯150mlを加え、すぐに沸騰したら下味をつけた魚のスライスを加え、そっと混ぜて魚がほぐれるようにします。塩2gと砂糖2gで味を調えます（この時点で塩加減はお好みで調整）。再び沸騰したらすぐに盛り付けます。","盛り付け：まず炒めた野菜を大きめのボウルに盛り、その上に熱々の魚のスライスをのせ、鍋に残った熱いスープをかけます！"]'::jsonb, '["魚介類","麻辣","香り豊か","四川料理","家庭料理","ご飯が進む"]'::jsonb),
  ('howtocook:aquatic/油焖大虾/油焖大虾', 'ja', '油焖大エビ', '魚介', 'この山東料理の定番は、甘辛いタレがエビ全体を包み込み、仕上がりは赤く艶やかで、エビの身は締まりつつも弾力があります。エビ自体は高品質のタンパク質とアスタキサンチンが豊富で、脂肪分が低く、栄養補給に適した食材です。調理には葱油作り、エビの下処理、蒸し焼き、煮詰めが必要で、火加減と味付けのコツがいるため、ある程度経験のある方におすすめです。全体で約40分かかります。', '[{"name":"黒虎エビ/車エビ","unit":"尾","note":""},{"name":"花椒","unit":"g","note":""},{"name":"ネギ","unit":"g","note":""},{"name":"ショウガ","unit":"g","note":""},{"name":"紹興酒","unit":"g","note":""},{"name":"水","unit":"小鉢","note":""},{"name":"塩","unit":"g","note":""},{"name":"氷砂糖","unit":"g","note":""},{"name":"植物油","unit":"","note":"適量"}]'::jsonb, '["エビの槍（とげ）は根元から、ヒゲと足はすべて切り落とし、砂袋を取り除き、背開きにして背ワタを取ったら、洗って水気を切る。","葱油を作る","油の温度が3割程度になったら花椒を入れ、油が熱くなったら火を止め、ネギとショウガを入れる（油の色が変わらないように注意）。ネギが少し黄色くなったら油をこす（葱油が余ったら、麺にかけるなどに使える）。","油を入れ、エビをきれいに並べ、両面の色が変わったら軽くエビの頭を押す。","生姜みじん切りを加える。","紹興酒30g","水 小鉢2杯","塩 3g","氷砂糖 10g","強火で沸騰させたら弱火にし、蓋をして蒸し焼きにする（途中でスープや水は追加せず、蓋を開けない）。","皮がつやつやしてエビが曲がったら火を止め、エビを盛り付ける。","煮汁をこして鍋に戻し、とろみがつくまで煮詰め（汁が1/4になったら）、葱油を加える。","盛り付けたエビに煮汁をかける。","完成","油焖大エビのプレビュー画像-1","いただきます✅"]'::jsonb, '["海鮮","山東料理","甘辛","蒸し焼き","家庭料理","おもてなし","旨味"]'::jsonb),
  ('howtocook:aquatic/混合烤鱼/烤鱼', 'ja', '焼き魚', '魚介', 'この四川風焼き魚は、辛くて香り高く、魚は外はカリッと中はふんわり。野菜がスープを吸ってご飯が進む一品です。草魚は良質なタンパク質が豊富で、様々な野菜と組み合わせることで栄養バランスも良好。作り方は一見複雑そうですが、手順に従えば実は簡単で、難しい料理に挑戦したい初心者にもおすすめです。準備から食卓へ約1時間かかります。', '[{"name":"草魚","unit":"斤"},{"name":"長ネギ","unit":"本"},{"name":"食用油","unit":"ml"},{"name":"料理酒","unit":"ml"},{"name":"食塩","unit":"g"},{"name":"白こしょう","unit":"g"},{"name":"桂皮","note":"一小片"},{"name":"八角","unit":"個"},{"name":"ニンニク","unit":"個"},{"name":"ローリエ","unit":"枚"},{"name":"青花椒","note":"一小把"},{"name":"乾燥唐辛子","unit":"個"},{"name":"丸唐辛子","unit":"個"},{"name":"セロリ","unit":"本"},{"name":"玉ねぎ","unit":"個"},{"name":"干し湯葉","unit":"枚"},{"name":"もやし","note":"適量"},{"name":"豆板醤","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"薄口醤油","unit":"ml"},{"name":"クミンパウダー","note":"適量"},{"name":"ピーナッツ","note":"適量"},{"name":"白ごま","note":"適量"},{"name":"小ネギ","note":"適量"},{"name":"パクチー","note":"お好みで"}]'::jsonb, '["草魚（通常3斤）を背中から切り開き、両面の背中に沿って数本切り込みを入れます。ただし腹側まで切らないように。そうしないと形が崩れやすくなります。","熱湯を魚にかけてぬめりを取るか、流水下でブラシでこすり洗いし、ぬめりがなくなるまで洗います。","魚を容器に入れ、料理酒、白こしょう10g、食塩5gを加えてよく揉み込み、20分置いて味をなじませます。","長ネギ半分をぶつ切りにし、ニンニクは半分に切って、八角、ローリエ、シナモンスティックと一緒に容器に入れます。","乾燥唐辛子を半分に切り、丸唐辛子と一緒に容器に入れます。","セロリは小口切りにします。","もやしは茹でておきます。","干し湯葉は茹でて千切りにします。","玉ねぎは千切りにします。","魚を焼きます。","オーブンがある場合、天板に油を塗り、魚の皮目を下にして両面がきつね色になるまで焼き、クミンを振ります。","オーブンがない場合は、鍋を熱して油を引き、鍋の縁に食塩2gをふり、草魚を入れて焼きます。入れ始めは動かさず、片面が固まったら裏返し、両面がきつね色になるまで焼き、クミンを振ってから皿に盛ります。","鍋にサラダ油20mlを引き、油が熱くなったら、長ネギ、ニンニク、八角、ローリエを入れて香りが立つまで炒めます。","火鍋の素の半量と豆板醤15-20gを加え、赤い油が出るまで炒めます。","砂糖5g、食塩10g、薄口醤油5mlを加えて味を調え、材料が浸るくらいの水を加えて沸騰させます。","セロリ、もやし、干し湯葉を順に加えます。完全に火を通さず、さっと茹でたら玉ねぎの千切りを敷き、焼き魚をのせます。","乾燥唐辛子、丸唐辛子、青花椒を加えます。","別の鍋で油を熱し、熱した油を先ほどの唐辛子の上にかけて香りを引き立てます。","最後にピーナッツ、小ネギ、白ごま、パクチーを散らします。","5～6分煮たら完成です。"]'::jsonb, '["水産","麻辣","うま味","ご飯が進む","四川料理","焼き","おもてなし"]'::jsonb),
  ('howtocook:aquatic/清蒸生蚝', 'ja', '蒸し牡蠣', '魚介', '蒸し牡蠣は、素材の味を生かした沿岸の家庭料理です。牡蠣の身は柔らかくてジューシーで、ほのかな海の塩気が感じられます。ニンニクと生姜の千切りが甘みを引き出します。牡蠣は良質なタンパク質と亜鉛が豊富で、免疫力向上に役立ちます。調理は難しくありませんが、熱い鍋の蓋を開けるときや殻の処理には少し注意が必要です。初心者でも簡単にできます。洗ってから盛り付けるまで、約20分で完成します。', '[{"name":"牡蠣","unit":"個"},{"name":"ねぎ","unit":"本"},{"name":"にんにく","unit":"かけ"},{"name":"しょうが","unit":"1片"},{"name":"しょうゆ","unit":"ml"}]'::jsonb, '["牡蠣をブラシでよく洗う（ブラシがない場合は歯ブラシを使う）。","蒸し鍋に水を入れ、蒸し板を置き、6個の牡蠣を平らに並べる。出力50%で3分蒸す。","右手で濡れ布巾を持って熱い蓋を開け、各牡蠣の上の殻を半分だけ取り除く。牡蠣の凸面を下に、平らな面を上にする。各牡蠣に生姜の千切り1本と、にんにくのみじん切り10gをのせる。","蓋を閉め、出力100%で3.5分蒸す。","火を止め、右手で布巾を持って熱い蓋を開け、各牡蠣に醤油5mlずつかける。","皿に盛り付ける。"]'::jsonb, '["魚介","蒸し","海鮮","あっさり","家庭料理","時短"]'::jsonb),
  ('howtocook:aquatic/清蒸鲈鱼/清蒸鲈鱼', 'ja', 'スズキの清蒸', '魚介', '清蒸スズキは広東料理の定番蒸し料理で、身はとても柔らかく滑らかで、味はあっさりとして旨味があり、スズキの本来の風味を最大限に引き出します。スズキは良質なタンパク質とDHAが豊富で、栄養価が高く消化が良いです。この料理は作り方が簡単で、初心者にも優しく、下準備から出来上がりまで約30分です。', '[{"name":"スズキ","unit":"尾"},{"name":"青ネギ","unit":"本"},{"name":"生姜","unit":"片"},{"name":"サラダ油","unit":"ml"},{"name":"蒸し魚醤油","unit":"ml"},{"name":"料理酒","unit":"ml"},{"name":"食塩","unit":"g"}]'::jsonb, '["生姜は薄切りと千切りにし、青ネギの白い部分はぶつ切りに、緑の部分は千切りにする。千切りにしたものは冷水に浸しておく。","スズキは処理して洗い、キッチンペーパーで水気を拭き取り、両面に数本切り目を入れる。塩で魚の表面のぬめりを洗い落とし、10gの塩を魚全体に内外まんべんなくすり込んで、10分以上漬け込む。","スズキの切り方と盛り付け方の補足：切り目を入れることでスズキを立てて蒸すことができ、均等に熱が通り、食べやすくなり、裏返す必要がありません。","切り目を入れる","清蒸スズキ-プレビュー図-2","魚のお腹に生姜と青ネギの白い部分を詰め、魚の表面にも生姜と青ネギの白い部分を振りかける（使う量は用意したものの半分）。蒸し皿には箸を敷いて魚を浮かせて蒸す。","お湯が温かくなったら魚を入れる。","強火で10分蒸す。","蒸し上がった魚を清潔な皿に移し、表面の生姜とネギを取り除く。","魚に15mlの蒸し魚醤油をかける。","魚の上に再び生姜と青ネギの千切りを乗せ、鍋に10mlのサラダ油を熱し、熱した油を魚にかけて完成。"]'::jsonb, '["魚介類","蒸し","広東風","あっさり","ふんわり","家庭料理"]'::jsonb),
  ('howtocook:aquatic/白灼虾/白灼虾', 'ja', '白灼エビ', '魚介', '白灼エビは広東料理の定番スピード料理で、エビの身は甘くてプリプリ、素材の味を生かしています。エビ自体は良質なタンパク質や各種ミネラルが豊富で、タレと合わせるとさっぱりとして食欲をそそります。作り方は簡単で失敗が少なく、初心者にとっても優しく、準備から完成まで約15分です。', '[{"name":"活きエビ","unit":"グラム"},{"name":"玉ねぎ","unit":"個"},{"name":"生姜","unit":"塊"},{"name":"ニンニク","unit":"片"},{"name":"ネギ","unit":"本"},{"name":"食用油","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"料理酒","unit":"ml"},{"name":"ゴマ","note":"ひとつかみ"},{"name":"香醋","unit":"ml"},{"name":"オイスターソース","unit":"ml"}]'::jsonb, '["玉ねぎを小さく切り、生姜を薄切りにし、フライパンに敷き詰める。","活きエビをさっと洗い（背ワタを取る、ハサミで脚やひげを切るのは任意）、水気を切り、フライパンの玉ねぎと生姜の上に並べる。","鍋に料理酒を注ぎ、蓋をして、中火で1分、弱火で5分、火を止めて5分置く。","前の手順と並行して、つけダレを作る：","ネギを小口切りにし、ニンニクをみじん切りにし、醤油、ゴマ、香醋を加えて混ぜる。","油を熱し、つけダレにかける。","エビを取り出し、清潔な皿に盛る。"]'::jsonb, '["海鮮","広東式","旨味","時短","家庭料理"]'::jsonb),
  ('howtocook:aquatic/糖醋鲤鱼/糖醋鲤鱼', 'ja', '糖酢鯉（タンツーリーユー）', '魚介', '糖酢鯉は山東料理の定番で、外はカリッと中はふんわり、甘酸っぱい味わいが食欲をそそります。魚を黄金色に揚げ、赤く輝く甘酢あんをかければ、見た目も美しい一品。鯉は良質なタンパク質とミネラルが豊富で、消化吸収も良好。初心者にはやや難しく、中級者向け。切り込み、衣付け、揚げ加減のコツが必要。下準備から完成まで約1時間。', '[{"name":"鯉","unit":"斤"},{"name":"ケチャップ","unit":"グラム"},{"name":"砂糖","unit":"グラム"},{"name":"白酢","unit":"グラム"},{"name":"片栗粉","unit":"グラム"},{"name":"塩","unit":"グラム"},{"name":"長ネギ","unit":"グラム"},{"name":"生姜","unit":"グラム"},{"name":"料理酒","unit":"グラム"},{"name":"パクチー","unit":"束"},{"name":"薄力粉","unit":"グラム"},{"name":"卵","unit":"個"},{"name":"水","unit":"グラム"},{"name":"食用油","unit":"リットル"}]'::jsonb, '["魚をきれいに洗い、うろこなどの異物がないことを確認する","魚の頭を左、腹を下にして、右手で包丁を持つ。包丁を垂直に1cm切り込み、魚を押さえながら左へ3-4cm薄くそぎ、さらに切り込みの中央に軽く包丁を入れる","魚をボウルに入れ、生姜をスライス、長ネギをぶつ切りにする（ざっくりでOK、主に臭み取り）","全力で長ネギと生姜の汁を絞ってボウルに入れる","塩20g、料理酒25gを加え、鯉によく揉み込むように塗り広げる","漬け込む","清潔なボウルに薄力粉100g、片栗粉200g、水180g、塩5gを入れ、手でよく混ぜる。衣はねっとりとして糸を引く状態になる。そこに卵1個を割り入れ、さらに混ぜる","30分待つ","魚をまな板に置き、乾いた布巾で水分を拭き取る（衣が付きやすくなる）","ボウルを洗い、乾いた布巾で拭く","鍋を熱して油を約1L入れ、油温を7割（約200-240℃）に熱する","魚の尾をつまんで頭から鍋底に沈め、お玉で熱い油を魚全体にかける。衣が固まってきたら、魚をゆっくり鍋に入れ、鍋杓子で魚の頭を軽く持ち上げ、笊籬を敷く。底が焦げるのを防ぐ","魚を盛り付ける皿を鍋の横に準備する","鍋杓子で魚の身をそっと支えながら、2つの道具を使ってひっくり返す。さらに2分揚げる。同じ方法（笊籬で頭を支え、鍋杓子で身を支えながら）で魚を皿に盛る","鍋の油を乾いたボウルに注ぎ、鍋を洗う","小さなボウルに水50g、ケチャップ40g、砂糖20g、白酢10gを入れ、混ぜる","別の小さなボウルに片栗粉10g、水10gを入れ、水溶き片栗粉を作る","強火で鍋を熱し、先ほどの合わせ調味料を入れて強火で沸かし、弱火にする","水溶き片栗粉を加え、混ぜながら20秒後に火を止める","出来上がった甘酢あんをスプーンで魚全体に均等にかけ、パクチーやネギを飾れば完成","糖酢鯉-プレビュー画像-2"]'::jsonb, '["水産","甘酸っぱい","揚げ物","山東料理","宴客","年夜飯"]'::jsonb),
  ('howtocook:aquatic/红烧鱼', 'ja', '紅焼き魚', '魚介', '紅焼き魚は家庭料理の定番で、塩味と甘みのバランスが良く、魚の身は滑らかで味が染み込みやすい、大衆に愛される中華風煮魚です。魚は良質なタンパク質と不飽和脂肪酸が豊富で、栄養が吸収されやすいです。調理には生魚の処理と油煎めが必要で、手順がやや多く初心者には挑戦的ですが、レシピ通りに進めば成功します。準備から完成まで約40分かかります。', '[{"name":"生姜","unit":"枚"},{"name":"ニンニク","unit":"片"},{"name":"乾燥唐辛子","unit":"本"},{"name":"油","unit":"ml"},{"name":"塩","unit":"グラム"},{"name":"料理酒","note":"適量"},{"name":"酢","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"砂糖","unit":"グラム"},{"name":"魚","unit":"尾"},{"name":"オイスターソース","unit":"グラム"},{"name":"ネギ","unit":"本"},{"name":"パクチー","note":"お好みで"},{"name":"小唐辛子"},{"name":"味の素（鶏ガラスープの素）","unit":"グラム"}]'::jsonb, '["生姜とニンニクを用意し、みじん切りにする","乾燥唐辛子をみじん切りにし、生姜とニンニクと一緒にする","油30〜50mlを加え、鍋が熱くなるのを待つ","水気を拭いた魚を入れ（熱い油が跳ねたくない場合）、鍋を揺らしながら弱火で魚を揚げ焼きにする","魚を裏返し、同じように揚げ焼きを繰り返す","生姜、ニンニク、唐辛子を加え、香りが立つまで炒める","料理酒を多めに加える（この工程は安全に注意、大量の油煙が立つ）","酢を加える（酢が好きなら多めに入れてよい）","次に砂糖と醤油（老抽）を加える","冷水を魚の身がちょうど浸るくらい加え、中火にして蓋をする。約1分後に魚を裏返し、再び蓋をする","3〜4分後、塩、小唐辛子、オイスターソース（味の素、鶏ガラスープの素など）を加え、再び蓋をして、その後も適宜裏返す","鍋の汁が魚の背びれの少し下まで煮詰まったら（または汁が少なくなったら）、弱火にし、パクチーとネギを加えて蓋をし、20秒後に火を止める","鍋から取り出す"]'::jsonb, '["水産","紅焼き","塩味と甘み","揚げ焼き","家庭料理","ご飯が進む"]'::jsonb),
  ('howtocook:aquatic/红烧鱼头', 'ja', '紅焼き魚頭', '魚介', '紅焼き魚頭は、定番の家庭料理です。魚頭はコラーゲンが豊富で、身はやわらかく、スープは塩味と旨味があり少し辛く、ご飯が進みます。魚頭には良質なたんぱく質、レシチン、不飽和脂肪酸が含まれており、肌や脳に良いです。生の魚の処理や骨切りが必要なためやや難易度が高く、初心者が一人で行うのはお勧めしません。全工程（漬け込み含む）で約2～2.5時間かかります。', '[{"name":"魚頭","unit":"個"},{"name":"長ネギ","unit":"g"},{"name":"生姜","unit":"g"},{"name":"ニンニク","unit":"個"},{"name":"美人唐辛子","unit":"個"},{"name":"パクチー","unit":"株"},{"name":"八角","unit":"個"},{"name":"乾燥唐辛子","unit":"個"},{"name":"油","unit":"ml"},{"name":"塩（漬け用）","unit":"g"},{"name":"塩（煮込み用）","unit":"g"},{"name":"薄口醤油（漬け用）","unit":"g"},{"name":"薄口醤油（煮込み用）","unit":"g"},{"name":"料理酒（漬け用）","unit":"g"},{"name":"料理酒（煮込み用）","unit":"g"},{"name":"鶏がらスープの素","unit":"g"},{"name":"濃口醤油","unit":"g"},{"name":"黒酢","unit":"g"},{"name":"黒胡椒","unit":"g"},{"name":"水","unit":"ml"}]'::jsonb, '["ネギ、生姜、ニンニク、パクチー、美人唐辛子をそれぞれ洗ってきれいにする。","乾燥唐辛子と八角は軽く洗うだけでよい。","長ネギを半分に切る。後半部分（白い部分）は長さ約4cmのぶつ切りにし、前半部分（葉の部分）もぶつ切りにしてから、さらに縦に四つ割りにする。","生姜は厚さ約3mmの薄切りにする。","ニンニクは包丁でつぶす。","パクチー2株の根を落とし、1.5cmのざく切りにする。","美人唐辛子は厚さ3mmの輪切りにする。","乾燥唐辛子は4等分に切る。","注：以下に述べる魚身とは、魚頭を購入した際に付いてくる魚肉のことです。","魚頭のうろこを取り、洗って、取り残した内臓を取り除く。","ひれを切り落とし、えらをきれいに取り除く。","魚頭の下あごと魚身のつなぎ目を切り離し、魚身はぶつ切りに、魚頭は4～6つに切り分ける。","注：魚の処理は文字だけでは説明しづらいので、動画などで確認することをおすすめします。","切り分けた魚を洗い、できれば血の塊を洗い流す。","洗った魚をボウルに入れ、塩5g、薄口醤油10g、料理酒10gを加える。刻んだネギの前半部分と、生姜の1/3を加えて混ぜ合わせ、1～2時間おく。","油30mlを加え、鍋が熱くなるのを待つ。","油が熱くなったら、火を弱火にする。","注：なぜこうするのかわからない場合は、「炒める・焼く」の項目で香りを出す炒め方を確認してください。","生姜の薄切りを入れ、ゆっくり炒める。生姜の汁気がほとんどなくなり、きつね色になるまで。","ネギのぶつ切りを加え、白っぽくなるまで炒める。","つぶしたニンニク、八角、乾燥唐辛子を加えて5秒炒める。","漬け込んだ魚を鍋に加え、2～3分炒める。","水500mlを注ぎ、塩2g、鶏がらスープの素3g、薄口醤油5g、濃口醤油3g、料理酒5g、黒胡椒2g、黒酢3gを加える。","パクチー2株を鍋に入れ、蓋をする。","強火にして沸騰させる。","中火にして、じっくりと煮含める。","煮汁が半分になったら蓋を取る。","強火にして煮詰め、煮汁が1/3になったら火を止め、小さな鉢に盛り付ける。","注：鍋の煮汁を魚に均一にかけ、盛り付ける際に鍋で煮たパクチーを鉢の底に敷くと、見た目も良く美味しく仕上がります。","盛り付けた魚の上にパクチーを飾り、その上に輪切りにした美人唐辛子をのせる。","彩り豊かな紅焼き魚頭の完成！"]'::jsonb, '["水産","紅焼き","塩味・旨味","少し辛い","煮込み","ご飯が進む","家庭料理"]'::jsonb),
  ('howtocook:aquatic/红烧鲤鱼', 'ja', '紅焼鯉魚', '魚介', '紅焼鯉魚は家庭的な魯菜（山東料理）で、魚は一度揚げてから煮込みます。皮は少し歯ごたえがあり、身は柔らかく、甘辛い醤油の風味に豚バラ肉のコクが加わり、とろみのある煮汁がご飯によく合います。良質なタンパク質やカルシウム、リンなどのミネラルが豊富で、滋養補給に役立ちます。魚の揚げ方や味付けの配分には少し手間がかかりますが、手順は明確なので初心者でも作れます。準備から仕上げまで約1時間かかります。', '[{"name":"鯉","unit":"斤"},{"name":"豚バラ肉","unit":"グラム"},{"name":"長ネギ","unit":"グラム"},{"name":"ショウガ","unit":"グラム"},{"name":"ニンニク","unit":"個"},{"name":"乾燥唐辛子","unit":"個"},{"name":"油","note":"適量"},{"name":"塩","unit":"グラム"},{"name":"薄口醤油","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"黒酢","unit":"ml"},{"name":"オイスターソース","unit":"ml"},{"name":"料理酒","unit":"ml"},{"name":"砂糖","unit":"グラム"}]'::jsonb, '["ネギ、ショウガ、ニンニク、乾燥唐辛子をそれぞれ洗う。","ネギの白い部分を長さ約4cmに切り、さらに各切れ目を縦に4つに裂く。","ショウガは厚さ約3mmのスライスにする。","ニンニク1片を潰してみじん切りにし、残りのニンニクは半分に切る。","乾燥唐辛子を4等分に切る。","豚バラ肉を約4cm×4cmのスライスに切る。","魚を洗う。","魚の背中の肉厚部分に斜めに数本切り込みを入れ、味が染み込みやすくする。","鍋に多めの油を入れ、7分熱（うっすら煙が出始める）になったら魚を入れ、1分間揚げて皮が少し固くなったら取り出す（入れたらすぐに触らず、しばらくしてから返す）。揚げ油は別の容器に移し、鍋には少量の油だけ残す。","鍋に残った油を熱し、豚バラ肉を入れて香りを出す。","乾燥唐辛子、ネギ、ショウガ、ニンニクの半切を加え、1分間炒める。","揚げた魚を鍋に入れる。","鍋肌に沿って、","50mlの料理酒","50mlの黒酢","50mlの薄口醤油","20mlの濃口醤油（色付け用）","5mlのオイスターソース（旨味追加）","5gの塩","50gの砂糖","魚が浸るくらいの水を加える。","中火にして沸騰させる。","弱火にしてじっくり煮込み、味を染み込ませる。","15分後、蓋を開け、鍋からネギ、ショウガ、ニンニク、乾燥唐辛子を取り出す。","強火にして煮汁を飛ばし、汁が1/4になったらみじん切りのニンニクを振り、火を止めて盛り付ける。","紅焼鯉魚の完成！"]'::jsonb, '["水産","紅焼","甘辛","醤油風味","ご飯が進む","魯菜","家庭料理"]'::jsonb),
  ('howtocook:aquatic/肉蟹煲', 'ja', '肉蟹の鍋', '魚介', 'この料理は濃厚な味噌風味で、カニの甘みとほのかな辛さが特徴。じゃがいもはほくほく、餅はもちもち、煮汁をご飯にかけると絶品です。集まりにぴったりのご馳走です。高品質のタンパク質とミネラルが豊富で栄養価も高いです。調理には生きたカニの処理や火加減、調味料のバランスが求められ、初心者にはやや難しいですが、全体で約1時間かかります。', '[{"name":"肉蟹","unit":"g"},{"name":"エビ","unit":"g"},{"name":"じゃがいも","unit":"g"},{"name":"餅","unit":"g"},{"name":"玉ねぎ","unit":"g"},{"name":"にんにく","unit":"g"},{"name":"にんにく（エビ追加時）","unit":"g"},{"name":"生姜","unit":"g"},{"name":"乾燥唐辛子","unit":"g"},{"name":"青ピーマン","unit":"g"},{"name":"赤ピーマン","unit":"g"},{"name":"オイスターソース","unit":"g"},{"name":"シーフードソース","unit":"g"},{"name":"黄豆醤（こうとうじゃん）","unit":"g"},{"name":"甜麺醤（てんめんじゃん）","unit":"g"},{"name":"トマトケチャップ","unit":"g"},{"name":"片栗粉","unit":"g"},{"name":"氷砂糖","unit":"g"},{"name":"チキンエッセンス","unit":"g"},{"name":"白こしょう","unit":"g"},{"name":"白こしょう（エビ追加時）","unit":"g"},{"name":"料理酒","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"サラダ油","unit":"ml"},{"name":"サラダ油（エビ追加時）","unit":"ml"},{"name":"サラダ油（揚げ油用）","unit":"ml"},{"name":"ビール","unit":"ml"},{"name":"ビール（エビ追加時）","unit":"ml"},{"name":"水","unit":"ml"},{"name":"水（エビ追加時）","unit":"ml"}]'::jsonb, '["じゃがいもは3cm角の立方体に、青ピーマンと赤ピーマンは一辺4cmのひし形に、玉ねぎは3cm幅の三日月形に切り、餅は1cm厚さの輪切りにする","カニを50～80gのぶつ切りにし、薄く片栗粉をまぶして180℃の油で1分揚げて取り出す","鍋に油をひき、にんにく、生姜、乾燥唐辛子を炒めて香りを出し、すべての調味料と氷砂糖を加えて弱火で赤い油が出るまで炒める（焦がさないように注意）","カニ、じゃがいも、ビールと水を加え、沸騰したら弱火で12分煮込む","餅と青・赤ピーマンを加え、強火で煮汁が具材に絡むまで煮詰め、最後に白こしょうを振る"]'::jsonb, '["水産","味噌風味","辛味","煮込み","おもてなし","ご飯が進む","集まり"]'::jsonb),
  ('howtocook:aquatic/芥末黄油罗氏虾/芥末黄油罗氏虾', 'ja', 'マスタードバターのテナガエビ', '魚介', 'この料理は、バターとマスタードの不思議な組み合わせが特徴で、エビの身は締まって弾力があり、ソースは濃厚でスパイシーな香りが広がる、新しいスタイルのシーフード料理です。エビには良質なタンパク質と各種ミネラルが豊富で、栄養バランスも良好。調理の難易度は中程度で、事前に材料を準備し火加減を調整すれば、初心者でも成功できます。活エビの処理から仕上げまで約30分です。', '[{"name":"テナガエビ","unit":"斤"},{"name":"バター","unit":"g"},{"name":"マスタード","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"醤油","unit":"g"},{"name":"オイスターソース","unit":"g"},{"name":"塩","unit":"g"},{"name":"料理酒、ラム酒またはビール","unit":"g"},{"name":"コリアンダー","unit":"本"},{"name":"ニンニク","unit":"片"}]'::jsonb, '["テナガエビの頭と尾のとげ、触角、脚を切り落とし、背中に切り込みを入れて背ワタを取り除きます。","マスタードソースをあらかじめ混ぜておきます：醤油、オイスターソース、マスタード、塩、砂糖をよく混ぜます。","コリアンダーを洗い、ざく切りにして準備します。","テナガエビの水気を切り、鍋に油を入れて直接エビを加え、中火で表面がきつね色になるまで焼き、取り出します。","みじん切りのニンニクを加え、強火で、エビを焼いた残りの油でニンニクを炒めます。鍋から白い煙が立ち、ニンニクの香りが立ったら、エビとバターを加え、エビにバターの香りをしっかり吸収させます。","調合したソースを加え、引き続き強火で沸騰させながらエビを炒め、ソースが絡まるまで煮詰めます。酒を加えます（料理酒やビールは30g、ラム酒は風味が強いので15gで十分です）。","ソースが少し煮詰まってきたら、コリアンダーを加えてさっと炒め合わせ、火を止めて完成です。"]'::jsonb, '["シーフード","マスタードの香り","炒め焼き","新しいスタイルのシーフード","おもてなし","時短"]'::jsonb),
  ('howtocook:aquatic/葱油桂鱼/葱油桂鱼', 'ja', '葱油桂魚', '魚介', '葱油桂魚は、葱の風味が豊かで、身が柔らかい家庭的な蒸し料理です。中国の薄味スタイルで、幅広い地域の人々に適しています。桂魚は高品質のたんぱく質と不飽和脂肪酸が豊富で、丁寧な下処理により臭みがなく、旨味と栄養を保っています。初心者にも優しく、手順通りにやれば失敗がほとんどありません。準備から完成まで約45分かかります。', '[{"name":"桂魚","unit":"グラム","note":""},{"name":"小ネギ","unit":"本","note":""},{"name":"ミニトウガラシ","unit":"個","note":""},{"name":"生姜","unit":"グラム","note":""},{"name":"料理酒","unit":"グラム","note":""},{"name":"植物油","unit":"グラム","note":""},{"name":"塩","unit":"グラム","note":""},{"name":"蒸し魚醤油","unit":"グラム","note":""},{"name":"水","unit":"L","note":""}]'::jsonb, '["市場で下処理済みの魚を買う（自分で処理する場合、内臓は取らないほうが良い）。魚の表面の鱗をすべてきれいに取り除く","キッチンペーパーで魚のお腹の中の骨に付いた血と黒い膜を拭き取る（骨の血は食感に影響し、黒い膜は生臭さの原因）","包丁で魚の表面を数回こすり、ぬめりを取り除き、さらに臭みを取る。その後、流水で魚の内外を洗い流す","魚をまな板に平らに置き、キッチンペーパーで内外の水分を拭き取る。魚の頭を左、尾を右にして、えらの端から3cmごとに縦に切り込みを入れ、深さは背骨に届くまで。反対側も同様に処理する","魚を平らなボウルに置き、皿に余分な水分がないことを確認する","生姜50g（卵大）を取り、皮をむいて洗い、厚さ3mmのスライスに切る","ミニトウガラシを洗ってヘタを取り、厚さ2mmの小口切りにする（または幅1mmの千切りにする）","小ネギを洗って根を切り落とし、3cmの長さに切る。太めの小ネギは縦に半分に切る","塩8g、料理酒25gをボウルに加え、使い捨て手袋をして魚を全身1分間マッサージし、塩と酒が均等に行き渡るようにする","マッサージ後、魚の各切り込みに生姜のスライスを1枚ずつ詰め、お腹に3枚の生姜を入れ、10分間漬け込む（漬けすぎると鮮度が落ちるので注意）","魚を漬けている間に、蒸し鍋に水5Lを入れて沸騰させ、蒸し台をセットする","魚の漬け込みが終わると水分が出るので、余分な水分と漬け込み用の酒、生姜を捨て、魚の身とお腹を流水で洗い流し、キッチンペーパーで水分を拭き取る","魚を蒸し皿に平らに置き、再度魚の身とお腹の切り込みに生姜のスライスを詰める","蒸し皿を蒸し台に置き、蓋をして中火で20分間蒸す","その間に蒸気が魚全体と皿に付着し、凝縮して魚のスープができる。出来上がったら絶対にこのスープを捨てないこと。これが旨味のエッセンス","耐熱トングで蒸し皿を取り出し、魚の身と周りに蒸し魚醤油10gをかける","魚の身と周りに小ネギとミニトウガラシを均等に散らす","鉄鍋に植物油15gを入れ、弱めの中火で5分間ゆっくり熱する。強火にしないと油がすぐに揮発する","熱した油を魚の身にゆっくりと均等にかける。これで絶品の葱油桂魚の完成！"]'::jsonb, '["水産","蒸し","葱風味","家庭料理","旨味","薄味"]'::jsonb),
  ('howtocook:aquatic/葱烧海参/葱烧海参', 'ja', '葱焼き海参', '魚介', 'これは、山東料理の定番で家庭的な海鮮煮込み料理です。濃厚なネギの香りと、やわらかく味の染みた海参（ナマコ）が特徴で、とろみのあるタレは塩味と旨味があり、ほのかな甘みが戻ります。海参はコラーゲンや様々な微量元素が豊富で、体を養うのに役立ちます。全体的に調理難易度は高くありませんが、乾燥海参を十分に戻すのに時間をかける必要があります。実際の調理時間は約30分で、初心者でも手順に従えば簡単に成功します。', '[{"name":"戻した海参（ナマコ）","unit":"個"},{"name":"長ネギの白い部分","unit":"本"},{"name":"食用油","unit":"ml"},{"name":"オイスターソース","unit":"g"},{"name":"薄口醤油","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"片栗粉","unit":"g"},{"name":"水","unit":"ml"}]'::jsonb, '["ネギの白い部分を1cmの長さに切り、取っておく。","海参（ナマコ）を1cmの長さに切り、取っておく。","空のボウルを用意し、オイスターソース20g、薄口醤油10g、砂糖2gを入れてよく混ぜる。合わせ調味料。","別のボウルに片栗粉と水を入れ、水溶き片栗粉を作る。とろみ付け用。","鍋を熱し、食用油20ml～25mlを入れる。10秒待って油の温度を上げる。","ネギの白い部分を入れ、弱火にする。焦がさないように注意しながら、約3～5分揚げ焼きにする。","箸でネギを取り出し、皿に取っておく。","合わせ調味料を入れ、香りが出るまで1～2分炒める。","切った海参を入れ、1分炒める。","水100mlを加え、中弱火で5分待つ。","鍋の汁がほぼなくなるまで待ち、水溶き片栗粉を加え、先に取り出したネギを加える。","外観がとろりとしたら火を止め、皿に盛る。葱焼き海参-プレビュー図-5"]'::jsonb, '["水産","山東料理","煮込み","塩味","おもてなし","海の幸"]'::jsonb),
  ('howtocook:aquatic/蒜蓉虾/蒜蓉虾', 'ja', 'ガーリックシュリンプ', '魚介', 'この広東の伝統的な名物料理は、香り高く滑らかな食感が特徴です。エビは甘くて弾力があり、ガーリックの香りが豊かに広がります。海エビには高品質のタンパク質やカルシウム、セレンなどの微量元素が豊富で、ガーリックと合わせると殺菌効果や食欲増進に役立ちます。作り方はとても簡単で、エビの下処理、ソースを塗る、蒸す、油をかけるの数ステップで完成。初心者でも気軽に作れ、全工程約15分です。', '[{"name":"海エビ","unit":"匹"},{"name":"ガーリックソース","unit":"g"},{"name":"食用油","unit":"ml"},{"name":"しょうゆ","unit":"ml"}]'::jsonb, '["包丁でエビの頭の中心から切り込みを入れ、尾から1cmのところまで切る","ガーリックソースをエビの身の中央にのせ、皿に並べる","鍋に熱湯を入れ、皿を鍋に入れて強火で3分蒸す","油を熱し、エビの皿にかけ、しょうゆを加える"]'::jsonb, '["海鮮","香ばしい","蒸し料理","広東風","時短","ご飯が進む"]'::jsonb),
  ('howtocook:aquatic/蒜香黄油虾/蒜香黄油虾', 'ja', 'ガーリックバターエビ', '魚介', 'ガーリックバターエビは定番の洋風シーフード料理です。エビはプリプリの食感で、濃厚なガーリックとバターの風味が絡み、レモンの爽やかな香りがほのかに漂います。エビには良質なタンパク質が豊富で、バターとの組み合わせでエネルギー補給にも最適。作り方は簡単で、いくつかの一般的な食材だけでOK。初心者でも手軽にでき、下ごしらえから完成まで約20分です。', '[{"name":"エビ","unit":"尾"},{"name":"無塩バター","unit":"g"},{"name":"ニンニク","unit":"片"},{"name":"白ワイン","unit":"ml"},{"name":"レモン","unit":"個"},{"name":"オリーブオイル","unit":"ml"}]'::jsonb, '["エビは頭と殻をむき、尾を残す。爪楊枝で背ワタを取り除き、洗ってキッチンペーパーで水気を拭き取る。","ニンニクはみじん切りにして置いておく。","フライパンを中火にかけ、オリーブオイル10mlを入れる。","油が熱くなったらエビを入れ、片面1～1.5分ずつ焼いて色が変わるまで焼き、取り出しておく。","同じフライパンにバターを加えて溶かし、ニンニクのみじん切りを入れて弱火で香りが立つまで炒める（約30秒）。","白ワインを使う場合は、ここで加えてアルコールが飛ぶまで煮る（約1分）。","エビをフライパンに戻し、ガーリックバターソースと絡めながら約1分炒める。","レモン汁を絞り入れ、さっと混ぜてすぐに火を止める。","皿に盛り、フライパンに残ったソースをかける。"]'::jsonb, '["シーフード","ガーリック風味","うま味","洋風","炒め","スピード料理","海鮮"]'::jsonb),
  ('howtocook:aquatic/蛏抱蛋/蛏抱蛋', 'ja', 'マテガイの卵焼き', '魚介', 'マテガイの卵焼きは福建福州一帯の伝統的な家庭料理で、マテガイの身が卵液に包まれて外はカリッと中はふんわり、玉ねぎと醤油の塩味と香りが広がります。マテガイは良質なタンパク質や亜鉛、鉄などの微量元素が豊富で、卵と組み合わせることで栄養バランスが良くなります。調理の難易度は普通で、揚げ焼きの火加減がポイントですが手順は複雑ではなく、約30分で食卓に並べられます。', '[{"name":"マテガイ","unit":"g"},{"name":"卵","unit":"個"},{"name":"サラダ油","unit":"ml"},{"name":"玉ねぎ","unit":"個"},{"name":"片栗粉","unit":"g"},{"name":"薄口醤油","unit":"ml"},{"name":"鶏がらスープの素","unit":"ml"},{"name":"料理酒","unit":"ml"}]'::jsonb, '["お湯を沸かし、マテガイを入れて2分茹で、取り出して殻をむき、大きめのボウルに入れる","大きめのボウルに玉ねぎ、薄口醤油、料理酒、鶏がらスープの素、片栗粉を加えてよく混ぜる","大きめのボウルに卵を2個割り入れ、さらに混ぜる","フライパンに油を熱し、ボウルのマテガイを流し入れ、片面がきつね色になるまで揚げ焼きにし、裏返してさらに揚げ焼きにする"]'::jsonb, '["海鮮","香ばしい","揚げ焼き","福建料理","家庭料理","ご飯のおかず"]'::jsonb),
  ('howtocook:aquatic/酱炖蟹', 'ja', '蟹のトウバンジャン蒸し', '魚介', 'この料理は浙江省平湖地方の秋限定の塩味と旨味が特徴。蟹の黄身がなめらかで醬の香りに包まれ、蟹身は甘く、汁をご飯にかけると絶品。良質なタンパク質と微量元素が豊富。難易度は中程度で、初心者でも基本があれば作れる。準備から完成まで約30分。', '[{"name":"カニ（できれば河ガニ、次にワタリガニ）","unit":"g"},{"name":"トウバンジャン","unit":"g"},{"name":"氷砂糖（お好みで）","unit":"g"},{"name":"濃口醤油","unit":"ml"},{"name":"菜種油（脱色していないもの、通称「毛菜油」または「土菜油」、代用はピーナッツ油）","unit":"ml"},{"name":"トマトケチャップ","unit":"ml"},{"name":"料理酒","unit":"ml"},{"name":"生姜","unit":"g"},{"name":"小ネギ","unit":"g"},{"name":"卵（お好みで）","unit":"個"},{"name":"豚ひき肉（お好みで）","unit":"g"},{"name":"水","unit":"mL"}]'::jsonb, '["カニをたわしできれいに洗い、まな板で半分に切る","鍋に菜種油を入れ、生姜のみじん切りとトウバンジャンを加えて香りが出るまで炒め、氷砂糖を加えて溶かし、小さな泡が出るまで炒めて取り出す","皿に先ほど作った醬を薄く敷き、切ったカニを切り口を下にしてきれいに並べる","ネギのぶつ切りと生姜の薄切りをのせる。卵を割り入れたり、皿の底にひき肉を敷くのがおすすめ","蒸し器で10～12分蒸す"]'::jsonb, '["魚介","塩味・旨味","醬香","蒸し","江浙","ご飯が進む","秋限定"]'::jsonb),
  ('howtocook:aquatic/阳朔啤酒鱼/阳朔啤酒鱼', 'ja', '陽朔ビール魚', '魚介', '陽朔ビール魚は広西陽朔のご当地料理で、漓江の新鮮な魚を鱗ごと揚げ焼きにし、水の代わりにビールで煮込みます。魚の鱗はサクサク、身はふんわり、ビールの香りとトマトの酸味が絶妙に絡み合い、風味豊かでユニークです。魚には良質なタンパク質やミネラルが豊富で、トマトや唐辛子と組み合わせることでビタミンもたっぷり、食欲をそそります。調理難易度は中程度で、初心者には少し挑戦的ですが、手順通りに進めれば成功します。所要時間は約30分です。', '[{"name":"剣骨魚またはコイ","unit":"尾"},{"name":"漓泉ビール","unit":"ml"},{"name":"トマト","unit":"個"},{"name":"青ピーマン","unit":"個"},{"name":"赤ピーマン","unit":"個"},{"name":"ニンニク","unit":"片"},{"name":"しょうが","unit":"塊"},{"name":"ネギ","unit":"本"},{"name":"桂林唐辛子味噌","unit":"g"},{"name":"料理酒","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"老抽","unit":"ml"},{"name":"砂糖","unit":"g"},{"name":"塩","unit":"g"},{"name":"サラダ油","unit":"ml"}]'::jsonb, '["魚の内臓を処理し、鱗はそのまま残してきれいに洗う。腹から半分に切り開く（背中はつなげたまま）。15mlの料理酒、しょうがのスライス、塩3gで15分漬け込む。","トマトはくし形切り、青ピーマンと赤ピーマンはざく切り、ニンニクはつぶす、しょうがは薄切り、ネギは小口切り（白い部分と緑の部分は分ける）。","生姜のスライスで鍋底を拭き、鍋を熱してから30mlのサラダ油を入れる。油が熱くなったら魚を皮目を下にして入れ、両面がきつね色になり、鱗がパリッとするまで焼き、取り出しておく。","鍋に油を少し残し、ネギの白い部分、生姜のスライス、ニンニクを入れて香りを出す。","桂林唐辛子味噌15gを加え、赤い油が出るまで炒める。","トマトを加え、トマトが汁を出して柔らかくなるまで炒める。","ビール1本（約330ml）を注ぎ入れ、醤油15ml、老抽5ml、砂糖5g、塩5gを加えて混ぜる。","焼いた魚を戻し入れ、強火で沸騰させたら中弱火にし、蓋をして15～20分煮込む。","蓋を開け、青ピーマンと赤ピーマンを加え、さらに3～5分煮る。","強火で汁を煮詰めてとろみをつけ、ネギの緑の部分を散らして出来上がり。"]'::jsonb, '["魚介","広西名菜","焼き煮","旨味と辛さ","ご飯が進む","おもてなし"]'::jsonb),
  ('howtocook:aquatic/香煎翘嘴鱼/香煎翘嘴鱼', 'ja', '香煎ハクレン', '魚介', '香煎ハクレンは風味豊かな家庭料理の川魚です。魚は塩漬けして干すことで乾燥して引き締まり、外側は金色にカリッと焼き上がり、肉は繊細で塩味と旨味があり、豆板醤とピーマンのほのかな辛味と甘みが加わります。魚肉は良質なタンパク質と不飽和脂肪酸が豊富で、栄養が吸収されやすいです。調理には2～4日の塩漬けと乾燥が必要で、調理時間は約30分、焼くときは根気強く火加減を調整する必要があり、初心者には少し難しいですが、完成すると香りが立ち、ご飯が進みます。', '[{"name":"ハクレン","unit":"斤","note":""},{"name":"生姜","unit":"g","note":""},{"name":"ネギ","unit":"g","note":""},{"name":"ニンニク","unit":"個","note":""},{"name":"ピーマン","unit":"","note":"適量"},{"name":"パクチー","unit":"","note":"お好みで"},{"name":"老抽","unit":"ml","note":""},{"name":"砂糖","unit":"g","note":""},{"name":"豆板醤","unit":"","note":"適量"},{"name":"料理酒","unit":"ml","note":""},{"name":"醤油","unit":"ml","note":""},{"name":"塩","unit":"g","note":""},{"name":"食用油","unit":"ml","note":""},{"name":"乾燥唐辛子","unit":"個","note":""},{"name":"熱湯","unit":"","note":"適量"},{"name":"鶏がらスープの素","unit":"","note":"適量"},{"name":"十三香","unit":"","note":"適量"},{"name":"黒酢","unit":"","note":"適量"}]'::jsonb, '["魚は背開きに処理してもらう（魚屋に頼む。腹開きは絶対にしない。背開きが肝心）、きれいに洗う。","魚の表面に塩をまんべんなく塗り、料理酒約80ml、生姜のみじん切り20gを加え、冷蔵庫のチルド室で1～2日漬け込む。","漬け込んだ魚を取り出し、紐で吊るして半乾きになるまで干す（約1～2日、気温と日差しにより調整）。","食べる前に魚を清水で洗い、水気を切る（油はね防止）。","強火で鍋を熱し、すぐに弱火にして鍋に油を入れ、鍋の全面に油が行き渡るようにする。魚を鍋の縁に沿って滑り込ませる（最初は背中側を焼く）。","魚を入れた後（および裏返した後）、すぐに動かさない（皮が破れやすい）。約30秒焼いたら、鍋を揺すってみる。","背面を約1分焼き、裏返してさらに1～2分焼き、両面が黄金色になるまで焼く。","両面焼けたら、魚を鍋の端に寄せ、空いたスペースに豆板醤を入れて香りを炒め、生姜とにんにくを加える。","調味料の香りが立ったら、料理酒、醤油、老抽を加え、熱湯を魚の高さまで、または少なめに注ぐ。","中強火にして5～10分煮込み、ピーマン、砂糖、鶏がらスープの素、十三香、黒酢を加える。","弱火にして2～5分、ネギとパクチーを加え、すぐに火を止めて盛り付ける。"]'::jsonb, '["水産","香辛","煎","川魚","ご飯が進む","家庭料理"]'::jsonb),
  ('howtocook:aquatic/鲤鱼炖白菜/鲤鱼炖白菜', 'ja', 'コイと白菜の煮込み', '魚介', 'コイと白菜の煮込みは、香り豊かで濃厚な味わいの家庭料理です。魚の身は柔らかく味が染み込み、白菜は甘味を吸って美味しい、典型的な北方風の味わいです。コイには良質のタンパク質と不飽和脂肪酸が豊富で、白菜の食物繊維やビタミンと合わせてバランスの良い栄養が摂れます。調理には魚を焼いてから煮込む工程があり、やや難易度は高いですが複雑ではありません。料理に慣れた方におすすめで、準備から完成まで約40分かかります。', '[{"name":"食用油","unit":"ml"},{"name":"生姜","unit":"枚"},{"name":"ニンニク","unit":"片"},{"name":"コイ","unit":"斤"},{"name":"ベビー白菜（白菜の芯）","unit":"枚"},{"name":"塩","unit":"g"},{"name":"濃口醤油","unit":"ml"},{"name":"薄口醤油","unit":"ml"},{"name":"シナモン（桂皮）","unit":"本"},{"name":"八角","unit":"個"},{"name":"トウバンジャン","unit":"g"},{"name":"唐辛子","unit":"本"}]'::jsonb, '["コイをきれいに洗い、切り込みを入れる（魚の身に何か所か切り込みを入れて味が染み込みやすくする）","ベビー白菜をきれいに洗い、皿に盛っておく","鍋に油を入れ、熱くなったら「少々の塩」「生姜」「ニンニク」「トウバンジャン」「シナモン」「八角」を加えて香りを炒める","魚を鍋に入れて焼く（3分間）毎（30秒）に裏返す","「水」（量は魚とほぼ同じ高さ、少し少なめでもよい）と「薄口醤油」「濃口醤油」「ベビー白菜」を加える","強火で15〜20分煮込み、煮汁が減ってきたら「塩」を加えてできあがり"]'::jsonb, '["魚介","香ばしい","煮込み","家庭料理","ご飯が進む","北方風味"]'::jsonb),
  ('howtocook:aquatic/鳊鱼炖豆腐/鳊鱼炖豆腐', 'ja', 'ヒラウオと豆腐の煮込み', '魚介', 'ヒラウオと豆腐の煮込みは家庭的な醤油煮込み料理で、魚の身は柔らかく味が染み込み、豆腐はたっぷりと汁を吸って、塩味と辛味がほどよく効いています。ヒラウオは良質なタンパク質と不飽和脂肪酸が豊富で、豆腐は植物性タンパク質とカルシウムを提供し、栄養バランスが良いです。調理の難易度は中程度で、魚を焼くときに焦げ付かないように少し注意が必要ですが、手順は明確で初心者にも挑戦しやすいです。準備から完成まで約40分かかります。', '[{"name":"ヒラウオ","unit":"グラム"},{"name":"木綿豆腐","unit":"グラム"},{"name":"生姜","unit":"枚"},{"name":"ネギ","unit":"本"},{"name":"ニンニク","unit":"個"},{"name":"濃口醤油","unit":"ミリリットル"},{"name":"シナモン","unit":"個"},{"name":"氷砂糖","unit":"個"},{"name":"唐辛子","unit":"個"},{"name":"料理酒","unit":"ミリリットル"},{"name":"醤油","unit":"ミリリットル"},{"name":"塩","unit":"グラム"},{"name":"八角","unit":"個"},{"name":"ローリエ","unit":"枚"},{"name":"食用油","unit":"ミリリットル"},{"name":"熱湯","unit":"グラム"}]'::jsonb, '["ヒラウオに切り目を入れ、生姜のスライスと料理酒をのせて5～10分漬け込む","木綿豆腐を切って水にさらしておく","鍋に油を入れ、少量の塩を加えて焦げ付き防止にする。漬け込んだ魚をキッチンペーパーで水分を拭き取り、鍋に入れて両面を焼く","両面焼けたら魚を鍋の端に寄せ、空いたスペースにネギ、生姜、ニンニク、唐辛子、ローリエ、八角を入れて香りを出す","香りが出たら料理酒、醤油、濃口醤油、氷砂糖、シナモンを加え、熱湯を魚と同量か少し少なめに入れる","強火で沸騰させたら、木綿豆腐を鍋の端に沿わせて加え、塩を加えて弱火にする","弱火で10～15分煮込み、強火で少し汁を飛ばして完成"]'::jsonb, '["水産物","醤油煮","家庭料理","ご飯が進む","旨味","辛味少なめ"]'::jsonb),
  ('howtocook:aquatic/黄油煎虾/黄油煎虾', 'ja', 'バターエビ', '魚介', 'バターエビは風味豊かで、エビの身が柔らかく弾力のある家庭的な海鮮料理です。生エビには良質なタンパク質やカルシウム、亜鉛などのミネラルが豊富で、バターを加えることでミルクの風味とエネルギーがプラスされます。作り方は比較的簡単で、生エビの下処理に少し忍耐があれば、初心者でもスムーズに作れます。全体の所要時間は約1時間です。', '[{"name":"生エビ","unit":"グラム"},{"name":"バター","unit":"グラム"},{"name":"ブラックペッパー (粒)","unit":"ml"},{"name":"サラダ油","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"米酒","unit":"ml"},{"name":"砂糖","unit":"ml"},{"name":"塩","unit":"ml"}]'::jsonb, '["生エビの頭を取り、一緒に背ワタを引き抜きます（この処理がうまくいかない場合は、次の工程で背開きにするときに背ワタを取り除きます）。ハサミで切るか包丁で背を開き、水気を切っておきます。","合わせ調味料を作る：小さなボウルに上記の分量の醤油、米酒、砂糖、塩をすべて入れて混ぜ合わせ、置いておきます。","中強火で鍋を熱し、熱した鍋にサラダ油を入れ、10秒待って油の温度を上げます。","エビをすべて鍋に入れ、ブラックペッパーを挽いてエビの上に均等に振りかけ、炒めます。","エビの色が変わったらバターを加え、バターが完全に溶けたら合わせ調味料を注ぎ入れ、さらに炒めます。","強火で15秒炒めて煮詰め、皿に盛り付けて完成です。"]'::jsonb, '["海鮮","風味豊か","ミルク風味濃厚","炒め物","時短レシピ","ご飯が進む"]'::jsonb),
  ('howtocook:breakfast/吐司果酱', 'ja', 'トーストジャム', '朝食', 'これは超シンプルな時短朝食。軽くトーストした食パンに甘いジャムを挟んで、外はカリッと中はふんわり。持ち運びにも便利で、典型的な簡単洋風軽食です。主に炭水化物と糖分を摂取でき、朝のエネルギーを素早く補給します。調理はほぼ初心者でもでき、忙しい初心者にぴったり。準備から完成まで約2分、火を使わず、調理器具もほとんど洗う必要がありません。', '[{"name":"新鮮な食パン","unit":"枚"},{"name":"ジャム","note":"トースト片面に十分塗れる量"}]'::jsonb, '["食パンをトースターに入れる","設定を選んで、時間が来たら自動でポップアップ","2分後にトーストが焼けてポップアップ","まず1枚のトーストを取り出し、ジャムを全面に塗り、もう1枚のトーストをのせる","ペーパータオルで包めば歩きながら食べられるし、食べてから出かけてもOK"]'::jsonb, '["朝食","時短","洋風","携帯","甘香"]'::jsonb),
  ('howtocook:breakfast/太阳蛋', 'ja', 'サニーサイドエッグ', '朝食', 'サニーサイドエッグは電子レンジで手早く作れる家庭的な朝食です。食感はなめらかで、白身は固まり、黄身はとろりとしています。典型的な時短料理です。卵は良質なタンパク質とビタミンが豊富で、消化吸収が良いです。作り方はとても簡単で、初心者にも優しいです。火力調節可能な電子レンジならわずか3分で完成し、調節できない場合でも数分加熱を繰り返すだけでできます。', '[{"name":"卵","unit":"個"},{"name":"塩","unit":"g"},{"name":"油","unit":"ml"}]'::jsonb, '["小さめのボウルを用意し、前の工程で計算した油を入れ、塩を振ってよく混ぜる。ボウルを傾けて油を表面に馴染ませる。","卵を1つ取り出し、ボウルに割り入れる。","黄身の表面に穴を開ける。つまようじで5箇所、または箸で1箇所刺す。","電子レンジに入れ、中火で3分加熱する。","小さめのボウルを用意し、前の工程で計算した油を入れ、塩を振ってよく混ぜる。ボウルを傾けて油を表面に馴染ませる。","卵を1つ取り出し、ボウルに割り入れる。","黄身の表面に穴を開ける。つまようじで5箇所、または箸で1箇所刺す。","電子レンジに入れ、1分加熱する。","while（サニーサイドエッグが広範囲に固まっていない）電子レンジで30秒加熱する；"]'::jsonb, '["朝食","時短","電子レンジ","なめらか","家庭料理"]'::jsonb),
  ('howtocook:breakfast/完美水煮蛋', 'ja', '完璧なゆで卵', '朝食', 'これは科学者によって開発された循環湯煮法で作られた卵で、黄身はなめらかで細かく、白身は均一に固まり、食感に層があります。従来の調理法より多くの栄養素を保持し、ポリフェノール含有量が23%高く、タンパク質が豊富です。調理の難易度は高く、正確な温度管理と繰り返しの移動が必要で、調理時間は約35分です。', '[{"name":"新鮮な卵（AAグレード推奨）","unit":"個"},{"name":"100°Cの沸騰水","unit":"ml"},{"name":"30°Cのぬるま湯","unit":"ml"},{"name":"氷水","note":"適量"}]'::jsonb, '["2つの鍋の水を準備: A鍋は100°Cの沸騰水、B鍋は30°Cのぬるま湯を保つ","穴あきおたまで卵をA鍋に入れ、タイマーをスタート","正確に2分ごとに卵を別の鍋の水に移す","この移動操作を合計16回繰り返す（合計時間32分）","最後の移動後、B鍋に30秒静置","すぐに氷水（0°C）に入れて加熱を止める（30秒間維持）","殻をむくときは、鈍端の気室から始め、縦軸に沿って卵膜をはがす"]'::jsonb, '["朝食","あっさり","うま味","ゆで","栄養"]'::jsonb),
  ('howtocook:breakfast/微波炉蒸蛋', 'ja', '電子レンジ蒸し卵', '朝食', '電子レンジで手軽に作るなめらかでプリンみたいな蒸し卵です。家常料理で、良質なタンパク質が豊富で消化吸収も良く、朝食や軽食にぴったり。作り方はとても簡単で初心者でもすぐにでき、全部で約10分で完成します。', '[{"name":"卵","unit":"個"},{"name":"ぬるま湯またはだし汁","unit":"ml"},{"name":"食塩","unit":"g"},{"name":"薄口醤油","unit":"ml"},{"name":"ごま油","note":"仕上げに数滴"}]'::jsonb, '["卵を溶きほぐし、ぬるま湯またはだし汁、塩、醤油を加えて、泡立てないように優しく混ぜます。","卵液をこして耐熱ボウルに注ぎ、表面の泡があれば爪楊枝で軽く突きます。","ラップをかけて8～10か所穴を開けるか、電子レンジ専用フタ（すき間をあける）を使います。","電子レンジで加熱：","700W：1分30秒 → 様子を見てさらに20～30秒、表面が固まるまで加熱。","600W：約1分40秒～2分10秒。","800W：約1分10秒～1分40秒。","加熱後取り出し、1分間置いて余熱で中心まで完全に火を通します。","ごま油をかけ、小ねぎを散らしてできあがり。"]'::jsonb, '["朝食","時短","あっさり","なめらか"]'::jsonb),
  ('howtocook:breakfast/微波炉荷包蛋', 'ja', '電子レンジポーチドエッグ', '朝食', '電子レンジで作るポーチドエッグは、手軽で簡単な家庭料理です。卵白はなめらかで、卵黄はとろりと柔らかく、ごま油の香りが広がります。卵には良質なタンパク質とレシチンが豊富に含まれています。作り方は非常に簡単で、初心者でも安心して作れ、準備から完成まで約2分です。', '[{"name":"卵","unit":"個"},{"name":"飲用水","unit":"ml"},{"name":"ごま油","unit":"ml"},{"name":"塩","unit":"g"}]'::jsonb, '["卵を小さな器に割り入れ、箸で卵黄に2か所穴を開けます。加熱中に電子レンジ内を汚さないためです。","次に、常温の飲用水を器に注ぎます。","さらに、食塩を加えます。","最後にごま油を加えます。","材料を入れた器を電子レンジに入れ、強火で80秒加熱します。","設定時間が経過したら、布巾を使って手を保護しながら取り出します。"]'::jsonb, '["朝食","手軽な朝食","あっさり","電子レンジ","家庭料理","おかず"]'::jsonb),
  ('howtocook:breakfast/微波炉蛋糕', 'ja', '電子レンジケーキ', '朝食', '電子レンジで作る簡単ケーキ。ふんわり甘く、初心者でも手軽に作れる家庭向けデザート。卵と小麦粉をベースに、バターでコクと香りをプラス。砂糖で素早くエネルギー補給。ナッツやフルーツを加えれば食物繊維やビタミンも追加。少ない材料で、電子レンジの強火で1分加熱するだけ。準備から試食まで最短2分、初心者でも約20分で完成。', '[{"name":"卵","unit":"個","note":""},{"name":"バター","unit":"","note":"卵半分大"},{"name":"小麦粉","unit":"g","note":""},{"name":"ベーキングパウダー","unit":"g","note":""},{"name":"白（赤）砂糖","unit":"g","note":""},{"name":"塩","unit":"g","note":""},{"name":"チョコレート","unit":"","note":"適量"},{"name":"バナナ","unit":"","note":"適量"},{"name":"コーヒー粉","unit":"","note":"適量"},{"name":"シリアル","unit":"","note":"適量"},{"name":"牛乳","unit":"","note":"適量"},{"name":"ナッツ","unit":"","note":"適量"},{"name":"ビスケットクラム","unit":"","note":"適量"}]'::jsonb, '["以下の材料を加える。容器の3/4を超えないように注意する。","卵半分大のバターを容器に入れ、電子レンジで15秒加熱して溶かす。","チョコレート/バナナを溶かす/つぶして粒/ペースト状にする。","卵1個を割り入れ、混ぜ合わせる。","15gの白（赤）砂糖（甘党は多めに追加可）（注4参照）","1gの塩を加える（後の味付け食材に塩分が含まれる場合は調整する）。","2.5gのベーキングパウダーを加える。","15gの小麦粉を加える（グルテン量はあまり影響しない）。","お好みの風味食材を加える！（ナッツやビスケットなどの乾燥食材は今は入れない）","粉っぽさがなくなるまで混ぜ、濃いヨーグルト状にする。","任意の乾燥食材（粉末タイプは除く）を上にのせる。","自分を褒める🥰","電子レンジ（強）で1分加熱する（ふんわりケーキ状になるまで）。","カップを取り出し（熱いので注意！）、写真を撮ってSNSに投稿して食べる。"]'::jsonb, '["朝食","甘い","電子レンジ","時短","デザート"]'::jsonb),
  ('howtocook:breakfast/意式香肠北非蛋', 'ja', 'イタリアンソーセージのシャクシュカ', '朝食', 'イタリアンソーセージのシャクシュカは、濃厚で香り高い地中海風料理です。半熟卵が甘酸っぱいトマトミートソースに浮かび、カリカリのパンを添えてディップしていただきます。主な食材は良質なたんぱく質を提供し、トマト、パプリカ、玉ねぎがビタミンと食物繊維をもたらします。作り方は簡単で、卵を蒸す火加減に注意すれば、全体で約30分で食卓に並びます。', '[{"name":"イタリアンポークソーセージ / チョリソー / ランチョンミート","unit":"グラム"},{"name":"バリラ ナポリタンパスタソース","unit":"缶"},{"name":"卵","unit":"個"},{"name":"パプリカ","unit":"個"},{"name":"玉ねぎ","unit":"個"},{"name":"オリーブオイル","unit":"ml"},{"name":"パルメザンチーズ","note":"適量"},{"name":"フレッシュパセリ","note":"適量"},{"name":"乾燥唐辛子（砕いたもの）","note":"適量"},{"name":"パン","note":"適量"},{"name":"水","unit":"ml"}]'::jsonb, '["イタリアンポークソーセージの腸衣を外して準備する。玉ねぎはみじん切り、パプリカは細切りにする。","広口のフライパンにオリーブオイル10ml～15mlを入れ、中火で熱する。","準備したソーセージまたはランチョンミートを加え、縁がきつね色でカリカリになるまで炒める（生ソーセージの場合は、スプーンでほぐしながら色が変わるまで炒める）。","玉ねぎのみじん切りとパプリカの細切りを肉と一緒にフライパンに加え、4～5分間、野菜が柔らかくなり玉ねぎが半透明になるまで炒める。","バリラのナポリタンパスタソースを加え、よく混ぜる。火を中弱火にし、微かに沸騰させながら2～3分煮込む。（ソースが濃すぎる場合は、水15mlを加えてもよい。）","スプーンの背でフライパンのソースの中に3～4個の小さなくぼみを作る。","卵を順に、それぞれのくぼみに慎重に割り入れる。","フライパンに蓋をし、蒸気で白身を蒸し焼きにする。3～5分待つ。注意：頻繁に状態を確認すること。白身が白く固まり、フライパンを軽く揺らすと黄身がまだ揺れる（半熟状態）になったら、この工程を終了する。","火を止める。お好みで、すりおろしたパルメザンチーズ、フレッシュパセリ、または乾燥唐辛子をふりかける。","フライパンをそのまま食卓に出し、硬めのパンを添えて、黄身とソースをディップしながらいただく。"]'::jsonb, '["朝食","香ばしい","甘酸っぱい","蒸し焼き","地中海風","時短"]'::jsonb),
  ('howtocook:breakfast/手抓饼', 'ja', '手抓餅', '朝食', '手抓餅は外はサクサク、中はふんわりで、層がはっきりしており、人気の家庭料理です。生地は半湯捏ねで作り、もっちりと歯ごたえがあり、卵と野菜を合わせて栄養バランスも良いです。作り方は初心者にも優しく、こね始めから焼き上がりまで約40分で、忙しい朝にぴったりです。', '[{"name":"薄力粉","unit":"g"},{"name":"熱湯","unit":"ml"},{"name":"冷水","unit":"ml"},{"name":"サラダ油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"卵","unit":"個"},{"name":"レタス","unit":"g"},{"name":"ハム","unit":"g"},{"name":"スライスチーズ","unit":"枚"}]'::jsonb, '["小麦粉をボウルに入れ、熱湯を加えてぼそぼそになるまで混ぜ、冷水を加えてなめらかな生地になるまでこね、濡れ布巾をかぶせて20分休ませる。","生地を約100gずつに分け、丸めて、薄くのばす。","表面にまんべんなくサラダ油を塗り、塩をふり、カタツムリ状に巻き、10分休ませる。","生地を再び薄く均等な厚さにのばす。","熱したフライパンに油をひき、弱火で両面がきつね色になって泡が出るまで焼く。","焼き上がった餅に目玉焼き、レタス、ハム、スライスチーズなどを順にのせ、巻いて完成。"]'::jsonb, '["朝食","塩味","サクサク","揚げ焼き","家庭料理","時短"]'::jsonb),
  ('howtocook:breakfast/桂圆红枣粥', 'ja', '龍眼と棗のお粥', '朝食', '甘くて香りがよく、もっちりとした中華風の伝統的なお粥です。もち米、棗、龍眼を一緒に煮込むことで、自然な甘さがあり、体を温めて胃に優しいです。血を補い、心を落ち着かせ、脳を活性化し、知能を高め、心脾を養う効果があります。作り方はとても簡単で、初心者でも気軽に作れます。準備からお粥の香りが部屋中に広がるまで約70分かかります。', '[{"name":"もち米","unit":"g"},{"name":"棗","unit":"個"},{"name":"龍眼","unit":"個"}]'::jsonb, '["龍眼の実を取り出し、清水で2回洗い、ボウルに入れて10分浸す","棗を清水で2回洗い、ボウルに入れて10分浸す","もち米を炊飯器に入れ、清水で2回研ぎ、2000mlの水を加える","龍眼と棗を炊飯器に加える","炊飯器の炊飯モードをオンにし、1時間後にお粥ができる"]'::jsonb, '["朝食","甘い香り","煮る","養生","時短","家庭料理"]'::jsonb),
  ('howtocook:breakfast/水煮玉米', 'ja', 'ゆでトウモロコシ', '朝食', 'ゆでトウモロコシは家庭的な時短料理で、甘くてもちもちとした食感が特徴です。新鮮なトウモロコシを皮ごと茹でることで本来の香りを閉じ込め、塩と砂糖でさらに味を引き立てます。食物繊維、ビタミン、炭水化物が豊富で、満腹感が得られます。作り方は非常に簡単で、初心者でも気軽に作れます。準備から食卓まで約15分です。', '[{"name":"新鮮なトウモロコシ","unit":"本"},{"name":"水","note":"トウモロコシが半分指の高さほど浸かる量"},{"name":"塩","unit":"g"},{"name":"砂糖","note":"適量"}]'::jsonb, '["新鮮なトウモロコシの外皮をむき、一部の皮を残して鍋に入れる","トウモロコシが半分指の高さほど浸かる水を加え、塩と砂糖を入れる","沸騰したら弱火にし、蓋をしてさらに15〜20分茹でる。トウモロコシは長めに茹でても問題ありません。","茹で上がったら水気を切り、冷ましてから食べる。"]'::jsonb, '["朝食","時短","家庭料理","甘くてさっぱり","ゆで"]'::jsonb),
  ('howtocook:breakfast/温泉蛋/温泉蛋', 'ja', '温泉卵', '朝食', '温泉卵は日本発祥で、白身が半熟のトロリとした状態で、黄身は温かく固まっており、とろけるような滑らかさが特徴で、半熟卵とは逆の食感です。卵には良質なタンパク質、レシチン、各種ビタミンが豊富で、栄養バランスが抜群です。作る際には温度計を使って水温を70℃に保つ必要がありますが、少し温度管理が求められるものの、手順は簡単で、約30分待てば完成します。昆布醤油と小ねぎを添えると、さっぱりとした風味で、手軽に作れる一品です。', '[{"name":"卵","unit":"個"},{"name":"昆布醤油","unit":"","note":"少々調味"},{"name":"小ねぎ","unit":"","note":"少々飾り用"}]'::jsonb, '["鍋に水を入れ、卵が約3cm浸かるようにし、温度計を差し込む","火またはIHをつけ、水温を70℃に保つように調整する","卵を鍋に入れる。卵は重ならないように底に置き、動くスペースを残す","その温度を25分間保つ","氷水を用意する","卵を取り出し、すぐに氷水に入れて3分待つ","卵を小さな器に割り入れて完成"]'::jsonb, '["朝食","和風","あっさり","なめらか","低温調理","副菜"]'::jsonb),
  ('howtocook:breakfast/溏心蛋', 'ja', '半熟卵', '朝食', 'これは普通の電気鍋で簡単に作れる家庭的な卵料理です。黄身はとろりとした半熟状態で、なめらかでコクがあります。1個の卵には約6gの良質なたんぱく質が含まれており、特に筋トレ向けの栄養補給に適しています。作り方はシンプルで、加熱と放置の時間を守れば初心者でもすぐにでき、全工程約15分です。', '[{"name":"卵","unit":"個"},{"name":"水","unit":"cm"}]'::jsonb, '["卵を電気鍋に入れる。卵は重ならないように底に並べ、揺れるスペースを残す","卵がかぶるくらいの冷水を約2cm注ぐ","蓋を開け、最大火力でお湯が沸騰するまで加熱する（約85～95度、少し泡が出る程度で完全沸騰は不要）","火を止め、蓋をして卵を放置する","中央にとろりとした黄身が欲しい場合は6分放置","完全に固まった崩れやすい黄身が欲しい場合は10分放置","水気を切り、冷水で約1分洗い流してから殻をむいて食べる"]'::jsonb, '["朝食","あっさり","茹でる","時短","家庭料理","なめらか"]'::jsonb),
  ('howtocook:breakfast/煎饺', 'ja', '焼き餃子', '朝食', '焼き餃子は、底が黄金色でカリッと、中身はジューシーな家庭的な点心で、よく北の食卓に登場します。冷凍餃子を使って作るため、炭水化物とタンパク質が豊富で、簡単で素早く作れます。難易度は2つ星で、初心者にも優しく、全部で約15分で食卓に出せます。', '[{"name":"餃子（冷凍餃子）","unit":"個"},{"name":"食用油","unit":"ml"},{"name":"清水","note":"適量"},{"name":"黒ごま","note":"適量"},{"name":"ネギ","note":"適量"}]'::jsonb, '["フライパンを取り出す（焦げ付きにくいフライパンが最適）","食用油 10ml～15ml を加える","火をつけ、餃子を入れる（均等に並べ、重ねないようにする）","すぐに清水を加え、水面が餃子の平均的な高さの 1/2 になるようにする","蓋をする（この時、コンロは強火にする）","8～10分待つ","鍋の水分が 2mm だけになったら、中火に変えて焼き始める","水分がすべて蒸発したら、フライパンを揺らして餃子に均等に熱を加える","黒ごまとネギを加えてさらに10秒蒸らす","1～2分後に一個の餃子を取り出して底を確認し、黄金色のカリッとした皮ができたらすぐに取り出す"]'::jsonb, '["朝食","簡単","家庭料理","焼き","サクサク"]'::jsonb),
  ('howtocook:breakfast/蒸水蛋', 'ja', '蒸し卵', '朝食', 'プルプルとした茶わん蒸しのような滑らかな食感と、上品で旨みのある風味が特徴の家庭料理。北も南も愛され、北の地域では「卵ケーキ」とも呼ばれます。卵は良質なタンパク質とレシチンが豊富で、手軽に栄養補給できる食材。コツは卵と水の割合と弱火でじっくり蒸すことだけなので初心者にも優しく、準備から出来上がりまで約15分で完成します。', '[{"name":"新鮮な卵","unit":"個"},{"name":"お湯","unit":"ml"},{"name":"塩","unit":"g"}]'::jsonb, '["卵をボウルに割り入れ、溶きほぐす。","別の容器に、卵液の1.5倍（卵の殻半分で0.5倍の水の目安）の温水（20～30℃）を入れ、塩を加えて溶かす。","塩水を卵液に加え、時計回りまたは反時計回りの一方向に混ぜる。泡は取り除くか、漉すとより滑らかになる。","卵液を入れた器をアルミホイルで覆い（または皿をかぶせ）、あらかじめ蓋をして約3cmの水を張った鍋に置く。","中火で沸騰させ、ごく弱火にしてさらに4分蒸す。"]'::jsonb, '["朝食","あっさり","蒸す","時短","家庭料理"]'::jsonb),
  ('howtocook:breakfast/蒸花卷', 'ja', '蒸し花巻き', '朝食', 'これは北方の伝統的な小麦粉料理で、ふんわり柔らかく、ほのかな麦の香りがします。冷凍花巻きを蒸すことで、手軽に炭水化物と食物繊維を補給できます。作り方は非常にシンプルで、料理初心者でも簡単にマスターでき、全行程わずか30分と、理想的な時短朝食です。', '[{"name":"冷凍花巻き","unit":"個"},{"name":"水","unit":"ml"}]'::jsonb, '["花巻きの袋から5個取り出す","花巻きを皿に平らに並べ、重ならないようにする","鍋に水400mlを入れ、蒸し台を置き、花巻きをのせた皿を蒸し台にのせ、蓋をする","強火で加熱し、沸騰させる","中火に変えて15分加熱する","蓋を開け、手で花巻きの表面の温度を確認し、熱くなければさらに蓋をして加熱し、熱ければ火を止めて取り出す","皿を取り出し、50度に冷めたら食べごろ"]'::jsonb, '["朝食","蒸し","簡単","家庭向け","小麦粉料理","北方"]'::jsonb),
  ('howtocook:breakfast/燕麦鸡蛋饼', 'ja', 'オートミールと卵のパンケーキ', '朝食', 'オートミールと卵のパンケーキは、手軽で栄養満点な朝食です。食感は柔らかく、オートミールの穀物の香りと卵と牛乳のコクがあります。家庭的なシンプルなスタイルです。タンパク質、炭水化物、食物繊維が豊富で、体に十分なエネルギーを提供します。特にフィットネス愛好家や平日の朝に適しています。作り方は簡単で、初心者にも優しく、準備から仕上げまで通常10数分です。', '[{"name":"卵","unit":"個"},{"name":"オートミール","unit":"g"},{"name":"野菜","unit":"g"},{"name":"牛乳","unit":"ml"},{"name":"バター","note":"適量"}]'::jsonb, '["牛乳とオートミールを混ぜ合わせ、粘り気が出るまでよく混ぜます。","卵を色が均一になるまでよく混ぜます。","卵液をオートミール牛乳に加え、粘り気が出て均一になるまで混ぜます。","フライパンにバターを入れて全体に広げます。","混ぜ合わせた材料をフライパンに流し入れ、平らに広げます。","弱火で2〜3分加熱します。野菜を加えたい場合は、加熱中に刻んだ野菜の葉を加えます。","裏返してさらに2分加熱します。","皿に盛り、残りの牛乳と一緒に朝食として提供します。"]'::jsonb, '["朝食","手軽","焼き","あっさり","フィットネス"]'::jsonb),
  ('howtocook:breakfast/牛奶燕麦', 'ja', 'ミルクオートミール', '朝食', '高タンパク・高食物繊維の手軽な栄養朝食。牛乳の滑らかさ、オートミールの香ばしさ、目玉焼きのカリッとした食感が絶妙に調和し、温かく優しい口当たりで消化も良く、満足感が高い。作り方はシンプルで初心者にも優しく、約3分で完成。野菜や果物を添えるとさらにさっぱり。', '[{"name":"牛乳","unit":"ml","note":""},{"name":"オートミール","unit":"グラム","note":""},{"name":"卵","unit":"個","note":""},{"name":"水","unit":"ml","note":""},{"name":"花椒塩","unit":"グラム","note":""}]'::jsonb, '["牛乳を朝食カップに注ぐ（冷たいままでもOK）","200mlの水を用意する。直接飲める水ならそのままオートミールを加え、そうでなければ沸騰させてからオートミールを加える","水が沸騰してから2分後、オートミールができあがる","できあがったオートミールをすくって牛乳に加える（煮汁も加えると食感に影響するので避ける）","オートミールをクイックオートミールに変える","クイックオートミールの入った容器に牛乳を注ぎ、かき混ぜる","混合物を電子レンジに入れる","中火で4分加熱する","フライパンを熱し、薄く油をひく。油が熱くなったら卵を割り入れ、片面20秒ずつ焼く。下味として（3gの花椒塩、お好みで）加える","火を止め、皿に盛る"]'::jsonb, '["朝食","時短","栄養","あっさり","高タンパク","高食物繊維"]'::jsonb),
  ('howtocook:breakfast/空气炸锅面包片', 'ja', 'エアフライヤーで焼くパン', '朝食', 'エアフライヤーで焼くパンは、超簡単で手早く作れる主食です。外はカリッと中はふんわり、小麦の香りが純粋で、ダイエット中に特に適しています。食物繊維と植物性タンパク質が豊富で、長時間満腹感が続きます。作り方は簡単で、パンをエアフライヤーに入れるだけ。初心者にもとても優しく、準備から完成まで約5分です。', '[{"name":"パン","unit":"枚"}]'::jsonb, '["2枚のパン（できれば全粒粉パン）を取り出す","パンをエアフライヤーに垂直に置く","200°Cで5分焼く","取り出してすぐに食べられる"]'::jsonb, '["朝食","手早い","あっさり","ダイエット","サクサク","満腹感"]'::jsonb),
  ('howtocook:breakfast/美式炒蛋', 'ja', 'アメリカ風スクランブルエッグ', '朝食', 'ふわふわで柔らかいアメリカ風の家庭的な卵料理です。牛乳を加えることで卵が細かくなめらかになり、口当たりがしっとりとしています。良質なタンパク質とカルシウムが豊富です。作り方は簡単で初心者にも優しく、準備から仕上がりまで約20分しかかかりません。', '[{"name":"卵","unit":"個"},{"name":"全脂牛乳/クリーム","unit":"g"},{"name":"バター","unit":"g"},{"name":"塩","unit":"g"}]'::jsonb, '["卵を大きなボウルに割り入れ、塩を加えて泡立つまで混ぜ、15分間置く。","バターを小さく切って鍋に入れ、卵液を注ぎ入れ、弱火で絶えず混ぜる。","バターが溶けたらすぐに卵液を素早く動かして細かくし、卵液が大体固まる前に火を止める。","牛乳を加えて15秒間混ぜ、スクランブルエッグがしっとりと滑らかになったら皿に盛る。"]'::jsonb, '["朝食","香ばしい","炒め","手早い","家庭料理"]'::jsonb),
  ('howtocook:breakfast/苏格兰蛋/苏格兰蛋', 'ja', 'スコッチエッグ', '朝食', 'この簡単版スコッチエッグは、外はサクサク、中は半熟でとろり、チーズのミルキーさとベーコンのスモーキーな風味が融合した、イギリス風のアレンジおやつです。卵は良質なタンパク質を、チーズはカルシウムを補い、手抓餅の皮と合わせることで一食分のエネルギーを満たせます。作り方は難しくなく、初心者でも簡単に挑戦でき、準備から出来上がりまで約20～30分で完成します。', '[{"name":"卵","unit":"グラム"},{"name":"手抓餅","unit":"枚"},{"name":"チーズスライス","unit":"枚"},{"name":"ベーコンスライス","unit":"枚"}]'::jsonb, '["冷水から茹で始め、沸騰してから3分後に取り出す","卵を取り出し、氷水に入れて殻を剥くと早くてきれいに剥ける","チーズスライスで卵を包む","ベーコンスライスで卵を包む","手抓餅の両端を切り落とし、四角形にして卵を包む","油温6割（油の表面が揺れ、青い煙が出て、箸を入れると周りに泡が立つ程度）で入れ、黄金色になるまで揚げる","エアフライヤー160度で15分","切ってそのまま食べられる"]'::jsonb, '["朝食","旨みと香ばしさ","サクサク","揚げ焼き","イギリス風","時短"]'::jsonb),
  ('howtocook:breakfast/茶叶蛋', 'ja', '茶葉蛋', '朝食', 'この伝統的なおやつは、茶葉の香りが豊かで、うま味があり、良質なタンパク質が豊富で、手軽な栄養満点の朝食に最適です。作り方はわかりやすく、難易度は中程度。初心者は火加減とスパイスの配合に注意が必要です。約30分で完成し、2〜3人分できあがるので、週末にゆったりと準備するのにぴったりです。', '[{"name":"卵","unit":"グラム"},{"name":"八角","unit":"グラム"},{"name":"ローリエ","unit":"グラム"},{"name":"シナモン","unit":"グラム"},{"name":"フェンネル","unit":"グラム"},{"name":"氷砂糖","unit":"グラム"},{"name":"紅茶","unit":"グラム"},{"name":"薄口醤油","unit":"グラム"},{"name":"濃口醤油","unit":"グラム"},{"name":"塩","unit":"グラム"}]'::jsonb, '["卵を冷水から茹で、強火で約8分（ご家庭の調理器具に合わせて調整）","卵を取り出し、冷水にさらす","卵同士をぶつけて、全体にひびを入れる","鍋に卵を戻し、八角、ローリエ、シナモン、フェンネル、氷砂糖、紅茶、薄口醤油、濃口醤油、塩を加える","卵が浸るまで水を加える","強火で沸騰させたら、中弱火にして15分煮る"]'::jsonb, '["朝食","茶香","煮込み","塩味","時短"]'::jsonb),
  ('howtocook:breakfast/蛋煎糍粑', 'ja', '卵焼きもち', '朝食', '簡単で素早く作れるおやつです。外は少しサクッと、中は柔らかくもちもち。卵の香りと甘さが絡み合い、南方の家庭料理の味わいです。もちは炭水化物が豊富で、卵がタンパク質を補います。カロリーは高めですが、腹持ちが良いです。作り方はとても簡単で、初心者でも楽に作れます。全行程は約10分です。', '[{"name":"もち","unit":"個"},{"name":"黒糖または白砂糖","unit":"g"},{"name":"卵","unit":"個"},{"name":"植物油","unit":"ml"},{"name":"食塩","unit":"g"}]'::jsonb, '["もちを長方形の小さな塊に切る。後で焼きやすくするため。","ボウルに卵1個を割り入れ、溶きほぐす。そこに食塩2gを加える。","切ったもちを順に卵液に入れ、両面に卵液を塗る。","鍋に植物油10mlを入れ、卵液を塗ったもちを並べて、弱火でゆっくりと柔らかくなるまで焼く。","残った卵液をもちの表面にゆっくりとかける。","箸やスプーンでもちを裏返し、両面がきつね色になるまで焼いたら食べる。"]'::jsonb, '["朝食","甘くて香ばしい","焼き","南方","簡単","家庭風"]'::jsonb),
  ('howtocook:breakfast/金枪鱼酱三明治', 'ja', 'ツナマヨサンドイッチ', '朝食', 'この洋風朝食サンドイッチは、水煮ツナにマヨネーズとロシアンピクルス汁を混ぜ合わせたもので、塩味と微かな酸味があり、口当たりが滑らかです。焼き上げたトーストとの相性が良く、満足感があります。良質なタンパク質やオメガ3などの栄養素が豊富で、素早くエネルギーを補給できます。作り方は非常に簡単で、ソースを混ぜてホットサンドメーカーで加熱するだけで、初心者でも5分で簡単に作れます。', '[{"name":"水煮ツナ缶","unit":"グラム","note":""},{"name":"角型食パン","unit":"枚","note":""},{"name":"マヨネーズ","unit":"ml","note":""},{"name":"ロシアンピクルス汁","unit":"ml","note":""},{"name":"スライスチーズ（お好みで）","unit":"","note":"適量"},{"name":"ハムスライス（お好みで）","unit":"","note":"適量"}]'::jsonb, '["ツナ、マヨネーズ、ロシアンピクルス汁をボウルに入れ、スプーンで混ぜる。ツナの塊をほぐして全体がペースト状になるようにし、置いておく。","食パン1枚をホットサンドメーカーに置く。","作ったツナマヨソースを食パンに塗る。推奨量は10～15ml。","もう一枚の食パンをかぶせ、ホットサンドメーカーを押さえて電源を入れる。","ホットサンドメーカーの加熱が自動的に停止したら、皿に盛って完成。"]'::jsonb, '["朝食","塩味と微かな酸味","時短","洋風","栄養","簡単"]'::jsonb),
  ('howtocook:breakfast/韩国麻药鸡蛋', 'ja', '韓国麻薬卵', '朝食', '甘辛くて濃厚な韓国風半熟卵の一品。タレが白身に絡み、口当たりはなめらかで、後味にほんのり辛さが残る。卵は良質なタンパク質とレシチンを提供し、栄養満点でお腹も満たす。作り方は非常に簡単で、初心者でも気軽に挑戦でき、茹で卵から冷蔵庫で味を含ませるまで約1時間半かかる。', '[{"name":"卵","unit":"個"},{"name":"韓国醤油（または薄口醤油）","unit":"大さじ"},{"name":"水","unit":"大さじ"},{"name":"みりん","unit":"大さじ"},{"name":"砂糖","unit":"大さじ"},{"name":"ごま油","unit":"ml"},{"name":"青ねぎ","unit":"g"},{"name":"唐辛子（青唐辛子または赤唐辛子）","unit":"g"}]'::jsonb, '["お湯を沸かし、沸騰したら卵を入れて7分茹でる（完璧な半熟卵の状態になる）。","卵を茹でている間にタレを作る：醤油大さじ4、水大さじ4、みりん大さじ2、砂糖大さじ2を小鍋に入れる。","タレを沸騰するまで加熱し、みりんのアルコール分を飛ばす。その後火を止めて冷ましておく。","切った輪切り唐辛子を冷ましたタレに加える。","茹で上がった卵を取り出し、氷水で冷やしてから殻をむく。","むいた卵をタレに入れ、表面にごま油5mlをかけ、小ねぎを散らす。","冷蔵庫で1〜2時間冷やし、味をしっかり染み込ませる。"]'::jsonb, '["朝食","韓国風","半熟卵","甘辛","時短","ご飯が進む"]'::jsonb),
  ('howtocook:breakfast/鸡蛋三明治', 'ja', '卵サンド', '朝食', 'これは簡単で素早く作れる洋風の軽食です。食パンにふわふわの卵サラダと塩味の効いたベーコンを挟み、柔らかくて香ばしい味わい。卵は良質なタンパク質が豊富で、ベーコンとバターを合わせることで素早くエネルギー補給ができます。作り方はとても簡単で、料理初心者でも楽に作れ、全工程わずか約10分で完成します。', '[{"name":"卵","unit":"個"},{"name":"食パン","unit":"枚"},{"name":"ベーコン","unit":"枚"},{"name":"バター","unit":"g"},{"name":"マヨネーズ","unit":"g"},{"name":"塩","unit":"g"},{"name":"黒コショウ","unit":"g"}]'::jsonb, '["食パンの耳を切り落とし、用意する","卵をゆでて、細かくつぶす","ゆで卵、マヨネーズ、塩、黒コショウを混ぜる","フライパンにバターを入れ、ベーコンを焼く","食パンに作った卵サラダとベーコンを挟む","四角い食パンを三角に切り、皿に盛る"]'::jsonb, '["朝食","簡単","洋風","塩味","焼き"]'::jsonb),
  ('howtocook:condiment/油泼辣子/油泼辣子', 'ja', '油潑辣子', 'ソース・調味料', '香り豊かでピリッと辛い陝西風調味料。赤い油がなめらかで、ゴマとニンニクの香りが絡み合い、口に入れると辛さが広がるが後味はすっきり。唐辛子にはビタミンCとカプサイシンが豊富で、食欲を増進し体を温める。油の温度管理が重要で初心者には少し難しいが、手順通りに進めれば成功する。全行程約10分で、家庭料理の和え物や麺類にぴったりの隠し味。', '[{"name":"ニンニク","unit":"個"},{"name":"乾燥唐辛子粉","unit":"g"},{"name":"塩","unit":"g"},{"name":"白ゴマ（炒り）","unit":"g"},{"name":"ミニトウガラシ","unit":"個"},{"name":"ピーナッツ油","unit":"ml"},{"name":"五香粉","unit":"g"},{"name":"草果","unit":"個"},{"name":"小ネギ","unit":"本"},{"name":"八角"},{"name":"花椒","unit":"粒"},{"name":"ローリエ","unit":"枚"},{"name":"白芷","unit":"枚"},{"name":"生姜スライス","note":"適量"},{"name":"砂糖","unit":"g"},{"name":"白酢","unit":"ml"},{"name":"味の素","note":"適量"}]'::jsonb, '["ニンニクを2片取り出して皮をむく","まな板でニンニクとミニトウガラシをみじん切りにする","ボウルにピーナッツ油を入れる","油が熱くなったら他の香辛料と小ネギを加え、香りが出て焦げ色がついたら取り出して捨てる","鉄鍋にボウルの油を移して2分加熱する（菜種油は煙が出るまで加熱）","この時点でボウルは空","空のボウルに乾燥唐辛子粉、白ゴマ、ニンニクのみじん切り、ミニトウガラシ、塩、五香粉、草果を「調味料」として加える","火を止めて油の温度を210℃まで冷ます","鍋の熱い油をボウルに注ぎ、スプーンで混ぜる（165℃で同じ「調味料」を入れた別のボウルと混ぜ合わせると辛さが増す）","熱い油を注いで軽く混ぜたら白酢を加える。この時再び沸騰する。さらに混ぜ続ける。白酢で香りが増す","油潑辣子が温かくなったら砂糖と味の素を加える。砂糖で辛みが和らぎ、刺激がマイルドになる"]'::jsonb, '["調味料","香辛","陝西風味","和え物","時短","調味料"]'::jsonb),
  ('howtocook:condiment/油酥', 'ja', '油酥', 'ソース・調味料', 'これは中華点心の材料で、よく焼き餅（烙饼）に使います。仕上がりに層を作り、外はサクサク、中はふんわりとします。主に炭水化物と脂質を提供し、エネルギー補給になります。作り方はとても簡単で、初心者にも優しく、たった3分で調合できます。', '[{"name":"小麦粉","note":"適量"},{"name":"油","unit":"ml"},{"name":"塩","note":"適量"}]'::jsonb, '["小麦粉を小さなボウルに入れ、塩を加える","200度の熱した油を加える","箸で固形物のないペースト状になるまで混ぜる。"]'::jsonb, '["ソース","サクサク","点心","烙饼","家庭料理","時短"]'::jsonb),
  ('howtocook:condiment/炸串酱料', 'ja', '串焼きソース', 'ソース・調味料', 'この万能串焼きソースは、スパイシーでコクがあり、塩味と旨味が絶妙なストリートフード風味。主に脂と香辛料の芳香成分が食欲をそそる。作り方は非常にシンプルで、初心者でもストレスフリー。全工程約10分で完成。', '[{"name":"乾燥唐辛子粉（粗挽きと細挽きを用意）","unit":"g"},{"name":"クミンパウダー","unit":"g"},{"name":"黒コショウパウダー","unit":"g"},{"name":"五香粉","unit":"g"},{"name":"花椒パウダー","unit":"g"},{"name":"十三香","unit":"g"},{"name":"麻辣鮮","unit":"g"},{"name":"白ごま","unit":"g"},{"name":"食塩","unit":"g"},{"name":"鶏がらスープの素","unit":"g"},{"name":"油","note":"全ての材料が浸る程度"},{"name":"ごま油","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"花椒油","unit":"ml"},{"name":"オイスターソース","unit":"ml"}]'::jsonb, '["全ての材料を容器に入れて混ぜ合わせる。","鍋で油を熱する。油の量は容器内の全ての材料が浸る程度がベスト。","熱した油を3回に分けて注ぎ入れ、毎回1/3ずつ加えながら混ぜる。","最後にごま油10ml、醤油10ml、花椒油10ml、オイスターソース10mlを加える。"]'::jsonb, '["ソース","スパイシー","ストリートフード","時短","香ばしい","万能"]'::jsonb),
  ('howtocook:condiment/简易版炒糖色', 'ja', '簡単版炒糖色', 'ソース・調味料', '糖色は中華料理の紅焼（醤油煮込み）系料理の色付けに欠かせない技法で、火加減が適切だと赤く輝く艶と独特の香ばしい風味をもたらします。主成分は砂糖でエネルギー源となりますが、主に料理の色合いと味を調和させる役割です。この簡単版炒糖色は火加減のコントロールが重要で、初心者は練習を重ねて苦味や甘くなりすぎを避ける必要があります。全体の調理時間は約10分です。', '[{"name":"氷砂糖/白砂糖/綿白糖（いずれか一つ）","unit":"g"},{"name":"油","unit":"ml"},{"name":"熱湯","unit":"ml"}]'::jsonb, '["火をつけ、鍋に100mlの熱湯を入れる","さらに鍋に100mlの油を入れる。最初の工程との間隔は短いほど良い。この時、鍋は強火でも中火でも良いが、急いでいる場合は強火で","氷砂糖を入れる（氷砂糖が固まっている場合は、事前に砕いて、固まりが少ないほど良い）","火力を中火にする","かき混ぜ始める","ずっとずっとずっとかき混ぜ続け、茶褐色になったら弱火にする","さらに液状になり、紅茶色になり、さらに醤油色になって小さな泡が出てきたら、以下の操作1または操作2を実行する準備をする","小さな泡が徐々に消え、その後大きな泡が出てくる。大きな泡が出たら糖色の完成","この時点で素早く次の操作を行う（どちらの操作でも事前に準備して素早く行うこと！さもないと火が通りすぎて糖色が苦くなる）。料理の流派や個人の好みに応じて選択する","操作1：直接400mlの熱湯を加えて温度を下げる","操作2（上級調味版）：糖液が棗色（なつめ色）になり密集した小さな泡が出たら、事前に用意したねぎ、しょうが、にんにく、花椒などの副材料を素早く加えて炒める。香りが立ったら（約5-10秒以内）、すぐに400mlの熱湯を加えて反応を止める。（注：後続のレシピで肉を炒めて色付けする必要がある場合は、この工程で先に肉を加えて炒め、最後に水を加える。）"]'::jsonb, '["調味料","塩味と甘味","香ばしい","炒め","家庭料理","紅焼きの色付け"]'::jsonb),
  ('howtocook:condiment/糖醋汁', 'ja', '甘酢ダレ', 'ソース・調味料', 'このタレは甘酸っぱくて美味しく、中華料理の甘酢料理の定番風味です。調合が簡単で、比率も覚えやすく、初心者でも簡単に作れます。準備から完成まで約10分。砂糖がエネルギーを供給し、酢の香りが食欲をそそり、脂っこさを和らげ、家庭料理が一気に美味しくなります。', '[{"name":"水","unit":"ml"},{"name":"薄口しょうゆ","unit":"ml"},{"name":"砂糖","unit":"g"},{"name":"白酢/米酢","unit":"ml"},{"name":"料理酒","unit":"ml"}]'::jsonb, '["割合に従って、各調味料を小さなボウルでよく混ぜる","各料理の方法に従って処理が完了したら、準備した甘酢ダレを鍋に加える","料理に応じて、5～10分間加熱する","強火で煮詰めると、料理の濃さ、香り、つやが増す"]'::jsonb, '["タレ","甘酸っぱい","調味料","中華","家庭料理","時短"]'::jsonb),
  ('howtocook:condiment/草莓酱/草莓酱', 'ja', 'いちごジャム', 'ソース・調味料', '甘酸っぱくてフルーティーな香りがたっぷりの家庭的なフルーツジャムで、パンに塗るのに最適です。いちごはビタミンCが豊富ですが、煮詰める時に砂糖が多めなので、好みで調整してください。作り方はとても簡単で、初心者でも楽にできます。準備から煮詰めるまで約2時間かかります。', '[{"name":"いちご","unit":"グラム"},{"name":"グラニュー糖","unit":"グラム"}]'::jsonb, '["いちごを洗い、ヘタを取る","いちごを細かく切り、適当なボウルに入れる","グラニュー糖をボウルに加え、いちごとよく混ぜる","ボウルにラップをかけて1時間置く","置いたいちごと砂糖の混合物をテフロン鍋に入れ、強火で沸騰させる","沸騰したら弱火にし、絶えず混ぜながらジャムがとろりとするまで煮詰め、火を止める","いちごジャムが冷めたら、準備しておいた密閉容器に詰める"]'::jsonb, '["ジャム","甘酸っぱい","家庭的","自家製","手軽"]'::jsonb),
  ('howtocook:condiment/葱油', 'ja', 'ネギ油', 'ソース・調味料', 'ネギ油は、香りを引き立て、うま味を加える家庭用調味油です。濃厚なネギの香りと干しエビの複合的な風味が特徴で、餡と和えたり、和え物や熱菜の仕上げ油に最適です。主に油脂のエネルギーを提供し、ネギや生姜などの香辛料には植物性有効成分が含まれており、消臭や食欲増進に役立ちます。作り方は簡単で、初心者にも優しく、準備から30分ほどで完成します。', '[{"name":"油","unit":"グラム"},{"name":"ネギ（長ネギでも小ネギでも可）","unit":"グラム"},{"name":"生姜","unit":"グラム"},{"name":"玉ねぎ","unit":"グラム"},{"name":"料理酒","unit":"ml"},{"name":"干しエビ（お好みで）","unit":"グラム"},{"name":"パクチー（お好みで）","note":"適量"}]'::jsonb, '["干しエビを50度の温水に浸し、10mlの料理酒を加えて臭みを取り、10分間浸した後、取り出して水気を切る。","ネギとパクチーを洗い、5cmの長さに切り、表面の水気を拭き取る。","玉ねぎを千切りにし、鍋で熱湯で5分間茹で、取り出して水気を切る。","生姜の皮をむき、薄切りにする。","鍋にすべての油を入れ、上記の下処理済みの材料を加え、中弱火で20分間揚げる。"]'::jsonb, '["ソース","ネギ香","うま味","調味油","餡和え","麺和え","熱かけ"]'::jsonb),
  ('howtocook:condiment/蒜香酱油', 'ja', 'ニンニク醤油', 'ソース・調味料', 'ニンニク醤油は、ニンニクの風味が豊かで、塩味と油の旨味がある家庭的なつけだれです。白切鶏や餃子などの料理の味を引き立てるのに使われます。ニンニクとゴマには、それぞれ抗菌作用と不飽和脂肪酸の補給効果があります。作り方は非常に簡単で、初心者にも優しく、約5分で完成します。', '[{"name":"ニンニク","unit":"片"},{"name":"白ごま","unit":"グラム"},{"name":"ピーナッツ油","unit":"ml"},{"name":"醤油","unit":"ml"}]'::jsonb, '["ニンニクを潰す","つけだれの皿に醤油を入れる","鍋を熱し、ピーナッツ油を加え、油が熱くなったら潰したニンニクを加えて30秒揚げる","30秒後、火を止め、熱した油をつけだれの皿に注ぎ、箸で混ぜる"]'::jsonb, '["たれ","ニンニク風味","塩味","揚げ","家庭料理","つけだれ"]'::jsonb),
  ('howtocook:condiment/蔗糖糖浆/蔗糖糖浆', 'ja', '蔗糖シロップ', 'ソース・調味料', '自家製ドリンクシロップ。白砂糖と水を1：1の割合で混ぜて溶かすだけ。冷たい飲み物の甘さを簡単に調整でき、ドリンク作りの基本レシピです。炭水化物が豊富ですぐにエネルギー補給ができます。作り方は非常に簡単で、初心者にも優しく、数分で完成。冷蔵庫で1週間保存可能です。', '[{"name":"白砂糖","unit":"グラム"},{"name":"水","unit":"グラム"}]'::jsonb, '["計量した白砂糖と水を容器に入れて混ぜ合わせる","容器に蓋をして冷蔵庫で保存する"]'::jsonb, '["ソース","甘味","ドリンク基本","時短","冷蔵"]'::jsonb),
  ('howtocook:dessert/反沙芋头/反沙芋头', 'ja', '反沙芋頭', 'デザート', '反沙芋頭は外はカリッと中はモチモチ、甘くて香ばしい潮州の伝統的なおやつで、よく午後のお茶うけとして楽しまれます。里芋は食物繊維やカリウム、ビタミンが豊富で、満腹感が持続します。作り方は難しくありませんが、砂糖を煮る火加減が肝心で、少し経験のある初心者にぴったり。全行程約20分で完成します。', '[{"name":"荔浦芋頭","unit":"g"},{"name":"白砂糖または氷砂糖","unit":"g"},{"name":"水","unit":"g"},{"name":"ネギ","note":"適量"}]'::jsonb, '["芋頭を長めの拍子切りにする（少し大きめに切ると、炒めている間に崩れにくい）","芋頭が浸かるくらいの油を入れ、油が温まったら（菜箸を入れて小さな泡が出ればOK）","芋頭を油に入れ、浮き上がってくるまで揚げる。目安はほんのりきつね色になり、菜箸でスッと刺さるようになったら","揚げ油は捨てずに保存しておく。後で炒め物などに使える","次に肝心の工程。砂糖(30g)と水(15g)を2:1の割合で鍋に入れ、色が変わらず小さな泡が出るまで加熱する","刻みネギと芋頭を加え、火を止めて炒め合わせる。温度が下がると砂糖が白く固まって反沙の状態になる","皿に盛って出来上がり！"]'::jsonb, '["デザート","潮州","揚げ物","甘い","おやつ","点心"]'::jsonb),
  ('howtocook:dessert/咖啡椰奶冻/咖啡椰奶冻', 'ja', 'コーヒーココナッツミルクゼリー', 'デザート', 'このデザートは、コーヒーのコクとココナッツミルクの清らかな甘さが融合し、プディングのようななめらかで繊細な口当たりで、豊かな層を持っています。生クリームとココナッツジュースは良質な脂肪と植物栄養を提供し、食べることで満足感が得られます。作り方は非常に簡単で、混ぜて加熱するだけ。複雑な技術は不要で、初心者でも一度で成功できます。冷蔵時間を除けば、実際の作業時間は約1時間、冷蔵で固める時間を含めると約4時間でいただけます。', '[{"name":"生クリーム","unit":"ml","note":""},{"name":"椰树牌ココナッツジュース","unit":"ml","note":""},{"name":"エスプレッソ","unit":"ml","note":""},{"name":"ココナッツウォーター","unit":"ml","note":""},{"name":"ゼラチン","unit":"g","note":""},{"name":"砂糖","unit":"","note":"適量"},{"name":"ブルーベリー","unit":"","note":"適量"},{"name":"コーヒーパウダー","unit":"","note":"適量"}]'::jsonb, '["定められた量の生クリーム、椰树牌のココナッツジュース、エスプレッソ、ココナッツウォーターを混ぜ合わせておきます。","上記の液体を1分間加熱し、温度が50〜60度になればokです。","（任意）特に甘いのが好きな場合は、追加の砂糖を加えてください。","ゼラチンを加え、溶けるまで混ぜ、1分間煮ます。","（任意）こし器で濾します（この工程でココナッツミルクゼリーの口当たりがさらになめらかになります）。","型に入れます。","（任意）表面の泡を取り除きます。この工程でココナッツミルクゼリーの口当たりが良くなり、見た目もきれいになります。","冷蔵庫に入れ、3時間待ちます。"]'::jsonb, '["デザート","コーヒーの香り","ココナッツの香り","焼かない","プリン食感","午後のお茶"]'::jsonb),
  ('howtocook:dessert/奥利奥冰淇淋/奥利奥冰淇淋', 'ja', 'オレオアイスクリーム', 'デザート', 'オレオアイスクリームは口当たりが滑らかで、ミルクの風味とオレオのサクサクした甘さが調和し、純生クリームを使っているので軽くてしつこくありません。主にエネルギーを供給し、脂質と炭水化物を含み、暑い日の軽いデザートに最適です。作り方は比較的簡単で、ビスケットのクリームを外し、生クリームを泡立てるだけで、初心者でも少し根気よくやれば完成します。準備時間は約30分、冷凍庫で4時間以上冷やせば食べられます。', '[{"name":"生クリーム（おすすめ：アンカー純生クリーム）","unit":"ml"},{"name":"プレーンオレオ","unit":"個"},{"name":"グラニュー糖","unit":"g"}]'::jsonb, '["オレオをひねって開け、中のクリームを取り出して取っておく","箸でオレオのビスケット部分を細かく砕く。半分は粉状に、残りの半分は最大長さ0.5cm以下になるようにする（時短したい方は「オレオクラッシュ」をネットで購入してもOK^^）","生クリームを全て深めの容器に入れ、準備した砂糖を加える","ハンドミキサーの高速で、泡立て器を持ち上げた時にクリームが垂れずに先端に0.5～1cmほど残るまで泡立てる（一部が垂れるのは正常）","泡立て終わったら、砕いたオレオを加え、底まで均一に混ぜる","オプション：混合物をアイスクリーム型に流し入れる","冷凍庫（-18度）で4時間以上冷やしてから取り出す"]'::jsonb, '["デザート","ミルク風味","甘い","冷凍","時短","おやつ"]'::jsonb),
  ('howtocook:dessert/戚风蛋糕/戚风蛋糕', 'ja', 'シフォンケーキ', 'デザート', 'このお菓子作り初心者向けのデザートは、口当たりがなめらかでふわふわ、雲のような軽い食感が特徴で、洋菓子の定番基本形です。主な材料の卵と牛乳は良質なタンパク質とカルシウムを提供し、栄養豊富です。作り方は泡立てや混ぜ合わせ、焼き加減にコツが必要で少し挑戦的ですが、根気よく手順を守れば初心者でも成功できます。準備から焼き上がりまで通常1.5～2時間かかります。', '[{"name":"卵","unit":"個"},{"name":"砂糖","unit":"g"},{"name":"牛乳（または水）","unit":"g"},{"name":"食用油（またはバター）","unit":"g"},{"name":"薄力粉","unit":"g"},{"name":"レモン汁または酢（お好みで）","note":"適量"}]'::jsonb, '["冷蔵庫から新鮮な卵を取り出す","2つの容器を用意して水気を拭き取り、卵白と卵黄をそれぞれ入れる","卵白用の容器は多少の水滴があっても良いが、油分があってはいけない。卵黄用の容器は水滴があってはいけない","卵を割り、手または卵黄分離器を使って卵白と卵黄を2つの容器に分ける","分離中に卵黄を割ってはいけない。卵白に卵黄が混ざると泡立ちに大きく影響する（白いカラザは卵白に入っても問題ない）","（注意：ハンドミキサーを使わない場合、卵白用の容器がそのまま泡立て容器になる。あふれを防ぐため、全卵白を入れた後は容器の1/8を超えないようにする）","新しいボウルを用意し、レシピの全食用油と全牛乳を加える","泡立て器で手早く混ぜ、油と水が完全に混ざり合って白濁した懸濁液状になるまで乳化させる","レシピの全薄力粉をふるいにかけ、乳化液に加える。ゴムベラで「Zの字」に混ぜ、粉っぽさがなくなるまで混ぜる（この時点で生地が少しざらついていても正常）","分けておいた全卵黄をボウルに加え、引き続きゴムベラで「Zの字」に混ぜる","生地がとてもなめらかになり、グルテンができにくくなる。置いておく","残りの砂糖の3/4を用意する。3等分し、各1/4量とする","卵白にレモン汁または酢を加える（お好みで）","ハンドミキサーを中速にして、卵白を大きな泡が立つまで泡立て、1回目の砂糖を加える","ハンドミキサーを高速にして、卵白の泡が細かくなるまで泡立て、2回目の砂糖を加える","ハンドミキサーを高速にして、「湿性泡立て」の状態になるまで泡立て、3回目の砂糖を加える","ハンドミキサーを中低速にして、「乾性泡立て」の状態になるまで泡立てる","卵白の泡立て具合が適切になった","（卵白の状態の判断は添付リンクの画像を参照）","（ハンドミキサーは容器の底に近づけて使い、表面だけ泡立って底が液体のままにならないようにする）","卵黄液を軽く数回混ぜる","ゴムベラでメレンゲの1/3を取り、卵黄生地に加える","「切り混ぜ」の手法を使う。これは泡を消さないための方法","切り混ぜの手順は：","まず右手でゴムベラをボウルの中心から底に差し入れる","8時の方向に向かってボウルの端までこそげ、そのままゴムベラですくい上げて空中に持ち上げ、再びボウルの中心に戻して生地を落とす","左手でボウルを9時の方向から7時の方向へ回す（60度回転）。これで1サイクル完了","速さは約1秒間に2回","この方法は『小島先生のケーキ教室』から。簡単に言うと、炒め物をするように混ぜる","1/3のメレンゲと卵黄生地を混ぜたものを、残りの2/3のメレンゲに加え、さらに切り混ぜて均一にする","ケーキ生地を型に流し入れ、軽く数回落として大きな気泡を抜く","焼成時間の目安：6インチ型で30～35分、8インチ型で50分。オーブンの特性に合わせて調整し、通常±5分以内。（最後の数分はオーブンの前で観察）","上火150℃、下火160℃に予熱して焼く。約10分で設定温度に達する","予熱完了後、型をオーブン下段に入れる","変温焼きを選択し、2段階に分ける","第1段階のオーブン設定温度：上火150℃、下火160℃","焼成時間の最初の3/5を第1段階とする","第2段階の温度：上火160℃、下火170℃","焼成時間の残り2/5を第2段階とする。オーブンの温度を直接調整して切り替える","焼き上がったら、オーブンから出す","この作業は熱いので、布巾などを使う","予熱：ノンフライヤーを130℃で5分予熱する","投入とカバー：ケーキ生地の入った型をノンフライヤーに入れる。すぐに型の上にアルミホイルをかぶせる（輝く面を上に、つや消し面が食材に触れるように）。端をしっかりと閉じて、熱風で飛ばされないようにする","第1段階焼成：130℃で35分焼く","第2段階（焼き色付け）：ノンフライヤーを開け、アルミホイルを取り外す。温度を150℃に上げ、10～15分追加で焼く","焼き上がりの判断：ケーキの上部が膨らみ、きつね色になって焼き色がつけば完成。中心に竹串を刺し、ぬれた生地がついてこなければ焼き上がり","焼き上がり後の熱気抜きと型外しの操作は、オーブン版と完全に同じ","（お好みで）型を高いところから落とし、熱気を抜く","型を逆さまにして10分置き、ケーキを冷ます","冷めていないケーキをすぐに型から外すと傷つく","この作業は熱いので、布巾などを使う","型から外し、食べる"]'::jsonb, '["デザート","甘い","焼き菓子","洋菓子","おやつ","定番"]'::jsonb),
  ('howtocook:dessert/提拉米苏/提拉米苏', 'ja', 'ティラミス', 'デザート', 'このイタリアの伝統的なデザートはオーブン不要で、チーズクリームはなめらかで軽やか、コーヒー液に浸した指餅は香ばしく柔らかく、初心者向けのスイーツです。タンパク質とカルシウムが豊富ですが、糖分とカロリーが高めなので、たまに楽しむのがおすすめ。操作は簡単で、ベーキング初心者にも優しく、手作業は約30分、冷蔵庫で4時間冷やせば完成です。', '[{"name":"マスカルポーネチーズ","unit":"グラム"},{"name":"指餅","unit":"パック"},{"name":"冷ましたエスプレッソ","unit":"ml"},{"name":"無菌卵","unit":"個"},{"name":"グラニュー糖","unit":"グラム"},{"name":"ココアパウダー","unit":"グラム"},{"name":"ラム酒","unit":"ml"}]'::jsonb, '["卵黄と卵白を分ける","卵白のボウルにグラニュー糖10gを加え、角が立つまで泡立てる","卵黄のボウルにグラニュー糖40gを3回に分けて加え、均一になるまで混ぜる","卵黄にマスカルポーネチーズを3回に分けて加え、均一になるまで混ぜる","卵黄に最後にラム酒を加え、均一に混ぜる","泡立てた卵白を卵黄チーズ液に3回に分けて加える","指餅の両面をコーヒー液にさっと浸し、容器に並べる","チーズ液と指餅を2層ずつ交互に容器に入れる（この手順はお好みや容器の高さに応じて調整）","冷蔵庫で4時間冷やす（急いでいる場合は早めに取り出しても可）","取り出した後、表面にココアパウダーをふりかけて完成"]'::jsonb, '["デザート","オーブン不要","イタリアン","甘い","おやつ","パーティー"]'::jsonb),
  ('howtocook:dessert/无厨师机蜂蜜面包/无厨师机蜂蜜面包', 'ja', 'ホームベーカリーなしのハチミツパン', 'デザート', 'これはホームベーカリーを使わない家庭的なハチミツ小さなパンです。ふわふわで甘く、底は少しカリッとし、表面にハチミツ水を塗ってゴマを振りかけ、素朴な甘い香りがします。主な材料は強力粉、牛乳、卵、バターで、炭水化物、タンパク質、カルシウムが豊富で、朝食やおやつにぴったりです。作り方は簡単で、全て手ごね、発酵時間も柔軟で、前の晩に冷蔵庫に入れて翌日焼くこともでき、初心者にも優しいレシピです。制作時間は約3時間ですが、そのほとんどは発酵の待ち時間で、実際の作業はそれほど手間がかかりません。', '[{"name":"強力粉","unit":"グラム"},{"name":"牛乳","unit":"グラム"},{"name":"イースト","unit":"グラム"},{"name":"卵","unit":"個"},{"name":"白砂糖","unit":"グラム"},{"name":"塩","unit":"グラム"},{"name":"バター","unit":"グラム"},{"name":"ハチミツ","unit":"グラム"},{"name":"水","unit":"グラム"},{"name":"ピーナッツ油","note":"適量"},{"name":"ゴマ","note":"適量"}]'::jsonb, '["生地を作る：強力粉、牛乳（40℃に温めることをおすすめ、私は電子レンジで15〜20秒加熱）、イースト、卵、強力粉、砂糖、塩を混ぜ合わせる。","生地を混ぜ、材料が均一にまとまるまで混ぜる。","バターを加えて混ぜる。","さらに混ぜ、手ごねで均一に混ぜ合わせる。","発酵を始める：容器にラップをかけ、常温（10〜20℃）で1〜2時間置く。少し長くても仕上がりに大きな影響はない。","生地が明らかに膨らんだら（2倍）、分割を始める。この時、生地はそれほどベタつかないはず。","生地を分割する：理想は1個60g（見た目が良い）。好みで大きさを調整しても良い。","それぞれの小さな生地を麺棒で舌状に伸ばして巻き、再び10分休ませる。","もう一度麺棒で舌状に伸ばして巻き、真ん中から切る（1つが2つになる）。","もう一度麺棒で舌状に伸ばして巻き、真ん中から切る（2つが4つになる）。（このステップは自分の時間に応じて何度か伸ばし/巻きを繰り返し、1個分の大きさを調整すれば良い。）","天板にクッキングシートを敷き、ピーナッツ油を注ぐ。（巻き終わったそれぞれの）底部を水+強力粉に付けてから天板に並べる。","再び発酵させる（ラップをかける）。このステップは冷蔵庫に入れて、次の日に焼くこともできる。","卵液を塗る。","オーブン180℃(355°F)、18〜20分。","焼き上がったら、ハチミツ水を塗り、ゴマを振りかける。"]'::jsonb, '["デザート","甘い","ベーキング","朝食","手ごね","初心者向け"]'::jsonb),
  ('howtocook:dessert/炸鲜奶/炸鲜奶', 'ja', '揚げミルク', 'デザート', '揚げミルクは、外はサクサク、中はとろける甘さの定番デザートで、家庭的なおやつです。たんぱく質とカルシウムが豊富で栄養バランスも良好。調理は中程度の難易度で初心者でも挑戦しやすく、作業時間は約20分ですが、冷蔵庫で1時間冷やし固める必要があります。', '[{"name":"牛乳","unit":"グラム"},{"name":"コーンスターチ","unit":"グラム"},{"name":"パン粉","unit":"グラム"},{"name":"卵","unit":"個"},{"name":"砂糖","unit":"グラム"}]'::jsonb, '["牛乳をボウルに注ぐ","コーンスターチと砂糖を加え、よく混ぜる","型に食用油を塗る","牛乳を鍋に入れ、中火で沸かす","沸騰したら弱火にし、混ぜながら煮る","牛乳がとろみ始めたら火を止め、型に流し入れる","型を冷蔵庫で1時間冷やす","取り出し、均等な大きさの棒状に切り、ボウルに入れる","パン粉の半量をボウルに加え、ミルクがらをまぶしたら取り出し、置いておく","新しいボウルに卵を割り入れ、よく溶く","ミルクがらを卵液に浸し、残りのパン粉をまぶす","鍋にミルクがらが浸るくらいの油を入れて熱し、揚げる","きつね色になったら火を止め、皿に盛る"]'::jsonb, '["デザート","甘い","揚げ物","外サク中トロ","家庭菓子","おやつ"]'::jsonb),
  ('howtocook:dessert/烤箱版巴斯克芝士蛋糕/烤箱版巴斯克芝士蛋糕', 'ja', 'オーブン版バスクチーズケーキ', 'デザート', 'バスクチーズケーキは、濃厚でしっとりとした食感、表面は焦げて香ばしく内部はしっとりとしたデザートで、スペインのバスク地方の定番風味です。主な原料はクリームチーズと卵で、良質なタンパク質とカルシウムが豊富です。作り方はとても簡単で、初心者でも気軽に挑戦できます。準備から焼き上がりまで約30分ですが、一晩冷蔵してから食べることをお勧めします。合計で8時間以上かかります。', '[{"name":"クリームチーズ","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"卵","unit":"個"},{"name":"卵黄","unit":"個"},{"name":"生クリーム","unit":"g"},{"name":"薄力粉","unit":"g"}]'::jsonb, '["クリームチーズを柔らかくし、電子レンジで10秒 + 10秒加熱。","クリームチーズに砂糖を加え、泡立て器でなめらかになるまで混ぜる。","全卵2個 + 卵黄1個を加え、よく混ぜる。","生クリームを加え、よく混ぜる。","薄力粉を加え、よく混ぜる。","オーブン220℃(425°F)で20〜25分（私は通常20分か22分）。","冷ました後、冷蔵庫に入れ、できれば一晩置く。"]'::jsonb, '["デザート","甘い","焼き菓子","洋風","簡単","おやつ"]'::jsonb),
  ('howtocook:dessert/烤蛋挞/烤蛋挞', 'ja', '焼きエッグタルト', 'デザート', '焼きエッグタルトは定番の中華スイーツで、外側はサクサク、中はなめらかでミルクの香りが豊かです。タンパク質、カルシウム、各種ビタミンが豊富で、エネルギー補給に最適。作り方はとても簡単で、初心者でも気軽に挑戦でき、半製品は冷凍保存も可能です。準備から焼き上がりまで約1時間かかります。', '[{"name":"エッグタルトの皮","unit":"個"},{"name":"卵","unit":"個"},{"name":"牛乳","unit":"ml"},{"name":"生クリーム","unit":"ml"},{"name":"白砂糖","unit":"g"}]'::jsonb, '["ボウルをスケールに乗せ、生クリーム450gを計量する（生クリームの密度はここでは1とする）","白砂糖80gを加える（甘さは中程度、好みで増減可、推奨範囲60〜100g）","牛乳200gを加える（牛乳の密度はここでは1とする）","卵黄8個を取り、卵白は別用途に取っておく","すべての材料を均一に混ぜ、白砂糖が完全に溶けるまで混ぜる","混ぜ合わせた材料を網で濾す。卵の膜、卵の殻、溶け残った白砂糖、固まった生クリームを取り除く","ここでオーブンを220℃に予熱し始める（約10分）。天板を忘れずに出す","エッグタルトの皮を天板に0.5cm間隔で均等に並べる","濾した材料をエッグタルトの皮に注ぐ。液面は皮の上端から0.5cm程度にし、多すぎないようにする","ここまでの工程で半製品のエッグタルトが完成。そのまま冷凍庫で12時間以上保存可能","半製品のエッグタルトをオーブンで焼く。温度200℃、時間25分","焼き上がったらすぐに食べられる"]'::jsonb, '["スイーツ","ミルク風味","焼き菓子","初心者","家庭料理","冷凍保存","お茶うけ"]'::jsonb),
  ('howtocook:dessert/玛格丽特饼干/玛格丽特饼干', 'ja', 'マーガレットクッキー', 'デザート', 'マーガレットクッキーはサクサクとした食感とバターの豊かな香りが特徴の、定番の洋風スイーツです。卵黄、バター、小麦粉を主原料とし、炭水化物と脂質が豊富で、手軽にエネルギー補給ができます。作り方は中程度の難易度で、準備から焼き上がりまで約45分かかりますが、初心者でも簡単に作れます。', '[{"name":"ゆで卵の黄身","unit":"個"},{"name":"バター","unit":"g"},{"name":"グラニュー糖","unit":"g"},{"name":"塩","unit":"g"},{"name":"薄力粉","unit":"g"},{"name":"コーンスターチ","unit":"g"}]'::jsonb, '["バターを湯煎で溶かし、卵黄をすりおろしておく。","溶かしたバターに砂糖、塩、すりおろした卵黄を加え、よく混ぜる。","薄力粉とコーンスターチを加え、ひとまとめになるまでこねる。","生地を均等に約8gずつに分割し、丸める。","親指で軽く押して、ひび割れ模様をつける。","オーブンを150℃に予熱し、丸めた生地を並べて20分焼く。","粗熱が取れたらできあがり。"]'::jsonb, '["デザート","サクサク","バターの香り","焼き菓子","洋菓子","おやつ"]'::jsonb),
  ('howtocook:dessert/红柚蛋糕/红柚蛋糕', 'ja', '紅柚ケーキ', 'デザート', '紅柚ケーキはエアフライヤーで簡単に作れる爽やかなデザートです。紅柚の果肉の微かな酸味と香り、そしてケーキのふんわりとした食感が融合し、一人分の午後のおやつに最適です。卵と小麦粉でタンパク質と炭水化物を、紅柚でビタミンCを摂取でき、シンプルながら基本的な栄養を提供します。調理難易度は中程度で、ポイントは数回に分けてダマのない薄黄色の生地に混ぜることです。初心者でも根気よく手順に従えば成功できます。材料準備から焼き上がりまで約35分かかり、焼きたてのおやつが食べたいときにあまり時間を取られません。', '[{"name":"卵","unit":"個"},{"name":"紅柚果肉","unit":"g"},{"name":"小麦粉","unit":"g"},{"name":"油","unit":"ml"},{"name":"砂糖","unit":"g"},{"name":"水","unit":"ml"}]'::jsonb, '["アルミホイルの皿に卵を2個割り入れ、紅柚果肉20gを加える","アルミホイルの皿に油15mlを注ぎ、皿を揺すって底に均一に広げる","アルミホイルの皿に砂糖10g、小麦粉40g、水40mlを加える","箸で時計回りに薄黄色の糊状になるまで混ぜる","アルミホイルの皿に砂糖5g、小麦粉40g、水40mlを加える","さらに箸で薄黄色の糊状になるまで混ぜる","アルミホイルの皿をエアフライヤーのバスケットに入れ、180℃で15分焼く","エアフライヤーを開け、慎重にアルミホイルの皿を取り出し、箸またはスプーンでケーキを裏返す","続けて180℃で8分焼く","取り出してそのまま食べられる"]'::jsonb, '["デザート","甘酸っぱい","焼き菓子","エアフライヤー","時短","午後のおやつ"]'::jsonb),
  ('howtocook:dessert/胡萝卜甜糕', 'ja', 'にんじんの甘いケーキ', 'デザート', 'にんじんの甘いケーキはインドで冬の定番デザートです。にんじんの千切りと牛乳をじっくり煮詰め、ギーとナッツを加えたもので、しっとりと甘く、色は黄金色がかっています。βカロテン、カルシウム、良質な脂質が豊富で、体を温め栄養を与えます。作り方は簡単ですが、初心者には少し忍耐が必要で、全体で約45分で完成します。', '[{"name":"にんじん","unit":"g"},{"name":"全乳","unit":"ml"},{"name":"砂糖","unit":"g"},{"name":"ギー","unit":"g"},{"name":"カルダモンパウダー","unit":"g"},{"name":"カシューナッツ","unit":"g"},{"name":"アーモンド","unit":"g"},{"name":"レーズン","unit":"g"}]'::jsonb, '["にんじんの皮をむき、おろし器で細かくおろす","厚底鍋にギー20g（半分）を入れ、中火で熱して溶かす","にんじんの千切りを加え、3〜5分間、にんじんが柔らかくなり香りが立つまで炒める","全乳500mlを注ぎ、よく混ぜる","強火で沸騰させたら中弱火にし、ゆっくりと沸騰した状態を保つ","25〜30分間、絶えずかき混ぜながら、牛乳がにんじんにほぼ完全に吸収され蒸発するまで加熱する（これが最も重要な工程で、焦げ付きを防ぐために絶えず混ぜる必要がある）","鍋に液体がほとんどなくなったら、砂糖80gを加え、よく混ぜる","砂糖を加えると再び水分が出るので、引き続き中弱火で5〜8分間、水分が再び蒸発するまで炒める","残りのギー20gとカルダモンパウダー3gを加え、2分間炒める","別の小鍋で、少量のギーでカシューナッツ、アーモンドスライス、レーズンをそれぞれ黄金色になるまで揚げる（約1分間）。レーズンは膨らむので注意する","揚げたナッツとレーズンの半分をにんじんの甘いケーキに混ぜ込む","器に盛り、残りのナッツとレーズンを表面に飾る"]'::jsonb, '["デザート","インド風味","甘い","じっくり煮る","体を温める","滋養"]'::jsonb),
  ('howtocook:dessert/芋泥雪媚娘/芋泥雪媚娘', 'ja', 'タロイモの雪媚娘', 'デザート', 'タロイモの雪媚娘は、外皮がもちもちで弾力があり、中には滑らかで甘いタロイモペーストと軽いクリームが入っていて、食感の層が豊かです。家庭的なアイデアから生まれた中華風スイーツです。タロイモと紫芋は食物繊維とアントシアニンを、牛乳と生クリームはカルシウムを補い、栄養バランスも良いです。オーブン不要で、手順も簡単なので初心者にも優しく、お菓子作りが苦手な方でも気軽に作れます。最初から最後まで約2時間で、子供が大好きな手作りおやつが完成します。', '[{"name":"タロイモ","unit":"g"},{"name":"紫芋パウダー","unit":"g"},{"name":"牛乳","unit":"g"},{"name":"白玉粉","unit":"g"},{"name":"白玉粉","unit":"g"},{"name":"コーンスターチ","unit":"g"},{"name":"バター","unit":"g"},{"name":"生クリーム","unit":"g"},{"name":"グラニュー糖","unit":"g"}]'::jsonb, '["タロイモを一口大に切り、強火で柔らかくなるまで茹でる（約40分）。全部をフードプロセッサーに入れる。","そこに牛乳30g、生クリーム25gを加え、ペースト状になるまで混ぜる。","さらに紫芋パウダー3g、グラニュー糖18gを加え、滑らかなタロイモペーストになるまで混ぜ続ける。","別のボウルに、白玉粉bの全量、コーンスターチ22g、牛乳135g、グラニュー糖50gを入れて混ぜ合わせ、一度ふるいにかける。ラップで覆い、小さな穴を開け、中火で30分蒸す。","蒸している間に、白玉粉aをフライパンで弱火で軽く色づくまで炒る（炒め粉＝手粉として使う）。","中火で30分蒸した牛乳ともち粉の混合物（ゼリー状）が熱いうちに、バター30gを加え、バターが完全に生地に吸収されるまで揉み込み、冷蔵庫で1時間冷やす。","別のボウルに生クリーム120g、グラニュー糖8gを入れ、ツノが立つまで泡立て、絞り袋に入れておく。","冷蔵庫から取り出した生地を5分間こね、30gずつに分け、手粉2gを均等に振ってくっつきを防ぎ、円形に伸ばす。まず絞りクリーム5gを絞り、その上にタロイモペースト30gをのせ、生地を包子（中華まん）のように包む（余分な皮は取り除いてもよい）。","包んだらさらに手粉2gを均等に振る。","以上の2工程を材料がなくなるまで繰り返す。"]'::jsonb, '["スイーツ","甘い","もちもち","蒸し調理","オーブン不要","おやつ"]'::jsonb),
  ('howtocook:dessert/英式司康/英式司康', 'ja', 'イギリス風スコーン', 'デザート', 'イギリス風スコーンは、クラシックな英国風アフタヌーンティー菓子で、外はサクサク、中はふんわり、卵とミルクの香り豊か。ジャムやクリームと合わせるとさらに美味しい。主に小麦粉、バター、卵、生クリームから作られ、炭水化物とタンパク質が豊富で、素早くエネルギー補給ができる。作り方は比較的簡単で、基本的なこね方をマスターすれば初心者でも十分。準備から焼き上がりまで約1時間。', '[{"name":"無塩バター","unit":"グラム"},{"name":"薄力粉","unit":"グラム"},{"name":"砂糖","unit":"グラム"},{"name":"塩","unit":"グラム"},{"name":"ベーキングパウダー","unit":"グラム"},{"name":"卵","unit":"個"},{"name":"生クリーム","unit":"グラム"},{"name":"クリームチーズ","unit":"グラム"}]'::jsonb, '["卵を溶きほぐし、30gの卵液を清潔な容器に量り取る。全量の生クリームとクリームチーズを加えて均一に混ぜる。チーズが硬い場合は、湯煎で約40度に温めてから混ぜるとよい。","薄力粉、塩、砂糖、ベーキングパウダーを清潔な容器に入れて均一に混ぜる。","バターを小さく切り、前の工程の混合物に入れる。手でバターを混ぜ込み、粗いコーンミール状にする。","最初の工程の卵液と生クリームの混合液を、前の工程で得た粉とバターの混合物に注ぎ入れ、均一に混ぜる。折り重ねるようにして均一な生地にする。","生地をまな板に置き、1.5cmの厚さに伸ばす。包丁や型で適当な形に切り分ける。","刷毛で残りの20gの卵液をスコーンの表面に塗る。","オーブンを180度に予熱し、27分焼く。"]'::jsonb, '["デザート","甘い","焼き菓子","イギリス風","アフタヌーンティー","菓子"]'::jsonb),
  ('howtocook:dessert/草莓冰淇淋/草莓冰淇淋', 'ja', 'ストロベリーアイスクリーム', 'デザート', 'これはミキサー不要で簡単に作れるお家のストロベリーアイスクリームです。果実の香りが豊かで、口当たりは滑らか。イチゴにはビタミンCが豊富で、ミルク感たっぷりの練乳とクリームを合わせることで、エネルギーとカルシウムを摂取できます。作り方は簡単で料理の腕前を問わず、初心者でも一度で成功します。全行程にかかる時間は約8時間で、そのほとんどは冷凍時間であり、実際に手を動かすのはわずか数十分です。', '[{"name":"いちご","unit":"グラム"},{"name":"砂糖","unit":"グラム"},{"name":"バニラエッセンス","unit":"グラム"},{"name":"塩","unit":"グラム"},{"name":"バニラエッセンス","unit":"グラム"},{"name":"生クリーム","unit":"グラム"},{"name":"塩","unit":"グラム"},{"name":"加糖練乳","unit":"グラム"}]'::jsonb, '["まずイチゴシロップを作ります。イチゴを洗い、ヘタを取り除きます。イチゴを5mmの大きさに切ります。半分の刻んだイチゴは取っておき、後でアイスクリームに混ぜ込みます。","残りの半分の刻んだイチゴと砂糖を鍋に入れます。中火でかき混ぜながら加熱し、イチゴから液体が出てきてシロップ状になるまで調理します。","イチゴをシロップの中で加熱し、時々かき混ぜながら、イチゴが崩れて形がなくなり、シロップが少しとろみがつくまで続けます。","シロップが3秒間分離したままになれば準備完了です。火から下ろし、バニラと塩を加えて混ぜます。イチゴシロップを冷ましておきます。","シロップが冷めている間に、アイスクリームベースを作ります。ボウルに加糖練乳、生クリーム、バニラエッセンス、塩を入れます。ハンドミキサーで軽くふんわりとして、やわらかいツノが立つまで混ぜます。","取っておいた刻んだ生のイチゴをアイスクリームベースにさっくりと混ぜ込みます。混ぜたアイスクリームベースを冷凍可能な容器に移します。冷ましたイチゴシロップをアイスクリームの上にかけ、軽くマーブル状に混ぜ合わせます。","アイスクリームに蓋をし、8時間冷凍します。その後、すくってお召し上がりください。"]'::jsonb, '["デザート","甘い","焼かない","簡単","お家で","夏"]'::jsonb),
  ('howtocook:dessert/酸奶意式奶冻/酸奶意式奶冻', 'ja', 'ヨーグルトパンナコッタ', 'デザート', 'イタリアの古典的なデザートをアレンジした一品。プレーンヨーグルトを加えることで、よりさっぱりとしてなめらかな口当たりに。甘すぎず、食後のデザートとしてフルーツやジャムと合わせるのに最適。乳製品が豊富なカルシウムとタンパク質を提供し、栄養バランスも優しい。作り方は簡単で、加熱して混ぜ、冷やして固めるだけ。初心者でも手軽にでき、準備から冷蔵完成まで約5時間かかる。', '[{"name":"生クリーム","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"プレーンヨーグルト","unit":"g"},{"name":"ゼラチンシート","unit":"g"}]'::jsonb, '["ゼラチンシートを小さく切って冷水に浸す","生クリームと砂糖を鍋に入れ、60度に加熱する","火を止め、ゼラチンを水から取り出し、水気を切って熱い生クリームに加え、よく混ぜる","生クリームを40度まで冷まし、プレーンヨーグルトを加えてよく混ぜる","上記の工程でできた混合物を2回ふるいにかける","適切な容器に分け入れ、冷蔵庫で4時間以上冷やす"]'::jsonb, '["デザート","甘酸っぱい","イタリア風","焼かない","簡単","おもてなし"]'::jsonb),
  ('howtocook:dessert/雪花酥/雪花酥', 'ja', 'スノーフレーククランチ', 'デザート', 'スノーフレーククランチは、サクサクとした食感と甘さ、濃厚なミルクの風味が特徴の小さなスイーツです。手軽に作れる家庭向けの焼き菓子で、箱詰めして贈り物にも適しています。バター、粉乳、ミックスナッツを含むため、エネルギーとタンパク質が豊富ですが、カロリーが高いため、たまに楽しむのに適しています。作りやすさは中程度で、初心者には少し挑戦的ですが、火加減と混ぜ方に注意すれば、通常30分で完成します。', '[{"name":"無塩バター","unit":"グラム"},{"name":"マシュマロ","unit":"グラム"},{"name":"全粉乳","unit":"グラム"},{"name":"ミックスナッツ","unit":"グラム"},{"name":"クッキー","unit":"グラム"}]'::jsonb, '["クッキーが1元硬貨より大きい場合は、小さく砕いておく。","無塩バターを鍋に入れ、弱火で完全に溶かす。","マシュマロを鍋に加え、ゴムベラで混ぜながら、マシュマロが溶けて無塩バターと均一に混ざるまで加熱する。","20gの全粉乳を鍋に加え、ゴムベラで混ぜる。粉乳とバター・マシュマロの混合物が均一になったらすぐに火を止める。","準備しておいたすべてのミックスナッツとクッキーを熱いうちに鍋に加え、ゴムベラで混ぜる。","温度が手で触れる程度まで下がったら、使い捨てのビニール手袋をはめて、鍋の中でこね合わせるか、両手で持って引き伸ばしながら、クッキー、ミックスナッツ、マシュマロ、バター、粉乳が均一に分散するようにする。","上記の混合物を型に押し込み、角をしっかり詰め、麺棒で平らに伸ばす。足りない辺は手でできるだけ真っ直ぐに整える。","室温で冷まし、完全に冷めたら型から外し、型の模様に沿って切るか、好きな大きさに切る。残りの粉乳をふりかけ、スノーフレーククランチの全面に粉乳が付くようにする。"]'::jsonb, '["デザート","ミルクの風味が濃厚","サクサクで甘い","手早く","焼き菓子","家庭料理","贈り物"]'::jsonb),
  ('howtocook:dessert/魔芋蛋糕/魔芋蛋糕', 'ja', 'こんにゃくケーキ', 'デザート', 'こんにゃくケーキは低カロリー・グルテンフリーのデザートで、白砂糖の代わりにエリスリトールを使用しています。軽くしっとりとした食感で、ココアの香りがします。ダイエット中の方に特に適しています。食物繊維とたんぱく質が豊富で、満腹感があります。作るにはある程度の難易度があり、メレンゲを泡立てたり、切り混ぜる技術が必要ですが、全体の時間は約30分程度で、手軽で健康的な焼き菓子の選択肢です。', '[{"name":"卵","unit":"個"},{"name":"エリスリトール","unit":"g"},{"name":"ココアパウダー","unit":"g"},{"name":"こんにゃく粉","unit":"g"},{"name":"タルタルパウダー","unit":"g"}]'::jsonb, '["ケーキ生地の準備の前に、時間節約のためオーブンを350°F(150°C)に予熱しておきます。","冷蔵庫から新鮮な卵を取り出します。","2つの容器を用意して拭き、それぞれ卵白と卵黄を入れます。","卵白用の容器は少し水滴があっても構いませんが、油気があってはいけません。卵黄用の容器は水滴があってはいけません。","卵を割り、手または卵黄分離器を使って卵白と卵黄を2つの容器に分けます。","分離中に卵黄が割れたり、卵白に卵黄が混ざらないように注意してください。白いカラザは卵白に入っても問題ありません。","（注意：ハンドミキサーを使用しない場合、卵白を入れる容器がそのまま泡立てる容器になります。溢れないように、卵白をすべて入れた後は容器の1/8を超えないようにしてください。）","卵白にタルタルパウダー1gを加えます。","ハンドミキサーを高速にして、卵白を粗い気泡が立つまで泡立て、エリスリトール50gを加えます。","ハンドミキサーを中低速にして、メレンゲが硬く立つまで泡立てます。（泡立て器を上げると短くて直立した角が立つ。容器を逆さまにしてもメレンゲが落ちない状態。）","これでメレンゲの泡立ては完了です。","ハンドミキサーはできるだけ容器の底に近づけて、表面だけが泡立って底が液状のままにならないようにします。","分けておいた卵黄を泡立てた卵白に加え、ハンドミキサーで中低速で均一に混ぜます。","卵白にココアパウダー10gとこんにゃく粉10gを加え、最初はナイフで切るように混ぜます。ハンドミキサーで直接混ぜると粉が飛び散るためです。","切り混ぜの手法は：","まず右手でゴムベラをボウルの中央から生地の底に差し込みます。","時計の8時の方向へボウルの縁までこそげ取り、そのまま生地を持ち上げて空中に上げ、再びボウルの中央に戻して生地を落とします。","左手でボウルを9時の方向から7時の方向へ回転させます（ちょうど60度回転）。これで1サイクル完了です。","速度は約1秒間に2回です。","この方法は「小島先生のケーキ教室」に由来します。簡単に言うと、炒め物をするように混ぜることです。","切り混ぜが終わったら、ハンドミキサーを低速で均一に混ぜます。","型にクッキングシートを敷き、底と側面に密着させます。","ケーキ生地を型に流し入れ、ナイフで表面を平らにならし、軽く揺すって大きな気泡を抜きます。","25分焼きます。","焼き上がったら、耐熱手袋をして取り出します。","（任意）型を高いところから落として中の熱気を逃がします。","型を逆さまにして10分置き、ケーキを冷まします。","冷めていないケーキをすぐに型から外すとケーキが傷みます。","この作業は熱くなることがあるので、耐熱手袋を着用してください。","型から外し、ナイフで切り分けて食べます。"]'::jsonb, '["デザート","低カロリー","グルテンフリー","ココア風味","焼き菓子","手軽","ダイエット"]'::jsonb),
  ('howtocook:dessert/龟苓膏/龟苓膏', 'ja', '亀苓膏', 'デザート', '亀苓膏は広東風の伝統的なデザートで、食感はなめらかでほろ苦く、後味に甘みがあります。夏の暑さをしのぐおやつとしてよく食べられます。体の熱を冷まし湿気を取り、滋陰養顔に効果があり、栄養豊富で健康的なお菓子です。作り方は簡単で、初心者でも気軽に作れます。材料を準備して混ぜ、加熱するだけで、冷蔵庫で約2時間冷やせば完成です。', '[{"name":"亀苓膏の粉","unit":"g"},{"name":"冷水","unit":"ml"},{"name":"熱湯","unit":"ml"},{"name":"グラニュー糖","unit":"g"}]'::jsonb, '["鍋に亀苓膏の粉25gと冷水120mlを入れ、ダマがなくなるまでよく混ぜます。","別の容器にグラニュー糖100gを入れ、熱湯500mlを注ぎ、砂糖が完全に溶けるまで混ぜます。","砂糖水をゆっくりと亀苓膏の粉液に注ぎ、すぐに均一に混ぜ、ダマにならないようにします。","混ぜ合わせた液体を鍋に入れ、中弱火で加熱し、焦げ付かないように絶えず混ぜます。","液体がとろみを帯び、小さな泡が出始めたら火を止めます。","素早く型に流し入れ、自然に冷まして固めます。冷蔵庫で1〜2時間冷やしてから食べると、より食感が良くなります。"]'::jsonb, '["デザート","広東風","暑気払い","なめらか","ほろ苦甘い","手軽"]'::jsonb),
  ('howtocook:drink/B52轰炸机', 'ja', 'B-52', '飲み物', 'このカクテルは層がはっきりしており、最初にウォッカの刺激、続いてコーヒーリキュールとクリームの甘い余韻があります。点火して飲むと独特のアイスとホットの体験ができます。クラシックなクリエイティブカクテルです。コーヒーリキュールとベイリーズは少量のカフェインと乳脂肪を提供しますが、全体の栄養は主にアルコールです。作るには、注ぎ分けと点火の技術の練習が必要で、初心者には少し難しいですが、全体の工程は約5分です。', '[{"name":"コーヒーリキュール（カルーア）","unit":"ml"},{"name":"アイリッシュベイリーズ","unit":"ml"},{"name":"スカイウォッカ（プレーン）","unit":"ml"}]'::jsonb, '["リキュールグラスの一番下にコーヒーリキュール（カルーア）を1/3まで注ぐ。(10ml)","バースプーンに沿ってゆっくりとアイリッシュベイリーズを注ぐ。こちらも1/3まで（10ml）。ゆっくり注ぐのがポイントで、層をはっきりさせるため。（速すぎるとベイリーズとコーヒーが混ざってしまう）","最後に上の層にスカイウォッカ（プレーン）を注ぐ（10ml）","ライターでグラスの縁を温める","最後に点火：薄青色の小さな炎が見えますか？"]'::jsonb, '["ドリンク","甘い","層","点火","カクテル","パーティー"]'::jsonb),
  ('howtocook:drink/Mojito莫吉托', 'ja', 'モヒート', '飲み物', 'このカクテルは爽やかで甘酸っぱく、ミントの清涼感とラムのほろ酔い感が楽しめる、夏の定番ドリンクです。アルコール度数は低めで、ビタミンC豊富なライムと合わせることで、喉の渇きを癒し、リフレッシュできます。作り方はとても簡単で初心者にも優しく、準備から完成まで約10分です。', '[{"name":"ライム","unit":"個"},{"name":"ミントの葉","unit":"枝"},{"name":"シュガーシロップ","unit":"ml"},{"name":"ゴールデンラム","unit":"ml"},{"name":"ブルースカイ オリジナル ウォッカ","unit":"ml","note":"適量"},{"name":"クラッシュアイス","note":"適量"},{"name":"冷やしたソーダ水","note":"適量"}]'::jsonb, '["半分に切ったライムのうち一つを小さく切り、ハイボールグラスに入れ、すりこぎで果汁を搾り出す。","3〜4枝のミントの葉でグラスの縁をこすり、その後ミントをグラスに入れる。","シュガーシロップ20mlを加える。","ゴールデンラム45mlを加える。","残りの半個のライムの果汁を搾ってグラスに入れる。","軽く混ぜ、砂糖/シロップが半溶け状態になるようにする。","砕いた氷をグラスの3/4まで入れる。","冷やしたソーダ水を砕いた氷がちょうど浸るまで加える。","回しながら30秒混ぜる。","砕いた氷でハイボールグラスを満たす。","残りの一枝のミントの葉を手で叩いて香りを引き出し、砕いた氷に挿して飾る。"]'::jsonb, '["飲み物","甘酸っぱい","爽やか","カクテル","簡単","夏"]'::jsonb),
  ('howtocook:drink/冬瓜茶', 'ja', '冬瓜茶', '飲み物', '冬瓜茶はさっぱりとした清涼飲料で、甘くて柔らかな味わい、冬瓜特有の清らかな香りがあり、冷やして飲むとさらに美味しいです。冬瓜自体は低カロリーで水分が豊富で、氷砂糖と一緒に煮るとエネルギーを補給し、喉の渇きを癒します。作り方は複雑ではありませんが、初心者には少し忍耐が必要で、全体で約4～5時間かかります。', '[{"name":"冬瓜","unit":"グラム"},{"name":"氷砂糖","unit":"グラム"}]'::jsonb, '["冬瓜を準備する：冬瓜の皮をむき、種を取り除き、小さな塊（1個4cm以下）に切ります。","氷砂糖を加える：冬瓜に氷砂糖を加え、よく混ぜ合わせ、ラップをかけて冷蔵庫で2時間以上冷やす。","冬瓜を煮る：冬瓜から水分が出てきたら、鍋に移して強火で沸騰させ、その後中弱火で1～2時間じっくり煮る。途中で焦げ付かないように何度もかき混ぜる。","冬瓜茶をこす：ざるを使って煮上がった冬瓜茶液をこし、冬瓜の塊を取り出し、液だけを残す。","冷ます：冬瓜茶液を冷ましてから、清潔な容器に移し、冷蔵庫で冷やす。","楽しむ：煮上がった冬瓜茶液は濃縮液なので、好みに応じて水や他の飲料で薄めて、冷たくても熱くても楽しめる。"]'::jsonb, '["飲み物","さっぱり","暑気払い","甘い","煮込み","冷やし"]'::jsonb),
  ('howtocook:drink/冰粉/冰粉', 'ja', '冰粉', '飲み物', '石凉粉（せきりょうふん）とは河南省信陽の伝統的な軽食で、舌触りが滑らかでゼリーのような食感です。ミントジュースやレモンジュースを加えると涼しくて暑さを和らげます。河南料理に属します。冰粉籽（ひょうふんし）を手でこねて作られ、天然で添加物がなく、豊富な植物性膠質を含んでいます。作り方は非常に簡単で初心者にも優しく、全行程約3時間、うち2.5時間は静置して固める時間で、ほぼ手間がかかりません。', '[{"name":"冰粉籽","unit":"g"},{"name":"冷ました白湯","unit":"g"},{"name":"ハッカ汁","unit":"ml"},{"name":"ハッカ粉末","unit":"g"},{"name":"遇水発光氷塊","note":"任意"}]'::jsonb, '["冷ました白湯（さゆ）をボウルに入れます。","冰粉籽（ひょうふんし）をすべてガーゼで包み、口を結びます。","包んだ冰粉籽を冷ました白湯に入れ、強く揉みながら6分間こねます。","その後、冷ました白湯を2.5時間静置すると固まります。","固まった石凉粉をスプーンで準備した使い捨て透明プラスチックカップに移し、10mlのハッカ汁または10gのハッカ粉末（レモン汁、山査子汁、桑の実汁でも可）を加え、さらに水に触れると光る氷（遇水発光氷塊）を入れ、スプーンでゆっくりと混ぜ合わせます。"]'::jsonb, '["飲み物","河南料理","清涼","暑さ対策","手作り","夏"]'::jsonb),
  ('howtocook:drink/印度奶茶', 'ja', 'インドチャイ', '飲み物', 'インドチャイは、異国情緒あふれる家庭的な飲み物で、紅茶、牛乳、そして各種スパイスを一緒に煮出して作ります。濃厚でなめらかな口当たりで、生姜、カルダモン、シナモンが織りなすスパイシーな温かさが特徴です。牛乳は良質なタンパク質とカルシウムを提供し、スパイスは体を温め、消化を促進する効果があります。作り方はシンプルで初心者にも優しく、準備から完成まで約10分です。', '[{"name":"水","unit":"ml"},{"name":"全脂牛乳","unit":"ml"},{"name":"紅茶（CTC紅茶が最適、またはアッサム紅茶）","unit":"g"},{"name":"生姜","unit":"g"},{"name":"カルダモン（緑色）","unit":"粒"},{"name":"シナモンスティック","unit":"小片"},{"name":"クローブ","unit":"粒"},{"name":"黒胡椒粒","unit":"粒"},{"name":"砂糖","unit":"g"}]'::jsonb, '["生姜を叩き潰す（細かく切らなくても、叩いて開ければ生姜の汁が出ます）","カルダモンを包丁の背で叩き開け、中の種を出す","黒胡椒粒を叩き潰す","小鍋に水120mlを入れる","叩いた生姜、カルダモン、シナモンスティック、クローブ、黒胡椒粒を入れる","強火で沸騰させたら弱火にし、2分煮てスパイスの風味を十分に引き出す","紅茶8gを加え、さらに弱火で2分煮る、茶の色が濃くなるまで","全脂牛乳120mlを注ぐ","中火で加熱し、注意深く見守る。チャイが泡立ち始めて上がってきたらすぐ弱火にする（牛乳は非常に溢れやすい）","弱火で2〜3分煮る。その間、鍋を持ち上げて戻す（3〜4回繰り返す）ことで、茶と牛乳をよく混ぜ合わせる","砂糖を加え、溶けるまで混ぜる","火を止める","茶こしで茶碗に濾し、茶葉とスパイスの残渣を取り除く","熱いうちに飲む"]'::jsonb, '["飲み物","インド風味","スパイシーで濃厚","煮出し","簡単・時短","体が温まる"]'::jsonb),
  ('howtocook:drink/可乐桶', 'ja', 'コーラバケツ', '飲み物', 'コーラバケツは簡単に作れるカジュアルカクテルで、爽やかで甘い味わいが特徴です。コーラの炭酸とレモン汁がウイスキーの強さを程よく中和し、パーティーに最適です。主にエネルギーを供給し、レモンがビタミンCを補います。調理時間はわずか5分で、初心者でも簡単に作れます。', '[{"name":"バーボンウイスキー","unit":"ミリリットル"},{"name":"コカ・コーラ","unit":"ミリリットル"},{"name":"氷","unit":"グラム"},{"name":"レモン","unit":"個"}]'::jsonb, '["レモンを半分に切る（包丁の向きをレモンのヘタとお尻を結ぶ線に垂直にする）。そのうちの半分から1枚のレモンスライスを取り出しておく","再びレモンを半分に切り、得られた4つの角のあるレモンを搾り器で搾り、レモン汁を容器にとっておく","搾った後のレモンを容器にとっておく","グラスを選ぶ。できれば約1リットルの容量の大きなグラスかブリキの酒樽がよい","氷と搾った後のレモンをグラスに入れる（好みでレモンと氷の配置を工夫してもよい）","レモン汁15ミリリットルを注ぐ（酸味が好みなら多めに入れるか全部入れてもよい）","グラスの縁に沿ってゆっくりとコカ・コーラを、グラスの口から3/4の位置まで注ぐ（コーラとウイスキーの比率は約5:1に調整する）","グラスがいっぱいになるまでウイスキーを注ぐ"]'::jsonb, '["飲み物","さっぱり","甘い","時短","パーティー","カクテル"]'::jsonb),
  ('howtocook:drink/奇异果菠菜特调/奇异果菠菜特调', 'ja', 'キウイほうれん草スペシャルドリンク', '飲み物', 'これはさわやかでヘルシーな野菜と果物の特製ドリンクです。味は甘酸っぱくてなめらかで、キウイとりんごの自然な果実の香りがし、ほうれん草の味は薄くて邪魔になりません。ビタミンCと食物繊維が豊富で、消化を促進します。作り方はとても簡単で、初心者でも一回で成功できます。全工程はわずか10分です。', '[{"name":"キウイ","unit":"個"},{"name":"りんご","unit":"個"},{"name":"ほうれん草の葉","unit":"枚"},{"name":"飲用水","unit":"ml"},{"name":"砂糖","unit":"グラム"}]'::jsonb, '["キウイを半分に切り、さらにそれぞれを4つの小さな塊に切る","りんごをさいの目に切る","ほうれん草の葉は茎を取り除き、葉の部分だけにする","ほうれん草を細かく切る","すべてをジューサーミキサーのカップに入れる","水を加える","砂糖を加える","ミキサーを起動し、約4回の15秒（15秒ごとに状態を確認）撹拌する"]'::jsonb, '["飲み物","甘酸っぱい","さわやか","手早い","ヘルシー","ビタミンC"]'::jsonb),
  ('howtocook:drink/奶茶', 'ja', 'ミルクティー', '飲み物', 'これは紅茶と粉ミルクで簡単に作れる家庭的な飲み物です。茶の香りとミルクの風味が調和し、なめらかで温かい味わいです。紅茶のカテキンと牛乳のたんぱく質・カルシウムが組み合わさり、目覚めを良くしつつ日常の栄養も補給できます。作り方はとても簡単で、初心者でも一回で成功します。約30分で自家製ミルクティーが楽しめます。', '[{"name":"袋入り紅茶（リプトンイエローラベルティー推奨）","unit":"包"},{"name":"全脂粉ミルク（またはエバミルク）","unit":"グラム"},{"name":"砂糖","unit":"グラム"},{"name":"熱湯","unit":"ml"}]'::jsonb, '["袋入り紅茶ティーバッグ2包をカップに入れ、180-200mlの熱湯を注ぎます。","20～30分待ちます。","粉ミルク11～12gと砂糖5～7gを量り、それぞれ前の工程の液体に加えます。","よく混ぜてお飲みください。"]'::jsonb, '["飲み物","ミルク風味","手早い","自家製","午後のお茶","胃に優しい"]'::jsonb),
  ('howtocook:drink/杨枝甘露', 'ja', '楊枝甘露', '飲み物', 'これは古典的な香港スイーツをアレンジしたもので、チアシードを使うことで、なめらかながらもプチプチした食感が楽しめます。マンゴーの甘さとグレープフルーツのほのかな酸味が調和し、ココナッツミルクがコクを加えます。食物繊維、ビタミンC、良質な脂質が豊富で、さっぱりとしていて暑い日にもぴったり。作り方はとても簡単で、初心者でも約20分で完成します。', '[{"name":"チアシード","unit":"g"},{"name":"牛乳","unit":"ml"},{"name":"氷","unit":"小さな塊"},{"name":"マンゴー","unit":"個"},{"name":"グレープフルーツ","unit":"個"},{"name":"ココナッツミルク","unit":"ml"},{"name":"ドライマンゴー","note":"千切り、お好みで"},{"name":"ドライオレンジ","note":"千切り、お好みで"}]'::jsonb, '["チアシードを牛乳に10分浸す。","チアシードを浸している間に、半分のマンゴーとグレープフルーツの皮をむいて小さく切り、カップに入れる。","残り半分のマンゴーを小さく切り、ミキサーに入れ、氷とココナッツミルクを加えてピューレ状にする。","カップに注ぎ、お好みでトッピングをのせる。","楽しみながらコードを書こう！！"]'::jsonb, '["飲み物","香港風","甘酸っぱい","さっぱり","簡単","暑気払い"]'::jsonb),
  ('howtocook:drink/柠檬水/柠檬水', 'ja', 'レモン水', '飲み物', 'このドリンクは新鮮なレモンを主役に、フルーツシロップを合わせて甘酸っぱいバランスが絶妙。冷やすとさらにひんやり爽やかで暑さも和らぎます。レモンはビタミンCが豊富で、常飲すると栄養補給やリフレッシュ、美白効果も期待できます。作り方はとても簡単で、レモンを叩き、材料を加えてシェイクするだけ。初心者でも3〜5分で完成します。', '[{"name":"レモン","unit":"グラム"},{"name":"フルーツシロップ","unit":"グラム"},{"name":"氷","note":"数個（お好みで）"}]'::jsonb, '["レモン40〜45グラムを量り、シェイカーに入れる","シェイカーの蓋を閉めて約10回叩く","フルーツシロップ40〜45グラムを加える","水を加える","よくシェイクする","最後に好みで氷を加える"]'::jsonb, '["飲み物","甘酸っぱい","時短","ひんやり爽やか","冷たい飲み物","ビタミンC"]'::jsonb),
  ('howtocook:drink/泰国手标红茶/泰国手标红茶', 'ja', 'タイの手標紅茶', '飲み物', 'これはタイの屋台で人気のクラシックなミルクティーです。茶葉の香りが濃厚で、口当たりはまろやかで滑らか。コンデンスミルクと牛乳が甘くてミルキーな味わいをもたらします。茶と乳の組み合わせにより少量のタンパク質とカルシウムが摂取できますが、糖分が多めなので、暑気払いや喉の渇きを癒すドリンクとして適しています。作り方は簡単ですが、茶液を何度も濾して長時間冷蔵する必要があり、全体で約4時間20分かかります。初心者でも少しの忍耐があれば完成できます。', '[{"name":"水","unit":"cc"},{"name":"茶粉","unit":"g"},{"name":"コンデンスミルク","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"牛乳","unit":"ml"},{"name":"氷","unit":"個"}]'::jsonb, '["600ccの水を強火で沸騰させる","フィルターバッグに20gの茶粉を入れ、熱湯をフィルターバッグに注ぎ、20回濾す","キッチンスケールでコンデンスミルク24g、砂糖24g、牛乳18mlを計り、1000ml以上のポットに入れる","濾した茶液をポットに注ぎ入れ、砂糖が溶けるまで混ぜる","ポットを冷蔵庫に4時間以上入れる","飲む前に氷を6～8個加える"]'::jsonb, '["飲み物","タイ風ミルクティー","冷たい飲み物","甘い","屋台風","暑気払い","ミルクティー"]'::jsonb),
  ('howtocook:drink/海边落日/海边落日', 'ja', '海辺の夕日', '飲み物', 'このカクテルは色の層が美しく、底のグレナデンシロップは夕焼け、中間のオレンジジュースは透き通り、上のブルーキュラソーは海水を思わせ、全体で海辺の夕日の景色を表現しています。飲むと甘酸っぱくさっぱりとして、ラムの香りが広がります。オレンジジュースとレモンジュースには少量のビタミンCが含まれ、アルコールはリラックス効果をもたらします。調理手順は難しくありませんが、マドラーを使って液体を注ぎ分ける際には少し忍耐が必要です。初心者でも成功でき、準備から完成まで約15分でできます。', '[{"name":"グレナデンシロップ","unit":"ml"},{"name":"NFCオレンジジュース","unit":"ml"},{"name":"ソーダ水","unit":"ml"},{"name":"ホワイトラム","unit":"ml"},{"name":"ブルーキュラソー","unit":"ml"},{"name":"レモンジュース","unit":"ml"},{"name":"氷","note":"適量"},{"name":"レモン","unit":"枚"}]'::jsonb, '["レモンを洗い、1枚切り取る","グラスを選び、容量350~400mlの透明なグラスを推奨","大きめの氷を入れ、マドラーでグラスを冷やす","グレナデンシロップを加える","オレンジジュースをマドラーに沿ってグラスの半分まで注ぐ","軽く半回転かき混ぜる","ソーダ水を注ぐ","シェーカーを取り出し、ホワイトラム + ブルーキュラソー + レモンジュース + 氷を加える。そしてシェイク、シェイク","ゆっくりとグラスに注ぐ","レモンとストローをさす"]'::jsonb, '["飲み物","甘酸っぱい","さっぱり","カクテル","層状","夏"]'::jsonb),
  ('howtocook:drink/牛油果拉西', 'ja', 'アボカドラッシー', '飲み物', 'これは、インドの伝統的なヨーグルトドリンク「ラッシー」をアレンジした革新的なドリンクです。口当たりは滑らかで、甘さがくどくなく、朝食や午後のリフレッシュに最適です。アボカドには一価不飽和脂肪酸と食物繊維が豊富で、ヨーグルトの良質なタンパク質とプロバイオティクスと組み合わさり、一杯で持続的な満腹感が得られます。作り方はとても簡単で、初心者でも失敗なく、準備から完成まで約5分でできます。', '[{"name":"プレーンヨーグルト","unit":"ml"},{"name":"アボカド","unit":"個"},{"name":"はちみつ","unit":"大さじ"},{"name":"冷たい牛乳","unit":"ml"},{"name":"カルダモンパウダー","unit":"少々"},{"name":"ミントの葉","note":"飾り用 適量"},{"name":"刻んだナッツ","unit":"g"}]'::jsonb, '["アボカドを半分に切り、種を取り、皮をむき、果肉を小さく切っておきます。","ミキサーにプレーンヨーグルト120ml、切ったアボカド、はちみつ大さじ1、冷えた牛乳60mlを加えます。","（お好みで）カルダモンパウダー少々を加えると風味が増します。","ミキサーを回し、約1分間、なめらかで濃厚になるまで混ぜます。","出来上がったドリンクをグラスに注ぎます。","（お好みで）表面にミントの葉を数枚飾るか、刻んだナッツ5gを振りかけます。"]'::jsonb, '["飲み物","甘さ控えめ","なめらか","時短","朝食","インド風味"]'::jsonb),
  ('howtocook:drink/百香果橙子特调/百香果橙子特调', 'ja', 'パッションフルーツとオレンジのスペシャルドリンク', '飲み物', '甘酸っぱくてさわやかな夏のドリンクです。パッションフルーツのトロピカルな香りとオレンジの甘みが絶妙にマッチ。ジャスミン緑茶または炭酸水と合わせることで、味わい深く、ひんやりとしていてさっぱりとしています。ビタミンCが豊富で、免疫力向上や肌の潤いに役立ちます。漬け込み、お茶を淹れる、搾るなどの工程がありますが、やや多めですが難易度は普通で初心者でも挑戦できます。パッションフルーツは前日から漬け込む必要があり、合計約24時間かかりますが、実際の作業時間は約30分です。', '[{"name":"パッションフルーツ","unit":"個"},{"name":"オレンジ","unit":"個"},{"name":"ジャスミン緑茶の茶葉","unit":"g"},{"name":"グラニュー糖","unit":"g"},{"name":"はちみつ","unit":"g"},{"name":"熱湯","unit":"ml"},{"name":"氷","unit":"g"},{"name":"炭酸水","unit":"","note":"適量、ジャスミン緑茶の茶葉と二択"},{"name":"ミントの葉など","unit":"","note":"お好みで、飾り用"}]'::jsonb, '["パッションフルーツの漬け込み（量が少なくて作りにくいので、ここでは2回分の分量）","パッションフルーツ3個の果肉を取り出す（中の果汁も逃さずに）、容器に入れる","グラニュー糖30gを量って入れる","はちみつ10gを量って入れる（なければグラニュー糖5gで代用可）","よく混ぜる","容器をラップで覆い、冷蔵庫で12〜24時間漬け込む","ジャスミン緑茶の準備（推奨比率：茶葉 : 水 : 氷 = 1〜2 : 50 : 30）","茶葉3〜6gを容器に量り入れ、熱湯150mlを注いで6分蒸らす","蒸らした緑茶に氷90gを入れて冷やし、かき混ぜて早く冷ます","氷がなくなったら、茶葉を濾してジャスミン緑茶約240mlを得る","オレンジの処理（お茶を蒸らしている間に行うと良い）","オレンジを半分に切る（包丁の向きはオレンジのヘタとお尻を結ぶ線に垂直に）、その半分から1枚の輪切りを取っておく","さらにオレンジを半分に切り、できた4つのくし形をジューサーで搾って果汁を容器に取っておく","最終調整","容量350〜400mlの透明なグラスを選ぶ","氷70gをグラスの底に置き、すべてのオレンジ果汁を注ぐ","先ほど用意したオレンジの輪切り1枚をグラスの内側に沿わせる","1回分の漬け込んだパッションフルーツを氷の上にかける","ジャスミン緑茶をゆっくりとグラスの縁まで注ぎ、層を作る","液面に飾り用の緑の葉を置く（お好みで）"]'::jsonb, '["ドリンク","甘酸っぱい","さわやか","淹れる","冷たい","夏"]'::jsonb),
  ('howtocook:drink/砂糖椰子冰沙/砂糖椰子冰沙', 'ja', '砂糖ココナッツスムージー', '飲み物', '砂糖ココナッツスムージーは、トロピカルな風味が楽しめる簡単な冷たい飲み物です。ココナッツの甘い香りと粗めの黄糖の焦がしたような香りが絶妙に絡み合い、口当たりは滑らかでひんやり。ココナッツウォーターには天然の電解質やミネラルが豊富で、水分補給にも最適。コーヒーシュガーが炭水化物エネルギーをプラスします。作り方はとても簡単で、ココナッツジュースを凍らせて叩いてスムージー状にするだけなので、初心者でも安心。冷凍から仕上げまでに10時間以上の準備が必要ですが、実際の作業は数分で済むので、のんびりした午後のおやつにぴったりです。', '[{"name":"ボトル入りココナッツジュース","unit":"ml"},{"name":"コーヒーシュガー","unit":"g"},{"name":"ナッツクラッシュ（お好みで）","note":"適量"}]'::jsonb, '["500mlのボトル入りココナッツジュースを200ml捨て、すぐにキャップをしっかり閉める。","このココナッツジュースを冷凍庫に入れ、10時間以上冷凍する。","このココナッツジュースを取り出し、中が完全に凍っていることを確認したら、壁の角や椅子の背もたれ、机の角などの硬い表面に強く打ち付ける。（表面が傷つかないことを必ず確認すること）","凍ったココナッツジュースがスムージー状になるまで打ち付けたら、キャップを開けてスムージーを器に出す。","スムージーの表面にコーヒーシュガーまたはナッツクラッシュを均等に振りかける。","完成"]'::jsonb, '["飲み物","簡単","冷たい飲み物","さっぱり","午後のお茶","トロピカル風味"]'::jsonb),
  ('howtocook:drink/耙耙柑茶/耙耙柑茶', 'ja', 'パパ柑茶', '飲み物', 'パパ柑茶は、柑橘の爽やかな甘さとジャスミンの香りが楽しめるフルーツティーです。口当たりはさっぱり、後味はほんのり甘く、創作ドリンクとして様々なシーンに合います。パパ柑にはビタミンCや食物繊維がたっぷり。緑茶と合わせると、すっきりとした目覚めにぴったりです。作り方は超簡単！お茶を淹れて混ぜるだけで、約15分で完成します。', '[{"name":"パパ柑"},{"name":"ジャスミン緑茶"},{"name":"氷","unit":"g"},{"name":"蔗糖シロップ","unit":"g"},{"name":"道具","note":"適量"}]'::jsonb, '["ジャスミン緑茶の準備（推奨比率：茶葉：水：氷＝1〜2：50：30）","茶葉2〜4gを計量して容器に入れ、100mlの熱湯を注ぎ、6分間蒸らす","淹れたての緑茶に氷60gを入れて冷ます。混ぜると早く冷める。","氷が溶けたら茶葉を濾し、ジャスミン緑茶約160mlを得る。","本格的な調合","容量約300mlの透明なグラスを選ぶ。","パパ柑の房を取り出し、外皮を剥いて果肉を得る。","果肉130gとジャスミン緑茶130mlをミキサーに入れる。","蔗糖シロップ10gを加える（お好みで、甘いのが好きなら追加）","蓋をしてミキサーを回し、20秒撹拌したらグラスに注ぐ。","果肉を少々ちぎって液面に散らす。"]'::jsonb, '["ドリンク","さっぱり","フルーツティー","手軽","甘酸っぱい","初心者向け"]'::jsonb),
  ('howtocook:drink/菠萝咖啡特调/菠萝咖啡特调', 'ja', 'パイナップルコーヒー特製', '飲み物', 'この特製ドリンクは、コーヒーの豊かな香りとパイナップルの甘酸っぱさを融合させ、爽やかな炭酸とクリーミーな泡が絶妙なハーモニーを生み出します。パイナップルはビタミンCと食物繊維が豊富で、コーヒーとの組み合わせで目覚めを促します。作り方は中程度で、クリームを泡立てて混ぜるだけで、約10分で完成します。', '[{"name":"コーヒー液","unit":"ml"},{"name":"パイナップルジュース","unit":"ml"},{"name":"氷","unit":"g"},{"name":"ソーダ水","unit":"ml"},{"name":"クリーム","unit":"ml"},{"name":"牛乳","unit":"ml"},{"name":"砂糖","unit":"g"},{"name":"海塩","unit":"g"},{"name":"ラム酒","unit":"ml"}]'::jsonb, '["グラスに氷、コーヒー液、パイナップルジュース、ソーダ水の順に加える。","クリームに砂糖を加えて角が立つまで泡立て、ラム酒と牛乳を加えて均一にし、流動性を持たせる。","1の混合液の上にクリームを注ぐ。","クリームの表面に海塩を振る。"]'::jsonb, '["飲み物","甘酸っぱい","爽やか","特製","手軽","午後のお茶"]'::jsonb),
  ('howtocook:drink/酒酿醪糟/酒酿醪糟', 'ja', '酒酿（中華風甘酒）', '飲み物', 'これは伝統的な中華風発酵デザートです。ほのかな甘さと酒の香りがあり、胃腸を整え、消化を促進します。作り方は簡単で、発酵に時間はかかるものの、実際の作業は約1時間と手軽なので、発酵初心者に最適です。全体の所要時間は約2日間です。', '[{"name":"もち米","unit":"g"},{"name":"安琪甜酒麹","unit":"g"},{"name":"水","unit":"g"},{"name":"水","unit":"g"},{"name":"温水","unit":"ml"},{"name":"桂花","note":"適量"},{"name":"水","unit":"ml"}]'::jsonb, '["800gのもち米を洗い、炊飯器に入れ、720gの水を加えて炊飯モードを選択する","炊き上がったらご飯を出して広げ、清潔な道具を使って30℃まで冷ます（温度計で測るのが良い。温かくて手が熱くない程度）","8gの安琪甜酒麹を20mlの温水（約30℃）で溶かし、もち米ご飯に均等に振りかけ、同時によく混ぜる","もち米ご飯に600gの水を加えて酒麹とよく混ぜる。2〜3分置くと、もち米が水分を吸収する。この加水により、初回発酵で酒酿の汁がたっぷりになる","めん棒でもち米ご飯の中央に小さなくぼみを作る（酒が出やすくなる）","混ぜたご飯を清潔な容器に入れ、表面を軽く平らに押し、蓋またはラップをして密閉する","28〜32℃の環境で24〜48時間発酵させる。発酵中は激しく揺らしたり動かしたりしない","発酵成功の目安：中央のくぼみに透明な酒液が出てくる。全体にほのかな酒の香りがあり、異臭や酸味がないこと","発酵が終わったらすぐに冷蔵保存可能（途中で桂花を加えてもよい）。食べるたびに清潔な道具で取り出し、冷蔵で7〜10日保存できる","さらに二次発酵させることもできる。500mlの水を加えて酒酿の量を増やす（水は800g以内）","酒酿は発酵を続ける。発酵を止めたい場合は、10分蒸して殺菌するか、冷蔵庫に入れる","800gのもち米を洗い、清水に6〜8時間浸す（冬は8〜10時間推奨）。米粒がふっくらするまで","もち米の水を切り、蒸し布に入れて40〜60分蒸す。20分ごとに蓋を開けて混ぜ、均一に蒸す","蒸し上がったらご飯を広げて冷まし、酒麹を加える。以降の手順は同じ","もちろん、酒酿の経験者は好みで異なる米を組み合わせてもよい。もち米の20%を粟、オーツ麦、黄米、血糯米などに置き換え可能"]'::jsonb, '["飲み物","さわやかな甘さとほろ酔い","発酵","中華伝統","胃腸を整える","初心者向け"]'::jsonb),
  ('howtocook:drink/酸梅汤（半成品加工）', 'ja', '酸梅湯（半製品加工）', '飲み物', '酸梅湯（半製品加工）は、甘酸っぱくて爽やかな夏の清涼飲料で、伝統的な北京風味です。酸梅湯には、渇きを癒し、消化を助ける効能があります。作り方は非常に簡単で、順番に混ぜるだけなので初心者でも難しくなく、全体で約5分で完成します。', '[{"name":"水","unit":"グラム"},{"name":"酸梅晶固体飲料","unit":"グラム"},{"name":"角砂糖（お好みで）","unit":"グラム"}]'::jsonb, '["水1177グラムを用意する。","酸梅晶固体飲料60グラムを入れ、スプーンで時計回りに50回かき混ぜる。","残りの酸梅晶固体飲料60グラムを入れ、再びスプーンで時計回りに50回かき混ぜる。","角砂糖9グラムを入れ、スプーンで時計回りに100回かき混ぜる。","北京二鍋頭酒48グラムを入れ、スプーンで時計回りに30回かき混ぜる。"]'::jsonb, '["飲料","甘酸っぱい","北京風","簡単","暑気払い","かき混ぜる"]'::jsonb),
  ('howtocook:drink/酸梅汤/酸梅汤', 'ja', '酸梅湯', '飲み物', '酸梅湯は甘酸っぱくて美味しく、暑気を払う伝統的な飲み物です。冷やして飲むと特に心に染み渡ります。レシピの烏梅、山査子、甘草などの材料は、喉の渇きを癒し、食欲を促進します。作り方は簡単で初心者にも優しく、浸漬、煮沸、冷却するだけです。全行程には浸漬、2回の煮沸、冷却が含まれ、約6時間以上かかりますので、事前に準備することをお勧めします。', '[{"name":"水","unit":"リットル"},{"name":"黒ナツメ","unit":"グラム"},{"name":"烏梅","unit":"グラム"},{"name":"山査子（生）","unit":"グラム"},{"name":"黄氷砂糖","unit":"グラム"},{"name":"甘草","unit":"グラム"},{"name":"陳皮","unit":"グラム"},{"name":"紅豆蔻","unit":"グラム"},{"name":"干し桂花","unit":"グラム"}]'::jsonb, '["材料を洗う（乾燥桂花と氷砂糖は除く）。1.5リットルの水に常温で2時間以上浸す（乾燥桂花と氷砂糖は除く）。","中強火で沸騰させ、蓋をして弱火で40分煮る。これが1回目の煎じ。","氷砂糖をボウルに入れ、漉した1回目の煎じ液を熱いうちに注ぎ入れ、氷砂糖が溶けるまで混ぜる。","薬材を再び鍋に戻し、600ミリリットルの水を加えて強火で沸騰させ、蓋をして中火でさらに20分煮る。これが2回目の煎じ。","最後に、2回目の煎じ液と氷砂糖水を熱いうちに混ぜ合わせて完成品とする。完成品が60〜70℃になったら乾燥桂花を加え（80℃を超えないように）、蓋をして冷まし、冷蔵庫で3時間以上冷やす。","飲む際には乾燥桂花を漉し出す。お茶のようにゆっくりと味わう。冷たくて歯にしみるほどで、酸味が冴え、甘さは程よく、風味豊かで余韻が長い。"]'::jsonb, '["飲み物","甘酸っぱい","煮る","暑気払い","冷やす","伝統的","家庭料理"]'::jsonb),
  ('howtocook:drink/金汤力/金汤力', 'ja', 'ジントニック', '飲み物', 'これは定番のジンベースのカクテルで、さっぱりとした味わいにほろ苦さ、レモンの爽やかな酸味とトニックウォーターの細かい泡が口当たり軽やかです。水分とアルコールのカロリーが主ですが、新鮮なレモン汁がビタミンCを補給し、リフレッシュ効果もあります。作り方はとても簡単で、初心者でもすぐにマスターでき、所要時間はたったの5分です。', '[{"name":"ジン","unit":"ml"},{"name":"トニックウォーター（炭酸水）","unit":"缶"},{"name":"レモン","unit":"個"},{"name":"氷","unit":"g"},{"name":"新鮮な緑の葉","note":"適量（飾り用）"}]'::jsonb, '["レモンを半分に切る（包丁の向きはレモンの上下のラインに垂直に）。そしてそのうちの半分から1枚のレモンスライスを取り、取っておく。","もう一度レモンを半分に切り、できた4つの角のレモンをレモン絞り器で絞り、レモン汁を容器に入れて取っておく。","グラスを1つ選ぶ。容量350～400mlの透明なグラスがおすすめ。","100gの氷をグラスの底に置く。","30～40mlのジンを注ぐ。","15mlのレモン汁を注ぐ（酸味が好みなら多めか全部入れてもよい）。","スプーンでよく混ぜる。","先に用意したレモンスライスを1枚置く。","ゆっくりとグラスの縁に沿ってトニックウォーターを満杯まで注ぐ（氷の上には注がない。泡が消えるのを防ぐため）。","スプーンで軽く上下に引き上げながら液体を混ぜる（回しながら混ぜない。泡が消えるのを防ぐため）。","液面に飾り用の緑の葉を置く（お好みで）。"]'::jsonb, '["飲み物","さっぱり","ほろ苦い","時短","カクテル"]'::jsonb),
  ('howtocook:drink/金菲士/金菲士', 'ja', 'ジンフィズ', '飲み物', 'クラシックなジンカクテルで、甘酸っぱく、泡が爽快です。レモンが豊富なビタミンCを提供し、蔗糖シロップが酸味をバランスします。作り方はとても簡単で、初心者でも5分で完成します。自宅で気軽に楽しめます。お酒は健康に害があるので、過剰摂取に注意してください。', '[{"name":"ジン","unit":"ml"},{"name":"ソーダ水","unit":"缶"},{"name":"レモン","unit":"個"},{"name":"蔗糖シロップ","unit":"g"},{"name":"氷","unit":"g"},{"name":"新鮮な緑の葉","note":"飾り用、適量"},{"name":"シェイカー","note":"任意"}]'::jsonb, '["レモンを半分に切ります（包丁の向きはレモンの頭と尾を結ぶ線に垂直に）。そのうちの半分からレモンスライスを1枚切り取り、取っておきます。","もう一度レモンを半分に切ります。得られた4つの角のレモンをレモン絞り器で絞り、レモン汁を容器に入れて取っておきます。","グラスを選びます。容量350〜400mlの透明なグラスをおすすめします。","100gの氷をグラスの底に置きます。","30〜40mlのジンを注ぎます。","20mlのレモン汁を注ぎます（酸味が好きな場合は多めに入れても、全部入れても大丈夫です）。","30〜40gの蔗糖シロップを注ぎます。","スプーンでよく混ぜます。","先ほど用意したレモンスライスを置きます。","ゆっくりとグラスの縁に沿ってソーダ水を満杯になるまで注ぎます（氷の上に注がないでください。泡が消えるのを防ぐためです）。","スプーンで優しく上下に引き上げて液体を均一に混ぜます（回して混ぜないでください。泡が消えるのを防ぐためです）。","液面に飾り用の緑の葉を置きます（任意）。","氷、ジン、レモン汁、蔗糖シロップをシェイカーに入れ、均一にシェイクします。","シェイクしたものをグラスに注ぎます（氷が細かくなりすぎた場合は、濾して氷を除き、新しい氷を追加しても結構です）。"]'::jsonb, '["飲み物","甘酸っぱい","さっぱり","泡","手早い","クラシック"]'::jsonb),
  ('howtocook:drink/长岛冰茶', 'ja', 'ロングアイランドアイスティー', '飲み物', 'ロングアイランドアイスティーは、味わいがアイスティーに似ており、口当たりは柔らかいですがアルコール度数がかなり高いクラシックカクテルです。栄養価は高くありませんが、たまに飲むとリラックスできますが、飲み過ぎには注意してください。作り方はとても簡単で、4種類のベーススピリッツ、リキュール、ジュースを割合通りに混ぜるだけで、初心者でも簡単に作れます。準備から完成まで約5分です。', '[{"name":"ジン","unit":"ml"},{"name":"テキーラ","unit":"ml"},{"name":"ウォッカ","unit":"ml"},{"name":"ホワイトラム","unit":"ml"},{"name":"オレンジリキュール","unit":"ml"},{"name":"レモン","unit":"個"},{"name":"レモン汁","unit":"ml"},{"name":"メープルシロップ","unit":"ml"},{"name":"コーラ","unit":"ml"},{"name":"氷","unit":"g"}]'::jsonb, '["レモンを半分に切り、30mlのレモン汁を搾ってグラスに入れる。","以下の順番でグラスに加える：","ジン 15ml、","テキーラ 15ml、","ウォッカ 15ml、","ホワイトラム 15ml、","オレンジリキュール 15ml；","メープルシロップ 20mlをゆっくりとグラスに注ぎながらかき混ぜる。","コーラ 75mlをグラスに加える。","グラスが満杯になるまで氷を加える。","20秒間優しくかき混ぜる。","お楽しみください。"]'::jsonb, '["飲み物","カクテル","ほろ酔い","時短","甘酸っぱい","クラシック"]'::jsonb),
  ('howtocook:meat_dish/农家一碗香/农家一碗香', 'ja', '農家の一碗香', '肉料理', 'これは塩味と香りがご飯に合う湖南の家庭料理です。豚バラ肉の脂の旨味、卵のなめらかさ、青椒の清らかな香りが調和し、豊かな食感が楽しめます。豚肉と卵で良質なタンパク質を摂取でき、青椒でビタミンCも補えて栄養バランスも良好。中程度の難易度で、炒め加減と調味の順序に注意が必要ですが、初心者でも少し練習すれば上手に作れます。準備に約7分、調理に10分、合計約17分で完成します。', '[{"name":"豚肉","unit":"g"},{"name":"卵","note":"適量"},{"name":"青椒","unit":"個"},{"name":"小粒唐辛子","unit":"個"},{"name":"ニンニク","unit":"片"},{"name":"生姜","unit":"片"},{"name":"豆瓣醤","unit":"g"},{"name":"醤油","unit":"ml"},{"name":"砂糖","unit":"g"},{"name":"油","note":"適量"}]'::jsonb, '["下準備：豚肉を薄切りにし、できれば脂身と赤身を分けて置きます。同時に青椒と唐辛子を小口切りにし、ニンニクは包丁の背で潰してみじん切り、生姜は千切りにします。卵を小さなボウルに割り入れ、箸で溶きほぐします。","下準備ができたら、いよいよ調理開始です。まず鍋に油を入れ、弱火で熱します。油が温まったら溶き卵を加え、かき混ぜながら半熟状に炒め、小さなボウルに戻しておきます。","鍋に油を少し足し、弱火で熱し、脂身の豚肉を加えて脂を引き出します。","脂身がきつね色になったら中火にし、赤身の豚肉も加えて炒め合わせます。","赤身の色が変わったら、千切り生姜、みじん切りニンニク、豆瓣醤を加えてよく炒め、豚肉に色をつけます。","青椒と赤唐辛子（小米辣）、先に炒めた卵を加え、醤油と砂糖を加えて、青椒がまだシャキッとしている程度に炒め合わせます。","火を止めて盛り付け、完成です！"]'::jsonb, '["肉料理","塩味香ばしい","ご飯が進む","家庭料理","炒め物","湖南"]'::jsonb),
  ('howtocook:meat_dish/冬瓜酿肉/冬瓜酿肉', 'ja', '冬瓜の肉詰め', '肉料理', '冬瓜の肉詰めは、肉と野菜のバランスが良い家庭的な蒸し料理です。食感は柔らかくて滑らかで、肉のうま味と冬瓜の甘みが調和し、さっぱりとしていて脂っこくありません。豚ひき肉は良質なたんぱく質と必須アミノ酸を提供し、冬瓜は熱を冷まし利尿作用があり水分補給にも役立ちます。作り方は簡単で、初心者でも気軽に挑戦でき、肉を巻くコツを少し練習するだけです。準備から出来上がりまで約30分かかります。', '[{"name":"冬瓜","unit":"グラム"},{"name":"豚ひき肉","unit":"グラム"},{"name":"卵","unit":"個"},{"name":"ネギ","unit":"グラム"},{"name":"ネギとショウガのみじん切り","unit":"グラム"},{"name":"コショウ","unit":"グラム"},{"name":"醤油","unit":"ミリリットル"},{"name":"片栗粉","unit":"グラム"},{"name":"塩","unit":"グラム"},{"name":"水溶き片栗粉","unit":"グラム"}]'::jsonb, '["冬瓜の皮をむき、長さ25cm、厚さ3cmのスライスに切る","切った冬瓜をボウルに入れ、塩15gを加えて全体にまぶし、10分置く","冬瓜を置いている間に、別のボウルにひき肉、ネギとショウガのみじん切り、塩5g、片栗粉5g、コショウ、醤油、コショウを入れる","箸でひき肉を時計回りに混ぜ、具材の色が均一になるまで（約2分）混ぜる","漬けた冬瓜（柔らかくなる）を清水で3回洗う","冬瓜のスライス1枚を取り出して巻き、中に肉を詰める","皿に並べ、皿の縁に沿って置く","中央の円形の部分に卵1個を割り入れる","普通の鉄鍋で水を沸かし、皿を入れ、蓋をして15分蒸す","蓋を開け、蒸し上がった冬瓜の肉詰めを取り出す","冬瓜の肉詰めの皿にたまった汁を鍋に移し、水溶き片栗粉を加え、さらに水50mlを加えて沸騰させる","冬瓜の肉詰めの上にかける"]'::jsonb, '["肉料理","蒸し料理","家庭料理","ご飯が進む","香ばしい","肉と野菜のバランス"]'::jsonb),
  ('howtocook:meat_dish/冷吃兔', 'ja', '冷製ウサギ', '肉料理', 'これは四川自貢の塩幫料理の定番で、麻辣で乾香、うさぎ肉は締まって噛みごたえがあり、口に入れるとまず辛さが来てから旨味が広がり、余韻が長く続きます。うさぎ肉は高タンパク低脂肪で、レシチンや各種アミノ酸が豊富で栄養価が高く消化も良いです。調理工程では多种の香辛料を処理し火力を厳密にコントロールする必要があり、初心者にはやや難しいです。下ごしらえから炒め終わりまで約1.5時間かかりますが、一晩置くと風味が増すので、前もって準備する価値があります。', '[{"name":"うさぎ肉","note":"適量"},{"name":"塩","unit":"グラム"},{"name":"味の素","unit":"グラム"},{"name":"オイスターソース","unit":"グラム"},{"name":"料理酒","unit":"グラム"},{"name":"ニンニク","unit":"頭"},{"name":"ショウガ","note":"ニンニクと同量"},{"name":"万能ネギ/長ネギ/玉ネギ","unit":"グラム"},{"name":"乾燥唐辛子","note":"量はうさぎ肉と同体積"},{"name":"青花椒","note":"うさぎ肉3斤に対して1椀分"},{"name":"八角","unit":"粒"},{"name":"桂皮","note":"親指大の長さ1片"},{"name":"ローリエ","unit":"枚"},{"name":"山奈","note":"大豆大の1片"},{"name":"白豆蔻","unit":"粒"},{"name":"フェンネル","unit":"グラム"},{"name":"白いりごま","unit":"グラム"}]'::jsonb, '["ニンニク、ショウガの皮をむきみじん切りにして準備する。八角、桂皮、ローリエ、山奈、白豆蔻、フェンネルは洗って準備する。","乾燥唐辛子を2cmの小口切りにし、洗って準備する。","万能ネギ/長ネギ/玉ネギを洗い、玉ネギは小さく切る。","うさぎ肉を2cmの小塊に切り、塩、料理酒、味の素で味付けし、15分漬け込む。","鍋に油を入れ、油温が4割熱くなったら万能ネギ/長ネギ/玉ネギを入れ、中弱火で香りが出るまで炒め、万能ネギ/長ネギ/玉ネギが少し焦げたら取り出す。","強火にして油温を上げ、油温が8割熱くなったらうさぎ肉を入れ、中弱火に変えてうさぎ肉が微かにきつね色になるまで揚げ、取り出す。","油温を上げ、乾燥唐辛子、青花椒、八角、桂皮、ローリエ、山奈、白豆蔻、フェンネルを入れ、弱火で唐辛子がカリッとするまで揚げる。","再びうさぎ肉を入れ、オイスターソースを加えて数分炒める。","火を止め、ニンニク、ショウガ、白いりごまを加えて均一に混ぜ炒める。","一晩置くとさらによく味が染み込む。"]'::jsonb, '["肉料理","麻辣","乾香","自貢塩幫","酒のつまみ","揚げ炒め"]'::jsonb),
  ('howtocook:meat_dish/凉拌鸡丝/凉拌鸡丝', 'ja', '鶏の細切りサラダ', '肉料理', '油少なめで低カロリーの家庭的な冷菜です。鶏肉は柔らかく味が染み込み、ごま油と香酢がほのかな痺れと酸味のさっぱりした味わいを醸し出し、夏の脂っこさを解消するのにぴったり。鶏むね肉は良質なタンパク質が豊富で脂質が低い。作り方は簡単で初心者でも楽々、準備から完成まで約30分です。', '[{"name":"鶏むね肉（常温・冷凍どちらでも）","unit":"g"},{"name":"花椒油（ホアジャオ油）","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"香酢","unit":"ml"},{"name":"砂糖","unit":"g"},{"name":"塩","unit":"g"},{"name":"料理酒","unit":"ml"},{"name":"生姜","unit":"g"},{"name":"冷ました白湯","note":"適量"}]'::jsonb, '["生姜を薄切りにしておく","鍋に水4リットルを入れる","鶏むね肉と生姜の薄切りを加える","料理酒20mlを加える","強火で蓋をせずに沸騰させる","沸騰したら中火にし、アクを取り除く","さらに5〜7分煮る。冷凍でない肉は5分、冷凍肉は7分","鶏むね肉の大きさによって火の通りが異なるので、箸を刺してすっと通れば火が通っている。通らなければさらに煮る","冷ました白湯で鶏むね肉を冷やし、室温まで下げる","鶏むね肉の繊維に沿って細かく裂く","ボウルを用意する","ボウルに花椒油、醤油、香酢、砂糖、塩を加える","調味料を混ぜて砂糖と塩をできるだけ溶かす","調味液を鶏肉に注ぎ、よく和える"]'::jsonb, '["肉料理","和え物","軽い痺れと酸味","さっぱり","低カロリー","時短","夏"]'::jsonb),
  ('howtocook:meat_dish/卤菜/卤菜', 'ja', '煮込み料理（ルー菜）', '肉料理', 'これは中国の定番煮込み料理です。肉は柔らかく味がしみ込み、香り豊か。煮汁は繰り返し使えて、古くなるほど風味が増します。冷菜やおつまみ、主食と合わせるのに最適です。良質なタンパク質とビタミンが豊富で栄養バランスも良いです。作るのに少し根気がいりますが、手順はわかりやすく、初心者にも優しいレシピです。血抜きのための浸水、飴色作り、圧力調理で約1時間。一晩漬け込んで味をしっかり染み込ませ、翌日スライスして召し上がれ。', '[{"name":"牛スジ肉（または他の肉）","unit":"グラム","note":""},{"name":"スパイスパック","unit":"パック","note":""},{"name":"甜面醤","unit":"ml","note":""},{"name":"豆板醤","unit":"ml","note":""},{"name":"オイスターソース","unit":"ml","note":""},{"name":"発酵豆腐（南乳）","unit":"ml","note":""},{"name":"玉ねぎ","unit":"個","note":""},{"name":"生姜","unit":"グラム","note":""},{"name":"ニンニク","unit":"グラム","note":""},{"name":"乾燥唐辛子","unit":"グラム","note":""},{"name":"醤油","unit":"ml","note":""},{"name":"老抽","unit":"ml","note":""},{"name":"塩","unit":"グラム","note":""},{"name":"砂糖","unit":"グラム","note":""},{"name":"ビール","unit":"缶","note":""},{"name":"清水","unit":"","note":"たっぷり"},{"name":"熱湯","unit":"ml","note":""},{"name":"酢","unit":"ml","note":""},{"name":"砂糖","unit":"ml","note":""},{"name":"味の素/鶏がらスープの素","unit":"","note":"適量"},{"name":"煮汁","unit":"ml","note":""},{"name":"にんにく（みじん切り）","unit":"","note":"適量"},{"name":"ネギ（みじん切り）","unit":"","note":"適量"},{"name":"白ごま","unit":"","note":"適量"},{"name":"チリパウダー","unit":"","note":"適量"},{"name":"小唐辛子","unit":"","note":"お好みで"},{"name":"ごま油または花椒油","unit":"","note":"少量"},{"name":"植物油","unit":"","note":"適量"},{"name":"キュウリ","unit":"","note":"適量"},{"name":"木耳","unit":"","note":"適量"},{"name":"揚げピーナッツ","unit":"","note":"適量"},{"name":"パクチー","unit":"","note":"適量"}]'::jsonb, '["牛スジ肉を冷たい水に3時間以上浸して血抜きをする","飴色を作る：鍋に砂糖30gを入れ、弱火で加熱。砂糖が完全に溶けて茶褐色になったら、熱湯150mlを加えて混ぜ合わせる","玉ねぎはくし形切り、生姜とニンニクは潰し、乾燥唐辛子は折っておく","鍋にたっぷりの水を入れ、スパイスパック、玉ねぎ、生姜、ニンニク、乾燥唐辛子を加えて強火で沸騰させる","甜面醤、豆板醤、オイスターソース、発酵豆腐（南乳）を各15ml加えて混ぜる","先に作った飴色を加えて混ぜる","醤油120mlと老抽60mlを加えて混ぜる","塩10～15gを加えて味を調える","ビール1缶（330ml）を加えて再び沸騰させる","牛スジ肉を鍋に入れて2～3分茹で、表面の浮きを取り除き、熱湯で洗い流す","下茹でした牛スジ肉を沸騰した煮汁に入れ、煮汁が肉を完全に覆うようにする","圧力鍋の蓋を閉め、圧がかかったら25～30分加熱する","加熱後、蓋を開けずにそのまま自然冷却し、一晩浸ける（味がより染み込む）","煮上がった肉を取り出し、冷蔵庫で冷やして固める","食べる前に取り出して薄切りにし、そのままか和え物にする","煮汁の再利用方法：肉を取り出した後、煮汁を濾して固形物を取り除き、再度沸騰させて殺菌し、冷めたら冷蔵または冷凍保存。使うときは元のレシピの割合で調味料を追加する（煮汁の量に応じて水を足す）","煮汁は適切に保存すれば長く使え、古いほど風味が増す","重要：野菜類を煮る場合は、必ず別の煮汁を使い、使い終わったらその煮汁は再利用しない","にんにくのみじん切り、ネギのみじん切り、白ごま、チリパウダーを1:1:1:1の割合で混ぜ、好みで小唐辛子を加える。植物油に少量のごま油または花椒油を加え、熱した油を数回に分けて調味料にかける。さらに醤油、酢、オイスターソース各10ml、砂糖5ml、味の素/鶏がらスープの素、最後に煮汁15mlを加えて混ぜる","和え物にするときは、キュウリの叩き、木耳、揚げピーナッツ、パクチーなどを加えても良い"]'::jsonb, '["肉料理","煮込み","醤油ベース","おつまみ","家庭料理","和え物"]'::jsonb),
  ('howtocook:meat_dish/口水鸡/口水鸡', 'ja', 'よだれ鶏', '肉料理', 'よだれ鶏は四川の定番冷菜。赤いラー油が絡んだ鶏肉は、冷たくてプリプリ、ピリッと辛くて香ばしい。夏にぴったりの一品で、食欲をそそります。鶏肉は高タンパク、砕いたピーナッツやスパイスで風味豊か。中級者向け、火加減とラー油の味付けがポイント。仕込みから完成まで約1.5時間。', '[{"name":"鶏肉","unit":"グラム"},{"name":"食用油","unit":"ミリリットル"},{"name":"唐辛子粉","unit":"グラム"},{"name":"花椒","unit":"グラム"},{"name":"ピーナッツ","unit":"グラム"},{"name":"小ネギ","unit":"グラム"},{"name":"生姜","unit":"グラム"},{"name":"ニンニク","unit":"グラム"},{"name":"砂糖","unit":"グラム"},{"name":"醤油","unit":"ミリリットル"},{"name":"酢","unit":"ミリリットル"},{"name":"味の素","unit":"グラム"},{"name":"花椒粉","unit":"グラム"},{"name":"パクチー","unit":"グラム"},{"name":"塩","note":"適量"},{"name":"ごま油","note":"適量"}]'::jsonb, '["生姜はスライスに、小ネギ1本、花椒15粒を準備する。","鶏肉を洗い、鍋に入れ、水をひたひたに入れ、生姜スライス、小ネギ、花椒を加えて強火で沸騰させる。","沸騰したら中弱火にし、20分煮て火を止める。","鶏肉を取り出し、氷水で冷やす。","鶏肉を取り出し、食べやすい大きさに切って皿に盛り、置いておく。","弱火で鍋を熱し、ピーナッツを入れて炒り、皮がはじけるまで焼く（焦がさないように常に混ぜる）。","ネギ1本を小口切りに、ニンニクは潰してみじん切りに、花椒15粒、ピーナッツは皮をむいて粗く刻む。","鍋に油を熱し、ネギ、花椒、半量のニンニクみじん切りを入れて香りを出す。","油が8割熱くなったら火を止め、熱した油を濾す。","熱した油を唐辛子粉の入ったボウルに注ぎ、混ぜ、ラー油を濾す。","ラー油に残りのニンニクみじん切り、醤油、酢、塩、味の素、砂糖、ごま油、花椒粉を加え、混ぜて冷ます。","鶏肉にピーナッツの粗刻みを散らし、ラー油をかけ、パクチーを散らして完成。"]'::jsonb, '["肉料理","麻辣","冷菜","四川料理","おつまみ","食欲増進"]'::jsonb),
  ('howtocook:meat_dish/可乐鸡翅', 'ja', 'コーラチキン', '肉料理', 'コーラチキンは赤く艶やかで、口当たりが柔らかく、甘辛い味わいが絶妙な、家庭料理として人気の創作料理です。鶏手羽先は良質なタンパク質と脂質が豊富で、コーラと一緒に煮込むことでより柔らかくなります。焼き目と煮詰めの火加減がポイントで、初心者には少し難しいかもしれませんが、手順に従えば成功できます。準備から完成までは約40分です。', '[{"name":"手羽先","unit":"本"},{"name":"コーラ","unit":"ml"},{"name":"砂糖","unit":"グラム"},{"name":"醤油","unit":"グラム"},{"name":"老抽","unit":"グラム"},{"name":"塩","unit":"グラム"},{"name":"生姜","unit":"枚"},{"name":"料理酒","unit":"ml"},{"name":"小ネギ","note":"適量"}]'::jsonb, '["手羽先を鍋に入れ、冷水をひたひたに注ぐ。生姜1枚と料理酒10～20mlを加える。強火で沸騰させ（約2分）、アクを取り除き、水気を切る。","この工程は冷蔵の手羽先用。買ってきた手羽先はそのまま切り込みを入れ、醤油で下味をつけるだけでOK。","手羽先を取り出し、両面に2本ずつ切り込みを入れる。醤油約10gで10分漬け込む（醤油が手羽先の表面にしっかり絡めばよい）。","鍋を弱火で再加熱し、残りの生姜を炒めて香りを出し、漬け込んだ手羽先を加える。手羽先が黄金色になるまで焼き、裏返して両面を焼く。菜箸で手羽先を返しながら、生姜と一緒に4～5回炒める（手羽先と生姜がくっつくのを防ぐため）。","手羽先が黄金色になったら、コーラを手羽先が浸るくらい注ぎ、強火で沸騰させる。その後、浮いてくる黒いアク（血合いを含む）を取り除く。ここでネギの結び目を加える。","味付け：食塩2g、砂糖10g、醤油3gを加える（必要に応じて老抽3gで色を調整してもよい）。","ネギの結び目が黄色くなったら生姜と一緒に取り出し、中火に落としてコーラチキンを煮続ける。","コーラが糸を引く状態になったら、弱火にしてタレを手羽先にしっかり絡める。火を止め、皿に盛り付ける。"]'::jsonb, '["肉料理","甘辛","焼き","煮込み","家庭料理","ご飯が進む"]'::jsonb),
  ('howtocook:meat_dish/台式卤肉饭/台式卤肉饭', 'ja', '台湾風ルーロー飯', '肉料理', '台湾風ルーロー飯は、香り豊かな台湾の家庭料理です。豚肉は柔らかく味が染み込み、タレは琥珀色に輝き、熱々のご飯にかけると脂の香りが口いっぱいに広がります。良質なタンパク質、コラーゲン、炭水化物が豊富で、素早くエネルギーを補給できます。初心者にも優しく、材料を揃えて火加減を抑えれば、全体で約1.5時間で完成します。そのうち実際に調理する時間は30分だけで、残りは弱火でじっくり煮込むだけです。', '[{"name":"エシャロット","unit":"g"},{"name":"皮付き豚バラ肉","unit":"g"},{"name":"卵","unit":"個"},{"name":"食用油","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"米酒"},{"name":"ニンニク","unit":"g"},{"name":"ローリエ","unit":"枚"},{"name":"八角","unit":"個"},{"name":"氷砂糖","unit":"g"},{"name":"白こしょう","unit":"g"},{"name":"五香粉","unit":"g"},{"name":"ご飯","note":"適量"}]'::jsonb, '["皮付き豚バラ肉を 0.7cm（長さ）×0.7cm（幅）×2.5cm（高さ）の細長い棒状に切る。","エシャロット、ニンニクをみじん切りにして用意する。","卵をゆでて殻をむき、包丁で白身に切れ目を入れる（味が染み込みやすくするため）。用意する。","強火で鍋を熱し、15mlの食用油を入れ、鍋底に油をなじませる。","油を入れる目的は、豚バラ肉を入れたときに鍋にくっつかないようにするため。5秒待って油の温度を少し上げる。","豚バラ肉の棒を入れ、肉の色が少し白くなるまで炒め、鍋肌から米酒10mlを回し入れる。豚バラ肉から油が出なくなるまでさらに炒める。","みじん切りにしたエシャロットを鍋に加え、1分炒めて油とエシャロットの香りを出す。","みじん切りにしたエシャロットを鍋に加え、30秒炒める。","豚肉を端に寄せ、氷砂糖を入れて溶けて泡立ちカラメルになるまで加熱し、豚肉と一緒に混ぜ合わせ、カラメルが均一に絡むようにする。","醤油を加えて香りが立つまで炒める。","米酒25mlを加え、水を豚肉がかぶるまで入れ、白こしょう、五香粉、八角、ローリエ、ゆで卵を加える。沸騰したら弱火にして1時間煮込む。","注意：醤油によって塩加減が異なるので、煮込む際に味を確認すること。甘すぎたら醤油を、塩辛すぎたら砂糖や水を加えて調整する。","弱火で煮込む間、15分ごとに混ぜて焦げ付きを防ぐ。","水分が少なくなったら、100mlの水を加えてさらに煮込む。","1時間後、強火にしてタレがとろりとし、艶やかな琥珀色になるまで煮詰めたら完成。","煮込みが終わったら、ご飯を茶碗に盛り、柔らかく煮えた豚肉をかけ、煮卵を添えて召し上がれ。"]'::jsonb, '["肉料理","台湾風","家庭料理","ご飯が進む","香ばしい","煮込み"]'::jsonb),
  ('howtocook:meat_dish/咕噜肉', 'ja', '酢豚', '肉料理', '酢豚は定番の広東風家庭料理で、甘酸っぱくてさっぱり、外はカリッと中は柔らか。パイナップルの香りが肉をさっぱりとさせます。豚肉は良質なタンパク質、ピーマンとパイナップルはビタミンと食物繊維を補給します。この料理の難点は揚げる火加減で、初心者には少し難しいですが、手順通りに行えば成功します。漬け込みから完成まで約40分かかります。家族のためにご飯が進む一品にぴったりです。', '[{"name":"豚肩ロース肉","unit":"g"},{"name":"ピーマン","unit":"g"},{"name":"パイナップル缶","unit":"g"},{"name":"塩","unit":"小さじ"},{"name":"ケチャップ","unit":"大さじ"},{"name":"酢","unit":"小さじ"},{"name":"にんにくみじん切り","unit":"大さじ"},{"name":"醤油","unit":"小さじ"},{"name":"片栗粉","unit":"小さじ"},{"name":"砂糖","unit":"大さじ"},{"name":"水","unit":"ml"},{"name":"油","note":"適量"}]'::jsonb, '["豚肩ロース肉（100g）を洗い、キッチンペーパーで水分を拭き取り、完成時の大きさより一回り小さく切る。","塩（小さじ1/2）で豚肩ロース肉を20分漬け込む。","ピーマン（25g）を細かく切る。","パイナップル缶（75g）を一口大に切る。","ボウルにケチャップ（大さじ4）、酢（小さじ2）、にんにくみじん切り（大さじ1）、醤油（小さじ1/2）、片栗粉（小さじ2.5）、砂糖（大さじ2）、塩（小さじ1/4）、水（200ml）を入れて混ぜ、ソースを作る。","豚肩ロース肉に片栗粉（大さじ6）をまぶす。","油（500ml）を中火で熱する。","豚肩ロース肉を鍋に入れ、中火で5分揚げてから取り出す。","豚肩ロース肉を再び強火で1分揚げる。","油（小さじ1）とソースを加え、中火で3分加熱する。","ピーマンとパイナップルを加え、強火で2分加熱する。","揚げた豚肩ロース肉とソースを和えて完成。"]'::jsonb, '["肉料理","甘酸っぱい","広東風","家庭料理","ご飯が進む","揚げ物"]'::jsonb),
  ('howtocook:meat_dish/咖喱肥牛/咖喱肥牛', 'ja', 'カレー牛バラ肉', '肉料理', 'カレー牛バラ肉は、ご飯が進む濃厚な家庭料理です。カレーのスパイシーな香りと牛肉の脂の旨味が融合し、ジャガイモや人参などの野菜と合わせることで、口当たりが柔らかくコクがあります。タンパク質、ビタミン、カルシウムが豊富で、肉と野菜のバランスが良い。作り方は簡単で、初心者にも優しく、通常40分ほどで食卓に並べられます。お弁当のおかずにも最適です。', '[{"name":"ローリエ","unit":"枚"},{"name":"牛乳","unit":"ml"},{"name":"玉ねぎ","unit":"g"},{"name":"人参","unit":"g"},{"name":"じゃがいも","unit":"g"},{"name":"牛バラ肉","unit":"g"},{"name":"カレールウ","unit":"個"},{"name":"サラダ油","unit":"ml"}]'::jsonb, '["玉ねぎは細切りに、人参とじゃがいもは一口大に切り、準備する。","鍋に湯を沸かし、沸騰したら牛バラ肉の薄切りを入れ、アクを取り除いてから水気を切っておく。","鍋を熱し、サラダ油（10～15ml）を入れ、10秒待って油の温度を上げる。","玉ねぎを加え、しんなり透き通るまで炒める。","じゃがいもと人参を加え、2分間炒める。","食材がかぶるくらいの冷水を加える。","ローリエとカレールウを鍋に加え、蓋をして沸騰したら弱火にし、じゃがいもと人参が柔らかくなるまで煮る（箸で確認）。","牛バラ肉と牛乳を加え、蓋をしてさらに弱火で2～3分煮る（スプーンで混ぜる際は、肉が崩れないように注意）。"]'::jsonb, '["肉料理","濃厚でご飯が進む","煮込み料理","家庭料理","時短","カレー"]'::jsonb),
  ('howtocook:meat_dish/商芝肉', 'ja', '商芝肉', '肉料理', '商芝肉は陝西省商県の伝統的な風味料理で、色は鮮やかな赤、柔らかくてなめらか、脂っこくなく、商芝独特の香りがします。豚肉は良質なタンパク質と脂質を提供し、シダ野菜の商芝は食物繊維や様々な微量元素を加えます。この料理は手順が多く、包丁さばきと火加減の技術が求められ、ある程度の料理経験者向けです。準備から完成まで約2.5時間かかります。', '[{"name":"豚バラ肉（皮付き）","unit":"g","note":""},{"name":"商芝","unit":"g","note":""},{"name":"ネギ","unit":"g","note":""},{"name":"生姜","unit":"g","note":""},{"name":"八角","unit":"個","note":""},{"name":"はちみつ","unit":"g","note":""},{"name":"酢","unit":"g","note":""},{"name":"料理酒","unit":"g","note":""},{"name":"味の素","unit":"g","note":""},{"name":"醤油","unit":"g","note":""},{"name":"薄焼き卵","unit":"枚","note":""},{"name":"塩","unit":"g","note":""},{"name":"鶏ガラスープ","unit":"g","note":""},{"name":"ごま油","unit":"g","note":""},{"name":"ラード","unit":"g","note":""}]'::jsonb, '["肉をこそげてきれいに洗い、鍋で6割程度火が通るまで茹で（色が白くなったら）、熱いうちに蜂蜜と酢を肉の皮に塗る。","中華鍋にラードを入れ、強火で8割程度の熱さ（約200度、油から大量の青煙が立ち、油面が静かになる）にし、肉の皮を下にして入れ、黄金色になるまで揚げたら、取り出して冷たい肉の茹で汁（前に使った茹で汁）に浸して柔らかくし、まな板に置いて、長さ約10cm、厚さ約0.6cmに切り、皮を下にして蒸し碗にきれいに並べる。","ネギ5gを2.4cmの長さのぶつ切りに、5gを2.4cmの斜め切りにする。生姜は皮をむいて洗い、1.5gを薄切りに、5gをみじん切りにする。薄焼き卵は2.4cmの二等辺三角形に切る。","商芝を沸騰したお湯で柔らかくなるまで茹でて取り出し、固い茎や不純物を取り除き、よく洗い、3cmの長さに切り、ボウルに入れて醤油5g、塩1g、ラード10gを加えて混ぜ、肉の上にのせる。別に小さなボウルに鶏ガラスープ100gを入れ、醤油5g、塩0.5g、酒15gを加えて混ぜ、蒸し碗に注ぎ入れ、さらに生姜の薄切り、ネギのぶつ切り、八角を加え、強火で約30分蒸した後、弱火に変えてさらに約1時間30分蒸し、柔らかくなったら取り出し、生姜、ネギ、八角を取り除き、煮汁を濾して別に取り、肉をスープ皿にひっくり返して盛る。","中華鍋に鶏ガラスープ100gを入れ、濾した煮汁を加え、強火で沸騰させ、みじん切り生姜、斜め切りネギ、味の素を加えて混ぜ、薄焼き卵を入れ、ごま油を回しかけ、スープ皿に注ぐ。"]'::jsonb, '["肉料理","陝西料理","蒸し料理","風味豊か","おもてなし","伝統的"]'::jsonb),
  ('howtocook:meat_dish/啤酒鸭/啤酒鸭', 'ja', 'ビール鴨', '肉料理', '風味豊かな家庭料理の定番。鴨肉は柔らかく、ほのかなビールの香りがして、あっさりとしていてしつこくない。鴨肉はタンパク質が豊富で、ビールが臭みを消して香りを引き立てる。初心者にも優しく、準備から完成まで約1時間。', '[{"name":"鴨肉","unit":"羽"},{"name":"ビール","unit":"ml"},{"name":"薄口醤油","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"生姜","unit":"枚"},{"name":"ニンニク","unit":"片"},{"name":"氷砂糖","unit":"g"},{"name":"乾燥唐辛子","unit":"本"},{"name":"料理酒","unit":"ml"},{"name":"塩","unit":"g"},{"name":"鶏ガラスープの素","unit":"g"},{"name":"クローブ","unit":"粒"},{"name":"八角","unit":"個"},{"name":"ローリエ","unit":"枚"},{"name":"豆板醤","unit":"g"}]'::jsonb, '["鴨肉を3cmの大きさに切り、冷水から鍋に入れ、生姜のスライスと料理酒を加えて下茹でし、水気を切っておく。","炒め鍋を熱し、約100mlのサラダ油を入れ、強火で油が熱くなったら鴨肉を入れて色が変わるまで炒める。","鴨肉の色が完全に変わったら（白っぽくなったら）、鴨肉を鍋の端に寄せ、豆板醤と砂糖を加え、弱火で香りと色が出るまで炒める。","クローブ、八角、ローリエ、唐辛子、薄口醤油、濃口醤油、ニンニクを加えて香りが出るまで炒める。","ビールを鴨肉が浸るまで注ぎ、塩と鶏ガラスープの素を加え、中火で30分煮込む（歯ごたえが柔らかい方が良ければ更に5分煮込む）。","皿に盛り付けて提供する。"]'::jsonb, '["肉料理","香ばしい","煮込み","四川料理","家庭料理","ご飯が進む"]'::jsonb),
  ('howtocook:meat_dish/回锅肉/回锅肉', 'ja', '回鍋肉', '肉料理', '回鍋肉は四川の伝統的な名菜で、二刀肉またはバラ肉を主材料とし、出来上がりは赤く輝き、脂身は透明でややカールし、赤身は香ばしくパサつかず、脂っこくなく、塩味と旨味にほんのり辛さが加わり、ニンニクの芽と豆板醤の複合的な香りが特徴です。豚肉は良質なたんぱく質と必須脂肪酸が豊富で、ピーマンや赤ピーマン、ニンニクの芽と組み合わせることでビタミンを補えます。この料理は手順がやや多く、茹でる、切る、炒めるを含み、火加減と包丁さばきに一定の技術が必要ですが、手順通りに進めれば初心者でも成功でき、全工程約40分かかります。', '[{"name":"バラ肉","unit":"斤"},{"name":"青ネギ","unit":"本"},{"name":"生姜","unit":"グラム"},{"name":"ピーマン・赤ピーマン","unit":"グラム"},{"name":"ニンニクの芽","unit":"束"},{"name":"料理酒","unit":"ml"},{"name":"豆板醤","unit":"ml"},{"name":"薄口醤油","unit":"ml"},{"name":"味の素","unit":"グラム"}]'::jsonb, '["鍋を熱し、手でバラ肉を鍋にしっかり押し付けて皮を炙る","これは豚皮の汗腺を処理するためです（または肉を買う時に店員に皮を焼いてもらっても良い。汗腺が好きな人は無視してよい）","金タワシで皮をこすり洗いし、黒く炭化した部分を完全に取り除く。取り除かないと苦味が出る","バラ肉を鍋に入れ、肉が浸るくらいの冷水を加え、生姜のスライス、料理酒、青ネギ（2本を結んで）を加える","強火で沸騰させ、アクを取り、さらに15分煮る。赤身の部分が箸で簡単に刺さるまで","ピーマンと赤ピーマンを輪切りにする","ニンニクの芽を食べやすい長さに切る","生姜を薄い小片に切る","5mlの豆板醤と5mlの薄口醤油をあらかじめ混ぜ合わせる","茹で上がったバラ肉を取り出し、冷水に入れて冷ます","バラ肉の水気を拭き取り、上部が脂身、下部が赤身になるように2mmの薄切りにする（厚いと食感が悪く、油っぽい）","鍋を熱し、底油を薄く引いて滑らせる","バラ肉を入れて炒め、脂身が透明になり肉片が軽くカールするまで（灯盏窩という状態、二刀肉が最適）","豆板醤と醤油の混ぜ物、味の素5gを加えて15秒炒める","ピーマンと赤ピーマンの輪切り、生姜の小片を加え、さらに豆板醤5mlを加えて30秒炒める","ニンニクの芽を加えて60秒炒める","火を止めて盛り付ける","冷凍バラ肉は常温で0.5時間、または生バラ肉は冷蔵庫で1時間置いてから、2～5mmの薄切りにする","中火にし、ピーマンと赤ピーマンを鍋に入れて空炒り（30～45秒）して取り出す","鍋を熱し、底油を薄く引いて滑らせ、生姜のスライスを入れて15秒炒める","バラ肉を入れ、10秒おきに炒め、バラ肉がきつね色になるまで（炒める時間が長いほど硬くなる）","先に空炒りしたピーマンと赤ピーマン、豆板醤10ml、薄口醤油を加えて調味し、さらに60秒炒める","切ったニンニクの芽を加えて10秒炒める","火を止めて盛り付ける"]'::jsonb, '["肉料理","四川料理","家庭料理","ご飯が進む","炒め物","塩味と旨味"]'::jsonb),
  ('howtocook:meat_dish/土豆炖排骨/土豆炖排骨', 'ja', 'ジャガイモとスペアリブの煮込み', '肉料理', 'スペアリブは柔らかくほろほろで、ジャガイモはとろけるように味が染み込み、甘辛い味噌の香りが豊かで、ほんのり甘くてピリ辛。典型的な北方の家庭料理です。タンパク質、カルシウム、炭水化物が豊富で栄養バランスが良いです。やや難易度は高いですが（キャラメルソース作りと火加減がポイント）、手順は明確なので初心者でも挑戦できます。全行程約1.5時間です。', '[{"name":"スペアリブ","unit":"克"},{"name":"ジャガイモ","unit":"克"},{"name":"生姜","unit":"克"},{"name":"小ねぎ","unit":"克"},{"name":"料理酒","unit":"ml"},{"name":"砂糖","unit":"克"},{"name":"乾燥唐辛子","unit":"克"},{"name":"八角","unit":"克"},{"name":"花椒","unit":"克"},{"name":"シナモン","unit":"克"},{"name":"しょうゆ","unit":"ml"},{"name":"老抽","unit":"ml"},{"name":"オイスターソース","unit":"ml"},{"name":"甜面醤","unit":"克"},{"name":"塩","unit":"克"},{"name":"サラダ油","unit":"ml"},{"name":"熱湯","unit":"ml"}]'::jsonb, '["ジャガイモの下処理：ジャガイモ300gの皮をむき、不規則な乱切りにします。切ったらすぐにボウルの水に浸し、空気に触れて黒く変色するのを防ぎます。","生姜と小葱の下処理：生姜30gをすべて薄切りにし（15gずつ2つに分ける）。小葱25gを処理する：15gはねぎ結びにし、残り10gは細かい小口切りにして取っておく。","タレの準備（ワンタッチで使えるように）：小さなボウルに、しょうゆ10ml、老抽5ml、オイスターソース5ml、甜面醤5mlを順に加え、よく混ぜ合わせ、コンロのすぐ手の届くところに置いておく。","スパイスの準備：小さな皿に、乾燥唐辛子5g、八角1g（約1〜2個）、花椒1g（約10粒）、シナモン1g（小片）、そして先に切った生姜15gを入れておく。","お湯を沸かす：電気ポットのスイッチを入れ、700mlのお湯を沸かし始める（炒め終わる頃にちょうど沸くようにする）。","冷水から下茹で：スペアリブ750gを冷水の鍋に入れ、ねぎ結び15g、生姜15g、料理酒15mlを加える。強火で沸騰させ、さらに2分間茹で続け、内部のアクを出す。","熱湯で洗う：スペアリブを取り出し、必ず熱湯で表面の浮いたアクを洗い流す（冷水だと肉が急激に縮んで硬くなる）。","完全に水気を取る（油跳ね防止）：洗ったスペアリブはキッチンペーパーで表面の水分を完全に拭き取り、皿に盛って炒め鍋の横に置いておく（後で高温のキャラメルソースに入れるときの油跳ねを防ぐ）。","キャラメルソースを作る：鍋を熱して油20mlを引き、砂糖10gを加え、中弱火で絶えず混ぜる。砂糖が完全に溶けて泡立ち、こげ茶色のキャラメル色になるまで炒める。","色付け：完全に水気を取ったスペアリブ750gを素早く加え、中強火で炒める。約2〜3分、スペアリブの両面が軽く黄金色になり、均一にキャラメル色が絡むまで炒める。","香りを出す：鍋の真ん中を少し空け、スパイスの皿を直接加える。鍋底の熱い油で約10秒炒めて香りを立たせる。","味付け：鍋の縁に沿って残りの料理酒10mlを回し入れ、鍋の香りを引き出す。続いてタレのボウルを直接加え、約30秒炒めてスペアリブにタレが完全に絡み、濃厚な香りが立つまで炒める。","水を加えて煮込む：この時点で電気ポットのお湯が沸騰しているはずなので、熱湯700mlを直接加える（スペアリブが浸る量）。強火で沸騰させ、ふたをして弱火で40分間煮込む。","ジャガイモを加える：40分後にふたを開け、水に浸していたジャガイモ300gを取り出して水気を切り、鍋に加える。再びふたをして、弱火でさらに15〜20分煮込み、箸がスッと通るまで柔らかくする。","味を調えて煮詰める：ふたを開け、塩3gを加える（この時点でスープの味をみて、好みで調整）。強火にして炒めながら煮詰める。約3〜5分。スープが濃くなり、スペアリブとジャガイモに均一に絡まったら火を止める。","仕上げ：皿に盛り、上からあらかじめ用意した小口切りねぎ10gを均等に散らして完成。"]'::jsonb, '["肉料理","味噌風味","ピリ辛","煮込み","北方風","ご飯が進む","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/奶酪培根通心粉/奶酪培根通心粉', 'ja', 'チーズベーコンマカロニ', '肉料理', 'チーズベーコンマカロニは定番のアメリカ風家庭料理で、濃厚でクリーミーな味わいが特徴です。歯ごたえのあるマカロニにチーズが絡み、カリカリのベーコンが塩気と旨味をプラス。タンパク質とカルシウムが豊富ですが、カロリーと脂質が高めなので、たまに楽しむのがおすすめです。作るには少し根気が必要で、ホワイトソースの基本と火加減は初心者にはやや難しいですが、全体的な難易度は中程度です。焼かない場合は約30分で完成し、焼く場合は予熱と焼き時間を含めて約1時間かかります。', '[{"name":"マカロニ","unit":"g"},{"name":"チーズ","unit":"g"},{"name":"チーズ（焼き用）","unit":"g"},{"name":"肉","unit":"g"},{"name":"玉ねぎ","unit":"g"},{"name":"バター","unit":"g"},{"name":"小麦粉","unit":"g"},{"name":"牛乳","unit":"ml"},{"name":"にんにく","unit":"片"}]'::jsonb, '["チーズをおろす","玉ねぎを千切りにする","マカロニを薄い塩水で6分茹でる","中火","鍋にバターを入れて溶かす","玉ねぎを加える","玉ねぎがしんなりしたら、にんにくを加える","にんにくの香りが立ったら、肉を加え、5秒待つ","弱火","牛乳を4回に分けて加え、毎回5秒ずつ混ぜてから次を加える","小麦粉を加えてよく混ぜる","チーズを加えて均一に混ぜる","マカロニとチーズソースを混ぜる","焼かない場合は、そのまま食べられます","焼く場合：","オーブンを180°Cに予熱する","追加のチーズ50gをマカロニの上にのせる","オーブンが180°Cに予熱されたら、マカロニを入れる","表面がきつね色になるまで、約24分焼く"]'::jsonb, '["肉料理","ミルク風味","塩味","グラタン","アメリカ風","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/姜炒鸡/姜炒鸡', 'ja', '生姜炒め鶏', '肉料理', '生姜炒め鶏は湖南風味のご飯が進むおかずで、鶏肉は干し焼きのように香ばしく、生姜の香りが豊かで、辛さはあるがしつこくない。鶏肉には良質なタンパク質が豊富で、生姜は体を温め、胃を整え、食欲を促進する効果がある。作り方は簡単で、初心者でもすぐにマスターできる。下味から完成まで約1時間。', '[{"name":"鶏肉","unit":"羽"},{"name":"生姜","unit":"グラム"},{"name":"ビール","unit":"ml"},{"name":"薄口醤油","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"塩","unit":"グラム"},{"name":"ミニ唐辛子","unit":"個"},{"name":"美人唐辛子","unit":"個"},{"name":"漬け唐辛子","unit":"個"},{"name":"ニンニク","unit":"頭"}]'::jsonb, '["鶏肉はできるだけ1cmの小塊に切り、洗って水気を切り、醤油と料理酒で30分漬け込む","鍋を熱し、微かに煙が出たら食用油を入れ、5秒待つ","生姜の薄切りを入れ、中火で30秒炒める","鶏肉を加えて3分炒め、水分を飛ばし、鶏の脂が出るまで炒める","みじん切りにした唐辛子類とニンニクを加え、塩と濃口醤油でさらに30秒炒める","ビールを注ぎ、中弱火で2分煮込む","強火で汁気を飛ばして盛り付ける"]'::jsonb, '["肉料理","湖南風味","ご飯が進む","香辛","炒め物","家常"]'::jsonb),
  ('howtocook:meat_dish/姜葱捞鸡/姜葱捞鸡', 'ja', '生姜ネギの鶏肉和え', '肉料理', '生姜ネギの鶏肉和えは広東風の定番家庭料理で、鶏肉は柔らかくジューシー、ネギと生姜の香りが豊かで、塩味と旨味がご飯にぴったり。鶏もも肉は良質なタンパク源で、生姜とネギは体を温め、食欲をそそります。調理は蒸して手で裂くのが主で、手順が明確なので初心者にも簡単。準備から完成まで約40分です。', '[{"name":"鶏もも肉","unit":"本"},{"name":"塩焼きチキンパウダー","unit":"g"},{"name":"生姜","unit":"g"},{"name":"ネギ","unit":"本"},{"name":"塩","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"油","unit":"ml"}]'::jsonb, '["鶏もも肉4本を洗ってきれいにし、ボウルに入れます","ボウルに塩焼きチキンパウダーと油5mlを加え、よく混ぜます","鶏もも肉を15分間漬け込みます。その間に蒸し器を用意して水を沸かします","漬け込みが終わったら、沸騰した蒸し器に入れて20分蒸します","生姜をお好みで1）生姜おろし、2）千切り、3）みじん切りにします","ネギは0.5cm幅の小口切りにします","ネギと生姜をタレ用の器に入れ、塩と砂糖を加えます","残りの油を別の鍋に入れて、6～7分熱に加熱します","熱した油をネギと生姜の器に回しかけます","鶏もも肉が蒸し上がったら、手で細かく裂きます。細すぎず、太さ約1cm程度で大丈夫です","生姜ネギ油を裂いた鶏肉にかけ、よく混ぜたら完成です"]'::jsonb, '["肉料理","広東式","蒸し","手で裂く","塩味","ご飯が進む","時短"]'::jsonb),
  ('howtocook:meat_dish/孜然牛肉', 'ja', 'クミンビーフ', '肉料理', 'クミンビーフは、香ばしくスパイシーで柔らかな家庭風炒め物です。濃厚なクミン風味と牛肉の柔らかさ、ピーマンのシャキシャキ感が絶妙に調和します。牛肉には良質のタンパク質と鉄分が豊富で、ピーマンと合わせることでビタミンも補給でき、栄養バランスが良いです。調理には包丁さばきと火加減のコントロールが必要で、ある程度料理経験がある方におすすめです。漬け込みと下ごしらえを含め、全体で約45分で食卓に並べられます。', '[{"name":"牛ヒレまたは牛肩ロース","unit":"グラム"},{"name":"ピーマン","unit":"個"},{"name":"クミン","unit":"グラム"},{"name":"赤唐辛子","unit":"本"},{"name":"醤油（薄口）","unit":"ミリリットル"},{"name":"片栗粉","unit":"グラム"},{"name":"油","unit":"ミリリットル"},{"name":"塩","unit":"グラム"},{"name":"ネギ","unit":"本"}]'::jsonb, '["まず、赤唐辛子をみじん切りにし、クミンシードと一緒にすり鉢で粗く潰します。こうすると味がよく染み込みます。時間がない場合は潰す工程を省いても構いません。","ピーマンはヘタと種を取り除きます（辛いのが好きな場合は種を取らなくても可）、千切りにします。ネギは斜め切りにします。","牛肉は事前に解凍し、水で洗って水気を切り、キッチンペーパーで拭き取ります。牛肉は繊維に沿って薄切りにします。","次に下味をつけます。醤油、片栗粉、油を加えてよく混ぜ、30分ほど置きます。漬け込み方法は他のレシピも参考にしてください。","フライパンに油を熱し、ネギを入れて香りが立ったら、漬け込んだ牛肉を加えて炒めます。","牛肉の色が変わったら、潰したクミンと唐辛子を全体に加え、さらに炒めます。","次にピーマンの千切りを加え、火が通ったら塩を加えます。","強火で1分炒め、火を止めてさらに30秒ほど混ぜながら余熱で火を通し、均一に熱が回ったら完成です。"]'::jsonb, '["肉料理","香辛料＆スパイシー","家庭風","炒め物","ご飯が進む","クミン"]'::jsonb),
  ('howtocook:meat_dish/宫保鸡丁/宫保鸡丁', 'ja', '宮保鶏丁', '肉料理', 'この四川風の名物料理は、糊辣（こら）とライチのような風味が特徴で、ほんのり甘酸っぱく、乾燥唐辛子と花椒の香りが広がります。鶏肉は柔らかく、ピーナッツはサクサクで、食感の層が豊かです。良質なタンパク質と不飽和脂肪酸が豊富で、食欲をそそりご飯が進みます。調理法は簡単バージョンと上級バージョンに分かれており、初心者にも優しく、漬け込み時間を事前に計画すれば大丈夫です。下準備から完成まで約1.5時間かかります。', '[{"name":"手羽元（または鶏むね肉）","unit":"本"},{"name":"長ネギ","unit":"本"},{"name":"生姜スライス","unit":"g"},{"name":"乾燥唐辛子","unit":"g"},{"name":"二荊条唐辛子","unit":"本"},{"name":"素焼きピーナッツ","unit":"g"},{"name":"生ピーナッツ","unit":"","note":"適量"},{"name":"花椒","unit":"g"},{"name":"薄口醤油","unit":"g"},{"name":"濃口醤油","unit":"g"},{"name":"香酢","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"料理酒","unit":"g"},{"name":"塩","unit":"g"},{"name":"鶏ガラスープの素","unit":"g"},{"name":"片栗粉","unit":"g"},{"name":"片栗粉（とろみ用）","unit":"g"},{"name":"植物油","unit":"g"},{"name":"ごま油","unit":"g"},{"name":"豆板醤","unit":"g"},{"name":"茎レタス","unit":"g"},{"name":"辣油","unit":"g"},{"name":"熱湯","unit":"g"},{"name":"水","unit":"g"}]'::jsonb, '["手羽元（もも）はキッチンバサミで骨を外し、鶏肉の表面を包丁の背で軽く叩き、1.5cm角の角切りにする。水に10分浸し、水気を切っておく（鶏むね肉の場合は、そのまま角切りにして以降の工程に進む）。","長ネギの青い部分と生姜スライス5gをボウルに入れ、熱湯50gを注いでおく。白い部分は1.5cmの輪切りにする。ピーナッツを電子レンジ強火で5分加熱し、乾煎りしておく。","鶏肉に塩2g、濃口醤油5g、料理酒15g、片栗粉15gを加えて混ぜ合わせ、少し乾いた感じになるまで混ぜる。葱姜水を少しずつ加えながら、鶏肉が手に粘りつくまで混ぜる。ラップで覆い、冷蔵庫で1時間漬け込む。","乾燥唐辛子は小口切りにする。鍋を強火で熱し、弱火にする。乾燥唐辛子を入れて焦げる手前まで乾煎りし、取り出しておく。花椒も香りが出るまで乾煎りし、取り出しておく。","強火に戻し、植物油20gを入れ、7割熱（竹箸を入れると泡が出る）になったら鶏肉を加え、上面が白くなり始めるまで焼き、ヘラで裏返して30秒焼き、その後全体を炒める。","ネギの輪切りを加えて炒め、残りの葱姜水（足りなければ熱湯を追加）を加える。蓋をして中弱火で2分蒸し煮にする。","強火にし、素焼きピーナッツ、乾燥唐辛子、花椒を加える。鶏ガラスープの素2g、香酢5g、砂糖2gを加えて全体をよく炒める。","片栗粉10gに水50gを混ぜて水溶き片栗粉を作り、鍋に加えて全体を混ぜ、好みの濃度になるまでとろみをつける。","火を止め、ごま油10gを回し入れて、完成。","茎レタスは皮をむき、1cm角の角切りにして、準備しておく。","二荊条唐辛子は1cmの長さに切る。","手羽元はキッチンバサミで骨を外し、包丁の背で軽く叩き、1.5cm角に切る。水に10分浸し、水気を切っておく（鶏むね肉の場合は角切りにしてそのまま進む）。","長ネギの青い部分と生姜スライス5gをボウルに入れ、熱湯50gを注いでおく。白い部分は1.5cmの輪切りにする。","鶏肉に塩2g、濃口醤油5g、料理酒15g、片栗粉15gを加えて混ぜ合わせ、少し乾いた感じになるまで混ぜる。葱姜水を少しずつ加えながら、鶏肉が手に粘りつくまで混ぜる。ラップで覆い、冷蔵庫で1時間漬け込む。","中火にし、植物油20gを入れ、生ピーナッツを表面が少し焦げるまで炒め、ピーナッツを取り出し、油は鍋に残す。","そのまま加熱し、7割熱（竹箸で泡が出る）になったら鶏肉を加え、豆板醤を加えて約1分炒める。","準備しておいた茎レタスを加え、さらに1分炒める。","ネギの輪切りを加えて炒め、残りの葱姜水（足りなければ熱湯を追加）を加え、二荊条唐辛子を加える。蓋をして中弱火で2分蒸し煮にする。","強火にし、先に取り出しておいたピーナッツと花椒を加える。鶏ガラスープの素2g、香酢5g、砂糖2gを加えて全体をよく炒める。","片栗粉10gに水50gを混ぜて水溶き片栗粉を作り、鍋に加えて全体を混ぜ、好みの濃度になるまでとろみをつける。","火を止め、ごま油10gと辣油5gを加えて10秒ほど混ぜ、完成。"]'::jsonb, '["肉料理","四川料理","麻辣","甘酸っぱい","ご飯が進む","炒め物","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/小炒肉', 'ja', '豚バラ肉の炒め物', '肉料理', '小炒肉（豚バラ肉の炒め物）は、香ばしくて辛い、ご飯が進む湖南風の定番家庭料理です。豚バラ肉の薄切りは香ばしく脂っぽさがなく、新鮮な唐辛子と豆豉（トウチ）、豆板醤で炒めて濃厚な味わいに。良質なタンパク質と脂質が含まれ、唐辛子はビタミンCが豊富で食欲をそそり体を温めます。調理難易度は中程度で、初心者でもある程度の経験があれば挑戦可能。肉の下味と火加減に注意が必要です。準備から盛り付けまで約1時間、うち漬け込み30分、炒め工程は約15分です。', '[{"name":"豚バラ肉","unit":"g"},{"name":"朝天唐辛子","unit":"本"},{"name":"ミニ唐辛子","unit":"個"},{"name":"豆豉（トウチ）","unit":"g"},{"name":"豆板醤","unit":"g"},{"name":"濃口醤油","unit":"ml"},{"name":"片栗粉","unit":"g"},{"name":"塩","unit":"g"},{"name":"ネギ","unit":"本"},{"name":"ニンニク","unit":"片"},{"name":"サラダ油","unit":"ml"}]'::jsonb, '["豚バラ肉をスライスする","ボウルに肉を入れ、片栗粉、濃口醤油、塩を加えて混ぜ、30分漬け込む","ネギをぶつ切りにする","ミニ唐辛子、朝天唐辛子を斜めに切る","フライパンを熱し、油を入れる","油が熱くなったら豚バラ肉を加えて炒める。色が変わったら一旦取り出す","フライパンにニンニクを加え、香りが立つまで炒め、豆豉を加えてよく炒める","豆板醤を加えてよく炒める","炒めた豚バラ肉を戻し入れ、さらに炒め合わせる","ミニ唐辛子、朝天唐辛子、ネギを加えて40秒炒める","皿に盛る"]'::jsonb, '["肉料理","香辛料","ご飯が進む","家庭料理","湖南風","炒め物","時短"]'::jsonb),
  ('howtocook:meat_dish/小炒鸡肝/小炒鸡肝', 'ja', '鶏レバーの小炒め', '肉料理', 'この鶏レバーの小炒めは、ニンニクの風味が豊かで、食感は柔らかく、クミンの香ばしさがアクセントの家庭料理です。鶏レバーは鉄分、ビタミンA、良質なタンパク質が豊富で、貧血予防や目の健康に役立ちます。下茹でして臭みを取るテクニックが必要で、初心者には少し難しいかもしれません。準備から完成まで約40分かかります。', '[{"name":"生鶏レバー","unit":"個"},{"name":"にんにくの芽","unit":"g"},{"name":"長ネギ","unit":"g"},{"name":"生姜","unit":"g"},{"name":"料理酒","unit":"ml"},{"name":"食塩","unit":"g"},{"name":"鶏がらスープの素（味の素）","unit":"g"},{"name":"五香粉","unit":"g"},{"name":"こしょう","unit":"g"},{"name":"バーベキューシーズニングまたはクミンパウダー","unit":"g"},{"name":"ごま","unit":"g"},{"name":"食用油","unit":"ml"}]'::jsonb, '["鶏レバーを洗い、準備する","にんにくの芽を洗い、ぶつ切りにし、準備する","長ネギを洗い、100gをぶつ切りに、50gをスライスにし、準備する","生姜を洗い、70gをスライスに、50gをみじん切りにし、準備する","ステップ1：下茹で","洗った鶏レバーを鍋に入れ、鶏レバーが浸るくらいの冷水を加え、100gのぶつ切り長ネギ、70gのスライス生姜、30mlの料理酒を入れる","強火にかけ、沸騰したら中火にしてアクを取り、5～10分待つ","火を止め、取り出して冷水で洗い、きれいにする","洗った後、スライスし、準備する","ステップ2：炒める","中火にする。鍋に30mlの食用油を入れ、10秒待って油を温める","50gのスライス長ネギと50gのみじん切り生姜を加え、炒めて香りを出す","香りが出たら、スライスした鶏レバーを加え、薄く色づくまで炒める","にんにくの芽を加え、30秒炒め、火が通ったら弱火にする","調味料を加える","食塩 5g","鶏がらスープの素（味の素） 5g","五香粉 5g","こしょう 5g","バーベキューシーズニングまたはクミンパウダー 10g（お好みで）","強火にし、焦げないように素早く30秒炒めて、火を止める","皿に盛り、飾りにごま5gをふる（お好みで。ない場合は省略可）"]'::jsonb, '["肉料理","家庭料理","ニンニク風味","クミン","強火炒め","ご飯が進む","貧血予防"]'::jsonb),
  ('howtocook:meat_dish/小炒黄牛肉/小炒黄牛肉', 'ja', '牛肉の小炒', '肉料理', 'この湘味小炒は強火で一気に炒めて牛肉の柔らかさと唐辛子の香りを引き出し、辛味と爽快感、セロリのシャキシャキ感が特徴の湖南風料理です。牛もも肉は良質のタンパク質と吸収されやすい鉄分を提供し、セロリは食物繊維を加え、栄養バランスが良い。準備と調理手順はシンプルで、強火で手早く炒めるだけなので初心者にも優しく、カットから完成まで約1時間でできます。', '[{"name":"牛ヒレ肉","unit":"g"},{"name":"セロリ","unit":"g"},{"name":"赤唐辛子","unit":"g"},{"name":"青唐辛子","unit":"g"},{"name":"パクチー","unit":"g"},{"name":"サラダ油","unit":"ml"},{"name":"醤油","unit":"ml"}]'::jsonb, '["牛ヒレ肉を幅3cm、厚さ3mm以下の薄切りにし、醤油6mlを加えて手でよく混ぜ合わせる。","セロリを5cm以下の長さに切り、用意する。","赤唐辛子を千切りにする。","青唐辛子をみじん切りにする。","パクチーを3cm以下の長さに切る。","鍋を熱し、サラダ油15mlを入れ、強火で30秒待って油の温度を上げる。","赤唐辛子と青唐辛子を加えて香りを出す。","牛肉とセロリを加え、強火で1分間炒める。","火を止め、パクチーを散らして皿に盛る。"]'::jsonb, '["肉料理","湖南料理","辛味","強火炒め","ご飯が進む","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/小米辣炒肉', 'ja', '小唐辛子炒め肉', '肉料理', '小唐辛子炒め肉は辛くてやみつきになる、典型的な西南風味のご飯のおかずです。豚肉の柔らかさと小唐辛子の爽やかな辛さが食欲をそそります。豚肉はタンパク質と脂質が豊富で、唐辛子はビタミンCが多く含まれ、食欲を促進します。炒めるときの火加減がポイントですが、手順は明確で初心者でも簡単に作れます。調理時間は約25分です。注意：この料理は辛さが際立つので、薄味の方はお控えください。', '[{"name":"小唐辛子","unit":"個"},{"name":"落花生油","unit":"ml"},{"name":"バラ肉/赤身肉","unit":"グラム"},{"name":"塩","unit":"グラム"},{"name":"醤油","unit":"ml"},{"name":"オイスターソース","unit":"ml"},{"name":"ニンニク","note":"適量"},{"name":"生姜","note":"適量"},{"name":"豆瓣醤","unit":"グラム"},{"name":"鶏がらスープの素","unit":"グラム"},{"name":"砂糖","unit":"グラム"}]'::jsonb, '["小唐辛子を洗い、斜めに大きめに切る","肉は、細切りにしてもスライスにしてもOK。調味料（醤油、オイスターソース、塩）を加えて5分漬け込む","熱した鍋に油を入れ、まず肉を炒めて取り出す","生姜とニンニクを炒めて香りを出し、豆瓣醤を加えて炒める。切った小唐辛子を加え、さらに赤身肉を戻し入れてさっと炒め、醤油、鶏がらスープの素、塩、砂糖を加えてさらに炒める"]'::jsonb, '["肉料理","辛味","四川料理","ご飯のおかず","家庭料理","炒め物"]'::jsonb),
  ('howtocook:meat_dish/小酥肉', 'ja', '小酥肉', '肉料理', '小酥肉は外はサクサク、中はジューシーで、塩味の香ばしさの中に花椒のピリッとした痺れがあり、四川・重慶地域のどの家庭でも作るおかずの揚げ物です。豚肉はタンパク質と脂質が豊富で、油で揚げるとカロリーが高くなるため、たまの贅沢にぴったりです。この料理は手順が少々多く、初めの揚げで形を整え、二度揚げで色をつける火加減を覚える必要があり、初心者には少し挑戦的です。最初から最後まで約1時間30分で完成します。', '[{"name":"豚肉（皮なし）","unit":"グラム"},{"name":"植物油","unit":"","note":"適量"},{"name":"生姜","unit":"グラム"},{"name":"小ねぎ","unit":"グラム"},{"name":"料理酒","unit":"グラム"},{"name":"塩","unit":"グラム"},{"name":"十三香","unit":"グラム"},{"name":"こしょう","unit":"グラム"},{"name":"うま味調味料","unit":"グラム"},{"name":"鶏ガラスープの素","unit":"グラム"},{"name":"花椒（粗びき）","unit":"グラム"},{"name":"花椒粒","unit":"グラム"},{"name":"薄口醬油","unit":"グラム"},{"name":"卵","unit":"個"},{"name":"小麦粉","unit":"グラム"},{"name":"さつまいもでんぷん","unit":"グラム"}]'::jsonb, '["生姜は千切りに、小ねぎは切らずにそのまま使う。","計算式に従って、料理酒と水を加える。","手で5分間揉み込み、生姜とねぎの風味を十分に水に移す。","豚肉の皮を取り除き、洗う。","長さ8～10cm、厚さ1.5cmの棒状に切る。","上記の計算式に従って、塩、十三香、こしょう、うま味調味料、鶏ガラスープの素、花椒粉、花椒粒、薄口醬油を加える。","先に作った生姜ねぎ水を加える。","よく混ぜて10分間揉み込み、肉が水分を吸収してべたつくまでする。","ラップをして冷蔵庫で30分寝かせる。","漬け込んだ肉に小麦粉とさつまいもでんぷんを加え、卵白を入れる。","15分間よく揉み込む。","鍋に植物油を入れ、鍋の大きさに応じて油の量を調整し、油の深さを3cm以上にする。","強火で油温を150℃に熱し、その後弱火にして温度を保つ。","衣をつけた肉の棒を箸で油に入れ、好みの形に整え、3～5分揚げて形を固定する。色が薄く黄色くなり、ヘラで触ると少し硬くなったらOK。時間は肉の大きさ、油温、衣の状態による。","取り出して油を切る。","油温を180℃に上げ、一度揚げた肉を入れ、きつね色になるまで揚げて取り出す。"]'::jsonb, '["肉料理","塩味の香ばしさ","ほのかな痺れ","四川・重慶","揚げ物","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/尖叫牛蛙/尖叫牛蛙', 'ja', '牛蛙の辛味炒め', '肉料理', 'この料理はピリ辛で食欲をそそり、蛙肉は滑らかで弾力があり、典型的な四川風の家庭料理です。牛蛙は高タンパク低脂肪で、漬け生姜や漬け唐辛子などの発酵食材と合わせることで食欲増進に役立ちます。作り方は比較的シンプルですが、油の温度管理と調味料のバランスに少し注意が必要です。初心者でも1～2時間で完成できます。', '[{"name":"牛蛙の肉","unit":"g"},{"name":"漬け生姜","unit":"g"},{"name":"漬け唐辛子","unit":"g"},{"name":"野山椒","unit":"g"},{"name":"青紅唐辛子","unit":"g"},{"name":"ニンニク","unit":"g"},{"name":"トウバンジャン","unit":"g"},{"name":"塩","unit":"g"},{"name":"コショウ粉","unit":"g"},{"name":"片栗粉","unit":"g"},{"name":"ビール","unit":"ml"},{"name":"料理酒","unit":"ml"},{"name":"花椒油","unit":"ml"},{"name":"ラード","unit":"ml"},{"name":"サラダ油","unit":"ml"},{"name":"刻みネギ","unit":"g"}]'::jsonb, '["牛蛙の肉を洗って水気を切り、塩10g以上とビール50ml以上を加え、手で5分間揉み込み、牛蛙の臭みを取る。","その後、流水で血や汚れがなくなるまで洗い、水気を切って適切な容器に入れ、下味の準備をする。","塩5g、片栗粉30g、料理酒10ml、コショウ粉5gを加え、手でよく混ぜ合わせ、5～10分漬け込む。","漬け生姜、漬け唐辛子、野山椒を千切りまたは薄切りにし（お好みで）、青紅唐辛子は輪切りに、ニンニクは皮をむいてそのままにしておく。","鍋を熱し、サラダ油200mlを加え（鍋底が平らな場合はさらに100ml追加）、油温が6割（小さな泡が出る程度）になったら、下味をつけた牛蛙を入れ、素早く揚げて10秒後に取り出す（長く揚げすぎると肉が硬くなるので注意）。","牛蛙を取り出して油を切り、鍋の油をボウルに移し、30ml残す。ラード20mlを加える（なければサラダ油を合計50ml残す）。","油温が6割になったら、漬け生姜、漬け唐辛子、野山椒、ニンニクを加えて香りを出し、トウバンジャン20gを加えて中火で赤い油が出るまで炒める（約30秒）。ビール400mlを注ぐ。","次に揚げた牛蛙を加え、お玉で優しく混ぜながら、コショウ粉5gと花椒油5mlを加え、中火で3分間煮込む。","強火にして半分間煮詰め、青紅唐辛子の輪切りを加え、さらに10秒煮て火を止める。","器に盛り、刻みネギを散らして完成！いただきます！"]'::jsonb, '["肉料理","ピリ辛","四川風","ご飯が進む","家庭料理","食欲増進"]'::jsonb),
  ('howtocook:meat_dish/尖椒炒牛肉', 'ja', 'ピーマンと牛肉の炒め物', '肉料理', '家庭的な炒め物で、塩味と香ばしさがあり、少し辛い。牛肉は柔らかくて味が染み込み、ピーマンはシャキシャキとした食感。牛肉は良質なタンパク質と鉄分を、ピーマンはビタミンCを豊富に含み、栄養バランスが良い。漬け込みに少し時間が必要だが、手順が明確なので初心者でも作れる。準備から完成まで約1時間。', '[{"name":"牛肉","unit":"g"},{"name":"ネギ","unit":"本"},{"name":"ショウガ","unit":"個"},{"name":"ニンニク","note":"適量"},{"name":"ピーマン","note":"適量"},{"name":"醤油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"砂糖","unit":"g"}]'::jsonb, '["ニンニクをみじん切りにする","ネギをぶつ切りにする","ショウガを薄切りにする","ピーマンをぶつ切りにする","牛肉をボウルに入れる","ショウガ、塩、醤油、砂糖を加えて30～40分漬け込む","漬け込んだらショウガを取り除く","冷たい油を鍋に入れ、油が熱くなり泡が出るまで待つ","みじん切りにしたニンニクを加える","ニンニクがきつね色になったらピーマンを加える","ピーマンの皮がしんなりしたら、漬け込んだ牛肉を加えて炒める","牛肉に火が通る直前にネギを加えてさらに炒める","牛肉に完全に火が通ったら火を止めて盛り付ける"]'::jsonb, '["肉料理","塩味香ばしい","少し辛い","強火で炒める","家庭料理","ご飯が進む"]'::jsonb),
  ('howtocook:meat_dish/山西过油肉', 'ja', '山西風過油肉', '肉料理', '過油肉は山西の伝統的な名物料理で、肉はなめらかで柔らかく、ニンニクの芽はシャキシャキ、塩味と旨味が効いて微かに酸味があり、老陳酢の芳醇な香りが特徴の、典型的な地方の家庭料理です。豚ヒレ肉は良質なタンパク質を提供し、キクラゲ、ニンニクの芽、タマネギと組み合わせることで栄養バランスが良いです。この料理は火加減と肉の下味・衣付けの技術にややコツが必要で、ある程度料理に慣れた方に適しています。下準備から出来上がりまで約40分かかります。', '[{"name":"豚ヒレ肉","unit":"g","note":""},{"name":"ニンニクの芽","unit":"本","note":""},{"name":"塩","unit":"g","note":""},{"name":"醤油","unit":"ml","note":""},{"name":"ネギ・生姜・ニンニク","unit":"g","note":""},{"name":"卵","unit":"個","note":""},{"name":"片栗粉","unit":"g","note":""},{"name":"食用油","unit":"ml","note":""},{"name":"キクラゲ","unit":"g","note":""},{"name":"タマネギ","unit":"g","note":""},{"name":"料理酒","unit":"","note":"適量"},{"name":"老陳酢","unit":"ml","note":""},{"name":"花椒粉","unit":"","note":"適量"},{"name":"鶏がらスープの素","unit":"","note":"適量"}]'::jsonb, '["キクラゲはあらかじめ戻しておきます。急ぐ場合はお湯で戻しても構いません。","豚ヒレ肉を薄切りにしてボウルに入れ、醤油20ml、料理酒、花椒粉を加え、卵1個を割り入れて手でよく混ぜます。片栗粉（サツマイモ澱粉推奨）を加えて混ぜ合わせ、食用油300mlを加えて衣をコーティングし、15分間漬け込みます。","ニンニクの芽は約3cmの長さに切り、タマネギは菱形に切っておきます。","鍋に多めの油を熱し、油温が5割程度になったら、漬け込んだ豚肉を入れ、ほぐしながら揚げ、取り出して油を切っておきます。","鍋の余分な油を捨て、10mlの油を残します。油温を7割程度に熱します。","ネギ、生姜、ニンニクを加えて香りを出し、まずニンニクの芽を加えて火が通るまで炒め、次にキクラゲとタマネギを加え、醤油と花椒粉を加えて数回炒め、先に揚げた豚肉を加えてさらに炒めます。","塩10gを加え、火を止める前に酢10mlと鶏がらスープの素を加え、火を止めて盛り付けます。"]'::jsonb, '["肉料理","山西料理","家庭料理","ご飯が進む","旨味と香り","滑らか炒め","塩味と旨味、微かな酸味"]'::jsonb),
  ('howtocook:meat_dish/巴基斯坦牛肉咖喱/巴基斯坦牛肉咖喱', 'ja', 'パキスタンビーフカレー', '肉料理', 'このパキスタン風ビーフカレーは、濃厚でとろけるような食感、酸味と辛味が食欲をそそり、スパイスの香りが豊かです。牛肉は良質なタンパク質を提供し、トマトとヨーグルトで栄養バランスも良好。作り方はそれほど複雑ではありませんが、じっくり煮込むのに少し忍耐が必要です。のんびりした週末にぴったりの一品です。準備から完成まで約2時間半で、温かい異国情緒あふれる料理がテーブルに並びます。', '[{"name":"牛肉","unit":"kg"},{"name":"トマト","unit":"個"},{"name":"ねじり唐辛子","unit":"個"},{"name":"プレーンヨーグルト","unit":"パック"},{"name":"マサラパウダー（ブランドはShanがおすすめ）","unit":"g"},{"name":"ガーリックパウダー","unit":"g"},{"name":"ジンジャーパウダー","unit":"g"},{"name":"油","note":"適量"},{"name":"水","unit":"ml"}]'::jsonb, '["全てのねじり唐辛子を輪切りにし、取っておく","全てのトマトをペースト状にし、取っておく","牛肉を2cm角に切り、洗って水気を切る","鍋に油をひく（トマトペーストが沸騰して蒸発するのを防ぐため）","トマトペーストを加え、2〜3分絶えず混ぜ、赤みが増すのを待つ","ガーリックパウダー5g、ジンジャーパウダー5g、マサラパウダー50g（1袋）を加え、よく混ぜる","牛肉とねじり唐辛子を加え、よく混ぜる","プレーンヨーグルト1パックを加え（ソースにとろみを出すため）、混ぜる","全ての材料を炊飯器またはスロークッカーに移し、水250mlを加え、肉モードまたはスロークッカーモードで2〜3時間セットする","完了したら、蓋を開けて牛肉が柔らかくなっているか確認し、出来上がり"]'::jsonb, '["肉料理","スパイシー","じっくり煮込む","パキスタン","ご飯が進む","週末"]'::jsonb),
  ('howtocook:meat_dish/带把肘子', 'ja', '带把肘子', '肉料理', '带把肘子は陝西省大荔の伝統的な名物料理で、豚の脚の形が柄（ハンドル）に似ていることから名付けられました。出来上がりは皮がもちもちと柔らかく、肉はとろけるほど柔らかく、脂っこくありません。甜面醤と葱を添えて食べると、塩味とコクがあります。コラーゲンと良質なタンパク質が豊富で、美容と健康に良いです。調理は骨抜き、成形、長時間の蒸しが必要で、初心者にはやや難しいですが、全体の調理時間は約3.5時間です。', '[{"name":"豚前脚（爪付き）","unit":"g"},{"name":"赤豆腐乳","unit":"g"},{"name":"甜面醤","unit":"g"},{"name":"食塩","unit":"g"},{"name":"紅醤油","unit":"g"},{"name":"白醤油","unit":"g"},{"name":"料理酒","unit":"g"},{"name":"にんにくスライス","unit":"g"},{"name":"生姜みじん切り","unit":"g"},{"name":"八角","unit":"個"},{"name":"桂皮","unit":"g"},{"name":"葱","unit":"g"}]'::jsonb, '["肘をこすってきれいに洗い、肘の先を外側、肘の柄（脚爪）を内側、皮を下にしてまな板に置く。","包丁で中央を肘の先から柄に向かって腿骨に沿って皮を切り開き、腿骨の両側の肉を除く（三面を骨から離す）。底部の骨と肉はつなげたまま、骨を露出させ、二節の腿骨を中央から包丁の背（または斧）で叩き折る。","肘を煮鍋に入れて七分熟まで煮て取り出し（外観は正常で内部は薄赤色）、清潔な布で水気を拭き取り、熱いうちに紅醤油を肉皮に塗る。","蒸し鍋を用意し、底に八角と桂皮を入れ、まず肘の柄の関節部分を手で折る（外皮を傷つけないように）。次に皮を下にして蒸し鍋に入れる。鍋に入れる際、肘の体格に合わせて柄を鍋の縁に沿わせて丸く収める。","食塩をふり、消毒済みの清潔なガーゼを肉の上に被せ、その上に甜面醤（50g）、葱（75g）、赤豆腐乳、紅醤油、白醤油、生姜、にんにくをガーゼの上に塗り広げ、強火で約3時間蒸す（柔らかくなるまで）。","蒸し終わったら取り出し、ガーゼをはがして皿に盛り、八角を取り除く。提供時には別添えの葱のぶつ切りと甜面醤の小皿を添える（または甜面醤を肘の表面に塗り、葱のぶつ切りの小皿を添えてもよい）。"]'::jsonb, '["肉料理","塩味と香り","蒸し","陝西","大荔","おもてなし"]'::jsonb),
  ('howtocook:meat_dish/干煸仔鸡/干煸仔鸡', 'ja', '干煸仔鶏', '肉料理', 'これは北京大学の食堂発祥の、甘辛い風味の革新的な四川料理です。鶏肉は下味をつけてから揚げ、外はサクサク中はジューシー、ジャガイモはほくほく、ピーマンはシャキシャキ。赤く輝く甘辛いタレが絡まり、塩味と甘味、ほんのり辛味で食欲をそそります。タンパク質、炭水化物、ビタミンが豊富。揚げ物とタレづくりが必要で、初心者には少し難しいかもしれませんが、手順通りに進めれば成功します。全行程約1時間かかります。', '[{"name":"鶏もも肉","unit":"g"},{"name":"じゃがいも","unit":"g"},{"name":"ピーマン","unit":"g"},{"name":"にんにく","unit":"g"},{"name":"塩","unit":"g"},{"name":"鶏ガラスープの素","unit":"g"},{"name":"こしょう","unit":"g"},{"name":"薄口醤油","unit":"g"},{"name":"濃口醤油","unit":"g"},{"name":"料理酒","unit":"g"},{"name":"片栗粉","unit":"g"},{"name":"郫県豆板醤（紅油入り）","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"花椒粉","unit":"g"},{"name":"水","unit":"ml"},{"name":"食用油","unit":"ml"}]'::jsonb, '["鶏もも肉の骨を外す（もも肉の切り身を使う場合はこの手順を省略可）。鶏もも肉を包丁の背で軽く叩き、2cm角に切る。","鶏もも肉に塩、鶏ガラスープの素（お好みで）、こしょう、薄口醤油、濃口醤油、料理酒を加え、手で混ぜて粘りが出たら片栗粉を加えてよく混ぜ、食用油を加えてくっつきを防ぎ、30分漬け込む。","じゃがいもの皮をむき、2cm角に切り、沸騰したお湯で5分茹でて取り出し、水気を切る（揚げる時に油がはねるのを防ぐため）。","ピーマンの種を取り、2cmの小片に切り、ざるに入れておく。","鍋に多めの油を入れ（鍋の形に合わせて、具材が浸る程度）、油温が180℃になったら、じゃがいもを入れて3分揚げ、取り出す。","油温が再び180℃になったら、鶏肉を入れて2分揚げ、取り出す。","油温が再び180℃になったら、鶏肉を入れてさらに1分揚げ（二度揚げ）、取り出す。","油温が再び180℃になったら、じゃがいもを入れてさらに1分揚げ、鍋の油とじゃがいもをざるで濾しながら取り出す。その際、ざるの上のピーマンに火を通す（油の余熱で）。","鍋に食用油5mlを入れ、弱火でにんにくを炒めて色づくまで炒め、郫県豆板醤（紅油入り）を加えて香りが立つまで炒め、砂糖を加えて溶けるまで炒め、花椒粉を加え、水40mlを加え、絶えず混ぜながらタレがとろりとするまで煮る。","揚げた鶏肉、じゃがいも、ピーマンを加え、よく混ぜ合わせて完成。"]'::jsonb, '["肉料理","甘辛","四川料理","揚げ物","ご飯が進む","家庭料理","おもてなし"]'::jsonb),
  ('howtocook:meat_dish/乡村啤酒鸭', 'ja', '田舎風ビール鴨', '肉料理', '鴨肉とビールを一緒に煮込み、スープは濃厚で、肉は柔らかく香ばしく、ほのかなビールの香りが広がる風味豊かな家庭料理です。鴨肉は栄養豊富で、タンパク質、ビタミンB群、ミネラルが多く含まれており、ビールと煮込むことで味が染み込みやすくなります。手順はやや多いですが、操作は難しくなく、初心者でも約1時間で完成します。', '[{"name":"鴨肉","unit":"kg"},{"name":"ビール","unit":"ml"},{"name":"ピーマン","unit":"本"},{"name":"赤ピーマン","unit":"本"},{"name":"ニンニク","unit":"片"},{"name":"生姜","unit":"cm"},{"name":"ミニ唐辛子","unit":"本"},{"name":"ニンニクの芽","unit":"本"},{"name":"長ネギ","unit":"本"},{"name":"草果","unit":"個"},{"name":"桂皮","unit":"cm"},{"name":"八角","unit":"個"},{"name":"ローリエ","unit":"枚"},{"name":"乾燥唐辛子","unit":"本"},{"name":"料理酒","unit":"ml"},{"name":"花椒","unit":"粒"},{"name":"ピーナッツオイル","unit":"ml"},{"name":"塩","unit":"g"},{"name":"薄口醤油","unit":"ml"},{"name":"濃口醤油","unit":"ml"}]'::jsonb, '["鴨肉を洗って鍋に入れる","鴨肉が浸る程度の水を加える","料理酒20mlを加える","用意しておいた長ネギ1本を加える","生姜（叩いてつぶしたもの）2cmを加える","強火で沸騰させる","アクを取り除く","鴨肉を取り出し、水で洗っておく","鍋を洗って熱し、ピーナッツオイル60mlを加える","油の温度が60度になったら、花椒ひとつかみ（30粒）を加える","鴨肉を加えて4分間炒める","2分後、全ての香辛料を加える","3分の時点で全ての香味野菜（生姜、ニンニク、ミニ唐辛子）を加える","ビール1000mlを加える","鴨肉を30分間煮る","10分経ったら、塩3g、薄口醤油10ml、濃口醤油5mlを加える","20分経ったら、全ての副材料（ピーマンと赤ピーマンのぶつ切り）を加える","29分経ったら、ニンニクの芽のぶつ切りと長ネギのぶつ切りを加える","1分間炒める","火を止めて盛り付ける"]'::jsonb, '["肉料理","香ばしい","煮込み","家庭料理","ご飯が進む","ピリ辛"]'::jsonb),
  ('howtocook:meat_dish/广式萝卜牛腩/广式萝卜牛腩', 'ja', '広式大根牛バラ肉', '肉料理', 'これは広式の家庭的な煮込み料理です。牛バラ肉は柔らかく味が染み込み、大根はスープを吸って甘く濃厚な味わいになります。全体に醤油の風味と甘みが広がります。良質なタンパク質と食物繊維が豊富で、食欲をそそり消化を助けます。手順はやや多いですが難易度は中程度で、初心者でも順を追って成功できます。最初から最後まで約2.5時間かかります。', '[{"name":"牛バラ肉","unit":"g"},{"name":"大根","unit":"本"},{"name":"生姜（スライス）","unit":"枚"},{"name":"ニンニク","unit":"片"},{"name":"ネギ","note":"一束"},{"name":"八角","unit":"個"},{"name":"シナモン","unit":"本"},{"name":"唐辛子（乾燥）","unit":"本"},{"name":"月桂樹の葉","unit":"枚"},{"name":"南乳（赤腐乳）","unit":"個"},{"name":"柱侯醤","unit":"g"},{"name":"オイスターソース","unit":"g"},{"name":"醤油","unit":"g"},{"name":"氷砂糖","unit":"g"},{"name":"塩","unit":"g"},{"name":"老抽","unit":"g"}]'::jsonb, '["大根は転がし切りにして下準備する。","牛バラ肉は塊のまま下茹でし、2枚の生姜と一束のネギを加え、沸騰したら5〜10分煮て、取り出して一口大に切る。","牛バラ肉を好みの大きさに切る（下茹でしたので、煮込む時にほとんど縮みません。大きい塊はより長く煮込む必要があります）。","牛バラ肉を煮込むためのタレを準備する。南乳、柱侯醤、醤油、オイスターソース、砂糖、塩を上記の分量で混ぜ合わせる（氷砂糖がなくなったので、上白糖で代用）。","鍋に油を熱し、生姜とニンニクを炒めて香りを出し、牛バラ肉を加えて水分が飛ぶまで炒める。先に混ぜたタレを加えて香りを炒め付ける。色を濃くしたい場合は、老抽を少々加えて色付けする。","調味料がよく混ざったら、熱湯を加える。","牛バラ肉を鍋に移し、シナモン、八角、月桂樹の葉、唐辛子を加え、約2時間煮込む。","牛バラ肉が半柔らかくなったら、大根を加えてさらに30分煮込む。","大根が柔らかくなったら完成。濃厚な香りの大根牛バラ煮込みができあがります。"]'::jsonb, '["肉料理","広式","煮込み","醤油風味","ご飯が進む","家庭料理","おもてなし"]'::jsonb),
  ('howtocook:meat_dish/徽派红烧肉/徽派红烧肉', 'ja', '徽式紅焼き豚肉', '肉料理', '徽式紅焼き豚肉は、色鮮やかで脂っこくなく、もちもちとした食感と甘じょっぱい味わいが特徴の、徽式の定番家庭料理です。豚バラ肉を主材料とし、良質なタンパク質と脂質が豊富で、エネルギー補給に最適です。作り方では、カラメル色をつける火加減と炒め加減がポイントで、やや挑戦的ですが、調理時間は約45分です。', '[{"name":"豚バラ肉","unit":"g"},{"name":"白砂糖","unit":"g"},{"name":"食用油","unit":"g"},{"name":"生抽","unit":"ml"},{"name":"オイスターソース","unit":"ml"},{"name":"老抽","unit":"ml"},{"name":"生姜のスライス","unit":"枚"},{"name":"ニンニク","unit":"個"},{"name":"料理酒","unit":"ml"},{"name":"ネギ","unit":"本"},{"name":"五香粉","unit":"g"},{"name":"塩","unit":"g"}]'::jsonb, '["豚バラ肉を一口大（2〜3cm）に切る","鍋に食用油150mlを加え、豚バラ肉を入れ、2分ほど揚げ焼きにする。塩を加えてさらに2分炒め、取り出す","鍋に食用油50mlを加え、白砂糖を入れてこげ茶色になるまで炒める","豚バラ肉を戻し入れ、30秒炒めたら、生姜のスライスとニンニクを加えてさらに30秒炒める","料理酒、五香粉、ネギを加え、豚バラ肉が浸る程度の水を注ぎ、蓋をして10分煮る","生抽、老抽、オイスターソースを加え、中火で20分煮る","蓋を外し、強火で汁を煮詰めて、器に盛る"]'::jsonb, '["肉料理","甘辛","紅焼き","徽式","ご飯が進む","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/意式烤鸡', 'ja', 'イタリア風焼きチキン', '肉料理', 'イタリア風焼きチキンは、地中海の風味を感じられる家庭的なオーブン料理です。鶏もも肉をガーリックオイルでマリネし、焼き上げると皮はパリッと、中はジューシーで柔らかく、レモン汁とパセリを添えることでさっぱりとした味わいになります。鶏肉は良質なタンパク質が豊富で、オリーブオイルには不飽和脂肪酸が含まれ、栄養バランスも良好です。作り方は中程度の難易度で、オーブンの予熱が必要ですが、初心者でも手順通りに進めれば、マリネから焼き上がりまで約50分で完成します。', '[{"name":"鶏もも肉","unit":"個"},{"name":"塩","unit":"g"},{"name":"黒胡椒","unit":"g"},{"name":"オリーブオイル","unit":"ml"},{"name":"にんにく","unit":"片"},{"name":"レモン汁","unit":"ml"},{"name":"パセリ","unit":"本"}]'::jsonb, '["鶏もも肉に塩、黒胡椒、オリーブオイル、にんにくのみじん切りを塗る","180度に予熱したオーブンで30〜40分、または火が通るまで焼く","パセリをみじん切りにしておく","レモンを絞って汁を用意する","焼き上がったチキンにレモン汁をかける","パセリのみじん切りを散らす"]'::jsonb, '["肉料理","イタリア風","オーブン焼き","地中海風","さっぱり","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/新疆大盘鸡/新疆大盘鸡', 'ja', '新疆大皿鶏', '肉料理', '新疆大皿鶏は風味豊かで色彩鮮やかな新疆の家庭料理です。鶏肉は柔らかくてパサつかず、ジャガイモはとろっとしていて汁を吸い込み、麻辣の中にほのかな甘さと後味の良さがあります。良質なタンパク質と炭水化物が豊富で、パプリカを加えるとビタミンCも補えます。調理過程では糖色を作り、煮詰めの火加減を調整する必要があり、初心者にはやや難しいですが、手順に従って丁寧に作れば難しくはありません。全体で約1時間で完成します。', '[{"name":"鶏肉（もも肉がベスト）","unit":"kg"},{"name":"ジャガイモ","unit":"g"},{"name":"長ネギ","unit":"g"},{"name":"ピーマン（お好みで）","unit":"g"},{"name":"パプリカ（お好みで）","unit":"g"},{"name":"白砂糖","unit":"g"},{"name":"乾燥唐辛子","unit":"本"},{"name":"ニンニク","unit":"片"},{"name":"油","unit":"g"},{"name":"塩","unit":"g"},{"name":"薄口醤油","unit":"ml"},{"name":"オイスターソース","unit":"g"},{"name":"料理酒（ビールで代用可）","unit":"g"},{"name":"水","unit":"L"},{"name":"花椒","note":"適量"},{"name":"ローリエ","note":"適量"},{"name":"香果","note":"適量"}]'::jsonb, '["肉を一口大に切り、水と塩に5分間浸して血抜きと臭み取りをし、水気を切る。","ネギ、ニンニク、唐辛子、ジャガイモなどを洗い、ジャガイモの皮をむく。","ネギの白い部分は長さ4cmのぶつ切りにし、ピーマンと細長い唐辛子は一口大に切る。","ジャガイモは乱切りにする（切るたびに転がしながら切る）。1かけらが約4cm角程度になるようにする。","糖色を作る：鍋に油を熱し、白砂糖を加えてヘラで混ぜながら溶かし、焦げ茶色になるまで炒める。そこへ水気を切った鶏肉を加えて炒め、色をつける。","花椒、ローリエ、香果、乾燥唐辛子などを加えて炒める。","塩5g、醤油7ml、オイスターソース10g、料理酒100gを加え、水1リットルを注ぐ。料理酒はビールで代用可。","中火にして沸騰させ、その後弱めの中火にしてじっくり煮込む。","汁が減って鶏肉がのぞき始めたら、ジャガイモを鍋の表面にのせる（ジャガイモを混ぜないこと。底に沈めると焦げ付きやすい）。蓋をしてさらに煮る。しばらくしたらネギ、ピーマン、パプリカを加えてさらに煮込む。","汁がほぼ煮詰まったら裏返してジャガイモに汁を吸わせ、最後に火を止めて盛り付ける。"]'::jsonb, '["肉料理","麻辣","ご飯が進む","新疆","煮込み","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/无骨鸡爪/无骨鸡爪', 'ja', '骨なし鶏の足', '肉料理', '酸辣で食欲をそそり、食感はプリプリ。家庭的な冷菜です。鶏の足にはコラーゲンが豊富で、肌に良いです。骨抜きの工程が面倒で手間がかかり、初心者には向いていません。全行程約8時間15分。', '[{"name":"骨なし鶏の足","unit":"kg"},{"name":"生姜","unit":"片"},{"name":"料理酒","unit":"g"},{"name":"長ネギ","unit":"本"},{"name":"ニンニク","unit":"片"},{"name":"ミニトウガラシ","unit":"個"},{"name":"タマネギ","unit":"個"},{"name":"薄口醤油","unit":"g"},{"name":"オイスターソース","unit":"g"},{"name":"黒酢（推奨：陳酢）","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"塩","unit":"g"},{"name":"花椒油","unit":"ml"},{"name":"パクチー","unit":"個"},{"name":"レモン","unit":"個"}]'::jsonb, '["はさみ/包丁で鶏の足の爪の部分を全部切り落とす。爪の下の肉と骨も含めて、爪が一切残らないようにする。","水で洗い、別に置いておく。","鶏の足を大きな鍋に入れ、臭み取りの準備をする。","長ネギ、料理酒、生姜をすべて入れる。","鶏の足が浸るまで水を加える。","強火で沸騰させ、途中でアクを取り除く。","水が100度で沸騰したら、10分間待つ。","火を止め、取り出して水気を切り、洗ってボウルに入れる。","冷凍庫に20分間入れる。","すべてを冷凍室ではない冷蔵室に移し、10個ずつ取り出して骨を抜く。","指（鶏の足の）の先端から始め、それぞれの指を包丁で手の甲部分まで切り開く。","次に手の甲から包丁で全体の腕部分まで切り開く。","それぞれの指の関節を折るようにして、音がするまで押す。","指の先端を押さえ、内側に押し込む。すべての指を同じように、まず手のひらと手の甲の間まで押す。","それぞれの指の皮が剥がれたら、手のひらから腕部分に向かって押し、全体が外れるまで行う。","碗に入れておく。","ミニトウガラシを均等な小粒に切る。","ニンニク、タマネギ、パクチーをみじん切りにする。","レモンを半分に切り、レモン汁を鶏の足の容器に絞り入れる。","すべての調味料を鶏の足の容器に注ぎ、ミニトウガラシ、ニンニク、タマネギ、パクチーも加える。","よく混ぜ合わせる。","冷蔵庫で一晩（6時間）寝かせる。","調合したら、すべてを準備した鶏の足に入れる。"]'::jsonb, '["肉料理","酸辣","冷菜","食欲増進","おつまみ","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/杀猪菜', 'ja', '酸菜と血腸の煮込み', '肉料理', 'これは東北地方発祥の定番煮込み料理です。酸味と爽やかさ、香ばしさが特徴で、心も体も温まります。酸菜には乳酸菌と食物繊維が豊富で、排骨は良質なタンパク質とカルシウムを提供し、血腸は鉄分を補給します。調理中は血腸が破裂しないように注意して扱う必要があり、初心者にはやや挑戦的です。準備から仕上げまで約1時間かかります。', '[{"name":"血腸","unit":"g"},{"name":"酸菜","unit":"g"},{"name":"排骨","unit":"g"},{"name":"料理酒","unit":"g"},{"name":"にんにく","unit":"片"},{"name":"生姜粉","unit":"g"},{"name":"乾燥唐辛子","unit":"本"},{"name":"ローリエ","unit":"枚"},{"name":"八角","unit":"個"},{"name":"ネギの結び","unit":"個"},{"name":"ごま油","unit":"g"},{"name":"菜種油","unit":"g"},{"name":"塩","unit":"g"},{"name":"クコの実","note":"適量"},{"name":"ラー油","unit":"g"},{"name":"薄口醤油","unit":"g"},{"name":"にんにくのすりおろし","unit":"g"},{"name":"ごま油","unit":"g"}]'::jsonb, '["血腸に爪楊枝でいくつか穴を開け、水に入れて弱火で10分煮ます。沸騰させないように80度を保ちます。そうしないと血腸が破裂しやすくなります。","煮上がった血腸を一口大に切っておきます。","排骨に料理酒を加えて下茹でし、水気を切っておきます。","鍋に菜種油を入れ、にんにく、乾燥唐辛子、生姜粉を加えて香りが出るまで炒めます。","排骨を加え、表面がきつね色になるまで炒めます。","酸菜を洗って水気を絞り、鍋に加えてごま油を入れ、強火で2分ほど炒めます。ごま油で酸味が和らぎ香りが良くなります。","600mlの熱湯を加えます。","圧力鍋に移し、ローリエ、八角、ネギの結び、塩を加えます。","濃香モードで40分加圧します。","時間が来たら蒸気を抜いて蓋を開けます。血腸とクコの実を加え、蓋をして2分ほど蒸らします。血腸は加熱済みなので再加熱不要です。","ボウルに盛り、上記の材料表に従って作ったタレをつけてお召し上がりください。"]'::jsonb, '["肉料理","東北","煮込み料理","酸味と爽やか","香ばしい","ご飯が進む"]'::jsonb),
  ('howtocook:meat_dish/枝竹羊腩煲/枝竹羊腩煲', 'ja', '枝竹羊腩鍋', '肉料理', 'これは広東発祥の伝統的な鍋料理です。羊肉と枝竹がチーホウ醤と腐乳の絶妙なハーモニーで、濃厚な醤油の風味とコクがあり、脂っこくなく、体の芯から温まります。特に寒い冬に最適です。羊肉はタンパク質と鉄分が豊富で血行を促進し、枝竹は良質な植物性タンパク質を提供し、栄養バランスが良いです。準備や煮込みの工程は多いですが、火加減の調整は難しくなく、初心者でも手順通りに進めれば成功します。準備から完成まで約2時間半を見込んでください。', '[{"name":"羊腩","unit":"g"},{"name":"揚げ枝竹","unit":"g"},{"name":"チーホウ醤","unit":"g"},{"name":"腐乳","unit":"g"},{"name":"南乳","unit":"g"},{"name":"老抽","unit":"ml"},{"name":"ラー油","unit":"ml"},{"name":"料理酒","note":"適量"},{"name":"オイスターソース","note":"適量"},{"name":"水","unit":"ml"},{"name":"氷砂糖","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"青ネギ","unit":"本"},{"name":"生姜","unit":"枚"},{"name":"干し椎茸","unit":"個"},{"name":"玉ねぎ","unit":"個"},{"name":"エシャロット","unit":"個"},{"name":"にんにく","unit":"片"},{"name":"ローリエ","unit":"枚"},{"name":"八角","unit":"個"},{"name":"シナモン","unit":"g"},{"name":"付け合わせ","note":"お好みで"}]'::jsonb, '["準備: 干し椎茸を2〜3時間浸して柔らかくする。枝竹を30分浸して柔らかくする。","ソース1: 南乳、チーホウ醤、20gの腐乳、老抽を同じ小鉢に入れて混ぜる。","ソース2: 20gの腐乳、砂糖、ラー油を同じ小鉢に入れて混ぜる。","浸した椎茸の根元を取る。","浸した枝竹を5cmの長さに切り、水気を絞る。","玉ねぎの皮をむいて千切りにする。代わりに皮をむいたエシャロットを使うと風味が良くなる。","青ネギを約5cmの長さに切る。","羊腩を冷水の鍋に入れ、生姜2〜3枚を加え、冷水を注ぎ、強火で沸騰したら火を止める。","羊腩を取り出し、準備した冷水のボウルに入れて冷ます。これで歯ごたえが増す。","鍋を熱して油を引き、生姜4〜5枚、玉ねぎ/エシャロット、ネギの白い部分、にんにく7〜8片を入れて香りを出す。","冷ました羊腩を加え、箸で約2〜5分混ぜながら炒め、きつね色になるまで炒める。","ソース1を加え、約2分炒めて色が均一になるまで炒める。","材料がちょうど浸かる程度の水を加える。","椎茸、氷砂糖、ローリエ、八角、シナモンを加える。","蓋をして弱火で90分煮込む。","蓋を開けて枝竹を加え、再び蓋をして中火で20分煮る。","蓋を開けてソース2を加え、混ぜる。","火を止め、盛り付ける前にネギの青い部分またはパクチーを加える。"]'::jsonb, '["肉料理","広東風","醤油風味","体が温まる","秋冬","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/柱候牛腩/柱候牛腩', 'ja', 'チュウホウ牛バラ', '肉料理', 'これは広東風の定番料理で、肉の香りが濃厚で、色は赤く輝いています。筋の入った牛バラ肉が柔らかく煮込まれ、味がしっかり染み込み、豊かな食感です。良質なタンパク質とコラーゲンが豊富で、体を温めます。忍耐が必要ですが、圧力鍋を使えば大幅に時間を短縮でき、初心者にも優しいです。通常の煮込みは約3時間、圧力鍋なら約1時間で完成します。', '[{"name":"牛バラ肉","unit":"グラム"},{"name":"生姜","unit":"グラム"},{"name":"ニンニク","unit":"玉"},{"name":"鷹の爪","unit":"本"},{"name":"ローリエ","unit":"枚"},{"name":"花椒","unit":"グラム"},{"name":"八角","unit":"個"},{"name":"乾燥唐辛子","unit":"本"},{"name":"クローブ","unit":"粒"},{"name":"甘草","unit":"枚"},{"name":"南乳（紅麹豆腐）","unit":"個"},{"name":"豆板醤","unit":"グラム"},{"name":"氷砂糖","unit":"グラム"},{"name":"花雕酒","unit":"グラム"},{"name":"白酒","unit":"グラム"},{"name":"チュウホウジャン","unit":"グラム"},{"name":"チャーシューのたれ","unit":"グラム"},{"name":"オイスターソース","unit":"グラム"},{"name":"老抽","unit":"グラム"},{"name":"生抽","unit":"グラム"}]'::jsonb, '["まず、副材料を準備します：","器1：生姜は1.5cm角に切り、ニンニクは半玉分皮をむき、あれば鷹の爪は1cmの小口切りにします","器2：ローリエ2枚、花椒0.5g、八角2個、乾燥唐辛子3本、クローブ3粒、甘草2枚を入れます","器3：南乳（紅麹豆腐）2個を入れます","器4：豆板醤15gを入れます","器5：氷砂糖10gを入れます","器6：花雕酒10gと白酒10gを注ぎます","器7：チュウホウジャン50g、オイスターソース20g、チャーシューのたれ20g、老抽5g、生抽60gを加えます","牛肉は切らずに、そのまま冷水の鍋に入れ、強火で茹でて、沸騰したら牛肉を取り出します","牛肉表面の不純物を洗い流し、4cm角に切り、水気を切って器に入れておきます","強火で鍋を熱して油を入れ、器1（生姜、ニンニク、鷹の爪）を鍋に加えて香りを出します","中弱火にし、器2（スパイス）を加えて均一に炒め、約30秒","中弱火で器3（南乳）を加え、ヘラで南乳を潰します","中弱火で器4（豆板醤）を加え、均一に炒めて約30秒","中弱火で器5（氷砂糖）を加え、溶けるまで炒めます","中弱火で牛バラ肉を加え、色がつくまで炒めます","強火にし、鍋肌に沿って器6（酒）を回し入れ、素早く炒めて牛肉の表面が少し焦げ茶色になるまで炒めます","器7（たれ）を加えて素早く炒め、底の汁に注意しながら、小さな泡が絶えず立ち、汁が少しとろみがつくまで炒めます","鍋の中のすべての材料を別の煮込み鍋または圧力鍋に移し、材料が浸る程度に水を加えます","使用する鍋に応じて煮込み時間を選びます：","a. 普通の鍋：弱火で3時間煮込む","b. 圧力鍋：40分加圧する","時間が来たら蓋を開けて味を調えます。塩気が足りなければ塩または生抽を加え（少量ずつ加え、味見を繰り返して適切になるまで）、甘さが足りなければ同様に砂糖を加えます","味を調えたら、牛バラ肉を取り出します","大根やジャガイモを食べる場合は、皮をむいて2cm厚の輪切りにし、鍋に加えて10～15分煮ます（または好みの硬さになるまで）。圧力鍋の場合は、再加圧して5分煮ます","煮えたら大根とジャガイモを牛バラ肉と一緒に取り出します","煮汁をこして器に注ぎます"]'::jsonb, '["肉料理","広東風","醬香","煮込み","ご飯のおかず","体が温まる","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/桂林十八酿/桂林十八酿', 'ja', '桂林十八種詰め物料理', '肉料理', '桂林伝統の詰め物料理シリーズ。味付けした豚肉やエビのすり身などの具を、ピーマン、ゴーヤ、タニシ、ナスなど十数種類の中空の食材に詰め、焼き煮込みにした料理。一品ごとに味わいが異なり、旨味が多くジューシーで、柔らかく弾力のある食感。濃厚な地方の家庭料理です。具材は良質なタンパク質を提供し、様々な野菜と組み合わさってビタミンや食物繊維が豊富で、栄養バランスが良いです。調理工程では一つずつ詰めて火加減を調整する必要があり、少し根気がいりますが、操作は簡単で料理初心者でも挑戦でき、完成まで約1.5時間かかります。', '[{"name":"ピーマン","note":"適量"},{"name":"ゴーヤ","note":"適量"},{"name":"ナス","note":"適量"},{"name":"タニシ","note":"適量"},{"name":"豆腐","note":"適量"},{"name":"シイタケ","note":"適量"},{"name":"カボチャの花","note":"適量"},{"name":"ユズ","note":"適量"},{"name":"タケノコ","note":"適量"},{"name":"トウガン","note":"適量"},{"name":"里芋","note":"適量"},{"name":"ニンニク","note":"適量"},{"name":"トマト","note":"適量"},{"name":"もやし","note":"適量"},{"name":"卵","note":"適量"},{"name":"キノコ","note":"適量"},{"name":"豚肉あん","note":"適量"},{"name":"エビのすり身","note":"適量"},{"name":"魚のすり身","note":"適量"},{"name":"混合あん","note":"適量"}]'::jsonb, '["ピーマン詰め：ピーマンの種を取り除いて空洞にする → 豚肉あんまたはエビのすり身を詰める → 焼き目がつくまで焼く → たれで煮込む","タニシ詰め：タニシを茹でて身を取り出す → タニシの身と豚肉をみじん切りにして混ぜる → 殻に詰め戻す → シソとミントで煮込む","豚肉あん：最も基本的で汎用性が高く、脂身と赤身の比率3:7がベスト","エビのすり身：甘くて弾力があり、ピーマン詰めによく使われる","タニシ肉と豚肉の混合あん：タニシ詰めの肝。タニシの身と豚肉を1:1で混ぜ、シソとミントを加える","混合あん：豚肉あんとエビのすり身をミックス。甘みと脂の香りを兼ね備える"]'::jsonb, '["肉料理","旨味","焼き煮込み","桂林風味","家庭料理","おもてなし"]'::jsonb),
  ('howtocook:meat_dish/梅菜扣肉/梅菜扣肉', 'ja', '梅菜の豚肉蒸し', '肉料理', '客家の伝統料理で、仕上がりはこっくりとした醤油色で油艶がよく、とろみのあるスープが特徴。豚バラ肉は脂っこくなく、柔らかくて香り高い。豚肉の良質なタンパク質と脂肪酸に加え、梅干菜の食物繊維も摂れる。工程は多めで、茹で・揚げ・蒸しの火加減が必要なので初心者には少し難しい。準備から梅干菜を戻す時間込みで約2.5時間。', '[{"name":"豚バラ肉","unit":"グラム"},{"name":"梅干菜","unit":"グラム"},{"name":"五香粉","unit":"グラム"},{"name":"食用油","unit":"ml"},{"name":"白砂糖","unit":"グラム"},{"name":"老抽","unit":"ml"},{"name":"生抽","unit":"ml"},{"name":"赤唐辛子","unit":"個"},{"name":"にんにくみじん切り","unit":"グラム"},{"name":"食塩","unit":"グラム"},{"name":"鶏ガラスープの素","unit":"グラム"}]'::jsonb, '["梅干菜を清水に1時間浸す","鍋に50mlの食用油を入れ、豚バラ肉の皮目を下にして1分置き、取り出して皮をこそげ取る（お好みで）","鍋に熱湯を入れ、豚バラ肉を入れて強火で20分茹でる（箸が通るまで）、豚バラ肉を取り出す","豚バラ肉の表面に老抽、五香粉、白砂糖をまんべんなく塗り、15分置く","鍋に油を熱し、豚バラ肉を入れて中火で両面がきつね色になるまで揚げる（3～5分）","鍋に油を熱し、梅干菜を入れ、赤唐辛子、にんにくみじん切り、鶏ガラスープの素、食塩を加えて炒め、梅干菜の水分が飛ぶまで炒める","豚バラ肉をスライスする（厚さ0.5～1cm）、大きめのボウルに並べ、上に梅干菜を散らす","中火で45分蒸す","皿を豚バラ肉のボウルに逆さにかぶせ、豚バラ肉を皿にひっくり返す"]'::jsonb, '["肉料理","客家","蒸し料理","ご飯のおかず","おもてなし","風味豊か"]'::jsonb),
  ('howtocook:meat_dish/椒盐排条', 'ja', '花椒塩ポークリブ', '肉料理', '椒塩排条（花椒塩ポークリブ）は上海本帮料理の定番家庭料理で、外はカリッと中はジューシー、塩味が効いて香ばしい。豚のロース肉は良質なタンパク質と必須アミノ酸を提供し、体力を補います。この料理は手順が少し多めですが、流れに沿って作れば難しくなく、初心者も気軽に挑戦できます。準備から完成まで約40分かかります。', '[{"name":"大排（豚ロース肉）","unit":"枚"},{"name":"卵","unit":"個"},{"name":"塩","unit":"g"},{"name":"花椒塩","unit":"g"},{"name":"ネギとショウガの水","unit":"ml"},{"name":"小麦粉","unit":"g"},{"name":"片栗粉","unit":"g"},{"name":"カスタードパウダー","unit":"g"},{"name":"水","unit":"g"},{"name":"油","unit":"g"}]'::jsonb, '["大排（ポークロース）を洗い、骨を除き、包丁の腹で叩いてほぐし、厚めのスライスに切り、さらに太めの棒状に切ります。","花椒塩を加えて混ぜ合わせ、粘りが出たらネギとショウガの水（葱姜水）を数回に分けて加え、冷蔵庫で20分漬け込みます。","衣を作ります。小麦粉80g、片栗粉20g（残り60gは後で使います）、カスタードパウダー2～3g、塩1gをボウルに入れます。","卵1個を割り入れて混ぜ、水100gを数回に分けて加え、さらに油10gを加えてよく混ぜます。衣が均一になり、ややとろみがつくまで混ぜます。","残りの片栗粉60gを取り出し、排条を取り出して、まず片栗粉をまぶし、次に衣をつけます。","鍋に油を入れ、食材がかぶるくらいにし、約150～160℃に熱します。排条を入れて薄いきつね色になるまで揚げ、取り出します。入れ始めはくっつくことがありますが、触らずにそのままにします。衣が固まったら箸で動かして離します。","油の温度が再び150～160℃に上がったら、排条を入れて二度揚げし、きつね色になったら取り出します。","花椒塩をふりかけ、よく混ぜてから盛り付けます。"]'::jsonb, '["肉料理","塩味と香ばしさ","揚げ物","上海本帮料理","おつまみ","外はカリッと中はジューシー"]'::jsonb),
  ('howtocook:meat_dish/水煮牛肉/水煮牛肉', 'ja', '水煮牛肉', '肉料理', '水煮牛肉は四川料理の定番麻辣味で、口当たりが滑らかで、スープは赤く、香ばしく辛くて熱いです。牛肉は良質のタンパク質と鉄分が豊富で、もやしと合わせることで食物繊維を補えます。この料理は初心者にはそれほど難しくありませんが、火加減と油はねに注意が必要で、全体で約40分かかります。', '[{"name":"牛肉","unit":"g"},{"name":"もやし","unit":"g"},{"name":"卵","unit":"個"},{"name":"パクチー","unit":"本"},{"name":"豆瓣醬","unit":"g"},{"name":"料理酒","unit":"ml"},{"name":"片栗粉","unit":"g"},{"name":"唐辛子粉","unit":"g"},{"name":"生姜","unit":"g"},{"name":"ニンニク","unit":"片"},{"name":"赤唐辛子","unit":"本"},{"name":"オイスターソース","unit":"g"}]'::jsonb, '["牛肉を洗い、薄切りにする。","生姜の千切り15g、卵1個、片栗粉15g、オイスターソース8g、料理酒10mlを加えてよく混ぜ、15分漬け込む。","パクチーを洗い、切っておく。","鍋に油をひき、豆瓣醬、生姜の千切り5g、ニンニクの薄切りを加える。","熱湯を注ぎ、赤いスープにする。","もやしを洗って根を取り、熱湯でさっと茹でる。","もやしを器の底に敷く。","牛肉の薄切りを一片ずつ赤いスープに入れ、火が通ったら取り出す。","牛肉をもやしの上に敷き、パクチーの茎を散らす。","パクチーの葉、唐辛子粉、輪切り唐辛子を散らす。","別の鍋で油を熱し、熱した油を料理の上にかけたら完成。"]'::jsonb, '["肉料理","麻辣","四川料理","ご飯が進む","家庭料理","滑らか"]'::jsonb),
  ('howtocook:meat_dish/水煮肉片', 'ja', '水煮肉片', '肉料理', '水煮肉片は、麻辣で鮮やかな香り、肉は柔らかく、野菜はシャキシャキの定番四川料理で、ご飯にぴったりです。豚ヒレ肉は良質なタンパク質を提供し、もやしなどの野菜と組み合わせて栄養バランスも良好です。作り方はやや手間がかかり、特に肉の下味と刀口辣椒を作るのに忍耐が必要で、初心者は約1〜2時間かかります。', '[{"name":"豚ヒレ肉","unit":"g"},{"name":"食塩","unit":"g"},{"name":"胡椒","unit":"g"},{"name":"醤油（薄口）","unit":"g"},{"name":"料理酒","unit":"g"},{"name":"卵白","unit":"個"},{"name":"じゃがいも澱粉","unit":"g"},{"name":"植物油","unit":"g"},{"name":"もやし","unit":"g"},{"name":"リーフレタス","unit":"本"},{"name":"セロリ","unit":"本"},{"name":"ニンニクの芽","unit":"本"},{"name":"ニンニク","unit":"g"},{"name":"生姜","unit":"g"},{"name":"赤漬け唐辛子","unit":"g"},{"name":"青花椒","unit":"g"},{"name":"乾燥唐辛子","unit":"g"},{"name":"紅油豆瓣醤","unit":"ml"},{"name":"鶏がらスープの素","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"青ネギ","unit":"本"},{"name":"菜種油","unit":"g"}]'::jsonb, '["ヒレ肉を一口大に切り、さらに2mmの薄切りにします（好みで調整可）。ボウルに入れ、水で2回洗って血や汚れを落とし、水気を絞っておきます。","ボウルに食塩1.5g、胡椒1g、醤油5g、料理酒3gを加え、一方向に2分間混ぜて味を染み込ませます。","別のボウルに卵白1個分とじゃがいも澱粉7gを入れて一方向に混ぜ、肉に加えます。","再び一方向に混ぜます（肉の表面に滑らかな膜ができ、より柔らかくなります）。","最後に植物油30gを加えて軽く混ぜ（肉がくっつかないようにします）。","もやし100g、リーフレタス1本（細切り）、セロリ3本を小口切りに、ニンニクの芽2本を叩いて小口切りにします。","ニンニク20gをみじん切り、生姜少々をみじん切り、赤漬け唐辛子20gをみじん切りにします。","乾燥小唐辛子15g、青花椒3g。鍋に油を入れてならし、油が少し熱くなったら余分な油を捨てて底油50gを残し、乾燥唐辛子と花椒を入れ、弱火で香りが立つまで炒めます（焦がさないように注意、色が黒くなったらOK）。取り出してまな板で細かく刻みます。","鍋を熱し、植物油100gを入れて6分熱になったら、青花椒2gと乾燥唐辛子を加えて香りを出し、野菜を加えて食塩1gを入れ、火が通るまで炒め、ボウルに盛って底に敷きます。","鍋を洗い、植物油150gを入れて6分熱にし、みじん切りにした生姜、ニンニク、赤唐辛子を加えて香りを出し、豆板醤10gを加え、弱火で炒めて赤い油が出るまで炒めます。","水800ml（状況に応じて調整）を加え、強火で沸騰させ、弱火にして味付け：食塩2.5g、鶏がらスープの素1.5g、砂糖1g、胡椒1g、水溶き片栗粉5g（状況に応じて調整）でとろみをつけます。","スープが沸いたら、弱火で下味をつけた肉を一枚ずつ入れ、中火で火が通るまでゆでます。ヘラで軽く混ぜてくっつかないようにします。スープが再び沸騰し、肉に火が通ったら、取り出して野菜の上に盛り、スープを注ぎます（料理の上まで）。","ボウルに刀口辣椒、ニンニクのみじん切り、ネギを均等に散らします。","鍋を洗い、菜種油200gを入れて7分熱にし、一気にボウルの肉に均等にかけます（火傷注意）。完成です。"]'::jsonb, '["肉料理","麻辣","四川料理","ご飯のおかず","水煮","おもてなし"]'::jsonb),
  ('howtocook:meat_dish/洋葱炒猪肉', 'ja', '豚肉と玉ねぎの炒め物', '肉料理', '家庭的な風味の炒め物で、塩味の中に甘みがあり、醤油の香りが豊かです。玉ねぎは炒めて柔らかくなると味わいがまろやかになり、柔らかい豚肉との相性が抜群でご飯が進みます。豚肉は良質なタンパク質とビタミンB群を、玉ねぎは食物繊維や抗酸化物質を多く含み、食欲をそそり消化を助けます。調理は簡単で初心者でも気軽に作れ、調理時間はたったの15分です。', '[{"name":"玉ねぎ","unit":"個"},{"name":"豚肉（薄切り）","unit":"克"},{"name":"にんにく","unit":"片"},{"name":"サラダ油","unit":"ml"},{"name":"黒胡椒","unit":"克"},{"name":"醤油","unit":"ml"},{"name":"砂糖","unit":"克"},{"name":"ごま油","unit":"ml"},{"name":"トマトケチャップ","unit":"ml"},{"name":"料理酒","unit":"ml"}]'::jsonb, '["玉ねぎはスライス、豚肉、にんにくは潰す。上記の調味料を混ぜ合わせておく。","炒め鍋にサラダ油大さじ1を入れ（10秒待って油の温度を上げる）、豚肉を加える。","色が変わるまで炒めたら、にんにくを加えて香りが出るまで炒め、取り出しておく。","同じ鍋に玉ねぎを入れ、3〜4分炒めたら、調味料を加えて混ぜ合わせる。","先に取り出しておいた豚肉を戻し入れ、豚肉に火が通るまで炒める。","豚肉に火が通ったら、さらに1〜2分炒めて火を止める。"]'::jsonb, '["肉料理","家庭料理","ご飯が進む","簡単時短","甘辛","醤油風味","炒め物"]'::jsonb),
  ('howtocook:meat_dish/淄博烧烤/淄博烧烤', 'ja', '淄博焼き', '肉料理', 'これは山東省淄博の名物料理で、小さな餅に肉を包み、ネギと一緒に食べる食べ方です。肉の香り、ソースの香り、ネギの香りが混ざり合い、風味豊かで食感の層が豊かです。豚バラ肉は良質なタンパク質と脂質を含み、長ネギは食物繊維を提供し、小さな餅と一緒に摂ることで素早くエネルギーを補給できます。調理には炭火の加減と返す技術が必要で、初心者には少し難しいかもしれませんが、全体で約40分で完成します。', '[{"name":"豚バラ肉","unit":"g"},{"name":"小さな薄餅","unit":"枚"},{"name":"長ネギ","unit":"本"},{"name":"練りごま","unit":"g"},{"name":"甜麺醤","unit":"g"},{"name":"芝麻塩","note":"適量"},{"name":"ぬるま湯","unit":"ml"}]'::jsonb, '["豚バラ肉を厚さ2cm以下の塊に切り、串に刺す。（豚バラ肉は事前に漬け込んでおくと更に美味しい）","長ネギを5cmの長さのぶつ切りにし、用意しておく","練りごまにぬるま湯10mlを加えてのばし、甜麺醤とよく混ぜ合わせる。（代わりに「芝麻塩」でもよい）","炭火に火をつけ、炭が真っ赤になり炎が立たなくなるまで待つ（約15分）","豚バラ肉の串を焼き網に均等に並べ、底面がこんがりと焼けて油が出てきたら裏返す","さらに2〜3分ほど焼き、両面がこんがりとし、端が微かに焦げてきたら取り出す","小さな薄餅1枚を平らに広げ、混ぜたタレを3〜4g塗る","焼いた肉と長ネギを1〜2切れのせ、巻いて出来上がり"]'::jsonb, '["肉料理","炭火焼き","魯菜","香ばしい","酒の肴","パーティー"]'::jsonb),
  ('howtocook:meat_dish/清蒸鳜鱼/清蒸鳜鱼', 'ja', '清蒸ケツギョ', '肉料理', '清蒸ケツギョは身が柔らかく、甘みと旨味が際立つ、素材の味を活かした家庭的な川魚料理です。ケツギョは良質なタンパク質や各種ミネラルが豊富で、消化吸収が良いです。調理の際はヒレに注意が必要ですが、全体の手順は複雑ではなく、初心者でも少し気をつければ十分調理できます。下ごしらえから完成まで約30分です。', '[{"name":"ケツギョ","unit":"グラム"},{"name":"長ねぎ","unit":"本"},{"name":"小ねぎ","unit":"本"},{"name":"醤油","unit":"グラム"},{"name":"赤唐辛子","unit":"個"},{"name":"生姜","unit":"枚"},{"name":"サラダ油","unit":"ml"}]'::jsonb, '["食材の下ごしらえ：","ケツギョを腹から切り開き、エラと内臓を取り除き、鱗をこそげ落とし、包丁で皮の表面のぬめりをこそげ取ります（この工程は親切な店主に頼んでもらっても構いません）","ケツギョの表面に飾り包丁を入れ、生姜のスライスをのせます。可能であればラードを少々加え、皿に盛る際に下に箸を一本敷いて、蒸す際に均等に熱が通るようにします。","長ねぎを縦に切って中の芯を取り除き、外側の2層だけを残します。","小ねぎを縦に切っておきます。","赤唐辛子の種と内側の果肉を取り除いておきます。","準備した長ねぎ、小ねぎ、唐辛子を重ねて千切りにし、水にさらしておきます。","加熱工程：","鍋にたっぷりの水を入れ、水が温まったらケツギョを入れ、蓋をして強火で8〜10分蒸します。魚を蒸すコツは「蒸気が多く、火力が強いこと」です。","魚を蒸している間に、別の鍋でサラダ油を熱し、煙が出るまで加熱します。","蒸し終わったら、魚から出た水を捨て、生姜のスライスを取り除き、千切りネギをのせ、熱した油をかけます。","醤油または魚醤油（蒸魚豉油）をかけて出来上がりです。"]'::jsonb, '["魚料理","清蒸","旨味","あっさり","川魚","家庭料理","おもてなし"]'::jsonb),
  ('howtocook:meat_dish/湖南家常红烧肉/湖南家常红烧肉', 'ja', '湖南風家常紅焼肉', '肉料理', '湖南風家常紅焼肉は、湖南の風味豊かな家庭料理です。豚バラ肉をじっくり煮込むことで、脂っこくなく、口の中でとろけるような柔らかさ。塩味と香りに、ほのかな辛味と甘みが広がります。良質なタンパク質と脂質が豊富で、エネルギーをしっかり補給できます。作るには少し忍耐が必要で、初心者にはやや難しいですが、手順通りに進めれば難しくありません。全工程約1時間です。', '[{"name":"皮付き豚バラ肉","unit":"g"},{"name":"食用油","unit":"g"},{"name":"氷砂糖","unit":"個"},{"name":"ローリエ","unit":"枚"},{"name":"生姜","unit":"枚"},{"name":"シナモン","unit":"小片"},{"name":"八角","unit":"個"},{"name":"料理酒","unit":"g"},{"name":"薄口醤油","unit":"g"},{"name":"濃口醤油","unit":"g"},{"name":"塩","unit":"g"},{"name":"干し小唐辛子","note":"お好みで"},{"name":"熱湯","note":"適量"}]'::jsonb, '["皮付き豚バラ肉を洗い、冷水から鍋に入れ、生姜スライス2～3枚を加えて臭みを取る。沸騰したら取り出し、冷水で白い泡を洗い流す。","豚バラ肉を1.5cm角のブロックに切る。","鍋を熱して油を入れ、氷砂糖を加えて弱火でかき混ぜながらカラメル色にする。切った豚バラ肉を加え、中火で炒めて色をつける。","準備した生姜、八角、シナモン、薄口醤油、濃口醤油、料理酒、干し小唐辛子、塩を加え、弱火で1分炒める。肉が浸るくらいの熱湯を加える。","蓋をして中火で沸騰させ、弱火にして30分煮込む。煮込んでいる間、10分おきに混ぜて焦げ付きを防ぐ。","弱火で煮汁が1/3になるまで煮詰め、中火にして汁を飛ばしながら仕上げる。"]'::jsonb, '["肉料理","湖南風","家庭風","紅焼","ご飯に合う","塩味・香り・辛味"]'::jsonb),
  ('howtocook:meat_dish/湘祁米夫鸭/湘祁米夫鸭', 'ja', '湘祁米夫鴨', '肉料理', '湖南の両祁地区の伝統的な郷土料理。鴨肉を炒めてから米粉をまぶして蒸し上げる。食感はもちもち、塩味と香ばしさが染み込み、余韻が長い。鴨肉は良質のタンパク質とビタミンB群が豊富で、米粉と組み合わせることでエネルギーを補給し、栄養バランスが良い。調理はまず炒めてから圧力鍋で蒸すため、やや難易度が高いが、料理に慣れた方に適している。準備から出来上がりまで約1時間かかる。古鴨を使用する場合は蒸し時間を延長する必要がある。', '[{"name":"鴨肉","unit":"g"},{"name":"もち米粉","unit":"g"},{"name":"うるち米粉","unit":"g"},{"name":"蒸し肉粉","unit":"g"},{"name":"細かい唐辛子粉","unit":"g"},{"name":"白こしょう粉","unit":"g"},{"name":"豚バラ肉","unit":"g"},{"name":"生姜とニンニク","unit":"g"},{"name":"塩","unit":"g"},{"name":"食用油","unit":"g"},{"name":"熱湯","unit":"g"},{"name":"ネギのみじん切り","note":"適量"}]'::jsonb, '["もち米粉、うるち米粉、蒸し肉粉、細かい唐辛子粉、塩5g、白こしょう粉を一緒に混ぜ合わせる。","鴨肉は、店主に蒸し煮用に切ってもらう。生姜は薄切り、ニンニクは皮をむき、豚バラ肉はスライスする。","鍋を熱して油をひき、豚バラ肉を炒めて油を出す。さらに食用油を加えて熱し、鴨肉を加えて炒める。","鴨肉の皮がこんがりと色づくまで炒め、生姜、ニンニク、塩を加えて香りが立つまで炒める。","弱火にし、米粉類を加えて炒め合わせ、鴨肉にまんべんなく米粉を絡める。熱湯を少しずつ加えながら炒める。","鴨肉と米粉がしっとりしたら、器に取り出す。圧力鍋に水を入れて20-25分蒸す。","仕上げにネギのみじん切りを散らしていただきます。"]'::jsonb, '["肉料理","湖南","蒸し料理","塩味と香ばしさ","ご飯が進む","郷土料理"]'::jsonb),
  ('howtocook:meat_dish/澳门湿版免治牛肉饭/澳门湿版免治牛肉饭', 'ja', 'マカオ風牛ひき肉ライス', '肉料理', 'これは澳門のポルトガル風ファストフードの定番です。牛ひき肉は柔らかくて塩味と香ばしさがあり、濃厚なソースと半熟卵液が絡み、ご飯に混ぜると油っぽくて食欲をそそる食感です。牛ひき肉は良質なタンパク質を提供し、卵と玉ねぎを組み合わせることで栄養バランスが良く、お腹も満たされます。調理手順は簡単で初心者にも最適で、準備から完成まで約30分です。', '[{"name":"牛ひき肉","unit":"g"},{"name":"玉ねぎ","unit":"個"},{"name":"卵","unit":"個"},{"name":"バター","unit":"g"},{"name":"青ネギ","unit":"g"},{"name":"醤油","unit":"大さじ"},{"name":"濃い口醤油","unit":"大さじ"},{"name":"ケチャップ","unit":"大さじ"},{"name":"砂糖","unit":"大さじ"},{"name":"料理酒","unit":"大さじ"},{"name":"黒こしょう","unit":"g"},{"name":"片栗粉","unit":"大さじ"},{"name":"水","unit":"ml"},{"name":"ご飯","note":"適量"}]'::jsonb, '["ボウルに牛ひき肉200gを入れ、醤油大さじ1、砂糖大さじ1/2、黒こしょう2gを加えてよく混ぜ、10分間漬け込みます。","玉ねぎ半分をみじん切りにし、取っておきます。","ソースを作る：ボウルに醤油大さじ2、ケチャップ大さじ2、料理酒大さじ1、片栗粉大さじ1、濃い口醤油大さじ1/2、水50mlを入れ、よく混ぜて取っておきます。","別の鍋で、ポーチドエッグまたは半熟の目玉焼きを1つ作って取っておきます。","フライパンを熱し、バター10gを入れます。バターが溶けたら、みじん切りの玉ねぎを加え、弱火で香りが立つまで炒めます。","漬け込んだ牛ひき肉を加え、玉ねぎと一緒に牛肉の色が変わるまで炒めます。","作っておいたソースを加え、黒こしょう2gを振り入れ、とろみがつくまで炒めて火を止めます。","炒めた牛ひき肉を温かいご飯の上にかけ、先に作ったポーチドエッグまたは半熟の目玉焼きをのせます。","（お好みで）表面に刻んだ青ネギ5gを飾ります。"]'::jsonb, '["肉料理","マカオ風","ポルトガル風","牛肉","ファストフード","混ぜご飯","ミンチビーフ","初心者向け"]'::jsonb),
  ('howtocook:meat_dish/烤鸡翅', 'ja', '手羽中のオーブン焼き', '肉料理', '下味をしっかりと染み込ませた手羽中を高温で焼き上げ、皮はパリッと中はジューシーで、黒胡椒と醤油の香ばしさが楽しめます。良質なタンパク質とコラーゲンが豊富。難易度は中程度で、初心者でも簡単に作れます。準備から出来上がりまで約1時間。お好みでハチミツや五香粉を加えて風味を変えることもできます。', '[{"name":"手羽中","unit":"個"},{"name":"塩","unit":"g"},{"name":"黒こしょう","unit":"g"},{"name":"醤油","unit":"ml"},{"name":"料理酒","unit":"ml"}]'::jsonb, '["手羽中をボウルに入れる","塩、黒こしょう、醤油、料理酒を加えて30～40分漬け込む","オーブンを200℃に予熱する","漬け込んだ手羽中を天板に均等に並べる","天板をオーブンの中段に入れ、15～20分焼く","天板を取り出し、手羽中を裏返してさらに15～20分、火が通るまで焼く"]'::jsonb, '["肉料理","塩味と香ばしさ","焼き料理","家庭料理","おもてなし"]'::jsonb),
  ('howtocook:meat_dish/煎烤羊排/煎烤羊排', 'ja', 'ラムチョップのフライパン焼き', '肉料理', '外はカリッと中はジューシーで香り豊かな一品。スパイスで煮込んでからフライパンで焼き上げ、黄金色のカリッとした皮が香ばしく、濃厚な味わいでしつこくない。家庭料理にもおもてなしにもぴったりのしっかりした料理です。ラム肉は良質なタンパク質、鉄分、亜鉛などのミネラルが豊富で、血行を良くして体を温める効果が期待できます。手順はやや多めですが、流れに沿って進めれば初心者でも成功できます。圧力鍋を使えば約1時間、普通の鍋なら約1.5時間です。', '[{"name":"ラムチョップ","unit":"グラム"},{"name":"シナモン","unit":"グラム"},{"name":"花椒","unit":"グラム"},{"name":"八角","unit":"個"},{"name":"白芷","unit":"グラム"},{"name":"ローリエ","unit":"枚"},{"name":"塩","unit":"グラム"},{"name":"料理酒","unit":"ミリリットル"},{"name":"チリパウダー","unit":"グラム"},{"name":"クミンシード","unit":"グラム"},{"name":"バーベキューシーズニング","unit":"グラム"},{"name":"クミンパウダー","unit":"グラム"},{"name":"白ごま","unit":"グラム"},{"name":"砂糖","unit":"グラム"}]'::jsonb, '["ラムチョップを骨に沿ってブロック状に切る。","炒め鍋に冷水を入れ、全てのラムチョップを加え、沸騰したらさらに2〜3分茹でて、取り出して置いておく。","茹でたラムチョップ、シナモン、花椒、八角、白芷、ローリエ、料理酒を鍋（圧力鍋または普通の鍋）に入れる。","全ての材料が浸るくらいの水を加える。圧力鍋を使用する場合は、沸騰後30分加圧する。普通の鍋の場合は80分煮込む。","煮上がったラムチョップを取り出し、水気を切り、油も水もない炒め鍋／フライパンに入れる。","中強火で6〜7分焼き、ラムチョップの脂が出て表面が黄金色でカリッとするまで焼く。","鍋に焼き出したラム脂を残し、チリパウダー、クミンシード、バーベキューシーズニング、クミンパウダー、白ごまを加え、よく炒め合わせる。","砂糖と塩（煮込みの時に加えていない場合）を加え、よく炒め合わせる。","よく混ざったら火を止め、皿に盛る。"]'::jsonb, '["肉料理","フライパン焼き","スパイシー","外はカリッと中はジューシー","家庭料理","おもてなし"]'::jsonb),
  ('howtocook:meat_dish/牛排/牛排', 'ja', 'ステーキ', '肉料理', 'これはクラシックな洋風ステーキのレシピです。焦げた外側に包まれた肉汁たっぷりの柔らかい肉が特徴で、バター、ニンニク、ハーブの風味が豊かです。良質なタンパク質、脂質、鉄分、亜鉛などのミネラルが豊富。調理工程は初心者にも優しいですが、火加減の習得には少し練習が必要です。全工程15〜30分で完了します。', '[{"name":"ステーキ肉","unit":"g"},{"name":"オリーブオイル","unit":"ml"},{"name":"バター","unit":"g"},{"name":"塩","unit":"g"},{"name":"黒こしょう","unit":"g"},{"name":"ニンニク","unit":"個"},{"name":"タイム","unit":"g"},{"name":"ローズマリー","note":"適量"},{"name":"市販のステーキソース","note":"適量"},{"name":"マッシュルーム","unit":"個"},{"name":"ミニポテト","unit":"個"},{"name":"ミニトマト","unit":"個"},{"name":"アスパラガス","note":"適量"}]'::jsonb, '["冷蔵庫からステーキを取り出して解凍する。","ステーキが冷凍状態の場合、前日の晩に冷蔵室に移し、調理の30分前に常温に置く。","ステーキを水に浸したり、加熱して解凍しないでください。","ミニトマト、ミニポテト、マッシュルームを洗い、半分に切って準備する。","ニンニクの皮をむき、大きめの5〜8片を残し、包丁の背で潰して準備する。","ステーキの下準備","リブアイステーキの場合（ステーキの種類の選び方参照）、キッチンばさみを垂直にリブアイセンターの結合組織に差し込み、1〜2回切る。これはリブアイの「アイ」（結合組織）が高温で急激に縮み、ステーキが変形して均一に加熱されなくなるのを防ぐため。","サーロインステーキの場合、縁の脂身が苦手なら、包丁で丁寧に取り除く。","次に、キッチンペーパーでステーキを包み、表面の水分を完全に拭き取る。まな板に置いて持ち上げた後、目立つ水跡が残らなくなるまで。","コンロを強火にし（火力の説明は付録参照）、鍋にオリーブオイルを入れ、15〜30秒加熱する。","ステーキの下味をつける。海塩と黒コショウをステーキの表面全体にまんべんなく振りかけ、手で揉み込んで、塩とコショウの粒が肉にできるだけ食い込むようにする。下味をつけたらすぐに鍋に入れること。事前に漬け込むのは推奨しない。表面の塩が肉の水分を引き出し、調理に影響を与え風味を損なうため。","油の温度が6〜8割になったら（油温の見分け方参照）、ステーキを手前から奥へゆっくり鍋に入れる。","付け合わせにポテトを使う場合、ポテトをボウルに入れて電子レンジで10分加熱するか、熱湯で3〜5分茹でる。","片面を1.5分焼く（この時間は厚さ2〜3cmのステーキに適します。ステーキが薄い場合は1分、厚い場合は2〜2.5分に調整）。","裏返して、さらに1.5分焼く。","サーロインとフィレステーキの場合、箸またはヘラでステーキを立てて、側面を約30秒焼く。","コンロを中火に切り替え、バター、ニンニク、タイムを順に素早く加える。ヘラでバターを鍋全体に広げながら完全に溶かす。ニンニクをステーキの下に押し込んで風味を加える。","フライパンを傾けてコンロに置き、油をすべて片側に集める。","香草とニンニクをステーキの上に置き、スプーンで鍋の油をすくい、ステーキの上に絶えずかけていく。この工程を30秒続け、その後ステーキを裏返してさらに30秒繰り返す。","油をステーキにかけたときの状態で火加減を確認する。油が泡立ち、色が濃い茶色になっていなければ適温。","ステーキの水分が十分に拭き取れていなかったり、推奨しない方法で解凍した場合、または事前に塩漬けにした場合、鍋に大量の水が出て、ステーキが「茹でられ」てしまい風味が損なわれる。","ステーキの表面に大量の油の泡が出て、油の色が濃い茶色になった場合は、油が高温すぎるので、鍋を火から外し、少し待ってから油をかけ続ける。","ステーキをまな板に取り出し、アルミホイルで包み、5〜10分置く。この工程（レスト）により、ステーキの余熱で内部を加熱し、肉汁を閉じ込める。","付け合わせ（ポテト、トマト、マッシュルーム）を鍋に入れ、中火で5分焼く。","ステーキを取り出し、幅1.5cmのリボン状に切る。このとき焼き加減を確認できる。","付け合わせを取り出し、皿に盛り、鍋に残った油またはステーキソースをかける（お好みで）。"]'::jsonb, '["肉料理","洋風","焼き","香ばしい","おもてなし","時短"]'::jsonb),
  ('howtocook:meat_dish/猪皮冻/猪皮冻', 'ja', '豚皮の煮凝り', '肉料理', '豚皮の煮凝りは北方の年夜飯によく出る伝統的な冷菜で、透明でつやがあり、口当たりは滑らかで弾力があり、お酒のつまみに最適です。豚皮はコラーゲンが豊富で、美容効果があります。この料理はやや難易度が高く、豚皮の臭み取りと長時間の煮込みに忍耐が必要で、製作時間は約24時間を見込んでいます。', '[{"name":"豚皮","unit":"kg"},{"name":"水","unit":"kg"},{"name":"塩","unit":"グラム"},{"name":"うま味調味料","unit":"グラム"},{"name":"鶏がらスープの素","unit":"グラム"},{"name":"薄口醤油","unit":"ml"},{"name":"老抽","unit":"ml"},{"name":"ネギ","unit":"グラム"},{"name":"生姜スライス","unit":"グラム"},{"name":"生姜","unit":"グラム"},{"name":"八角","unit":"グラム"},{"name":"花椒","unit":"グラム"},{"name":"料理酒","unit":"ml"},{"name":"白酢","unit":"グラム"},{"name":"白芷（ビャクシ）","note":"適量"},{"name":"桂皮（ケイヒ）","note":"適量"},{"name":"クローブ","note":"適量"},{"name":"香葉（ローリエ）","note":"適量"},{"name":"小茴香（フェンネル）","note":"適量"}]'::jsonb, '["豚皮を10cm以下の小片に切り、清水に12時間浸します。その後、冷水から鍋に入れ、生姜10g、料理酒50mlを加えて5〜10分間茹でこぼし、取り出して冷水に入れます。","茹でた豚皮をまな板に置き、中の白い脂身をすべて取り除き、3mm以下の細切りにしてボウルに入れます。","白酢20g、塩5gを加えて3分間よく揉み洗いし、清水で洗い流します。この時点で豚皮の臭みはほとんどなくなっています。","鍋に水4kgを入れ、豚皮、ネギ10g、生姜スライス10g、八角10g、花椒5gを加え、強火で沸騰させたら弱火で90分間煮込み、豚皮が柔らかくなるまで煮ます。","さらに塩8g、うま味調味料10g、鶏がらスープの素15g、薄口醤油50ml、老抽20mlを加えて味を調え、皿に注ぎ、ネギ、生姜、八角を取り出し、ゼリー状になるまで冷まします。","冷蔵庫で冷やし固めます。食べる際に、小さな塊か厚めのスライスに切ります。"]'::jsonb, '["肉料理","塩味","煮込み","北方","酒のつまみ","年夜飯"]'::jsonb),
  ('howtocook:meat_dish/猪肉烩酸菜', 'ja', '豚肉と酸菜の煮込み', '肉料理', '豚肉と酸菜の煮込みは、北の方の家庭料理で、酸味が豊かで、豚バラ肉は柔らかくトロトロ、スペアリブに味が染み込んでいます。主にタンパク質を提供し、酸菜は乳酸菌などの有益な成分ももたらします。手順は明確で、初心者でも順を追って完成できますが、根気よくじっくり煮込む必要があり、最初から最後まで約3時間かかります。', '[{"name":"豚バラ肉または豚スペアリブ","unit":"グラム"},{"name":"東北酸菜","unit":"グラム"},{"name":"長ネギ","unit":"本"},{"name":"生姜","unit":"グラム"},{"name":"にんにく","unit":"片"},{"name":"塩","unit":"グラム"},{"name":"薄口しょうゆ","unit":"グラム"},{"name":"五香粉","unit":"グラム"},{"name":"料理酒","unit":"ミリリットル"},{"name":"八角","unit":"個"}]'::jsonb, '["長ネギをぶつ切りにする。生姜50グラムをぶつ切りにし、50グラムをみじん切りにする。にんにくをみじん切りにし、準備する。","酸菜をすべて千切りにし、水で2〜3回洗って準備する。","スペアリブと豚バラ肉を鍋に入れ、冷水がかぶるまで注ぐ。すべての長ネギのぶつ切り、50グラムの生姜のぶつ切り、料理酒20ミリリットルを加える。強火で沸騰させ、5分待つ。火を止め、スペアリブと豚バラ肉を取り出し、冷水でアクを洗い流して準備する。","茹でた豚バラ肉を薄切りまたは一口大に切り、準備する。","先ほどの鍋をきれいに洗い、拭いて乾かす（そうしないと油を入れたときにはねる）。","鍋に油を入れ、中火にかけ、生姜とにんにくのみじん切りを加えて香りを出す。豚バラ肉とスペアリブを加える。豚バラ肉とスペアリブがきつね色になるまで炒め、五香粉10グラムと薄口しょうゆ15グラムを加え、へらで1〜2分混ぜる。","洗っておいた酸菜の千切りを鍋に加え、3分間炒める。","純水を具材がちょうどかぶるくらいまで注ぎ、八角2個を加え、強火にして沸騰させる。中火にし、蓋をして煮込む。","1.5〜2時間待ち、豚バラ肉が柔らかくなるまで（箸で簡単に刺さるまで）煮込む。","蓋を開け、強火にして煮詰める。鍋の中の具材を混ぜながら、水分が鍋底だけに残るまで煮詰めたら、弱火にして味付けの準備をする。","味付け：食塩10グラムを加え、よく混ぜる。","火を止め、器に盛る。"]'::jsonb, '["肉料理","酸味","煮込み料理","北方","家庭料理","ご飯が進む"]'::jsonb),
  ('howtocook:meat_dish/甜辣烤全翅', 'ja', '甘辛焼き手羽', '肉料理', 'この甘辛焼き手羽はエアフライヤーで作ります。皮はパリッと中はジューシーで、甘辛い風味が人気です。鶏肉は良質なタンパク質が豊富で、揚げる代わりにエアフライを使うことで油を大幅に減らし、軽やかに食べられます。作り方は明確で、事前に漬け込んで途中で一度ひっくり返すだけで、初心者にも優しいです。食材の準備から完成まで約3時間かかりますが、そのほとんどは漬け込み時間で、実際の作業はそれほど手間ではありません。', '[{"name":"手羽","unit":"本"},{"name":"薄口醤油","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"ガーリックパウダー","unit":"g"},{"name":"胡椒","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"パプリカパウダー","unit":"g"},{"name":"唐辛子粉","unit":"g"},{"name":"オイスターソース","unit":"ml"},{"name":"水","unit":"ml"},{"name":"油","unit":"ml"}]'::jsonb, '["新鮮な手羽4本を取り出し、手羽中の2本の骨の間に皮目に切れ込みを入れ、表裏それぞれ1カ所ずつ切る。","手羽4本をボウルに入れ、薄口醤油45ml、濃口醤油15ml、ガーリックパウダー10g、胡椒5g、砂糖10g、パプリカパウダー10g、唐辛子粉5g、オイスターソース15ml、水20ml、油10mlを加える。","スプーンでタレを手羽に均等に塗り、特に手羽中の切れ目にしっかり塗る。約3分かける。","ラップをかけて油が飛び散らないようにし、冷蔵庫で120分置く。","手羽を取り出し、アルミホイルのトレイに手羽4本を並べ、ボウルに残ったタレを均等にかける。","アルミホイルトレイをエアフライヤーのバスケットに置き、200℃で25分焼く。","エアフライヤーを開け、慎重にアルミホイルトレイを取り出し、手羽を裏返す。","再度200℃で25分焼く。","取り出してそのまま食べられる。"]'::jsonb, '["肉料理","甘辛","焼き","エアフライヤー","おつまみ","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/田螺酿/田螺酿', 'ja', '田螺の詰め物', '肉料理', '田螺の詰め物は陽朔の「十八の詰め物料理」のトップ。田螺の身は歯ごたえがあり、豚肉は柔らかく、シソとミントの香りが際立つ。『舌尖上的中国2』にも登場。タンパク質とミネラルが豊富で、田螺と豚肉の栄養バランスが良い。少し手間がかかり、初心者には挑戦的。半日前に田螺の砂抜きが必要で、調理時間は約40分。休日に家族みんなで作るのにぴったり。', '[{"name":"大田螺","unit":"個"},{"name":"豚肉","unit":"g"},{"name":"ミントの葉","unit":"g"},{"name":"シソの葉","unit":"g"},{"name":"生姜","unit":"g"},{"name":"ネギ","unit":"本"},{"name":"桂林三花酒","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"食用油","unit":"ml"},{"name":"酸笋","unit":"g"},{"name":"大蒜","unit":"片"},{"name":"乾燥唐辛子","unit":"個"},{"name":"オイスターソース","unit":"ml"},{"name":"片栗粉","unit":"g"},{"name":"白コショウ","unit":"g"}]'::jsonb, '["午前中に田螺を買い、バケツの水に入れて午後まで静置し砂を吐かせる","水にごま油（またはわさび）を数滴垂らすと砂抜きが早くなる","ブラシで田螺の殻をよく洗う（時間をかけて丁寧に）","ペンチまたは包丁で田螺の尾部を切り落とす（約1/3から半分）","大きめの鍋で湯を沸かし、田螺を1〜2分茹でる（長くすると身が硬くなる）","取り出して爪楊枝で身を取り出し、蓋と黒い内臓を取り除く","殻を水でよく洗い、水気を切っておく","田螺の身を塩でもみ洗いし、細かく刻む（ペースト状にせず、粒感を残す）","豚肉をミンチにする","ミントの葉とシソの葉を細かく切り、生姜はみじん切り、ネギは小口切り","ボウルに刻んだ田螺、豚ミンチ、ミント、シソ、生姜、ネギを入れる","三花酒15ml、醤油15ml、塩3gを加える","お好みで：オイスターソース10ml、白コショウ2g、片栗粉10g","一方向にかき混ぜ、餡が粘り気を帯びるまで混ぜる","手間を省く場合は上記すべてをフードプロセッサーでまとめて混ぜる","箸で餡を田螺の殻に詰める。ぎっしり詰めるが、殻を割らないように注意","すべての田螺に詰め終える","鍋を熱し、食用油30mlを入れ、お好みで酸笋と乾燥唐辛子を加えて香りを出す","水またはスープ300ml、醤油15ml、塩2gを加え強火で沸騰させる","詰めた田螺を鍋に入れ、蓋をして中弱火で10分煮込む","煮込む間は頻繁に動かさず、餡が6〜7割固まったら軽く返す","蓋を開け、残りのミントとシソを加え、さらに2〜3分煮込む","強火で煮詰めてとろみが出たら完成"]'::jsonb, '["肉料理","香ばしい","詰め物料理","煮込み","広西料理","おもてなし"]'::jsonb),
  ('howtocook:meat_dish/番茄红酱', 'ja', 'トマトソース', '肉料理', 'このイタリア風ソースは香り高く美味しく、野菜と牛肉の組み合わせが豊かな食感を生み出します。タンパク質と各種ビタミンが豊富で、栄養バランスが良好です。調理プロセスはやや手間がかかり、牛肉をパラパラに炒める技術や火加減を調整しながらじっくり煮るなどの基本的な調理スキルが必要です。下ごしらえから完成まで約1時間かかり、一度に多めに作って冷凍保存すれば、必要な時に取り出して使えて非常に便利です。', '[{"name":"挽き肉","unit":"g"},{"name":"にんにく","unit":"個"},{"name":"にんじん","unit":"本"},{"name":"セロリ","unit":"本"},{"name":"玉ねぎ","unit":"個"},{"name":"オリーブオイル","unit":"ml"},{"name":"砂糖","unit":"g"},{"name":"塩","unit":"g"},{"name":"黒コショウ","unit":"g"},{"name":"トマトソース","unit":"g"},{"name":"牛乳","unit":"ml"},{"name":"乾燥バジルまたはタイム（お好みで）","unit":"","note":"適量"}]'::jsonb, '["ニンジン、セロリ、タマネギをみじん切りにし、ニンニクはスライスする。","オリーブオイル10mlを加え、熱した油に野菜を入れ、強火で炒めて色が変わったら取り出す。","鍋にさらにオリーブオイル10mlを加え、ニンニクを10秒炒め、挽き肉、砂糖、塩、黒コショウ、ハーブを加えて牛肉がパラパラになるまで炒める。","炒めた野菜とトマトソースを加えてさらに炒め、よく混ぜ合わせる。","牛乳を数回に分けてゆっくりと加え、中弱火で30分煮込んで完成。"]'::jsonb, '["肉料理","イタリア風","煮込み","ソースの香り","副菜","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/瘦肉土豆片/瘦肉土豆片', 'ja', '豚肉とジャガイモの炒め物', '肉料理', '手早く作れる家庭料理の炒め物。肉はなめらかで柔らかく、ジャガイモはしっとりと味が染み込み、ニンニクの芽の香りが広がる、典型的な家庭料理のスタイルです。豚肉には良質なタンパク質と鉄分が豊富に含まれ、ジャガイモは炭水化物と食物繊維を提供し、バランスが良いです。調理工程はシンプルで、包丁さばきと火加減に注意が必要です。初心者でもある程度の基礎があれば挑戦できます。材料の準備から仕上げまで、約1時間で完成します。', '[{"name":"豚赤身肉","unit":"g"},{"name":"ジャガイモ","unit":"g"},{"name":"ニンニクの芽","unit":"本"},{"name":"片栗粉","unit":"g"},{"name":"醤油","unit":"g"},{"name":"老抽","unit":"g"},{"name":"食塩","unit":"g"},{"name":"サラダ油","unit":"ml"}]'::jsonb, '["ジャガイモの皮をむき、半分に切ってから、約2mmの薄切りにし、準備する。","ニンニクの芽を洗い、約1cmの長さに切り、準備する。","豚肉を洗い、約2mmの薄切りにしてボウルに入れ、片栗粉5g、醤油5g、老抽3gを加えて10分間漬け込む。","豚肉を漬けている間に、お湯を沸かし、ジャガイモの薄切りを入れて、約5分間下茹でする。","フライパンを熱し、サラダ油10ml～15mlを入れる。10秒待って油の温度を上げる。","豚肉を入れ、色が変わるまで炒め、ニンニクの芽を加えて一緒に炒める。ニンニクの芽を約20秒炒める。","ジャガイモを加え、炒め続け、食塩2g、醤油5gを加える。","約3分炒めて、皿に盛る。"]'::jsonb, '["肉料理","家庭料理","時短","炒め物","ご飯が進む","さわやかな香り"]'::jsonb),
  ('howtocook:meat_dish/白菜猪肉炖粉条', 'ja', '白菜と豚肉の春雨煮込み', '肉料理', '白菜と豚肉の春雨煮込みは東北地方の代表的な家庭料理です。スープは濃厚で塩味と旨味があり、豚バラ肉はとろけるように柔らかく、春雨は肉の旨味を吸ってコシがあり味がしみています。白菜は甘みがあってさっぱりしています。肉と野菜のバランスが良く、タンパク質、ビタミン、炭水化物が摂れて栄養満点で満腹感も得られます。調理には少し忍耐が必要で、特に春雨の処理と煮込みの火加減は初心者にはやや難しいかもしれませんが、手順通りに進めば失敗しにくく、最初から最後まで約45分で食卓に出せます。', '[{"name":"豚バラ肉","unit":"g"},{"name":"白菜","unit":"g"},{"name":"じゃがいも春雨（乾燥）","unit":"g"},{"name":"十三香（スパイスミックス）","unit":"g"},{"name":"鶏がらスープの素","unit":"g"},{"name":"食塩","unit":"g"},{"name":"老抽（濃い醤油）","unit":"ml"},{"name":"生抽（薄口醤油）","unit":"ml"}]'::jsonb, '["鍋で湯を沸かし、沸騰したら乾燥春雨を入れて5分煮る。その後、水ごと容器に移し、蓋をしてさらに浸しておく（最初にこれを行い、その間に次の手順を進める）","豚バラ肉を3mm幅に切り、準備する","白菜の柔らかい葉と芯の部分を分け、それぞれを2つに切っておく","鍋を熱し、食用油10～15mlを入れる。10秒待って油の温度を上げる","豚バラ肉を入れ、肉の色が変わるまで炒める","老抽（濃い醤油）を加え、1分炒めて肉に色をつける","白菜の芯の部分を加え、食塩、生抽（薄口醤油）を加えて1分炒める（鍋にくっつくようなら水10mlを加える）","すべての食材が浸る程度の水を加え、鶏がらスープの素、十三香を加える。沸騰したら火を弱めて20分待つ","春雨の水気を切り、短く切ってボウルに入れておく","白菜の柔らかい葉を加え、さっと混ぜたら春雨を上にのせる。蓋をしてさらに5分煮る","味を調え、火を止めて、汁気を煮詰める"]'::jsonb, '["肉料理","東北料理","家庭的な煮込み料理","塩味と旨味","ご飯が進む","肉と野菜のバランス"]'::jsonb),
  ('howtocook:meat_dish/空气炸锅脆皮现腌炸鸡/空气炸锅脆皮现腌炸鸡', 'ja', 'エアフライヤーカリカリ即席漬け込み唐揚げ', '肉料理', 'エアフライヤー唐揚げは、先に漬け込んでから揚げる家庭的な肉料理です。外はカリカリ、中はジューシーで、味付けは好みに合わせて変えられます。手羽先は良質なタンパク質と脂質が豊富で、メインのおかずや軽食に適しています。実際の作業時間は約55～70分（1回衣付けの場合；2回衣付けの場合は約70～90分）。最高の結果を求める場合は、冷蔵庫で一晩漬け込む（前日に準備し、翌日に揚げる）ことをお勧めします。', '[{"name":"手羽中","unit":"個"},{"name":"醤油","unit":"ml"},{"name":"ガーリックパウダー","unit":"g"},{"name":"パプリカパウダー","unit":"g"},{"name":"オニオンパウダー","unit":"g"},{"name":"黒こしょう","unit":"g"},{"name":"中力粉","unit":"g"},{"name":"片栗粉","unit":"g"},{"name":"食用油","unit":"ml"},{"name":"ヨーグルトまたは牛乳","unit":"ml"},{"name":"卵","unit":"個"},{"name":"ベーキングパウダー","unit":"g"}]'::jsonb, '["手羽中を洗って水気を拭き取り、各手羽に両面2本ずつ切り込みを入れて味が染み込みやすくします。","漬けダレを作る：醤油15ml、ガーリックパウダー8g、パプリカパウダー5g、オニオンパウダー3g、黒こしょう3g、牛乳またはギリシャヨーグルト5ml（お好みで、鶏肉をより柔らかくする）を混ぜ合わせます。","漬けダレと手羽中を大きめのジップロック袋に入れ、よく揉み込み、冷蔵庫で一晩置きます。","衣の粉：中力粉60g、片栗粉30g、ガーリックパウダー5g、パプリカパウダー5g、オニオンパウダー2g、黒こしょう2g、ベーキングパウダー1g（お好みで、衣をよりカリカリにする）を混ぜ合わせます。","衣の液（お好みで）：卵1個、牛乳または水5mlをよく溶きます。","衣付け：手羽中の水気を軽く拭き取り、粉の衣に押し付けてから余分な粉をはたき落とし、10分ほど置きます。","衣の液（お好みで）：より厚い衣にしたい場合は、液をくぐらせてから再度粉の衣を付けます。","粉の衣を付けて置いた手羽先を液の衣にくぐらせ、余分な液を軽く落とします。","再び粉の衣に入れ、軽く押さえ、余分な粉をはたき落とします。","20分ほど置きます（可能であればさらに長く置くと、衣がしっかり付き剥がれにくくなります）。","エアフライヤーを180°Cに予熱し、5分予熱します。","バスケットに薄く油を塗り、皮目を下にして手羽先を並べ、手羽先の上にも薄く油をスプレーまたは塗ります。","エアフライヤーを180°Cに設定し、まず10分加熱します。","バスケットを開けて裏返し、手羽先の表面に再度薄く油をスプレーまたは塗り、さらに180°Cで6分加熱します。","皮の色を確認し、最も厚い部分に竹串を刺して血が出てこないか確認します。","必要に応じて200°Cで1～2分追加加熱してカリッと色付けします（繰り返し可能。まず1分加熱して様子を見てから続けるか判断します）。"]'::jsonb, '["肉料理","カリカリ","ガーリック風味","エアフライヤー","家庭料理","主菜"]'::jsonb),
  ('howtocook:meat_dish/粉蒸肉', 'ja', '粉蒸肉', '肉料理', '粉蒸肉は、中国の代表的な蒸し料理で、香り豊かで、柔らかくもちもちとした食感が特徴で、広く親しまれている家庭料理です。豚バラ肉は良質なタンパク質と脂質を提供し、ジャガイモなどの根菜と組み合わせることで栄養バランスが良くなります。この料理はある程度の調理経験がある方に適しており、準備から完成まで約90分かかります。', '[{"name":"豚バラ肉","unit":"g"},{"name":"蒸し肉用米粉","unit":"g"},{"name":"薄口醤油","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"料理酒","unit":"ml"},{"name":"郷県豆板醤","unit":"g"},{"name":"生姜のみじん切り","unit":"g"},{"name":"ニンニクのみじん切り","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"ジャガイモまたはカボチャ","unit":"g"},{"name":"水","unit":"ml"}]'::jsonb, '["豚バラ肉を洗い、長さ約5cm、幅約3cm、厚さ約0.5cmの薄切りにする","生姜とニンニクを直径1mm以下の粒になるように細かく刻む","大きめのボウルに、切った豚バラ肉、薄口醤油15ml、濃口醤油10ml、料理酒15ml、郷県豆板醤10g、生姜のみじん切り10g、ニンニクのみじん切り10g、砂糖5gを入れる","箸でよく混ぜ、ラップをかけ、室温（20°C〜25°C）で30分間漬け込む","漬け込みが終わったら、蒸し肉用米粉100gを加え、さらに2分間混ぜ、肉の一枚一枚に均等に米粉がまぶされるようにする","ジャガイモの皮をむき、厚さ0.8cm、面積約5cm×5cmの大きさに切り、重量300gになるように調整する","直径20cmの深めのボウルの底に、ジャガイモのスライスを重ならないように敷き詰める","米粉をまぶした豚バラ肉をジャガイモの上に均等に並べ、軽く押し固める","蒸し器に水2000mlを入れ、火にかけて水面が持続的に泡立つまで加熱する（100°C）","食材を入れたボウルを蒸し器に入れ、蓋をする","中火で60分蒸す（沸騰が続く程度の火力、約600Wの熱出力に相当）","時間が経ったら、箸を肉の中央に刺し、すっと通って抵抗がなければ蒸し上がった状態","その状態でなければ、さらに10〜15分加熱し、肉が柔らかくなり脂が滲み出るまで続ける","取り出して器に盛り、そのまま食べる"]'::jsonb, '["肉料理","四川料理","蒸し料理","やわらかもちもち","ご飯が進む","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/糖醋排骨/糖醋排骨', 'ja', 'スペアリブの甘酢あん', '肉料理', 'スペアリブの甘酢あんは、甘酸っぱくて外はカリッと中はジューシーな伝統的な名物料理で、広く親しまれています。スペアリブには良質なタンパク質とカルシウムが豊富に含まれており、栄養補給にも優れています。この料理は、下茹で、揚げ、飴色炒め、煮詰めなど複数の工程があり、火加減と調味料の加減が肝心です。初心者には少し難しいかもしれませんが、最適化された手順に従えば成功率は高いです。調理時間は約45分です。', '[{"name":"スペアリブ","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"サラダ油","unit":"ml"},{"name":"薄口醤油","unit":"ml"},{"name":"オイスターソース","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"鶏がらスープの素","unit":"g"},{"name":"生姜スライス","unit":"枚"},{"name":"ごま","unit":"g"},{"name":"ケチャップ","unit":"g"},{"name":"黒酢","unit":"ml"},{"name":"五香粉","unit":"g"}]'::jsonb, '["スペアリブと生姜スライスを冷水に入れ、強火で加熱して沸騰し泡がたくさん出てきたら中火にし、沸騰が続いたら弱火にして2〜3分下茹でし、取り出して水気を切る。","熱湯でスペアリブを2〜3回よく洗い、血のアクを完全に取り除く。","鍋に揚げ油を十分に入れ（油の量は鍋の大きさによるが、一般的な家庭では約300mlが目安）、油温が約170℃になったらスペアリブを入れ、表面が薄くきつね色になるまで3〜5分揚げ、取り出して油を切る。","別の清潔な鍋を弱火にかけ、熱湯50mlを加え、砂糖30gを入れて軽く混ぜながら完全に溶かし、薄く黄色くなるまで加熱する。この工程は砂糖の溶け具合を観察することがポイントで、色の変化にこだわりすぎない。","揚げたスペアリブを砂糖水の入った鍋に加え、手早く30秒炒めた後、香醋5ml、薄口醤油5ml、オイスターソース5ml、鶏がらスープの素2g、ケチャップ10g、五香粉0.5gを順に加え、さらに30秒炒めて調味料をスペアリブに絡める。その後、スペアリブがかぶる程度の熱湯を加える。","強火で鍋の中の液体を沸騰させたら、濃口醤油5mlを加えて色をつけ、手早く煮詰める。スペアリブの身が大きい場合は、弱火にして5〜10分ほど煮込むと味が染み込みやすい。中火で20分以上長時間煮込むと食感が損なわれるので注意。","器に盛り付け、ごま2gをふりかけて完成。"]'::jsonb, '["肉料理","甘酸っぱい","揚げ物","家庭料理","ご飯が進む","おもてなし"]'::jsonb),
  ('howtocook:meat_dish/糖醋里脊', 'ja', '甘酢あんかけ豚ヒレ肉', '肉料理', '糖醋里脊（甘酢あんかけ豚ヒレ肉）は甘酸っぱくて濃厚な味わいで、外はカリッと中は柔らかく、多くの地域の料理で広く愛される家庭的な味です。豚ヒレ肉は良質なタンパク質を提供しますが、衣をつけて揚げ、甘酢ソースをからめるため全体のカロリーは高めです。作る際には下味、二度揚げ、ソースの火加減をマスターする必要があり、初心者には少し難しいかもしれません。材料を事前に準備し、一気に仕上げることをおすすめします。準備から完成まで約45分から1時間かかります。', '[{"name":"豚ヒレ肉","unit":"g"},{"name":"酢","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"片栗粉","unit":"g"},{"name":"卵","unit":"g"},{"name":"薄口醤油","unit":"ml"},{"name":"料理酒","unit":"g"},{"name":"オイスターソース","unit":"g"},{"name":"ケチャップ","unit":"ml"},{"name":"白こしょう","unit":"g"},{"name":"塩","unit":"g"}]'::jsonb, '["豚ヒレ肉を厚めに切り、包丁の背で軽く叩いて肉を柔らかくします。指一本分の太さの棒状に切ります。料理酒、薄口醤油、オイスターソース、塩、白こしょう、卵1個を加え、手でよく混ぜて20分以上漬け込みます。","ソースを作る：ケチャップ+10gの酢+30gの砂糖+150mlの水を混ぜ、砂糖が溶けるまでかき混ぜ、取っておきます。","衣をつける：先にすべての肉に衣をつけてから揚げます。大きめのボウルに片栗粉を入れ、肉の棒1本1本に片栗粉をたっぷりとまぶします。","揚げる：油を160℃に熱し、豚ヒレ肉を入れます。乾いた箸を油に入れてみて、周りに小さな泡が出てきたら入れ時です。","表面が薄く色づくまで揚げて取り出します。中火で通し揚げします。その後、油を200℃に上げ、豚ヒレ肉を戻し入れて40秒だけ再揚げします。表面がカリッとなるのですぐに取り出します。","ソースを絡める：別の鍋に油を少々入れ、調合したソースを加えて沸騰させます。揚げた豚ヒレ肉を加えて炒め、すべての肉にソースが絡むようにします。","揚げた豚ヒレ肉を加えて炒め、火を止めて盛り付けます。"]'::jsonb, '["肉料理","甘酸っぱい","揚げ物","家庭料理","おもてなし","ご飯が進む"]'::jsonb),
  ('howtocook:meat_dish/红烧猪蹄/红烧猪蹄', 'ja', '豚足の醤油煮込み', '肉料理', '豚足の醤油煮込みは、濃厚なスープと柔らかくもちもちとした食感が特徴の定番家庭料理です。塩味と甘みがあり、ご飯が進みます。豚足はコラーゲンとタンパク質が豊富で栄養満点。初心者には少し難しいかもしれませんが、圧力鍋を使えば手順が簡略化でき、ある程度料理に慣れている方には作りやすい一品です。準備から完成まで約1時間かかります。', '[{"name":"豚足","unit":"本"},{"name":"ローリエ","unit":"枚"},{"name":"生姜","unit":"枚"},{"name":"ネギ","unit":"本"},{"name":"濃口醤油","unit":"ml"},{"name":"肉桂","unit":"個"},{"name":"氷砂糖","unit":"粒"},{"name":"料理酒","unit":"ml"},{"name":"薄口醤油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"八角","unit":"個"},{"name":"食用油","unit":"ml"}]'::jsonb, '["冷水の鍋に、親切な店員が切ってくれた豚足を入れ、料理酒20mlとネギ・生姜を加え、15分間茹でて血抜きをする。","熱した鍋に油を引き、食用油30mlを入れ、氷砂糖7〜8粒を加え、弱火で飴色になるまで炒める。その間、ヘラで氷砂糖を潰しながら、約2分間炒める。","飴色になったら、下茹でした豚足を加え、弱火のまま炒め、全体が薄く色づくまで炒める。","ローリエ2枚、肉桂1個、八角4個、薄口醤油20ml、濃口醤油20ml、料理酒10ml、生姜3枚、塩8gを加え、中火に変えて1分間炒める。","熱湯または冷水を豚足が浸るまで加え、蓋をして強火で沸騰させ、沸騰したら火を止める。","鍋の中身をすべて圧力鍋に移し、圧力鍋で15分間加圧調理する（圧力鍋がない場合は、鍋のまま強火から弱火にして煮込んでもよい）。","15分後、圧力鍋の食材を炒め鍋に移し、強火で煮詰める。この時、箸で味見をし、薄ければ塩2〜3gを加える。","煮詰める時間は鍋の水分量によるが、通常30秒程度。少し残っても構わない。豚足の煮汁もご飯が進む。"]'::jsonb, '["肉料理","塩味と香り","やわらかもちもち","醤油煮込み","ご飯が進む","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/红烧肉/南派红烧肉', 'ja', '南派風紅焼き肉', '肉料理', 'この紅焼き肉は出来上がりが赤く艶やかで、脂身は口の中でとろけ、赤身はほろほろでパサつかず、甘じょっぱい味わいが特徴の典型的な南方風味です。豚バラ肉は良質なタンパク質とコラーゲンが豊富で、香辛料が臭みを消し体を温めます。砂糖色を炒めてじっくり煮込む手間はかかりますが、各工程をわかりやすく解説しているので初心者でも成功間違いなし。全行程約1.5時間で食卓に並びます。', '[{"name":"豚バラ肉","unit":"g"},{"name":"油","unit":"ml"},{"name":"氷砂糖","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"濃口醤油","unit":"ml"},{"name":"料理酒","unit":"ml"},{"name":"ローリエ","unit":"枚"},{"name":"八角","unit":"個"},{"name":"生姜","unit":"枚"},{"name":"ネギ","unit":"g"},{"name":"ニンニク","unit":"g"},{"name":"塩","unit":"g"},{"name":"花椒","unit":"g"},{"name":"冷水","unit":"ml","note":"材料が浸る程度"},{"name":"お湯","unit":"ml","note":"材料が浸る程度"}]'::jsonb, '["豚バラ肉は最初から小さく切らず、鍋に入る大きさのブロック（約5～6cm幅）に切る","生姜は薄切りにする（1枚約3mm厚）","お湯を沸かす","冷水は水道水でOK","ネギは白い部分を小口切りにする（万能ネギがベスト、長ネギでも可）","ニンニクは半分に切る（潰さないこと。潰すと後で取り出しにくく、煮詰める際に味を損ねる）","薬味を2つの「準備パック」に分ける：","Aパック（臭み取り用）：生姜2枚、ネギの白い部分2節","Bパック（煮込み用）：残りの生姜4枚、ネギの白い部分、ニンニク、花椒、八角、ローリエをまとめて小鉢に入れておく","冷水の鍋に豚バラ肉のブロックを入れ、料理酒20mlとAパック（生姜2枚、ネギ2節）を加えて15分茹でて血抜きをし、取り出して洗う","茹でた豚バラ肉を取り出し、少し冷まして（手で触れる程度）、一辺約3cm×3cm×3cmの立方体に切る（茹でると肉が締まり、生のまま切るより切りやすく、出来上がりの大きさが均一。3cmのサイズは最終的に約2.5cmになり、口当たりが良く火の通りも均一）","別の鍋で砂糖色を炒める。注意：このレシピでは「操作2」の方法で行う。砂糖液に細かい泡が立ち始めたら、すぐにBパック（生姜、ネギ、ニンニク、花椒、八角、ローリエ）を鍋に加えて香りを爆発させる","香りが立ったら（約5～10秒以内）、お湯はまだ加えず、すぐに茹でた豚バラ肉を鍋に入れて強火で炒め、肉全体に砂糖色を絡めて油を出す。肉の香りがしてきたら、お湯を肉がすべて浸るまで注ぎ、蓋をして中弱火で50～60分煮込む（圧力鍋の場合は40分）","料理酒10mlを加える","蓋をして沸騰させたら、25分ごとに蓋を開けて表面の脂とアクをすくい取る","水の量が肉の高さと鍋底の高さの3/5になったら中火にし、肉と水以外のすべての薬味を取り出して、煮詰め始める","蓋を開け、汁気がほとんどなくなってとろみがついたら火を止めて盛り付ける（絶対に煮詰めすぎないこと）"]'::jsonb, '["肉料理","南方風味","紅焼き","甘口","ご飯が進む","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/红烧肉/简易红烧肉', 'ja', '簡易紅焼き肉', '肉料理', 'この家庭的な美味しさは、色合いが赤く艶やかで、口当たりは柔らかく、脂身はしつこくなく、醤油の香りが豊かで、ご飯にぴったりです。豚バラ肉は良質なタンパク質と必須脂肪酸を提供し、うずらの卵や湯葉を加えると栄養バランスがさらに良くなります。作り方は初心者にも優しく、準備から完成まで約1.5時間です。', '[{"name":"豚バラ肉","unit":"斤"},{"name":"うずらの卵または鶏卵","unit":"個"},{"name":"湯葉","unit":"克"},{"name":"生姜","unit":"片"},{"name":"氷砂糖","unit":"克"},{"name":"薄口醤油","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"料理酒","unit":"ml"},{"name":"ローリエ","unit":"枚"},{"name":"八角","unit":"個"},{"name":"塩","unit":"克"},{"name":"水","unit":"ml"},{"name":"ネギ","unit":"","note":"長ネギの白い部分、適量"}]'::jsonb, '["豚バラ肉を大きめに切る（約4.5cm、冷凍30分～1時間すると切りやすい）","湯葉を幅2cmに切る","生姜をスライス（1枚の厚さ約3mm）","お湯を沸かす","うずらの卵を茹でて、フォークや爪楊枝で穴を開ける（できるだけ多く刺すと味が染みやすい）","長ネギの白い部分（白ネギ）","冷水の鍋に切った豚バラ肉を入れ、料理酒とネギ・生姜を加えて15分煮て血抜きする","鍋に生姜2枚を入れて風味付け","中弱火にして直接豚バラ肉を入れ、食用油は不要。各面を焼き、油が出てくるまで焼く","焼き出した油を取り出して別に置き、豚バラ肉を端に寄せ、氷砂糖15gを加えて溶けるまで炒める","溶けたら豚バラ肉と氷砂糖を炒めて色を付け、加える","薄口醤油10ml","濃口醤油15ml","料理酒5ml","色が付くまで炒める","沸かしたお湯を加えて40分煮込む（包丁が苦手な人は大きめに切っているので、時間を延ばすこと）。さらに加える：","生姜2枚","ローリエ3枚","八角2個","蓋をして沸騰したら、茹でて穴を開けたうずらの卵と湯葉を加え、中弱火で40分待つ（途中適宜混ぜて焦げ付き防止）","蓋を開け、汁がほとんどなくなるまで強火で煮詰める（絶対に煮詰め過ぎないこと）","塩2～3gを加え、ひと炒めして完成"]'::jsonb, '["肉料理","家庭料理","ご飯が進む","煮込み","醤油風味","柔らか"]'::jsonb),
  ('howtocook:meat_dish/红烧鸡翅', 'ja', '紅焼きチキンウイング', '肉料理', '紅焼きチキンウイングは、家庭料理の定番おかずです。塩味と甘みがあり、色は赤く輝き、肉は柔らかくて骨から外れやすいです。鶏手羽先は良質なタンパク質とコラーゲンを豊富に含み、栄養が吸収されやすいです。調理の難易度は適度で、初心者でも手順通りに進めればうまく作れます。下ごしらえから完成まで約40分かかります。', '[{"name":"新鮮な鶏手羽先","unit":"g"},{"name":"生姜（薄切り）","unit":"g"},{"name":"ねぎ（ぶつ切り）","unit":"g"},{"name":"にんにく","unit":"g"},{"name":"ローリエ","unit":"枚"},{"name":"八角","unit":"個"},{"name":"乾燥唐辛子","unit":"本"},{"name":"氷砂糖","unit":"g"},{"name":"黄酒または料理酒","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"胡椒","unit":"g"},{"name":"白ごま","unit":"g"},{"name":"小口切りの青ネギ","unit":"g"},{"name":"食用油","unit":"ml"}]'::jsonb, '["鶏手羽先を洗います。包丁で手羽先の厚い部分に3本の切り込みを入れ、裏側に1本切り込みを入れて味を染み込みやすくします。","手羽先が新鮮でない場合は、切り込みを入れた後、生姜水に10～20分浸してください。","生姜10g（3～4枚）、ネギ15g（2～3切れ）を用意します。ニンニク3～4片（約15g）は包丁で潰します（みじん切り不要）。ローリエ1枚、八角1個、乾燥唐辛子2本（お好みで）をまとめて用意します。","鍋を火にかけ、手羽先が浸かるくらいの水を入れ、冷水の状態で手羽先を入れます。黄酒または料理酒20ml、生姜2枚（約5g）を加え、強火で沸騰させます。沸騰したらそのまま強火で2～3分煮続け、アクを取ります。","煮上がった手羽先を取り出し、ぬるま湯で2回洗って血のアクを完全に取り除き、水気を切っておきます。","別の鍋を火にかけて熱し、食用油10～15mlを入れます。","油の温度が5割程度になったら、氷砂糖15gを加え、強火で完全に溶かします。氷砂糖が溶けて色が変わったら弱火にし、さらに炒めて飴色が焦げ茶色になったら、すぐに水気を切った手羽先を入れ、1～2分素早く炒めて、均等に糖色を絡めます。","用意したローリエ1枚、八角1個、乾燥唐辛子2本（お好みで）、残りの生姜2枚（約5g）、ネギ15g、潰したニンニクを加え、さらに30秒炒めて香りを完全に出します。","鍋肌に沿って料理酒または黄酒15ml、醤油15mlを回し入れ、10秒素早く炒めます。","ぬるま湯（50～60℃程度）を手羽先が少し浸かるくらい加えます。","濃口醤油5ml、塩3g、砂糖2g、胡椒1gを加え、炒め杓で軽く混ぜ合わせます。","蓋をして中火で7～8分煮ます。","蓋を開け、箸で鍋の中のローリエ、八角、生姜、ネギ、ニンニクを取り出して捨てます。","強火にし、絶えず炒めながら、煮汁がとろみがつくまで（約1～2分）煮詰めます。","火を止め、手羽先を皿に盛り、鍋に残ったとろみのある煮汁をかけます。","最後に白ごま3gと小口切りの青ネギ5gを散らして完成です。"]'::jsonb, '["肉料理","家庭料理","おかず","塩味と甘み","紅焼き","おもてなし"]'::jsonb),
  ('howtocook:meat_dish/羊排焖面/羊排焖面', 'ja', 'ラム肉の蒸し麺', '肉料理', 'ラム肉の蒸し麺は、肉の香り豊かで麺がコシのある北方の家庭料理の定番です。ラム肉は柔らかく煮込まれ、幅広の麺がたっぷりとスープを吸って、一口ごとに満足感があります。肉、麺、野菜が一度に摂れ、食事としてタンパク質、炭水化物、脂質をバランスよく補えます。調理はまずラム肉を煮込み、その後麺をこねて蒸し上げる手順で、やや手間がかかるため、ある程度料理経験のある方に適しています。全工程で約1時間半かかります。', '[{"name":"皮付きラムリブ肉","unit":"g","note":""},{"name":"青椒","unit":"個","note":""},{"name":"パプリカ","unit":"個","note":""},{"name":"長ネギ","unit":"","note":"適量"},{"name":"花椒","unit":"","note":"適量"},{"name":"乾燥唐辛子","unit":"","note":"適量"},{"name":"生姜","unit":"枚","note":""},{"name":"白砂糖","unit":"","note":"適量"},{"name":"老抽","unit":"","note":"適量"},{"name":"塩","unit":"","note":"適量"},{"name":"食用油","unit":"","note":"適量、多めでも大丈夫"}]'::jsonb, '["ラム肉を冷水から鍋に入れて下茹でし、沸騰したらアクをすくい取り、ラム肉を取り出します。","生姜（4枚）を切り、乾燥唐辛子と花椒を器に入れて用意します。","炒め鍋に油を加えます。（多めでも大丈夫です。）","油が熱くなったら、白砂糖を加え、ラム肉にキャラメル色がつくまで炒めます。","ラム肉の水分が飛んだら、塩、老抽、そして用意した調味料を加えます。","ラム肉が浸るくらいの水を加え、強火で沸騰させたら、さらに10分煮ます。その後、弱火で30分煮込みます。","その間に麺をこねます。麺の量と作り方は別途記載（注1）を参照してください。","青椒、パプリカ、長ネギ、そして麺皮を加えて炒めます。","全体がよく混ざったら、火を止めて完成です。"]'::jsonb, '["肉料理","旨味","蒸し煮","北方","家庭料理","しっかりおかず"]'::jsonb),
  ('howtocook:meat_dish/老妈蹄花/老妈蹄花', 'ja', 'ママの豚足煮', '肉料理', 'スープは白く、豚足は柔らかく骨から外れ、なめらかな食感。酸辣のタレで食欲をそそる四川風家庭料理。コラーゲン豊富で白インゲン豆がとろっとした食感を加える。圧力鍋と事前浸漬が必要だが、手順通りにやればマスターできる。浸漬と加圧調理を含め約2時間（白インゲン豆の一晩浸漬時間は除く）。', '[{"name":"豚足","unit":"本"},{"name":"ネギ","unit":"グラム"},{"name":"生姜","unit":"グラム"},{"name":"料理酒","note":"適量"},{"name":"薄口醤油","unit":"グラム"},{"name":"ビャクシ","note":"適量"},{"name":"トウキ","unit":"グラム"},{"name":"チキンエキス","unit":"グラム"},{"name":"塩","note":"適量"},{"name":"ニンニク","unit":"グラム"},{"name":"赤唐辛子","note":"適量"},{"name":"白胡椒","unit":"グラム"},{"name":"黒酢","note":"適量"},{"name":"花椒油","note":"適量"},{"name":"辣油","note":"適量"},{"name":"白インゲン豆","unit":"グラム"}]'::jsonb, '["白インゲン豆200gを前の晩から水に浸けておく","豚の前足を用意する（買うときに真ん中から割ってもらい、バーナーで毛根を焼き、家で洗う）","冷水の鍋に豚足、ネギのぶつ切り、生姜スライス、料理酒を入れ、10分下茹でする。アクを取り、取り出して洗っておく","圧力鍋に豚足、トウキ、ビャクシ、白胡椒、生姜スライスを入れ、加圧して30分。白インゲン豆を加えてさらに10分加圧。スープが白ければ成功（途中で水を足す場合は熱湯のみ）","蓋を開けて、塩、チキンエキス、ネギのみじん切りで味を調える","秘伝のタレを作る：ネギ、ニンニク、赤唐辛子、白胡椒、薄口醤油、黒酢、辣油、花椒油、豚足の煮汁を合わせる","秘伝のタレをかけて完成"]'::jsonb, '["肉料理","四川料理","煮込み","酸辣","家庭料理","おもてなし"]'::jsonb),
  ('howtocook:meat_dish/老式锅包肉/老式锅包肉', 'ja', '昔ながらの鍋包肉', '肉料理', '鍋包肉は東北の代表的な名物料理で、ハルビンの道台府が発祥。白酢で鮮やかな酸味を出し、外はサクサク、中はジューシーで甘酸っぱくさっぱり。豚肉は良質なたんぱく質を提供し、ネギや生姜などの野菜で食欲をそそる。この料理は衣付け、油温、二度揚げのテクニックが必要で、難易度は中級以上。初心者は根気よく練習が必要。漬け込みから揚げ、仕上げまでの調理時間は約90分。', '[{"name":"豚ロース肉","unit":"g"},{"name":"長ネギ","unit":"g"},{"name":"生姜","unit":"g"},{"name":"ニンニク","unit":"片"},{"name":"人参","unit":"g"},{"name":"パクチー","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"料理酒","unit":"ml"},{"name":"塩","unit":"g"},{"name":"味の素","unit":""},{"name":"じゃがいも澱粉","unit":"g"},{"name":"じゃがいも澱粉","unit":"g"},{"name":"中力粉","unit":"g"},{"name":"重曹","unit":"g"},{"name":"重曹","unit":"g"},{"name":"白ごま","unit":"g"},{"name":"食用油","unit":"ml"},{"name":"白酢","unit":"g"},{"name":"醤油","unit":"g"},{"name":"コーンスターチ","unit":"g"},{"name":"水","unit":"g"},{"name":"清水","unit":"ml"}]'::jsonb, '["豚肉の下処理：","豚のロース肉を厚さ8mmの均等な薄切りにし、白い筋を取り除く。","肉を清水で洗い、血抜きをする。","オプション：重曹5gを加えてよく揉み込み、5分間置く。","清水で1～2回洗い、余分な重曹を取り除く。","下味をつける：","肉に塩3g、料理酒5mlを加えて混ぜ、15分間漬け込む。","衣付け：","方法一（推奨）：","じゃがいも澱粉170gにたっぷりの清水を加えて混ぜ、60分間静置して澱粉を沈殿させる。","上澄みの清水をすべて捨て、底の澱粉ペースト（非ニュートン流体のような状態）を残す。","肉を入れ、清水5mlと食用油3mlを加えてよく混ぜる。","方法二：","じゃがいも澱粉210gと中力粉70gを混ぜる。","清水を少しずつ加え、ヨーグルト状になるまで混ぜる。持ち上げると糸を引き、ボウルの中で山ができるくらいにする。","食用油10mlと重曹1gを加えてよく混ぜる。","下味をつけた肉を衣の中に入れ、全体にまんべんなく絡める。","甘酢だれを作る：","砂糖65g、白酢55g、醤油4g、塩2gを混ぜてよく溶かし、置いておく。","オプション：水4g、コーンスターチ1.5gを加えると、たれにとろみがつく。","付け合わせの準備：","長ネギ、生姜、人参は千切りに、パクチーはざく切りに、ニンニクは薄切りにする。","肉を揚げる：","1回目の揚げ：","鍋に食用油を入れ、170℃（6分熱）に熱する。","肉を1枚ずつ油に入れ、表面が固まり、衣が箸につかず、肉が浮き上がり、薄い黄色になるまで揚げる（約30秒、肉の大きさによる）。取り出して置いておく。","2回目の揚げ：","油温を200℃（7分熱）に上げる。","すべての肉を油に入れ、外側が黄金色でサクサクになるまで揚げる（約30秒）。取り出して置いておく。","3回目の揚げ（オプション）：","油温を220℃（8分熱）に上げる。","肉をさっと再び揚げ、肉が黄色く透き通るまで（約30秒、油温の維持による）、サクサク感を増す。取り出して油を切る。","炒める：","鍋に油20mlを残し、作っておいた甘酢だれを入れ、強火で沸騰させ、とろみがつくまで煮詰める（約30～60秒）。","オプション：甘酢だれの半分を取り出しておくと、後の炒めがやりやすくなる。","揚げた肉、ネギの千切り、ニンニクの薄切り、人参の千切り、パクチーのざく切りを加え、先に取り出しておいた甘酢だれをかけ、手早く3回炒め合わせ、たれを肉に均等に絡める。","盛り付け：","鍋包肉を皿に盛り、白ごま（お好みで）をふりかけて、どうぞ。"]'::jsonb, '["肉料理","東北","甘酸っぱい","サクサク","揚げ物","おもてなし"]'::jsonb),
  ('howtocook:meat_dish/肉饼炖蛋', 'ja', '豚ひき肉の卵蒸し', '肉料理', '豚ひき肉の卵蒸しは、塩味と旨味が効いた滑らかでやわらかい伝統的な家庭料理です。肉団子がたっぷりとタレを吸い込み、その上に卵がのっていて、やわらかくてご飯が進みます。良質なタンパク質とさまざまなアミノ酸が豊富で、体力回復に役立ちます。作り方はとても簡単で、料理初心者にも優しく、準備から出来上がりまで約20分しかかかりません。', '[{"name":"豚ひき肉","unit":"g"},{"name":"卵","unit":"個"},{"name":"料理酒","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"白こしょう","unit":"g"},{"name":"ごま油","unit":"ml"}]'::jsonb, '["ボウルに豚ひき肉、料理酒、醤油、白こしょう、卵、ごま油を入れて、よく混ぜます。","味付けした豚ひき肉を皿に広げ、真ん中にスプーンでくぼみを作り、そこに卵1個を割り入れます。","鍋に水を1/4の高さまで入れ、沸騰したら皿を鍋に入れ、蓋をして15分蒸します。"]'::jsonb, '["肉料理","塩味","蒸し料理","家庭料理","ご飯に合う","簡単時短"]'::jsonb),
  ('howtocook:meat_dish/腐乳肉', 'ja', '腐乳肉', '肉料理', 'これは江南地方の定番家庭料理です。豚バラ肉を紅腐乳とじっくり煮込み、琥珀のように赤く輝く色合い。肉はとろけるほど柔らかく、甘じょっぱい酒の香りと豆の風味が舌の上で広がります。良質なタンパク質とビタミンB群が豊富で、弱火でじっくり煮ることで消化も良くなります。火加減と煮詰め加減に丁寧さが必要で、初心者にはやや難しい料理。調理時間は約1時間。', '[{"name":"皮付き豚バラ肉","unit":"g"},{"name":"紅腐乳","unit":"g"},{"name":"腐乳汁","unit":"ml"},{"name":"氷砂糖","unit":"g"},{"name":"老抽","unit":"ml"},{"name":"料理酒","unit":"ml"},{"name":"葱の白い部分","unit":"g"},{"name":"刻みネギ","unit":"g"},{"name":"生姜","unit":"g"},{"name":"水","unit":"ml"},{"name":"サラダ油","unit":"ml"}]'::jsonb, '["豚バラ肉を2.5cm角に切る","冷水に料理酒と生姜の薄切りを加え、豚肉を入れて火にかけ、沸騰したら取り出す","紅腐乳の固形と汁をペースト状に潰し、氷砂糖と老抽を加えてタレを作る","鍋に油を熱し、ネギの白い部分と生姜を香りが出るまで炒め、豚肉を加えて黄金色になるまで炒める","腐乳ダレを加えて炒め合わせ、熱湯を注いで蓋をする","弱火で40分煮込む","強火にして煮詰め、とろりとした大きな泡が出てきたら火を止める"]'::jsonb, '["肉料理","甘辛","煮込み","江南","ご飯が進む","おもてなし","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/芥末罗氏虾/芥末罗氏虾', 'ja', 'ローズシュリンプのわさび炒め', '肉料理', 'この料理は香ばしく辛みがあり、わさびの風味が豊かで、エビの身は締まって弾力があります。手早く作れる家庭向けの海鮮料理です。エビ自体は良質なタンパク質やカルシウムが豊富で脂質が少なく、わさびと合わせるとさっぱりとして食欲をそそります。中程度の難易度ですが、調味液の準備と火加減を守れば初心者でも手早く作れ、全体で約30分かかります。', '[{"name":"ローズシュリンプ","unit":"g"},{"name":"ニンニク","unit":"個"},{"name":"練りわさび","unit":"g"},{"name":"片栗粉","unit":"g"},{"name":"醤油","unit":"g"},{"name":"こしょう","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"オイスターソース","unit":"g"},{"name":"塩","unit":"g"},{"name":"唐辛子","unit":"個"},{"name":"バター","unit":"g"},{"name":"サラダ油","unit":"ml"}]'::jsonb, '["エビの下処理：","エビの背を切り開き、背わたと砂袋を取り除きます。腹側から切ると揚げたときに広がり、見た目がきれいになります。","水でよく洗い、水気を切ったら片栗粉をまぶしても、まぶさなくてもよい。","ニンニクと調味液の準備：","ニンニク2片をみじん切りにする。","調味液を作る。醤油、オイスターソース、砂糖、こしょう、塩を入れ、好みで練りわさびを絞り入れ、水で薄めて片栗粉を加えて溶かす。","炒め工程：","鍋を熱してサラダ油を入れ、鍋底を覆うくらいの量にする。","水気を切ったローズシュリンプを入れ、ゆっくりと焼き色をつける。","エビの油が出てきたら（鍋にたくさんの泡が出てくる）、準備したニンニクのみじん切りと唐辛子を加える。","ニンニクの香りが立ったら、バターを加える。","バターが溶けたら混ぜ合わせ、準備した調味液を加える。","蓋をして2分間煮込み、とろみが出たら火を止める。"]'::jsonb, '["肉料理","香ばしく辛みがある","炒め物","手早い家庭料理","海鮮","さっぱり"]'::jsonb),
  ('howtocook:meat_dish/茭白炒肉/茭白炒肉', 'ja', 'マコモタケの肉炒め', '肉料理', 'マコモタケの肉炒めは家庭料理のスピードおかずで、食感は柔らかくシャキシャキ、塩味と旨味が程よく、典型的な江南家庭の味わいです。マコモタケは食物繊維やビタミンが豊富で、赤身の肉と合わせることで良質なタンパク質を補い、栄養バランスが良い一品です。調理難易度は中程度で、初心者でも少し練習すれば習得できます。調理時間は約20分です。', '[{"name":"マコモタケ","unit":"本"},{"name":"赤身肉","unit":"g"},{"name":"片栗粉","unit":"g"},{"name":"サラダ油","unit":"ml"},{"name":"鶏がらスープの素","unit":"g"},{"name":"生姜","unit":"枚"},{"name":"ニンニク","unit":"個"},{"name":"料理酒","unit":"ml"},{"name":"塩","unit":"g"}]'::jsonb, '["マコモタケをスライスし、厚さは0.5cm。","赤身の肉を細切りにし、厚さ0.3～0.5cm。料理酒、片栗粉、塩、水を加えて混ぜる。","生姜はスライス、ニンニクはみじん切りにする。","鍋に湯を沸かし、マコモタケを入れて60～90秒茹で、取り出して水気を切る。","鍋にサラダ油15mlをひき、赤身の肉を入れて60秒ほど炒め、取り出す。","鍋にサラダ油15mlをひき、生姜とニンニクを30秒炒め、マコモタケを加えてさらに30秒炒める。","続いて肉を加えて60秒炒め、水20ml、塩、鶏がらスープの素を加えて60秒炒めて完成。"]'::jsonb, '["肉料理","塩味と旨味","炒め","家庭料理","スピード","江南"]'::jsonb),
  ('howtocook:meat_dish/荔枝肉/荔枝肉', 'ja', '荔枝肉', '肉料理', '荔枝肉は甘酸っぱくて香ばしい福州の伝統的な福建料理です。外はカリッと中はジューシーな肉塊が赤く光るタレに絡み、フルーツが爽やかな甘みを加えます。豚赤身肉は良質なタンパク質が豊富で、パイナップルには食物繊維とビタミンが含まれ、食欲を促進し脂っこさを和らげます。調理では肉を切り、衣をつけ、二度揚げする必要があり、やや挑戦的ですが手順は明確で、ある程度料理経験のある方に適しています。約45分で食卓に並べられます。', '[{"name":"豚赤身肉","unit":"克"},{"name":"パイナップル","unit":"克"},{"name":"卵","unit":"个"},{"name":"食用油","unit":"ml"},{"name":"白砂糖","unit":"克"},{"name":"でんぷん","unit":"克"},{"name":"薄口醤油","unit":"ml"},{"name":"鶏ガラスープの素","unit":"克"},{"name":"生姜みじん切り","unit":"克"},{"name":"ごま","unit":"克"},{"name":"トマトケチャップ","unit":"克"},{"name":"香醋","unit":"ml"}]'::jsonb, '["瘦肉を一口大（2～3cm）に切り、ボウルに入れ、卵1個、でんぷん50g、薄口醤油3ml、鶏ガラスープの素2gを加える。","よく混ぜ、でんぷんが瘦肉に絡むまで混ぜる（緩すぎればでんぷんを追加、固すぎれば水を追加）。その後、油5mlを加えてさらに混ぜ、置いておく。","別のボウルにトマトケチャップ、鶏ガラスープの素3g、薄口醤油2ml、生姜みじん切り、白砂糖、でんぷん10g、香醋、水200mlを入れてよく混ぜ、ソースを用意する。","パイナップルを切り、1.5～2cm角のものを6個用意する。","鍋に油500mlを入れて熱し、油がはねる音がするまで加熱する。","瘦肉を一つずつ鍋に入れる（決して一度に全部入れないこと）。それぞれの肉がくっつかないようにする。","すべての瘦肉を入れたら、30秒ごとにスプーンで裏返しながら、瘦肉の表面が黄金色になるまで揚げる。","瘦肉を取り出し、1分後に再び油鍋に入れて、表面がこんがり焦げ色になるまで揚げる。その後、取り出して大きめのボウルに入れておく。","鍋を熱し、ソースを入れて30秒後、瘦肉とパイナップルを加えてよく炒め、火を止める。","ごまを振りかける。"]'::jsonb, '["肉料理","甘酸っぱい","揚げ物","福建料理","家庭料理","ご飯のおかず"]'::jsonb),
  ('howtocook:meat_dish/荷兰豆炒腊肠/荷兰豆炒腊肠', 'ja', 'スナップエンドウとラーチャンの炒め物', '肉料理', 'スナップエンドウとラーチャンの炒め物は、さっぱりとした塩味香ばしい家庭料理です。ラーチャンの油が緑鮮やかなスナップエンドウを絡め、食感はシャキシャキでしつこくありません。スナップエンドウは良質なタンパク質と多種のビタミンが豊富で、免疫力向上に役立ちます。作り方は簡単で、包丁さばきもほとんど必要なく、初心者でもすぐに作れます。準備から完成まで約15分です。', '[{"name":"スナップエンドウ","unit":"個"},{"name":"ラーチャン","unit":"g"},{"name":"薄口醤油","unit":"ml"},{"name":"サラダ油","unit":"ml"}]'::jsonb, '["スナップエンドウのヘタを取り除きます。時間があれば、尾の部分も一緒に取り除きます。","ラーチャンを買う前に、お店の人に生か加熱済みか確認してください。生の場合は、事前に蒸しておきます。加熱済みの場合はそのまま使えます。","スナップエンドウを洗い、さっと茹でます（約45秒）。色が変わったら、冷水に取って水気を切ります。","鍋を熱し、サラダ油約10mlを入れます。10秒待って油の温度を上げます。","ラーチャンを入れ、弱火で炒めます。ラーチャンの端が少し反ってくるまで炒めます。ここは必ずごく弱火で行ってください。焦げやすいので注意。","スナップエンドウを加え、中強火にします。30秒炒めたら薄口醤油を加え、さらに20～30秒炒めて完成です。"]'::jsonb, '["肉料理","塩味香ばしい","炒め物","家庭料理","時短","ご飯に合う"]'::jsonb),
  ('howtocook:meat_dish/萝卜炖羊排', 'ja', '大根とラムリブの煮込み', '肉料理', 'このスープ料理はあっさりとして脂っこくなく、羊肉は柔らかく味が染み込み、大根はスープを吸って甘くてとろける。北国の冬によく見られる家庭の温まる料理。羊肉には良質なタンパク質と鉄分が豊富で、大根にはビタミンと食物繊維が含まれ、一緒に食べると胃腸を温め、寒さを払い消化を助ける。下茹でで臭みを取り、2回煮込む工程があるが、手順は明確で初心者でも簡単に作れる。全体で約2時間かかるが、圧力鍋を使えば約1時間に短縮できる。', '[{"name":"ラムリブ","unit":"グラム"},{"name":"大根","unit":"本"},{"name":"長ねぎ","unit":"本"},{"name":"花椒","unit":"粒"},{"name":"白芷","note":"お好みで、適量"},{"name":"生姜","unit":"グラム"},{"name":"酒（料理酒または黄酒）","unit":"ミリリットル"},{"name":"食塩","unit":"グラム"},{"name":"氷砂糖","unit":"粒"},{"name":"水","unit":"ミリリットル"}]'::jsonb, '["大根の皮をむき、乱切りで3～5cmの大きさに切っておく。","ラムリブは購入時にカットしてもらうと良い（家庭用の包丁では切りにくいため）。そのまま用意する。","羊肉を冷水から鍋に入れ、酒の半量と長ねぎ・生姜の半量を加えて10分間茹で、血抜きをする（お好みで、茹でている間に浮かぶアクをすくい取る）。","別の鍋に冷水を入れ、切った大根を加え、氷砂糖の半量を入れて、沸騰してから5分間茹で、大根の辛みを抜く。","下茹でしたラムリブを取り出し、圧力鍋に入れ、食材がかぶるくらいの水を加え、さらに約300mlの水を足す。","残りの長ねぎ・生姜・酒、花椒、氷砂糖、白芷（お好みで）、塩を鍋に入れ、蓋をして蒸気が上がったら中火で約15分間煮込む。","圧力鍋がない場合は、普通の鍋で約40分～1時間煮込む。","火を止め、圧力鍋の蒸気が完全に抜けるまで待ち、蓋を開ける。先に下茹でした大根を加え、味を調え、3～10gの塩または水を加え、スープの塩加減を味見する。","再び火をつけ、中火で圧力鍋は蒸気が上がってから10分、普通の鍋は蓋をして20分間煮込む。","火を止め、器に盛る。"]'::jsonb, '["肉料理","香ばしい","煮込み","北方","温まる","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/蒜苔炒肉末', 'ja', 'にんにくの芽と豚バラ肉の炒め物', '肉料理', 'にんにくの芽と豚バラ肉の炒め物は北方の家庭料理で、塩味と旨味があり、シャキシャキとした食感、にんにくの香りが豊かです。にんにくの芽には食物繊維とビタミンが豊富で、豚バラ肉はたんぱく質を提供し、肉と野菜のバランスが良いです。作り方は簡単で、準備も楽で、初心者でもすぐに作れます。切ってから盛り付けるまで約10分しかかかりません。', '[{"name":"豚バラ肉の薄切り","unit":"枚"},{"name":"にんにくの芽","unit":"束"},{"name":"にんにく","unit":"片"},{"name":"醤油","unit":"ml"},{"name":"サラダ油","unit":"ml"},{"name":"塩","unit":"グラム"}]'::jsonb, '["にんにくの芽を5cmの長さに切り、準備しておく","豚バラ肉を5mm×5cmの細切りにし、準備しておく","にんにくを潰してみじん切りにし、準備しておく","鍋を熱し、サラダ油10mlを入れる。10秒待って油の温度を上げる","にんにくのみじん切りを入れ、中火で10秒炒めて香りを出す","豚バラ肉と醤油5mlを加え、中火で30秒炒めて肉に火を通し色をつける","にんにくの芽を鍋に入れ、醤油10mlを加えて30秒炒める","水20gを加え、中火で5分炒めてにんにくの芽が少し柔らかくなるまで炒める","最後に塩2gを加え、中火で30秒炒めて、火を止めて皿に盛る"]'::jsonb, '["肉料理","塩味と旨味","強火で炒める","北方の家庭料理","ご飯が進む","簡単"]'::jsonb),
  ('howtocook:meat_dish/虎皮肘子', 'ja', '虎皮の豚肘', '肉料理', 'この料理は、出来上がりが赤く輝き、豚皮が魅力的な虎皮模様になり、口の中でとろけるほど柔らかく、脂っこくなく、赤身はほろほろとしています。伝統的な中国のおもてなし料理です。豚肘はコラーゲンと良質なタンパク質が豊富で、長時間煮込むことで吸収されやすくなり、肌や関節に良いとされています。皮を焼く、揚げる、飴色をつける、圧力鍋で煮込むなど複数の工程があり、初心者には難しいので、ある程度料理経験がある方におすすめです。下準備から食卓に並ぶまで、約2.5時間かかります。', '[{"name":"豚前肘","unit":"個"},{"name":"サラダ油","unit":"ボトル"},{"name":"氷砂糖","unit":"ボトル"},{"name":"塩","unit":"小さじ"},{"name":"濃口醤油","unit":"小さじ"},{"name":"薄口醤油","unit":"大さじ"},{"name":"白酢","unit":"大さじ"},{"name":"ローリエ","unit":"枚"},{"name":"シナモンスティック","unit":"g"},{"name":"カルダモン","unit":"個"},{"name":"花椒","unit":"個"},{"name":"八角","unit":"個"},{"name":"片栗粉","unit":"大さじ"},{"name":"長ネギ","unit":"本"},{"name":"生姜","unit":"g"},{"name":"ニンニク","unit":"粒"},{"name":"水","unit":"ml"},{"name":"料理酒","unit":"大さじ"}]'::jsonb, '["豚肘を解凍し、1時間水に浸して血抜きをする。","火炎バーナーがあれば、豚肘の皮を焦がして茶黒くし、毛穴や汗腺を除去する。同じ場所を焼きすぎないように注意し、皮全体が茶黒くなったらやめる。","火炎バーナーがない場合、中華鍋を200℃以上に熱し、豚肘を鍋に入れ、ヘラや箸で皮を鍋の表面にしっかり接触させる。皮が焦げ茶色になったら場所を変え、全体をまんべんなく焼く。鍋の温度に注意し、赤熱させない。","水中でたわしを使って豚肘をこすり、表面の焦げた部分を取り除く。洗い終わると、豚肘は焼く前の状態に戻る。","豚肘を中華鍋に入れ、できるだけ多くの冷水を加える。鍋の深さと豚肘の大きさによるが、鍋と中身を持ち運べる範囲で、豚肘の3/4以上が浸かる量が最適。","ネギ1本の白い部分を3等分し、鍋に入れる。","ニンニク3粒を包丁の腹で潰し、鍋に入れる。","生姜3gを鍋に入れる。","料理酒大さじ2を鍋に加える。","鍋の水が沸騰したら5分待ち、豚肘を取り出し、鍋の中の調味料をすべて取り除く。煮汁は別の容器に移して取っておく。","鍋に冷たい油を加える。先ほどの水量を参考に、豚肘の3/5以上が浸かる量が良い。中火で加熱する。","油の温度が5割になったら弱火にし、豚肘を入れて揚げる。","揚げている間、調理者は安全に注意する。","揚げている間、ヘラなどの耐熱器具を使って、鍋の油を豚肘の浸かっていない部分に均等にかける。可能であれば3分おきに豚肘を返し、均一に揚げる。","揚げ時間は約20分。豚肘の皮全体が薄茶色になり、赤身の部分が少し焦げたら取り出す。","揚げた後の油は他の揚げ物に使えるが、何度も使わないように注意する。","飴色ソース200mlを用意する。","豚肘を圧力鍋に入れ、すべての煮汁、飴色ソース、ローリエ、シナモン、カルダモン、花椒、八角、濃口醤油、薄口醤油、白酢を加える。甘めが好きな場合は、さらに氷砂糖2～3gを加えてもよい。","ネギ1本の白い部分を3等分し、鍋に入れる。","ニンニク3粒を包丁の腹で潰し、鍋に入れる。","生姜3gを鍋に入れる。","蓋をし、加圧して40分煮込む。","煮込んでいる間に水溶き片栗粉を作る。ボウルに片栗粉大さじ1、水100mlを入れ、白い懸濁液になるまで混ぜる。","煮込みが終わったら、圧力鍋の蓋を開け、鍋の中の調味料をすべて取り除き、豚肘だけを残す。","圧力鍋に残った煮汁を中華鍋に移し、豚肘は皿かボウルに移す。","中華鍋を強火にかける。煮詰める途中で、箸の先で煮汁を味見し、塩加減を調整する。煮汁が多いときは少ないときより味が薄く感じるので、塩を加える際は考慮する。","煮汁が沸騰したら、残りの煮汁の量を確認する。","残りの煮汁が元の量の半分以下になったら、先ほど作った水溶き片栗粉を再度混ぜ、半分を加える。","煮汁が再び沸騰するのを待ち、残りの半分を加える。","再び沸騰したら1～2分待って火を止める。鍋の中の煮汁は赤茶色でとろみがある。","スプーンで煮汁をすくい、豚肘の上に均等にかける。豚肘全体に行き渡るように。全部かけ終わる前に煮汁がなくなったら、そのままテーブルに出し、残った煮汁があればかけずにそのまま出す。"]'::jsonb, '["肉料理","紅焼き","やわらか","揚げ煮込み","おもてなし","伝統的"]'::jsonb),
  ('howtocook:meat_dish/蚂蚁上树', 'ja', 'アリの木登り', '肉料理', 'アリの木登りは古典的な四川風家庭料理で、塩味と香ばしさ、少し辛さがあり、春雨は柔らかく滑らかで汁を吸い、ひき肉は細かくて柔らかく香ばしいです。主材料は春雨とひき肉で、炭水化物とタンパク質が豊富で、素早くエネルギーを補給できます。調理難易度は中程度で、手順が明確なため初心者にも優しく、全部で約20分で完成します。', '[{"name":"春雨","unit":"克"},{"name":"豚ひき肉（または牛ひき肉）","unit":"克"},{"name":"豆板醤","unit":"克"},{"name":"薄口醤油","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"食用油","unit":"ml"},{"name":"ニンニクのみじん切り","unit":"克"},{"name":"生姜のみじん切り","unit":"克"},{"name":"小ねぎ（お好みで）","note":"適量"},{"name":"水","unit":"ml"}]'::jsonb, '["春雨をあらかじめ水で20分間戻し、水気を切っておく。","ニンニクと生姜をそれぞれみじん切りにしておく。","鍋を熱し、食用油10mlを加え、ニンニクのみじん切りと生姜のみじん切りを加えて香りが出るまで炒める。","豚ひき肉を加え、肉の色が白くなり、油が少し出るまで炒める。","豆板醤（トウバンジャン）を加え、赤い油が出るまで炒める。","醤油（薄口）と老抽（濃口醤油）を加え、均一に炒める。","水300mlを加え、沸騰させる。","戻して水気を切った春雨を入れ、箸で軽くほぐしてくっつかないようにする。","中弱火で約5分間、春雨が完全に汁を吸い、やや煮詰まった状態になるまで煮る。","好みで小ねぎのみじん切りをふり、火を止めて器に盛る。"]'::jsonb, '["肉料理","四川風","塩味香ばし少し辛い","炒め煮","ご飯が進む","時短","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/血浆鸭/血浆鸭', 'ja', '血鴨', '肉料理', '血鴨（シュエヤー）は湖南省武岡の伝統的な名物料理です。アヒルの肉は香ばしくてサクサク、柔らかく、酢と血に浸すことで生姜や唐辛子まで甘くて辛くなくなります。アヒルの肉と血は良質なタンパク質と鉄分を提供し、血を補い体を養うのに適しています。手順が多く、火加減と炒めに注意が必要ですが、手順に従えば初心者でも約2時間で完成します。', '[{"name":"若アヒルの肉","unit":"g"},{"name":"生のアヒルの血","unit":"ml"},{"name":"生姜","unit":"枚"},{"name":"ニンニク","unit":"片"},{"name":"ネギ","unit":"本"},{"name":"唐辛子","unit":"g"},{"name":"小さな唐辛子（または朝天唐辛子）","unit":"個"},{"name":"高濃度の白酒","unit":"ml"},{"name":"水","unit":"ml"},{"name":"ビール","unit":"ml"},{"name":"米酒","unit":"ml"},{"name":"薄口醤油","unit":"ml"},{"name":"料理酒","unit":"ml"},{"name":"塩","unit":"g"},{"name":"鶏がらスープの素","unit":"g"},{"name":"食用油","unit":"ml"},{"name":"熱湯","unit":"ml"},{"name":"山胡椒油","unit":"滴"}]'::jsonb, '["若アヒルの肉を約3cmの小さな塊に切り、料理酒と生姜のスライスを加えて血抜きをする。","炒め鍋を熱し、約100mlの食用油を入れ、強火で油が熱くなるまで待ち、下味をつけた若アヒルの肉を入れて絶えず炒める。","アヒルの肉の色が完全に変わる（肉眼で白っぽくなるのが見える）まで待ち、酒を入れ、さらに200mlの熱湯を加え、アヒルの肉がちょうど浸かる程度にし、蓋をして中火で15分煮る。","お湯が沸いたら、蓋を開けて生姜とニンニクを入れ、一度炒め、再び蓋をして10分加熱を続ける。","蓋を開けて唐辛子を入れ、絶えず炒める。唐辛子が柔らかくなるのが肉眼で見えるまで待ち、生のアヒルの血を入れる。このとき絶えず炒め、すべてのアヒルの肉と唐辛子にアヒルの血が行き渡るようにする（これが血鴨の真髄です）。","アヒルの血がすべて黒くなるまで炒め、塩、鶏がらスープの素、ネギを加える（山椒油（サンショウ油）が好きな方は、この時点で山椒油を3-6滴加えてもよい）さらに1-2回炒めたら完成。","鍋から取り出して皿に盛り、食卓に出して食べる。"]'::jsonb, '["肉料理","湖南料理","香ばしく辛い","炒め物","ご飯が進む","宴会料理"]'::jsonb),
  ('howtocook:meat_dish/西红柿土豆炖牛肉/西红柿土豆炖牛肉', 'ja', 'トマトとじゃがいもの牛肉煮込み', '肉料理', '家庭的な煮込み料理で、甘酸っぱくて食欲をそそり、スープは濃厚、牛肉は柔らかく、じゃがいもはほくほく。牛肉は良質なタンパク質、トマトはリコピンが豊富で、じゃがいもと玉ねぎとの組み合わせで栄養バランスも良い。操作は簡単で複雑なテクニックは不要、初心者でも気軽に作れる。下ごしらえから完成まで約1～1.5時間。', '[{"name":"牛肉","unit":"g"},{"name":"長ねぎ","unit":"本"},{"name":"しょうが","unit":"枚"},{"name":"酒","note":"煮込み用と炒め用に分けて加える"},{"name":"花椒","unit":"g"},{"name":"八角","unit":"個"},{"name":"ローリエ","unit":"枚"},{"name":"油","unit":"ml"},{"name":"砂糖/氷砂糖","note":"適量"},{"name":"醤油","unit":"ml"},{"name":"濃口醤油","note":"適量"},{"name":"黒こしょう（または白こしょう）","unit":"g"},{"name":"じゃがいも","unit":"個"},{"name":"トマト","unit":"個"},{"name":"玉ねぎ","unit":"個"},{"name":"トマトペースト/トマトケチャップ","unit":"g"},{"name":"トマト缶","note":"お好みで、トマトペーストの代わりに"},{"name":"塩","note":"適量"}]'::jsonb, '["下ごしらえ:","じゃがいもの皮をむき、5cmの大きめの塊に切っておく","トマトは十字に切り込みを入れ、熱湯にさっと通して皮をむき、芯を取り除いて3cmの小塊に切っておく","長ねぎはみじん切り4g分を取り、残りは5～8cmの長さに切る","牛肉は冷水に30分浸けて血抜きをするか、または冷水から火にかけて表面が白くなるまで茹で、アクを取りながら引き上げる","玉ねぎは0.5～1cmの小粒に切る","調理:","ずっと中火","牛肉が浸るくらいの冷水と、長ねぎのぶつ切り、しょうがスライス、酒20gを圧力鍋に入れ、加圧して20分加熱する","牛肉を取り出し、5cmの大きめの塊に切り、しょうがは取り除く。煮汁は大きめのボウルに取って後で煮込むときに使う","油をひき、4～5割熱したら花椒、八角、ローリエを入れ、香りが立ったら焦げる前に取り出す","牛肉、長ねぎ、しょうがを入れ、香りが立つまで炒める。焦げそうになったら煮汁を10mlほど加える。以降も同様","香りが立ったら醤油15ml、酒15ml、こしょう、トマトペーストまたはトマトケチャップ5～10g（またはトマト缶1缶）を加え、玉ねぎが透き通るまで炒める","（お好みで）玉ねぎから水分を出して焦げ付きにくくするために塩を少々加えてもよいが、入れすぎない。後で味を調える","トマトを加えてトロトロになるまで炒め、残りの煮汁を加える","煮込み:","中火で沸騰したら、終始弱火","仕上げの30～40分前にじゃがいもを加え、味を調える","味を見ながら砂糖と塩を加え、お好みの味にする","箸で牛肉がホロホロになるまで煮込んだら完成！"]'::jsonb, '["肉料理","甘酸っぱい","煮込み","家庭料理","ご飯が進む"]'::jsonb),
  ('howtocook:meat_dish/西红柿牛腩/西红柿牛腩', 'ja', 'トマトと牛スネ肉の煮込み', '肉料理', 'トマトと牛スネ肉の煮込みは、スープが濃厚で甘酸っぱく、牛肉は柔らかく香ばしく、食欲をそそるご飯のおかずにぴったりの家庭料理です。たんぱく質、ビタミン、リコピンが豊富で栄養バランスも良いです。初心者には少し挑戦的で、肉の煮込み加減とトマトの炒め方のコツをつかむ必要があります。一般的な初心者は約90分で完成します。', '[{"name":"トマト","unit":"個"},{"name":"牛スネ肉","unit":"g"},{"name":"食用油","unit":"ml"},{"name":"水","unit":"L"},{"name":"ネギ","unit":"本"},{"name":"ショウガ（薄切り）","unit":"枚"},{"name":"八角","unit":"片"},{"name":"料理酒/黄酒","unit":"ml"},{"name":"ネギ（小口切り）","unit":"g"},{"name":"ショウガ","unit":"g"},{"name":"薄口醤油","note":"適量"},{"name":"白こしょう","note":"適量"},{"name":"砂糖","note":"適量"},{"name":"塩","note":"適量"}]'::jsonb, '["牛スネ肉を2cm角に切り、冷水から鍋に入れ、沸騰したら2分間煮て血抜きをし、取り出して洗い流す。","別の鍋に2Lの水を沸かし、長さ2cmのネギのぶつ切り2本、ショウガの薄切り2枚、八角、料理酒/黄酒5-10mlを加え、下茹でした牛肉を入れ、蓋をして煮込む（土鍋で1時間、圧力鍋の煮込みモードで45分）。箸がすっと通れば煮えた証拠。","トマトの皮むき：トマトのヘタ側に十字の切り込みを入れる（腰のラインまで）。箸やフォークをヘタから刺し、ガスコンロの弱火で回しながら炙り、皮が浮いてきたら剥がし、切る。小さく切るほど良い。","皮を剥くときはやけどに注意。皮をむいたトマトはとても滑りやすいので、ゆっくり切って安全に注意。","鍋に油を熱し、油が7割熱くなったら、ネギとショウガ各10gを入れ、トマトを加えて炒め、トマトの赤色が出るまでしっかり炒める。煮えた牛スネ肉と煮汁を加え、煮汁が肉をちょうど浸す程度にする。","好みで塩、砂糖、薄口醤油で味を調え、蓋をする。","沸騰したら強火でさらに3-5分炒める。","トマトソースが中程度のとろみになったら火を止め、ネギの小口切りを散らして盛り付ける。"]'::jsonb, '["肉料理","甘酸っぱい","煮込み","家庭料理","ご飯が進む"]'::jsonb),
  ('howtocook:meat_dish/豆豉鲮鱼油麦菜/豆豉鲮鱼油麦菜', 'ja', 'トウチとカラスミのサンチュ炒め', '肉料理', 'トウチとカラスミのサンチュ炒めは、塩味と旨みがあってご飯が進む、手早く作れる家庭料理です。広東風の缶詰料理に由来し、サンチュはシャキシャキ、カラスミはサクサク。肉と野菜のバランスが良く、たんぱく質と食物繊維が豊富。作り方は簡単で初心者にも優しく、通常15分で完成します。', '[{"name":"サンチュ","unit":"g"},{"name":"甘竹牌カラスミの缶詰","unit":"缶"},{"name":"ニンニク","unit":"片"},{"name":"醤油","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"サラダ油","unit":"ml"}]'::jsonb, '["食材の下準備：","サンチュを洗ってから、食べやすい長さに切る","カラスミの缶詰を開け、魚の骨を取り除き、小さく切っておく","ニンニクをみじん切りにする","調理手順：","鍋を熱して油を入れ、油が熱くなったら洗ったサンチュを加え、しんなりして水分が出るまで炒め、一旦取り出す。炒め汁は捨てる","鍋を再び熱し、カラスミの缶詰の油を加え、ニンニクのみじん切りを入れて香りを出す","ニンニクの香りが立ったら、缶詰のトウチ（黒豆鼓）を加えて混ぜ、次に切った魚の身を加えてさらに混ぜる","よく混ざったらサンチュを戻し入れ、醤油と砂糖で味を調える","味が決まったら軽く混ぜて、皿に盛り付けて完成"]'::jsonb, '["おかず","塩味","広東風","炒め物","ご飯が進む","家庭料理","手早い"]'::jsonb),
  ('howtocook:meat_dish/豉汁排骨', 'ja', '豉汁排骨', '肉料理', 'これは広東風喫茶店の人気蒸し料理で、豆鼓の香りが豊かで、スペアリブは滑らかで骨から外れやすいです。スペアリブは良質なタンパク質とカルシウムを提供し、発酵豆鼓が風味を加え吸収も良くします。作り方は、水に浸して洗い、下味をつけ、火加減を調整して蒸す必要があり、初心者には少し挑戦的ですが、手順は明確で取り組みやすく、準備から出来上がりまで約1時間です。残ったスープをご飯や麺にかけると格別に美味しいです。', '[{"name":"スペアリブ","unit":"g"},{"name":"陽江豆鼓","unit":"g"},{"name":"ニンニクのみじん切り","unit":"g"},{"name":"生姜のみじん切り","unit":"g"},{"name":"薄口醤油","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"オイスターソース","unit":"g"},{"name":"白砂糖","unit":"g"},{"name":"片栗粉","unit":"g"},{"name":"食用油","unit":"ml"},{"name":"水","unit":"ml"},{"name":"ネギのみじん切り","note":"適量"},{"name":"白ごま","note":"適量"}]'::jsonb, '["スペアリブを冷水に10分浸して血抜きをし、水を替えて2回繰り返し、キッチンペーパーで水気を拭き取る","豆鼓を水に5分浸す","全ての材料を混ぜ合わせ（食用油は10ml）、8～30分漬け込む","湯が沸いたら蒸し器に入れて18分蒸す","2分蒸らす","鍋に10mlの熱油を入れ、180～200℃に熱する","均等にネギと白ごまをふりかけ、熱した油を上からかける"]'::jsonb, '["肉料理","広東風","蒸し","塩味香ばしい","ご飯が進む","おもてなし"]'::jsonb),
  ('howtocook:meat_dish/豉汁蒸白鱔/豉汁蒸白鱔', 'ja', '豆豉蒸し白ウナギ', '肉料理', '豆豉蒸し白ウナギは広東料理の定番蒸し料理。豆豉（トウチ）とニンニクの香りが白身魚に染み込み、なめらかで旨味のある一品。白ウナギは良質なタンパク質と不飽和脂肪酸が豊富で、体に良い。手順は明瞭ですが、生魚の処理と火加減に少しコツがいるため、ある程度料理経験のある方に最適。準備から食卓まで約30分。', '[{"name":"白ウナギ","unit":"グラム"},{"name":"豆豉","unit":"大さじ"},{"name":"ニンニク","unit":"かけ"},{"name":"ショウガ","unit":"枚"},{"name":"ネギ","unit":"本"},{"name":"薄口醤油","unit":"大さじ"},{"name":"濃口醤油","unit":"小さじ"},{"name":"砂糖","unit":"小さじ"},{"name":"ごま油","unit":"小さじ"},{"name":"片栗粉","unit":"小さじ"},{"name":"水","unit":"大さじ"},{"name":"赤ピーマン","unit":"グラム"}]'::jsonb, '["白ウナギの確認と下洗い：","購入時に魚屋で内臓を取り、ぬめりをこそげ落とし、約5cmのぶつ切りにしてもらう。","家に帰ったら白ウナギを確認し、流水で洗い、ぬめりや残渣がないようにする。","オプション：塩3gと片栗粉小さじ1で優しく揉み込み、5分置いてから洗い流すと、臭みが取れてなめらかになる。","ソースの準備：","小鉢に豆豉大さじ1、ニンニクみじん切り2片分、薄口醤油大さじ1.5、濃口醤油小さじ0.5、砂糖小さじ0.5、ごま油小さじ0.5、水大さじ1を混ぜ合わせる。","より濃厚な豆豉風味が好みなら、豆豉をさらに大さじ0.5追加する。","盛り付け：","切った白ウナギを耐熱皿に平らに並べ、重ならないようにする。","ショウガの千切りを白ウナギの上に均等に散らす。","調製した豆豉ソースを白ウナギの上にまんべんなくかける。","蒸し：","蒸し器または電気蒸し器に水（500ml）を入れ、沸騰させる。","白ウナギをのせた皿を蒸し器に入れ、蓋をする。","中～強火で約8～10分（白ウナギの大きさにより調整）、白ウナギに火が通りすぎず、身が白くなり血がなくなるまで蒸す。","飾り付けと仕上げ：","蒸し上がったら取り出し、ネギの千切りと赤ピーマンの千切り（お好みで）を飾る。","熱々のごま油を回しかけると香りが増す。","熱いうちにご飯と一緒にどうぞ。"]'::jsonb, '["魚料理","広東風","蒸し料理","あっさり","ご飯が進む","家庭料理","おもてなし"]'::jsonb),
  ('howtocook:meat_dish/贵州辣子鸡/贵州辣子鸡', 'ja', '貴州風 辣子鶏', '肉料理', '貴州風辣子鶏は貴州地方の定番家庭料理で、もち米唐辛子ペーストや様々な香辛料を使って調理されます。鶏肉は柔らかくホロホロ、じゃがいもはほくほくで味が染み込み、全体的に香ばしくピリ辛。鶏肉は高タンパクで、じゃがいもなどの具材と合わせて栄養バランスも良いです。手順は多めで初心者にはややハードルが高いですが、順を追えば成功できます。準備から完成まで約1.5時間かかります。', '[{"name":"農家のトウモロコシ鶏","unit":"斤"},{"name":"じゃがいも","unit":"個"},{"name":"ニンニク","unit":"個"},{"name":"ローリエ","unit":"枚"},{"name":"生姜","unit":"個"},{"name":"老抽","unit":"ml"},{"name":"花椒/麻椒","note":"適量"},{"name":"糍粑辣椒","unit":"g"},{"name":"豆瓣醬","note":"適量"},{"name":"ビール","unit":"瓶"},{"name":"葉ニンニク","unit":"本"},{"name":"酒粕","note":"適量"},{"name":"食用油","unit":"斤"}]'::jsonb, '["鍋に半分の高さまで油を入れ、細切りにしたじゃがいもを表面がきつね色になるまで揚げて取り出す。油の温度が手をかざすと熱く感じる程度になったら、切った鶏肉を入れ、スライスした生姜と花椒も加えて揚げる。","鶏肉を揚げ始めた時は、鶏肉に水分があるため油が濁っているが、油が澄んできたら鶏肉が揚がった合図なので、取り出しておく。","鍋の油の3分の1を取り出す。今はこんなに油は必要ない。","鍋に残った油を熱し、糍粑辣椒、豆瓣醬、スライスした生姜を加えて赤い油が出るまで炒め、揚げた鶏肉を加えて均一に炒め合わせる。","鶏肉に色が付いたら、老抽を加え、ビールを注ぐ。ビールは鶏肉が浸るくらいにする。ローリエを加えて蓋をし、10分間蒸し煮にする。その間、時々混ぜる。","じゃがいもとニンニク（切らずに、一粒ずつのままが良い）を加え、さらに20分間蒸し煮にする。","最後に酒粕を加えて均一に炒め、切った葉ニンニクを加えてさっと炒めたら、完成。"]'::jsonb, '["肉料理","香辛料が効いた","貴州風","揚げ煮","ご飯が進む","おもてなし"]'::jsonb),
  ('howtocook:meat_dish/辣椒炒肉', 'ja', '青椒と豚肉の炒めもの', '肉料理', '青椒と豚肉の炒めものは、湖南風味が豊かな家庭料理です。青椒は乾煎りで香ばしく、豚肉はなめらかで味がしみ込み、塩辛くて少し辛くご飯が進みます。豚肉には良質なタンパク質とビタミンB群が含まれ、青椒はビタミンCが豊富です。この料理は乾煎りと強火で炒める火加減が重要で、ある程度の料理経験がある方におすすめです。準備から完成まで約30分かかります。', '[{"name":"青椒","unit":"個"},{"name":"豚もも肉（赤身）","unit":"グラム"},{"name":"塩","unit":"グラム"},{"name":"薄口醤油","unit":"ml"},{"name":"オイスターソース","unit":"ml"},{"name":"ニンニク","unit":"グラム"},{"name":"生姜","unit":"グラム"},{"name":"サラダ油","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"豆豉（トウチ）","unit":"グラム"}]'::jsonb, '["青椒を洗い、ヘタと種を取り除き、乱切りにして準備する。","ニンニクを包丁で叩き、横に切って薄切りにし、生姜はみじん切りにする。","豚もも肉（または豚ロース）を薄切りにする（肉の繊維に沿って切る、つまり包丁と繊維が平行になるように切ると、切った断面に繊維が「川」の字のように見える）。","切った豚肉を洗い、ボウルに入れ、計量した醤油、オイスターソース、塩を加えてよく混ぜ、10分間漬け込む。","鍋を熱し、油を入れずに、切った青椒を鍋に入れ、強火で乾煎りして焼き目がついたら、さらに塩2gを加えて1分炒め、取り出す。","鍋を洗わずに強火で熱し、油8mlを加え、30秒待ってから、ニンニクの薄切りと生姜のみじん切りを加えて15秒炒める。","漬け込んだ豚肉を鍋に加えて2分炒め、さらに乾煎りした青椒を加えて1分炒める。","好みで豆豉を加え、最後に醤油を加えてさらに30秒炒める。","火を止めて皿に盛る。"]'::jsonb, '["肉料理","湖南料理","塩辛くて少し辛い","乾煎り","強火炒め","ご飯が進む","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/酱排骨/酱排骨', 'ja', 'スペアリブの醤油煮', '肉料理', '醬排骨（スペアリブの醤油煮）は、美しい醤油色で、肉はほろほろ、骨の旨みが濃厚、タレはとろりとして味わい深く、塩味と甘味が調和した定番の家庭料理です。スペアリブは良質なタンパク質とカルシウムが豊富で栄養バランスも良いです。作り方には砂糖を炒める作業と長時間の煮込みが必要で、初心者には少し難しいかもしれませんが、手順通りに進めれば大丈夫です。準備から完成まで約1時間です。', '[{"name":"スペアリブ","unit":"g"},{"name":"五香粉","unit":"g"},{"name":"料理酒","unit":"ml"},{"name":"食用油","unit":"ml"},{"name":"白砂糖","unit":"g"},{"name":"濃口醤油","unit":"ml"},{"name":"薄口醤油","unit":"ml"},{"name":"オイスターソース","unit":"ml"},{"name":"唐辛子","unit":"本"},{"name":"ニンニク","unit":"片"},{"name":"生姜","unit":"枚"}]'::jsonb, '["鍋に湯を沸かし、スペアリブ、生姜の薄切り、料理酒を入れ、沸騰したらお玉で白いアクを取り除き、2〜3分後に取り出す。","冷水でスペアリブを洗い、2〜3回すすぐ。","弱火で鍋に油を入れ、白砂糖を加え、砂糖が黄色くなるまで優しく混ぜる。","スペアリブを加えて30秒炒め、薄口醤油、オイスターソース、五香粉、ニンニク、唐辛子を加えてさらに30秒炒め、スペアリブがかぶるくらいの水を加える。","強火で30分煮込み、濃口醤油を加えて色をつけ、さらに10分煮る。","火からおろして盛り付ける。"]'::jsonb, '["肉料理","醤油風味","塩味と甘味","煮込み","ご飯が進む","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/酱牛肉/酱牛肉', 'ja', '牛肉の醤油煮', '肉料理', '牛肉の醤油煮は、北派の家庭的な冷たい肉料理で、醤油の風味が豊かで、食感はしっかりとしていてほぐれず、噛みごたえがあります。牛のスネ肉は良質なタンパク質と様々なアミノ酸が豊富で、長時間煮込むことで消化吸収されやすくなります。作り方はそれほど複雑ではありませんが、漬け込み、長時間の煮込み、そして長時間の冷蔵が必要で、初心者には少し忍耐が必要です。最初から最後まで約10時間かかります。', '[{"name":"牛スネ肉","unit":"g"},{"name":"ローリエ","unit":"枚"},{"name":"生姜","unit":"枚"},{"name":"ネギ","unit":"本"},{"name":"濃口醤油","unit":"ml"},{"name":"シナモンスティック","unit":"本"},{"name":"氷砂糖","unit":"粒"},{"name":"花椒","unit":"粒"},{"name":"料理酒","unit":"ml"},{"name":"薄口醤油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"八角","unit":"個"},{"name":"甜麺醤","unit":"ml"}]'::jsonb, '["牛スネ肉をよく洗い、水に1時間浸して血抜きをする。","爪楊枝またはフォークで牛スネ肉の表面に穴をあけ、料理酒、花椒、生姜のスライスを加え、ラップで容器を密閉して4～6時間漬け込む。","牛スネ肉を8cm、最大10cmの大きさに切る。","牛スネ肉を鍋に入れ、冷水を牛肉が浸るまで加える。沸騰し始めたらタイマーをセットし、アクを取り除く。3分後に火を止め、牛肉を取り出し、ぬるま湯で洗う。","洗った牛スネ肉を土鍋または煮込み鍋に入れ、水を牛スネ肉が浸るまで加え、強火にかける。塩以外の残りの調味料を加える。","沸騰したら弱火にし、90分間加熱する。その後塩を加える。","塩を加えた後、さらに弱火で90分加熱する（注意：30分ごとに水位を確認し、牛肉の表面の高さの80%以上を保つこと）。","加熱開始から180分後、牛スネ肉を取り出し、牛スネ肉を取り出し、ラップでしっかり包んで冷蔵庫で数時間冷やす。","取り出したら、牛肉の筋目に沿って薄切りにし、盛り付けて食べる。残りの牛スネ肉は切らずに冷蔵保存することをお勧めします。"]'::jsonb, '["肉料理","醤油風味","冷たい肉料理","北派","長時間煮込み","酒の肴","宴会向け"]'::jsonb),
  ('howtocook:meat_dish/醉排骨/醉排骨', 'ja', '酔排骨', '肉料理', '酔排骨は福州の伝統的な名物料理で、外はカリッと中はジューシー、甘酸っぱくて食欲をそそり、独特のナンプラーの風味があります。排骨はタンパク質とカルシウムが豊富で、栄養たっぷり。この料理は衣をつけて二度揚げするテクニックが必要で、ある程度料理経験のある方におすすめです。全体で約40分かかります。', '[{"name":"排骨","unit":"グラム"},{"name":"片栗粉","unit":"グラム"},{"name":"卵黄","unit":"個"},{"name":"ナンプラー","unit":"ml"},{"name":"にんにくみじん切り","unit":"粒"},{"name":"黒酢","unit":"ml"},{"name":"白砂糖","unit":"グラム"},{"name":"トマトケチャップ","unit":"グラム"},{"name":"ねぎ","unit":"本"},{"name":"白ごま","unit":"グラム"},{"name":"サラダ油","unit":"ml"}]'::jsonb, '["排骨に片栗粉5gと水を加えて混ぜ、2～3回洗ってから大きめのボウルに入れておく","排骨にナンプラー、片栗粉、卵黄を加えてよく混ぜる","排骨を一つずつ鍋に入れる（ボウルごと入れないこと）。それぞれがくっつかないようにする","全て入れ終わったら、30秒ごとにスプーンで肉をひっくり返しながら、排骨の表面がきつね色になるまで揚げる","排骨を取り出し、1分後に再び油鍋に入れてさらに揚げる。肉の表面がこんがり焦げ目がつくまで揚げたら、取り出して大きめのボウルに入れておく","小さなボウルに、みじん切りにんにく、黒酢、白砂糖、ナンプラー、ケチャップ、小ねぎのみじん切り、白ごまを入れて混ぜ合わせ、熱した油を5ml注ぐ","タレを排骨に回しかけ、よく混ぜ合わせてから皿に盛る"]'::jsonb, '["肉料理","甘酸っぱい","風味豊か","揚げ物","福州料理","おもてなし","ご飯に合う"]'::jsonb),
  ('howtocook:meat_dish/青椒土豆炒肉/青椒土豆炒肉', 'ja', 'ピーマンとじゃがいもと肉の炒め物', '肉料理', 'ピーマンとじゃがいもと肉の炒め物は、肉と野菜のバランスが良い家常料理です。食感は香ばしくシャキシャキで、タレの風味が豊かでご飯が進みます。じゃがいもは炭水化物とビタミンCが豊富で、ピーマンはビタミンCと食物繊維が多く、豚肉の良質なタンパク質と合わせて栄養バランスが良いです。この料理の作り方は複雑ではなく、初心者にもやさしく、下ごしらえから完成まで約1時間でできます。', '[{"name":"ピーマン","unit":"個"},{"name":"じゃがいも","unit":"個"},{"name":"豚肉（バラ肉）","unit":"g"},{"name":"ネギ","unit":"本"},{"name":"生姜","unit":"塊"},{"name":"ニンニク","unit":"片"},{"name":"塩","unit":"g"},{"name":"醤油","unit":"ml"},{"name":"食用油","unit":"ml"},{"name":"片栗粉","unit":"g"},{"name":"水","unit":"g"}]'::jsonb, '["ピーマンはヘタを取り除き小さく切る。じゃがいもは皮をむき2mmの薄切りにする。豚肉は4mmの薄切りにする。ネギは縦横に3mmの小口切りにする。生姜とニンニクは皮をむき、潰して細かく刻む。片栗粉に約15gの水を加えてよく混ぜ、水溶き片栗粉を作る。","鍋に油を熱し、7割熱になったら豚肉を入れ、ゆっくりと返しながら炒めて肉の色が変わるまで炒める。醤油約3mlを加え、肉に均一に色がつくように炒め、塩約2gを加える。","火を5割に下げ、ネギ、生姜、ニンニクを加えて5秒炒める。次にじゃがいもを加え、火を7割に上げて均一に炒める。醤油約5mlと塩2gを加え、じゃがいもに火が通り、表面が少しきつね色になるまで炒める。","火を8割に上げてピーマンを加え、強火で炒めて鍋気を出す（白い煙が出るまで）。均一に返しながら1分間炒めて色をつける。最後に鍋肌から水溶き片栗粉を回し入れ、火を4割に下げてとろみをつける。","外観がとろりとしたら火を止め、皿に盛る。"]'::jsonb, '["肉料理","香ばしい","家常","ご飯が進む","炒め物","時短"]'::jsonb),
  ('howtocook:meat_dish/青椒酿/青椒酿', 'ja', 'ピーマンの肉詰め', '肉料理', '広西の定番家庭料理。ピーマンに味付けした肉だねまたはエビのすり身を詰め、表面に焼き目をつけてから煮込みます。ピーマンの香りと具材の旨味が絡み合い、塩味とほのかな辛みでご飯が進みます。豚肉とエビは良質なタンパク質、ピーマンはビタミンCが豊富で栄養バランス良好。詰めるのに少し手間がかかりますが、工程は明確で、手順通りに進めれば30分ほどで完成します。', '[{"name":"ピーマン（青唐辛子、まっすぐで肉厚なもの）","unit":"個"},{"name":"豚肉（前の部位、肩ロースがおすすめ）","unit":"g"},{"name":"ネギ","unit":"本"},{"name":"生姜","unit":"少々"},{"name":"醤油","unit":"ml"},{"name":"老抽","unit":"ml"},{"name":"塩","unit":"g"},{"name":"サラダ油","unit":"ml"},{"name":"水","unit":"ml"},{"name":"片栗粉（お好みで）","unit":"g"},{"name":"ニンニク（お好みで）","unit":"片"},{"name":"オイスターソース（お好みで）","unit":"ml"},{"name":"料理酒（お好みで）","unit":"ml"},{"name":"卵（お好みで）","unit":"個"},{"name":"白胡椒（お好みで）","unit":"g"},{"name":"砂糖（お好みで）","unit":"g"},{"name":"エビ（エビすり身版）","unit":"g"}]'::jsonb, '["豚肉を洗って包丁でたたいてミンチにする（またはフードプロセッサーを使う）。生姜はみじん切り、ネギは小口切りにする。","ミンチに生姜、ネギ、醤油15ml、老抽5ml、塩3gを加えてよく混ぜる。","お好みで：料理酒10ml、オイスターソース10ml、卵1個、片栗粉5g、白胡椒2g、砂糖5gを加える。","一方向に混ぜて粘りが出るまで練り、10分ほど置く。","ピーマンは洗ってヘタを取り、箸で中の種と白い筋を丁寧に取り除く。ピーマンを破らないように注意する。","お好みでピーマンの内側に片栗粉約5gをふり入れ、よく振って全体に行き渡らせる。こうすると肉だねがはがれにくくなる。","味付けした肉だねを箸か絞り袋でピーマンに詰める。詰めすぎて破れないよう、きっちりと詰める。","全て詰めたら準備完了。","ボウルに醤油15ml、老抽5ml、水100mlを入れて混ぜる。","お好みで片栗粉5gを加えると、とろみがつく。","フライパンを熱し、サラダ油30mlを入れ、油が五六分熱くなったら詰めたピーマンを入れる（肉の面を下にして先に焼く）。","中弱火でじっくり焼き、ひっくり返しながらピーマンの表面全体に焼き色がつき、しわが寄って虎皮状になるまで焼く。一度取り出す。","フライパンに油を少し残し、お好みでニンニクのみじん切りを入れて香りを出す。","合わせた調味液を入れ、沸騰したら焼いたピーマンを戻す。","中弱火にし、蓋をして5〜8分煮込む。とろみがつき、ピーマンが柔らかくなるまで。","蓋を開け、強火で汁気を飛ばしながらピーマンに照りが出るまで煮詰めて、完成。","エビ250gは背ワタを取り、包丁の背でたたいてすり身にする（粒感を残すと食感が良い。市販のすり身を使っても良い。三角形の絞り袋からそのまま絞り出せる）。","エビのすり身の味付け：生姜みじん切り5g、塩2g、片栗粉5g、醤油10ml。","お好みで：料理酒5ml、白胡椒1g、卵白半分。","一方向に混ぜて粘りが出るまで練り、10分ほど置く。","その後の詰める・焼く・煮込む工程は豚肉バージョンと同じ。","エビは火が通りやすいので、煮込み時間は4〜5分に短縮する。"]'::jsonb, '["肉料理","塩味","ほんのり辛い","ご飯が進む","焼き煮","広西風味"]'::jsonb),
  ('howtocook:meat_dish/香干肉丝', 'ja', '香干肉絲', '肉料理', '香干肉絲は塩味と香りがご飯に合う家常の炒め物です。肉絲は柔らかく滑らか、香干はしなやか、ピーマンはシャキシャキ。動物性と植物性のダブルのタンパク質が豊富で、ピーマンでビタミンも補えます。難易度は普通で、初心者も少し練習すればマスターできます。調理時間は約30分です。', '[{"name":"豚ヒレ肉（肉絲）","unit":"g"},{"name":"香干","unit":"g"},{"name":"ピーマン","unit":"個"},{"name":"塩","unit":"g"},{"name":"薄口醤油","unit":"ml"},{"name":"片栗粉","unit":"g"},{"name":"ニンニク","unit":"g"},{"name":"鶏がらスープの素","unit":"g"}]'::jsonb, '["肉絲（肉絲がない場合は自分で切る）を醤油(3ml)、片栗粉と混ぜ合わせておく。","ピーマンを洗い、乱切りにして準備する。","ニンニクは薄切りにし、香干は細切りにする。","片栗粉と水(10ml)を混ぜ、よくかき混ぜる。","きれいな鍋に油15mlを入れ、油が熱くなる前に肉絲を入れてゆっくりほぐす。肉絲に火が通ったらすぐに取り出し、油は鍋に残す。","ニンニクの薄切りと香干を鍋に入れ、醤油2mlを加えてよく炒める。","2～3分、火加減を見ながら、ピーマンの細切りを加えて混ぜ、炒める。","1分後、肉絲を加えて混ぜる。","片栗粉と水の混ぜ合わせたものを加えてとろみをつけ、塩3g、鶏がらスープの素2gを加えて、2～3分炒めて火を止める。","完成。"]'::jsonb, '["肉料理","塩味と香り","手早く炒める","家庭料理","ご飯が進む"]'::jsonb),
  ('howtocook:meat_dish/香干芹菜炒肉/香干芹菜炒肉', 'ja', 'くんせい豆腐とセロリの肉炒め', '肉料理', '香干芹菜炒肉は家庭料理の炒め物です。くんせい豆腐はコシがあり、セロリはシャキシャキ、豚肉は柔らかく、塩味と少しの辛さが効いています。セロリには食物繊維が豊富で、くんせい豆腐と豚肉から良質の植物性・動物性たんぱく質が摂れます。作り方は簡単で初心者にも優しく、下ごしらえから出来上がりまで約30分です。', '[{"name":"くんせい豆腐","unit":"g"},{"name":"セロリ","unit":"本"},{"name":"豚肉","unit":"g"},{"name":"ニンニク","unit":"片"},{"name":"唐辛子","unit":"個"},{"name":"花椒","unit":"粒"},{"name":"塩","unit":"g"},{"name":"鶏がらスープの素","unit":"g"},{"name":"老抽","unit":"ml"},{"name":"オイスターソース","unit":"ml"},{"name":"サラダ油","unit":"ml"}]'::jsonb, '["セロリは葉を取り除き、4cm以下の長さに切り、細切りにする。","くんせい豆腐は小指くらいの太さに切って、置いておく。","ニンニクは薄切りでもみじん切りでも好きな方で切って、置いておく。","唐辛子は輪切りでも斜め切りでも好きな方で切って、置いておく。","鍋を熱し、サラダ油を10ml～15ml入れる。10秒ほど待って油の温度を上げる。","花椒とニンニクを入れて香りを出す（生姜が好きな人は生姜の薄切りや千切りを追加しても良い）。","豚肉を加えて色が変わるまで炒め、さらに老抽8mlを加えて色をつけながら均一に炒める（豆板醤がある場合は、豆板醤3mlも加えて一緒に炒めても良い）。","くんせい豆腐を加えて均一に炒める（約2分）。","唐辛子を加えて均一に炒める（約1～2分）。","セロリを加え、塩5gを入れて1分間炒める。","鶏がらスープの素3g、オイスターソース5mlを加えて均一に炒め、火を止めて出来上がり。"]'::jsonb, '["肉料理","家庭料理","ご飯が進む","簡単早い","塩味でうまみ","少し辛い","炒め物"]'::jsonb),
  ('howtocook:meat_dish/香煎五花肉/香煎五花肉', 'ja', '香煎豚バラ肉', '肉料理', '香煎豚バラ肉は家庭的な味わいの時短肉料理です。豚バラ肉を香ばしくカリッと焼き上げ、脂っこくなく、シャキシャキのレタスと塩味の効いた豆瓣酱で巻いて食べると、味噌の風味が広がりさっぱりと頂けます。豚肉には良質なタンパク質と脂質が含まれ、エネルギー補給に最適。レタスは食物繊維とビタミンを補い、栄養バランスも良いです。この料理は少し料理に慣れた方におすすめですが、初心者でも火加減と油跳ねに注意すれば簡単に作れます。下ごしらえから完成まで約30分で楽しめます。', '[{"name":"豚バラ肉ブロック（推奨サイズ：20cm×6cm×5cm）"},{"name":"レタス","unit":"玉"},{"name":"醤油","unit":"g"},{"name":"塩","unit":"g"},{"name":"味の素","unit":"g"},{"name":"料理酒","unit":"g"},{"name":"生姜","unit":"枚"},{"name":"ニンニク","unit":"片"},{"name":"サラダ油","unit":"ml"},{"name":"豆瓣酱","note":"適量"}]'::jsonb, '["豚バラ肉ブロックを長辺に沿って1mm〜1.5mmの厚さにスライスし、準備する。","スライスした豚バラ肉をボウルに入れ、醤油8g、塩1g、味の素1g、料理酒10g、生姜2枚、潰したニンニク2片を加えて10分漬け込む。","レタスを手で剥がして洗い、準備する。","熱した鍋にサラダ油5mlを入れる。油が軽く煙ったら豚バラ肉を加える。片面がこんがりと焼けたら裏返し、同じように焼く。","豚バラ肉を焼き上げたら、皿に盛る。","レタスに豆瓣酱を塗り、豚バラ肉を巻いて食べる。"]'::jsonb, '["肉料理","香煎","家庭料理","時短","ご飯が進む","味噌風味"]'::jsonb),
  ('howtocook:meat_dish/香菇滑鸡/香菇滑鸡', 'ja', 'しいたけと鶏肉の滑らか煮', '肉料理', 'しいたけと鶏もも肉を使った家庭料理です。鶏もも肉は炒めてから煮込むことで、滑らかで柔らかな食感に。しいたけの独特な香りと旨味が溶け込んだ、コクのあるスープが魅力の、老若男女問わず楽しめる広東風の一品です。鶏肉は良質なタンパク質と各種アミノ酸を豊富に含み、しいたけにはしいたけ多糖類や食物繊維が含まれ、免疫力向上や消化促進に役立ちます。調理には包丁さばきと火加減のコツが必要で、初心者には少し難しいかもしれませんが、全体で約1時間で作れます。', '[{"name":"鶏もも肉","unit":"個"},{"name":"干ししいたけ","unit":"粒"},{"name":"生姜","unit":"片"},{"name":"ねぎ","unit":"本"},{"name":"にんにく","unit":"片"},{"name":"ぬるま湯","unit":"ml"},{"name":"料理酒","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"濃口醤油","unit":"ml"},{"name":"砂糖","unit":"ml"},{"name":"ごま油","unit":"ml"}]'::jsonb, '["ぬるま湯で干ししいたけを戻す","生姜は薄切り、ねぎはざく切り、にんにくは半分に切る","鶏もも肉は骨を取り除く（骨付きのままでも良いが、プログラマーの食事効率が少し落ちるだけ）、一口大に切る","戻したしいたけは4等分に切り、しいたけの戻し汁は取っておく","鶏もも肉を1分間茹でて、アクと不純物を取り除く","鶏もも肉に料理酒15ml、醤油15ml、塩1.5g、濃口醤油15mlを加えてよく揉み込む","油を3割程度の温度に熱し、鶏もも肉を炒めて、きつね色になったら取り出す","鍋に油を少し残し、ねぎ、生姜、にんにくを炒めて香りを出し、しいたけを加えて強火で炒め合わせる","20秒ほどでしいたけの香りが立ったら、先に炒めた鶏もも肉を戻し入れ、しいたけの戻し汁（全部、本プログラマーが魂の作業と思う）、砂糖15ml、醤油30mlを加える","中火にして蓋をせず、2分ほど煮詰めてスープを濃縮し、ごま油5mlを回し入れ、ねぎの小口切りを散らして火を止め、器に盛る"]'::jsonb, '["肉料理","うま味","広東風","家庭料理","ご飯が進む","煮込み"]'::jsonb),
  ('howtocook:meat_dish/香辣鸡爪煲/香辣鸡爪煲', 'ja', 'スパイシーな鶏足の煮込み', '肉料理', 'スパイシーでコクがあり、プリプリした食感が楽しめる、定番の家庭料理です。鶏足にはコラーゲンが豊富で、肌の潤いや骨や腱を強くする効果が期待できます。調理の際はまず爪を切り落とし、丸ごとの鶏足を使う場合は骨を取り除く必要があり、初心者には少しハードルが高いですが、手順通りに根気よく進めれば成功します。下茹でから弱火でじっくり煮込み、炒めて味を染み込ませるまで、全工程で約45分かかります。', '[{"name":"鶏足","unit":"斤"},{"name":"ネギ","unit":"本"},{"name":"生姜","unit":"g"},{"name":"ニンニク","unit":"g"},{"name":"料理酒","note":"適量"},{"name":"ローリエ","unit":"枚"},{"name":"八角","unit":"個"},{"name":"薄口醤油","note":"適量"},{"name":"濃口醤油","note":"適量"},{"name":"唐辛子","unit":"本"},{"name":"唐辛子粉（お好みで）","note":"適量"},{"name":"オイスターソース","unit":"g"},{"name":"五香粉","note":"適量"},{"name":"塩","note":"適量"},{"name":"チキンエッセンス","note":"適量"}]'::jsonb, '["鶏足の爪を切り落とします。購入した鶏足が足の裏部分だけの場合は、半分に切ります。丸ごとの鶏足の場合は、骨を取り除く必要があります。水でよく洗います。","鶏足を冷水から鍋に入れ、ネギ、生姜、料理酒を加えて下茹でします。沸騰したらアクを取り除きます。","ローリエ、八角、薄口醤油、濃口醤油を加え、蓋をして弱火で30分煮込みます。","鶏足を取り出し、煮汁を一碗取っておきます。","鍋に油を熱し、弱火で生姜のみじん切り、ニンニクのみじん切り、唐辛子を炒めて香りを出します。辛さが欲しい場合は、さらに唐辛子粉を加えます。薄口醤油、濃口醤油、オイスターソース、五香粉、塩を加え、香ばしいタレの香りが立つまで炒めます。","鶏足を加え、塩少々で味を調え、1〜2分炒めます。そして取っておいた煮汁を加え、炒めながら混ぜます。","チキンエッセンスを加えて旨味を引き出し、刻んだネギを加えて混ぜ合わせたら、器に盛り付けます。"]'::jsonb, '["肉料理","スパイシー","煮込み","ご飯が進むおかず","家庭料理","プリプリ"]'::jsonb),
  ('howtocook:meat_dish/鱼香肉丝', 'ja', '魚香肉絲', '肉料理', '魚香肉絲（ユーシャンロースー）は定番の四川料理です。甘酸っぱくて少し辛く、肉は柔らかく、にんじん、ピーマン、きくらげと合わせて豊かな食感が楽しめます。たんぱく質と各種ビタミンが豊富で、お肉と野菜のバランスが良く栄養価も高いです。調理には少しコツが必要で、香汁をしっかり作り、炒める火加減が重要です。初心者は手順を厳守することをおすすめします。調理時間は約40分（きくらげの戻し時間を除く）です。', '[{"name":"豚ヒレ肉","unit":"g"},{"name":"にんじん","unit":"g"},{"name":"ピーマン","unit":"g"},{"name":"きくらげ（乾燥）","unit":"g"},{"name":"薄口醤油","unit":"ml"},{"name":"料理酒","unit":"ml"},{"name":"卵白","unit":"個"},{"name":"片栗粉","unit":"g"},{"name":"酢","unit":"ml"},{"name":"砂糖","unit":"g"},{"name":"塩","unit":"g"},{"name":"しょうが","unit":"g"},{"name":"ねぎ","unit":"g"},{"name":"にんにく","unit":"片"},{"name":"豆板醤","unit":"g"}]'::jsonb, '["下味を作る：以下の材料を混ぜ合わせる：","薄口醤油 5ml","料理酒 5ml","片栗粉 5g","水 20ml","卵白 1個","香汁を作る：以下の材料を混ぜ合わせる：","薄口醤油 5ml","酢 15ml","砂糖 10g","塩 1g","片栗粉 5g","水 20ml","下味で豚ヒレ肉を15～30分漬け込む。肉をよく揉み込むこと。","乾燥きくらげを4時間水に戻し、洗って小さく切る。","ピーマンを洗い、へたを取り、千切りにする。","にんじんを洗い、千切りにして、さっと茹でる。","しょうが、にんにくをみじん切りにする。","ねぎを5mmの小口切りにする。","鍋を熱し、油15mlを加える。","鍋に漬け込んだ肉を入れ、手早くほぐしながら色が変わるまで炒め、取り出しておく。","鍋を熱し、油5mlを加える。","ねぎ、しょうが、にんにく、豆板醤をすべて加える。","にんじんをすべて加え、20秒炒めたら、ピーマンときくらげを加えて2分炒める。","炒めた肉を加える。手早く全体を混ぜ合わせる。20秒以上炒めないこと。","香汁を加える。手早く全体を混ぜ合わせる。15秒以上炒めないこと。","火を止め、皿に盛る。"]'::jsonb, '["肉料理","四川料理","甘酸っぱい","辛さ控えめ","ご飯が進む","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/鱼香茄子/鱼香茄子', 'ja', '魚香茄子', '肉料理', '魚香茄子は定番の四川風家庭料理で、甘酸っぱくて少し辛いです。茄子は柔らかくて汁を吸い込み、ご飯が進みます。茄子には食物繊維とビタミンが豊富で、ひき肉と合わせるとタンパク質も摂れます。調理の難易度は中程度で、揚げ茄子と味付けのコツが必要ですが、初心者でも少し練習すれば成功できます。準備から完成まで約30分かかります。', '[{"name":"茄子","unit":"本"},{"name":"ひき肉","unit":"g"},{"name":"塩","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"味の素","unit":"g"},{"name":"薄口醤油","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"酢","unit":"ml"},{"name":"水溶き片栗粉","unit":"ml"},{"name":"豆板醤","unit":"g"},{"name":"小ネギ","note":"適量"},{"name":"ショウガ","note":"適量"},{"name":"ニンニク","note":"適量"},{"name":"ミニ唐辛子","note":"適量"}]'::jsonb, '["茄子を棒状に切る。","肉をひき肉にし、ネギ・ショウガ・ニンニクをみじん切りに、ミニ唐辛子を小口切りにする。","魚香ソースを作る：ボウルに塩、味の素、砂糖、薄口醤油、濃口醤油、酢、水溶き片栗粉を入れて混ぜる。","鍋に300mlの油を入れ、弱火にかける（弱火の方が調整しやすい）。油が七分熱（弱火で約40秒、煙が出てくる）になったら茄子を入れ、2分揚げる。茄子の端が薄く色づいたら取り出す。余った油は後で炒め物に使える。","鍋に15-30mlの油を残し、ひき肉を入れて色が白くなるまで炒めたら取り出す。","鍋に15-30mlの油を入れ、豆板醤、ネギの白い部分、ショウガ、ニンニクを入れて香りが立つまで炒め、ひき肉を戻して均等に炒める。","80-150mlの水を加える（水面が茄子の8割程度の高さになるようにする）。茄子とソースを入れ、強火で炒めて味を絡めながら煮詰める。最後にネギを加えて炒め合わせ、火を止める。"]'::jsonb, '["肉料理","四川風","魚香","甘酸っぱくて少し辛い","家庭料理","ご飯が進む"]'::jsonb),
  ('howtocook:meat_dish/麻婆豆腐/麻婆豆腐', 'ja', 'マーボー豆腐', '肉料理', 'この香辛料が効いて滑らかな豆腐料理は、伝統的な豆板醤の代わりに塩漬けアヒルの卵を使用し、塩味と旨味の中にほのかな痺れと辛みが広がり、ご飯が進む一品です。良質なタンパク質やカルシウム、鉄などの微量元素が豊富。調理難易度は中程度で初心者にも優しく、全体で約40分かかります。', '[{"name":"ソフト豆腐","unit":"パック"},{"name":"塩漬けアヒルの卵","unit":"個"},{"name":"豚バラ肉","unit":"g"},{"name":"ニンニク","unit":"片"},{"name":"ショウガ","unit":"片"},{"name":"小唐辛子","unit":"本"},{"name":"辛味ソース","unit":"g"},{"name":"花椒","unit":"粒"},{"name":"塩","unit":"g"},{"name":"醤油","unit":"g"},{"name":"食用油","unit":"ml"}]'::jsonb, '["ニンニクとショウガをみじん切りにし、取っておく","小さな唐辛子を輪切りにし、取っておく","豚バラ肉をミンチにする（元々ミンチを買った場合はスキップ）","ミンチに塩の半分と味極醤油を加え、よく混ぜて取っておく","アヒルの卵を包丁で縦に半分に切る（安全に注意）、黄身を取り除く（必ず除く、臭みの原因）、残った白身を約2mm角に細かく刻み、取っておく","豆腐のパッケージを開け、フルーツナイフで豆腐を容器の中で約2.5cm×3cmに切り、取っておく","鍋を熱し、10ml～15mlの食用油を入れる。10秒待って油の温度を上げる","弱火にし、ニンニク、ショウガ、唐辛子の輪切り、花椒、塩漬けアヒルの卵、ニンニク味の辛味噌を加えて20秒炒め、香りを出す","中火にし、ミンチを加えて約1分炒め、肉の色が変わるまで炒める","弱火にし、豆腐を加え、残りの塩と味極醤油を豆腐に均等に振りかける","鍋肌から熱湯を注ぐ（そうしないと豆腐が崩れやすい）、豆腐が浸る程度にする","強火にし、沸騰したらすぐに中火にし、約10分待つ","水分が1/5になり、豆腐の表面に色がついたら火を止め、皿に盛る"]'::jsonb, '["肉料理","スパイシー","塩味と旨味","微かな痺れと辛み","ご飯が進む","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/麻辣香锅', 'ja', '麻辣香鍋', '肉料理', 'マーラーの風味が豊かな四川風家庭料理で、野菜や肉、豆腐製品を集め、ピリ辛でやみつきになる味わい。栄養バランスも良く、約30分で完成。', '[{"name":"青菜（油菜、油麦菜、菠菜）","unit":"g"},{"name":"骨なし肉（豚肉、牛肉、鶏肉、魚団子、ハムソーセージ）","unit":"g"},{"name":"干し豆腐","unit":"g"},{"name":"北京麻辣即席麺","unit":"袋"},{"name":"乾燥唐辛子","unit":"g"},{"name":"食用油","unit":"g"}]'::jsonb, '["水を沸騰させる（食材が第2-4手順で浸かる程度の量）。","沸騰したお湯に青菜を入れ、5分茹でて取り出す。","沸騰したお湯に骨なし肉を入れ、4分茹でて取り出す。","沸騰したお湯に北京麻辣即席麺を入れ、2分茹でて取り出す。","お湯を捨て、鍋を拭き、食用油105gを入れ、強火で30秒加熱する。","麻辣香鍋の調味料を入れ、20秒炒める。","乾燥唐辛子を入れ、10秒炒める。","茹でた青菜を入れ、中火に変えて3分炒める。","茹でた骨なし肉を入れ、3分炒める。","茹でた北京麻辣即席麺を入れ、箸で1分混ぜる。","火を止め、盛り付ける。"]'::jsonb, '["肉料理","麻辣","四川風","炒め","ご飯が進む","家庭料理"]'::jsonb),
  ('howtocook:meat_dish/黄油鸡', 'ja', 'バターチキン', '肉料理', 'インド発祥の定番カレー料理。焼いてから煮込んだ鶏もも肉をトマト、バター、生クリームで作ったソースで味付けし、コクと滑らかさがあり、甘酸っぱくて少し辛く、独特のスパイスの香りが広がります。鶏肉、ヨーグルト、カシューナッツは豊富なタンパク質と健康的な脂肪を提供し、トマトとスパイスもビタミンと抗酸化物質をもたらします。作るのはやや難しく、火加減とスパイスのバランスが重要で、漬け込み時間を含め約1時間45分で完成します。', '[{"name":"鶏もも肉（骨なし）","unit":"g"},{"name":"ヨーグルト","unit":"ml"},{"name":"生姜","unit":"g"},{"name":"にんにく","unit":"片"},{"name":"唐辛子粉","unit":"g"},{"name":"ターメリックパウダー","unit":"g"},{"name":"塩","unit":"g"},{"name":"レモン汁","unit":"ml"},{"name":"サラダ油","unit":"ml"},{"name":"トマト","unit":"個"},{"name":"玉ねぎ","unit":"個"},{"name":"カシューナッツ（とろみ付け用）","unit":"g"},{"name":"生姜","unit":"g"},{"name":"にんにく","unit":"片"},{"name":"バター","unit":"g"},{"name":"生クリーム(ヘビークリーム)","unit":"ml"},{"name":"唐辛子粉","unit":"g"},{"name":"コリアンダーパウダー","unit":"g"},{"name":"クミンパウダー","unit":"g"},{"name":"ガラムマサラ","unit":"g"},{"name":"カルダモンパウダー","unit":"g"},{"name":"ドライフェヌグリークリーフ(カスリメティ)","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"塩","unit":"g"},{"name":"水","unit":"ml"}]'::jsonb, '["ボウルにヨーグルト、生姜すりおろし、にんにくすりおろし、唐辛子粉、ターメリックパウダー、塩、レモン汁を混ぜ合わせる","鶏肉を加えて、漬けダレを全体にまぶす","ラップをかけ、冷蔵庫で最低1時間漬け込む","フライパンにサラダ油15mlを入れ、強火で熱する","漬けた鶏肉を（漬けダレは入れずに）フライパンに並べる","強火で両面に焼き色をつける（片面約3分）。鶏肉は完全に火が通っていなくてよい","取り出して置いておく","鍋にトマト、玉ねぎ、カシューナッツ、生姜、にんにく、水100mlを入れる","強火で沸騰させ、中火にして15分煮る。すべての材料が柔らかくなるまで","少し冷ましたら、ミキサーにかけて滑らかになるまでピューレにする","ざるで濾して、なめらかなソースにする。取っておく","炒め鍋にバター50gを入れ、中火で溶かす","濾したトマトソースを加える","唐辛子粉5g、コリアンダーパウダー5g、クミンパウダー3g、塩5gを加える","3〜5分炒め、ソースの色が濃くなり油が浮いてくるまで","焼いた鶏肉を加え、全体を混ぜる","砂糖10g（トマトの酸味を和らげる）を加え、混ぜる","生クリーム100mlを加え、よく混ぜる","弱火で10〜12分煮込み、鶏肉に完全に火が通りソースが絡むまで","ガラムマサラ3g、カルダモンパウダー2gを加える","ドライフェヌグリークリーフ3gを（手で揉んで砕いてから）加える","よく混ぜたら火を止める","皿に盛り、お好みで生クリームを少量かけて飾る"]'::jsonb, '["肉料理","インド風味","カレー","スパイシー","コクがある","おもてなし"]'::jsonb),
  ('howtocook:meat_dish/黄焖鸡', 'ja', '黄焖チキン', '肉料理', '黄焖鶏は、鶏もも肉、椎茸、ピーマンを主材料とする家庭料理です。スープは濃厚で、鶏肉は柔らかく、塩味と旨味に甘みがほんのりあり、ご飯が進みます。良質なタンパク質やキノコ類の多糖類などの栄養が豊富です。炒め糖色の工程は少し難しいですが、老抽で代用可能で、全体的に難易度は高くなく、初心者でも無理なく作れます。下ごしらえから完成まで約40分かかります。', '[{"name":"鶏もも肉","unit":"本"},{"name":"椎茸（干し椎茸がベスト）","unit":"個"},{"name":"ピーマン","unit":"個"},{"name":"生姜（薄切り）","unit":"枚"},{"name":"干し唐辛子","unit":"本"},{"name":"塩","unit":"g"},{"name":"料理酒","unit":"ml"},{"name":"白こしょう","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"醤油","unit":"ml"},{"name":"味の素","note":"適量"},{"name":"じゃがいも（お好みで）","unit":"個"}]'::jsonb, '["鶏もも肉を洗い、4cm大のぶつ切りにする","生姜は薄切りに、干し唐辛子は小口切りにする","椎茸は薄切りに、ピーマンは細長い馬蹄形に切る。干し椎茸の場合は、ほこりを洗い落とし、一晩水に浸けて戻し、戻し汁を取っておく","じゃがいもを使う場合は、鶏肉と同じくらいの大きさの乱切りにする","糖色炒め：鍋に油をひき、冷たい油の状態で砂糖を入れる（少し難しいので、初心者は鶏肉炒めの工程に飛び、老抽で代用してもよい）","弱火でゆっくり加熱し、油の温度が上がるにつれて砂糖が溶け始め、濃い茶色になるまで炒める（焦げないように絶えず混ぜる）","すぐに鶏肉を加え、強火にして手早く炒める！料理酒を加え、さらに炒める","生姜の薄切りと干し唐辛子を加える","醤油を加え、炒め合わせる","椎茸の戻し汁または水を、鶏肉がかぶるくらいまで加える","椎茸の薄切り、白こしょう、塩、じゃがいもを加える","よく混ぜ合わせたら、蓋をして煮込む。中弱火にして15〜20分。可能なら土鍋に移す","鶏肉が柔らかくなり、煮汁がとろりとしたら（煮詰めすぎない）、最後にピーマンを加える","味の素を加え、さっと炒め合わせ、火を止める！ピーマンに火が通ったらOK、炒めすぎない"]'::jsonb, '["肉料理","塩味と旨味","ほんのり甘い","煮込み","家庭料理","ご飯が進む"]'::jsonb),
  ('howtocook:meat_dish/黄瓜炒肉', 'ja', 'きゅうりの肉炒め', '肉料理', 'さっぱりとしたシャキシャキ食感の家庭料理です。塩味と旨味が効いていて、ニンニクの香りとほんのり辛さが特徴。たんぱく質やビタミンが豊富で、体の熱を冷まし水分補給にも役立ちます。初心者にも優しく、火加減に注意すれば成功間違いなし。調理時間は約25分です。', '[{"name":"きゅうり","unit":"g"},{"name":"豚もも肉","unit":"g"},{"name":"サラダ油","unit":"g"},{"name":"醤油","unit":"g"},{"name":"塩","unit":"g"},{"name":"ニンニク","unit":"片"},{"name":"唐辛子（小）","unit":"本"}]'::jsonb, '["豚もも肉をスライスし、ボウルに入れ、サラダ油10g、醤油を加えて混ぜ合わせ、10分間漬け込む","きゅうりの端を5cm切り落とし、残りを斜めに0.5cmの薄切りにする","きゅうりをボウルに入れ、塩8gをふりかけ、混ぜ合わせて5分間漬ける","ニンニクの皮をむき、つぶして、みじん切りにする","唐辛子（小）のヘタを除き、0.5cm幅の輪切りにする","フライパンを熱し、油40gを入れ、煙が出るまで温めたら、ニンニクみじん切りと唐辛子を加えて5回炒める","漬け込んだ豚肉を加え、肉の色が変わるまで炒める","きゅうりを加え、塩2gをふり、強火で手早く30秒ほど炒めて完成","強火が保てない場合、少し生っぽくなるかもしれません。その場合は50秒に増やしてください。"]'::jsonb, '["肉料理","家庭料理","スピード料理","塩味","ピリ辛","ご飯が進む","さっぱり"]'::jsonb),
  ('howtocook:meat_dish/黑椒牛柳/黑椒牛柳', 'ja', 'ブラックペッパー牛柳', '肉料理', 'ブラックペッパー牛柳は、人気の家庭料理です。ブラックペッパーの風味が豊かで、牛柳は柔らかく、甘くてシャキシャキの玉ねぎとパプリカと合わせて、肉と野菜のバランスが良く、老若男女問わず好まれます。牛肉は良質なタンパク質と鉄分が豊富で、パプリカと玉ねぎは様々なビタミンを補給できます。この料理は初心者にも優しく、準備から完成まで通常1時間以内でできます。', '[{"name":"牛肉（ヒレ肉/ステーキ肉）","unit":"g"},{"name":"玉ねぎ","unit":"個"},{"name":"パプリカ（赤/黄）","unit":"個"},{"name":"片栗粉","unit":"g"},{"name":"ブラックペッパー（粉）","unit":"g"},{"name":"ブラックペッパー（漬けダレ）","note":"適量"},{"name":"塩","unit":"g"},{"name":"ピーナッツ油","unit":"ml"}]'::jsonb, '["牛肉を細切りにします。長さは8cm以下、厚さは約5-10mm、幅は約1cmが目安です（厳密でなくてOK）。","漬けダレで牛肉を漬け込みます。よく混ぜてから置いておきます。量と時間は商品の説明に従ってください。延ばすことはできますが、短縮しないでください。","液体の漬けダレを使用する場合、漬け込み終了の3分前にブラックペッパーをふりかけ、その後で片栗粉を加え、再び混ぜ合わせて20分置きます。","火をつけて鍋を熱し、ピーナッツ油を加えます。","鍋の油からわずかに煙が出てきたら、牛肉を入れて炒めます。","中火よりやや強火にして、2分ほど牛肉の表面の色が変わるまで炒めます（血の色がなくなること。血の色が残っている部分は炒めが足りない証拠です）。油のはねに注意してください。","玉ねぎとパプリカを加えて、2分ほど炒めます。","塩を加え、再度ブラックペッパーをふりかけ、30秒ほど炒めて均一に混ぜます。","玉ねぎが柔らかくなったら火を止め、皿に盛り付けます。"]'::jsonb, '["肉料理","ブラックペッパー","家庭料理","炒め物","ご飯が進む","手早くできる"]'::jsonb),
  ('howtocook:meat_dish/黔式腊肠娃娃菜/黔式腊肠娃娃菜', 'ja', '黔式ソーセージとベビー白菜の煮物', '肉料理', 'この料理は塩味と旨味が絶妙で、黔式ソーセージの豊かな香りとベビー白菜の自然な甘さが調和しています。西南料理の中では珍しい辛くない味わいで、南北どちらでも好まれます。ベビー白菜はビタミンと食物繊維が豊富で、ソーセージのたんぱく質や脂質と組み合わせることで栄養バランスが良いです。調理法は非常に簡単で、火加減を気にしたり追加の調味料を加える必要はなく、準備から完成までたったの15分。初心者にも忙しい日常にもぴったりです。', '[{"name":"黔式ソーセージ","unit":"グラム"},{"name":"ベビー白菜","unit":"グラム"},{"name":"水","unit":"ミリリットル"}]'::jsonb, '["鍋に750mlの水を入れ、火にかけて沸騰させます。","ソーセージを入れ、13分茹でます。","ベビー白菜を入れ、2分茹でます。","火を止め、ソーセージとベビー白菜を取り出します。","ベビー白菜はざく切り、ソーセージは輪切りにして、皿に盛ります。"]'::jsonb, '["肉料理","塩味と旨味","煮る","黔式","時短","家庭料理"]'::jsonb),
  ('howtocook:semi-finished/凉皮', 'ja', '涼皮（リャンピー）', '半調理品', '涼皮は陝西省発祥の家庭的な軽食で、コシがありつるっとした食感が特徴。酸味と辛味が食欲をそそり、濃厚なごまダレの風味が広がります。ごまダレと麩は良質な植物性タンパク質とカルシウムを提供し、さっぱりしたキュウリともやしがビタミンと食物繊維を補います。調理難易度は中程度で、茹でて切ってタレを合わせるだけなので、初心者でも気軽に作れます。準備から完成まで約40分で、夏の食卓にぴったりです。', '[{"name":"涼皮","unit":"g","note":""},{"name":"麩（面筋）","unit":"","note":"適量"},{"name":"塩","unit":"","note":"好みで調整"},{"name":"鶏がらスープの素","unit":"","note":"数回に分けて加える"},{"name":"オイスターソース","unit":"","note":"数回に分けて加える"},{"name":"薄口醤油","unit":"","note":"数回に分けて加える"},{"name":"濃口醤油","unit":"","note":"数回に分けて加える"},{"name":"ごま油","unit":"g","note":""},{"name":"香醋","unit":"","note":"好みで調整"},{"name":"芝麻酱（ごまペースト）","unit":"g","note":""},{"name":"きゅうり","unit":"g","note":""},{"name":"にんにく","unit":"g","note":""},{"name":"もやし","unit":"g","note":""}]'::jsonb, '["鍋に水500mlを加える。沸騰させる。","もやしを鍋に入れ、強火で60秒茹でる。ザルにあげて冷水にさらし、皿に盛っておく。","キュウリを千切りにして皿に盛っておく。","ニンニク10gの皮をむき、すり鉢に入れて塩1gを加え、すりつぶしてペースト状にする。水10gを加えて混ぜ、置いておく。","注：スーパーで買った涼皮の表面には食用油がついていることがあるので、水道水で洗ってもよい。麩も同様。","注：麩を洗った後は、手でしっかり水気を絞る（強く絞りすぎない）。","小さなボウルに塩3g、鶏がらスープの素2g、薄口醤油5g、濃口醤油1g、ごま油1g、オイスターソース2g、香醋5gを入れる（塩と香醋は好みで調整可。上記は一般的な量）。","上記の調味料にぬるま湯25〜35g（好みの塩加減に応じて）を加え、箸でよく混ぜて溶かす。冷まして置いておく。","注：以下の分量は1人前です。n人分の場合はn倍にしてください。","小さなボウルを用意し、準備したごまダレを入れる。","塩4g、鶏がらスープの素3g、薄口醤油5g、濃口醤油1g、オイスターソース3gを加える。","箸で調味料とごまダレをよく混ぜる。","水10gを加えて混ぜる。","前の手順を2〜3回繰り返す（回数は好みの濃度による）。","先ほど用意した大きめのボウルに、準備した涼皮を入れる。","塩水を注ぎ入れ、箸でよく混ぜる。そのまま小さな器に盛る（塩水も一緒に）. ","もやしを涼皮の上にのせ、その上に麩をのせる。","調合したごまダレを麩の上からかける。","キュウリの千切りを散らす。","お好みでラー油をかける。","色・香り・味がそろった家庭的な涼皮の完成！"]'::jsonb, '["半製品","酸辣","和え物","陝西風","家庭料理","食欲増進","夏向け"]'::jsonb),
  ('howtocook:semi-finished/半成品意面', 'ja', '半製品パスタ', '半調理品', '市販の半製品を使って手早く作れる洋風の簡単料理。麺はコシがありもっちり、ソースは濃厚な味わい。炭水化物がメインですぐにエネルギーを補給でき、タンパク質も含む。初心者でも失敗なく、火をつけてから盛り付けまで約2分。', '[{"name":"半製品パスタ（おすすめブランド：プルムド）","unit":"g"},{"name":"水","unit":"ml"}]'::jsonb, '["フライパンを熱する","フライパンに水50mlを入れる","麺を入れて1分炒める","ソースを入れて1分炒める","盛り付けて完成","麺を電子レンジ対応の皿に入れる","付属のソースを麺にかける","水50mlを加える","700Wで2分加熱する","取り出して混ぜて完成"]'::jsonb, '["半製品","時短","家庭料理","洋風","パスタ","インスタント"]'::jsonb),
  ('howtocook:semi-finished/懒人蛋挞/懒人蛋挞', 'ja', '懒人エッグタルト', '半調理品', 'このデザートは市販のエッグタルトの皮と液を使い、外はサクサク、中はとろけるような滑らかさで、キャラメルの斑点が特徴です。広東風点心の中でも最も簡単に作れるバージョンです。主な材料の卵と牛乳は良質なたんぱく質とカルシウムを提供し、家庭での軽食に最適です。作業は組み立てと焼くだけで、完全な初心者にも優しく、オーブンの予熱から焼き上がりまで約40分です。', '[{"name":"エッグタルトの皮","unit":"個"},{"name":"エッグタルト液","unit":"ml"}]'::jsonb, '["オーブンを200度に予熱し、10分放置する","天板にエッグタルトの皮を並べ、皮にエッグタルト液を約10ml注ぐ。量は皮の大きさによるが、通常は4/5程度入れる","天板をオーブンに入れ、上下火190度で10〜20分焼く。液に焦げ目を早く付けたい場合は、上火を200〜210度に高くする","エッグタルト液に焦げ目がつき、皮が完全に膨らんで油が浮き出てきたら完成"]'::jsonb, '["半製品","甘い","焼き菓子","広東風","時短","初心者向け"]'::jsonb),
  ('howtocook:semi-finished/炸薯条/炸薯条', 'ja', 'フライドポテト', '半調理品', '外はカリッと中はホクホク、黄金色で塩味の効いたフライドポテトは、大人気のファストフードおやつです。じゃがいもは炭水化物と食物繊維を提供しますが、油で揚げたりエアフライヤーで調理するとカロリーが高くなります。冷凍フライドポテトとエアフライヤーを使えば、初心者でも簡単に作れます。予熱から完成まで約25分です。', '[{"name":"半製品フライドポテト（おすすめブランド：マッケイン）","unit":"g"},{"name":"油","note":"適量"}]'::jsonb, '["大容量の半製品フライドポテトを開封する際は、開口部を小さくしてください。長期間保存した際にポテト表面の霜を効果的に減らせます。","電源を入れ、200℃で5分予熱する。","予熱の目的は、食材を入れるときに鍋内が調理に必要な温度に達していることを確認するためです。","注意：予熱が終わってからポテトを取り出してください。ポテトが柔らかくなってから揚げないでください。","ポテトを取り出してエアフライヤーに入れ、200℃で20分加熱する。","ポテトを取り出す際、半製品ポテトにはすでに油が付いているので、やけどに注意。挟み具を使うことをおすすめします。","5～10分経ったら、鍋を取り出して振り、ポテトに均等に熱が通り、くっつかないようにする。","10～15分経ったら、鍋を取り出し、乾いたポテトの表面に、ポテト表面積の3分の2の面積に油を1回スプレーする。","カリッとしたポテトが好きな場合は、鍋を持って踊るように空気を通してから盛り付け。柔らかいポテトが好きな場合はそのまま盛り付け。ディップソースやソースをかけるとさらに美味しい。"]'::jsonb, '["半製品","時短","おやつ","塩味","エアフライヤー"]'::jsonb),
  ('howtocook:semi-finished/牛油火锅底料', 'ja', '牛油火鍋の素', '半調理品', 'この重慶火鍋の素は、たっぷりの牛油をベースに、もち米唐辛子とさまざまな香辛料をブレンドして煮込んだもので、辛さとコクが深く、香り高い。ハチノスやアヒルの腸などの具材をしゃぶしゃぶするのに欠かせない。牛油とラードは豊富なエネルギーを提供し、唐辛子と花椒は体を温め、食欲を促進するが、油分が多いので控えめに食べるのが良い。製造工程では油の温度と炒め加減を正確にコントロールする必要があり、初心者には少し難しい。準備から完成まで約1時間かかる。', '[{"name":"牛油","unit":"g"},{"name":"サラダ油/菜種油","unit":"ml"},{"name":"純ラード","unit":"g"},{"name":"豆板醤","unit":"g"},{"name":"もち米唐辛子","unit":"g"},{"name":"ショウガ","unit":"g"},{"name":"長ネギ","unit":"g"},{"name":"タマネギ","unit":"g"},{"name":"ニンニク","unit":"g"},{"name":"豆鼓","unit":"g"},{"name":"豆母子","unit":"g"},{"name":"花椒","unit":"g"},{"name":"粒状香辛料","unit":"g"},{"name":"整形香辛料","unit":"g"},{"name":"麦芽粉","unit":"g"},{"name":"白酒","unit":"ml"},{"name":"乾燥唐辛子粉","unit":"g"},{"name":"山奈","unit":"g"},{"name":"八角","unit":"g"},{"name":"草果","unit":"g"},{"name":"肉桂","unit":"g"},{"name":"丁香","unit":"g"},{"name":"小茴香","unit":"g"},{"name":"白芷","unit":"g"},{"name":"荜拨","unit":"g"},{"name":"香草","unit":"g"},{"name":"香果","unit":"g"},{"name":"山楂","unit":"g"},{"name":"陳皮","unit":"g"},{"name":"香茅","unit":"g"},{"name":"砂仁","unit":"g"},{"name":"白蔻","unit":"g"},{"name":"香葉","unit":"g"}]'::jsonb, '["鍋を強火にかけ、牛油を入れて240±10°C（8分熱）まで熱し、ショウガ、長ネギ、タマネギ、ニンニク（各100g）を加えて乾くまで揚げ（臭み（牛油の生臭さ）を吸わせる）、取り出して捨てる。","サラダ油（または菜種油）と純ラードを加え、油温が150±10°C（5分熱）に下がったら、もち米唐辛子を加えて5〜8分間絶えず炒める。","豆板醤を加えてほぐし、中弱火でゆっくりと炒め、具が少し白っぽくなりサラサラと音がするまで炒める。","油がサクランボ色になったら、ショウガのスライス（150g）とニンニク（100g）を加えて香りが立つまで約15秒炒める。","豆鼓、豆母子を加えて香りを出し、花椒、小茴香を加えて香りを出す。","（老油）ここで粒状香辛料を加える。","麦芽粉を加えてほぐし、白酒を加えてほぐす。","鍋から取り出して容器に入れ、低温（10〜20℃）の場所に5日間置いてから使用すると最良。","鍋から取り出して容器に入れ、乾燥唐辛子粉を加えて混ぜ、24時間置いて老油を作る。","底料を鍋に戻し、3/5の熱湯を加えて強火で沸騰させる（底料：2/5、熱湯：3/5）。","沸騰後に表面に浮かぶ泡を取り除く。","中弱火に変えてゆっくりと味を抽出する（約25〜30分）、濾してかすを取り除く。","容器内で油と水が分離するのを待ち、表面の油を取り除き（油をすくい取る）、別の容器に入れる。","前の工程ですくい取った油をきれいな鍋に戻し、油中の水分が完全に飛ぶまで加熱し、鍋から取り出して容器に入れる。これが火鍋老油となる。"]'::jsonb, '["半製品","麻辣","炒め","重慶","油多め","自家製底料"]'::jsonb),
  ('howtocook:semi-finished/空气炸锅羊排/空气炸锅羊排', 'ja', 'エアフライヤーラムチョップ', '半調理品', 'この料理は超ずぼらな作り方で、エアフライヤーを使うことで余分な脂を落とし、外はカリッと中はジューシー、ガーリックの香りが豊か。味は主にラムチョップの質に左右されます。ラム肉には良質なタンパク質や鉄、亜鉛などのミネラルが豊富で、体を温め、気血を補い、体力向上に役立ちます。調理難易度は中程度で、初心者でも簡単に作れます。実際の作業時間はわずか10分、漬け込み時間を含めても約40分で食卓に出せます。', '[{"name":"ラムチョップ","unit":"枚"},{"name":"黒胡椒ミックスステーキ調味料","unit":"g"},{"name":"ニンニクペースト","unit":"g"},{"name":"バター","unit":"小パック"},{"name":"焼き肉のタレ","unit":"g"},{"name":"乾燥バジル","note":"適量"}]'::jsonb, '["ラムチョップをボウルに入れ、水で血を洗い流す","ラムチョップの水気をキッチンペーパーで拭き取り、両面に黒胡椒ミックス調味料とニンニクペーストを塗り、20分間漬け込む","アルミホイルの器を焼き網に置き、その上にラムチョップをのせ、バジルをふりかけ、バターまたは焼き肉のタレをラムチョップの上にのせ、エアフライヤーで180°Cで10分","ラムチョップを裏返し、バジルをふりかけ、バター（アルミホイルの器からすくい上げる）または焼き肉のタレをラムチョップの上にのせ、エアフライヤーで180°Cで5分（好みで少し時間を追加してもよいが、ここでは焦げない時間を記載）"]'::jsonb, '["半製品","エアフライヤー","ガーリック香","黒胡椒","時短","家庭料理","ずぼら"]'::jsonb),
  ('howtocook:semi-finished/空气炸锅鸡翅中/空气炸锅鸡翅中', 'ja', 'エアフライヤーチキンウィングミドル', '半調理品', '手軽で便利な家庭料理のスピードレシピです。外はカリッと中はジューシーで、油の香りが食欲をそそります。ファストフード店のものよりずっと美味しいです。チキンウィングミドルは良質なタンパク質と脂肪が豊富で、エネルギーたっぷり。初心者にも優しく、実際の作業は数分で、全体で約40分で食べられます。', '[{"name":"鶏中手羽","unit":"個"},{"name":"ドライバジル","note":"適量"},{"name":"雲南単山蘸水","note":"適量"}]'::jsonb, '["冷凍庫から鶏中手羽を取り出し、皮面を下にしてアルミホイルトレイに並べ、ドライバジルをふりかけ、ラップをかけて自然解凍20分","ドライバジルをふりかけ、エアフライヤー200°Cで10分","裏返し、ドライバジルをふりかけ、エアフライヤー200°Cで7分"]'::jsonb, '["半製品","スピード","家庭料理","オルレアン","香ばしい","おつまみ"]'::jsonb),
  ('howtocook:semi-finished/速冻水饺', 'ja', '冷凍餃子', '半調理品', 'これは中国発祥の家庭的な麺料理で、市販の冷凍餃子を使った即席レシピです。皮は薄く、具はたっぷりで、風味豊かです。酢、生姜、にんにくなどのタレをつけることで、味わいに深みが増します。一食として、十分なタンパク質と炭水化物を摂取でき、栄養満点でお腹も満たされます。難しい工程は一切なく、初心者でも簡単に作れ、前後わずか約15分で完成します。', '[{"name":"冷凍餃子","unit":"個"},{"name":"水","note":"適量"},{"name":"酢","note":"適量"},{"name":"生姜","note":"適量"},{"name":"にんにく","note":"適量"}]'::jsonb, '["中火で鍋に水を入れ、沸騰するまで待ちます。","餃子を鍋に入れます。","鍋に入れる前に、軽く水で洗っても構いません。","餃子を入れた後、お玉やヘラで水をかき混ぜますが、餃子に当たらないように注意してください。鍋にくっついて皮が破れたり、互いにくっついて中まで火が通らなくなるのを防ぎます。","頻度は高くなくてよく、平均30秒ごとに3秒ほど揺らします。餃子が浮いてきたらこの工程は不要です。","餃子が浮き、再び沸騰したら、お玉で1つすくい上げて確認します。皮に生焼けがあれば、お玉で80mlの冷水を加えて温度を下げ、再び沸騰するまで煮ます。その間、この確認とかき混ぜを繰り返し、最大2回水を加えれば完全に火が通ります。","すべての餃子が浮き上がったら（餃子を入れてから約8分後）、ヘラや穴あきお玉で餃子を皿や器に取り出し、盛り付けて完成です。","餃子を食べ終わったら、鍋の水温が下がるのを待って、水を捨て、食器用洗剤で鍋をすぐに洗います。そうしないと、時間が経つと鍋に煮た小麦粉がべとべとした状態で固まってしまいます。"]'::jsonb, '["半製品","時短","家庭料理","風味豊か","煮る","満腹"]'::jsonb),
  ('howtocook:semi-finished/速冻汤圆/速冻汤圆', 'ja', '冷凍白玉団子', '半調理品', '冷凍白玉団子は手軽な電子レンジデザートで、皮はもちもち、中身は甘く、中華風伝統のおやつです。主に炭水化物を補給し、素早くエネルギーをチャージできます。作り方はとても簡単で、初心者でも楽に作れます。準備から完成まで約6分です。', '[{"name":"冷凍白玉団子","unit":"個"}]'::jsonb, '["冷凍白玉団子を取り出し、器に入れる。","熱湯を白玉団子が浸かるまで注ぐ。","電子レンジ強火で4分加熱する。","白玉団子がすべて水分を吸って膨らんでいたら、加熱完了。","もし加熱が足りなければ、さらに1分加熱する。"]'::jsonb, '["半製品","手軽","電子レンジ","もちもち","甘い","中華風"]'::jsonb),
  ('howtocook:semi-finished/速冻馄饨', 'ja', '冷凍ワンタン', '半調理品', '冷凍ワンタンは皮が薄くて餡が柔らかく、スープは澄んでいて味がさっぱりしている、便利な家庭向け麺料理です。主に炭水化物とタンパク質を提供し、素早くエネルギーを補給できます。作り方は簡単で、初心者にもとても優しく、炊飯器で完成します。お湯を沸かしてから出来上がりまで約55分かかります。', '[{"name":"冷凍ワンタン","unit":"個"},{"name":"水","unit":"ml"},{"name":"塩","note":"調味料の小袋がない場合、好みで適量"},{"name":"チキンエッセンス","note":"調味料の小袋がない場合、好みで適量"},{"name":"胡椒","note":"調味料の小袋がない場合、好みで適量"},{"name":"ごま油","note":"調味料の小袋がない場合、好みで適量"},{"name":"パクチー","unit":"枚"}]'::jsonb, '["炊飯器に水を入れ、煮込み又は炊飯モードで35分運転する。この時、蓋を開けて水が沸騰していることを確認する。","冷凍ワンタンを慎重に水の中に入れる。やけどに注意する。","炊飯器に入れる前に、軽く水で洗ってもよい。","ワンタンに調味料の小袋が付いている場合は、この時一緒に水に加える。","炊飯器の蓋を閉め、同じ煮込み又は炊飯モードで20分運転する。","全てのワンタンを、全てのワンタンが浸る程度のスープと一緒に丼に盛る。","もし先に調味料を加えていなければ、この時自分の好みに応じて塩、チキンエッセンス、胡椒、ごま油で味を調える。","また、パクチーの葉を5〜8枚散らしてもよい（パクチーの味が気にならない方のみ）。"]'::jsonb, '["半製品","家庭料理","あっさり","麺類","煮る","初心者向け"]'::jsonb),
  ('howtocook:soup/勾芡香菇汤/勾芡香菇汤', 'ja', 'しいたけのとろみスープ', 'スープ', 'しいたけのとろみスープは、濃厚で旨味があり、滑らかで飲みやすい、手早く作れる家庭的なスープです。しいたけには豊富なアミノ酸と多糖類が含まれており、免疫力向上に役立ちます。調理には基本的な火加減ととろみをつける技術が必要ですが、初心者にも優しいレシピです。準備から完成まで約25分です。', '[{"name":"生しいたけ","unit":"個"},{"name":"長ネギ","unit":"本"},{"name":"サラダ油","unit":"ml"},{"name":"食塩","unit":"g"},{"name":"鶏がらスープの素","unit":"g"},{"name":"片栗粉","unit":"g"},{"name":"熱湯","unit":"ml"}]'::jsonb, '["しいたけを薄切りにし（厚さ0.5〜1cm、薄いより厚めの方が歯応えがあります）、大きめのボウルに入れ、2gの食塩を加えて15分浸します。","片栗粉を小さなボウルに入れ、50mlの水を加えて、ダマがなくなるまで混ぜます（水溶き片栗粉）。","ボウルの塩水を捨て、しいたけの水分を適度に取り除きます（次の炒め工程のため）【任意】","弱火で油を熱し、小さな泡が出始めたら（弱火で30秒、鍋の出力による）、しいたけを加え、片面10秒ずつ炒めます【任意】","熱湯300mlを注ぎ、中火にしてさらに3〜5分煮ます。","水溶き片栗粉を加え、鍋のスープを軽く混ぜた後、3gの塩、3gの鶏がらスープの素を加え、最後に刻みネギを散らして完成です。"]'::jsonb, '["スープ","旨味","あっさり","時短","家庭料理","とろみ"]'::jsonb),
  ('howtocook:soup/奶油蘑菇汤', 'ja', 'クリームマッシュルームスープ', 'スープ', 'これはクラシックなフランス風の濃厚スープで、なめらかでクリーミーな口当たり、キノコの香りとミルクの風味が調和しています。マッシュルームは食物繊維とミネラルが豊富で、牛乳は良質なタンパク質とカルシウムを提供します。作り方はとても簡単で、初心者でも楽に作れます。準備から完成まで約30分かかります。', '[{"name":"マッシュルーム","unit":"グラム"},{"name":"玉ねぎ","unit":"グラム"},{"name":"バター","unit":"グラム"},{"name":"小麦粉","unit":"グラム"},{"name":"牛乳","unit":"ミリリットル"},{"name":"生クリーム","unit":"ミリリットル"},{"name":"水","unit":"ミリリットル"},{"name":"塩","unit":"グラム"},{"name":"黒コショウ","unit":"グラム"}]'::jsonb, '["マッシュルームは薄切りにし、玉ねぎはみじん切りにしておく。","フライパンにバターを入れ、弱火で溶かしたら玉ねぎを加えて透明になるまで炒める。","マッシュルームを加えて水分が出て柔らかくなるまで炒め、小麦粉を振り入れてよく混ぜる。","牛乳と水を加えて混ぜ合わせ、弱火で沸騰させる。焦げ付かないように混ぜ続ける。","弱火で約10分煮込み、スープにとろみが出るまで加熱する。","生クリームを加えてさらに1分加熱し、塩と黒コショウで味を調える。","火を止めた後、ブレンダーでなめらかなスープにしてもよい（お好みで）。"]'::jsonb, '["スープ","フレンチ","ミルク風味","煮込み","簡単","家庭料理","旨味"]'::jsonb),
  ('howtocook:soup/小米粥', 'ja', '粟粥', 'スープ', '粟粥は北方でよく見られる家庭的なお粥で、口当たりは滑らかで、米の香りが豊かです。特に煮出した米油は胃に優しいです。たんぱく質、脂質、炭水化物、カロテンが豊富で、ビタミンB1の含有量は穀物の中でトップクラスです。消化吸収が良く、作り方はとても簡単で、初心者でも気軽に作れます。湯を沸かしてから出来上がりまで約30〜35分かかります。', '[{"name":"粟","unit":"グラム"},{"name":"水（山の湧き水がベスト）","unit":"グラム"}]'::jsonb, '["粟 100グラムをボウルに入れ、水で軽くひと洗いします（手で混ぜて水を捨てます。外側のほこりを取るだけで、こすり洗いは絶対にしないでください！！！）","水を沸騰させます。必ず沸騰させてください！！！","水が沸騰したら、粟を鍋に加えます。（見落としがちなとても重要なポイントです）","かき混ぜて粟が鍋底にくっつかないようにし、強火のまま6〜10分間煮ます。途中で何度かかき混ぜてください。","中火〜弱火にして15〜20分間煮ます。鍋の蓋は少しずらして、粟の油が逃げないように注意してください。途中で何度かかき混ぜて、鍋底が焦げないようにしてください。"]'::jsonb, '["お粥","あっさり","風味豊か","煮込み","北方","朝食","家庭料理"]'::jsonb),
  ('howtocook:soup/排骨山药玉米汤/排骨山药玉米汤', 'ja', 'スペアリブと長芋とトウモロコシのスープ', 'スープ', 'スペアリブと長芋とトウモロコシのスープは、甘くてコクがあり、長芋は柔らかく、トウモロコシは甘みが戻って、スペアリブの旨みが溶け込んだ、老若男女問わず楽しめる家庭的なスープです。タンパク質、食物繊維、各種ビタミンが豊富で、脾と胃を丈夫にし、抵抗力を高める効果があります。作り方は簡単で、下準備と煮込みの手順が明確なため、初心者でも気軽に作れ、全体で約1時間で完成します。', '[{"name":"スペアリブ","unit":"g"},{"name":"長芋","unit":"本"},{"name":"人参","unit":"本"},{"name":"トウモロコシ","unit":"本"},{"name":"生姜","unit":"g"},{"name":"小ネギ","unit":"g"},{"name":"料理酒","unit":"ml"},{"name":"食用油","unit":"ml"},{"name":"飲料水","unit":"ml"},{"name":"食塩","unit":"g"}]'::jsonb, '["食材の下ごしらえ：","人参を洗って皮をむき、約3cmの乱切りにする。","トウモロコシを洗い、約4cmの円柱状の小片に切る。","長芋の皮をむく（粘液で肌がかぶれないよう手袋を推奨）、約4cmの長さに切り、準備しておく。","スペアリブの下茹で：","鍋に十分な冷水を入れ、洗ったスペアリブを加える。","約10gの生姜の薄切り、ネギの結び、15mlの料理酒を加える。","強火で沸騰させ、沸騰してから3分間待ち、その間スプーンで表面のアクを取り除く。","スペアリブを取り出し、約40℃のぬるま湯で不純物を洗い流し、水気を切っておく。","スペアリブを炒める：","鍋を熱し、10mlの食用油を入れ、10秒待って油の温度を上げる。","残りの約10gの生姜の薄切りを入れて香りを出す。","準備したスペアリブをすべて入れ、中火で約1分間炒め、表面が軽く焦げ目がつくまで炒める。","煮込み工程：","鍋に一度に1500ml～2000mlの飲料水を加える。","準備した人参、トウモロコシ、長芋をすべて加える。","強火で沸騰させたら弱火にし、蓋をして40分間弱火で煮込む。","味付けと盛り付け：","6g～8gの食塩を加え、スプーンでよく混ぜる。","弱火のままさらに2分間煮込み、塩味をなじませる。","火を止め、お好みで小口ネギを散らして盛り付ける。"]'::jsonb, '["スープ","あっさり","煮込み","家庭料理","滋養"]'::jsonb),
  ('howtocook:soup/排骨苦瓜汤/排骨苦瓜汤', 'ja', '豚スペアリブと苦瓜のスープ', 'スープ', '豚スペアリブと苦瓜のスープは、スープの色が澄んでいて、旨味が広がり後味に甘みのある広東風の家庭的なスープです。スペアリブは柔らかく、苦瓜は熱を冷まし油っこさを取ります。タンパク質とビタミンが豊富で、桜エビがカルシウムも補給します。処理には下茹でして臭みを取り、苦瓜のワタを丁寧に取り除く必要があり、初心者には少し難しいですが、電気圧力鍋を使うと大幅に簡略化できます。伝統的な弱火煮込みは2～4時間かかりますので、4時間前に準備することをおすすめします。圧力鍋なら約1時間で済みます。', '[{"name":"豚スペアリブ","unit":"グラム"},{"name":"ゴーヤ","unit":"グラム"},{"name":"桜エビ","unit":"グラム"},{"name":"生姜","unit":"グラム"}]'::jsonb, '["スペアリブを洗い、約4cm ±2cm × 3 ±2cmの小片に切る（骨切り道具がない場合は、お店の人に頼んでも良い）","炒め鍋に冷水700mlとスペアリブを入れ、加熱して沸騰させる。火を止めてスペアリブを取り出す。","苦瓜を半分に切り、内部の種とワタをきれいに取り除き、0.5 ± 0.3 cmの細切りにして洗う。","スープ鍋に水1100mlとスペアリブを入れ、強火にする。","水が沸騰したら苦瓜と桜エビを加え、弱火にする。120～240分待つ（120分後に肉を一つ取り出して味見し、骨から簡単にほぐれるようであれば火を止める）。","火を止める時に塩と白こしょうを加える。推奨量は250mlあたり塩0.3～0.6g、白こしょう0.1～0.5g。","水1000mlとスペアリブ、桜エビ、苦瓜を入れる。","スープモードを選択して調理する（通常は加圧調理45分）。","火を止め、スープ鍋と同じように塩とこしょうで味を調える。"]'::jsonb, '["スープ","広東風","家庭料理","旨味","清熱","煮込み","カルシウム補給"]'::jsonb),
  ('howtocook:soup/昂刺鱼豆腐汤/昂刺鱼豆腐汤', 'ja', 'ギギナマズ豆腐スープ', 'スープ', 'ギギナマズ豆腐スープは、やわらかくて白いスープが美味しい家庭料理。魚は骨が少なくて身が柔らかく、豆腐はなめらか。胡椒のピリッとした温かさがポイントで、どの年代の人にも合うよ。魚には良質なタンパク質がたっぷり、豆腐と一緒に食べるとカルシウムも補給できて、栄養バランスが良くて吸収されやすい。作り方はそんなに複雑じゃなくて、臭み取りと魚を焼くときのくっつき防止に気をつければ、初心者でも大丈夫。調理時間は約40分。', '[{"name":"ギギナマズまたはハゼ","unit":"尾"},{"name":"豆腐","unit":"グラム"},{"name":"青ネギ","unit":"本"},{"name":"生姜","unit":"かけ"},{"name":"食用油","unit":"ミリリットル"},{"name":"料理酒","unit":"ミリリットル"},{"name":"食塩","unit":"グラム"},{"name":"胡椒","unit":"グラム"},{"name":"熱湯","unit":"リットル"}]'::jsonb, '["魚を処理して洗い（特に腹の中の血の筋は丁寧に洗わないと生臭い）、大きめのボウルに入れ、料理酒、生姜スライス10g、塩5gを加えて15分漬け込む。","豆腐を一口大に切り、冷水に5分浸してから水気を切っておく。","魚を焼く前に、生姜の切り口で鍋の内側を拭いてくっつき防止。油（魚の尾数×15ml）を入れて熱し、魚を並べて2～3分焼く。途中、鍋を揺すって底にくっつかないようにし、一度ひっくり返す。","魚をすべて焼き終えたら、熱湯、料理酒5ml、生姜スライスを加え、弱火から強火に切り替えて蓋をし、強火で10分煮る（水は多めにしておく。後で少し蒸発する）。","スープが白くなったら準備した豆腐を加え、中火にしてさらに5分煮る。塩10g、胡椒3gで味を調え、最後に刻みネギを散らして出来上がり。"]'::jsonb, '["スープ","うまみ","煮込み","家庭料理","カルシウム補給","体を温める"]'::jsonb),
  ('howtocook:soup/朱雀汤/朱雀汤', 'ja', '朱雀湯', 'スープ', '朱雀湯は豫東地方の家庭的な簡単スープです。滑らかで甘い口当たりで、ごま油の豊かな香りが広がります。卵は良質なタンパク質を提供し、作り方はとても簡単で、お湯を沸かして卵に注ぐだけ。10分もかからずにでき上がり、体の熱を取る効果もあります。', '[{"name":"卵","unit":"個"},{"name":"ごま油","unit":"ml"},{"name":"砂糖","unit":"g"},{"name":"水","unit":"ml"}]'::jsonb, '["卵をボウルで溶きほぐし、ごま油を加える。","お湯を沸かし、沸騰したらすぐに卵の入ったボウルに注ぐ。","砂糖を加える。"]'::jsonb, '["スープ","豫東","簡単","甘い","家庭料理"]'::jsonb),
  ('howtocook:soup/玉米排骨汤/玉米排骨汤', 'ja', 'トウモロコシとスペアリブのスープ', 'スープ', 'トウモロコシとスペアリブのスープは、旨味と甘みのある家庭的なスープです。スペアリブは柔らかく、トウモロコシとニンジンが自然な甘さを添えます。タンパク質、ビタミン、食物繊維が豊富で、栄養バランスが良いです。作り方は簡単で初心者にも優しく、スペアリブを下茹でして炒めた後、約1時間じっくり煮込むだけです。準備から完成まで約1時間半かかります。', '[{"name":"スペアリブ","unit":"g"},{"name":"トウモロコシ","unit":"本"},{"name":"ニンジン","unit":"本"},{"name":"長ネギ","unit":"本"},{"name":"青ネギ","unit":"本"},{"name":"生姜","note":"適量"},{"name":"食用油","unit":"ml"},{"name":"酢","unit":"ml"},{"name":"料理酒","unit":"ml"},{"name":"黒胡椒","unit":"g"},{"name":"塩","unit":"g"},{"name":"熱湯","unit":"ml"}]'::jsonb, '["長ネギを3〜4cmの長さに切り、包丁の背で軽く叩く","トウモロコシを小さめのぶつ切りにする","ニンジンを乱切りにする","生姜の皮をむき、大きめの薄切りにする","新鮮なスペアリブを小さめのぶつ切りにする","スペアリブを冷水の鍋に入れ、長ネギ、生姜、料理酒を加えて下茹でする。強火で沸騰させ、アクを取り除き、スペアリブを取り出して水気を切る","鍋を熱して油を引いたら、生姜の薄切りとスペアリブを入れて炒める。スペアリブの表面が軽く焼き色づいたら、酢（肉を柔らかくする効果あり）を加え、さらに1分炒める","熱湯を一度に十分加える（後で追加しない）。強火で沸騰させる","まずトウモロコシを加え、胡椒を入れ、蓋をして弱火で20分煮る。次にニンジンを加え、蓋をしてさらに弱火で40分煮る","味付けは簡単、出来上がり3分前に塩だけ加える（他は不要）。最後に刻んだ青ネギをひとつまみ散らす"]'::jsonb, '["スープ","旨味","煮込み","家庭料理","栄養バランス"]'::jsonb),
  ('howtocook:soup/生汆丸子汤', 'ja', '生肉団子スープ', 'スープ', '生肉団子スープは、肉のうま味と弾力が楽しめる、素材の味を生かした家庭的なスープです。豚肉は良質なタンパク質を提供し、木耳や金針菜などの食材と組み合わせることで栄養バランスが良いです。調理には肉を手切りし、団子の火加減を調整する必要があり、ややハードルが高いため、中級以上の料理愛好家向けです。準備から食卓まで約1時間かかります。', '[{"name":"豚前もも肉","note":"適量"},{"name":"塩","note":"適量"},{"name":"こしょう","note":"適量"},{"name":"ねぎ・しょうが・花椒水","note":"適量"},{"name":"卵白","unit":"個"},{"name":"じゃがいも澱粉","unit":"g"},{"name":"加熱した大豆油","note":"適量"},{"name":"木耳","note":"適量"},{"name":"金針菜","note":"適量"},{"name":"小ねぎ","note":"適量"},{"name":"春雨","note":"適量"},{"name":"チキンパウダー","note":"適量"},{"name":"ごま油","unit":"滴"},{"name":"パクチー","unit":"株"}]'::jsonb, '["肉を切り分け、脂身と赤身を3：7の割合にする。","包丁で細かく切り、包丁の背で叩いて肉の筋をほぐす。","切りながら叩き、ミンチにする。美味しくするには手切りが必須で、機械では粘りすぎる。","肉500gに対して、塩6g、こしょう1g。","手でよく混ぜる。","ねぎ・しょうが・花椒水を数回に分けて加え、混ぜながら手で揉み込み、肉に水分を吸収させる。肉500gに対して80gのねぎ・しょうが・花椒水。","卵白を加え、同じ方向に混ぜ続ける。","じゃがいも澱粉40gを加えて混ぜる。","加熱した大豆油を加える。これでなめらかで弾力のある食感を保つ。","鍋に水を入れて沸騰させ、弱火にして沸騰直前の状態にする。","手で団子を絞り出す。","全部浮かんできたら、弱火で1分煮る。","春雨を丼の底に敷く。","木耳、金針菜、小ねぎを加え、塩、こしょう、チキンパウダーで下味をつける。","スープごと団子を丼に注ぐ。","ごま油を3～5滴垂らす。","パクチー少々を加える。"]'::jsonb, '["スープ","うま味","あっさり","湯通し","家庭料理","栄養バランス"]'::jsonb),
  ('howtocook:soup/番茄牛肉蛋花汤', 'ja', 'トマトと牛肉の卵スープ', 'スープ', 'トマトと牛肉の卵スープは、甘酸っぱくて食欲をそそる家庭的なスープで、口当たりが柔らかく滑らかです。牛肉には良質なタンパク質と鉄分が豊富で、トマトはリコピンとビタミンC、卵はレシチンを補給します。作り方は簡単で、初心者でも気軽に作れ、通常約30分で食卓に並びます。', '[{"name":"牛肉","unit":"g"},{"name":"トマト","unit":"個"},{"name":"卵","unit":"個"},{"name":"ネギ","note":"適量"},{"name":"ショウガ","note":"適量"},{"name":"ニンニク","note":"適量"},{"name":"塩","unit":"g"},{"name":"コショウ","unit":"g"}]'::jsonb, '["牛肉を薄切りにする","トマトを小さめの角切りにする","ネギを細かく刻む","ショウガを薄切りにする","ニンニクをすりおろす","牛肉をボウルに入れる","塩、コショウで下味をつけて15～20分置く","水を沸かす","ショウガの薄切りと牛肉を加え、牛肉の色が変わるまで煮る","トマトの角切りを加え、トマトが柔らかくなるまで煮る","溶き卵をゆっくりと鍋に流し入れ、箸でかき混ぜて卵花を作る","塩とコショウで味を調える","最後に刻みネギを加えて火を止める"]'::jsonb, '["スープ","甘酸っぱい","風味豊か","煮る","家庭料理","時短"]'::jsonb),
  ('howtocook:soup/皮蛋瘦肉粥', 'ja', 'ピータンと赤身肉のお粥', 'スープ', 'ピータンと赤身肉のお粥は広東の定番家庭料理です。お粥のベースはとろりとなめらかで、ピータンの濃厚な風味と赤身肉の柔らかさが溶け合い、温かくて美味しい味わいです。炭水化物と良質なタンパク質が豊富で、野菜を加えると栄養バランスが良く、消化吸収も優れています。手順は多めですが、直感的に進められるので、初心者でも問題なく完成できます。調理時間は約1.5時間で、炊飯器の予約や保温機能を活用すれば、朝食として特に便利です。', '[{"name":"飲用水","unit":"リットル"},{"name":"ピータン（松花蛋）","unit":"個"},{"name":"赤身肉","unit":"g"},{"name":"米","unit":"ml"},{"name":"青ネギ","unit":"本"},{"name":"パクチー","unit":"本"},{"name":"レタス","unit":"枚"},{"name":"生姜","unit":"親指大"},{"name":"醤油","unit":"ml"},{"name":"オイスターソース","unit":"ml"},{"name":"塩","unit":"g"},{"name":"胡椒","unit":"g"},{"name":"食用油","unit":"ml"}]'::jsonb, '["米 - 洗います - 炊飯器の内釜に入れます - 1リットルの飲用水を加えます","赤身肉 - 洗います - 簡単に水気を切ります - 10mlの食用油を加えます - よく揉み込みます - 炊飯器の内釜に入れます","ピータン（松花蛋） - 殻をむきます - 洗います - 半分に切ります - 白身と黄身に分けます - 白身は粗く刻みます - 黄身は潰します - 炊飯器の内釜に入れます","生姜 - 洗います - 皮をむきます - 傷んだ部分を取り除きます - 千切りにします - 炊飯器の内釜に入れます","青ネギ - 洗います - 根を切り落とします - 傷んだ部分を取り除きます - みじん切りにします - 小さなボウルに入れておきます","パクチー - 洗います - 根を切り落とします - 傷んだ部分を取り除きます - みじん切りにします - 小さなボウルに入れておきます","レタス - 洗います - 根を切り落とします - 傷んだ部分を取り除きます - みじん切りにします - 小さなボウルに入れておきます","醤油 + オイスターソース + 塩 + 胡椒 - よく混ぜます - 小さなボウルに入れておきます","主材料 - 炊飯器のお粥モードで炊きます","副材料 - 主材料が炊き上がったら、レタスだけ一度湯通しし、他の副材料と一緒に蓋を開けて主材料に加え、よく混ぜます","調味料 - 主材料が炊き上がったら、他の副材料と一緒に蓋を開けて主材料に加え、よく混ぜます"]'::jsonb, '["スープ","広東風","家庭料理","朝食","旨味"]'::jsonb),
  ('howtocook:soup/米粥', 'ja', 'お粥', 'スープ', '白粥はあっさりとして柔らかく、家庭に欠かせない胃を温める主食です。お米の香りが純粋で、老若男女問わず楽しめます。炭水化物と少量のタンパク質が豊富で、消化吸収が良く、脾を補い、胃を和らげ、肺を清める効能があります。操作は簡単で、火加減と水加減さえ掴めれば初心者でも楽に作れます。全行程約25分です。', '[{"name":"米","unit":"ml"},{"name":"水","note":"適量"},{"name":"植物油","note":"任意、適量"}]'::jsonb, '["（任意）洗ったお米にMo mlの油を混ぜ、なるべく全体に行き渡るようにする。つまり、一粒一粒に油が少しずつついている状態にする。","（任意）米と油を混ぜたものを冷蔵庫で保存する。保存時間はTc。","鍋に米と水を入れる。","強火でT1まで加熱する。","T1になる前に火を弱める。この手順を忘れると、水が吹きこぼれて火が消える恐れがある。非常に危険！","Trまで加熱する。Trになったら火を止める。"]'::jsonb, '["スープ・汁物","あっさり","胃を温める","朝食","家庭料理","時短","米の香り"]'::jsonb),
  ('howtocook:soup/紫菜蛋花汤', 'ja', '青のりと卵のスープ', 'スープ', '青のりと卵のスープは、あっさりとした美味しい家庭的なスープで、中国の簡単スープ料理です。青のりにはヨウ素、カルシウム、食物繊維が豊富で、卵は良質なタンパク質を提供し、栄養バランスが良いです。作り方は非常に簡単で、初心者にも優しく、準備から完成まで約20分です。', '[{"name":"青のり","unit":"g"},{"name":"卵","unit":"個"},{"name":"水","unit":"L"},{"name":"塩","unit":"g"},{"name":"油","unit":"ml"},{"name":"ごま油","note":"数滴"},{"name":"刻みネギ","note":"適量"},{"name":"エビ","note":"適量"}]'::jsonb, '["乾燥青のりを水に15分浸し、引き上げて水気を切っておく。","鍋を熱し、1.5Lの水、5mlの油、2gの塩を入れる。沸騰したら青のりを加える。","青のりが沸騰してから3分後、溶いた卵をゆっくりと鍋に流し入れ、30秒で火を止める。","刻みネギを散らし、弱火で20秒加熱する。","火を止め、鍋から出す前にごま油を数滴加える。干しエビを加える人もいて、それも美味しい。"]'::jsonb, '["スープ","あっさり","旨味","時短","家庭料理","煮物"]'::jsonb),
  ('howtocook:soup/罗宋汤', 'ja', 'ロソンタン', 'スープ', 'ロシアのビーツスープを起源とし、上海で改良された海派の家庭的なスープです。トマトと牛肉がベースで、甘酸っぱくコクのある味わいで、深い旨味があります。良質なタンパク質、リコピン、各種ビタミンが豊富で栄養バランスが良いです。作り方は簡単で初心者にも優しく、全体で約2～3時間で完成します。', '[{"name":"牛肉","unit":"g"},{"name":"牛肉スープ","unit":"mL"},{"name":"トマト缶","unit":"缶"},{"name":"トマトペースト","unit":"g"},{"name":"じゃがいも","unit":"g"},{"name":"玉ねぎ","unit":"g"},{"name":"人参","unit":"g"},{"name":"セロリ","unit":"g"},{"name":"キャベツ","unit":"g"},{"name":"赤ウインナー","unit":"g"},{"name":"オリーブオイル","unit":"mL"},{"name":"植物油","unit":"mL"},{"name":"塩","unit":"g"},{"name":"黒コショウ","unit":"g"},{"name":"野菜スープ（セロリ、人参、玉ねぎのセット）","note":"適量"}]'::jsonb, '["玉ねぎ、人参、セロリは1cm角のさいの目切りにする","赤ウインナー、じゃがいもは2cm角に切る","キャベツは芯を取り、手で2cm大にちぎる","牛肉に塩3g、黒コショウ3gをふり、5分おく","フライパンを熱し、植物油を加える","牛肉を焼き、表面がこんがりきつね色になるまで（中は生でも良い、絶対に焦がさないように）焼き、取り出しておく。","鍋を熱し、オリーブオイル、玉ねぎのみじん切り、人参のみじん切り、セロリのみじん切りを加える","玉ねぎが透き通るまで炒め、トマトペースト、トマト缶を加える","牛肉、じゃがいもを加えて全体を混ぜながら炒める","材料がかぶるくらいの水を加え、中火で1時間煮る","蓋を開け、キャベツ、赤ウインナーを加えて混ぜる","中火で30分煮る","蓋を開け、残りの塩15gを加えて混ぜ、器に盛る"]'::jsonb, '["スープ","甘酸っぱい","煮込みスープ","海派","家庭料理","牛肉","食欲増進"]'::jsonb),
  ('howtocook:soup/羊肉汤/羊肉汤', 'ja', '羊肉スープ', 'スープ', '羊肉スープは家庭的な体を温めるスープで、スープは白く濁り、肉は柔らかく、長ネギと白コショウの爽やかな香りとほのかな辛みがあります。タンパク質、カルシウム、鉄などの栄養素が豊富で、胃腸を温め、寒さを防ぐ効果があります。作り方も簡単で、初心者でも気軽に作れ、調理時間は約30分です。', '[{"name":"羊肉（または羊の内臓）","unit":"グラム"},{"name":"サラダ油","unit":"ミリリットル"},{"name":"料理酒","unit":"ミリリットル"},{"name":"長ネギ","unit":"グラム"},{"name":"常温の水","unit":"ミリリットル"},{"name":"熱湯","unit":"ミリリットル"},{"name":"白コショウ","unit":"グラム"},{"name":"食塩","unit":"グラム"},{"name":"クミンパウダー（お好みで）","unit":"グラム"},{"name":"パクチー（お好みで）","unit":"グラム"}]'::jsonb, '["羊肉を長さ5cm、幅0.5cmのブロックに切る","長ネギを小口切りにする","羊肉を鍋に入れ、常温の水1000ml、料理酒、長ネギを加える","2分間沸騰させた後、羊肉を取り出し、常温の水で洗い、水気を切る","熱した鍋にサラダ油を入れ、羊肉を加えて2分間、表面が薄く色づくまで炒める","熱湯を加え、強火にする","5分後、白コショウ、塩を加え、さらに5分間沸騰させる","火を止めた後、パクチー、クミンパウダーを加えて混ぜ合わせる"]'::jsonb, '["スープ","香ばしい","ほろ苦い","煮込み","家庭料理","体が温まる"]'::jsonb),
  ('howtocook:soup/腊八粥', 'ja', '臘八粥', 'スープ', '臘八粥は伝統的な節句の甘いお粥で、粘り気があり柔らかく、さまざまな穀物、豆類、ドライフルーツの複合的な香りが融合しています。炭水化物、ミネラル、各種ビタミンが豊富で、蓮の実には心を落ち着かせる効果があり、仕事のストレスが多い方に適しています。材料は多いですが、手順は簡単で、根気よく弱火で煮込むだけでよく、初心者にも優しいです。浸漬などの準備時間を除けば、煮込み時間は約3時間です。', '[{"name":"飲料水","unit":"L"},{"name":"白米","unit":"g"},{"name":"もち米","unit":"g"},{"name":"ピーナッツ","unit":"g"},{"name":"小豆","unit":"g"},{"name":"ナツメ","unit":"g"},{"name":"はと麦","unit":"g"},{"name":"黒米","unit":"g"},{"name":"アワ","unit":"g"},{"name":"蓮の実","unit":"g"},{"name":"緑豆","unit":"g"},{"name":"大豆","unit":"g"},{"name":"グリーンピース","unit":"g"},{"name":"赤インゲン豆","unit":"g"},{"name":"龍眼（種なし干し龍眼）","unit":"g"},{"name":"栗","unit":"g"},{"name":"クルミ（殻なし）","unit":"g"},{"name":"レーズン","unit":"g"},{"name":"氷砂糖（または白砂糖、調味用）","unit":"g"}]'::jsonb, '["あらかじめ緑豆、小豆、ピーナッツ、大豆、グリーンピース、赤インゲン豆を洗い、清潔なガラスボウルに入れ、ボウルの3/4の量の飲料水を注ぎ、一晩（または最低8時間）浸す。","あらかじめ白米、もち米、はと麦、黒米、アワ、蓮の実を洗い、清潔なガラスボウルに入れ、ボウルの3/4の量の飲料水を注ぎ、3時間浸す。","手順1で準備した緑豆、小豆、ピーナッツ、大豆、グリーンピース、赤インゲン豆の入ったガラスボウルの水を切り、それらを粥鍋に入れ、1リットルの飲料水（または材料が指1本分浸るくらい）を加え、強火で沸騰させる。沸騰したら蓋をして弱火で30分煮る。","手順2で準備した白米、もち米、はと麦、黒米、アワ、蓮の実の入ったガラスボウルの水を切り、それらを粥鍋に加え、蓋をして弱火で60分煮る。","ナツメ、龍眼（種なし干し龍眼）、栗、クルミ（殻なし）、レーズンを洗い（ナツメは薄切りにする）、氷砂糖と一緒に鍋に加え、蓋をして弱火で60分煮る。","粥がとろりとするまで煮えたら火を止め、器に盛り付けて食べる。"]'::jsonb, '["スープ","甘い","煮込み","伝統","朝食","家庭料理"]'::jsonb),
  ('howtocook:soup/菌菇炖乳鸽/菌菇炖乳鸽', 'ja', 'きのこ鳩の煮込み', 'スープ', 'きのこ鳩の煮込みは、スープの色が澄んでいて、肉は柔らかく、きのこの香りと鳩の旨味が融合した、家庭的な広東風の煮込みスープです。鳩は高品質のタンパク質と各種アミノ酸を豊富に含み、きのこは多糖類と食物繊維を提供し、穏やかな滋養効果があります。この料理は、まず鳩を下茹でして臭みを取り、その後トウモロコシやきのこと一緒に煮込む必要があります。火加減と時間の調整に少しコツが必要ですが、初心者でも注意すれば十分に作れます。準備から完成まで、圧力鍋を使う場合は約45分、土鍋でじっくり煮る場合は1時間強かかります。', '[{"name":"鳩","unit":"グラム"},{"name":"きのこ","unit":"グラム"},{"name":"トウモロコシ","unit":"グラム"},{"name":"生姜","unit":"グラム"},{"name":"料理酒","unit":"ml"},{"name":"食塩","unit":"グラム"}]'::jsonb, '["冷水で、親切な店主が処理してくれた鳩を洗います。","冷水の鍋に洗った鳩を入れ、料理酒15mlと生姜を加え、水が沸騰したら鳩を取り出します。そうしないと栄養が逃げます。","鳩を圧力鍋または土鍋に入れ、水を鳩が浸かるくらい注ぎ、生姜20g、トウモロコシ200g、きのこ100gを加えます。","時間が来たら、器に盛り、塩3〜5gを加えて完成です。"]'::jsonb, '["スープ","旨味","あっさり","煮込み","広東風","家庭料理","滋養"]'::jsonb),
  ('howtocook:soup/西红柿鸡蛋汤', 'ja', 'トマトと卵のスープ', 'スープ', 'トマトと卵のスープは、甘酸っぱくて食欲をそそり、口当たりがなめらかな家庭的なスープです。作り方はとても簡単で、老若男女を問わず愛される大衆料理です。リコピン、ビタミンC、良質なタンパク質が豊富で、栄養バランスが良く吸収されやすいです。初心者にも非常に優しく、手早くできて時間も節約できます。調理時間は約15分です。', '[{"name":"トマト","unit":"個"},{"name":"卵","unit":"個"},{"name":"ごま油","unit":"滴"},{"name":"味の素","unit":"g"},{"name":"塩","unit":"g"},{"name":"ネギ、ショウガ、ニンニク","unit":"g"}]'::jsonb, '["トマトを洗い、一口大に切る。","ネギ、ショウガ、ニンニクをみじん切りにする。","卵をボウルに割り入れ、箸（または泡立て器）でよく混ぜる。","鍋を熱し、油15mlを入れ、油からほんのり煙が出てきたら、ネギ、ショウガ、ニンニクを加えて30秒炒める。","トマトを加えて1分炒める。","水を加える（鍋の中の具材の高さの約1.2倍）、塩を加える。","沸騰したら卵液を流し入れ、箸でかき混ぜて卵をほぐす。味の素とごま油を加える。","30秒待ち、火を止めて完成。"]'::jsonb, '["スープ","甘酸っぱい","時短","家庭料理","食欲をそそる","汁物"]'::jsonb),
  ('howtocook:soup/金针菇汤', 'ja', 'エノキのスープ', 'スープ', 'これはあっさりとしてさっぱりした家庭的なスープで、味は美味しく、簡単でスピーディーな料理です。エノキダケにはアミノ酸と食物繊維が豊富に含まれ、卵を加えることで良質なたんぱく質も補えます。作り方はとても簡単で、初心者でも気軽に作れます。準備から完成まで約10分です。', '[{"name":"エノキ","unit":"g"},{"name":"卵","note":"適量（お好みで）"},{"name":"塩","unit":"g"},{"name":"味の素","unit":"g"}]'::jsonb, '["エノキを手でほぐします。ほぐすほどよく、そうしないと歯に挟まりやすいので、よくほぐしてから洗っておきます。","包丁や果物ナイフでエノキを小口切りにします。お好みに応じて切って構いませんが、長さは5cm以下にしてください。","エノキを鍋に入れ、材料の総高さの約1.1倍の水を加え、沸騰したら3分待ちます。","味の素と塩を加えて混ぜます。","さらに約30秒加熱し、火を止めて器に盛ります。"]'::jsonb, '["スープ","あっさり","スピーディー","家庭的","旨味"]'::jsonb),
  ('howtocook:soup/银耳莲子粥/银耳莲子粥', 'ja', '白きくらげと蓮子の粥', 'スープ', '白きくらげと蓮子の粥は、あっさり甘くてなめらか。白きくらげは柔らかくもっちり、蓮子はほくほくとして、よく知られた滋養粥です。天然のコラーゲン、食物繊維、様々なミネラルが豊富で、心を落ち着かせ、精神を安定させる効果があります。作るには浸水とことこと煮込む時間が必要で、初心者の忍耐が試されます。全工程に約3.5時間かかります。', '[{"name":"白きくらげ","unit":"グラム"},{"name":"蓮子（芯抜き）","unit":"グラム"},{"name":"赤なつめ","unit":"グラム"},{"name":"クコの実","unit":"グラム"},{"name":"氷砂糖","unit":"グラム"}]'::jsonb, '["白きくらげと蓮子を水に2時間浸し、赤なつめは10～20分浸し、クコの実は洗っておく。","鍋に600mlの水を入れ、沸騰したら白きくらげ、蓮子、赤なつめの順に入れる。","再び沸騰したら蓋をし、中火にして煮続ける。","約1時間煮たら、氷砂糖5～10gとクコの実5～6gを加え、弱火にする。","弱火でさらに30分煮ると、白きくらげがとろりとしてくる。","再び氷砂糖5～10gを加え、スプーンで5～10分混ぜる。","火を止め、スプーンで器に盛る。"]'::jsonb, '["スープ類","あっさり甘い","滋養","ことこと煮","家庭料理","健康"]'::jsonb),
  ('howtocook:soup/陈皮排骨汤', 'ja', '陳皮スペアリブスープ', 'スープ', '清潤で滋養豊かな広式の煮込みスープです。スープの色は澄んでいて、口当たりは甘く、陳皮の独特の香りが広がります。スペアリブは良質なタンパク質を提供し、西洋参や石斛などの食材と合わせることで、肺を潤し脾を強め、津液を生み喉の渇きを癒します。夜更かしが多い人に適しています。調理難易度は中程度で、材料を準備してスープ鍋に入れ、約2時間弱火で煮込むだけで完成です。', '[{"name":"スペアリブ","unit":"切れ"},{"name":"陳皮","unit":"枚"},{"name":"西洋参","unit":"枚"},{"name":"石斛","unit":"個"},{"name":"玉竹","unit":"枚"},{"name":"麦門冬","unit":"個"},{"name":"塩","unit":"グラム"}]'::jsonb, '["スペアリブを熱湯でさっと茹で、血抜きをする","陳皮、麦門冬、玉竹、石斛、西洋参を洗っておく","スープ鍋をきれいに洗う","スープ鍋の蓋を開け、底にスペアリブを入れ、その上に陳皮、麦門冬、玉竹、石斛、西洋参の順に重ねる","熱湯をスープ鍋に注ぐ。水は入れすぎないようにする","スープ容器に水を入れ、1.5時間煮込む","塩を加え、熱いうちに飲む"]'::jsonb, '["スープ"]'::jsonb),
  ('howtocook:soup/陈皮排骨汤/陈皮排骨汤', 'ja', '陳皮スペアリブスープ', 'スープ', 'このスープは広東式の老火湯で、澄んだスープに甘みとコクがあり、陳皮特有の芳醇な香りが広がります。スペアリブは良質なタンパク質とカルシウムを提供し、陳皮、西洋人参、石斛などの食材と組み合わせることで、気の巡りを整え胃腸を健やかにし、陰を潤し肺を養う効果が期待できます。特に夜更かしが続く方や喉の不調がある方におすすめです。調理は簡単で、材料を準備して煮込む時間を守れば初心者でも問題なく作れます。準備から完成までは約2時間かかります。', '[{"name":"スペアリブ","unit":"塊"},{"name":"陳皮","unit":"枚"},{"name":"西洋人参","unit":"枚"},{"name":"石斛","unit":"粒"},{"name":"玉竹","unit":"枚"},{"name":"麦門冬","unit":"個"},{"name":"塩","unit":"g"}]'::jsonb, '["スペアリブを熱湯で一度茹でて、血抜きをする","陳皮、麦門冬、玉竹、石斛、西洋人参をさっと洗う","スープ用の陶器の鍋をきれいに洗う","鍋を開け、最初にスペアリブを底に敷き、その上に陳皮、麦門冬、玉竹、石斛、西洋人参を順に並べる","熱湯を鍋に注ぎ、水は満杯にしない","スープ容器に水を入れ、1.5時間とろ火で煮込む","塩を加え、熱いうちにいただく"]'::jsonb, '["スープ","広東式","煮込み","滋養","甘味とコク","家庭料理"]'::jsonb),
  ('howtocook:soup/黄瓜皮蛋汤', 'ja', 'キュウリとピータンのスープ', 'スープ', 'キュウリとピータンのスープは、手早く作れる家庭的なスープで、あっさりとした味わい。ピータンとニンニクを炒めた香ばしさがあり、心も体も温まり、脂っこくありません。キュウリは熱を冷まし水分を補給し、ピータンはタンパク質を提供し、低脂肪で負担が少ないです。作り方はほとんど技術的なハードルがなく、料理初心者でも簡単にでき、準備から完成まで約10分です。', '[{"name":"キュウリ","unit":"本"},{"name":"ピータン","unit":"個"},{"name":"ニンニク","unit":"片"},{"name":"小ネギ","note":"適量"},{"name":"食用油（おすすめはラード）","unit":"g"},{"name":"塩","unit":"g"},{"name":"鶏がらスープの素（お好みで）","unit":"g"},{"name":"水","unit":"ml"}]'::jsonb, '["キュウリを洗い、0.5～1.2 mmの薄切りにする","ネギは洗ってみじん切りにし、ニンニクは包丁で叩いて皮をむき、半分に切る","ピータンの殻をむき、1個を6～8等分に切る。鍋に油を入れ、切ったピータンとニンニクを加える","弱火でピータンとニンニクの表面が少し焦げるまで炒め、水を加え、強火にして沸騰させる","キュウリの薄切りを加える。再び沸騰したらすぐに火を止め、塩と鶏がらスープの素で味を調え、火から下ろす","器に盛り、ネギを散らす"]'::jsonb, '["スープ","あっさり","旨味","手早い","家庭的","低脂肪"]'::jsonb),
  ('howtocook:staple/中式馅饼/中式馅饼', 'ja', '中華風ミートパイ', '主食', '外はカリッと、中はふんわりとした食感で、具材は塩味が効いた家庭的な麺料理です。炭水化物とタンパク質が豊富で、にんじんと卵が栄養をプラス。中程度の難易度で、初心者は火加減に注意が必要ですが、手順は明確で取り組みやすいです。準備から完成まで約1時間かかります。', '[{"name":"小麦粉","unit":"g"},{"name":"ミンチ肉","unit":"g"},{"name":"油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"片栗粉","unit":"g"},{"name":"醤油","unit":"g"},{"name":"風味調味料","unit":"g"},{"name":"にんにく","unit":"片"},{"name":"長ねぎ","unit":"本"},{"name":"卵","unit":"個"},{"name":"にんじん","note":"適量"}]'::jsonb, '["ミンチ肉（解凍済み）に、調味料（油、塩、砂糖、醤油、風味調味料）の半量と片栗粉をすべて加え、よく混ぜて30分漬け込む。","ボウルに小麦粉を入れ、卵を加え、残りの調味料半量と、小麦粉の半分の量の水（ややとろみが出て流れる程度）を加え、よく混ぜる。","にんにくはみじん切りにする。","長ねぎは小口切りにする。","にんじんはみじん切りにする（具材用なので細かく刻む。包丁でたたいてもよい）。","フライパンに油を多めに入れて熱する。","油が熱したら、にんにくのみじん切りを入れて香りを出す。","漬け込んだミンチ肉を加え、色が変わるまで炒める。","にんじんのみじん切りをミンチ肉に加えて一緒に炒め、油が黄金色になるまで炒める（にんじんの風味を引き出すため）。","火を止め、2分冷ます。","炒めたミンチ肉を生の生地に加え、よく混ぜる。","再び火をつけ、フライパンに底油を敷く。","弱火にして、生地をフライパンに均等に広げる。厚くなりすぎないようにする。フライパンを傾けて生地を広げるとよい。","パイの表面がまだ液体状のうちに、長ねぎの小口切りを散らす。","弱火のまま、底面が固まるまで焼く。","パイを裏返し、引き続き弱火で反対側も固まるまで焼く。","その後、両面をさらに20秒ずつ焼く。","火を止めて取り出す。"]'::jsonb, '["主食","塩味","焼き","家庭料理","麺料理","朝食"]'::jsonb),
  ('howtocook:staple/凉粉/凉粉', 'ja', '涼粉', '主食', '涼粉は四川発祥の伝統的な軽食で、ひんやりと滑らかな食感と酸味と辛みが食欲をそそり、夏の暑さをしのぐのにぴったりです。主原料はエンドウ豆でんぷんで、炭水化物が豊富で素早くエネルギー補給ができます。作り方は複雑ではありませんが、丁寧にかき混ぜながら煮ることと、長時間冷やして固める必要があり、初心者にはほどよい難易度です。調理から完成まで約3～4時間かかりますが、その大半は冷蔵庫で冷やす時間で、実際の作業は約30分です。', '[{"name":"エンドウ豆でんぷん","unit":"グラム"},{"name":"にんにく","unit":"片"},{"name":"小唐辛子","unit":"個"},{"name":"唐辛子粉","unit":"グラム"},{"name":"醤油","unit":"ml"},{"name":"酢","unit":"ml"},{"name":"砂糖","unit":"ml"},{"name":"チキンエッセンス","unit":"グラム"},{"name":"塩","unit":"グラム"},{"name":"砕いたピーナッツ","unit":"グラム"},{"name":"パクチー","unit":"グラム"}]'::jsonb, '["材料を準備します。","エンドウ豆でんぷんと水をそれぞれ100gずつ混ぜてかき混ぜます。","鍋に水600gを入れ、強火で沸騰させたら弱火にします。","でんぷん水を鍋に注ぎ入れ、絶えずかき混ぜながら、とろみがついて色が均一になるまで混ぜます。","容器を用意し、内側に薄く食用油を塗ります。","煮上がったでんぷんを容器に流し入れ、冷蔵庫で2～4時間冷やし固めます。","冷やし固めたら取り出して型から外し、棒状に切ります。","にんにくと小唐辛子をみじん切りにし、唐辛子粉10g、砕いたピーナッツ5gを加え、熱した油をかけて混ぜます。","さらに醤油10ml、酢10ml、砂糖5ml（※）、チキンエッセンス3g、塩3gを加えて混ぜます。","タレを涼粉にかけ、最後にパクチーを散らしてできあがり。"]'::jsonb, '["主食","四川料理","酸辣","冷やし和え","暑さ対策","伝統的な軽食"]'::jsonb),
  ('howtocook:staple/利提巧卡', 'ja', 'リティ・チョカ', '主食', 'リティ・チョカはインドのビハール州の伝統的主食で、こんがりと焼いた小麦のボールとスモーキーな風味の野菜ペーストからなり、外はカリッと中はふんわり、香り豊か。ローストひよこ豆粉の具には植物性タンパク質と食物繊維が豊富で、ナス、トマト、ジャガイモなどの野菜と組み合わせて栄養満点。作り方は生地作り、包み、焼き、野菜の処理と手順が多く、初心者にはやや挑戦的で、全体で約60分かかる。', '[{"name":"全粒粉（アッタ）","unit":"g"},{"name":"ローストひよこ豆粉（サットゥ、炒ったひよこ豆を粉にしたもので代用可）","unit":"g"},{"name":"ナス","unit":"個"},{"name":"トマト","unit":"個"},{"name":"ジャガイモ","unit":"個"},{"name":"玉ねぎ","unit":"個"},{"name":"ニンニク","unit":"片"},{"name":"生姜","unit":"g"},{"name":"青唐辛子","unit":"本"},{"name":"青唐辛子","unit":"本"},{"name":"レモン汁","unit":"ml"},{"name":"コリアンダー","unit":"g"},{"name":"コリアンダー","unit":"g"},{"name":"マスタードオイル（他の食用油で代用可）","unit":"ml"},{"name":"マスタードオイル（他の食用油で代用可）","unit":"ml"},{"name":"クミンシード","unit":"g"},{"name":"カラナマック（普通の塩で代用可）","unit":"g"},{"name":"レッドペッパーパウダー","unit":"g"},{"name":"ゴマ","unit":"g"},{"name":"ギー","unit":"g"},{"name":"塩","unit":"g"},{"name":"塩","unit":"g"}]'::jsonb, '["ボウルにローストひよこ豆粉120g、みじん切り玉ねぎ、青唐辛子、生姜を混ぜる","クミンシード3g、ゴマ5g、レッドペッパーパウダー3g、カラナマック3g、塩3gを加える","マスタードオイル15ml、レモン汁10ml、みじん切りコリアンダーを加える","よく混ぜ合わせ、具はほぐれているがまとまる状態にしておく","全粒粉200gを大きなボウルに入れる","ぬるま湯を少しずつ加えながらこね、滑らかで柔らかい生地にする","生地を15分休ませる","生地を8等分する","各生地を手で直径約8cmの円形に伸ばす（中央を少し厚めに）","中央に約15gの具を置く","生地の端を寄せて具を包み、閉じ口をしっかり閉じて丸める","オーブンを200℃に予熱する","リティを天板に並べ、25〜30分焼く。途中で一度裏返し、表面が黄金色でひび割れるまで焼く","直火の場合：リティを炭火またはガス火の弱火に直接置き、絶えず返しながら均一に焦げ目がつくまで焼く","焼き上がったら熱いうちに各リティの表面にギーを塗り、染み込ませる","ナス、トマト、ジャガイモを直火で直接焼くか、200℃のオーブンで20〜25分、皮が黒く焦げて内部が完全に柔らかくなるまで焼く","焼き上がったら皮をむき、ナス、トマト、ジャガイモをそれぞれフォークまたは手で潰す","潰した野菜を混ぜ合わせる","みじん切りニンニク、青唐辛子、塩4g、マスタードオイル15mlを加える","よく混ぜ合わせる","コリアンダーの葉を散らして飾る","リティを皿に盛り、横にチョカ（野菜ペースト）を添える","熱いうちに手でリティを割いてチョカにつけて食べる"]'::jsonb, '["主食","インド主食","風味豊か","辛味","焼き","包み","伝統"]'::jsonb),
  ('howtocook:staple/印度烤饼', 'ja', 'インドのナン', '主食', 'これはインド風のナンで、表面はカリッと香ばしく、中はふんわりもっちり。カレーによく合います。炭水化物とタンパク質が豊富で、ヨーグルト入りで消化も良いです。少々難しいですが、生地の硬さと火加減に気をつければフライパンで作れます。発酵に1時間、合計約1.5時間かかります。', '[{"name":"中力粉","unit":"グラム"},{"name":"ヨーグルト","unit":"ミリリットル"},{"name":"ドライイースト","unit":"グラム"},{"name":"砂糖","unit":"グラム"},{"name":"塩","unit":"グラム"},{"name":"食用油","unit":"ミリリットル"},{"name":"ぬるま湯","unit":"ミリリットル"},{"name":"ギーまたはバター","unit":"グラム"},{"name":"黒ゴマ","unit":"グラム"},{"name":"パクチー","unit":"グラム"},{"name":"ニンニク","unit":"片"}]'::jsonb, '["ドライイースト3gと砂糖10gをぬるま湯100ml（約40°C、熱すぎないこと）に溶かす","5分間置き、表面に細かい泡が出るまで待つ（イーストが活性化した証拠）","大きめのボウルに中力粉300gと塩5gを入れ、よく混ぜる","イースト水、ヨーグルト60ml、食用油15mlを加える","手で滑らかで柔らかい生地にこねる（通常の生地よりやや柔らかく、少し手に付く程度が良い）","8～10分こねる","生地の表面に油3mlを塗って乾燥を防ぐ","濡れ布巾またはラップでボウルの口を覆う","暖かい場所で少なくとも1時間発酵させ、生地が約2倍に膨らむまで待つ","発酵した生地を取り出し、軽くこねてガスを抜く","6等分に分ける（1つ約80g）","1つを取り、手に小麦粉か油3mlをつける","めん棒で長楕円形または涙滴形に伸ばし、厚さ約4～5mmにする","ガーリックナンを作る場合：生地の表面にみじん切りにしたニンニクとパクチーを散らし、軽く伸ばして埋め込む","生地の表面にゴマを振ってもよい","フライパン（鋳鉄製が最適）を強火で非常に熱くする（水滴を落とすとすぐに蒸発する程度）","生地の片面に薄く水を塗る","水を塗った面を下にしてフライパンに入れる","1～2分焼き、底面にこんがりとした斑点ができ、生地が膨らみ始めるまで","裏返し、さらに1～2分焼く","ガスコンロがある場合：裏返した後、トングで生地をつまみ、直火で数秒焼くとすぐに膨らむ","取り出したらすぐに表面にギーまたはバターを塗る","オーブンを最高温度（通常250°C）に予熱する","生地を天板に置く","3～5分焼き、表面がきつね色になり膨らむまで","取り出してギーまたはバターを塗る","熱いうちに食べる","バターチキンやレッドキドニーカレーなど、どんなインドカレーにも合う"]'::jsonb, '["主食","インド","ナン","発酵","カレーに合う","香ばしい","ミルク風味"]'::jsonb),
  ('howtocook:staple/印度焖饭', 'ja', 'ビリヤニ', '主食', 'ビリヤニはムガル帝国時代に起源を持つ宮廷料理で、長粒米と香り高いスパイス、柔らかい鶏肉が特徴です。タンパク質とスパイスが豊富で食欲をそそります。調理工程はやや複雑で初心者には不向きですが、全体で約90分（鶏肉のマリネに1時間）かかります。', '[{"name":"バスマティライス","unit":"g"},{"name":"鶏もも肉（骨なし、羊肉でも代用可）","unit":"g"},{"name":"ヨーグルト","unit":"ml"},{"name":"トマト","unit":"適量","note":"適量"},{"name":"生姜（すりおろし）","unit":"g"},{"name":"にんにく（すりおろし）","unit":"片"},{"name":"青唐辛子（切り目を入れたもの）","unit":"本"},{"name":"コリアンダー","unit":"g"},{"name":"ミント","unit":"g"},{"name":"サフラン（食用黄色色素で代用可）","unit":"g"},{"name":"温かい牛乳","unit":"ml"},{"name":"ギー","unit":"g"},{"name":"食用油","unit":"ml"},{"name":"ターメリックパウダー","unit":"g"},{"name":"パプリカパウダー","unit":"g"},{"name":"ガラムマサラ","unit":"g"},{"name":"塩（肉下味用）","unit":"g"},{"name":"塩（米茹で用）","unit":"g"},{"name":"ローリエ","unit":"枚"},{"name":"シナモンスティック（約5cm）","unit":"本"},{"name":"カルダモン","unit":"個"},{"name":"クローブ","unit":"粒"},{"name":"八角","unit":"個"},{"name":"レモン汁","unit":"ml"},{"name":"玉ねぎ（薄切り）","unit":"個"}]'::jsonb, '["ボウルにヨーグルト、すりおろした生姜とにんにく、パプリカパウダー、ターメリックパウダー、ガラムマサラ、塩、レモン汁を混ぜる","鶏肉を加え、マリネ液をよく絡める","ラップをかけ、冷蔵庫で少なくとも1時間（できれば一晩）マリネする","サフラン0.5gを温かい牛乳30mlに15分浸して、取っておく","鍋に食用油50mlを入れ、中火で熱する","玉ねぎの薄切りを加え、濃いきつね色でカリカリになるまで炒める（約12〜15分、根気が必要）","炒めた玉ねぎを取り出し、キッチンペーパーで油を切って、取っておく","浸しておいたバスマティライスをザルにあげて水気を切る","大きめの鍋に水2000mlを沸かす","ローリエ、カルダモン、クローブ、シナモンスティック、八角、塩10gを加える","米を入れ、強火で5〜6分茹でる（米が7割ほど柔らかくなり、芯がまだ少し硬い状態）","すぐにざるに上げ、すべてのホールスパイスを取り除き、取っておく","厚底鍋の底にギー15gを塗る","1層目：マリネした鶏肉を鍋底に均等に広げる","2層目：半茹で米の半分を重ねる","その上に、炒めた玉ねぎの半分、ミント、コリアンダー、青唐辛子を散らす","3層目：残りの米を重ねる","残りの炒めた玉ねぎ、ミント、コリアンダーを散らす","サフランミルクを一番上のご飯の表面にまんべんなくかける","残りのギー15gを小さく切って上に散らす","蓋を密閉する：小麦粉を水で練った紐を鍋の縁に沿って貼り付ける（伝統的な方法）、またはアルミホイルで鍋口を覆ってから蓋をする","強火で3分加熱し、鍋から蒸気が出始めるまで加熱する","次にごく弱火にし、25〜30分蒸らす","火を止めた後、蓋を開けずに5分そのまま置く","蓋を開け、大きなヘラで底からそっと混ぜ、各層を均一にする","皿に盛り、ラータ（ヨーグルトソース）を添える"]'::jsonb, '["主食","風味豊か","炊き込みご飯","インド","濃厚","おもてなし"]'::jsonb),
  ('howtocook:staple/可乐炒饭', 'ja', 'コーラ炒飯', '主食', 'この料理は砂糖の代わりにコーラを使って味付けし、独特の香ばしくてほのかな甘さを引き出しています。ソースが濃厚で一粒一粒のご飯に絡み、クリエイティブな家庭風炒飯です。卵とソーセージが良質なタンパク質とエネルギーを提供し、主食のご飯と合わせて栄養バランスが良くお腹も満たされます。操作手順は分かりやすく、初心者でも挑戦しやすく、通常約20分でテーブルに出せます。', '[{"name":"ご飯","unit":"g"},{"name":"コーラ","unit":"ml"},{"name":"卵","unit":"個"},{"name":"ソーセージ","unit":"g"},{"name":"ランチョンミート","note":"適量（お好みで）"},{"name":"油","unit":"ml"},{"name":"薄口醤油","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"豆板醤","unit":"ml"},{"name":"オイスターソース","unit":"ml"},{"name":"ネギ（みじん切り）","unit":"g"},{"name":"コショウ","unit":"g"}]'::jsonb, '["鍋を熱し、油25mlを入れ、卵2個を割り入れ、底面が完全に固まるまで焼く","裏返し、両面が完全に固まるまで焼く","火を止め、卵を取り出し、2～5cm²の大きさに切って鍋に戻す（ヘラで直接崩してもよい）","再び火をつけ、コーラ、薄口醤油、濃口醤油、豆板醤、オイスターソースを加え、よく混ぜる","鍋の液体が1/3になるまで加熱し、ご飯とソーセージを加えて炒める","全体が混ざったら弱火にし、中央に穴を開けて卵1個を割り入れ、蓋をして2分蒸し焼きにする","蓋を開け、卵が固まるまで炒め、ネギとコショウをふって出来上がり"]'::jsonb, '["主食","香ばし甘い","炒飯","時短","クリエイティブ","家庭風"]'::jsonb),
  ('howtocook:staple/咸肉菜饭', 'ja', '塩漬け肉と青菜のご飯', '主食', '上海の路地裏の風情が漂う家庭的な主食。塩漬け肉の豊かな香りと青菜の甘みがラードの力で一粒一粒のご飯に染み込み、お焦げのパリッとした食感と菜っ葉のシャキシャキ感が絶妙に調和します。青菜はビタミンと食物繊維が豊富で、塩漬け肉はタンパク質とエネルギーを提供し、バランスの良い一皿です。作り方は難しくありませんが、菜っ葉を分けて加えるコツが必要で、初心者には少し挑戦的。下準備から出来上がりまで約1時間かかります。', '[{"name":"米","unit":"グラム"},{"name":"青菜","unit":"グラム"},{"name":"塩漬け肉","unit":"グラム"},{"name":"タケノコ","unit":"グラム"},{"name":"ラード","unit":"グラム"},{"name":"料理酒","unit":"ml"},{"name":"砂糖","unit":"グラム"},{"name":"白胡椒","unit":"グラム"},{"name":"水","unit":"ml"}]'::jsonb, '["もしタケノコを加えるなら、薄切りにして冷水から10分茹でて渋みを取る","塩漬け肉を1cm角に切る","塩漬け肉とタケノコを冷たい鍋に入れ、ラード10g、料理酒、砂糖を加え、中弱火で透明になって泡が出るまで炒める","青菜を細かく切り、茎と葉を別々に置く。茎は0.5cm角の正方形に、葉は長さ2-3cm、幅1-1.5cmの長方形に切る","茎を鍋に入れて翡翠色になるまで炒める","米を洗って炊飯器に入れ、水を加える","炒めた塩漬け肉と茎を米の上に広げる","通常の炊飯モードでスタート、最後の10分で蓋を開け、素早く葉を広げる","炊き上がったら5分蒸らし、さらにラード5g、白胡椒を加えてよく混ぜる"]'::jsonb, '["主食","上海風味","家庭料理","塩味・旨味","炊き込みご飯"]'::jsonb),
  ('howtocook:staple/基础牛奶面包/基础牛奶面包', 'ja', '基本ミルクパン', '主食', 'この基本ミルクパンは、前発酵種を使うことで伝統的なパン作りの工程を簡略化し、ミルクの風味が豊かで、やわらかい食感に仕上がります。炭水化物とタンパク質が豊富で、エネルギーを補給できます。難易度は中程度で、パン作り初心者にもおすすめです。全工程で約200分かかります。', '[{"name":"強力粉または中力粉（前発酵種用）","unit":"カップ"},{"name":"ぬるま湯（約30℃）","unit":"カップ"},{"name":"ドライイースト","unit":"グラム"},{"name":"塩","unit":"グラム"},{"name":"強力粉または中力粉（生地用）","unit":"カップ"},{"name":"卵","unit":"個"},{"name":"砂糖またはシロップ","unit":"カップ"},{"name":"牛乳または生クリームまたはコンデンスミルクまたは粉ミルク","unit":"カップ"},{"name":"バターまたはコーン油","unit":"カップ"},{"name":"グルテンパウダー（お好みで）","unit":"カップ"},{"name":"バニラエッセンス（お好みで）","unit":"グラム"},{"name":"布","note":"適量"}]'::jsonb, '["まず、ドライイーストと30℃のぬるま湯を、ゴムベラや調理器具でよく混ぜ合わせ、5分間置きます。その後、小麦粉と混ぜ、均一になるまで混ぜます。この時点での前発酵種は、特に粘り気のあるペースト状です。","布でペーストを覆い、暖かい場所で45〜60分間発酵させます。","最終的なペーストは、表面にたくさんの泡があり、体積が明らかに増加している状態です。"]'::jsonb, '["主食","ミルク風味","やわらかい","焼き菓子","発酵","初心者向け"]'::jsonb),
  ('howtocook:staple/微波炉腊肠煲仔饭/微波炉腊肠煲仔饭', 'ja', '電子レンジで作るラー腸の煲仔飯', '主食', 'これは簡単で手早く作れる広東風の主食です。ご飯がラー腸の脂を吸って、コクと塩味が効いて香ばしい。青菜や人参のシャキシャキ感と組み合わせ、食感の層が豊かです。炭水化物、タンパク質、各種ビタミンが豊富で栄養バランスも良好。電子レンジで調理するので初心者にも優しく、わずか15分で楽しめます。', '[{"name":"米","unit":"ml"},{"name":"ラー腸","unit":"本"},{"name":"卵","unit":"個"},{"name":"人参","unit":"本"},{"name":"塩","unit":"g"},{"name":"油","unit":"ml"},{"name":"薄口醤油","unit":"ml"},{"name":"ねぎ","unit":"本"},{"name":"青菜","note":"適量"},{"name":"水","unit":"ml"}]'::jsonb, '["米を研いでご飯用の器に入れ、400mlの水を加えて蓋をする。","電子レンジに入れ、強火で6分加熱します。その間に他の材料を準備します。","ラー腸を切る。","青菜を洗う。","人参を薄切りにする。","ねぎを小口切りにする。","青菜用のボウルに青菜と人参を入れ、10mlの油と5gの塩を加える。","小鉢に薄口醤油10mlと油5mlを入れる。","6分後、タオルや耐熱手袋を使って器を取り出す。ご飯が8割ほど炊けているのが確認できる。","ご飯の上に切ったラー腸を並べ、さらに強火で2分加熱する。","ラー腸ご飯を取り出し、青菜用のボウルを電子レンジに入れて強火で4〜5分加熱する。","ラー腸ご飯の上に青菜をのせ、卵を割り入れる。好みに応じてさらに強火で40〜60秒加熱する。","ラー腸ご飯を取り出す。これでほぼ完成。","小鉢を電子レンジに入れ、強火で30秒加熱する。","加熱した薄口醤油をラー腸ご飯にかけ、ねぎを散らして出来上がり。","余った青菜は醤油をつけて食べてもよい。"]'::jsonb, '["主食","広東風","電子レンジ","時短","塩味香ばしい","家庭風"]'::jsonb),
  ('howtocook:staple/意式肉酱面/意式肉酱面', 'ja', 'イタリアンミートソースパスタ', '主食', 'イタリアンミートソースパスタは簡単で手早く作れる家庭的な洋食。ソースが濃厚で麺はコシがあり、忙しい日常にぴったり。ひき肉と玉ねぎに市販のパスタソースを合わせることで、素早くタンパク質と炭水化物を補給でき、玉ねぎには食物繊維も含まれています。初心者にも優しく、切って炒めるだけで、慣れれば15分で完成。インスタントラーメンより満足感があります。', '[{"name":"パスタ","unit":"グラム"},{"name":"イタリアンパスタソース","unit":"グラム"},{"name":"ひき肉","unit":"グラム"},{"name":"白玉ねぎ","unit":"グラム"},{"name":"食用油","unit":"ml"}]'::jsonb, '["鍋に水を入れ、沸騰したらパスタを入れる（6～12分待つ）","湯を沸かしている間に以下の手順を行うこともできますが、麺の茹で時間に注意してください","玉ねぎを小さなみじん切りにする","空の鍋に油を入れ、中火で玉ねぎのみじん切りを入れる","焦げないように常に混ぜながら、玉ねぎが半透明になるまで炒める","ひき肉を加え、ほぐしながら混ぜ、肉の色が変わるまで炒める","イタリアンパスタソースを加え、少し混ぜるだけでOK","茹で上がったパスタの水気を切り、ミートソースに加えてよく混ぜる（または、作ったミートソースをパスタの上に直接かけてもよい）"]'::jsonb, '["主食","手早い","家庭料理","旨味","洋食"]'::jsonb),
  ('howtocook:staple/手工水饺', 'ja', '手作り水餃子', '主食', '手作り水餃子は中華の定番主食で、皮は薄く具はたっぷり、旨味と肉汁が溢れ、満足感があり、好みで味付けを変えられます。豚ひき肉は良質なタンパク質と脂質を提供し、ニラを加えることでビタミンと食物繊維も補えます。この料理は初心者には難易度が高く、生地をこねる、皮を伸ばす、あんを調味する、水餃子を茹でる火加減を習得する必要があり、調理時間は約3時間です。', '[{"name":"小麦粉","unit":"g"},{"name":"冷水","unit":"ml"},{"name":"ごま油","unit":"ml"},{"name":"赤身のひき肉","unit":"g"},{"name":"脂身のひき肉","unit":"g"},{"name":"ショウガ","unit":"g"},{"name":"ネギ","unit":"g"},{"name":"塩","unit":"g"},{"name":"オイスターソース","unit":"ml"},{"name":"ごま油","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"卵","unit":"個"},{"name":"ニラ","note":"適量"}]'::jsonb, '["ボウルにすべての小麦粉を入れる","ごま油を加える","小麦粉の中央に小さなくぼみを作る","水を4〜5回に分けて加え、混ぜ合わせ、粉っぽいやや乾燥した生地になったら","水を加えるのをやめ、手で生地を押し固める","生地を押し固めて、ボウルの周りの粉も取り込み、ボウルと手がきれいになるまで行う","生地を台の上に置き、ボウルをかぶせて、室温25度で約45分寝かせる","寝かせた後、生地を棒状にのばし、ひとまとめにしてまた棒状にのばす。これを3回繰り返す","棒状にのばし、20等分に切り、直径約3〜3.5cmの球状に丸める","生地球を平らにし、手、台、めん棒、生地に打ち粉をする（くっつき防止）","めん棒で直径約8cm、厚さ約2mmに伸ばす。中央は周りより1mmほど厚くする","豚肉の皮を除き、脂身を一部残して小さく切る","包丁（2本推奨）で豚肉をたたいてひき肉にし、ボウルに入れる","ネギ、ショウガをみじん切りにし、肉のボウルに加えて混ぜ合わせる","ニラを洗い、3mm以下の長さに切る","ニラとひき肉を混ぜ、オイスターソース、醤油、ごま油を各2ml加え、卵1個の卵白を加え、手でよく混ぜ合わせる","30分置いたら、餃子を包み始める","左手に皮を置き、餃子の具をのせる面にできるだけ粉をつけない（閉じにくくなるため）","右手で箸を使って、皮の直径の1/2程度の具を取り、皮の上にのせる","皮の周囲を合わせてしっかりと閉じる。家庭用なのでひだは不要、具が漏れなければよい","20個の餃子が入る鍋を使うか、数回に分けて茹でる","水を沸かす。水の量は鍋の高さの3/4程度","強火で沸騰させたら餃子を入れ、中火にする","初めて餃子を入れ、水が泡立ったら、鍋の縁から冷水50mlを加える（この作業をさらに2回繰り返す）","3度目に水が沸騰したら冷水50mlを加え、再び沸騰したら弱火にして60秒待ったら出来上がり"]'::jsonb, '["主食","家庭料理","香ばしい","麺料理","手作り","おもてなし"]'::jsonb),
  ('howtocook:staple/扬州炒饭/扬州炒饭', 'ja', '揚州チャーハン', '主食', '具だくさんでアップグレードされたチャーハンです。ご飯はパラパラ、卵はとろりと柔らかく、エビ、ランチョンミート、野菜の角切りが加わり、食感のコントラストがはっきりとした、淮揚料理の代表的な主食です。良質なタンパク質、炭水化物、各種ビタミンが豊富で栄養バランスも良好。手順は多いですが、作業は直感的で初心者にも優しく、根気よく材料を準備すれば大丈夫です。調理時間は約1時間。', '[{"name":"冷やご飯","unit":"g"},{"name":"卵","unit":"個"},{"name":"冷凍むきエビ","unit":"尾"},{"name":"ランチョンミート缶","unit":"g"},{"name":"グリンピース","unit":"g"},{"name":"人参","unit":"g"},{"name":"コーン","unit":"g"},{"name":"ネギ","unit":"本"},{"name":"油","unit":"ml"},{"name":"塩","unit":"g"}]'::jsonb, '["人参は0.2cm角に切り、取っておく","ランチョンミートは0.2cm角に切り、取っておく","ネギは白い部分と青い部分に分け、それぞれ0.25～0.5cmの小口切りにし、別々に取っておく","ボウルに卵を割り入れ、よく混ぜて取っておく","人参、グリンピース、コーンを茹でて取り出し、取っておく（茹で汁は捨てない）","エビを茹でて取り出し、取っておく（茹で汁は捨ててよい）","鍋を熱して油を入れ、「炒める・焼く」の「熱鍋双油」を参考に","2度目の油は20～30ml入れ、冷たい油が温まったら、卵液をゆっくりと流し入れる（ボウルから鍋までの注ぐ径を約0.5cmにする）混ぜない","卵が固まったらすぐに取り出し、取っておく","ランチョンミート、グリンピース、人参、コーン、エビを鍋に入れて1～2分炒め、皿に取り出して取っておく","鍋を水でさっと洗い、汚れを取り除く（油は残っていてもよいが、不純物はないように）","鍋を熱して油（10ml）を入れ、ネギの白い部分を加えて香りを出す","弱火にする（油温が高すぎる場合は1～2分火を止める）、ご飯を入れ、ヘラでご飯を素早く叩きながら炒め、均等に油が絡んでパラパラになるようにする","卵を加え、さらに叩きながら炒めて卵を細かくし、ご飯とよく混ざるようにする","強火にし、他の下準備した具材をすべて加え、手早く1～2分炒める","塩をふり入れ、全体が混ざるまで炒める","ネギの青い部分を加え、1分炒める","火を止め、皿に盛る"]'::jsonb, '["主食","旨味","チャーハン","家庭料理","淮揚","簡単"]'::jsonb),
  ('howtocook:staple/披萨饼皮/披萨饼皮', 'ja', 'ピザ生地', '主食', 'ピザ生地は低温で一晩発酵させ、出来上がりは柔らかくほんのり噛みごたえのある、家庭的な洋風点心です。主に炭水化物と少量の良質な脂質を提供します。作り方は簡単ですが、生地の発酵を待つ忍耐が必要で、初心者にも優しいです。準備から焼き上がりまで、一晩の冷蔵時間を含めて約10～14時間かかるので、前日に準備するのがおすすめです。', '[{"name":"中力粉","unit":"g"},{"name":"ぬるま湯","unit":"g"},{"name":"ドライイースト","unit":"g"},{"name":"塩","unit":"g"},{"name":"オリーブオイル","unit":"g"},{"name":"砂糖","unit":"g"}]'::jsonb, '["用意しておいたぬるま湯でドライイーストを溶かし、軽く混ぜておく。","用意した小麦粉に、塩、オリーブオイル、砂糖を順に加える。","水と小麦粉を混ぜる準備をし、水を加えながら全ての水がなくなるまで混ぜる。","乾いた粉が見えなくなるまで混ぜる。","生地の約3倍の大きさの容器に入れ、密閉して冷蔵庫（4℃）で8～12時間寝かせる。通常は夜に仕込めば翌日使える。","生地が発酵完了したか確認する。元の大きさの約2倍になれば発酵完了。","発酵した生地を取り出し、均等に4等分し、それぞれラップで包んでおく。","まな板に多めの打ち粉をふり、捏ねる準備をする。","少し湿った生地なので、打ち粉をつけると手にくっつきにくくなる。あまり捏ねすぎず、表面が少し滑らかになればよい。","手で伸ばすか、麺棒で平らに伸ばす。必ずしも円形でなくてもよく、厚さが均一でオーブンに入る大きさであればよい。","クッキングシートを敷き、生地をのせ、好みに応じて用意した具材をのせ、チーズを散らす。","フルーツの場合：オーブン上段180℃、下段220℃で16分。","肉野菜の場合：オーブン上段200℃、下段230℃で18分。","マヨネーズやお好みのソースをかけて召し上がれ～"]'::jsonb, '["主食","洋風","焼き","一晩発酵","家庭向け","初心者向け"]'::jsonb),
  ('howtocook:staple/日式咖喱饭/日式咖喱饭', 'ja', '和風カレーライス', '主食', '和風カレーライスは、コクがあってまろやかな家庭的な和風料理です。カレールーで味付けし、ジャガイモ、ニンジン、玉ねぎ、肉を合わせ、なめらかでとろみのある、スパイシーでほのかに甘い味わいです。タンパク質、炭水化物、各種ビタミンが豊富で、エネルギーをしっかり補給できます。作り方は全体的に難しくありませんが、火加減と混ぜる技術が重要で、少し料理に慣れた方におすすめです。下ごしらえから出来上がりまで約1時間かかり、冷蔵するとさらに味が深まります。', '[{"name":"カレールー（ハウス推奨）","unit":"グラム"},{"name":"ジャガイモ","unit":"個"},{"name":"ニンジン","unit":"本"},{"name":"玉ねぎ","unit":"個"},{"name":"肉（豚肉/鶏肉/牛肉いずれでも）","unit":"斤"},{"name":"ニンニク","unit":"片"},{"name":"ブロッコリー（ゆでたもの）","note":"適量"},{"name":"ベーコン（そのまま食べられるもの）","note":"適量"},{"name":"目玉焼き","note":"適量"}]'::jsonb, '["ニンジンのヘタと尻尾を切り落とし、皮をむいて乱切りにする","玉ねぎの外側の皮をむき、芯を取り除いて、三日月形に切る","ジャガイモの皮をむいて、大きめの乱切りにする","肉を一口大に切る","ニンニクの皮をむき、包丁の腹で潰してからみじん切りにする","カレールーを細かく刻んで、表面積を増やして溶けやすくする","油を熱した鍋にニンニクと肉を入れ、肉の表面が白くなるまで強火で炒める","ニンジンを加え、全体に油が回るように強火で炒める","玉ねぎを加え、透き通るまで強火で炒める","ジャガイモを加え、少し柔らかくなるまで炒める（箸で確認）","材料がかぶるくらいの水を加え、沸騰したら15分待つ","火を止め、カレールーを加えて混ぜる","カレールーが溶けたら再び火をつけ、焦げ付かないようにゆっくり混ぜながら10分煮る","とろみがついたら火を止めて完成","電子レンジの場合：一人分なら強火で2〜3分","鍋の場合：水を50ml追加し、加熱中は混ぜ続ける"]'::jsonb, '["主食","和風","コクがある","家庭料理","ご飯が進む","煮込み"]'::jsonb),
  ('howtocook:staple/日式肥牛丼饭/日式肥牛丼饭', 'ja', '牛丼', '主食', '定番の和風家庭料理。牛肉と玉ねぎを甘辛いタレで煮込み、肉は柔らかく、玉ねぎは甘く、旨味たっぷり。牛肉は良質なタンパク質とヘム鉄を含み、玉ねぎは食物繊維と抗酸化物質が豊富。調理は難しくなく、初心者でも手順通りに作れば約30分で完成。', '[{"name":"玉ねぎ","unit":"個"},{"name":"牛肉（薄切り）","unit":"g"},{"name":"ネギ","unit":"本"},{"name":"白ごま","unit":"g"},{"name":"味醂","unit":"g"},{"name":"料理酒","unit":"g"},{"name":"温泉卵","note":"適量"},{"name":"だし","note":"適量"},{"name":"米","unit":"合"},{"name":"醤油","unit":"g"},{"name":"オイスターソース","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"老抽","unit":"g"},{"name":"水","unit":"g"}]'::jsonb, '["玉ねぎは外側の皮と芯を取り、三日月形に切る","ネギは洗って0.5cmの小口切りにする","熱した鍋に白ごまを入れ、鍋を前後に揺らしながら均等に熱し、薄いきつね色になるまで炒る","牛肉は1分間下茹でして取り出す","味醂40g（または酒30g）、醤油30g、オイスターソース20g、砂糖5g、老抽5g（お好みで、色付け用）をボウルで混ぜ合わせる（この工程は電子秤の上で直接行ってもよい）","油を熱した鍋に玉ねぎを入れ、透き通るまで強火で炒める","弱火にして水250g（またはだし）を加え、強火に戻して3分加熱する","牛肉と調味料を加える","すべての材料を絶えず混ぜながら10分煮る（焦げ付き防止）","火を止める","ご飯の上に牛丼を盛り付ける（汁もご飯にかける）","ネギと白ごまを散らして完成","電子レンジ：一人分なら強火で2〜3分","鍋：水50mlを追加し、加熱中は絶えず混ぜる"]'::jsonb, '["主食","和風","甘辛","煮込み","ご飯が進む","家庭料理"]'::jsonb),
  ('howtocook:staple/汤面', 'ja', 'スープ麺', '主食', 'スープ麺は自由にアレンジできる家庭的な主食です。スープはあっさり、麺は柔らかく、様々な肉や野菜と相性が良く、味は濃くも薄くも調節できます。炭水化物と良質なタンパク質が豊富で、野菜を加えることでビタミンや食物繊維も補給でき、栄養バランスが良く満腹感も得られます。作り方はとても簡単で、料理経験がなくても初心者が簡単に作れます。材料の準備から調理まで、通常約30分かかります。', '[{"name":"麺類","unit":"g"},{"name":"冷水","unit":"ml"},{"name":"野菜類","note":"量は麺類と同程度"},{"name":"塩","note":"適量"},{"name":"こしょう","note":"適量"},{"name":"ごま油","note":"適量"}]'::jsonb, '["まず野菜類を一辺が4cm以下のブロック状に切り、火の通りを良くします。","生肉がある場合は、まず冷水に入れ、蓋をして沸騰させます。表面のアクを取り除き、火を止めて半生の肉を取り出し、取っておきます。","まず強火で水を沸騰させ、その後中火にします。","火が通りにくい食材（半生の肉、しいたけなど）を最初に鍋に入れます。確実に火を通すため、沸騰してから10分間計時し、特に火が通りにくい大きい食材はさらに5分追加します。","麺類を鍋に入れ、麺とスープがよく絡むように適度に混ぜ、液面が軽く沸騰している状態を保ちながら5分間煮ます。麺を加えると白い泡が出やすくなるので、適宜蓋をずらして空気を入れるか、蓋を外します。","青菜など火が通りやすい食材を鍋に入れ、よく混ぜて完全に浸るようにし、2〜5分間煮ます。","火を止め、塩、こしょう、ごま油などお好みの調味料を加え、適度に混ぜてから盛り付けていただきます。"]'::jsonb, '["主食","あっさり","家庭料理","時短","自由にアレンジ","栄養バランス"]'::jsonb),
  ('howtocook:staple/河南蒸面条/河南蒸面条', 'ja', '河南蒸し麺', '主食', '河南蒸し麺は河南省発祥の家庭料理で、麺を先に蒸し、その後炒めてから再び蒸すことで、油がしみ込んでコクがあり、コシと滑らかさが際立ちます。豚バラ肉とニンニクの芽が豊富なタンパク質と食物繊維を提供し、主食と組み合わせることでバランスの取れた栄養が摂れます。工程はやや多めですが、初心者でも順番通りに作業すれば成功します。準備から完成まで約40分かかります。', '[{"name":"乾麺（丸麺推奨）","unit":"g"},{"name":"豚バラ肉","unit":"g"},{"name":"ニンニクの芽","unit":"g"},{"name":"ネギ","unit":"g"},{"name":"ショウガ","unit":"g"},{"name":"ニンニク","unit":"g"},{"name":"料理酒","unit":"ml"},{"name":"塩","unit":"g"},{"name":"鶏ガラスープの素","unit":"g"},{"name":"五香粉","unit":"g"},{"name":"薄口醤油","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"オイスターソース","unit":"ml"},{"name":"食用油","unit":"ml"},{"name":"ごま油","unit":"ml"},{"name":"蒸し網","unit":"適量","note":"適量"}]'::jsonb, '["鍋に水を7割入れ、沸騰したら蒸し網を設置する","乾麺を均等に広げ、5mlの油をかけて塗り広げ、15分蒸す","蒸した麺と蒸し網を取り出し、別に置き、鍋の水を捨てる","豚バラ肉を2mmの厚さに切る","ニンニクの芽を3cmの長さに切る","ネギを0.2cmの薄切りにする","ショウガを1mm×1mm×3cmの細切りにする","ニンニクをまな板に置いて潰し、1mmのみじん切りにする","鍋を加熱して水分を飛ばし、食用油3mlを加える","鍋の取っ手を持って揺すり、油を鍋の2/3に満遍なく広げる","中火で豚肉を加え、1分炒める","ネギ、ショウガ、ニンニク、料理酒を加え、さらに1分炒める","ニンニクの芽を鍋に入れ、1分炒める","味付け：濃口醤油、薄口醤油、オイスターソース、塩、鶏ガラスープの素、五香粉を加え、1分炒める","水500mlを加え、野菜が浸る程度にし、1分煮る","蒸した麺を加え、絶えず混ぜながら3分、麺に均等に色がついたら火を止める","混ぜ合わせた麺と野菜をすべて別のボウルに移す","鍋に冷水を7割入れ、蒸し網を置き、混ぜた麺と野菜を均等に広げる","沸騰したら強火で15分蒸し、完成","ごま油10gをかけていただきます"]'::jsonb, '["主食","河南風味","家庭料理","香ばしい","蒸し炒め","ご飯が進む"]'::jsonb),
  ('howtocook:staple/火腿饭团/火腿饭团', 'ja', 'ハムおにぎり', '主食', '簡単で素早く作れる和風おにぎり。塩味のハムとマヨネーズ、海苔の組み合わせが豊かな味わいで満足感があります。炭水化物、タンパク質、ビタミンが豊富で、素早くエネルギー補給ができます。調理はとても簡単で、初心者でも気軽に作れます。ご飯を炊くところから完成まで約1時間です。', '[{"name":"ハム","unit":"克"},{"name":"ご飯","unit":"克"},{"name":"水","unit":"ml"},{"name":"冷凍グリーンピース","unit":"克"},{"name":"冷凍コーン","unit":"克"},{"name":"刻み海苔","unit":"克"},{"name":"マヨネーズ","unit":"克"},{"name":"サラダ油","unit":"ml"}]'::jsonb, '["ご飯と水を炊飯器に入れ、炊飯モードを選択して完了を待ちます。","冷凍コーンと冷凍グリーンピースを鍋に入れ、食材がかぶるくらいの水を加え、沸騰したら2分待ってから引き上げます。","ハムを1cmの角切りにします。","その間に、サラダ油10mlを加え、ハムに色がつくまで炒めます。","ご飯、ハム、刻み海苔、グリーンピース、コーン、マヨネーズをボウルに入れ、よく混ぜ合わせます。","盛り付けます（お好みで）"]'::jsonb, '["主食","和風","簡単","家庭風","塩味","おにぎり"]'::jsonb),
  ('howtocook:staple/炒凉粉/炒凉粉', 'ja', '涼粉炒め', '主食', '涼粉炒めは山西・陜西地方の家庭的な軽食です。なめらかな口当たりで、塩味と香ばしさ、ほんのり辛さが特徴。ニンニクと味噌の風味が広がります。涼粉は主にデンプンからできていて、炭水化物が豊富ですぐにエネルギー補給できます。調理は少しコツがいりますが、初心者にもチャレンジしやすいです。全体で約15分でできます。', '[{"name":"涼粉","unit":"g"},{"name":"コーン油","unit":"ml"},{"name":"ニンニク","unit":"g"},{"name":"ネギ","unit":"g"},{"name":"豆板醤","unit":"g"},{"name":"薄口醤油","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"十三香","unit":"g"},{"name":"中粗唐辛子粉","unit":"g"},{"name":"ミネラルウォーター","unit":"ml"}]'::jsonb, '["涼粉をマージャン牌の大きさに切る","弱火で鍋に油を入れ、鍋が少し温まったら、みじん切りにしたニンニクを入れて香りを出し、豆板醤を加えて赤い油が出るまで炒める。","涼粉の塊を鍋に入れ、10秒炒める。","薄口醤油を加えて味をつけ、濃口醤油で色をつけ、均一に炒めたら、中粗唐辛子粉を加えてさらに均一に炒める。","塩、十三香を加え、さらに10秒炒める。","用意したミネラルウォーターを加え、再び10秒炒め、汁がとろみをついたら火を止め、皿に盛り付ける。","刻んだネギを散らして完成。"]'::jsonb, '["主食","塩味と香ばしさ ほんのり辛い","炒め","晋陜風味","家庭的小吃","手軽"]'::jsonb),
  ('howtocook:staple/炒年糕', 'ja', 'チャオニエンガオ（炒め餅）', '主食', 'これは閩南風味の主食です。餅は柔らかくもちもちとした食感で、葱油の香ばしい香りが特徴で、家庭的な味わいで満足感があります。米粉から作られた餅は炭水化物が豊富で、卵や青菜と合わせることでタンパク質やビタミンを補え、栄養バランスが良いです。作り方は簡単で初心者にも優しく、準備から仕上がりまで約30分かかります。', '[{"name":"年糕（ニエンガオ）/白粿（バイグオ）","unit":"g"},{"name":"小ねぎ","unit":"本"},{"name":"食用油","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"卵","note":"適量"},{"name":"青菜","note":"適量"}]'::jsonb, '["鍋に水を入れて沸かし、年糕を茹でる。ボウルに水を入れて年糕がくっつかないようにし、年糕を取り出して置く。","小ねぎは小口切りにする（白い部分と青い部分を分ける）。青菜は小さめに切っておく。","（任意）炒め卵を作る（トマト炒め卵のレシピ参照）。","鍋を熱し、食用油30mlを加える。","鍋に小ねぎの白い部分を入れ、大部分が焦げ茶色になり香りが立つまで炒める。葱油を取り出しておく。","鍋を再度熱し、食用油20mlを加える。","すべての副材料（卵、青菜など）を加え、よく炒め合わせる。","年糕の水を切り、鍋に年糕を加える。","醤油と塩を加え、よく炒め合わせる。","火を止め、葱油を加えて混ぜ合わせ、器に盛る。"]'::jsonb, '["主食","閩南風味","炒め","家庭料理","時短","香り豊か"]'::jsonb),
  ('howtocook:staple/炒意大利面/炒意大利面', 'ja', 'スパゲッティ炒め', '主食', 'このスパゲッティ炒めは、もちもちとした食感で、牛肉とソースの組み合わせが香ばしく、洋風の味わいのある家庭料理です。炭水化物とたんぱく質が豊富で、エネルギーをすばやく補給できます。作り方は簡単で、初心者でも気軽に作れます。全体で約30分かかります。', '[{"name":"スパゲッティ","unit":"g"},{"name":"牛肉の薄切り","unit":"枚"},{"name":"トマトケチャップ","unit":"g"},{"name":"黒胡椒ソース","note":"どちらか一つでよい"},{"name":"菜種油","unit":"ml"},{"name":"水","unit":"g"},{"name":"塩","unit":"g"}]'::jsonb, '["水250g（一人分）を加える","水が沸騰したら、パスタを入れ、中火で15〜20分茹でる（このパスタは通常硬めなので、引き上げる前に味見をして、中心が少し硬い場合はさらに茹でる）","パスタを引き上げ、皿に盛っておく","フライパンに油を熱し、中温になったらパスタを入れて1分炒める（乾燥しすぎる場合は少量の水を加える）","トマトケチャップ10g、牛肉、塩2gを加え、さらに1分炒める","火を止める"]'::jsonb, '["主食","ソース香","洋風","炒め","時短","家庭料理"]'::jsonb),
  ('howtocook:staple/炒方便面/炒方便面', 'ja', '炒めインスタントラーメン', '主食', 'この炒めインスタントラーメンは、もちもちとした食感で、塩味が効いており、伝統的な茹で麺からアレンジした家庭風の簡単主食です。卵とウインナーを加えることで、たんぱく質とエネルギー源が豊富になります。作り方は簡単で、冷水で麺を洗って食感を保つことだけ注意すれば、初心者でも手軽にでき、全体で約15分で完成します。', '[{"name":"インスタントラーメン","unit":"袋"},{"name":"卵","unit":"個"},{"name":"ウインナー","unit":"本"},{"name":"食用油","unit":"ml"},{"name":"水","unit":"ml"}]'::jsonb, '["ウインナーの包装をはがし、幅1cmの小片に切ります。","鍋に水1200mlを加えます（実際には麺が浸る程度）。完全に沸騰させます。沸騰する前に麺を入れないでください。","インスタントラーメンの麺を入れ、45秒間茹でます。茹でている間に麺をほぐしながら混ぜます。","麺がほぐれたらすぐに火を止めます。茹で過ぎないように！","鍋から茹で汁を80ml取り出しておきます。","麺と茹で汁を分けます。麺を冷水でさっと洗います。","麺の水気を切ります。長時間水に浸さないでください。","小さなボウルを用意し、インスタントラーメンの調味パックを絞り出します。","全ての野菜パックを絞り入れます。","全てのソースパックを絞り入れます。","粉パックの50%～80%を絞り入れます（全部入れると塩辛くなります）。","先ほど取り出した80mlの茹で汁を全て小ボウルに注ぎ、よく混ぜて調味液を作ります。","必要数の卵を割り、小さなボウルに入れます。塩は加えないでください（卵は最終的に鍋の具材の塩味と混ざります）。","フライパンを20秒加熱し、分量の油8mlを加えます。","準備した卵を加え、約20秒炒めて固まったらOKです。","炒り卵を取り出して一旦置きます。フライパンは洗わなくて大丈夫です。通常、油はあまり残っていません。","再度フライパンを20秒加熱し、油10mlを加えます。","最初に切ったウインナーを加え、10秒炒めます。","先ほどの麺を加え、30秒炒めます。","調味液を加え、30秒炒めます。","炒り卵を加え、30秒炒めます。","火を止めて皿に盛り付けて完成です。"]'::jsonb, '["主食","塩味","時短","家庭風","炒め"]'::jsonb),
  ('howtocook:staple/炒河粉', 'ja', '炒め河粉', '主食', '炒め河粉は広東地方で人気の定番軽食で、鍋の香りが重要で、パラッと仕上げてのどごし良く、河粉は柔らかく透き通り、肉、もやし、キュウリと合わせて食感の層を楽しめます。主に炭水化物とタンパク質を供給し、野菜でビタミンと食物繊維も補えます。このレシピは難易度中程度で、初心者でも材料が揃えば挑戦でき、調理時間は約30分で食卓に出せます。', '[{"name":"河粉","unit":"g","note":""},{"name":"豚肉/牛肉","unit":"","note":"適量"},{"name":"塩","unit":"g","note":""},{"name":"うま味調味料","unit":"g","note":""},{"name":"老抽","unit":"ml","note":""},{"name":"生抽","unit":"ml","note":""},{"name":"クミンパウダー","unit":"g","note":""},{"name":"河粉用シーズニング","unit":"g","note":""},{"name":"こしょう","unit":"","note":"適量"},{"name":"きゅうり","unit":"g","note":""},{"name":"グルテンブロック","unit":"g","note":""},{"name":"もやし","unit":"g","note":""},{"name":"卵","unit":"個","note":""},{"name":"にんにく","unit":"個","note":""},{"name":"青ネギ","unit":"本","note":""},{"name":"片栗粉","unit":"","note":"適量"},{"name":"食用油","unit":"g","note":""}]'::jsonb, '["小葱をみじん切りにする（白い部分と青い部分は分ける）。にんにくを潰してまな板に置く。","卵を割り、白身少々を一つのボウルに取り、残りは別のボウルに入れる。","もやしを鍋に入れ、強火で60秒茹でる。もやしを取り出し、冷水にさらしてから皿に取る。","きゅうりを千切りにして皿に取り、もやしと一緒にしてもよい。","グルテンを処理し、別の皿に取る。","肉を細切りにし、でんぷんと先ほど取った卵白、こしょうを加え、時計回りに混ぜ合わせる。","注：スーパーで買った涼皮は表面に食用油が塗ってある場合があるので、水道水で洗ってもよい。グルテンも同様。","注：グルテンを洗った後、手で中の水分をしっかり絞る（強く絞りすぎない）。","食用油を加え、鍋を熱して油を出す。","処理した肉を入れ、色が変わるまで炒め、ボウルに取る。","鍋が熱いうちに食用油20gを加え（高血圧の人は量を減らしてもよい）、葱白、にんにくを入れて香りが出るまで炒める。","河粉を加え、老抽で色を付け、よく混ぜてから河粉用シーズニングを加え、さらに炒める。","河粉が透き通りかけたら、炒めた肉とグルテンを加え、生抽で旨味を足し、さっと二度炒める。","もやしときゅうりの千切りを加え、河粉が完全に透き通るまで炒める。","火を止める！","葱の青い部分を散らし、鍋を持ち上げる。","皿に盛り付けて、ご飯をいただく。"]'::jsonb, '["主食","香り豊か","炒め","広東風","時短","ご飯のおかず"]'::jsonb),
  ('howtocook:staple/炒馍', 'ja', '炒め饅頭', '主食', '炒め饅頭は、塩味と香ばしさが魅力のサクサク食感、家庭的な麺料理で、北方風味です。饅頭の角切りを黄金色に炒め、外はカリッと中はふんわり。クミンと五香粉の風味が食欲をそそります。卵でタンパク質、小ねぎで香りをプラスし、栄養バランスも良いです。難易度は中程度で、初心者でもすぐに作れ、約15分で完成します。', '[{"name":"饅頭","unit":"個"},{"name":"塩","unit":"g"},{"name":"油","unit":"ml"},{"name":"クミン粉","unit":"g"},{"name":"唐辛子粉","unit":"g"},{"name":"五香粉","unit":"g"},{"name":"小ねぎ","unit":"本"},{"name":"卵","unit":"個"},{"name":"粉胡椒","note":"適量"}]'::jsonb, '["饅頭を小さな塊または薄切りに切る。","卵を使う場合は、卵をボウルに割り入れ、溶きほぐす（塩と五香粉を各1g加えてもよいし、加えなくてもよい。炒める途中で加えてもよい）。","卵を饅頭の上にかけ、混ぜ合わせる。卵は多すぎないように。","強火で鍋を熱し、食用油を入れる（ステンレス鍋が傷むのが心配な場合は、先に油を入れてから加熱してもよい）。","饅頭の角切りを入れて炒め、均一に炒める。","火を弱め、饅頭が黄金色になるまで炒める。","塩、胡椒、五香粉を加える。","最後に小ねぎを加えて一緒に数回炒める。","火を止めて器に盛る。"]'::jsonb, '["主食","塩味香ばしい","炒め","北方風味","時短","家庭料理"]'::jsonb),
  ('howtocook:staple/炸酱面', 'ja', 'ジャージャー麺', '主食', 'ジャージャー麺は、味噌の香りが豊かでコシのある麺が特徴的な北京の伝統的な家庭料理です。さっぱりとした野菜トッピングと組み合わせ、甘辛く仕上がります。主な栄養は赤身肉のタンパク質と野菜のビタミンから摂れ、エネルギーをしっかり補給できます。初心者にも優しく、調理時間は約30分。慣れれば具材の準備と味噌炒めを並行してさらに短縮できます。', '[{"name":"豚肉（角切り/ひき肉）","unit":"g"},{"name":"乾麺","unit":"g"},{"name":"普通の麺","unit":"g"},{"name":"ネギ","unit":"g"},{"name":"ニンニク","note":"適量"},{"name":"野菜トッピング","unit":"g"},{"name":"食用油","unit":"g"},{"name":"豆瓣醤","unit":"g"},{"name":"甜麺醤","unit":"g"}]'::jsonb, '["野菜トッピングを千切りにして用意する。","ネギをみじん切りにする。油を熱した鍋にネギと肉を入れ、肉に火が完全に通るまで（赤みがなくなるまで）炒める。","豆瓣醤（トウバンジャン）と甜麺醤（テンメンジャン）を加え、少しとろみがつくまで炒め続ける。取り出してジャージャーソースとする。","大きめのボウルに冷水を入れておく。","麺を芯がなくなるまで茹で、4の冷水を入れたボウルに移す。","すぐに水気を切って取り出し、清潔なボウルに盛る。","3のジャージャーソースを加えて混ぜる。次に1の野菜トッピングを加えて混ぜる。"]'::jsonb, '["主食","味噌風味","甘辛","炒め味噌","北京","家庭料理","時短"]'::jsonb),
  ('howtocook:staple/烙饼/烙饼', 'ja', 'ローピン', '主食', 'この家庭風ローピンは、層がはっきりしていて、外はサクサク、中はふんわり。油酥の香ばしさが香る、北方の食卓に欠かせない主食です。主に炭水化物とエネルギーを摂取でき、おかずと一緒に食べるのにぴったりです。作り方には少しコツが必要ですが、特に巻き方や伸ばし方の工程を丁寧にやれば、初心者でもマスターできます。生地をこねてから焼き上がりまで、約1時間かかります。', '[{"name":"小麦粉","unit":"グラム"},{"name":"お湯","unit":"ミリリットル"},{"name":"冷水","unit":"ミリリットル"},{"name":"油","unit":"","note":"適量"},{"name":"ホットプレート","unit":"","note":"適量"}]'::jsonb, '["ボウルに400gの小麦粉を入れ、半分は冷水で、半分はお湯でこね、ぼろぼろになるまで混ぜ、手でひとまとめにする。ラップで覆い、40分間寝かせる。","寝かせる時間が終わる10分前に、コツの油酥の作り方を確認する（熱い油酥の方が効果的）。","寝かせた生地はこねずに、軽く押して、横一文字、縦一文字に切って4等分する。","丸めて、伸ばし、ホットプレートと同じくらいの大きさの円形に伸ばし、油酥の1/4を取り、表面に均一に塗る。","円の半径に沿って切り込みを入れ、外側から円錐形に巻き、先端をつまんで油酥が漏れないようにする。","円錐の先端を押して平らにし、再度ホットプレートと同じくらいの大きさに伸ばす（厚さ約3mm）。","ホットプレートを予熱し、冷たい油を塗る（熱い鍋に冷たい油）。伸ばした生地を入れ、上面にも油を刷毛で均一に塗る（水分を閉じ込めるため）、蓋をする。","強火で1分焼き、蓋を開けて裏返し、さらに1分焼く。","以上の工程を繰り返し、焼き上げる。"]'::jsonb, '["主食","焼き","北方","家常主食","外はサクサク中はふんわり","層がはっきり"]'::jsonb),
  ('howtocook:staple/烧饼/芝麻烧饼', 'ja', 'ごま焼餅', '主食', 'ごま焼餅は北方で誰もが知っている麺料理です。表面にはごまがたっぷりと付いていて香ばしく、中は層がはっきりとしていて柔らかく美味しいです。小麦粉は十分な炭水化物を供給し、ごまにはカルシウムと不飽和脂肪酸が豊富に含まれています。作り方はこねる工程や油酥を作る工程がありますが、操作は複雑ではなく、初心者でも作ることができます。準備から完成まで約40分かかります。', '[{"name":"小麦粉","unit":"g"},{"name":"小麦粉","unit":"g"},{"name":"ドライイースト","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"ぬるま湯（40℃）","unit":"g"},{"name":"食用油","unit":"g"},{"name":"食用油","unit":"g"},{"name":"十三香","unit":"g"},{"name":"塩","unit":"g"},{"name":"白ごま","note":"適量"}]'::jsonb, '["生地：小麦粉300g、ドライイースト3g、砂糖3g、ぬるま湯180g、食用油20g、10分間休ませる","油酥：小さなボウルに小麦粉30g、塩2g、十三香4g、食用油20gを入れ、混ぜ合わせてから置いておく","餅作り：生地を長方形に伸ばし、調製した油酥を塗り、端から巻き上げ、7つの生地に切り、半分に折り、親指と人差し指でくぼみを閉じ、水に浸してから白ごまをつけ、小さな丸い餅に伸ばす","焼き：電気フライパンを予熱し、冷たい油を入れ（鍋底に油が敷き詰められるように）、伸ばした餅を電気フライパンに入れ、餅の表面にも油を塗り、均一に塗ったら蓋を閉め、大餅モードを選び、チンという音がしたら取り出す"]'::jsonb, '["主食","香ばしくサクサク","焼き","北方","家庭料理","麺料理"]'::jsonb),
  ('howtocook:staple/热干面', 'ja', '熱乾麺', '主食', '熱乾麺は武漢を代表する軽食の一つで、湖北料理に属します。鹹水麺はコシがあり滑らかで、濃厚な芝麻醤が絡み、酸豆角、干し大根、挽き肉がトッピングされ、塩味と香ばしさにほんのり辛みがあり、深い味わいです。主に炭水化物とタンパク質を摂取でき、芝麻醤にはカルシウムも豊富です。調理は簡単で手早くでき、初心者でも麺を茹でてから和えるまで約10分ほどで完成します。', '[{"name":"熱乾麺用鹹水麺","unit":"g"},{"name":"小ネギ","unit":"g"},{"name":"酸豆角","unit":"g"},{"name":"挽き肉","unit":"g"},{"name":"ニンニク水","unit":"ml"},{"name":"肉汁","unit":"ml"},{"name":"干し大根","unit":"g"},{"name":"芝麻醤","unit":"ml"},{"name":"ラー油","unit":"ml"},{"name":"胡椒","unit":"g"},{"name":"醤油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"鶏がらスープの素","unit":"g"}]'::jsonb, '["湯を沸かし、鹹水麺を入れて25秒ほど茹で、引き上げる","塩、鶏がらスープの素、胡椒を振る","芝麻醤を90mlの水で溶いて混ぜ、加える","醤油5ml、肉汁30ml、ニンニク水を加える","干し大根、挽き肉、酸豆角、ネギを加える","よく混ぜて出来上がり"]'::jsonb, '["主食","武漢","軽食","和え麺","時短","塩味香ばしく少し辛い","家庭料理"]'::jsonb),
  ('howtocook:staple/煮泡面加蛋', 'ja', '卵入りインスタントラーメン', '主食', '卵入りインスタントラーメンは手軽で簡単な主食です。なめらかな食感と濃厚なスープが特徴で、いつでもお腹を満たすのに適しています。主に炭水化物とタンパク質を摂取でき、素早くエネルギーを補給できます。作り方は非常に簡単で、お湯を沸かし、麺を茹で、卵を割り入れて茹でるだけ。初心者でも簡単にでき、全工程約10分で完成します。', '[{"name":"インスタントラーメン","unit":"袋"},{"name":"卵","unit":"個"},{"name":"水","unit":"ml"}]'::jsonb, '["まず水を沸騰するまで加熱します（火加減は厳密でなくて大丈夫、熱湯を使うとより早いです）","取り出した麺ブロックを鍋に入れます","インスタントラーメン付属の調味料を鍋に入れます","箸で麺を軽くほぐし、調味料をよく溶かし、麺ブロックに均等に熱が通るようにします","蓋をして約1分待ち、鍋の中の水が再び沸騰するのを待ちます","卵の殻を割り、鍋に加えます","約3～4分待てば出来上がりです"]'::jsonb, '["主食","手軽","家庭風","煮","旨味","満腹感"]'::jsonb),
  ('howtocook:staple/照烧鸡腿饭', 'ja', '照り焼きチキン丼', '主食', '照り焼きチキン丼は甘辛い味付けでご飯が進む一品。鶏もも肉を香ばしく焼き、濃厚なタレが絡んで柔らかく味が染み込んでいます。鶏もも肉は良質なたんぱく質が豊富で、ブロッコリーや人参と一緒に食べることで食物繊維やビタミンも補えます。調理には骨を外す技術が少し必要ですが、全体的に難しくなく、初心者でも手順通りに作れば成功します。下ごしらえから出来上がりまで約30分で食卓に並べられます。', '[{"name":"鶏もも肉","unit":"g"},{"name":"酒","unit":"ml"},{"name":"しょうゆ","unit":"ml"},{"name":"はちみつ","unit":"ml"},{"name":"粗びき黒こしょう","unit":"g"},{"name":"黒こしょう粉","unit":"g"},{"name":"塩","unit":"g"},{"name":"ブロッコリー","unit":"g"},{"name":"にんじん","unit":"g"},{"name":"濃い口しょうゆ","unit":"ml"},{"name":"にんにく","unit":"g"},{"name":"しょうが","unit":"g"},{"name":"サラダ油","unit":"ml"},{"name":"水","unit":"ml"},{"name":"ご飯","unit":"g"}]'::jsonb, '["鶏もも肉1枚を取り、皮目を下にしてまな板に置く。","包丁の先で骨に沿って、端から端まで軽く切り目を入れる。","指または包丁の背でゆっくりと肉を押し広げ、骨を露出させる。筋膜があれば、包丁の先で切る。","肉が完全に離れたら、骨の一端を持ち、軽くひねりながら引き抜く。","残りの鶏もも肉も同様に骨を取り除く。","骨を取った鶏もも肉に黒こしょう粉、粗びき黒こしょう、塩、生姜の薄切りを加えて5分ほど漬け込む。","ボウルに酒、しょうゆ、はちみつ、濃い口しょうゆ、水を入れて混ぜ合わせる。","野菜を1-2分ゆでて、ザルにあげる。","フライパンを熱して油15mlを入れ、つぶしたにんにくを加えて香りを出す。","鶏もも肉を入れ、中弱火で両面がこんがりとするまで焼く。もしフライパンが乾いているようなら、油を5-10ml追加する。","合わせたタレを加え、蓋をして中弱火（ガスコンロの場合は弱火）で5-10分煮て、火を通し、タレがとろりとして泡立つまで煮詰める。","食べやすく切り、野菜と一緒にご飯の上に盛り、鶏肉を焼いた時のタレをかけて召し上がれ。"]'::jsonb, '["主食","甘辛","焼き煮","和風","ご飯が進む","時短"]'::jsonb),
  ('howtocook:staple/蒸卤面', 'ja', '蒸し煮込み麺', '主食', 'これは豫南（河南南部）地方の定番家庭料理の麺料理で、肉と野菜がバランスよく、麺にスープがよく染み込み、柔らかくも歯ごたえがあり、塩味と香りがしっかりとしています。豚バラ肉は良質のタンパク質と脂質を提供し、セロリは食物繊維が豊富です。作り方は簡単で、初心者でも気軽にでき、全体で約1時間かかります。', '[{"name":"豚バラ肉","unit":"グラム"},{"name":"生麺","unit":"グラム"},{"name":"セロリ","unit":"本"},{"name":"長ネギ","unit":"cm"},{"name":"生姜","unit":"グラム"},{"name":"にんにく","unit":"片"},{"name":"ピーマン","unit":"個"},{"name":"乾燥赤唐辛子","unit":"個"},{"name":"花椒（ホアジャオ）","unit":"粒"},{"name":"塩","unit":"グラム"},{"name":"五香粉","unit":"グラム"},{"name":"薄口醤油","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"食用油（ピーナッツオイルが最適）","note":"適量"},{"name":"料理酒","note":"適量"}]'::jsonb, '["豚肉の皮を取り、2cm×6cm×0.5cmの薄切りにする。","セロリの葉を取り、根元から2cm切り落とし、半分に切ってから2cmの長さに切る。","にんにくの皮をむき、みじん切りにする。長ネギは0.2cmの薄切り、生姜は細切りにする。","炒め鍋を熱して煙が出たら、サラダ油3mlを入れて鍋全体に油をなじませ、余分な油を捨てる。","新しくサラダ油を加え、豚肉、ネギ、生姜、にんにく、乾燥赤唐辛子を入れ、1分間絶えず均等に炒める。","料理酒、薄口醤油、濃口醤油を加え、さらに1分間炒める。","熱湯500mlを加える。蓋をして3分間煮込む。","セロリとピーマンを鍋に入れ、塩と五香粉で味を調え、蓋をしてさらに3分間煮込んだ後火を止める。","蒸し鍋に水1000mlを入れ、沸騰して蒸気が上がったら、麺を平らに広げて蒸し籠にのせ、15分間蒸す。","麺が蒸し上がったら取り出し、箸と手でほぐしながらまな板の上に広げ、室温で冷ます。","麺を鍋の具材と混ぜ合わせる。混ぜ方は、片手で箸、もう一方の手で鍋杓子を使い、具材を麺の上に返しながら、全体に均一に色がつくまで混ぜる。","混ぜた麺を再び蒸し籠にのせ、さらに10分間蒸して火を止める。"]'::jsonb, '["主食","塩味と香り","蒸し料理","豫南","家庭料理","肉と野菜の組み合わせ"]'::jsonb),
  ('howtocook:staple/猪油拌饭', 'ja', 'ラードご飯', '主食', 'これは南国の家庭的な雰囲気あふれる簡単混ぜご飯です。ご飯粒が溶かしたラードに包まれ、醤油の塩気とネギの香りが広がります。食欲が落ちた子供たちの安心メニューとして親しまれています。主に素早い炭水化物と脂肪エネルギーを供給しますが、コレステロールが高いので頻繁には食べられません。調理に特別な技術は不要で、料理が全くできなくても簡単に作れます。炊いたご飯に数分で混ぜるだけで香ばしい主食が完成します。', '[{"name":"ご飯（うるち米推奨）","unit":"グラム"},{"name":"ラード","unit":"グラム"},{"name":"薄口醤油（李錦記または海天推奨）","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"オイスターソース（お好みで）","unit":"グラム"},{"name":"ネギ（お好みで）","unit":"グラム"},{"name":"ラードの油かす（お好みで）","unit":"グラム"}]'::jsonb, '["器の底にラードを敷く","ご飯を加える","醤油とオイスターソースをかける","ネギとラードの油かすを散らす","よく混ぜる"]'::jsonb, '["主食","塩味","混ぜご飯","時短","家庭料理","南方風","ご飯が進む"]'::jsonb),
  ('howtocook:staple/电饭煲三文鱼炊饭/电饭煲三文鱼炊饭', 'ja', '炊飯器サーモン炊き込みご飯', '主食', 'これは和風炊き込みご飯の作り方を取り入れた家庭料理です。ご飯がバターとサーモンの香りを吸って、濃厚で風味豊か。サーモンは良質なたんぱく質と不飽和脂肪酸を提供し、きのこを加えることで食物繊維もアップ。操作はとても簡単で、炊飯器でボタン一つで完成。準備から出来上がりまで約45分で、初心者にもおすすめです。', '[{"name":"米","unit":"g"},{"name":"サーモン","unit":"g"},{"name":"有塩バター","unit":"大さじ"},{"name":"水","note":"適量"},{"name":"とうもろこし（お好みで）","note":"適量"},{"name":"えのき（お好みで）","note":"適量"},{"name":"しいたけ（お好みで）","note":"適量"}]'::jsonb, '["サーモンの鱗と骨を取る","えのき、しいたけをみじん切りにする","米を三回洗う","サーモン、米、バターを炊飯器に入れる","濃厚にしたい場合は、バターをもう大さじ1杯加える","炊飯器の目盛りに合わせて水を入れる","炊飯器を炊飯モードに設定し、約30～45分待つ"]'::jsonb, '["主食","風味豊か","炊飯器","家庭料理","時短"]'::jsonb),
  ('howtocook:staple/空气炸锅照烧鸡饭/空气炸锅照烧鸡饭', 'ja', 'エアフライヤー照り焼きチキンライス', '主食', 'この和風照り焼き風味のチキンライスは、甘じょっぱいタレが濃厚で、表面はカリッと、中は柔らかくジューシー。ご飯によく合います。鶏肉と卵で良質なタンパク質が摂れますが、醤油と砂糖の量が多いので、たまのリッチメニューに最適です。作り方は簡単で、材料を混ぜてエアフライヤーにお任せ。初心者でも簡単にでき、準備から仕上がりまで約1時間です。', '[{"name":"鶏肉","unit":"g"},{"name":"醤油","unit":"ml"},{"name":"砂糖","unit":"g"},{"name":"酢","unit":"ml"},{"name":"リッツクラッカー","unit":"個"},{"name":"卵","unit":"個"},{"name":"ご飯","note":"適量"}]'::jsonb, '["醤油、砂糖、酢を混ぜ合わせ、タレを用意する","別のボウルに鶏肉、卵、タレの半量、砕いたリッツクラッカーを入れ、よく混ぜる","エアフライヤーにアルミホイルのカップを敷き、肉だねを入れ、残りのタレを均等にかける","350°F(177°C)で40分加熱する。ご飯の上にのせて食べるのがおすすめ","表面がきつね色でカリッとしたら取り出し、切り分けて盛り付ける"]'::jsonb, '["主食","甘じょっぱい","エアフライヤー","和風","ご飯が進む","家庭料理"]'::jsonb),
  ('howtocook:staple/米饭/煮锅蒸米饭', 'ja', '鍋で炊くご飯', '主食', 'これは飾り気のない家庭的な主食で、普通の鍋でふっくらとしたご飯が炊けます。白米は主に炭水化物を提供し、体に素早くエネルギーを補給します。作り方は非常に簡単で、初心者は火加減に注意するだけで簡単にマスターできます。米を入れてから出来上がりまで約25分かかります。', '[{"name":"北方米","unit":"ml"},{"name":"水","note":"適量"}]'::jsonb, '["米を洗う","米と水を鍋に入れる","強火で沸騰させる","底をかき混ぜてくっつかないようにする","蓋をして弱火で10〜15分加熱する（好みの柔らかさに応じて）、途中で蓋を開けないこと","火を止めて5分置く","楽しんでください :)"]'::jsonb, '["主食","あっさり","ふっくら","煮る","家庭料理","時短"]'::jsonb),
  ('howtocook:staple/米饭/电饭煲蒸米饭', 'ja', '炊飯器でご飯を炊く', '主食', '家庭で広く知られる基本の主食。米の香りが純粋で、食感はもちもち。水加減で硬めにも柔らかめにも調整できる。炭水化物が豊富でエネルギー補給に最適。様々なおかずに合う。操作は非常に簡単で初心者でも安心。米を洗ってから蒸らし終えるまで約40分。', '[{"name":"江南米または北方の米","unit":"ml"},{"name":"水","note":"適量"}]'::jsonb, '["米を洗う","米と水を一緒に炊飯器に入れる。","炊飯器の電源を入れ、加熱モードにする。約30分待つ。","炊飯器が自動的に保温モードになったら。","炊飯器の中で10〜15分ほど蒸らす。","ご飯をよそう。"]'::jsonb, '["主食","あっさり","時短","家庭料理"]'::jsonb),
  ('howtocook:staple/红芸豆拌饭', 'ja', '紅いんげん豆の混ぜご飯', '主食', 'この北インドの家庭料理は、パンジャーブ州とデリー地域の伝統的な料理です。トマトと玉ねぎのスープは濃厚でスパイシー、煮込んだ紅いんげん豆は柔らかく味が染み込み、温かいご飯と混ぜると体が温まり満足感があります。豆はタンパク質、食物繊維、様々なミネラルが豊富で栄養バランスが良いです。作り方は簡単で初心者でも気軽に作れます。全工程約40分ですが、乾燥豆は事前に8時間浸水させてください。濃厚な家庭の味、お母さんの味がします。', '[{"name":"乾燥紅いんげん豆","unit":"g"},{"name":"玉ねぎ","unit":"個"},{"name":"トマト","unit":"個"},{"name":"トマトペースト","unit":"ml"},{"name":"生姜","unit":"g"},{"name":"ニンニク","unit":"片"},{"name":"青唐辛子","unit":"本"},{"name":"食用油またはギー","unit":"ml"},{"name":"ローリエ","unit":"枚"},{"name":"ターメリックパウダー","unit":"g"},{"name":"レッドチリパウダー","unit":"g"},{"name":"コリアンダーパウダー","unit":"g"},{"name":"クミンパウダー","unit":"g"},{"name":"インド混合スパイス（ガラムマサラ）","unit":"g"},{"name":"塩","unit":"g"},{"name":"水","unit":"ml"},{"name":"パクチーの葉","unit":"g"},{"name":"米","unit":"g"},{"name":"水","unit":"ml"}]'::jsonb, '["乾燥紅いんげん豆を水に少なくとも8時間（一晩）浸します。浸すと体積が約2倍に膨らみます。","浸した紅いんげん豆を水切りします。","圧力鍋を使用：紅いんげん豆と水600mlを入れ、蓋をして強火で加圧し、弱火にして15～20分加圧し、豆が指で簡単に潰せるまで調理します。","普通の鍋を使用：紅いんげん豆とたっぷりの水を入れ、強火で沸騰させたら中火にして60～90分、豆が完全に柔らかくなるまで煮ます。","茹で上がったら、煮汁を取っておきます。","フライパンに食用油30mlを入れ、中火で熱します。","ローリエの葉2枚を入れ、香りが立つまで（約10秒）揚げます。","みじん切りにした玉ねぎを入れ、黄金色になるまで（約6～8分）炒めます。","すりおろした生姜とニンニクを加え、1分間炒めます。","みじん切りにしたトマトを加え、トマトが完全に柔らかくなり油が分離するまで（約5分）炒めます。","ターメリックパウダー3g、レッドチリパウダー5g、コリアンダーパウダー5g、クミンパウダー3g、塩6gを加えます。","2分間炒め、スパイスとトマトをなじませます。","茹でた紅いんげん豆を煮汁ごと鍋に加えます。","青唐辛子を加え、よく混ぜます。","強火で沸騰させたら弱火にし、15～20分煮込みます。","その間、ヘラの背で豆の一部を潰し、スープにとろみをつけます。","インド混合スパイス（ガラムマサラ）3gを加え、よく混ぜます。","火を止め、パクチーの葉を散らします。","米を研ぎ、洗います。","炊飯器に入れ、水400mlを加えます。","通常通り炊飯します。","ご飯を器に盛ります。","紅いんげん豆のカレーをご飯の上または横にかけます。","玉ねぎサラダとレモンくし切りを添えても良いです。"]'::jsonb, '["主食","北インド","煮込み料理","スパイシー","ご飯が進む","家庭料理","カレー"]'::jsonb),
  ('howtocook:staple/老友猪肉粉/老友猪肉粉', 'ja', '老友豚肉ビーフン', '主食', '老友豚肉ビーフンは酸味と辛味、香りが特徴で、ビーフンは滑らかで、豆豉と酸竹筍特有の濃厚な風味が広がる、典型的な南寧の家庭料理です。豚肉は良質なタンパク質を提供し、ビーフンは素早く炭水化物エネルギーを補給します。全体的に中程度の難易度で、ビーフンを事前に戻す必要があり、慣れれば約40分で食卓に出せます。', '[{"name":"ビーフン","unit":"グラム"},{"name":"豚肉","unit":"グラム"},{"name":"酸竹筍","unit":"グラム"},{"name":"刻み唐辛子","unit":"グラム"},{"name":"豆豉","unit":"グラム"},{"name":"大蒜","unit":"グラム"},{"name":"料理酒","unit":"ml"},{"name":"薄口醤油","unit":"ml"},{"name":"砂糖","unit":"グラム"},{"name":"米酢","unit":"ml"},{"name":"塩","unit":"ml"},{"name":"油","unit":"ml"},{"name":"片栗粉","unit":"ml"},{"name":"こしょう","unit":"ml"}]'::jsonb, '["豚肉全てに料理酒、塩、薄口醤油、片栗粉、こしょうをボウルに入れて調味し、置いておく","熱した鍋に油を入れず、酸竹筍全てを入れて水分を炒め飛ばし、炒めた酸竹筍の中央に少しスペースを空ける","10ml - 15mlの食用油と、大蒜全て、刻み唐辛子、豆豉を炒めた酸竹筍の中央に入れ、全てを中央に寄せて香りを炒める","調味した豚肉全てを入れ、続けて10mlの薄口醤油を加えて1分炒める","5mlの米酢、10mlの薄口醤油、450mlの清水を加えて一緒に沸かす","沸騰したら、温水で戻したビーフンを入れ、さらに3分煮てから盛り付ける"]'::jsonb, '["主食","酸辣","煮込み","南寧風味","家庭料理","ビーフン"]'::jsonb),
  ('howtocook:staple/老干妈拌面', 'ja', '老干妈和え麺', '主食', '香辛で食欲をそそる家庭風の簡単時短麺料理。麺はコシがあり、老干妈の豆豉の辛い香りが絡み、醤油で旨味をプラス。シンプルながら風味豊か。主食として素早く炭水化物とエネルギーを補給でき、カプサイシンが食欲を促進。作り方は簡単で初心者でも楽々。湯を沸かしてから出来上がりまで約10分。', '[{"name":"水","unit":"リットル"},{"name":"麺","unit":"グラム"},{"name":"老干妈","unit":"ml"},{"name":"醤油","unit":"ml"}]'::jsonb, '["鍋に水を入れ、沸騰させる。","麺を均等に鍋に入れる。","茹でる際は混ぜながら、麺が一塊にならないように注意する。","箸で一本の麺を引き上げ、その麺が自然に箸から滑り落ちるようになったら、さらに30秒待って火を止める。","麺を箸で取り、丼に入れる。","上記の分量で老干妈と醤油を入れる。","箸で丼の中の麺、老干妈、醤油をよく混ぜる。","食べる。"]'::jsonb, '["主食","香辛","和え麺","時短","家庭風","食欲増進"]'::jsonb),
  ('howtocook:staple/肉蛋盖饭', 'ja', '肉たまご丼', '主食', 'この料理は、醤油の香りが豊かで、塩味と甘味のバランスが良く、ひき肉は香ばしく焼け、卵はとろりと柔らか。熱々のご飯にかけて食べると満足感があり、家庭で手軽に作れるスピード料理です。良質なタンパク質と必須アミノ酸が豊富で、エネルギーを素早く補給できます。作り方は簡単で、初心者でも気軽に挑戦でき、準備から完成まで約15分です。', '[{"name":"ご飯","unit":"g"},{"name":"卵","unit":"個"},{"name":"ひき肉","unit":"g"},{"name":"老抽","unit":"ml"},{"name":"生抽","unit":"ml"},{"name":"酢","unit":"ml"},{"name":"紅葱油","unit":"g"},{"name":"ネギ","unit":"g"},{"name":"油","unit":"ml"},{"name":"砂糖","unit":"g"}]'::jsonb, '["ご飯を炊いておく。通常、お米を買った時にもらう計量カップを使い、1カップの米は240g","鍋に油30mlを入れる","ひき肉を入れ、中火で両面が軽く焦げるまで焼く","卵を割り入れる（混ぜずに）、蓋をする","合わせ調味料を作る。ボウルに計算通りの老抽、生抽、酢、砂糖、紅葱油を入れ、よく混ぜる","蓋を開け、合わせ調味料を鍋に注ぎ入れ、3分待つ","火を止め、肉と卵をご飯の上にのせる","安全確認をして、丼を食べ始める"]'::jsonb, '["主食","醤油風味","甘辛","時短","ご飯が進む","家庭料理"]'::jsonb),
  ('howtocook:staple/茄子肉煎饼/茄子肉煎饼', 'ja', '茄子とラーロウの焼きパン', '主食', 'この家庭的な焼きパンは、ラーロウの塩味と香ばしさ、茄子の柔らかさととろみが融合し、外はカリッと中はしっとりとした、田舎風味あふれる米粉の主食です。炭水化物と良質なタンパク質が豊富で、茄子は食物繊維とビタミンを提供し、肉と野菜のバランスが取れています。難易度は中程度で、生地の濃さと焼き加減のコツが必要ですが、初心者でも手順通りに作れば成功します。準備から完成まで約30分かかります。', '[{"name":"米粉","unit":"g"},{"name":"小麦粉","unit":"g"},{"name":"卵","unit":"個"},{"name":"ラーロウ","unit":"g"},{"name":"茄子","unit":"本"},{"name":"食用油","unit":"ml"},{"name":"食塩","unit":"g"}]'::jsonb, '["茄子の皮をむき、薄切りにする。ラーロウも薄切りにして、準備する。","ボウルに順番に米粉（米を挽いた粉）250g、小麦粉50g、卵1個を加える。","箸で混ぜながら水（とろみ調整用）を加え、米粉、小麦粉、卵を混ぜて生地を作る。生地が茄子の薄切りや肉の薄切りに付着して落ちなくなったら水を止め、全ての茄子と肉を生地に入れて、まんべんなく絡める。","フライパンに食用油10～30mlを入れ、弱火にかける。","箸やスプーンで生地を絡めた茄子と肉をフライパンに入れ、まず両面がきつね色になるまで焼き、さらに3～6分焼く（焼いているうちに油が減るので、適宜追加する）。","塩を振り、全体を炒め合わせ、火を止めて皿に盛る。"]'::jsonb, '["主食","塩味香ばしい","焼き","家庭料理","田舎風味","栄養バランス"]'::jsonb),
  ('howtocook:staple/葱油拌面', 'ja', 'ネギ油和え麺', '主食', 'ネギ油和え麺は、独特のネギ油の香りが特徴的な上海の定番家庭料理で、作り方は簡単で手早くできます。炭水化物と脂質が豊富で、すぐにエネルギーを補給できます。初心者でも20分ほどで完成し、普段の忙しい日の夕食に最適です。', '[{"name":"乾麺","unit":"グラム"},{"name":"青ネギ","unit":"グラム"},{"name":"薄口醤油","unit":"ミリリットル"},{"name":"濃口醤油","unit":"ミリリットル"},{"name":"砂糖","unit":"グラム"},{"name":"食用油","unit":"ミリリットル"}]'::jsonb, '["青ネギを洗い、長さ5〜7cmのぶつ切りにする。白い部分と緑の部分は分けておく。","鍋に食用油100mlを入れ、中火で熱する。まず白い部分を入れ、薄く色づくまで炒める。","緑の部分を加え、弱火にしてさらに炒める。","弱火のまま、約15〜20分かけて、ネギがカリッと濃いきつね色になるまでじっくり炒める。","焦がしたネギを取り出す（油は鍋に残す）。","鍋のネギ油に、薄口醤油60ml、濃口醤油20ml、砂糖15gを加える。弱火で約1分、砂糖が溶けてタレが均一になるまで混ぜながら加熱する。すぐに火を止める。作ったネギ油タレを容器に移し、冷ましてから密閉保存する。","乾麺80gを用意する。","鍋に飲用水1000mlを入れ、強火で沸騰させる。","麺を入れ、麺の表示時間通りに茹でる（通常3〜8分、表示に従う）。","茹で上がった麺をざるに上げ、水気を切って器に入れる。","麺の入った器に、先に作ったネギ油タレ15mlを加える。","前の工程で揚げたネギを加えてもよい（お好みで）。","箸で手早くよく混ぜて、出来上がり。"]'::jsonb, '["主食","上海","香ばしい","スピード料理","家庭料理","和え麺"]'::jsonb),
  ('howtocook:staple/蛋包饭', 'ja', 'オムライス', '主食', 'なめらかな卵の皮でケチャップライスを包んだ一品。食感豊かで、甘酸っぱく食欲をそそる、定番の和風家庭料理。たんぱく質、炭水化物、各種ビタミンがバランス良く含まれています。卵の皮を包むのに少しコツがいりますが、全体的な難易度は普通で、初心者でも挑戦できます。準備から完成まで約25分です。', '[{"name":"卵","unit":"個"},{"name":"玉ねぎ","unit":"g"},{"name":"にんじん","unit":"g"},{"name":"コーン、グリーンピース（お好みで）","unit":"g"},{"name":"ウインナーまたは鶏むね肉","unit":"g"},{"name":"ご飯","unit":"g"},{"name":"ケチャップ","unit":"ml"},{"name":"サラダ油","unit":"ml"},{"name":"牛乳（お好みで）","unit":"ml"}]'::jsonb, '["玉ねぎ、にんじん、ウインナーまたは鶏むね肉を小さな角切りにし、用意しておく。","鍋を熱し、10mlのサラダ油を入れ、10秒待って加熱する。","最初に玉ねぎを入れて1分炒め、香りが出たらにんじん、コーン、グリーンピースを加えてさらに2分炒める。","ウインナーまたは鶏むね肉の角切りを加え、色が変わるまで炒める。","ご飯を加えてほぐしながら炒め、ケチャップ20mlを加えて全体を混ぜ合わせる。炒飯が完成したら、取り出して用意しておく。","卵を溶きほぐし、牛乳10mlを加えて混ぜる。","鍋に5mlのサラダ油を入れ、溶き卵を流し入れ、鍋底を軽く揺すって卵液を均等に広げる。","弱火で加熱し、卵の表面が半熟状態になったら、炒飯を卵液の中央に置く。","ヘラで卵の皮を折りたたんでご飯を包み、楕円形にする。","ヘラでそっと皿に移し、形を整える。お好みで表面に少量のケチャップを絞って飾る。"]'::jsonb, '["主食","甘酸っぱい","炒め","簡単","家庭料理","和風","食欲増進"]'::jsonb),
  ('howtocook:staple/蛋炒饭', 'ja', '卵炒飯', '主食', '家庭的な卵炒飯のレシピです。黄金色の卵がご飯一粒一粒に絡み、ハム、にんじん、きゅうりの食感が楽しい、塩味香ばしい一品。卵は良質なタンパク質、にんじんはビタミン、ご飯は炭水化物でエネルギー補給に。工程は少し多めですが、初心者でも手順通りに作れば成功間違いなし。全体で約25分。', '[{"name":"冷ご飯","unit":"ml"},{"name":"卵"},{"name":"ハム","unit":"個"},{"name":"きゅうり","unit":"g"},{"name":"にんじん","unit":"g"},{"name":"油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"胡椒","unit":"g"},{"name":"小ねぎ","unit":"本"},{"name":"醤油","unit":"ml"},{"name":"灯影牛肉絲/ランチョンミート/ソーセージ/煮豚などの調理済み肉（オプション）","note":"適量"}]'::jsonb, '["ご飯は事前にシャモジでほぐしておく","ハム、にんじん、きゅうりなどを好みでスライスまたはさいの目に切る","家に調理済みの肉があれば準備しておくとより美味しい","卵白と卵黄を分け、それぞれ大きめのボウルに入れてよく混ぜる。注意：この段階で塩は加えない。","強火で鍋を熱し、煙が出たらサラダ油を入れ、卵白を加える。全体が固まったら取り出して置いておく。","油が十分ならそのまま卵黄を加える。油が足りなければサラダ油を足して強火で熱する。","卵黄が固まったら中弱火にし、ハム、調理済み肉、にんじん、きゅうりなどの具材を加えて10秒炒める（香りが立つまで）。","卵白を戻し入れ、5秒炒めたら、素早くご飯を加えて強火で炒める。ご飯一粒一粒に卵が絡むように。","炒めながらご飯の塊をほぐす。この工程は時間がかかるが、ご飯がすべてほぐれて均一に混ざったらOK。","弱火にし、塩、胡椒、醤油を加える。","さらに均一になるまで炒める。ご飯が鍋の中で跳ねるようになったらほぼ完成。","最後に小ねぎを加えて10秒炒める。","火を止め、器に盛る。"]'::jsonb, '["主食","塩味香ばしい","家庭風","時短","炒め物","ご飯が進む"]'::jsonb),
  ('howtocook:staple/螺蛳粉', 'ja', 'ルオスーフェン', '主食', 'ルオスーフェンは広西柳州の名物料理で、スープは旨味豊かで酸辣さっぱり、米粉は柔らかくコシがあります。味わいは、タニシスープの旨味、酸竹の子独特の発酵風味、ラー油の刺激が融合し、層をなしています。主食として、米粉は十分な炭水化物を供給し、タニシ肉やトッピングはタンパク質をもたらし、酸竹の子は食欲をそそり消化を助けます。この料理は操作が簡単で、順番に米粉を茹でて調味するだけで、初心者にも優しいです。湯沸かしから盛り付けまで、早ければ約10分で食卓に出せ、手早く一食を済ませるのに適しています。', '[{"name":"袋入りルオスーフェン","unit":"パック"},{"name":"水","unit":"L"},{"name":"米粉","note":"適量"},{"name":"タニシ肉パック","note":"適量"},{"name":"スープの素パック","note":"適量"},{"name":"酸竹の子パック","note":"適量"},{"name":"ピーナッツパック","note":"適量"},{"name":"湯葉パック","note":"適量"},{"name":"きくらげパック","note":"適量"},{"name":"酢パック","note":"適量"},{"name":"ラー油","note":"適量"}]'::jsonb, '["鍋に水を入れ、沸騰させる。","米粉を入れ、3～5分茹でる。その間、箸で混ぜて米粉がくっつかないようにする。","スープの素パックを入れ、お好みで加える。","一部のトッピングパック（きくらげ、ピーナッツ、タニシなど）を入れる（これらのトッピングは煮込むと味が染みる）。","調味パックを入れ、お好みで加える。","混ぜ合わせてから取り出し、丼に入れる。","残りのトッピングパック（酸竹の子、湯葉など）を入れる（これらのトッピングはスープに長時間浸すとよくない）。","出来上がり。"]'::jsonb, '["主食","酸辣","旨味","時短","広西風味","スープ米線"]'::jsonb),
  ('howtocook:staple/西红柿鸡蛋挂面/西红柿鸡蛋挂面', 'ja', 'トマトと卵の掛け麺', '主食', 'トマトと卵の掛け麺は家庭的な簡単麺料理で、甘酸っぱくて塩辛い、スープが濃厚で麺にコシがある、北方風味を取り入れた日常の主食です。卵は良質なタンパク質を提供し、トマトにはリコピンやビタミンが豊富で、炭水化物の主食と合わせて栄養バランスが良いです。操作は簡単で手順も明確、初心者にも優しく、準備から完成まで約20分です。', '[{"name":"掛け麺","unit":"グラム"},{"name":"トマト","unit":"個"},{"name":"卵","unit":"個"},{"name":"塩","unit":"グラム"},{"name":"ネギ","note":"適量"},{"name":"ニンニク","note":"適量"},{"name":"ピーマン","note":"適量"},{"name":"食用油","unit":"グラム"},{"name":"醤油","unit":"グラム"},{"name":"オイスターソース","unit":"グラム"},{"name":"鶏ガラスープの素","unit":"グラム"},{"name":"白砂糖","unit":"グラム"},{"name":"ごま油","unit":"グラム"},{"name":"白酢","unit":"グラム"},{"name":"水","note":"適量"}]'::jsonb, '["小ネギを洗い、小口切りにする","トマトは一口大に切る。切り方が分からなければ先にネットで調べてね～","ピーマンは菱形に切る","生卵を小さなボウルに割り入れ、溶きほぐす。卵に生臭さがある場合は白酢2gを加えて臭みを取る","鍋を熱し、食用油15～20gを入れる。卵をふんわりと炒めるには多めの油が必要で、同時に後でトマトを炒めるための油を残す","油が七分熱になったら（手のひらを10cmくらい離して熱を感じる程度）、溶き卵を流し入れ、素早くかき混ぜる","卵が固まって液状の部分がなくなったら、小さなボウルに取り出しておく。このとき少し油を残す","鍋に残した油で、まず白ネギの部分とニンニクのみじん切りを炒めて香りを出す","トマトとピーマンを加え、トマトから少し汁が出るまで炒める","ここで素早く醤油5gと白砂糖2gを加える","十数秒炒めたら、水を1カップ加える（トマトがちょうどひたひたになるくらい）","沸騰したら炒めた卵を加え、オイスターソース5g、または鶏ガラスープの素2gを加えて旨味を足す","中弱火で煮詰める。焦げ付きを防ぐため時々混ぜる。写真のように煮詰まったら、残っている青ネギの部分を少々加え、ごま油を加える（なくてもよい）。具の完成","鍋を洗わずに、そのまま水500mlを加える","沸騰したら掛け麺を加え、麺が柔らかくなったら水100mlを加える","再び沸騰したら、麺が浮いてきたらさらに水100mlを加える","沸騰したら麺の両側が透明になっているか確認する。透明なら茹で上がり","麺を具のボウルに移し、混ぜ合わせて出来上がり～"]'::jsonb, '["主食","家庭料理","時短","甘酸っぱい","麺料理","ご飯が進む"]'::jsonb),
  ('howtocook:staple/豆角焖面/豆角焖面', 'ja', '豆角焖面', '主食', '豆角焖面は北方の家庭的な麺料理で、麺がスープを吸い込み、柔らかくもあり歯ごたえもあり、塩味と香ばしさがあり、豆角の清涼感と肉の脂の旨味が調和しています。豚バラ肉はタンパク質と脂質を、豆角は食物繊維とビタミンを提供し、バランスの良い一皿です。全体の手順は難しくありませんが、火加減とスープを加えるタイミングに注意が必要で、ある程度調理経験のある方におすすめです。約30分で完成します。', '[{"name":"生麺","unit":"g"},{"name":"豚バラ肉","unit":"g"},{"name":"豆角","unit":"g"},{"name":"食用油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"薄口醤油","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"オイスターソース","unit":"g"},{"name":"十三香","unit":"g"},{"name":"チキンエキス","unit":"g"},{"name":"味の素","unit":"g"},{"name":"ネギ","unit":"g"},{"name":"生姜","unit":"g"},{"name":"にんにく","unit":"g"},{"name":"熱湯","unit":"ml"}]'::jsonb, '["豆角を5cm～6cmの長さに切る。","ネギを1cm～2cmの小口切りにする。","生姜を1mm×1mm×3cmの細切りにする。","にんにくをまな板の上で潰し、1mmの粗みじん切りにする。","豚バラ肉を2mmの厚さに切る。","まず鍋を熱し、内部の水分を完全に飛ばす。手を鍋底から10cmの位置にかざし、明らかに熱く感じる程度にする。","上記の定量の食用油を加え、鍋の取っ手を持ち、火から5cm離して鍋を揺すり、食用油が鍋の下から3分の2の範囲に均一に行き渡るようにする。","すべての生姜とネギを入れ、香りが立つまで5秒間炒める（注意！油が飛び散る危険があるので、手袋をするか対策を講じること）。","すべての肉を入れ、すぐには返さず5秒間置いてから、すべての肉に油が絡むように炒める。","肉を絶えず炒め、すべての肉の色が変わったら、鍋肌に沿って準備した薄口醤油を均等に回し入れ、よく炒め合わせる。","準備した塩、濃口醤油、オイスターソース、十三香、チキンエキス、およびすべての豆角を順に加え、2分間炒める。","準備した熱湯を加える。","沸騰したら、お玉で鍋の中のスープの半分をすくい出す（注意！具材はすくい出さないこと）。","すべての麺を具材の上に平らに広げる。","蓋をして中火で5分間蒸し煮にする。","蓋を開け、すくい出したスープをお玉で一度に一勺ずつ麺の上に均等にかける。","蓋をして中火で3分間蒸し煮にする。","蓋を開け、すべてのにんにくと味の素を均等に振り入れる。","箸で絶えず混ぜながら、具材と肉を均一に絡める。","火を止める"]'::jsonb, '["主食","北方家常","焖面","塩味と香ばしさ","スピード料理"]'::jsonb),
  ('howtocook:staple/酱拌荞麦面/酱拌荞麦面', 'ja', 'ソース和えそば', '主食', '甘酸っぱくて冷たく滑らかなソース和えそばは、簡単で手早く作れる家庭料理の冷やし和え麺です。そばは食物繊維とタンパク質が豊富で、キュウリとニンジンを加えることで爽やかな食感とビタミンがプラスされ、栄養バランスが良いです。麺を茹で、野菜を切り、ラーガンマーを和えるだけで完成し、初心者にも優しく、約20分でできます。冷蔵庫で冷やしてから食べるとさらに美味しいです。', '[{"name":"そば","unit":"g"},{"name":"きゅうり","unit":"本"},{"name":"にんじん","unit":"本"},{"name":"ラーガンマー","unit":"ml"}]'::jsonb, '["そばを冷水から茹で、8〜10分後に取り出して水気を切っておく","きゅうり、にんじんを細切りにする","そば、きゅうり、にんじんを皿に盛り、ラーガンマーをのせて混ぜる"]'::jsonb, '["主食","冷和え","スピード","家庭料理","甘酸っぱい","辛さ控えめ","さっぱり"]'::jsonb),
  ('howtocook:staple/酸辣蕨根粉', 'ja', '酸辣ワラビ春雨', '主食', '酸辣ワラビ春雨は口当たりが滑らかでコシがあり、酸味と辛みで食欲をそそる家庭的な冷菜です。主食としても楽しめます。ワラビ春雨はデンプンと食物繊維が豊富で、エネルギーを補給できます。この料理は非常に簡単で、初心者にも優しく、準備から完成までたった10分です。', '[{"name":"ワラビ春雨","note":"適量"},{"name":"ラー油","note":"適量"},{"name":"醤油","note":"適量"},{"name":"酢","note":"適量"},{"name":"青唐辛子","note":"適量"},{"name":"ニンニク","note":"適量"},{"name":"ネギ","note":"適量"},{"name":"塩","unit":"g"},{"name":"砂糖","unit":"g"}]'::jsonb, '["鍋に深さの3/5くらいの水を入れ、沸騰させる","沸騰したらワラビ春雨を加え、中弱火で8分茹でる","ザルに取る","割合に従って、醤油、酢、ラー油を加える","箸で少し取って味見をする","もし醤油の味が濃いと感じたら、用意した塩を加える","もしうまみが足りないと感じたら、用意した砂糖を加える","粒状の調味料がほとんど溶けるまでよく混ぜる","ボウルを一つ用意する","先ほど作ったたれを加える","ワラビ春雨を冷水で締めてからたれに入れる","よく和える","用意したネギ、ニンニク、青唐辛子をみじん切りにして上に散らす","完成です(｡･∀･)ﾉﾞ"]'::jsonb, '["主食","酸辣","和え物","時短","家庭料理","食欲増進"]'::jsonb),
  ('howtocook:staple/醪糟小汤圆', 'ja', '酒粕の小団子', '主食', '酒粕の小団子は、甘くて柔らかい伝統的な中国のデザートです。酒粕のほのかな酸味ともち米のなめらかさが溶け合い、心も体も温めてくれます。炭水化物と少量のビタミンB群が豊富で、素早くエネルギーを補給でき、血行促進にも役立ちます。作り方は非常に簡単で、初心者にも優しく、お湯を沸かしてから出来上がりまで約15分。いつでも気軽に作れる家庭的な甘いスープです。', '[{"name":"水","unit":"ml","note":""},{"name":"小さな団子","unit":"g","note":""},{"name":"酒粕","unit":"g","note":""},{"name":"枸杞","unit":"粒","note":""},{"name":"砂糖","unit":"","note":"適量"}]'::jsonb, '["鍋に水を入れ、沸騰させる","小さな団子を入れて8分煮る","酒粕と枸杞を加えてさらに2分煮る","器に盛り、好みに応じて砂糖を加えて混ぜる","食べる"]'::jsonb, '["主食","甘い","柔らかい","煮る","時短","家庭料理"]'::jsonb),
  ('howtocook:staple/陕西油泼面/陕西油泼面', 'ja', '陝西油潑麺', '主食', 'この西北地方の伝統的な麺料理は、コシのある引き麺と熱した油をかける香ばしい辛さが特徴で、陝西省では誰もが知る日常の主食です。麺は炭水化物が豊富で、青菜ともやしを組み合わせることで、手軽にエネルギーを補給でき、栄養バランスも良いです。工程はシンプルで明確、初心者にも優しく、準備から完成まで約30分です。', '[{"name":"生麺（引き麺が最適）","unit":"本"},{"name":"塩","unit":"g"},{"name":"ネギ","unit":"本"},{"name":"ニンニク","unit":"片"},{"name":"乾燥唐辛子粉（秦椒粉）","unit":"g"},{"name":"サラダ油","unit":"ml"},{"name":"薄口醤油","unit":"ml"},{"name":"香酢","unit":"ml"},{"name":"青菜","unit":"g"},{"name":"もやし","unit":"g"},{"name":"花椒","note":"適量"},{"name":"八角","note":"適量"},{"name":"桂皮","note":"適量"},{"name":"ローリエ","note":"適量"},{"name":"ごま","note":"適量"}]'::jsonb, '["引き麺の場合、めん棒（なければ手でも可）で上下を軽く押さえ、両手で左右の端を持ち、ゆっくりと引き伸ばします。","ネギは小口切りに、ニンニクはみじん切りにして用意します。","青菜は洗い、もやしも洗って用意します（使用する場合）。","鍋にたっぷりの水を入れ、強火で沸騰させたら塩1gを加えます。","麺を入れ、箸で軽く混ぜてくっつかないようにし、麺が浮いてきたらさらに1〜2分茹でます。","麺を茹でている最後の1分で、青菜ともやしを加えてさっと茹でます。","茹で上がった麺、青菜、もやしをざるに取り、水気を切って器に入れます。","麺の上に、醤油、香酢、ネギ、ニンニク、乾燥唐辛子粉を順にのせ、お好みでごまも加えます。","フライパンにサラダ油を入れ、花椒、八角、桂皮、ローリエ（使用する場合）も加え、弱火で香りが出るまで加熱したら、香辛料を取り出します。","油の温度が7割熱くなったら（少し煙が出る程度）、素早く均一に器の唐辛子粉にかけ、ジュッという音がすればOKです。","箸で全ての調味料と麺をよく混ぜ合わせてからお召し上がりください。"]'::jsonb, '["主食","陝西","麺類","香辛","時短","家庭料理"]'::jsonb),
  ('howtocook:staple/韩式拌饭/韩式拌饭', 'ja', '韓式ビビンバ', '主食', '韓式ビビンバは、色鮮やかで味わい豊かな韓国の家庭料理です。甘辛いタレがご飯、野菜、牛肉、半熟卵と絡み合い、混ぜて食べると一口で大満足。多様な野菜からビタミンと食物繊維が摂れ、牛肉と卵で良質なタンパク質も補給でき、栄養バランスも抜群。調理は簡単ですが、下準備がやや多いため初心者でも落ち着いて作れます。準備から盛り付けまで約45分かかります。', '[{"name":"ご飯","unit":"椀"},{"name":"卵","unit":"個"},{"name":"牛肉巻き","unit":"巻"},{"name":"もやし","unit":"g"},{"name":"きのこ","unit":"g"},{"name":"にんじん","unit":"本"},{"name":"ズッキーニ","unit":"g"},{"name":"韓式辣醬","unit":"ml"},{"name":"スプライト","unit":"ml"},{"name":"ごま","unit":"g"},{"name":"ごま油","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"塩","note":"適量"}]'::jsonb, '["野菜を洗い、千切りにする。鍋で炒め、柔らかくなったら取り出す。","お湯を沸かし、沸騰したら牛肉の巻きを茹でる。火が通れば十分、約3分で取り出す。","半熟卵を焼く。","ご飯を小皿に盛り、それを大きめの器にひっくり返してのせる。","準備した野菜と牛肉の巻きを順にご飯の上に円を描くように並べ、中央に目玉焼きをのせる。","タレを準備する。","10ml 韓式辣醬（甘辛口）+ 5ml 醤油 + キャップ2つのスプライト（ダイエット中なら無糖スプライトでも可）+ 10g ごま + 5ml ごま油","上記のタレを混ぜる。お好みで醤油と塩を追加してもよい。","準備したタレを盛り付けた器にかける。"]'::jsonb, '["主食","韓式","甘辛","家庭料理","ご飯が進む","混ぜご飯"]'::jsonb),
  ('howtocook:staple/韭菜盒子', 'ja', 'ニラの包み焼き', '主食', 'ニラの包み焼きは伝統的な中華点心で、外側は黄金色でサクサク、中は香ばしくジューシーです。ニラにエビと卵を合わせ、ビタミンと良質なタンパク質が豊富。作り方は簡単で初心者にも優しく、生地作りから完成まで約2.5時間かかります。', '[{"name":"ニラ","unit":"グラム"},{"name":"エビ","unit":"グラム"},{"name":"卵","unit":"個"},{"name":"ごま油","unit":"ml"},{"name":"塩","unit":"グラム"},{"name":"小麦粉","unit":"グラム"}]'::jsonb, '["大きめのボウルに小麦粉を入れ、水を加えて滑らかな生地になるまで混ぜ、30分休ませる。","ニラを洗ってみじん切りにし、溶き卵、塩5gを加えてよく混ぜる。","生地を小さな塊に分け、薄い円形に伸ばし、ニラ、エビ、卵液を包む。","フライパンを熱して油を引き、包んだニラの包み焼きを入れ、両面が黄金色になるまで約3～4分焼く。","皿に盛り、少し冷ましたらできあがり。"]'::jsonb, '["主食","香ばしい","焼き","家庭料理","中華点心"]'::jsonb),
  ('howtocook:staple/鲜肉烧卖', 'ja', '豚肉焼売', '主食', 'これは江南風味の繊細な点心で、皮は紙のように薄く、餡はたっぷりでジューシー。一口噛むと肉の旨味、筍の風味、そして皮凍が溶け出したスープが絡み合い、塩味の中に甘みがあり、柔らかくて弾力のある食感が楽しめます。豚肉とえびは良質なタンパク質を提供し、冬筍としいたけは食物繊維とミネラルを加え、低脂肪バージョンではさらに飽和脂肪を減らしています。包む技術には少し忍耐が必要ですが、全体の手順は明確で、初心者でも練習すれば習得できます。餡を混ぜ始めてから蒸し上がるまで約1時間かかります。', '[{"name":"焼売の皮","unit":"g"},{"name":"豚ひき肉（脂身3:7）","unit":"g"},{"name":"豚ヒレ肉または豚もも肉（低脂肪バージョン）","unit":"g"},{"name":"生姜みじん切り","unit":"g"},{"name":"ネギみじん切り（青い部分のみ）","unit":"g"},{"name":"薄口醤油","unit":"mL"},{"name":"料理酒","unit":"mL"},{"name":"塩","unit":"g"},{"name":"砂糖（お好みで）","unit":"g"},{"name":"白こしょう（お好みで）","unit":"g"},{"name":"ごま油","unit":"mL"},{"name":"スープ","unit":"mL"},{"name":"コンソメキューブ","unit":"g"},{"name":"冬筍（お好みで）","unit":"g"},{"name":"皮凍（お好みだが推奨）","unit":"g"},{"name":"しいたけ（お好みで）","unit":"g"},{"name":"干ししいたけ（戻したもの、お好みで）","unit":"g"},{"name":"えび（お好みで）","unit":"g"},{"name":"複合食品増粘剤（低脂肪バージョン）","unit":"g"},{"name":"コーンスターチ（低脂肪バージョン）","unit":"g"},{"name":"ラード（またはチキンオイル）（低脂肪バージョン）","unit":"g"}]'::jsonb, '["（低脂肪バージョン）冷水10mLを取り、複合食品増粘剤を加え、ペースト状に混ぜる","（低脂肪バージョン）熱湯25mLを加え、半透明のゲル状になるまで混ぜる","（低脂肪バージョン）冷めたら、純粋な赤身ひき肉280gと溶かしたラード（またはチキンオイル）15gを混ぜ込む","豚ひき肉に生姜みじん切り、ネギみじん切りを混ぜ、醤油、料理酒、塩、砂糖、白こしょうを加え、一方向に混ぜて粘りを出す","コンソメキューブを使用する場合は、キューブを15mLの熱湯に加えて混ぜ、乳濁液が完全に分散するまで攪拌し、さらに常温水15mLを加える","水またはスープを少しずつ加え、餡が水分を吸収してとろみがつくまで混ぜ続ける。もし餡が固すぎると感じたら、水5mLを追加してさらに混ぜる","お好みで（冬筍、皮凍、しいたけ）を加え、最後にごま油を回し入れ、よく混ぜる。冷蔵庫で30分冷やし、味をなじませる","焼売の皮を1枚取り、約20-25gの餡をのせる（欲張りすぎると包めないので注意）","親指と人差し指の付け根で皮の縁を軽く寄せて、花瓶のような形にし、上部を開けたままにする","指で底を軽く押さえて、安定して立つようにする","えびを加える場合は、トップにえびを1個のせる","焼売を包む手順を繰り返し、すべて包み終える","蒸し器に並べ、間隔を空けてくっつかないようにする","強火で8〜10分蒸せば完成"]'::jsonb, '["主食","江南風味","塩味と旨味","蒸し","おもてなし点心","薄皮で餡たっぷり","低脂肪バージョン対応"]'::jsonb),
  ('howtocook:staple/鲣鱼海苔玉米饭/鲣鱼海苔玉米饭', 'ja', 'かつお節と海苔のコーンピラフ', '主食', 'これは風味豊かな和風の簡単ご飯です。ご飯は一粒一粒がはっきりしており、かつお節の塩気、海苔の香ばしさ、コーンの甘さと歯ごたえが絶妙に調和します。かつお節は良質なタンパク質とDHAが豊富で、海苔のミネラル、コーンの食物繊維と組み合わせて栄養バランスも抜群。作り方はとてもシンプルで、初心者でも簡単にできます。実際の作業はわずか5分、ご飯を炊く時間を含めても約40分で楽しめます。', '[{"name":"ご飯","note":"適量"},{"name":"コーン","unit":"g"},{"name":"かつお節と海苔のふりかけ","unit":"g"}]'::jsonb, '["ご飯をよそい、コーンを混ぜ合わせる","かつお節と海苔のふりかけをのせる"]'::jsonb, '["主食","和風","時短","風味豊か","家庭料理","簡単"]'::jsonb),
  ('howtocook:staple/鹰嘴豆炸饼', 'ja', 'ひよこ豆の揚げパン', '主食', 'ひよこ豆カレーに揚げパンを添えた北インドの定番ストリートフード。ふんわりとした揚げパンとスパイスが効いたひよこ豆が絶妙にマッチし、酸味・辛味・塩味が豊かな味わいです。ひよこ豆は植物性たんぱく質と食物繊維が豊富で、食べ応えがあり栄養満点。工程はやや多めですが、手順通りに進めれば難しくありません。料理初心者から中級者向け。約50分で完成（ひよこ豆は8時間以上水に浸しておく必要あり）。', '[{"name":"乾燥ひよこ豆","unit":"g"},{"name":"玉ねぎ","unit":"個"},{"name":"トマト","unit":"個"},{"name":"生姜","unit":"g"},{"name":"ニンニク","unit":"片"},{"name":"青唐辛子","unit":"本"},{"name":"食用油（カレー炒め用）","unit":"ml"},{"name":"紅茶のティーバッグ（ひよこ豆の色付け用）","unit":"個"},{"name":"ターメリックパウダー","unit":"g"},{"name":"パプリカパウダー","unit":"g"},{"name":"コリアンダーパウダー","unit":"g"},{"name":"クミンパウダー","unit":"g"},{"name":"塩（カレー用）","unit":"g"},{"name":"ガラムマサラ","unit":"g"},{"name":"ザクロパウダー","unit":"g"},{"name":"レモン汁","unit":"ml"},{"name":"水","unit":"ml"},{"name":"中力粉","unit":"g"},{"name":"ヨーグルト","unit":"ml"},{"name":"食用油（生地練り用）","unit":"ml"},{"name":"重曹","unit":"g"},{"name":"塩（生地用）","unit":"g"},{"name":"ぬるま湯","unit":"ml"},{"name":"食用油（揚げ用）","unit":"ml"},{"name":"パクチー","note":"適量"},{"name":"レモンくし切り","note":"適量"}]'::jsonb, '["乾燥ひよこ豆を水に一晩（最低8時間）浸す。浸すと体積が約2倍になる。","浸したひよこ豆の水を切る。","鍋に入れ、500mlの水と紅茶のティーバッグ1個（色付け用）を加える。","強火で沸騰させたら中火にし、25～30分煮る。指で簡単につぶせるまで。","紅茶のティーバッグを取り出し、煮汁は取っておく。","フライパンに食用油30mlを入れ、中火で熱する。","みじん切りにした玉ねぎを加え、きつね色になるまで炒める（約6～8分）。","すりおろした生姜とニンニクを加え、1分炒める。","みじん切りにしたトマトを加え、完全に柔らかくなり油が浮くまで炒める（約5分）。","ターメリックパウダー3g、パプリカパウダー5g、コリアンダーパウダー8g、クミンパウダー5g、塩6gを加える。","2分炒め、スパイスの香りを引き出す。","煮たひよこ豆を煮汁ごと鍋に加える。","青唐辛子を加え、よく混ぜる。","強火で沸騰させたら弱火にし、15～20分煮込む。途中、へらの背でひよこ豆を少しつぶしてとろみをつける。","ガラムマサラ5gとザクロパウダー3g（またはレモン汁15ml）を加える。","よく混ぜて火を止め、取っておく。","ボウルに中力粉250g、重曹2g、塩3gを入れて混ぜる。","ヨーグルト60mlと食用油15mlを加える。","ぬるま湯を少しずつ加えながらこね、なめらかで柔らかい生地にする（通常の生地よりやや柔らかめ）。","濡れ布巾をかぶせ、30分休ませる。","生地を8等分に分割する。","1つを取り、手に油を少々つけて直径約15cm、厚さ約3mmの円形に伸ばす。","深鍋に食用油500mlを入れ、中強火で180°Cに熱する。","生地をそっと油に入れ、お玉で軽く押さえて膨らませる。","1～2分揚げ、裏返して両面がきつね色になるまで揚げる。","取り出し、キッチンペーパーで余分な油を切る。","ひよこ豆カレーを再加熱する。","揚げパンは熱いうちに、ひよこ豆カレーと一緒に盛り付ける。","スライスした玉ねぎ、青唐辛子、レモンくし切りを添えてもよい。"]'::jsonb, '["主食","北インド","ストリートフード","酸味・辛味・塩味・風味","揚げ物","食べ応え"]'::jsonb),
  ('howtocook:staple/麻油拌面', 'ja', 'ごま油和え麺', '主食', 'ごま油の香りが豊かで、老抽（濃口しょうゆ）と黒コショウでシンプルに味付けした、塩味と香ばしさが食欲をそそる、節約にもなる家庭的な和え麺です。麺は炭水化物が豊富で、ごま油には不飽和脂肪酸やビタミンEが含まれ、エネルギー補給に役立ちます。調理はとても簡単で、キッチン初心者でも楽々。お湯を沸かしてから和えるまで約10分で完成します。', '[{"name":"水","unit":"リットル"},{"name":"即席麺","unit":"ブロック"},{"name":"ごま油","unit":"ミリリットル"},{"name":"老抽（濃口しょうゆ）","unit":"グラム"},{"name":"塩","unit":"グラム"},{"name":"黒コショウ","unit":"グラム"},{"name":"生抽（薄口しょうゆ）","unit":"グラム"}]'::jsonb, '["鍋に水を入れて沸騰させる（もちもちした麺が好きな人は、水に30グラムの塩を加えると、塩水で茹でた麺がもちもちになります）","即席麺を鍋に入れて3分茹でる（使用するブランドの推奨調理時間を参考にしても可）","麺がほぐれ始めたら混ぜ始め、均等に熱が通るようにする","水を切って麺をボウルに移す","上記の分量に従って、ごま油、老抽、黒コショウ、生抽（薄口しょうゆ）（お好みで）を加える","箸でよく混ぜる","簡単で節約にもなる、ずぼらなごま油和え麺の完成です"]'::jsonb, '["主食","塩味・香ばしい","和え","時短","家庭料理"]'::jsonb),
  ('howtocook:staple/麻辣减脂荞麦面', 'ja', 'マーラーダイエットそば', '主食', 'マーラーのスープは火鍋の素とピーナッツバター、牛乳を合わせたもので、濃厚でまろやか、はっきりとしたマーラーの風味があります。食物繊維豊富なそばと新鮮野菜を組み合わせ、低カロリーで満腹感があり、ダイエット中に最適です。作り方はとても簡単で、料理の基礎知識は不要、全体で約20分で鍋ごと食べられます。', '[{"name":"半干しそば","unit":"グラム"},{"name":"ベビー白菜","unit":"枚"},{"name":"レタス","unit":"枚"},{"name":"ピーナッツバター","unit":"グラム"},{"name":"全脂牛乳","unit":"ml"},{"name":"薄口醤油","unit":"ml"},{"name":"ラー油","unit":"ml"},{"name":"酢","unit":"ml"},{"name":"花椒油","unit":"ml"},{"name":"水","unit":"ml"}]'::jsonb, '["ベビー白菜とレタスを洗って、準備しておく","鍋に500mlの水を入れ、強火にかけ、そばとベビー白菜を入れ、沸騰するまで待つ","沸騰したら弱火にし、火鍋の素、ピーナッツバター、牛乳、醤油、ラー油を加え、再度沸騰したら5分煮る","レタスを加え、さらに2分煮る","酢と花椒油を加え、火を止め、そのまま鍋ごと食べる。"]'::jsonb, '["主食","マーラー","旨味","時短","ダイエット","低カロリー","茹でそば"]'::jsonb),
  ('howtocook:vegetable_dish/上汤娃娃菜/上汤娃娃菜', 'ja', '上湯ベビー白菜', '野菜料理', 'この上湯ベビー白菜は、清らかな甘さと旨味があり、食感は柔らかく、家庭的な野菜料理です。特にダイエット中に適しています。ベビー白菜はビタミンと食物繊維が豊富で、低脂肪・低カロリー。ピータンとランチョンミートを加えることで風味が増し、負担も少なく済みます。調理難易度は中程度で、初心者でも挑戦でき、準備から出来上がりまで約20分です。', '[{"name":"ベビー白菜","unit":"g"},{"name":"えのき茸","unit":"g"},{"name":"ピータン","unit":"個"},{"name":"ランチョンミート（ハム）","note":"適量"},{"name":"ネギ","unit":"g"},{"name":"ショウガ","unit":"g"},{"name":"ニンニク","unit":"g"},{"name":"塩","note":"適量"},{"name":"砂糖","note":"適量"},{"name":"片栗粉","note":"適量"}]'::jsonb, '["ベビー白菜を洗い、縦に切ってから、さらに食べやすい大きさに切る。","ネギ3gを小口切りにする。ニンニク10gを薄切りにする。ショウガ10gを薄切りにする。","ピータンをさいの目切りに、ハムまたはランチョンミートを1cm角のさいの目切りにする。","えのき茸を洗い、ほぐす。","お湯を沸かし、ベビー白菜を10秒ほど入れて軽く湯通しし、取り出す。","鍋を熱して油を入れ、一度全体になじませてから油を捨て、新しく油を少量加える。","弱火にしてネギ、ショウガ、ニンニクを加え、香りが立つまで炒める。","水300g（ベビー白菜が浸る程度）を加え、ベビー白菜、えのき茸、ランチョンミートを入れる。","調味料（オイスターソース、砂糖、塩、味の素）を加えて沸騰させる。","3分煮る。沸騰したら盛り付けをする。ベビー白菜を取り出して、その上にピータンをのせ、スープをかける。これで完成。","上湯ベビー白菜"]'::jsonb, '["野菜料理","あっさり","家庭料理","時短","煮込み","低脂肪","旨味"]'::jsonb),
  ('howtocook:vegetable_dish/乾隆白菜/乾隆白菜', 'ja', '乾隆白菜', '野菜料理', '乾隆白菜は、北京風の定番サラダです。手でちぎった白菜の芯に濃厚なゴマだれを和え、甘酸っぱくてシャキシャキ、コクがあって食欲をそそります。白菜はビタミンと食物繊維が豊富で、ゴマだれは良質な脂質とカルシウムをプラス。さっぱりしていて栄養満点です。炒めたり煮たりする必要はなく、タレを混ぜるだけなので初心者にも優しく、10分ほどで食卓に出せます。', '[{"name":"白菜の柔らかい葉","unit":"g"},{"name":"ゴマだれ","unit":"g"},{"name":"黒酢","unit":"ml"},{"name":"砂糖","unit":"g"},{"name":"ごま油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"白いりごま","unit":"g"}]'::jsonb, '["白菜は内側の柔らかい葉（黄色い部分）だけを使い、葉元（白い部分）を取り除く。手で半手のひら大にちぎる（包丁で切らないこと。ちぎった断面が粗い方がタレが絡みやすい）。","ちぎった白菜の葉をよく洗い、水気をしっかり切る。水分が残っているとタレが絡まない。","ボウルにゴマだれ30gを入れ、まず黒酢45mlを加え、同じ方向に混ぜてゴマだれを少しずつ伸ばす。糸状に落ちるくらいになるまで混ぜる（絶対に行ったり来たり混ぜないこと。ゴマだれが油分離する）。","ゴマだれに砂糖5gを加えて混ぜ、さらに塩1gを加えて混ぜ、最後にごま油5mlを加えて混ぜる（各調味料は少しずつ加え、その都度混ぜ、濃度を確認しながら調整する）。","調製したゴマだれを白菜の葉に均等にかけ、手で軽く和え、すべての葉にタレが絡むようにする。","白いりごまをふりかけて盛り付け、そのまま食べられる。時間があれば5分ほど置いて味をなじませてから食べるとより美味しい。"]'::jsonb, '["精進料理","北京風","甘酸っぱい","サラダ","食欲をそそる","時短","家庭料理"]'::jsonb),
  ('howtocook:vegetable_dish/凉拌木耳/凉拌木耳', 'ja', '木耳の和え物', '野菜料理', '木耳の和え物は、配給物資に乾物が多いため、木耳は健康的な食材です。また、調理法も比較的簡単です。', '[{"name":"乾燥木耳","unit":"グラム"},{"name":"生木耳","unit":"グラム"},{"name":"にんにく","unit":"個"},{"name":"唐辛子","unit":"個"},{"name":"塩","unit":"グラム"},{"name":"砂糖","unit":"グラム"},{"name":"醤油","unit":"ml"},{"name":"酢","unit":"ml"},{"name":"ごま油","unit":"ml"},{"name":"わさび","unit":"cm"}]'::jsonb, '["乾燥木耳を戻します。水は約400ml、時間は約45分です。（生木耳の場合はこの手順を省略）","戻した木耳の根元を取ります（図4,5,6参照）。そしてしっかり洗います。","鍋に水を入れて沸騰させ、木耳を入れ、強火で1.5～2分茹でます。","にんにく、唐辛子をみじん切りにしてボウル（中～大）に入れ、塩、砂糖、醤油、酢、ごま油、わさびを上記の分量で順に加えます。","木耳を茹で上がったら水気を切り、前の手順のボウルに入れます。","よく混ぜて、器に盛り付けます。"]'::jsonb, '["野菜料理","和え物","時短","酸辣","食欲増進","家庭料理"]'::jsonb),
  ('howtocook:vegetable_dish/凉拌油麦菜', 'ja', '油麦菜の和え物', '野菜料理', 'さっぱりとして脂っこさを取る、家庭的な冷菜です。ごまペーストの濃厚さが油麦菜のシャキシャキ感を包み込み、甘酸っぱさと塩気、香りが絶妙に絡み合い、食欲をそそります。油麦菜はビタミンと食物繊維が豊富で、ごまペーストはカルシウムと健康的な脂質を補い、栄養バランスも良好。作り方は超簡単で、切って和えるだけ。準備から食卓までたった10数分で、初心者や忙しい時のスピードおかずにぴったりです。', '[{"name":"油麦菜","unit":"株"},{"name":"酢","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"ごまペースト","unit":"ml"},{"name":"ごま油","unit":"ml"},{"name":"砂糖","unit":"g"},{"name":"オイスターソース","unit":"ml"},{"name":"ニンニク","unit":"頭"},{"name":"塩","note":"適量"}]'::jsonb, '["ニンニクを潰してみじん切りにする","酢、醤油、ごまペースト、ごま油、砂糖、オイスターソース、ニンニクのみじん切りをボウルに入れてよく混ぜる","油麦菜を4cm以下の長さに切る","油麦菜を大きめのボウルに入れ、上記のタレを加えてよく和える"]'::jsonb, '["野菜料理","さっぱり","和え物","時短","家庭料理","食欲増進"]'::jsonb),
  ('howtocook:vegetable_dish/凉拌莴笋/凉拌莴笋', 'ja', '莴笋の和え物', '野菜料理', 'シャキシャキとした食感が楽しい家常の冷菜です。莴笋を塩漬けにすることで一層歯ごたえが良くなり、ほのかな辛みが食欲をそそります。ビタミンと食物繊維が豊富でカロリーも低め。作り方も簡単で初心者にも優しく、材料準備から完成まで約20分。冷やすとさらに風味が増します。', '[{"name":"莴笋","unit":"本"},{"name":"大根","unit":"本"},{"name":"唐辛子","unit":"本"},{"name":"生姜","unit":"片"},{"name":"にんにく","unit":"かけ"},{"name":"塩","unit":"g"},{"name":"食用油","unit":"ml"}]'::jsonb, '["莴笋の皮をむき、細切りにする。大根も細切りにして、一緒にボウルに入れ、塩を加えて混ぜ、10分置く。","置いた莴笋を水で1～2回洗う。","鍋に水を沸かし、莴笋を入れて1分茹で、取り出して水気を切り、ボウルに入れる。","鍋に油を熱し、生姜の薄切り、にんにく、唐辛子を30～45秒炒め、莴笋の上にかける。","よく混ぜて、皿に盛る。"]'::jsonb, '["野菜料理","さっぱり","ピリ辛","和え物","時短","家庭料理","食欲増進"]'::jsonb),
  ('howtocook:vegetable_dish/凉拌豆腐', 'ja', '豆腐の和え物', '野菜料理', 'この冷菜はさっぱりとして美味しく、植物性タンパク質とカルシウムが豊富で、低脂肪で健康的です。作り方は簡単で迅速、初心者でもたったの10分で完成します。', '[{"name":"豆腐","unit":"g"},{"name":"小ねぎ","unit":"g"},{"name":"にんにく","unit":"片"},{"name":"醤油","unit":"ml"},{"name":"ごま油","unit":"ml"},{"name":"酢","unit":"ml"},{"name":"砂糖","unit":"g"},{"name":"ラー油","unit":"ml"}]'::jsonb, '["豆腐を2cm角の小さな塊に切り、準備しておく。","鍋に飲用水500mlを入れ、強火で沸騰させる。","豆腐の塊を入れ、1〜2分茹でる。これにより豆腐の生臭さを取り除き、食感を引き締める。","茹で上がった豆腐の塊を取り出し、水気を切って、ボウルに入れ、準備しておく。","小ねぎを洗い、小口切りにして、準備しておく。","にんにくの皮をむき、みじん切りにして、準備しておく。","清潔な小さなボウルに、醤油15ml、ごま油5ml、酢5ml（お好みで）、砂糖2g（お好みで）を加える。","切ったにんにくのみじん切りを加える。","よく混ぜ、砂糖が完全に溶けて、たれが均一になるようにする。","作ったたれを豆腐の塊に均一にかける。","切った小ねぎを散らす。","お好みで、ラー油5mlをかける。","箸やスプーンで軽く混ぜ合わせ、すぐに食べられる。"]'::jsonb, '["野菜料理","さっぱり","時短","和え物","家庭料理","低脂肪"]'::jsonb),
  ('howtocook:vegetable_dish/凉拌金针菇', 'ja', 'エノキの和え物', '野菜料理', 'エノキの和え物は、簡単で素早く作れる家庭的な前菜です。食感はシャキシャキで滑らか、塩味と旨味にほのかな酸味があります。エノキは食物繊維とビタミンが豊富で、低カロリーです。調理は茹でて和えるだけで、初心者にも優しく、忙しい時でもさっと作れます。準備から完成まで約10分です。', '[{"name":"エノキ","unit":"g"},{"name":"青ネギ","unit":"g"},{"name":"ニンニク","unit":"片"},{"name":"醤油","unit":"ml"},{"name":"酢","unit":"ml"},{"name":"砂糖","unit":"g"},{"name":"ごま油","unit":"ml"},{"name":"ラー油","unit":"ml"}]'::jsonb, '["エノキの根元を切り落とし、水でよく洗っておく。","青ネギを洗い、小口切りにしておく。","ニンニクの皮をむき、みじん切りにしておく。","鍋に飲用水1000mlを入れ、強火で沸騰させる。","エノキを入れ、1〜2分煮て柔らかくなるまで。","茹で上がったエノキを取り出し、水気を切って大きめのボウルに入れておく。","別の清潔な小鉢に、醤油15ml、酢10ml、砂糖3g（お好みで）、ごま油5ml（お好みで）を入れる。","刻んだニンニクを加える。","よく混ぜて砂糖を完全に溶かし、タレを均一にする。","作ったタレをエノキの上に均等にかける。","刻んだ青ネギを散らす。","お好みでラー油5mlをかける。","箸で軽く混ぜ合わせて、できあがり。"]'::jsonb, '["野菜料理","和え物","家庭料理","時短","食欲増進","さっぱり","塩味・うま味"]'::jsonb),
  ('howtocook:vegetable_dish/凉拌黄瓜', 'ja', 'キュウリの和え物', '野菜料理', 'これはさっぱりとした食欲をそそる家庭的な冷菜で、歯触りがシャキシャキして、酸味と香りが良いです。キュウリは水分とビタミンが豊富で、熱を冷まし、美肌効果があります。作り方はとても簡単で、初めての方にもおすすめです。キュウリを潰して、調味料で和え、15分間漬けるだけで、全体で約20分で完成します。', '[{"name":"キュウリ","unit":"グラム"},{"name":"酢"},{"name":"醤油"},{"name":"ニンニク","unit":"片"},{"name":"砂糖","unit":"グラム"},{"name":"塩"},{"name":"オイスターソース","unit":"ml"},{"name":"ごま油"}]'::jsonb, '["包丁でキュウリを潰し、3cmの長さに切る","切ったキュウリをボウルに入れる","ニンニクを潰してみじん切りにする","ボウルに砂糖5gを加えて混ぜ合わせ、15分間漬ける（砂糖で漬けると美味しく、色も良くてしおれない）","酢、醤油、塩、オイスターソース、ニンニクの順にボウルに加えてよく混ぜる","ごま油を加えて均一に混ぜる"]'::jsonb, '["野菜料理","さっぱり","和え物","時短","家庭料理","食欲増進"]'::jsonb),
  ('howtocook:vegetable_dish/包菜炒鸡蛋粉丝/包菜炒鸡蛋粉丝', 'ja', 'キャベツの卵炒め春雨添え', '野菜料理', 'キャベツの卵炒め春雨添えは、塩味で美味しい家庭料理のスピードメニューです。甘くてシャキシャキのキャベツと柔らかくて歯ごたえのある春雨、なめらかな卵が絶妙に絡み合い、食感のハーモニーが楽しめます。キャベツはビタミンと食物繊維が豊富で、卵は良質なタンパク質を提供し、人参が栄養をプラス。野菜と肉のバランスが良い一品です。春雨は事前に水で戻す必要があり、全体的な工程は少し多いですが、操作は複雑ではありません。初心者には少し挑戦的かもしれません。準備から盛り付けまで、約1時間20分かかります。', '[{"name":"キャベツ","unit":"玉"},{"name":"卵","unit":"個"},{"name":"春雨","unit":"束"},{"name":"人参","unit":"本"},{"name":"菜種油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"醤油","unit":"ml"},{"name":"老抽","unit":"ml"},{"name":"オイスターソース","unit":"ml"},{"name":"ネギ","unit":"本"},{"name":"ニンニク","unit":"片"},{"name":"乾燥唐辛子","unit":"本"}]'::jsonb, '["人参とキャベツを千切りにする","春雨を冷水に1時間浸し、その後鍋に入れて熱湯で柔らかくなるまで茹で、水気を切っておく","卵をボウルに割り入れ、塩を加えて15秒かき混ぜる","ネギ、ニンニク、唐辛子をみじん切りにする","フライパンに油を熱し、卵を入れてほぐしながら炒め、取り出す","再び油を入れ、ネギ、ニンニク、乾燥唐辛子を8秒炒める","人参とキャベツの千切りを加えて30秒炒める","春雨を加える","調味料を加える：醤油15ml、老抽10ml、オイスターソース10ml、塩2g","先に炒めた卵を戻し入れ、約15秒炒める","火を止めて盛り付ける"]'::jsonb, '["野菜料理","塩味","強火炒め","家庭料理","ご飯が進む","スピード料理"]'::jsonb),
  ('howtocook:vegetable_dish/印度土豆花菜', 'ja', 'インド風ジャガイモとカリフラワーの炒め物', '野菜料理', 'このインド風家庭料理のベジタリアン炒め物は、乾煎りで香ばしく黄金色に仕上がり、スパイスが豊かです。ジャガイモはほくほく、カリフラワーは焦げ目がついて、北インド風の味わいです。ジャガイモとカリフラワーには食物繊維とビタミンCが豊富で栄養バランスが良いです。作り方は簡単で初心者にも優しく、準備から完成まで約25分です。', '[{"name":"ジャガイモ","unit":"個"},{"name":"カリフラワー","unit":"個"},{"name":"玉ねぎ","unit":"個"},{"name":"トマト","unit":"個"},{"name":"生姜","unit":"g"},{"name":"ニンニク","unit":"片"},{"name":"青唐辛子","unit":"本"},{"name":"パクチー","unit":"g"},{"name":"サラダ油","unit":"ml"},{"name":"クミンシード","unit":"g"},{"name":"ターメリックパウダー","unit":"g"},{"name":"レッドチリパウダー","unit":"g"},{"name":"コリアンダーパウダー","unit":"g"},{"name":"ガラムマサラ","unit":"g"},{"name":"塩","unit":"g"}]'::jsonb, '["ジャガイモの皮をむき、約2cmの角切りにする","カリフラワーを均等な小房に分け、大きいものは包丁で切る","フライパンにサラダ油30mlを入れ、中火で熱する","油が熱くなったらクミンシード3gを加え、色が濃くなり香りが立つまで炒める（約10秒、焦がさないように注意）","みじん切りにした玉ねぎを加え、透き通り薄黄色になるまで炒める（約3～4分）","生姜、ニンニク、青唐辛子を加え、1分炒める","みじん切りにしたトマトを加え、柔らかくなるまで炒める（約2～3分）","ターメリックパウダー3g、レッドチリパウダー3g、コリアンダーパウダー5g、塩5gを加える","1分炒めて、スパイスと野菜をなじませる","ジャガイモの角切りを加え、2分炒めて表面にスパイスを絡める","カリフラワーの小房を加え、優しく混ぜ合わせる","蓋をして中弱火にし、12～15分蒸し焼きにする。途中3～4分おきに蓋を開けて混ぜ、焦げ付きを防ぐ","ジャガイモが箸で簡単に刺さるくらい柔らかくなり、カリフラワーに軽く焦げ目がついたら、ガラムマサラ3gを振り入れる","1分炒める","火を止め、パクチーの葉を散らして盛り付ける"]'::jsonb, '["ベジタリアン料理","北インド","スパイシー","蒸し炒め","家庭料理","ご飯が進む"]'::jsonb),
  ('howtocook:vegetable_dish/印度葫芦丸子', 'ja', 'インド風ひょうたん団子', '野菜料理', '北インドのベジタリアン料理。ひょうたんを細切りにし、ひよこ豆粉と混ぜて団子にし、揚げた後、トマトと玉ねぎのカレーに浸します。外はカリッと中はふんわり、スパイシーで濃厚なソースが絡みます。ひょうたんのさっぱり感とひよこ豆粉の植物性たんぱく質・食物繊維がバランスよく、満足感のある一品。揚げてソースを作る工程は少し多めですが、順を追えば難しくありません。全行程約40分。', '[{"name":"ひょうたん","unit":"本","note":""},{"name":"ひよこ豆粉","unit":"g","note":""},{"name":"塩","unit":"g","note":""},{"name":"赤唐辛子粉","unit":"g","note":""},{"name":"コリアンダーパウダー","unit":"g","note":""},{"name":"食用油","unit":"ml","note":"揚げ用"},{"name":"玉ねぎ","unit":"個","note":""},{"name":"トマト","unit":"個","note":""},{"name":"生姜","unit":"g","note":""},{"name":"ニンニク","unit":"かけ","note":""},{"name":"青唐辛子","unit":"本","note":""},{"name":"食用油","unit":"ml","note":"ソース用"},{"name":"ターメリックパウダー","unit":"g","note":""},{"name":"赤唐辛子粉","unit":"g","note":""},{"name":"コリアンダーパウダー","unit":"g","note":""},{"name":"クミンパウダー","unit":"g","note":""},{"name":"ガラムマサラ","unit":"g","note":""},{"name":"塩","unit":"g","note":""},{"name":"水","unit":"ml","note":""},{"name":"パクチー","unit":"g","note":""}]'::jsonb, '["ひょうたんの皮をむき、スライサーで細切りにする","ひょうたんの細切りを手でしっかり絞って水気を切る（絞り切らないと団子がまとまらない）","水気を切ったひょうたんに、ひよこ豆粉80g、塩3g、赤唐辛子粉3g、コリアンダーパウダー3gを加える","手でよく混ぜ合わせ、手に付かない生地状にする","直径約3cmの小さな団子に丸めて、おく","深鍋にサラダ油500mlを入れ、中火で約170℃に熱する（生地をひとつ入れるとすぐに浮き上がり、泡が出る程度）","団子を数回に分けて入れ、表面がきつね色になるまで4～5分揚げる","揚げた団子はキッチンペーパーで余分な油を吸い取り、おく","フライパンにサラダ油30mlを入れ、中火で10秒熱する","みじん切りにした玉ねぎを加え、こげ茶色になるまで炒める（約5～7分）","すりおろした生姜とニンニクを加え、香りが立つまで1分炒める","みじん切りにしたトマトを加え、トマトが完全にやわらかくなり油が分離するまで炒める（約5分）","ターメリックパウダー3g、赤唐辛子粉5g、コリアンダーパウダー5g、クミンパウダー3g、塩5gを加える","2分炒めて、スパイスとトマトをよく混ぜ合わせる","水200mlを加えて混ぜ、沸騰したら弱火にして5分煮る","揚げた団子をそっとソースに入れ、弱火で3～5分煮て、団子にソースを吸わせる","ガラムマサラ3gとみじん切りにした青唐辛子をふりかける","火を止め、パクチーの葉を飾って器に盛る"]'::jsonb, '["素菜","北インド","スパイシー","カレー","ベジタリアン","おもてなし"]'::jsonb),
  ('howtocook:vegetable_dish/地三鲜/地三鲜', 'ja', '地三鮮', '野菜料理', '地三鮮は東北地方の定番家庭料理です。茄子はとろり、じゃがいもはほくほく、青唐辛子はシャキッとしていて、醤油ベースのタレがご飯にぴったり。食材の組み合わせでビタミンと食物繊維が豊富に摂れ、じゃがいもが炭水化物エネルギーを補給してくれます。油で揚げて手早く炒める工程があり、少々コツがいりますが、初心者も練習すれば大丈夫。調理時間は約40分です。', '[{"name":"なす","unit":"グラム"},{"name":"じゃがいも","unit":"グラム"},{"name":"青唐辛子","unit":"個"},{"name":"ネギ","unit":"グラム"},{"name":"ショウガ","unit":"グラム"},{"name":"ニンニク","unit":"グラム"},{"name":"トウバンジャン","unit":"ml"},{"name":"薄口醤油","unit":"ml"},{"name":"砂糖","unit":"グラム"},{"name":"片栗粉","unit":"グラム"}]'::jsonb, '["じゃがいも、茄子、青唐辛子を洗う。","じゃがいもの皮をむく。","茄子とじゃがいもをそれぞれ15g程度の一口大の乱切りにする。","青唐辛子は手で筋に沿って裂き、じゃがいもや茄子より25%ほど大きめに裂く。","青唐辛子の表面の水分をできるだけ拭き取り、揚げる際にはねるのを防ぐ。キッチンペーパーで拭くか、30分ほど乾かす。","ネギは0.5cm幅の小口切りにし、5g用意する。ニンニクはみじん切りにして15g（7.5gずつ2つに分ける）。ショウガはみじん切りにして5g。","ボウルに薄口醤油10ml、砂糖10g、片栗粉8g、水80mlを入れ、よく混ぜ合わせてタレを作り、置いておく。","フライパンを熱し、油150mlを入れる。","じゃがいもを加え、きつね色になり、箸がすっと通るまで約3～4分揚げ焼きにする。","じゃがいもを取り出し、油は残しておく。","茄子を加え、柔らかくなり、縁が少し焼けて油が浮き出てくるまで、約2～3分（7割ほど火が通るまで）揚げ焼きにする。","茄子を取り出し、油は残しておく（油がなくなっている場合もある）。","フライパンに油が足りないようなら、15ml追加する。","青唐辛子を加え、約15秒揚げ焼きにし、縁が少ししわっぽくなったらすぐに取り出す。フライパンの油を捨てる。","フライパンを再度熱し、新しくサラダ油15mlを加える。","ネギ5g、ショウガ5g、ニンニク7.5gを入れ、中弱火で香りを出す。","トウバンジャン15mlを加え、弱火にして赤い油と香りが出るまで炒める。","合わせたタレを注ぎ入れ、すぐに強火にして手早く混ぜ、焦げ付かないようにする。約10秒でとろみがついて泡立ってくる。","すぐに先に揚げたじゃがいも、茄子、青唐辛子をすべて加える。","20秒ほど炒め、濃厚なタレが具材に均等に絡むようにする。","火を止め、残りのニンニク7.5gを振り入れ、さっと混ぜ合わせて器に盛る。"]'::jsonb, '["野菜料理","東北","家庭料理","ご飯が進む","醤香","炒め物"]'::jsonb),
  ('howtocook:vegetable_dish/家常日本豆腐', 'ja', '家庭風玉子豆腐', '野菜料理', '家庭風玉子豆腐は、外はカリッと中はとろける時短料理。黄金色の衣に包まれた滑らかな玉子豆腐に、ピーマンやにんじんなどの野菜を合わせ、塩味または甘酸っぱい味付けに。玉子豆腐は卵が主原料で良質なたんぱく質が豊富、きくらげや野菜も加わり栄養バランスも良い。豆腐を揚げ焼きにするコツが必要だが、初心者でも挑戦しやすく、約30分で完成する。', '[{"name":"玉子豆腐","unit":"g"},{"name":"ピーマン","unit":"g"},{"name":"にんじん","unit":"g"},{"name":"ウインナー","unit":"g"},{"name":"きくらげ","unit":"g"},{"name":"片栗粉","unit":"g"},{"name":"玉ねぎ","unit":"g"},{"name":"ニンニク","unit":"g"},{"name":"油","unit":"ml"},{"name":"薄口醤油","unit":"ml"},{"name":"オイスターソース","unit":"ml"},{"name":"塩","unit":"g"},{"name":"鶏ガラスープの素","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"ケチャップ","unit":"ml"}]'::jsonb, '["にんじんは薄切り、ピーマンは薄切り、ねぎとにんにくはみじん切りにする","玉子豆腐の袋を開けて、厚さ1cmくらいの円柱に切る","片栗粉を平らな皿に広げ、豆腐にまぶす準備をする","豆腐を優しく片栗粉の上に置き、上下と側面に粉をまぶす。厚くなりすぎないように注意","フライパンに油150mlを入れ、豆腐の大部分が浸かる程度にする。縁が黄金色になったら裏返して揚げ焼きにする","両面がきつね色になったら取り出し、清潔な皿に置いておく","鍋に油10-15mlを入れ、ねぎとにんにくを炒めて香りを出し、ピーマン、にんじん、ウインナー、きくらげを加える","オイスターソース、薄口醤油、塩、鶏ガラスープの素、砂糖、ケチャップを加える","色が均一になるまで軽く炒める"]'::jsonb, '["野菜料理","炒め物","塩味","甘酸っぱい","時短","ご飯が進む"]'::jsonb),
  ('howtocook:vegetable_dish/小炒藕丁/小炒藕丁', 'ja', '小炒れんこん', '野菜料理', '小炒れんこんは手早く作れる家庭的な野菜料理です。れんこんはシャキシャキとした食感で、塩味の中にほのかな辛さがあり、ご飯が進みます。れんこんには食物繊維やビタミンが豊富で、体の熱を取り、乾燥を潤す効果があります。作り方は簡単で、れんこんを茹でて味付けするだけなので、料理初心者でも簡単に作れます。全体で約20分で食卓に並べられます。', '[{"name":"長ネギ","unit":"本"},{"name":"唐辛子","unit":"本"},{"name":"れんこん","unit":"節"},{"name":"薄口醤油","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"オイスターソース","unit":"ml"},{"name":"食用油","unit":"ml"}]'::jsonb, '["長ネギと唐辛子を小さく切っておく","れんこんの皮をむき、3cm以下の角切りにし、水にさらしておく（変色防止）","中華鍋に500mlの水を入れ、沸騰させる","れんこんを沸騰したお湯に入れて2分間茹で、取り出して皿に置く","鍋の水を捨て、鍋を加熱して乾かし、10～15mlの食用油を加える","油が熱くなったら、ネギと唐辛子を加えて香りを出す","下処理したれんこんを鍋に入れ、強火で炒める","薄口醤油、濃口醤油、オイスターソースを加える","2分間炒めて火を止める"]'::jsonb, '["野菜料理","塩味","辛さ控えめ","炒め物","家庭料理","ご飯が進む"]'::jsonb),
  ('howtocook:vegetable_dish/干锅花菜/干锅花菜', 'ja', '干鍋花菜', '野菜料理', '干鍋花菜は湖南風の家庭料理で、食感はシャキッとしていて香ばしく、豚バラ肉の香ばしさが広がり、ほんのりとした辛さがあります。カリフラワーはビタミンCと食物繊維が豊富で、豚バラ肉と組み合わせることでタンパク質とエネルギーを補えます。調理の難易度は中程度で、下茹でした後にしっかり水気を切り、豚バラ肉の脂をしっかり出すことに注意すれば、ある程度経験のある初心者にも適しています。準備から完成まで約40分かかります。', '[{"name":"カリフラワー","unit":"グラム"},{"name":"豚バラ肉","unit":"グラム"},{"name":"唐辛子","unit":"本"},{"name":"薄口醤油","unit":"ml"},{"name":"白砂糖","unit":"グラム"},{"name":"ニンニク","unit":"個"},{"name":"塩","unit":"グラム"},{"name":"油","unit":"ml"}]'::jsonb, '["カリフラワーは房を下にして、薄い塩水に20分浸します。その後、洗って、小刀で小房に分けます。","沸騰したお湯で1分茹で、取り出してすぐに冷水で完全に冷やし、水気を切っておきます。","豚バラ肉は薄切りに、ニンニクの白い部分は切って包丁の背で潰し、赤唐辛子は小口切りにします。","鍋を熱して油を入れ、油が熱くなったら長ネギの白い部分を入れて香りを出します。","豚バラ肉を加え、中火で表面の色が変わるまで炒め、さらに炒めて脂身から油を出します。","赤唐辛子とカリフラワーを加え、軽く炒め合わせます。","薄口醤油10mlを加えます。","さらに白砂糖5gを加え、強火にして1分ほど炒めます。","ニンニクの葉の部分を切り、加えて軽く炒め、火を止めて蓋をして1分蒸らして完成です。"]'::jsonb, '["野菜料理","湖南風","干鍋","家庭料理","ご飯が進む","香ばしい"]'::jsonb),
  ('howtocook:vegetable_dish/手撕包菜/手撕包菜', 'ja', '手撕きキャベツ', '野菜料理', '手撕きキャベツは、酸っぱ辛くてシャキシャキとした食感が魅力の湖南料理の定番です。仕上がりはキャベツが柔らかく味が染み込み、豚バラ肉は香ばしくてしつこくなく、食欲をそそりご飯が進みます。キャベツはビタミンCや食物繊維が豊富で、豚バラ肉と合わせることでたんぱく質やエネルギーも摂取できます。強火で手早く炒める火加減がポイントで、初心者には少々難しいかもしれませんが、手順通りに進めれば成功します。下準備から盛り付けまで約20分です。', '[{"name":"キャベツ","unit":"玉"},{"name":"豚バラ肉","unit":"g"},{"name":"鷹の爪","unit":"本"},{"name":"サラダ油","unit":"ml"},{"name":"料理酒","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"香酢","unit":"ml"},{"name":"鶏がらスープの素","unit":"g"},{"name":"生姜","unit":"片"},{"name":"ニンニク","unit":"粒"},{"name":"ニンニクの芽","unit":"本"},{"name":"塩","unit":"g"}]'::jsonb, '["キャベツを半分に切り、白い芯の部分を取り除く【図1参照】","キャベツを手でちぎり、ボウルに塩2gを入れ、キャベツを洗って水気を切り、取っておく【図2参照】","生姜のスライス、ニンニク、鷹の爪、ニンニクの芽を下処理して取っておく【図3参照】","豚バラ肉をスライスし、水で洗って取っておく","鍋にサラダ油30mlを入れ、キャベツを加えて強火で1分炒め、塩3gを加えてさらに2分炒め、取り出す","同じ鍋にサラダ油30mlを入れ、豚バラ肉を加えて強火で1分炒める","生姜などの材料を加えて1分炒める","キャベツを戻し入れ、香酢、料理酒、鶏がらスープの素、料理酒を加え、強火でさらに2分炒めて完成"]'::jsonb, '["野菜料理","酸辣","炒め","湖南料理","ご飯が進む","家庭料理"]'::jsonb),
  ('howtocook:vegetable_dish/拔丝土豆/拔丝土豆', 'ja', '拔絲土豆', '野菜料理', '拔絲土豆は、古典的な魯菜（山東料理）の一品です。出来上がりは黄金色で、細長い糖糸が魅力的。外はカリッと中はもっちり、甘くて美味しい。じゃがいもは炭水化物とビタミンCが豊富で、素早くエネルギー補給ができます。この料理は少し難易度が高く、初心者は砂糖を煮る火加減に注意し、ざらついたり焦げたりしないようにしてください。準備から盛り付けまで約30分の調理時間を見込んでください。', '[{"name":"じゃがいも","unit":"個"},{"name":"食用油","unit":"ml"},{"name":"片栗粉","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"水","unit":"ml"},{"name":"ごま","unit":"g"}]'::jsonb, '["じゃがいもの皮をむき、均等な大きさに切る。片栗粉（水を加えずに）をまぶして、表面を覆うように混ぜる。","鍋に油を熱し、じゃがいもを入れてゆっくり転がしながら5〜7分揚げ焼きにする。箸が通るまで。","じゃがいもを取り出し、大きめのボウルに入れておく。","鍋に水と砂糖を入れ、一方向にゆっくり混ぜながら、砂糖の色が茶色になるまで加熱する。","再びじゃがいもを加え、30秒炒めてから火を止める。","じゃがいもを皿に盛り、ごまを散らす。"]'::jsonb, '["野菜料理","魯菜","飴がけ","甘い","揚げ物","家庭料理"]'::jsonb),
  ('howtocook:vegetable_dish/松仁玉米', 'ja', '松の実とコーン', '野菜料理', '松の実とコーンは、甘くてシャキシャキした食感の家庭料理で、松の実は香ばしく、コーンは甘く、北方の家庭料理として人気があります。コーンと松の実の組み合わせは、食物繊維、不飽和脂肪酸、各種ビタミンを豊富に含み、栄養バランスが良いです。作り方は簡単で、初心者でも手軽に作れ、下準備から出来上がりまで約15分です。', '[{"name":"コーン","unit":"克"},{"name":"炒った松の実","unit":"克"},{"name":"ニンジン","unit":"克"},{"name":"食用油","unit":"ml"},{"name":"砂糖","unit":"克"},{"name":"塩","unit":"克"},{"name":"片栗粉","unit":"克"},{"name":"水","unit":"ml"}]'::jsonb, '["コーンとニンジンの角切りを1分間下茹でした後、ざるにあげて水気を切っておく。","鍋を熱して油を引き、ニンジンの角切りを軽く炒め、コーンを加えて炒める。","砂糖と塩を加えて混ぜ合わせる。","水と片栗粉を混ぜて水溶き片栗粉を作り、鍋に加えて素早く炒め、とろみをつける。","炒った松の実を加えて全体を混ぜ合わせる。","皿に盛り付ける。"]'::jsonb, '["野菜料理","あっさり","時短","家庭料理","北方風味","炒め物"]'::jsonb),
  ('howtocook:vegetable_dish/椒盐玉米/椒盐玉米', 'ja', '花椒塩コーン', '野菜料理', '外はサクサク、中はジューシーで塩気が香ばしい風味豊かなおやつ。四川料理店でよく見られる乾いた香ばしい食感で、噛むとコーンの自然な甘さが広がります。コーンは豊富な炭水化物と食物繊維を提供し、ゴマを加えることで良質な脂質とビタミンEも補えます。手順はやや多いですが操作は簡単で、水気を切って粉をまぶすのに少し根気が必要ですが、初心者にも優しいレシピです。解凍から完成まで約30分かかります。', '[{"name":"コーン（粒）","unit":"g"},{"name":"片栗粉","unit":"g"},{"name":"花椒塩","unit":"g"},{"name":"ゴマ（粒）","unit":"g"},{"name":"油","note":"適量"},{"name":"プラスチックのざる","unit":"個"}]'::jsonb, '["コーンは粒をほぐして、そのまま解凍。ぬるま湯に15分浸すか、コンロで沸騰したお湯で5分茹でます。","ざるを一つ用意し、BoxAとします。キッチンペーパーを敷き、解凍したコーンを入れます。","シャカシャカ振る！ - キッチンペーパーが全部濡れるまで。","二つ目のざるBoxBを用意し、キッチンペーパーを敷き、BoxAのコーンをすべてBoxBに移します。","シャカシャカ振る！ - キッチンペーパーが全部濡れるまで。","コーンの表面に目立った水滴がなく、しっとりした状態になるまで、上記の操作を繰り返します。","たっぷりの片栗粉を加え、コーンが完全に覆われるようにします。","シャカシャカ振る！ - コーンに片栗粉がまぶされるまで。","コンロをつける - 鍋を置く - 油を入れ、鍋底に広がる程度に（多すぎないように）。","油が8割熱くなったら、片栗粉をまぶしたコーンを入れます。","中火で30秒そのまま焼き、混ぜないでください（片栗粉が落ちます）。","軽く混ぜながら3分炒めたら、火を止めます。","最も重要なステップ：3gの花椒塩をふりかけ、ゴマを散らします！","香ばしい「花椒塩コーン」の完成です！"]'::jsonb, '["野菜料理","塩香ばしい","サクサク","四川料理","家庭料理","時短"]'::jsonb),
  ('howtocook:vegetable_dish/榄菜肉末四季豆/榄菜肉末四季豆', 'ja', 'オリーブ菜と挽き肉のいんげん炒め', '野菜料理', 'オリーブ菜と挽き肉のいんげん炒めは、潮汕風味豊かな家庭的な炒め物で、塩辛く香ばしく、シャキシャキとした食感がご飯によく合います。いんげんには食物繊維とビタミンが豊富で、挽き肉と合わせることで良質なタンパク質が摂れ、オリーブ菜が独特の塩辛い風味を加えます。この料理は手順が明確で、初心者でも簡単に作れますが、いんげんは必ず完全に火を通すように注意してください。下ごしらえから完成まで約30分でできます。', '[{"name":"さやいんげん","unit":"グラム"},{"name":"豚バラ肉","unit":"グラム"},{"name":"オリーブ菜","unit":"グラム"},{"name":"ニンニク","unit":"グラム"},{"name":"小唐辛子","unit":"グラム"}]'::jsonb, '["いんげんを洗い、筋を取って、同じくらいの大きさの粒に切る。","ニンニクを包丁で潰して、みじん切りにする。","小唐辛子を同じくらいの大きさの粒に切る。","豚バラ肉の皮を取り除き、挽き肉にする。","鍋を熱し、20mlの油を入れて鍋に馴染ませ、熱い油を捨ててから10mlの冷たい油を加える。これが熱鍋冷油という方法で、挽き肉が鍋にくっつくのを防ぐ。","油差しがない場合は、油を入れたらすぐに挽き肉を加えて炒め始め、弱火で2分ほど炒めて豚の脂を出す。","挽き肉の香りが立ったら、ニンニクのみじん切り、オリーブ菜、小唐辛子を加えて香りを出す。","いんげんを加えて中火で炒める。いんげんは少なくとも5分は炒め、完全に火を通すこと。そうしないと食中毒の恐れがある。","いんげんに火が通ったら、鍋肌から2mlの醤油を回し入れ、2gの塩、1gの鶏がらスープの素、1gのこしょう、0.5gの砂糖を加える。","調味料をよく混ぜ合わせる。","火を止めて、皿に盛る。"]'::jsonb, '["おかず","塩辛い","潮汕風","ご飯が進む","炒め物"]'::jsonb),
  ('howtocook:vegetable_dish/水油焖蔬菜', 'ja', '水油煮野菜', '野菜料理', '水油煮野菜は、手早く作れる簡単な家庭料理です。沸騰したお湯に油と調味料を加えることで、葉野菜は柔らかく、ツヤよく仕上がり、さっぱりとした中にも油の香りが広がります。この調理法は脂溶性ビタミンの吸収率を高め、生のまま食べるよりも栄養価が高まります。初心者にも優しく、洗い菜から出来上がりまで通常10分で完成します。', '[{"name":"葉野菜","unit":"g"},{"name":"食用油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"オイスターソース","unit":"ml"}]'::jsonb, '["野菜を洗う","鍋に水150mlを加え、沸騰させる。（水は野菜を完全に浸す必要はありません）","塩3gを加える","（お好みで）オイスターソース3mlを加える","食用油2mlを加える","野菜を入れ、軽く混ぜ合わせ、蓋をして1分間蒸し煮にする","器に盛る"]'::jsonb, '["野菜料理","あっさり","蒸し煮","手早い","家庭料理"]'::jsonb),
  ('howtocook:vegetable_dish/油醋爆蛋', 'ja', '油酢爆卵', '野菜料理', 'これは湖南風味たっぷりの家庭向け簡単おかずです。酸っぱくて辛くて香ばしく、卵はカリッとふわふわで濃厚なタレが絡み、とても食欲をそそります。卵は良質なタンパク質とレシチンを提供し、香酢と合わせることでさらに食欲を促進します。作り方はとても簡単で初心者にも優しく、準備から完成まで約10分です。', '[{"name":"卵","unit":"個"},{"name":"ミニ唐辛子","unit":"g"},{"name":"食用油","unit":"ml"},{"name":"小ネギ","unit":"g"},{"name":"ニンニク","unit":"g"},{"name":"香酢","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"オイスターソース","unit":"g"},{"name":"砂糖","unit":"g"}]'::jsonb, '["卵は溶かずに、そのまま器に割り入れておく","小ネギは3cmの長さに切る","ニンニクとミニ唐辛子をガーリッククラッシャーに入れ、みじん切りにする","香酢、醤油、オイスターソース、砂糖、水を小さなボウルに入れ、混ぜ合わせて甘酢だれを作る","油を熱し、卵を流し入れる。卵が固まったら大きめに切り分け、ニンニクのみじん切りとミニ唐辛子のみじん切りを加え、甘酢だれを加える","強火で煮詰め、火を止める直前に小ネギを加えて完成"]'::jsonb, '["卵料理","酸辣","時短","ご飯が進む","家庭向け","湖南風味"]'::jsonb),
  ('howtocook:vegetable_dish/洋葱炒鸡蛋/洋葱炒鸡蛋', 'ja', '玉ねぎと卵の炒め物', '野菜料理', '玉ねぎと卵の炒め物は、塩味がきいて香ばしい、ご飯が進む家庭料理です。卵はふんわり、玉ねぎは甘く、国民的なおかずです。卵には良質なタンパク質やビタミンが豊富で、玉ねぎには食物繊維や抗酸化物質が含まれ、栄養バランスの良い時短料理です。調理は非常に簡単で、初心者にも優しく、準備から完成まで約5分です。', '[{"name":"卵","unit":"個"},{"name":"玉ねぎ","unit":"g"},{"name":"食用油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"小ネギ","unit":"本"},{"name":"料理酒","unit":"ml"}]'::jsonb, '["卵を大きめのボウルに割り入れ、玉ねぎの薄切り、塩を加えて60秒混ぜる。","フライパンに油を熱し、卵液を流し入れる。片面を30-45秒焼き、裏返してさらに炒める。これを繰り返し2〜3分後、料理酒を振りかけて火から下ろす。","卵を皿に盛り、刻みネギを散らす。"]'::jsonb, '["野菜料理","塩味香ばしい","家庭料理","時短","ご飯のおかず","炒め物"]'::jsonb),
  ('howtocook:vegetable_dish/清炒花菜', 'ja', 'カリフラワーのシンプル炒め', '野菜料理', '一般的な家庭料理の野菜炒めで、食感はシャキシャキとして爽やか。ビタミンCと食物繊維が豊富。作り方は簡単で、初心者でも約15分で完成する。', '[{"name":"カリフラワー","unit":"g","note":""},{"name":"ニンニク","unit":"片","note":""},{"name":"塩","unit":"g","note":""},{"name":"食用油","unit":"ml","note":""},{"name":"飲用水","unit":"ml","note":""}]'::jsonb, '["カリフラワーを洗い、包丁または手で小房に分ける。太い茎の部分は薄切りにして、取っておく。","ニンニクの皮をむき、スライスして取っておく。","鍋に飲用水1000mlを入れ、強火で沸騰させる。","カリフラワーの小房を入れ、2〜3分茹でる。色が薄くなり、少し柔らかくなるまで。","茹でたカリフラワーを取り出し、水気を切って取っておく。","鍋を熱し、食用油15mlを入れ、強火で加熱する。","ニンニクのスライスを入れ、香りが立つまで素早く炒める。","湯通ししたカリフラワーを加え、中強火にして約2分、全体に火が通るように手早く炒める。","塩3gを加え、さらに炒め合わせる。","鍋肌に沿って飲用水50mlを回し入れ、蓋をして1分間蒸し焼きにする。カリフラワーに完全に火が通り、味が染み込むように。","蓋を開け、手早く混ぜ合わせて、完成。"]'::jsonb, '["野菜料理","あっさり","シンプル炒め","家庭料理","時短","ご飯のおかず"]'::jsonb),
  ('howtocook:vegetable_dish/清蒸南瓜', 'ja', '南瓜の蒸し物', '野菜料理', '素材の味を生かした家庭的な蒸し料理です。かぼちゃ本来の甘みと栄養を最大限に引き出し、ほっくりとやわらかな食感が特徴。デザートにも主食にもなります。かぼちゃにはβ-カロテンや食物繊維が豊富で、視力や胃腸の健康に役立ちます。作り方はとても簡単で、初心者でも気軽に作れます。下ごしらえから蒸し上がりまでわずか15〜20分です。', '[{"name":"かぼちゃ","unit":"g"},{"name":"飲用水","unit":"ml"}]'::jsonb, '["かぼちゃの外皮を洗い、わたと種を取り除く。","かぼちゃを厚さ約2cmの切りにし、準備しておく。","蒸し器の鍋に飲用水1000mlを加える。","切ったかぼちゃのスライスを皿に均等に並べる。","蒸し器の水が沸騰したら、かぼちゃをのせた皿を蒸し器に入れる。","蓋をし、強火で15〜20分蒸す。かぼちゃが柔らかくなり、箸がすっと通るようになるまで。","火を止め、慎重に皿を取り出す。"]'::jsonb, '["野菜料理","あっさり","蒸し料理","時短","家庭料理","精進"]'::jsonb),
  ('howtocook:vegetable_dish/炒滑蛋/炒滑蛋', 'ja', 'ふわふわ炒め卵', '野菜料理', 'ふわふわ炒め卵は、口当たりが滑らかで卵の風味が豊かな定番家庭料理です。ほのかなミルクの香りがします。卵には良質なタンパク質や多種のビタミンが豊富で、栄養たっぷりで吸収されやすいです。作り方もとても簡単で、初心者でも気軽に作れます。下ごしらえから完成まで約5分で、忙しい時に手軽にエネルギー補給できる理想的な一品です。', '[{"name":"卵","unit":"個"},{"name":"牛乳","unit":"ml"},{"name":"食用油","unit":"ml"}]'::jsonb, '["卵に牛乳と5mlの食用油を加えてよく混ぜ、取っておきます。","強火でフライパンを約30秒加熱し、5mlの食用油を加えます。","30秒加熱したら弱火にし、混ぜた卵を入れます。","鍋で5秒置いた後、へらで卵液を端から中央へゆっくりと押しやります。","卵が大体固まるまで炒めたら火を止め、皿に盛ります。"]'::jsonb, '["卵料理","風味豊か","ふわふわ","手軽","家庭料理","朝食"]'::jsonb),
  ('howtocook:vegetable_dish/炒茄子', 'ja', '茄子の炒め物', '野菜料理', 'この家庭風茄子炒めは柔らかく味が染み込み、醤油の香りが豊かで、八角を加えると風味がさらに増します。茄子は食物繊維、ビタミンP、カリウムが豊富で、心臓血管の健康に役立ちます。作り方は簡単で初心者にも優しく、強火で手早く炒め、準備から完成まで約20分でできます。', '[{"name":"茄子","unit":"本"},{"name":"八角（オプション）","unit":"個"},{"name":"桜エビ（オプション）","unit":"つかみ"},{"name":"ネギ（オプション）","unit":"本"},{"name":"ひき肉（オプション）","unit":"g"},{"name":"醤油","unit":"ml"},{"name":"砂糖（オプション）","unit":"g"},{"name":"酢（オプション）","unit":"ml"},{"name":"菜種油またはピーナッツ油","note":"適量"}]'::jsonb, '["茄子を洗い、縦に半分に切る。それぞれの半分を菱形に切り、ボウルに入れておく。","ネギを洗い、小口切りにしてまな板に置いておく。","八角を切って、まな板に置いておく。","ひき肉を入れる場合は、まず油10ml（赤身肉のみの場合は15ml）で中火で色が変わるまで（約1分）炒め、取り出しておく。","火をつけて鍋を熱し、鍋内の水分がなくなるまで加熱する。","鍋に食用油を、底の2倍の高さまで注ぐ（油は多めでもよいが、少なすぎないように）。","油が6割程度熱くなったら、八角、桜エビ、ネギの3つのオプション食材を加える。","八角などのオプション食材がない場合は、油を9割程度まで熱する。","油が9割程度熱くなったら、ボウルの茄子を鍋に加え、ヘラで炒める。","約40秒炒めたら、ヘラを鍋と平行に浮かせ、ヘラに醤油を注ぐ。一人あたり約2.5杯分（醤油は少なめでもよいが、多すぎると塩辛くなる）。","茄子が半柔らかくなったら（約1分後）、先に炒めたひき肉を戻し入れ、手早く混ぜ合わせる。","砂糖と酢を加える場合は、ここで加える。","引き続き炒める。","鍋内の全ての茄子の色が変わり柔らかくなったら、火を止めて取り出す。"]'::jsonb, '["野菜料理","家庭料理","スピーディー","ご飯が進む","うま味と香り","強火で手早く炒める"]'::jsonb),
  ('howtocook:vegetable_dish/炒青菜', 'ja', '青菜炒め', '野菜料理', 'さっぱりとして美味しい家庭的な野菜料理です。食感はシャキシャキで、塩味と旨味があり、後味に甘みが広がります。青菜にはビタミンと食物繊維が豊富で、消化を助けます。作り方はとても簡単で、初心者でも気軽に作れます。材料の準備から出来上がりまで約10分です。', '[{"name":"青菜","unit":"g"},{"name":"にんにく","unit":"片"},{"name":"サラダ油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"水","unit":"ml"},{"name":"砂糖","unit":"g"}]'::jsonb, '["青菜を小房に分け、水で洗い、水気を切っておく。","にんにくをみじん切りにする。","中火から強火で鍋を熱し、サラダ油10-15mlを入れる。30秒待って油の温度を上げる。","準備した青菜を鍋に加え、青菜がしんなりするまで（約1分）炒める。","みじん切りにしたにんにくを加える。","計算した水を加え、水位が青菜を完全に浸すか、もう少しで浸るくらいにする。塩（2g）を加え、さらに約1分炒める。","最後に砂糖を加え、弱火で2分加熱する。加熱中は蓋をする。","器に盛る。"]'::jsonb, '["野菜料理","あっさり","旨味","家庭料理","時短","炒め物"]'::jsonb),
  ('howtocook:vegetable_dish/烤茄子/烤茄子', 'ja', '焼き茄子', '野菜料理', '焼き茄子は香り豊かで、外はカリッと中はとろり。クミンとにんにくの香りが柔らかな茄子の身に完璧に溶け込み、屋台の焼き茄子の味を家庭で手軽に再現できる料理です。茄子にはビタミンPやアントシアニンが豊富に含まれ、心血管の保護や抗酸化作用に役立ちます。オーブンを使いますが、手順は明確で初心者でも約30分で完成します。家族団らんの簡単おかずに最適です。', '[{"name":"茄子","unit":"本"},{"name":"食用油","unit":"ミリリットル"},{"name":"醤油（薄口）","unit":"グラム"},{"name":"唐辛子","unit":"本"},{"name":"にんにく","unit":"片"},{"name":"クミン","unit":"グラム"},{"name":"食塩","unit":"グラム"}]'::jsonb, '["醤油（薄口）、クミン、食塩、にんにくのみじん切り、刻んだ唐辛子をボウルに入れ、よく混ぜ合わせておきます。","茄子を洗い、キッチンペーパーで表面の水分を拭き取ります。","フォークで茄子の片面に4～8ヶ所穴を開けます。","15～25mlの食用油を茄子の表面にまんべんなく塗ります。","オーブンを200℃に設定し（オーブンファンを強火にする）、2分予熱します。","茄子をオーブンの中央段か上段に入れ、12～15分焼きます（茄子の表面にしわが寄り、0.3～0.5cm押し込める程度になったらOKです）。","茄子を取り出し、包丁で茄子に縦に切れ目を入れます。切れ目は中心に入れ、上下に1～1.5cmの余白を残します。","小さなナイフまたはフォークを切れ目に差し込み、茄子の内部を縦に切り離します。","切れ目を少し開き、最初に準備した調味料を注ぎ入れます。","再び茄子をオーブンに入れ、200℃で4～7分焼きます。","取り出し、オーブンの電源を切ります。"]'::jsonb, '["野菜料理","にんにく風味","クミン","オーブン焼き","簡単","家庭料理","ご飯のおかず"]'::jsonb),
  ('howtocook:vegetable_dish/白灼菜心/白灼菜心', 'ja', '白灼菜心（白く茹でた菜心）', '野菜料理', 'この定番広東料理は白灼技法を用い、沸騰したお湯でさっと茹でることで菜心の甘みとシャキシャキ感を引き出し、根元の部分が特に歯ごたえよく、あっさりとして美味しい。ビタミンCと食物繊維が豊富で低脂肪・低カロリー、健康的な食生活を求める人にぴったり。作り方はとても簡単で、難易度は2つ星程度、初心者でも15分で完成する、緑黄色野菜を手軽に補給するのに理想的な一品。', '[{"name":"新鮮な菜心","unit":"g"},{"name":"醤油","unit":"g"},{"name":"オイスターソース","unit":"g"},{"name":"塩","unit":"g"},{"name":"ニンニク","unit":"片"},{"name":"唐辛子（輪切り）","unit":"本"},{"name":"サラダ油","unit":"g"}]'::jsonb, '["菜心を洗い、根元の硬い部分や古い部分を取り除く。ここでは包丁で菜心の根元をこそげて外側の硬い皮を取り除き、内側をおいしくする。ただし根元の茹で時間に注意し、長すぎるとシャキシャキ感がなくなる。","ニンニクをみじん切りにする。玉ねぎがあれば少し加える。","魂のタレを作る：醤油 5g、オイスターソース 5g、砂糖 3g、水 100g（半カップから1カップ分）を混ぜる。","鍋に水 500ml、塩 5g、サラダ油 10gを入れて沸騰させる。","菜心の根元を熱湯で1分間茹で、色が濃い緑になるまで。次に全体を鍋に入れてさらに1分間茹で、取り出して皿に並べる。","別の小鍋に合わせたタレを入れ、弱火で沸かす。ニンニクのみじん切りの半量、ショウガの細切り少々、唐辛子みじん切り少々を加える。実際には玉ねぎのみじん切りとニンニクも少し加え、鍋底に油をひき、5割熱したらニンニクと玉ねぎを入れて軽く炒め香りを立て、タレを加えて唐辛子を入れ煮立たせる。","タレを少し煮詰め、沸騰後10秒ほど置いてから菜心にかける。多すぎないように。ただしニンニクのみじん切りはたっぷりと、減らさない。"]'::jsonb, '["野菜料理","広東料理","白灼","あっさり","時短","家庭料理"]'::jsonb),
  ('howtocook:vegetable_dish/皮蛋豆腐', 'ja', 'ピータン豆腐', '野菜料理', 'ピータン豆腐はさっぱりとした前菜になる和え物の家庭料理です。ピータンはプリプリで滑らか、絹ごし豆腐は口どけがよく、塩味とほのかな酸味がご飯によく合います。豆腐には良質な植物性たんぱくとカルシウムが豊富で、ピータンには鉄分やビタミンAなどの栄養素が含まれ、一緒に食べることで消化吸収が良くなります。調理はほとんどハードルがなく、初心者でも簡単にでき、準備から食卓まで約5分で完成します。', '[{"name":"ピータン","unit":"個"},{"name":"絹ごし豆腐","unit":"パック"},{"name":"しょうゆ","unit":"ml"},{"name":"白砂糖","unit":"グラム"},{"name":"酢（推奨：鎮江香酢）","unit":"ml"},{"name":"ごま油（お好みで）","unit":"ml"},{"name":"ラー油（お好みで）","unit":"ml"},{"name":"ピーナッツクラッシュ（お好みで）","unit":"グラム"},{"name":"ネギみじん切り（お好みで）","unit":"グラム"},{"name":"パクチー（お好みで）","unit":"株"}]'::jsonb, '["まずピータンの殻をむき、4つに切る。","絹ごし豆腐を一口大に切って中央に置く。","しょうゆ、白砂糖、酢、ごま油、ラー油を混ぜてたれを作り、かける。","最後に好みでピーナッツクラッシュ、ネギのみじん切り、パクチーを散らす。"]'::jsonb, '["野菜料理","和え物","時短","家庭料理","さっぱり","ご飯が進む"]'::jsonb),
  ('howtocook:vegetable_dish/糖拌西红柿/糖拌西红柿', 'ja', 'トマトの砂糖和え', '野菜料理', 'これは夏にぴったりの家庭料理の冷菜です。甘酸っぱくてさっぱりしており、作り方も簡単です。トマトにはビタミンCが豊富で、食欲をそそり、脂っこさを和らげます。初心者でも簡単にでき、全体の工程（冷蔵時間を含む）は約15分で食卓に出せます。', '[{"name":"トマト","unit":"個"},{"name":"砂糖","unit":"グラム"}]'::jsonb, '["包丁でトマトの皮に十字の切り込みを入れる","箸でトマトのへたの部分を刺し、ガスコンロで回しながら10秒焼く（または熱湯を30秒かける）、皮がめくれるまで","トマトの皮を剥く","トマトを8等分に切る（筋に沿って切ると汁気を残せる）、へたの部分を取り除き、取っておく","全て切り終えたら、皿にトマトを均等に並べる","砂糖を振りかけ、全てのトマトを並べ終えるまで同じ手順を繰り返す","冷蔵庫で10分冷やす","トマトの砂糖和えの完成。栄養満点で美味しく、甘酸っぱくてさっぱり、夏の暑さ対策にぴったり"]'::jsonb, '["野菜料理","甘酸っぱい","和え物","家庭料理","時短","暑さ対策"]'::jsonb),
  ('howtocook:vegetable_dish/红烧冬瓜/红烧冬瓜', 'ja', '冬瓜の紅焼き', '野菜料理', '冬瓜の紅焼きは、色鮮やかで香りが良く、味も美味しい家庭的な野菜料理です。食感は柔らかく、味がよく染み込んでおり、多くの人に愛される中華の煮物料理です。冬瓜自体は水分、食物繊維、ビタミンCが豊富で、熱を冷まし、利尿作用があり、むくみを取る効果があります。簡単な調味料で栄養も消化も良く、初心者にも優しいレシピです。手順が明確で、火加減と味付けをしっかり押さえれば、約25分で作れます。', '[{"name":"冬瓜","unit":"グラム"},{"name":"食用油","unit":"ml"},{"name":"料理酒","unit":"ml"},{"name":"片栗粉","unit":"グラム"},{"name":"薄口醤油","unit":"ml"},{"name":"濃い口醤油（老抽）","unit":"ml"},{"name":"鶏がらスープの素","unit":"グラム"},{"name":"ネギ","unit":"本"},{"name":"生姜のみじん切り","unit":"粒"},{"name":"オイスターソース","unit":"ml"}]'::jsonb, '["冬瓜の皮をむき、2cm以下の小さな角切りにする","鍋に油を熱し、冬瓜を入れて、ゆっくりと転がしながら2分間揚げ焼きにし、表面が黄金色になるまで炒める","冬瓜を取り出し、大きめのボウルに入れておく","鍋に残った油で、生姜のみじん切り、醤油、オイスターソースを順に入れ、15秒炒める","冬瓜を戻し入れ、30秒炒めたら、熱湯を冬瓜がかぶるくらい注ぎ、強火で10分煮る","濃い口醤油（老抽）を加えて色をつけ、冬瓜が柔らかくなるまで煮る（箸がすっと通るまで）","鶏がらスープの素、料理酒、ネギを加えて30秒炒め、冬瓜をボウルに取り出す","鍋に残った煮汁に水溶き片栗粉を加え、沸騰させてとろみをつけ、冬瓜の上からかける"]'::jsonb, '["野菜料理","紅焼き","塩味と旨味","家庭料理","時短","柔らか"]'::jsonb),
  ('howtocook:vegetable_dish/红烧茄子', 'ja', 'ナスの甘辛煮', '野菜料理', 'ナスの甘辛煮は、塩味と香りが豊かな家庭的なおかずです。柔らかく煮込んだナスがたっぷりのタレを吸い込み、ピーマンとトマトの酸味と辛味が絶妙にマッチします。ナスには食物繊維とビタミンPが豊富で、揚げたナスは香ばしくてしつこくありません。衣をつけて揚げ、じっくり煮込んで味を染み込ませる必要があり、手順はやや多めですが、初心者でも挑戦可能です。細かい部分に注意すれば成功します。下準備から仕上げまで約45分かかります。', '[{"name":"ニンニク","unit":"片"},{"name":"長ネギ","unit":"本"},{"name":"青唐辛子","unit":"個"},{"name":"玉ねぎ","unit":"個"},{"name":"トマト","unit":"個"},{"name":"青ナス","unit":"個"},{"name":"塩","note":"適量"},{"name":"醤油","note":"適量"},{"name":"卵","unit":"個"},{"name":"小麦粉","unit":"g"},{"name":"片栗粉","note":"適量"}]'::jsonb, '["青ナス、青唐辛子、トマト、玉ねぎ、長ネギを洗う。","長ネギを5mm幅の小口切りにする。ニンニクの皮をむき、潰す。トマトを6立方センチの角切り、青唐辛子と玉ねぎを5gのブロックに切る。","ナスを斜め切り（菱形切り）にする（まず2cm厚さの輪切りにし、それを2cm幅の棒状に切り、最後に斜めに切る）。","小麦粉をボウルに入れ、少量の水を加えながら混ぜ、とろりとした糊状にする。","片栗粉を加え、30gの水を加えてよく混ぜる。","卵をボウルに割り入れ、（小麦粉 / 20）gの塩を加えてよく混ぜる。","ナスの塊を衣に加え、全体に衣が絡むように混ぜる。","強火で鍋を熱し、500mlの油を入れる。油から煙が立ち始めたら弱火にし、菜箸でナスを1個ずつ油に入れる。すべてのナスを入れ終えたら中火にし、ナスが黄金色になるまで揚げて取り出し、油を捨てる。","（分量 5）gの油を加え、ニンニクとネギを入れ、15秒炒める。青唐辛子を加えて30秒炒め、トマトを加えて30秒炒める。","揚げたナスを加え、食材の高さの0.8倍まで水を加える。","醤油と（分量 3）gの塩を加える。","タレがとろりとするまで待つ（水位が食材の高さの0.2～0.3倍になったら）、蓋を開けて料理を取り出し、火を止める。"]'::jsonb, '["野菜料理","塩味香ばしい","紅焼き","家庭料理","おかず","揚げ物"]'::jsonb),
  ('howtocook:vegetable_dish/素炒豆角', 'ja', 'インゲンの素炒め', '野菜料理', 'これは醤油の香り豊かな家庭料理の炒め物で、インゲンは柔らかく味が染み込み、ピリ辛でご飯が進みます。食物繊維や各種ビタミンが豊富で、消化を促進します。作り方は簡単で、初心者でも気軽に作れます。準備から完成まで約20分です。', '[{"name":"インゲン","unit":"グラム"},{"name":"小さな唐辛子","unit":"個"},{"name":"ネギ","unit":"束"},{"name":"ニンニク","unit":"個"},{"name":"薄口醤油","unit":"ミリリットル"},{"name":"濃口醤油","unit":"ミリリットル"},{"name":"オイスターソース","unit":"ミリリットル"},{"name":"塩","unit":"グラム"},{"name":"油","unit":"ミリリットル"},{"name":"水","unit":"ミリリットル"}]'::jsonb, '["ネギは小口切り、ニンニクはみじん切りにして、準備しておく。","薄口醤油、濃口醤油、オイスターソース、塩を混ぜ合わせて調味液を作り、準備しておく。","小さな唐辛子は輪切りにして、準備しておく。","インゲンは筋を取り、45度の斜め切りで4-10cmの長さに切り、準備しておく。","鍋に油（10ml-15ml）を熱し、煙が出たらネギと唐辛子を入れて香りが立つまで炒める。","インゲンを加え、30秒炒める。","調味液を加え、強火で2分間炒める。","水150mlを加える。","中弱火にし、蓋をして8-10分間蒸し煮にする。","みじん切りにしたニンニクを加え、完成。"]'::jsonb, '["野菜料理","旨味","素炒め","ご飯が進む","時短","家庭料理"]'::jsonb),
  ('howtocook:vegetable_dish/脆皮豆腐', 'ja', 'カリカリ豆腐', '野菜料理', 'カリカリ豆腐は外はカリカリ、中はふんわり。タレは甘辛でちょうどよく、ご飯が進む時短おかずです。豆腐には植物性たんぱく質とカルシウムが豊富、卵には良質なたんぱく質が含まれ、栄養バランスが良いです。黄金色のカリカリの皮を焼くには忍耐が必要ですが、手順は明確で初心者でも作れます。全工程約30分です。', '[{"name":"木綿豆腐","unit":"丁"},{"name":"卵","unit":"個"},{"name":"醤油","unit":"g"},{"name":"老抽","unit":"g"},{"name":"オイスターソース","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"片栗粉","unit":"g"},{"name":"サラダ油","unit":"ml"}]'::jsonb, '["卵を溶いて卵液を作り、置いておく","タレを作る（醤油20g＋オイスターソース10g＋老抽5g＋砂糖10g＋片栗粉10g＋水200ml）","木綿豆腐を切る（目安：一人5枚、厚さ1.2cm）","片栗粉を皿に広げ、豆腐に片栗粉をまぶし、次に卵液をつけて置いておく","鍋を熱し、サラダ油18mlを入れる。10秒待って油の温度を上げる","卵液をつけた豆腐を鍋に均等に並べ、弱火で黄金色になるまで焼き、ひっくり返す","両面が黄金色になったら、タレを加え、すべての豆腐にタレが絡まるようにし、強火で3分、タレがとろりとするまで煮る","火を止める"]'::jsonb, '["精進料理","甘辛","焼き","家庭料理","ご飯が進む","時短"]'::jsonb),
  ('howtocook:vegetable_dish/芹菜拌茶树菇/芹菜拌茶树菇', 'ja', 'セロリとチャシュウキノコの和え物', '野菜料理', 'さっぱりとした歯ごたえのある和え物です。セロリのシャキシャキ感とチャシュウキノコの噛みごたえが絶妙で、豊かな食感が楽しめます。ビタミンやミネラルが豊富で、栄養たっぷりで食欲をそそります。作り方はとても簡単で、初心者でも気軽に作れます。下準備から完成まで約30分です。', '[{"name":"闽星チャシュウキノコ","unit":"瓶"},{"name":"セロリ","unit":"グラム"},{"name":"ごま油","unit":"ml"},{"name":"オイスターソース","unit":"ml"},{"name":"味極鮮","unit":"ml"},{"name":"食塩","unit":"グラム"}]'::jsonb, '["（セロリ苗の場合はこのステップを省略）やかんでお湯を沸かし、準備する。","新鮮なセロリ苗またはセロリの黄ばんだ葉を取り除き、洗って準備する。","（セロリ苗の場合は省略）セロリの葉を別のボウルに入れ、茎を包丁で2～3mm幅の細切りにする。これにより、セロリがより早く均一に火が通り、シャキッとした食感になる。","セロリ苗を4cmの長さに切って準備する。","（セロリ苗の場合は省略）鍋を火にかけ、やかんの熱湯を鍋に注ぎ、沸騰するまで待つ。","（セロリ苗の場合は省略）切ったセロリの細切りを鍋に入れて湯通しし、約20秒後にセロリの葉を加え、5秒後に火を止めてすべてを取り出し、冷水にさらして準備する。","ボウルに入れた湯通ししたセロリまたはセロリ苗に、準備しておいた塩、ごま油、オイスターソース、味極鮮を加えてよく混ぜる。","チャシュウキノコを加えてさらに混ぜる。","皿に盛り付ける。","いただきます。"]'::jsonb, '["野菜料理","和え物","あっさり","簡単","食欲増進","家庭料理"]'::jsonb),
  ('howtocook:vegetable_dish/茄子炖土豆', 'ja', '茄子とじゃがいもの煮物', '野菜料理', '茄子とじゃがいもの煮物は東北地方の家庭料理で、口当たりは柔らかく塩味と旨味があり、唐辛子の辛味とニンニクの香りが食欲をそそります。茄子にはアントシアニンと食物繊維が豊富で、じゃがいもは炭水化物とビタミンCを、豚肉はタンパク質を提供し、栄養バランスが良く満足感があります。この料理は手順は簡単ですが、炒め煮の火加減が重要で、初心者には少し難しいかもしれません。難易度は中程度です。準備から完成まで約45分かかります。', '[{"name":"茄子","unit":"個"},{"name":"じゃがいも","unit":"個"},{"name":"豚肉","unit":"グラム"},{"name":"青唐辛子","unit":"グラム"},{"name":"醤油","unit":"ミリリットル"},{"name":"塩","unit":"グラム"},{"name":"ニンニク","unit":"片"},{"name":"食用油","unit":"ミリリットル"},{"name":"水","note":"適量"}]'::jsonb, '["茄子、じゃがいも、青唐辛子を洗い、ニンニクの皮をむいてつぶす。","茄子とじゃがいもを約6立方センチメートルの角切りにし、青唐辛子を5グラムの小片に、肉を3センチメートルの細切りにする。","火をつけ、鍋を熱し、13ミリリットルの油を加える。","鍋の油が少し煙を上げ始めたら、青唐辛子を入れる。","青唐辛子の香りが立ったらすぐに肉を加え、ヘラで30秒炒める。","じゃがいもを加え、30秒炒める。","茄子を加え、30秒炒める。","醤油と塩を加え、さらに5分炒める。","水を加え、水面の高さが鍋の食材の高さの0.9倍になるようにし、蓋をする。","鍋の水の高さが食材の高さの0.1倍になるまで待ち、蓋を開けてニンニクを加え、よく混ぜて火を止める。"]'::jsonb, '["野菜料理","東北","家庭料理","煮込み","塩味","ご飯が進む","ピリ辛"]'::jsonb),
  ('howtocook:vegetable_dish/莴笋叶煎饼/莴笋叶煎饼', 'ja', 'レタスの葉の焼き餅', '野菜料理', 'レタスの葉の焼き餅は、簡単で手早く作れる家庭的な軽食です。外はカリッと中はふんわりとした食感で、レタスの葉の清涼感あふれる香りが楽しめます。レタスの葉はビタミンと食物繊維が豊富で、卵と組み合わせることで良質なタンパク質も補給でき、栄養バランスが良いです。調理工程は複雑な技術を必要とせず、混ぜて両面を焼くだけで、初心者でも簡単に作れます。準備から完成まで約10分と予想されます。', '[{"name":"レタスの葉","unit":"g"},{"name":"卵","unit":"個"},{"name":"サラダ油","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"片栗粉","unit":"g"},{"name":"鶏がらスープの素","unit":"g"}]'::jsonb, '["レタスの葉をみじん切りにし、卵、片栗粉、醤油、鶏がらスープの素を加えてよく混ぜ合わせる。","フライパンに油を熱し、レタスの葉の生地を流し入れ、鍋の表面に均等に広げる。","表面を120秒焼き、裏返してさらに60秒焼いてから取り出す。"]'::jsonb, '["野菜料理","手早い","家庭料理","焼き","あっさり","栄養満点"]'::jsonb),
  ('howtocook:vegetable_dish/菠菜炒鸡蛋/菠菜炒鸡蛋', 'ja', 'ほうれん草と卵の炒め物', '野菜料理', 'ほうれん草と卵の炒め物は、あっさりとした味わいで食べやすい家庭料理のスピードメニューです。ほうれん草は柔らかく、卵は香ばしく、南北を問わず愛される大衆的な味わいです。ほうれん草には鉄分、葉酸、ビタミンが豊富に含まれ、卵は良質なタンパク質とレシチンを提供します。一緒に食べることで、血を補い気を養い、体質を強化するのに役立ちます。調理は簡単で、調理初心者にも最適です。準備から盛り付けまで約15分で完成します。', '[{"name":"ほうれん草","unit":"g"},{"name":"卵","unit":"個"},{"name":"食用油","unit":"ml"},{"name":"食塩","unit":"g"}]'::jsonb, '["ほうれん草の根を切り落とし、洗って、ザルに上げ、茹でる","卵をボウルに割り入れ、溶きほぐす","鍋を熱し、10mlの油を加える","油が熱くなったら、溶き卵を流し入れ、中火で15秒炒め、最初に卵焼きにしてから、フライ返しで小さく切る","火を止め、卵の塊を皿に取り出し、鍋は洗わない","再び火をつけ、5mlの油を加え、油が熱くなったらほうれん草を入れ、強火で15秒炒め、卵の塊を加えて全体を炒め合わせる","5gの塩、100mlの水を加え、強火で10秒炒める","火を止め、皿に盛る"]'::jsonb, '["精進料理","あっさり","香ばしい","スピード","家庭料理","炒め"]'::jsonb),
  ('howtocook:vegetable_dish/葱煎豆腐', 'ja', 'ネギ焼き豆腐', '野菜料理', '外はカリッと中はふんわり、ネギの香りが豊かで、塩味と旨味、ほんのり辛い家庭料理の定番。豆腐は植物性たんぱく質とカルシウムが豊富で、青唐辛子とネギを合わせ栄養バランスも良い。調理の難易度は中程度で、豆腐を焼く時は弱火でじっくり。初心者でも手順通りに丁寧に作れば上手くできる。全体で約30分。', '[{"name":"木綿豆腐","note":"適量"},{"name":"ネギ","unit":"本"},{"name":"青唐辛子","unit":"本"},{"name":"塩","unit":"g"},{"name":"鶏ガラスープの素","unit":"g"},{"name":"油","unit":"ml"},{"name":"水","unit":"ml"}]'::jsonb, '["豆腐を洗い、約5mmの厚さに切って皿に置く。","ネギを洗い、根元を除いて小口切りにし、準備する。","青唐辛子を洗い、縦に切って種を取り、1cm角に切って準備する。","鍋を熱し、油9mlを加える。","油が鍋全体に広がったら、豆腐を並べ、弱火で焼き色がつくまで焼き、裏返す。","両面が黄金色になったら、皿に取り出して準備する。","油を足して鍋底を覆い、青唐辛子を加えて強火で炒め、さらに3分ほど炒めつぶす。","豆腐を加えて炒め、塩と鶏ガラスープの素を加え、中火で1分炒めた後、水10mlを加え、強火で煮詰める。","火を止める前に、先に用意したネギを散らし、器に盛る。"]'::jsonb, '["野菜料理","塩味旨味ほんのり辛い","香ばし焼き","家庭料理","ご飯が進む","時短"]'::jsonb),
  ('howtocook:vegetable_dish/蒜蓉空心菜/蒜蓉空心菜', 'ja', '空心菜のニンニク炒め', '野菜料理', '空心菜のニンニク炒めは、歯ごたえがよく、さっぱりとして、ニンニクの風味が豊かな家庭料理です。典型的な四川風の炒め物に属します。空心菜は食物繊維、ビタミン、カルシウムが豊富で、腸の蠕動を促進するのに役立ちます。作り方はとても簡単で、初心者にも優しく、準備から完成まで約15分しかかかりません。', '[{"name":"空心菜","unit":"g"},{"name":"ニンニクのみじん切り","unit":"個"},{"name":"食用油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"醤油","unit":"ml"}]'::jsonb, '["空心菜を洗い、傷んだ葉や硬い茎を取り除き、均等に2～3等分に切ります（長すぎると炒めにくいため）。","鍋にまず少量の油を入れ、薄く煙が出るまで熱します。その時、鍋を持ち上げて熱い油を鍋の内側に全体に行き渡らせ、油が鍋底に均一に広がるようにします。その後、残りの油を加えます（熱鍋冷油法）。","ニンニクのみじん切りを入れ、弱火で10～15秒炒めて香りを出します。","素早く均等に空心菜を入れ、強火にします。左手にヘラ、右手に箸を持ち、協力して空心菜を絶えず混ぜながら、柔らかくなり緑色になるまで炒めます。","次に、箸を使わずにヘラだけで柔らかくなった空心菜を15～20秒素早く炒め、均一に加熱します。そこに塩2g、砂糖3g、醤油8mlを加えます。","さらに強火で10秒炒めて、火を止めて完成です。"]'::jsonb, '["野菜料理","ニンニク風味","あっさり","四川風","時短","家庭料理","炒め物"]'::jsonb),
  ('howtocook:vegetable_dish/蒜蓉西兰花', 'ja', 'にんにくブロッコリー', '野菜料理', 'この家庭料理は、にんにくの風味が濃厚で、味付けがシンプルなのが特徴です。ブロッコリーを茹でて、柔らかく、または少しシャキシャキに仕上げ、あっさりと美味しいです。ビタミンC、食物繊維、様々な抗酸化物質が豊富で、栄養バランスの良い簡単な野菜料理です。作り方は難しくなく、初心者でも簡単に作れます。下準備から完成まで約15分でできます。', '[{"name":"ブロッコリー","unit":"g"},{"name":"にんにく","unit":"片"},{"name":"しょうゆ","unit":"ml"},{"name":"オイスターソース","unit":"ml"},{"name":"砂糖","unit":"g"}]'::jsonb, '["ブロッコリーを小房に分け、よく洗います。","にんにくの皮をむき、みじん切りにして、用意します。","鍋に飲料水1000mlを入れ、強火で沸騰させます。","ブロッコリーを入れ、強火のまま2〜3分茹で、ブロッコリーの色が鮮やかな緑になり、柔らかくなるまでにします。","茹で上がったブロッコリーを取り出し、水気を切り、皿に盛っておきます。","鍋を熱し、食用油10mlを加えます。油の温度が上がったら、にんにくのみじん切りを入れ、弱火で香りが出るまで炒めます。","しょうゆ10ml、オイスターソース5ml、砂糖2gを加え、飲料水30mlを加えます。","鍋の中のタレを沸騰させます。","出来上がったにんにくのタレを、皿のブロッコリーの上に均等にかけます。"]'::jsonb, '["野菜料理","にんにく風味","あっさり","時短","家庭料理"]'::jsonb),
  ('howtocook:vegetable_dish/蒲烧茄子', 'ja', '蒲焼き茄子', '野菜料理', '蒲焼き茄子は、甘辛い味わいで、とろっとした食感の家庭料理です。和風の蒲焼き風味を取り入れつつ、中華風の焼き調理法で作ります。茄子は食物繊維やビタミンが豊富で、体を冷ます効果や血行促進に役立ちます。難易度は普通で、初心者には少し忍耐が必要ですが、調理時間は約30分です。', '[{"name":"茄子","unit":"個"},{"name":"蒲焼きのたれ","unit":"人分"},{"name":"はちみつ","unit":"ml"},{"name":"砂糖","unit":"ml"},{"name":"薄口醤油","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"料理酒","unit":"ml"},{"name":"水","unit":"ml"}]'::jsonb, '["茄子の皮をむき、横に半分に切る","5分蒸す","縦に切れ目を入れ、切らないように注意し、両面の切り口に2～3本の切り込みを入れて平らにできるようにする","両面が黄金色になるまで焼く","茄子に蒲焼きのたれを、茄子の高さの1/2が浸るくらいかける","裏面に焼き色がつくまで焼き、裏返す","同時にとろみをつける。とろみがつかない場合は、水溶き片栗粉（片栗粉と水の割合は1:4～1:10、とろみ具合に応じて調整）を加える","残りの蒲焼きのたれを茄子にかける","出来上がり。これで茄子の蒲焼き風の出来上がり"]'::jsonb, '["野菜料理","甘辛い","焼き","家庭料理","ご飯が進む","とろっとした"]'::jsonb),
  ('howtocook:vegetable_dish/虎皮青椒/虎皮青椒', 'ja', '虎皮ピーマン', '野菜料理', '虎皮ピーマンは家庭料理の一品で、外皮は焦げてしわが寄り、食感は柔らかくてシャキシャキ、塩味と酸味と甘味が効いており、とても食欲をそそります。ピーマンはビタミンCと食物繊維が豊富で、免疫力向上や消化促進に役立ちます。作り方は簡単で、押さえつけるコツと火加減さえ掴めば初心者にも優しく、約15分で完成します。', '[{"name":"ピーマン","unit":"個"},{"name":"ニンニク","unit":"片"},{"name":"油","unit":"ml"},{"name":"砂糖","unit":"g"},{"name":"醤油","unit":"ml"},{"name":"酢","unit":"ml"},{"name":"塩","unit":"g"}]'::jsonb, '["ピーマンのヘタを取り、水道水でよく洗います。","ピーマンを縦に3〜4等分に切ります。","ニンニクの皮をむき、みじん切りにします（約2mm角）。","調味料A：小さなボウルに油20mlを入れ、ニンニクのみじん切りを加えます。","調味料B：砂糖、醤油、酢、塩をすべて器に入れて混ぜます。","フライパンに調味料Aを入れ、中火で熱し、ピーマンを重ならないように並べます。","ヘラでピーマンを押さえつけながら焼き、適宜裏返します。","約2分炒め、ピーマンの皮にしわができたら調味料Bを加えます。","強火にしてさらに30秒炒め、皿に盛り付けます。"]'::jsonb, '["野菜料理","家庭料理","ご飯が進む","時短","旨味","甘酸っぱい","炒め物"]'::jsonb),
  ('howtocook:vegetable_dish/蚝油三鲜菇/蚝油三鲜菇', 'ja', 'オイスターソースの三種きのこ', '野菜料理', 'オイスターソースの三種きのこは、旨味と滑らかさが魅力の簡単家庭料理。きのこがオイスターソースをたっぷり吸い込み、柔らかく歯ごたえがあり、ほんのり辛味がアクセントでさっぱり。植物性たんぱく質、食物繊維、ビタミンが豊富で、ブロッコリーと合わせて栄養バランス抜群。作り方は簡単で初心者でも安心、下ごしらえから調理完了まで約15分。', '[{"name":"しいたけ","unit":"個"},{"name":"ブナシメジ","unit":"g"},{"name":"シロタマギ","unit":"g"},{"name":"鷹の爪","unit":"本"},{"name":"ピーマン","unit":"個"},{"name":"食用油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"料理酒","unit":"ml"},{"name":"片栗粉","unit":"g"},{"name":"薄口醤油","unit":"ml"},{"name":"鶏がらスープの素","unit":"g"},{"name":"青ネギ","unit":"本"},{"name":"生姜みじん切り","unit":"粒"},{"name":"オイスターソース","unit":"ml"},{"name":"ブロッコリー","unit":"g"},{"name":"熱湯","unit":"ml"}]'::jsonb, '["ブナシメジとシロタマギは根元の土を取り、小房に分ける","しいたけはスライスする（厚さ0.5〜1cm、厚めの方が歯ごたえが良い）","片栗粉を小さなボウルに入れ、水50mlを加えてダマがなくなるまで混ぜる（水溶き片栗粉）","湯を沸かし、ブロッコリーを入れて3分茹で、器に取っておく","鍋を洗い、湯を沸かし、食塩5gを加え、ブナシメジ、シロタマギ、シイタケを入れて1分茹でる","1分後、取り出して水気を切る","鍋に油を熱し、油が小さな泡を立て始めたら、みじん切りの生姜、鷹の爪、ピーマンを加えて30秒炒める","三種のきのこを加え、順に薄口醤油、オイスターソース、鶏がらスープの素を加えて炒め合わせ、水溶き片栗粉を加える","中火で汁気が少なくなるまで炒め、料理酒と刻みネギを加えて火を止める","ブロッコリーを飾る"]'::jsonb, '["野菜料理","旨味","少し辛い","簡単スピード","家庭料理","ご飯が進む"]'::jsonb),
  ('howtocook:vegetable_dish/蚝油生菜', 'ja', 'オイスターソースレタス', '野菜料理', 'オイスターソースレタスは、さっぱりとして香ばしい家庭料理です。シャキシャキのレタスに、ガーリック風味のオイスターソースだれが絡み、塩味と甘味が絶妙。広東料理や四川料理の定番で、スピーディーな野菜料理です。ビタミンや食物繊維が豊富で、消化を促進します。初心者にもやさしく、洗ってから15分ほどで完成します。', '[{"name":"レタス","unit":"株"},{"name":"オイスターソース","unit":"ml"},{"name":"ニンニク","unit":"かけ"},{"name":"薄口醤油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"砂糖","unit":"g"},{"name":"食用油","unit":"ml"}]'::jsonb, '["レタスを洗い、傷んだ葉を取り除く。","鍋を熱し、まず1Lの冷水を入れ、次に食用油2〜3mlと塩0.5gを加え、水が沸騰するのを待つ。","沸騰したら、レタスを入れ、各葉を10秒間湯通しする。","レタスを取り出し、水気を切り、皿に盛る。","タレを作る：薄口醤油10ml、オイスターソース6〜8ml、塩0.5g、砂糖1gをボウルに入れて混ぜ、さらに冷水10〜15mlを加えてよく混ぜる。","再び火をつけ、鍋を熱し、食用油5〜8mlを入れ、油が熱くなったらすりおろしニンニクを加える。","ニンニクの香りが立ったら、混ぜたタレを加え、沸騰したらすぐに火を止める。","鍋のタレをレタスの上に均等にかける。"]'::jsonb, '["野菜料理","旨味","塩味と甘味","手早い","広東料理","家庭料理","ご飯が進む"]'::jsonb),
  ('howtocook:vegetable_dish/西红柿炒鸡蛋', 'ja', 'トマトと卵の炒め物', '野菜料理', '甘酸っぱくて食欲をそそる家庭料理。トロッとした卵に柔らかくジューシーなトマトが絡み、中国の食卓の定番です。卵は良質なタンパク質、トマトはビタミンCとリコピンが豊富で栄養バランスも良好。手順が簡単で材料も手に入りやすく、特に料理初心者におすすめ。下ごしらえから盛り付けまで約15分で完成します。', '[{"name":"トマト","unit":"個"},{"name":"卵","unit":"個"},{"name":"サラダ油","unit":"ml"},{"name":"塩","unit":"グラム"},{"name":"砂糖（オプション）","unit":"グラム"},{"name":"刻みネギ（オプション）","unit":"グラム"},{"name":"酢","unit":"ml"},{"name":"ケチャップ","unit":"ml"},{"name":"水","unit":"ml"}]'::jsonb, '["トマトを洗う","オプション：トマトの皮を取り除く","熱湯で皮を湯むきし、冷水にとって皮を剥く","トマトのヘタを取り、一辺が4cm以下の角切りにする（トマトブロック）","卵をボウルに割り入れ、塩1gを加え、よく混ぜる（卵液）","オプション：卵に酢1mlを加えると、臭みが取れてふんわりする","鍋を熱し、サラダ油を入れる","油が熱くなったら卵液を流し入れ、固まってほんのり色づくまで炒める（半熟卵）","火を止め、半熟卵を取り出し、再び火をつける","注意：鍋は洗わない","トマトブロックを加え、ヘラで押さえながら20秒炒める。またはトマトが柔らかくなるまで","鍋に半熟卵を戻し入れ、よく混ぜながら炒める","オプション：ケチャップ10mlと水50mlを加えると、汁気が増す","お好みで他の肉や具材を追加してもよい","残りの塩、砂糖（甘めが好みならオプション）、ネギ（オプション）を加え、よく混ぜる","火を止め、皿に盛る"]'::jsonb, '["野菜料理","甘酸っぱい","炒め物","家庭料理","時短","ご飯が進む"]'::jsonb),
  ('howtocook:vegetable_dish/西红柿豆腐汤羹/西红柿豆腐汤羹', 'ja', 'トマト豆腐スープ', '野菜料理', 'あっさりとした美味しい家庭的なスープです。甘酸っぱくて食欲をそそり、口当たりは滑らか。トマトはビタミンCとリコピンが豊富で、卵と豆腐を合わせることで良質なタンパク質が補え、栄養バランスが良く吸収されやすいです。作り方は簡単で、切って炒めて煮るだけで、初心者でも気軽に作れます。準備から完成まで約15分でできます。', '[{"name":"トマト","unit":"個"},{"name":"卵","unit":"個"},{"name":"豆腐","unit":"g"},{"name":"食用油","unit":"ml"},{"name":"塩","unit":"g"},{"name":"片栗粉","unit":"g"},{"name":"鶏がらスープの素","unit":"g"},{"name":"小ネギ","unit":"本"},{"name":"生姜","unit":"枚"},{"name":"熱湯","unit":"ml"}]'::jsonb, '["トマトは小さな角切りにし、卵はボウルに割って溶きほぐし、豆腐は一口大に切っておく","鍋に油を熱し、生姜のスライスを入れて5秒後、トマトを加えて30秒炒める","鍋に熱湯を加え、沸騰したら60秒後、溶き卵と豆腐を加える","再び沸騰したら、水溶き片栗粉を加え、一方向に2回かき混ぜる","鶏がらスープの素、塩、ネギを加え、30秒後に火を止める"]'::jsonb, '["野菜料理","あっさり","甘酸っぱい","家庭料理","時短"]'::jsonb),
  ('howtocook:vegetable_dish/西葫芦炒鸡蛋/西葫芦炒鸡蛋', 'ja', 'ズッキーニの卵炒め', '野菜料理', 'ズッキーニの卵炒めは、さっぱりとして美味しい家庭料理の時短レシピです。ズッキーニは柔らかくジューシーで、卵はふんわり香ばしく、トマトを加えると甘酸っぱい風味が加わり、ご飯が進みます。卵は良質なタンパク質とレシチンを、ズッキーニは豊富なビタミンCと食物繊維を含み、栄養バランスが良いです。調理工程は簡単で、初心者にも優しく、準備から完成まで初心者でも約15分でできます。', '[{"name":"ズッキーニ","unit":"g"},{"name":"卵","unit":"個"},{"name":"トマト","unit":"g"},{"name":"サラダ油","unit":"ml"},{"name":"食塩","unit":"g"}]'::jsonb, '["トマトを洗い、小さめの角切りにしておく","ズッキーニを洗い、一辺約4cmのひし形に切っておく","卵を3個ボウルに割り入れ、よく溶いておく","鍋を熱し、サラダ油5ml～10mlを入れる","卵を流し入れ、固まるまで炒め、へらで小さく切ってから器に取り出しておく","鍋にサラダ油5ml～10mlを入れ、トマトを加えて柔らかくなるまで炒める","ズッキーニを加えて全体を炒め合わせ、食塩6gを入れ、弱火にして4～5分待つ","取り出しておいた卵を戻し入れ、中火で15秒炒める","火を止め、皿に盛る"]'::jsonb, '["野菜料理","あっさり","炒め物","家庭料理","時短","ご飯が進む"]'::jsonb),
  ('howtocook:vegetable_dish/话梅煮毛豆/话梅煮毛豆', 'ja', '梅干し枝豆煮', '野菜料理', '梅干し枝豆煮は甘酸っぱくて食欲をそそる家庭料理です。食感はさっぱりとして柔らかく、梅の自然な果実の香りが楽しめます。枝豆は植物性タンパク質と食物繊維が豊富で、エネルギー補給や消化促進に役立ちます。作り方はとても簡単で、初心者でも気軽に作れます。全行程は35〜45分で完成します。', '[{"name":"枝豆","unit":"g"},{"name":"梅干し","unit":"個"},{"name":"食塩","unit":"g"}]'::jsonb, '["清水に食塩を加え、枝豆を15分間浸す","熱湯を加え、枝豆と梅干しを入れて20〜30分茹でる","火を止めて、お皿に盛って食べる"]'::jsonb, '["野菜料理","甘酸っぱい","煮物","家庭料理","食欲増進","時短"]'::jsonb),
  ('howtocook:vegetable_dish/酸辣土豆丝', 'ja', '酸辣じゃがいもの千切り', '野菜料理', '酸っぱくて辛い、食欲をそそる定番の家庭料理。食感はシャキシャキで、色鮮やか。誰にでも人気の手早く作れる炒め物です。じゃがいもは炭水化物とカリウムを、唐辛子はビタミンCを豊富に含み、食欲増進に役立ちます。手順はシンプルで初心者にも優しく、下ごしらえから完成まで約20分でできます。', '[{"name":"じゃがいも","unit":"g"},{"name":"ニンニク","unit":"片"},{"name":"青ピーマン","unit":"個"},{"name":"赤ピーマン","unit":"個"},{"name":"乾燥唐辛子","unit":"個"},{"name":"ネギ","unit":"本"},{"name":"醤油","unit":"ml"},{"name":"黒酢","unit":"ml"},{"name":"塩","unit":"g"},{"name":"食用油","unit":"ml"}]'::jsonb, '["じゃがいもの皮をむき、千切りにする（またはスライサーを使う）。","切ったじゃがいもを水で洗い、余分なでんぷんを落とし、10秒ほど茹でる。水気を切り、取っておく。","ネギは小口切りに；ニンニクは潰してみじん切りにする（2等分して取っておく）；乾燥唐辛子は小口切りに；青ピーマンと赤ピーマンは千切りにする。","鍋を熱し、弱火で油を熱し、半分のネギ（白い部分）、半分のニンニクのみじん切り、乾燥唐辛子を加えて香りを出す。","青ピーマンと赤ピーマンを加えて軽く炒め、じゃがいもを加えて色が変わるまで炒める。","醤油5ml、黒酢10ml、残りのニンニクのみじん切り、塩2gを加えて手早く均一に炒める。","火を止める前に残りのネギを散らし、さっと混ぜて皿に盛る。"]'::jsonb, '["野菜料理","酸辣","炒め物","家庭料理","手早い","ご飯が進む"]'::jsonb),
  ('howtocook:vegetable_dish/金针菇日本豆腐煲', 'ja', 'エノキと玉子豆腐の土鍋煮', '野菜料理', 'エノキと玉子豆腐の土鍋煮は、醬油の香り豊かな家庭的なおかずです。豆腐は外はカリッと中はふんわり、エノキはつるっとした食感で味がしみ込んでいます。エノキにはアミノ酸と食物繊維が豊富で、玉子豆腐は良質なたんぱく質を提供し、栄養満点で食欲をそそります。この料理は手順が簡単で、初心者でも気軽に作れます。準備から完成まで約30分です。', '[{"name":"エノキ","unit":"束"},{"name":"玉子豆腐","unit":"袋"},{"name":"鷹の爪","unit":"本"},{"name":"にんにく","unit":"片"},{"name":"醤油","unit":"ml"},{"name":"オイスターソース","unit":"ml"},{"name":"濃口醤油","unit":"ml"},{"name":"砂糖","unit":"g"},{"name":"サラダ油","unit":"ml"},{"name":"塩","note":"適量"},{"name":"水","unit":"ml"}]'::jsonb, '["玉子豆腐を輪切りにし、弱火で両面がきつね色になるまで焼いてから取り出しておく。","にんにくをみじん切りにする。醤油、オイスターソース、濃口醤油、砂糖、水100mlを混ぜて調味液を作っておく。","鍋に油を熱し、鷹の爪（小口切り）とにんにくみじん切りを香りが出るまで炒める。最初にエノキを入れ、しんなりするまで炒める。焼いた玉子豆腐をエノキの上に平らに並べ、手順2の調味液を注ぎ入れ、蓋をして5分煮る。最後に強火で汁気をとばす。"]'::jsonb, '["野菜料理","醬油風味","家庭料理","ご飯が進む","炒め煮"]'::jsonb),
  ('howtocook:vegetable_dish/金钱蛋', 'ja', '金運玉子（ゴールデンエッグ）', '野菜料理', '外はカリッと中はふんわり、塩味とほんのり辛味が効いた湖南風家庭料理。黄金色に焼けた卵は銅貨の形に似て縁起が良い。卵と青唐辛子・赤唐辛子の組み合わせで、良質なタンパク質とビタミンが豊富。栄養バランスも良い。調理は中級程度だが、初心者でも少し練習すればマスターできる。約30分で完成するご飯泥棒的おかず。', '[{"name":"卵","unit":"個"},{"name":"青唐辛子","unit":"g"},{"name":"赤唐辛子","unit":"g"},{"name":"豆板醤","unit":"ml"},{"name":"ニンニク","unit":"g"},{"name":"小ネギ","unit":"g"},{"name":"片栗粉","unit":"g"},{"name":"食用油","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"オイスターソース","unit":"ml"},{"name":"砂糖","unit":"g"}]'::jsonb, '["卵を冷水から入れ、強火で沸騰させたら弱火にして8分茹でる","水道水で冷やし、殻を剥きやすくする","ニンニクをみじん切り（粒径1mm以下）、青唐辛子と赤唐辛子を小粒に切る（約2～3mm）","ゆで卵を短軸に沿って4等分に切る","片栗粉を付ける場合は、各卵に片栗粉をまぶし、余分な粉をはたく","鍋に25mlの油を入れ（片栗粉を付けない場合は20ml）、ゆで卵を入れる","焦げ目がつくまで焼き、追加の10mlの油を加え（片栗粉を付けない場合も10ml）、裏返す","裏面も軽く焦げたら、青唐辛子、赤唐辛子、ニンニクのみじん切りを加え約1分炒め、裏返す","続いて豆板醤を加え約数十秒炒め、裏返す","醤油、オイスターソース、砂糖を混ぜ合わせたタレを加え、軽く鍋を振って完成"]'::jsonb, '["野菜料理","塩味","辛味少々","焼き","湖南風","ご飯泥棒"]'::jsonb),
  ('howtocook:vegetable_dish/陕北熬豆角', 'ja', '陝北風インゲンの煮込み', '野菜料理', 'これは西北の農家風の煮込み料理で、インゲンは柔らかく、ジャガイモはほくほく、トマトのスープが濃厚で酸味と香りが食欲をそそります。食物繊維、ビタミン、炭水化物が豊富で栄養バランスが良いです。作り方は非常に簡単で、食材の量は好みに応じて調整でき、失敗の可能性はほとんどなく、初心者にも特に優しいです。下準備から出来上がりまで、約30分しかかかりません。', '[{"name":"インゲン","unit":"g"},{"name":"ジャガイモ","unit":"個"},{"name":"トマト","unit":"個"},{"name":"獅子唐辛子","unit":"個"},{"name":"塩","unit":"g"},{"name":"薄口醤油","unit":"ml"},{"name":"五香粉","unit":"g"},{"name":"オイスターソース","unit":"ml"},{"name":"ネギ","unit":"本"},{"name":"ショウガ","unit":"g"},{"name":"ニンニク","unit":"片"},{"name":"パクチーのみじん切り","note":"お好みで"},{"name":"油","unit":"ml"}]'::jsonb, '["ネギはみじん切り、ニンニクはみじん切り、ショウガは千切りにして、用意する。","インゲンは筋を取り、2-10cmの小口切りにして、用意する。","ジャガイモは皮をむき、1cm角の小さめの角切りにして、用意する。","トマトは皮をむき、1cm角の小さめの角切りにして、用意する。","唐辛子は種を取り、0.15cm幅の細切りにして、用意する。","鍋に油(10ml～15ml)を熱し、煙が出たらネギ、ショウガ、ニンニクを入れて、香りが立つまで炒める。","インゲンを加え、色が変わるまで（青緑から鮮やかな緑に）炒める。","ジャガイモの角切りを加え、30秒炒める。","熱湯（具材がちょうど浸るくらい）を注ぎ、蓋をしてジャガイモが柔らかくなるまで煮込む（箸で確認できる）。","トマトの角切り、塩、薄口醤油、オイスターソース、五香粉、唐辛子を加え、トマトが溶けて汁になるまで煮込む（焦げ付かないように混ぜる）。","パクチーのみじん切りを加え、火を止めて皿に盛る。"]'::jsonb, '["野菜料理","家庭料理","ご飯が進む","煮込み料理","西北","時短"]'::jsonb),
  ('howtocook:vegetable_dish/雷椒皮蛋', 'ja', '雷椒ピータン', '野菜料理', '雷椒ピータンは見た目は素朴ですが風味豊かな家庭的な冷菜です。青椒の焦げた香りとピータンの滑らかな味わいが溶け合い、酸味と辛味が食欲をそそり、特に夏の副菜に最適です。ピータンはタンパク質とミネラルが豊富で、青椒はビタミンCを多く含み、ニンニクは食欲を増進します。調理は簡単で初心者でも気軽に作れ、準備から完成まで約15分です。', '[{"name":"ピータン","unit":"個"},{"name":"青椒","unit":"本"},{"name":"ネギ","unit":"cm"},{"name":"ニンニク","unit":"片"},{"name":"ミニトウガラシ","unit":"個"},{"name":"サラダ油","unit":"ml"},{"name":"醤油","unit":"ml"},{"name":"黒酢","unit":"ml"},{"name":"砂糖","unit":"g"},{"name":"ごま油","unit":"ml"}]'::jsonb, '["青椒を洗い、ヘタを除いて縦半分に切り、中の種を取り除き、まな板で平らに押さえておく（必ず種を取り除くこと、さもないと鍋ではじける）","ネギを0.5cmの小口切りにして、おいておく","ニンニクの皮をむき、みじん切りにして、おいておく","ピータンの殻をむき、おいておく","ミニトウガラシを5～10mmの小口切りにして、おいておく","鍋を熱し、鍋にサラダ油10ml～20mlを入れる","青椒をすべて入れ、弱火にして鍋の温度を保ちながら、青椒が柔らかくなるまで焼く（箸で試し、すっと差し込めればOK）","火を止め、ピータンと青椒を小さな鉄のボウルに入れる","方法1： 麺棒があり、叩いても近所に騒音が気にならない場合：麺棒の端でボウルの中でピータンと青椒を叩き、ピータンと青椒が混ざるまでする（選択肢）","方法2： 青椒を手で裂き、約0.5cm幅の細切りにし、フォークでピータンを潰す（選択肢）","ミニトウガラシを加える","醤油、黒酢、砂糖、ごま油、およびその他未使用の用意した食材を加える","均等に混ぜる"]'::jsonb, '["野菜料理","酸辣","和え物","食欲増進","家庭料理","時短"]'::jsonb),
  ('howtocook:vegetable_dish/鸡蛋火腿炒黄瓜', 'ja', '卵とハムのキュウリ炒め', '野菜料理', 'これはさっぱりとした時短の家庭料理です。塩味と旨味がちょうどよく、きゅうりのシャキシャキ感、卵のふわふわ感、ハムの風味が楽しめる、中華風の定番おかずです。卵は良質なタンパク質、きゅうりはビタミンと水分、ハムは旨味を補い、栄養バランスも良好。調理工程はシンプルで難易度は低く、初心者にも優しいです。下ごしらえから盛り付けまで、わずか約10分で完成します。', '[{"name":"きゅうり","unit":"本"},{"name":"卵","unit":"個"},{"name":"ハム","unit":"本"},{"name":"赤唐辛子","unit":"個"},{"name":"サラダ油","unit":"ml"},{"name":"薄口醤油","unit":"ml"},{"name":"塩","unit":"g"}]'::jsonb, '["きゅうりは洗って半月切りにし、準備する。","ハムは半月切りにして準備する。","赤唐辛子（あれば）はみじん切りにして準備する。","卵をボウルに割り入れ、よく混ぜて卵液を作る。","熱したフライパンにサラダ油5mlを入れる。","油が熱くなったら弱火にし、溶き卵を流し入れ、箸でかき混ぜながら、卵が固まって薄く色づくまで炒める。半熟卵になったら、取り出しておく。","フライパンを洗わずに、サラダ油5mlを入れ、きゅうりを加えて強火で1分炒める。","半熟卵をフライパンに戻し入れ、塩2g、薄口醤油3mlを加え、すぐにハムの半月切りと唐辛子のみじん切り（あれば）を加えて全体を炒め合わせる。","火を止め、器に盛る。"]'::jsonb, '["野菜","あっさり","塩味","炒め物","時短","家庭料理"]'::jsonb),
  ('howtocook:vegetable_dish/鸡蛋羹/微波炉鸡蛋羹', 'ja', '電子レンジで茶碗蒸し', '野菜料理', '電子レンジで作る茶碗蒸しは、簡単で手早くできる家庭料理です。なめらかで繊細な食感が特徴で、夜食やちょっとした補食にぴったり。卵には良質なタンパク質とビタミンが豊富で、身体に必要な栄養を補え、干しエビでカルシウムも追加。このレシピは初心者にも優しく、火加減のコツは不要。卵を溶いて味付けしてから出来上がりまでわずか約10分で完成します。', '[{"name":"卵","unit":"個"},{"name":"水","unit":"ml"},{"name":"塩","unit":"g"},{"name":"干しエビ","unit":"個"},{"name":"ネギ","unit":"g"},{"name":"ごま油（香油）","unit":"ml"},{"name":"醤油","note":"適量"}]'::jsonb, '["卵を電子レンジ対応の陶器のボウルに割り入れ、箸で溶きほぐす。","水と塩を加え、よく混ぜる。","干しエビをボウルに入れ、均一に混ぜる。干しエビが固まらないようにする。","ネギをみじん切り（0.6±3mm角）にして、ボウルに入れて混ぜる。","ボウルと内容物を電子レンジに入れ、表面にラップをかけるか、電子レンジ対応の磁器の皿で蓋をする（注：密閉せず、膨張のための余裕を残すこと）。500Wで2分加熱する。","慎重にラップや蓋を取り外し、さらに2分加熱する。","電子レンジに回転ターンテーブルがない場合は、ボウルをゆっくり水平に180度回転させ、均一に加熱されるようにする。","ごま油を加える。","慎重に電子レンジからボウルを取り出す（非常に熱いので注意）。","醤油を加える場合は、茶碗蒸しの表面を流れながら最も薄く全体に絡む程度にする。","楽しく茶碗蒸しを味わう"]'::jsonb, '["精進料理","時短","家庭料理","なめらか","夜食","電子レンジ"]'::jsonb),
  ('howtocook:vegetable_dish/鸡蛋羹/蒸箱鸡蛋羹', 'ja', '蒸し器で作る卵の蒸し物', '野菜料理', 'これは蒸し器を使って手早く作れる、なめらかで家庭的な卵の蒸し物です。食感は調整可能で、水が少なければ弾力があり、多ければより柔らかくなります。良質なタンパク質や様々な栄養素が豊富で、消化吸収が良いです。難易度は中程度で、初心者でも少し注意すれば作れます。準備から完成まで約15分です。', '[{"name":"卵","unit":"個"},{"name":"食塩","unit":"g"},{"name":"食用油","unit":"ml"},{"name":"醤油（薄口醤油、任意）","unit":"ml"}]'::jsonb, '["卵1個をボウルに入れて溶きほぐす","ボウルに卵の体積の1.0〜1.5倍の60度の純水を加え、よく混ぜる","適正範囲内では、水が少ないほど弾力があり、多いほど柔らかくなる","注意：範囲を超えると、水が少なすぎると硬くなり、多すぎると薄くなりすぎる","食塩1gを加える","塩は味のベースと凝固に重要な役割を果たす","食用油5mlを加える","卵液を濾して浮き泡を取り除く（任意。濾さないと蒸した卵に気泡ができて見栄えが悪くなる）","蒸し器の水が十分にあることを確認する（不安な場合は水タンクを満タンにする）","完全に混ぜた卵液のボウルを蒸し器に入れる","100℃に設定して10分蒸す","蒸し器を開ける（注意：開けるときに蒸気が一気に噴出するのでゆっくり開ける）","取り出す（お好みで醤油をかけて味を調える）","いただく"]'::jsonb, '["野菜料理","蒸し","時短","家庭風","なめらか","あっさり"]'::jsonb),
  ('howtocook:vegetable_dish/鸡蛋羹/鸡蛋羹', 'ja', '卵の茶碗蒸し', '野菜料理', 'この料理は簡単で手早く作れる家庭的な蒸し料理です。食感はなめらかでゼリーのようで、塩味と旨味がちょうど良く、朝食やおかずとしてよく食べられます。卵は良質なタンパク質とレシチンを含み、消化吸収が良いです。初心者にも優しく、簡単な手順で滑らかな卵の茶碗蒸しが作れます。全体で約15分かかります。', '[{"name":"卵","unit":"個"},{"name":"食塩","unit":"g"},{"name":"ごま油（または胡麻油）","unit":"ml"},{"name":"醤油（または味極鮮）","unit":"ml"},{"name":"白酢（または料理酒）","unit":"ml"},{"name":"花椒油","note":"適量"}]'::jsonb, '["卵2個をボウルに入れて溶きほぐす","食塩3gを加える","塩は重要な下味と凝固の役割を果たす","白酢2mlを加えて卵の臭みを取る（お好みで）","米酢でも良いが、米酢の色で卵が少し黒ずむことがある","料理酒も加えられ、臭み消し効果があり、酢のような酸味がない","ボウルに卵の体積の1〜1.5倍の70度の純水を加え、よく混ぜる","水の量が1倍だと卵はより弾力があり、1.5倍だとより柔らかい","卵液をこして、表面の泡を取り除く（お好みで。こさないと蒸した時に泡が残って見栄えが悪い）","任意の鍋に300〜500mlの水を入れ、沸騰させた後、卵液の入ったボウルを置く","蒸し碗には蓋をするか、凹型の鉄皿を逆さに被せるか、ラップをして蒸気の侵入を防ぐ。こうすることでスが入るのを防ぐ","蒸し工程（以下のどちらかを選ぶ）","中火で10分蒸し、火を止めてさらに5分蒸らす。","強火で5分蒸す。鍋の水が常に沸騰していることを確認し、そうでなければ時間を延ばす。2分おきに蓋を開けて蒸気を逃がす。蓋を開けるのが遅すぎるとスが入りやすく、早すぎると蒸し時間が長くなる。","火の通し方の見極め：","碗を揺らして、卵液が液体ではなく、ゼリーのようにぷるぷるした状態になれば完成。","鍋から取り出す。","ごま油と醤油をかけてすぐに食べられる。","ごま油の代わりに花椒油をかけると、ピリッとした風味が増す。"]'::jsonb, '["卵料理","蒸し料理","時短","家庭料理","朝食","旨味"]'::jsonb),
  ('howtocook:vegetable_dish/鸡蛋花/鸡蛋花', 'ja', '卵の花', '野菜料理', '簡単に作れる家庭料理のスープで、甘味と塩味の二種類の味わいがあります。口当たりは滑らかで柔らかく、民間の喉の潤い方として知られています。良質のタンパク質とレシチンが豊富で、消化吸収しやすく、喉の乾きやイガイガ感を和らげます。作り方は非常に簡単で、初心者でも一度見ればすぐにできます。お湯を沸かしてから完成まで約5分かかります。', '[{"name":"卵","unit":"個"},{"name":"沸騰したお湯","unit":"ml"},{"name":"砂糖","unit":"g"},{"name":"塩","unit":"g"}]'::jsonb, '["卵をボウルに割り入れる。","箸や泡立て器を使い、一方向に卵液を混ぜる。卵白と卵黄が完全に混ざり合い、色が均一になるまで混ぜる（この作業は約1～2分かかる）。","砂糖または塩などの調味料を卵液に加え、軽く混ぜる。","沸騰したての100℃のお湯を用意する。","箸でボウルの卵液を素早く混ぜながら、沸騰したお湯を細く流し入れる。卵液とよく混ざるようにする。","しばらく混ぜ続け、卵液が完全に湯で固まり、均一な淡黄色の卵の花ができるまで続ける。"]'::jsonb, '["精進料理","甘味と塩味","時短","家庭料理","喉の潤い","スープ"]'::jsonb),
  ('howtocook:aquatic/咖喱炒蟹', 'fr', 'Crabe sauté au curry', 'Fruits de mer', 'Un plat de fruits de mer familial aux influences thaïlandaises, où la chair de crabe généreuse est enveloppée d''un curry parfumé, avec des notes de corail et une texture onctueuse de lait de coco. Le crabe est riche en protéines de haute qualité et en oligo-éléments, idéal pour reprendre des forces. La préparation est claire : il suffit de bien saisir le corail et de remuer la sauce hors du feu à la fin. Ce plat est adapté aux cuisiniers ayant un peu d''expérience ; il faut compter environ 30 minutes de la préparation à l''assiette.', '[{"name":"Crabe","unit":"pièce"},{"name":"Pâte de curry","unit":"g"},{"name":"Oignon","unit":"g"},{"name":"Lait de coco","unit":"ml"},{"name":"Œuf","unit":"pièce"},{"name":"Fécule de maïs","unit":"g"},{"name":"Ail","unit":"gousse"}]'::jsonb, '["Ouvrir le crabe en deux, fendre les pinces avec le dos d''un couteau, saupoudrer les coupes et les pinces d''un peu de fécule (ne pas trop en mettre). Saupoudrer 5 g de fécule dans la carapace pour couvrir le corail ; réserver.","Hacher l''oignon finement ; réserver.","Hacher l''ail finement ; réserver.","Faire bouillir de l''eau ; réserver.","Chauffer l''huile dans un wok, verser environ 20 ml d''huile de cuisson, attendre 10 secondes que l''huile chauffe.","Poser délicatement les morceaux de crabe côté coupé vers le bas dans le wok, saisir 20 secondes (pour sceller le corail et la chair). Retourner chaque face 10 secondes. Retirer le crabe et réserver.","Mettre la carapace dans le wok, arroser le corail avec l''huile chaude à l''aide d''une louche pour le saisir, 20 secondes. Retirer et réserver.","Sans nettoyer le wok, ajouter 10 ml d''huile, chauffer à feu vif jusqu''à ce qu''elle fume légèrement. Ajouter l''ail et l''oignon hachés, faire revenir 10 secondes.","Ajouter le cube de curry dans le wok pour le faire fondre (10 secondes), puis remettre le crabe saisi et mélanger.","Verser 300 ml d''eau bouillante, couvrir et laisser mijoter 3 minutes.","Après la cuisson, ajouter le lait de coco et le blanc d''œuf. Éteindre le feu, puis remuer sans cesse jusqu''à ce que la sauce épaississe.","Servir."]'::jsonb, '["Fruits de mer","Thaï","Savoureux","Riche","Sauté","Accompagnement","Plat de fête"]'::jsonb),
  ('howtocook:aquatic/响油鳝丝', 'fr', 'Anguille sautée à l''huile parfumée', 'Fruits de mer', 'Les filaments d''anguille à l''huile grésillante sont un grand classique de la cuisine familiale du Jiangsu-Zhejiang-Shanghai. L''anguille est tendre et fondante, l''ail parfumé, la sauce légèrement sucrée, et le saindoux chaud versé dessus libère un arôme incroyable, parfait pour accompagner le riz. L''anguille est riche en protéines de haute qualité et en DHA, très nutritive. Ce plat demande un certain savoir-faire au couteau et en cuisson, de difficulté moyenne, les débutants devront s''exercer un peu. De la préparation à l''assiette, il faut compter environ 40 minutes.', '[{"name":"Lanières d''anguille","unit":"g"},{"name":"Ail","unit":"g"},{"name":"Gingembre haché","unit":"g"},{"name":"Vin de cuisson","unit":"g"},{"name":"Sauce soja légère","unit":"g"},{"name":"Sauce d''huître","unit":"g"},{"name":"Sauce soja foncée","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Poivre moulu","unit":"g"},{"name":"Fécule","unit":"g"},{"name":"Eau","unit":"g"},{"name":"Ail haché","unit":"g"},{"name":"Oignon vert ciselé","unit":"g"},{"name":"Saindoux","unit":"g"},{"name":"Huile de sésame","unit":"g"}]'::jsonb, '["Couper l''anguille en trois morceaux, puis en fines lanières.","Ajouter 0.5 g de poivre moulu, 3 g de vin de cuisson, mélanger, puis ajouter 5 g d''huile de sésame et laisser mariner.","Chauffer de l''huile et huiler la poêle.","Ajouter de l''huile végétale et chauffer à feu moyen-vif (environ 60% de la chaleur maximale).","Ajouter la moitié de l''ail haché et tout le gingembre haché, faire sauter quelques fois.","Ajouter les lanières d''anguille, faire sauter à feu moyen-vif pendant 30 secondes.","Verser 10 g de vin de cuisson sur les bords, faire sauter quelques fois.","Ajouter la sauce soja légère, mélanger.","Ajouter la sauce d''huître et la sauce soja foncée, faire sauter quelques fois.","Ajouter le sel, le sucre blanc, 3 g de poivre moulu, mélanger.","Mélanger la fécule et l''eau pour faire un slurry, verser dans la poêle et laisser épaissir.","Dresser dans une assiette, saupoudrer d''ail haché et d''oignon vert ciselé.","Dans une autre poêle, chauffer le saindoux jusqu''à ce qu''il soit à 70% de chaleur, puis verser sur les lanières d''anguille."]'::jsonb, '["Poisson","Jiangsu-Zhejiang-Shanghai","Frais et parfumé","Légèrement sucré","Sauté à feu vif","Accompagnement du riz"]'::jsonb),
  ('howtocook:aquatic/小龙虾/小龙虾', 'fr', 'Écrevisses', 'Fruits de mer', 'Ce plat est épicé et parfumé, la chair des écrevisses est tendre et juteuse. C''est un classique des cuisines du Sichuan et du Hunan, parfait pour accompagner l''alcool. Fait maison, c''est propre et économique. Les écrevisses sont riches en protéines de qualité et en oligo-éléments, mais la sauce contient beaucoup d''huile et de sel, donc à consommer avec modération. Manipuler des écrevisses vivantes et plusieurs épices peut être un défi pour les débutants, mais ne pas retirer le boyau intestinal réduit considérablement la difficulté. De la préparation à la cuisson, il faut environ 45 minutes.', '[{"name":"Écrevisses","unit":"livre"},{"name":"Huile","unit":"ml"},{"name":"Feuilles de laurier","unit":"feuille"},{"name":"Anis étoilé","unit":"pièce"},{"name":"Cannelle","unit":"g"},{"name":"Poivre vert du Sichuan","unit":"g"},{"name":"Poivre du Sichuan","unit":"g"},{"name":"Piments ''zi dan tou''","unit":"g"},{"name":"Oignon vert","unit":"tige"},{"name":"Gingembre","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Pâte de fèves de Pixian","unit":"g"},{"name":"Pâte de soja jaune","unit":"g"},{"name":"Bière","unit":"ml"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sel","unit":"g"}]'::jsonb, '["Brosser les écrevisses et retirer le boyau intestinal. Couper les oignons verts en tronçons de 2 cm. Hacher le gingembre et l''ail.","Chauffer l''huile. Quand elle est tiède, ajouter les feuilles de laurier, l''anis étoilé, la cannelle, le poivre vert du Sichuan, le poivre du Sichuan et les piments séchés (type ''zi dan tou'').","Une fois les épices parfumées, ajouter l''oignon vert, le gingembre et l''ail dans la poêle.","Après avoir fait sauter l''oignon, le gingembre et l''ail, ajouter la pâte de fèves de Pixian et la pâte de soja jaune. Faire revenir jusqu''à l''obtention d''une huile rouge.","Ajouter les écrevisses et faire sauter jusqu''à ce qu''elles changent de couleur.","Ajouter la bière. Porter à ébullition, puis ajouter la sauce soja légère et le sel.","Laisser cuire jusqu''à ce que les écrevisses soient bien cuites, puis retirer du feu."]'::jsonb, '["Fruits de mer","Épicé et numbing","Parfumé","Sichuan-Hunan","Accompagnement pour alcool","Maison"]'::jsonb),
  ('howtocook:aquatic/干煎阿根廷红虾/干煎阿根廷红虾', 'fr', 'Crevettes rouges d''Argentine poêlées à sec', 'Fruits de mer', 'Un plat de fruits de mer rapide et délicieux. Après la cuisson, les crevettes rouges d''Argentine ont une chair blanche et tendre, une saveur sucrée et riche, et la carapace est croustillante. Riches en iode, phosphore et astaxanthine, elles aident à renforcer l''immunité, protéger le cœur et réduire le cholestérol. Difficulté moyenne : il faut maîtriser la cuisson et le retournement, mais les étapes sont claires, même un débutant peut réussir. Temps prévu : environ 20 minutes.', '[{"name":"Crevettes rouges d''Argentine (surgelées)","unit":"pièces"},{"name":"Sel de mer (à moudre)","unit":"g"},{"name":"Poivre noir (à moudre)","unit":"","note":"quantité suffisante"},{"name":"Vin blanc","unit":"ml"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Coriandre","unit":"feuilles"},{"name":"Citron","unit":"tranches"},{"name":"Oignon","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Ail","unit":"g"}]'::jsonb, '["Décongeler les crevettes rouges d''Argentine, idéalement les sortir du congélateur 1 jour à l''avance et les mettre au réfrigérateur pour une décongélation naturelle, ce qui préserve mieux la saveur et la texture. On peut acheter des crevettes déjà nettoyées (dos ouvert et veine retirée) pour gagner du temps.","Laver et essuyer les crevettes décongelées, veiller à bien les égoutter. Si pressé, utiliser du papier absorbant pour sécher.","Couper le gingembre en tranches, l''oignon en petits dés. Laver la coriandre, séparer les feuilles des tiges, hacher les feuilles. Écraser et hacher l''ail en petits morceaux.","Chauffer la poêle à feu vif, ajouter deux cuillères à soupe d''huile d''olive. Quand l''huile est chaude, ajouter les tranches de gingembre, les dés d''oignon et les tiges de coriandre, faire revenir.","Au bout d''environ 1 minute, retirer le gingembre, l''oignon et les tiges de coriandre, les jeter.","Passer à feu moyen-vif, ajouter les crevettes et commencer à les poêler. Veiller à ce que chaque crevette soit en contact complet avec la poêle sur une face. Poêler environ 2 minutes, tout en badigeonnant chaque crevette d''un peu d''huile.","Lorsque la face inférieure des crevettes est légèrement dorée, les retourner. Saupoudrer d''ail haché, secouer légèrement la poêle pour une cuisson uniforme.","Au bout d''environ 1 minute, ajouter 20 ml de vin blanc.","Poêler encore 1 minute, puis réduire à feu moyen-doux. Saupoudrer uniformément d''une couche de sel et de poivre noir.","Ajouter une goutte de sauce soja claire sur chaque crevette.","Saupoudrer de feuilles de coriandre, dresser dans l''assiette.","Couper des tranches de citron, les disposer sur le bord de l''assiette."]'::jsonb, '["Fruits de mer","Savoureux","Poêlé à sec","Rapide","Maison"]'::jsonb),
  ('howtocook:aquatic/微波葱姜黑鳕鱼', 'fr', 'Cabillaud noir au micro-ondes avec oignons verts et gingembre', 'Fruits de mer', 'Cuisson au micro-ondes, l''oignon vert et le gingembre rehaussent la saveur, un filet d''huile chaude et le parfum se répand. C''est un plat de poisson cuit à la vapeur fait maison, à la chair tendre et au goût salé et frais, une version améliorée du style cantonais. Le cabillaud noir est riche en protéines de haute qualité et en acides gras oméga-3, bénéfiques pour la santé cardiaque et cérébrale. L''opération n''est pas compliquée, mais il faut maîtriser le feu et la température de l''huile, plus adapté aux cuisiniers ayant un peu d''expérience. De la préparation à la table, il ne faut qu''environ vingt minutes.', '[{"name":"Cabillaud noir (avec peau)","unit":"g"},{"name":"Oignon vert (blanc)","unit":"g"},{"name":"Oignon vert (vert)","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Vin de cuisine","unit":"mL"},{"name":"Sauce soja","unit":"mL"},{"name":"Huile de sésame","unit":"mL"},{"name":"Huile d''arachide","unit":"mL"}]'::jsonb, '["Placez chaque filet de poisson dans un sac de congélation, peau vers le bas, sur une assiette.","Prenez 25g de blanc d''oignon vert, coupez en julienne, 10g de gingembre pelé et coupé en julienne, mélangez et divisez en deux, déposez sur les filets dans les sacs.","Versez 2.5 mL de vin de cuisine dans chaque sac.","Fermez hermétiquement les sacs, placez-les au micro-ondes et faites cuire à puissance moyenne (800 W) jusqu''à ce que le poisson soit opaque et se défasse facilement (environ 3.5 à 5 minutes). Sortez les filets des sacs.","Retirez l''oignon vert et le gingembre.","Mélangez 25 mL de sauce soja et 2 mL d''huile de sésame, puis versez uniformément sur les deux filets.","Prenez 10g de vert d''oignon vert coupé en fine julienne, 3g de gingembre pelé et coupé en julienne, mélangez et divisez en deux, saupoudrez sur les filets.","Faites chauffer 50 mL d''huile d''arachide dans une petite casserole jusqu''à 190°C.","Versez l''huile chaude sur les filets garnis de vert d''oignon, servez immédiatement."]'::jsonb, '["Poisson","Savoureux","Micro-ondes","Cantonais","Fait maison","Rapide","Pour invités"]'::jsonb),
  ('howtocook:aquatic/水煮鱼', 'fr', 'Poisson poché à l''eau', 'Fruits de mer', 'Le poisson poché à l''eau est un plat classique du Sichuan, épicé et parfumé, avec une chair tendre. Le poisson basa est riche en protéines de haute qualité et faible en matières grasses, associé à des légumes de saison pour un équilibre nutritionnel. La difficulté est moyenne, un défi pour les débutants mais réalisable en suivant les étapes. Temps de préparation estimé : environ 2 heures.', '[{"name":"Poisson basa","unit":"g"},{"name":"Légumes (ex: pommes de terre en tranches, germes de soja, chou-fleur, laitue, etc.)","unit":"g"},{"name":"Pâte de haricots chili à l''huile rouge","unit":"g"},{"name":"Douchi (optionnel)","unit":"g"},{"name":"Huile de poivre vert","unit":"ml"},{"name":"Huile de colza","unit":"ml"},{"name":"Poivre blanc moulu","unit":"g"},{"name":"Gousses d''ail","unit":"gousse"},{"name":"Sel","unit":"g"},{"name":"Sucre","unit":"g"},{"name":"Eau chaude","unit":"ml"}]'::jsonb, '["Préparation : si le poisson basa est sorti du congélateur, laisser décongeler à température ambiante pendant 5 heures avant de le trancher.","Trancher : couper le poisson basa en fines tranches d''environ 5 cm de long sur 3 cm de large.","Marinade : mettre les tranches de poisson dans un grand bol en inox.","Ajouter 30 g de pâte de haricots chili, 3 g de sel, 10 ml d''huile de poivre vert, 3 g de poivre blanc moulu.","Mélanger avec les mains, puis ajouter 5 ml d''huile de colza pour sceller les saveurs.","Laisser mariner à température ambiante pendant au moins 30 minutes.","Préparation des légumes : hacher l''ail. Pour l''exemple, 300 g de chou-fleur et 200 g de laitue, laver le chou-fleur et la laitue.","Blanchir et sauter : blanchir le chou-fleur dans l''eau bouillante et réserver; laver et sécher la laitue, la faire revenir sans huile et réserver.","Faire revenir la pâte de haricots : chauffer la poêle avec 20 ml d''huile de colza, ajouter 10 g de pâte de haricots chili, 10 g de douchi (optionnel), ajouter l''ail haché, faire revenir à feu moyen.","Pocher les filets de poisson : ajouter 150 ml d''eau chaude, porter à ébullition, ajouter les tranches de poisson marinées, remuer doucement pour les séparer, ajouter 2 g de sel et 2 g de sucre pour assaisonner (ajuster le sel selon le goût). Dès que l''eau bout à nouveau, égoutter et servir.","Dressage : mettre d''abord les légumes cuits dans un grand bol, puis disposer le poisson chaud par-dessus, arroser du bouillon chaud restant dans la poêle. C''est prêt !"]'::jsonb, '["Poisson","Épicé","Parfumé","Sichuan","Maison","Accompagne le riz"]'::jsonb),
  ('howtocook:aquatic/油焖大虾/油焖大虾', 'fr', 'Crevettes braisées à l''huile', 'Fruits de mer', 'Ce grand classique de la cuisine du Shandong enrobe les crevettes entières d''une sauce salée-sucrée. Le plat final est rouge vif et huileux, la chair des crevettes est ferme et élastique. Les crevettes sont riches en protéines de qualité et en astaxanthine, faibles en matières grasses, ce qui en fait un ingrédient nutritif sans alourdir. La préparation nécessite de faire de l''huile d''oignon, de couper les crevettes, de les braiser et de réduire la sauce, ce qui demande une certaine maîtrise du feu et de l''assaisonnement. Convient mieux aux cuisiniers expérimentés. L''ensemble prend environ 40 minutes.', '[{"name":"Crevettes tigrées / crevettes roses","unit":"pièce"},{"name":"Poivre du Sichuan","unit":"gramme"},{"name":"Oignon vert","unit":"gramme"},{"name":"Gingembre","unit":"gramme"},{"name":"Vin de cuisine","unit":"gramme"},{"name":"Eau","unit":"petit bol"},{"name":"Sel","unit":"gramme"},{"name":"Sucre candi","unit":"gramme"},{"name":"Huile végétale","note":"quantité suffisante"}]'::jsonb, '["Couper les antennes des crevettes à la base, retirer les barbes et les pattes. Enlever la poche de sable. Inciser le dos et retirer le fil intestinal. Laver et réserver.","Préparer l''huile aromatisée","À feu moyen (3/10 de la température maximale), ajouter le poivre du Sichuan. Lorsque l''huile est chaude, retirer du feu, ajouter l''oignon vert et le gingembre (il est préférable que l''huile ne change pas de couleur). Lorsque l''oignon devient légèrement jaune, égoutter l''huile (l''excédent d''huile d''oignon peut être conservé pour assaisonner des nouilles).","Verser l''huile, disposer les crevettes bien rangées. Lorsque les deux côtés ont changé de couleur, presser légèrement la tête des crevettes.","Ajouter le gingembre haché fin (gingembre coupé en très petits morceaux)","Vin de Shaoxing 30 g","Eau deux petits bols","Sel 3 g","Sucre candi 10 g","Porter à ébullition à feu vif, puis baisser à feu doux et couvrir pour mijoter (ne pas ajouter de liquide en cours de route, ne pas ouvrir le couvercle).","Lorsque la peau est brillante et les crevettes courbées, retirer du feu. Disposer les crevettes sur l''assiette.","Réduire la sauce (après filtrage, remettre dans la casserole pour réduire, ajouter de l''huile d''oignon). Lorsqu''il ne reste qu''1/4 du liquide.","Verser la sauce","Terminé","Crevettes braisées à l''huile - aperçu 1","Bon appétit ✅"]'::jsonb, '["Fruits de mer","Shandong","Salé-sucré","Braiser","Familial","Réception","Savoureux"]'::jsonb),
  ('howtocook:aquatic/混合烤鱼/烤鱼', 'fr', 'Poisson grillé', 'Fruits de mer', 'Cette recette de poisson grillé sichuanaise est épicée et parfumée, la chair du poisson est croustillante à l''extérieur et tendre à l''intérieur, les légumes d''accompagnement imbibés de sauce sont délicieux avec du riz. La carpe herbivore est riche en protéines de qualité, associée à une variété de légumes, offrant un équilibre nutritionnel. La préparation semble complexe, mais en suivant les étapes ce n''est pas difficile, parfait pour les débutants qui veulent relever un défi. Du début à la table, cela prend environ une heure.', '[{"name":"Carpe herbivore","unit":"livre"},{"name":"Poireau","unit":"tige"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Poivre blanc moulu","unit":"g"},{"name":"Cannelle","note":"un petit morceau"},{"name":"Anis étoilé","unit":"pièce"},{"name":"Ail","unit":"gousse"},{"name":"Feuilles de laurier","unit":"feuille"},{"name":"Poivre du Sichuan vert","note":"une petite poignée"},{"name":"Piments séchés","unit":"pièce"},{"name":"Piments lanternes","unit":"pièce"},{"name":"Céleri","unit":"tige"},{"name":"Oignon","unit":"pièce"},{"name":"Feuilles de tofu séché","unit":"feuille"},{"name":"Germes de soja vert","note":"quantité suffisante"},{"name":"Pâte de haricots épicée","unit":"g"},{"name":"Sucre","unit":"g"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Cumin moulu","note":"quantité suffisante"},{"name":"Cacahuètes grillées","note":"quantité suffisante"},{"name":"Graines de sésame blanches","note":"quantité suffisante"},{"name":"Oignons verts émincés","note":"quantité suffisante"},{"name":"Coriandre fraîche","note":"selon votre goût, facultatif"}]'::jsonb, '["La carpe (environ 1,5 kg) est fendue du dos, incisez les deux côtés le long du dos sans traverser le ventre pour qu''elle garde sa forme.","Arrosez le poisson d''eau chaude pour enlever le mucus, ou frottez-le sous l''eau courante jusqu''à ce qu''il ne soit plus glissant.","Placez le poisson dans un récipient, ajoutez le vin de cuisine, 10 g de poivre blanc moulu, 5 g de sel, mélangez et laissez mariner 20 minutes.","Coupez une demi-tige de poireau en morceaux, coupez les gousses d''ail en deux, mettez-les avec les étoiles d''anis, la cannelle et les feuilles de laurier dans un récipient.","Coupez les piments séchés en deux dans le sens de la longueur et mettez-les avec les piments lanternes dans un récipient.","Coupez le céleri en petits morceaux.","Blanchissez les germes de soja.","Blanchissez les feuilles de tofu séché et coupez-les en lanières.","Coupez l''oignon en rondelles.","Cuire le poisson au four ou à la poêle.","Si vous avez un four, huilez la plaque, mettez le poisson peau vers le bas, faites cuire jusqu''à ce qu''il soit doré des deux côtés, puis saupoudrez de cumin moulu.","Sans four, faites chauffer l''huile dans une poêle, saupoudrez 2 g de sel sur les bords, déposez le poisson, ne le bougez pas avant qu''un côté soit doré, puis retournez-le, faites cuire jusqu''à dorure, saupoudrez de cumin moulu, mettez dans une assiette.","Dans la poêle, versez 20 ml d''huile, quand elle est chaude, faites revenir le poireau, l''ail, l''anis étoilé et la cannelle.","Ajoutez la moitié d''un paquet de fondue de Sichuan et 15-20 g de pâte de haricots, faites revenir jusqu''à ce que l''huile devienne rouge.","Ajoutez 5 g de sucre, 10 g de sel, 5 ml de sauce soja légère, versez de l''eau à hauteur des ingrédients, portez à ébullition.","Ajoutez successivement le céleri, les germes de soja, les lanières de tofu séché, ne les cuisez pas complètement, juste les blanchir, puis disposez les rondelles d''oignon, placez le poisson grillé dessus.","Ajoutez les piments séchés, les piments lanternes, le poivre du Sichuan vert.","Faites chauffer de l''huile dans une autre casserole, versez-la sur les piments pour libérer les arômes.","Parsemez de cacahuètes grillées, d''oignons verts émincés, de graines de sésame blanches, de coriandre.","Cuisez 5 à 6 minutes, puis servez."]'::jsonb, '["Poisson","Épicé","Parfumé","Accompagnement du riz","Cuisine sichuanaise","Grillé","Pour invités"]'::jsonb),
  ('howtocook:aquatic/清蒸生蚝', 'fr', 'Huîtres cuites à la vapeur', 'Fruits de mer', 'Les huîtres cuites à la vapeur sont un plat familial côtier authentique. La chair est tendre et juteuse, avec une légère saveur salée de la mer. L''ail et le gingembre relèvent la douceur. Les huîtres sont riches en protéines de qualité et en zinc, ce qui aide à renforcer l''immunité. L''opération n''est pas compliquée, mais il faut faire attention en soulevant le couvercle chaud et en manipulant les coquilles. Même un débutant peut y arriver. Du nettoyage à la cuisson, environ vingt minutes.', '[{"name":"huîtres","unit":"pièces"},{"name":"ciboule","unit":"pièce"},{"name":"ail","unit":"gousse"},{"name":"gingembre","unit":"petit morceau"},{"name":"sauce soja","unit":"ml"}]'::jsonb, '["Brossez les huîtres (si pas de brosse, utilisez une brosse à dents).","Mettez de l''eau dans le cuiseur vapeur, placez le panier, puis disposez les 6 huîtres à plat sur le panier. Faites cuire à 50% de puissance pendant 3 minutes.","Avec la main droite, utilisez un torchon humide pour soulever le couvercle chaud. Ouvrez chaque huître à moitié et enlevez la coquille supérieure. Placez la partie bombée vers le bas, la partie plate vers le haut. Ajoutez 1 filament de gingembre et 10g d''ail haché sur chaque huître.","Refermez le couvercle chaud. Faites cuire à 100% de puissance pendant 3,5 minutes.","Éteignez le feu. Avec la main droite, utilisez un torchon pour soulever le couvercle chaud. Ajoutez 5 ml de sauce soja sur chaque huître.","Dressez dans un plat."]'::jsonb, '["Fruits de mer","Vapeur","Fruits de mer","Léger","Familial","Rapide"]'::jsonb),
  ('howtocook:aquatic/清蒸鲈鱼/清蒸鲈鱼', 'fr', 'Bar vapeur', 'Fruits de mer', 'Le bar vapeur est un plat de vapeur classique cantonais. La chair du poisson est tendre et lisse, la saveur est légère et délicieuse, maximisant la saveur naturelle du bar. Le bar est riche en protéines de haute qualité et en DHA, nutritif et facile à digérer. Ce plat est simple à réaliser, très accessible aux débutants, et prend environ trente minutes de la préparation à la cuisson.', '[{"name":"Bar","unit":"pièce"},{"name":"Oignons verts","unit":"tige"},{"name":"Gingembre","unit":"morceau"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sauce soja pour poisson vapeur","unit":"ml"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Sel","unit":"g"}]'::jsonb, '["Couper le gingembre en tranches puis en filaments, couper le blanc des oignons verts en tronçons et le vert en filaments. Tremper les filaments dans de l''eau froide et réserver.","Nettoyer le bar, l''essuyer avec du papier absorbant. Faire quelques entailles sur chaque face. Frotter le poisson avec du sel pour enlever le mucus, puis saler l''intérieur et l''extérieur avec 10 g de sel. Laisser mariner au moins 10 minutes.","Ajout d''une méthode de découpe et de présentation : après la découpe, le bar peut être cuit à la vapeur debout pour une cuisson uniforme et plus facile à manger sans avoir à le retourner.","Découpe","清蒸鲈鱼-预览图-2","Farcir l''intérieur du poisson avec du gingembre et du blanc d''oignon vert, et en parsemer également sur le corps. Utiliser la moitié de la quantité réservée. Placer des baguettes dans le plat de cuisson pour surélever le poisson et le cuire à la vapeur.","Porter l''eau à ébullition, puis ajouter le poisson.","Cuire à la vapeur à feu vif pendant 10 minutes.","Retirer le poisson cuit, le mettre dans un plat propre et enlever le gingembre et l''oignon vert.","Verser 15 ml de sauce soja pour poisson vapeur sur le poisson.","Parsemer de nouveau de filaments de gingembre et d''oignon vert. Chauffer 10 ml d''huile de cuisson dans une casserole, puis verser l''huile chaude sur le poisson. Servir."]'::jsonb, '["Poisson","Vapeur","Cantonnais","Léger","Tendre","Maison"]'::jsonb),
  ('howtocook:aquatic/白灼虾/白灼虾', 'fr', 'Crevettes blanchies', 'Fruits de mer', 'Les crevettes blanchies sont un plat classique cantonais rapide, la chair des crevettes est sucrée, ferme et tendre, avec un goût authentique. Les crevettes sont riches en protéines de haute qualité et en plusieurs minéraux, la sauce d''accompagnement ouvre l''appétit sans être grasse. La préparation est simple et tolérante aux erreurs, très accessible aux débutants, il faut environ 15 minutes de la préparation à la cuisson.', '[{"name":"Crevettes vivantes","unit":"g"},{"name":"Oignon","unit":"pièce"},{"name":"Gingembre","unit":"morceau"},{"name":"Ail","unit":"gousse"},{"name":"Oignon vert","unit":"tige"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sauce soja","unit":"ml"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Graines de sésame","note":"une poignée"},{"name":"Vinaigre de riz","unit":"ml"},{"name":"Sauce d''huître","unit":"ml"}]'::jsonb, '["Couper l''oignon en petits morceaux, couper le gingembre en tranches, étaler au fond de la poêle.","Rincer rapidement les crevettes vivantes (retirer les veines, couper les pattes et les antennes avec des ciseaux sont facultatifs), égoutter, disposer sur les oignons et le gingembre dans la poêle.","Verser le vin de cuisine dans la poêle, couvrir, cuire à feu moyen pendant 1 minute, puis à feu doux pendant 5 minutes, éteindre le feu et laisser reposer 5 minutes.","Parallèlement à l''étape précédente, préparer la sauce d''accompagnement :","Hacher l''oignon vert en ciboule, hacher l''ail, ajouter la sauce soja, les graines de sésame et le vinaigre de riz, mélanger.","Faire chauffer l''huile, puis l''arroser sur la sauce.","Sortir les crevettes de la poêle et les disposer dans un plat propre."]'::jsonb, '["Fruits de mer","Cantonais","Frais et savoureux","Rapide","Fait maison"]'::jsonb),
  ('howtocook:aquatic/糖醋鲤鱼/糖醋鲤鱼', 'fr', 'Carpe à l''aigre-douce', 'Fruits de mer', 'La carpe à l''aigre-douce est un plat classique de la cuisine du Shandong. Elle est croustillante à l''extérieur et tendre à l''intérieur, avec une sauce aigre-douce brillante et appétissante. Le poisson est riche en protéines de haute qualité et en minéraux, faciles à digérer. Cette recette est d''un niveau intermédiaire à avancé, nécessitant de maîtriser les techniques de découpe, d''enrobage et de friture. Du début à la fin, il faut compter environ 1 heure.', '[{"name":"Carpe","unit":"livre"},{"name":"Ketchup","unit":"grammes"},{"name":"Sucre blanc","unit":"grammes"},{"name":"Vinaigre blanc","unit":"grammes"},{"name":"Fécule de maïs","unit":"grammes"},{"name":"Sel","unit":"grammes"},{"name":"Oignon vert","unit":"grammes"},{"name":"Gingembre","unit":"grammes"},{"name":"Vin de cuisine","unit":"grammes"},{"name":"Coriandre","unit":"bouquet"},{"name":"Farine","unit":"grammes"},{"name":"Œuf","unit":"pièce"},{"name":"Eau claire","unit":"grammes"},{"name":"Huile de cuisson","unit":"litre"}]'::jsonb, '["Nettoyez soigneusement le poisson, en vous assurant qu''il ne reste pas d''écailles ou d''impuretés.","Placez le poisson tête à gauche, ventre vers le bas, tenez le couteau de la main droite. Coupez verticalement à 1 cm de profondeur, en appuyant sur le corps du poisson, puis tranchez vers la gauche sur 3-4 cm. Faites une légère incision au milieu de la tranche.","Mettez le poisson dans un bol. Coupez le gingembre en tranches et l''oignon vert en tronçons (coupez-les simplement, ils serviront à désodoriser).","Pressez vigoureusement le jus du gingembre et de l''oignon dans le bol.","Ajoutez 20 g de sel et 25 g de vin de cuisine, puis frottez bien la carpe pour enrober uniformément.","Laissez mariner.","Dans un bol propre, mélangez 100 g de farine, 200 g de fécule de maïs, 180 g d''eau et 5 g de sel. Mélangez à la main jusqu''à obtenir une pâte épaisse et filante. Ajoutez un œuf et mélangez à nouveau.","Attendez 30 minutes.","Placez le poisson sur une planche à découper et essuyez-le avec un torchon sec (pour une meilleure adhérence de la pâte).","Rincez le bol et essuyez-le avec un torchon sec.","Chauffez environ 1 L d''huile dans une poêle ou un wok. Portez l''huile à 70 % de sa capacité de chauffe, soit environ 200-240 °C.","Tenez le poisson par la queue, plongez la tête dans l''huile. Arrosez le corps d''huile chaude avec une louche. Une fois la pâte figée, déposez délicatement le poisson dans l''huile. Soulevez légèrement la tête avec une spatule et placez une écumoire en dessous pour éviter que le fond ne brûle.","Préparez un plat pour le poisson, à côté de la poêle.","À l''aide d''une spatule, soulevez doucement le corps du poisson pour le retourner (en utilisant les deux ustensiles). Faites frire encore 2 minutes. Sortez le poisson de la même manière (écumoire sous la tête, spatule sous le corps) et déposez-le dans le plat.","Versez l''huile de la poêle dans un bol résistant à la chaleur et réservez. Nettoyez la poêle.","Dans un petit bol, mélangez 50 g d''eau claire, 40 g de ketchup, 20 g de sucre blanc et 10 g de vinaigre blanc. Remuez bien.","Préparez un autre petit bol avec 10 g de fécule de maïs et 10 g d''eau, mélangez pour obtenir une sauce à la fécule.","Chauffez la poêle à feu vif, versez le mélange de sauce préparé. Portez à ébullition à feu vif, puis réduisez à feu doux.","Ajoutez la sauce à la fécule en remuant constamment. Après 20 secondes, éteignez le feu.","Versez la sauce aigre-douce uniformément sur le poisson avec une louche. Vous pouvez décorer avec de la coriandre ou de l''oignon vert. La carpe à l''aigre-douce est prête.","Image de la carpe à l''aigre-douce - 2"]'::jsonb, '["Poisson","Aigre-doux","Friture","Cuisine du Shandong","Pour invités","Réveillon du Nouvel An"]'::jsonb),
  ('howtocook:aquatic/红烧鱼', 'fr', 'Poisson braisé à la sauce rouge', 'Fruits de mer', 'Le poisson braisé à la sauce rouge est un plat classique au goût familial prononcé, salé et légèrement sucré, avec une chair tendre et savoureuse. C''est un plat chinois cuit à l''étouffée apprécié de tous. Le poisson est riche en protéines de haute qualité et en acides gras insaturés, faciles à absorber. La préparation nécessite de manipuler du poisson cru et de le frire, avec plusieurs étapes, ce qui peut être un défi pour les débutants, mais en suivant la recette, on peut réussir. Du début à la fin, il faut environ 40 minutes.', '[{"name":"Gingembre","unit":"tranches"},{"name":"Gousses d''ail","unit":"pièces"},{"name":"Piments séchés","unit":"pièces"},{"name":"Huile","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Vin de cuisson","note":"quantité suffisante"},{"name":"Vinaigre","unit":"ml"},{"name":"Sauce soja","unit":"ml"},{"name":"Sucre blanc","unit":"g"},{"name":"Poisson","unit":"pièce"},{"name":"Sauce d''huître","unit":"g"},{"name":"Oignons verts","unit":"tiges"},{"name":"Coriandre","note":"selon le goût"},{"name":"Petits piments rouges"},{"name":"MSG (bouillon de poule)","unit":"g"}]'::jsonb, '["Préparez le gingembre et l''ail, hachez-les finement.","Hachez les piments séchés et mettez-les avec le gingembre et l''ail.","Ajoutez 30 à 50 ml d''huile et attendez que la poêle soit chaude...","Déposez le poisson bien essuyé (pour éviter les éclaboussures d''huile), puis secouez la poêle pour faire frire le poisson à l''huile chaude. Assurez-vous de cuire à feu doux.","Retournez le poisson et répétez le processus de friture.","Ajoutez le gingembre, l''ail et les piments, faites sauter jusqu''à ce qu''ils dégagent une odeur aromatique.","Versez le vin de cuisson, un peu plus que d''habitude. Faites attention, cela produira beaucoup de fumée.","Versez le vinaigre (vous pouvez en mettre un peu plus si vous aimez).","Ajoutez ensuite le sucre blanc et la sauce soja (vieille sauce).","Ajoutez de l''eau froide, juste assez pour couvrir le poisson. Puis réglez sur feu moyen, couvrez et laissez cuire environ 1 minute avant de retourner le poisson, puis recouvrez.","Après 3 à 4 minutes, ajoutez le sel, les petits piments rouges, la sauce d''huître (MSG, bouillon de poule...), puis recouvrez. Continuez à retourner le poisson plus tard.","Lorsque la sauce a réduit jusqu''à atteindre juste en dessous des nageoires dorsales (ou quand il reste peu de sauce), baissez le feu, ajoutez la coriandre et les oignons verts, couvrez pendant 20 secondes, puis éteignez le feu.","Dressez dans un plat."]'::jsonb, '["Poisson","Braiser","Salé et sucré","Frire et braiser","Familial","Accompagne bien le riz"]'::jsonb),
  ('howtocook:aquatic/红烧鱼头', 'fr', 'Tête de poisson braisée au soja', 'Fruits de mer', 'La tête de poisson braisée au soja est un plat familial classique. La tête de poisson est riche en collagène, sa chair est tendre et la sauce salée, légèrement épicée, accompagne parfaitement le riz. Riche en protéines de qualité, lécithine et acides gras insaturés, elle est bénéfique pour la peau et le cerveau. La préparation nécessitant de manipuler du poisson cru et de le découper, le niveau de difficulté est un peu plus élevé; il est déconseillé aux débutants complets de s''y essayer seuls. Le temps total (incluant la marinade) est d''environ 2 à 2,5 heures.', '[{"name":"Tête de poisson","unit":"pièce"},{"name":"Poireau (oignon vert géant)","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Piment de beauté","unit":"pièce"},{"name":"Coriandre fraîche","unit":"tige"},{"name":"Anis étoilé","unit":"pièce"},{"name":"Piment séché","unit":"pièce"},{"name":"Huile","unit":"ml"},{"name":"Sel (pour mariner)","unit":"g"},{"name":"Sel (pour cuisson)","unit":"g"},{"name":"Sauce soja claire (pour mariner)","unit":"g"},{"name":"Sauce soja claire (pour cuisson)","unit":"g"},{"name":"Vin de cuisine (pour mariner)","unit":"g"},{"name":"Vin de cuisine (pour cuisson)","unit":"g"},{"name":"Bouillon de poulet en poudre","unit":"g"},{"name":"Sauce soja foncée","unit":"g"},{"name":"Vinaigre vieux","unit":"g"},{"name":"Poivre noir moulu","unit":"g"},{"name":"Eau claire","unit":"ml"}]'::jsonb, '["Laver séparément l''oignon vert, le gingembre, l''ail, la coriandre et le piment de beauté.","Rincer rapidement le piment séché et l''anis étoilé.","Couper l''oignon vert en deux. La moitié arrière (partie blanche) en tronçons d''environ 4 cm. La moitié avant (partie verte) d''abord en tronçons, puis fendre chaque tronçon en quatre.","Trancher le gingembre en tranches d''environ 3 mm d''épaisseur.","Écraser l''ail.","Prendre deux brins de coriandre, couper les racines, puis hacher en morceaux de 1,5 cm.","Couper le piment de beauté en rondelles de 3 mm d''épaisseur.","Couper le piment séché en quatre morceaux.","NB : Le corps du poisson mentionné ci-dessous est la chair attachée lors de l''achat de la tête.","Écailler la tête de poisson, nettoyer les viscères non retirés.","Couper les nageoires et retirer les branchies.","Séparer la mâchoire inférieure du corps, couper le corps en morceaux, fendre la tête en quatre ou six parts.","NB : Il est difficile d''expliquer entièrement le traitement du poisson par écrit ; chercher des vidéos sur le sujet.","Laver les morceaux de poisson, idéalement pour enlever le sang résiduel.","Mettre les morceaux propres dans un bol, ajouter 5g de sel, 10g de sauce soja claire, 10g de vin de cuisine. Ajouter l''oignon vert (la moitié avant hachée) et 1/3 des tranches de gingembre. Mélanger et laisser reposer 1 à 2 heures.","Ajouter 30ml d''huile, attendre que la poêle chauffe...","Huile chaude, réduire le feu à doux.","Si vous ne comprenez pas pourquoi, consultez la section ''Apprendre à sauter et frire : faire revenir les aromates''.","Ajouter les tranches de gingembre, faire revenir doucement jusqu''à ce que la plupart du jus soit extrait et qu''elles soient dorées.","Ajouter les tronçons d''oignon vert, faire revenir jusqu''à ce qu''ils blanchissent légèrement.","Ajouter l''ail écrasé, l''anis étoilé et le piment séché, faire revenir 5 secondes.","Verser la tête de poisson marinée dans la poêle, faire revenir 2 à 3 minutes.","Ajouter 500ml d''eau claire, 2g de sel, 3g de bouillon de poulet en poudre, 5g de sauce soja claire, 3g de sauce soja foncée, 5g de vin de cuisine, 2g de poivre noir moulu, 3g de vinaigre vieux.","Mettre deux brins de coriandre entiers dans la poêle, couvrir.","Augmenter le feu à vif pour porter à ébullition.","Réduire le feu à moyen, laisser mijoter doucement pour imprégner les saveurs.","Quand la sauce a réduit de moitié, retirer le couvercle.","Passer à feu vif pour faire réduire la sauce; lorsqu''il en reste environ un tiers, éteindre le feu et verser dans un petit plat.","NB : Verser uniformément la sauce de la poêle sur la tête de poisson; au moment de servir, placer la coriandre cuite au fond du plat pour un aspect et un goût améliorés.","Déposer la coriandre fraîche sur la tête de poisson, puis disposer les rondelles de piment de beauté dessus.","La tête de poisson braisée au soja, parfaite en couleur, arôme et goût, est prête !"]'::jsonb, '["Produits aquatiques","Braisé au soja","Salé et frais","Légèrement épicé","Mijoté","Accompagnement de riz","Famille"]'::jsonb),
  ('howtocook:aquatic/红烧鲤鱼', 'fr', 'Carpe braisée à la sauce rouge', 'Fruits de mer', 'La carpe braisée à la sauce rouge est un plat familial de la cuisine du Shandong. Le poisson est d''abord frit puis mijoté, la peau est légèrement ferme, la chair tendre, avec une saveur salée-sucrée et une sauce parfumée, rehaussée par la richesse de la poitrine de porc. La sauce épaisse accompagne bien le riz. Riche en protéines de haute qualité et en minéraux comme le calcium et le phosphore, il est nutritif. La friture du poisson et l''équilibre des assaisonnements demandent un peu de patience, mais les étapes sont claires et même un débutant peut y arriver. De la préparation à la sortie du plat, compter environ 1 heure.', '[{"name":"carpe","unit":"livre"},{"name":"poitrine de porc","unit":"gramme"},{"name":"oignon vert","unit":"gramme"},{"name":"gingembre","unit":"gramme"},{"name":"gousse d''ail","unit":"gousse"},{"name":"piment séché","unit":"pièce"},{"name":"huile","note":"quantité suffisante"},{"name":"sel","unit":"gramme"},{"name":"sauce soja claire","unit":"ml"},{"name":"sauce soja foncée","unit":"ml"},{"name":"vinaigre noir","unit":"ml"},{"name":"sauce d''huître","unit":"ml"},{"name":"vin de cuisine","unit":"ml"},{"name":"sucre blanc","unit":"gramme"}]'::jsonb, '["Laver séparément l''oignon vert, le gingembre, l''ail et les piments séchés.","Couper la partie blanche des oignons verts en tronçons d''environ 4 cm, puis fendre chaque tronçon en quatre.","Trancher le gingembre en rondelles d''environ 3 mm d''épaisseur.","Écraser une gousse d''ail et la hacher finement, couper les autres gousses en deux.","Couper les piments séchés en quatre morceaux.","Trancher la poitrine de porc en morceaux d''environ 4 cm de côté.","Nettoyer le poisson.","Faire quelques incisions obliques sur le dos du poisson là où la chair est épaisse pour faciliter l''imprégnation.","Verser généreusement de l''huile dans la poêle, chauffer à 70 % (juste avant que cela fume), y plonger le poisson et le faire frire 1 minute jusqu''à ce que la peau durcisse légèrement, puis le retirer et réserver (attention : ne pas remuer le poisson immédiatement après l''avoir mis dans l''huile, attendre un peu avant de le retourner). Vider l''huile de friture en ne laissant qu''un fond dans la poêle.","Chauffer le fond d''huile dans la poêle, ajouter la poitrine de porc et faire revenir jusqu''à ce qu''elle dégage son arôme.","Ajouter les piments séchés, les oignons verts, le gingembre et les gousses d''ail, faire sauter 1 minute.","Remettre le poisson frit dans la poêle.","Verser le long du bord de la poêle","50 ml de vin de cuisine","50 ml de vinaigre noir","50 ml de sauce soja claire","20 ml de sauce soja foncée pour la couleur","5 ml de sauce d''huître pour le goût umami","5 g de sel","50 g de sucre blanc","Ajouter de l''eau claire jusqu''à couvrir le poisson.","Passer à feu moyen et porter à ébullition.","Réduire à feu doux et laisser mijoter pour que les saveurs s''imprègnent.","Après 15 minutes, ouvrir le couvercle et retirer les oignons verts, le gingembre, l''ail et les piments séchés de la poêle.","Passer à feu vif pour réduire la sauce, quand il en reste environ 1/4, saupoudrer d''ail haché, éteindre le feu et servir.","La carpe braisée à la sauce rouge est prête !"]'::jsonb, '["Poissons","Braisé","Salé-sucré","Sauce parfumée","Accompagne le riz","Cuisine du Shandong","Familial"]'::jsonb),
  ('howtocook:aquatic/肉蟹煲', 'fr', 'Crabe mijoté en sauce', 'Fruits de mer', 'Ce plat a une sauce riche et parfumée, la chair de crabe est sucrée et légèrement épicée, les pommes de terre sont fondantes, les gâteaux de riz sont moelleux et élastiques, la sauce mélangée au riz est particulièrement savoureuse. C''est un plat copieux idéal pour un repas entre amis. Il est riche en protéines de qualité et en multiples oligo-éléments, très nutritif. La préparation est assez difficile : il faut manipuler des crabes vivants, maîtriser le feu et les proportions d''assaisonnement, ce qui représente un défi pour les débutants. Le temps total est d''environ 1 heure.', '[{"name":"Crabe","unit":"g"},{"name":"Crevettes","unit":"g"},{"name":"Pommes de terre","unit":"g"},{"name":"Gâteaux de riz","unit":"g"},{"name":"Oignon","unit":"g"},{"name":"Ail","unit":"g"},{"name":"Ail (supplémentaire pour les crevettes)","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Piments séchés","unit":"g"},{"name":"Poivron vert","unit":"g"},{"name":"Poivron rouge","unit":"g"},{"name":"Sauce d''huître","unit":"g"},{"name":"Sauce aux fruits de mer","unit":"g"},{"name":"Pâte de haricots jaunes","unit":"g"},{"name":"Pâte de soja sucrée","unit":"g"},{"name":"Ketchup","unit":"g"},{"name":"Fécule","unit":"g"},{"name":"Sucre candi","unit":"g"},{"name":"Bouillon de poule en poudre","unit":"g"},{"name":"Poivre blanc moulu","unit":"g"},{"name":"Poivre blanc moulu (supplémentaire pour les crevettes)","unit":"g"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Huile de cuisson (supplémentaire pour les crevettes)","unit":"ml"},{"name":"Huile de cuisson (pour friture)","unit":"ml"},{"name":"Bière","unit":"ml"},{"name":"Bière (supplémentaire pour les crevettes)","unit":"ml"},{"name":"Eau claire","unit":"ml"},{"name":"Eau claire (supplémentaire pour les crevettes)","unit":"ml"}]'::jsonb, '["Couper les pommes de terre en cubes de 3 cm de côté, les poivrons verts/rouges en losanges de 4 cm de côté, l''oignon en demi-lunes de 3 cm de large, et les gâteaux de riz en tranches de 1 cm d''épaisseur.","Couper le crabe en morceaux de 50-80 g, les enrober légèrement de fécule, les frire à 180 °C pendant 1 minute, puis les égoutter.","Dans une poêle, chauffer de l''huile, faire revenir l''ail, le gingembre et les piments séchés. Ajouter toutes les sauces et le sucre candi, cuire à feu doux jusqu''à obtenir une huile rouge, en veillant à ne pas brûler.","Ajouter le crabe, les pommes de terre, la bière et l''eau claire. Porter à ébullition, puis réduire le feu et mijoter 12 minutes.","Ajouter les gâteaux de riz et les poivrons verts/rouges, augmenter le feu et réduire la sauce jusqu''à ce qu''elle nappe les ingrédients. Saupoudrer de poivre blanc en fin de cuisson."]'::jsonb, '["Fruits de mer","Sauce parfumée","Légèrement épicé","Mijoté","Pour recevoir","Accompagne bien le riz","Repas entre amis"]'::jsonb),
  ('howtocook:aquatic/芥末黄油罗氏虾/芥末黄油罗氏虾', 'fr', 'Crevettes au beurre et wasabi', 'Fruits de mer', 'Ce plat met en valeur l''association étonnante du beurre et du wasabi. La chair des crevettes est ferme et élastique, la sauce est riche et piquante. C''est un plat de fruits de mer moderne. La crevette est riche en protéines de haute qualité et en oligo-éléments, équilibrée sur le plan nutritionnel. La difficulté est modérée : avec des ingrédients préparés à l''avance et une bonne maîtrise du feu, même un débutant peut réussir. De la préparation des crevettes vivantes à la sortie du plat, il faut environ 30 minutes.', '[{"name":"Crevettes géantes d''eau douce","unit":"livre","note":""},{"name":"Beurre","unit":"gramme","note":""},{"name":"Wasabi","unit":"gramme","note":""},{"name":"Sucre blanc","unit":"gramme","note":""},{"name":"Sauce soja","unit":"gramme","note":""},{"name":"Sauce d''huître","unit":"gramme","note":""},{"name":"Sel","unit":"gramme","note":""},{"name":"Vin de cuisine, rhum ou bière","unit":"gramme","note":""},{"name":"Coriandre","unit":"branche","note":""},{"name":"Ail","unit":"tête","note":""}]'::jsonb, '["Couper les pointes de la tête et de la queue, les antennes et les pattes des crevettes. Ouvrir le dos des crevettes avec des ciseaux et retirer l''intestin.","Préparer la sauce wasabi à l''avance : mélanger la sauce soja, la sauce d''huître, le wasabi, le sel et le sucre. Bien remuer.","Laver la coriandre et la couper en tronçons. Réserver.","Égoutter les crevettes. Ajouter de l''huile dans la poêle, y mettre directement les crevettes. Cuire à feu moyen jusqu''à ce que l''extérieur soit doré. Retirer les crevettes.","Ajouter l''ail haché. À feu vif, faire revenir l''ail dans l''huile de cuisson des crevettes. Lorsque de la fumée blanche se dégage et que l''ail est parfumé, ajouter les crevettes et le beurre. Laisser les crevettes absorber le parfum du beurre.","Verser la sauce préparée. Continuer à feu vif, faire bouillir et remuer les crevettes jusqu''à ce que la sauce réduise. Ajouter le vin (30 g de vin de cuisine ou de bière, ou 15 g de rhum si l''on veut une saveur plus forte).","Quand la sauce a légèrement réduit, ajouter la coriandre, remuer deux fois, puis retirer du feu."]'::jsonb, '["Fruits de mer","Wasabi relevé","Sauté","Fruits de mer modernes","Repas entre amis","Rapide"]'::jsonb),
  ('howtocook:aquatic/葱油桂鱼/葱油桂鱼', 'fr', 'Poisson mandarin à l''huile de cébette', 'Fruits de mer', 'Le poisson mandarin à l''huile de cébette est un plat familial cuit à la vapeur, parfumé à la cébette, à la chair tendre. Il appartient aux saveurs légères chinoises, adapté à tous. Le poisson mandarin est riche en protéines de qualité et en acides gras insaturés. Après un traitement minutieux pour éliminer les odeurs, il conserve sa saveur et ses nutriments. La recette est très accessible pour les débutants, avec une grande marge d''erreur. En suivant les étapes, c''est presque garanti. De la préparation à la sortie du plat, il faut environ 45 minutes.', '[{"name":"Poisson mandarin","unit":"g"},{"name":"Cébette","unit":"pièce(s)"},{"name":"Piment oiseau","unit":"pièce(s)"},{"name":"Gingembre","unit":"g"},{"name":"Vin de cuisine","unit":"g"},{"name":"Huile végétale","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Sauce soja pour poisson vapeur","unit":"g"},{"name":"Eau claire","unit":"L"}]'::jsonb, '["Allez au marché acheter un poisson déjà préparé (si vous le préparez vous-même, enlevez les viscères), grattez toutes les écailles sur la peau du poisson.","Avec du papier absorbant, essuyez le sang et la membrane noire dans le ventre du poisson (le sang affecte la texture, la membrane noire est source d''odeur de poisson).","Avec un couteau de cuisine, grattez la surface du poisson plusieurs fois pour enlever le mucus, supprimant ainsi davantage l''odeur, puis rincez le poisson intérieur et extérieur à l''eau claire.","Placez le poisson à plat sur une planche à découper, séchez l''intérieur et l''extérieur avec du papier absorbant. Orientez la tête à gauche, la queue à droite. À partir de l''ouïe, faites des incisions verticales tous les 3 cm jusqu''à l''arête dorsale. Répétez de l''autre côté.","Placez le poisson à plat dans un plat, assurez-vous qu''il n''y a pas d''eau résiduelle.","Prenez 50 g de gingembre (de la taille d''un œuf), pelez-le et lavez-le, puis coupez-le en tranches de 3 mm d''épaisseur.","Lavez les piments oiseaux, retirez les queues, coupez-les en rondelles de 2 mm d''épaisseur (ou en fines lanières de 1 mm de large).","Lavez les cébettes, retirez les racines, coupez-les en tronçons de 3 cm. Pour les cébettes plus épaisses, fendez-les en deux dans le sens de la longueur.","Ajoutez 8 g de sel et 25 g de vin de cuisine dans le plat, portez des gants jetables, puis massez le poisson entier pendant 1 minute pour bien répartir le sel et le vin.","Après le massage, insérez une tranche de gingembre dans chaque incision, et 3 tranches dans le ventre. Laissez mariner 10 minutes (ne pas mariner trop longtemps pour ne pas altérer la fraîcheur).","Pendant la marinade, ajoutez 5 L d''eau claire dans un cuiseur vapeur, portez à ébullition, puis placez le panier vapeur.","Une fois mariné, du liquide s''est formé. Jetez l''excès de marinade et les tranches de gingembre, rincez le poisson à l''eau claire, puis séchez-le avec du papier absorbant.","Placez le poisson à plat dans un plat allant à la vapeur. Remettez des tranches de gingembre dans les incisions et le ventre.","Puis placez le plat dans le panier vapeur, couvrez et faites cuire à feu moyen pendant 20 minutes.","Pendant la cuisson, la vapeur se condense sur le poisson et le plat, formant un bouillon. Ne jetez surtout pas ce jus après cuisson, c''est le concentré de saveur.","Avec une pince anti-chaleur, sortez le plat. Versez 10 g de sauce soja pour poisson vapeur sur le poisson et autour.","Saupoudrez uniformément les tronçons de cébette et les rondelles de piment sur le poisson et autour.","Dans une poêle en fer, versez 15 g d''huile végétale et chauffez à feu moyen-doux pendant 5 minutes. Ne pas utiliser un feu vif, l''huile s''évaporerait trop vite.","Versez lentement et uniformément l''huile chaude sur le poisson. Le poisson mandarin à l''huile de cébette, si savoureux qu''il vous fera tomber les sourcils, est prêt !"]'::jsonb, '["Poisson","Cuit à la vapeur","Parfumé à la cébette","Fait maison","Savoureux","Léger"]'::jsonb),
  ('howtocook:aquatic/葱烧海参/葱烧海参', 'fr', 'Concombre de mer braisé aux oignons verts', 'Fruits de mer', 'Ce plat de fruits de mer familial classique du Shandong se caractérise par le parfum riche des oignons verts et la texture tendre et savoureuse du concombre de mer. La sauce est épaisse, brillante, salée et légèrement sucrée. Le concombre de mer est riche en collagène et oligo-éléments, bon pour le corps. La cuisson est simple mais nécessite de réhydrater le concombre de mer séché à l''avance. La cuisson proprement dite prend environ trente minutes, même les débutants peuvent réussir.', '[{"name":"Concombre de mer réhydraté","unit":"pièce"},{"name":"Blancs d''oignons verts","unit":"tige"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sauce d''huîtres","unit":"g"},{"name":"Sauce soja légère","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Fécule","unit":"g"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Couper le blanc des oignons verts en tronçons de 1 cm, réserver.","Couper le concombre de mer en tronçons de 1 cm, réserver.","Préparer un bol vide, verser 20 g de sauce d''huîtres, 10 g de sauce soja légère, 2 g de sucre blanc, bien mélanger. Sauce.","Dans un autre bol, verser la fécule et l''eau, préparer la fécule liquide pour lier la sauce.","Chauffer la poêle, ajouter 20-25 ml d''huile de cuisson. Attendre 10 secondes pour que l''huile chauffe.","Ajouter les blancs d''oignons verts, réduire le feu, veiller à ne pas les brûler. Faire frire environ 3-5 minutes. Oignons verts.","Retirer les blancs d''oignons verts avec des baguettes et les mettre dans une assiette, réserver.","Verser la sauce préparée, faire sauter jusqu''à ce qu''elle soit parfumée, attendre 1-2 minutes.","Ajouter le concombre de mer coupé, faire sauter pendant 1 minute.","Ajouter 100 ml d''eau, feu moyen-doux, attendre 5 minutes.","Lorsque la sauce est presque évaporée, ajouter la fécule liquide, puis ajouter les blancs d''oignons verts réservés.","Éteindre le feu lorsque la sauce est épaisse, servir dans un plat. Concombre de mer braisé aux oignons verts - image d''aperçu-5."]'::jsonb, '["Fruits de mer","Cuisine du Shandong","Braisé","Salé et umami","Plat de banquet","Produits de la mer"]'::jsonb),
  ('howtocook:aquatic/蒜蓉虾/蒜蓉虾', 'fr', 'Crevettes à l''ail', 'Fruits de mer', 'Ce plat traditionnel cantonais est réputé pour sa fraîcheur, sa saveur et sa texture tendre. La chair des crevettes est sucrée et élastique, avec un arôme d''ail riche et envahissant. Les crevettes de mer sont riches en protéines de haute qualité et en oligo-éléments comme le calcium et le sélénium. Associées à l''ail, elles aident à tuer les bactéries et à ouvrir l''appétit. La préparation est très simple : préparer les crevettes, étaler la pâte, cuire à la vapeur, arroser d''huile chaude ; même les débutants peuvent s''en sortir facilement, environ 15 minutes au total.', '[{"name":"Crevettes de mer","unit":"pièce"},{"name":"Pâte d''ail","unit":"gramme"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sauce soja claire","unit":"ml"}]'::jsonb, '["Couper le milieu de la tête de la crevette jusqu''à 1 cm de la queue.","Étaler la pâte d''ail au milieu du corps de la crevette et placer dans un plat.","Verser de l''eau chaude dans une casserole, placer le plat dans la casserole et cuire à la vapeur à feu vif pendant 3 minutes.","Chauffer l''huile, verser sur les crevettes dans le plat, puis ajouter la sauce soja claire."]'::jsonb, '["Produits aquatiques","Frais et parfumé","Cuisson à la vapeur","Cantonnais","Rapide","Accompagnement du riz"]'::jsonb),
  ('howtocook:aquatic/蒜香黄油虾/蒜香黄油虾', 'fr', 'Crevettes à l''ail et au beurre', 'Fruits de mer', 'Les crevettes à l''ail et au beurre sont un plat de fruits de mer occidental classique. Les crevettes sont tendres et élastiques, enveloppées d''un riche arôme d''ail et de beurre, avec une légère touche de citron. Riches en protéines de haute qualité, elles sont accompagnées de beurre pour fournir de l''énergie, idéales pour un apport nutritionnel rapide. La recette est simple, ne nécessitant que quelques ingrédients courants, même les débutants peuvent la réussir facilement ; de la préparation à la cuisson, environ vingt minutes.', '[{"name":"Crevettes","unit":"pièce"},{"name":"Beurre non salé","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Vin blanc","unit":"ml"},{"name":"Citron","unit":"pièce"},{"name":"Huile d''olive","unit":"ml"}]'::jsonb, '["Décortiquer les crevettes en laissant la queue, retirer le boyau avec un cure-dent, les laver et les sécher avec du papier absorbant.","Hacher l''ail en fines lamelles.","Chauffer une poêle à feu moyen, ajouter 10 ml d''huile d''olive.","Une fois l''huile chaude, ajouter les crevettes et les faire cuire 1 à 1,5 minutes de chaque côté jusqu''à ce qu''elles soient colorées, puis les réserver.","Dans la même poêle, ajouter le beurre, le faire fondre, puis ajouter l''ail haché et le faire revenir à feu doux (environ 30 secondes).","Si vous utilisez du vin blanc, l''ajouter à ce moment et le laisser cuire jusqu''à évaporation de l''alcool (environ 1 minute).","Remettre les crevettes dans la poêle et les mélanger avec la sauce à l''ail et au beurre (environ 1 minute).","Presser le jus de citron, mélanger rapidement, puis éteindre le feu immédiatement.","Dresser dans une assiette et arroser du reste de sauce dans la poêle."]'::jsonb, '["Produits de la mer","Ail","Savoureux","Occidental","Poêlé","Rapide","Fruits de mer"]'::jsonb),
  ('howtocook:aquatic/蛏抱蛋/蛏抱蛋', 'fr', 'Œufs brouillés aux palourdes', 'Fruits de mer', 'Les œufs brouillés aux palourdes sont un plat traditionnel de la région de Fuzhou, au Fujian. La chair des palourdes enrobée d''œufs est frite jusqu''à ce qu''elle soit croustillante à l''extérieur et tendre à l''intérieur, avec les arômes salés et parfumés de l''oignon et de la sauce soja. Les palourdes sont riches en protéines de haute qualité et en oligo-éléments comme le zinc et le fer, et leur association avec les œufs offre un équilibre nutritionnel. La difficulté de préparation est modérée ; il faut maîtriser la température de friture mais les étapes ne sont pas compliquées. On estime qu''environ 30 minutes suffisent pour servir ce plat.', '[{"name":"Palourdes","unit":"g"},{"name":"Œufs","unit":"pièce"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Oignon","unit":"pièce"},{"name":"Fécule de maïs","unit":"g"},{"name":"Sauce soja","unit":"ml"},{"name":"Assaisonnement au poulet","unit":"ml"},{"name":"Vin de cuisson","unit":"ml"}]'::jsonb, '["Faire bouillir de l''eau, y plonger les palourdes et les cuire 2 minutes. Les retirer, enlever les coquilles et les mettre dans un grand bol.","Ajouter dans le bol l''oignon, la sauce soja, le vin de cuisson, l''assaisonnement au poulet et la fécule de maïs. Bien mélanger.","Casser 2 œufs dans le bol et continuer à mélanger.","Chauffer de l''huile dans une poêle, y verser le mélange de palourdes. Frire jusqu''à ce qu''un côté soit doré, puis retourner et continuer la friture."]'::jsonb, '["Fruits de mer","Salé et parfumé","Frit","Cuisine du Fujian","Fait maison","Accompagnement du riz"]'::jsonb),
  ('howtocook:aquatic/酱炖蟹', 'fr', 'Crabe braisé à la sauce', 'Fruits de mer', 'Ce plat est une spécialité automnale de la région de Pinghu, Zhejiang, offrant une saveur salée et umami. La crémeuse du crabe enveloppée de sauce parfumée, la chair sucrée, et la sauce qui se marie parfaitement avec le riz. Riche en protéines de qualité et oligo-éléments. Difficulté moyenne, adapté aux débutants ayant des bases. Préparation et cuisson environ 30 minutes.', '[{"name":"Crabe (de préférence crabe de rivière, sinon crabe nageur)","unit":"g"},{"name":"Pâte de haricots fermentés (Doubanjiang)","unit":"g"},{"name":"Sucre candi (facultatif)","unit":"g"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Huile de colza (non raffinée, appelée ''huile de colza brute'' ou ''huile de colza paysanne'', alternative : huile d''arachide)","unit":"ml"},{"name":"Concentré de tomate","unit":"ml"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Gingembre (mûr)","unit":"g"},{"name":"Ciboule","unit":"g"},{"name":"Œuf (facultatif)","unit":"pièce"},{"name":"Viande de porc hachée (facultatif)","unit":"g"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Lavez et brossez soigneusement les crabes, puis coupez-les en deux sur une planche à découper.","Dans une poêle, faites chauffer l''huile de colza, ajoutez le gingembre haché et la pâte de haricots fermentés (Doubanjiang) pour les faire revenir jusqu''à ce qu''ils soient parfumés. Ajoutez le sucre candi (facultatif) et faites-le fondre jusqu''à l''apparition de petites bulles, puis retirez du feu.","Étalez une couche de sauce dans une assiette, puis disposez les morceaux de crabe, côté coupé vers le bas, bien alignés sur la sauce.","Ajoutez quelques morceaux de ciboule et de gingembre en tranches. Il est conseillé de casser un œuf ou de répartir de la viande hachée au fond du plat.","Faites cuire à la vapeur pendant 10 à 12 minutes."]'::jsonb, '["Fruits de mer","Salé et umami","Parfumé à la sauce","Vapeur","Jiang-Zhe","Accompagnement du riz","Spécialité automnale"]'::jsonb),
  ('howtocook:aquatic/阳朔啤酒鱼/阳朔啤酒鱼', 'fr', 'Poisson à la bière de Yangshuo', 'Fruits de mer', 'Le poisson à la bière de Yangshuo est un plat local célèbre de Yangshuo, Guangxi. On utilise du poisson frais de la rivière Li, cuit avec les écailles, frit, puis mijoté avec de la bière à la place de l''eau. Les écailles sont croustillantes, la chair tendre, et le goût de la bière se mêle à l''acidité des tomates pour une saveur riche et unique. Le poisson est riche en protéines de haute qualité et en minéraux, accompagné de tomates et de piments, apportant des vitamines et ouvrant l''appétit. La difficulté de préparation est moyenne, un peu difficile pour les débutants, mais en suivant les étapes on peut réussir. Environ 30 minutes suffisent.', '[{"name":"Poisson (carpe ou poisson à l''épée)","unit":"pièce"},{"name":"Bière LiQuan","unit":"ml"},{"name":"Tomate","unit":"pièce"},{"name":"Poivron vert","unit":"pièce"},{"name":"Poivron rouge","unit":"pièce"},{"name":"Ail","unit":"gousse"},{"name":"Gingembre","unit":"morceau"},{"name":"Oignon vert","unit":"tige"},{"name":"Sauce chili de Guilin","unit":"g"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Sucre","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Huile de cuisson","unit":"ml"}]'::jsonb, '["Nettoyer le poisson en conservant les écailles, vider les entrailles, bien laver. Ouvrir le poisson en deux par le ventre (en laissant le dos attaché). Faire mariner avec 15 ml de vin de cuisine, des tranches de gingembre, et 3 g de sel pendant 15 minutes.","Couper les tomates en morceaux, les poivrons verts et rouges en morceaux, écraser l''ail, trancher le gingembre, couper l''oignon vert en tronçons (séparer le blanc et le vert).","Frotter le fond de la poêle avec une tranche de gingembre. Faire chauffer la poêle, verser 30 ml d''huile de cuisson. Quand l''huile est chaude, déposer le poisson (côté peau vers le bas) et faire frire jusqu''à ce que les deux côtés soient dorés et les écailles croustillantes. Retirer et réserver.","Dans la poêle, laisser un peu d''huile, faire revenir le blanc d''oignon vert, les tranches de gingembre et les gousses d''ail jusqu''à ce qu''ils soient parfumés.","Ajouter 15 g de sauce chili de Guilin, faire sauter jusqu''à ce que l''huile devienne rouge.","Ajouter les morceaux de tomate, faire sauter jusqu''à ce qu''ils libèrent leur jus et deviennent tendres.","Verser toute la bouteille de bière, ajouter 15 ml de sauce soja claire, 5 ml de sauce soja foncée, 5 g de sucre, 5 g de sel, bien mélanger.","Déposer le poisson frit. Porter à ébullition à feu vif, puis réduire à feu moyen-doux, couvrir et laisser mijoter 15 à 20 minutes.","Découvrir, ajouter les morceaux de poivrons verts et rouges, continuer la cuisson 3 à 5 minutes.","Augmenter le feu pour réduire la sauce jusqu''à épaississement, parsemer de tronçons de vert d''oignon, servir dans un plat."]'::jsonb, '["Poisson","Spécialité du Guangxi","Frit et mijoté","Frais et légèrement épicé","Idéal avec du riz","Pour les invités"]'::jsonb),
  ('howtocook:aquatic/香煎翘嘴鱼/香煎翘嘴鱼', 'fr', 'Poisson à la bouche pointue poêlé', 'Fruits de mer', 'Le poisson à la bouche pointue poêlé est un plat familial de rivière riche en saveurs. Le poisson, salé et séché, devient ferme et parfumé. Poêlé jusqu''à ce que la peau soit dorée et croustillante, la chair est fine et savoureuse, avec une légère chaleur de la pâte de fèves et des poivrons verts. Riche en protéines de haute qualité et en acides gras insaturés, ce plat est nutritif et facile à digérer. La préparation nécessite un salage et un séchage de deux à quatre jours à l''avance, la cuisson prend environ une demi-heure. Il faut être patient pour contrôler le feu lors de la friture, ce qui peut être un défi pour les débutants, mais le résultat est incroyablement parfumé et se marie parfaitement avec le riz.', '[{"name":"Poisson à la bouche pointue","unit":"livre"},{"name":"Gingembre","unit":"g"},{"name":"Oignon vert","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Poivron vert","note":"quantité suffisante"},{"name":"Coriandre","note":"selon votre goût"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Sucre","unit":"g"},{"name":"Pâte de fèves (Doubanjiang)","note":"quantité suffisante"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Piment séché","unit":"pièce"},{"name":"Eau chaude","note":"quantité suffisante"},{"name":"Volaille (ou glutamate)","note":"quantité suffisante"},{"name":"Mélange d''épices treize parfums","note":"quantité suffisante"},{"name":"Vinaigre de riz","note":"quantité suffisante"}]'::jsonb, '["Faire fendre le dos du poisson par le poissonnier (ne pas ouvrir le ventre, bien par le dos), nettoyer soigneusement.","Frotter uniformément la surface du poisson avec du sel, ajouter environ 80 ml de vin de cuisine et 20 g de gingembre haché. Mettre au réfrigérateur pour mariner 1 à 2 jours.","Sortir le poisson mariné, le suspendre avec une ficelle et le faire sécher à l''air jusqu''à mi-séchage (environ 1 à 2 jours, selon la température et l''ensoleillement).","Avant la cuisson, laver le poisson à l''eau claire et l''égoutter (pour éviter les éclaboussures d''huile).","Chauffer la poêle à feu vif, puis réduire immédiatement à feu doux. Ajouter de l''huile en veillant à ce que toute la surface de la poêle en soit recouverte. Glisser le poisson dans la poêle en le faisant glisser le long du bord (cuire d''abord le dos).","Une fois le poisson dans la poêle (et après l''avoir retourné), ne pas le déplacer immédiatement (cela risque de casser la peau). Après environ 30 secondes, essayer de secouer doucement la poêle.","Cuire le dos environ 1 minute, puis retourner et cuire l''autre côté environ 1 à 2 minutes, jusqu''à ce que les deux faces soient dorées.","Lorsque les deux faces sont bien cuites, pousser le poisson sur le côté de la poêle, laisser un espace pour faire revenir la pâte de fèves jusqu''à ce qu''elle soit parfumée, puis ajouter le gingembre et l''ail.","Après avoir fait revenir les aromates, ajouter le vin de cuisine, la sauce soja claire et la sauce soja foncée. Verser de l''eau chaude jusqu''à atteindre le niveau du poisson ou légèrement moins.","Passer à feu moyen-vif et cuire 5 à 10 minutes. Ajouter ensuite les morceaux de poivron vert, le sucre, la volaille, le mélange d''épices treize parfums et le vinaigre de riz.","Réduire à feu doux et cuire 2 à 5 minutes. Ajouter l''oignon vert et la coriandre, puis servir."]'::jsonb, '["Poisson d''eau douce","Épicé et parfumé","Poêlé","Fruits de rivière","Accompagnement de riz","Fait maison"]'::jsonb),
  ('howtocook:aquatic/鲤鱼炖白菜/鲤鱼炖白菜', 'fr', 'Carpe braisée au chou chinois', 'Fruits de mer', 'La carpe braisée au chou chinois est un plat mijoté familial savoureux et riche. La chair du poisson est tendre et bien imprégnée, le chou est doux et absorbe le jus. C''est un plat typique du nord de la Chine. La carpe est riche en protéines de haute qualité et en acides gras insaturés, tandis que le chou apporte des fibres et des vitamines, offrant un équilibre nutritionnel. La préparation nécessite de frire le poisson puis de le braiser, ce qui demande un peu d''expérience mais reste accessible aux cuisiniers amateurs. Du début à la fin, il faut compter environ 40 minutes.', '[{"name":"huile de cuisson","unit":"ml"},{"name":"gingembre","unit":"tranche"},{"name":"ail","unit":"gousse"},{"name":"carpe","unit":"jin"},{"name":"chou chinois (cœur de chou)","unit":"feuille"},{"name":"sel","unit":"g"},{"name":"sauce soja foncée","unit":"ml"},{"name":"sauce soja claire","unit":"ml"},{"name":"cannelle (écorce)","unit":"morceau"},{"name":"anis étoilé","unit":"unité"},{"name":"pâte de piment de Pixian","unit":"g"},{"name":"piment séché","unit":"unité"}]'::jsonb, '["Nettoyer la carpe, faire des entailles (plusieurs incisions sur le poisson pour qu''il s''imprègne bien des saveurs).","Nettoyer le chou chinois et le réserver dans une assiette.","Dans une poêle, ajouter de l''huile. Quand elle est chaude, ajouter ''un peu de sel'', ''gingembre'', ''ail'', ''pâte de piment de Pixian'', ''cannelle'', ''anis étoilé'' et faire revenir jusqu''à ce que les arômes se dégagent.","Mettre le poisson dans la poêle et le faire frire (3 minutes) en le retournant toutes les 30 secondes.","Ajouter de l''eau (la quantité doit être à peu près au niveau du poisson, un peu moins peut-être). Ajouter ''sauce soja claire'', ''sauce soja foncée'', ''chou chinois''.","Laisser mijoter à feu vif pendant 15 à 20 minutes. Quand la sauce est presque réduite, ajouter ''sel'' puis retirer du feu."]'::jsonb, '["Poisson","Savoureux","Mijoté","Fait maison","Accompagnement","Saveur du nord"]'::jsonb),
  ('howtocook:aquatic/鳊鱼炖豆腐/鳊鱼炖豆腐', 'fr', 'Brème braisée au tofu ferme', 'Fruits de mer', 'La brème braisée au tofu ferme est un plat familial mijoté à la sauce soja. La chair du poisson est tendre et savoureuse, le tofu imbibé de sauce est salé et légèrement épicé. La brème est riche en protéines de haute qualité et en acides gras insaturés, tandis que le tofu apporte des protéines végétales et du calcium, offrant un équilibre nutritif. La difficulté est modérée ; il faut un peu de patience pour saisir le poisson sans qu''il colle, mais les étapes sont claires et même les débutants peuvent essayer. De la préparation à la fin, il faut environ 40 minutes.', '[{"name":"Brème","unit":"g"},{"name":"Tofu ferme","unit":"g"},{"name":"Gingembre","unit":"tranche"},{"name":"Oignon vert","unit":"tige"},{"name":"Ail","unit":"pièce"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Cannelle en bâton","unit":"bâton"},{"name":"Sucre candi","unit":"morceau"},{"name":"Piment séché","unit":"pièce"},{"name":"Vin de cuisson","unit":"ml"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Anis étoilé","unit":"pièce"},{"name":"Feuille de laurier","unit":"feuille"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Eau chaude","unit":"g"}]'::jsonb, '["Inciser la brème, déposer des tranches de gingembre et du vin de cuisson, laisser mariner 5 à 10 minutes.","Couper le tofu ferme en morceaux et le mettre dans de l''eau, réserver.","Chauffer de l''huile dans la poêle, ajouter un peu de sel pour éviter que le poisson n''attache. Essuyer le poisson mariné avec du papier absorbant, le mettre dans la poêle et le saisir des deux côtés.","Lorsque les deux côtés sont dorés, pousser le poisson sur le côté de la poêle, laisser un espace pour ajouter l''oignon vert, le gingembre, l''ail, les piments séchés, les feuilles de laurier et l''anis étoilé, faire revenir jusqu''à ce que les arômes se dégagent.","Une fois les arômes des épices libérés, ajouter le vin de cuisson, la sauce soja claire, la sauce soja foncée, le sucre candi, la cannelle en bâton, verser de l''eau chaude à hauteur du poisson ou un peu moins.","Porter à ébullition à feu vif, puis ajouter le tofu ferme en le plaçant contre le bord de la poêle, ajouter le sel, réduire à feu doux.","Laisser mijoter à feu doux pendant 10 à 15 minutes, puis augmenter le feu pour faire réduire la sauce, et servir."]'::jsonb, '["Produits aquatiques","Braisé","Familial","Accompagne riz","Frais et savoureux","Légèrement épicé"]'::jsonb),
  ('howtocook:aquatic/黄油煎虾/黄油煎虾', 'fr', 'Crevettes sautées au beurre', 'Fruits de mer', 'Les crevettes sautées au beurre sont un plat de fruits de mer maison riche en saveurs, avec une chair tendre et élastique. Les crevettes fraîches sont riches en protéines de haute qualité, calcium, zinc et autres minéraux, et le beurre ajoute une note lactée et de l''énergie. La préparation est relativement simple, il suffit de traiter les crevettes vivantes avec patience, même les débutants peuvent réussir, le temps total est d''environ une heure.', '[{"name":"Crevettes fraîches","unit":"grammes"},{"name":"Beurre","unit":"grammes"},{"name":"Grains de poivre noir","unit":"ml"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Vin de riz","unit":"ml"},{"name":"Sucre blanc","unit":"ml"},{"name":"Sel","unit":"ml"}]'::jsonb, '["Retirer la tête des crevettes fraîches et en profiter pour retirer le boyau (si cette étape est mal faite, on peut retirer le boyau lors de l''ouverture du dos à l''étape suivante). Utiliser des ciseaux pour couper ou un couteau pour fendre le dos des crevettes, égoutter et réserver.","Préparer la sauce : dans un petit bol, mettre toutes les quantités indiquées de sauce soja légère, vin de riz, sucre blanc et sel, bien mélanger et réserver.","Chauffer une poêle à feu moyen-vif, ajouter l''huile de cuisson, attendre 10 secondes pour que l''huile chauffe.","Mettre toutes les crevettes dans la poêle, commencer à moudre du poivre noir au moulin, saupoudrer uniformément sur les crevettes et faire sauter.","Lorsque les crevettes changent de couleur, ajouter le beurre. Une fois le beurre complètement fondu, verser la sauce préparée et continuer à faire sauter.","Faire sauter à feu vif pendant 15 secondes pour faire réduire la sauce, puis servir."]'::jsonb, '["Fruits de mer","Savoureux","Riche en saveur lactée","Sauté","Plat rapide","Accompagnement de riz"]'::jsonb),
  ('howtocook:breakfast/吐司果酱', 'fr', 'Tartines à la confiture', 'Petit-déjeuner', 'C''est un petit-déjeuner ultra rapide et simple : du pain grillé légèrement croustillant garni de confiture sucrée, croustillant à l''extérieur et moelleux à l''intérieur, facile à emporter. C''est un classique du petit-déjeuner occidental pratique. Il apporte principalement des glucides et du sucre, idéal pour un regain d''énergie matinal. La préparation est quasi sans difficulté, parfaite pour les débutants pressés qui ne savent pas cuisiner. Du début à la fin, il faut environ 2 minutes, sans utiliser de feu, et presque pas de vaisselle à laver.', '[{"name":"Pain de mie frais","unit":"tranche"},{"name":"Confiture","note":"Quantité suffisante pour tartiner une face du pain"}]'::jsonb, '["Mettez les tranches de pain de mie dans le grille-pain.","Réglez le niveau de cuisson ; le pain sortira automatiquement quand ce sera prêt.","Au bout de deux minutes, le pain grillé est prêt et saute.","Prenez d''abord une tranche, tartinez-la de confiture, puis recouvrez avec l''autre tranche.","Enveloppez la tartine dans une serviette en papier pour la manger en marchant, ou finissez-la avant de sortir."]'::jsonb, '["Petit-déjeuner","Rapide","Occidental","Portable","Sucré"]'::jsonb),
  ('howtocook:breakfast/太阳蛋', 'fr', 'Œuf soleil', 'Petit-déjeuner', 'L''œuf soleil est un petit-déjeuner fait maison rapidement au micro-ondes. La texture est tendre, le blanc est cuit et le jaune légèrement coulant, c''est un plat typique rapide. L''œuf est riche en protéines de haute qualité et en vitamines, facile à digérer et à absorber. La préparation est très simple, adaptée aux débutants. Avec un micro-ondes à puissance réglable, cela ne prend que 3 minutes ; avec un micro-ondes non réglable, il suffit de quelques minutes de chauffage répété.', '[{"name":"Œuf","unit":"pièce"},{"name":"Sel","unit":"g"},{"name":"Huile","unit":"ml"}]'::jsonb, '["Préparez un petit bol, versez l''huile calculée à l''étape précédente, saupoudrez de sel, mélangez bien. Inclinez le bol pour que l''huile recouvre la surface.","Sortez un œuf et cassez-le dans le petit bol.","Percez des trous à la surface du jaune. Faites 5 trous avec un cure-dent ou 1 trou avec une baguette.","Placez au micro-ondes, puissance moyenne pendant 3 minutes.","Préparez un petit bol, versez l''huile calculée à l''étape précédente, saupoudrez de sel, mélangez bien. Inclinez le bol pour que l''huile recouvre la surface.","Sortez un œuf et cassez-le dans le petit bol.","Percez des trous à la surface du jaune. Faites 5 trous avec un cure-dent ou 1 trou avec une baguette.","Placez au micro-ondes, 1 minute.","tant que (l''œuf soleil n''est pas largement solide) passer au micro-ondes (30s);"]'::jsonb, '["Petit-déjeuner","Rapide","Micro-ondes","Tendre","Maison"]'::jsonb),
  ('howtocook:breakfast/完美水煮蛋', 'fr', 'Œuf parfait cuit à l''eau', 'Petit-déjeuner', 'Voici un œuf préparé selon la méthode de cuisson cyclique développée par des scientifiques. Le jaune est crémeux et fin, le blanc uniformément coagulé, avec une texture en couches distinctes. Il conserve plus de nutriments, avec une teneur en polyphénols 23 % plus élevée que la cuisson traditionnelle, et riche en protéines. La difficulté de préparation est élevée, nécessitant un contrôle précis de la température et des transferts répétés. Le temps de préparation estimé est d''environ 35 minutes.', '[{"name":"Œufs frais (de préférence de calibre AA)","unit":"pièce"},{"name":"Eau bouillante à 100°C","unit":"ml"},{"name":"Eau tiède à 30°C","unit":"ml"},{"name":"Eau glacée","note":"Quantité suffisante"}]'::jsonb, '["Préparez deux casseroles d''eau : maintenez l''eau de la casserole A à 100°C (ébullition) et l''eau de la casserole B à 30°C (tiède).","À l''aide d''une écumoire, placez l''œuf dans la casserole A et démarrez le minuteur.","Transférez précisément l''œuf dans l''autre casserole toutes les 2 minutes.","Répétez l''opération de transfert 16 fois (durée totale de 32 minutes).","Après le dernier transfert, laissez reposer dans la casserole B pendant 30 secondes.","Plongez immédiatement dans de l''eau glacée (0°C) pour arrêter la cuisson (maintenez 30 secondes).","Pour écaler, commencez par l''extrémité la plus large (chambre à air) et retirez la membrane le long de l''axe longitudinal."]'::jsonb, '["Petit-déjeuner","Léger","Savoureux","Cuit à l''eau","Nutritif"]'::jsonb),
  ('howtocook:breakfast/微波炉蒸蛋', 'fr', 'Œufs cuits à la vapeur au micro-ondes', 'Petit-déjeuner', 'Un plat d''œufs à la vapeur tendres et lisses, rapide à préparer au micro-ondes, avec une texture fine comme un pudding. C''est un plat maison rapide. Riche en protéines de haute qualité, facile à digérer et à absorber, parfait pour le petit-déjeuner ou un repas léger. La préparation est très simple, même les débutants peuvent réussir, et le temps total est d''environ 10 minutes.', '[{"name":"Œufs","unit":"pièce(s)"},{"name":"Eau tiède ou bouillon","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Huile de sésame","note":"quelques gouttes (pour servir)"}]'::jsonb, '["Battre les œufs, ajouter de l''eau tiède/bouillon, du sel et de la sauce soja légère, mélanger doucement pour éviter les bulles.","Filtrer le mélange d''œufs dans un bol résistant à la chaleur, si des bulles apparaissent, les percer avec un cure-dent.","Couvrir d''un film plastique et percer 8 à 10 petits trous, ou utiliser un couvercle spécial micro-ondes (en laissant un espace).","Placer au micro-ondes :","700 W : 1 min 30 s → vérifier et chauffer 20-30 s supplémentaires jusqu''à ce que la surface soit juste prise.","600 W : environ 1 min 40 s à 2 min 10 s.","800 W : environ 1 min 10 s à 1 min 40 s.","Une fois la cuisson terminée, laisser reposer 1 minute pour que la chaleur résiduelle cuise complètement le centre.","Arroser d''huile de sésame et saupoudrer d''oignons verts ciselés avant de servir."]'::jsonb, '["Petit-déjeuner","Rapide","Léger","Fondant"]'::jsonb),
  ('howtocook:breakfast/微波炉荷包蛋', 'fr', 'Œuf poché au micro-ondes', 'Petit-déjeuner', 'L''œuf poché au micro-ondes est un plat rapide et pratique de la cuisine familiale. Le blanc est tendre, le jaune est moelleux, avec un parfum d''huile de sésame. Les œufs sont riches en protéines de haute qualité et en lécithine. La préparation est extrêmement simple, même les débutants peuvent la maîtriser. Du début à la fin, il ne faut qu''environ 2 minutes.', '[{"name":"Œuf","unit":"pièce"},{"name":"Eau potable","unit":"ml"},{"name":"Huile de sésame","unit":"ml"},{"name":"Sel","unit":"g"}]'::jsonb, '["Cassez l''œuf dans un petit bol, percez 2 trous dans chaque jaune avec une baguette pour éviter les éclaboussures au micro-ondes.","Versez ensuite de l''eau potable à température ambiante dans le bol.","Ajoutez du sel de table dans le bol.","Enfin, ajoutez de l''huile de sésame.","Placez le bol avec les ingrédients dans le micro-ondes, faites chauffer à puissance maximale pendant 80 secondes.","Une fois le temps écoulé, utilisez un torchon pour protéger vos mains et sortez le produit."]'::jsonb, '["Petit-déjeuner","Petit-déjeuner rapide","Léger","Micro-ondes","Cuisine familiale","Accompagnement"]'::jsonb),
  ('howtocook:breakfast/微波炉蛋糕', 'fr', 'Gâteau au micro-ondes', 'Petit-déjeuner', 'Version rapide du gâteau au micro-ondes, texture moelleuse et sucrée, un dessert familial facile même pour les débutants. À base d''œufs et de farine, avec du beurre pour l''énergie et l''arôme, le sucre apporte un regain d''énergie, et l''ajout de noix ou de fruits augmente les fibres et les vitamines. Peu d''ingrédients nécessaires, une minute à puissance maximale au micro-ondes suffit : de la préparation à la dégustation, 2 minutes chrono, même les débutants y arrivent en 20 minutes.', '[{"name":"Œuf","unit":"pièce"},{"name":"Beurre","note":"de la taille d''un demi-œuf"},{"name":"Farine","unit":"g"},{"name":"Levure chimique","unit":"g"},{"name":"Sucre blanc (roux)","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Chocolat","note":"quantité suffisante"},{"name":"Banane","note":"quantité suffisante"},{"name":"Café en poudre","note":"quantité suffisante"},{"name":"Flocons d''avoine","note":"quantité suffisante"},{"name":"Lait","note":"quantité suffisante"},{"name":"Fruits secs","note":"quantité suffisante"},{"name":"Miettes de biscuit","note":"quantité suffisante"}]'::jsonb, '["Ajoutez les ingrédients suivants, sans dépasser les 3/4 du récipient","Mettez une noix de beurre de la taille d''un demi-œuf dans le récipient, faites chauffer 15 secondes au micro-ondes jusqu''à fusion","Faites fondre le chocolat / écrasez la banane en pépins / purée","Cassez un œuf et battez-le pour mélanger","15 g de sucre blanc (ou roux) (les gourmands peuvent en ajouter) (voir note 4)","Ajoutez 1 g de sel (si les ingrédients de saveur ultérieure contiennent du sel, ajustez)","Ajoutez 2,5 g de levure chimique","Ajoutez 15 g de farine (le taux de gluten n''a pas grande importance)","Ajoutez tous les ingrédients de saveur que vous aimez ! (les fruits secs et biscuits ne sont pas pour maintenant)","Mélangez jusqu''à obtenir une pâte épaisse comme un yaourt, sans grumeaux","Ajoutez les ingrédients secs optionnels (sauf les poudres à infuser) sur le dessus","Félicitez-vous 🥰","Chauffez 1 minute au micro-ondes (puissance maximale) jusqu''à ce que le gâteau soit gonflé","Sortez la tasse (attention, ça brûle !!!) et prenez une photo pour les réseaux sociaux, puis dégustez"]'::jsonb, '["Petit déjeuner","Sucré","Micro-ondes","Rapide","Dessert"]'::jsonb),
  ('howtocook:breakfast/意式香肠北非蛋', 'fr', 'Œufs à la nord-africaine aux saucisses italiennes', 'Petit-déjeuner', 'Les œufs à la nord-africaine aux saucisses italiennes sont un plat méditerranéen riche et savoureux, avec des œufs coulants posés sur une sauce tomate aigre-douce et de la viande, servis avec du pain croustillant pour tremper. Les ingrédients principaux fournissent des protéines de qualité, tandis que les tomates, les poivrons et les oignons apportent vitamines et fibres. Ce n''est pas difficile à préparer, il suffit de surveiller la cuisson des œufs. Comptez environ 30 minutes du début à la fin.', '[{"name":"Saucisses de porc italiennes / Chorizo / Spam","unit":"g"},{"name":"Sauce napolitaine Barilla","unit":"bocal"},{"name":"Œufs","unit":"pièce"},{"name":"Poivron","unit":"pièce"},{"name":"Oignon","unit":"pièce"},{"name":"Huile d''olive","unit":"ml"},{"name":"Parmesan râpé","note":"quantité suffisante"},{"name":"Persil frais","note":"quantité suffisante"},{"name":"Piment sec émietté","note":"quantité suffisante"},{"name":"Pain","note":"quantité suffisante"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Retirez la peau des saucisses italiennes et réservez. Coupez l''oignon en petits dés et le poivron en fines lanières.","Dans une grande poêle, versez 10 ml à 15 ml d''huile d''olive et chauffez à feu moyen.","Ajoutez les saucisses préparées ou le Spam et faites revenir jusqu''à ce qu''ils soient dorés et croustillants sur les bords. Si vous utilisez des saucisses crues, émiettez-les avec une cuillère en les faisant cuire jusqu''à ce qu''elles soient colorées.","Ajoutez l''oignon et le poivron dans la poêle avec la viande et faites revenir pendant 4 à 5 minutes, jusqu''à ce que les légumes soient tendres et l''oignon translucide.","Versez la sauce napolitaine Barilla et mélangez bien. Réduisez le feu à moyen-doux et laissez mijoter à petits bouillons pendant 2 à 3 minutes. Si la sauce semble trop épaisse, ajoutez 15 ml d''eau.","Avec le dos d''une cuillère, creusez 3 à 4 petits puits dans la sauce.","Cassez délicatement un œuf dans chaque puits, un par un.","Couvrez la poêle avec un couvercle et laissez cuire à la vapeur pendant 3 à 5 minutes. Vérifiez fréquemment. Lorsque les blancs sont opaques et fermes mais que les jaunes tremblent encore légèrement lorsque vous secouez la poêle (œufs coulants), la cuisson est terminée.","Éteignez le feu. Saupoudrez de parmesan râpé, de persil frais ou de piment sec émietté selon votre goût.","Servez la poêle directement sur la table, accompagnée de pain croustillant pour tremper dans le jaune d''œuf et la sauce."]'::jsonb, '["Petit-déjeuner","Savoureux","Aigre-doux","Poêlé-mijoté","Méditerranéen","Rapide"]'::jsonb),
  ('howtocook:breakfast/手抓饼', 'fr', 'Pain plat feuilleté', 'Petit-déjeuner', 'Le pain plat feuilleté est croustillant à l''extérieur et moelleux à l''intérieur, avec des couches distinctes. C''est une pâtisserie maison très appréciée. La pâte est préparée avec de l''eau bouillante, ce qui la rend souple et élastique. Accompagnée d''œufs et de légumes, elle offre un équilibre nutritionnel. La recette est adaptée aux débutants : du pétrissage à la cuisson, comptez environ 40 minutes, idéal pour les matins pressés.', '[{"name":"Farine tout usage","unit":"g"},{"name":"Eau bouillante","unit":"ml"},{"name":"Eau froide","unit":"ml"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Œuf(s)","unit":"pièce(s)"},{"name":"Laitue","unit":"g"},{"name":"Jambon","unit":"g"},{"name":"Tranche(s) de fromage","unit":"tranche(s)"}]'::jsonb, '["Placez la farine dans un bol, ajoutez l''eau bouillante et mélangez pour obtenir des grumeaux, puis ajoutez l''eau froide et pétrissez jusqu''à ce que la pâte soit lisse. Couvrez avec un torchon humide et laissez reposer 20 minutes.","Divisez la pâte en portions d''environ 100 g, roulez-les en boules, puis étalez-les en fines galettes.","Badigeonnez uniformément la surface d''huile de cuisson, saupoudrez de sel, roulez en forme d''escargot et laissez reposer 10 minutes.","Étalez à nouveau la pâte en une galette fine et uniforme.","Versez de l''huile dans une poêle chaude, faites cuire à feu doux jusqu''à ce que les deux faces soient dorées et croustillantes.","Sur la galette cuite, disposez successivement les œufs au plat, la laitue, le jambon, les tranches de fromage, etc., puis roulez-la."]'::jsonb, '["Petit-déjeuner","Salé et savoureux","Croustillant","Poêlé","Fait maison","Rapide"]'::jsonb),
  ('howtocook:breakfast/桂圆红枣粥', 'fr', 'Porridge de longane et jujube', 'Petit-déjeuner', 'Un porridge traditionnel chinois sucré, parfumé et moelleux. Cuit avec du riz gluant, des jujubes et des longanes, il est naturellement sucré et réchauffe le corps et l''estomac. Il a des effets nourrissants pour enrichir le sang, calmer l''esprit, améliorer la mémoire et renforcer la rate et le cœur. La préparation est très simple, même les débutants peuvent la maîtriser facilement. Du début à la fin, il faut environ 70 minutes pour que l''arôme du porridge remplisse la maison.', '[{"name":"Riz gluant","unit":"grammes"},{"name":"Jujubes","unit":"pièces"},{"name":"Longanes","unit":"pièces"}]'::jsonb, '["Détacher la chair des longanes, laver deux fois à l''eau claire, mettre dans un bol et laisser tremper 10 minutes","Laver les jujubes deux fois à l''eau claire, mettre dans un bol et laisser tremper 10 minutes","Mettre le riz gluant dans le cuiseur à riz, rincer deux fois à l''eau claire, puis ajouter 2000 ml d''eau","Ajouter les longanes et les jujubes dans le cuiseur à riz","Activer le mode cuisson du riz, après 1 heure le porridge est prêt"]'::jsonb, '["Petit-déjeuner","Sucré et parfumé","Cuit","Bien-être","Rapide","Fait maison"]'::jsonb),
  ('howtocook:breakfast/水煮玉米', 'fr', 'Maïs bouilli', 'Petit-déjeuner', 'Le maïs bouilli est un plat rapide et fait maison, à la texture sucrée et tendre. Le maïs frais cuit avec sa peau conserve sa saveur originale. L''ajout de sel et de sucre rehausse le goût. Il est riche en fibres alimentaires, vitamines et glucides, ce qui procure une sensation de satiété. La recette est extrêmement simple, même les débutants peuvent la réussir. De la préparation à la table, il ne faut qu''environ 15 minutes.', '[{"name":"Maïs frais","unit":"pièce","note":""},{"name":"Eau","unit":"","note":"à hauteur de couvrir le maïs d''environ une demi-phalange"},{"name":"Sel","unit":"g","note":""},{"name":"Sucre","unit":"","note":"quantité suffisante"}]'::jsonb, '["Épluchez les épis de maïs frais en gardant une partie des feuilles, puis mettez-les dans une casserole.","Ajoutez de l''eau à hauteur de couvrir le maïs d''environ une demi-phalange, puis ajoutez le sel et le sucre.","Portez à ébullition, réduisez le feu et laissez mijoter à couvert pendant 15 à 20 minutes. Il n''y a pas de problème si le maïs cuit un peu plus longtemps.","Une fois cuit, égouttez-le et laissez refroidir avant de servir."]'::jsonb, '["Petit-déjeuner","Rapide","Fait maison","Sucré","Bouilli"]'::jsonb),
  ('howtocook:breakfast/温泉蛋/温泉蛋', 'fr', 'Œuf onsen', 'Petit-déjeuner', 'L''œuf onsen est originaire du Japon. Le blanc d''œuf est semi-liquide et caillé, tandis que le jaune est chaud et ferme, avec une texture lisse et délicate, contrastant avec l''œuf mollet. Les œufs sont riches en protéines de haute qualité, en lécithine et en diverses vitamines, offrant une nutrition complète. Pour la préparation, il faut contrôler la température de l''eau à 70°C à l''aide d''un thermomètre. Bien que cela exige une certaine température, les étapes sont simples et il suffit d''attendre patiemment environ une demi-heure. Servi avec de la sauce soja kombu et des oignons verts, c''est frais et savoureux, une collation facile à réaliser.', '[{"name":"Œufs","unit":"pièce"},{"name":"Sauce soja kombu","note":"Pour assaisonner (un peu)"},{"name":"Oignons verts","note":"Pour décorer (un peu)"}]'::jsonb, '["Remplir une casserole d''eau du robinet, en veillant à ce que l''eau recouvre les œufs d''environ 3 cm. Insérer un thermomètre dans l''eau.","Allumer le feu ou la plaque à induction, et ajuster progressivement la puissance ou la flamme pour maintenir l''eau à 70 °C.","Mettre les œufs dans la casserole. Les œufs ne doivent pas être empilés, mais reposer au fond, avec suffisamment d''espace pour bouger.","Maintenir la température actuelle pendant 25 minutes.","Préparer un verre d''eau glacée.","Retirer les œufs et les placer immédiatement dans l''eau glacée. Attendre 3 minutes.","Casser l''œuf dans un petit bol. La préparation est terminée."]'::jsonb, '["Petit-déjeuner","Japonais","Léger","Onctueux","Cuisson lente","Accompagnement"]'::jsonb),
  ('howtocook:breakfast/溏心蛋', 'fr', 'Œufs mollets', 'Petit-déjeuner', 'Voici une recette d''œufs facile à réaliser avec un cuiseur électrique ordinaire. Le jaune est coulant et la texture est tendre et savoureuse. Chaque œuf apporte environ 6 g de protéines de qualité, idéal pour les sportifs. La préparation est simple : il suffit de bien maîtriser les temps de chauffe et de repos. Même les débutants peuvent réussir du premier coup, le tout en environ 15 minutes.', '[{"name":"Œufs","unit":"pièce"},{"name":"Eau","unit":"cm"}]'::jsonb, '["Placez les œufs dans le cuiseur électrique. Les œufs ne doivent pas être empilés ; ils doivent tous reposer au fond avec un espace pour bouger.","Versez de l''eau froide jusqu''à ce qu''elle dépasse les œufs d''environ 2 cm.","Faites chauffer à couvert à puissance maximale jusqu''à ce que l''eau frémisse (environ 85-95 °C, légèrement en mouvement, sans bouillir complètement).","Éteignez le feu, couvrez et laissez reposer les œufs.","Pour un jaune coulant au centre, laissez reposer 6 minutes.","Pour un jaune bien cuit et friable, laissez reposer 10 minutes.","Égouttez l''eau et rincez les œufs à l''eau froide pendant environ 1 minute. Ils sont alors prêts à être écalés et dégustés."]'::jsonb, '["Petit-déjeuner","Léger","Bouilli","Rapide","Fait maison","Tendre et onctueux"]'::jsonb),
  ('howtocook:breakfast/煎饺', 'fr', 'Raviolis poêlés', 'Petit-déjeuner', 'Les raviolis poêlés sont un plat familial avec un fond croustillant doré et une garniture juteuse, courant sur les tables du nord de la Chine. Réalisés avec des raviolis surgelés, riches en glucides et en protéines, simples et rapides. Difficulté estimée à deux étoiles, très accessible aux débutants, il faut environ 15 minutes pour les servir.', '[{"name":"Raviolis (surgelés)","unit":"pièce"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Eau","note":"Quantité suffisante"},{"name":"Graines de sésame noir","note":"Quantité suffisante"},{"name":"Ciboule ciselée","note":"Quantité suffisante"}]'::jsonb, '["Sortez une poêle (de préférence antiadhésive)","Ajoutez 10 ml à 15 ml d''huile de cuisson","Allumez le feu, disposez les raviolis (répartissez-les bien, sans les empiler)","Ajoutez immédiatement de l''eau jusqu''à la moitié de la hauteur moyenne des raviolis","Couvrez (le feu doit être vif)","Attendez 8 à 10 minutes","Lorsqu''il ne reste que 2 mm d''eau, passez à feu moyen et commencez à faire frire","Une fois l''eau complètement évaporée, secouez la poêle pour répartir la chaleur uniformément","Ajoutez les graines de sésame noir et la ciboule, puis couvrez 10 secondes","Après 1 à 2 minutes, sortez un ravioli pour vérifier le fond ; s''il est croustillant et doré, retirez-les du feu immédiatement"]'::jsonb, '["Petit-déjeuner","Rapide","Familial","Poêlé","Croustillant"]'::jsonb),
  ('howtocook:breakfast/蒸水蛋', 'fr', 'Œufs vapeur', 'Petit-déjeuner', 'Ce plat familial réputé pour sa texture lisse et soyeuse comme un pudding et sa saveur délicate est apprécié partout en Chine. Au nord, on l''appelle affectueusement « gâteau aux œufs ». Les œufs sont riches en protéines de haute qualité et en lécithine, un choix pratique pour un apport nutritionnel quotidien. La recette nécessite seulement de maîtriser le rapport œuf/eau et la cuisson à la vapeur à feu doux, très accessible pour les débutants. De la préparation à la sortie du cuiseur, cela prend généralement environ 15 minutes.', '[{"name":"Œufs frais","unit":"pièce"},{"name":"Eau chaude","unit":"ml"},{"name":"Sel","unit":"gramme"}]'::jsonb, '["Casser les œufs dans un bol, les battre.","Dans un autre récipient, verser de l''eau tiède (20~30°C) en quantité égale à 1,5 fois le volume des œufs (la moitié d''une coquille d''œuf équivaut à 0,5 fois l''eau). Dissoudre le sel dans l''eau.","Verser l''eau salée dans les œufs battus. Mélanger doucement dans un sens (horaire ou antihoraire). Vous pouvez retirer les bulles à l''aide d''une cuillère, ou passer le mélange au tamis pour une texture encore plus fine.","Couvrir le bol avec du papier d''aluminium (ou une assiette), puis le placer dans une casserole avec couvercle contenant environ 3 cm d''eau.","Porter à ébullition à feu moyen, puis réduire à feu très doux et cuire à la vapeur pendant 4 minutes."]'::jsonb, '["Petit-déjeuner","Léger","Vapeur","Rapide","Fait maison"]'::jsonb),
  ('howtocook:breakfast/蒸花卷', 'fr', 'Rouleaux de pâte vapeur', 'Petit-déjeuner', 'C''est une spécialité traditionnelle du nord de la Chine, moelleuse et savoureuse, avec un léger goût de blé. Cuite à la vapeur à partir de rouleaux de pâte surgelés, elle apporte rapidement des glucides et des fibres alimentaires. La préparation est très simple, même les débutants en cuisine peuvent la maîtriser facilement, et l''ensemble ne prend qu''une demi-heure, ce qui en fait un petit-déjeuner rapide idéal.', '[{"name":"Rouleaux de pâte vapeur surgelés","unit":"pièce"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Sortez 5 rouleaux de pâte vapeur du sachet","Disposez les rouleaux à plat sur une assiette, en évitant de les superposer","Versez 400 ml d''eau dans la casserole, placez le panier vapeur, déposez l''assiette avec les rouleaux sur le panier, et couvrez.","Chauffez à feu vif jusqu''à ébullition.","Réduisez à feu moyen et laissez cuire 15 minutes.","Ouvrez le couvercle et touchez la surface des rouleaux pour vérifier la température. S''ils ne sont pas assez chauds, continuez à cuire couvert. Sinon, éteignez le feu et sortez-les.","Sortez l''assiette et laissez refroidir jusqu''à 50 °C avant de déguster."]'::jsonb, '["Petit-déjeuner","Vapeur","Rapide","Maison","Farineux","Nord"]'::jsonb),
  ('howtocook:breakfast/燕麦鸡蛋饼', 'fr', 'Galette d''avoine et d''œufs', 'Petit-déjeuner', 'La galette d''avoine et d''œufs est un petit-déjeuner rapide et nutritif, avec une texture tendre, un parfum de céréale d''avoine et la richesse des œufs et du lait. De style simple et familial. Riche en protéines, glucides et fibres alimentaires, elle fournit suffisamment d''énergie, idéale pour les sportifs et les matins de semaine. Simple à réaliser, même pour les débutants, elle ne prend qu''une dizaine de minutes de la préparation à la cuisson.', '[{"name":"Œufs","unit":"pièce(s)"},{"name":"Flocons d''avoine","unit":"g"},{"name":"Légumes","unit":"g"},{"name":"Lait","unit":"ml"},{"name":"Beurre","note":"Quantité suffisante"}]'::jsonb, '["Mélanger le lait avec les flocons d''avoine jusqu''à obtenir une consistance épaisse et homogène.","Battre les œufs jusqu''à ce qu''ils soient homogènes et de couleur uniforme.","Verser les œufs battus dans le mélange lait-avoine et continuer à remuer jusqu''à ce que la pâte soit épaisse et homogène.","Ajouter une couche de beurre dans une poêle et l''étaler uniformément.","Verser la pâte dans la poêle et l''étaler en forme de galette.","Chauffer à feu doux pendant deux à trois minutes. Si vous souhaitez ajouter des légumes, vous pouvez les incorporer en morceaux pendant la cuisson.","Retourner la galette et poursuivre la cuisson pendant deux minutes.","Servir avec le reste du lait en accompagnement pour le petit-déjeuner."]'::jsonb, '["Petit-déjeuner","Rapide","Poêlé","Léger","Fitness"]'::jsonb),
  ('howtocook:breakfast/牛奶燕麦', 'fr', 'Flocons d''avoine au lait', 'Petit-déjeuner', 'Un petit-déjeuner nutritif, pratique, riche en protéines et en fibres, combinant le côté onctueux du lait, le goût de céréale des flocons d''avoine et le croustillant tendre de l''œuf au plat. Chaud, doux, facile à digérer et très rassasiant. La préparation est simple et directe, très accessible aux débutants, et se fait en environ trois minutes. Accompagné de fruits et légumes, c''est encore plus frais.', '[{"name":"lait","unit":"ml","note":""},{"name":"flocons d''avoine","unit":"grammes","note":""},{"name":"œuf","unit":"pièce","note":""},{"name":"eau","unit":"ml","note":""},{"name":"poivre et sel","unit":"grammes","note":""}]'::jsonb, '["Verser le lait dans un bol de petit-déjeuner (froid, c''est bien)","Préparer 200 ml d''eau. Si c''est de l''eau potable, ajouter directement les flocons d''avoine, sinon porter à ébullition puis ajouter les flocons d''avoine","Après ébullition, laisser cuire 2 minutes, les flocons d''avoine sont cuits","Égoutter les flocons d''avoine cuits et les verser dans le lait (essayer de ne pas verser l''eau de cuisson dans le lait, cela affecte la texture)","Remplacer les flocons d''avoine par des flocons d''avoine instantanés","Verser le lait dans le récipient contenant les flocons d''avoine instantanés et remuer","Mettre le mélange au micro-ondes","Cuire à puissance moyenne pendant 4 minutes","Chauffer une poêle, ajouter une fine couche d''huile. Quand l''huile est chaude, faire cuire l''œuf, 20 secondes de chaque côté. Assaisonner (3 g de poivre et sel, optionnel)","Éteindre le feu, dresser dans une assiette"]'::jsonb, '["Petit-déjeuner","Rapide","Nutritif","Léger","Riche en protéines","Riche en fibres"]'::jsonb),
  ('howtocook:breakfast/空气炸锅面包片', 'fr', 'Tranches de pain à l''air fryer', 'Petit-déjeuner', 'Les tranches de pain à l''air fryer sont un plat principal simple et rapide, croustillant à l''extérieur et moelleux à l''intérieur, avec un pur goût de blé, particulièrement adapté à une période de perte de poids. Elles sont riches en fibres alimentaires et en protéines végétales, offrant une sensation de satiété prolongée. La préparation est sans difficulté : il suffit de mettre les tranches de pain dans l''air fryer. C''est très facile pour les débutants, du début à la fin, cela ne prend qu''environ cinq minutes.', '[{"name":"tranches de pain","unit":"tranche"}]'::jsonb, '["Prenez deux tranches de pain (de préférence du pain complet)","Placez les tranches de pain verticalement dans l''air fryer","Cuire à 200°C pendant 5 minutes","Sortez et servez"]'::jsonb, '["Petit-déjeuner","Rapide","Léger","Perte de poids","Croustillant","Rassasiant"]'::jsonb),
  ('howtocook:breakfast/美式炒蛋', 'fr', 'Œufs brouillés à l''américaine', 'Petit-déjeuner', 'C''est un plat d''œufs à l''américaine moelleux et tendre. L''ajout de lait donne des œufs brouillés fins et crémeux, riches en protéines et calcium. Simple à réaliser, idéal pour les débutants, il faut environ 20 minutes de la préparation à l''assiette.', '[{"name":"Œufs","unit":"pièce"},{"name":"Lait entier/Crème","unit":"g"},{"name":"Beurre","unit":"g"},{"name":"Sel","unit":"g"}]'::jsonb, '["Casser les œufs dans un grand bol, ajouter du sel et battre jusqu''à ce que cela mousse, laisser reposer 15 minutes.","Couper le beurre en petits morceaux dans une poêle, verser les œufs battus, chauffer à feu doux en remuant constamment.","Dès que le beurre est fondu, remuer rapidement les œufs pour les briser en petits morceaux fins, éteindre le feu avant que les œufs ne soient complètement pris.","Ajouter le lait et remuer pendant 15 secondes, jusqu''à ce que les œufs soient humides et crémeux, servir dans une assiette."]'::jsonb, '["Petit-déjeuner","Savoureux","Poêlé","Rapide","Maison"]'::jsonb),
  ('howtocook:breakfast/苏格兰蛋/苏格兰蛋', 'fr', 'Œuf écossais simplifié', 'Petit-déjeuner', 'Cette version simplifiée de l''œuf écossais est croustillante à l''extérieur, coulante à l''intérieur, avec une touche de fromage fondant et de bacon fumé. C''est une collation créative d''origine britannique. L''œuf apporte des protéines de qualité, le fromage du calcium, et la galette chinoise de l''énergie pour un repas complet. La préparation est simple, même pour un débutant, et prend environ 20 à 30 minutes de la préparation à la cuisson.', '[{"name":"Œufs","unit":"g"},{"name":"Galettes chinoises","unit":"portion"},{"name":"Tranches de fromage","unit":"tranche"},{"name":"Tranches de bacon","unit":"tranche"}]'::jsonb, '["Plonger les œufs dans l''eau froide, porter à ébullition et cuire 3 minutes, puis les sortir.","Mettre les œufs dans de l''eau glacée pour les écaler plus facilement et plus proprement.","Envelopper chaque œuf d''une tranche de fromage.","Envelopper chaque œuf d''une tranche de bacon.","Couper les extrémités de la galette chinoise pour former un rectangle et envelopper l''œuf.","Faire chauffer l''huile à 160°C (quand elle frémit et des bulles se forment autour d''une baguette) et frire jusqu''à ce que ce soit doré.","Cuire à l''air fryer à 160°C pendant 15 minutes.","Couper et servir."]'::jsonb, '["Petit-déjeuner","Savoureux","Croustillant","Friture","Britannique","Rapide"]'::jsonb),
  ('howtocook:breakfast/茶叶蛋', 'fr', 'Œufs au thé', 'Petit-déjeuner', 'Cette collation traditionnelle au riche arôme de thé est savoureuse et riche en protéines de qualité, idéale pour un petit-déjeuner rapide et nutritif. Les étapes sont claires, la difficulté modérée, les débutants doivent faire attention au feu et aux proportions d''épices. Environ 30 minutes suffisent pour préparer une portion pour 2-3 personnes, parfait pour un week-end tranquille.', '[{"name":"Œufs","unit":"g"},{"name":"Anis étoilé","unit":"g"},{"name":"Feuille de laurier","unit":"g"},{"name":"Cannelle","unit":"g"},{"name":"Fenouil","unit":"g"},{"name":"Sucre candi","unit":"g"},{"name":"Thé noir","unit":"g"},{"name":"Sauce soja claire","unit":"g"},{"name":"Sauce soja foncée","unit":"g"},{"name":"Sel","unit":"g"}]'::jsonb, '["Faire cuire les œufs dans l''eau froide à feu vif environ 8 minutes (ajuster selon votre cuisinière)","Sortir les œufs et les passer sous l''eau froide","Taper les œufs les uns contre les autres pour créer des fissures","Remettre les œufs dans la casserole, ajouter l''anis étoilé, la feuille de laurier, la cannelle, le fenouil, le sucre candi, le thé noir, la sauce soja claire, la sauce soja foncée, et le sel","Ajouter de l''eau jusqu''à couvrir les œufs","Porter à ébullition à feu vif, puis réduire à feu moyen-doux et cuire 15 minutes"]'::jsonb, '["Petit-déjeuner","Arôme de thé","Braiser","Salé et savoureux","Rapide"]'::jsonb),
  ('howtocook:breakfast/蛋煎糍粑', 'fr', 'Gâteau de riz gluant frit à l''œuf', 'Petit-déjeuner', 'Une collation simple et rapide, croustillante à l''extérieur, moelleuse à l''intérieur, enveloppée de l''arôme de l''œuf et de la douceur, c''est une saveur familiale du sud. Le gâteau de riz gluant fournit des glucides riches, l''œuf complète les protéines, il est assez calorique mais très rassasiant. Le processus de fabrication est extrêmement simple, même les débutants peuvent le maîtriser facilement, il ne faut qu''environ dix minutes.', '[{"name":"Gâteau de riz gluant","unit":"pièce"},{"name":"Sucre brun ou sucre blanc","unit":"g"},{"name":"Œuf","unit":"pièce"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sel de table","unit":"g"}]'::jsonb, '["Coupez le gâteau de riz gluant en petits morceaux rectangulaires pour faciliter la friture.","Cassez un œuf dans un bol et battez-le, ajoutez 2 g de sel de table.","Trempez les petits morceaux de gâteau de riz gluant un par un dans l''œuf battu, en enduisant les deux faces.","Versez 10 ml d''huile végétale dans la poêle, mettez les morceaux de gâteau de riz gluant enrobés et faites-les frire doucement à feu doux jusqu''à ce qu''ils ramollissent.","Versez lentement le reste de l''œuf battu sur la surface des gâteaux de riz gluant.","Retournez les gâteaux de riz gluant avec des baguettes ou une cuillère, faites-les frire des deux côtés jusqu''à ce qu''ils soient dorés, puis dégustez."]'::jsonb, '["Petit-déjeuner","Doux","Frit","Sud","Rapide","Fait maison"]'::jsonb),
  ('howtocook:breakfast/金枪鱼酱三明治', 'fr', 'Sandwich à la pâte de thon', 'Petit-déjeuner', 'Ce sandwich occidental pour le petit-déjeuner est préparé avec du thon au naturel mélangé à de la mayonnaise et du jus de cornichons russes, salé et légèrement acide, texture onctueuse, accompagné de pain de mie grillé, particulièrement rassasiant. Riche en protéines de qualité et en oméga-3, il apporte rapidement de l''énergie. La préparation est très simple : il suffit de mélanger la pâte et de chauffer avec un appareil à sandwichs légers, même un débutant peut le faire en 5 minutes.', '[{"name":"Thon au naturel en boîte","unit":"g"},{"name":"Pain de mie (tranches)","unit":"tranche"},{"name":"Mayonnaise","unit":"ml"},{"name":"Jus de cornichons russes","unit":"ml"},{"name":"Tranche de fromage (facultatif)","note":"à votre convenance"},{"name":"Tranche de jambon (facultatif)","note":"à votre convenance"}]'::jsonb, '["Verser le thon, la mayonnaise et le jus de cornichons russes dans un bol. Mélanger avec une cuillère jusqu''à ce que le thon soit émietté et que la pâte soit homogène. Réserver.","Déposer 1 tranche de pain de mie sur l''appareil à sandwichs.","Étaler la pâte de thon préparée sur la tranche de pain, environ 10-15 ml.","Couvrir avec l''autre tranche de pain de mie, puis presser l''appareil et l''allumer.","Lorsque l''appareil s''arrête automatiquement, servir dans une assiette."]'::jsonb, '["Petit-déjeuner","Salé et légèrement acide","Rapide","Occidental","Nutritif","Simple"]'::jsonb),
  ('howtocook:breakfast/韩国麻药鸡蛋', 'fr', 'Œufs coréens Mayak', 'Petit-déjeuner', 'Un plat d''accompagnement coréen d''œufs mollets sucré-épicé, la sauce enrobe le blanc, la texture est tendre et le goût légèrement piquant. Les œufs apportent des protéines de qualité et de la lécithine, nourrissants et rassasiants. La recette est très simple, même les débutants peuvent la réussir, de la cuisson à la marinade au réfrigérateur, cela prend environ une heure et demie.', '[{"name":"Œufs","unit":"pièce"},{"name":"Sauce soja coréenne (ou sauce soja légère)","unit":"cuillère à soupe"},{"name":"Eau","unit":"cuillère à soupe"},{"name":"Mirin","unit":"cuillère à soupe"},{"name":"Sucre blanc","unit":"cuillère à soupe"},{"name":"Huile de sésame","unit":"ml"},{"name":"Oignons verts","unit":"g"},{"name":"Piments (piment oiseau ou piment vert/rouge)","unit":"g"}]'::jsonb, '["Faites bouillir une casserole d''eau, une fois à ébullition, plongez les œufs et faites-les cuire 7 minutes (pour obtenir un œuf mollet parfait).","Pendant la cuisson des œufs, préparez la sauce : versez 4 cuillères à soupe de sauce soja, 4 cuillères à soupe d''eau, 2 cuillères à soupe de mirin et 2 cuillères à soupe de sucre blanc dans une petite casserole.","Faites chauffer la sauce jusqu''à ébullition pour évaporer l''alcool du mirin, puis éteignez le feu et laissez refroidir.","Ajoutez les rondelles de piment dans la sauce refroidie.","Sortez les œufs cuits, plongez-les dans de l''eau glacée pour les refroidir, puis écalez-les.","Placez les œufs écalés dans la sauce préparée, arrosez de 5 ml d''huile de sésame et saupoudrez d''oignon vert ciselé.","Placez au réfrigérateur pendant 1 à 2 heures pour que les œufs s''imprègnent bien de la sauce."]'::jsonb, '["Petit-déjeuner","Coréen","Œuf mollet","Sucré-épicé","Rapide","Accompagnement"]'::jsonb),
  ('howtocook:breakfast/鸡蛋三明治', 'fr', 'Sandwich aux œufs', 'Petit-déjeuner', 'C''est un repas simple et rapide de style occidental. Le pain de mie est garni d''une sauce crémeuse aux œufs et de bacon salé, la texture est tendre avec une touche croustillante. Les œufs sont riches en protéines de haute qualité, et associés au bacon et au beurre, ils apportent rapidement de l''énergie. La préparation est très accessible, même les débutants en cuisine peuvent s''en sortir facilement, et l''ensemble ne prend qu''environ 10 minutes.', '[{"name":"Œuf","unit":"pièce"},{"name":"Pain de mie","unit":"tranche"},{"name":"Bacon","unit":"tranche"},{"name":"Beurre","unit":"gramme"},{"name":"Mayonnaise","unit":"gramme"},{"name":"Sel","unit":"gramme"},{"name":"Poivre noir","unit":"gramme"}]'::jsonb, '["Couper les croûtes du pain de mie, réserver.","Faire cuire les œufs durs, les écraser.","Mélanger les œufs, la mayonnaise, le sel et le poivre noir.","Ajouter le beurre dans une poêle, faire cuire le bacon.","Assembler le sandwich : entre deux tranches de pain de mie, ajouter la préparation aux œufs et le bacon.","Couper le sandwich carré en triangles et servir."]'::jsonb, '["Petit-déjeuner","Rapide","Occidental","Salé","Poêlé"]'::jsonb),
  ('howtocook:condiment/油泼辣子/油泼辣子', 'fr', 'Huile pimentée', 'Sauces', 'Un condiment épicé et parfumé du Shaanxi, à l''huile rouge brillante, mêlant sésame et ail. En bouche, il est piquant sans être irritant, avec une longue rémanence. Le piment est riche en vitamine C et en capsaïcine, ce qui stimule l''appétit et réchauffe le corps. La maîtrise de la température de l''huile demande un peu d''attention pour les débutants, mais en suivant les étapes, c''est réalisable. Prêt en environ 10 minutes, c''est la touche finale pour les salades et les nouilles maison.', '[{"name":"tête d''ail","unit":"pièce"},{"name":"poudre de piment séché","unit":"gramme"},{"name":"sel","unit":"gramme"},{"name":"graines de sésame blanc grillées","unit":"gramme"},{"name":"piment rouge","unit":"pièce"},{"name":"huile d''arachide","unit":"millilitre"},{"name":"cinq-épices","unit":"gramme"},{"name":"amome","unit":"pièce"},{"name":"ciboule","unit":"tige"},{"name":"anis étoilé"},{"name":"poivre de Sichuan","unit":"grain"},{"name":"feuille de laurier","unit":"feuille"},{"name":"angélique","unit":"tranche"},{"name":"tranche de gingembre","note":"quantité suffisante"},{"name":"sucre","unit":"gramme"},{"name":"vinaigre blanc","unit":"ml"},{"name":"glutamate monosodique","note":"quantité suffisante"}]'::jsonb, '["Prenez 2 petites têtes d''ail, épluchez-les.","Sur une planche à découper, hachez finement l''ail et les piments rouges.","Prenez un bol et versez l''huile d''arachide.","Quand l''huile est chaude, ajoutez les autres ingrédients et la ciboule. Attendez que les épices brunissent, puis retirez-les et jetez-les.","Prenez une casserole en fer, versez l''huile du bol et chauffez 2 minutes (l''huile de colza doit fumer).","Pendant ce temps, le bol est vide.","Dans le bol vide, ajoutez la poudre de piment séché, les graines de sésame blanc grillées, l''ail haché, le piment rouge, le sel, le cinq-épices, l''amome comme ''assaisonnement''.","Éteignez le feu et laissez l''huile refroidir à 210°C.","Versez l''huile chaude dans le bol et remuez avec une cuillère. (On peut, à 165°C, ajouter un autre bol du même assaisonnement pour augmenter le piquant.)","Après avoir versé l''huile chaude et remué légèrement, ajoutez le vinaigre blanc. Il va bouillonner à nouveau. Continuez de remuer. Le vinaigre blanc rehausse l''arôme.","Laissez refroidir l''huile pimentée à tiède, puis ajoutez le sucre blanc et le glutamate. Le sucre blanc adoucit le piquant, le rend moins agressif."]'::jsonb, '["Sauce","Épicé","Style du Shaanxi","En salade","Rapide","Condiment"]'::jsonb),
  ('howtocook:condiment/油酥', 'fr', 'Pâte à l''huile', 'Sauces', 'C''est un ingrédient de pâtisserie chinoise, souvent utilisé pour les crêpes, qui donne une texture feuilletée, croustillante à l''extérieur et moelleuse à l''intérieur. Il apporte principalement des glucides et des lipides pour fournir de l''énergie. La préparation est très simple, idéale pour les débutants, et prend seulement 3 minutes.', '[{"name":"farine","note":"quantité suffisante"},{"name":"huile","unit":"ml"},{"name":"sel","note":"quantité suffisante"}]'::jsonb, '["Mettez la farine dans un petit bol, ajoutez le sel.","Ajoutez l''huile chaude à 200 degrés.","Remuez avec des baguettes jusqu''à obtenir une pâte lisse sans grumeaux."]'::jsonb, '["Condiment","Croustillant","Pâtisserie chinoise","Crêpe chinoise","Fait maison","Rapide"]'::jsonb),
  ('howtocook:condiment/炸串酱料', 'fr', 'Sauce pour brochettes frites', 'Sauces', 'Cette sauce universelle pour brochettes frites est épicée, riche, salée et savoureuse, avec une saveur de rue. Elle apporte principalement des matières grasses et des arômes d''épices qui stimulent l''appétit. La préparation est très simple, sans stress pour les débutants, et ne prend qu''environ 10 minutes.', '[{"name":"Poudre de piment sec (grossière et fine)","unit":"grammes"},{"name":"Poudre de cumin","unit":"grammes"},{"name":"Poudre de poivre","unit":"grammes"},{"name":"Poudre de cinq épices","unit":"grammes"},{"name":"Poudre de poivre du Sichuan","unit":"grammes"},{"name":"Treize épices","unit":"grammes"},{"name":"Mélange piquant et salé","unit":"grammes"},{"name":"Graines de sésame blanc","unit":"grammes"},{"name":"Sel","unit":"grammes"},{"name":"Glutamate monosodique","unit":"grammes"},{"name":"Huile","note":"suffisamment pour recouvrir tous les ingrédients"},{"name":"Huile de sésame","unit":"ml"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Huile de poivre du Sichuan","unit":"ml"},{"name":"Sauce d''huître","unit":"ml"}]'::jsonb, '["Mélanger tous les ingrédients dans un récipient et remuer uniformément.","Faire chauffer l''huile dans une casserole, la quantité d''huile doit être suffisante pour recouvrir tous les ingrédients dans le récipient.","Verser l''huile chaude en trois fois, 1/3 à chaque fois, en remuant en même temps.","Ajouter enfin 10 ml d''huile de sésame, 10 ml de sauce soja légère, 10 ml d''huile de poivre du Sichuan et 10 ml de sauce d''huître."]'::jsonb, '["Sauce","Épicé","Saveur de rue","Rapide","Savoureux","Universel"]'::jsonb),
  ('howtocook:condiment/简易版炒糖色', 'fr', 'Caramelisation simplifiée', 'Sauces', 'La caramélisation du sucre est une technique clé pour colorer les plats mijotés (braisés) de la cuisine chinoise. Lorsque la cuisson est maîtrisée, elle apporte une brillance rouge éclatante et une saveur caramélisée unique. L''ingrédient principal est le sucre, qui fournit de l''énergie, mais surtout harmonise la couleur et le goût du plat. Cette version simplifiée de la caramélisation du sucre demande un certain contrôle de la cuisson ; les débutants doivent s''entraîner pour éviter un goût amer ou trop sucré. La préparation prend environ dix minutes.', '[{"name":"Sucre candi / Sucre blanc / Sucre en poudre (au choix)","unit":"g"},{"name":"Huile","unit":"ml"},{"name":"Eau bouillante","unit":"ml"}]'::jsonb, '["Allumez le feu et versez 100 ml d''eau bouillante dans la poêle.","Versez ensuite 100 ml d''huile dans la poêle, le plus rapidement possible après la première étape. À ce stade, le feu peut être vif ou moyen ; si vous êtes pressé, utilisez un feu vif.","Ajoutez le sucre candi (sucre en morceaux). Si les morceaux sont trop liés, cassez-les à l''avance pour qu''ils soient le plus séparés possible.","Réduisez le feu à moyen.","Commencez à remuer.","Remuez sans cesse, sans cesse, sans cesse, jusqu''à ce que le mélange prenne une couleur brun foncé, puis passez à feu doux.","Il devient plus liquide, prend une couleur de thé rouge, puis une couleur rouge foncé avec de petites bulles. Préparez-vous à effectuer l''option 1 ou l''option 2 ci-dessous.","Les petites bulles disparaissent progressivement, puis de grosses bulles apparaissent. Lorsque les grosses bulles apparaissent, la caramélisation est prête.","Il faut alors rapidement passer à l''étape suivante (quelle que soit l''option choisie, préparez-la à l''avance et agissez vite ! Sinon, la caramélisation brûlera et deviendra amère). Choisissez selon le type de plat et vos goûts personnels.","Option 1 : Ajoutez directement 400 ml d''eau bouillante pour refroidir.","Option 2 (version avancée avec assaisonnement) : Lorsque le sirop de sucre devient rouge jujube et forme des bulles denses, ajoutez rapidement les aromates préparés à l''avance (oignon vert, gingembre, ail, poivre du Sichuan, etc.) et faites-les sauter. Après avoir libéré les arômes (environ 5 à 10 secondes), versez immédiatement 400 ml d''eau bouillante pour arrêter la réaction. (Remarque : si la recette suivante nécessite de faire sauter de la viande pour la colorer, ajoutez d''abord la viande à cette étape et faites-la sauter avant d''ajouter l''eau.)"]'::jsonb, '["Sauce","Salé-sucré","Caramélisé","Sauté","Fait maison","Coloration pour braisé"]'::jsonb),
  ('howtocook:condiment/糖醋汁', 'fr', 'Sauce aigre-douce', 'Sauces', 'Cette sauce aigre-douce est sucrée et acidulée, source de saveur classique dans les plats aigres-doux de la cuisine chinoise. La préparation est simple, les proportions faciles à retenir, même les débutants peuvent la maîtriser. Du début à la fin, il faut environ 10 minutes. Le sucre fournit de l''énergie, le vinaigre ouvre l''appétit et coupe le gras, transformant un plat familial en un mets savoureux.', '[{"name":"Eau","unit":"ml"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Sucre blanc","unit":"g"},{"name":"Vinaigre blanc/vinaigre de riz","unit":"ml"},{"name":"Vin de cuisine chinois","unit":"ml"}]'::jsonb, '["Mélanger tous les assaisonnements dans un petit bol selon les proportions.","Après avoir préparé les ingrédients selon la méthode du plat choisi, verser la sauce aigre-douce dans la poêle.","Cuire pendant 5 à 10 minutes selon le plat.","Faire réduire à feu vif pour augmenter la concentration, l''arôme et le brillant du plat."]'::jsonb, '["Sauce","Aigre-doux","Assaisonnement","Cuisine chinoise","Maison","Rapide"]'::jsonb),
  ('howtocook:condiment/草莓酱/草莓酱', 'fr', 'Confiture de fraises', 'Sauces', 'C''est une confiture maison aigre-douce et fruitée, parfaite pour tartiner sur du pain. Les fraises sont riches en vitamine C, mais la cuisson ajoute beaucoup de sucre, vous pouvez ajuster selon votre goût. La préparation est très simple, même les débutants peuvent la réussir facilement. Il faut environ deux heures de la préparation à la fin de la cuisson.', '[{"name":"Fraises","unit":"g"},{"name":"Sucre blanc","unit":"g"}]'::jsonb, '["Laver les fraises et enlever les feuilles","Couper les fraises en morceaux et les mettre dans un bol approprié","Verser le sucre blanc dans le bol et mélanger avec les fraises","Couvrir le bol avec du film alimentaire et laisser reposer 1 heure","Verser le mélange de fraises et de sucre reposé dans une poêle antiadhésive et porter à ébullition à feu vif","Une fois à ébullition, réduire à feu doux et remuer constamment jusqu''à ce que la confiture épaississe, puis éteindre le feu","Laisser refroidir la confiture de fraises, puis la verser dans un pot hermétique préparé"]'::jsonb, '["Confiture","Aigre-doux","Familial","Fait maison","Rapide"]'::jsonb),
  ('howtocook:condiment/葱油', 'fr', 'Huile de ciboule', 'Sauces', 'L''huile de ciboule est une huile d''assaisonnement maison qui rehausse les arômes et la saveur, avec un fort parfum d''oignon vert et la saveur umami des crevettes séchées. Elle convient pour les farces, les salades ou comme huile de finition pour les plats chauds. Elle fournit principalement de l''énergie lipidique, et les épices comme l''oignon vert et le gingembre contiennent des composés actifs végétaux qui aident à éliminer les odeurs et à ouvrir l''appétit. La recette est simple et convient aux débutants ; la préparation et la cuisson prennent environ 30 minutes.', '[{"name":"Huile","unit":"g"},{"name":"Ciboule (grosse ou petite)","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Oignon","unit":"g"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Crevettes séchées (optionnel)","unit":"g"},{"name":"Coriandre (optionnel)","note":"Quantité suffisante"}]'::jsonb, '["Faire tremper les crevettes séchées dans de l''eau tiède à 50°C, ajouter 10 ml de vin de cuisine pour enlever l''odeur, laisser tremper 10 minutes, puis égoutter.","Laver les oignons verts et la coriandre, couper en tronçons de 5 cm, sécher la surface.","Émincer l''oignon, le blanchir dans de l''eau chaude bouillante pendant 5 minutes, égoutter.","Peler le gingembre, le couper en tranches.","Verser toute l''huile dans une casserole, ajouter tous les ingrédients préparés, chauffer à feu moyen-doux pendant 20 minutes."]'::jsonb, '["Condiment","Arôme d''oignon vert","Saveur umami","Huile d''assaisonnement","Pour farces","Pour nouilles","Versée chaude"]'::jsonb),
  ('howtocook:condiment/蒜香酱油', 'fr', 'Sauce soja à l''ail', 'Sauces', 'La sauce soja à l''ail est une trempette maison parfumée à l''ail, salée et huileuse, souvent utilisée pour rehausser le goût du poulet blanc, des raviolis, etc. L''ail et le sésame ont respectivement des propriétés antibactériennes et apportent des acides gras insaturés. La préparation est extrêmement simple, très accessible aux débutants, et ne prend qu''environ 5 minutes.', '[{"name":"Ail","unit":"gousse(s)"},{"name":"Sésame blanc","unit":"gramme(s)"},{"name":"Huile d''arachide","unit":"ml"},{"name":"Sauce soja","unit":"ml"}]'::jsonb, '["Écraser les gousses d''ail","Ajouter la sauce soja dans le bol de trempette","Mettre une casserole sur le feu, ajouter l''huile d''arachide, quand l''huile est très chaude, ajouter l''ail écrasé et faire frire pendant une demi-minute","Au bout d''une demi-minute, éteindre le feu, verser l''huile chaude dans le bol de trempette, et remuer avec des baguettes."]'::jsonb, '["Sauce","Ail","Salé","Frit","Maison","Trempette"]'::jsonb),
  ('howtocook:condiment/蔗糖糖浆/蔗糖糖浆', 'fr', 'Sirop de sucre', 'Sauces', 'Sirop de boisson maison, mélanger le sucre blanc et l''eau dans un rapport 1:1 pour dissoudre, pratique pour contrôler la douceur des boissons froides, c''est la base des boissons mélangées. Riche en glucides, donne rapidement de l''énergie. La méthode est très simple, très conviviale pour les débutants, ne prend que quelques minutes, se conserve une semaine au réfrigérateur.', '[{"name":"Sucre blanc","unit":"g"},{"name":"Eau","unit":"g"}]'::jsonb, '["Mélanger le sucre blanc pesé et l''eau potable dans un récipient","Couvrir le récipient et placer au réfrigérateur"]'::jsonb, '["Sauce","Sucré","Base pour boissons","Rapide","Au réfrigérateur"]'::jsonb),
  ('howtocook:dessert/反沙芋头/反沙芋头', 'fr', 'Taro frit au sucre', 'Desserts', 'Le taro frit au sucre est une collation traditionnelle de Chaozhou, croustillante à l''extérieur et moelleuse à l''intérieur, sucrée et parfumée. Souvent servi au goûter. Le taro de Lipu est riche en fibres alimentaires, potassium et diverses vitamines, offrant une satiété durable. La préparation n''est pas difficile mais nécessite de maîtriser la cuisson du sucre. Convient aux débutants ayant quelques bases, le tout se fait en environ 20 minutes.', '[{"name":"Taro de Lipu","unit":"grammes"},{"name":"Sucre blanc ou sucre candi","unit":"grammes"},{"name":"Eau","unit":"grammes"},{"name":"Oignon vert","note":"Quantité suffisante"}]'::jsonb, '["Couper le taro en bâtonnets (assez gros pour ne pas se défaire pendant la cuisson).","Ajouter suffisamment d''huile pour couvrir le taro, chauffer jusqu''à ce que l''huile soit chaude (des petites bulles apparaissent quand on y plonge une baguette).","Mettre le taro dans l''huile et frire jusqu''à ce qu''il remonte à la surface, généralement légèrement doré et qu''une baguette le transperce facilement.","Conserver l''huile de friture pour une autre utilisation (sautés, etc.).","Étape cruciale : mélanger le sucre (30g) et l''eau (15g) dans un rapport 2:1, chauffer sans coloration jusqu''à apparition de petites bulles.","Ajouter l''oignon vert et le taro, éteindre le feu et remuer. Laisser refroidir pour que le sucre cristallise et donne un aspect givré.","Dresser et servir !"]'::jsonb, '["Dessert","Chaozhou","Frit","Sucré parfumé","Goûter","Pâtisserie"]'::jsonb),
  ('howtocook:dessert/咖啡椰奶冻/咖啡椰奶冻', 'fr', 'Gelée de café au lait de coco', 'Desserts', 'Ce dessert allie la richesse du café à la douceur du lait de coco. Sa texture est aussi fine et soyeuse qu''un pudding, avec des couches riches. La crème légère et le lait de coco apportent des lipides de qualité et des nutriments végétaux, ce qui procure une sensation de satisfaction. La préparation est très simple : il suffit de mélanger et de chauffer, sans technique compliquée, même les débutants réussissent du premier coup. Sans compter la réfrigération, le temps de préparation est d''environ 1 heure, et avec la prise au froid, il faut compter environ 4 heures avant de déguster.', '[{"name":"Crème légère","unit":"ml"},{"name":"Lait de coco (marque Cocowang)","unit":"ml"},{"name":"Espresso","unit":"ml"},{"name":"Eau de coco","unit":"ml"},{"name":"Gélatine","unit":"g"},{"name":"Sucre","note":"au goût"},{"name":"Myrtilles","note":"au goût"},{"name":"Café en poudre","note":"au goût"}]'::jsonb, '["Mélanger la crème légère, le lait de coco (marque Cocowang), l''espresso et l''eau de coco. Réserver.","Chauffer le mélange liquide pendant 1 minute, jusqu''à une température de 50-60 °C.","(Optionnel) Ajouter du sucre supplémentaire si vous aimez très sucré.","Ajouter la gélatine, remuer jusqu''à dissolution, puis cuire 1 minute.","(Optionnel) Passer au tamis (cette étape rend la gelée de coco plus lisse).","Verser dans des moules.","(Optionnel) Filtrer les bulles en surface. Cette étape améliore la texture et l''apparence de la gelée.","Placer au réfrigérateur et laisser prendre pendant 3 heures."]'::jsonb, '["Dessert","Arôme de café","Arôme de coco","Sans cuisson","Texture de pudding","Goûter"]'::jsonb),
  ('howtocook:dessert/奥利奥冰淇淋/奥利奥冰淇淋', 'fr', 'Glace à l''Oréo', 'Desserts', 'La glace à l''Oréo est onctueuse, avec un mélange de saveur lactée et du croquant sucré des Oréo. La crème entière animale la rend légère et non grasse. Elle apporte principalement de l''énergie, des lipides et des glucides, parfaite comme petite douceur rafraîchissante. La préparation est simple : il suffit de retirer le fourrage des biscuits et de fouetter la crème. Un débutant patient peut y arriver. Comptez environ 30 minutes de préparation, puis 4 heures de congélation minimum.', '[{"name":"Crème liquide entière (marque recommandée : Anchor)","unit":"ml"},{"name":"Oréo original","unit":"pièces"},{"name":"Sucre blanc","unit":"g"}]'::jsonb, '["Tourner les Oréo pour les ouvrir, retirer le fourrage (appelé ''利利'') et réserver.","Écraser les biscuits Oréo (les ''奥奥'') avec une baguette. La moitié doit devenir en poudre, l''autre moitié avoir des morceaux de moins de 0,5 cm. Réserver. (Sur Taobao, cherchez ''miettes d''Oréo'' pour gagner du temps ^-^)","Verser toute la crème dans un grand bol et ajouter le sucre préparé.","Fouetter à vitesse élevée avec un batteur électrique jusqu''à ce que la crème forme des pics mous (0,5 cm à 1 cm) lorsqu''on soulève le batteur, et qu''elle ne coule plus comme un liquide (un peu de coulure est normal).","Une fois fouettée, incorporer les miettes d''Oréo et mélanger uniformément jusqu''à ce que le fond en contienne.","Optionnel : verser le mélange dans des moules à glace.","Placer au congélateur (à -18 °C) pendant au moins 4 heures avant de servir."]'::jsonb, '["Dessert","Lacté","Sucré","Surgelé","Rapide","Goûter"]'::jsonb),
  ('howtocook:dessert/戚风蛋糕/戚风蛋糕', 'fr', 'Gâteau chiffon', 'Desserts', 'Ce dessert de pâtisserie d''entrée de gamme a une texture délicate et moelleuse, avec une légèreté semblable à un nuage. C''est un grand classique de la pâtisserie occidentale. Les ingrédients principaux, œufs et lait, fournissent des protéines de qualité et du calcium, riches en nutriments. Le processus de fabrication exige une certaine maîtrise pour le fouettage, le mélange et la cuisson, ce qui représente un défi, mais en suivant les étapes avec patience, même un débutant peut réussir. De la préparation à la sortie du four, il faut généralement 1h30 à 2h.', '[{"name":"Œufs","unit":"pièce","note":""},{"name":"Sucre blanc","unit":"g","note":""},{"name":"Lait (ou eau)","unit":"g","note":""},{"name":"Huile végétale (ou beurre)","unit":"g","note":""},{"name":"Farine à gâteau","unit":"g","note":""},{"name":"Jus de citron ou vinaigre blanc (facultatif)","unit":"","note":"quantité suffisante"}]'::jsonb, '["Sortez les œufs frais du réfrigérateur.","Préparez deux récipients et essuyez-les, l''un pour les blancs d''œufs, l''autre pour les jaunes.","Le récipient pour les blancs peut avoir quelques gouttes d''eau, mais pas de graisse ; celui pour les jaunes ne doit avoir aucune goutte d''eau.","Cassez les œufs, à la main ou à l''aide d''un séparateur, et séparez les blancs des jaunes dans les deux récipients.","Pendant la séparation, les jaunes ne doivent pas se briser, et les blancs ne doivent contenir aucun jaune, sinon le fouettage sera compromis (les cordons blancs peuvent aller dans les blancs, sans problème).","(Note : sans robot, le récipient des blancs sert aussi à les fouetter ; pour éviter les débordements, ne dépassez pas 1/8 du récipient après avoir ajouté tous les blancs.)","Préparez un nouveau bol vide, ajoutez toute l''huile et tout le lait de la recette.","Fouettez rapidement à la main jusqu''à ce que l''huile et l''eau soient complètement fusionnées, formant un liquide blanc laiteux (émulsion).","Tamisez toute la farine à gâteau dans l''émulsion. Mélangez en forme de « Z » avec une spatule jusqu''à ce qu''il n''y ait plus de farine visible (la pâte peut être un peu grumeleuse, c''est normal).","Ajoutez tous les jaunes d''œufs séparés dans le bol, continuez à mélanger en « Z » avec la spatule.","Maintenant, la pâte devient très lisse et ne développe pas facilement de gluten. Laissez reposer.","Préparez les 3/4 restants du sucre. Divisez-les en trois parts, chacune représentant 1/4 du total.","Ajoutez du jus de citron ou du vinaigre blanc (facultatif) aux blancs d''œufs.","Fouettez les blancs à vitesse moyenne jusqu''à ce qu''ils aient de grosses bulles, puis ajoutez la première part de sucre.","Fouettez à vitesse élevée jusqu''à ce que les bulles soient plus fines, ajoutez la deuxième part de sucre.","Fouettez à vitesse élevée jusqu''au stade « pics mous », ajoutez la troisième part de sucre.","Fouettez à vitesse moyenne-basse jusqu''au stade « pics fermes ».","Les blancs sont maintenant à la bonne consistance.","Pour juger de l''état des blancs, référez-vous aux images dans le lien en annexe.)","Le fouet doit rester près du fond du récipient pour éviter que le dessus soit monté mais que le fond reste liquide.)","Mélangez rapidement la pâte aux jaunes.","Prélevez 1/3 des blancs montés avec une spatule et incorporez-les à la pâte aux jaunes.","Utilisez la technique de « mélange par pliage » pour éviter de casser les blancs.","La technique est la suivante :","Avec la main droite, insérez la spatule au centre du bol jusqu''au fond.","Raclez vers la position 8 heures jusqu''à rencontrer la paroi, puis soulevez la pâte en l''air et ramenez-la au centre du bol.","Avec la main gauche, tournez le bol de la position 9 heures à 7 heures, soit une rotation de 60 degrés, pour compléter un cycle.","La vitesse est d''environ deux mouvements par seconde.","Cette méthode vient du « Cours de pâtisserie de M. Kojima ». En termes simples, c''est comme faire sauter des aliments.","Versez le mélange de 1/3 des blancs et des jaunes dans les 2/3 restants des blancs, et continuez à mélanger par pliage.","Versez la pâte dans le moule et tapotez quelques fois pour éliminer les grosses bulles.","Temps de cuisson total : pour un moule de 6 pouces, 30-35 minutes ; pour 8 pouces, 50 minutes. Ajustez selon votre four, généralement pas plus de ±5 minutes (observer pendant les dernières minutes).","Préchauffez à 150°C en chaleur sole et 160°C en chaleur voûte, environ 10 minutes pour atteindre la température.","Une fois le préchauffage terminé, placez le moule en bas du four.","Choisissez une cuisson à température variable en deux étapes.","Première étape : thermostat à 150°C en haut, 160°C en bas.","Les 3/5 du temps de cuisson total correspondent à la première étape.","Deuxième étape : température à 160°C en haut, 170°C en bas.","Les 2/5 restants du temps total correspondent à la deuxième étape. Ajustez directement le four.","Une fois cuit, sortez du four.","Attention, cela peut brûler, utilisez un torchon.","Préchauffage : airfryer à 130°C pendant 5 minutes.","Mettez le moule avec la pâte dans l''airfryer. Couvrez immédiatement d''une feuille d''aluminium (côté brillant vers le haut, côté mat en contact avec les aliments), serrez les bords pour éviter qu''elle ne s''envole.","Première étape de cuisson : 130°C pendant 35 minutes.","Deuxième étape pour le coloriage : ouvrez l''airfryer, retirez le papier aluminium. Augmentez la température à 150°C et poursuivez la cuisson pendant 10–15 minutes.","Vérifiez la cuisson : le gâteau est gonflé et doré ; plantez un cure-dent au centre, s''il ressort sec, c''est cuit.","Les opérations de retournement et de démoulage après cuisson sont identiques à celles du four.","(Facultatif) Faites tomber le moule de hauteur pour libérer la vapeur.","Retournez le moule pendant 10 minutes pour refroidir le gâteau.","Démouler un gâteau chaud l''endommagera.","Attention, cela peut brûler, utilisez un torchon.","Démoulez et servez."]'::jsonb, '["dessert","sucré","pâtisserie","gâteau","goûter","classique"]'::jsonb),
  ('howtocook:dessert/提拉米苏/提拉米苏', 'fr', 'Tiramisu', 'Desserts', 'Ce dessert italien traditionnel ne nécessite pas de four. La crème au mascarpone est onctueuse et légère, les biscuits à la cuiller imbibés de café sont parfumés et moelleux. C''est un dessert d''entrée de gamme. Riche en protéines et en calcium, mais assez sucré et calorique, à consommer avec modération. Simple à réaliser, très accessible aux débutants en pâtisserie. Il ne faut qu''environ une demi-heure de préparation, puis quatre heures de réfrigération pour le déguster.', '[{"name":"mascarpone","unit":"g"},{"name":"biscuits à la cuiller","unit":"paquet"},{"name":"café expresso refroidi","unit":"ml"},{"name":"œufs stérilisés","unit":"pièce(s)"},{"name":"sucre blanc","unit":"g"},{"name":"cacao en poudre","unit":"g"},{"name":"rhum","unit":"ml"}]'::jsonb, '["Séparer les jaunes des blancs d''œufs","Dans le bol contenant les blancs, ajouter 10g de sucre blanc et les fouetter jusqu''à ce qu''ils soient mousseux","Dans le bol des jaunes, ajouter 40g de sucre blanc en trois fois, en mélangeant jusqu''à homogénéité","Ajouter le mascarpone aux jaunes en trois fois, en mélangeant jusqu''à homogénéité","Ajouter le rhum aux jaunes et mélanger bien","Incorporer les blancs montés en neige au mélange jaunes-mascarpone en trois fois","Tremper rapidement les biscuits à la cuiller des deux côtés dans le café refroidi, puis les disposer en une couche dans le plat","Alterner deux couches de crème et deux couches de biscuits (ajuster selon la hauteur du plat et vos préférences)","Réfrigérer pendant quatre heures (on peut sortir plus tôt si on est pressé)","Saupoudrer de cacao en poudre avant de servir"]'::jsonb, '["Dessert","Sans cuisson","Italien","Sucré","Goûter","Pour recevoir"]'::jsonb),
  ('howtocook:dessert/无厨师机蜂蜜面包/无厨师机蜂蜜面包', 'fr', 'Pain au miel sans robot pétrisseur', 'Desserts', 'Ce petit pain au miel fait maison ne nécessite pas de robot pétrisseur. Il est moelleux et sucré, avec un fond légèrement croustillant. Badigeonné d''eau de miel et parsemé de sésame, il dégage un parfum sucré et rustique. Les ingrédients principaux sont la farine de blé, le lait, les œufs et le beurre, fournissant des glucides, des protéines et du calcium. Parfait pour le petit-déjeuner ou une collation. La recette est simple, entièrement pétrie à la main, avec un temps de fermentation flexible. On peut même le laisser au réfrigérateur toute la nuit et le cuire le lendemain, idéal pour les débutants. Le temps de préparation est d''environ 3 heures, dont la plupart est le temps de levée, le travail réel est minime.', '[{"name":"Farine de blé","unit":"g"},{"name":"Lait","unit":"g"},{"name":"Levure","unit":"g"},{"name":"Œufs","unit":"unité(s)"},{"name":"Sucre blanc","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Beurre","unit":"g"},{"name":"Miel","unit":"g"},{"name":"Eau","unit":"g"},{"name":"Huile d''arachide","note":"quantité suffisante"},{"name":"Sésame","note":"quantité suffisante"}]'::jsonb, '["Préparer la pâte : mélanger la farine, le lait (suggéré de chauffer à 40°C, j''utilise le micro-ondes 15-20s), la levure, les œufs, la farine, le sucre et le sel.","Mélanger la pâte jusqu''à obtenir une boule homogène.","Ajouter le beurre et mélanger.","Continuer à mélanger et pétrir à la main jusqu''à incorporation homogène.","Commencer la levée : couvrir le récipient avec du film plastique, laisser reposer à température ambiante (10-20°C) pendant 1 à 2 heures. Un temps plus long n''affecte pas beaucoup le résultat.","Une fois que la pâte a doublé de volume, la diviser. À ce stade, la pâte ne devrait plus être trop collante.","Diviser la pâte : idéalement en portions de 60g pour un bel aspect, mais ajuster selon les préférences.","Étaler chaque portion en forme de langue avec un rouleau à pâtisserie, puis rouler. Laisser reposer à nouveau 10 minutes.","Étaler à nouveau en forme de langue, rouler, puis couper en deux au milieu (un morceau devient deux).","Étaler encore une fois, rouler, et couper en deux (deux deviennent quatre). (Cette étape peut être répétée selon le temps disponible, en ajustant la taille des portions.)","Mettre du papier sulfurisé dans le moule et verser de l''huile d''arachide. Tremper le fond de chaque morceau roulé dans l''eau puis dans la farine, et les disposer dans le moule.","Laisser lever à nouveau (couvrir avec du film plastique). On peut aussi le mettre au réfrigérateur et cuire le lendemain.","Badigeonner d''œuf battu.","Cuire au four à 180°C (355°F) pendant 18-20 minutes.","À la sortie du four, badigeonner d''eau de miel et saupoudrer de sésame."]'::jsonb, '["Desserts","Sucré","Pâtisserie","Petit-déjeuner","Pétrissage à la main","Débutant"]'::jsonb),
  ('howtocook:dessert/炸鲜奶/炸鲜奶', 'fr', 'Lait frit', 'Desserts', 'Le lait frit est un dessert classique croustillant à l''extérieur et tendre à l''intérieur, sucré et délicieux, appartenant aux collations maison. Riche en protéines et calcium, son équilibre nutritionnel est bon. Difficulté moyenne, même les débutants peuvent le réussir. Temps de préparation environ 20 minutes, mais nécessite 1 heure de réfrigération pour la prise.', '[{"name":"Lait","unit":"g"},{"name":"Fécule de maïs","unit":"g"},{"name":"Chapelure","unit":"g"},{"name":"Œuf","unit":"pièce"},{"name":"Sucre blanc","unit":"g"}]'::jsonb, '["Versez le lait dans un bol","Ajoutez la fécule de maïs et le sucre blanc, mélangez bien","Huilez légèrement un moule avec de l''huile de cuisson","Versez le lait dans une casserole et portez à ébullition à feu moyen","Une fois à ébullition, réduisez à feu doux et remuez constamment","Lorsque le lait épaissit, retirez du feu et versez dans le moule","Placez le moule au réfrigérateur pendant 1 heure pour refroidir et prendre","Sortez du réfrigérateur, coupez en bâtonnets de taille égale, puis placez dans un bol","Versez la moitié de la chapelure dans le bol, enrobez les bâtonnets, retirez et réservez","Dans un nouveau bol, battez l''œuf, réservez","Enrobez les bâtonnets d''œuf battu puis du reste de chapelure","Versez suffisamment d''huile dans une casserole pour couvrir les bâtonnets, puis plongez-les","Lorsqu''ils sont dorés, retirez du feu et disposez dans une assiette"]'::jsonb, '["Dessert","Sucré","Frit","Croustillant dehors, tendre dedans","Dessert maison","Goûter"]'::jsonb),
  ('howtocook:dessert/烤箱版巴斯克芝士蛋糕/烤箱版巴斯克芝士蛋糕', 'fr', 'Gâteau au fromage basque', 'Desserts', 'Le gâteau au fromage basque est un dessert à la texture riche et crémeuse, avec une surface caramélisée et un intérieur humide. C''est une spécialité classique de la région basque en Espagne. Les ingrédients principaux sont le cream cheese et les œufs, riches en protéines et calcium. La préparation est très simple, même les débutants peuvent le réussir. De la préparation à la sortie du four, cela ne prend qu''environ 30 minutes, mais il est recommandé de le réfrigérer toute une nuit avant de le déguster, le temps total est donc de plus de 8 heures.', '[{"name":"Cream cheese","unit":"gramme"},{"name":"Sucre blanc","unit":"gramme"},{"name":"Œuf","unit":"pièce"},{"name":"Jaune d''œuf","unit":"pièce"},{"name":"Crème liquide","unit":"gramme"},{"name":"Farine de blé (type 45)","unit":"gramme"}]'::jsonb, '["Ramollir le cream cheese au micro-ondes : 10s + 10s.","Ajouter le sucre blanc au cream cheese, battre avec un batteur jusqu''à obtenir une consistance lisse.","Ajouter 2 œufs entiers + 1 jaune d''œuf, mélanger uniformément.","Ajouter la crème liquide, mélanger uniformément.","Ajouter la farine de blé (type 45), mélanger uniformément.","Cuire au four à 220°C (425°F) pendant 20 à 25 minutes (je fais généralement 20 ou 22 minutes).","Laisser refroidir, puis placer au réfrigérateur, de préférence toute une nuit."]'::jsonb, '["Dessert","Sucré","Cuisson au four","Occidental","Rapide","Goûter"]'::jsonb),
  ('howtocook:dessert/烤蛋挞/烤蛋挞', 'fr', 'Tartelettes aux œufs', 'Desserts', 'Les tartelettes aux œufs sont un dessert chinois classique, avec une croûte croustillante et une garniture lisse et crémeuse, au riche goût de lait. Riches en protéines, calcium et diverses vitamines, elles fournissent une bonne énergie. La préparation est très simple, même les débutants peuvent facilement réussir, et les mi-cuites peuvent être congelées pour être dégustées à tout moment. De la préparation à la sortie du four, cela prend environ 1 heure.', '[{"name":"Fonds de tarte","unit":"pièce"},{"name":"Œufs","unit":"pièce"},{"name":"Lait","unit":"ml"},{"name":"Crème liquide","unit":"ml"},{"name":"Sucre blanc","unit":"g"}]'::jsonb, '["Placez le bol sur une balance et pesez 450 g de crème liquide (la densité de la crème liquide est considérée comme 1 ici).","Ajoutez 80 g de sucre blanc (douceur moyenne, ajustez selon votre goût, plage suggérée 60-100 g).","Ajoutez 200 g de lait (la densité du lait est considérée comme 1 ici).","Prenez 8 jaunes d''œufs et ajoutez-les (les blancs peuvent être réservés pour autre usage).","Mélangez uniformément tous les ingrédients jusqu''à ce que le sucre soit complètement dissous.","Filtrez le mélange à l''aide d''un tamis pour éliminer les membranes des œufs, les coquilles, le sucre non dissous et les grumeaux de crème.","Préchauffez le four à 220 °C (environ 10 minutes) et sortez la plaque de cuisson.","Placez les fonds de tarte uniformément sur la plaque de cuisson avec un espacement de 0,5 cm.","Versez le mélange filtré dans les fonds de tarte, jusqu''à 0,5 cm du bord, ne pas trop remplir.","À ce stade, les tartelettes mi-cuites sont prêtes. Vous pouvez les congeler directement pendant au moins 12 heures pour les conserver.","Placez les tartelettes mi-cuites au four et cuisez à 200 °C pendant 25 minutes.","Une fois cuites, elles sont prêtes à être dégustées."]'::jsonb, '["Dessert","Lacté","Pâtisserie","Débutant","Fait maison","Congélation","Goûter"]'::jsonb),
  ('howtocook:dessert/玛格丽特饼干/玛格丽特饼干', 'fr', 'Biscuits Marguerite', 'Desserts', 'Les biscuits Marguerite sont croustillants, riches en arôme de beurre, et constituent un classique des petits desserts occidentaux. Ils sont principalement composés de jaune d''œuf, de beurre et de farine, riches en glucides et en lipides, fournissant une énergie rapide. La difficulté de préparation est modérée, nécessitant environ 45 minutes de la préparation à la sortie du four, et même les débutants peuvent les réaliser facilement.', '[{"name":"Jaune d''œuf cuit","unit":"pièce"},{"name":"Beurre","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Farine de blé tendre","unit":"g"},{"name":"Fécule de maïs","unit":"g"}]'::jsonb, '["Faire fondre le beurre au bain-marie, réduire le jaune d''œuf en poudre.","Ajouter le sucre, le sel et le jaune d''œuf écrasé au beurre fondu, mélanger uniformément.","Ajouter la farine de blé tendre et la fécule de maïs, pétrir en une pâte.","Diviser la pâte en petites boules d''environ 8 g, puis les rouler en boules.","Presser légèrement chaque petite boule avec le pouce pour créer des fissures.","Préchauffer le four à 150°C, placer les petites boules dans le four, cuire 20 minutes.","Laisser refroidir légèrement avant de déguster."]'::jsonb, '["Dessert","Croustillant","Saveur de beurre","Pâtisserie","Dessert occidental","Goûter"]'::jsonb),
  ('howtocook:dessert/红柚蛋糕/红柚蛋糕', 'fr', 'Gâteau au pamplemousse rouge', 'Desserts', 'Le gâteau au pamplemousse rouge est un dessert frais et facile à réaliser avec une friteuse à air. Il allie l''acidité légère des morceaux de pamplemousse rouge à la texture moelleuse du gâteau, parfait pour un goûter individuel. Les œufs et la farine apportent protéines et glucides, tandis que le pamplemousse rouge est riche en vitamine C, offrant une base nutritive simple. La difficulté est moyenne, l''étape clé étant de mélanger progressivement pour obtenir une pâte jaune pâle sans grumeaux. Les débutants patients réussiront en suivant les étapes. De la préparation à la dégustation, comptez environ 35 minutes, ce qui ne prend pas trop de temps pour un dessert fraîchement cuit.', '[{"name":"Œufs","unit":"pièce"},{"name":"Pulpe de pamplemousse rouge","unit":"g"},{"name":"Farine","unit":"g"},{"name":"Huile","unit":"ml"},{"name":"Sucre","unit":"g"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Cassez 2 œufs dans un moule en aluminium, ajoutez 20 g de pulpe de pamplemousse rouge.","Versez 15 ml d''huile dans le moule et inclinez-le pour bien répartir l''huile sur le fond.","Ajoutez 10 g de sucre, 40 g de farine et 40 ml d''eau dans le moule.","Mélangez dans le sens des aiguilles d''une montre jusqu''à l''obtention d''une pâte jaune pâle.","Ajoutez 5 g de sucre, 40 g de farine et 40 ml d''eau dans le moule.","Continuez à mélanger avec une cuillère jusqu''à l''obtention d''une pâte jaune pâle.","Placez le moule dans le panier de la friteuse à air, cuisez à 180 °C pendant 15 minutes.","Ouvrez la friteuse, retirez délicatement le moule, retournez le gâteau avec une cuillère ou une fourchette.","Continuez la cuisson à 180 °C pendant 8 minutes.","Sortez le gâteau et dégustez-le."]'::jsonb, '["Dessert","Aigre-doux","Pâtisserie","Friteuse à air","Rapide","Goûter"]'::jsonb),
  ('howtocook:dessert/胡萝卜甜糕', 'fr', 'Gâteau sucré aux carottes', 'Desserts', 'Le gâteau sucré aux carottes est un dessert indien emblématique de l''hiver. Les carottes râpées mijotent lentement avec du lait jusqu''à épaississement, enrichies de ghee et de noix, pour une texture fondante et sucrée, d''une belle couleur rouge doré. Riche en bêta-carotène, calcium et bonnes graisses, il réchauffe et nourrit. La préparation est simple mais demande un peu de patience pour les débutants ; il faut environ 45 minutes au total.', '[{"name":"carottes","unit":"g"},{"name":"lait entier","unit":"ml"},{"name":"sucre","unit":"g"},{"name":"ghee","unit":"g"},{"name":"cardamome en poudre","unit":"g"},{"name":"noix de cajou","unit":"g"},{"name":"amandes","unit":"g"},{"name":"raisins secs","unit":"g"}]'::jsonb, '["Peler les carottes et les râper finement à l''aide d''une râpe.","Verser 20 g de ghee (la moitié) dans une casserole à fond épais et faire fondre à feu moyen.","Ajouter les carottes râpées et faire revenir 3 à 5 minutes jusqu''à ce qu''elles soient tendres et parfumées.","Verser 500 ml de lait entier et bien mélanger.","Porter à ébullition à feu vif, puis réduire à feu moyen-doux et maintenir un léger frémissement.","Remuer constamment pendant 25 à 30 minutes jusqu''à ce que le lait soit presque entièrement absorbé et évaporé par les carottes (c''est l''étape la plus importante, il faut patience et remuer sans cesse pour éviter que ça n''attache).","Lorsqu''il n''y a presque plus de liquide dans la casserole, ajouter 80 g de sucre et bien mélanger.","L''ajout de sucre va libérer de l''eau, continuer à remuer à feu moyen-doux pendant 5 à 8 minutes jusqu''à ce que l''eau s''évapore à nouveau.","Ajouter les 20 g de ghee restants et 3 g de cardamome en poudre, mélanger pendant 2 minutes.","Dans une petite casserole séparée, faire revenir les noix de cajou, les amandes effilées et les raisins secs dans un peu de ghee jusqu''à ce qu''ils soient dorés (environ 1 minute), en notant que les raisins secs gonflent.","Incorporer la moitié des noix et raisins secs frits dans le gâteau de carottes.","Servir et garnir du reste des noix et raisins secs sur le dessus."]'::jsonb, '["Dessert","Saveur indienne","Sucré","Mijoté","Réconfortant","Nourrissant"]'::jsonb),
  ('howtocook:dessert/芋泥雪媚娘/芋泥雪媚娘', 'fr', 'Mochi à la purée de taro', 'Desserts', 'Le mochi à la purée de taro a une peau moelleuse et élastique, avec une garniture de purée de taro fine et sucrée et de crème légère, offrant une riche texture en bouche. C''est un dessert chinois d''inspiration maison. Le taro et la patate douce violette apportent des fibres alimentaires et des anthocyanes, le lait et la crème liquide fournissent du calcium, pour un équilibre nutritionnel. La préparation ne nécessite pas de four, les étapes sont simples, idéales pour les débutants, même sans expérience en pâtisserie. Comptez environ deux heures du début à la fin pour réaliser ces petites gourmandises qui raviront les enfants.', '[{"name":"Taro de Lipu","unit":"g"},{"name":"Poudre de patate douce violette","unit":"g"},{"name":"Lait","unit":"g"},{"name":"Farine de riz gluant a","unit":"g"},{"name":"Farine de riz gluant b","unit":"g"},{"name":"Fécule de maïs","unit":"g"},{"name":"Beurre","unit":"g"},{"name":"Crème liquide","unit":"g"},{"name":"Sucre blanc","unit":"g"}]'::jsonb, '["Couper le taro en morceaux, cuire à feu vif jusqu''à ce qu''il soit tendre (40 minutes suffisent), mettre le tout dans un mixeur.","Ajouter 30g de lait et 25g de crème liquide, mixer en purée.","Ajouter 3g de poudre de patate douce violette et 18g de sucre blanc, continuer à mixer jusqu''à obtenir une purée de taro lisse.","Dans un autre bol, ajouter toute la farine de riz gluant b, 22g de fécule de maïs, 135g de lait, 50g de sucre blanc, mélanger et passer au tamis une fois. Couvrir de film alimentaire et percer des petits trous, cuire à la vapeur à feu moyen pendant une demi-heure.","Pendant la cuisson vapeur, faire griller à sec la farine de riz gluant a dans une poêle à feu doux jusqu''à ce qu''elle soit légèrement dorée (cuite), réserver comme farine à saupoudrer.","À la sortie du four vapeur, ajouter 30g de beurre au mélange lait-farine de riz cuit (consistance gelée) encore chaud, pétrir jusqu''à absorption complète du beurre, puis réfrigérer une heure.","Dans un autre bol, ajouter 120g de crème liquide et 8g de sucre blanc, fouetter jusqu''à l''obtention de pics fermes. Mettre dans une poche à douille et réserver.","Sortir la pâte réfrigérée, pétrir 5 minutes, diviser en portions de 30g. Saupoudrer uniformément 2g de farine à saupoudrer pour éviter que ça colle, étaler en rond. Déposer d''abord 5g de crème en poche, puis 30g de purée de taro, et refermer la pâte comme un baozi (on peut retirer l''excédent de pâte).","Saupoudrer à nouveau uniformément 2g de farine à saupoudrer pour éviter que ça colle.","Répéter les deux étapes précédentes jusqu''à épuisement des ingrédients."]'::jsonb, '["Dessert","Sucré","Moelleux","Cuisson vapeur","Sans four","Goûter"]'::jsonb),
  ('howtocook:dessert/英式司康/英式司康', 'fr', 'Scones anglais', 'Desserts', 'Le scone anglais est un classique du goûter britannique, croustillant à l''extérieur et moelleux à l''intérieur, avec un riche arôme d''œuf et de crème. Il est délicieux servi avec de la confiture ou de la crème. Principalement composé de farine, de beurre, d''œufs et de crème liquide, il est riche en glucides et protéines, offrant un regain d''énergie rapide. La préparation est assez simple ; en maîtrisant les gestes de base du pétrissage, même un débutant peut réussir, du début à la sortie du four, cela prend environ une heure.', '[{"name":"Beurre non salé","unit":"g"},{"name":"Farine à gâteau","unit":"g"},{"name":"Sucre","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Levure chimique","unit":"g"},{"name":"Œuf","unit":"pièce"},{"name":"Crème liquide","unit":"g"},{"name":"Cream cheese","unit":"g"}]'::jsonb, '["Battre l''œuf, peser 30 g d''œuf battu dans un récipient propre, ajouter toute la crème liquide et le cream cheese, mélanger uniformément. Si le fromage est trop dur, le chauffer au bain-marie à environ 40 °C avant de mélanger.","Mettre la farine à gâteau, le sel, le sucre et la levure chimique dans un récipient propre et mélanger uniformément.","Couper le beurre en petits morceaux, les ajouter au mélange précédent, et incorporer le beurre avec les mains jusqu''à obtenir une texture de semoule grossière.","Verser le mélange œuf-crème de la première étape dans le mélange farine-beurre de l''étape précédente, mélanger jusqu''à ce que la pâte se rassemble. Plier et presser pour former une pâte homogène.","Placer la pâte sur un plan de travail, l''étaler en une épaisseur de 1,5 cm, et découper des formes à l''aide d''un couteau ou d''un emporte-pièce.","Avec un pinceau, tremper dans les 20 g d''œuf battu restants et badigeonner la surface des scones.","Préchauffer le four à 180 °C et cuire pendant 27 minutes."]'::jsonb, '["Dessert","Sucré","Pâtisserie","Anglais","Goûter","Amuse-bouche"]'::jsonb),
  ('howtocook:dessert/草莓冰淇淋/草莓冰淇淋', 'fr', 'Crème glacée à la fraise', 'Desserts', 'Cette glace à la fraise maison se prépare facilement sans mixeur. Elle est fruitée et onctueuse. Les fraises sont riches en vitamine C, et associées au lait concentré sucré et à la crème, elles fournissent énergie et calcium. La recette est simple et ne nécessite pas de compétences culinaires, même un débutant peut réussir du premier coup. Le temps total de préparation est d''environ huit heures, dont la majeure partie est le temps de congélation ; le travail actif ne prend que quelques dizaines de minutes.', '[{"name":"fraises","unit":"grammes"},{"name":"sucre blanc","unit":"grammes"},{"name":"extrait de vanille","unit":"grammes"},{"name":"sel","unit":"grammes"},{"name":"extrait de vanille","unit":"grammes"},{"name":"crème entière","unit":"grammes"},{"name":"sel","unit":"grammes"},{"name":"lait concentré sucré","unit":"grammes"}]'::jsonb, '["Préparez d''abord le sirop de fraises. Lavez les fraises et retirez les feuilles du dessus. Coupez les fraises en petits morceaux de 5 mm. Réservez la moitié des fraises coupées pour les incorporer plus tard à la glace.","Mettez l''autre moitié des fraises coupées et le sucre dans une casserole. Remuez et cuisez à feu moyen jusqu''à ce que les fraises libèrent leur jus et forment un sirop.","Laissez chauffer les fraises dans le sirop en remuant de temps en temps jusqu''à ce qu''elles se décomposent et que le sirop épaississe légèrement.","Lorsque le sirop met 3 secondes à se refermer après avoir tracé un trait, il est prêt. Retirez le sirop du feu et incorporez la vanille et le sel. Laissez le sirop de fraises refroidir.","Pendant que le sirop refroidit, préparez la base de la glace. Dans un bol, mélangez le lait concentré sucré, la crème entière, l''extrait de vanille et le sel. Fouettez le mélange au batteur électrique jusqu''à ce qu''il devienne léger et mousseux et forme des pics mous.","Incorporez délicatement les fraises fraîches coupées réservées à la base de la glace. Transférez la base de glace dans un récipient allant au congélateur. Versez le sirop de fraises refroidi sur la glace et incorporez-le délicatement en tournant.","Couvrez la glace et congelez-la pendant huit heures, puis servez."]'::jsonb, '["Dessert","Sucré","Sans cuisson","Rapide","Maison","Été"]'::jsonb),
  ('howtocook:dessert/酸奶意式奶冻/酸奶意式奶冻', 'fr', 'Panna cotta au yaourt', 'Desserts', 'Un dessert revisité du classique italien, avec du yaourt nature pour une texture plus légère et onctueuse, sucré sans être écoeurant, parfait en petit dessert après le repas avec des fruits ou de la confiture. Les produits laitiers apportent du calcium et des protéines, un apport nutritionnel doux. La préparation est simple : il suffit de chauffer, mélanger et réfrigérer, même les débutants peuvent réussir. Du début à la réfrigération, comptez environ 5 heures.', '[{"name":"Crème liquide","unit":"g"},{"name":"Sucre","unit":"g"},{"name":"Yaourt nature","unit":"g"},{"name":"Feuilles de gélatine","unit":"g"}]'::jsonb, '["Couper les feuilles de gélatine en petits morceaux et les faire tremper dans de l''eau froide.","Mettre la crème liquide et le sucre dans une casserole, chauffer à 60°C.","Éteindre le feu. Sortir la gélatine de l''eau, l''égoutter et l''ajouter à la crème chaude. Bien mélanger.","Laisser refroidir la crème à 40°C, ajouter le yaourt nature et bien mélanger.","Passer le mélange obtenu au tamis deux fois.","Répartir dans des contenants adaptés et réfrigérer au moins 4 heures."]'::jsonb, '["Dessert","Aigre-doux","Italien","Sans cuisson","Rapide","Pour recevoir"]'::jsonb),
  ('howtocook:dessert/雪花酥/雪花酥', 'fr', 'Croustillant neige', 'Desserts', 'Le croustillant neige est une petite douceur croustillante, sucrée et riche en lait, facile et rapide à préparer à la maison, également idéale pour être emballée en cadeau. Contenant du beurre, du lait en poudre et des fruits secs mélangés, il apporte énergie et protéines, mais est calorique, donc à consommer avec modération. La difficulté est modérée, un défi pour les débutants, mais en surveillant la cuisson et la technique de mélange, cela prend généralement 30 minutes.', '[{"name":"Beurre non salé","unit":"g"},{"name":"Guimauves","unit":"g"},{"name":"Lait en poudre entier","unit":"g"},{"name":"Fruits secs mélangés","unit":"g"},{"name":"Biscuits","unit":"g"}]'::jsonb, '["Couper les biscuits en petits morceaux s''ils sont plus gros qu''une pièce d''un yuan.","Ajouter le beurre non salé dans la casserole, chauffer à feu doux jusqu''à ce qu''il soit complètement fondu.","Ajouter les guimauves dans la casserole, mélanger avec une spatule jusqu''à ce qu''elles fondent et soient bien incorporées au beurre.","Ajouter 20g de lait en poudre, mélanger avec une spatule jusqu''à ce que le lait en poudre soit bien incorporé au mélange beurre-guimauves, puis éteindre immédiatement le feu.","Ajouter tous les fruits secs mélangés et les biscuits préparés dans la casserole pendant qu''ils sont chauds, mélanger avec une spatule.","Après avoir mélangé jusqu''à ce que la température descende à une température manipulable, enfiler des gants en plastique jetables et malaxer dans la casserole ou soulever et étirer avec les mains pour répartir uniformément les biscuits et les fruits secs dans le mélange de guimauves, beurre et lait en poudre.","Presser le mélange dans un moule, compacter les coins, aplatir avec un rouleau à pâtisserie, et presser le côté non rempli avec les mains pour former un bord droit.","Laisser refroidir à température ambiante, démouler une fois complètement refroidi, couper en morceaux selon les rainures du moule ou à la taille souhaitée, saupoudrer du reste de lait en poudre en essayant d''en recouvrir toutes les faces."]'::jsonb, '["Dessert","Riche en lait","Croustillant et sucré","Rapide","Pâtisserie","Maison","Cadeau"]'::jsonb),
  ('howtocook:dessert/魔芋蛋糕/魔芋蛋糕', 'fr', 'Gâteau au konjac', 'Desserts', 'Le gâteau au konjac est un dessert hypocalorique et sans gluten, utilisant de l''érythritol à la place du sucre blanc. Sa texture est légère et humide, avec un arôme de cacao, particulièrement adapté aux personnes en perte de poids. Riche en fibres et en protéines, il procure une forte sensation de satiété. La préparation est d''un niveau intermédiaire : il faut monter les blancs d''œufs en neige et maîtriser la technique de mélange, mais le temps total n''est que d''environ une demi-heure, ce qui en fait une option de pâtisserie rapide et saine.', '[{"name":"Œufs","unit":"pièce"},{"name":"Érythritol","unit":"g"},{"name":"Cacao en poudre","unit":"g"},{"name":"Poudre de konjac","unit":"g"},{"name":"Crème de tartre","unit":"g"}]'::jsonb, '["Préchauffez le four à 150°C (350°F) pour gagner du temps, avant de préparer la pâte.","Sortez les œufs frais du réfrigérateur.","Préparez deux récipients et essuyez-les : l''un pour les blancs, l''autre pour les jaunes.","Pour le récipient des blancs, de légères gouttelettes d''eau sont acceptables, mais pas de graisse ; pour les jaunes, pas de gouttelettes d''eau.","Cassez les œufs (à la main ou avec un séparateur) et séparez les blancs des jaunes dans les deux récipients.","Pendant la séparation, les jaunes ne doivent pas se briser et aucun jaune ne doit se mélanger aux blancs, sinon la montée en neige sera compromise. (Les filaments blancs peuvent aller dans les blancs sans problème.)","(Note : Si vous n''utilisez pas de robot, le récipient des blancs servira aussi à les battre. Pour éviter les débordements, ne dépassez pas 1/8 de la capacité du récipient après avoir ajouté tous les blancs.)","Ajoutez 1 g de crème de tartre aux blancs.","Battez les blancs à haute vitesse jusqu''à ce qu''ils soient mousseux et à gros bulles, puis ajoutez 50 g d''érythritol.","Battez à vitesse moyenne-basse jusqu''à ce que les blancs soient fermes (soulevés, ils forment des pics droits et courts ; retournez le récipient, les blancs ne tombent pas).","Les blancs sont maintenant à la consistance souhaitée.","Le batteur doit être maintenu près du fond du récipient pour éviter que le dessus ne soit monté tandis que le fond reste liquide.","Ajoutez les jaunes d''œufs aux blancs montés et mélangez à vitesse moyenne-basse jusqu''à homogénéité.","Ajoutez 10 g de cacao en poudre et 10 g de poudre de konjac aux blancs. Mélangez d''abord avec un couteau de cuisine pour éviter que la poudre ne s''envole si vous utilisiez le batteur.","La technique de mélange (folding) est la suivante :","Avec la main droite, insérez la spatule au centre du bol et allez jusqu''au fond de la pâte.","Raclez en direction de 8 heures jusqu''à toucher la paroi, puis soulevez la pâte en l''air et ramenez-la au centre du bol.","Avec la main gauche, faites tourner le bol de 9 heures à 7 heures (une rotation de 60 degrés) pour un cycle.","La vitesse est d''environ 2 mouvements par seconde.","Cette méthode est tirée du livre de pâtisserie de M. Kojima. En termes simples, c''est comme si vous faisiez sauter des légumes.","Après le mélange, utilisez le batteur à basse vitesse pour homogénéiser brièvement.","Tapissez le moule de papier cuisson en l''ajustant bien au fond et aux parois.","Versez la pâte dans le moule, lissez-la avec un couteau, puis tapotez le moule quelques fois pour éliminer les grosses bulles.","Faites cuire pendant 25 minutes.","Après cuisson, sortez le moule avec des gants thermiques.","(Optionnel) Laissez tomber le moule de haut pour libérer la vapeur chaude.","Retournez le moule et laissez refroidir 10 minutes.","Démouler le gâteau encore chaud l''endommagerait.","Cette opération peut être chaude, portez des gants thermiques.","Démoulez et coupez le gâteau en parts avec un couteau."]'::jsonb, '["Dessert","Hypocalorique","Sans gluten","Arôme cacao","Pâtisserie","Rapide","Perte de poids"]'::jsonb),
  ('howtocook:dessert/龟苓膏/龟苓膏', 'fr', 'Gelée d''herbes chinoises', 'Desserts', 'La gelée d''herbes chinoises est un dessert traditionnel cantonais. Sa texture est lisse, légèrement amère avec un arrière-goût sucré. C''est une collation rafraîchissante pour l''été. Elle aide à éliminer la chaleur et l''humidité, nourrit le yin et embellit la peau. C''est un en-cas nutritif et sain. La préparation est simple, même les débutants peuvent la maîtriser : il suffit de préparer les ingrédients, mélanger et chauffer, puis réfrigérer environ deux heures avant de déguster.', '[{"name":"poudre de gelée d''herbes chinoises","unit":"g"},{"name":"eau froide","unit":"ml"},{"name":"eau bouillante","unit":"ml"},{"name":"sucre blanc","unit":"g"}]'::jsonb, '["Dans une casserole, versez 25 g de poudre de gelée d''herbes chinoises et 120 ml d''eau froide, mélangez bien jusqu''à obtenir une pâte lisse sans grumeaux.","Dans un autre récipient, ajoutez 100 g de sucre blanc et versez 500 ml d''eau bouillante, remuez jusqu''à dissolution complète du sucre.","Versez lentement l''eau sucrée dans la pâte de gelée, mélangez immédiatement pour éviter les grumeaux.","Mettez le mélange dans une casserole, chauffez à feu moyen-doux en remuant constamment pour éviter d''attacher.","Chauffez jusqu''à ce que le liquide épaississe et que de petites bulles apparaissent, puis retirez du feu.","Versez rapidement le liquide dans des moules, laissez refroidir et prendre naturellement. Il est conseillé de réfrigérer 1 à 2 heures avant de servir pour une meilleure texture."]'::jsonb, '["Dessert","Cantonais","Rafraîchissant","Lisse","Amer-doux","Rapide"]'::jsonb),
  ('howtocook:drink/B52轰炸机', 'fr', 'B52 Bombardier', 'Boissons', 'Ce cocktail offre des couches de saveurs distinctes : d''abord la force de la vodka, puis le retour sucré de la crème de café. Servi flambé, il procure une expérience unique de glace et de feu, un cocktail créatif classique. La liqueur de café et le Bailey''s apportent un peu de caféine et de crème, mais l''essentiel des calories provient de l''alcool. Sa préparation nécessite de la pratique pour verser en couches et flamber, un peu difficile pour les débutants, le processus total prend environ 5 minutes.', '[{"name":"Liqueur de café Kahlúa","unit":"ml"},{"name":"Irish Cream Bailey''s","unit":"ml"},{"name":"Vodka Skyy nature","unit":"ml"}]'::jsonb, '["Verser la liqueur de café Kahlúa dans un verre à liqueur jusqu''à 1/3 (10 ml).","Verser lentement le Bailey''s Irish Cream le long d''une cuillère à mélange, également jusqu''à 1/3 (10 ml). Veiller à ce que ce soit lent pour garder les couches distinctes. (Si trop rapide, le Bailey''s se mélangera avec le café.)","Enfin, verser la vodka Skyy par-dessus (10 ml).","Chauffer le bord du verre avec un briquet.","Dernière étape : flamber. Vous voyez la petite flamme bleue ?"]'::jsonb, '["Boisson","Sucré","En couches","Flambe","Cocktail","Fête"]'::jsonb),
  ('howtocook:drink/Mojito莫吉托', 'fr', 'Mojito', 'Boissons', 'Ce cocktail a un goût rafraîchissant, aigre-doux, avec la fraîcheur de la menthe et la légère ivresse du rhum. C''est une boisson estivale classique. Peu alcoolisé, il est accompagné de citron vert riche en vitamine C, ce qui stimule la salivation, désaltère et rafraîchit l''esprit. La préparation est très simple, adaptée aux débutants, et ne prend qu''environ dix minutes de la mise en place à la finition.', '[{"name":"Citron vert","unit":"morceau"},{"name":"Feuilles de menthe","unit":"branche"},{"name":"Sirop","unit":"ml"},{"name":"Rhum ambré","unit":"ml"},{"name":"Vodka naturelle Blue Sky","unit":"ml"},{"name":"Glaçon pilé","note":"quantité suffisante"},{"name":"Eau de Seltz glacée","note":"quantité suffisante"}]'::jsonb, '["Couper un des demi-citrons verts en petits morceaux, les mettre dans un verre highball, puis les écraser avec un pilon pour en extraire le jus ;","Frotter le bord du verre avec 3-4 branches de menthe, puis les mettre dans le verre ;","Ajouter 20 ml de sirop ;","Ajouter 45 ml de rhum ambré ;","Presser le jus de l''autre demi-citron vert et le verser dans le verre ;","Remuer doucement pour que le sucre/le sirop soit à moitié dissous ;","Mettre de la glace pilée dans le verre jusqu''à remplir les 3/4 ;","Ajouter de l''eau de Seltz glacée jusqu''à juste recouvrir la glace pilée ;","Tourner et remuer pendant une demi-minute ;","Remplir le verre highball avec de la glace pilée ;","Frapper la dernière branche de menthe pour réveiller son arôme, l''insérer dans la glace pilée pour décorer."]'::jsonb, '["饮品","酸甜","清爽","调酒","快手","夏日"]'::jsonb),
  ('howtocook:drink/冬瓜茶', 'fr', 'Thé de courge cireuse', 'Boissons', 'Le thé de courge cireuse est une boisson traditionnelle rafraîchissante qui combat la chaleur. Sa saveur est douce et sucrée, avec l''arôme caractéristique de la courge cireuse, et elle est encore meilleure servie glacée. La courge cireuse est faible en calories, riche en eau, et cuite avec du sucre candi pour reconstituer l''énergie et étancher la soif. La préparation n''est pas compliquée, mais nécessite un peu de patience pour les débutants ; l''ensemble prend environ 4 à 5 heures.', '[{"name":"Courge cireuse","unit":"grammes"},{"name":"Sucre candi","unit":"grammes"}]'::jsonb, '["Préparer la courge cireuse : peler la courge, retirer les graines, et couper en petits morceaux (ne dépassant pas 4 cm).","Ajouter le sucre candi : ajouter le sucre candi à la courge, bien mélanger, couvrir de film plastique et réfrigérer pendant au moins 2 heures.","Cuire la courge : la courge a maintenant libéré beaucoup d''eau. Verser dans une casserole et porter à ébullition à feu vif, puis réduire à feu moyen-doux et laisser mijoter 1 à 2 heures en remuant fréquemment pour éviter que cela n''attache.","Filtrer le thé : filtrer le liquide de courge cuit à l''aide d''un tamis, retirer les morceaux de courge, et ne conserver que le liquide.","Refroidir : laisser refroidir le liquide de thé, puis verser dans un récipient propre et réfrigérer.","Déguster : le liquide de thé de courge concentré peut être dilué avec de l''eau ou d''autres boissons selon les préférences, chaud ou froid."]'::jsonb, '["Boisson","Rafraîchissante","Désaltérante","Sucrée","Mijotée","Glacée"]'::jsonb),
  ('howtocook:drink/冰粉/冰粉', 'fr', 'Gelée de graines de basilic', 'Boissons', 'Le shiliangfen est une collation traditionnelle de Xinyang, dans le Henan. Sa texture est lisse et gélatineuse, accompagnée de jus de menthe ou de citron pour rafraîchir et dissiper la chaleur. Il fait partie de la cuisine du Henan. Fabriqué en frottant les graines de basilic à la main, il est naturel et sans additifs, riche en gomme végétale. La préparation est très simple, adaptée aux débutants. Le processus prend environ 3 heures, dont 2h30 de repos pour la prise, ne nécessitant presque pas de travail.', '[{"name":"Graines de basilic","unit":"g"},{"name":"Eau bouillie refroidie","unit":"g"},{"name":"Jus de menthe","unit":"ml"},{"name":"Poudre de menthe","unit":"g"},{"name":"Glaçons lumineux","note":"Facultatif"}]'::jsonb, '["Versez l''eau bouillie refroidie dans un saladier ;","Enveloppez toutes les graines de basilic dans une étamine, faites un nœud à l''ouverture.","Placez le sachet dans l''eau bouillie refroidie et frottez-le vigoureusement dans l''eau pendant 6 minutes.","Laissez reposer l''eau bouillie refroidie pendant 2h30, elle prendra forme.","Ensuite, à l''aide d''une cuillère, versez le shiliangfen dans des gobelets en plastique transparent jetables préparés, ajoutez 10 ml de jus de menthe ou 10 g de poudre de menthe (jus de citron, jus d''aubépine, jus de mûre possible), puis ajoutez des glaçons lumineux au contact de l''eau, et mélangez doucement avec une cuillère."]'::jsonb, '["Boisson","Cuisine du Henan","Rafraîchissant","Dissipe la chaleur","Artisanal","Estival"]'::jsonb),
  ('howtocook:drink/印度奶茶', 'fr', 'Chai indien', 'Boissons', 'Le chai indien est une boisson maison exotique, préparée avec du thé noir, du lait et un mélange d''épices. Sa texture est riche et onctueuse, avec des notes chaudes de gingembre, cardamome et cannelle. Le lait apporte des protéines et du calcium, tandis que les épices aident à réchauffer et à faciliter la digestion. La préparation est simple et rapide, idéale pour les débutants, et ne prend qu''environ 10 minutes du début à la fin.', '[{"name":"Eau","unit":"ml"},{"name":"Lait entier","unit":"ml"},{"name":"Thé noir (de préférence CTC, ou Assam)","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Cardamome verte","unit":"gousse"},{"name":"Bâton de cannelle","unit":"petit bâton"},{"name":"Clous de girofle","unit":"clou"},{"name":"Grains de poivre noir","unit":"grain"},{"name":"Sucre","unit":"g"}]'::jsonb, '["Écrasez le gingembre (ne le coupez pas trop fin, écrasez-le pour libérer le jus de gingembre)","Fendez les gousses de cardamome avec le dos d''un couteau pour exposer les graines","Écrasez les grains de poivre noir","Versez 120 ml d''eau dans une petite casserole","Ajoutez le gingembre écrasé, la cardamome, le bâton de cannelle, les clous de girofle et le poivre noir écrasé","Portez à ébullition à feu vif, puis réduisez à feu doux et laissez mijoter 2 minutes pour libérer les arômes des épices","Ajoutez 8 g de thé noir et continuez à mijoter 2 minutes jusqu''à ce que le thé prenne une couleur foncée","Versez 120 ml de lait entier","Chauffez à feu moyen. Surveillez attentivement : dès que le lait commence à monter et à bouillonner, réduisez immédiatement à feu doux (le lait déborde facilement)","Laissez mijoter 2 à 3 minutes, en soulevant et en versant la casserole (répétez 3 à 4 fois) pour bien mélanger le thé et le lait","Ajoutez le sucre et remuez jusqu''à dissolution","Retirez du feu","Filtrez le chai dans une tasse à thé à travers une passoire fine pour retirer les résidus de thé et d''épices","Buvez bien chaud"]'::jsonb, '["Boisson","Saveur indienne","Épicé et aromatique","Bouilli","Rapide","Réconfortant"]'::jsonb),
  ('howtocook:drink/可乐桶', 'fr', 'Seau de Coca', 'Boissons', 'Le seau de Coca est un cocktail simple à préparer, rafraîchissant et doux. Les bulles du Coca et le jus de citron neutralisent bien la force du whisky, parfait pour les soirées entre amis. Il apporte principalement de l''énergie, et le citron fournit de la vitamine C. La préparation ne prend que 5 minutes, même les débutants peuvent s''y essayer facilement.', '[{"name":"Whisky Bourbon","unit":"ml"},{"name":"Coca-Cola","unit":"ml"},{"name":"Glaçons","unit":"g"},{"name":"Citron","unit":"pièce"}]'::jsonb, '["Coupez le citron en deux (la lame du couteau perpendiculaire à l''axe tête-queue) et coupez une tranche de l''une des moitiés pour la décoration.","Coupez à nouveau le citron en deux, pressez les quartiers obtenus à l''aide d''un presse-citron et réservez le jus dans un récipient.","Réservez les quartiers pressés dans un récipient.","Choisissez un verre, de préférence un grand verre ou un seau en fer-blanc d''environ 1 litre de capacité.","Ajoutez les glaçons et les quartiers de citron pressés dans le verre (disposez selon votre goût).","Versez 15 ml de jus de citron (ajoutez-en plus si vous aimez l''acidité).","Versez doucement le Coca-Cola le long de la paroi jusqu''aux 3/4 du verre (maintenez un rapport Coca/whisky d''environ 5:1).","Versez le whisky jusqu''à remplir le verre."]'::jsonb, '["Boisson","Rafraîchissant","Doux","Rapide","Soirée","Cocktail"]'::jsonb),
  ('howtocook:drink/奇异果菠菜特调/奇异果菠菜特调', 'fr', 'Spécial kiwi et épinards', 'Boissons', 'Cette boisson santé aux fruits et légumes est fraîche et saine, avec une texture aigre-douce et fine, et un arôme naturel de kiwi et de pomme ; le goût des épinards est léger et ne domine pas. Riche en vitamine C et en fibres alimentaires, elle aide à la digestion. Très simple à réaliser, même les débutants réussiront du premier coup, le tout en seulement 10 minutes environ.', '[{"name":"kiwi","unit":"pièce"},{"name":"pomme","unit":"pièce"},{"name":"feuilles d''épinard","unit":"feuille"},{"name":"eau potable","unit":"ml"},{"name":"sucre blanc","unit":"g"}]'::jsonb, '["Coupez le kiwi en deux, puis chaque moitié en quatre petits morceaux","Coupez la pomme en dés","Retirez les tiges des feuilles d''épinard, ne conservez que les feuilles","Hachez les épinards","Versez le tout dans le bol du mixeur","Ajoutez de l''eau","Ajoutez le sucre blanc","Mettez le mixeur en marche et mixez environ 4 fois 15 secondes (arrêtez toutes les 15 secondes pour vérifier la consistance)"]'::jsonb, '["Boisson","Aigre-doux","Rafraîchissant","Rapide","Santé","Vitamine C"]'::jsonb),
  ('howtocook:drink/奶茶', 'fr', 'Thé au lait', 'Boissons', 'Une boisson maison facile à préparer avec du thé noir et du lait en poudre, où les arômes du thé et du lait se mêlent pour une texture douce et réconfortante. Les polyphénols du thé noir associés aux protéines et au calcium du lait offrent à la fois un regain d''énergie et des nutriments quotidiens. La recette est très simple, même les débutants réussissent du premier coup. Il ne faut qu''environ une demi-heure pour déguster son propre thé au lait fait maison.', '[{"name":"Thé noir en sachet (recommander Lipton Yellow Label)","unit":"sachet"},{"name":"Lait en poudre entier (ou lait évaporé)","unit":"g"},{"name":"Sucre","unit":"g"},{"name":"Eau bouillante","unit":"ml"}]'::jsonb, '["Prenez 2 sachets de thé noir en sachet et mettez-les dans une tasse. Ajoutez 180-200 mL d''eau bouillante.","Attendez 20 à 30 minutes.","Pesez 11-12 g de lait en poudre et 5-7 g de sucre, puis ajoutez-les séparément au liquide obtenu à l''étape précédente.","Mélangez bien et dégustez."]'::jsonb, '["Boisson","Lacté","Rapide","Fait maison","Goûter","Réconfortant"]'::jsonb),
  ('howtocook:drink/杨枝甘露', 'fr', 'Mangue et pamplemousse au lait de coco', 'Boissons', 'Une version revisitée du dessert cantonais classique, avec des graines de chia remplaçant le sagou. La texture est onctueuse avec un léger croquant des graines. La douceur de la mangue et l''acidité du pamplemousse s''entremêlent, tandis que le lait de coco ajoute de la richesse. Riche en fibres, vitamine C et bonnes graisses, rafraîchissant et désaltérant. Très simple à réaliser, même pour les débutants, prêt en environ 20 minutes.', '[{"name":"Graines de chia","unit":"g"},{"name":"Lait","unit":"ml"},{"name":"Glaçons","unit":"petits morceaux"},{"name":"Mangue","unit":"pièce"},{"name":"Pamplemousse","unit":"pièce"},{"name":"Lait de coco","unit":"ml"},{"name":"Mangue séchée","note":"en julienne, optionnel"},{"name":"Orange séchée","note":"en julienne, optionnel"}]'::jsonb, '["Faire tremper les graines de chia dans le lait pendant 10 minutes.","Pendant ce temps, peler et couper en dés la moitié de la mangue et le pamplemousse, les mettre dans un verre.","Couper l''autre moitié de la mangue en petits morceaux, les mettre dans un mixeur avec des glaçons et le lait de coco, mixer jusqu''à obtenir une purée.","Verser dans le verre, ajouter les garnitures (si utilisées).","Déguster tout en codant !!"]'::jsonb, '["Boisson","Cantonais","Aigre-doux","Rafraîchissant","Rapide","Désaltérant"]'::jsonb),
  ('howtocook:drink/柠檬水/柠檬水', 'fr', 'Citronnade', 'Boissons', 'Cette boisson est à base de citron frais, associé à un sirop de fruits pour un équilibre aigre-doux. Servie glacée, elle est encore plus rafraîchissante et désaltérante. Le citron est riche en vitamine C ; en consommer régulièrement aide à apporter des nutriments, à se revigorer et à éclaircir le teint. La préparation est simple : il suffit de pilonner, d''ajouter les ingrédients et de secouer. Même un débutant peut le faire en trois à cinq minutes.', '[{"name":"Citron","unit":"g"},{"name":"Sirop de fruit","unit":"g"},{"name":"Glaçons","note":"Quelques-uns (facultatif)"}]'::jsonb, '["Peser 40 à 45 g de citron, les mettre dans un shaker.","Couvrir le shaker et pilonner environ 10 fois.","Ajouter 40 à 45 g de sirop de fruit.","Ajouter de l''eau.","Secouer pour mélanger.","Ajouter de la glace selon votre goût."]'::jsonb, '["Boisson","Aigre-doux","Rapide","Rafraîchissant et désaltérant","Boisson froide","Vitamine C"]'::jsonb),
  ('howtocook:drink/泰国手标红茶/泰国手标红茶', 'fr', 'Thé noir thaïlandais', 'Boissons', 'C''est un classique du thé au lait thaïlandais de rue, au fort arôme de thé, à la texture crémeuse et lisse. Le lait concentré sucré et le lait apportent une saveur sucrée et laiteuse. La combinaison de thé et de lait fournit un peu de protéines et de calcium, mais la teneur en sucre est élevée, ce qui en fait une boisson rafraîchissante et désaltérante. Les étapes de préparation sont simples, mais il faut filtrer le thé à plusieurs reprises et attendre une longue réfrigération. Le temps total est d''environ 4 heures 20 minutes, et un débutant patient peut y parvenir.', '[{"name":"Eau","unit":"cc"},{"name":"Thé en poudre","unit":"g"},{"name":"Lait concentré sucré","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Lait","unit":"ml"},{"name":"Glace","unit":"cube"}]'::jsonb, '["Porter 600cc d''eau à ébullition à feu vif.","Mettre 20g de thé en poudre dans un sac filtrant, verser l''eau bouillante dans le sac, filtrer 20 fois.","À l''aide d''une balance, peser 24g de lait concentré sucré, 24g de sucre blanc et 18ml de lait, les mettre dans une carafe d''au moins 1000ml.","Verser le thé filtré dans la carafe et remuer jusqu''à ce que le sucre soit fondu.","Placer la carafe au réfrigérateur pendant au moins 4 heures.","Avant de servir, ajouter 6-8 cubes de glace."]'::jsonb, '["Boisson","Thé au lait thaïlandais","Boisson froide","Sucré","Style de rue","Rafraîchissant","Thé au lait"]'::jsonb),
  ('howtocook:drink/海边落日/海边落日', 'fr', 'Coucher de soleil en bord de mer', 'Boissons', 'Ce cocktail présente des couches de couleurs distinctes : le sirop de grenadine rouge au fond évoque le coucher de soleil, le jus d''orange clair au milieu et la liqueur bleue en haut rappellent l''eau de mer, créant une image de coucher de soleil au bord de la mer. La boisson est aigre-douce et rafraîchissante, avec un arôme de rhum. Le jus d''orange et le jus de citron apportent un peu de vitamine C, et l''alcool aide à se détendre. Les étapes ne sont pas compliquées, mais verser les liquides le long de la baguette pour créer des couches demande un peu de patience ; même un débutant peut réussir. La préparation et le mélange prennent environ un quart d''heure.', '[{"name":"Sirop de grenadine","unit":"ml"},{"name":"Jus d''orange NFC","unit":"ml"},{"name":"Eau gazeuse","unit":"ml"},{"name":"Rhum blanc","unit":"ml"},{"name":"Liqueur de curaçao bleu","unit":"ml"},{"name":"Jus de citron","unit":"ml"},{"name":"Glaçons","note":"quantité suffisante"},{"name":"Citron","unit":"tranche"}]'::jsonb, '["Laver le citron et couper une tranche.","Choisir un verre, de préférence un verre transparent d''une capacité de 350 à 400 ml.","Mettre des gros glaçons et refroidir le verre avec une baguette à mélanger.","Ajouter le sirop de grenadine.","Verser le jus d''orange le long de la baguette jusqu''à mi-hauteur du verre.","Remuer doucement un demi-tour.","Verser l''eau gazeuse.","Dans un shaker, ajouter le rhum blanc + la liqueur de curaçao bleu + le jus de citron + des glaçons. Puis shaker.","Verser délicatement dans le verre.","Décorer avec la tranche de citron et une paille."]'::jsonb, '["Boisson","Aigre-doux","Rafraîchissant","Cocktail","Couches","Estival"]'::jsonb),
  ('howtocook:drink/牛油果拉西', 'fr', 'Lassi à l''avocat', 'Boissons', 'Cette boisson est une version innovante du lassi, une boisson traditionnelle indienne à base de yaourt. Sa texture est onctueuse et lisse, sucrée mais pas écœurante, parfaite pour le petit-déjeuner ou comme boisson revigorante l''après-midi. L''avocat est riche en acides gras mono-insaturés et en fibres alimentaires, associé aux protéines de haute qualité et aux probiotiques du yaourt, un verre procure une sensation de satiété durable. La préparation est très simple, même les débutants réussissent à tous les coups, de la préparation à la dégustation en seulement 5 minutes environ.', '[{"name":"yaourt nature","unit":"ml"},{"name":"avocat","unit":"pièce"},{"name":"miel","unit":"cuillère à soupe"},{"name":"lait froid","unit":"ml"},{"name":"poudre de cardamome","unit":"pincée"},{"name":"feuilles de menthe","unit":"","note":"Quantité suffisante pour la décoration"},{"name":"noix concassées","unit":"g"}]'::jsonb, '["Couper l''avocat en deux, retirer le noyau, éplucher la peau et couper la chair en petits morceaux. Réserver.","Dans un mixeur, ajouter 120 ml de yaourt nature, les morceaux d''avocat, 1 cuillère à soupe de miel et 60 ml de lait froid.","(Optionnel) Ajouter une pincée de poudre de cardamome pour rehausser la saveur.","Actionner le mixeur pendant environ 1 minute jusqu''à ce que le liquide soit complètement lisse et crémeux.","Verser la boisson dans un verre.","(Optionnel) Décorer de quelques feuilles de menthe ou saupoudrer de 5 g de noix concassées."]'::jsonb, '["Boisson","Doux","Onctueux","Rapide","Petit-déjeuner","Saveur indienne"]'::jsonb),
  ('howtocook:drink/百香果橙子特调/百香果橙子特调', 'fr', 'Spécialité fruit de la passion et orange', 'Boissons', 'C''est une boisson estivale acidulée et rafraîchissante, mêlant le parfum tropical du fruit de la passion à la douceur de l''orange, accompagnée de thé vert au jasmin ou d''eau pétillante. Les saveurs sont bien distinctes, glacées et désaltérantes. Riche en vitamine C, elle aide à renforcer l''immunité et à hydrater la peau. Comprend des étapes de macération, infusion, pressage, etc. Un peu d''opérations mais de difficulté modérée, accessible aux débutants. Il faut mariner le fruit de la passion la veille, le temps total est d''environ 24 heures, mais le temps de préparation effectif n''est que d''environ 30 minutes.', '[{"name":"fruit de la passion","unit":"pièce"},{"name":"orange","unit":"pièce"},{"name":"thé vert au jasmin","unit":"gramme"},{"name":"sucre blanc","unit":"gramme"},{"name":"miel","unit":"gramme"},{"name":"eau bouillante","unit":"millilitre"},{"name":"glaçons","unit":"gramme"},{"name":"eau pétillante","note":"quantité suffisante, alternative au thé vert au jasmin"},{"name":"feuilles de menthe ou autres feuilles vertes","note":"optionnel, pour la décoration"}]'::jsonb, '["Marinade du fruit de la passion (comme les petites quantités sont difficiles à doser, voici deux portions)","Extraire la pulpe de trois fruits de la passion (ne pas perdre le jus), et la mettre dans un récipient.","Peser 30 grammes de sucre blanc et ajouter.","Peser 10 grammes de miel et ajouter (si vous n''avez pas de miel, vous pouvez remplacer par 5 grammes de sucre blanc).","Mélanger bien.","Couvrir le récipient de film plastique et placer au réfrigérateur pour une marinade de 12 à 24 heures.","Préparation du thé vert au jasmin (proportion recommandée => thé : eau : glaçons = 1~2 : 50 : 30).","Peser 3 à 6 grammes de thé dans un récipient, ajouter 150 millilitres d''eau bouillante et infuser 6 minutes.","Ajouter 90 grammes de glaçons au thé infusé pour refroidir, remuer pour accélérer.","Une fois les glaçons fondus, filtrer les feuilles pour obtenir environ 240 millilitres de thé vert au jasmin.","Traitement de l''orange (peut être fait pendant l''infusion du thé).","Couper l''orange en deux (le couteau perpendiculaire à la ligne tête-queue), puis couper une tranche de la moitié pour la garniture.","Couper à nouveau l''orange en deux, presser les quartiers pour obtenir le jus et le mettre dans un récipient.","Assemblage final.","Choisir un verre, de préférence un verre transparent d''une capacité de 350 à 400 millilitres.","Placer 70 grammes de glaçons au fond du verre et verser tout le jus d''orange.","Placer la tranche d''orange préparée contre la paroi intérieure du verre.","Verser une portion de fruit de la passion mariné sur les glaçons.","Verser lentement le thé vert au jasmin jusqu''à remplir le verre, pour permettre la stratification.","Déposer une feuille verte décorative sur le dessus (optionnel)."]'::jsonb, '["Boisson","Acidulé","Rafraîchissant","Infusion","Glacé","Estival"]'::jsonb),
  ('howtocook:drink/砂糖椰子冰沙/砂糖椰子冰沙', 'fr', 'Granité de noix de coco au sucre brun', 'Boissons', 'Le granité de noix de coco au sucre brun est une boisson glacée rapide au caractère tropical prononcé. La douceur parfumée de la noix de coco se marie avec les notes caramélisées du sucre brun grossier, pour une texture onctueuse et rafraîchissante. L''eau de coco est naturellement riche en électrolytes et minéraux, idéale pour une hydratation rapide, tandis que le sucre apporte de l''énergie glucidique. La préparation est très simple : il suffit de congeler l''eau de coco puis de la casser en granité. Aucune difficulté pour les débutants. Comptez au moins 10 heures de congélation, mais la manipulation ne prend que quelques minutes. Parfait pour une boisson glacée de l''après-midi.', '[{"name":"Eau de coco en bouteille","unit":"ml"},{"name":"Sucre au café","unit":"g"},{"name":"Éclats de noix (optionnel)","unit":"","note":"selon le goût"}]'::jsonb, '["Verser 200 ml d''une bouteille de 500 ml d''eau de coco, puis refermer immédiatement le bouchon.","Placer la bouteille au congélateur pendant au moins 10 heures.","Sortir la bouteille et, une fois l''eau de coco bien congelée, frapper vigoureusement la bouteille contre une surface dure (angle de mur, dossier de chaise, coin de table, etc.) en veillant à ne pas endommager la surface.","Lorsque la glace s''est transformée en granité, ouvrir le bouchon et verser le granité dans un bol.","Saupoudrer uniformément de sucre au café ou d''éclats de noix.","Servir."]'::jsonb, '["Boissons","Rapide","Glacé","Rafraîchissant","Goûter","Tropical"]'::jsonb),
  ('howtocook:drink/耙耙柑茶/耙耙柑茶', 'fr', 'Thé à la mandarine dekopon', 'Boissons', 'Le thé à la mandarine dekopon est une boisson fruitée qui allie la douceur des agrumes au parfum du jasmin. Sa texture est rafraîchissante avec un arrière-goût sucré. C''est une boisson créative qui n''appartient à aucune cuisine spécifique. La mandarine dekopon est riche en vitamine C et en fibres alimentaires. Associée au thé vert, elle offre une expérience fraîche et revigorante. La recette est très simple et adaptée aux débutants. De l''infusion au mélange final, il ne faut qu''environ 15 minutes.', '[{"name":"Mandarine dekopon","unit":"","note":""},{"name":"Thé vert au jasmin","unit":"","note":""},{"name":"Glaçons","unit":"g","note":""},{"name":"Sirop de sucre de canne","unit":"g","note":""},{"name":"Outils","unit":"","note":"à volonté"}]'::jsonb, '["Préparation du thé vert au jasmin (rapport recommandé => thé : eau : glace = 1~2 : 50 : 30)","Peser 2 à 4 g de feuilles de thé dans un récipient, ajouter 100 ml d''eau bouillante, infuser 6 minutes.","Ajouter 60 g de glaçons dans le thé vert infusé pour le refroidir, remuer pour accélérer le refroidissement.","Une fois les glaçons fondus, filtrer les feuilles de thé pour obtenir environ 160 ml de thé vert au jasmin.","Assemblage final","Choisir un verre, de préférence un verre transparent d''environ 300 ml.","Extraire les quartiers de la mandarine dekopon et enlever la peau pour obtenir la pulpe.","Mettre 130 g de pulpe et 130 ml de thé vert au jasmin dans un mixeur.","Ajouter 10 g de sirop de sucre de canne (facultatif, si vous aimez sucré).","Fermer et mixer pendant 20 secondes, puis verser le mélange dans le verre.","Prendre un peu de pulpe, l''émietter et le parsemer sur le dessus."]'::jsonb, '["Boisson","Rafraîchissant","Thé aux fruits","Rapide","Aigre-doux","Adapté aux débutants"]'::jsonb),
  ('howtocook:drink/菠萝咖啡特调/菠萝咖啡特调', 'fr', 'Café spécial à l''ananas', 'Boissons', 'Cette boisson spéciale allie l''arôme riche du café à l''acidité sucrée de l''ananas. Elle est pétillante, avec une mousse crémeuse, offrant des couches de saveurs. L''ananas est riche en vitamine C et en fibres, et associé au café, il aide à se réveiller et à stimuler l''esprit. La difficulté est moyenne : il suffit de monter la crème et de mélanger les liquides. L''ensemble prend environ 10 minutes.', '[{"name":"Café liquide","unit":"ml"},{"name":"Jus d''ananas","unit":"ml"},{"name":"Glaçons","unit":"g"},{"name":"Eau gazeuse","unit":"ml"},{"name":"Crème","unit":"ml"},{"name":"Lait","unit":"ml"},{"name":"Sucre","unit":"g"},{"name":"Sel de mer","unit":"g"},{"name":"Rhum","unit":"ml"}]'::jsonb, '["Dans un verre, ajoutez successivement des glaçons, le café liquide, le jus d''ananas et l''eau gazeuse.","Montez la crème avec le sucre en pics mous, puis ajoutez le rhum et le lait, et mélangez jusqu''à obtenir une consistance fluide.","Versez la crème sur le mélange de la première étape.","Saupoudrez le dessus de la crème de sel de mer."]'::jsonb, '["Boisson","Aigre-doux","Rafraîchissant","Spécial","Rapide","Goûter"]'::jsonb),
  ('howtocook:drink/酒酿醪糟/酒酿醪糟', 'fr', 'Riz gluant fermenté (Jiuniang)', 'Boissons', 'C''est un dessert fermenté traditionnel chinois, au goût sucré et légèrement alcoolisé, avec un arôme subtil d''alcool. Il aide à renforcer la rate et à ouvrir l''appétit, favorisant la digestion. Le processus de préparation est simple et amusant, bien qu''il nécessite du temps de fermentation, les manipulations sont faciles, ce qui en fait une excellente introduction à la fermentation. Le temps total de préparation est d''environ 2 jours, avec seulement environ 1 heure de travail actif.', '[{"name":"Riz gluant","unit":"g"},{"name":"Levure de riz sucré Angel","unit":"g"},{"name":"Eau","unit":"g"},{"name":"Eau","unit":"g"},{"name":"Eau tiède","unit":"ml"},{"name":"Fleurs d''osmanthe","note":"selon votre goût"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Rincez 800g de riz gluant, mettez-le dans un cuiseur à riz, ajoutez 720g d''eau et sélectionnez le mode cuisson vapeur.","Une fois cuit, versez le riz et étalez-le pour le refroidir à 30°C (utilisez un thermomètre, il doit être tiède au toucher).","Dissolvez 8g de levure de riz sucré Angel dans 20ml d''eau tiède (environ 30°C), puis saupoudrez uniformément sur le riz gluant en mélangeant bien.","Ajoutez 600g d''eau au riz gluant pour aider à mélanger la levure. Laissez reposer 2-3 minutes jusqu''à ce que le riz ait absorbé l''eau. Cette eau supplémentaire rendra le fermenté juteux dès la première fermentation.","Avec un rouleau à pâtisserie, faites un petit trou au centre du riz (pour faciliter la production de liquide).","Transférez le riz mélangé dans un récipient propre, tassez doucement la surface, couvrez avec un couvercle ou un film plastique pour bien sceller.","Placez dans un environnement à 28-32°C et laissez fermenter 24 à 48 heures. Ne secouez pas et ne déplacez pas violemment pendant la fermentation.","Le succès de la fermentation se reconnaît à la présence de liquide clair dans le trou central, une légère odeur d''alcool, et aucune odeur désagréable ou aigre.","Après fermentation, conservez au réfrigérateur immédiatement (vous pouvez ajouter des fleurs d''osmanthe pendant le processus). Prélevez avec un ustensile propre à chaque utilisation. Se conserve 7 à 10 jours au réfrigérateur.","Vous pouvez poursuivre une seconde fermentation en ajoutant 500ml d''eau pour augmenter le rendement (maximum 800g d''eau supplémentaires).","La fermentation continue. Pour l''arrêter, faites cuire à la vapeur 10 minutes pour stériliser, ou placez au réfrigérateur.","Rincez 800g de riz gluant, faites-le tremper dans l''eau claire pendant 6 à 8 heures (8 à 10 heures en hiver), jusqu''à ce que les grains soient rebondis.","Égouttez le riz, placez-le dans un linge de cuisson à la vapeur et faites cuire à la vapeur 40 à 60 minutes. Toutes les 20 minutes, ouvrez le couvercle et remuez pour une cuisson uniforme.","Une fois cuit, étalez le riz pour le refroidir, ajoutez la levure, puis suivez les étapes précédentes.","Bien sûr, les experts peuvent essayer différentes combinaisons de riz. Remplacez 20% du riz gluant par du millet, de l''avoine, du riz jaune, du riz gluant noir, etc."]'::jsonb, '["Boisson","Doux et légèrement alcoolisé","Fermentation","Tradition chinoise","Revitalisant pour la rate et l''estomac","Débutant"]'::jsonb),
  ('howtocook:drink/酸梅汤（半成品加工）', 'fr', 'Boisson aux prunes aigres (transformation semi-finie)', 'Boissons', 'La boisson aux prunes aigres (transformation semi-finie) est une boisson estivale rafraîchissante, aigre-douce, de style traditionnel pékinois. Cette boisson aide à étancher la soif et faciliter la digestion. La préparation est extrêmement simple : il suffit de mélanger dans l''ordre. Aucune difficulté pour les débutants, et le processus prend environ cinq minutes.', '[{"name":"Eau potable","unit":"grammes"},{"name":"Poudre de boisson aux prunes aigres","unit":"grammes"},{"name":"Sucre en morceaux (optionnel)","unit":"grammes"}]'::jsonb, '["Prendre 1177 grammes d''eau potable.","Ajouter 60 grammes de poudre de boisson aux prunes aigres, remuer 50 tours dans le sens des aiguilles d''une montre avec une cuillère à soupe.","Ajouter les 60 grammes restants de poudre de boisson aux prunes aigres, remuer à nouveau 50 tours dans le sens des aiguilles d''une montre avec une cuillère à soupe.","Ajouter 9 grammes de sucre en morceaux, remuer 100 tours dans le sens des aiguilles d''une montre avec une cuillère à soupe.","Ajouter 48 grammes d''alcool de Pékin Erguotou, remuer 30 tours dans le sens des aiguilles d''une montre avec une cuillère à soupe."]'::jsonb, '["Boisson","Aigre-doux","Saveur de Pékin","Rapide","Rafraîchissant","Mélange"]'::jsonb),
  ('howtocook:drink/酸梅汤/酸梅汤', 'fr', 'Boisson de prunes acides', 'Boissons', 'La boisson de prunes acides est une boisson traditionnelle aigre-douce et rafraîchissante, particulièrement délicieuse servie glacée. Les ingrédients comme les prunes acides, l''aubépine et la réglisse aident à stimuler la salive, étancher la soif et faciliter la digestion. La recette est simple, idéale pour les débutants : il suffit de faire tremper, bouillir et réfrigérer. Le processus complet, y compris le trempage, deux ébullitions et la réfrigération, prend environ 6 heures ou plus ; prévoyez à l''avance.', '[{"name":"Eau","unit":"litre"},{"name":"Jujubes noirs","unit":"gramme"},{"name":"Prunes acides séchées","unit":"gramme"},{"name":"Tranches d''aubépine (crues)","unit":"gramme"},{"name":"Sucre de roche jaune","unit":"gramme"},{"name":"Réglisse","unit":"gramme"},{"name":"Écorce de mandarine séchée","unit":"gramme"},{"name":"Cardamome rouge","unit":"gramme"},{"name":"Fleurs d''osmanthus séchées","unit":"gramme"}]'::jsonb, '["Rincer les ingrédients (sauf les fleurs d''osmanthus séchées et le sucre de roche), puis les faire tremper dans 1.5 litre d''eau à température ambiante pendant au moins deux heures (sauf les fleurs d''osmanthus séchées et le sucre de roche).","Porter à ébullition à feu moyen-vif, couvrir, réduire à feu doux et laisser mijoter 40 minutes pour la première décoction.","Mettre le sucre de roche dans un bol, verser le premier bouillon chaud filtré et remuer jusqu''à dissolution du sucre.","Remettre les herbes dans la casserole avec 600 ml d''eau, porter à ébullition à feu vif, couvrir, réduire à feu moyen et laisser mijoter encore 20 minutes pour la seconde décoction.","Mélanger la seconde décoction avec le sirop de sucre de roche encore chaud pour obtenir la boisson finale. Lorsque la boisson atteint 60-70°C (ne pas dépasser 80°C), ajouter les fleurs d''osmanthus séchées, couvrir, laisser refroidir, puis réfrigérer au moins 3 heures.","Avant de servir, filtrer pour retirer les fleurs d''osmanthus séchées. Déguster comme un thé, en sirotant lentement. La boisson glacée est acidulée, légèrement sucrée, avec une saveur riche et longue."]'::jsonb, '["Boisson","Aigre-doux","Bouilli","Rafraîchissant","Glacé","Traditionnel","Fait maison"]'::jsonb),
  ('howtocook:drink/金汤力/金汤力', 'fr', 'Gin Tonic', 'Boissons', 'C''est un cocktail classique au gin, au goût frais et légèrement amer, avec l''acidité vive du citron et les fines bulles de l''eau tonique, léger et agréable en bouche. Bien qu''il apporte principalement de l''eau et peu de calories provenant de l''alcool, le jus de citron frais fournit de la vitamine C, aidant à se rafraîchir. La préparation est très simple, même un débutant peut la maîtriser, et elle ne prend que 5 minutes.', '[{"name":"Gin","unit":"ml"},{"name":"Eau tonique gazeuse","unit":"canette"},{"name":"Citron","unit":"pièce"},{"name":"Glaçons","unit":"g"},{"name":"Feuilles vertes fraîches","note":"Quantité suffisante (pour la décoration)"}]'::jsonb, '["Coupez le citron en deux (la direction du couteau perpendiculaire à la ligne de la tête à la queue du citron), et à partir d''une moitié, coupez une tranche de citron et réservez.","Coupez à nouveau le citron en deux, puis pressez les quatre quartiers de citron à l''aide d''un presse-agrumes pour en extraire le jus, et réservez le jus dans un récipient.","Choisissez un verre, de préférence un verre transparent d''une capacité de 350 à 400 ml.","Placez 100 g de glaçons au fond du verre.","Versez 30 à 40 ml de gin.","Versez 15 ml de jus de citron (si vous aimez l''acidité, vous pouvez en ajouter plus ou tout mettre).","Mélangez bien avec une cuillère.","Placez la tranche de citron réservée auparavant.","Versez lentement de l''eau tonique le long de la paroi du verre jusqu''à ce qu''il soit plein (ne versez pas sur la glace pour éviter de perdre les bulles).","À l''aide d''une cuillère, soulevez et abaissez doucement le liquide pour le mélanger (ne tournez pas pour éviter de perdre les bulles).","Placez une feuille verte décorative sur la surface (optionnel)."]'::jsonb, '["Boisson","Rafraîchissant","Légèrement amer","Rapide","Cocktail"]'::jsonb),
  ('howtocook:drink/金菲士/金菲士', 'fr', 'Gin Fizz', 'Boissons', 'Cocktail classique au gin, aigre-doux et rafraîchissant avec des bulles. Le citron apporte de la vitamine C, associé à un sirop de sucre de canne pour équilibrer l''acidité. Très simple à préparer, même un débutant peut le réaliser en 5 minutes, idéal pour une dégustation à la maison. Attention : l''alcool est nocif pour la santé, à consommer avec modération.', '[{"name":"Gin","unit":"ml"},{"name":"Eau gazeuse","unit":"boîte"},{"name":"Citron","unit":"pièce"},{"name":"Sirop de sucre de canne","unit":"g"},{"name":"Glaçons","unit":"g"},{"name":"Feuilles vertes fraîches","note":"pour la décoration, quantité suffisante"},{"name":"Shaker","note":"facultatif"}]'::jsonb, '["Couper le citron en deux (la lame perpendiculaire à l''axe du citron), puis prélever une tranche de citron sur une moitié et réserver.","Couper à nouveau le citron en deux, presser les quartiers obtenus avec un presse-agrumes et réserver le jus dans un récipient.","Choisir un verre, de préférence un verre transparent d''une capacité de 350 à 400 ml.","Placer 100 g de glaçons au fond du verre.","Verser 30 à 40 ml de gin.","Verser 20 ml de jus de citron (ajouter plus si vous aimez l''acidité).","Verser 30 à 40 g de sirop de sucre de canne.","Mélanger avec une cuillère.","Déposer la tranche de citron réservée.","Verser lentement de l''eau gazeuse le long de la paroi du verre jusqu''à ce qu''il soit plein (ne pas verser sur la glace pour éviter la perte de bulles).","Soulever et abaisser doucement le liquide avec une cuillère pour mélanger (ne pas remuer en rotation pour éviter la perte de bulles).","Déposer une feuille verte décorative sur le dessus (facultatif).","Verser les glaçons, le gin, le jus de citron et le sirop de sucre de canne dans un shaker et secouer vigoureusement.","Verser le contenu du shaker dans le verre (si la glace est trop concassée, on peut la filtrer et ajouter de nouveaux glaçons)."]'::jsonb, '["Boissons","Aigre-doux","Rafraîchissant","Pétillant","Rapide","Classique"]'::jsonb),
  ('howtocook:drink/长岛冰茶', 'fr', 'Long Island Iced Tea', 'Boissons', 'Le Long Island Iced Tea est un cocktail classique qui ressemble à du thé glacé, doux en bouche mais avec une teneur en alcool assez élevée. Il n''a pas une grande valeur nutritive, mais un petit verre occasionnel peut détendre le corps et l''esprit, à ne pas consommer avec excès. La recette est très simple : il suffit de mélanger quatre alcools de base, un liqueur douce et du jus dans les bonnes proportions, même les débutants peuvent le préparer facilement. De la préparation à la finition, cela ne prend qu''environ 5 minutes.', '[{"name":"Gin","unit":"ml"},{"name":"Tequila","unit":"ml"},{"name":"Vodka","unit":"ml"},{"name":"Rhum blanc","unit":"ml"},{"name":"Liqueur d''orange","unit":"ml"},{"name":"Citron","unit":"pièce"},{"name":"Jus de citron","unit":"ml"},{"name":"Sirop d''érable","unit":"ml"},{"name":"Cola","unit":"ml"},{"name":"Glaçons","unit":"g"}]'::jsonb, '["Coupez le citron en deux et pressez 30 ml de jus de citron dans le verre ;","Ajoutez successivement dans le verre :","15 ml de gin,","15 ml de tequila,","15 ml de vodka,","15 ml de rhum blanc,","15 ml de liqueur d''orange ;","Versez lentement 20 ml de sirop d''érable dans le verre en remuant ;","Ajoutez 75 ml de cola dans le verre ;","Ajoutez des glaçons jusqu''à remplir le verre ;","Remuez doucement pendant 20 secondes ;","Dégustez."]'::jsonb, '["Boisson","Cocktail","Légèrement ivre","Rapide","Aigre-doux","Classique"]'::jsonb),
  ('howtocook:meat_dish/农家一碗香/农家一碗香', 'fr', 'Parfum de Ferme', 'Plats de viande', 'Ce plat sauté du Hunan est salé et parfumé, idéal pour accompagner le riz. La poitrine de porc grasse, les œufs tendres et les piments verts frais se combinent pour une texture riche. Le porc et les œufs fournissent des protéines de qualité, et les piments verts apportent de la vitamine C, pour un équilibre nutritionnel. Difficulté moyenne : il faut surveiller la cuisson et l''ordre des assaisonnements, mais les débutants peuvent réussir avec un peu de pratique. Temps de préparation : 7 minutes, cuisson : 10 minutes, soit environ 17 minutes au total.', '[{"name":"Porc","unit":"g"},{"name":"Œufs","note":"quantité suffisante"},{"name":"Piment vert","unit":"pièce"},{"name":"Piment rouge","unit":"pièce"},{"name":"Ail","unit":"tranche"},{"name":"Gingembre","unit":"tranche"},{"name":"Pâte de haricots fermentés (doubanjiang)","unit":"g"},{"name":"Sauce soja","unit":"ml"},{"name":"Sucre blanc","unit":"g"},{"name":"Huile","note":"quantité suffisante"}]'::jsonb, '["Phase de préparation : couper le porc en tranches, de préférence en séparant le gras du maigre. Couper les piments verts et les piments rouges en morceaux, écraser l''ail avec le dos du couteau pour en faire une pâte, et couper le gingembre en fines lamelles. Casser les œufs dans un bol et les battre avec des baguettes.","Une fois les ingrédients prêts, on peut commencer la cuisson. Verser d''abord de l''huile dans la poêle à feu doux. Quand l''huile est chaude, verser les œufs battus et les brouiller jusqu''à ce qu''ils soient cuits mais encore tendres. Les remettre dans le bol et réserver.","Ajouter un peu d''huile dans la poêle, à feu doux. Quand la poêle est chaude, ajouter le gras de porc et faire fondre la graisse.","Quand le gras devient doré, augmenter le feu à moyen, ajouter la viande maigre et faire sauter.","Quand toute la viande a changé de couleur, ajouter les lamelles de gingembre, la pâte d''ail et la pâte de haricots fermentés (doubanjiang). Mélanger pour colorer le porc.","Ajouter les piments verts et rouges, les œufs précuits, puis la sauce soja et le sucre. Continuer à sauter jusqu''à ce que les piments soient légèrement cuits mais encore croquants.","Servir !"]'::jsonb, '["Viande","Savoureux","Pour le riz","Familial","Sauté","Hunan"]'::jsonb),
  ('howtocook:meat_dish/冬瓜酿肉/冬瓜酿肉', 'fr', 'Courge farcie à la viande', 'Plats de viande', 'La courge farcie est un plat vapeur familial associant légume et viande. Sa texture est tendre et lisse, la saveur salée de la farce de viande se marie parfaitement avec la douceur de la courge, pour un résultat léger et non gras. La viande de porc hachée apporte des protéines de qualité et des acides aminés essentiels, tandis que la courge aide à éliminer la chaleur et à favoriser la diurèse, tout en hydratant. La préparation est simple, même un débutant peut réussir facilement, il suffit de s''entraîner un peu à rouler la viande. De la préparation à la cuisson, comptez environ 30 minutes.', '[{"name":"Courge d''hiver","unit":"grammes"},{"name":"Viande de porc hachée","unit":"grammes"},{"name":"Œuf","unit":"pièce"},{"name":"Oignon vert","unit":"grammes"},{"name":"Oignon et gingembre hachés","unit":"grammes"},{"name":"Poivre en poudre","unit":"grammes"},{"name":"Sauce soja légère","unit":"millilitres"},{"name":"Fécule","unit":"grammes"},{"name":"Sel","unit":"grammes"},{"name":"Fécule (pour la liaison)","unit":"grammes"}]'::jsonb, '["Peler la courge, couper en tranches de 25 cm de long et 3 cm d''épaisseur.","Mettre les tranches de courge dans un bol, ajouter 15 g de sel, enrober uniformément, laisser reposer 10 minutes.","Pendant ce temps, dans un autre bol, mettre la viande hachée, l''oignon et le gingembre hachés, 5 g de sel, 5 g de fécule, du poivre, de la sauce soja légère, du poivre.","Remuer la farce dans le sens des aiguilles d''une montre avec des baguettes jusqu''à ce que les couleurs soient homogènes (environ 2 minutes).","Laver les tranches de courge marinées (elles auront ramolli) trois fois à l''eau claire.","Prendre une tranche de courge, la rouler et y insérer la farce.","Disposer dans une assiette en les plaçant sur le bord.","Casser un œuf au centre du cercle.","Placer dans un wok en fer ordinaire avec de l''eau portée à ébullition, cuire à la vapeur 15 minutes, couvrir.","Ouvrir le couvercle, retirer la courge farcie cuite.","Verser le jus de l''assiette dans une casserole, ajouter la fécule délayée, ajouter 50 ml d''eau claire, porter à ébullition.","Verser sur la courge farcie."]'::jsonb, '["Plat de viande","Vapeur","Familial","Accompagnement du riz","Savoureux et parfumé","Viande et légume"]'::jsonb),
  ('howtocook:meat_dish/冷吃兔', 'fr', 'Lapin froid épicé', 'Plats de viande', 'C''est un plat classique de la cuisine salée de Zigong, dans le Sichuan. Il est épicé, sec et parfumé, avec une viande ferme et savoureuse. En bouche, d''abord piquant puis frais, avec un long arrière-goût. Le lapin est riche en protéines, faible en matières grasses, et contient de la lécithine et divers acides aminés. Il est nutritif et facile à digérer. La préparation demande de manipuler plusieurs épices et de contrôler soigneusement le feu, ce qui représente un certain défi pour les débutants. Du début à la cuisson, il faut environ 1h30, mais le plat est encore meilleur après une nuit de repos, ce qui vaut la peine de le préparer à l''avance.', '[{"name":"lapin","note":"quantité suffisante"},{"name":"sel","unit":"g"},{"name":"glutamate","unit":"g"},{"name":"sauce d''huître","unit":"g"},{"name":"vin de cuisine","unit":"g"},{"name":"ail","unit":"tête"},{"name":"gingembre","note":"même quantité que l''ail"},{"name":"oignons verts/poireaux/oignons","unit":"g"},{"name":"piments séchés","note":"volume égal au lapin"},{"name":"poivre vert du Sichuan","note":"pour 3 livres de lapin, un bol entier"},{"name":"étoiles de badiane","unit":"pièce"},{"name":"cannelle","note":"un morceau de la taille du pouce"},{"name":"feuilles de laurier","unit":"feuille"},{"name":"nard","note":"un morceau de la taille d''un haricot"},{"name":"cardamomes blanches","unit":"pièce"},{"name":"fenouil","unit":"g"},{"name":"graines de sésame blanches","unit":"g"}]'::jsonb, '["Éplucher et hacher l''ail et le gingembre. Laver les étoiles de badiane, la cannelle, les feuilles de laurier, le nard, les cardamomes blanches et le fenouil. Réserver.","Couper les piments séchés en tronçons de 2 cm, les laver et réserver.","Laver les oignons verts/poireaux/oignons. Couper les oignons en petits morceaux.","Couper le lapin en morceaux de 2 cm. Assaisonner avec le sel, le vin de cuisine et le glutamate. Laisser mariner 15 minutes.","Verser l''huile dans la poêle. Quand l''huile est à 40 % de sa température maximale, ajouter les oignons verts/poireaux/oignons. Faire revenir à feu moyen-doux jusqu''à ce qu''ils soient légèrement dorés, puis les retirer.","Augmenter le feu à vif. Quand l''huile est à 80 % de sa température, ajouter le lapin. Réduire à feu moyen-doux et frire jusqu''à ce que le lapin soit légèrement doré. Retirer le lapin.","Augmenter la température de l''huile. Ajouter les piments séchés, le poivre vert du Sichuan, les étoiles de badiane, la cannelle, les feuilles de laurier, le nard, les cardamomes blanches et le fenouil. Passer à feu doux et faire frire jusqu''à ce que les piments soient croustillants.","Remettre le lapin, ajouter la sauce d''huître et faire sauter quelques minutes.","Éteindre le feu. Ajouter l''ail, le gingembre et les graines de sésame blanches. Mélanger uniformément.","Laisser reposer une nuit pour une meilleure imprégnation des saveurs."]'::jsonb, '["Plat de viande","Épicé","Sec et parfumé","Style Zigong Yambang","Accompagnement d''alcool","Frit et sauté"]'::jsonb),
  ('howtocook:meat_dish/凉拌鸡丝/凉拌鸡丝', 'fr', 'Salade de poulet effiloché', 'Plats de viande', 'Une entrée froide maison peu grasse et peu calorique. Le poulet effiloché est tendre et savoureux, l''huile de sésame et le vinaigre aromatique créent une saveur légèrement poivrée et acidulée, rafraîchissante, idéale pour couper la graisse en été. La poitrine de poulet est riche en protéines de qualité et faible en matières grasses. La recette est simple, même les débutants peuvent la réussir facilement. De la préparation à la fin, il faut environ 30 minutes.', '[{"name":"Poitrine de poulet (fraîche ou surgelée)","unit":"g"},{"name":"Huile de sésame (huile de poivre du Sichuan)","unit":"ml"},{"name":"Sauce soja","unit":"ml"},{"name":"Vinaigre aromatique (vinaigre de riz)","unit":"ml"},{"name":"Sucre blanc","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Vin de cuisson","unit":"ml"},{"name":"Gingembre","unit":"g"},{"name":"Eau bouillie refroidie","note":"quantité suffisante"}]'::jsonb, '["Couper le gingembre en tranches, réserver","Verser 4 litres d''eau dans une casserole","Ajouter la poitrine de poulet et les tranches de gingembre","Ajouter 20 ml de vin de cuisson","Porter à ébullition à feu vif sans couvrir","Après ébullition, réduire à feu moyen et écumer la mousse avec une cuillère","Continuer la cuisson 5-7 minutes : 5 minutes si la viande n''est pas congelée, 7 minutes si elle est congelée","La taille de la poitrine de poulet affecte le temps de cuisson. Piquer la poitrine avec des baguettes ; si elles s''enfoncent facilement, le poulet est cuit. Sinon, prolonger la cuisson","Rincer la poitrine de poulet à l''eau bouillie refroidie pour la ramener à température ambiante","Effilocher la poitrine de poulet en filaments fins dans le sens des fibres","Préparer un bol","Ajouter dans le bol l''huile de sésame, la sauce soja, le vinaigre aromatique, le sucre blanc et le sel préparés","Mélanger la sauce pour dissoudre le sucre et le sel autant que possible","Verser la sauce sur le poulet effiloché et mélanger uniformément"]'::jsonb, '["Plat de viande","En salade","Légèrement poivré et acidulé","Rafraîchissant","Faible en calories","Rapide","Estival"]'::jsonb),
  ('howtocook:meat_dish/卤菜/卤菜', 'fr', 'Braisé', 'Plats de viande', 'C''est un plat braisé chinois classique. La viande est tendre et savoureuse, l''arôme est riche. Le bouillon de braisage peut être réutilisé plusieurs fois, devenant plus parfumé avec le temps. Il convient comme plat froid, en apéritif ou avec des plats principaux. Ce plat est riche en protéines de haute qualité et en diverses vitamines, équilibré sur le plan nutritionnel. La préparation demande un peu de patience, mais les étapes sont claires et adaptées aux débutants. Le trempage préalable pour éliminer le sang, la préparation du caramel et le braisage sous pression prennent environ 1 heure, puis un trempage toute une nuit permet aux saveurs de pénétrer. Le lendemain, il suffit de sortir la viande et de la trancher pour la déguster.', '[{"name":"Jarret de bœuf (ou autre viande)","unit":"grammes"},{"name":"Sachet d''épices pour braisé","unit":"sachet"},{"name":"Pâte de soja jaune","unit":"ml"},{"name":"Pâte de haricots fermentés (doubanjiang)","unit":"ml"},{"name":"Sauce d''huître","unit":"ml"},{"name":"Fromage de soja fermenté (nanru)","unit":"ml"},{"name":"Oignon","unit":"pièce"},{"name":"Gingembre","unit":"grammes"},{"name":"Ail","unit":"grammes"},{"name":"Piments séchés","unit":"grammes"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Sel","unit":"grammes"},{"name":"Sucre blanc","unit":"grammes"},{"name":"Bière","unit":"canette"},{"name":"Eau claire","note":"quantité suffisante"},{"name":"Eau chaude","unit":"ml"},{"name":"Vinaigre","unit":"ml"},{"name":"Sucre","unit":"ml"},{"name":"Glutamate/Calcium glutamatique","note":"quantité suffisante"},{"name":"Bouillon de braisage","unit":"ml"},{"name":"Ail haché","note":"quantité suffisante"},{"name":"Ciboule ciselée","note":"quantité suffisante"},{"name":"Graines de sésame blanches","note":"quantité suffisante"},{"name":"Piment en poudre","note":"quantité suffisante"},{"name":"Piment oiseau","note":"selon goût"},{"name":"Huile de sésame ou huile de poivre vert","note":"un peu"},{"name":"Huile végétale","note":"quantité suffisante"},{"name":"Concombre","note":"quantité suffisante"},{"name":"Oreilles de bois (champignons noirs)","note":"quantité suffisante"},{"name":"Cacahuètes frites","note":"quantité suffisante"},{"name":"Coriandre","note":"quantité suffisante"}]'::jsonb, '["Faire tremper le jarret de bœuf dans de l''eau froide pendant au moins 3 heures pour éliminer le sang.","Préparer le caramel : dans une casserole, ajouter 30g de sucre blanc, chauffer à feu doux jusqu''à ce que le sucre soit complètement fondu et prenne une couleur brun foncé. Ajouter 150ml d''eau chaude, bien mélanger et réserver.","Couper l''oignon en morceaux, écraser le gingembre et l''ail, casser les piments séchés en morceaux et réserver.","Ajouter suffisamment d''eau dans une casserole, y mettre le sachet d''épices pour braisé, l''oignon, le gingembre, l''ail et les piments séchés. Porter à ébullition à feu vif.","Ajouter 15ml de pâte de soja jaune, 15ml de pâte de haricots fermentés (doubanjiang), 15ml de sauce d''huître et 15ml de fromage de soja fermenté (nanru), bien mélanger.","Verser le caramel préparé et bien mélanger.","Ajouter 120ml de sauce soja claire et 60ml de sauce soja foncée, bien mélanger.","Ajouter 10-15g de sel pour assaisonner.","Verser 1 canette de bière (330ml) et porter à nouveau à ébullition.","Blanchir le jarret de bœuf dans la casserole pendant 2-3 minutes, puis le retirer et le rincer à l''eau chaude pour enlever les impuretés en surface.","Mettre le jarret blanchi dans le bouillon de braisage bouillant, en s''assurant que le bouillon recouvre toute la viande.","Fermer le couvercle de l''autocuiseur, et après la montée en pression, cuire encore 25-30 minutes.","Après la cuisson, ne pas ouvrir le couvercle, laisser refroidir naturellement et tremper toute une nuit (pour une meilleure imprégnation des saveurs).","Sortir la viande braisée et la placer au réfrigérateur pour qu''elle se raffermisse.","Avant de servir, sortir la viande et la trancher. Elle peut être dégustée telle quelle ou en salade.","Méthode de réutilisation du bouillon : après chaque braisage de viande, filtrer le bouillon pour retirer tous les solides, le porter à nouveau à ébullition pour le stériliser, puis le laisser refroidir avant de le conserver au réfrigérateur ou au congélateur. Lors de l''utilisation, ajouter les assaisonnements selon les proportions de la recette originale. (La quantité d''eau ajoutée dépend de l''utilisation du bouillon.)","Un bouillon bien conservé peut être utilisé très longtemps et devient plus parfumé avec le temps.","Remarque importante : si vous braisez des légumes, prélevez une partie du bouillon et utilisez-le séparément. Le bouillon utilisé pour les légumes ne peut pas être réutilisé.","Mélanger l''ail haché, la ciboule ciselée, les graines de sésame blanches et le piment en poudre dans un rapport 1:1:1:1. Ajouter du piment oiseau selon votre goût. Dans de l''huile végétale chaude, ajouter un peu d''huile de sésame ou d''huile de poivre vert, verser progressivement sur les assaisonnements. Ajouter ensuite 10ml de sauce soja claire, 10ml de vinaigre, 10ml de sauce d''huître, 5ml de sucre, du glutamate/calcium glutamatique, et enfin 15ml de bouillon de braisage. Bien mélanger.","Pour une salade, vous pouvez ajouter du concombre écrasé, des oreilles de bois, des cacahuètes frites et de la coriandre."]'::jsonb, '["Viande","Braisé","Sauce parfumée","Apéritif","Fait maison","Salade"]'::jsonb),
  ('howtocook:meat_dish/口水鸡/口水鸡', 'fr', 'Poulet sauce piquante', 'Plats de viande', 'Le poulet sauce piquante est un plat froid classique du Sichuan. Le poulet enrobé d''huile pimentée est glacé, tendre et élastique, épicé et savoureux. Idéal en été pour ouvrir l''appétit et couper le gras. Le poulet est riche en protéines de qualité, accompagné de cacahuètes concassées et d''épices, fournissant énergie et saveur. Difficulté moyenne, nécessitant une attention à la cuisson du poulet et à l''assaisonnement de l''huile pimentée, adapté aux cuisiniers ayant une certaine expérience. De la préparation à la finition, compter environ 1h30.', '[{"name":"Poulet","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Poudre de piment","unit":"g"},{"name":"Poivre du Sichuan","unit":"g"},{"name":"Cacahuètes","unit":"g"},{"name":"Oignon vert","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Ail","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Vinaigre","unit":"ml"},{"name":"Glutamate monosodique","unit":"g"},{"name":"Poudre de poivre du Sichuan","unit":"g"},{"name":"Coriandre","unit":"g"},{"name":"Sel","note":"à volonté"},{"name":"Huile de sésame","note":"à volonté"}]'::jsonb, '["Couper le gingembre en tranches, 1 oignon vert, 15 grains de poivre du Sichuan, réserver.","Laver le poulet, le mettre dans une casserole, couvrir d''eau froide, ajouter les tranches de gingembre, l''oignon vert et les grains de poivre du Sichuan. Porter à ébullition à feu vif.","Après ébullition, réduire à feu moyen-doux et cuire 20 minutes, puis éteindre le feu.","Retirer le poulet, le plonger dans de l''eau glacée jusqu''à ce qu''il soit bien froid.","Retirer le poulet, le couper en morceaux et disposer dans un plat. Réserver.","Chauffer une poêle à feu doux, ajouter les cacahuètes et les griller jusqu''à ce que la peau éclate. (Remuer constamment pour ne pas brûler.)","Couper 1 oignon vert en tronçons, écraser l''ail en purée, 15 grains de poivre du Sichuan, éplucher et hacher les cacahuètes.","Chauffer de l''huile dans une poêle, ajouter les tronçons d''oignon vert, les grains de poivre et la moitié de l''ail écrasé. Faire revenir jusqu''à ce que cela dégage une odeur.","Lorsque l''huile est très chaude (environ 80% de la température maximale), éteindre le feu et filtrer l''huile chaude.","Verser l''huile chaude dans un bol contenant la poudre de piment, mélanger, puis filtrer pour obtenir l''huile pimentée.","Ajouter à l''huile pimentée le reste d''ail écrasé, la sauce soja légère, le vinaigre, le sel, le glutamate monosodique, le sucre, l''huile de sésame et la poudre de poivre du Sichuan. Bien mélanger et laisser refroidir.","Saupoudrer les cacahuètes hachées sur le poulet, verser l''huile pimentée sur le poulet, parsemer de coriandre. Servir."]'::jsonb, '["Plat de viande","Épicé et piquant","Salade froide","Cuisine du Sichuan","Amuse-gueule","Apéritif"]'::jsonb),
  ('howtocook:meat_dish/可乐鸡翅', 'fr', 'Ailes de poulet au cola', 'Plats de viande', 'Les ailes de poulet au cola sont rouge vif, tendres et glissantes, avec un goût salé-sucré agréable. C''est un plat créatif populaire sur les tables familiales. Les ailes de poulet sont riches en protéines de haute qualité et en graisses, et cuites avec du cola, la viande devient plus tendre. La préparation nécessite de maîtriser le feu pour la friture et la réduction du liquide, ce qui est un défi pour les débutants, mais en suivant les étapes, on peut réussir. De la préparation à la fin, cela prend environ 40 minutes.', '[{"name":"Ailes de poulet (milieu)","unit":"pièce"},{"name":"Cola","unit":"ml"},{"name":"Sucre blanc","unit":"g"},{"name":"Sauce soja légère","unit":"g"},{"name":"Sauce soja foncée","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Gingembre","unit":"tranche"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Ciboule","note":"quantité suffisante"}]'::jsonb, '["Mettez les ailes de poulet dans une casserole, couvrez d''eau froide. Ajoutez 1 tranche de gingembre et 10 à 20 ml de vin de cuisine. Portez à ébullition à feu vif (environ 2 minutes), puis écumez la mousse et égouttez.","Cette étape concerne les ailes de poulet fraîches. Pour les ailes de poulet fraîchement achetées, faites des entailles et marinez directement avec de la sauce soja légère.","Sortez les ailes de poulet, faites deux entailles de chaque côté. Marinez avec environ 10 g de sauce soja légère pendant 10 minutes (il suffit que la sauce soja enrobe bien la surface des ailes).","Remettez la casserole sur feu doux avec de l''huile, faites d''abord revenir les tranches de gingembre restantes, puis ajoutez les ailes de poulet marinées. Faites-les dorer des deux côtés jusqu''à ce qu''elles soient dorées, puis retournez-les. Remuez les ailes avec une spatule et faites-les sauter avec le gingembre 4 à 5 fois (pour éviter qu''elles n''attachent).","Lorsque les ailes sont dorées, versez le cola jusqu''à les recouvrir. Portez à ébullition à feu vif, puis écumez la mousse noire qui flotte (contenant le sang). Ajoutez alors un bouquet de ciboule.","Assaisonnez : ajoutez 2 g de sel, 10 g de sucre blanc, 3 g de sauce soja légère (vous pouvez aussi ajouter un peu de sauce soja foncée pour la couleur, 3 g).","Lorsque le bouquet de ciboule jaunit, retirez-le avec les tranches de gingembre, puis réduisez à feu moyen et continuez à mijoter les ailes de poulet au cola.","Lorsque le cola devient sirupeux, baissez à feu doux pour que la sauce adhère bien aux ailes. Retirez du feu et servez."]'::jsonb, '["Plat de viande","Salé-sucré","Friture","Mijoté","Familial","Accompagne le riz"]'::jsonb),
  ('howtocook:meat_dish/台式卤肉饭/台式卤肉饭', 'fr', 'Riz au porc braisé à la taïwanaise', 'Plats de viande', 'Le riz au porc braisé à la taïwanaise est un plat familial taïwanais riche et parfumé. Les lanières de porc sont tendres et savoureuses, la sauce ambrée et brillante, versée sur du riz chaud, elle est pleine de saveurs. Riche en protéines de qualité, en collagène et en glucides, il apporte rapidement de l''énergie. La recette est très accessible aux débutants : il suffit de préparer les ingrédients et de maîtriser le feu. L''ensemble prend environ 1h30, dont seulement 30 minutes de travail actif, le reste est laissé à mijoter à feu doux.', '[{"name":"Échalote","unit":"grammes"},{"name":"Poitrine de porc avec couenne","unit":"grammes"},{"name":"Œuf","unit":"pièce"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Vin de riz"},{"name":"Ail","unit":"grammes"},{"name":"Feuille de laurier","unit":"feuille"},{"name":"Anis étoilé","unit":"pièce"},{"name":"Sucre candi","unit":"grammes"},{"name":"Poivre blanc moulu","unit":"grammes"},{"name":"Poudre cinq-épices","unit":"grammes"},{"name":"Riz","note":"Quantité suffisante"}]'::jsonb, '["Couper la poitrine de porc avec couenne en fines lanières de 0,7 cm de long × 0,7 cm de large × 2,5 cm de haut.","Hacher l''échalote et l''ail.","Faire cuire les œufs durs, les écaler et inciser le blanc avec un couteau (pour faciliter l''absorption), réserver.","Chauffer une poêle à feu vif, ajouter 15 ml d''huile de cuisson et en enduire le fond.","Le but de l''huile est d''éviter que la poitrine de porc n''attache au début. Attendre 5 secondes que l''huile chauffe légèrement.","Ajouter les lanières de porc, faire sauter jusqu''à ce que la chair blanchisse, puis verser 10 ml de vin de riz le long du bord. Continuer à sauter jusqu''à ce que le porc ne rende plus de graisse.","Ajouter l''échalote hachée dans la poêle et faire sauter 1 minute jusqu''à ce qu''elle libère son parfum.","Ajouter l''échalote hachée dans la poêle et faire sauter 30 secondes.","Pousser le porc sur le côté, ajouter le sucre candi et chauffer jusqu''à ce qu''il fonde et fasse des bulles pour obtenir un caramel, puis mélanger le porc pour bien l''enrober.","Ajouter la sauce soja légère et faire sauter jusqu''à ce que l''arôme se dégage.","Déglacer avec 25 ml de vin de riz, ajouter de l''eau jusqu''à ce que le porc soit recouvert, ajouter le poivre blanc, la poudre cinq-épices, l''anis étoilé, la feuille de laurier et les œufs durs. Porter à ébullition puis réduire à feu doux et laisser mijoter 1 heure.","Note : les sauces soja ont des salinités différentes, goûtez impérativement pendant la cuisson. Si c''est trop sucré, ajoutez de la sauce soja ; si c''est trop salé, ajoutez un peu de sucre ou d''eau pour ajuster.","Pendant la cuisson à feu doux, remuer et vérifier toutes les 15 minutes pour éviter que cela n''attache.","Si c''est trop sec, ajouter 100 ml d''eau claire et continuer la cuisson.","Après 1 heure, augmenter le feu à vif pour réduire la sauce jusqu''à ce qu''elle soit épaisse et brillante, de couleur ambrée. C''est prêt.","Servir un bol de riz, déposer le porc braisé tendre sur le riz, ajouter un œuf braisé et déguster."]'::jsonb, '["Viande","Taïwanais","Familial","Accompagne bien le riz","Parfumé","Mijoté"]'::jsonb),
  ('howtocook:meat_dish/咕噜肉', 'fr', 'Porc aigre-doux à l''ananas', 'Plats de viande', 'Le porc aigre-doux à l''ananas est un plat classique de la cuisine cantonaise, aigre-doux et appétissant, croustillant à l''extérieur et tendre à l''intérieur. L''arôme de l''ananas rend la viande particulièrement rafraîchissante et dégraissante. Le porc fournit des protéines de qualité, tandis que le poivron vert et l''ananas apportent des vitamines et des fibres. La difficulté de ce plat réside dans la maîtrise de la friture, ce qui peut être un défi pour les débutants, mais en suivant les étapes, on réussira. De la marinade à la sortie du feu, il faut environ 40 minutes, ce qui en fait un plat rapide idéal pour la famille.', '[{"name":"Échine de porc","unit":"grammes"},{"name":"Poivron vert","unit":"grammes"},{"name":"Tranches d''ananas en conserve","unit":"grammes"},{"name":"Sel","unit":"cuillère à café"},{"name":"Ketchup","unit":"cuillère à soupe"},{"name":"Vinaigre blanc","unit":"cuillère à café"},{"name":"Ail émincé","unit":"cuillère à soupe"},{"name":"Sauce soja légère","unit":"cuillère à café"},{"name":"Fécule de maïs","unit":"cuillère à café"},{"name":"Sucre blanc","unit":"cuillère à soupe"},{"name":"Eau","unit":"millilitres"},{"name":"Huile","note":"Quantité suffisante"}]'::jsonb, '["Lavez l''échine de porc (100 g) et séchez-la avec du papier absorbant. Coupez la viande en morceaux légèrement plus petits que la taille finale souhaitée.","Faites mariner l''échine de porc avec du sel (1/2 cuillère à café) pendant 20 minutes.","Hachez le poivron vert (25 g).","Coupez les tranches d''ananas en conserve (75 g) en morceaux.","Dans un bol, mélangez le ketchup (4 cuillères à soupe), le vinaigre blanc (2 cuillères à café), l''ail émincé (1 cuillère à soupe), la sauce soja légère (½ cuillère à café), la fécule de maïs (2½ cuillères à café), le sucre blanc (2 cuillères à soupe), le sel (¼ cuillère à café) et l''eau (200 ml). Mélangez bien pour obtenir une sauce.","Enrobez les morceaux d''échine de porc de fécule de maïs (6 cuillères à soupe).","Ajoutez l''huile (500 ml) et chauffez à feu moyen.","Faites frire les morceaux d''échine de porc à feu moyen pendant 5 minutes, puis égouttez-les.","Ajoutez à nouveau les morceaux d''échine de porc et faites-les frire à feu vif pendant 1 minute.","Ajoutez l''huile (1 cuillère à café) et la sauce, chauffez à feu moyen pendant 3 minutes.","Ajoutez le poivron vert et l''ananas, chauffez à feu vif pendant 2 minutes.","Mélangez les morceaux d''échine de porc frits avec la sauce, puis servez."]'::jsonb, '["Plat de viande","Aigre-doux","Cantonnais","Familial","Accompagnement de riz","Friture"]'::jsonb),
  ('howtocook:meat_dish/咖喱肥牛/咖喱肥牛', 'fr', 'Bœuf au curry', 'Plats de viande', 'Le bœuf au curry est un plat familial savoureux qui se marie bien avec le riz. La chaleur du curry se mêle au gras du bœuf, accompagné de légumes comme les pommes de terre et les carottes, pour une texture fondante et riche. Riche en protéines, vitamines et calcium, il offre un équilibre entre viande et légumes. La recette est simple, idéale pour les débutants, et prête en 40 minutes environ. Parfait pour les lunchbox.', '[{"name":"Feuilles de laurier","unit":"feuille"},{"name":"Lait entier","unit":"ml"},{"name":"Oignon","unit":"g"},{"name":"Carotte","unit":"g"},{"name":"Pomme de terre","unit":"g"},{"name":"Tranches de bœuf (pour fondue)","unit":"g"},{"name":"Bloc de curry","unit":"bloc"},{"name":"Huile de cuisson","unit":"ml"}]'::jsonb, '["Couper l''oignon en lanières, les carottes et les pommes de terre en morceaux. Réserver.","Porter une casserole d''eau à ébullition. Y plonger les tranches de bœuf, écumer la mousse, puis égoutter. Réserver.","Chauffer la poêle avec 10 à 15 ml d''huile de cuisson. Attendre 10 secondes pour que l''huile chauffe.","Ajouter l''oignon et faire revenir jusqu''à ce qu''il devienne tendre et translucide.","Ajouter les pommes de terre et les carottes, faire sauter 2 minutes.","Ajouter de l''eau froide jusqu''à ce que tous les ingrédients soient juste recouverts.","Ajouter les feuilles de laurier et le bloc de curry. Couvrir. Quand l''eau bout, réduire le feu et laisser mijoter jusqu''à ce que les pommes de terre et les carottes soient tendres (vérifier avec une fourchette).","Ajouter les tranches de bœuf et le lait. Couvrir et laisser mijoter à feu doux 2-3 minutes. Servir (remuer délicatement à la cuillère pour ne pas casser la viande)."]'::jsonb, '["plat de viande","savoureux avec du riz","mijoté","familial","rapide","curry"]'::jsonb),
  ('howtocook:meat_dish/商芝肉', 'fr', 'Porc à la fougère', 'Plats de viande', 'Le porc à la fougère est un plat traditionnel du comté de Shang, dans la province du Shaanxi. Sa couleur est rouge vif, sa texture tendre, gras mais pas lourd, avec l''arôme unique de la fougère Shang. Le porc fournit des protéines de haute qualité et des graisses, tandis que la fougère Shang, un légume de type fougère, ajoute des fibres alimentaires et divers oligo-éléments. Ce plat a des étapes complexes et exige des compétences en coupe et en contrôle de la température, adapté à ceux qui ont une certaine base culinaire. De la préparation à la finition, il faut environ 2,5 heures.', '[{"name":"Poitrine de porc avec peau","unit":"g"},{"name":"Fougère Shang","unit":"g"},{"name":"Poireau","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Anis étoilé","unit":"pièce"},{"name":"Miel","unit":"g"},{"name":"Vinaigre","unit":"g"},{"name":"Vin de cuisine","unit":"g"},{"name":"Glutamate monosodique","unit":"g"},{"name":"Sauce soja","unit":"g"},{"name":"Crêpe à l''œuf","unit":"pièce"},{"name":"Sel fin","unit":"g"},{"name":"Bouillon de poulet","unit":"g"},{"name":"Huile de sésame","unit":"g"},{"name":"Saindoux cuit","unit":"g"}]'::jsonb, '["Grattez et lavez la viande, faites-la cuire dans une casserole d''eau jusqu''à ce qu''elle soit cuite à 60% (blanchisse), retirez-la et, pendant qu''elle est encore chaude, badigeonnez la peau de miel et de vinaigre.","Dans un wok, mettez du saindoux cuit, chauffez à feu vif jusqu''à 80% de chaleur (environ 200°C, beaucoup de fumée bleue, l''huile est calme), plongez le morceau de viande côté peau vers le bas, faites frire jusqu''à ce qu''il soit rouge doré, retirez-le et trempez-le dans la casserole d''eau froide (la même casserole que celle utilisée pour la cuisson) pour le ramollir, placez-le sur une planche à découper, coupez-le en tranches de 10 cm de long et 0,6 cm d''épaisseur, toujours côté peau vers le bas, et disposez-les bien alignées dans un bol à vapeur.","Coupez 5 g de poireau en tronçons de 2,4 cm, et 5 g en tranches obliques de 2,4 cm. Pelez et lavez le gingembre, coupez 1,5 g en tranches, 5 g en hachis. Coupez la crêpe à l''œuf en triangles isocèles de 2,4 cm de côté.","Faites bouillir la fougère dans de l''eau bouillante jusqu''à ce qu''elle soit tendre, retirez-la, enlevez les tiges dures et les impuretés, lavez-la bien, coupez-la en tronçons de 3 cm, mettez-la dans un bol, ajoutez la sauce soja (5 g), le sel (1 g), le saindoux cuit (10 g), mélangez, et couvrez les tranches de viande. Dans un petit bol, mettez le bouillon de poulet (100 g), ajoutez la sauce soja (5 g), le sel (0,5 g), le vin de cuisine (15 g), mélangez, versez dans le bol à vapeur. Ajoutez les tranches de gingembre, les tronçons de poireau et l''anis étoilé. Faites cuire à la vapeur à feu vif pendant environ 30 minutes, puis réduisez le feu et continuez à cuire à la vapeur pendant environ 1 heure 30 minutes. Lorsque la viande est bien tendre, retirez-la, enlevez le gingembre, le poireau et l''anis étoilé, filtrez le jus, et renversez la viande dans une assiette creuse.","Dans un wok, mettez le bouillon de poulet (100 g), ajoutez le jus filtré, portez à ébullition à feu vif. Ajoutez le hachis de gingembre, les tranches de poireau et le glutamate monosodique, mélangez. Ajoutez la crêpe à l''œuf, versez l''huile de sésame, puis versez le tout sur la viande dans l''assiette. Servez."]'::jsonb, '["Viande","Shaanxi","Vapeur","Savoureux","Pour invités","Traditionnel"]'::jsonb),
  ('howtocook:meat_dish/啤酒鸭/啤酒鸭', 'fr', 'Canard à la bière', 'Plats de viande', 'Ce plat familial au caractère unique est tendre et savoureux, avec un parfum subtil de bière. Il est chaud sans être lourd, parfumé sans être gras. Le canard est riche en protéines, et la bière élimine le goût de gibier tout en rehaussant les arômes. La recette est idéale pour les débutants, et nécessite environ 1 heure de la préparation à l''assiette.', '[{"name":"Canard","unit":"pièce","note":""},{"name":"Bière","unit":"ml","note":""},{"name":"Sauce soja claire","unit":"ml","note":""},{"name":"Sauce soja foncée","unit":"ml","note":""},{"name":"Gingembre","unit":"tranche","note":""},{"name":"Ail","unit":"gousse","note":""},{"name":"Sucre candi","unit":"g","note":""},{"name":"Piment sec","unit":"pièce","note":""},{"name":"Vin de cuisson","unit":"ml","note":""},{"name":"Sel","unit":"g","note":""},{"name":"Bouillon de poulet","unit":"g","note":""},{"name":"Clou de girofle","unit":"pièce","note":""},{"name":"Anis étoilé","unit":"pièce","note":""},{"name":"Feuille de laurier","unit":"pièce","note":""},{"name":"Pâte de fèves épicée","unit":"g","note":""}]'::jsonb, '["Couper le canard en morceaux de 3 cm. Mettre les morceaux dans une casserole d''eau froide avec des tranches de gingembre et du vin de cuisson. Blanchir, puis égoutter et réserver.","Faire chauffer le wok, ajouter environ 100 ml d''huile de cuisson. À feu vif, une fois l''huile chaude, faire sauter le canard jusqu''à coloration.","Lorsque le canard a complètement changé de couleur (visiblement blanchi), le pousser sur un côté du wok. Ajouter la pâte de fèves et le sucre, faire revenir à feu doux jusqu''à obtenir une couleur caramélisée et un parfum agréable.","Ajouter les clous de girofle, l''anis étoilé, les feuilles de laurier, les piments secs, la sauce soja claire, la sauce soja foncée et l''ail. Faire sauter jusqu''à dégager les arômes.","Verser la bière de façon à recouvrir le canard. Ajouter le sel et le bouillon de poulet. Cuire à feu moyen pendant 30 minutes (si vous préférez une viande plus tendre, laisser cuire 5 minutes de plus).","Dresser dans un plat de service et servir."]'::jsonb, '["Viande","Savoureux","Mijoté","Sichuan","Familial","Accompagnement riz"]'::jsonb),
  ('howtocook:meat_dish/回锅肉/回锅肉', 'fr', 'Porc double cuisson', 'Plats de viande', 'Le porc double cuisson est un plat traditionnel du Sichuan, à base de poitrine de porc. Le plat fini a une couleur rouge vif, la graisse est translucide et légèrement enroulée, la viande maigre est sèche et parfumée sans être filandreuse. La texture est grasse mais pas grasse, salée et légèrement épicée, avec un arôme composé de ciboule et de sauce aux fèves de soja. Le porc est riche en protéines de haute qualité et en acides gras essentiels, et l''ajout de poivrons rouges et verts et de ciboule apporte des vitamines. Ce plat comporte plusieurs étapes, notamment l''ébullition, la coupe et la cuisson, ce qui demande un certain contrôle du feu et des compétences en coupe, mais suivre la procédure permet même aux débutants de réussir. Le temps total estimé est d''environ 40 minutes.', '[{"name":"Poitrine de porc","unit":"livre"},{"name":"Oignon vert","unit":"pièce"},{"name":"Gingembre","unit":"g"},{"name":"Poivrons rouges et verts","unit":"g"},{"name":"Ciboule","unit":"botte"},{"name":"Vin de cuisson","unit":"ml"},{"name":"Sauce aux fèves de soja","unit":"ml"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Glutamate","unit":"g"}]'::jsonb, '["Faites chauffer la poêle et pressez fermement la poitrine de porc avec la main pour griller la peau.","Cette étape permet de traiter les glandes sudoripares sur la peau (ou demandez au boucher de griller la peau, ignorer si vous aimez le goût).","Frottez la peau avec une éponge métallique jusqu''à ce que les parties noires carbonisées soient complètement enlevées, sinon cela donnera un goût amer.","Placez la poitrine de porc dans une casserole, ajoutez de l''eau froide à hauteur, des tranches de gingembre, du vin de cuisson et des oignons verts (nouez 2 oignons verts).","Portez à ébullition à feu vif, écumez la mousse, puis continuez à cuire pendant 15 minutes, jusqu''à ce qu''un couteau traverse facilement la partie maigre.","Coupez les poivrons rouges et verts en rondelles.","Coupez la ciboule en tronçons.","Coupez le gingembre en fines tranches.","Mélangez à l''avance 5 ml de sauce aux fèves de soja et 5 ml de sauce soja légère.","Sortez la poitrine de porc cuite et plongez-la dans l''eau froide pour la refroidir.","Épongez la poitrine de porc et coupez-la en tranches de 2 mm d''épaisseur (trop épaisses, la texture est mauvaise et très grasse).","Faites chauffer la poêle et ajoutez une fine couche d''huile pour l''enduire.","Faites revenir les tranches de porc jusqu''à ce que la graisse devienne translucide et que les tranches s''enroulent légèrement (forme de lampe), avec la poitrine de porc de deuxième coupe pour le meilleur effet.","Versez le mélange de sauce aux fèves de soja et de sauce soja légère, ajoutez 5 g de glutamate, et faites revenir 15 secondes.","Ajoutez les rondelles de poivrons rouges et verts et les fines tranches de gingembre, ajoutez 5 ml supplémentaires de sauce aux fèves de soja, et faites revenir 30 secondes.","Ajoutez la ciboule et faites revenir 60 secondes.","Servez.","Pour la poitrine de porc congelée, laissez reposer à température ambiante 0,5 heure, ou pour la poitrine fraîche, placez-la au réfrigérateur 1 heure, puis coupez-la en tranches de 2 à 5 mm.","À feu moyen, faites griller à sec les piments dans la poêle pendant 30 à 45 secondes, puis retirez-les.","Faites chauffer la poêle, ajoutez une fine couche d''huile, et faites revenir les tranches de gingembre 15 secondes.","Ajoutez la poitrine de porc, remuez toutes les 10 secondes, jusqu''à ce que la viande prenne une couleur jaune brunâtre (plus on remue, plus la texture devient ferme).","Ajoutez les piments grillés à sec, 10 ml de sauce aux fèves de soja, et de la sauce soja légère pour assaisonner, continuez à remuer 60 secondes.","Ajoutez la ciboule coupée en tronçons et remuez 10 secondes.","Servez."]'::jsonb, '["Plat de viande","Cuisine sichuanaise","Maison","Accompagnement du riz","Sauté","Salé et frais"]'::jsonb),
  ('howtocook:meat_dish/土豆炖排骨/土豆炖排骨', 'fr', 'Ragoût de côtes de porc et pommes de terre', 'Plats de viande', 'Les côtes de porc sont tendres et se détachent des os, les pommes de terre sont fondantes et imprégnées de saveur, la sauce est riche, légèrement sucrée et épicée. C''est un ragoût familial typique du nord. Riche en protéines, calcium et glucides, équilibré nutritionnellement. La préparation est un peu difficile, nécessitant la maîtrise du caramel de sucre et du feu, mais les étapes sont claires et les débutants peuvent essayer. Durée totale : environ 1h30.', '[{"name":"côtes de porc","unit":"g"},{"name":"pommes de terre","unit":"g"},{"name":"gingembre","unit":"g"},{"name":"ciboule","unit":"g"},{"name":"vin de cuisine","unit":"ml"},{"name":"sucre blanc","unit":"g"},{"name":"piments séchés","unit":"g"},{"name":"anis étoilé","unit":"g"},{"name":"poivre de Sichuan","unit":"g"},{"name":"cannelle","unit":"g"},{"name":"sauce soja claire","unit":"ml"},{"name":"sauce soja foncée","unit":"ml"},{"name":"sauce d''huître","unit":"ml"},{"name":"pâte de soja jaune","unit":"g"},{"name":"sel","unit":"g"},{"name":"huile de cuisson","unit":"ml"},{"name":"eau bouillante","unit":"ml"}]'::jsonb, '["Préparer les pommes de terre : Éplucher 300g de pommes de terre, les couper en morceaux irréguliers (coupe en biais). Les immerger immédiatement dans un bol d''eau froide pour éviter l''oxydation. Réserver.","Préparer le gingembre et la ciboule : Couper 30g de gingembre en fines tranches (diviser en deux portions de 15g). Préparer 25g de ciboule : en faire un fagot avec 15g, ciseler finement les 10g restants. Réserver.","Bol de sauce (appel unique) : Dans un petit bol, ajouter successivement 10ml de sauce soja claire, 5ml de sauce soja foncée, 5ml de sauce d''huître, 5g de pâte de soja jaune. Mélanger jusqu''à homogénéité. Placer à portée de main.","Assiette d''épices (appel unique) : Dans une petite assiette, mettre 5g de piments séchés, 1g d''anis étoilé (1-2 étoiles), 1g de poivre de Sichuan (environ 10 grains), 1g de cannelle (un petit morceau), et les 15g de tranches de gingembre préparées. Réserver.","Processus eau asynchrone : Allumer la bouilloire électrique pour faire chauffer 700ml d''eau bouillante (s''assurer qu''elle soit prête à la fin de la cuisson).","Blanchir à l''eau froide : Mettre 750g de côtes de porc dans une casserole d''eau froide, ajouter le fagot de ciboule (15g), 15g de tranches de gingembre, 15ml de vin de cuisine. Porter à ébullition à feu vif, puis maintenir l''ébullition pendant 2 minutes pour extraire les impuretés.","Rincer à l''eau chaude, éviter l''eau froide : Égoutter les côtes. Les rincer à l''eau chaude pour enlever les impuretés en surface (l''eau froide contracterait la viande et la durcirait).","Séchage absolu (anti-éclaboussures) : Essuyer soigneusement les côtes avec du papier absorbant pour qu''elles soient bien sèches. Les mettre dans une assiette à côté du wok (pour éviter les éclaboussures lors de l''ajout du caramel chaud).","Caraméliser le sucre : Mettre le wok à feu moyen-doux avec 20ml d''huile de cuisson. Ajouter 10g de sucre blanc, remuer sans cesse jusqu''à ce que le sucre fonde et devienne une couleur caramel brun-rouge.","Colorer et saisir : Ajouter rapidement les 750g de côtes de porc bien séchées, passer à feu moyen-vif. Faire saisir pendant environ 2-3 minutes jusqu''à ce que les côtes soient dorées et bien enrobées de caramel.","Explosion d''arômes en un geste : Faire un espace au centre du wok, y verser l''assiette d''épices. Faire revenir dans l''huile chaude pendant environ 10 secondes pour libérer les arômes.","Assaisonnement en un geste : Verser le long du bord du wok les 10ml de vin de cuisine restants pour faire monter les arômes. Ajouter immédiatement le bol de sauce, faire sauter environ 30 secondes pour bien enrober les côtes et libérer les arômes de la sauce.","Ajouter l''eau et mijoter : L''eau bouillante est prête, verser directement 700ml d''eau bouillante (doit couvrir les côtes), porter à ébullition à feu vif. Couvrir et réduire à feu doux, laisser mijoter 40 minutes.","Ajouter les pommes de terre : Après 40 minutes, ouvrir le couvercle, égoutter les 300g de pommes de terre de l''eau et les ajouter dans le wok. Recouvrir et continuer à mijoter à feu doux pendant 15-20 minutes jusqu''à ce qu''une baguette les transperce facilement.","Ajuster l''assaisonnement et faire réduire la sauce : Ouvrir le couvercle, ajouter 3g de sel (goûter et ajuster selon les préférences). Passer à feu vif et remuer pour faire réduire la sauce, environ 3-5 minutes jusqu''à ce qu''elle épaississe et nappe bien les côtes et les pommes de terre. Éteindre le feu.","Dresser et décorer : Servir dans un plat, saupoudrer uniformément les 10g de ciboule ciselée réservée pour la décoration."]'::jsonb, '["Viande","Sauce parfumée","Légèrement piquant","Mijoté","Nord","Accompagnement de riz","Familial"]'::jsonb),
  ('howtocook:meat_dish/奶酪培根通心粉/奶酪培根通心粉', 'fr', 'Macaroni au fromage et bacon', 'Plats de viande', 'Le macaroni au fromage et bacon est un plat américain classique et réconfortant. La texture est riche et crémeuse, le fromage enrobe les macaronis al dente, accompagné de bacon croustillant, salé et satisfaisant. Riche en protéines et calcium, mais aussi en calories et graisses, à consommer avec modération. La préparation demande un peu de patience ; maîtriser la béchamel de base et la cuisson peut être un défi pour les débutants, mais dans l''ensemble c''est de difficulté moyenne. Sans cuisson au four, il est prêt en environ 30 minutes ; si vous choisissez de le gratiner, il faudra préchauffer et cuire plus longtemps, soit environ 1 heure au total.', '[{"name":"Macaronis","unit":"g"},{"name":"Fromage","unit":"g"},{"name":"Fromage (pour gratiner)","unit":"g"},{"name":"Viande","unit":"g"},{"name":"Oignon","unit":"g"},{"name":"Beurre","unit":"g"},{"name":"Farine","unit":"g"},{"name":"Lait","unit":"ml"},{"name":"Ail","unit":"gousse"}]'::jsonb, '["Râper le fromage en copeaux fins.","Couper l''oignon en lanières.","Faire cuire les macaronis dans de l''eau légèrement salée pendant 6 minutes.","Feu moyen.","Mettre le beurre dans la casserole et attendre qu''il fonde.","Ajouter l''oignon.","Une fois l''oignon ramolli, ajouter l''ail.","Lorsque l''ail dégage son arôme, ajouter la viande et attendre 5 secondes.","Feu doux.","Ajouter le lait en quatre fois, en remuant 5 secondes après chaque ajout avant d''ajouter le suivant.","Ajouter la farine et bien mélanger.","Ajouter le fromage et mélanger jusqu''à consistance lisse.","Incorporer les macaronis au mélange de fromage.","Si vous ne prévoyez pas de gratiner, vous pouvez le servir directement.","Gratinage :","Préchauffer le four à 180°C.","Répartir les 50 g de fromage supplémentaires sur les macaronis.","Une fois le four préchauffé à 180°C, y placer les macaronis.","Faire cuire jusqu''à ce que le dessus soit doré, environ 24 minutes."]'::jsonb, '["Plat de viande","Saveur lactée","Salé","Gratiné","Américain","Fait maison"]'::jsonb),
  ('howtocook:meat_dish/姜炒鸡/姜炒鸡', 'fr', 'Poulet sauté au gingembre', 'Plats de viande', 'Le poulet sauté au gingembre est un plat d''accompagnement typique du Hunan. Le poulet est sec et parfumé, le gingembre est riche et épicé sans être sec. Le poulet est riche en protéines de qualité, le gingembre aide à chasser le froid et à réchauffer l''estomac, stimulant l''appétit. La recette est simple, même les débutants peuvent la maîtriser facilement. Du marinage au service, il faut environ 1 heure.', '[{"name":"Poulet","unit":"pièce"},{"name":"Gingembre frais","unit":"g"},{"name":"Bière","unit":"ml"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Piment oiseau","unit":"pièce"},{"name":"Piment long rouge","unit":"pièce"},{"name":"Piment mariné","unit":"pièce"},{"name":"Ail","unit":"tête"}]'::jsonb, '["Couper le poulet en petits morceaux d''environ 1 cm, les laver et les égoutter, puis les faire mariner avec de la sauce soja légère et du vin de cuisine pendant 30 minutes.","Chauffer la poêle jusqu''à ce qu''elle soit légèrement fumante, ajouter l''huile de cuisson, attendre 5 secondes.","Ajouter les tranches de gingembre et faire sauter à feu moyen pendant 30 secondes.","Ajouter les morceaux de poulet et faire sauter pendant 3 minutes, jusqu''à ce que l''eau soit évaporée et que la graisse du poulet soit libérée.","Ajouter les piments hachés et les gousses d''ail, saler et ajouter de la sauce soja foncée, continuer à faire sauter pendant 30 secondes.","Verser la bière, couvrir et laisser mijoter à feu moyen-doux pendant 2 minutes.","Augmenter le feu pour réduire la sauce, puis servir."]'::jsonb, '["Plat de viande","Saveur du Hunan","Plat d''accompagnement","Épicé","Sauté","Familial"]'::jsonb),
  ('howtocook:meat_dish/姜葱捞鸡/姜葱捞鸡', 'fr', 'Poulet au gingembre et à la ciboule', 'Plats de viande', 'Le poulet au gingembre et à la ciboule est un plat familial classique cantonais. La viande de poulet est tendre et juteuse, avec un arôme intense de gingembre et d''oignon vert. Salé et savoureux, il se marie très bien avec le riz. Les cuisses de poulet fournissent des protéines de qualité, et le gingembre et l''oignon vert aident à réchauffer l''estomac et à stimuler l''appétit. La préparation se fait principalement à la vapeur et à la main, les étapes sont claires et faciles pour les débutants. Du début à la fin, cela prend environ 40 minutes.', '[{"name":"Cuisses de poulet","unit":"pièce"},{"name":"Poudre de poulet salé","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Ciboule","unit":"tige"},{"name":"Sel","unit":"g"},{"name":"Sucre","unit":"g"},{"name":"Huile","unit":"ml"}]'::jsonb, '["Nettoyez quatre cuisses de poulet et placez-les dans un bol.","Ajoutez la poudre de poulet salé et 5 ml d''huile dans le bol, mélangez bien.","Laissez mariner les cuisses de poulet pendant 15 minutes, pendant ce temps, préparez un cuiseur vapeur et portez l''eau à ébullition.","Une fois la marinade terminée, placez les cuisses dans le cuiseur vapeur et faites cuire à la vapeur pendant 20 minutes.","Coupez le gingembre selon votre goût : 1) en purée, 2) en julienne, ou 3) en petits dés.","Coupez la ciboule en petits morceaux de 0,5 cm.","Mettez le gingembre et la ciboule dans un bol pour la sauce, ajoutez le sel et le sucre.","Versez l''huile restante dans une autre casserole et chauffez-la à 60-70% de sa capacité (6 à 7 sur 10).","Versez l''huile chaude sur le gingembre et la ciboule dans le bol.","Une fois les cuisses de poulet cuites à la vapeur, effilochez-les en lamelles d''environ 1 cm de large (pas trop fines).","Versez l''huile au gingembre et à la ciboule sur les lamelles de poulet, mélangez bien et servez."]'::jsonb, '["Plat de viande","Cantonnais","Cuit à la vapeur","Effiloché","Salé et savoureux","Accompagnement de riz","Rapide"]'::jsonb),
  ('howtocook:meat_dish/孜然牛肉', 'fr', 'Bœuf au cumin', 'Plats de viande', 'Le bœuf au cumin est un sauté maison épicé et tendre, où le riche arôme du cumin se marie parfaitement avec la douceur du bœuf et le croquant du poivron vert. Le bœuf est riche en protéines de haute qualité et en fer, et associé au poivron vert, il apporte également des vitamines, pour un repas équilibré. La préparation demande un peu de maîtrise du couteau et du feu, et convient aux amateurs ayant quelques bases en cuisine. En comptant la marinade et la préparation des ingrédients, il faut environ 45 minutes pour le servir.', '[{"name":"Filet de bœuf ou épaule de bœuf","unit":"g"},{"name":"Poivron vert","unit":"pièce"},{"name":"Cumin","unit":"g"},{"name":"Piment rouge","unit":"pièce"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Fécule","unit":"g"},{"name":"Huile","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Ciboule","unit":"tige"}]'::jsonb, '["Commencez par hacher les piments rouges, puis mettez-les dans un mortier avec les grains de cumin et pilez-les jusqu''à obtenir une texture granuleuse, pour plus de saveur. Si vous manquez de temps, vous pouvez sauter cette étape.","Coupez l''extrémité du poivron vert et retirez les graines (si vous aimez le piquant, vous pouvez les laisser), puis coupez-le en julienne. Coupez la ciboule en tronçons.","Décongelez le bœuf à l''avance, rincez-le à l''eau, séchez-le avec du papier absorbant ou laissez-le égoutter, puis coupez-le en tranches dans le sens des fibres.","Ensuite, marinez la viande : ajoutez la sauce soja légère, la fécule, l''huile, mélangez bien et laissez reposer 30 minutes. Vous pouvez également vous référer à la méthode de marinade apprise.","Chauffez un wok avec de l''huile, ajoutez la ciboule, une fois parfumé, ajoutez le bœuf mariné et faites-le sauter.","Lorsque le bœuf change de couleur, ajoutez uniformément le mélange de cumin et de piment pilé, et faites cuire jusqu''à ce qu''il soit bien cuit.","Ajoutez ensuite les juliennes de poivron vert, et une fois qu''elles sont cuites mais encore croquantes, assaisonnez de sel.","Faites sauter à feu vif pendant 1 minute, puis éteignez le feu et remuez encore 30 secondes pour assurer une cuisson uniforme, puis servez."]'::jsonb, '["Plat de viande","Épicé","Maison","Sauté","Accompagnement de riz","Cumin"]'::jsonb),
  ('howtocook:meat_dish/宫保鸡丁/宫保鸡丁', 'fr', 'Poulet Kung Pao', 'Plats de viande', 'Ce célèbre plat du Sichuan se distingue par son goût de poivre et de piment, avec une touche aigre-douce subtile où l''arôme des piments secs et du poivre de Sichuan se mêle à la tendreté du poulet et au croustillant des cacahuètes, offrant une texture riche. Riche en protéines de qualité et en acides gras insaturés, il ouvre l''appétit et accompagne parfaitement le riz. La recette se décline en deux versions, simple et avancée, accessible aux débutants à condition de bien planifier le temps de marinade. De la préparation à la cuisson, comptez environ 1h30.', '[{"name":"Cuisse de poulet (ou poitrine de poulet)","unit":"pièce"},{"name":"Oignon vert","unit":"tige"},{"name":"Gingembre","unit":"g"},{"name":"Piments secs","unit":"g"},{"name":"Piments Er Jing Tiao","unit":"pièce"},{"name":"Cacahuètes cuites","unit":"g"},{"name":"Cacahuètes crues","note":"quantité suffisante"},{"name":"Poivre de Sichuan","unit":"g"},{"name":"Sauce soja claire","unit":"g"},{"name":"Sauce soja foncée","unit":"g"},{"name":"Vinaigre parfumé","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Vin de cuisine","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Glutamate monosodique","unit":"g"},{"name":"Fécule","unit":"g"},{"name":"Fécule (pour liaison)","unit":"g"},{"name":"Huile végétale","unit":"g"},{"name":"Huile de sésame","unit":"g"},{"name":"Pâte de piment","unit":"g"},{"name":"Laitue asperge","unit":"g"},{"name":"Huile de piment","unit":"g"},{"name":"Eau bouillante","unit":"g"},{"name":"Eau claire","unit":"g"}]'::jsonb, '["Désosser la cuisse de poulet avec des ciseaux, attendrir le côté chair avec le dos d''un couteau, couper en lanières puis en dés de 1,5 cm de côté ; les tremper dans de l''eau claire pendant 10 minutes, égoutter et réserver (si vous utilisez une poitrine de poulet, vous pouvez directement la couper en dés et passer aux étapes suivantes).","Mettre la partie verte de l''oignon vert et 5 g de gingembre dans un bol, verser 50 g d''eau bouillante et réserver ; couper la partie blanche de l''oignon en rondelles de 1,5 cm et réserver ; mettre les cacahuètes au micro-ondes à puissance maximale pendant 5 minutes pour les torréfier, réserver.","Ajouter 2 g de sel, 5 g de sauce soja foncée, 15 g de vin de cuisine, 15 g de fécule aux dés de poulet, mélanger jusqu''à ce que la préparation soit légèrement sèche ; ajouter lentement une partie de l''eau à l''oignon et au gingembre, mélanger jusqu''à ce que les dés de poulet soient collants ; couvrir d''un film plastique et mettre au réfrigérateur pour mariner 1 heure.","Couper les piments secs en morceaux ; chauffer une poêle à feu vif puis passer à feu doux ; mettre les piments secs à torréfier jusqu''à ce qu''ils soient légèrement brûlés, les retirer et réserver ; torréfier le poivre de Sichuan jusqu''à ce qu''il soit parfumé, le retirer et réserver.","Passer à feu vif, verser 20 g d''huile végétale, lorsqu''elle est à 70 % de chaleur (les baguettes en bambou font des bulles), ajouter les dés de poulet, les faire cuire jusqu''à ce que le dessus blanchisse, retourner avec une spatule, cuire 30 secondes puis mélanger.","Ajouter les rondelles d''oignon et faire sauter, ajouter le reste de l''eau à l''oignon et au gingembre (si moins de 100 g, compléter avec un peu d''eau chaude) ; couvrir, réduire à feu moyen-doux et laisser mijoter 2 minutes.","Passer à feu vif, ajouter les cacahuètes cuites, les piments secs et le poivre de Sichuan ; ajouter 2 g de glutamate monosodique, 5 g de vinaigre parfumé, 2 g de sucre blanc, mélanger.","Mélanger 10 g de fécule avec 50 g d''eau claire pour faire une sauce de liaison, l''ajouter à la poêle, mélanger et épaissir la sauce à la consistance désirée.","Éteindre le feu, arroser de 10 g d''huile de sésame, puis servir.","Peler la laitue asperge et la couper en dés de 1 cm de côté, réserver.","Couper les piments Er Jing Tiao en segments de 1 cm.","Désosser la cuisse de poulet avec des ciseaux, attendrir le côté chair avec le dos d''un couteau, couper en lanières puis en dés de 1,5 cm de côté ; les tremper dans de l''eau claire pendant 10 minutes, égoutter et réserver (si vous utilisez une poitrine de poulet, vous pouvez directement la couper en dés et passer aux étapes suivantes).","Mettre la partie verte de l''oignon vert et 5 g de gingembre dans un bol, verser 50 g d''eau bouillante et réserver ; couper la partie blanche de l''oignon en rondelles de 1,5 cm et réserver.","Ajouter 2 g de sel, 5 g de sauce soja foncée, 15 g de vin de cuisine, 15 g de fécule aux dés de poulet, mélanger jusqu''à ce que la préparation soit légèrement sèche ; ajouter lentement une partie de l''eau à l''oignon et au gingembre, mélanger jusqu''à ce que les dés de poulet soient collants ; couvrir d''un film plastique et mettre au réfrigérateur pour mariner 1 heure.","Passer à feu moyen, verser 20 g d''huile végétale, ajouter les cacahuètes crues et les faire sauter jusqu''à ce qu''elles soient légèrement brûlées en surface, retirer les cacahuètes mais laisser l''huile dans la poêle.","Continuer à chauffer, à 70 % de chaleur (les baguettes en bambou font des bulles), ajouter les dés de poulet et la pâte de piment, faire sauter environ 1 minute.","Ajouter les dés de laitue asperge réservés, continuer à faire sauter 1 minute.","Ajouter les rondelles d''oignon et faire sauter, ajouter le reste de l''eau à l''oignon et au gingembre (si moins de 100 g, compléter avec un peu d''eau chaude) ; ajouter les segments de piments Er Jing Tiao ; couvrir, réduire à feu moyen-doux et laisser mijoter 2 minutes.","Passer à feu vif, ajouter les cacahuètes réservées et le poivre de Sichuan ; ajouter 2 g de glutamate monosodique, 5 g de vinaigre parfumé, 2 g de sucre blanc, mélanger.","Mélanger 10 g de fécule avec 50 g d''eau claire pour faire une sauce de liaison, l''ajouter à la poêle, mélanger et épaissir la sauce à la consistance désirée.","Éteindre le feu, arroser de 10 g d''huile de sésame et 5 g d''huile de piment, mélanger 10 secondes, puis servir."]'::jsonb, '["Viande","Cuisine du Sichuan","Épicé","Aigre-doux","Accompagnement de riz","Sauté","Maison"]'::jsonb),
  ('howtocook:meat_dish/小炒肉', 'fr', 'Porc sauté', 'Plats de viande', 'Le porc sauté est un classique épicé de la cuisine du Hunan qui se marie parfaitement avec le riz. Les tranches de poitrine de porc sont croustillantes sans être grasses, sautées avec des piments frais, des haricots noirs fermentés et de la pâte de haricots fermentés pour une sauce riche. Riche en protéines et en graisses de qualité, les piments apportent de la vitamine C, ce qui ouvre l''appétit et réchauffe le corps. La difficulté est moyenne, adapté aux débutants ayant quelques bases ; il faut veiller à la marinade de la viande et à la maîtrise du feu. Du début à la fin, il faut environ 1 heure, dont 30 minutes de marinade et 15 minutes de cuisson.', '[{"name":"poitrine de porc","unit":"g"},{"name":"piment du Sichuan","unit":"pièce"},{"name":"petit piment rouge","unit":"pièce"},{"name":"haricots noirs fermentés","unit":"g"},{"name":"pâte de haricots fermentés épicée","unit":"g"},{"name":"sauce soja foncée","unit":"ml"},{"name":"fécule","unit":"g"},{"name":"sel","unit":"g"},{"name":"oignon vert","unit":"pièce"},{"name":"ail","unit":"gousse"},{"name":"huile de cuisson","unit":"ml"}]'::jsonb, '["Couper la poitrine de porc en tranches.","Mettre la viande dans un récipient, ajouter la fécule, la sauce soja foncée et le sel, mélanger et laisser mariner 30 minutes.","Couper les oignons verts en tronçons.","Couper les piments en diagonale.","Chauffer la poêle, ajouter l''huile.","Quand l''huile est chaude, ajouter la poitrine de porc et faire sauter jusqu''à ce qu''elle change de couleur, puis réserver.","Ajouter l''ail dans la poêle, faire revenir jusqu''à parfumé, ajouter les haricots noirs fermentés, mélanger.","Ajouter la pâte de haricots fermentés épicée et mélanger.","Remettre la poitrine de porc cuite et mélanger.","Ajouter les piments et les oignons verts, faire sauter 40 secondes.","Servir."]'::jsonb, '["Plat de viande","Épicé","Accompagne le riz","Fait maison","Style du Hunan","Sauté","Rapide"]'::jsonb),
  ('howtocook:meat_dish/小炒鸡肝/小炒鸡肝', 'fr', 'Foies de poulet sautés', 'Plats de viande', 'Ce sauté de foies de poulet est parfumé à l''ail, tendre et légèrement grillé au cumin, un plat familial. Les foies de poulet sont riches en fer, vitamine A et protéines de qualité, bénéfiques pour le sang et la vue. La préparation nécessite de maîtriser le blanchiment pour enlever l''odeur, un peu difficile pour les débutants. De la préparation à la cuisson, environ 40 minutes.', '[{"name":"Foies de poulet crus","unit":"pièce"},{"name":"Pousses d''ail","unit":"g"},{"name":"Oignon vert","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Sel de table","unit":"g"},{"name":"Bouillon de poule (glutamate)","unit":"g"},{"name":"Cinq-épices (treize épices)","unit":"g"},{"name":"Poivre","unit":"g"},{"name":"Assaisonnement barbecue ou cumin en poudre","unit":"g"},{"name":"Sésame","unit":"g"},{"name":"Huile de cuisson","unit":"ml"}]'::jsonb, '["Nettoyer les foies de poulet, réserver","Nettoyer les pousses d''ail, couper en tronçons, réserver","Nettoyer l''oignon vert, prendre 100g en tronçons, 50g en tranches, réserver","Nettoyer le gingembre, prendre 70g en tranches, 50g en dés, réserver","Première étape : blanchir","Mettre les foies nettoyés dans une casserole, couvrir d''eau froide, ajouter 100g d''oignon vert en tronçons, 70g de gingembre en tranches et 30ml de vin de cuisine","Chauffer à feu vif, quand l''eau bout réduire à feu moyen, écumer la mousse, attendre 5 à 10 minutes","Éteindre le feu, égoutter, passer sous l''eau froide et nettoyer","Après nettoyage, couper en tranches, réserver","Deuxième étape : sauter","Chauffer à feu moyen. Ajouter 30ml d''huile de cuisson, attendre 10 secondes","Ajouter 50g d''oignon vert en tranches et 50g de gingembre en dés, faire revenir jusqu''à ce que ça sente bon","Ajouter les foies de poulet en tranches, faire sauter jusqu''à ce qu''ils soient légèrement dorés","Ajouter les pousses d''ail, faire sauter 30 secondes, une fois cuites réduire à feu doux","Ajouter les assaisonnements","Sel de table 5g","Bouillon de poule (glutamate) 5g","Cinq-épices (treize épices) 5g","Poivre 5g","Assaisonnement barbecue ou cumin en poudre 10g (facultatif)","Passer à feu vif, faire sauter rapidement 30 secondes pour éviter de brûler, éteindre le feu","Servir dans une assiette, saupoudrer de 5g de sésame en décoration, si vous n''aimez pas ou n''en avez pas, vous pouvez omettre."]'::jsonb, '["Plat de viande","Fait maison","Ail","Cumin","Sauté","Accompagnement riz","Tonifiant pour le sang"]'::jsonb),
  ('howtocook:meat_dish/小炒黄牛肉/小炒黄牛肉', 'fr', 'Sauté de bœuf jaune', 'Plats de viande', 'Ce sauté hunanais, cuit à feu vif, révèle la tendreté du bœuf et le parfum du piment, avec une saveur piquante et vive, et du céleri croquant, typique du Hunan. Le filet de bœuf apporte des protéines de qualité et du fer facilement absorbable, associé au céleri qui ajoute des fibres, pour un équilibre nutritionnel. La préparation et les étapes sont simples, tout le processus se fait à feu vif, idéal pour les débutants, de la coupe à l''assiette en environ une heure.', '[{"name":"filet de bœuf","unit":"g"},{"name":"céleri","unit":"g"},{"name":"piments rouges","unit":"g"},{"name":"piments sauvages","unit":"g"},{"name":"coriandre","unit":"g"},{"name":"huile de cuisson","unit":"ml"},{"name":"sauce soja","unit":"ml"}]'::jsonb, '["Couper le filet de bœuf en fines tranches de 3 cm de large et 3 mm d''épaisseur maximum. Verser 6 ml de sauce soja, mélanger avec les mains et réserver.","Couper le céleri en tronçons de 5 cm maximum. Réserver.","Couper les piments rouges en fines lanières. Réserver.","Couper les piments sauvages en petits morceaux. Réserver.","Couper la coriandre en tronçons de 3 cm maximum. Réserver.","Chauffer la poêle, ajouter 15 ml d''huile de cuisson, attendre 30 secondes à feu vif pour que l''huile chauffe.","Ajouter les piments rouges et les piments sauvages, faire revenir à feu vif jusqu''à ce qu''ils libèrent leur arôme.","Ajouter le filet de bœuf et le céleri, puis faire sauter à feu vif pendant 1 minute.","Éteindre le feu, parsemer de coriandre, et servir dans un plat."]'::jsonb, '["viande","cuisine hunanaise","piquant","sauté à feu vif","accompagnement de riz","familial"]'::jsonb),
  ('howtocook:meat_dish/小米辣炒肉', 'fr', 'Porc sauté aux piments oiseaux', 'Plats de viande', 'Le porc sauté aux piments oiseaux est épicé et addictif, un plat typique du Sud-Ouest de la Chine qui accompagne parfaitement le riz. La tendreté du porc associée au piquant des piments ouvre l''appétit. Le porc est riche en protéines et en lipides, et les piments apportent une bonne dose de vitamine C qui stimule l''appétit. Bien qu''il faille maîtriser la cuisson pour faire revenir et sauter, les étapes sont claires et les débutants peuvent facilement réussir. Le temps de préparation est d''environ 25 minutes. Attention, ce plat est très épicé, il est déconseillé aux personnes qui préfèrent une alimentation douce.', '[{"name":"Piments oiseaux","unit":"pièce(s)"},{"name":"Huile d''arachide","unit":"ml"},{"name":"Poitrine de porc / filet","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sauce huître","unit":"ml"},{"name":"Ail","note":"quantité suffisante"},{"name":"Gingembre","note":"quantité suffisante"},{"name":"Pâte de haricots fermentés (doubanjiang)","unit":"g"},{"name":"Bouillon de poule","unit":"g"},{"name":"Sucre blanc","unit":"g"}]'::jsonb, '["Lavez les piments oiseaux et coupez-les en biais en gros morceaux.","Pour la viande, coupez-la en lanières ou en tranches selon votre préférence, puis mélangez avec les assaisonnements (sauce soja légère, sauce huître, sel) et laissez mariner 5 minutes.","Chauffez l''huile dans une poêle, faites revenir la viande, puis réservez-la.","Faites revenir l''ail et le gingembre jusqu''à ce qu''ils soient parfumés, ajoutez la pâte de haricots fermentés (doubanjiang) et faites sauter, puis ajoutez les piments oiseaux coupés, remettez la viande, faites sauter brièvement et ajoutez un peu de sauce soja légère, de bouillon de poule, de sel et de sucre, puis faites sauter."]'::jsonb, '["Plat de viande","Épicé","Cuisine du Sichuan","Accompagnement de riz","Fait maison","Sauté"]'::jsonb),
  ('howtocook:meat_dish/小酥肉', 'fr', 'Porc frit croustillant', 'Plats de viande', 'Le porc frit croustillant est croustillant à l''extérieur et tendre à l''intérieur, avec un léger picotement du poivre de Sichuan dans la saveur salée. C''est un frit maison que chaque foyer de la région du Sichuan et du Chongqing prépare. Le porc est riche en protéines et en matières grasses, et après friture, il est assez calorique, idéal pour une petite gourmandise occasionnelle. Cette recette comporte plusieurs étapes ; il faut maîtriser la friture initiale pour fixer la forme et la seconde friture pour la coloration, ce qui est un peu difficile pour les débutants. On prévoit environ 1h30 du début à la fin.', '[{"name":"Poitrine de porc sans couenne","unit":"g"},{"name":"Huile végétale","note":"quantité suffisante"},{"name":"Vieux gingembre","unit":"g"},{"name":"Oignon vert","unit":"g"},{"name":"Vin de cuisine","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Mélange d''épices treize parfums","unit":"g"},{"name":"Poivre blanc en poudre","unit":"g"},{"name":"Glutamate monosodique","unit":"g"},{"name":"Poudre de volaille","unit":"g"},{"name":"Poivre de Sichuan concassé","unit":"g"},{"name":"Grains de poivre de Sichuan","unit":"g"},{"name":"Sauce soja légère","unit":"g"},{"name":"Œuf","unit":"pièce"},{"name":"Farine","unit":"g"},{"name":"Fécule de patate douce","unit":"g"}]'::jsonb, '["Couper le vieux gingembre en julienne, ne pas couper les oignons verts.","Selon la formule de calcul, verser le vin de cuisine et l''eau.","Pétrir à la main pendant 5 minutes pour que les arômes du gingembre et de l''oignon se dissolvent bien dans l''eau.","Peler et laver la poitrine de porc.","Couper en lanières de 8 à 10 cm de long et 1,5 cm d''épaisseur.","Selon la formule de calcul ci-dessus, ajouter le sel, le mélange d''épices treize parfums, le poivre blanc en poudre, le glutamate monosodique, la volaille en poudre, le poivre de Sichuan concassé, les grains de poivre de Sichuan et la sauce soja légère.","Verser l''eau de gingembre et d''oignon préparée précédemment.","Mélanger et pétrir soigneusement pendant 10 minutes, jusqu''à ce que la viande absorbe toute l''eau et devienne collante.","Couvrir de film alimentaire et laisser reposer au réfrigérateur pendant 30 minutes.","Verser la farine et la fécule de patate douce dans la viande marinée, ajouter le blanc d''œuf.","Pétrir soigneusement pendant 15 minutes.","Verser de l''huile végétale dans la casserole, ajuster la quantité selon la taille de la casserole, la hauteur d''huile doit être d''au moins 3 cm.","Chauffer à feu vif jusqu''à 150°C, puis passer à feu doux pour maintenir la température.","À l''aide de baguettes, plonger les lanières de viande enrobées dans l''huile, leur donner la forme souhaitée, et frire 3 à 5 minutes pour les fixer. Quand elles sont légèrement jaunes et que la spatule sent qu''elles sont un peu dures, c''est prêt. Le temps exact dépend de la taille des morceaux, de la température de l''huile et de l''enrobage.","Égoutter et déposer sur du papier absorbant.","Monter la température de l''huile à 180°C, y replonger les lanières de viande précuites et frire jusqu''à ce qu''elles soient dorées. Égoutter."]'::jsonb, '["Plat de viande","Salé","Légèrement piquant","Sichuan-Chongqing","Frit","Maison"]'::jsonb),
  ('howtocook:meat_dish/尖叫牛蛙/尖叫牛蛙', 'fr', 'Grenouilles criardes', 'Plats de viande', 'Ce plat est frais et épicé, la chair de grenouille est lisse et élastique, c''est un plat typique de la cuisine sichuanaise. La grenouille elle-même est riche en protéines et pauvre en matières grasses, associée à des ingrédients fermentés comme le gingembre mariné et les piments marinés, ce qui aide à stimuler l''appétit. La méthode est relativement directe, mais il faut faire attention au contrôle de la température de l''huile et aux proportions d''assaisonnement. Généralement, un débutant peut le réaliser en 1 à 2 heures.', '[{"name":"Chair de grenouille","unit":"g"},{"name":"Gingembre mariné","unit":"g"},{"name":"Piments marinés","unit":"g"},{"name":"Piments sauvages","unit":"g"},{"name":"Piments verts et rouges","unit":"g"},{"name":"Ail","unit":"g"},{"name":"Pâte de haricots (Doubanjiang)","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Poivre en poudre","unit":"g"},{"name":"Fécule de maïs","unit":"g"},{"name":"Bière","unit":"ml"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Huile de poivre vert","unit":"ml"},{"name":"Saindoux","unit":"ml"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Oignon vert haché","unit":"g"}]'::jsonb, '["Laver la chair de grenouille et l''égoutter. Ajouter au moins 10 g de sel et 50 ml de bière, pétrir à la main pendant 5 minutes pour éliminer l''odeur de la grenouille.","Rincer ensuite sous l''eau courante jusqu''à ce qu''il n''y ait plus de sang ni d''impuretés, égoutter et placer dans un récipient approprié pour la marinade.","Ajouter 5 g de sel, 30 g de fécule de maïs, 10 ml de vin de cuisine, 5 g de poivre en poudre, mélanger uniformément à la main et laisser mariner 5 à 10 minutes.","Couper le gingembre mariné, les piments marinés et les piments sauvages en lanières ou en rondelles (selon vos compétences au couteau), couper les piments verts et rouges en anneaux, éplucher l''ail.","Chauffer la poêle et ajouter 200 ml d''huile de cuisson (si le fond de la poêle est très plat, ajouter 100 ml supplémentaires). Chauffer jusqu''à 60 % de la température (apparition de petites bulles). Verser la grenouille marinée, faire frire rapidement dans l''huile, retirer après 10 secondes (ne pas dépasser ce temps, sinon la chair deviendra dure).","Retirer la chair de grenouille, égoutter l''huile. Verser l''huile chaude de la poêle dans un bol, conserver 30 ml. Ajouter 20 ml de saindoux (sinon, conserver un total de 50 ml d''huile de cuisson dans la poêle).","Lorsque l''huile est à 60 % de chaleur, ajouter le gingembre mariné, les piments marinés, les piments sauvages et l''ail, faire revenir jusqu''à ce que les arômes se dégagent. Ajouter 20 g de pâte de haricots, faire sauter à feu moyen jusqu''à ce que l''huile devienne rouge (environ 30 secondes). Verser 400 ml de bière.","Ajouter ensuite la chair de grenouille frite. Remuer doucement avec une cuillère, ne pas mélanger vigoureusement. Ajouter 5 g de poivre en poudre, ajouter 5 ml d''huile de poivre vert. Laisser mijoter à feu moyen pendant 3 minutes.","Augmenter le feu, faire réduire la sauce à feu vif pendant une demi-minute. Ajouter les anneaux de piments verts et rouges, cuire encore 10 secondes avant de retirer du feu.","Verser dans un plat, saupoudrer d''oignon vert haché, et déguster !"]'::jsonb, '["Plat de viande","Frais et épicé","Sichuanais","Accompagne le riz","Fait maison","Appétissant"]'::jsonb),
  ('howtocook:meat_dish/尖椒炒牛肉', 'fr', 'Bœuf sauté aux piments verts', 'Plats de viande', 'Un plat sauté maison, salé et légèrement épicé, le bœuf est tendre et savoureux, les piments verts sont croquants et rafraîchissants. Le bœuf fournit des protéines de qualité et du fer, les piments verts sont riches en vitamine C, l''association est équilibrée nutritionnellement. Bien que la marinade demande un peu de patience, les étapes sont claires, même les débutants peuvent le réussir, difficulté modérée. De la préparation à la sortie du feu, il faut environ 1 heure.', '[{"name":"bœuf","unit":"g"},{"name":"ciboule","unit":"pièce"},{"name":"gingembre","unit":"pièce"},{"name":"ail","note":"au goût"},{"name":"piments verts","note":"au goût"},{"name":"sauce soja","unit":"ml"},{"name":"sel","unit":"g"},{"name":"sucre","unit":"g"}]'::jsonb, '["Hacher l''ail en purée","Couper la ciboule en tronçons","Couper le gingembre en tranches","Couper les piments verts en tronçons","Mettre le bœuf dans un bol","Ajouter le gingembre, le sel, la sauce soja et le sucre pour mariner 30 à 40 minutes","Après la marinade, le gingembre peut être retiré","Mettre l''huile froide dans la poêle, attendre qu''elle chauffe jusqu''à quelques bulles","Ajouter la purée d''ail","Lorsque la purée d''ail devient dorée, ajouter les piments verts","Lorsque la peau des piments est légèrement ridée, ajouter le bœuf mariné et faire sauter","Avant que le bœuf ne soit complètement cuit, ajouter la ciboule et continuer à faire sauter","Faire sauter jusqu''à ce que le bœuf soit cuit, puis éteindre le feu et servir"]'::jsonb, '["Plat de viande","Salé","Légèrement épicé","Sauté","Maison","Accompagnement de riz"]'::jsonb),
  ('howtocook:meat_dish/山西过油肉', 'fr', 'Porc sauté du Shanxi', 'Plats de viande', 'Le porc sauté du Shanxi est un plat traditionnel de la région. Les tranches de porc sont tendres, les tiges d''ail croquantes, avec une saveur salée, légèrement acidulée et un arôme de vinaigre vieilli. C''est un plat familial typique. Le filet de porc fournit des protéines de qualité, accompagné de champignons noirs, de tiges d''ail et d''oignons, pour un équilibre nutritionnel. Ce plat demande une certaine maîtrise du feu et de la technique d''enrobage, il convient mieux aux cuisiniers amateurs ayant un peu d''expérience. De la préparation à la fin, cela prend environ 40 minutes.', '[{"name":"filet de porc","unit":"g"},{"name":"tiges d''ail","unit":"tige"},{"name":"sel","unit":"g"},{"name":"sauce soja claire","unit":"ml"},{"name":"oignon, gingembre, ail","unit":"g"},{"name":"œuf","unit":"pièce"},{"name":"fécule","unit":"g"},{"name":"huile de cuisson","unit":"ml"},{"name":"champignons noirs","unit":"g"},{"name":"oignon","unit":"g"},{"name":"vin de cuisine","note":"quantité suffisante"},{"name":"vinaigre de Shanxi","unit":"ml"},{"name":"poudre de poivre du Sichuan","note":"quantité suffisante"},{"name":"bouillon de poule en poudre","note":"quantité suffisante"}]'::jsonb, '["Faire tremper les champignons noirs à l''avance, si pressé, utiliser de l''eau chaude.","Couper le filet de porc en tranches et les mettre dans un bol. Ajouter 20 ml de sauce soja claire, du vin de cuisine, de la poudre de poivre du Sichuan, casser un œuf, mélanger avec les mains. Ajouter de la fécule (de préférence de patate douce) et bien mélanger. Verser 300 ml d''huile de cuisson pour couvrir, laisser mariner 15 minutes.","Couper les tiges d''ail en tronçons d''environ 3 cm, couper l''oignon en losanges et réserver.","Chauffer une bonne quantité d''huile dans un wok. À 50 % de chaleur, ajouter les tranches de porc marinées, les séparer, les retirer et égoutter.","Vider l''excédent d''huile du wok, ne laisser que 10 ml pour la cuisson. Chauffer à 70 % de chaleur.","Ajouter l''oignon, le gingembre et l''ail et faire revenir jusqu''à ce qu''ils soient parfumés. Ajouter d''abord les tiges d''ail et cuire jusqu''à ce qu''elles soient tendres mais encore croquantes, puis ajouter les champignons noirs et l''oignon. Ajouter la sauce soja claire et la poudre de poivre du Sichuan, remuer quelques fois, puis ajouter les tranches de porc frites et mélanger.","Ajouter 10 g de sel, avant de retirer du feu ajouter 10 ml de vinaigre de Shanxi et du bouillon de poule en poudre, puis servir."]'::jsonb, '["Viande","Cuisine du Shanxi","Familial","Accompagnement du riz","Savoureux","Sauté onctueux","Salé et légèrement acidulé"]'::jsonb),
  ('howtocook:meat_dish/巴基斯坦牛肉咖喱/巴基斯坦牛肉咖喱', 'fr', 'Cari de boeuf pakistanais', 'Plats de viande', 'Ce cari de bœuf pakistanais est parfumé et tendre, acidulé et épicé, avec un arôme riche d''épices. Le bœuf fournit des protéines de qualité, associé à la tomate et au yaourt, pour un équilibre nutritionnel. La recette n''est pas compliquée, mais la cuisson lente demande un peu de patience, parfaite pour un week-end tranquille. De bout en bout, environ deux heures et demie, vous obtiendrez un plat chaud et exotique.', '[{"name":"Bœuf","unit":"kg"},{"name":"Tomates","unit":"pièces"},{"name":"Piments vis","unit":"pièces"},{"name":"Yaourt nature","unit":"pot"},{"name":"Poudre de Masala (marque Shan optionnelle)","unit":"g"},{"name":"Ail en poudre","unit":"g"},{"name":"Gingembre en poudre","unit":"g"},{"name":"Huile","note":"Quantité suffisante"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Coupez tous les piments vis en sections, réservez.","Mixez toutes les tomates en purée, réservez.","Coupez le bœuf en morceaux de 2 cm, lavez et réservez.","Versez une couche d''huile dans la poêle (pour empêcher la purée de tomate de bouillir et de s''évaporer).","Ajoutez la purée de tomate, remuez continuellement pendant 2-3 minutes, jusqu''à ce qu''elle devienne plus rouge.","Ajoutez 5 g d''ail en poudre, 5 g de gingembre en poudre et 1 sachet de 50 g de poudre de Masala, mélangez bien.","Ajoutez le bœuf et les morceaux de piment vis, mélangez bien.","Ajoutez 1 pot de yaourt (pour épaissir la sauce), mélangez bien.","Transférez le tout dans un autocuiseur/ mijoteuse, ajoutez 250 ml d''eau, lancez le mode cuisson lente/ mijotage, réglez sur 2-3 heures.","Attendez la fin, ouvrez et vérifiez que le bœuf est tendre, puis servez."]'::jsonb, '["Plat de viande","Épicé","Mijoté","Pakistanais","Accompagnement de riz","Week-end"]'::jsonb),
  ('howtocook:meat_dish/带把肘子', 'fr', 'Jambonneau à l''anse', 'Plats de viande', 'Le jambonneau à l''anse est un plat traditionnel de Dali, au Shaanxi, nommé ainsi car la forme du pied ressemble à une poignée. Une fois cuit, la peau devient collante et moelleuse, la chair est tendre et fondante sans être grasse. On le déguste trempé dans la sauce de soja sucrée accompagné de morceaux de ciboule, pour une saveur salée et riche. Riche en collagène et en protéines de haute qualité, il est nourrissant et bon pour la peau. La préparation nécessite de désosser, de donner une forme, et de cuire à la vapeur longuement, ce qui représente un défi pour les débutants. Le processus total prend environ 3,5 heures.', '[{"name":"Jambonneau de porc avec patte","unit":"g"},{"name":"Pâte de soja rouge","unit":"g"},{"name":"Sauce de soja sucrée (tianmianjiang)","unit":"g"},{"name":"Sel fin","unit":"g"},{"name":"Sauce soja rouge","unit":"g"},{"name":"Sauce soja blanche","unit":"g"},{"name":"Vin de cuisson","unit":"g"},{"name":"Ail en tranches","unit":"g"},{"name":"Gingembre haché","unit":"g"},{"name":"Étoile de badiane","unit":"pièce(s)"},{"name":"Cannelle","unit":"g"},{"name":"Ciboule","unit":"g"}]'::jsonb, '["Nettoyez soigneusement le jambonneau en le grattant. Placez-le sur la planche à découper, la tête du jambonneau vers l''extérieur, l''anse (le pied) vers l''intérieur, et la peau vers le bas.","À l''aide d''un couteau, fendez la peau au milieu depuis la tête du jambonneau jusqu''à l''anse le long de l''os de la jambe. Détachez la chair des deux côtés de l''os (trois côtés séparés), en laissant l''os attaché à la chair par le bas, de sorte que l''os soit exposé. Ensuite, cassez les deux sections de l''os de la jambe au milieu avec le dos du couteau (ou mieux, avec une hache).","Plongez le jambonneau dans une casserole d''eau bouillante et faites-le cuire jusqu''à ce qu''il soit cuit à 70% (aspect normal, intérieur rose clair). Retirez-le, essuyez-le avec un torchon propre, et badigeonnez la peau de sauce soja rouge pendant qu''il est encore chaud.","Prenez un cuit-vapeur. Placez l''étoile de badiane et la cannelle au fond. Commencez par casser l''articulation de l''anse avec les mains sans abîmer la peau, puis disposez le jambonneau dans le cuit-vapeur, peau vers le bas. En l''installant, selon la taille du jambonneau, faites en sorte que l''anse touche le bord du cuit-vapeur en le repliant pour lui donner une forme ronde.","Saupoudrez de sel fin. Couvrez la viande d''une étamine propre et stérilisée. Étalez sur l''étamine la sauce de soja sucrée (50 g), la ciboule (75 g), la pâte de soja rouge, la sauce soja rouge, la sauce soja blanche, le gingembre et l''ail. Faites cuire à la vapeur à feu vif pendant environ trois heures (jusqu''à ce que ce soit bien tendre).","Sortez-le du cuit-vapeur, retirez l''étamine, démoulez dans un plat, enlevez l''étoile de badiane. Servez avec des morceaux de ciboule et une petite coupelle de sauce de soja sucrée (ou bien, étalez la sauce de soja sucrée sur le jambonneau et servez avec une coupelle de ciboule)."]'::jsonb, '["Plat de viande","Salé et parfumé","Vapeur","Shaanxi","Dali","Pour recevoir"]'::jsonb),
  ('howtocook:meat_dish/干煸仔鸡/干煸仔鸡', 'fr', 'Poulet sauté façon Sichuan', 'Plats de viande', 'Ce plat est une création sichuanaise innovante, originaire de la cantine de l''Université de Pékin. Il allie le sucré et l''épicé. Le poulet est d''abord mariné puis frit, croustillant à l''extérieur et tendre à l''intérieur. Les pommes de terre sont moelleuses et parfumées, les poivrons verts croquants. Le tout est enrobé d''une sauce rouge et brillante, sucrée-salée et légèrement épicée, très appétissante. Riche en protéines, glucides et vitamines. La cuisson implique friture et préparation de sauce, ce qui peut être un défi pour les débutants, mais en suivant les étapes, on réussit facilement. Le processus prend environ 1 heure.', '[{"name":"Cuisses de poulet","unit":"g"},{"name":"Pommes de terre","unit":"g"},{"name":"Poivrons verts","unit":"g"},{"name":"Gousses d''ail","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Assaisonnement au poulet","unit":"g"},{"name":"Poivre moulu","unit":"g"},{"name":"Sauce soja claire","unit":"g"},{"name":"Sauce soja foncée","unit":"g"},{"name":"Vin de cuisson","unit":"g"},{"name":"Fécule de maïs","unit":"g"},{"name":"Pâte de fèves épicée à l''huile rouge (doubanjiang)","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Poivre du Sichuan moulu","unit":"g"},{"name":"Eau","unit":"ml"},{"name":"Huile de cuisson","unit":"ml"}]'::jsonb, '["Désossez les cuisses de poulet (ignorez cette étape si vous utilisez des filets de cuisse). Tapotez la chair des cuisses avec le dos d''un couteau, puis coupez-la en morceaux de 2 cm.","Dans la chair de poulet, ajoutez du sel, de l''assaisonnement au poulet (facultatif), du poivre moulu, de la sauce soja claire, de la sauce soja foncée et du vin de cuisson. Mélangez jusqu''à ce que la préparation colle aux mains, puis incorporez la fécule de maïs. Ajoutez un peu d''huile de cuisson pour éviter que les morceaux ne collent entre eux. Laissez mariner 30 minutes.","Épluchez les pommes de terre et coupez-les en morceaux de 2 cm. Faites-les bouillir dans de l''eau pendant 5 minutes, puis égouttez-les bien pour éviter les éclaboussures lors de la friture.","Épépinez les poivrons verts et coupez-les en petits morceaux de 2 cm. Réservez-les dans une passoire.","Versez une grande quantité d''huile dans une casserole (suffisamment pour immerger les ingrédients). Chauffez l''huile à 180°C, puis faites frire les morceaux de pommes de terre pendant 3 minutes. Égouttez-les.","Lorsque l''huile atteint à nouveau 180°C, faites frire les morceaux de poulet pendant 2 minutes. Égouttez-les.","Lorsque l''huile atteint à nouveau 180°C, faites frire les morceaux de poulet une seconde fois pendant 1 minute. Égouttez-les.","Lorsque l''huile atteint à nouveau 180°C, faites frire les morceaux de pommes de terre une seconde fois pendant 1 minute. Versez l''huile et les pommes de terre à travers une passoire sur les poivrons verts pour les blanchir rapidement.","Ajoutez 5 ml d''huile de cuisson dans la casserole. Faites revenir les gousses d''ail à feu doux jusqu''à ce qu''elles soient dorées. Ajoutez la pâte de fèves épicée (doubanjiang à l''huile rouge) et faites-la revenir jusqu''à ce qu''elle dégage son arôme. Ajoutez le sucre et faites-le fondre. Ajoutez le poivre du Sichuan moulu. Versez 40 ml d''eau claire et remuez constamment jusqu''à ce que la sauce épaississe.","Ajoutez le poulet frit, les pommes de terre frites et les morceaux de poivron. Mélangez bien, puis retirez du feu et servez."]'::jsonb, '["Viande","Sucré-épicé","Cuisine sichuanaise","Friture","Accompagne le riz","Plat familial","Pour les invités"]'::jsonb),
  ('howtocook:meat_dish/乡村啤酒鸭', 'fr', 'Canard à la bière campagnard', 'Plats de viande', 'Le canard est mijoté avec de la bière, le bouillon est riche, la viande est tendre et savoureuse, avec un léger arôme de bière. C''est un plat familial unique. Le canard est nutritif, riche en protéines, vitamines B et divers minéraux. Il est plus savoureux après avoir été mijoté avec de la bière. Bien que les étapes soient nombreuses, la préparation n''est pas compliquée. Un débutant peut le réaliser en environ 1 heure.', '[{"name":"Canard","unit":"kg"},{"name":"Bière","unit":"ml"},{"name":"Poivron vert","unit":"pièce"},{"name":"Poivron rouge","unit":"pièce"},{"name":"Ail","unit":"gousse"},{"name":"Gingembre","unit":"cm"},{"name":"Piment oiseau","unit":"pièce"},{"name":"Ciboule","unit":"tige"},{"name":"Poireau","unit":"tige"},{"name":"Cardamome noire","unit":"pièce"},{"name":"Cannelle","unit":"cm"},{"name":"Anis étoilé","unit":"pièce"},{"name":"Feuille de laurier","unit":"feuille"},{"name":"Piment séché","unit":"pièce"},{"name":"Vin de cuisson","unit":"ml"},{"name":"Poivre du Sichuan","unit":"grain"},{"name":"Huile d''arachide","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"}]'::jsonb, '["Rincer le canard une fois et le mettre dans la casserole","Ajouter de l''eau pour couvrir le canard","Ajouter 20 ml de vin de cuisson","Ajouter 1 poireau réservé","Ajouter 2 cm de gingembre écrasé","Porter à ébullition","Écumer les impuretés","Retirer le canard, le rincer à l''eau claire et réserver","Nettoyer la casserole, chauffer et ajouter 60 ml d''huile d''arachide","Lorsque l''huile est à 60 °C, ajouter une poignée de poivre du Sichuan (30 grains)","Ajouter le canard et faire sauter pendant 4 minutes","Après 2 minutes, ajouter toutes les épices","À 3 minutes, ajouter tous les aromates (gingembre, ail, piment oiseau)","Ajouter 1000 ml de bière","Cuire le canard 30 minutes","À 10 minutes, ajouter 3 g de sel, 10 ml de sauce soja claire, 5 ml de sauce soja foncée","À 20 minutes, ajouter tous les légumes d''accompagnement (morceaux de poivron vert et rouge)","À 29 minutes, ajouter les tronçons de ciboule et les tronçons de poireau","Faire sauter 1 minute","Servir"]'::jsonb, '["Plat de viande","Savoureux","Mijoté","Familial","Accompagne le riz","Légèrement épicé"]'::jsonb),
  ('howtocook:meat_dish/广式萝卜牛腩/广式萝卜牛腩', 'fr', 'Bœuf braisé au radis blanc (façon cantonaise)', 'Plats de viande', 'C''est un plat mijoté familial cantonais. Le bœuf est tendre et savoureux, le radis blanc absorbe le bouillon pour devenir doux et parfumé, l''ensemble a un goût de sauce umami et sucré. Riche en protéines de qualité et en fibres, il ouvre l''appétit et facilite la digestion. Les étapes sont un peu nombreuses mais de difficulté modérée, même un débutant peut réussir en suivant les instructions. Il faut compter environ 2,5 heures du début à la fin.', '[{"name":"Poitrine de bœuf","unit":"g"},{"name":"Radis blanc","unit":"pièce"},{"name":"Gingembre","unit":"tranche"},{"name":"Ail","unit":"gousse"},{"name":"Ciboule","note":"une poignée"},{"name":"Anis étoilé","unit":"pièce"},{"name":"Cannelle","unit":"petit morceau"},{"name":"Piment séché","unit":"pièce"},{"name":"Feuille de laurier","unit":"feuille"},{"name":"Fromage de haricots fermentés (nam yue)","unit":"pièce"},{"name":"Pâte de soja cantonaise (zhuhou)","unit":"g"},{"name":"Sauce d''huître","unit":"g"},{"name":"Sauce soja","unit":"g"},{"name":"Sucre candi","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Sauce soja foncée","unit":"g"}]'::jsonb, '["Couper le radis blanc en gros morceaux et réserver.","Blanchir le bœuf entier dans l''eau bouillante avec 2 tranches de gingembre et une poignée de nœuds de ciboule. Après ébullition, cuire 5 à 10 minutes, puis égoutter et couper en morceaux.","Couper le bœuf en morceaux de la taille désirée (après blanchiment, il ne rétrécira pas beaucoup lors du braisage ; les gros morceaux nécessitent un temps de cuisson plus long).","Préparer la sauce pour le braisage : mélanger le fromage de haricots fermentés (nam yue), la pâte de soja (zhuhou), la sauce soja, la sauce d''huître, le sucre et le sel selon les quantités indiquées (remplacer le sucre candi par du sucre blanc si nécessaire).","Chauffer l''huile dans une poêle, faire revenir le gingembre et l''ail. Ajouter le bœuf et faire sauter jusqu''à ce qu''il soit sec. Incorporer la sauce préparée et faire revenir pour libérer les arômes. Si vous préférez une couleur plus foncée, ajouter un peu de sauce soja foncée.","Une fois les assaisonnements bien mélangés, verser de l''eau chaude.","Transférer le bœuf dans une marmite, ajouter la cannelle, l''anis étoilé, les feuilles de laurier et les piments séchés. Laisser mijoter environ 2 heures.","Lorsque le bœuf est à moitié tendre, ajouter le radis blanc et continuer à mijoter 30 minutes.","Lorsque le radis est tendre, c''est prêt. Un délicieux bœuf braisé au radis blanc est terminé."]'::jsonb, '["Plat de viande","Cantonais","Braisé","Sauce parfumée","Accompagnement de riz","Familial","Pour invités"]'::jsonb),
  ('howtocook:meat_dish/徽派红烧肉/徽派红烧肉', 'fr', 'Porc braisé à la mode de Huizhou', 'Plats de viande', 'Le porc braisé à la mode de Huizhou est un plat familial classique, rouge et brillant, gras mais pas huileux, avec une texture moelleuse et élastique, et une saveur sucrée-salée. À base de poitrine de porc, riche en protéines de qualité et en matières grasses, il fournit une énergie abondante. La cuisson nécessite de maîtriser le caramélisation du sucre et le feu, un peu de défi, temps de préparation estimé à environ 45 minutes.', '[{"name":"Poitrine de porc","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Huile de cuisson","unit":"g"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sauce d''huître","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Tranches de gingembre","unit":"tranche"},{"name":"Gousses d''ail","unit":"gousse"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Oignon vert","unit":"brin"},{"name":"Cinq-épices","unit":"g"},{"name":"Sel","unit":"g"}]'::jsonb, '["Couper la poitrine de porc en morceaux de 2-3 cm de côté","Ajouter 150 ml d''huile de cuisson dans la poêle, y mettre la poitrine de porc, faire frire 2 minutes, puis ajouter du sel, remuer la poitrine de porc, retirer après 2 minutes","Ajouter 50 ml d''huile de cuisson dans la poêle, verser le sucre blanc, remuer jusqu''à ce qu''il devienne brun café","Ajouter la poitrine de porc, remuer 30 secondes, ajouter les tranches de gingembre et les gousses d''ail, remuer encore 30 secondes","Ajouter le vin de cuisine, les cinq-épices et l''oignon vert, ajouter de l''eau pour couvrir la poitrine de porc, couvrir et cuire 10 minutes","Ajouter la sauce soja légère, la sauce soja foncée et la sauce d''huître, cuire à feu moyen 20 minutes","Découvrir, réduire la sauce à feu vif, servir dans un plat"]'::jsonb, '["Viande","Salé-sucré","Braisé","Style Huizhou","Accompagnement de riz","Cuisine familiale"]'::jsonb),
  ('howtocook:meat_dish/意式烤鸡', 'fr', 'Poulet rôti à l''italienne', 'Plats de viande', 'Le poulet rôti à l''italienne est un plat familial au four aux saveurs méditerranéennes. Les cuisses de poulet sont marinées avec de l''ail et de l''huile d''olive, puis rôties jusqu''à ce que la peau soit légèrement croustillante et l''intérieur juteux. Servi avec du jus de citron et du persil, il est frais et léger. Le poulet est riche en protéines de haute qualité, et l''huile d''olive apporte des acides gras insaturés, pour un équilibre nutritionnel. La difficulté est modérée ; il faut préchauffer le four à l''avance. Même les débutants peuvent suivre les étapes, le tout prenant environ 50 minutes de la marinade à la sortie du four.', '[{"name":"Cuisses de poulet","unit":"pièce"},{"name":"Sel","unit":"g"},{"name":"Poivre noir","unit":"g"},{"name":"Huile d''olive","unit":"ml"},{"name":"Ail","unit":"gousse"},{"name":"Jus de citron","unit":"ml"},{"name":"Persil","unit":"branche"}]'::jsonb, '["Badigeonner les cuisses de poulet de sel, de poivre noir, d''huile d''olive et d''ail haché.","Placer dans un four préchauffé à 180 °C et cuire 30 à 40 minutes ou jusqu''à cuisson complète.","Hacher le persil finement et réserver.","Presser le citron pour en extraire le jus et réserver.","Sortir le poulet cuit du four et arroser de jus de citron.","Saupoudrer de persil haché et servir."]'::jsonb, '["Plat de viande","Italien","Rôti","Méditerranéen","Frais","Familial"]'::jsonb),
  ('howtocook:meat_dish/新疆大盘鸡/新疆大盘鸡', 'fr', 'Poulet du Xinjiang en grand plat', 'Plats de viande', 'Le poulet du Xinjiang en grand plat est un plat familial du Xinjiang riche en saveurs et coloré. Le poulet est tendre et moelleux, les pommes de terre sont fondantes et imprégnées de sauce, avec un goût épicé et piquant et une légère douceur en fin de bouche. Riche en protéines de haute qualité et en glucides, accompagné de poivrons, il apporte également de la vitamine C. La préparation nécessite de caraméliser le sucre et de maîtriser la réduction de la sauce, ce qui peut être un défi pour les débutants, mais en suivant les étapes avec soin, ce n''est pas difficile. L''ensemble prend environ 1 heure.', '[{"name":"Poulet (de préférence des cuisses)","unit":"kg"},{"name":"Pommes de terre","unit":"g"},{"name":"Oignon vert","unit":"g"},{"name":"Poivron vert (optionnel)","unit":"g"},{"name":"Poivron rouge (optionnel)","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Piment séché","unit":"pièce"},{"name":"Ail","unit":"gousse"},{"name":"Huile","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Sauce d''huître","unit":"g"},{"name":"Vin de cuisine (ou bière)","unit":"ml"},{"name":"Eau claire","unit":"L"},{"name":"Poivre du Sichuan","note":"selon votre goût"},{"name":"Feuilles de laurier","note":"selon votre goût"},{"name":"Cardamome","note":"selon votre goût"}]'::jsonb, '["Couper la viande en morceaux. Les faire tremper dans de l''eau additionnée de sel pendant 5 minutes pour éliminer le sang et les odeurs. Puis égoutter.","Laver l''oignon vert, l''ail, les piments, les pommes de terre, etc. Éplucher les pommes de terre.","Couper la partie blanche de l''oignon vert en tronçons de 4 cm. Couper le poivron vert et le piment vert en morceaux.","Couper les pommes de terre en morceaux irréguliers (roulés), en les tournant à chaque coupe, d''environ 4 cm de côté.","Caraméliser le sucre : chauffer l''huile dans la poêle, ajouter le sucre blanc et remuer avec une spatule jusqu''à ce qu''il fonde et prenne une couleur dorée. Ajouter alors le poulet égoutté et le faire sauter pour le colorer.","Ajouter les grains de poivre du Sichuan, les feuilles de laurier, la cardamome et les piments séchés. Faire sauter.","Ajouter 5 g de sel, 7 ml de sauce soja claire, 10 g de sauce d''huître, 100 ml de vin de cuisine (ou de bière). Verser 1 litre d''eau claire.","Passer à feu moyen, porter à ébullition, puis réduire à feu doux et laisser mijoter pour imprégner les saveurs.","Lorsque le liquide a réduit et que le poulet commence à apparaître, déposer les pommes de terre sur le dessus (ne pas les remuer, sinon elles colleront au fond). Couvrir et continuer la cuisson. Après un moment, ajouter les oignons verts, le poivron vert et le poivron rouge. Continuer à mijoter.","Lorsque la sauce est presque réduite, retourner les pommes de terre pour qu''elles absorbent la sauce. Éteindre le feu et servir."]'::jsonb, '["Plat de viande","Épicé et piquant","Accompagne le riz","Xinjiang","Mijoté","Familial"]'::jsonb),
  ('howtocook:meat_dish/无骨鸡爪/无骨鸡爪', 'fr', 'Pattes de poulet désossées', 'Plats de viande', 'Aigre-douce et épicée, la texture est élastique et ferme, c''est une entrée froide maison. Les pattes de poulet sont riches en collagène, bonnes pour la peau. Le désossage est fastidieux et laborieux, la préparation est assez difficile, pas vraiment adaptée aux débutants. Le temps total est d''environ 8 heures et 15 minutes.', '[{"name":"pattes de poulet","unit":"kg"},{"name":"gingembre","unit":"tranche"},{"name":"vin de cuisson","unit":"g"},{"name":"oignon vert","unit":"morceau"},{"name":"ail","unit":"gousse"},{"name":"piment rouge","unit":"pièce"},{"name":"oignon","unit":"pièce"},{"name":"sauce soja claire","unit":"g"},{"name":"sauce d''huître","unit":"g"},{"name":"vinaigre noir (vinaigre vieilli recommandé)","unit":"g"},{"name":"sucre blanc","unit":"g"},{"name":"sel","unit":"g"},{"name":"huile de poivre du Sichuan","unit":"ml"},{"name":"coriandre","unit":"botte"},{"name":"citron","unit":"pièce"}]'::jsonb, '["Avec des ciseaux ou un couteau, coupez toutes les griffes des pattes de poulet, y compris la chair et les os sous les griffes, de sorte qu''il ne reste aucune griffe.","Lavez-les à l''eau, mettez de côté.","Mettez les pattes de poulet dans une grande marmite, préparez-vous à enlever l''odeur de gibier.","Ajoutez l''oignon vert, le vin de cuisson et le gingembre.","Ajoutez de l''eau pour couvrir les pattes de poulet.","Portez à ébullition à feu vif. En cours de route, vous pouvez écumer la mousse.","Quand l''eau bout à 100°C, après l''ébullition, attendez 10 minutes.","Éteignez le feu, sortez-les, égouttez, lavez, mettez dans un bol.","Mettez au congélateur pendant 20 minutes.","Mettez le tout dans le réfrigérateur (pas le congélateur), puis sortez par lots de 10 pour désosser.","En commençant par l''extrémité des doigts (des pattes), coupez chaque doigt avec un couteau jusqu''au dos de la patte.","Ensuite, à partir du dos de la patte, coupez jusqu''au bras entier.","Pliez chaque articulation des doigts jusqu''à ce qu''ils craquent.","Appuyez sur l''extrémité du doigt et poussez vers l''intérieur, faites de même pour chaque doigt, poussez d''abord vers la paume et le dos de la main.","Une fois la peau de chaque doigt détachée, poussez de la paume vers le bras jusqu''à ce que tout soit désossé.","Mettez dans un bol, réservez.","Coupez les piments rouges en petits morceaux uniformes.","Hachez l''ail, l''oignon et la coriandre.","Coupez le citron en deux, pressez le jus dans le récipient des pattes de poulet.","Versez tous les assaisonnements dans le récipient avec les pattes de poulet, ajoutez aussi les piments, l''ail, l''oignon et la coriandre.","Mélangez bien avec les mains.","Mettez au réfrigérateur pour une nuit (6 heures).","Une fois l''assaisonnement prêt, mettez tout sur les pattes de poulet préparées."]'::jsonb, '["Plat de viande","Aigre-doux et épicé","Froid","Appétissant","À servir avec de l''alcool","Cuisine maison"]'::jsonb),
  ('howtocook:meat_dish/杀猪菜', 'fr', 'Ragoût de chou aigre au porc', 'Plats de viande', 'Ce ragoût classique du Nord-Est de la Chine est aigre et savoureux, réconfortant pour le corps et l''esprit. Le chou aigre est riche en probiotiques et en fibres, les travers de porc apportent des protéines de qualité et du calcium, tandis que le boudin fournit du fer. La préparation demande de la patience avec le boudin pour éviter qu''il n''éclate, ce qui peut être un défi pour les débutants. De la préparation à la mise en plat, comptez environ une heure.', '[{"name":"Boudin","unit":"g"},{"name":"Chou aigre","unit":"g"},{"name":"Travers de porc","unit":"g"},{"name":"Vin de cuisson","unit":"g"},{"name":"Gousses d''ail","unit":"pièce"},{"name":"Gingembre en poudre","unit":"g"},{"name":"Piments séchés","unit":"pièce"},{"name":"Feuilles de laurier","unit":"pièce"},{"name":"Badiane","unit":"pièce"},{"name":"Faisceau de ciboule","unit":"pièce"},{"name":"Huile de sésame","unit":"g"},{"name":"Huile de colza","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Baies de goji","note":"au goût"},{"name":"Huile pimentée","unit":"g"},{"name":"Sauce soja claire","unit":"g"},{"name":"Ail haché","unit":"g"},{"name":"Huile de sésame","unit":"g"}]'::jsonb, '["Piquez le boudin à plusieurs endroits avec un cure-dent, puis faites-le cuire dans de l''eau à feu doux pendant dix minutes, sans laisser bouillir (maintenez à 80°C), sinon le boudin risque d''éclater.","Coupez le boudin cuit en morceaux et réservez.","Blanchissez les travers de porc avec du vin de cuisson, égouttez et réservez.","Dans une casserole, mettez de l''huile de colza et faites revenir les gousses d''ail, les piments séchés et le gingembre en poudre.","Ajoutez les travers de porc et faites-les sauter jusqu''à ce qu''ils soient dorés.","Lavez le chou aigre, essorez-le, ajoutez-le dans la casserole avec de l''huile de sésame et faites sauter à feu vif pendant deux minutes. L''huile de sésame aide à éliminer l''acidité et rend le chou plus parfumé.","Ajoutez 600 ml d''eau chaude.","Transférez dans un autocuiseur électrique, ajoutez les feuilles de laurier, la badiane, le faisceau de ciboule et le sel.","Faites cuire sous pression en mode ''riche'' pendant 40 minutes.","Une fois le temps écoulé, relâchez la pression et ouvrez le couvercle. Ajoutez le boudin et les baies de goji, couvrez et laissez reposer deux minutes – le boudin est déjà cuit et n''a pas besoin de plus de cuisson.","Versez dans un bol, préparez la sauce d''accompagnement selon le tableau ci-dessus, et dégustez."]'::jsonb, '["Plat de viande","Nord-Est","Ragoût","Aigre et piquant","Savoureux","Accompagne bien le riz"]'::jsonb),
  ('howtocook:meat_dish/枝竹羊腩煲/枝竹羊腩煲', 'fr', 'Ragoût d''agneau et bâtonnets de tofu séché', 'Plats de viande', 'C''est un plat traditionnel cantonais en potée, où l''agneau et les bâtonnets de tofu sont mijotés avec de la sauce Chu Hou et du fromage de soja fermenté, offrant une sauce riche et savoureuse, une texture grasse mais non grasse, réchauffant le corps et l''âme, particulièrement adapté aux froids hivernaux. L''agneau est riche en protéines et en fer, tonifie le qi et le sang, tandis que les bâtonnets de tofu fournissent des protéines végétales de qualité, pour un équilibre nutritionnel. Bien que la préparation et la cuisson soient nombreuses, le contrôle de la température n''est pas compliqué, et les débutants peuvent réussir en suivant les étapes. Comptez environ deux heures et demie de la préparation à la cuisson.', '[{"name":"Poitrine d''agneau","unit":"g"},{"name":"Bâtonnets de tofu séché frits","unit":"g"},{"name":"Pâte de Chu Hou","unit":"g"},{"name":"Fromage de soja fermenté","unit":"g"},{"name":"Fromage de soja rouge","unit":"g"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Huile de piment","unit":"ml"},{"name":"Vin de cuisson","note":"Quantité suffisante"},{"name":"Sauce d''huître","note":"Quantité suffisante"},{"name":"Eau claire","unit":"ml"},{"name":"Sucre candi","unit":"g"},{"name":"Sucre granulé","unit":"g"},{"name":"Oignons verts","unit":"pièce"},{"name":"Tranches de gingembre","unit":"tranche"},{"name":"Champignons shiitake","unit":"pièce"},{"name":"Oignon","unit":"pièce"},{"name":"Échalote","unit":"pièce"},{"name":"Gousse d''ail","unit":"gousse"},{"name":"Feuille de laurier","unit":"feuille"},{"name":"Anis étoilé","unit":"pièce"},{"name":"Cannelle en bâton","unit":"g"},{"name":"Accompagnement","note":"À ajouter selon les préférences"}]'::jsonb, '["Préparation : Faire tremper les champignons shiitake 2 à 3 heures jusqu''à ce qu''ils soient tendres.","Préparer la sauce 1 : Mélanger dans un petit bol le fromage de soja rouge, la sauce Chu Hou, 20g de fromage de soja fermenté et la sauce soja foncée, bien remuer.","Préparer la sauce 2 : Mélanger dans un petit bol 20g de fromage de soja fermenté, le sucre et l''huile de piment, bien remuer.","Retirer les pieds des champignons trempés.","Couper les bâtonnets de tofu trempés en morceaux de 5 cm, essorer l''excès d''eau.","Éplucher et émincer l''oignon. On peut aussi utiliser des échalotes pelées pour un meilleur goût.","Couper les oignons verts en tronçons d''environ 5 cm.","Mettre la poitrine d''agneau dans une casserole d''eau froide, ajouter 2-3 tranches de gingembre, porter à ébullition à feu vif, puis éteindre le feu.","Retirer l''agneau et le plonger dans un bol d''eau froide préparé pour le refroidir, ce qui lui donnera une texture plus ferme.","Chauffer la poêle, ajouter de l''huile froide, puis faire revenir 4-5 tranches de gingembre, l''oignon/les échalotes, les tronçons blancs d''oignon vert et 7-8 gousses d''ail jusqu''à ce qu''ils dégagent un parfum.","Ajouter l''agneau refroidi, remuer avec des baguettes pendant environ 2 à 5 minutes jusqu''à ce qu''il soit doré.","Ajouter la sauce 1 préparée, faire sauter environ 2 minutes jusqu''à ce que la couleur soit uniforme.","Verser de l''eau claire juste assez pour couvrir les ingrédients.","Ajouter les champignons, le sucre candi, les feuilles de laurier, l''anis étoilé et la cannelle.","Couvrir et mijoter à feu doux pendant 90 minutes.","Découvrir, ajouter les bâtonnets de tofu, couvrir et cuire à feu moyen pendant 20 minutes.","Découvrir, ajouter la sauce 2 et bien mélanger.","Éteindre le feu, avant de servir ajouter les tronçons verts d''oignon vert ou de la coriandre."]'::jsonb, '["Plat de viande","Cantonais","Sauce parfumée","Réconfortant","Automne/Hiver","Fait maison"]'::jsonb),
  ('howtocook:meat_dish/柱候牛腩/柱候牛腩', 'fr', 'Poitrine de bœuf sauce Chu Hou', 'Plats de viande', 'Ce plat cantonais classique a une riche saveur de viande, une couleur rouge vif, une poitrine de bœuf tendre et savoureuse avec une texture riche. Riche en protéines de haute qualité et en collagène, il est réconfortant et réchauffe le corps. Bien qu''il demande un peu de patience, l''utilisation d''un autocuiseur réduit considérablement le temps, ce qui le rend accessible aux débutants. La cuisson normale prend environ 3 heures, mais avec un autocuiseur, elle est prête en environ 1 heure.', '[{"name":"poitrine de bœuf","unit":"g","note":""},{"name":"gingembre","unit":"g","note":""},{"name":"ail","unit":"tête","note":""},{"name":"piment oiseau","unit":"pièce","note":""},{"name":"feuille de laurier","unit":"feuille","note":""},{"name":"poivre de Sichuan","unit":"g","note":""},{"name":"badiane","unit":"étoile","note":""},{"name":"piment sec","unit":"pièce","note":""},{"name":"clou de girofle","unit":"clou","note":""},{"name":"réglisse","unit":"tranche","note":""},{"name":"fromage de soja fermenté (nam yu)","unit":"cube","note":""},{"name":"pâte de piment de Pixian","unit":"g","note":""},{"name":"sucre de roche","unit":"g","note":""},{"name":"vin de Shaoxing (Hua Diao)","unit":"g","note":""},{"name":"alcool de riz","unit":"g","note":""},{"name":"sauce Chu Hou","unit":"g","note":""},{"name":"sauce Char Siu","unit":"g","note":""},{"name":"sauce d''huîtres","unit":"g","note":""},{"name":"sauce soja foncée","unit":"g","note":""},{"name":"sauce soja claire","unit":"g","note":""}]'::jsonb, '["D''abord, préparez les ingrédients pour les bols :","Bol 1 : coupez le gingembre en petits dés de 1,5 cm x 1,5 cm, épluchez une demi-tête d''ail, et si vous utilisez des piments oiseaux, coupez-les en tronçons de 1 cm.","Bol 2 : mettez 2 feuilles de laurier, 0,5 g de poivre de Sichuan, 2 étoiles de badiane, 3 piments secs, 3 clous de girofle, et 2 tranches de réglisse.","Bol 3 : mettez 2 cubes de fromage de soja fermenté (nam yu).","Bol 4 : mettez 15 g de pâte de piment de Pixian.","Bol 5 : mettez 10 g de sucre de roche.","Bol 6 : versez 10 g de vin de Shaoxing (Hua Diao) et 10 g d''alcool de riz.","Bol 7 : ajoutez 50 g de sauce Chu Hou, 20 g de sauce d''huîtres, 20 g de sauce Char Siu, 5 g de sauce soja foncée, et 60 g de sauce soja claire.","Ne coupez pas la viande. Mettez-la directement dans une casserole d''eau froide, portez à forte ébullition, puis retirez le bœuf dès l''ébullition.","Rincez les impuretés à la surface du bœuf, coupez-le en gros cubes de 4 cm x 4 cm x 4 cm, égouttez-les et réservez dans un bol.","À feu vif, chauffez de l''huile dans une poêle, versez le contenu du bol 1 (gingembre, ail, piments oiseaux) et faites revenir jusqu''à ce que cela soit parfumé.","À feu moyen-doux, versez le bol 2 (épices) et remuez bien pendant environ 30 secondes.","À feu moyen-doux, ajoutez le bol 3 (fromage de soja fermenté) et écrasez-le avec une spatule.","À feu moyen-doux, ajoutez le bol 4 (pâte de piment de Pixian) et remuez bien pendant environ 30 secondes.","À feu moyen-doux, ajoutez le bol 5 (sucre de roche) et faites cuire jusqu''à ce qu''il soit fondu.","À feu moyen-doux, ajoutez la poitrine de bœuf et faites revenir jusqu''à ce que la viande soit colorée.","À feu vif, versez le bol 6 (alcools) le long des bords de la poêle, remuez rapidement jusqu''à ce que la surface de la viande soit légèrement grillée.","Versez le bol 7 (sauces), remuez rapidement, surveillez le fond de la poêle, faites revenir jusqu''à ce que de petites bulles apparaissent et que la sauce épaississe légèrement.","Transférez tous les ingrédients dans une autre marmite ou un autocuiseur, ajoutez de l''eau à hauteur des ingrédients.","Selon le type de récipient, choisissez le temps de cuisson :","a. Marmite ordinaire : laissez mijoter à feu doux pendant 3 heures.","b. Autocuiseur : faites cuire sous pression pendant 40 minutes.","Une fois le temps écoulé, ouvrez et assaisonnez : si ce n''est pas assez salé, ajoutez du sel ou de la sauce soja claire (ajoutez petit à petit en goûtant), si ce n''est pas assez sucré, ajoutez du sucre de la même manière.","Après avoir ajusté l''assaisonnement, retirez d''abord le bœuf.","Si vous voulez ajouter du daïkon ou des pommes de terre, épluchez-les, coupez-les en tranches de 2 cm d''épaisseur et faites-les cuire dans la sauce pendant 10 à 15 minutes (ou jusqu''à la texture désirée). Si vous utilisez un autocuiseur, faites cuire sous pression pendant 5 minutes supplémentaires.","Une fois cuits, retirez les légumes et le bœuf et mettez-les ensemble.","Filtrez le jus de cuisson et versez-le sur la viande et les légumes dans un bol."]'::jsonb, '["Plat de viande","Cantonais","Sauce parfumée","Braiser","Accompagnement de riz","Réconfortant","Fait maison"]'::jsonb),
  ('howtocook:meat_dish/桂林十八酿/桂林十八酿', 'fr', 'Les dix-huit farcis de Guilin', 'Plats de viande', 'Série de plats farcis traditionnels de Guilin. On farcit des ingrédients creux comme les poivrons verts, courges amères, escargots, aubergines, etc., avec une farce de porc ou de crevettes assaisonnée, puis on les fait frire et mijoter. Chaque bouchée a sa propre saveur, juteuse et parfumée, avec une texture tendre ou élastique. C''est un plat familial de caractère régional. La farce apporte des protéines de qualité, accompagnée de divers légumes riches en vitamines et fibres, pour un équilibre nutritionnel. Les étapes nécessitent de farcir un par un et de maîtriser le feu, un peu de patience, mais la logique est simple, même les débutants peuvent essayer. Le temps total estimé est d''environ 1h30.', '[{"name":"poivron vert","note":"quantité suffisante"},{"name":"courge amère","note":"quantité suffisante"},{"name":"aubergine","note":"quantité suffisante"},{"name":"escargot","note":"quantité suffisante"},{"name":"tofu","note":"quantité suffisante"},{"name":"champignon shiitake","note":"quantité suffisante"},{"name":"fleur de courge","note":"quantité suffisante"},{"name":"pomélo","note":"quantité suffisante"},{"name":"pousse de bambou","note":"quantité suffisante"},{"name":"courge d''hiver","note":"quantité suffisante"},{"name":"taro parfumé","note":"quantité suffisante"},{"name":"ail","note":"quantité suffisante"},{"name":"tomate","note":"quantité suffisante"},{"name":"pousses de soja","note":"quantité suffisante"},{"name":"œuf","note":"quantité suffisante"},{"name":"champignon aromatique","note":"quantité suffisante"},{"name":"farce de porc","note":"quantité suffisante"},{"name":"farce de crevettes","note":"quantité suffisante"},{"name":"farce de poisson","note":"quantité suffisante"},{"name":"farce mixte","note":"quantité suffisante"}]'::jsonb, '["Farcis de poivron : épépiner et vider le poivron → farcir avec de la farce de porc ou de crevettes → faire frire jusqu''à coloration → mijoter dans une sauce","Farcis d''escargot : blanchir les escargots et en extraire la chair → hacher la chair d''escargot avec du porc et mélanger → remettre dans la coquille → mijoter avec du shiso et de la menthe","Farce de porc : le choix de base le plus courant, 30% de gras et 70% de maigre pour une meilleure texture","Farce de crevettes : sucrée et élastique, souvent utilisée dans les farcis de poivron","Farce mixte escargot-porc : l''âme du farci d''escargot, escargot et porc à parts égales, avec du shiso et de la menthe","Farce mixte : porc et crevettes mélangés, alliant le sucré et le gras parfumé"]'::jsonb, '["Plat de viande","Savoureux et parfumé","Frit et mijoté","Saveur de Guilin","Fait maison","Pour recevoir"]'::jsonb),
  ('howtocook:meat_dish/梅菜扣肉/梅菜扣肉', 'fr', 'Porc braisé au chou salé', 'Plats de viande', 'C''est un plat traditionnel de la Hakka, d''une belle couleur rouge-brun brillante, avec une sauce épaisse. Le porc est gras mais pas gras, tendre et savoureux. La poitrine de porc est riche en protéines de qualité et en acides gras, et le chou salé apporte des fibres alimentaires. L''ensemble demande un peu de travail, il faut maîtriser la cuisson, la friture et la vapeur, ce qui peut être un défi pour les débutants. De la préparation à la sortie du plat, y compris le temps de trempage du chou salé, cela prend environ 2,5 heures.', '[{"name":"Poitrine de porc","unit":"g"},{"name":"Chou salé de Meizhou","unit":"g"},{"name":"Cinq-épices","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sucre blanc","unit":"g"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Piment oiseau","unit":"pièce"},{"name":"Ail haché","unit":"g"},{"name":"Sel de cuisine","unit":"g"},{"name":"Bouillon de poulet","unit":"g"}]'::jsonb, '["Mettre le chou salé dans de l''eau claire et le faire tremper pendant 1 heure.","Verser 50 ml d''huile de cuisson dans une casserole, déposer la poitrine de porc entière côté peau vers le bas, laisser cuire 1 minute, puis retirer et gratter la peau (optionnel).","Ajouter de l''eau bouillante dans une casserole, y déposer la poitrine de porc, cuire à feu vif pendant 20 minutes (une baguette doit pouvoir s''enfoncer dans la viande), puis retirer la poitrine.","Badigeonner uniformément la surface de la poitrine de porc de sauce soja foncée, de cinq-épices et de sucre blanc, laisser reposer 15 minutes.","Chauffer de l''huile dans une casserole, ajouter la poitrine de porc et la faire frire à feu moyen jusqu''à ce qu''elle soit dorée des deux côtés (3 à 5 minutes).","Chauffer de l''huile dans une casserole, ajouter le chou salé, puis les piments oiseaux, l''ail haché, le bouillon de poulet et le sel de cuisine, faire sauter jusqu''à ce que le chou salé soit sec.","Trancher la poitrine de porc en morceaux de 0,5 à 1 cm d''épaisseur, les disposer dans un grand bol, puis répartir le chou salé par-dessus.","Cuire à la vapeur à feu moyen pendant 45 minutes.","Prendre une assiette, la retourner sur le bol de poitrine de porc, puis renverser le porc sur l''assiette."]'::jsonb, '["Plat de viande","Hakka","Cuit à la vapeur","Accompagnement de riz","Pour recevoir","Savoureux et parfumé"]'::jsonb),
  ('howtocook:meat_dish/椒盐排条', 'fr', 'Bâtonnets de porc au poivre et sel', 'Plats de viande', 'Les bâtonnets de porc au poivre et sel sont un classique de la cuisine familiale shanghaïenne, croustillants à l''extérieur et tendres à l''intérieur, salés et savoureux. La côte de porc apporte des protéines de qualité et des acides aminés essentiels, parfaits pour recharger les batteries. Bien que cette recette comporte plusieurs étapes, elle n''est pas difficile à suivre, même pour les débutants. De la préparation à la cuisson, comptez environ 40 minutes.', '[{"name":"Côte de porc","unit":"pièce"},{"name":"Œuf","unit":"pièce"},{"name":"Sel","unit":"g"},{"name":"Mélange de poivre et sel","unit":"g"},{"name":"Eau à l''oignon et au gingembre","unit":"ml"},{"name":"Farine","unit":"g"},{"name":"Fécule","unit":"g"},{"name":"Poudre de custard","unit":"g"},{"name":"Eau","unit":"g"},{"name":"Huile","unit":"g"}]'::jsonb, '["Lavez les côtes de porc, désossez-les, aplatissez-les avec le plat d''un couteau, coupez-les en tranches épaisses, puis en lanières épaisses.","Ajoutez le mélange de poivre et sel, mélangez bien. Lorsque la viande commence à devenir collante, ajoutez progressivement l''eau à l''oignon et au gingembre, puis mettez au réfrigérateur pendant 20 minutes.","Préparez la pâte à frire. Mélangez 80 g de farine, 20 g de fécule (note : 20 g de fécule, réservez les 60 g restants), 2-3 g de poudre de custard et 1 g de sel.","Cassez un œuf, mélangez, puis ajoutez progressivement 100 g d''eau, puis 10 g d''huile, en mélangeant constamment. Continuez jusqu''à obtenir une pâte lisse et légèrement épaisse.","Sortez les 60 g de fécule restants, prenez les lanières de porc, enrobez-les de fécule, puis de pâte à frire.","Faites chauffer de l''huile dans une casserole, suffisamment pour immerger les ingrédients, à environ 150-160 °C. Plongez les lanières et faites-les frire jusqu''à ce qu''elles soient légèrement dorées, puis égouttez. Au début, elles peuvent coller entre elles, ne les touchez pas. Une fois qu''elles sont fermes, vous pouvez les retourner avec des baguettes pour les séparer.","Lorsque l''huile remonte à 150-160 °C, replongez les lanières pour une seconde friture jusqu''à ce qu''elles soient dorées, puis égouttez.","Saupoudrez de mélange de poivre et sel, mélangez bien et servez."]'::jsonb, '["Viande","Salé et savoureux","Frit","Cuisine shanghaïenne","Apéritif","Croustillant à l''extérieur, tendre à l''intérieur"]'::jsonb),
  ('howtocook:meat_dish/水煮牛肉/水煮牛肉', 'fr', 'Bœuf poché à l''eau', 'Plats de viande', 'Le bœuf poché à l''eau est un plat classique du Sichuan, au goût piquant et engourdissant. La texture est tendre, le bouillon rouge vif, parfumé, épicé et brûlant. Le bœuf est riche en protéines et en fer, accompagné de pousses de soja qui apportent des fibres. Ce plat n''est pas trop difficile pour les débutants, mais il faut faire attention à la cuisson et à la sécurité lorsqu''on verse l''huile chaude. La préparation prend environ 40 minutes.', '[{"name":"Bœuf","unit":"g"},{"name":"Pousses de soja","unit":"g"},{"name":"Œuf","unit":"pièce"},{"name":"Coriandre","unit":"tige"},{"name":"Pâte de fèves épicée","unit":"g"},{"name":"Vin de cuisson","unit":"ml"},{"name":"Fécule","unit":"g"},{"name":"Poudre de piment sec","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Piment rouge","unit":"tige"},{"name":"Sauce d''huître","unit":"g"}]'::jsonb, '["Lavez le bœuf et coupez-le en tranches.","Ajoutez 15g de gingembre en julienne, 1 œuf, 15g de fécule, 8g de sauce d''huître, 10ml de vin de cuisson, mélangez bien et laissez mariner 15 minutes.","Lavez la coriandre et coupez-la.","Versez de l''huile dans la casserole, ajoutez la pâte de fèves épicée, 5g de gingembre en julienne, et des tranches d''ail.","Versez de l''eau bouillante et faites cuire jusqu''à obtention d''un bouillon rouge.","Lavez les pousses de soja, retirez les extrémités, puis blanchissez-les dans l''eau bouillante.","Disposez les pousses de soja au fond du bol.","Placez les tranches de bœuf une par une dans le bouillon rouge, faites-les cuire, puis retirez-les.","Disposez le bœuf sur les pousses de soja et saupoudrez de tiges de coriandre.","Saupoudrez de feuilles de coriandre, de poudre de piment, et de rondelles de piment.","Dans une autre casserole, faites chauffer de l''huile puis versez-la sur le plat. C''est prêt."]'::jsonb, '["Plat de viande","Piquant et engourdissant","Cuisine du Sichuan","Accompagne bien le riz","Familial","Tendre"]'::jsonb),
  ('howtocook:meat_dish/水煮肉片', 'fr', 'Tranches de porc poché épicées (Sichuan)', 'Plats de viande', 'Les tranches de porc poché épicées sont un plat sichuanais classique, à la fois piquant et frais, avec une viande tendre et des légumes croquants. Idéal pour accompagner le riz. Le filet de porc fournit des protéines de qualité, associé à des légumes comme les pousses de soja, pour un équilibre nutritionnel. La préparation est un peu complexe, nécessitant notamment de mariner la viande avec patience et de préparer les piments hachés. Les débutants compteront environ 1 à 2 heures.', '[{"name":"Filet de porc","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Poivre blanc","unit":"g"},{"name":"Sauce soja claire","unit":"g"},{"name":"Vin de cuisine","unit":"g"},{"name":"Blanc d''œuf","unit":"pièce"},{"name":"Fécule de pomme de terre","unit":"g"},{"name":"Huile végétale","unit":"g"},{"name":"Pousses de soja vert","unit":"g"},{"name":"Laitue","unit":"tige"},{"name":"Céleri","unit":"branche"},{"name":"Ciboule","unit":"tige"},{"name":"Ail","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Piments confits rouges","unit":"g"},{"name":"Poivre vert du Sichuan","unit":"g"},{"name":"Piments séchés","unit":"g"},{"name":"Pâte de fèves épicée (doubanjiang)","unit":"ml"},{"name":"Bouillon de poule en poudre","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Oignon vert","unit":"tige"},{"name":"Huile de colza","unit":"g"}]'::jsonb, '["Couper le filet de porc en petits morceaux, puis en tranches de 2 mm d''épaisseur (ajuster selon votre préférence). Mettre dans un bol, laver deux fois à l''eau claire pour éliminer le sang et les impuretés. Égoutter et essorer en pressant. Réserver.","Ajouter dans le bol 1,5 g de sel, 1 g de poivre blanc, 5 g de sauce soja claire, 3 g de vin de cuisine. Mélanger dans un sens pendant 2 minutes pour faire pénétrer la saveur.","Dans un autre bol, ajouter un blanc d''œuf, 7 g de fécule de pomme de terre. Mélanger dans un sens jusqu''à homogénéité, puis verser sur la viande.","Mélanger à nouveau dans le même sens (une pellicule lubrifiante se forme à la surface de la viande, ce qui la rendra plus tendre).","Enfin, ajouter 30 g d''huile végétale et mélanger délicatement (pour éviter que les tranches de viande ne collent).","100 g de pousses de soja vert, 1 tige de laitue (coupée en lanières), 3 branches de céleri coupées en tronçons, 2 tiges de ciboule écrasées puis coupées en morceaux.","20 g d''ail haché, un petit morceau de gingembre haché, 20 g de piments confits rouges hachés.","15 g de piments séchés (type Xiaomila), 3 g de poivre vert du Sichuan. Huiler la poêle, chauffer légèrement puis jeter l''excédent d''huile en ne gardant que 50 g d''huile de fond. Ajouter les piments séchés et le poivre de Sichuan, faire revenir à feu doux jusqu''à ce qu''ils soient parfumés, sans les brûler (ils doivent noircir). Les sortir et les hacher finement sur une planche à découper.","Chauffer la poêle, ajouter 100 g d''huile végétale et chauffer jusqu''à 60 % de la température maximale. Ajouter 2 g de poivre vert du Sichuan et des piments séchés pour les faire exploser. Ajouter les légumes d''accompagnement, 1 g de sel, faire sauter jusqu''à ce qu''ils soient cuits mais encore croquants. Transférer dans un bol pour garnir le fond, réserver.","Nettoyer la poêle, ajouter 150 g d''huile végétale et chauffer à 60 %. Ajouter le gingembre, l''ail et les piments confits hachés, faire revenir jusqu''à ce qu''ils soient parfumés, puis ajouter 10 g de pâte de fèves épicée (doubanjiang), faire revenir à feu doux jusqu''à ce que l''huile devienne rouge.","Ajouter 800 ml d''eau (ajuster selon besoin), porter à ébullition sur feu vif, puis réduire à feu doux pour assaisonner. Ajouter 2,5 g de sel, 1,5 g de bouillon de poule en poudre, 1 g de sucre blanc pour rehausser la saveur, 1 g de poivre blanc, 5 g de fécule de pomme de terre diluée dans un peu d''eau (ajuster selon besoin) pour épaissir légèrement la sauce.","Une fois la sauce à ébullition, réduire à feu doux et ajouter les tranches de viande marinées une par une. Passer à feu moyen pour les cuire, en remuant doucement avec une spatule pour éviter qu''elles ne collent. Quand la sauce bout à nouveau et que la viande est cuite, retirer les tranches et les déposer sur les légumes dans le bol. Verser ensuite la sauce d''origine (sans dépasser le niveau des aliments).","Saupoudrer uniformément sur le bol le mélange de piments et poivre haché (couteau), la purée d''ail et les oignons verts émincés.","Nettoyer la poêle, ajouter 200 g d''huile de colza, chauffer jusqu''à 70 % de la température. Verser ensuite l''huile chaude d''un seul coup uniformément sur les tranches de viande dans le bol (attention à la sécurité). Le plat est délicieusement prêt."]'::jsonb, '["Plat de viande","Piquant et numbing","Cuisine sichuanaise","Accompagnement de riz","Poché","Plat pour invités"]'::jsonb),
  ('howtocook:meat_dish/洋葱炒猪肉', 'fr', 'Porc sauté aux oignons', 'Plats de viande', 'C''est un plat sauté maison, salé avec une touche sucrée, riche en sauce soja. Les oignons deviennent tendres et doux, se marient parfaitement avec les fines tranches de porc fondantes, ce qui est très appétissant avec du riz. Le porc fournit des protéines de qualité et des vitamines B, les oignons contiennent des fibres alimentaires et des antioxydants, stimulant l''appétit et facilitant la digestion. Simple à réaliser, même les débutants peuvent le réussir, le temps de préparation est d''environ 15 minutes.', '[{"name":"oignon","unit":"pièce"},{"name":"tranches de porc","unit":"g"},{"name":"ail","unit":"gousse"},{"name":"huile de cuisson","unit":"ml"},{"name":"poivre noir","unit":"g"},{"name":"sauce soja","unit":"ml"},{"name":"sucre","unit":"g"},{"name":"huile de sésame","unit":"ml"},{"name":"ketchup","unit":"ml"},{"name":"vin de cuisson","unit":"ml"}]'::jsonb, '["Émincer l''oignon, couper le porc en tranches, écraser l''ail, et mélanger les assaisonnements ci-dessus. Réserver.","Verser 1 cuillère à soupe d''huile de cuisson dans le wok (attendre 10 secondes pour que l''huile chauffe), ajouter le porc.","Faire sauter jusqu''à ce qu''il change de couleur, puis ajouter l''ail et faire revenir jusqu''à ce qu''il soit parfumé. Retirer et réserver.","Dans le même wok, ajouter l''oignon et faire sauter pendant 3 à 4 minutes, puis ajouter l''assaisonnement et mélanger.","Remettre le porc réservé et faire sauter jusqu''à ce que le porc soit cuit.","Une fois le porc cuit, faire sauter encore 1 à 2 minutes, puis servir."]'::jsonb, '["Viande","Maison","Accompagnement riz","Rapide","Salé-sucré","Arôme sauce soja","Sauté"]'::jsonb),
  ('howtocook:meat_dish/淄博烧烤/淄博烧烤', 'fr', 'Barbecue de Zibo', 'Plats de viande', 'Voici un barbecue typique de Zibo, dans le Shandong. La méthode de dégustation consistant à envelopper la viande dans une petite galette avec de l''oignon vert est unique et savoureuse. Les arômes de la viande, de la sauce et de l''oignon se mêlent pour une expérience gustative riche. La poitrine de porc est riche en protéines de qualité et en graisses, l''oignon vert apporte des fibres alimentaires, et la petite galette fournit un regain d''énergie rapide. La préparation nécessite de maîtriser la température du charbon et les techniques de retournement, ce qui peut être un défi pour les débutants. L''ensemble prend environ 40 minutes.', '[{"name":"Poitrine de porc","unit":"g"},{"name":"Petites galettes fines","unit":"pièce"},{"name":"Oignon vert","unit":"tige"},{"name":"Pâte de sésame","unit":"g"},{"name":"Sauce de soja sucrée","unit":"g"},{"name":"Sel de sésame","note":"quantité suffisante"},{"name":"Eau tiède","unit":"ml"}]'::jsonb, '["Couper la poitrine de porc en morceaux ne dépassant pas 2 cm d''épaisseur et les enfiler sur des brochettes. (On peut mariner la poitrine de porc à l''avance pour un meilleur goût.)","Couper l''oignon vert en tronçons de 5 cm de long et réserver.","Délayer la pâte de sésame avec 10 ml d''eau tiède, puis mélanger avec la sauce de soja sucrée. Réserver. (On peut remplacer par du sel de sésame.)","Allumer le charbon de bois et attendre qu''il soit rougeoyant sans flamme (environ 15 minutes).","Disposer les brochettes de poitrine de porc uniformément sur la grille. Griller jusqu''à ce que le dessous soit doré et que la graisse fonde, puis retourner.","Continuer à griller pendant environ 2 à 3 minutes jusqu''à ce que les deux faces soient dorées et les bords légèrement croustillants, puis retirer.","Étaler une petite galette fine, y étaler 3 à 4 g du mélange de sauces.","Déposer les morceaux de viande grillée et 1 à 2 tronçons d''oignon vert sur la galette, rouler et déguster."]'::jsonb, '["viande","grillé au charbon","cuisine du Shandong","savoureux","à grignoter avec l''alcool","repas entre amis"]'::jsonb),
  ('howtocook:meat_dish/清蒸鳜鱼/清蒸鳜鱼', 'fr', 'Perche mandarine à la vapeur', 'Plats de viande', 'La perche mandarine à la vapeur a une chair tendre et délicate, avec une saveur naturelle sucrée qui se démarque. C''est une méthode familiale pour cuisiner les poissons d''eau douce en préservant leur goût authentique. La perche mandarine est riche en protéines de haute qualité et en oligo-éléments, facile à digérer et à absorber. Lors de la préparation, il faut faire attention aux nageoires, mais les étapes dans leur ensemble ne sont pas compliquées, même un débutant peut s''en sortir avec un peu d''attention. De la préparation à la cuisson, cela prend environ une demi-heure.', '[{"name":"perche mandarine","unit":"g"},{"name":"poireau","unit":"tronçon"},{"name":"oignon vert","unit":"tige"},{"name":"sauce soja claire","unit":"g"},{"name":"piment rouge","unit":"pièce"},{"name":"tranches de gingembre","unit":"tranche"},{"name":"huile de cuisson","unit":"ml"}]'::jsonb, '["Préparation des ingrédients :","Ouvrir la perche mandarine par le ventre, retirer les branchies et les viscères, enlever les écailles, et gratter le mucus sur la peau avec un couteau (cette étape peut être confiée au marchand zélé).","Faire des entailles sur le poisson, placer des tranches de gingembre, et si possible, ajouter un peu de saindoux. Déposer le poisson dans un plat en le surélevant avec une baguette pour une cuisson uniforme à la vapeur.","Fendre le poireau en deux, retirer le cœur et ne conserver que les deux couches extérieures.","Fendre les oignons verts et réserver.","Retirer les graines et la chair interne du piment rouge, réserver.","Mélanger le poireau, les oignons verts et le piment préparés, les couper en julienne et les mettre à tremper dans l''eau, réserver.","Cuisson :","Remplir une casserole d''eau (assez d''eau), une fois l''eau chaude, y déposer la perche mandarine, couvrir et cuire à la vapeur à feu vif pendant 8 à 10 minutes. Le secret pour cuire le poisson à la vapeur : vapeur abondante et feu vif.","Pendant la cuisson à la vapeur, faire chauffer de l''huile dans une autre poêle jusqu''à ce qu''elle fume.","Une fois la cuisson terminée, jeter l''eau de cuisson, retirer les tranches de gingembre, disposer la julienne d''oignons et de piment sur le poisson, puis verser l''huile chaude dessus.","Ajouter de la sauce soja claire ou de la sauce pour poisson vapeur, et servir."]'::jsonb, '["Plat de poisson","Vapeur","Savoureux","Léger","Poisson d''eau douce","Familial","Pour recevoir"]'::jsonb),
  ('howtocook:meat_dish/湖南家常红烧肉/湖南家常红烧肉', 'fr', 'Porc braisé familial du Hunan', 'Plats de viande', 'Le porc braisé familial du Hunan est un plat familial typique de la cuisine du Hunan, riche en saveurs. La poitrine de porc, après une longue cuisson, devient fondante sans être grasse, tendre en bouche, avec un goût salé et légèrement piquant qui laisse une douce rémanence. Riche en protéines et en lipides de qualité, il fournit une énergie suffisante au corps. Sa préparation demande un peu de patience et représente un défi pour les débutants, mais en suivant les étapes, c''est facile à maîtriser. Le temps total est d''environ 1 heure.', '[{"name":"Poitrine de porc avec la peau","unit":"g"},{"name":"Huile de cuisson","unit":"g"},{"name":"Sucre candi","unit":"morceau"},{"name":"Feuille de laurier","unit":"feuille"},{"name":"Gingembre","unit":"tranche"},{"name":"Cannelle","unit":"petit morceau"},{"name":"Anis étoilé","unit":"pièce"},{"name":"Vin de cuisine","unit":"g"},{"name":"Sauce soja claire","unit":"g"},{"name":"Sauce soja foncée","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Piments séchés","note":"Selon votre goût"},{"name":"Eau bouillante","note":"Quantité suffisante"}]'::jsonb, '["Laver la poitrine de porc avec la peau, la mettre dans une casserole d''eau froide, ajouter 2 à 3 tranches de gingembre pour enlever l''odeur, porter à ébullition, puis retirer et rincer à l''eau froide pour enlever l''écume blanche.","Couper la poitrine de porc en cubes d''environ 1,5 cm de côté.","Chauffer l''huile dans une poêle, ajouter le sucre candi et remuer à feu doux jusqu''à ce qu''il caramélise, puis ajouter les cubes de poitrine de porc et faire sauter à feu moyen pour les colorer.","Ajouter les tranches de gingembre, l''anis étoilé, la cannelle, la sauce soja claire, la sauce soja foncée, le vin de cuisine, les piments séchés et le sel. Faire revenir à feu doux pendant 1 minute, puis ajouter de l''eau bouillante à hauteur de la viande.","Couvrir et porter à ébullition à feu moyen, puis réduire à feu doux et laisser mijoter 30 minutes. Pendant la cuisson, remuer toutes les 10 minutes pour éviter que cela n''attache.","Lorsqu''il ne reste qu''un tiers du bouillon, augmenter à feu moyen pour faire réduire la sauce, puis retirer du feu."]'::jsonb, '["Viande","Hunan","Familial","Braisé","Accompagne le riz","Salé et légèrement piquant"]'::jsonb),
  ('howtocook:meat_dish/湘祁米夫鸭/湘祁米夫鸭', 'fr', 'Canard Xiangqi au riz', 'Plats de viande', 'Spécialité traditionnelle de la région des Deux Qi dans le Hunan. Le canard est sauté puis enrobé d''un mélange de farines de riz et cuit à la vapeur. La texture est moelleuse, le goût salé et parfumé, avec un arrière-goût durable. Le canard est riche en protéines de haute qualité et en vitamines B, tandis que la farine de riz fournit de l''énergie, pour un repas équilibré. La préparation nécessite un sauté puis une cuisson sous pression, un peu technique, adaptée aux cuisiniers ayant une certaine expérience. Du début à la fin, il faut compter environ 1 heure ; si vous utilisez un canard vieux, prolongez la cuisson à la vapeur.', '[{"name":"Canard","unit":"g"},{"name":"Farine de riz gluant","unit":"g"},{"name":"Farine de riz","unit":"g"},{"name":"Poudre à viande vapeur","unit":"g"},{"name":"Poudre de piment fin","unit":"g"},{"name":"Poivre blanc en poudre","unit":"g"},{"name":"Poitrine de porc","unit":"g"},{"name":"Gingembre et ail","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Huile de cuisson","unit":"g"},{"name":"Eau bouillante","unit":"g"},{"name":"Ciboule hachée","note":"Quantité suffisante"}]'::jsonb, '["Mélanger la farine de riz gluant, la farine de riz, la poudre à viande vapeur, la poudre de piment fin, 5 g de sel et le poivre blanc.","Demander au marchand de couper le canard en morceaux pour la cuisson à la vapeur. Couper le gingembre en tranches, peler les gousses d''ail, couper la poitrine de porc en tranches.","Dans une poêle chaude avec un peu d''huile, faire sauter la poitrine de porc pour extraire la graisse, puis ajouter de l''huile de cuisson et faire sauter le canard.","Faire sauter le canard jusqu''à ce que la peau soit dorée, ajouter le gingembre, l''ail et le sel, continuer à faire sauter pour libérer les arômes.","Baisser le feu, ajouter la farine de riz et mélanger pour bien enrober le canard. Ajouter de l''eau bouillante petit à petit en remuant.","Lorsque le mélange est humide, le transférer dans un bol. Mettre de l''eau dans une cocotte-minute et cuire à la vapeur pendant 20 à 25 minutes.","Avant de servir, saupoudrer de ciboule hachée."]'::jsonb, '["Plat de viande","Hunan","Cuit à la vapeur","Salé et parfumé","Accompagne le riz","Spécialité locale"]'::jsonb),
  ('howtocook:meat_dish/澳门湿版免治牛肉饭/澳门湿版免治牛肉饭', 'fr', 'Riz au bœuf haché humide façon Macao', 'Plats de viande', 'C''est un plat rapide classique de la cuisine macanaise (portugaise). Le bœuf haché est tendre, savoureux et légèrement salé, enveloppé dans une sauce riche et un œuf mi-cuit, mélangé avec du riz pour une texture onctueuse et appétissante. La viande de bœuf hachée fournit des protéines de qualité, avec l''œuf et l''oignon, c''est un repas équilibré et copieux. Les étapes sont simples et faciles à suivre, particulièrement adaptées aux débutants. De la préparation au service, cela ne prend qu''environ 30 minutes.', '[{"name":"Bœuf haché","unit":"g"},{"name":"Oignon","unit":"pièce"},{"name":"Œuf","unit":"pièce"},{"name":"Beurre","unit":"g"},{"name":"Ciboule","unit":"g"},{"name":"Sauce soja claire","unit":"c. à soupe"},{"name":"Sauce soja foncée","unit":"c. à soupe"},{"name":"Ketchup","unit":"c. à soupe"},{"name":"Sucre blanc","unit":"c. à soupe"},{"name":"Vin de cuisson","unit":"c. à soupe"},{"name":"Poivre noir","unit":"g"},{"name":"Fécule de maïs","unit":"c. à soupe"},{"name":"Eau claire","unit":"ml"},{"name":"Riz cuit","note":"quantité suffisante"}]'::jsonb, '["Placez 200 g de bœuf haché dans un bol, ajoutez 1 c. à soupe de sauce soja claire, 1/2 c. à soupe de sucre blanc et 2 g de poivre noir. Mélangez bien et laissez mariner 10 minutes.","Coupez un demi-oignon en petits dés et réservez.","Préparez la sauce : dans un bol, mélangez 2 c. à soupe de sauce soja claire, 2 c. à soupe de ketchup, 1 c. à soupe de vin de cuisson, 1 c. à soupe de fécule de maïs, 1/2 c. à soupe de sauce soja foncée et 50 ml d''eau claire. Mélangez bien et réservez.","Dans une autre casserole, préparez un œuf poché ou un œuf au plat mi-cuit et réservez.","Faites chauffer une poêle, ajoutez 10 g de beurre. Une fois le beurre fondu, ajoutez les dés d''oignon et faites-les revenir à feu doux jusqu''à ce qu''ils soient parfumés.","Ajoutez le bœuf haché mariné et faites-le sauter avec les oignons jusqu''à ce que la viande change de couleur.","Versez la sauce préparée, ajoutez 2 g de poivre noir et continuez à cuire jusqu''à ce que la sauce épaississe. Retirez du feu.","Versez le bœuf haché cuit sur le riz chaud, puis déposez l''œuf poché ou l''œuf au plat mi-cuit préparé.","(Facultatif) Saupoudrez de 5 g de ciboule ciselée pour la garniture."]'::jsonb, '["Viande","Macao","Portugais","Bœuf","Plat rapide","Riz mélangé","Bœuf haché","Débutant"]'::jsonb),
  ('howtocook:meat_dish/烤鸡翅', 'fr', 'Ailes de poulet rôties', 'Plats de viande', 'Marinées, les ailes de poulet sont cuites au four à haute température, la peau légèrement croustillante, la chair tendre et juteuse, avec le goût savoureux du poivre noir et de la sauce soja. Riches en protéines de qualité et en collagène. De difficulté moyenne, les débutants peuvent facilement réussir, du début à la sortie du four environ 1 heure. On peut aussi ajouter du miel ou de la poudre de cinq épices selon les goûts pour plus de saveur.', '[{"name":"Ailes de poulet","unit":"pièce"},{"name":"Sel","unit":"g"},{"name":"Poivre noir moulu","unit":"g"},{"name":"Sauce soja","unit":"ml"},{"name":"Vin de cuisine","unit":"ml"}]'::jsonb, '["Mettez les ailes de poulet dans un bol.","Ajoutez du sel, du poivre noir, de la sauce soja et du vin de cuisine pour mariner 30 à 40 minutes.","Préchauffez le four à 200°C.","Disposez les ailes de poulet marinées uniformément sur la plaque de cuisson.","Placez la plaque au milieu du four et faites cuire 15 à 20 minutes.","Sortez la plaque, retournez les ailes de poulet, puis faites cuire à nouveau 15 à 20 minutes jusqu''à ce qu''elles soient bien cuites."]'::jsonb, '["Viande","Salé et savoureux","Grill","Maison","Réception"]'::jsonb),
  ('howtocook:meat_dish/煎烤羊排/煎烤羊排', 'fr', 'Côtelettes d''agneau poêlées', 'Plats de viande', 'Un plat croustillant à l''extérieur et tendre à l''intérieur, riche en arômes. D''abord braisé avec des épices, puis poêlé jusqu''à obtenir une croûte dorée et croustillante. La saveur est riche mais pas grasse, parfait pour un repas quotidien ou pour recevoir. L''agneau est riche en protéines de haute qualité et en minéraux comme le fer et le zinc, ce qui aide à réchauffer et nourrir le corps. Les étapes sont un peu nombreuses, mais en suivant le processus, même un débutant peut réussir ; avec un autocuiseur, cela prend environ 1 heure, avec une casserole ordinaire, environ 1,5 heures.', '[{"name":"Côtelettes d''agneau","unit":"grammes"},{"name":"Bâton de cannelle","unit":"grammes"},{"name":"Grains de poivre du Sichuan","unit":"grammes"},{"name":"Étoiles de badiane","unit":"pièce"},{"name":"Angélique (Bai Zhi)","unit":"grammes"},{"name":"Feuilles de laurier","unit":"feuille"},{"name":"Sel","unit":"grammes"},{"name":"Vin de cuisson (Shaoxing)","unit":"ml"},{"name":"Piment en poudre","unit":"grammes"},{"name":"Graines de cumin","unit":"grammes"},{"name":"Mélange d''épices pour barbecue","unit":"grammes"},{"name":"Cumin en poudre","unit":"grammes"},{"name":"Graines de sésame blanc","unit":"grammes"},{"name":"Sucre","unit":"grammes"}]'::jsonb, '["Couper les côtelettes d''agneau en morceaux en suivant les os.","Dans une poêle, ajouter de l''eau froide et tous les morceaux d''agneau. Porter à ébullition et continuer à blanchir pendant 2 à 3 minutes, puis égoutter.","Mettre les côtelettes blanchies, le bâton de cannelle, les grains de poivre du Sichuan, les étoiles de badiane, l''angélique, les feuilles de laurier et le vin de cuisson dans une casserole (autocuiseur ou casserole ordinaire).","Ajouter de l''eau de boisson jusqu''à couvrir tous les ingrédients. Si vous utilisez un autocuiseur, cuire sous pression pendant 30 minutes. Si vous utilisez une casserole ordinaire, mijoter pendant 80 minutes.","Sortir les côtelettes cuites, les égoutter, et les placer dans une poêle ou une sauteuse sans eau ni huile.","Faire poêler à feu moyen-vif pendant 6 à 7 minutes, jusqu''à ce que la graisse des côtelettes soit rendue et que la surface soit dorée et croustillante.","Conserver la graisse d''agneau rendue dans la poêle, ajouter le piment en poudre, les graines de cumin, le mélange d''épices pour barbecue, le cumin en poudre et les graines de sésame blanc. Mélanger bien.","Ajouter le sucre et le sel (si non ajoutés lors du braisage), et mélanger uniformément.","Une fois bien mélangé, éteindre le feu et servir dans un plat."]'::jsonb, '["Viande","Poêlé et grillé","Épicé","Croustillant dehors, tendre dedans","Cuisine maison","Pour invités"]'::jsonb),
  ('howtocook:meat_dish/牛排/牛排', 'fr', 'Steak', 'Plats de viande', 'C''est un steak poêlé classique de style occidental, avec une croûte croustillante enveloppant une chair tendre et juteuse, accompagné de beurre, d''ail et d''herbes aromatiques, riche en saveurs. Riche en protéines de qualité, en matières grasses et en minéraux comme le fer et le zinc. Le processus de cuisson est relativement facile pour les débutants, mais maîtriser la cuisson nécessite un peu de pratique. Le tout peut être préparé en 15 à 30 minutes.', '[{"name":"Steak","unit":"g"},{"name":"Huile d''olive","unit":"ml"},{"name":"Beurre","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Poivre noir moulu","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Thym","unit":"g"},{"name":"Romarin","note":"Quantité suffisante"},{"name":"Sauce à steak préparée","note":"Quantité suffisante"},{"name":"Champignons de Paris","unit":"pièce"},{"name":"Pommes de terre nouvelles","unit":"pièce"},{"name":"Tomates cerises","unit":"pièce"},{"name":"Asperges","note":"Quantité suffisante"}]'::jsonb, '["Sortez le steak du réfrigérateur pour le décongeler.","Si le steak est congelé, transférez-le au réfrigérateur la veille et sortez-le à température ambiante 30 minutes avant la cuisson.","Ne mettez pas le steak dans l''eau et ne le décongelez pas à la chaleur.","Lavez les tomates cerises, les pommes de terre nouvelles et les champignons de Paris, coupez-les en deux et réservez.","Épluchez l''ail, gardez 5 à 8 grosses gousses et écrasez-les avec le plat du couteau, réservez.","Préparation du steak.","Pour le steak d''entrecôte (voir comment choisir différents types de steaks), utilisez des ciseaux de cuisine pour insérer verticalement dans le tissu conjonctif au centre de l''entrecôte et coupez 1 à 2 fois. Cela est dû au fait que le ''œil'' de l''entrecôte (ce tissu conjonctif) se contracte fortement à haute température, déformant le steak et empêchant une cuisson uniforme.","Pour le faux-filet, si vous n''aimez pas la graisse sur le côté, vous pouvez l''enlever lentement avec un couteau.","Ensuite, enveloppez le steak avec du papier absorbant et séchez toute l''eau à la surface jusqu''à ce qu''il ne reste plus de taches d''eau visibles lorsque vous soulevez le steak de la planche.","Allumez le feu vif (voir l''annexe pour les explications sur l''intensité du feu) et ajoutez de l''huile d''olive dans la poêle, faites chauffer 15 à 30 secondes.","Assaisonnez le steak. Saupoudrez uniformément du sel de mer et du poivre noir sur toute la surface du steak, puis frottez avec les mains pour que les grains de sel et de poivre s''incrustent dans la viande. Notez que le steak doit être mis immédiatement dans la poêle après l''assaisonnement ; il n''est pas recommandé de l''assaisonner à l''avance. Car le sel en surface extrait l''eau du bœuf, affectant la cuisson et la saveur.","Faites chauffer la poêle jusqu''à ce que l''huile atteigne 6 à 8 dixièmes de sa température maximale (voir les techniques d''évaluation de la température de l''huile), puis déposez délicatement le steak dans la poêle en le glissant de près à loin.","Si vous utilisez des pommes de terre comme accompagnement, mettez-les dans un bol et chauffez au micro-ondes 10 minutes, ou faites-les bouillir dans de l''eau 3 à 5 minutes.","Faites cuire un côté pendant 1,5 minute (ce temps est pour un steak d''environ 2-3 cm d''épaisseur. Si votre steak est plus fin, réduisez à 1 minute. S''il est plus épais, augmentez à 2-2,5 minutes).","Retournez et faites cuire l''autre côté pendant 1,5 minute.","Pour le faux-filet et le filet mignon, utilisez des baguettes ou une spatule pour redresser le steak et cuire les côtés pendant environ 30 secondes.","Passez le feu à moyen, puis ajoutez rapidement dans l''ordre le beurre, l''ail et le thym. Poussez le beurre avec la spatule en le faisant fondre rapidement. Placez l''ail sous le steak pour plus de saveur.","Inclinez la poêle sur le feu pour que l''huile s''écoule d''un côté.","Placez les herbes et l''ail sur le steak, puis arrosez continuellement le steak avec l''huile de la poêle à l''aide d''une cuillère. Cela dure 30 secondes, puis retournez le steak et répétez pendant 30 secondes.","Vous pouvez juger de la température de l''huile en observant son comportement lorsqu''elle est versée sur le steak. Si l''huile pétille et ne devient pas brune, la température est bonne.","Si votre steak n''a pas été bien séché ou a été décongelé de manière non recommandée, ou si vous l''avez assaisonné avec du sel à l''avance, beaucoup d''eau apparaîtra dans la poêle, ce qui cuira le steak à l''eau et lui fera perdre sa saveur.","Si beaucoup de bulles d''huile apparaissent à la surface du steak et que l''huile devient brune, cela signifie que l''huile est trop chaude ; retirez la poêle du feu, attendez un moment, puis continuez à arroser.","Sortez le steak et placez-le sur une planche, enveloppez-le de papier d''aluminium et laissez reposer 5 à 10 minutes. Ce processus (appelé repos) permet à la chaleur interne du steak de continuer à cuire et de verrouiller l''humidité.","Versez les accompagnements (pommes de terre, tomates, champignons) dans la poêle et faites-les revenir à feu moyen pendant 5 minutes.","Sortez le steak, coupez-le en lanières d''environ 1,5 cm de large. Vous pouvez maintenant observer le degré de cuisson.","Sortez les accompagnements, dressez l''assiette, arrosez avec l''huile restante dans la poêle ou une sauce à steak préparée (optionnel)."]'::jsonb, '["Viande","Occidental","Poêlé","Savoureux","Pour invités","Rapide"]'::jsonb),
  ('howtocook:meat_dish/猪皮冻/猪皮冻', 'fr', 'Gelée de peau de porc', 'Plats de viande', 'La gelée de peau de porc est un plat froid traditionnel courant lors du dîner du Nouvel An chinois dans le nord. Translucide, sa texture est lisse, tendre et rebondissante, parfaite pour accompagner l''alcool. La peau de porc est riche en collagène, bénéfique pour la beauté de la peau. Cette recette est un peu difficile, nécessitant de traiter la peau de porc pour enlever l''odeur et une longue cuisson. Le temps de préparation est d''environ 24 heures.', '[{"name":"Peau de porc","unit":"kg"},{"name":"Eau","unit":"kg"},{"name":"Sel","unit":"g"},{"name":"Glutamate monosodique","unit":"g"},{"name":"Bouillon de poule en poudre","unit":"g"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Oignon vert","unit":"g"},{"name":"Tranches de gingembre","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Badiane","unit":"g"},{"name":"Poivre du Sichuan","unit":"g"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Vinaigre blanc","unit":"g"},{"name":"Angélique","note":"Quantité suffisante"},{"name":"Cannelle","note":"Quantité suffisante"},{"name":"Clou de girofle","note":"Quantité suffisante"},{"name":"Feuille de laurier","note":"Quantité suffisante"},{"name":"Fenouil","note":"Quantité suffisante"}]'::jsonb, '["Couper la peau de porc en morceaux ne dépassant pas 10 cm. Faire tremper dans l''eau claire pendant 12 heures. Ensuite, mettre dans une casserole d''eau froide, ajouter 10 g de gingembre et 50 ml de vin de cuisine, blanchir pendant 5 à 10 minutes. Égoutter et plonger dans l''eau froide.","Mettre la peau de porc blanchie sur une planche à découper. Retirer toute la partie de gras blanc à l''intérieur, puis couper en lanières ne dépassant pas 3 mm d''épaisseur. Mettre dans un bol.","Ajouter 20 g de vinaigre blanc et 5 g de sel. Frotter vigoureusement pendant 3 minutes, puis rincer à l''eau claire. À ce stade, la peau de porc n''a presque plus d''odeur.","Ajouter 4 kg d''eau dans une casserole, mettre la peau de porc, 10 g d''oignon vert, 10 g de tranches de gingembre, 10 g de badiane, 5 g de poivre du Sichuan. Porter à ébullition à feu vif, puis réduire à feu doux et laisser mijoter pendant 90 minutes jusqu''à ce que la peau de porc soit tendre.","Ajouter ensuite 8 g de sel, 10 g de glutamate monosodique, 15 g de bouillon de poule en poudre, 50 ml de sauce soja claire, 20 ml de sauce soja foncée pour assaisonner. Verser dans un plat. Retirer l''oignon vert, le gingembre et la badiane. Laisser refroidir jusqu''à ce que le mélange prenne une consistance de gelée.","Mettre au réfrigérateur pour refroidir. Au moment de servir, couper en petits morceaux ou en tranches épaisses."]'::jsonb, '["Plat de viande","Salé et umami","Mijoté","Nord","Accompagnement d''alcool","Dîner du Nouvel An"]'::jsonb),
  ('howtocook:meat_dish/猪肉烩酸菜', 'fr', 'Porc braisé à la choucroute', 'Plats de viande', 'Le porc braisé à la choucroute est un plat mijoté du nord de la Chine, au goût acidulé et parfumé, avec de la poitrine de porc tendre et des travers de porc savoureux. Il apporte principalement des protéines, et la choucroute fournit également des probiotiques bénéfiques. Les étapes sont claires, même un débutant peut les suivre, mais il faut mijoter patiemment pendant environ 3 heures au total.', '[{"name":"Poitrine de porc ou travers de porc","unit":"g"},{"name":"Choucroute du Nord-Est","unit":"g"},{"name":"Poireau","unit":"tige"},{"name":"Gingembre","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Sel","unit":"g"},{"name":"Sauce soja claire","unit":"g"},{"name":"Cinq-épices","unit":"g"},{"name":"Vin de cuisson","unit":"ml"},{"name":"Anis étoilé","unit":"pièce"}]'::jsonb, '["Couper le poireau en tronçons ; couper 50 g de gingembre en tronçons et 50 g en hachis ; hacher l''ail. Réserver.","Couper toute la choucroute en lanières, la rincer 2 à 3 fois à l''eau. Réserver.","Mettre les travers et la poitrine de porc dans une casserole, couvrir d''eau froide. Ajouter tous les tronçons de poireau, 50 g de gingembre en tronçons et 20 ml de vin de cuisson. Porter à ébullition à feu vif, attendre 5 minutes. Éteindre le feu, retirer les travers et la poitrine, les rincer à l''eau froide pour enlever les impuretés. Réserver.","Couper la poitrine de porc cuite en tranches ou en morceaux. Réserver.","Laver la casserole précédente et l''essuyer (sinon l''huile éclaboussera).","Ajouter de l''huile dans la casserole, chauffer à feu moyen, faire revenir le gingembre et l''ail hachés jusqu''à parfum, puis ajouter la poitrine et les travers de porc. Les faire revenir jusqu''à ce qu''ils soient dorés, verser 10 g de cinq-épices et 15 g de sauce soja claire, remuer avec une spatule pendant 1 à 2 minutes.","Ajouter la choucroute rincée dans la casserole, faire sauter pendant 3 minutes.","Verser de l''eau pure jusqu''à juste recouvrir les ingrédients, ajouter 2 morceaux d''anis étoilé, passer à feu vif jusqu''à ébullition. Réduire à feu moyen, couvrir et laisser mijoter.","Attendre 1h30 à 2 heures, jusqu''à ce que la poitrine de porc soit tendre (on peut la transpercer facilement avec une baguette).","Soulever le couvercle, passer à feu vif pour réduire le jus, remuer les ingrédients jusqu''à ce qu''il ne reste qu''une fine couche d''eau au fond, passer à feu doux. Préparer l''assaisonnement.","Assaisonnement : ajouter 10 g de sel de table, bien mélanger.","Éteindre le feu, servir."]'::jsonb, '["Plat de viande","Acidulé","Mijoté","Nordique","Familial","Accompagne le riz"]'::jsonb),
  ('howtocook:meat_dish/甜辣烤全翅', 'fr', 'Ailes de poulet entières rôties sucré-piment', 'Plats de viande', 'Cette recette d''ailes de poulet entières sucré-piment est préparée avec une friteuse à air. La peau est légèrement croustillante, la chair juteuse, et la saveur sucrée-épicée est très appréciée. Le poulet est riche en protéines de qualité. L''utilisation de la friteuse à air au lieu de la friture réduit considérablement la quantité de matière grasse, ce qui rend le plat plus léger. Le processus est clair et simple : il suffit de mariner à l''avance et de retourner une fois à mi-cuisson, ce qui est également adapté aux débutants. De la préparation à la sortie du four, il faut compter environ 3 heures, dont la majeure partie est le temps de marinade, la manipulation proprement dite n''est pas compliquée.', '[{"name":"Ailes de poulet entières","unit":"pièce"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Poudre d''ail","unit":"g"},{"name":"Poivre moulu","unit":"g"},{"name":"Sucre","unit":"g"},{"name":"Paprika doux","unit":"g"},{"name":"Piment en poudre","unit":"g"},{"name":"Sauce d''huîtres","unit":"ml"},{"name":"Eau","unit":"ml"},{"name":"Huile","unit":"ml"}]'::jsonb, '["Sortez 4 ailes de poulet entières fraîches. Fendez la peau entre les deux os du milieu de l''aile avec un couteau, une entaille de chaque côté.","Placez les 4 ailes de poulet entières dans un bol. Ajoutez 45 ml de sauce soja légère, 15 ml de sauce soja foncée, 10 g de poudre d''ail, 5 g de poivre moulu, 10 g de sucre, 10 g de paprika doux, 5 g de piment en poudre, 15 ml de sauce d''huîtres, 20 ml d''eau et 10 ml d''huile.","À l''aide d''une cuillère, répartissez uniformément la marinade sur les ailes de poulet, en particulier dans les entailles du milieu. Cela prend environ 3 minutes.","Couvrez le bol avec du film plastique pour éviter les projections et placez-le au réfrigérateur pour mariner pendant 120 minutes.","Sortez les ailes de poulet. Disposez les 4 ailes dans un plat en aluminium. Versez uniformément le reste de la marinade du bol sur les ailes.","Placez le plat en aluminium sur le panier de la friteuse à air. Faites cuire à 200 °C pendant 25 minutes.","Ouvrez la friteuse à air, retirez délicatement le plat en aluminium et retournez les ailes de poulet.","Continuez la cuisson à 200 °C pendant 25 minutes.","Sortez et servez."]'::jsonb, '["Viande","Sucré-épicé","Rôti","Friteuse à air","Apéritif","Familial"]'::jsonb),
  ('howtocook:meat_dish/田螺酿/田螺酿', 'fr', 'Escargots de rivière farcis', 'Plats de viande', 'Les escargots de rivière farcis sont le plat principal des « dix-huit farcis » de Yangshuo. La chair des escargots est ferme et élastique, la viande de porc est tendre et juteuse, et le parfum de la menthe et du shiso est enivrant. Ce plat a été présenté dans « Chinese Food » (saison 2). Riche en protéines et en oligo-éléments, l''association de la chair d''escargot et du porc offre un apport nutritionnel complémentaire. Cette recette comporte plusieurs étapes, un défi pour les débutants. Il faut prévoir une demi-journée pour faire dégorger les escargots, et la préparation proprement dite prend environ 40 minutes. Elle convient pour une activité familiale pendant les vacances.', '[{"name":"Gros escargots de rivière","unit":"pièce"},{"name":"Porc","unit":"g"},{"name":"Feuilles de menthe","unit":"g"},{"name":"Feuilles de shiso","unit":"g"},{"name":"Gingembre frais","unit":"g"},{"name":"Ciboule","unit":"tige"},{"name":"Vin de riz Sanhua","unit":"ml"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Pousses de bambou fermentées","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Piments séchés","unit":"pièce"},{"name":"Sauce d''huître","unit":"ml"},{"name":"Fécule","unit":"g"},{"name":"Poivre blanc moulu","unit":"g"}]'::jsonb, '["Le matin, acheter les escargots de rivière, les placer dans un bassin d''eau claire et les laisser reposer tout l''après-midi pour qu''ils évacuent le sable.","Ajouter quelques gouttes d''huile de sésame (ou de moutarde) dans l''eau pour accélérer l''évacuation du sable.","Brosser soigneusement les coquilles des escargots (cette étape peut prendre un peu plus de temps).","Avec une pince ou un couteau de cuisine, couper l''extrémité des escargots (environ 1/3 à la moitié).","Dans une grande casserole, porter de l''eau à ébullition, puis blanchir les escargots 1 à 2 minutes (ne pas trop cuire, la chair deviendrait dure).","Les égoutter, puis à l''aide d''un cure-dent, extraire la chair, retirer l''opercule et l''intestin noir.","Rincer les coquilles à l''eau claire, les égoutter et réserver.","Frotter la chair des escargots avec du sel, rincer, puis hacher grossièrement (ne pas réduire en purée, garder une texture granuleuse pour le croquant).","Hacher la viande de porc en chair à saucisse.","Hacher les feuilles de menthe et de shiso, émincer le gingembre, couper la ciboule en fines rondelles.","Mettre dans un bol la chair d''escargot hachée, le porc haché, la menthe hachée, le shiso haché, le gingembre émincé et la ciboule.","Ajouter 15 ml de vin de riz Sanhua, 15 ml de sauce soja légère, 3 g de sel.","Optionnel : ajouter 10 ml de sauce d''huître, 2 g de poivre blanc, 10 g de fécule.","Mélanger dans le même sens jusqu''à ce que la farce soit élastique et collante.","Pour gagner du temps, on peut mettre tous les ingrédients dans un hachoir électrique et mixer directement.","Avec des baguettes, farcir les coquilles d''escargots en tassant bien sans les casser.","Farcir ainsi tous les escargots.","Chauffer une poêle, verser 30 ml d''huile de cuisson, optionnel : ajouter les pousses de bambou fermentées et les piments séchés et faire revenir jusqu''à ce qu''ils soient parfumés.","Verser environ 300 ml d''eau ou de bouillon, ajouter 15 ml de sauce soja légère, 2 g de sel, porter à ébullition à feu vif.","Placer les escargots farcis dans la poêle, couvrir et laisser mijoter à feu moyen-doux pendant 10 minutes.","Ne pas trop remuer pendant la cuisson ; lorsque la farce est à moitié cuite et prise, remuer doucement.","Ouvrir le couvercle, ajouter les feuilles de menthe et de shiso fraîches restantes, couvrir et laisser encore 2 à 3 minutes.","À feu vif, réduire la sauce jusqu''à ce qu''elle soit épaisse, puis servir."]'::jsonb, '["Plat de viande","Savoureux","Farcis","Mijoté","Cuisine du Guangxi","Pour invités"]'::jsonb),
  ('howtocook:meat_dish/番茄红酱', 'fr', 'Sauce rouge à la tomate', 'Plats de viande', 'Cette sauce de style italien est savoureuse et riche, la combinaison de légumes et de bœuf apporte une texture riche. Elle est riche en protéines et en plusieurs vitamines, avec une nutrition équilibrée. La préparation est un peu fastidieuse et nécessite quelques compétences culinaires de base, comme faire sauter le bœuf pour qu''il soit granuleux et contrôler le feu pour une cuisson lente. De la préparation à la fin, il faut environ une heure. On peut en faire une plus grande quantité et la congeler, très pratique à utiliser.', '[{"name":"Bœuf haché","unit":"g"},{"name":"Gousses d''ail","unit":"pièce"},{"name":"Carotte","unit":"pièce"},{"name":"Céleri","unit":"pièce"},{"name":"Oignon","unit":"pièce"},{"name":"Huile d''olive","unit":"ml"},{"name":"Sucre","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Poivre noir moulu","unit":"g"},{"name":"Sauce tomate","unit":"g"},{"name":"Lait","unit":"ml"},{"name":"Basilic sec ou thym (facultatif)","note":"quantité suffisante"}]'::jsonb, '["Hacher les carottes, le céleri et l''oignon, et trancher les gousses d''ail.","Ajouter 10 ml d''huile d''olive, chauffer l''huile, faire sauter les légumes à feu vif jusqu''à ce qu''ils commencent légèrement à changer de couleur, puis retirer.","Ajouter 10 ml d''huile dans la casserole, faire revenir l''ail 10 secondes, ajouter le bœuf haché, le sucre, le sel, le poivre et les épices, faire revenir le bœuf jusqu''à ce qu''il soit croustillant (granuleux).","Ajouter les légumes sautés et la sauce tomate, continuer à faire revenir en mélangeant bien.","Verser le lait petit à petit en plusieurs fois, cuire à feu moyen-doux pendant 30 minutes, c''est prêt."]'::jsonb, '["Plat de viande","Italien","Mijoté","Sauce","Accompagnement","Maison"]'::jsonb),
  ('howtocook:meat_dish/瘦肉土豆片/瘦肉土豆片', 'fr', 'Porc maigre et pommes de terre sautés', 'Plats de viande', 'Un plat sauté rapide et familial, avec des tranches de viande tendres et des pommes de terre fondantes et imprégnées de saveur, accompagnées d''un parfum frais de pousses d''ail. De style typiquement familial. Le porc maigre est riche en protéines de qualité et en fer, les pommes de terre apportent glucides et fibres, pour un équilibre parfait. La préparation est simple et claire, nécessitant de l''attention pour le tranchage et la cuisson, idéale pour les débutants un peu expérimentés. De la préparation à la finition, comptez environ 1 heure.', '[{"name":"Porc maigre","unit":"g"},{"name":"Pommes de terre","unit":"g"},{"name":"Pousses d''ail","unit":"tige"},{"name":"Fécule de maïs","unit":"g"},{"name":"Sauce soja claire","unit":"g"},{"name":"Sauce soja foncée","unit":"g"},{"name":"Sel de table","unit":"g"},{"name":"Huile de cuisson","unit":"ml"}]'::jsonb, '["Éplucher les pommes de terre, les couper en deux, puis les trancher en fines lamelles d''environ 2 mm, réserver.","Laver les pousses d''ail, les couper en tronçons d''environ 1 cm, réserver.","Laver le porc maigre et le trancher en fines lamelles d''environ 2 mm, les mettre dans un bol, ajouter 5 g de fécule de maïs, 5 g de sauce soja claire, 3 g de sauce soja foncée, laisser mariner dix minutes, réserver.","Pendant la marinade, porter une casserole d''eau à ébullition, blanchir les lamelles de pommes de terre dans l''eau bouillante pendant environ 5 minutes.","Chauffer une poêle, y verser 10 ml à 15 ml d''huile de cuisson. Attendre 10 secondes pour que l''huile chauffe.","Ajouter le porc mariné, faire sauter jusqu''à ce qu''il change de couleur, puis ajouter les pousses d''ail, faire sauter ensemble environ 20 secondes.","Ajouter les pommes de terre, continuer à faire sauter, ajouter 2 g de sel de table et 5 g de sauce soja claire.","Faire sauter environ 3 minutes, puis dresser dans un plat."]'::jsonb, '["Plat de viande","Fait maison","Rapide","Sauté","Accompagnement du riz","Parfumé"]'::jsonb),
  ('howtocook:meat_dish/白菜猪肉炖粉条', 'fr', 'Porc et chou chinois braisés aux vermicelles', 'Plats de viande', 'Le ragoût de porc, chou chinois et vermicelles est un plat mijoté classique de la région du Nord-Est de la Chine. La sauce est riche et salée, la poitrine de porc fondante, les vermicelles imprégnés de la saveur de la viande sont lisses et élastiques, et le chou chinois apporte une douceur qui coupe le gras. Ce plat équilibré allie viande et légumes, offrant protéines, vitamines et glucides pour un repas nourrissant. La préparation demande un peu de patience, surtout pour le traitement des vermicelles et la maîtrise du feu, ce qui peut être un défi pour les débutants, mais en suivant les étapes, c''est facile à réussir. Comptez environ 45 minutes du début à la fin.', '[{"name":"poitrine de porc","unit":"g"},{"name":"chou chinois","unit":"g"},{"name":"vermicelles de pomme de terre séchés","unit":"g"},{"name":"treize épices","unit":"g"},{"name":"bouillon de poule","unit":"g"},{"name":"sel","unit":"g"},{"name":"sauce soja foncée","unit":"ml"},{"name":"sauce soja claire","unit":"ml"}]'::jsonb, '["Faire bouillir de l''eau dans une casserole. Une fois à ébullition, ajouter les vermicelles secs, cuire 5 minutes puis verser le tout dans un récipient avec l''eau. Couvrir et laisser tremper jusqu''à utilisation (faire ceci en premier, pendant ce temps, effectuer les étapes suivantes).","Couper la poitrine de porc en tranches de 3 mm, réserver.","Séparer les feuilles tendres du chou chinois des côtes, puis couper le tout en morceaux de taille moyenne. Réserver.","Chauffer une casserole, ajouter 10 à 15 ml d''huile de cuisson. Attendre 10 secondes pour que l''huile chauffe.","Ajouter la poitrine de porc et faire sauter jusqu''à ce que la viande change de couleur.","Ajouter la sauce soja foncée, faire sauter 1 minute pour colorer la viande.","Ajouter les côtes de chou, le sel et la sauce soja claire, faire sauter 1 minute (si ça attache, ajouter 10 ml d''eau).","Ajouter de l''eau à hauteur des ingrédients, ajouter le bouillon de poule et les treize épices. Porter à ébullition, puis réduire le feu et laisser mijoter 20 minutes.","Égoutter les vermicelles, les couper en petits morceaux et les mettre dans un bol, réserver.","Ajouter les feuilles tendres de chou, mélanger, puis déposer les vermicelles sur le dessus. Couvrir et cuire encore 5 minutes.","Goûter, éteindre le feu et laisser la sauce épaissir."]'::jsonb, '["Plat de viande","Cuisine du Nord-Est chinois","Ragoût maison","Salé et savoureux","Accompagnement de riz","Équilibré viande-légumes"]'::jsonb),
  ('howtocook:meat_dish/空气炸锅脆皮现腌炸鸡/空气炸锅脆皮现腌炸鸡', 'fr', 'Poulet frit croustillant à l''air fryer (marinade maison)', 'Plats de viande', 'L''air fryer chicken est un plat de viande maison mariné puis frit, à la croûte croustillante et à l''intérieur juteux, l''assaisonnement peut être adapté selon les goûts. Les ailes de poulet sont riches en protéines et en graisses de qualité, idéales comme plat principal ou en-cas. Comptez environ 55-70 minutes (avec une panure ; si double panure, environ 70-90 minutes). Pour un meilleur résultat, vous pouvez laisser mariner au réfrigérateur toute la nuit (préparer la veille, frire le lendemain).', '[{"name":"Ailes de poulet","unit":"pièce"},{"name":"Sauce soja","unit":"ml"},{"name":"Ail en poudre","unit":"g"},{"name":"Paprika (poudre de poivron rouge)","unit":"g"},{"name":"Oignon en poudre","unit":"g"},{"name":"Poivre noir moulu","unit":"g"},{"name":"Farine tout usage","unit":"g"},{"name":"Fécule de maïs","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Yaourt ou lait","unit":"ml"},{"name":"Œuf","unit":"pièce"},{"name":"Levure chimique","unit":"g"}]'::jsonb, '["Lavez et séchez les ailes de poulet. Faites deux entailles de chaque côté pour une meilleure imprégnation.","Préparez la marinade : mélangez 15 ml de sauce soja, 8 g d''ail en poudre, 5 g de paprika, 3 g d''oignon en poudre, 3 g de poivre noir, et 5 ml de lait ou de yaourt grec (optionnel, pour attendrir le poulet). Remuez bien.","Mettez la marinade et les ailes dans un grand sac de congélation. Massez bien pour enrober, puis laissez reposer au réfrigérateur toute une nuit.","Préparez la panure : mélangez 60 g de farine tout usage, 30 g de fécule de maïs, 5 g d''ail en poudre, 5 g de paprika, 2 g d''oignon en poudre, 2 g de poivre noir, et 1 g de levure chimique (optionnel, pour plus de croustillant). Remuez bien.","Préparez la pâte à frire (optionnelle) : battez 1 œuf avec 5 ml de lait ou d''eau.","Panure : égouttez les ailes, puis enrobez-les de panure en pressant légèrement. Secouez l''excédent et laissez reposer 10 minutes.","Pâte à frire (optionnelle) : pour une croûte plus épaisse, trempez dans la pâte puis répétez l''étape de panure.","Trempez les ailes panées dans la pâte à frire, puis secouez légèrement pour retirer l''excédent.","Remettez-les dans la panure, pressez légèrement, et secouez l''excédent.","Laissez reposer 20 minutes (ou plus si possible, pour une croûte plus stable).","Préchauffez l''air fryer à 180°C pendant 5 minutes.","Huilez légèrement le panier. Placez les ailes côté peau vers le bas. Vaporisez ou badigeonnez d''huile.","Cuire à 180°C pendant 10 minutes.","Ouvrez le panier, retournez les ailes, vaporisez ou badigeonnez à nouveau d''huile, puis cuire encore 6 minutes à 180°C.","Vérifiez la couleur de la peau. Piquez la partie la plus épaisse avec un cure-dent pour voir si du sang s''écoule.","Si nécessaire, cuire encore 1-2 minutes à 200°C pour plus de croustillant et de coloration (procédez par itérations : 1 minute, puis vérifiez)."]'::jsonb, '["Viande","Croustillant","Ail","Air fryer","Maison","Plat principal"]'::jsonb),
  ('howtocook:meat_dish/粉蒸肉', 'fr', 'Porc cuit à la vapeur avec farine de riz', 'Plats de viande', 'Le porc cuit à la vapeur avec farine de riz est un plat chinois classique, riche en arômes, avec une texture tendre et moelleuse, un goût familial répandu. La poitrine de porc fournit des protéines de qualité et des graisses, accompagnée de légumes racines comme les pommes de terre, pour un équilibre nutritionnel. Ce plat convient aux cuisiniers ayant une certaine expérience, et nécessite environ 90 minutes de la préparation à la finition.', '[{"name":"Poitrine de porc","unit":"g"},{"name":"Farine de riz pour cuisson vapeur","unit":"g"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Vin de riz","unit":"ml"},{"name":"Pâte de haricots Pixian","unit":"g"},{"name":"Gingembre haché","unit":"g"},{"name":"Ail haché","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Pommes de terre ou citrouille","unit":"g"},{"name":"Eau claire","unit":"ml"}]'::jsonb, '["Lavez la poitrine de porc et coupez-la en tranches d''environ 5 cm de long, 3 cm de large et 0,5 cm d''épaisseur.","Hachez le gingembre et l''ail en fines particules d''un diamètre ne dépassant pas 1 mm.","Dans un grand bol, placez la poitrine de porc coupée, 15 ml de sauce soja légère, 10 ml de sauce soja foncée, 15 ml de vin de riz, 10 g de pâte de haricots Pixian, 10 g de gingembre haché, 10 g d''ail haché, 5 g de sucre blanc.","Mélangez bien avec des baguettes, puis couvrez de film plastique et laissez mariner à température ambiante (20°C - 25°C) pendant 30 minutes.","Après la marinade, ajoutez 100 g de farine de riz pour cuisson à la vapeur, et mélangez pendant 2 minutes pour que chaque tranche soit bien enrobée.","Épluchez les pommes de terre et coupez-les en tranches d''environ 0,8 cm d''épaisseur, d''une surface d''environ 5 cm x 5 cm, pour un poids total de 300 g.","Dans un bol profond de 20 cm de diamètre, tapissez le fond de tranches de pomme de terre sans les chevaucher.","Disposez uniformément la poitrine de porc enrobée sur les pommes de terre et tassez bien.","Ajoutez 2000 ml d''eau claire dans un cuit-vapeur et portez à ébullition (100°C).","Placez le bol avec les ingrédients dans le cuit-vapeur et couvrez.","Faites cuire à la vapeur à feu moyen pendant 60 minutes (en maintenant une ébullition constante, environ 600 W de puissance).","Après le temps de cuisson, insérez une baguette au centre de la viande ; si elle pénètre facilement sans résistance, la cuisson est terminée.","Si ce n''est pas le cas, poursuivez la cuisson pendant 10 à 15 minutes jusqu''à ce que la viande soit tendre et que la graisse suinte.","Retirez du cuit-vapeur, servez dans un plat et dégustez."]'::jsonb, '["Plat de viande","Cuisine sichuanaise","Cuisson à la vapeur","Tendre et moelleux","Accompagnement de riz","Familial"]'::jsonb),
  ('howtocook:meat_dish/糖醋排骨/糖醋排骨', 'fr', 'Travers de porc aigre-doux', 'Plats de viande', 'Le travers de porc aigre-doux est un plat traditionnel célèbre, à la fois sucré et acidulé, croustillant à l''extérieur et tendre à l''intérieur, très apprécié. Le travers de porc est riche en protéines de haute qualité et en calcium, avec de bons effets tonifiants. Cette recette implique plusieurs étapes comme le blanchiment, la friture, la caramélisation du sucre et la réduction de la sauce, avec des exigences en matière de température et d''assaisonnement. Elle n''est pas idéale pour les débutants, mais en suivant le processus optimisé, le taux de réussite est élevé. Le temps de préparation estimé est d''environ 45 minutes.', '[{"name":"Travers de porc","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sauce d''huîtres","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Bouillon de poulet en poudre","unit":"g"},{"name":"Tranches de gingembre","unit":"tranche"},{"name":"Graines de sésame","unit":"g"},{"name":"Ketchup","unit":"g"},{"name":"Vinaigre aromatique","unit":"ml"},{"name":"Cinq épices","unit":"g"}]'::jsonb, '["Mettez les travers de porc et les tranches de gingembre dans de l''eau froide, portez à ébullition à feu vif. Lorsque de nombreuses bulles apparaissent, réduisez à feu moyen. Une fois que l''eau bout continuellement, réduisez à feu doux et blanchissez pendant 2–3 minutes. Égouttez et réservez.","Lavez les travers de porc à l''eau bouillante 2–3 fois pour éliminer complètement les impuretés.","Versez suffisamment d''huile de cuisson dans une casserole pour une friture profonde (la quantité d''huile dépend de la taille de la casserole, environ 300 ml pour une utilisation domestique). Lorsque l''huile atteint environ 170°C, faites frire les travers de porc pendant 3–5 minutes jusqu''à ce qu''ils soient légèrement dorés. Égouttez et retirez l''excès d''huile.","Dans une autre casserole propre, chauffez 50 ml d''eau chaude à feu doux, ajoutez 30 g de sucre blanc et remuez doucement jusqu''à ce que le sucre soit complètement dissous et légèrement jaune. L''objectif est d''observer la dissolution du sucre, sans trop se fier au changement de couleur.","Versez les travers de porc frits dans la casserole avec le sucre caramélisé. Faites sauter rapidement pendant 30 secondes, puis ajoutez successivement 5 ml de vinaigre aromatique, 5 ml de sauce soja légère, 5 ml de sauce d''huîtres, 2 g de bouillon de poulet en poudre, 10 g de ketchup, 0,5 g de cinq épices. Faites sauter à nouveau pendant 30 secondes pour bien enrober les travers de porc. Ajoutez ensuite de l''eau bouillante jusqu''à ce qu''elle recouvre à peine la viande.","Portez le liquide à ébullition à feu vif, puis ajoutez 5 ml de sauce soja foncée pour colorer et réduisez rapidement la sauce. Si les morceaux de travers sont gros, vous pouvez réduire à feu doux et laisser mijoter pendant 5–10 minutes pour mieux imprégner la saveur. N''utilisez surtout pas de feu moyen pendant une longue cuisson de 20 minutes, car cela nuirait à la texture.","Retirez du feu, dressez dans une assiette et saupoudrez de 2 g de graines de sésame. Servez."]'::jsonb, '["Plat de viande","Aigre-doux","Frit","Maison","Accompagnement","Pour invités"]'::jsonb),
  ('howtocook:meat_dish/糖醋里脊', 'fr', 'Porc aigre-doux', 'Plats de viande', 'Le porc aigre-doux est à la fois aigre et sucré, croustillant à l''extérieur et tendre à l''intérieur. C''est une saveur familiale très appréciée, courante dans de nombreuses cuisines régionales. Le filet de porc fournit des protéines de qualité, mais l''enrobage et la friture ainsi que la sauce aigre-douce augmentent l''apport calorique. La préparation nécessite de maîtriser la marinade, la double friture et le réglage de la sauce, ce qui peut être un défi pour les débutants. Il est conseillé de préparer tous les ingrédients à l''avance et de cuisiner d''une traite. Du début à la fin, cela prend environ 45 minutes à 1 heure.', '[{"name":"filet de porc","unit":"g"},{"name":"vinaigre","unit":"g"},{"name":"sucre blanc","unit":"g"},{"name":"fécule","unit":"g"},{"name":"œuf","unit":"g"},{"name":"sauce soja légère","unit":"ml"},{"name":"vin de cuisine","unit":"g"},{"name":"sauce d''huître","unit":"g"},{"name":"ketchup","unit":"ml"},{"name":"poivre blanc","unit":"g"},{"name":"sel","unit":"g"}]'::jsonb, '["Mariner la viande : couper le filet de porc en tranches épaisses, les attendrir avec le dos du couteau. Couper en bâtonnets de l''épaisseur d''un doigt. Ajouter le vin de cuisine, la sauce soja légère, la sauce d''huître, le sel, le poivre blanc, un œuf. Bien mélanger avec les mains et laisser mariner au moins 20 minutes.","Préparer la sauce : mélanger le ketchup, 10 g de vinaigre, 30 g de sucre blanc, 150 ml d''eau. Remuer jusqu''à dissolution du sucre. Réserver.","Enrober : préparer tous les bâtonnets enrobés avant de frire pour éviter de s''affoler. Mettre la fécule dans un grand bol, enrober chaque bâtonnet de fécule généreusement.","Frire : chauffer l''huile à 160 °C. Tester avec une baguette sèche : si de petites bulles se forment autour, c''est prêt. Plonger les bâtonnets.","Frire jusqu''à ce qu''ils soient légèrement dorés, puis retirer. Maintenir le feu moyen. Ensuite, augmenter la température de l''huile à 200 °C et plonger à nouveau les bâtonnets pendant seulement 40 secondes pour qu''ils soient croustillants. Retirer immédiatement.","Enrober de sauce : dans une autre poêle, mettre un peu d''huile, verser la sauce préparée et porter à ébullition. Ajouter les bâtonnets frits et remuer pour bien les enrober.","Ajouter les bâtonnets frits, remuer, puis éteindre le feu et servir."]'::jsonb, '["Plat de viande","Aigre-doux","Friture","Familial","Pour invités","Accompagnement du riz"]'::jsonb),
  ('howtocook:meat_dish/红烧猪蹄/红烧猪蹄', 'fr', 'Pieds de porc braisés au soja', 'Plats de viande', 'Les pieds de porc braisés au soja sont un plat familial classique avec une sauce riche et une viande tendre et moelleuse. Salé, sucré et délicieux, il est parfait pour accompagner le riz. Les pieds de porc sont riches en collagène et en protéines, ce qui les rend nutritifs. Ce plat peut être un défi pour les débutants, mais l''utilisation d''un autocuiseur simplifie le processus ; une certaine expérience culinaire facilite la tâche. Il faut environ 1 heure de la préparation à la finition.', '[{"name":"Pieds de porc","unit":"pièce"},{"name":"Feuille de laurier","unit":"feuille"},{"name":"Gingembre","unit":"tranche"},{"name":"Oignon vert","unit":"tige"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Bâton de cannelle","unit":"morceau"},{"name":"Sucre candi","unit":"morceau"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Anis étoilé","unit":"étoile"},{"name":"Huile de cuisson","unit":"ml"}]'::jsonb, '["Dans une casserole d''eau froide, placez les pieds de porc déjà coupés par le vendeur attentionné, ajoutez 20 ml de vin de cuisine et de l''oignon vert et du gingembre, faites bouillir 15 minutes pour éliminer le sang.","Dans une poêle chaude avec de l''huile froide, versez 30 ml d''huile de cuisson, ajoutez 7-8 morceaux de sucre candi, allumez à feu doux, caramélisez le sucre jusqu''à ce qu''il prenne une couleur ambrée, en écrasant les morceaux avec une spatule, environ 2 minutes.","Une fois le sucre caramélisé, ajoutez les pieds de porc blanchis, continuez à feu doux, faites sauter les pieds de porc jusqu''à ce qu''ils soient légèrement dorés des deux côtés.","Ajoutez 2 feuilles de laurier, 1 morceau de bâton de cannelle, 4 étoiles d''anis, 20 ml de sauce soja légère, 20 ml de sauce soja foncée, 10 ml de vin de cuisine, 3 tranches de gingembre, 8 g de sel, passez à feu moyen, continuez à faire sauter pendant 1 minute.","Ajoutez de l''eau bouillante ou froide, suffisamment pour couvrir les pieds de porc, couvrez, portez à ébullition à feu vif, puis éteignez le feu.","Versez tout le contenu de la casserole dans un autocuiseur, faites cuire sous pression pendant 15 minutes (si vous n''avez pas d''autocuiseur, vous pouvez laisser mijoter à feu doux après ébullition dans une casserole ordinaire).","Après 15 minutes, versez le contenu de l''autocuiseur dans une poêle, faites réduire la sauce à feu vif. Goûtez avec des baguettes, si c''est trop fade, ajoutez 2-3 g de sel.","Le temps de réduction dépend de la quantité de liquide, généralement 30 secondes suffisent. Il n''y a pas de mal à laisser un peu plus de sauce, elle est aussi délicieuse avec du riz."]'::jsonb, '["Plat de viande","Salé et parfumé","Tendre et moelleux","Braises au soja","Accompagnement de riz","Familial"]'::jsonb),
  ('howtocook:meat_dish/红烧肉/南派红烧肉', 'fr', 'Porc braisé façon Sud', 'Plats de viande', 'Ce porc braisé se présente avec une couleur rouge brillante, le gras fond dans la bouche, le maigre est tendre sans être sec, salé avec une touche sucrée, typique du style sucré du Sud. La poitrine de porc apporte des protéines de qualité et du collagène, les épices éliminent les odeurs et réchauffent l''estomac. La préparation nécessite de caraméliser le sucre et de mijoter lentement, mais chaque étape est clairement expliquée, même les débutants peuvent réussir en suivant les instructions. Comptez environ 1h30 pour le servir.', '[{"name":"poitrine de porc","unit":"g"},{"name":"huile","unit":"ml"},{"name":"sucre candi","unit":"g"},{"name":"sucre blanc","unit":"g"},{"name":"sauce soja foncée","unit":"ml"},{"name":"vin de cuisson","unit":"ml"},{"name":"feuille de laurier","unit":"feuille"},{"name":"badiane","unit":"pièce"},{"name":"gingembre","unit":"tranche"},{"name":"oignon vert","unit":"g"},{"name":"ail","unit":"g"},{"name":"sel","unit":"g"},{"name":"poivre de Sichuan","unit":"g"},{"name":"eau froide","unit":"ml","note":"Quantité suffisante pour couvrir les ingrédients"},{"name":"eau bouillante","unit":"ml","note":"Quantité suffisante pour couvrir les ingrédients"}]'::jsonb, '["Couper la poitrine de porc en gros morceaux (environ 5-6 cm de large) sans la couper trop petit, afin qu''ils puissent tenir dans la casserole.","Couper le gingembre en tranches (environ 3 mm d''épaisseur).","Faire bouillir de l''eau.","Utiliser de l''eau froide du robinet.","Couper la partie blanche des oignons verts en petits tronçons (de préférence des oignons verts, mais des oignons nouveaux peuvent aussi convenir).","Couper l''ail en deux dans le sens de la longueur, sans l''écraser, sinon il sera difficile à retirer et affectera la saveur lors de la réduction de la sauce.","Diviser les ingrédients en deux « paquets préparatoires » :","Paquet A (pour supprimer l''odeur) : 2 tranches de gingembre, 2 tronçons d''oignon vert.","Paquet B (pour la cuisson) : les 4 tranches de gingembre restantes, les parties blanches des oignons verts, les gousses d''ail, le poivre de Sichuan, la badiane et les feuilles de laurier, le tout dans un petit bol.","Dans une casserole d''eau froide, ajouter les gros morceaux de poitrine de porc, 20 ml de vin de cuisson et le paquet A. Faire bouillir 15 minutes pour éliminer le sang, puis égoutter et rincer.","Sortir la poitrine de porc blanchie, la laisser refroidir légèrement (jusqu''à ce qu''elle ne brûle plus), puis la couper en cubes d''environ 3 cm de côté (après blanchiment, la viande se resserre, il est plus facile de couper et les morceaux sont plus uniformes. Les cubes de 3 cm donneront environ 2,5 cm après cuisson, taille idéale pour une bouchée et une cuisson parfaite).","Dans une autre casserole, préparer le caramel de sucre. Important : dans cette recette, utiliser la « méthode 2 » : lorsque le sucre forme de petites bulles denses, ajouter rapidement le paquet B (gingembre, oignon, ail, poivre de Sichuan, badiane, feuilles de laurier) et faire revenir pour libérer les arômes.","Après avoir dégagé les arômes (environ 5-10 secondes), ne pas ajouter d''eau bouillante tout de suite. Ajouter immédiatement la poitrine de porc blanchie et faire sauter à feu vif pour enrober uniformément la viande de caramel et faire fondre le gras. Lorsque l''odeur de la viande se dégage, ajouter de l''eau bouillante à hauteur, couvrir et mijoter à feu moyen-doux pendant 50 à 60 minutes (40 minutes à l''autocuiseur).","Ajouter 10 ml de vin de cuisson.","Couvrir et porter à ébullition. Toutes les 25 minutes, ouvrir le couvercle et retirer la graisse et les impuretés qui flottent à la surface.","Lorsque le niveau d''eau atteint environ 3/5 de la hauteur de la viande par rapport au fond de la casserole, passer à feu moyen. Retirer tous les ingrédients sauf la viande et l''eau, et commencer à réduire la sauce.","Ouvrir le couvercle, lorsque la sauce est presque évaporée et devient sirupeuse, retirer du feu (attention à ne pas la réduire à sec)."]'::jsonb, '["Plat de viande","Cuisine du Sud","Braised","Sucré","Accompagnement riz","Familial"]'::jsonb),
  ('howtocook:meat_dish/红烧肉/简易红烧肉', 'fr', 'Porc braisé (Hongshao)', 'Plats de viande', 'Ce plat familial, brillant et d''un rouge appétissant, est tendre et fondant, gras mais pas écœurant, avec une riche sauce parfumée. Il se marie parfaitement avec du riz. La poitrine de porc fournit des protéines de qualité et des acides gras essentiels, et l''ajout d''œufs de caille ou de tofu séché rend le plat encore plus nutritif. La recette est très accessible aux débutants : de la préparation à la cuisson, comptez environ 1 h 30.', '[{"name":"Poitrine de porc","unit":"livre","note":""},{"name":"Œufs de caille ou œufs","unit":"pièce(s)","note":""},{"name":"Tofu séché","unit":"g","note":""},{"name":"Gingembre","unit":"tranche(s)","note":""},{"name":"Sucre candi (glace)","unit":"g","note":""},{"name":"Sauce soja claire","unit":"ml","note":""},{"name":"Sauce soja foncée","unit":"ml","note":""},{"name":"Vin de cuisson (ou vin de riz)","unit":"ml","note":""},{"name":"Feuilles de laurier","unit":"pièce(s)","note":""},{"name":"Badiane (anis étoilé)","unit":"pièce(s)","note":""},{"name":"Sel","unit":"g","note":""},{"name":"Eau","unit":"ml","note":""},{"name":"Oignons verts","note":"Partie blanche, quantité suffisante"}]'::jsonb, '["Couper la poitrine de porc en gros morceaux (environ 4,5 cm ; il est plus facile de couper après 30 min à 1 h au congélateur)","Couper le tofu séché en lanières de 2 cm de large","Trancher le gingembre (chaque tranche d''environ 3 mm d''épaisseur)","Faire bouillir de l''eau","Faire cuire les œufs de caille et les piquer avec une fourchette ou un cure-dent (le plus possible pour qu''ils s''imprègnent bien)","Partie blanche des oignons verts","Dans une casserole d''eau froide, mettre les morceaux de poitrine de porc, ajouter le vin de cuisson et les oignons verts et le gingembre, faire bouillir 15 minutes pour enlever le sang","Mettre deux tranches de gingembre dans la casserole pour parfumer","À feu moyen-doux, ajouter directement la poitrine de porc sans huile, faire dorer chaque face (six faces) jusqu''à ce que la graisse fonde","Verser la graisse fondue et la réserver, pousser la poitrine sur le côté, ajouter 15 g de sucre candi, remuer jusqu''à ce que le sucre fonde","Une fois fondu, mélanger la poitrine et le sucre pour la colorer, ajouter","Sauce soja claire 10 ml","Sauce soja foncée 15 ml","Vin de cuisson 5 ml","Remuer pour colorer","Ajouter de l''eau bouillante et laisser mijoter 40 minutes (les débutants qui coupent trop gros doivent augmenter le temps), puis ajouter","Gingembre 2 tranches","Feuilles de laurier 3","Badiane 2","Couvrir et porter à ébullition, puis ajouter les œufs de caille cuits et piqués et le tofu séché, baisser à feu moyen-doux et laisser cuire 40 minutes (remuer de temps en temps pour éviter que ça n''attache)","Ouvrir le couvercle, quand il ne reste presque plus de sauce, augmenter le feu pour faire réduire (ne pas réduire à sec)","Ajouter 2-3 g de sel, remuer, et servir"]'::jsonb, '["Viande","Familial","Accompagne le riz","Mijoté","Sauce parfumée","Tendre et moelleux"]'::jsonb),
  ('howtocook:meat_dish/红烧鸡翅', 'fr', 'Ailes de poulet braisées (红烧鸡翅)', 'Plats de viande', 'Les ailes de poulet braisées sont un plat familial qui accompagne bien le riz. Elles sont salées et légèrement sucrées, d''une couleur rouge brillante, avec une viande tendre qui se détache facilement des os. Les ailes de poulet sont riches en protéines de haute qualité et en collagène, faciles à absorber. La difficulté est modérée ; les débutants peuvent suivre les étapes facilement. Du début à la fin, il faut environ 40 minutes.', '[{"name":"ailes de poulet fraîches","unit":"grammes"},{"name":"tranches de gingembre","unit":"grammes"},{"name":"morceaux de ciboule","unit":"grammes"},{"name":"ail","unit":"grammes"},{"name":"feuille de laurier","unit":"feuille"},{"name":"anis étoilé","unit":"pièce"},{"name":"piments séchés","unit":"pièce"},{"name":"sucre candi (glace)","unit":"grammes"},{"name":"vin de riz jaune ou vin de cuisine","unit":"ml"},{"name":"sauce soja légère","unit":"ml"},{"name":"sauce soja foncée","unit":"ml"},{"name":"sel","unit":"grammes"},{"name":"sucre blanc","unit":"grammes"},{"name":"poivre blanc moulu","unit":"grammes"},{"name":"graines de sésame blanc","unit":"grammes"},{"name":"ciboule ciselée","unit":"grammes"},{"name":"huile de cuisson","unit":"ml"}]'::jsonb, '["Lavez les ailes de poulet. À l''aide d''un couteau, faites trois entailles sur la partie épaisse et une entaille sur le dos pour mieux imprégner les saveurs.","Si les ailes ne sont pas fraîches, après les avoir entaillées, faites-les tremper dans de l''eau gingembre pendant 10 à 20 minutes.","Préparez 10 grammes de tranches de gingembre (3-4 tranches), 15 grammes de morceaux de ciboule (2-3 morceaux) ; 3-4 gousses d''ail (environ 15 grammes) écrasées avec un couteau (sans les hacher) ; 1 feuille de laurier, 1 anis étoilé, 2 piments séchés (optionnel), réservez.","Mettez une casserole sur le feu, ajoutez assez d''eau froide pour couvrir toutes les ailes, puis ajoutez les ailes préparées, 20 ml de vin de riz jaune ou de vin de cuisine, 2 tranches de gingembre (environ 5 grammes). Portez à ébullition à feu vif, puis maintenez l''ébullition 2-3 minutes en écumant les impuretés.","Égouttez les ailes, rincez-les 2 fois à l''eau tiède pour éliminer complètement les impuretés, puis égouttez-les bien et réservez.","Dans une autre casserole, chauffez à feu vif puis ajoutez 10-15 ml d''huile de cuisson.","Lorsque l''huile est à 50% de chaleur, ajoutez 15 grammes de sucre candi (glace). Faites chauffer à feu vif jusqu''à ce que le sucre soit complètement fondu. Lorsqu''il change de couleur, passez à feu doux et continuez à remuer jusqu''à ce que le sucre prenne une couleur rouge foncé (couleur de jujube). Ajoutez immédiatement les ailes égouttées et faites-les sauter rapidement 1-2 minutes pour que chaque aile soit uniformément enrobée de caramel.","Ajoutez la feuille de laurier, l''anis étoilé, les 2 piments séchés (optionnel), les 2 tranches de gingembre restantes (environ 5 grammes), les 15 grammes de morceaux de ciboule et l''ail écrasé. Faites sauter encore 30 secondes jusqu''à ce que les arômes des épices se libèrent.","Versez 15 ml de vin de cuisine ou de vin de riz jaune le long du bord de la casserole, puis 15 ml de sauce soja légère. Faites sauter rapidement 10 secondes.","Ajoutez de l''eau tiède (environ 50-60°C) jusqu''à ce que les ailes soient juste couvertes.","Ajoutez 5 ml de sauce soja foncée, 3 grammes de sel, 2 grammes de sucre blanc, 1 gramme de poivre blanc moulu. Mélangez doucement avec une spatule.","Couvrez et laissez cuire à feu moyen pendant 7-8 minutes.","Retirez le couvercle, utilisez des baguettes pour retirer la feuille de laurier, l''anis étoilé, les tranches de gingembre, les morceaux de ciboule et l''ail, puis jetez-les.","Passez à feu vif et remuez continuellement jusqu''à ce que la sauce épaississe (environ 1-2 minutes).","Éteignez le feu, déposez les ailes dans une assiette et nappez-les de la sauce épaisse restante.","Saupoudrez de 3 grammes de graines de sésame blanc et 5 grammes de ciboule ciselée. C''est prêt !"]'::jsonb, '["Viande","Familial","Accompagnement du riz","Salé et umami","Braisé","Pour invités"]'::jsonb),
  ('howtocook:meat_dish/羊排焖面/羊排焖面', 'fr', 'Côtes d''agneau braisées aux nouilles', 'Plats de viande', 'Les côtes d''agneau braisées aux nouilles sont un plat familial du nord, riche en saveur de viande et aux nouilles al dente. Les côtes sont tendres, les larges nouilles absorbent bien le jus, chaque bouchée est satisfaisante. Ce plat contient de la viande, des nouilles et des légumes, un repas complet apportant protéines, glucides et lipides nécessaires au corps, une nutrition équilibrée. La préparation nécessite d''abord de braiser les côtes, puis de pétrir la pâte et d''étouffer les nouilles, les étapes sont un peu nombreuses, plus adapté aux cuisiniers ayant un peu d''expérience, le temps total estimé est d''environ une heure et demie.', '[{"name":"Côtes d''agneau avec peau","unit":"gramme"},{"name":"Poivron vert","unit":"pièce"},{"name":"Poivron doux","unit":"pièce"},{"name":"Oignon vert","note":"selon besoin"},{"name":"Poivre de Sichuan","note":"selon besoin"},{"name":"Piments séchés","note":"selon besoin"},{"name":"Gingembre","unit":"tranche"},{"name":"Sucre blanc","note":"selon besoin"},{"name":"Sauce soja foncée","note":"selon besoin"},{"name":"Sel","note":"selon besoin"},{"name":"Huile de cuisson","note":"quantité suffisante, un peu plus ne fait pas de mal"}]'::jsonb, '["Mettre l''agneau dans une casserole d''eau froide, porter à ébullition, écumer la mousse, puis égoutter l''agneau.","Couper le gingembre (4 tranches), mettre les piments séchés et le poivre de Sichuan dans un bol et réserver.","Ajouter de l''huile dans un wok. (un peu plus ne fait pas de mal)","Une fois l''huile chaude, ajouter le sucre blanc pour caraméliser l''agneau.","Une fois que l''agneau a rendu son eau, ajouter le sel, la sauce soja foncée et les assaisonnements réservés.","Ajouter de l''eau claire à hauteur de l''agneau, porter à ébullition à feu vif, laisser bouillir 10 minutes, puis mijoter à feu doux 30 minutes.","Pendant ce temps, pétrir la pâte. La quantité et la méthode de pétrissage sont expliquées dans les notes supplémentaires (note 1).","Ajouter le poivron vert, le poivron doux, l''oignon vert et la pâte étalée, puis faire sauter.","Une fois bien mélangé, retirer du feu et servir."]'::jsonb, '["Plat de viande","Savoureux","Étouffé","Nord","Fait maison","Plat copieux"]'::jsonb),
  ('howtocook:meat_dish/老妈蹄花/老妈蹄花', 'fr', 'Pieds de porc de maman', 'Plats de viande', 'La soupe de pieds de porc est d''un blanc laiteux, les pieds de porc sont si tendres qu''ils se détachent des os, la texture est délicate, et accompagnée d''une sauce aigre-piquante, elle est très appétissante. C''est un plat familial classique du Sichuan. Les pieds de porc sont riches en collagène, les haricots blancs ajoutent une texture fondante et sont nutritifs. La préparation nécessite un autocuiseur et un trempage préalable, ce qui peut être un défi pour les débutants, mais en suivant les étapes, c''est facile à maîtriser. Le temps total, y compris le trempage et la cuisson sous pression, est d''environ 2 heures (sans compter le trempage des haricots blancs la veille).', '[{"name":"Pieds de porc","unit":"pièce"},{"name":"Ciboule","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Vin de cuisine","note":"quantité suffisante"},{"name":"Sauce soja claire","unit":"g"},{"name":"Baï-zhi (angélique)","note":"quantité suffisante"},{"name":"Angélique chinoise","unit":"g"},{"name":"Bouillon de poule","unit":"g"},{"name":"Sel","note":"quantité suffisante"},{"name":"Ail","unit":"g"},{"name":"Piment oiseau","note":"quantité suffisante"},{"name":"Poivre blanc moulu","unit":"g"},{"name":"Vinaigre aromatique","note":"quantité suffisante"},{"name":"Huile de poivre du Sichuan","note":"quantité suffisante"},{"name":"Huile pimentée","note":"quantité suffisante"},{"name":"Haricots blancs","unit":"g"}]'::jsonb, '["200g de haricots blancs trempés dans l''eau la veille, réservés","Préparez les pieds avant de porc : demandez au boucher de les fendre en deux, utilisez un chalumeau pour enlever les poils, puis nettoyez-les à la maison","Dans une casserole d''eau froide, ajoutez les pieds de porc, des morceaux de poireau, des tranches de gingembre, du vin de cuisine. Blanchissez 10 minutes, écumez, égouttez et rincez, réservez.","Dans un autocuiseur, mettez les pieds de porc, angélique, baï-zhi (racine d''angélique), poivre blanc moulu, tranches de gingembre. Cuire sous pression 30 minutes après la montée en pression. Ajoutez les haricots blancs et cuire encore 10 minutes. À ce stade, si le bouillon est blanc laiteux, félicitations, c''est correct (si vous devez ajouter de l''eau en cours de route, ajoutez uniquement de l''eau chaude).","Après avoir ouvert le couvercle, ajoutez du sel, du bouillon de poule (ou glutamate), de la ciboulette ciselée pour assaisonner.","Préparez la sauce secrète : mettez de la ciboulette, de l''ail, des piments oiseaux, du poivre blanc moulu, de la sauce soja claire, du vinaigre aromatique, de l''huile pimentée, de l''huile de poivre du Sichuan, du bouillon de pieds de porc.","Versez la sauce secrète sur le plat."]'::jsonb, '["Viande","Cuisine sichuanaise","Braisé","Aigre-piquant","Familial","Pour recevoir"]'::jsonb),
  ('howtocook:meat_dish/老式锅包肉/老式锅包肉', 'fr', 'Porc aigre-doux croustillant à l''ancienne', 'Plats de viande', 'Le porc aigre-doux croustillant est un plat classique du nord-est de la Chine, originaire de la résidence Daotai de Harbin. Il se caractérise par une acidité vive grâce au vinaigre blanc, une coque croustillante et des tranches de viande tendres, avec une saveur aigre-douce rafraîchissante. Le porc fournit des protéines de qualité, accompagné d''oignons verts et de gingembre pour ouvrir l''appétit et couper le gras. Cette recette nécessite de maîtriser la technique de l''enrobage, la température de l''huile et la double friture ; la difficulté est moyenne à élevée, les débutants doivent être patients. De la marinade à la friture, le temps de préparation est d''environ 90 minutes.', '[{"name":"Longe de porc","unit":"g"},{"name":"Oignon vert","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Carotte","unit":"g"},{"name":"Coriandre","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"MSG"},{"name":"Fécule de pomme de terre","unit":"g"},{"name":"Fécule de pomme de terre","unit":"g"},{"name":"Farine tout usage","unit":"g"},{"name":"Bicarbonate de soude","unit":"g"},{"name":"Bicarbonate de soude","unit":"g"},{"name":"Sésame blanc grillé","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Vinaigre blanc","unit":"g"},{"name":"Sauce soja légère","unit":"g"},{"name":"Fécule de maïs","unit":"g"},{"name":"Eau","unit":"g"},{"name":"Eau claire","unit":"ml"}]'::jsonb, '["Préparer le porc :","Couper la longe de porc en tranches uniformes de 8 mm d''épaisseur, en retirant les aponévroses blanches.","Rincer les tranches de porc à l''eau claire pour éliminer le sang.","Optionnel : Ajouter 5 g de bicarbonate de soude, bien mélanger, laisser reposer 5 minutes.","Rincer à l''eau claire 1 à 2 fois pour éliminer l''excès de bicarbonate.","Mariner les tranches de porc :","Ajouter 3 g de sel et 5 ml de vin de cuisine aux tranches de porc, bien mélanger, laisser mariner 15 minutes.","Préparer l''enrobage :","Méthode 1 (recommandée) :","Ajouter 170 g de fécule de pomme de terre à de l''eau claire en excès, mélanger, laisser reposer 60 minutes jusqu''à ce que la fécule se dépose.","Verser toute l''eau claire du dessus, conserver la pâte de fécule au fond (ressemble à un fluide non newtonien).","Ajouter les tranches de porc, 5 ml d''eau claire et 3 ml d''huile de cuisson, bien mélanger.","Méthode 2 :","Mélanger 210 g de fécule de pomme de terre et 70 g de farine tout usage.","Ajouter de l''eau claire petit à petit tout en remuant jusqu''à obtenir une consistance de yaourt, en formant un filet lorsqu''on soulève, et la pâte doit s''accumuler dans le bol.","Ajouter 10 ml d''huile de cuisson et 1 g de bicarbonate de soude, bien mélanger.","Mettre les tranches de porc marinées dans la pâte, bien enrober chaque tranche.","Préparer la sauce aigre-douce :","Mélanger 65 g de sucre blanc, 55 g de vinaigre blanc, 4 g de sauce soja légère et 2 g de sel, bien remuer, réserver.","Optionnel : 4 g d''eau et 1,5 g de fécule de maïs pour épaissir la sauce.","Préparer les accompagnements :","Couper l''oignon vert, le gingembre et la carotte en julienne, couper la coriandre en tronçons, émincer l''ail.","Frire les tranches de porc :","Première friture :","Ajouter de l''huile de cuisson dans la poêle, chauffer à 170°C (sixième chaleur).","Mettre les tranches de porc une par une dans l''huile, frire jusqu''à ce que la surface soit fixée, que l''enrobage ne colle pas aux baguettes, que la viande remonte et soit jaune pâle, environ 30 secondes (selon la taille), retirer et réserver.","Deuxième friture :","Augmenter la température de l''huile à 200°C (septième chaleur).","Mettre toutes les tranches de porc dans l''huile, frire jusqu''à ce que la coque soit dorée et croustillante, environ 30 secondes, retirer et réserver.","Troisième friture (optionnelle) :","Augmenter la température de l''huile à 220°C (huitième chaleur).","Remettre les tranches de porc rapidement dans l''huile jusqu''à ce qu''elles soient légèrement rosées à l''intérieur du jaune, environ 30 secondes (selon la capacité de maintien de la température), pour augmenter le croustillant, retirer et égoutter.","Sauter :","Laisser 20 ml d''huile de fond dans la poêle, verser la sauce aigre-douce préparée, chauffer à feu vif jusqu''à ébullition, laisser réduire jusqu''à ce que la sauce épaississe, environ 30 à 60 secondes.","Optionnel : Retirer la moitié de la sauce pour faciliter le sauté ultérieur.","Ajouter les tranches de porc frites, la julienne d''oignon vert, les tranches d''ail, la julienne de carotte et les tronçons de coriandre, arroser de la sauce réservée, sauter rapidement 3 fois pour enrober uniformément la viande de sauce.","Servir :","Disposer le porc aigre-doux dans une assiette, saupoudrer de sésame blanc grillé (facultatif), et servir."]'::jsonb, '["Plat de viande","Nord-est","Aigre-doux","Croustillant","Friture","Pour invités"]'::jsonb),
  ('howtocook:meat_dish/肉饼炖蛋', 'fr', 'Galette de viande aux œufs', 'Plats de viande', 'La galette de viande aux œufs est un plat traditionnel familial, salé, tendre et soyeux. La galette de viande imbibée de sauce, avec l''œuf niché dedans, a une texture tendre qui accompagne bien le riz. Riche en protéines de haute qualité et en acides aminés, il rechargera bien votre énergie. La préparation est très simple, idéale pour les débutants en cuisine ; du début à la fin, cela ne prend qu''environ 20 minutes.', '[{"name":"Viande de porc hachée","unit":"g"},{"name":"Œuf","unit":"pièce"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Poivre blanc moulu","unit":"g"},{"name":"Huile de sésame","unit":"ml"}]'::jsonb, '["Dans un bol, mélanger la viande de porc hachée, le vin de cuisine, la sauce soja légère, le poivre blanc moulu, l''œuf et l''huile de sésame. Bien remuer.","Étaler la viande de porc assaisonnée dans une assiette. Faire un creux au milieu avec une cuillère et y casser un œuf.","Remplir une casserole d''eau au 1/4 de sa hauteur. Porter à ébullition, puis placer l''assiette dans la casserole, couvrir et cuire à la vapeur pendant 15 minutes."]'::jsonb, '["Plat de viande","Salé et umami","Plat vapeur","Familial","Accompagne le riz","Rapide"]'::jsonb),
  ('howtocook:meat_dish/腐乳肉', 'fr', 'Porc au tofu fermenté rouge', 'Plats de viande', 'C''est un plat familial classique du Jiangnan, la poitrine de porc braisée avec du tofu fermenté rouge, d''une couleur rouge vif comme l''ambre, la viande fondante à tel point qu''elle se dissout en bouche, les arômes de vin et de soja sucré-salé se déploient en couches sur la langue. Riche en protéines de haute qualité et en vitamines B, plus facile à digérer après une cuisson lente. La préparation nécessite de la patience pour maîtriser le feu et la réduction de la sauce, un défi pour les débutants, temps de préparation estimé à environ 1 heure.', '[{"name":"Poitrine de porc avec peau","unit":"g"},{"name":"Tofu fermenté rouge","unit":"g"},{"name":"Saumure de tofu fermenté","unit":"ml"},{"name":"Sucre candi","unit":"g"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Vin de cuisson","unit":"ml"},{"name":"Blanc d''oignon vert","unit":"g"},{"name":"Oignon vert ciselé","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Eau","unit":"ml"},{"name":"Huile de cuisson","unit":"ml"}]'::jsonb, '["Couper la poitrine de porc en morceaux de 2,5 cm de côté","Mettre de l''eau froide avec du vin de cuisson et des tranches de gingembre, ajouter la poitrine de porc, porter lentement à ébullition, puis égoutter","Écraser les cubes de tofu fermenté rouge avec la saumure en purée, ajouter du sucre candi et de la sauce soja foncée pour obtenir une sauce","Faire chauffer l''huile dans un wok, faire revenir l''oignon et le gingembre, ajouter les morceaux de viande et faire sauter jusqu''à ce qu''ils soient dorés","Verser la sauce au tofu fermenté, mélanger, ajouter de l''eau chaude et laisser mijoter","Laisser mijoter à feu doux pendant 40 minutes","Augmenter le feu pour réduire la sauce, éteindre lorsque la sauce fait de grosses bulles épaisses"]'::jsonb, '["Plat de viande","Sucré-salé","Braisé","Jiangnan","Accompagnement de riz","Pour invités","Cuisine familiale"]'::jsonb),
  ('howtocook:meat_dish/芥末罗氏虾/芥末罗氏虾', 'fr', 'Gambas au wasabi', 'Plats de viande', 'Ce plat est savoureux et légèrement épicé, avec une forte saveur de wasabi. Les gambas sont fermes et élastiques, un plat de fruits de mer rapide et familial. Les gambas sont riches en protéines de qualité et en calcium, faibles en matières grasses, et le wasabi ouvre l''appétit et coupe la graisse. Difficulté moyenne, en suivant les étapes pour préparer la sauce et contrôler le feu, même un débutant peut le faire rapidement, environ 30 minutes au total.', '[{"name":"gambas","unit":"g"},{"name":"ail","unit":"tête(s)"},{"name":"wasabi","unit":"g"},{"name":"fécule de maïs","unit":"g"},{"name":"sauce soja légère","unit":"g"},{"name":"poivre","unit":"g"},{"name":"sucre","unit":"g"},{"name":"sauce d''huître","unit":"g"},{"name":"sel","unit":"g"},{"name":"piment rouge","unit":"pièce(s)"},{"name":"beurre","unit":"g"},{"name":"huile de cuisson","unit":"ml"}]'::jsonb, '["Préparation des gambas :","Coupez les gambas dans le dos, retirez le boyau et la poche de sable. Vous pouvez aussi les couper par le ventre, elles s''ouvriront à la friture et le plat sera plus beau.","Lavez-les à l''eau claire, égouttez-les. Vous pouvez les saupoudrer de fécule de maïs ou non.","Préparation de l''ail et de la sauce :","Émincez 2 gousses d''ail.","Préparez la sauce : mélangez la sauce soja légère, la sauce d''huître, le sucre, le poivre, le sel, et selon votre goût, ajoutez du wasabi. Diluez avec un peu d''eau et ajoutez de la fécule de maïs en remuant.","Processus de cuisson :","Faites chauffer de l''huile dans une poêle, suffisamment pour couvrir le fond.","Ajoutez les gambas égouttées et faites-les cuire doucement.","Une fois que l''huile des gambas est extraite (beaucoup de bulles dans la poêle), ajoutez l''ail émincé et les piments rouges.","Quand vous sentez l''odeur de l''ail, ajoutez le beurre.","Une fois le beurre fondu, mélangez bien et ajoutez la sauce préparée.","Couvrez et laissez mijoter 2 minutes jusqu''à ce que la sauce épaississe, puis servez."]'::jsonb, '["Fruits de mer","Frais et légèrement épicé","Poêlé","Rapide et familial","Fruits de mer","Appétissant et rafraîchissant"]'::jsonb),
  ('howtocook:meat_dish/茭白炒肉/茭白炒肉', 'fr', 'Sauté de porc au bambou d''eau', 'Plats de viande', 'Le sauté de porc au bambou d''eau est un plat familial rapide, tendre et croquant, salé et savoureux, typique de la cuisine du Jiangnan. Le bambou d''eau est riche en fibres et vitamines, associé à du porc maigre pour des protéines de qualité, un équilibre viande-légumes. Difficulté moyenne, les débutants peuvent maîtriser après un peu de pratique. Temps de préparation environ 20 minutes.', '[{"name":"Bambou d''eau","unit":"pièce"},{"name":"Porc maigre","unit":"g"},{"name":"Fécule","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Assaisonnement au poulet","unit":"g"},{"name":"Gingembre","unit":"tranche"},{"name":"Ail","unit":"gousse"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Sel","unit":"g"}]'::jsonb, '["Couper le bambou d''eau en tranches de 0,5 cm d''épaisseur.","Couper le porc maigre en lanières de 0,3 à 0,5 cm d''épaisseur, ajouter le vin de cuisine, la fécule, le sel et l''eau, mélanger.","Couper le gingembre en tranches, hacher l''ail.","Porter de l''eau à ébullition dans une casserole, blanchir le bambou d''eau 60 à 90 secondes, égoutter.","Chauffer 15 ml d''huile dans un wok, faire sauter le porc 60 secondes, réserver.","Chauffer 15 ml d''huile dans le wok, faire revenir le gingembre et l''ail 30 secondes, ajouter le bambou d''eau et sauter 30 secondes.","Ajouter le porc réservé, sauter 60 secondes, ajouter 20 ml d''eau, du sel et de l''assaisonnement au poulet, sauter 60 secondes et servir."]'::jsonb, '["Plat de viande","Salé et savoureux","Sauté","Fait maison","Rapide","Jiangnan"]'::jsonb),
  ('howtocook:meat_dish/荔枝肉/荔枝肉', 'fr', 'Porc aux litchis', 'Plats de viande', 'Le porc aux litchis est un plat traditionnel du Fujian, aigre-doux et croustillant. Les morceaux de viande, croustillants à l''extérieur et tendres à l''intérieur, sont enveloppés d''une sauce rouge brillante, accompagnés de fruits pour une fraîcheur fruitée. Le porc maigre est riche en protéines de qualité, l''ananas apporte des fibres et des vitamines, ce qui aide à ouvrir l''appétit et à éliminer le gras. La préparation nécessite de couper la viande, de la paner et de la frire deux fois, un peu difficile mais avec des étapes claires, adaptée aux amateurs de cuisine ayant une certaine base. Environ 45 minutes suffisent pour le servir.', '[{"name":"Porc maigre","unit":"g"},{"name":"Ananas","unit":"g"},{"name":"Œuf","unit":"pièce"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sucre blanc","unit":"g"},{"name":"Fécule","unit":"g"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Bouillon de poule en poudre","unit":"g"},{"name":"Gingembre haché","unit":"g"},{"name":"Graines de sésame","unit":"g"},{"name":"Sauce tomate","unit":"g"},{"name":"Vinaigre noir","unit":"ml"}]'::jsonb, '["Couper le porc maigre en morceaux (2-3 cm chacun), les mettre dans un grand bol, ajouter 1 œuf, 50 g de fécule, 3 ml de sauce soja légère, 2 g de bouillon de poule en poudre.","Bien mélanger jusqu''à ce que la fécule enrobe les morceaux de viande (si trop liquide, ajouter de la fécule ; si trop sec, ajouter de l''eau), puis ajouter 5 ml d''huile, bien mélanger et réserver.","Préparer un bol, ajouter la sauce tomate, 3 g de bouillon de poule en poudre, 2 ml de sauce soja légère, du gingembre haché, du sucre blanc, 10 g de fécule, du vinaigre noir, 200 ml d''eau froide, bien mélanger et réserver.","Couper un ananas, préparer 6 morceaux (1,5-2 cm chacun).","Chauffer une poêle avec de l''huile, verser 500 ml d''huile, chauffer jusqu''à entendre le bruit de friture.","Mettre les morceaux de viande un par un dans la poêle (ne pas verser tout le bol d''un coup), veiller à ce qu''ils ne collent pas entre eux.","Après avoir mis toute la viande, retourner les morceaux toutes les 30 secondes avec une cuillère jusqu''à ce qu''ils soient dorés.","Retirer la viande, après une minute la remettre dans l''huile chaude et continuer à frire jusqu''à ce qu''elle soit bien dorée, puis la retirer et la mettre dans un grand bol de réserve.","Dans la poêle, verser la sauce, après 30 secondes ajouter la viande et les morceaux d''ananas, bien mélanger, puis servir.","Parsemer de graines de sésame."]'::jsonb, '["Plat de viande","Aigre-doux","Friture","Cuisine du Fujian","Maison","Accompagnement"]'::jsonb),
  ('howtocook:meat_dish/荷兰豆炒腊肠/荷兰豆炒腊肠', 'fr', 'Mange-tout sauté à la saucisse chinoise', 'Plats de viande', 'Le mange-tout sauté à la saucisse chinoise est un plat familial rafraîchissant et salé. La graisse de la saucisse enrobe les mange-tout verts, donnant une texture croquante et légère. Les mange-tout sont riches en protéines de qualité et en vitamines, ce qui renforce la résistance du corps. La recette est simple, ne nécessite presque pas de compétences en coupe, même les débutants peuvent la réaliser rapidement. De la préparation à l''assiette, il faut environ 15 minutes.', '[{"name":"mange-tout","unit":"pièce","note":""},{"name":"saucisse chinoise","unit":"g","note":""},{"name":"sauce soja claire","unit":"ml","note":""},{"name":"huile de cuisson","unit":"ml","note":""}]'::jsonb, '["Retirez les extrémités des mange-tout, si vous avez le temps, retirez aussi les queues.","Avant d''acheter la saucisse, demandez au vendeur si elle est crue ou cuite. Si elle est crue, faites-la cuire à la vapeur à l''avance ; si elle est cuite, utilisez-la directement.","Lavez les mange-tout, puis blanchissez-les environ 45 secondes jusqu''à ce qu''ils changent de couleur. Égouttez et passez sous l''eau froide, réservez.","Chauffez la poêle et ajoutez environ 10 ml d''huile de cuisson. Attendez 10 secondes pour que l''huile chauffe.","Ajoutez la saucisse chinoise et faites-la sauter jusqu''à ce qu''elle commence à s''enrouler légèrement. Maintenez un feu très doux (le plus petit possible) pour éviter de brûler.","Ajoutez les mange-tout, passez à feu moyen-vif et faites sauter 30 secondes. Ajoutez la sauce soja claire, puis continuez à sauter 20 à 30 secondes. Servez immédiatement."]'::jsonb, '["viande","salé et parfumé","sauté","familial","rapide","accompagne le riz"]'::jsonb),
  ('howtocook:meat_dish/萝卜炖羊排', 'fr', 'Ragoût de travers d''agneau au daikon', 'Plats de viande', 'Ce plat en sauce est léger et non gras, la viande d''agneau est tendre et savoureuse, les daikons absorbent le bouillon et deviennent doux et sucrés. C''est un plat réconfortant courant en hiver dans le nord de la Chine. L''agneau est riche en protéines de qualité et en fer, les daikons contiennent des vitamines et des fibres alimentaires ; leur combinaison réchauffe la rate et l''estomac, chasse le froid et facilite la digestion. Bien qu''il nécessite un blanchiment pour enlever l''odeur et deux cuissons, les étapes sont claires et faciles à suivre, même pour les débutants. La préparation totale prend environ deux heures, mais avec un autocuiseur, elle peut être réduite à environ une heure.', '[{"name":"Travers d''agneau","unit":"g"},{"name":"Daikon","unit":"pièce"},{"name":"Ciboule","unit":"pièce"},{"name":"Grains de poivre du Sichuan","unit":"grain"},{"name":"Angélique","note":"Optionnel, selon le goût"},{"name":"Gingembre","unit":"g"},{"name":"Vin de cuisson ou vin de riz","unit":"ml"},{"name":"Sel de table","unit":"g"},{"name":"Sucre candi","unit":"morceau"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Éplucher les daikons et les couper en morceaux de 3 à 5 cm. Réserver.","Pour les travers d''agneau, demander au boucher de les couper, car un couteau domestique ne suffit généralement pas. Réserver.","Mettre la viande dans une casserole d''eau froide, ajouter la moitié du vin de cuisson, la moitié des ciboules et du gingembre, faire bouillir 10 minutes pour enlever le sang. (Optionnel) Écumer les impuretés qui remontent à l''aide d''une cuillère.","Dans une autre casserole d''eau froide, mettre les daikons coupés et la moitié du sucre candi. Porter à ébullition et cuire 5 minutes pour enlever le piquant des daikons. Égoutter et réserver.","Sortir les travers d''agneau blanchis et les mettre dans un autocuiseur. Ajouter de l''eau jusqu''à couvrir tous les ingrédients, puis ajouter environ 300 ml d''eau supplémentaire.","Ajouter le reste des ciboules, du gingembre, du vin de cuisson, les grains de poivre du Sichuan, le sucre candi, l''angélique (optionnel) et le sel. Fermer le couvercle, attendre la montée en pression, puis cuire à feu moyen pendant environ 15 minutes.","Si vous n''avez pas d''autocuiseur, utiliser une casserole ordinaire et cuire environ 40 minutes à 1 heure.","Éteindre le feu, attendre que la pression de l''autocuiseur soit complètement relâchée, ouvrir le couvercle. Ajouter les daikons blanchis, rectifier l''assaisonnement en ajoutant 3 à 10 g de sel ou de l''eau, goûter le bouillon.","Remettre sur le feu à feu moyen. Pour l''autocuiseur, cuire encore 10 minutes après la montée en pression ; pour une casserole ordinaire, couvrir et cuire encore 20 minutes.","Éteindre le feu et servir dans un plat."]'::jsonb, '["Plat de viande","Savoureux","Brasé","Nord","Réchauffant","Maison"]'::jsonb),
  ('howtocook:meat_dish/蒜苔炒肉末', 'fr', 'Sauté de porc haché aux pointes d''ail', 'Plats de viande', 'Le sauté de porc haché aux pointes d''ail est un plat familial du nord de la Chine, salé et savoureux avec une texture croquante et tendre, riche en arôme d''ail. Les pointes d''ail sont riches en fibres alimentaires et en vitamines, tandis que la poitrine de porc apporte des protéines, offrant un équilibre entre viande et légumes. La recette est simple, les ingrédients faciles à préparer, même les débutants peuvent la réussir rapidement. De la préparation à la cuisson, cela prend environ 10 minutes.', '[{"name":"Poitrine de porc en tranches fines","unit":"tranche"},{"name":"Pointes d''ail","unit":"botte"},{"name":"Gousses d''ail","unit":"gousse"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sel","unit":"g"}]'::jsonb, '["Couper les pointes d''ail en tronçons de 5 cm, réserver.","Couper la poitrine de porc en lanières de 5 mm d''épaisseur et 5 cm de long, réserver.","Écraser les gousses d''ail et les hacher finement, réserver.","Chauffer la poêle, ajouter 10 ml d''huile de cuisson. Attendre 10 secondes pour que l''huile chauffe.","Ajouter l''ail haché, faire sauter à feu moyen pendant 10 secondes jusqu''à ce qu''il soit parfumé.","Ajouter la poitrine de porc et 5 ml de sauce soja légère, faire sauter à feu moyen pendant 30 secondes jusqu''à ce que la viande soit cuite et colorée.","Ajouter les pointes d''ail dans la poêle avec 10 ml de sauce soja légère, faire sauter 30 secondes.","Ajouter 20 g d''eau dans la poêle, faire sauter à feu moyen pendant 5 minutes jusqu''à ce que les pointes d''ail soient légèrement ramollies.","Enfin, ajouter 2 g de sel, faire sauter à feu moyen pendant 30 secondes, puis servir."]'::jsonb, '["Plat de viande","Salé et savoureux","Sauté rapide","Cuisine familiale du nord","Accompagne le riz","Rapide"]'::jsonb),
  ('howtocook:meat_dish/虎皮肘子', 'fr', 'Jarret de porc à la peau de tigre', 'Plats de viande', 'Ce plat se caractérise par une couleur rouge brillante, une peau de jarret présentant un motif attrayant de peau de tigre, une texture fondante et savoureuse, gras mais pas lourd, et une viande maigre tendre. C''est un grand plat traditionnel chinois pour recevoir. Le jarret de porc est riche en collagène et en protéines de haute qualité, plus facile à absorber après une longue cuisson, bénéfique pour la peau et les articulations. La préparation comprend plusieurs étapes : brûlage de la peau, friture, caramélisation du sucre et cuisson sous pression. C''est un défi pour les débutants, donc recommandé pour ceux qui ont une certaine expérience culinaire. Du prétraitement à la table, le temps total estimé est d''environ 2,5 heures.', '[{"name":"Jarret de porc avant","unit":"pièce"},{"name":"Huile végétale","unit":"bouteille"},{"name":"Sucre candi","unit":"bouteille"},{"name":"Sel","unit":"c. à café"},{"name":"Sauce soja foncée","unit":"c. à café"},{"name":"Sauce soja claire","unit":"c. à soupe"},{"name":"Vinaigre blanc","unit":"c. à soupe"},{"name":"Feuille de laurier","unit":"feuille"},{"name":"Bâton de cannelle","unit":"g"},{"name":"Cardamome","unit":"pièce"},{"name":"Poivre du Sichuan","unit":"pièce"},{"name":"Anis étoilé","unit":"pièce"},{"name":"Fécule (maïs ou pomme de terre)","unit":"c. à soupe"},{"name":"Oignon vert","unit":"pièce"},{"name":"Gingembre","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Eau","unit":"ml"},{"name":"Vin de cuisine","unit":"c. à soupe"}]'::jsonb, '["Après décongélation, faire tremper le jarret de porc dans l''eau pendant 1 heure pour éliminer le sang.","Si vous avez un chalumeau, brûler la peau du jarret jusqu''à ce qu''elle devienne brun-noir pour enlever les poils et détruire les glandes sudoripares. Attention à ne pas brûler au même endroit trop longtemps pour éviter de carboniser. Arrêter lorsque la peau est presque entièrement brun-noir.","Si vous n''avez pas de chalumeau, chauffer une poêle en fer à plus de 200°C, placer le jarret directement dans la poêle et utiliser une spatule ou des baguettes pour que la peau soit en contact avec la surface. Lorsque la peau devient brune au contact, changer de position et continuer jusqu''à ce que toute la peau soit traitée. Attention à la température de la poêle, ne pas la faire devenir rouge.","Utiliser une éponge métallique pour frotter le jarret dans l''eau et enlever les parties brûlées. Après le nettoyage, le jarret doit avoir l''aspect d''avant la brûlure.","Placer le jarret dans une marmite en fer, ajouter le maximum d''eau froide possible (selon la taille de la marmite et du jarret, en veillant à pouvoir la soulever), de sorte que l''eau couvre au moins les 3/4 du jarret.","Prendre la partie blanche d''un oignon vert, la couper en 3 tronçons, et les mettre dans la marmite.","Prendre 3 gousses d''ail, les écraser avec le plat du couteau, et les mettre dans la marmite.","Prendre 3 g de gingembre, le mettre dans la marmite.","Ajouter 2 cuillères à soupe de vin de cuisine.","Après ébullition, attendre 5 minutes, puis retirer le jarret et tous les aromates, et conserver le bouillon de viande dans un récipient.","Ajouter de l''huile froide dans la marmite (assez pour couvrir les 3/5 du jarret), et chauffer à feu moyen.","Lorsque l''huile est à 50 % de sa température maximale, réduire à feu doux et ajouter le jarret pour le frire.","Pendant la friture, faire attention à la sécurité personnelle.","Pendant la friture, utiliser une spatule ou un ustensile résistant à la chaleur pour arroser uniformément les parties non immergées du jarret. Si possible, retourner le jarret toutes les 3 minutes pour une friture homogène.","La friture dure environ 20 minutes. Lorsque la peau du jarret est devenue brun clair et que les parties maigres sont légèrement grillées, retirer et réserver.","L''huile de friture peut être réutilisée pour d''autres aliments frits, mais ne pas la réutiliser trop de fois.","Préparer 200 ml de caramel (sucre caramélisé) et réserver.","Mettre le jarret dans une cocotte-minute, ajouter tout le bouillon de viande, le caramel, les feuilles de laurier, le bâton de cannelle, la cardamome, le poivre du Sichuan, l''anis étoilé, la sauce soja foncée, la sauce soja claire et le vinaigre blanc. Si vous aimez sucré, ajouter 2-3 g de sucre candi supplémentaire.","Prendre la partie blanche d''un oignon vert, la couper en 3 tronçons, et les mettre dans la cocotte.","Prendre 3 gousses d''ail, les écraser, et les mettre dans la cocotte.","Prendre 3 g de gingembre, le mettre dans la cocotte.","Fermer le couvercle et cuire sous pression pendant 40 minutes.","Pendant la cuisson, préparer la liaison à la fécule. Dans un bol, mélanger 1 cuillère à soupe de fécule avec 100 ml d''eau pour obtenir une suspension blanche.","Après la cuisson, ouvrir la cocotte-minute, retirer tous les aromates et ne garder que le jarret.","Transférer le bouillon restant dans une marmite en fer, et placer le jarret dans un plat.","Placer la marmite sur le feu et porter à grande ébullition. Pendant la réduction, goûter le jus avec le bout des baguettes et ajuster le sel selon le goût. Attention, le liquide est plus dilué quand il y en a beaucoup, donc en ajouter moins au début.","Quand le bouillon bout, surveiller la quantité restante.","Lorsqu''il ne reste plus que la moitié du volume initial, remuer la liaison à la fécule et en ajouter la moitié.","Attendre l''ébullition, puis ajouter le reste de la liaison.","Attendre l''ébullition, puis laisser bouillir 1 à 2 minutes avant d''éteindre le feu. Le bouillon doit être épais et brun-rouge.","À l''aide d''une cuillère, verser la sauce uniformément sur le jarret, en essayant de couvrir toute la surface. Si la sauce s''épuise avant d''avoir tout couvert, servir tel quel. Sinon, le reste de sauce peut être servi à part."]'::jsonb, '["Viande","Mijoté","Fondant","Frit et braisé","Pour invités","Traditionnel"]'::jsonb),
  ('howtocook:meat_dish/蚂蚁上树', 'fr', 'Fourmis grimpant aux arbres', 'Plats de viande', 'Les fourmis grimpant aux arbres sont un plat familial classique du Sichuan, salé et légèrement épicé, les vermicelles sont lisses et absorbent la sauce, la viande hachée est tendre et savoureuse. À base de vermicelles de patate douce et de viande hachée, riche en glucides et protéines, il fournit rapidement de l''énergie. Difficulté moyenne, étapes claires, adapté aux débutants, environ 20 minutes au total.', '[{"name":"Vermicelles de patate douce","unit":"g"},{"name":"Viande de porc hachée (ou bœuf haché)","unit":"g"},{"name":"Pâte de haricots de Pixian","unit":"g"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Ail haché","unit":"g"},{"name":"Gingembre haché","unit":"g"},{"name":"Oignon vert (optionnel)","note":"Quantité suffisante"},{"name":"Eau claire","unit":"ml"}]'::jsonb, '["Faire tremper les vermicelles de patate douce à l''avance pendant 20 minutes, réserver.","Hacher l''ail et le gingembre séparément, réserver.","Chauffer la poêle, ajouter 10 ml d''huile de cuisson, faire revenir l''ail et le gingembre hachés jusqu''à ce qu''ils soient parfumés.","Ajouter la viande de porc hachée, faire sauter jusqu''à ce qu''elle blanchisse et libère un peu d''huile.","Ajouter la pâte de haricots de Pixian, faire sauter jusqu''à ce que l''huile rouge se sépare.","Ajouter la sauce soja légère et la sauce soja foncée, mélanger uniformément.","Verser 300 ml d''eau claire, porter à ébullition.","Ajouter les vermicelles trempés et égouttés, remuer doucement avec des baguettes pour éviter qu''ils ne collent.","Cuire à feu moyen-doux pendant environ 5 minutes, jusqu''à ce que les vermicelles aient absorbé le bouillon et soient légèrement secs.","Selon le goût, saupoudrer d''oignon vert haché, éteindre le feu et servir dans une assiette."]'::jsonb, '["Plat de viande","Sichuan","Salé et légèrement épicé","Sauté et bouilli","Accompagnement de riz","Rapide","Fait maison"]'::jsonb),
  ('howtocook:meat_dish/血浆鸭/血浆鸭', 'fr', 'Canard au sang', 'Plats de viande', 'Le canard au sang est un plat traditionnel de Wugang, dans le Hunan. La viande de canard est croustillante et tendre, imprégnée de sang vinaigré, ce qui rend même le gingembre et les piments doux et non piquants. Le canard et son sang fournissent des protéines de qualité et du fer, idéaux pour nourrir le sang et renforcer le corps. La préparation comporte plusieurs étapes, il faut surveiller la cuisson et les remuer, mais en suivant les étapes, même un débutant peut le réaliser en environ 2 heures.', '[{"name":"Jeune canard","unit":"g"},{"name":"Sang de canard frais","unit":"ml"},{"name":"Gingembre","unit":"tranches"},{"name":"Ail","unit":"gousses"},{"name":"Oignons verts","unit":"tiges"},{"name":"Piments","unit":"g"},{"name":"Petits piments (ou piments du ciel)","unit":"pièces"},{"name":"Alcool de riz (baijiu)","unit":"ml"},{"name":"Eau","unit":"ml"},{"name":"Bière","unit":"ml"},{"name":"Vin de riz","unit":"ml"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Vin de cuisson","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Bouillon de poulet","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Eau bouillante","unit":"ml"},{"name":"Huile de poivre du Sichuan","unit":"gouttes"}]'::jsonb, '["Couper le jeune canard en morceaux d''environ 3 cm. Ajouter du vin de cuisson et des tranches de gingembre pour éliminer le sang.","Chauffer un wok, ajouter environ 100 ml d''huile de cuisson. À feu vif, quand l''huile est chaude, ajouter le canard mariné et remuer constamment.","Quand la viande a complètement changé de couleur (blanchâtre visible), ajouter de l''alcool, puis 200 ml d''eau bouillante, juste assez pour couvrir le canard. Couvrir et cuire à feu moyen pendant 15 minutes.","Après ébullition, ouvrir le couvercle, ajouter le gingembre et l''ail, remuer une fois, refermer et chauffer encore 10 minutes.","Ouvrir le couvercle, ajouter les piments, remuer constamment. Quand les piments sont ramollis, ajouter le sang de canard frais. Remuer sans cesse pour que chaque morceau de canard et chaque tranche de piment soient imprégnés de sang (c''est l''essence du canard au sang).","Remuer jusqu''à ce que le sang soit devenu noir. Ajouter du sel, du bouillon de poulet, des oignons verts (ceux qui aiment l''huile de poivre du Sichuan peuvent ajouter 3 à 6 gouttes à ce moment). Remuer une ou deux fois de plus.","Sortir du wok, dresser dans un plat, servir."]'::jsonb, '["Plat de viande","Cuisine hunanaise","Épicé","Sauté","Accompagne le riz","Pour les invités"]'::jsonb),
  ('howtocook:meat_dish/西红柿土豆炖牛肉/西红柿土豆炖牛肉', 'fr', 'Bœuf braisé à la tomate et aux pommes de terre', 'Plats de viande', 'Un ragoût familial, aigre-doux et appétissant, sauce riche, bœuf tendre, pommes de terre fondantes. Le bœuf fournit des protéines de qualité, les tomates sont riches en lycopène, avec pommes de terre et oignon, équilibré en nutriments. Simple à réaliser, sans techniques complexes, même les débutants peuvent le faire facilement. De la préparation à la fin, cela prend environ 1 à 1,5 heure.', '[{"name":"Bœuf","unit":"g"},{"name":"Ciboule","unit":"pièce"},{"name":"Gingembre","unit":"tranche"},{"name":"Vin de cuisine","note":"Ajouté en deux fois : pour la cuisson sous pression et le sauté"},{"name":"Poivre du Sichuan","unit":"g"},{"name":"Anis étoilé","unit":"pièce"},{"name":"Feuille de laurier","unit":"pièce"},{"name":"Huile","unit":"ml"},{"name":"Sucre blanc / sucre candi","note":"quantité suffisante"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sauce soja foncée","note":"quantité suffisante"},{"name":"Poivre noir moulu (ou poivre blanc)","unit":"g"},{"name":"Pommes de terre","unit":"pièce"},{"name":"Tomates","unit":"pièce"},{"name":"Oignon","unit":"pièce"},{"name":"Concentré de tomate / Ketchup","unit":"g"},{"name":"Tomates en boîte","note":"Optionnel, remplace le concentré de tomate"},{"name":"Sel","note":"quantité suffisante"}]'::jsonb, '["Préparation:","Éplucher les pommes de terre, les couper en gros morceaux de 5 cm, réserver.","Faire une incision en croix sur les tomates, les blanchir à l''eau bouillante puis les peler, retirer le cœur, les couper en petits morceaux de 3 cm, réserver.","Couper 4 g de ciboule en fines rondelles, et casser le reste en gros morceaux de 5-8 cm.","Faire tremper le bœuf dans l''eau froide pendant une demi-heure pour enlever le sang, ou le blanchir dans l''eau froide jusqu''à ce que la surface blanchisse, écumer la mousse.","Couper l''oignon en petits dés de 0,5-1 cm.","Cuisson","Feu moyen tout le temps.","Recouvrir le bœuf d''eau froide, le mettre dans la cocotte-minute avec les morceaux de ciboule, les tranches de gingembre, 20 g de vin de cuisine, et cuire sous pression pendant 20 minutes une fois la vapeur montée.","Retirer le bœuf, le couper en gros morceaux de 5 cm, enlever le gingembre, verser le bouillon dans un grand bol pour la cuisson ultérieure.","Verser l''huile, lorsqu''elle est à 40-50% de chaleur, ajouter le poivre du Sichuan, l''anis étoilé et la feuille de laurier, les retirer dès qu''ils sont parfumés avant qu''ils ne brûlent.","Ajouter le bœuf, la ciboule et le gingembre, faire revenir jusqu''à ce que ce soit parfumé (la durée n''a pas d''importance, s''il commence à attacher, ajouter 10 ml de bouillon, même principe ensuite).","Après avoir fait revenir, ajouter 15 ml de sauce soja légère, 15 ml de vin de cuisine, du poivre, 5-10 g de concentré de tomate ou une boîte de tomates pelées, et l''oignon, faire revenir jusqu''à ce qu''il soit translucide.","(Optionnel) Ajouter une pincée de sel pour faire suer l''oignon et éviter qu''il brûle, ne pas en mettre trop, on assaisonnera plus tard.","Ajouter les tomates, faire revenir jusqu''à ce qu''elles soient fondues et tendres, puis verser le reste du bouillon.","Mijotage","Une fois à ébullition à feu moyen, réduire à feu doux pour toute la durée.","30 à 40 minutes avant la fin, ajouter les pommes de terre et assaisonner.","Ajouter du sucre et du sel au goût en goûtant, jusqu''à ce que ce soit à votre convenance.","Quand le bœuf est tendre (piqué avec des baguettes), servir !"]'::jsonb, '["Plat de viande","Aigre-doux","Braisé","Familial","Accompagnement du riz"]'::jsonb),
  ('howtocook:meat_dish/西红柿牛腩/西红柿牛腩', 'fr', 'Bœuf braisé à la tomate', 'Plats de viande', 'Le bœuf braisé à la tomate a une sauce épaisse, aigre-douce et délicieuse. La viande est tendre et savoureuse. C''est un plat familial qui ouvre l''appétit. Riche en protéines, vitamines et lycopène, équilibré. Un défi pour les débutants, nécessitant de maîtriser la cuisson de la viande et la technique de la sauce tomate. Les débutants mettent environ 90 minutes.', '[{"name":"Tomates","unit":"pièce(s)"},{"name":"Bœuf à braiser","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Eau","unit":"L"},{"name":"Tronçons de ciboule","unit":"tronçon(s)"},{"name":"Tranches de gingembre","unit":"tranche(s)"},{"name":"Anis étoilé","unit":"petite(s) pièce(s)"},{"name":"Vin de cuisine/vin de riz","unit":"ml"},{"name":"Ciboule ciselée","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Sauce soja légère","note":"quantité suffisante"},{"name":"Poivre blanc","note":"quantité suffisante"},{"name":"Sucre blanc","note":"quantité suffisante"},{"name":"Sel","note":"quantité suffisante"}]'::jsonb, '["Couper le bœuf en morceaux de 2 cm de côté. Le mettre dans une casserole d''eau froide, porter à ébullition et cuire 2 minutes pour enlever le sang. Égoutter et rincer.","Dans une autre casserole, porter 2 L d''eau à ébullition. Ajouter 2 tronçons de ciboule de 2 cm, 2 tranches de gingembre, 1 anis étoilé, 5-10 ml de vin de cuisine/vin de riz. Ajouter le bœuf blanchi, couvrir et laisser mijoter (1h en pot en terre, 45 min en cocotte-minute mode viande). La viande est cuite quand une baguette la traverse facilement.","Éplucher les tomates : inciser une croix sur le dessus jusqu''à la moitié. Enfoncer une baguette/couteau-fourchette par le pédoncule. Chauffer à feu doux sur une gazinière en tournant, vérifier régulièrement. Quand la peau se soulève, l''enlever puis couper en petits dés. Plus c''est petit, mieux c''est.","Attention en retirant la peau, c''est chaud. Les tomates pelées sont très glissantes, couper lentement et prudemment.","Chauffer de l''huile dans une poêle à 70 % de la température maximale. Ajouter 10 g de ciboule et 10 g de gingembre, puis les tomates. Faire sauter jusqu''à ce qu''elles soient cuites et que la couleur rouge apparaisse. Ajouter le bœuf cuit et son bouillon, juste assez pour couvrir la viande.","Assaisonner avec du sel, du sucre et de la sauce soja légère selon le goût. Couvrir.","Après ébullition, cuire à feu vif encore 3-5 minutes.","Lorsque la sauce tomate est moyennement épaisse, éteindre le feu. Parsemer de ciboule ciselée et servir."]'::jsonb, '["Plat de viande","Aigre-doux","Mijoté","Familial","Accompagnement du riz"]'::jsonb),
  ('howtocook:meat_dish/豆豉鲮鱼油麦菜/豆豉鲮鱼油麦菜', 'fr', 'Laitue sautée aux conserves de poisson dace et aux haricots noirs', 'Plats de viande', 'La laitue sautée aux conserves de poisson dace et aux haricots noirs est un plat sauté maison rapide, salé et savoureux, qui accompagne bien le riz. Il est originaire des plats en conserve cantonnais. La laitue est croquante et le poisson dace est croustillant. Mélange de viande et de légumes, riche en protéines et en fibres. Recette simple, très accessible aux débutants, environ quinze minutes suffisent.', '[{"name":"Laitue","unit":"g"},{"name":"Conserve de poisson dace (marque Ganzhu)","unit":"boîte"},{"name":"Ail","unit":"gousse(s)"},{"name":"Sauce soja légère","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Huile de cuisson","unit":"ml"}]'::jsonb, '["Préparation des ingrédients :","Lavez la laitue et coupez-la en tronçons.","Ouvrez la boîte de poisson dace, retirez les arêtes principales, coupez en petits morceaux et réservez.","Hachez l''ail.","Processus de cuisson :","Faites chauffer la poêle avec de l''huile, ajoutez la laitue lavée, faites revenir jusqu''à ce qu''elle flétrisse et rende de l''eau, puis retirez-la et jetez l''eau.","Réchauffez la poêle, ajoutez l''huile de la boîte de poisson dace, puis faites revenir l''ail haché jusqu''à ce qu''il soit parfumé.","Après avoir fait revenir l''ail, ajoutez les haricots noirs fermentés de la boîte, mélangez, puis ajoutez les morceaux de poisson dace hachés et mélangez à nouveau.","Une fois bien mélangé, ajoutez la laitue, puis assaisonnez avec la sauce soja légère et le sucre.","Après avoir assaisonné, mélangez rapidement et servez dans un plat."]'::jsonb, '["Plat de viande","Salé et savoureux","Cantonnais","Sauté rapide","Accompagne le riz","Maison","Rapide"]'::jsonb),
  ('howtocook:meat_dish/豉汁排骨', 'fr', 'Travers de porc aux haricots noirs fermentés', 'Plats de viande', 'C''est un plat cuit à la vapeur très apprécié dans les salons de thé cantonais. La saveur des haricots noirs fermentés est riche et les travers de porc sont tendres et se détachent de l''os. Les travers de porc apportent des protéines de qualité et du calcium, tandis que les haricots noirs fermentés ajoutent de la saveur et facilitent l''absorption. La préparation nécessite de tremper, de laver, de mariner et de maîtriser la cuisson à la vapeur, ce qui peut être un défi pour les débutants, mais les étapes sont claires et faciles à suivre. Du début à la fin, il faut environ une heure. Le jus restant est particulièrement délicieux pour accompagner le riz ou les nouilles.', '[{"name":"Travers de porc","unit":"g"},{"name":"Haricots noirs fermentés","unit":"g"},{"name":"Ail haché","unit":"g"},{"name":"Gingembre haché","unit":"g"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Sauce d''huîtres","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Fécule de maïs","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Eau claire","unit":"ml"},{"name":"Oignon vert émincé","note":"à volonté"},{"name":"Graines de sésame blanc","note":"à volonté"}]'::jsonb, '["Faire tremper les travers de porc dans de l''eau froide pendant 10 minutes pour éliminer le sang, changer l''eau et répéter 2 fois, puis sécher avec du papier absorbant.","Faire tremper les haricots noirs fermentés dans de l''eau pendant 5 minutes.","Mélanger tous les ingrédients (ajouter 10 ml d''huile de cuisson), laisser mariner pendant 8 à 30 minutes.","Après ébullition de l''eau, cuire à la vapeur pendant 18 minutes.","Laisser reposer 2 minutes.","Verser 10 ml d''huile chaude dans une casserole et chauffer à 180-200 °C.","Parsemer uniformément d''oignon vert émincé et de graines de sésame blanc, puis verser l''huile chaude sur les garnitures."]'::jsonb, '["Plat de viande","Cantonnais","À la vapeur","Salé et parfumé","Accompagne le riz","Pour invités"]'::jsonb),
  ('howtocook:meat_dish/豉汁蒸白鱔/豉汁蒸白鱔', 'fr', 'Anguille vapeur aux haricots noirs', 'Plats de viande', 'L''anguille vapeur aux haricots noirs est un plat classique cantonais cuit à la vapeur. L''arôme de la sauce aux haricots noirs et à l''ail imprègne la chair du poisson, qui est tendre et savoureuse. L''anguille est riche en protéines de haute qualité et en acides gras insaturés, ce qui est bénéfique pour le corps. Les étapes sont claires, mais la manipulation du poisson cru et la maîtrise de la cuisson peuvent être un défi, adapté aux cuisiniers ayant un peu d''expérience. De la préparation à la table, cela prend environ 30 minutes.', '[{"name":"Anguille","unit":"grammes"},{"name":"Haricots noirs fermentés","unit":"cuillère à soupe"},{"name":"Ail","unit":"gousses"},{"name":"Gingembre","unit":"tranches"},{"name":"Ciboule","unit":"pièce"},{"name":"Sauce soja claire","unit":"cuillère à soupe"},{"name":"Sauce soja foncée","unit":"cuillère à café"},{"name":"Sucre","unit":"cuillère à café"},{"name":"Huile de sésame","unit":"cuillère à café"},{"name":"Fécule de maïs","unit":"cuillère à café"},{"name":"Eau","unit":"cuillère à soupe"},{"name":"Piment rouge","unit":"grammes"}]'::jsonb, '["Vérifier et laver l''anguille :","À l''achat, demandez au poissonnier d''éviscérer, de gratter le mucus et de couper en morceaux d''environ 5 cm.","À la maison, vérifiez l''anguille, rincez-la bien pour vous assurer qu''il ne reste ni mucus ni impuretés.","Optionnel : frottez doucement les morceaux d''anguille avec 3 g de sel et 1 cuillère à café de fécule de maïs, laissez mariner 5 minutes puis rincez pour enlever l''odeur et obtenir une texture plus tendre.","Préparer la sauce :","Dans un petit bol, mélangez 1 cuillère à soupe de haricots noirs fermentés, 2 gousses d''ail hachées, 1,5 cuillère à soupe de sauce soja claire, 0,5 cuillère à café de sauce soja foncée, 0,5 cuillère à café de sucre, 0,5 cuillère à café d''huile de sésame et 1 cuillère à soupe d''eau. Mélangez bien.","Si vous préférez une sauce plus forte, ajoutez 0,5 cuillère à soupe supplémentaire de haricots noirs.","Dresser :","Disposez les morceaux d''anguille à plat dans un plat allant au four en évitant de les superposer.","Saupoudrez uniformément les filaments de gingembre sur l''anguille.","Versez uniformément la sauce aux haricots noirs préparée sur l''anguille.","Cuire à la vapeur :","Ajoutez de l''eau (500 ml) dans un cuiseur vapeur ou un autocuiseur électrique et portez à ébullition.","Placez le plat contenant l''anguille dans le cuiseur vapeur et couvrez.","Faites cuire à la vapeur à feu moyen-vif pendant environ 8 à 10 minutes (ajustez selon la taille des morceaux), jusqu''à ce que l''anguille soit cuite mais pas trop cuite (la chair devient blanche, plus de sang).","Décorer et terminer :","Sortez le plat, parsemez de filaments de ciboule et de filaments de piment rouge (optionnel) pour la décoration.","Vous pouvez arroser d''un peu d''huile de sésame chaude pour rehausser l''arôme.","Servez chaud avec du riz blanc."]'::jsonb, '["Viande","Cantonais","Vapeur","Savoureux","Accompagnement de riz","Familial","Pour invités"]'::jsonb),
  ('howtocook:meat_dish/贵州辣子鸡/贵州辣子鸡', 'fr', 'Poulet épicé du Guizhou', 'Plats de viande', 'Le poulet épicé du Guizhou est un plat familial classique de la région du Guizhou, cuit avec du piment ciba et diverses épices. La viande de poulet est tendre et moelleuse, les pommes de terre sont fondantes et imprégnées de saveurs, l''ensemble est épicé et riche. Le poulet est riche en protéines de haute qualité, accompagné de pommes de terre et d''autres légumes, équilibré sur le plan nutritionnel. Cette recette comporte plusieurs étapes, ce qui peut être un défi pour les débutants, mais en suivant les instructions, on peut réussir. De la préparation à la sortie du feu, il faut compter environ 1,5 heures.', '[{"name":"Poulet fermier au maïs","unit":"livre"},{"name":"Pomme de terre","unit":"pièce"},{"name":"Ail","unit":"pièce"},{"name":"Feuille de laurier","unit":"feuille"},{"name":"Gingembre","unit":"pièce"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Poivre du Sichuan / Poivre du Sichuan engourdissant","note":"quantité suffisante"},{"name":"Piment ciba","unit":"g"},{"name":"Pâte de soja fermentée (doubanjiang)","note":"quantité suffisante"},{"name":"Bière","unit":"bouteille"},{"name":"Tige d''ail","unit":"tige"},{"name":"Vin de riz fermenté (jiuzao)","note":"quantité suffisante"},{"name":"Huile de cuisson","unit":"livre"}]'::jsonb, '["Dans la poêle, ajoutez de l''huile jusqu''à mi-hauteur de la poêle. Faites frire les pommes de terre coupées en bâtonnets jusqu''à ce qu''elles soient dorées, puis réservez. Lorsque l''huile est assez chaude pour chauffer la main, mettez les morceaux de poulet coupés dans la poêle pour les faire frire, ajoutez les tranches de gingembre et les grains de poivre du Sichuan.","Au début de la friture du poulet, l''huile est trouble à cause de l''eau contenue dans le poulet. Lorsque l''huile devient claire, le poulet est frit, puis réservez-le.","Maintenant, retirez un tiers de l''huile de la poêle, car vous n''avez pas besoin d''autant d''huile pour la suite.","Chauffez l''huile restante dans la poêle, ajoutez le piment ciba, la pâte de soja fermentée (doubanjiang), les tranches de gingembre, faites revenir jusqu''à obtenir une huile rouge. Ajoutez les morceaux de poulet frits et faites-les sauter uniformément.","Lorsque le poulet est bien coloré, ajoutez la sauce soja foncée (lao chou), versez la bière (elle doit recouvrir le poulet), ajoutez les feuilles de laurier, couvrez et laissez mijoter pendant dix minutes, en remuant de temps en temps.","Ajoutez ensuite les bâtonnets de pommes de terre et les gousses d''ail (entières, non coupées, de préférence une par une), puis laissez mijoter encore 20 minutes.","Enfin, ajoutez le vin de riz fermenté (jiuzao), faites sauter uniformément, puis ajoutez les tiges d''ail (ciboule) coupées, et servez."]'::jsonb, '["Plat de viande","Épicé","Saveur du Guizhou","Frit puis mijoté","Accompagnement du riz","Pour les invités"]'::jsonb),
  ('howtocook:meat_dish/辣椒炒肉', 'fr', 'Poivrons sautés au porc', 'Plats de viande', 'Le poivron sauté au porc est un plat familial au goût prononcé du Hunan. Les poivrons sont séchés et légèrement grillés, les tranches de viande sont tendres et savoureuses, salées et légèrement épicées, parfaites avec du riz. Le porc est riche en protéines de haute qualité et en vitamines B, tandis que le poivron vert fournit une abondance de vitamine C. Ce plat nécessite de maîtriser la cuisson à sec et le sauté rapide, adapté aux cuisiniers ayant une certaine expérience. De la préparation à la finition, il faut environ 30 minutes.', '[{"name":"Poivron vert","unit":"pièce"},{"name":"Porc maigre","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sauce d''huître","unit":"ml"},{"name":"Ail","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Haricots noirs fermentés","unit":"g"}]'::jsonb, '["Lavez les poivrons verts, retirez les queues et les graines, puis coupez-les en morceaux à la manière ''rouleau'' (en biais). Réservez.","Écrasez l''ail avec le plat du couteau, puis coupez-le en lamelles. Hachez finement le gingembre.","Coupez le porc maigre en tranches (dans le sens des fibres, c''est-à-dire que le couteau et les fibres sont parallèles, les tranches auront des stries en forme de ''chuan'').","Rincez les tranches de porc, mettez-les dans un bol, ajoutez la sauce soja légère, la sauce d''huître et le sel mesurés, mélangez bien, et laissez mariner 10 minutes.","Chauffez la poêle, sans huile, ajoutez les poivrons coupés et faites-les sauter à feu vif jusqu''à ce qu''ils soient légèrement grillés (aspect tigré). Ajoutez 2g de sel et continuez à remuer pendant 1 minute, puis retirez.","Sans laver la poêle, chauffez-la à feu vif, ajoutez 8 ml d''huile, attendez 30 secondes, ajoutez l''ail et le gingembre, faites revenir 15 secondes.","Ajoutez le porc mariné dans la poêle et faites sauter 2 minutes, puis ajoutez les poivrons précuits et faites sauter 1 minute.","Selon votre goût, ajoutez les haricots noirs fermentés, puis la sauce soja foncée, continuez à remuer 30 secondes.","Retirez du feu et servez."]'::jsonb, '["Plat de viande","Cuisine du Hunan","Salé et légèrement épicé","Cuisson à sec","Sauté rapide","Accompagnement de riz","Familial"]'::jsonb),
  ('howtocook:meat_dish/酱排骨/酱排骨', 'fr', 'Côtes levées à la sauce soja', 'Plats de viande', 'Les côtes levées à la sauce soja sont d’un rouge profond, la viande est fondante, l’os parfumé, la sauce épaisse et savoureuse, salée avec une touche sucrée. C’est un plat familial classique. Les côtes levées sont riches en protéines et en calcium. La recette demande de caraméliser le sucre et une cuisson longue, un défi pour les débutants, mais en suivant les étapes, ça se maîtrise. Comptez environ 1 heure du début à la fin.', '[{"name":"Côtes levées","unit":"g"},{"name":"Poudre cinq-épices","unit":"g"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sucre blanc","unit":"g"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sauce d''huître","unit":"ml"},{"name":"Piment oiseau","unit":"pièce(s)"},{"name":"Ail","unit":"gousse(s)"},{"name":"Gingembre","unit":"tranche(s)"}]'::jsonb, '["Mettez de l''eau à chauffer dans une casserole, ajoutez les côtes levées, les tranches de gingembre et le vin de cuisine. Portez à ébullition, écumez la mousse blanche avec une cuillère, puis retirez après 2-3 minutes.","Rincez les côtes levées à l''eau froide, lavez-les 2 à 3 fois.","À feu doux, ajoutez de l''huile de cuisson, puis le sucre blanc. Remuez doucement jusqu''à ce que le sucre devienne jaune (caramel).","Ajoutez les côtes levées et faites-les sauter 30 secondes. Ajoutez la sauce soja légère, la sauce d''huître, la poudre cinq-épices, l''ail et les piments oiseaux, faites sauter encore 30 secondes. Ajoutez de l''eau claire à hauteur des côtes levées.","Faites cuire à feu vif pendant 30 minutes, ajoutez la sauce soja foncée pour colorer, puis laissez cuire encore 10 minutes.","Retirez du feu et disposez dans un plat."]'::jsonb, '["Plat de viande","Sauce soja","Salé-sucré","Mijoté","Accompagnement de riz","Plat familial"]'::jsonb),
  ('howtocook:meat_dish/酱牛肉/酱牛肉', 'fr', 'Bœuf à la sauce soja', 'Plats de viande', 'Le bœuf à la sauce soja est un plat froid traditionnel du nord de la Chine, à la sauce parfumée, à la texture ferme et moelleuse. Le jarret de bœuf est riche en protéines de haute qualité et en acides aminés, et devient plus digeste après une longue cuisson. La préparation n''est pas compliquée, mais elle comprend la marinade, le mijotage et un long repos au réfrigérateur. Pour les débutants, il faut un peu de patience. Le temps total nécessaire est d''environ 10 heures.', '[{"name":"Jarret de bœuf","unit":"grammes"},{"name":"Feuille de laurier","unit":"feuille(s)"},{"name":"Gingembre","unit":"tranche(s)"},{"name":"Ciboule","unit":"morceau(x)"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Cannelle (bâton)","unit":"morceau(x)"},{"name":"Sucre candi (morceaux)","unit":"morceau(x)"},{"name":"Poivre du Sichuan","unit":"grain(s)"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Sel","unit":"grammes"},{"name":"Anis étoilé","unit":"unité(s)"},{"name":"Pâte de soja jaune","unit":"ml"}]'::jsonb, '["Lavez soigneusement le jarret de bœuf, puis faites-le tremper dans l''eau claire pendant 1 heure pour éliminer le sang.","À l''aide d''un cure-dent ou d''une fourchette, percez des trous sur la surface du jarret de bœuf. Ajoutez le vin de cuisine, le poivre du Sichuan et les tranches de gingembre. Enveloppez bien le récipient d''un film plastique et laissez mariner pendant 4 à 6 heures.","Coupez le jarret de bœuf en morceaux d''environ 8 cm, sans dépasser 10 cm.","Placez les morceaux de bœuf dans une marmite, ajoutez de l''eau froide jusqu''à ce qu''ils soient entièrement recouverts. Portez à ébullition et commencez à minuter. Écumez la mousse. Au bout de 3 minutes, retirez du feu, sortez le bœuf et rincez-le à l''eau tiède.","Mettez le bœuf rincé dans une cocotte ou une marmite. Ajoutez de l''eau jusqu''à couvrir. Portez à grand feu, puis ajoutez tous les ingrédients non utilisés sauf le sel.","Une fois l''eau bouillante, réduisez le feu à doux et laissez cuire 90 minutes. Ensuite, ajoutez le sel.","Après avoir ajouté le sel, continuez la cuisson à feu doux pendant 90 minutes (note : vérifiez le niveau d''eau toutes les 30 minutes ; il doit être au moins à 80 % de la hauteur du bœuf).","Au bout de 180 minutes de cuisson totale, sortez le jarret de bœuf. Enveloppez-le hermétiquement de film plastique et placez-le au réfrigérateur pendant plusieurs heures.","Une fois refroidi, coupez le bœuf en tranches dans le sens des fibres et servez. Conservez le reste du bœuf non tranché au réfrigérateur."]'::jsonb, '["Plat de viande","Sauce soja","Plat froid","Nordique","Mijoté","Pour l''apéritif","Pour les invités"]'::jsonb),
  ('howtocook:meat_dish/醉排骨/醉排骨', 'fr', 'Côtes de porc ivres', 'Plats de viande', 'Les côtes de porc ivres sont un plat traditionnel de Fuzhou, à la texture croustillante à l''extérieur et tendre à l''intérieur, aigre-douce et appétissante, avec l''arôme unique de la sauce de poisson. Les côtes de porc sont riches en protéines et en calcium, nutritives et savoureuses. Ce plat nécessite de maîtriser les techniques d''enrobage et de double friture, il est donc plus adapté aux cuisiniers ayant un peu d''expérience. Il faut environ 40 minutes au total.', '[{"name":"Côtes de porc","unit":"g"},{"name":"Fécule de patate douce","unit":"g"},{"name":"Jaune d''œuf","unit":"pièce(s)"},{"name":"Sauce de poisson","unit":"ml"},{"name":"Ail émincé","unit":"gousse(s)"},{"name":"Vinaigre aromatique","unit":"ml"},{"name":"Sucre blanc","unit":"g"},{"name":"Ketchup","unit":"g"},{"name":"Ciboule","unit":"tige(s)"},{"name":"Graines de sésame","unit":"g"},{"name":"Huile de cuisson","unit":"ml"}]'::jsonb, '["Ajouter 5 g de fécule de patate douce et de l''eau aux côtes de porc, mélanger, rincer 2 à 3 fois, puis mettre dans un grand bol et réserver.","Ajouter aux côtes de porc la sauce de poisson, la fécule de patate douce et le jaune d''œuf, bien mélanger.","Mettre les côtes de porc une par une dans la poêle (ne surtout pas verser tout le bol), en veillant à ce qu''elles ne se collent pas entre elles.","Après avoir mis toutes les côtes, toutes les 30 secondes, retourner les morceaux de viande des deux côtés avec une cuillère, jusqu''à ce que la surface des côtes soit dorée.","Sortir les côtes, une minute plus tard les remettre dans l''huile chaude pour continuer à frire, jusqu''à ce que la surface des morceaux de viande soit bien dorée, puis les sortir et les mettre dans un grand bol pour réserver.","Préparer un petit bol, ajouter l''ail émincé, le vinaigre aromatique, le sucre blanc, la sauce de poisson, le ketchup, la ciboule hachée et les graines de sésame, bien mélanger, puis verser 5 ml d''huile chaude.","Verser la sauce sur les côtes de porc, bien mélanger, puis transvaser dans un plat de service."]'::jsonb, '["Viande","Aigre-doux","Savoureux","Friture","Cuisine de Fuzhou","Pour recevoir","Accompagnement du riz"]'::jsonb),
  ('howtocook:meat_dish/青椒土豆炒肉/青椒土豆炒肉', 'fr', 'Poivron vert, pomme de terre et porc sauté', 'Plats de viande', 'Le sauté de poivron vert, pomme de terre et porc est un plat familial combinant viande et légumes. Il est savoureux, croquant et parfumé, excellent avec du riz. La pomme de terre est riche en glucides et vitamine C, le poivron vert fournit vitamine C et fibres, et le porc apporte des protéines de qualité. La recette n''est pas compliquée, adaptée aux débutants, du début à la fin en environ 1 heure.', '[{"name":"Poivron vert","unit":"pièce"},{"name":"Pomme de terre","unit":"pièce"},{"name":"Porc (poitrine)","unit":"g"},{"name":"Ciboule","unit":"tige"},{"name":"Gingembre","unit":"morceau"},{"name":"Ail","unit":"gousse"},{"name":"Sel","unit":"g"},{"name":"Sauce soja","unit":"ml"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Fécule de pomme de terre","unit":"g"},{"name":"Eau","unit":"g"}]'::jsonb, '["Retirer les pédoncules des poivrons et les couper en petits morceaux. Éplucher la pomme de terre et la couper en fines tranches de 2 mm. Couper le porc en fines tranches de 4 mm. Couper la ciboule en petits tronçons de 3 mm en coupe transversale et longitudinale. Éplucher le gingembre et l''ail, les écraser et les hacher finement. Mélanger la fécule de pomme de terre avec environ 15 g d''eau jusqu''à obtenir une sauce épaisse.","Chauffer l''huile dans un wok à 70 % de chaleur maximale. Ajouter les tranches de porc et les faire sauter doucement jusqu''à ce qu''elles perdent leur couleur rouge. Ajouter environ 3 ml de sauce soja, remuer pour bien colorer la viande. Ajouter environ 2 g de sel.","Baisser à 50 % de chaleur, ajouter la ciboule, le gingembre et l''ail, faire sauter 5 secondes. Ajouter les tranches de pomme de terre, passer à 70 % de chaleur et remuer uniformément. Ajouter environ 5 ml de sauce soja et 2 g de sel. Faire sauter jusqu''à ce que les pommes de terre soient cuites mais encore fermes, avec une légère coloration dorée.","Passer à 80 % de chaleur, ajouter les poivrons verts. Sauter à feu vif pour faire dégager les arômes (de la fumée blanche apparaît). Remuer uniformément pendant 1 minute pour colorer. Enfin, verser la sauce de fécule autour du wok et baisser à 40 % de chaleur pour épaissir.","Lorsque la sauce devient visqueuse, éteindre le feu et servir dans une assiette."]'::jsonb, '["Plat de viande","Savoureux","Familial","Accompagnement de riz","Sauté","Rapide"]'::jsonb),
  ('howtocook:meat_dish/青椒酿/青椒酿', 'fr', 'Poivrons farcis', 'Plats de viande', 'Ce plat classique de la cuisine familiale du Guangxi consiste en des poivrons verts farcis d''une farce de viande ou de crevettes bien assaisonnée, poêlés jusqu''à ce que la peau plisse et prenne une couleur tigrée, puis mijotés pour imprégner les saveurs. Le parfum du poivron se mêle à la saveur umami de la farce, salé et légèrement épicé, parfait pour accompagner le riz. Le porc et les crevettes apportent des protéines de qualité, et les poivrons sont riches en vitamine C, offrant un repas équilibré. Il faut un peu de patience pour farcir, mais la recette est claire et se réalise en environ 30 minutes.', '[{"name":"Poivrons verts (piments verts, choisir droits et à chair épaisse)","unit":"pièce(s)"},{"name":"Porc (de préférence l''épaule)","unit":"g"},{"name":"Oignon vert","unit":"tige(s)"},{"name":"Gingembre","unit":"petit morceau"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Eau","unit":"ml"},{"name":"Fécule (optionnel)","unit":"g"},{"name":"Ail (optionnel)","unit":"gousse(s)"},{"name":"Sauce d''huître (optionnel)","unit":"ml"},{"name":"Vin de cuisine (optionnel)","unit":"ml"},{"name":"Œuf (optionnel)","unit":"pièce(s)"},{"name":"Poivre blanc (optionnel)","unit":"g"},{"name":"Sucre (optionnel)","unit":"g"},{"name":"Crevettes (pour version crevettes)","unit":"g"}]'::jsonb, '["Laver le porc et le hacher en farce (ou utiliser un hachoir). Hacher finement le gingembre et l''oignon vert.","Ajouter à la farce de porc : gingembre haché, oignon vert haché, 15 ml de sauce soja légère, 5 ml de sauce soja foncée, 3 g de sel. Mélanger uniformément.","Optionnel : ajouter 10 ml de vin de cuisine, 10 ml de sauce d''huître, 1 œuf, 5 g de fécule, 2 g de poivre blanc, 5 g de sucre.","Mélanger la farce dans un sens jusqu''à ce qu''elle devienne collante et ferme. Laisser reposer 10 minutes.","Laver les poivrons, retirer le pédoncule. À l''aide de baguettes, retirer délicatement les graines et les membranes blanches intérieures, en gardant le poivron entier et intact.","Optionnel : saupoudrer environ 5 g de fécule à l''intérieur des poivrons, secouer pour répartir uniformément, afin d''aider la farce à adhérer.","À l''aide de baguettes ou d''une poche à douille, farcir les poivrons avec la farce, en remplissant bien mais sans trop serrer pour éviter de les déchirer.","Réserver tous les poivrons farcis.","Dans un bol, mélanger 15 ml de sauce soja légère, 5 ml de sauce soja foncée et 100 ml d''eau. Bien mélanger.","Optionnel : ajouter 5 g de fécule pour épaissir la sauce.","Chauffer une poêle avec 30 ml d''huile de cuisson. Lorsque l''huile est à 50-60 % de chaleur, déposer les poivrons farcis (côté farce vers le bas d''abord).","Cuire à feu moyen-doux en retournant les poivrons pour que chaque face soit poêlée jusqu''à ce que la peau plisse et prenne une couleur tigrée. Réserver.","Laisser un peu d''huile dans la poêle. Optionnel : faire revenir de l''ail haché.","Verser la sauce préparée dans la poêle, porter à ébullition, puis ajouter les poivrons farcis.","Réduire à feu moyen-doux, couvrir et laisser mijoter 5 à 8 minutes, jusqu''à ce que la sauce épaississe et que les poivrons soient tendres.","Retirer le couvercle et augmenter le feu pour réduire la sauce jusqu''à ce qu''elle soit brillante et enrobe les poivrons. Servir.","Pour la version aux crevettes : retirer le boyau de 250 g de crevettes, les écraser avec le dos d''un couteau en une pâte (garder une texture légèrement granuleuse pour une meilleure texture. On peut aussi utiliser de la pâte de crevette du commerce, de forme triangulaire, à presser directement dans les poivrons).","Assaisonnement de la pâte de crevette : 5 g de gingembre haché, 2 g de sel, 5 g de fécule, 10 ml de sauce soja légère.","Optionnel : ajouter 5 ml de vin de cuisine, 1 g de poivre blanc, un demi-blanc d''œuf.","Mélanger dans un sens jusqu''à ce que la pâte de crevette soit ferme. Laisser reposer 10 minutes.","Les étapes de farce, poêlage et mijotage sont identiques à la version au porc.","La pâte de crevette cuit plus rapidement ; réduire le temps de mijotage à 4-5 minutes."]'::jsonb, '["Plat de viande","Salé","Légèrement épicé","Accompagnement du riz","Poêlé-mijoté","Style Guangxi"]'::jsonb),
  ('howtocook:meat_dish/香干肉丝', 'fr', 'Lanières de porc et tofu pressé', 'Plats de viande', 'Le porc et tofu pressé est un sauté familial salé et parfumé qui accompagne bien le riz. Les lanières de porc sont tendres, le tofu pressé est souple, et les poivrons verts sont croquants. Riche en protéines animales et végétales, avec des poivrons verts pour les vitamines. Difficulté moyenne, accessible aux débutants après un peu de pratique. Temps de préparation estimé : environ 30 minutes.', '[{"name":"Filet de porc (lanières)","unit":"g"},{"name":"Tofu pressé parfumé","unit":"g"},{"name":"Poivron vert","unit":"pièce(s)"},{"name":"Sel","unit":"g"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Fécule de maïs","unit":"g"},{"name":"Ail","unit":"g"},{"name":"Bouillon de poule en poudre","unit":"g"}]'::jsonb, '["Mélanger les lanières de porc (si vous n''en avez pas, coupez-les vous-même) avec la sauce soja légère (3 ml) et la fécule de maïs. Réserver.","Laver les poivrons verts, puis les tailler en biais (rouleau) et réserver.","Couper l''ail en tranches horizontales. Couper le tofu pressé en lanières.","Mélanger la fécule de maïs avec l''eau (10 ml) et bien remuer.","Dans une poêle propre, ajouter 15 ml d''huile. Sans attendre qu''elle soit chaude, ajouter les lanières de porc et les séparer délicatement. Dès qu''elles sont cuites, les retirer immédiatement, en laissant l''huile dans la poêle.","Mettre les tranches d''ail et les lanières de tofu pressé dans la poêle. Ajouter 2 ml de sauce soja légère et faire sauter uniformément.","Après 2-3 minutes (selon la puissance du feu), ajouter les lanières de poivron vert, mélanger et faire sauter.","Après 1 minute, ajouter les lanières de porc et mélanger.","Verser le mélange de fécule et d''eau pour lier. Ajouter 3 g de sel et 2 g de bouillon de poule en poudre. Faire sauter 2-3 minutes, puis servir.","Prêt."]'::jsonb, '["Plat de viande","Salé et parfumé","Sauté rapide","Familial","Accompagne le riz"]'::jsonb),
  ('howtocook:meat_dish/香干芹菜炒肉/香干芹菜炒肉', 'fr', 'Sauté de tofu pressé, céleri et porc', 'Plats de viande', 'Le sauté de tofu pressé, céleri et porc est un plat familial : le tofu est moelleux, le céleri croquant, le porc tendre, avec une saveur salée-umami légèrement épicée. Le céleri est riche en fibres, le tofu et le porc fournissent des protéines végétales et animales de qualité. La recette est simple, adaptée aux débutants, de la préparation à la cuisson en environ 30 minutes.', '[{"name":"Tofu pressé","unit":"g"},{"name":"Céleri","unit":"branche"},{"name":"Porc","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Piment","unit":"pièce"},{"name":"Poivre du Sichuan","unit":"grain"},{"name":"Sel","unit":"g"},{"name":"Bouillon de poulet en poudre","unit":"g"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Sauce d''huître","unit":"ml"},{"name":"Huile de cuisson","unit":"ml"}]'::jsonb, '["Retirer les feuilles du céleri, couper en tronçons ne dépassant pas 4 cm, réserver.","Couper le tofu pressé en lanières de la largeur d''un petit doigt, réserver.","Émincer ou hacher l''ail, réserver.","Couper le piment en rondelles ou en biais, réserver.","Chauffer la poêle, ajouter 10 à 15 ml d''huile de cuisson. Attendre 10 secondes que l''huile chauffe.","Ajouter les grains de poivre du Sichuan et l''ail, faire revenir jusqu''à ce qu''ils soient parfumés (si vous aimez le gingembre, vous pouvez ajouter quelques tranches ou filaments).","Ajouter le porc et faire sauter jusqu''à ce qu''il change de couleur, puis ajouter 8 ml de sauce soja foncée pour colorer et bien mélanger (si vous avez de la pâte de haricots fermentés, ajouter 3 ml et mélanger).","Ajouter le tofu pressé et faire sauter environ 2 minutes.","Ajouter le piment et faire sauter environ 1 à 2 minutes.","Ajouter le céleri, ajouter 5 g de sel, faire sauter 1 minute.","Ajouter 3 g de bouillon de poulet en poudre, 5 ml de sauce d''huître, bien mélanger, puis servir."]'::jsonb, '["Plat de viande","Familial","Accompagne le riz","Rapide","Salé-umami","Légèrement épicé","Sauté"]'::jsonb),
  ('howtocook:meat_dish/香煎五花肉/香煎五花肉', 'fr', 'Poitrine de porc poêlée', 'Plats de viande', 'La poitrine de porc poêlée est un plat de viande rapide de style familial. Les tranches de poitrine sont poêlées jusqu''à devenir croustillantes et légèrement grasses mais non grasses, accompagnées de feuilles de laitue croquantes et de pâte de fèves salée et umami, le tout offrant une saveur riche et dégraissante. Le porc est riche en protéines de haute qualité et en graisses, fournissant rapidement de l''énergie, tandis que la laitue apporte des fibres alimentaires et des vitamines pour un équilibre nutritionnel. Ce plat convient aux personnes ayant une certaine base en cuisine ; les débutants peuvent aussi le réaliser facilement en faisant attention à la température et aux éclaboussures d''huile. De la préparation à la cuisson, il faut environ une demi-heure.', '[{"name":"Poitrine de porc (de préférence 20 cm × 6 cm × 5 cm)"},{"name":"Laitue","unit":"pièce"},{"name":"Sauce soja","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Glutamate monosodique","unit":"g"},{"name":"Vin de cuisson","unit":"g"},{"name":"Gingembre","unit":"tranche"},{"name":"Ail","unit":"gousse"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Pâte de fèves","note":"quantité suffisante"}]'::jsonb, '["Trancher la poitrine de porc dans le sens de la longueur en tranches de 1 mm à 1,5 mm d''épaisseur, réserver.","Mettre les tranches de porc dans un bol, ajouter successivement 8 g de sauce soja, 1 g de sel, 1 g de glutamate monosodique, 10 g de vin de cuisson, deux tranches de gingembre et deux gousses d''ail écrasées. Laisser mariner 10 minutes.","Détacher les feuilles de laitue à la main, les laver et les réserver.","Chauffer la poêle, verser 5 ml d''huile de cuisson. Lorsque l''huile commence à fumer légèrement, ajouter les tranches de porc. Faire dorer un côté puis retourner, et faire de même pour l''autre côté.","Retirer le porc de la poêle et le disposer dans un plat.","Étaler de la pâte de fèves sur les feuilles de laitue, puis enrouler les tranches de porc dedans et déguster."]'::jsonb, '["Plat de viande","Poêlé","Fait maison","Rapide","Accompagnement de riz","Sauce salée"]'::jsonb),
  ('howtocook:meat_dish/香菇滑鸡/香菇滑鸡', 'fr', 'Poulet soyeux aux champignons parfumés', 'Plats de viande', 'Poulet soyeux aux champignons parfumés est un plat familial à base de cuisses de poulet et de champignons shiitakés. Les cuisses de poulet, après avoir été sautées et mijotées, deviennent tendres et soyeuses, accompagnées de l''arôme unique des champignons. La sauce est riche et savoureuse. Ce plat de style cantonais convient à tous les âges. Le poulet est riche en protéines de haute qualité et en acides aminés, tandis que les champignons contiennent des polysaccharides et des fibres alimentaires, bénéfiques pour l''immunité et la digestion. Ce plat demande un certain savoir-faire au niveau du couteau et du contrôle de la cuisson, ce qui peut être un défi pour les débutants. La préparation prend environ 1 heure.', '[{"name":"Cuisses de poulet","unit":"pièce"},{"name":"Champignons shiitakés séchés","unit":"pièce"},{"name":"Gingembre","unit":"tranche"},{"name":"Oignon vert","unit":"pièce"},{"name":"Ail","unit":"gousse"},{"name":"Eau tiède","unit":"ml"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Sucre","unit":"ml"},{"name":"Huile de sésame","unit":"ml"}]'::jsonb, '["Faire tremper les champignons shiitakés séchés dans de l''eau tiède.","Couper le gingembre en petits morceaux, couper les oignons verts en tronçons, couper les gousses d''ail en deux (en petits dés).","Désosser les cuisses de poulet (possible sans désosser, mais cela ralentit un peu le repas du programmeur), les couper en petits morceaux.","Couper les champignons réhydratés en quatre, réserver l''eau de trempage.","Blanchir les morceaux de poulet 1 minute pour enlever les impuretés et le sang.","Ajouter aux morceaux de poulet 15 ml de vin de cuisine, 15 ml de sauce soja claire, 1,5 g de sel, 15 ml de sauce soja foncée. Mélanger pour enrober.","Chauffer l''huile à 30 % de sa capacité (feu moyen-doux), ajouter le poulet et faire sauter jusqu''à ce qu''il soit doré. Réserver.","Laisser un fond d''huile dans la poêle, ajouter les oignons, le gingembre et l''ail, faire revenir jusqu''à ce qu''ils soient parfumés. Ajouter les champignons et faire sauter à feu vif en remuant.","Attendre environ 20 secondes que l''arôme des champignons se dégage, puis ajouter le poulet réservé, toute l''eau de trempage des champignons (l''opération clé selon le programmeur), 15 ml de sucre et 30 ml de sauce soja claire.","Baisser à feu moyen sans couvrir, laisser mijoter 2 minutes pour réduire la sauce. Ajouter 5 ml d''huile de sésame, parsemer d''oignon vert ciselé, puis éteindre le feu et servir."]'::jsonb, '["viande","savoureux","cantonais","fait maison","accompagne le riz","mijoté"]'::jsonb),
  ('howtocook:meat_dish/香辣鸡爪煲/香辣鸡爪煲', 'fr', 'Ragoût de pattes de poulet pimenté', 'Plats de viande', 'Épicé et riche, avec une texture moelleuse, c''est un plat d''accompagnement courant dans les repas familiaux. Les pattes de poulet sont riches en collagène, aident à hydrater la peau et renforcer les os. La préparation nécessite d''abord de couper les griffes, et si vous utilisez des pattes entières, il faut aussi les désosser, ce qui est un peu difficile pour les débutants, mais en suivant les étapes patiemment, on peut réussir. De l''ébouillantage au mijotage puis au sauté, cela prend environ 45 minutes.', '[{"name":"pattes de poulet","unit":"livre"},{"name":"oignon vert","unit":"tige"},{"name":"gingembre","unit":"gramme"},{"name":"ail","unit":"gramme"},{"name":"vin de cuisson","note":"quantité suffisante"},{"name":"feuille de laurier","unit":"feuille"},{"name":"anis étoilé","unit":"pièce"},{"name":"sauce soja claire","note":"quantité suffisante"},{"name":"sauce soja foncée","note":"quantité suffisante"},{"name":"piment rouge","unit":"pièce"},{"name":"poudre de piment (optionnel)","note":"quantité suffisante"},{"name":"sauce d''huître","unit":"gramme"},{"name":"poudre cinq-épices","note":"quantité suffisante"},{"name":"sel","note":"quantité suffisante"},{"name":"glutamate","note":"quantité suffisante"}]'::jsonb, '["Coupez les griffes des pattes de poulet. Si vous avez acheté seulement la partie du pied, coupez-la en deux. Si ce sont des pattes entières, il faut les désosser. Lavez à l''eau claire.","Mettez les pattes de poulet dans une casserole d''eau froide, ajoutez l''oignon, le gingembre et le vin de cuisson, portez à ébullition, écumez les impuretés.","Ajoutez les feuilles de laurier, l''anis étoilé, la sauce soja claire et la sauce soja foncée, couvrez et laissez mijoter à feu doux pendant trente minutes.","Retirez les pattes de poulet, réservez un bol de bouillon de poule.","Faites chauffer de l''huile dans une poêle, faites revenir à feu doux le gingembre haché, l''ail haché et les piments rouges. Si vous aimez épicé, ajoutez un peu de poudre de piment. Ajoutez la sauce soja claire, la sauce soja foncée, la sauce d''huître, la poudre cinq-épices et le sel, faites revenir jusqu''à ce que la sauce soit parfumée.","Ajoutez les pattes de poulet, assaisonnez avec un peu de sel, faites sauter pendant une à deux minutes, puis versez le bouillon de poule en remuant.","Ajoutez le glutamate pour rehausser la saveur, saupoudrez de morceaux d''oignon vert, mélangez bien et servez."]'::jsonb, '["Plat de viande","Épicé","Mijoté","Accompagnement de riz","Fait maison","Moelleux"]'::jsonb),
  ('howtocook:meat_dish/鱼香肉丝', 'fr', 'Lanières de porc à la sauce aigre-douce', 'Plats de viande', 'Les lanières de porc à la sauce aigre-douce sont un classique de la cuisine sichuanaise. La sauce est aigre-douce et légèrement épicée, la viande est tendre, accompagnée de carottes, de poivron vert et de champignons noirs, ce qui donne une texture riche. Ce plat est riche en protéines et en vitamines, avec un bon équilibre entre viande et légumes. La préparation demande un certain savoir-faire : il faut bien ajuster la sauce et maîtriser le sauté. Les débutants sont invités à suivre scrupuleusement les étapes. Temps de préparation estimé : environ 40 minutes (hors temps de trempage des champignons).', '[{"name":"Filet de porc","unit":"g"},{"name":"Carotte","unit":"g"},{"name":"Poivron vert","unit":"g"},{"name":"Champignon noir séché","unit":"g"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Blanc d''œuf","unit":"unité"},{"name":"Fécule","unit":"g"},{"name":"Vinaigre","unit":"ml"},{"name":"Sucre blanc","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Ciboule","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Pâte de soja épicée","unit":"g"}]'::jsonb, '["Préparation de la marinade : mélanger les ingrédients suivants :","Sauce soja légère 5ml","Vin de cuisine 5ml","Fécule 5g","Eau 20ml","Blanc d''œuf 1","Préparation de la sauce : mélanger les ingrédients suivants :","Sauce soja légère 5ml","Vinaigre 15ml","Sucre blanc 10g","Sel 1g","Fécule 5g","Eau 20ml","Mariner le filet de porc avec la marinade pendant 15-30 minutes. Bien masser la viande.","Faire tremper les champignons noirs séchés 4 heures, les laver et les couper en petits morceaux.","Laver le poivron vert, retirer le pédoncule, couper en lanières.","Laver la carotte, couper en lanières, blanchir les lanières de carotte.","Hacher le gingembre et l''ail.","Ciboule coupée en tronçons de 5mm.","Chauffer la poêle, ajouter 15ml d''huile.","Verser la viande marinée dans la poêle, la saisir rapidement jusqu''à ce qu''elle blanchisse, réserver.","Chauffer la poêle, ajouter 5ml d''huile.","Ajouter toute la ciboule, le gingembre, l''ail et la pâte de soja épicée.","Ajouter toute la carotte, faire sauter 20s, puis ajouter le poivron vert et les champignons noirs, faire sauter 2 minutes.","Ajouter la viande sauté. Mélanger rapidement. Ne pas faire sauter plus de 20 secondes.","Verser la sauce. Mélanger rapidement. Ne pas faire sauter plus de 15 secondes.","Éteindre le feu, servir dans une assiette."]'::jsonb, '["Viande","Sichuan","Aigre-doux","Légèrement épicé","Accompagnement de riz","Fait maison"]'::jsonb),
  ('howtocook:meat_dish/鱼香茄子/鱼香茄子', 'fr', 'Aubergines à la sauce Yuxiang', 'Plats de viande', 'L''aubergine à la sauce Yuxiang est un plat familial classique du Sichuan, aigre-doux et légèrement épicé. Les aubergines sont tendres et imbibées de sauce, parfaites avec du riz. Riches en fibres et en vitamines, elles sont associées à de la viande hachée pour un apport en protéines. La difficulté est moyenne ; il faut maîtriser la friture des aubergines et l''assaisonnement, mais même les débutants peuvent réussir avec un peu de pratique. Du début à la fin, il faut environ 30 minutes.', '[{"name":"aubergine","unit":"pièce","note":""},{"name":"viande hachée","unit":"g","note":""},{"name":"sel","unit":"g","note":""},{"name":"sucre","unit":"g","note":""},{"name":"glutamate","unit":"g","note":""},{"name":"sauce soja claire","unit":"ml","note":""},{"name":"sauce soja foncée","unit":"ml","note":""},{"name":"vinaigre","unit":"ml","note":""},{"name":"fécule diluée","unit":"ml","note":""},{"name":"pâte de haricots fermentés","unit":"g","note":""},{"name":"oignon vert","unit":"","note":"quantité suffisante"},{"name":"gingembre","unit":"","note":"quantité suffisante"},{"name":"ail","unit":"","note":"quantité suffisante"},{"name":"piment oiseau","unit":"","note":"quantité suffisante"}]'::jsonb, '["Couper les aubergines en bâtonnets.","Hacher la viande, émincer l''oignon vert, le gingembre et l''ail, couper les piments en dés.","Préparer la sauce Yuxiang : dans un bol, mélanger le sel, le glutamate, le sucre, la sauce soja claire, la sauce soja foncée, le vinaigre et la fécule diluée jusqu''à obtenir une consistance homogène.","Verser 300 ml d''huile dans la poêle, chauffer à feu doux (c''est plus facile à contrôler). Quand l''huile est à 70 % de chaleur (environ 40 secondes à feu doux, quand de la fumée apparaît), ajouter les aubergines et les frire pendant 2 minutes. Lorsque les bords des aubergines sont légèrement dorés, les retirer. L''huile restante peut être réservée pour une future utilisation.","Garder 15-30 ml d''huile dans la poêle, ajouter la viande hachée et la faire sauter jusqu''à ce qu''elle blanchisse, puis la retirer.","Verser 15-30 ml d''huile dans la poêle, ajouter la pâte de haricots fermentés, le blanc d''oignon vert, le gingembre et l''ail, les faire revenir jusqu''à ce qu''ils soient parfumés, puis ajouter la viande hachée et mélanger.","Ajouter 80-150 ml d''eau (l''eau doit atteindre environ 80 % de la hauteur des aubergines), ajouter les aubergines et la sauce préparée, faire sauter à feu vif pour imprégner et réduire la sauce. Enfin, ajouter l''oignon vert émincé, mélanger, puis retirer du feu."]'::jsonb, '["Plat de viande","Saveur du Sichuan","Yuxiang","Aigre-doux légèrement épicé","Fait maison","Accompagne le riz"]'::jsonb),
  ('howtocook:meat_dish/麻婆豆腐/麻婆豆腐', 'fr', 'Tofu mapo', 'Plats de viande', 'Ce plat de tofu épicé et soyeux remplace la sauce de haricots traditionnelle par des œufs de canard salés, offrant une saveur salée et umami avec une touche légèrement engourdissante et épicée, parfait pour ouvrir l''appétit. Riche en protéines de qualité, calcium, fer et autres oligo-éléments. La difficulté est modérée, accessible aux débutants, et prend environ 40 minutes.', '[{"name":"Tofu soyeux","unit":"boîte"},{"name":"Œuf de canard salé","unit":"pièce"},{"name":"Poitrine de porc","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Gingembre","unit":"tranche"},{"name":"Piment oiseau","unit":"pièce"},{"name":"Sauce pimentée","unit":"g"},{"name":"Poivre du Sichuan","unit":"baie"},{"name":"Sel","unit":"g"},{"name":"Sauce soja","unit":"g"},{"name":"Huile de cuisson","unit":"ml"}]'::jsonb, '["Hacher finement l''ail et le gingembre, réserver.","Couper les piments oiseau en rondelles, réserver.","Hacher finement la poitrine de porc (si ce n''est déjà fait).","Ajouter la moitié du sel et la sauce soja à la viande hachée, bien mélanger, réserver.","Couper les œufs de canard salés en deux dans le sens de la longueur (attention), retirer les jaunes (obligatoire pour éviter le goût fort), écraser les blancs en morceaux d''environ 2 mm sur 2 mm, sans trop les réduire, réserver.","Ouvrir l''emballage du tofu, couper le tofu dans la boîte en morceaux d''environ 2,5 cm sur 3 cm avec un couteau à fruits, réserver.","Chauffer la poêle, ajouter 10 ml à 15 ml d''huile de cuisson. Attendre 10 secondes pour que l''huile chauffe.","Passer à feu doux, ajouter l''ail, le gingembre, les rondelles de piment, le poivre du Sichuan, les œufs de canard salés et la sauce pimentée. Faire revenir 20 secondes jusqu''à ce que les arômes se dégagent.","Passer à feu moyen, ajouter la viande hachée, faire revenir environ 1 minute jusqu''à ce qu''elle change de couleur.","Passer à feu doux, ajouter le tofu, saupoudrer uniformément le reste du sel et de la sauce soja sur le tofu.","Verser de l''eau bouillante le long du bord de la poêle (pour ne pas casser le tofu), juste assez pour couvrir le tofu.","Monter à feu vif, dès l''ébullition, réduire immédiatement à feu moyen et laisser cuire environ 10 minutes.","Lorsqu''il ne reste qu''1/5 du liquide et que la surface du tofu est colorée, éteindre le feu et servir dans un plat."]'::jsonb, '["Plat de viande","Épicé","Salé et umami","Légèrement engourdissant et épicé","Accompagnement de riz","Familial"]'::jsonb),
  ('howtocook:meat_dish/麻辣香锅', 'fr', 'Poêlée épicée du Sichuan', 'Plats de viande', 'Une recette familiale du Sichuan riche en mala, combinant légumes, viande et tofu. Saveur épicée et relevée, texture riche. L''association viande-légumes offre des protéines de qualité et diverses vitamines, nutrition complète. Les étapes sont claires, nécessite maîtrise de l''ébouillantage et du sauté, un défi pour les débutants, temps total environ 30 minutes.', '[{"name":"Légumes verts (bok choy, laitue, épinards)","unit":"g"},{"name":"Viande désossée (porc, bœuf, poulet, boulettes de poisson, saucisse)","unit":"g"},{"name":"Tofu sec","unit":"g"},{"name":"Nouilles instantanées épicées de Beijing","unit":"sachet"},{"name":"Piments séchés","unit":"g"},{"name":"Huile de cuisson","unit":"g"}]'::jsonb, '["Portez à ébullition une casserole d''eau (assez pour couvrir les ingrédients des étapes 2-4).","Dans l''eau bouillante, mettez les légumes verts, blanchissez 5 minutes, puis retirez et réservez.","Dans l''eau bouillante, mettez la viande désossée, blanchissez 4 minutes, puis retirez et réservez.","Dans l''eau bouillante, mettez les nouilles instantanées épicées de Beijing, faites cuire 2 minutes, puis retirez et réservez.","Videz l''eau bouillante, essuyez la casserole, mettez 105 g d''huile de cuisson, chauffez à feu vif 30 secondes.","Ajoutez l''assaisonnement pour poêlée épicée, faites sauter 20 secondes.","Ajoutez les piments séchés, faites sauter 10 secondes.","Ajoutez les légumes verts blanchis, réduisez à feu moyen, faites sauter 3 minutes.","Ajoutez la viande désossée blanchie, faites sauter 3 minutes.","Ajoutez les nouilles instantanées de Beijing cuites, remuez avec des baguettes pendant 1 minute.","Éteignez le feu, servez."]'::jsonb, '["Plat de viande","Mala","Sichuan","Sauté","Accompagne le riz","Maison"]'::jsonb),
  ('howtocook:meat_dish/黄油鸡', 'fr', 'Poulet au beurre', 'Plats de viande', 'C''est un plat de curry classique originaire d''Inde, à base de cuisses de poulet grillées puis mijotées dans une sauce tomate, beurre et crème. La texture est riche et soyeuse, avec des notes aigre-douces et légèrement épicées, et un arôme complexe d''épices. Le poulet, le yaourt et les noix de cajou apportent des protéines et des graisses saines, tandis que les tomates et les épices fournissent vitamines et antioxydants. La préparation est un défi, nécessitant de maîtriser le feu et l''équilibre des épices, et prend environ 1 heure 45 minutes avec la marinade.', '[{"name":"Cuisses de poulet désossées","unit":"g"},{"name":"Yaourt nature","unit":"ml"},{"name":"Gingembre","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Poudre de piment rouge","unit":"g"},{"name":"Poudre de curcuma","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Jus de citron","unit":"ml"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Tomates","unit":"pièce"},{"name":"Oignon","unit":"pièce"},{"name":"Noix de cajou (pour épaissir)","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Beurre","unit":"g"},{"name":"Crème liquide (Heavy Cream)","unit":"ml"},{"name":"Poudre de piment rouge","unit":"g"},{"name":"Poudre de coriandre","unit":"g"},{"name":"Poudre de cumin","unit":"g"},{"name":"Garam Masala","unit":"g"},{"name":"Poudre de cardamome","unit":"g"},{"name":"Feuilles de fenugrec séchées (Kasuri Methi)","unit":"g"},{"name":"Sucre","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Dans un grand bol, mélanger le yaourt, la pâte de gingembre, la pâte d''ail, la poudre de piment rouge, la poudre de curcuma, le sel et le jus de citron.","Ajouter les morceaux de poulet, bien enrober de la marinade.","Couvrir de film alimentaire, réfrigérer au moins 1 heure.","Dans une poêle, verser 15 ml d''huile de cuisson, chauffer à feu vif.","Placer les morceaux de poulet marinés dans la poêle (sans verser la marinade).","Faire dorer à feu vif des deux côtés (environ 3 minutes chaque côté), le poulet n''a pas besoin d''être cuit complètement.","Retirer et réserver.","Dans la poêle, ajouter les tomates coupées, l''oignon coupé, les noix de cajou, le gingembre, l''ail et 100 ml d''eau.","Porter à ébullition à feu vif, puis réduire à feu moyen et cuire 15 minutes, jusqu''à ce que tous les ingrédients soient tendres.","Laisser refroidir légèrement, puis verser dans un mixeur et mixer jusqu''à obtenir une purée lisse.","Passer au tamis pour éliminer les résidus, obtenir une sauce lisse, réserver.","Dans une sauteuse, mettre 50 g de beurre, chauffer à feu moyen jusqu''à fonte.","Verser la sauce tomate filtrée.","Ajouter 5 g de poudre de piment rouge, 5 g de poudre de coriandre, 3 g de poudre de cumin, 5 g de sel.","Faire revenir 3-5 minutes, jusqu''à ce que la sauce fonce et que l''huile remonte à la surface.","Ajouter les morceaux de poulet grillés, mélanger pour bien enrober.","Ajouter 10 g de sucre (pour équilibrer l''acidité des tomates), mélanger.","Verser 100 ml de crème liquide, mélanger uniformément.","Laisser mijoter à feu doux 10-12 minutes, jusqu''à ce que le poulet soit bien cuit et imprégné de la sauce.","Ajouter 3 g de Garam Masala et 2 g de poudre de cardamome.","Saupoudrer 3 g de feuilles de fenugrec séchées (émiettées entre les doigts).","Mélanger, puis éteindre le feu.","Servir, en arrosant éventuellement d''un peu de crème liquide pour la décoration."]'::jsonb, '["Plat principal","Saveur indienne","Curry","Épicé","Riche","Plat de fête"]'::jsonb),
  ('howtocook:meat_dish/黄焖鸡', 'fr', 'Poulet braisé à l''étouffée', 'Plats de viande', 'Le poulet braisé à l''étouffée est un plat familial à base de cuisses de poulet, champignons shiitake et poivron vert. Sa sauce est riche, la viande tendre, avec un goût salé-umami légèrement sucré, parfait pour accompagner le riz. Riche en protéines de qualité et en polysaccharides de champignons. L''étape du caramel de sucre est un peu délicate, mais peut être remplacée par de la sauce soja foncée ; la recette reste accessible aux débutants. De la préparation à la finition, comptez environ 40 minutes.', '[{"name":"Cuisses de poulet","unit":"pièce"},{"name":"Champignons shiitake (de préférence séchés)","unit":"pièce"},{"name":"Poivron vert","unit":"pièce"},{"name":"Tranches de gingembre","unit":"tranche"},{"name":"Piments séchés","unit":"pièce"},{"name":"Sel","unit":"gramme"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Poivre blanc moulu","unit":"gramme"},{"name":"Sucre blanc","unit":"gramme"},{"name":"Sauce soja","unit":"ml"},{"name":"Glutamate monosodique","note":"selon goût"},{"name":"Pomme de terre (optionnel)","unit":"pièce"}]'::jsonb, '["Laver les cuisses de poulet, les couper en morceaux de 4 cm.","Couper le gingembre en tranches, les piments séchés en petits anneaux.","Couper les champignons en tranches, le poivron vert en fines lamelles en forme de fer à cheval ; si vous utilisez des champignons séchés, les rincer puis les faire tremper toute une nuit, en réservant l''eau de trempage.","Si vous utilisez des pommes de terre, les couper en morceaux de taille similaire à celle du poulet.","Préparer le caramel de sucre : verser un fond d''huile dans la casserole, ajouter le sucre blanc à froid (étape délicate ; les débutants peuvent passer directement à la cuisson du poulet et utiliser de la sauce soja foncée).","Chauffer doucement à feu doux. Quand la température de l''huile monte, le sucre fond et prend une couleur brune foncée (remuer constamment pour éviter de brûler).","Ajouter rapidement les morceaux de poulet, passer à feu vif et faire sauter rapidement. Verser le vin de cuisine et continuer à sauter quelques instants.","Ajouter les tranches de gingembre et les piments séchés.","Ajouter la sauce soja et bien mélanger.","Verser l''eau de trempage des champignons ou de l''eau claire, de manière à couvrir le poulet.","Ajouter les champignons en tranches, le poivre blanc, le sel, les pommes de terre.","Mélanger, couvrir et laisser mijoter à feu moyen-doux pendant 15 à 20 minutes ; si possible, transférer dans une casserole en terre cuite.","Quand le poulet est tendre et la sauce réduite (ne pas trop dessécher), ajouter le poivron vert en dernier.","Ajouter le glutamate, mélanger rapidement, puis éteindre le feu. Le poivron doit être juste cuit, ne pas prolonger la cuisson."]'::jsonb, '["Viande","Salé-umami","Légèrement sucré","Mijoté","Familial","Accompagne bien le riz"]'::jsonb),
  ('howtocook:meat_dish/黄瓜炒肉', 'fr', 'Concombre sauté au porc', 'Plats de viande', 'Ce plat familial rapide est frais, croquant et tendre, salé et umami, avec une pointe d''ail et un peu de piquant. Riche en protéines et en vitamines, il aide à rafraîchir et hydrater. Idéal pour les débutants, il suffit de maîtriser la cuisson. Temps de préparation estimé : environ 25 minutes.', '[{"name":"Concombre","unit":"g"},{"name":"Porc maigre","unit":"g"},{"name":"Huile de cuisson","unit":"g"},{"name":"Sauce soja","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Piment","unit":"pièce"}]'::jsonb, '["Coupez la viande de porc maigre en tranches, mettez-la dans un bol, ajoutez 10 g d''huile de cuisson et de la sauce soja, mélangez bien et laissez mariner 10 minutes.","Coupez les extrémités du concombre (5 cm), coupez le reste en tranches obliques de 0,5 cm d''épaisseur.","Mettez le concombre dans un bol, saupoudrez de 8 g de sel, mélangez bien et laissez mariner 5 minutes.","Épluchez les gousses d''ail, écrasez-les et hachez-les finement. Réservez.","Retirez les queues des piments et coupez-les en segments de 0,5 cm.","Faites chauffer la poêle, ajoutez 40 g d''huile. Lorsque l''huile commence à fumer, ajoutez l''ail haché et les piments, faites revenir en remuant 5 fois.","Ajoutez la viande de porc marinée, faites sauter jusqu''à ce qu''elle soit cuite et colorée.","Ajoutez le concombre et 2 g de sel, faites sauter à feu vif pendant 30 secondes en remuant bien. Sortez du feu.","Si vous ne pouvez pas maintenir un feu vif, le concombre peut rester un peu cru. Vous pouvez augmenter le temps à 50 secondes."]'::jsonb, '["Viande","Familial","Rapide","Salé et umami","Légèrement épicé","Pour le riz","Rafraîchissant"]'::jsonb),
  ('howtocook:meat_dish/黑椒牛柳/黑椒牛柳', 'fr', 'Bœuf au poivre noir', 'Plats de viande', 'Le bœuf au poivre noir est un plat sauté très apprécié dans la cuisine familiale. Il a une riche saveur de poivre noir, le bœuf est tendre et glissant, accompagné d''oignons croquants et de poivrons, équilibrant viande et légumes, convenant à tous les âges. Le bœuf est riche en protéines de haute qualité et en fer, les poivrons et les oignons apportent diverses vitamines. Cette recette est très adaptée aux débutants, de la préparation au service, elle peut être réalisée en moins d''une heure.', '[{"name":"Bœuf (filet/steak)","unit":"grammes"},{"name":"Oignon","unit":"pièce"},{"name":"Poivron (rouge/jaune)","unit":"pièce"},{"name":"Fécule","unit":"grammes"},{"name":"Poivre noir (moulu)","unit":"grammes"},{"name":"Marinade au poivre noir","note":"quantité suffisante"},{"name":"Sel","unit":"grammes"},{"name":"Huile d''arachide","unit":"millilitres"}]'::jsonb, '["Couper le bœuf en lanières, de préférence de moins de 8 cm de long, d''environ 5 à 10 mm d''épaisseur et 1 cm de large (pas strict).","Mariner le bœuf avec la marinade, mélanger uniformément et laisser reposer. Suivre les instructions du produit pour les quantités et le temps, on peut prolonger mais pas réduire.","Si on utilise une marinade liquide, saupoudrer une couche de poivre noir moulu trois minutes avant la fin de la marinade, puis ajouter la fécule, mélanger à nouveau et laisser reposer 20 minutes.","Allumer le feu, chauffer la poêle, ajouter l''huile d''arachide.","Quand on voit une légère fumée monter de l''huile dans la poêle, ajouter le bœuf et faire sauter.","Cuire à feu moyen-vif pendant 2 minutes jusqu''à ce que le bœuf change de couleur (pas de rose visible, les parties rosées indiquent une cuisson insuffisante) (attention aux éclaboussures d''huile).","Ajouter l''oignon et le poivron, faire sauter 2 minutes.","Ajouter le sel, saupoudrer une nouvelle dose de poivre noir moulu, faire sauter 30 secondes, mélanger uniformément.","Lorsque l''oignon est ramolli, éteindre le feu, servir et dresser dans une assiette."]'::jsonb, '["Plat de viande","Poivre noir","Cuisine familiale","Sauté","Accompagnement du riz","Rapide"]'::jsonb),
  ('howtocook:meat_dish/黔式腊肠娃娃菜/黔式腊肠娃娃菜', 'fr', 'Mini chou chinois à la saucisse fumée du Guizhou', 'Plats de viande', 'Ce plat salé et umami marie la saveur riche de la saucisse fumée du Guizhou avec la douceur du mini chou chinois. C''est une rareté non épicée dans la cuisine du Sud-Ouest, appréciée partout. Le mini chou chinois est riche en vitamines et fibres, tandis que la saucisse apporte protéines et lipides pour un équilibre nutritionnel. La préparation est très simple, sans maîtrise du feu ni assaisonnement supplémentaire, du début à la fin en seulement 15 minutes, idéale pour les débutants et les jours chargés.', '[{"name":"Saucisse fumée du Guizhou","unit":"g"},{"name":"Mini chou chinois","unit":"g"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Dans une casserole, versez 750ml d''eau et portez à ébullition","Ajoutez la saucisse, faites cuire 13 minutes","Ajoutez le mini chou chinois, faites cuire 2 minutes","Éteignez le feu, retirez la saucisse et le mini chou chinois","Coupez le mini chou chinois en tronçons et la saucisse en tranches, dressez dans l''assiette"]'::jsonb, '["viande","salé et umami","bouilli","style Guizhou","rapide","familial"]'::jsonb),
  ('howtocook:semi-finished/凉皮', 'fr', 'Liang Pi (galettes de riz froides)', 'Semi-préparés', 'Le Liang Pi est une collation familiale originaire du Shaanxi, à la texture ferme et lisse, aigre-piquante et appétissante, avec un riche arôme de pâte de sésame. La pâte de sésame et le gluten de blé fournissent des protéines végétales et du calcium, accompagnés de concombre croquant et de germes de soja vert, riches en vitamines et fibres. La difficulté est moyenne, nécessitant simplement de bouillir, couper en julienne et préparer la sauce, même un débutant peut le faire. Du début à la fin, cela prend environ 40 minutes, idéal pour les tables estivales.', '[{"name":"Liang Pi","unit":"g","note":""},{"name":"Gluten de blé","unit":"","note":"quantité suffisante"},{"name":"Sel","unit":"","note":"ajouter selon votre goût"},{"name":"Bouillon de poule en poudre","unit":"","note":"à ajouter en plusieurs fois"},{"name":"Sauce d''huître","unit":"","note":"à ajouter en plusieurs fois"},{"name":"Sauce soja claire","unit":"","note":"à ajouter en plusieurs fois"},{"name":"Sauce soja foncée","unit":"","note":"à ajouter en plusieurs fois"},{"name":"Huile de sésame","unit":"g","note":""},{"name":"Vinaigre de riz noir","unit":"","note":"ajouter selon votre goût"},{"name":"Pâte de sésame","unit":"g","note":""},{"name":"Concombre","unit":"g","note":""},{"name":"Ail","unit":"g","note":""},{"name":"Germes de soja vert","unit":"g","note":""}]'::jsonb, '["Ajouter 500 ml d''eau dans une casserole. Porter à ébullition.","Mettre les germes de soja vert dans la casserole, cuire à feu vif pendant 60 secondes. Égoutter les germes, les passer sous l''eau froide, puis les déposer dans une assiette et réserver.","Couper le concombre en julienne et le déposer dans une assiette. Réserver.","Peler 10 g de gousses d''ail, les mettre dans un mortier avec 1 g de sel. Piler en pâte, ajouter 10 g d''eau du robinet. Laisser reposer.","Note : Les Liang Pi achetés en supermarché ont généralement de l''huile de cuisson en surface ; vous pouvez les rincer à l''eau du robinet. Idem pour le gluten de blé.","Note : Après avoir rincé le gluten de blé, pressez-le à la main pour en extraire l''excès d''eau (sans trop forcer).","Préparer un petit bol. Ajouter 3 g de sel, 2 g de bouillon de poule en poudre, 5 g de sauce soja claire, 1 g de sauce soja foncée, 1 g d''huile de sésame, 2 g de sauce d''huître, 5 g de vinaigre de riz noir. (Le sel et le vinaigre peuvent être ajustés selon votre goût ; les quantités ci-dessus sont pour un goût standard.)","Ajouter 25 à 35 g d''eau tiède (selon votre goût salé) aux assaisonnements ci-dessus. Mélanger avec des baguettes jusqu''à dissolution. Laisser refroidir.","Note : Les mesures ci-dessous sont pour une personne. S''il y a n personnes, multipliez les quantités par n.","Sortir un petit bol et y mettre la pâte de sésame préparée.","Ajouter 4 g de sel, 3 g de bouillon de poule en poudre, 5 g de sauce soja claire, 1 g de sauce soja foncée, 3 g de sauce d''huître.","Mélanger avec des baguettes jusqu''à ce que les assaisonnements soient bien incorporés à la pâte de sésame.","Ajouter 10 g d''eau claire et mélanger.","Répéter l''étape précédente 2 à 3 fois (selon l''épaisseur souhaitée de la pâte de sésame).","Sortir le petit saladier préparé précédemment et y ajouter les Liang Pi.","Verser la sauce salée, mélanger avec des baguettes. Puis transvaser dans un petit bol (verser également la sauce salée dans le bol).","Déposer les germes de soja sur les Liang Pi, puis le gluten de blé par-dessus.","Verser la pâte de sésame préparée sur le gluten de blé.","Saupoudrer de julienne de concombre.","Si vous le souhaitez, ajouter de l''huile de piment.","Voilà, votre Liang Pi maison coloré, parfumé et savoureux est prêt !"]'::jsonb, '["Semi-préparé","Aigre-piquant","Salade froide","Style du Shaanxi","Familial","Apéritif","Estival"]'::jsonb),
  ('howtocook:semi-finished/半成品意面', 'fr', 'Pâtes semi-préparées', 'Semi-préparés', 'Ceci est un plat occidental rapide réalisé avec des pâtes semi-préparées du commerce. Les pâtes sont élastiques et fermes, avec une sauce prête à l''emploi riche en saveurs. Principalement des glucides, elles fournissent rapidement de l''énergie et contiennent des protéines. La préparation est extrêmement simple, même les débutants peuvent réussir sans erreur, du feu à l''assiette en seulement 2 minutes environ.', '[{"name":"Pâtes italiennes semi-préparées (marque recommandée : Pulmuone)","unit":"g"},{"name":"Eau claire","unit":"ml"}]'::jsonb, '["Chauffer la poêle","Verser 50 ml d''eau claire dans la poêle","Ajouter les pâtes et faire sauter 1 minute","Verser la sauce et faire revenir 1 minute","Dresser dans l''assiette","Placer les pâtes dans une assiette adaptée au micro-ondes","Verser la sauce incluse sur les pâtes","Ajouter 50 ml d''eau claire","Chauffer à 700W pendant 2 minutes","Sortir et mélanger"]'::jsonb, '["semi-préparé","rapide","maison","occidental","pâtes","cuisine facile"]'::jsonb),
  ('howtocook:semi-finished/懒人蛋挞/懒人蛋挞', 'fr', 'Tarte aux œufs paresseuse', 'Semi-préparés', 'Ce dessert utilise des croûtes et un appareil à tarte aux œufs prêts à l''emploi. La croûte est croustillante et parfumée, la garniture est lisse et onctueuse, avec des taches caramélisées. C''est la version la plus simple des classiques pâtisseries cantonaises. Les ingrédients principaux, œufs et lait, fournissent des protéines et du calcium de qualité, ce qui en fait une gourmandise familiale idéale. La préparation se limite à assembler et cuire, et elle est très accessible aux débutants complets. De la préchauffe du four à la sortie du four, comptez environ 40 minutes.', '[{"name":"croûte pour tarte aux œufs","unit":"pièce"},{"name":"appareil à tarte aux œufs","unit":"ml"}]'::jsonb, '["Préchauffer le four à 200°C pendant 10 minutes.","Déposer les croûtes pour tarte aux œufs sur une plaque de cuisson. Verser environ 10 ml d''appareil à tarte aux œufs dans chaque croûte, la quantité exacte dépend de la taille des croûtes, généralement remplir aux 4/5.","Placer la plaque dans le four et cuire à 190°C chaleur tournante (haut et bas) pendant 10 à 20 minutes. Pour obtenir rapidement des taches brunies sur le dessus, augmenter la chaleur du haut à 200-210°C.","Cuire jusqu''à ce que l''appareil présente des taches brunies et que les croûtes soient bien gonflées et légèrement huileuses."]'::jsonb, '["semi-préparé","sucré","pâtisserie","cantonnais","rapide","débutant"]'::jsonb),
  ('howtocook:semi-finished/炸薯条/炸薯条', 'fr', 'Frites', 'Semi-préparés', 'Les frites sont croustillantes à l''extérieur et moelleuses à l''intérieur, dorées et salées, un snack populaire. Les pommes de terre fournissent des glucides et des fibres alimentaires, mais la friture ou la cuisson à l''air les rend plus caloriques. Utilisez des frites semi-finies et une friteuse à air, facile à préparer même pour les débutants. Du préchauffage au service, cela prend environ 25 minutes.', '[{"name":"Frites semi-finies (marque recommandée : McCain)","unit":"grammes"},{"name":"Huile","note":"Quantité suffisante"}]'::jsonb, '["Ouvrez le paquet de frites semi-finies en grande quantité, en veillant à faire une petite ouverture pour réduire la formation de givre à la surface lors du stockage à long terme.","Branchez, préchauffez à 200°C pendant 5 minutes.","Le préchauffage permet de s''assurer que la température de la cuve est à celle requise pour la cuisson lors de l''ajout des aliments.","Attention, sortez les frites après le préchauffage, ne les laissez pas ramollir avant de les cuire.","Sortez les frites et placez-les dans la friteuse à air, à 200°C pendant 20 minutes.","En sortant les frites, notez que les frites semi-finies contiennent déjà de l''huile, donc pour effectuer les opérations asynchrones à l''intérieur du client, utilisez des pinces.","Au bout de 5 à 10 minutes, vous pouvez sortir le panier et secouer pour une cuisson uniforme et éviter que les frites ne collent.","Entre 10 et 15 minutes, sortez le panier, vaporisez une couche d''huile sur les frites déjà sèches, couvrant les 2/3 de la surface des frites.","Pour des frites croustillantes, après les avoir sorties, secouez le panier en dansant pour que l''air circule, puis dressez ; pour des frites molles, dressez directement. Accompagnez de sauce ou de vinaigrette pour plus de saveur."]'::jsonb, '["semi-finis","rapide","snack","salé","friteuse à air"]'::jsonb),
  ('howtocook:semi-finished/牛油火锅底料', 'fr', 'Base de fondue au gras de bœuf', 'Semi-préparés', 'Cette base de fondue de Chongqing est à base de gras de bœuf en grande quantité, mélangée à des piments cijiao et diverses épices. La base obtenue est épicée, riche et aromatique, et constitue l''âme pour y tremper des tripes, des intestins de canard et autres ingrédients. Le gras de bœuf et le saindoux fournissent une énergie abondante, tandis que les piments et le poivre du Sichuan réchauffent le corps et stimulent l''appétit, mais leur teneur élevée en matières grasses nécessite une consommation modérée. La préparation nécessite un contrôle précis de la température de l''huile et du feu de cuisson, ce qui représente un défi pour les débutants. Du début à la fin, il faut environ 1 heure.', '[{"name":"Gras de bœuf","unit":"g"},{"name":"Huile de salade/huile de colza","unit":"ml"},{"name":"Saindoux pur","unit":"g"},{"name":"Pâte de haricots fermentée (douban)","unit":"g"},{"name":"Piments cijiao","unit":"g"},{"name":"Gingembre vieux","unit":"g"},{"name":"Oignon vert","unit":"g"},{"name":"Oignon","unit":"g"},{"name":"Ail","unit":"g"},{"name":"Haricots noirs fermentés (douchi)","unit":"g"},{"name":"Pâte de graines de soja (dou muzi)","unit":"g"},{"name":"Poivre rouge du Sichuan","unit":"g"},{"name":"Épices en grains","unit":"g"},{"name":"Épices entières","unit":"g"},{"name":"Poudre de malt","unit":"g"},{"name":"Alcool de riz","unit":"ml"},{"name":"Poudre de piment séché","unit":"g"},{"name":"Galanga (shan nai)","unit":"g"},{"name":"Badiane","unit":"g"},{"name":"Cardamome noire (caoguo)","unit":"g"},{"name":"Cannelle","unit":"g"},{"name":"Clous de girofle","unit":"g"},{"name":"Graines de fenouil","unit":"g"},{"name":"Angélique (baizhi)","unit":"g"},{"name":"Poivre long (bibo)","unit":"g"},{"name":"Herbes aromatiques","unit":"g"},{"name":"Xiangguo (fruit aromatique)","unit":"g"},{"name":"Baies d''aubépine (shanzha)","unit":"g"},{"name":"Écorce de mandarine séchée (chenpi)","unit":"g"},{"name":"Citronnelle","unit":"g"},{"name":"Cardamome du Sichuan (shareng)","unit":"g"},{"name":"Cardamome blanche (baiko)","unit":"g"},{"name":"Feuilles de laurier","unit":"g"}]'::jsonb, '["Placez la casserole sur feu vif (grand feu) et faites chauffer le gras de bœuf jusqu''à 80% de chaleur (240±10°C). Ajoutez 100g chacun de gingembre vieux, d''oignon vert, d''oignon et d''ail. Faites-les frire jusqu''à ce qu''ils soient secs (pour absorber les odeurs indésirables et l''odeur de gras de bœuf), puis retirez-les et jetez-les.","Ajoutez l''huile de salade ou l''huile de colza, et le saindoux pur. Attendez que la température de l''huile descende à 50% (150±10°C), puis ajoutez les piments cijiao et faites sauter continuellement pendant 5 à 8 minutes.","Ajoutez la pâte de haricots (douban) et faites sauter pour émietter. Réduisez le feu à moyen-doux et faites cuire lentement jusqu''à ce que les résidus blanchissent légèrement et deviennent granuleux (en émettant un bruit de sable).","Lorsque l''huile prend une teinte rouge cerise, ajoutez 150g de tranches de gingembre et 100g d''ail, faites revenir environ 15 secondes jusqu''à ce qu''ils soient odorants.","Ajoutez les haricots noirs fermentés (douchi) et la pâte de graines de soja (dou muzi), faites revenir jusqu''à ce qu''ils soient parfumés. Ajoutez les poivres rouges du Sichuan et les graines de fenouil, faites revenir jusqu''à ce qu''ils soient parfumés.","(Vieille huile) À ce moment, ajoutez les épices en grains.","Ajoutez la poudre de malt, faites sauter pour mélanger. Ajoutez l''alcool de riz, faites sauter pour mélanger.","Retirez du feu et mettez dans un récipient. Laissez reposer dans un environnement à basse température (10-20°C) pendant 5 jours avant utilisation pour un meilleur résultat.","Retirez du feu et mettez dans un récipient. Ajoutez la poudre de piment séché et mélangez. Laissez reposer 24 heures, en attendant pour préparer la vieille huile (lao you).","Versez la base dans la casserole, ajoutez 3/5 d''eau bouillante et portez à ébullition sur grand feu (base: 2/5, eau: 3/5).","Après ébullition, de la mousse apparaîtra à la surface ; écumez-la.","Réduisez à feu moyen-doux et laissez mijoter lentement pour extraire les saveurs (environ 25-30 minutes), puis filtrez pour retirer les résidus.","Attendez que l''huile et l''eau se séparent dans le récipient, puis écumez l''huile en surface (retirez l''huile) et mettez-la dans un autre récipient.","Reversez l''huile écumée de l''étape précédente dans une casserole propre, jusqu''à ce que l''humidité de l''huile soit évaporée. Retirez du feu et mettez dans un récipient : c''est la vieille huile de fondue (huile de fondue vieillie)."]'::jsonb, '["Semi-produit","Épicé et engourdissant","Sauté","Chongqing","Riche en huile","Base maison"]'::jsonb),
  ('howtocook:semi-finished/空气炸锅羊排/空气炸锅羊排', 'fr', 'Côtes d''agneau à l''Air Fryer', 'Semi-préparés', 'Cette recette est super paresseuse, l''Air Fryer permet d''extraire l''excès de gras, le résultat est croustillant à l''extérieur et tendre à l''intérieur, avec un fort goût d''ail. La saveur dépend principalement de la qualité des côtes d''agneau. L''agneau est riche en protéines de haute qualité et en oligo-éléments comme le fer et le zinc, ce qui aide à réchauffer le sang et renforcer le corps. La difficulté est modérée, même les débutants peuvent la réussir facilement. Le temps de préparation actif n''est que de 10 minutes, et avec la marinade, il faut environ 40 minutes pour servir.', '[{"name":"Côtes d''agneau","unit":"pièce"},{"name":"Mélange d''épices au poivre noir pour steak","unit":"gramme"},{"name":"Sauce à l''ail","unit":"gramme"},{"name":"Beurre","unit":"petite plaquette"},{"name":"Assaisonnement barbecue","unit":"gramme"},{"name":"Basilic séché","note":"quantité suffisante"}]'::jsonb, '["Placez les côtes d''agneau dans un bol et lavez-les à l''eau claire pour enlever le sang.","Séchez les côtes d''agneau avec du papier absorbant, badigeonnez les deux faces avec le mélange d''épices au poivre noir et la sauce à l''ail, laissez mariner 20 minutes.","Placez un bol en aluminium sur la grille, mettez les côtes d''agneau sur la grille, saupoudrez de basilic séché, placez le beurre ou l''assaisonnement barbecue sur les côtes, faites cuire à l''Air Fryer à 180°C pendant 10 minutes.","Retournez les côtes d''agneau, saupoudrez de basilic séché, placez le beurre (prélevé du bol en aluminium) ou l''assaisonnement barbecue sur les côtes, faites cuire à l''Air Fryer à 180°C pendant 5 minutes (vous pouvez ajuster le temps selon votre goût, le temps indiqué ici évite de brûler)."]'::jsonb, '["Semi-préparé","Air Fryer","Ail","Poivre noir","Rapide","Familial","Paresseux"]'::jsonb),
  ('howtocook:semi-finished/空气炸锅鸡翅中/空气炸锅鸡翅中', 'fr', 'Ailes de poulet à la friteuse à air', 'Semi-préparés', 'C''est un plat fait maison rapide et pratique. Les ailes de poulet sont croustillantes à l''extérieur et tendres à l''intérieur, avec leur propre arôme gras, plus savoureuses que celles des fast-foods. Riches en protéines de qualité et en graisses, elles fournissent beaucoup d''énergie. Très adapté aux débutants, la préparation ne prend que quelques minutes, et le tout est prêt en environ quarante minutes.', '[{"name":"Ailes de poulet (partie médiane)","unit":"pièce"},{"name":"Basilic séché","note":"Quantité suffisante"},{"name":"Épices Yunnan Dan Shan","note":"Quantité suffisante"}]'::jsonb, '["Sortez les ailes de poulet du réfrigérateur, placez-les côté peau vers le bas dans un plat en aluminium, saupoudrez de basilic séché, couvrez de film alimentaire et laissez décongeler naturellement pendant 20 minutes.","Saupoudrez de basilic séché, faites cuire à la friteuse à air à 200°C pendant 10 minutes.","Retournez, saupoudrez de basilic séché, faites cuire à la friteuse à air à 200°C pendant 7 minutes."]'::jsonb, '["Semi-préparé","Rapide","Maison","Orléans","Frais et parfumé","Apéritif"]'::jsonb),
  ('howtocook:semi-finished/速冻水饺', 'fr', 'Raviolis surgelés', 'Semi-préparés', 'C''est un plat de pâtes familiale originaire de Chine, préparé rapidement avec des raviolis surgelés du commerce. La pâte est fine, la garniture généreuse, la saveur fraîche et parfumée. Accompagné de trempettes comme le vinaigre, le gingembre et l''ail, les saveurs gagnent en profondeur. En tant que repas, il apporte suffisamment de protéines et de glucides, nutritif et rassasiant. La préparation ne présente aucune difficulté, même les débutants peuvent facilement réussir, il ne faut qu''environ un quart d''heure.', '[{"name":"Raviolis surgelés","unit":"pièce","note":""},{"name":"Eau","unit":"","note":"quantité suffisante"},{"name":"Vinaigre","unit":"","note":"quantité suffisante"},{"name":"Gingembre","unit":"","note":"quantité suffisante"},{"name":"Ail","unit":"","note":"quantité suffisante"}]'::jsonb, '["À feu moyen, versez l''eau dans une casserole et attendez qu''elle bout.","Versez les raviolis dans la casserole.","Avant de les verser, vous pouvez les rincer brièvement à l''eau.","Après avoir versé les raviolis, vous pouvez remuer l''eau avec une cuillère ou une spatule, mais attention à ne pas toucher les raviolis pour éviter qu''ils ne collent à la casserole et se déchirent, ou qu''ils ne collent entre eux provoquant des parties crues.","La fréquence n''a pas besoin d''être élevée, en moyenne 3 secondes toutes les 30 secondes. Une fois les raviolis remontés à la surface, cette étape n''est plus nécessaire.","Après que les raviolis aient remonté et que l''eau bout à nouveau, prenez-en un avec une cuillère pour vérifier. Si la pâte est encore crue, ajoutez 80 ml d''eau froide avec la cuillère pour refroidir l''eau, puis continuez à cuire jusqu''à ébullition. Pendant ce temps, répétez l''observation et le mélange. Au maximum, ajoutez de l''eau deux fois pour qu''ils soient bien cuits.","Une fois que tous les raviolis sont remontés (environ 8 minutes après les avoir mis dans l''eau), sortez-les avec une spatule ou une écumoire et placez-les dans une assiette ou un bol. Ils sont prêts à être dégustés.","Après avoir mangé les raviolis, attendez que l''eau refroidisse, videz-la et lavez la casserole immédiatement avec du liquide vaisselle. Sinon, la farine cuite formera une substance collante sur les parois de la casserole."]'::jsonb, '["semi-préparé","rapide","familial","frais et parfumé","bouilli","rassasiant"]'::jsonb),
  ('howtocook:semi-finished/速冻汤圆/速冻汤圆', 'fr', 'Boules de riz glutineux surgelées', 'Semi-préparés', 'Les boules de riz glutineux surgelées sont un dessert rapide et pratique au micro-ondes, à l''enveloppe moelleuse et à la garniture sucrée, une spécialité traditionnelle chinoise. Elles fournissent principalement des glucides pour un regain d''énergie rapide. La préparation est très simple, même les débutants peuvent la réussir, et il ne faut qu''environ 6 minutes du début à la fin.', '[{"name":"Boules de riz glutineux surgelées","unit":"pièce"}]'::jsonb, '["Sortez les boules de riz glutineux surgelées et placez-les dans un bol.","Versez de l''eau bouillante jusqu''à ce qu''elles soient immergées.","Chauffez au micro-ondes à puissance maximale pendant 4 minutes.","Si les boules ont absorbé l''eau et gonflé, elles sont cuites.","Sinon, chauffez encore 1 minute."]'::jsonb, '["Produit semi-fini","Rapide","Micro-ondes","Moelleux","Sucré","Chinois"]'::jsonb),
  ('howtocook:semi-finished/速冻馄饨', 'fr', 'Raviolis surgelés', 'Semi-préparés', 'Les raviolis surgelés ont une peau fine et une farce tendre, une soupe claire et savoureuse. C''est un plat de nouilles maison pratique. Ils fournissent principalement des glucides et des protéines, faciles pour reconstituer rapidement l''énergie. La préparation est simple, très adaptée aux débutants, réalisable avec un cuiseur à riz. Environ 55 minutes de l''ébullition de l''eau jusqu''au service.', '[{"name":"Raviolis surgelés","unit":"pièce"},{"name":"Eau","unit":"ml"},{"name":"Sel","note":"Selon le goût, sans sachet d''assaisonnement"},{"name":"Bouillon de poulet","note":"Selon le goût, sans sachet d''assaisonnement"},{"name":"Poivre moulu","note":"Selon le goût, sans sachet d''assaisonnement"},{"name":"Huile de sésame","note":"Selon le goût, sans sachet d''assaisonnement"},{"name":"Coriandre","unit":"feuille","note":"Uniquement pour ceux qui tolèrent la coriandre"}]'::jsonb, '["Versez l''eau dans le cuiseur à riz, mettez en mode mijotage ou cuisson pendant 35 minutes, puis ouvrez le couvercle : l''eau doit bouillir.","Déposez délicatement les raviolis surgelés dans l''eau en évitant les éclaboussures.","Vous pouvez les rincer rapidement à l''eau avant de les mettre dans le cuiseur.","Si un sachet d''assaisonnement est fourni, ajoutez-le en même temps dans l''eau.","Fermez le couvercle et lancez à nouveau le mode mijotage ou cuisson pendant 20 minutes.","Versez tous les raviolis avec suffisamment d''eau pour les recouvrir dans un bol.","Si vous n''avez pas ajouté le sachet d''assaisonnement, assaisonnez selon votre goût avec du sel, du bouillon de poulet, du poivre moulu et de l''huile de sésame.","Vous pouvez aussi parsemer de 5 à 8 feuilles de coriandre pour la saveur (uniquement si vous tolérez la coriandre)."]'::jsonb, '["Semi-préparé","Familial","Léger","Nouilles","Bouilli","Débutant"]'::jsonb),
  ('howtocook:soup/勾芡香菇汤/勾芡香菇汤', 'fr', 'Soupe de champignons liée', 'Soupes', 'La soupe de champignons liée est épaisse et savoureuse, onctueuse et agréable, c''est une soupe maison rapide. Les champignons sont riches en acides aminés et polysaccharides, ce qui aide à renforcer l''immunité. La cuisson nécessite quelques techniques de contrôle du feu et de liaison, mais reste accessible aux débutants. De la préparation à la finition, il faut environ 25 minutes.', '[{"name":"Champignons frais","unit":"pièce"},{"name":"Ciboule","unit":"tige"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sel de table","unit":"g"},{"name":"Bouillon de poulet","unit":"g"},{"name":"Fécule de maïs","unit":"g"},{"name":"Eau bouillante","unit":"ml"}]'::jsonb, '["Trancher les champignons (épaisseur 0,5-1 cm, plus épais donne plus de mâche), les mettre dans un grand bol, ajouter 2g de sel de table et laisser tremper 15 minutes.","Verser la fécule dans un petit bol, ajouter 50ml d''eau, remuer jusqu''à dissolution complète (mélange de fécule et d''eau).","Jeter l''eau salée du bol, essorer légèrement les champignons (pour faciliter la friture) [optionnel].","À feu doux, verser l''huile, attendre que de petites bulles apparaissent (feu doux 30s, selon la puissance de la casserole), ajouter les champignons, faire revenir 10s chaque face [optionnel].","Verser 300ml d''eau bouillante, passer à feu moyen et cuire encore 3-5 minutes.","Verser le mélange de fécule, remuer légèrement le bouillon, ajouter 3g de sel, 3g de bouillon de poulet, parsemer de ciboule ciselée et servir."]'::jsonb, '["Soupe","Savoureux","Léger","Rapide","Maison","Lié"]'::jsonb),
  ('howtocook:soup/奶油蘑菇汤', 'fr', 'Soupe de champignons à la crème', 'Soupes', 'C''est une soupe épaisse classique française, à la texture soyeuse et onctueuse, où les arômes de champignons et de crème se mêlent. Les champignons sont riches en fibres alimentaires et en oligo-éléments, tandis que le lait apporte des protéines de qualité et du calcium. La recette est très simple, même les débutants peuvent la réaliser facilement. De la préparation à la fin, cela prend environ 30 minutes.', '[{"name":"Champignons de Paris","unit":"g"},{"name":"Oignon","unit":"g"},{"name":"Beurre","unit":"g"},{"name":"Farine","unit":"g"},{"name":"Lait","unit":"ml"},{"name":"Crème liquide","unit":"ml"},{"name":"Eau","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Poivre noir moulu","unit":"g"}]'::jsonb, '["Trancher les champignons de Paris et les réserver. Hacher l''oignon et le réserver.","Dans une poêle, faire fondre le beurre à feu doux, puis ajouter l''oignon et le faire revenir jusqu''à ce qu''il soit translucide.","Ajouter les champignons tranchés et les faire revenir jusqu''à ce qu''ils rendent leur eau et deviennent tendres. Saupoudrer de farine et bien mélanger.","Ajouter le lait et l''eau, bien mélanger, puis porter à ébullition à feu doux en remuant constamment pour éviter que ça n''attache.","Réduire le feu et laisser mijoter environ 10 minutes, jusqu''à ce que la soupe épaississe.","Verser la crème liquide et chauffer encore 1 minute. Assaisonner avec du sel et du poivre noir moulu.","Éteindre le feu. Si désiré, mixer la soupe jusqu''à obtenir une texture lisse (optionnel)."]'::jsonb, '["Soupe","Française","Crémeux","Mijoté","Rapide","Familial","Savoureux"]'::jsonb),
  ('howtocook:soup/小米粥', 'fr', 'Bouillie de millet', 'Soupes', 'La bouillie de millet est une bouillie familiale courante dans le nord de la Chine. Sa texture est onctueuse, son arôme de millet est riche, et l''huile de millet qui se forme à la cuisson est particulièrement bonne pour l''estomac. Elle est riche en protéines, lipides, glucides et carotène, et sa teneur en vitamine B1 est parmi les plus élevées des céréales. Elle est facile à digérer et à absorber. La préparation est très simple, même un débutant peut la maîtriser. Il faut environ 30 à 35 minutes de l''ébullition de l''eau à la fin de la cuisson.', '[{"name":"Millet","unit":"g"},{"name":"Eau (de préférence de source)","unit":"g"}]'::jsonb, '["100 g de millet, mettez-le dans un bol, rincez-le légèrement à l''eau (remuez avec la main, puis jetez l''eau, juste pour enlever la poussière en surface, ne pas frotter !!!)","Portez l''eau à ébullition, impérativement à ébullition !!!","Lorsque l''eau bout vigoureusement, versez le millet dans la casserole. (Une étape très importante souvent négligée)","Remuez pour que le millet n''adhère pas au fond de la casserole, continuez à cuire à feu vif pendant 6 à 10 minutes, en remuant de temps en temps.","Passez à feu moyen-doux et laissez mijoter 15 à 20 minutes, le couvercle doit être légèrement décalé pour ne pas laisser s''échapper l''huile de millet, remuez plusieurs fois entre-temps pour éviter que cela n''attache au fond."]'::jsonb, '["Bouillie","Léger","Parfumé","Mijoté","Nord","Petit-déjeuner","Familial"]'::jsonb),
  ('howtocook:soup/排骨山药玉米汤/排骨山药玉米汤', 'fr', 'Soupe de travers de porc, igname et maïs', 'Soupes', 'La soupe de travers de porc, igname et maïs est douce et riche, l''igname est moelleuse, le maïs offre une douceur persistante, le tout mêlé à la saveur du porc. C''est une soupe familiale pour tous les âges. Riche en protéines, fibres alimentaires et vitamines, elle renforce la rate et l''estomac, et améliore l''immunité. La recette est simple, avec des étapes claires de préparation et de cuisson, même les débutants peuvent la réussir facilement. L''ensemble prend environ 1 heure.', '[{"name":"Travers de porc","unit":"g"},{"name":"Igname","unit":"pièce"},{"name":"Carotte","unit":"pièce"},{"name":"Maïs","unit":"pièce"},{"name":"Gingembre frais","unit":"g"},{"name":"Oignon vert","unit":"g"},{"name":"Vin de cuisson","unit":"ml"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Eau potable","unit":"ml"},{"name":"Sel","unit":"g"}]'::jsonb, '["Préparation des ingrédients :","Laver et éplucher la carotte, la couper en morceaux de taille d''environ 3 cm (coupe en biais).","Laver le maïs, le couper en petits tronçons d''environ 4 cm de longueur.","Éplucher l''igname (il est recommandé de porter des gants pour éviter les irritations cutanées dues au mucilage), la couper en tronçons d''environ 4 cm, réserver.","Blanchir les travers de porc :","Dans une casserole, ajouter suffisamment d''eau froide, y mettre les travers de porc lavés.","Ajouter environ 10 g de tranches de gingembre, un bouquet d''oignons verts et 15 ml de vin de cuisson.","Porter à ébullition à feu vif, laisser bouillir 3 minutes en écumant la mousse à la surface.","Retirer les travers de porc, les rincer à l''eau tiède (environ 40 °C) pour éliminer les impuretés, égoutter.","Faire revenir les travers de porc :","Chauffer la casserole, verser 10 ml d''huile de cuisson, attendre 10 secondes pour que l''huile chauffe.","Ajouter les tranches de gingembre restantes (environ 10 g) et les faire revenir jusqu''à ce qu''elles dégagent leur parfum.","Ajouter tous les travers de porc préparés, les faire revenir à feu moyen environ 1 minute jusqu''à ce qu''ils soient légèrement dorés.","Cuisson de la soupe :","Verser 1500 ml à 2000 ml d''eau potable dans la casserole d''un seul coup.","Ajouter tous les morceaux de carotte, maïs et igname préparés.","Porter à ébullition à feu vif, puis réduire à feu doux, couvrir et laisser mijoter 40 minutes.","Assaisonnement et service :","Ajouter 6 g à 8 g de sel, bien mélanger avec une cuillère.","Laisser mijoter à feu doux encore 2 minutes pour que le sel pénètre.","Éteindre le feu, parsemer d''oignons verts hachés selon votre goût, puis servir."]'::jsonb, '["Soupe","Léger","Braiser","Familial","Nourrissant"]'::jsonb),
  ('howtocook:soup/排骨苦瓜汤/排骨苦瓜汤', 'fr', 'Soupe de travers de porc et melon amer', 'Soupes', 'La soupe de travers de porc et melon amer est une soupe cantonaise familiale au bouillon clair, savoureuse et légèrement sucrée. Les travers sont tendres, le melon amer rafraîchit et dégraisse. Riche en protéines et vitamines, les crevettes séchées apportent du calcium. La préparation nécessite le blanchiment pour enlever l''odeur, retirer soigneusement la pulpe du melon amer, ce qui est un défi pour les débutants, mais l''utilisation d''un autocuiseur électrique simplifie grandement la tâche. La cuisson lente traditionnelle prend de 2 à 4 heures, il est recommandé de préparer 4 heures à l''avance ; avec l''autocuiseur, seulement environ 1 heure.', '[{"name":"Travers de porc","unit":"grammes"},{"name":"Melon amer","unit":"grammes"},{"name":"Crevettes séchées","unit":"grammes"},{"name":"Gingembre","unit":"grammes"}]'::jsonb, '["Lavez les travers de porc, coupez-les en morceaux d''environ 4 cm ± 2 cm sur 3 ± 2 cm (si vous n''avez pas d''outil pour couper, demandez au boucher).","Dans une poêle, versez 700 ml d''eau froide et les travers, portez à ébullition, puis éteignez le feu et égouttez les travers.","Coupez le melon amer en deux dans la longueur, retirez soigneusement les graines et la pulpe blanche intérieure, coupez en tranches de 0,5 ± 0,3 cm d''épaisseur, lavez.","Dans une marmite, versez 1100 ml d''eau et les travers, mettez à feu vif.","Quand l''eau bout, ajoutez le melon amer et les crevettes séchées, réduisez à feu doux, laissez cuire 120 à 240 minutes (après 120 minutes, vous pouvez prélever un morceau de viande pour goûter ; si la viande se détache facilement de l''os, éteignez le feu).","Au moment de servir, ajoutez du sel et du poivre blanc, les doses recommandées sont de 0,3 à 0,6 g de sel et 0,1 à 0,5 g de poivre blanc pour 250 ml de bouillon.","Versez 1000 ml d''eau, les travers, les crevettes séchées et le melon amer.","Sélectionnez la fonction soupe de l''autocuiseur et faites cuire (généralement 45 minutes en pression).","Servez, et assaisonnez avec du sel et du poivre comme pour la marmite."]'::jsonb, '["Soupe","Cantonais","Familial","Savoureux","Rafraîchissant","Mijoté","Calcium"]'::jsonb),
  ('howtocook:soup/昂刺鱼豆腐汤/昂刺鱼豆腐汤', 'fr', 'Soupe de poisson-chat et tofu', 'Soupes', 'La soupe de poisson-chat et tofu est un plat familial à la texture tendre, au bouillon blanc et au goût riche. Le poisson a peu d''arêtes, le tofu est soyeux, avec une légère chaleur poivrée, adaptée à tous les âges. Le poisson est riche en protéines de haute qualité, et le tofu apporte du calcium, équilibrant la nutrition pour une bonne absorption. La préparation n''est pas compliquée ; il suffit de bien désodoriser le poisson et d''éviter qu''il n''attache à la poêle. Les débutants peuvent aussi réussir. Le temps de préparation est d''environ 40 minutes.', '[{"name":"poisson-chat (ou poisson de sable)","unit":"pièce"},{"name":"tofu","unit":"g"},{"name":"ciboule","unit":"tige"},{"name":"gingembre","unit":"morceau"},{"name":"huile de cuisson","unit":"ml"},{"name":"vin de cuisine","unit":"ml"},{"name":"sel","unit":"g"},{"name":"poivre","unit":"g"},{"name":"eau bouillante","unit":"L"}]'::jsonb, '["Nettoyer le poisson, (surtout les veines de sang dans le ventre, sinon il sera odorant), le mettre dans un grand bol, ajouter le vin de cuisine, 10 g de gingembre en tranches, 5 g de sel, laisser mariner 15 minutes.","Couper le tofu en dés, le faire tremper dans l''eau froide 5 minutes, puis égoutter et réserver.","Avant de frire le poisson, frotter la poêle avec une tranche de gingembre pour éviter qu''il n''attache. Verser l''huile (quantité : 15 ml par poisson), chauffer, puis déposer le poisson et le frire 2 à 3 minutes. Pendant ce temps, secouer la poêle pour éviter qu''il n''attache, et le retourner une fois.","Une fois tous les poissons frits, verser de l''eau bouillante, 5 ml de vin de cuisine, les tranches de gingembre. Passer du feu doux au feu vif, couvrir et cuire à feu vif 10 minutes (l''eau doit être un peu abondante car elle s''évaporera).","Quand le bouillon devient blanc, ajouter le tofu préparé, réduire à feu moyen et cuire encore 5 minutes. Assaisonner avec 10 g de sel et 3 g de poivre. Parsemer de ciboule ciselée et servir."]'::jsonb, '["Soupe","Savoureux","Mijoté","Fait maison","Riche en calcium","Réconfortant"]'::jsonb),
  ('howtocook:soup/朱雀汤/朱雀汤', 'fr', 'Soupe de l''Oiseau Rouge', 'Soupes', 'La soupe de l''Oiseau Rouge est une soupe rapide et facile de la région de l''Est du Henan. Elle est douce, soyeuse et parfumée avec l''arôme riche de l''huile de sésame. Les œufs fournissent des protéines de haute qualité. La préparation est très simple : il suffit de faire bouillir de l''eau et de la verser sur les œufs. Le tout prend moins de dix minutes, et cette soupe a également un effet rafraîchissant et détoxifiant.', '[{"name":"Œufs","unit":"pièce"},{"name":"Huile de sésame","unit":"ml"},{"name":"Sucre blanc","unit":"g"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Battre les œufs dans un bol, puis ajouter l''huile de sésame.","Porter l''eau à ébullition, puis verser rapidement l''eau bouillante dans le bol contenant les œufs.","Ajouter le sucre blanc."]'::jsonb, '["Soupe","Est du Henan","Rapide","Douce","Familiale"]'::jsonb),
  ('howtocook:soup/玉米排骨汤/玉米排骨汤', 'fr', 'Soupe de côtes de porc au maïs', 'Soupes', 'La soupe de côtes de porc au maïs est un potage maison savoureux et légèrement sucré. Les côtes sont tendres, le maïs et la carotte apportent une douceur naturelle. Riche en protéines, vitamines et fibres, équilibré. Simple à réaliser, idéal pour les débutants : il suffit de blanchir les côtes, de les faire revenir, puis de mijoter environ une heure. De la préparation à l’assiette, comptez environ une heure et demie.', '[{"name":"Côtes de porc","unit":"g"},{"name":"Maïs","unit":"pièce"},{"name":"Carotte","unit":"pièce"},{"name":"Poireau","unit":"pièce"},{"name":"Ciboule","unit":"pièce"},{"name":"Gingembre","note":"au goût"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Vinaigre","unit":"ml"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Poivre noir moulu","unit":"g"},{"name":"Sel de table","unit":"g"},{"name":"Eau bouillante","unit":"ml"}]'::jsonb, '["Couper le poireau en tronçons de 3 à 4 cm, les écraser avec le dos du couteau.","Couper le maïs en petits morceaux.","Couper la carotte en morceaux taillés en biais (rouleaux).","Peler le gingembre et le couper en grandes tranches.","Couper les côtes de porc fraîches en petits morceaux.","Mettre les côtes dans une casserole d''eau froide, ajouter le poireau, le gingembre et le vin de cuisine pour blanchir. Porter à ébullition à feu vif, écumer, retirer les côtes et égoutter.","Chauffer la poêle avec un peu d''huile, ajouter les grandes tranches de gingembre et les côtes, faire revenir jusqu''à ce qu''elles soient légèrement dorées. Ajouter le vinaigre (pour attendrir la viande), continuer à revenir une minute.","Verser de l''eau bouillante en une seule fois (assez pour couvrir, ne pas en rajouter ensuite). Porter à ébullition à feu vif.","Ajouter d''abord le maïs, saupoudrer de poivre noir, couvrir et mijoter à feu doux 20 minutes. Puis ajouter la carotte, couvrir et continuer à mijoter à feu doux 40 minutes.","Assaisonnement très simple : trois minutes avant la fin, ne rien ajouter sauf du sel. Parsemer de ciboule ciselée juste avant de servir."]'::jsonb, '["Potages","Savoureux","Mijoté","Fait maison","Équilibré"]'::jsonb),
  ('howtocook:soup/生汆丸子汤', 'fr', 'Soupe de boulettes pochées', 'Soupes', 'La soupe de boulettes pochées est tendre, élastique et glissante, une soupe maison au goût authentique. Le porc fournit des protéines de qualité, associé à des ingrédients comme les champignons noirs et les lis séchés, l''équilibre nutritionnel est bon. La préparation nécessite de hacher la viande soi-même et de maîtriser le pochage des boulettes, ce qui est un peu difficile, plus adapté aux amateurs de cuisine ayant un certain niveau. Du début à la fin, il faut environ 1 heure.', '[{"name":"Épaule de porc","note":"quantité suffisante"},{"name":"Sel","note":"quantité suffisante"},{"name":"Poivre","note":"quantité suffisante"},{"name":"Eau d''oignon-gingembre-poire du Sichuan","note":"quantité suffisante"},{"name":"Blanc d''œuf","unit":"pièce"},{"name":"Fécule de pomme de terre","unit":"g"},{"name":"Huile de soja cuite","note":"quantité suffisante"},{"name":"Champignons noirs","note":"quantité suffisante"},{"name":"Lis séchés","note":"quantité suffisante"},{"name":"Oignons verts","note":"quantité suffisante"},{"name":"Vermicelles","note":"quantité suffisante"},{"name":"Poudre de poulet","note":"quantité suffisante"},{"name":"Huile de sésame","unit":"gouttes"},{"name":"Coriandre","unit":"branche"}]'::jsonb, '["Couper la viande en morceaux, avec un rapport 70% maigre, 30% gras.","Hacher avec le couteau, puis frapper avec le dos du couteau pour détendre les tendons et assouplir la viande.","Hacher et frapper jusqu''à obtenir une farce. Pour un bon résultat, il faut hacher à la main, la machine rend la texture trop collante.","Pour 500 g de viande, 6 g de sel, 1 g de poivre.","Mélanger à la main.","Ajouter l''eau d''oignon-gingembre-poire du Sichuan en plusieurs fois, en mélangeant et en pétrissant pour que la viande absorbe bien l''eau. Pour 500 g de farce, 80 g d''eau aromatique.","Ajouter le blanc d''œuf et continuer à mélanger dans le même sens.","Ajouter 40 g de fécule de pomme de terre et mélanger.","Ajouter de l''huile de soja cuite pour maintenir la texture tendre et élastique.","Porter de l''eau à ébullition dans une casserole, puis réduire à feu doux, juste avant l''ébullition.","Avec les mains, former des boulettes en pressant.","Lorsque toutes les boulettes remontent à la surface, cuire à feu doux pendant 1 minute.","Mettre les vermicelles au fond du bol.","Ajouter les champignons noirs, les lis séchés, les oignons verts, et assaisonner avec du sel, du poivre et de la poudre de poulet.","Verser la soupe et les boulettes dans le bol.","Verser 3 à 5 gouttes d''huile de sésame.","Ajouter une petite branche de coriandre."]'::jsonb, '["Soupe","Savoureux","Léger","Poché","Maison","Équilibré"]'::jsonb),
  ('howtocook:soup/番茄牛肉蛋花汤', 'fr', 'Soupe à la tomate, au bœuf et aux œufs en fleurs', 'Soupes', 'La soupe à la tomate, au bœuf et aux œufs en fleurs est une soupe familiale aigre-douce et appétissante, à la texture tendre et onctueuse. Le bœuf est riche en protéines de haute qualité et en fer, la tomate apporte du lycopène et de la vitamine C, et les œufs complètent avec de la lécithine. La recette est simple, même les débutants peuvent la maîtriser facilement, et elle est généralement prête en une demi-heure environ.', '[{"name":"Bœuf","unit":"g"},{"name":"Tomate","unit":"pièce"},{"name":"Œuf","unit":"pièce"},{"name":"Oignon vert","note":"quantité suffisante"},{"name":"Gingembre","note":"quantité suffisante"},{"name":"Ail","note":"quantité suffisante"},{"name":"Sel","unit":"g"},{"name":"Poivre","unit":"g"}]'::jsonb, '["Couper le bœuf en tranches fines","Couper les tomates en petits morceaux","Hacher l''oignon vert en ciboule","Couper le gingembre en tranches","Hacher l''ail en purée","Mettre le bœuf dans un bol","Saler et poivrer, laisser mariner 15 à 20 minutes","Porter de l''eau à ébullition","Ajouter les tranches de gingembre et les tranches de bœuf, cuire jusqu''à ce que le bœuf change de couleur","Ajouter les morceaux de tomate, cuire jusqu''à ce qu''ils ramollissent","Battre les œufs, verser lentement dans la casserole en remuant avec des baguettes pour former des fils d''œuf","Assaisonner avec du sel et du poivre","Ajouter enfin la ciboule, retirer du feu"]'::jsonb, '["Soupe","Aigre-doux","Savoureux","Bouilli","Familial","Rapide"]'::jsonb),
  ('howtocook:soup/皮蛋瘦肉粥', 'fr', 'Porridge aux œufs de cent ans et porc maigre', 'Soupes', 'Le porridge aux œufs de cent ans et porc maigre est une bouillie classique de la cuisine cantonaise. La base est onctueuse et soyeuse, le goût riche des œufs de cent ans se marie avec la tendreté du porc maigre, offrant une texture douce et savoureuse. Il est riche en glucides et en protéines de qualité, accompagné de légumes, offrant un équilibre nutritionnel et facile à digérer. Bien que les étapes soient nombreuses, elles sont intuitives, même un débutant peut suivre le processus avec succès. La préparation prend environ 1h30, et grâce à la fonction de programmation ou de maintien au chaud du cuiseur à riz, ce plat est particulièrement pratique pour le petit-déjeuner.', '[{"name":"Eau potable","unit":"litre"},{"name":"Œufs de cent ans (œufs de canard conservés)","unit":"pièce"},{"name":"Porc maigre","unit":"gramme"},{"name":"Riz","unit":"ml"},{"name":"Oignons verts","unit":"brin"},{"name":"Coriandre","unit":"brin"},{"name":"Laitue","unit":"feuille"},{"name":"Gingembre","unit":"morceau (pouce)"},{"name":"Sauce soja","unit":"ml"},{"name":"Sauce d''huître","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Poivre","unit":"g"},{"name":"Huile de cuisson","unit":"ml"}]'::jsonb, '["Riz - laver - mettre dans la cuve du cuiseur à riz - ajouter 1 litre d''eau potable","Porc maigre - laver - égoutter rapidement - ajouter 10 ml d''huile de cuisson - mélanger en frottant - mettre dans la cuve du cuiseur à riz","Œufs de cent ans - écaler - laver - couper en deux - séparer le blanc du jaune - couper le blanc en petits morceaux - écraser le jaune - mettre dans la cuve du cuiseur à riz","Gingembre - laver - peler - retirer les parties abîmées - couper en julienne - mettre dans la cuve du cuiseur à riz","Oignons verts - laver - retirer les racines - retirer les parties abîmées - ciseler - mettre dans un petit bol et réserver","Coriandre - laver - retirer les racines - retirer les parties abîmées - ciseler - mettre dans un petit bol et réserver","Laitue - laver - retirer les racines - retirer les parties abîmées - couper en morceaux - mettre dans un petit bol et réserver","Sauce soja + sauce d''huître + sel + poivre - bien mélanger - mettre dans un petit bol et réserver","Ingrédients principaux - cuire en mode porridge du cuiseur à riz","Accompagnements - après la cuisson des ingrédients principaux, blanchir la laitue dans de l''eau chaude, puis ajouter tous les accompagnements dans la cuve, couvercle ouvert, et mélanger","Sauce - après la cuisson des ingrédients principaux, ajouter la sauce avec les accompagnements dans la cuve, couvercle ouvert, et bien mélanger"]'::jsonb, '["Bouillie","Cantonnais","Fait maison","Petit-déjeuner","Savoureux"]'::jsonb),
  ('howtocook:soup/米粥', 'fr', 'Porridge de riz', 'Soupes', 'La bouillie de riz naturelle est légère et douce, un plat de base réconfortant pour l''estomac, indispensable à la maison. Le goût du riz est pur, adapté à tous les âges. Riche en glucides et en petites quantités de protéines, facile à digérer et à absorber, elle a des effets bénéfiques sur la rate, l''estomac et les poumons. La préparation est simple, il suffit de maîtriser le feu et la quantité d''eau, même les débutants peuvent la réaliser facilement, le tout prend environ 25 minutes.', '[{"name":"Riz","unit":"ml","note":""},{"name":"Eau","unit":"","note":"Quantité suffisante"},{"name":"Huile végétale","unit":"","note":"Optionnelle, quantité suffisante"}]'::jsonb, '["(Optionnel) Mélanger Mo ml d''huile avec le riz lavé, en veillant à bien mélanger pour que chaque grain de riz soit légèrement enrobé d''huile.","(Optionnel) Réfrigérer le mélange riz-huile pendant une durée Tc.","Ajouter le riz et l''eau dans la casserole.","Chauffer à feu vif jusqu''à T1.","Avant T1, réduire le feu. Si vous oubliez cette étape, l''eau pourrait déborder et éteindre la flamme. Très dangereux !","Chauffer jusqu''à Tr. À Tr, éteindre le feu."]'::jsonb, '["Soupe","Léger","Réconfortant pour l''estomac","Petit-déjeuner","Fait maison","Rapide","Arôme de riz"]'::jsonb),
  ('howtocook:soup/紫菜蛋花汤', 'fr', 'Soupe aux algues et aux œufs battus', 'Soupes', 'La soupe aux algues et aux œufs battus est un plat familial léger et savoureux, appartenant aux soupes simples chinoises. Les algues sont riches en iode, calcium et fibres alimentaires, les œufs fournissent des protéines de qualité, leur combinaison est nutritionnellement équilibrée. La préparation est très simple, adaptée aux débutants, du début à la fin en seulement 20 minutes environ.', '[{"name":"Algues séchées","unit":"g"},{"name":"Œufs","unit":"pièce"},{"name":"Eau","unit":"litre"},{"name":"Sel","unit":"g"},{"name":"Huile","unit":"ml"},{"name":"Huile de sésame","note":"quelques gouttes"},{"name":"Oignons verts ciselés","note":"quantité suffisante"},{"name":"Crevettes","note":"quantité suffisante"}]'::jsonb, '["Faire tremper les algues séchées dans l''eau claire pendant 15 minutes, les égoutter et réserver.","Chauffer une casserole, verser 1,5 litre d''eau claire, 5 ml d''huile, 2 g de sel. Porter à ébullition puis ajouter les algues.","3 minutes après l''ébullition des algues, verser lentement les œufs battus dans la casserole, laisser cuire 30 secondes puis retirer du feu.","Saupoudrer d''oignons verts ciselés, réduire à feu doux pendant 20 secondes.","Éteindre le feu, ajouter quelques gouttes d''huile de sésame avant de servir. Certains ajoutent aussi un peu de crevettes séchées, ce qui est également délicieux."]'::jsonb, '["Soupe","Léger","Savoureux","Rapide","Familial","Cuit"]'::jsonb),
  ('howtocook:soup/罗宋汤', 'fr', 'Bortsch shanghaien', 'Soupes', 'Une soupe familiale d''origine russe (bortsch) adaptée à Shanghai, à base de tomates et de bœuf, avec une saveur aigre-douce riche et umami. Riche en protéines de qualité, en lycopène et en vitamines, équilibrée. Simple à préparer, idéale pour les débutants, comptez 2 à 3 heures.', '[{"name":"Bœuf","unit":"g"},{"name":"Bouillon de bœuf","unit":"mL"},{"name":"Tomates en conserve","unit":"boîte"},{"name":"Concentré de tomate","unit":"g"},{"name":"Pomme de terre","unit":"g"},{"name":"Oignon","unit":"g"},{"name":"Carotte","unit":"g"},{"name":"Persil","unit":"g"},{"name":"Chou","unit":"g"},{"name":"Saucisse rouge","unit":"g"},{"name":"Huile d''olive","unit":"mL"},{"name":"Huile végétale","unit":"mL"},{"name":"Sel","unit":"g"},{"name":"Poivre noir","unit":"g"},{"name":"Bouillon de légumes (persil, carotte, oignon)","note":"à volonté"}]'::jsonb, '["Couper l''oignon, la carotte et le persil en petits dés de 1 cm.","Couper la saucisse rouge et la pomme de terre en morceaux de 2 cm.","Retirer la tige du chou, puis déchirer en morceaux de 2 cm.","Assaisonner le bœuf avec 3 g de sel et 3 g de poivre noir, laisser mariner 5 minutes.","Chauffer une poêle et ajouter l''huile végétale.","Faire saisir le bœuf jusqu''à ce qu''il soit bien coloré (il peut rester cru à l''intérieur, surtout ne pas brûler). Réserver.","Chauffer une marmite, ajouter l''huile d''olive, les dés d''oignon, de carotte et de persil.","Faire revenir jusqu''à ce que l''oignon soit translucide, ajouter la pâte de tomate et la tomate en conserve.","Ajouter le bœuf et les dés de pomme de terre, mélanger.","Ajouter de l''eau à hauteur des ingrédients, cuire à feu moyen pendant 1 heure.","Ajouter les morceaux de chou et de saucisse rouge, mélanger.","Cuire à feu moyen pendant 30 minutes.","Ajouter le reste de sel (15 g), mélanger et servir."]'::jsonb, '["Soupe","Aigre-doux","Mijoté","Shanghaien","Familial","Bœuf","Appétissant"]'::jsonb),
  ('howtocook:soup/羊肉汤/羊肉汤', 'fr', 'Soupe d''agneau', 'Soupes', 'La soupe d''agneau est une soupe réconfortante maison, de couleur laiteuse, à la viande tendre, avec le parfum et le piquant de l''oignon vert et du poivre blanc. Riche en protéines, calcium, fer et autres nutriments, elle réchauffe l''estomac et la rate, et aide à lutter contre le froid. Les étapes sont simples, même les débutants peuvent la réaliser facilement, l''ensemble de la cuisson prend environ 30 minutes.', '[{"name":"Agneau (ou abats d''agneau)","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Oignon vert","unit":"g"},{"name":"Eau à température ambiante","unit":"ml"},{"name":"Eau bouillante","unit":"ml"},{"name":"Poivre blanc moulu","unit":"g"},{"name":"Sel de table","unit":"g"},{"name":"Cumin en poudre (facultatif)","unit":"g"},{"name":"Coriandre (facultatif)","unit":"g"}]'::jsonb, '["Couper l''agneau en morceaux de 5 cm de long et 0,5 cm de large","Couper l''oignon vert en petits tronçons","Mettre l''agneau dans une casserole, ajouter 1000 ml d''eau à température ambiante, ajouter le vin de cuisine et l''oignon vert","Après ébullition pendant 2 minutes, retirer l''agneau, le rincer à l''eau à température ambiante et l''égoutter","Chauffer la casserole avec de l''huile de cuisson, ajouter l''agneau, faire sauter 2 minutes jusqu''à ce que la surface de l''agneau soit légèrement dorée","Ajouter de l''eau bouillante, mettre à feu vif","Après 5 minutes, ajouter le poivre blanc moulu et le sel, continuer à faire bouillir 5 minutes","Après avoir retiré du feu, ajouter la coriandre et le cumin en poudre, bien mélanger"]'::jsonb, '["Soupe","Savoureux","Légèrement piquant","Mijoté","Maison","Réconfortant"]'::jsonb),
  ('howtocook:soup/腊八粥', 'fr', 'Bouillie de Laba', 'Soupes', 'La bouillie de Laba est un porridge sucré traditionnel de fête, à la texture épaisse et moelleuse, mêlant les arômes complexes de multiples céréales, légumineuses et fruits secs. Riche en glucides, minéraux et vitamines diverses, les graines de lotus ont également un effet calmant sur l''esprit, adapté aux personnes stressées. Bien qu''il y ait beaucoup d''ingrédients, la préparation est simple, il suffit de mijoter patiemment, accessible aux débutants. Temps de cuisson environ 3 heures, hors trempage.', '[{"name":"Eau potable","unit":"L"},{"name":"Riz","unit":"g"},{"name":"Riz gluant","unit":"g"},{"name":"Cacahuètes","unit":"g"},{"name":"Haricots azuki","unit":"g"},{"name":"Jujubes","unit":"g"},{"name":"Graines de coix","unit":"g"},{"name":"Riz noir","unit":"g"},{"name":"Millet","unit":"g"},{"name":"Graines de lotus","unit":"g"},{"name":"Haricots mungo","unit":"g"},{"name":"Soja","unit":"g"},{"name":"Pois","unit":"g"},{"name":"Haricots rouges","unit":"g"},{"name":"Longanes séchés (sans pépins)","unit":"g"},{"name":"Marrons (châtaignes)","unit":"g"},{"name":"Noix décortiquées","unit":"g"},{"name":"Raisins secs","unit":"g"},{"name":"Sucre de roche (ou sucre blanc, pour assaisonnement)","unit":"g"}]'::jsonb, '["Lavez à l''avance les haricots mungo, les haricots azuki, les cacahuètes, le soja, les pois, les haricots rouges, et placez-les dans un bol en verre propre. Versez de l''eau potable jusqu''à 3/4 du bol et laissez tremper toute une nuit (ou au moins 8 heures).","Lavez à l''avance le riz, le riz gluant, les graines de coix, le riz noir, le millet, les graines de lotus, et placez-les dans un bol en verre propre. Versez de l''eau potable jusqu''à 3/4 du bol et laissez tremper 3 heures.","Séparez et jetez l''eau du bol de l''étape 1 contenant les haricots mungo, azuki, cacahuètes, soja, pois et haricots rouges. Versez les ingrédients dans une casserole à bouillie, ajoutez 1 litre d''eau potable (ou jusqu''à ce que l''eau dépasse les ingrédients d''une phalange), portez à ébullition à feu vif, puis couvrez et laissez mijoter à feu doux pendant 30 minutes.","Séparez et jetez l''eau du bol de l''étape 2 contenant le riz, riz gluant, graines de coix, riz noir, millet et graines de lotus. Versez ces ingrédients dans la casserole, couvrez et laissez mijoter à feu doux pendant 60 minutes.","Lavez les jujubes, les longanes séchés, les marrons, les noix, les raisins secs (coupez les jujubes en petits morceaux) et le sucre de roche. Ajoutez le tout dans la casserole, couvrez et laissez mijoter à feu doux pendant 60 minutes.","Vérifiez que la bouillie est épaisse, puis éteignez le feu, servez dans des bols et dégustez."]'::jsonb, '["Soupe","Sucré","Mijoté","Traditionnel","Petit-déjeuner","Familial"]'::jsonb),
  ('howtocook:soup/菌菇炖乳鸽/菌菇炖乳鸽', 'fr', 'Pigeon braisé aux champignons', 'Soupes', 'La soupe de pigeon braisé aux champignons est claire, la viande tendre, et les arômes de champignons et de pigeon se mêlent. C''est une soupe mijotée cantonaise maison. Le pigeon est riche en protéines de haute qualité et en acides aminés, tandis que les champignons apportent des polysaccharides et des fibres alimentaires. C''est un plat nourrissant et doux. La recette nécessite de blanchir le pigeon pour enlever l''odeur, puis de le mijoter avec du maïs et des champignons. La maîtrise du feu et du temps est un peu exigeante, mais un débutant attentif peut y arriver. De la préparation au plat fini, il faut environ 45 minutes avec un autocuiseur, ou un peu plus d''une heure avec une mijoteuse en terre cuite.', '[{"name":"Pigeon","unit":"g"},{"name":"Champignons","unit":"g"},{"name":"Maïs","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Sel","unit":"g"}]'::jsonb, '["Laver à l''eau froide le pigeon déjà préparé par le commerçant attentionné.","Dans une casserole d''eau froide, mettre le pigeon lavé, ajouter 15 ml de vin de cuisine et du gingembre. Porter à ébullition puis retirer le pigeon immédiatement pour ne pas perdre les nutriments.","Mettre le pigeon dans un autocuiseur ou une marmite en terre cuite, ajouter de l''eau jusqu''à couvrir le pigeon, puis ajouter 20 g de gingembre, 200 g de maïs et 100 g de champignons.","Une fois le temps écoulé, servir dans un bol et ajouter 3 à 5 g de sel."]'::jsonb, '["Soupe","Savoureux","Léger","Mijoté","Cantonnais","Maison","Nourrissant"]'::jsonb),
  ('howtocook:soup/西红柿鸡蛋汤', 'fr', 'Soupe à la tomate et aux œufs', 'Soupes', 'La soupe à la tomate et aux œufs est une soupe familiale aigre-douce et appétissante, à la texture soyeuse. Sa préparation est très simple, et elle plaît à tous, jeunes et moins jeunes. Riche en lycopène, vitamine C et protéines de qualité, elle est équilibrée et facile à digérer. Idéale pour les débutants, rapide et économique, elle se prépare en environ 15 minutes.', '[{"name":"tomates","unit":"pièces"},{"name":"œufs","unit":"pièces"},{"name":"huile de sésame","unit":"gouttes"},{"name":"glutamate monosodique","unit":"grammes"},{"name":"sel","unit":"grammes"},{"name":"oignon vert, gingembre, ail","unit":"grammes"}]'::jsonb, '["Lavez les tomates et coupez-les en morceaux.","Hachez finement l''oignon vert, le gingembre et l''ail.","Cassez les œufs dans un bol et battez-les bien avec des baguettes (ou un fouet).","Chauffez la poêle, ajoutez 15 ml d''huile. Lorsque l''huile commence à fumer, ajoutez l''oignon vert, le gingembre et l''ail et faites-les sauter 30 secondes.","Ajoutez les tomates et faites-les sauter 1 minute.","Versez de l''eau, la hauteur de l''eau doit être environ 1,2 fois celle des ingrédients dans la poêle, puis ajoutez le sel.","Lorsque l''eau bout, versez les œufs battus et remuez avec des baguettes pour les disperser. Ajoutez le glutamate monosodique et l''huile de sésame.","Attendez 30 secondes, puis éteignez le feu et servez."]'::jsonb, '["Soupe","Aigre-doux","Rapide","Familial","Appétissant","Potage"]'::jsonb),
  ('howtocook:soup/金针菇汤', 'fr', 'Soupe aux champignons enoki', 'Soupes', 'C''est une soupe maison légère et rafraîchissante, au goût délicat et facile à préparer. Les champignons enoki sont riches en acides aminés et en fibres alimentaires, et l''ajout d''œufs apporte des protéines de qualité. La recette est très simple, même les débutants peuvent la réussir, du début à la fin en seulement 10 minutes.', '[{"name":"Champignons enoki","unit":"g"},{"name":"Œuf","note":"Quantité suffisante (si nécessaire)"},{"name":"Sel","unit":"g"},{"name":"Glutamate monosodique","unit":"g"}]'::jsonb, '["Détachez les champignons enoki à la main, le plus possible pour éviter qu''ils ne retiennent la saleté, puis lavez-les et égouttez-les.","Coupez les champignons enoki en morceaux avec un couteau de cuisine ou un couteau à fruits, selon votre préférence, mais les morceaux ne doivent pas dépasser 5 cm de long.","Mettez les champignons enoki dans une casserole, ajoutez de l''eau jusqu''à environ 1,1 fois la hauteur totale des ingrédients, portez à ébullition et laissez cuire 3 minutes.","Ajoutez le glutamate monosodique et le sel, puis mélangez.","Continuez à chauffer environ 30 secondes, éteignez le feu et versez dans un bol."]'::jsonb, '["Soupe","Léger","Rapide","Maison","Savoureux"]'::jsonb),
  ('howtocook:soup/银耳莲子粥/银耳莲子粥', 'fr', 'Bouillon de tremelle et lotus', 'Soupes', 'Le bouillon de tremelle et lotus est doux et onctueux, la tremelle tendre et les graines de lotus fondantes, c''est une soupe tonique courante. Riche en collagène naturel, fibres alimentaires et divers oligo-éléments, elle aide à apaiser l''esprit. Sa préparation nécessite trempage et mijotage lent, mettant la patience des débutants à l''épreuve, le tout prenant environ 3,5 heures.', '[{"name":"Tremelle","unit":"grammes"},{"name":"Graines de lotus sans cœur","unit":"grammes"},{"name":"Jujubes","unit":"grammes"},{"name":"Baies de goji","unit":"grammes"},{"name":"Sucre de roche","unit":"grammes"}]'::jsonb, '["Faire tremper la tremelle et les graines de lotus dans de l''eau claire pendant 2 heures, les jujubes pendant 10 à 20 minutes, laver les baies de goji, réserver","Verser 600 ml d''eau dans une casserole, porter à ébullition puis ajouter successivement la tremelle, les graines de lotus et les jujubes","Attendre que l''eau bout de nouveau, couvrir et baisser à feu moyen, continuer à mijoter","Après environ 1 heure de cuisson, ajouter 5 g à 10 g de sucre de roche et 5 g à 6 g de baies de goji, passer à feu doux","Laisser mijoter à feu doux encore 30 minutes, la tremelle commence à devenir visqueuse","Ajouter à nouveau 5 g à 10 g de sucre de roche, remuer avec une cuillère pendant 5 à 10 minutes","Éteindre le feu, servir à l''aide d''une cuillère"]'::jsonb, '["Soupe","Doux","Tonique","Mijoté","Familial","Bien-être"]'::jsonb),
  ('howtocook:soup/陈皮排骨汤', 'fr', 'Soupe de côtes levées à l''écorce de mandarine', 'Soupes', 'Une soupe cantonnaise claire et nourrissante, au bouillon limpide et au goût doux, avec l''arôme unique de l''écorce de mandarine. Les côtes levées fournissent des protéines de qualité, tandis que le ginseng américain, le dendrobium et d''autres ingrédients aident à humidifier les poumons, renforcer la rate et étancher la soif. Idéale pour les personnes qui veillent tard. Difficulté moyenne : il suffit de préparer les ingrédients, de les mettre dans une casserole de cuisson et de mijoter environ deux heures.', '[{"name":"côtes levées","unit":"morceau"},{"name":"écorce de mandarine","unit":"morceau"},{"name":"ginseng américain","unit":"tranche"},{"name":"dendrobium","unit":"morceau"},{"name":"sceau de Salomon","unit":"tranche"},{"name":"liriope","unit":"pièce"},{"name":"sel","unit":"gramme"}]'::jsonb, '["Ébouillanter les côtes levées dans de l''eau chaude pour éliminer le sang.","Rincer l''écorce de mandarine, la liriope, le sceau de Salomon, le dendrobium et le ginseng américain.","Nettoyer la casserole de cuisson.","Ouvrir la casserole, placer d''abord les côtes levées au fond, puis ajouter successivement l''écorce de mandarine, la liriope, le sceau de Salomon, le dendrobium et le ginseng américain.","Ajouter de l''eau chaude dans la casserole sans trop remplir.","Ajouter de l''eau dans le récipient extérieur, mijoter pendant 1h30.","Ajouter du sel et boire chaud."]'::jsonb, '["Soupe"]'::jsonb),
  ('howtocook:soup/陈皮排骨汤/陈皮排骨汤', 'fr', 'Soupe de côtes de porc à l''écorce de mandarine', 'Soupes', 'Cette soupe est un classique de la cuisine cantonaise, avec un bouillon clair, une saveur douce et un arôme unique d''écorce de mandarine. Les côtes de porc apportent des protéines de qualité et du calcium, associées à l''écorce de mandarine, au ginseng américain, à la dendrobium et autres ingrédients, elle aide à réguler le qi, renforcer la rate, nourrir le yin et humidifier les poumons. Idéale pour les personnes qui veillent tard ou ont des gorges irritées. La recette est simple : il suffit de préparer les ingrédients et de maîtriser le temps de cuisson. Les débutants peuvent la réussir facilement. Du début à la fin, cela prend environ deux heures.', '[{"name":"Côtes de porc","unit":"morceaux"},{"name":"Écorce de mandarine","unit":"quartiers"},{"name":"Ginseng américain","unit":"tranches"},{"name":"Dendrobium","unit":"tiges"},{"name":"Polygonatum odoratum","unit":"tranches"},{"name":"Ophiopogon","unit":"pièces"},{"name":"Sel","unit":"grammes"}]'::jsonb, '["Ébouillanter les côtes de porc dans de l''eau chaude pour enlever le sang","Rincer l''écorce de mandarine, l''ophiopogon, le polygonatum odoratum, la dendrobium et le ginseng américain","Nettoyer la casserole à soupe","Ouvrir la casserole, mettre d''abord les côtes au fond, puis ajouter l''écorce de mandarine, l''ophiopogon, le polygonatum odoratum, la dendrobium et le ginseng américain","Ajouter de l''eau chaude dans la casserole, ne pas trop remplir","Mettre de l''eau dans le récipient de cuisson, mijoter 1h30","Ajouter du sel, boire chaud"]'::jsonb, '["Soupe","Cantonaise","Mijotée","Nourrissante","Douce","Fait maison"]'::jsonb),
  ('howtocook:soup/黄瓜皮蛋汤', 'fr', 'Soupe de concombre et œufs de cent ans', 'Soupes', 'La soupe de concombre et œufs de cent ans est une soupe maison rapide, au goût léger, avec le parfum grillé des œufs de cent ans et des gousses d''ail sauté. Elle réchauffe le cœur et l''estomac sans être grasse. Le concombre rafraîchit et hydrate, les œufs de cent ans apportent des protéines, faible en matières grasses et léger. La préparation ne demande presque aucune compétence technique, même un débutant en cuisine peut la réaliser facilement, de la préparation à la sortie de la casserole, cela ne prend qu''environ dix minutes.', '[{"name":"concombre","unit":"pièce"},{"name":"œufs de cent ans","unit":"pièce"},{"name":"ail","unit":"gousse"},{"name":"ciboule","note":"à volonté"},{"name":"huile de cuisson (saindoux recommandé)","unit":"g"},{"name":"sel","unit":"g"},{"name":"bouillon de poulet (facultatif)","unit":"g"},{"name":"eau","unit":"ml"}]'::jsonb, '["Laver le concombre, couper en fines tranches de 0,5 à 1,2 mm d''épaisseur.","Laver et hacher finement la ciboule. Écraser l''ail avec le plat d''un couteau, enlever la peau, couper en deux.","Écaler les œufs de cent ans, puis couper chacun en 6 à 8 morceaux. Verser de l''huile dans la casserole, ajouter les œufs de cent ans et l''ail coupés.","Faire sauter à feu doux jusqu''à ce que les œufs de cent ans et l''ail soient légèrement dorés. Ajouter de l''eau, porter à ébullition à feu vif.","Ajouter les tranches de concombre. Dès que l''eau bout à nouveau, éteindre le feu. Assaisonner avec du sel et du bouillon de poulet (facultatif), puis retirer du feu.","Verser dans un bol, saupoudrer de ciboule hachée et servir."]'::jsonb, '["Soupe","Léger","Frais et parfumé","Rapide","Maison","Faible en matières grasses"]'::jsonb),
  ('howtocook:staple/中式馅饼/中式馅饼', 'fr', 'Galette farcie chinoise', 'Féculents', 'Cette galette a une croûte légèrement croustillante et un intérieur moelleux, avec une farce salée et savoureuse. C''est un plat de pâtes fait maison. Riche en glucides et protéines, l''ajout de carotte et d''œuf apporte plus de nutriments. La difficulté est moyenne, les débutants doivent maîtriser le feu, mais les étapes sont claires et faciles à suivre. Du début à la fin, il faut environ 1 heure.', '[{"name":"Farine","unit":"grammes"},{"name":"Viande hachée","unit":"grammes"},{"name":"Huile","unit":"millilitres"},{"name":"Sel","unit":"grammes"},{"name":"Sucre","unit":"grammes"},{"name":"Fécule","unit":"grammes"},{"name":"Sauce soja","unit":"grammes"},{"name":"Assaisonnement","unit":"grammes"},{"name":"Ail","unit":"gousses"},{"name":"Oignon vert","unit":"tiges"},{"name":"Œuf","unit":"pièces"},{"name":"Carotte","note":"selon besoin"}]'::jsonb, '["Prenez la viande hachée (décongelée), ajoutez la moitié de tous les assaisonnements ci-dessus (huile, sel, sucre, sauce soja, assaisonnement) et toute la fécule, mélangez bien, et laissez mariner 30 minutes.","Mettez la farine dans un bol, ajoutez l''œuf, ajoutez l''autre moitié de tous les assaisonnements ci-dessus, ajoutez une quantité d''eau équivalente à la moitié de la farine (pour que la pâte soit relativement épaisse mais fluide), mélangez bien.","Hachez l''ail en petits morceaux.","Coupez l''oignon vert en tronçons.","Hachez finement la carotte (pour la farce, donc aussi fin que possible, vous pouvez hacher aléatoirement).","Chauffez la poêle à froid avec de l''huile, mettez suffisamment d''huile.","Quand l''huile est chaude, faites revenir l''ail haché jusqu''à ce qu''il soit parfumé.","Ajoutez la viande hachée marinée, faites-la sauter jusqu''à ce qu''elle soit cuite.","Ajoutez la carotte hachée à la viande et faites sauter ensemble jusqu''à ce que l''huile devienne dorée (pour extraire la saveur de la carotte).","Éteignez le feu. Laissez refroidir 2 minutes.","Versez la viande hachée cuite dans la pâte crue, mélangez bien.","Rallumez le feu, couvrez le fond de la poêle d''huile.","Réduisez à feu doux, versez la pâte dans la poêle et étalez-la uniformément. Assurez-vous que l''épaisseur ne soit pas trop grande. Vous pouvez soulever la poêle pour laisser la pâte couvrir le fond.","Tant que la surface de la galette est encore liquide, saupoudrez les tronçons d''oignon vert.","Maintenez à feu doux jusqu''à ce que le dessous soit pris.","Retournez la galette, continuez à cuire à feu doux jusqu''à ce que l''autre côté soit pris.","Ensuite, faites cuire chaque côté 20 secondes supplémentaires.","Éteignez le feu et sortez la galette."]'::jsonb, '["Plat principal","Salé","Poêlé","Fait maison","Farineux","Petit déjeuner"]'::jsonb),
  ('howtocook:staple/凉粉/凉粉', 'fr', 'Liangfen', 'Féculents', 'Le Liangfen est une collation traditionnelle originaire du Sichuan. Sa texture est fraîche et lisse, aigre-piquante et appétissante, parfaite pour se rafraîchir en été. L''ingrédient principal est la fécule de pois, riche en glucides, qui fournit rapidement de l''énergie. La préparation n''est pas très compliquée, mais nécessite une cuisson patiente en remuant et une longue réfrigération pour prendre forme, ce qui est d''une difficulté modérée pour les débutants. Du début de la cuisson à la fin, il faut compter environ 3 à 4 heures, dont la majeure partie est consacrée à la réfrigération, tandis que le travail pratique ne prend qu''environ une demi-heure.', '[{"name":"fécule de pois","unit":"g"},{"name":"ail","unit":"gousse"},{"name":"piment oiseau","unit":"pièce"},{"name":"piment en poudre","unit":"g"},{"name":"sauce soja","unit":"ml"},{"name":"vinaigre","unit":"ml"},{"name":"sucre blanc","unit":"ml"},{"name":"bouillon en poudre","unit":"g"},{"name":"sel","unit":"g"},{"name":"éclats de cacahuètes","unit":"g"},{"name":"coriandre","unit":"g"}]'::jsonb, '["Préparer les ingrédients.","Mélanger 100 g de fécule de pois et 100 g d''eau.","Verser 600 g d''eau dans une casserole, porter à ébullition à feu vif, puis réduire à feu doux.","Verser le mélange de fécule en remuant constamment, jusqu''à ce que le mélange épaississe et devienne homogène en couleur.","Trouver un récipient, le badigeonner d''une fine couche d''huile de cuisson.","Verser la fécule cuite dans le récipient et réfrigérer pendant 2 à 4 heures.","Après réfrigération, démouler et couper en lanières.","Hacher l''ail et les piments oiseau en fines miettes. Ajouter 10 g de piment en poudre, 5 g d''éclats de cacahuètes. Verser de l''huile chaude et mélanger.","Ajouter 10 ml de sauce soja, 10 ml de vinaigre, 5 g de sucre blanc, 3 g de bouillon en poudre, 3 g de sel. Mélanger.","Verser l''assaisonnement sur le Liangfen, puis saupoudrer de coriandre. C''est prêt !"]'::jsonb, '["Plat principal","Cuisine du Sichuan","Aigre-piquant","Salade froide","Rafraîchissant","Snack traditionnel"]'::jsonb),
  ('howtocook:staple/利提巧卡', 'fr', 'Litti Chokha', 'Féculents', 'Le Litti Chokha est un plat traditionnel du Bihar, en Inde, composé de boules de blé dorées et d''une purée de légumes fumée. La texture est croustillante à l''extérieur et moelleuse à l''intérieur, avec un arôme riche. La farce de farine de pois chiches grillée est riche en protéines végétales et en fibres, accompagnée d''aubergines, tomates, pommes de terre, etc., offrant une nutrition complète. La préparation nécessite de pétrir la pâte, farcir, cuire au four et traiter les légumes, ce qui comporte plusieurs étapes et peut être un défi pour les débutants. Le temps total est d''environ 60 minutes.', '[{"name":"Farine de blé complet (Atta)","unit":"gramme"},{"name":"Farine de pois chiches grillée (Sattu, peut être remplacée par de la farine de pois chiches torréfiée)","unit":"gramme"},{"name":"Aubergine","unit":"pièce"},{"name":"Tomate","unit":"pièce"},{"name":"Pomme de terre","unit":"pièce"},{"name":"Oignon","unit":"pièce"},{"name":"Ail","unit":"gousse"},{"name":"Gingembre","unit":"gramme"},{"name":"Piment vert","unit":"pièce"},{"name":"Piment vert","unit":"pièce"},{"name":"Jus de citron","unit":"ml"},{"name":"Coriandre","unit":"gramme"},{"name":"Coriandre","unit":"gramme"},{"name":"Huile de moutarde (peut être remplacée par une autre huile végétale)","unit":"ml"},{"name":"Huile de moutarde (peut être remplacée par une autre huile végétale)","unit":"ml"},{"name":"Cumin","unit":"gramme"},{"name":"Sel noir indien (Kala Namak, peut être remplacé par du sel ordinaire)","unit":"gramme"},{"name":"Poudre de piment rouge","unit":"gramme"},{"name":"Sésame","unit":"gramme"},{"name":"Ghee","unit":"gramme"},{"name":"Sel","unit":"gramme"},{"name":"Sel","unit":"gramme"}]'::jsonb, '["Dans un bol, mélanger 120 g de farine de pois chiches grillée, l''oignon haché, le piment vert et le gingembre hachés.","Ajouter 3 g de cumin, 5 g de sésame, 3 g de poudre de piment rouge, 3 g de sel noir indien, 3 g de sel.","Ajouter 15 ml d''huile de moutarde, 10 ml de jus de citron, et les feuilles de coriandre hachées.","Mélanger soigneusement ; la farce doit être friable mais pouvoir se former en boule. Réserver.","Mettre 200 g de farine de blé complet dans un grand bol.","Ajouter progressivement de l''eau tiède en pétrissant jusqu''à obtenir une pâte lisse et souple.","Laisser reposer la pâte 15 minutes.","Diviser la pâte en 8 portions égales.","Avec la main, aplatir chaque portion en un cercle d''environ 8 cm de diamètre (plus épais au centre).","Placer environ 15 g de farce au centre du cercle.","Replier les bords autour de la farce, sceller hermétiquement et former une boule.","Préchauffer le four à 200 °C.","Placer les littis sur une plaque de cuisson et cuire 25 à 30 minutes, en les retournant une fois, jusqu''à ce qu''ils soient dorés et fissurés.","Si vous utilisez une flamme : griller les littis directement sur des braises ou à feu doux sur une cuisinière à gaz, en les retournant constamment, jusqu''à ce qu''ils soient uniformément dorés.","À la sortie du four, badigeonner chaque litti de ghee chaud pour qu''il s''imprègne.","Griller l''aubergine, la tomate et la pomme de terre directement sur une flamme ou au four à 200 °C pendant 20 à 25 minutes, jusqu''à ce que la peau soit noircie et la chair tendre.","Une fois grillés, retirer la peau et écraser séparément l''aubergine, la tomate et la pomme de terre à la fourchette ou à la main.","Mélanger les légumes écrasés.","Ajouter l''ail haché, le piment vert haché, 4 g de sel et 15 ml d''huile de moutarde.","Bien mélanger.","Parsemer de feuilles de coriandre pour décorer.","Disposer les littis dans une assiette, accompagnés de la purée de légumes (chokha).","Servir chaud. Casser un litti avec les mains et tremper dans le chokha."]'::jsonb, '["Plat principal","Plat indien","Savoureux","Épicé","Grillé","Farcis","Traditionnel"]'::jsonb),
  ('howtocook:staple/印度烤饼', 'fr', 'Naan indien', 'Féculents', 'Ce naan indien est un pain plat fermenté, légèrement brûlé et croustillant à l''extérieur, moelleux et élastique à l''intérieur. C''est l''accompagnement parfait pour les currys. Riche en glucides et en protéines, l''ajout de yaourt rend le pain plus facile à digérer. La préparation est modérément difficile, il faut faire attention à la consistance de la pâte et à la cuisson, mais elle se fait à la poêle. Il faut prévoir 1 heure de levée, pour un temps total d''environ 1h30.', '[{"name":"Farine tout usage","unit":"g"},{"name":"Yaourt","unit":"ml"},{"name":"Levure sèche","unit":"g"},{"name":"Sucre","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Eau tiède","unit":"ml"},{"name":"Ghee ou beurre","unit":"g"},{"name":"Graines de sésame noir","unit":"g"},{"name":"Feuilles de coriandre","unit":"g"},{"name":"Ail","unit":"gousse"}]'::jsonb, '["Dissoudre 3g de levure sèche et 10g de sucre dans 100ml d''eau tiède (environ 40°C, ne pas surchauffer).","Laisser reposer 5 minutes jusqu''à ce que des petites bulles apparaissent en surface (la levure est activée).","Dans un grand bol, mélanger 300g de farine tout usage et 5g de sel.","Verser l''eau levurée, 60ml de yaourt et 15ml d''huile de cuisson.","Pétrir à la main pour obtenir une pâte lisse et souple (la pâte doit être un peu plus molle qu''une pâte normale, légèrement collante est normal).","Pétrir pendant 8 à 10 minutes.","Badigeonner la surface de la pâte avec 3ml d''huile pour éviter qu''elle ne sèche.","Couvrir le bol avec un torchon humide ou du film plastique.","Placer dans un endroit chaud et laisser lever au moins 1 heure jusqu''à ce que la pâte double de volume.","Dégazer la pâte en la pétrissant légèrement.","Diviser la pâte en 6 parts égales (environ 80g chacune).","Prendre une part, humidifier les mains avec 3ml de farine ou d''huile.","Étaler en forme ovale allongée ou en larme, d''une épaisseur d''environ 4-5mm.","Si vous préparez du naan à l''ail : saupoudrer la surface de la pâte d''ail émincé et de feuilles de coriandre, puis presser légèrement avec le rouleau pour les incorporer.","Saupoudrer de graines de sésame noir.","Chauffer une poêle (de préférence en fonte) à feu vif jusqu''à ce qu''elle soit très chaude (une goutte d''eau s''évapore immédiatement).","Badigeonner un côté du pain d''une fine couche d''eau.","Placer le côté badigeonné face vers le bas dans la poêle.","Cuire 1 à 2 minutes jusqu''à ce que le dessous présente des taches brun doré et que le pain commence à gonfler.","Retourner et cuire encore 1 à 2 minutes.","Si vous avez une cuisinière à gaz : après avoir retourné, saisir le pain avec des pinces et le placer directement sur la flamme quelques secondes, il gonflera rapidement.","Retirer et badigeonner immédiatement de ghee ou de beurre fondu.","Préchauffer le four à la température maximale (généralement 250°C).","Placer les pains sur une plaque de cuisson.","Cuire 3 à 5 minutes jusqu''à ce qu''ils soient dorés et gonflés.","Retirer et badigeonner de ghee ou de beurre.","Servir chaud.","Se marie bien avec tous les currys indiens, comme le poulet au beurre ou le curry de haricots rouges."]'::jsonb, '["Plat principal","Indien","Naan","Fermenté","Pour curry","Croustillant","Lacté"]'::jsonb),
  ('howtocook:staple/印度焖饭', 'fr', 'Biryani indien', 'Féculents', 'Le biryani indien est un plat royal originaire de l''époque de l''empire moghol. Les grains de riz sont longs, les épices parfumées, le poulet tendre, le riz bien séparé, avec des couches riches. Riche en protéines et en extraits d''épices, il stimule l''appétit. La préparation est assez complexe, pas très adaptée aux débutants. Il faut compter environ 90 minutes au total (le poulet doit être mariné 1 heure à l''avance).', '[{"name":"Riz basmati","unit":"g"},{"name":"Cuisses de poulet (désossées, peut être remplacé par de l''agneau)","unit":"g"},{"name":"Yaourt","unit":"ml"},{"name":"Tomate","note":"quantité modérée"},{"name":"Gingembre (râpé)","unit":"g"},{"name":"Ail (râpé)","unit":"gousse"},{"name":"Piment vert (fendu)","unit":"pièce"},{"name":"Feuilles de coriandre","unit":"g"},{"name":"Feuilles de menthe","unit":"g"},{"name":"Safran (peut être remplacé par du colorant alimentaire jaune)","unit":"g"},{"name":"Lait tiède","unit":"ml"},{"name":"Ghee","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Curcuma en poudre","unit":"g"},{"name":"Piment rouge en poudre","unit":"g"},{"name":"Garam masala","unit":"g"},{"name":"Sel (pour la marinade)","unit":"g"},{"name":"Sel (pour la cuisson du riz)","unit":"g"},{"name":"Feuilles de laurier","unit":"feuille"},{"name":"Bâton de cannelle (environ 5 cm)","unit":"bâton"},{"name":"Gousses de cardamome","unit":"gousse"},{"name":"Clous de girofle","unit":"clou"},{"name":"Anis étoilé","unit":"étoile"},{"name":"Jus de citron","unit":"ml"},{"name":"Oignon (émincé fin)","unit":"pièce"}]'::jsonb, '["Dans un grand bol, mélanger le yaourt, le gingembre et l''ail râpés, la poudre de piment rouge, le curcuma, le garam masala, le sel et le jus de citron.","Ajouter les morceaux de poulet et les enrober uniformément de la marinade.","Couvrir de film alimentaire et laisser mariner au réfrigérateur au moins 1 heure (de préférence toute une nuit).","Faire tremper 0,5 g de safran dans 30 ml de lait tiède pendant 15 minutes, réserver.","Verser 50 ml d''huile de cuisson dans une casserole et chauffer à feu moyen.","Ajouter les oignons émincés, faire revenir jusqu''à ce qu''ils soient brun doré foncé et croustillants (environ 12-15 minutes, soyez patient).","Retirer les oignons frits, les égoutter sur du papier absorbant, réserver.","Égoutter le riz basmati trempé.","Dans une grande casserole, porter 2000 ml d''eau à ébullition.","Ajouter les feuilles de laurier, les gousses de cardamome, les clous de girofle, le bâton de cannelle, l''étoile d''anis et 10 g de sel.","Ajouter le riz, cuire à feu vif pendant 5-6 minutes, jusqu''à ce que les grains soient cuits à environ 70 % (mous à l''extérieur, encore fermes au centre).","Égoutter immédiatement, jeter les épices entières, réserver.","Badigeonner le fond d''une casserole à fond épais avec 15 g de ghee.","Première couche : disposer le poulet mariné uniformément au fond de la casserole.","Deuxième couche : étaler la moitié du riz mi-cuit.","Parsemer de la moitié des oignons frits, des feuilles de menthe, des feuilles de coriandre et des piments verts.","Troisième couche : étaler le reste du riz.","Parsemer du reste des oignons frits, des feuilles de menthe et des feuilles de coriandre.","Verser le lait de safran uniformément sur la couche supérieure de riz.","Déposer le reste du ghee (15 g) en petits morceaux dispersés.","Sceller le couvercle : former un boudin de pâte avec de la farine et de l''eau pour obturer les bords du couvercle (méthode traditionnelle), ou bien envelopper le bord de la casserole avec du papier aluminium avant de mettre le couvercle.","Chauffer d''abord à feu vif pendant 3 minutes, jusqu''à ce que de la vapeur commence à s''échapper.","Puis réduire à feu très doux et laisser cuire à l''étouffée pendant 25-30 minutes.","Éteindre le feu, ne pas ouvrir le couvercle, laisser reposer encore 5 minutes.","Ouvrir le couvercle, mélanger délicatement de bas en haut avec une grande spatule pour bien incorporer les couches.","Servir dans une assiette, accompagner de yaourt (raita)."]'::jsonb, '["Plat principal","Savoureux","Biryani","Indien","Riche","Pour recevoir"]'::jsonb),
  ('howtocook:staple/可乐炒饭', 'fr', 'Riz sauté au cola', 'Féculents', 'Ce plat utilise du cola à la place du sucre pour apporter une saveur caramélisée et légèrement sucrée. La sauce riche enrobe chaque grain de riz, c''est un riz sauté créatif et fait maison. Les œufs et les bâtonnets de jambon fournissent des protéines et de l''énergie de qualité, avec le riz comme base, le repas est équilibré et rassasiant. Les étapes sont simples, idéales pour les débutants, et le plat est prêt en environ 20 minutes.', '[{"name":"Riz cuit","unit":"g"},{"name":"Cola","unit":"ml"},{"name":"Œufs","unit":"pièce"},{"name":"Bâtonnets de jambon","unit":"g"},{"name":"Jambon en conserve","note":"quantité au choix (optionnel)"},{"name":"Huile","unit":"ml"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Pâte de haricots fermentés","unit":"ml"},{"name":"Sauce d''huîtres","unit":"ml"},{"name":"Ciboule ciselée","unit":"g"},{"name":"Poivre moulu","unit":"g"}]'::jsonb, '["Faites chauffer la poêle, puis ajoutez 25 ml d''huile. Cassez 2 œufs et faites-les frire jusqu''à ce que le dessous soit bien pris.","Retournez les œufs et faites-les frire jusqu''à ce qu''ils soient bien cuits des deux côtés.","Éteignez le feu, retirez les œufs, coupez-les en morceaux de 2 à 5 cm² et remettez-les dans la poêle (vous pouvez aussi les écraser directement avec la spatule).","Rallumez le feu, versez le cola, la sauce soja claire, la sauce soja foncée, la pâte de haricots fermentés et la sauce d''huîtres. Mélangez bien.","Chauffez jusqu''à ce que le liquide réduise au 1/3, puis ajoutez le riz et les bâtonnets de jambon. Faites revenir.","Une fois bien mélangé, réduisez à feu doux. Creusez un puits au centre du riz, cassez 1 œuf dedans, couvrez et laissez mijoter 2 minutes.","Retirez le couvercle, faites revenir jusqu''à ce que le troisième œuf soit cuit, saupoudrez de ciboule ciselée et de poivre moulu, puis servez."]'::jsonb, '["Plat principal","Caramélisé et légèrement sucré","Riz sauté","Rapide","Créatif","Fait maison"]'::jsonb),
  ('howtocook:staple/咸肉菜饭', 'fr', 'Riz au lard salé et légumes verts', 'Féculents', 'C''est un plat principal familial typique des ruelles de Shanghai. La saveur riche du lard salé et la douceur des légumes verts se fondent dans chaque grain de riz grâce au saindoux. Il y a à la fois du croustillant et la tendreté des tiges, pour une texture en couches. Les légumes verts sont riches en vitamines et fibres, le lard salé apporte des protéines et de l''énergie, un équilibre entre viande et légumes. La recette n''est pas compliquée, mais il faut maîtriser l''astuce d''ajouter les feuilles en plusieurs fois, ce qui est un peu difficile pour les débutants. De la préparation à la cuisson, cela prend environ 1 heure.', '[{"name":"Riz","unit":"g"},{"name":"Légumes verts","unit":"g"},{"name":"Lard salé","unit":"g"},{"name":"Pousses de bambou d''hiver","unit":"g"},{"name":"Saindoux","unit":"g"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Sucre blanc","unit":"g"},{"name":"Poivre blanc","unit":"g"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Si vous ajoutez des pousses de bambou d''hiver, coupez-les en fines tranches et faites-les cuire dans l''eau froide pendant 10 minutes pour enlever l''âpreté.","Coupez le lard salé en petits dés de 1 cm.","Dans une poêle froide, mettez le lard salé et les pousses de bambou avec 10 g de saindoux, du vin de cuisine et du sucre. Faites revenir à feu moyen-doux jusqu''à ce qu''ils soient transparents et bouillonnants.","Hachez les légumes verts. Séparez les tiges et les feuilles. Coupez les tiges en petits carrés de 0,5 cm de côté. Coupez les feuilles en rectangles de 2-3 cm de long sur 1-1,5 cm de large.","Faites sauter les tiges dans la poêle jusqu''à ce qu''elles deviennent vert émeraude.","Rincez le riz et mettez-le dans le cuiseur à riz. Ajoutez de l''eau.","Disposez le lard salé et les tiges sautés sur le riz.","Lancez le mode normal de cuisson du riz. Dans les 10 dernières minutes, ouvrez le couvercle et ajoutez rapidement les feuilles.","Après la cuisson, laissez reposer 5 minutes. Versez ensuite 5 g de saindoux et du poivre blanc, et mélangez vigoureusement."]'::jsonb, '["Plat principal","Saveur de Shanghai","Familial","Salé et umami","Riz mijoté"]'::jsonb),
  ('howtocook:staple/基础牛奶面包/基础牛奶面包', 'fr', 'Pain au lait de base', 'Féculents', 'Ce pain au lait de base simplifie la fabrication traditionnelle du pain par une pré-fermentation avec un levain. Le résultat est un pain riche en lait, moelleux. Riche en glucides et protéines, il fournit de l''énergie. De difficulté moyenne, idéal pour les débutants en pâtisserie, le processus prend environ 200 minutes.', '[{"name":"Farine de blé forte ou moyenne (pour le levain)","unit":"tasse"},{"name":"Eau tiède (environ 30°C)","unit":"tasse"},{"name":"Levure sèche","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Farine de blé forte ou moyenne (pour la pâte)","unit":"tasse"},{"name":"Œuf","unit":"pièce"},{"name":"Sucre ou sirop","unit":"tasse"},{"name":"Lait ou crème liquide ou lait concentré ou lait en poudre","unit":"tasse"},{"name":"Beurre ou huile de maïs","unit":"tasse"},{"name":"Gluten de blé (facultatif)","unit":"tasse"},{"name":"Extrait de vanille (facultatif)","unit":"g"},{"name":"Torchon","note":"Quantité suffisante"}]'::jsonb, '["Tout d''abord, mélangez la levure et l''eau tiède à 30°C à l''aide d''une spatule ou d''un ustensile de cuisine. Laissez reposer 5 minutes. Ensuite, mélangez avec la farine, remuez bien. Le levain doit être une pâte particulièrement collante.","Couvrez la pâte avec un torchon et placez-la dans un endroit chaud pour fermenter pendant 45 à 60 minutes.","La pâte finale doit avoir de nombreuses bulles à sa surface et avoir augmenté de volume de manière significative."]'::jsonb, '["Plat principal","Lait parfumé","Moelleux","Pâtisserie","Fermentation","Idéal pour débutants"]'::jsonb),
  ('howtocook:staple/微波炉腊肠煲仔饭/微波炉腊肠煲仔饭', 'fr', 'Riz cantonnais au micro-ondes avec saucisse chinoise', 'Féculents', 'C''est un plat principal simple et rapide de style cantonnais. Le riz absorbe la graisse de la saucisse, devenant savoureux et parfumé, accompagné de légumes verts croquants et de carottes, offrant une texture riche. Riche en glucides, protéines et diverses vitamines, il est équilibré. La cuisson au micro-ondes est très conviviale pour les débutants, et le plat est prêt en seulement 15 minutes.', '[{"name":"Riz","unit":"ml"},{"name":"Saucisse chinoise","unit":"pièce"},{"name":"Œuf","unit":"pièce"},{"name":"Carotte","unit":"pièce"},{"name":"Sel","unit":"g"},{"name":"Huile","unit":"ml"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Ciboule","unit":"pièce"},{"name":"Légumes verts","note":"quantité suffisante"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Lavez le riz puis versez-le dans un bol, ajoutez 400 ml d''eau, couvrez.","Mettez au micro-ondes, puissance maximale, 6 minutes. Pendant la cuisson du riz, préparez les ingrédients.","Coupez la saucisse chinoise en tranches.","Lavez les légumes verts.","Coupez la carotte en rondelles.","Ciselez la ciboule.","Dans un bol pour légumes, mettez les légumes verts et les rondelles de carotte, ajoutez 10 ml d''huile et 5 g de sel.","Dans un petit bol, versez 10 ml de sauce soja claire et 5 ml d''huile.","Après 6 minutes, sortez le bol avec un torchon ou un gant de cuisine. Le riz est cuit à 80%.","Disposez les tranches de saucisse sur le riz, puis remettez au micro-ondes à puissance maximale pendant 2 minutes.","Sortez le riz avec la saucisse, placez le bol de légumes au micro-ondes, puissance maximale pendant 4 à 5 minutes.","Disposez les légumes cuits sur le riz, cassez l''œuf par-dessus, puis selon votre goût, remettez au micro-ondes à puissance maximale pendant 40 à 60 secondes.","Sortez le riz, il est presque prêt.","Placez le petit bol au micro-ondes, puissance maximale pendant 30 secondes.","Arrosez le riz avec la sauce soja claire chaude, saupoudrez de ciboule ciselée, puis servez.","Les légumes verts restants peuvent être trempés dans la sauce soja."]'::jsonb, '["Plat principal","Cantonnais","Micro-ondes","Rapide","Salé et parfumé","Familial"]'::jsonb),
  ('howtocook:staple/意式肉酱面/意式肉酱面', 'fr', 'Pâtes à la bolognaise', 'Féculents', 'Les pâtes à la bolognaise sont un plat occidental simple et rapide, avec une sauce riche et des pâtes al dente, parfait pour les jours chargés. La viande hachée et l''oignon, associés à une sauce pour pâtes prête à l''emploi, apportent rapidement des protéines et des glucides, et l''oignon contient des fibres alimentaires. La recette est très accessible aux débutants : il suffit de couper et de faire revenir, et après un peu de pratique, on peut le préparer en 15 minutes, plus satisfaisant que des nouilles instantanées.', '[{"name":"Pâtes","unit":"g"},{"name":"Sauce pour pâtes","unit":"g"},{"name":"Viande hachée","unit":"g"},{"name":"Oignon blanc","unit":"g"},{"name":"Huile de cuisson","unit":"ml"}]'::jsonb, '["Dans une casserole, portez de l''eau à ébullition et ajoutez les pâtes (attendez 6 à 12 minutes)","Pendant que l''eau chauffe, vous pouvez effectuer les étapes suivantes, mais surveillez le temps de cuisson des pâtes","Coupez l''oignon en petits dés","Dans une poêle vide, versez de l''huile et ajoutez les dés d''oignon à feu moyen","Remuez constamment en veillant à ne pas brûler l''oignon, jusqu''à ce qu''il devienne translucide","Ajoutez la viande hachée, continuez à remuer (en émiettant) jusqu''à ce qu''elle soit brunie","Ajoutez la sauce pour pâtes et mélangez brièvement","Égouttez les pâtes cuites et versez-les dans la sauce à la viande, mélangez bien (ou versez directement la sauce sur les pâtes)"]'::jsonb, '["Plat principal","Rapide","Maison","Savoureux","Occidental"]'::jsonb),
  ('howtocook:staple/手工水饺', 'fr', 'Raviolis chinois faits maison', 'Féculents', 'Les raviolis chinois faits maison sont un plat de base classique chinois, avec une peau fine et une farce généreuse, savoureux et juteux, rassasiants et pouvant être assaisonnés selon les goûts personnels. La farce de porc fournit des protéines de haute qualité et des matières grasses, accompagnée de ciboule de Chine pour des vitamines et des fibres alimentaires. Cette recette est assez difficile pour les débutants, nécessitant de maîtriser le pétrissage, l''étalage, la préparation de la farce et la cuisson des raviolis, avec un temps de préparation d''environ 3 heures.', '[{"name":"farine","unit":"g"},{"name":"eau froide","unit":"ml"},{"name":"huile de sésame","unit":"ml"},{"name":"viande maigre hachée","unit":"g"},{"name":"viande grasse hachée","unit":"g"},{"name":"gingembre","unit":"g"},{"name":"oignon vert","unit":"g"},{"name":"sel","unit":"g"},{"name":"sauce d''huîtres","unit":"ml"},{"name":"huile de sésame","unit":"ml"},{"name":"sauce soja claire","unit":"ml"},{"name":"œuf","unit":"unité"},{"name":"ciboule de Chine","note":"quantité suffisante"}]'::jsonb, '["Dans un bol, ajouter toute la farine.","Ajouter l''huile de sésame.","Creuser un puits au centre de la farine.","Ajouter l''eau en 4 à 5 fois en mélangeant, jusqu''à obtenir une pâte légèrement sèche et grumeleuse.","Cesser d''ajouter de l''eau et presser la pâte à la main.","Presser la pâte jusqu''à ce qu''elle intègre toute la farine du bol, la pâte et le bol doivent être propres.","Poser la pâte sur le plan de travail, couvrir avec le bol retourné, à température ambiante de 25°C, laisser reposer environ 45 minutes.","Après repos, rouler la pâte en un boudin, la rassembler, la rouler à nouveau, répéter 3 fois.","Rouler en un long boudin, couper en 20 portions de taille égale, rouler chaque portion en boule d''environ 3-3,5 cm de diamètre.","Aplatir chaque boule, saupoudrer de farine sur les mains, le plan de travail, le rouleau à pâtisserie et la pâte pour éviter qu''elle colle.","Étaler chaque boule au rouleau en un disque d''environ 8 cm de diamètre et 2 mm d''épaisseur, le centre légèrement plus épais que les bords d''environ 1 mm.","Enlever la peau du porc, garder un peu de gras, couper en petits morceaux.","Hacher la viande de porc en hachis à l''aide d''un couteau de cuisine (de préférence deux), mettre dans un bol.","Hacher finement l''oignon vert et le gingembre, ajouter au bol de viande et mélanger.","Laver la ciboule de Chine, couper en morceaux de moins de 3 mm.","Mélanger la ciboule avec le hachis, ajouter 2 ml de sauce d''huîtres, 2 ml de sauce soja claire, 2 ml d''huile de sésame, et le blanc d''un œuf. Mélanger à la main.","Laisser reposer 30 minutes, puis commencer à monter les raviolis.","Placer une peau de ravioli sur la main gauche, éviter que le côté farci touche la farine pour permettre la fermeture.","Avec des baguettes dans la main droite, prendre une quantité de farce d''environ la moitié du diamètre de la peau.","Fermer le long du bord, pincer fermement. Pour une consommation personnelle, il n''est pas nécessaire de faire des plis, il suffit que la peau ne fuie pas.","Utiliser une marmite pouvant contenir 20 raviolis, ou cuire par lots.","Porter de l''eau à ébullition, remplir la marmite aux 3/4.","À ébullition à feu vif, ajouter les raviolis et réduire à feu moyen.","Quand l''eau bout après la première addition, verser 50 ml d''eau froide le long de la paroi (répéter cette étape deux fois).","Après la troisième ébullition, ajouter 50 ml d''eau froide, puis à la reprise de l''ébullition, réduire à feu doux et attendre 60 secondes avant de retirer."]'::jsonb, '["Plat principal","Familial","Savoureux","Pâtes","Artisanal","Pour invités"]'::jsonb),
  ('howtocook:staple/扬州炒饭/扬州炒饭', 'fr', 'Riz sauté de Yangzhou', 'Féculents', 'Il s''agit d''un riz sauté amélioré aux garnitures abondantes. Les grains de riz sont bien séparés, les œufs sont tendres, accompagnés de crevettes, de jambon en conserve et de dés de légumes. Les couches de saveurs sont distinctes. C''est un plat classique de la cuisine Huaiyang. Riche en protéines de haute qualité, glucides et vitamines variées, il offre un équilibre nutritionnel. Bien que les étapes soient nombreuses, les opérations sont intuitives et conviennent aux cuisiniers débutants à condition de préparer les ingrédients patiemment. Temps de préparation estimé : environ 1 heure.', '[{"name":"Riz froid","unit":"g"},{"name":"Œufs","unit":"pièce"},{"name":"Crevettes décortiquées surgelées","unit":"pièce"},{"name":"Jambon en conserve","unit":"g"},{"name":"Petits pois","unit":"g"},{"name":"Carotte","unit":"g"},{"name":"Maïs en grains","unit":"g"},{"name":"Oignon vert","unit":"tige"},{"name":"Huile","unit":"ml"},{"name":"Sel","unit":"g"}]'::jsonb, '["Couper la carotte en dés de 0.2 cm de côté, réserver.","Couper le jambon en conserve en dés de 0.2 cm de côté, réserver.","Séparer le blanc et le vert de l''oignon vert, les couper en petits morceaux de 0.25-0.5 cm, réserver séparément.","Casser les œufs dans un bol, battre uniformément, réserver.","Faire bouillir la carotte, les petits pois et le maïs, les égoutter, réserver (ne pas jeter l''eau).","Faire cuire les crevettes, les égoutter, réserver (l''eau peut être jetée).","Chauffer la poêle et l''huile ; on peut se référer à la technique de la double huile chaude dans ''sauté et poêlé''.","Ajouter 20-30 ml d''huile pour la deuxième fois. Quand cette huile est chaude, verser lentement les œufs (contrôler le diamètre du filet d''œuf à environ 0.5 cm). Ne pas remuer.","Dès que les œufs sont pris, les retirer immédiatement, réserver.","Dans la poêle, faire revenir le jambon, les petits pois, la carotte, le maïs et les crevettes pendant 1-2 minutes, les mettre dans un plat, réserver.","Rincer la poêle à l''eau pour enlever les résidus, en veillant à ce qu''elle soit propre (de l''huile peut rester, mais pas d''impuretés).","Chauffer la poêle et l''huile (10 ml), faire revenir le blanc d''oignon vert pour le parfumer.","Passer à feu doux (si l''huile est trop chaude, éteindre le feu 1-2 minutes). Ajouter le riz, concasser rapidement avec une spatule et remuer pour que le riz soit uniformément enrobé d''huile et que les grains soient bien séparés.","Ajouter les œufs, concasser à nouveau pour briser les œufs et les mélanger complètement au riz.","Passer à feu vif. Ajouter tous les autres ingrédients réservés, faire sauter rapidement 1-2 minutes.","Saupoudrer de sel, remuer pour bien mélanger.","Saupoudrer de vert d''oignon vert, faire sauter 1 minute.","Éteindre le feu, servir."]'::jsonb, '["Plat principal","Savoureux","Riz sauté","Maison","Huaiyang","Rapide"]'::jsonb),
  ('howtocook:staple/披萨饼皮/披萨饼皮', 'fr', 'Pâte à pizza', 'Féculents', 'La pâte à pizza est fermentée à froid toute une nuit, la base obtenue est moelleuse et légèrement élastique, c''est une pâtisserie occidentale maison. Elle apporte principalement des glucides et un peu de bonnes graisses. La préparation est simple, mais il faut être patient pour la fermentation, ce qui est accessible aux débutants. Du début à la cuisson, en comptant le repos au frigo, il faut environ 10 à 14 heures, idéal à préparer la veille.', '[{"name":"Farine tout usage","unit":"grammes"},{"name":"Eau tiède","unit":"grammes"},{"name":"Levure sèche","unit":"grammes"},{"name":"Sel de table","unit":"grammes"},{"name":"Huile d''olive","unit":"grammes"},{"name":"Sucre blanc","unit":"grammes"}]'::jsonb, '["Dissoudre la levure dans l''eau tiède préparée, remuer légèrement, réserver.","Prendre la farine préparée, ajouter successivement le sel, l''huile d''olive, le sucre.","Mélanger l''eau et la farine, ajouter l''eau petit à petit en remuant jusqu''à épuisement.","Remuer jusqu''à ce qu''il n''y ait plus de farine sèche.","Mettre dans un récipient environ trois fois plus grand que la pâte, fermer hermétiquement, réfrigérer à 4°C pendant 8 à 12 heures. En général, préparer le soir, elle est prête le lendemain.","Vérifier que la pâte a levé : elle doit avoir doublé de volume.","Prendre la pâte levée, la diviser en quatre parts égales, couvrir chacune de film alimentaire, réserver.","Saupoudrer un peu plus de farine sur le plan de travail, commencer à pétrir.","Comme la pâte est assez humide, la farine l''empêche de coller. Ne pas trop pétrir, juste jusqu''à ce que la surface soit légèrement lisse.","Étirer à la main ou au rouleau, pas besoin que ce soit parfaitement rond, pourvu que l''épaisseur soit uniforme et que ça tienne dans le four.","Poser du papier sulfurisé, déposer la pâte, ajouter les ingrédients préparés selon votre goût, saupoudrer de fromage râpé.","Pour une pizza aux fruits : four à 180°C en haut, 220°C en bas, 16 minutes.","Pour une pizza viande-légumes : four à 200°C en haut, 230°C en bas, 18 minutes.","Ajouter de la sauce salade ou une autre sauce de votre choix, déguster !"]'::jsonb, '["Plat principal","Occidental","Au four","Fermentation longue","Maison","Débutants"]'::jsonb),
  ('howtocook:staple/日式咖喱饭/日式咖喱饭', 'fr', 'Riz au curry japonais', 'Féculents', 'Le riz au curry japonais est un plat familial riche et onctueux, assaisonné avec des cubes de curry, accompagné de pommes de terre, carottes, oignons et viande. Sa texture est lisse et fondante, avec une saveur épicée et légèrement sucrée. Il est riche en protéines, glucides et vitamines, offrant une bonne source d''énergie. La préparation n''est pas très compliquée mais nécessite de maîtriser le feu et les techniques de mélange ; elle convient aux cuisiniers ayant un peu d''expérience. De la préparation à la cuisson, il faut environ 1 heure ; le goût est meilleur après réfrigération.', '[{"name":"Cubes de curry (recommandé : House Foods)","unit":"g"},{"name":"Pommes de terre","unit":"pièce(s)"},{"name":"Carottes","unit":"pièce(s)"},{"name":"Oignon","unit":"pièce(s)"},{"name":"Viande (porc/poulet/bœuf au choix)","unit":"livre"},{"name":"Ail","unit":"gousse(s)"},{"name":"Brocoli (cuit à l''eau)","note":"quantité suffisante"},{"name":"Bacon (prêt à consommer)","note":"quantité suffisante"},{"name":"Œuf au plat / œuf miroir","note":"quantité suffisante"}]'::jsonb, '["Couper les extrémités des carottes, les éplucher, les couper en morceaux en les tournant (coupe roulée)","Peler l''oignon, retirer le cœur, couper en quartiers en forme de croissant","Éplucher les pommes de terre, les couper en gros morceaux","Couper la viande en morceaux","Peler l''ail, écraser et hacher finement","Couper les cubes de curry en petits morceaux pour augmenter la surface et accélérer la dissolution","Faire chauffer l''huile, ajouter l''ail et la viande, faire revenir rapidement jusqu''à ce que la viande blanchisse","Ajouter les carottes, faire revenir rapidement pour qu''elles soient uniformément chauffées","Ajouter l''oignon, faire revenir rapidement jusqu''à ce qu''il devienne translucide","Ajouter les pommes de terre, continuer à remuer jusqu''à ce qu''elles ramollissent (vérifier avec une baguette)","Ajouter de l''eau pour couvrir tous les ingrédients, porter à ébullition et laisser cuire 15 minutes","Éteindre le feu, ajouter le curry et mélanger","Attendre que le curry fonde, puis rallumer le feu et remuer doucement pendant 10 minutes pour éviter que ça attache","Éteindre le feu lorsque la préparation a une consistance épaisse et collante","Micro-ondes : pour une portion individuelle, chauffer à puissance maximale 2-3 minutes","Casserole : ajouter 50 ml d''eau supplémentaire, chauffer en remuant constamment"]'::jsonb, '["Plat principal","Japonais","Riche","Fait maison","Accompagnement de riz","Mijoté"]'::jsonb),
  ('howtocook:staple/日式肥牛丼饭/日式肥牛丼饭', 'fr', 'Donburi de bœuf à la japonaise', 'Féculents', 'Un classique donburi japonais fait maison, des tranches de bœuf et des oignons blancs mijotés dans une sauce salée-sucrée, viande tendre, oignons doux, sauce savoureuse. Le bœuf fournit des protéines de qualité et du fer hémique, les oignons sont riches en fibres et en antioxydants. La préparation n''est pas compliquée, même un débutant peut la réaliser facilement en suivant les étapes, le processus de cuisson prend environ 30 minutes.', '[{"name":"oignon","unit":"pièce"},{"name":"tranches de bœuf","unit":"g"},{"name":"ciboule","unit":"tige"},{"name":"graines de sésame blanc","unit":"g"},{"name":"mirin","unit":"g"},{"name":"vin de riz","unit":"g"},{"name":"œuf onsen","note":"quantité suffisante"},{"name":"dashi","note":"quantité suffisante"},{"name":"riz","unit":"tasse"},{"name":"sauce soja","unit":"g"},{"name":"sauce d''huître","unit":"g"},{"name":"sucre","unit":"g"},{"name":"sauce soja foncée","unit":"g"},{"name":"eau","unit":"g"}]'::jsonb, '["Peler l''oignon, retirer le cœur, couper en demi-lunes.","Laver et couper la ciboule en petits tronçons de 0,5 cm.","Dans une poêle chaude, mettre les graines de sésame blanc, agiter la poêle d''avant en arrière pour les faire griller uniformément jusqu''à ce qu''elles soient légèrement dorées.","Blanchir les tranches de bœuf dans l''eau bouillante pendant 1 minute, puis égoutter.","Mélanger dans un bol : 40 g de mirin (ou 30 g de vin de riz), 30 g de sauce soja, 20 g de sauce d''huître, 5 g de sucre, 5 g de sauce soja foncée (facultatif, pour la couleur). Remuer pour obtenir la sauce. (Cette étape peut être faite en posant le bol sur une balance.)","Faire chauffer un peu d''huile dans une poêle, ajouter l''oignon, faire sauter rapidement jusqu''à ce qu''il devienne translucide.","Baisser le feu, ajouter 250 g d''eau (ou de dashi), remettre à feu vif et chauffer pendant 3 minutes.","Ajouter le bœuf et la sauce.","Remuer constamment tous les ingrédients pendant 10 minutes pour éviter que cela n''attache.","Éteindre le feu.","Servir le bœuf et les oignons sur le riz (veiller à verser un peu de sauce sur le riz).","Saupoudrer de ciboule hachée et de graines de sésame. C''est prêt.","Micro-ondes : pour une portion, chauffer à puissance maximale 2-3 minutes.","Casserole : ajouter 50 ml d''eau supplémentaire, chauffer en remuant constamment."]'::jsonb, '["Plat principal","Japonais","Salé-sucré","Mijoté","Accompagnement riz","Fait maison"]'::jsonb),
  ('howtocook:staple/汤面', 'fr', 'Nouilles en bouillon', 'Féculents', 'Les nouilles en bouillon sont un plat principal maison que l''on peut personnaliser librement. Le bouillon est clair, les nouilles sont douces et glissantes, et elles s''accordent avec toutes sortes d''ingrédients, viandes ou légumes, pour un goût qui peut être à la fois savoureux ou léger. Riches en glucides et en protéines de qualité, accompagnées de légumes, elles apportent également des vitamines et des fibres alimentaires, offrant un repas équilibré et rassasiant. La préparation est très simple, aucune compétence culinaire n''est requise, même les débutants peuvent s''en sortir facilement. De la préparation des ingrédients à la sortie du feu, il faut compter environ 30 minutes.', '[{"name":"Nouilles","unit":"g"},{"name":"Eau froide","unit":"ml"},{"name":"Légumes","note":"Volume approximativement égal à celui des nouilles"},{"name":"Sel","note":"Quantité appropriée"},{"name":"Poivre","note":"Quantité appropriée"},{"name":"Huile de sésame","note":"Quantité appropriée"}]'::jsonb, '["Coupez d''abord les ingrédients végétaux en morceaux d''au plus 4 cm de côté pour faciliter la cuisson.","S''il y a de la viande crue, placez-la d''abord dans de l''eau froide, couvrez, portez à ébullition, écumez la mousse de sang, puis éteignez le feu et sortez la viande à moitié cuite pour réserve.","Portez d''abord l''eau à ébullition à feu vif, puis réduisez à feu moyen.","Mettez dans la casserole les ingrédients qui mettent plus de temps à cuire (comme les viandes à moitié cuites, les champignons, etc., en premier). Pour assurer une cuisson complète, chronométrez 10 minutes après ébullition, et ajoutez 5 minutes pour les gros morceaux particulièrement difficiles.","Mettez les nouilles dans la casserole, remuez légèrement pour assurer un bon contact entre les nouilles et le bouillon, maintenez une légère ébullition et laissez cuire 5 minutes. Après l''ajout des nouilles, de la mousse blanche peut se former ; vous pouvez soulever le couvercle pour aérer ou l''enlever.","Mettez les ingrédients qui cuisent rapidement, comme les légumes verts, dans la casserole, remuez légèrement pour les immerger complètement, et laissez cuire 2 à 5 minutes.","Éteignez le feu, puis ajoutez du sel, du poivre, de l''huile de sésame ou d''autres assaisonnements de votre choix, remuez légèrement et servez."]'::jsonb, '["Plat principal","Léger","Maison","Rapide","Personnalisable","Équilibré"]'::jsonb),
  ('howtocook:staple/河南蒸面条/河南蒸面条', 'fr', 'Nouilles à la vapeur du Henan', 'Féculents', 'Les nouilles à la vapeur du Henan sont un plat familial originaire du Henan. Les nouilles sont d''abord cuites à la vapeur, puis sautées, puis à nouveau cuites à la vapeur, ce qui les rend huileuses, savoureuses et fermes. La poitrine de porc et les tiges d''ail fournissent des protéines et des fibres, avec les nouilles comme base équilibrée. Les étapes sont un peu nombreuses, mais pour un débutant, il suffit de suivre l''ordre pour réussir. De la préparation à la sortie du plat, il faut environ 40 minutes.', '[{"name":"Nouilles (de préférence rondes)","unit":"grammes"},{"name":"Poitrine de porc","unit":"grammes"},{"name":"Tiges d''ail","unit":"grammes"},{"name":"Oignon","unit":"grammes"},{"name":"Gingembre","unit":"grammes"},{"name":"Ail","unit":"grammes"},{"name":"Vin de cuisson","unit":"ml"},{"name":"Sel","unit":"grammes"},{"name":"Bouillon de poulet","unit":"grammes"},{"name":"Treize parfums","unit":"grammes"},{"name":"Sauce claire","unit":"ml"},{"name":"Sauce vieille","unit":"ml"},{"name":"Sauce d''huître","unit":"ml"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Huile de sésame","unit":"ml"},{"name":"Panier vapeur","note":"à volonté"}]'::jsonb, '["Dans une casserole, ajouter de l''eau aux 7/10, porter à ébullition, placer le panier vapeur.","Étaler uniformément les nouilles, verser 5 ml d''huile et bien les enrober, cuire à la vapeur 15 minutes.","Retirer les nouilles et le panier vapeur, les mettre de côté, vider l''eau de la casserole.","Couper la poitrine de porc en tranches de 2 mm d''épaisseur.","Couper les tiges d''ail en tronçons de 3 cm.","Couper l''oignon en fines tranches de 0,2 cm.","Couper le gingembre en fines lanières de 1 mm x 1 mm x 3 cm.","Écraser l''ail sur la planche, le hacher en morceaux de 1 mm.","Chauffer la casserole, sécher l''eau, ajouter 3 ml d''huile de cuisson.","Tenir le manche, faire tourner la casserole pour que l''huile tapisse les 2/3 de la surface.","À feu moyen, ajouter les tranches de porc, faire sauter 1 minute.","Ajouter l''oignon, le gingembre, l''ail et le vin de cuisson, continuer à sauter 1 minute.","Ajouter les tronçons de tiges d''ail, faire sauter 1 minute.","Assaisonner avec la sauce vieille, la sauce claire, la sauce d''huître, le sel, le bouillon de poulet, le mélange treize parfums, faire sauter 1 minute.","Ajouter 500 ml d''eau, couvrir les légumes, mijoter 1 minute.","Ajouter les nouilles cuites à la vapeur, mélanger sans arrêt 3 minutes jusqu''à ce qu''elles soient uniformément colorées, éteindre le feu.","Verser les nouilles mélangées et les légumes dans un saladier.","Dans la casserole, ajouter de l''eau froide aux 7/10, placer le panier vapeur, étaler uniformément les nouilles et les légumes mélangés.","À ébullition, cuire à feu vif 15 minutes, sortir du panier.","Arroser de 10 g d''huile de sésame, servir immédiatement."]'::jsonb, '["Plat principal","Saveur du Henan","Familial","Savoureux","Vapeur et sauté","Accompagnement du riz"]'::jsonb),
  ('howtocook:staple/火腿饭团/火腿饭团', 'fr', 'Boulettes de riz au jambon', 'Féculents', 'Une recette de boulettes de riz style japonais simple et rapide, jambon salé accompagné de mayonnaise et d''algues, riche en saveurs et rassasiant. Riche en glucides, protéines et vitamines, elle permet de recharger rapidement les énergies. Très facile à réaliser, même les débutants peuvent s''en sortir, il faut environ 1 heure de la cuisson du riz à la finition.', '[{"name":"Jambon","unit":"g"},{"name":"Riz","unit":"g"},{"name":"Eau","unit":"ml"},{"name":"Petits pois surgelés","unit":"g"},{"name":"Maïs surgelé","unit":"g"},{"name":"Algues émiettées","unit":"g"},{"name":"Mayonnaise","unit":"g"},{"name":"Huile de cuisson","unit":"ml"}]'::jsonb, '["Mettre le riz et l''eau dans le cuiseur à riz, sélectionner le mode riz, attendre la fin.","Mettre les grains de maïs surgelés et les petits pois surgelés dans une casserole, couvrir d''eau, porter à ébullition, laisser reposer 2 minutes, puis égoutter.","Couper le jambon en dés de 1 cm.","Pendant ce temps, ajouter 10 ml d''huile de cuisson, faire revenir le jambon jusqu''à ce qu''il soit coloré.","Mettre le riz, le jambon, les algues émiettées, les petits pois, le maïs et la mayonnaise dans un bol, mélanger uniformément.","Dresser (si désiré)."]'::jsonb, '["Plat principal","Japonais","Rapide","Fait maison","Salé","Boulettes de riz"]'::jsonb),
  ('howtocook:staple/炒凉粉/炒凉粉', 'fr', 'Liangfen sauté', 'Féculents', 'Le Liangfen sauté est une spécialité des régions du Shanxi et du Shaanxi. Il est doux et tendre, salé et légèrement épicé, avec des arômes d''ail et de sauce. Le liangfen est principalement composé d''amidon, fournissant des glucides riches pour un apport énergétique rapide. La difficulté de cuisson est modérée, adaptée aux débutants ayant quelques bases. La préparation complète prend environ 15 minutes.', '[{"name":"Liangfen","unit":"g"},{"name":"Huile de maïs","unit":"ml"},{"name":"Ail","unit":"g"},{"name":"Oignon vert","unit":"g"},{"name":"Pâte de fèves fermentées (doubanjiang)","unit":"g"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Mélange d''épices (shisanxiang)","unit":"g"},{"name":"Piment en poudre moyenne","unit":"g"},{"name":"Eau minérale","unit":"ml"}]'::jsonb, '["Couper le liangfen en dés de la taille d''un dé de mahjong.","À feu doux, chauffer l''huile dans la poêle. Quand la poêle est légèrement chaude, ajouter l''ail haché et le faire revenir jusqu''à ce qu''il soit parfumé, puis ajouter la pâte de fèves fermentées (doubanjiang) et faire revenir jusqu''à ce que l''huile devienne rouge.","Ajouter les cubes de liangfen dans la poêle et faire sauter pendant 10 secondes.","Ajouter la sauce soja claire pour l''assaisonnement et la sauce soja foncée pour la couleur. Mélanger uniformément, puis ajouter le piment en poudre et continuer à mélanger.","Ajouter le sel et le mélange d''épices (shisanxiang) et faire sauter pendant 10 secondes supplémentaires.","Ajouter l''eau minérale préparée, faire sauter à nouveau pendant 10 secondes, jusqu''à ce que la sauce épaississe, puis éteindre le feu, verser dans une assiette.","Parsemer d''oignons verts ciselés et servir."]'::jsonb, '["Plat principal","Salé et légèrement épicé","Sauté","Saveur du Shanxi et du Shaanxi","Snack maison","Rapide"]'::jsonb),
  ('howtocook:staple/炒年糕', 'fr', 'Gâteaux de riz sautés', 'Féculents', 'C''est un plat principal typique du Fujian du Sud. Les gâteaux de riz sont moelleux et élastiques, avec le parfum caramélisé de l''huile d''oignon vert, à la fois simple et copieux. Les gâteaux de riz à base de farine de riz fournissent des glucides, auxquels s''ajoutent des œufs et des légumes verts pour apporter protéines et vitamines, équilibrant ainsi la nutrition. La recette est simple, même pour les débutants, et prend environ 30 minutes de la préparation à la cuisson.', '[{"name":"Gâteaux de riz / Baiguo","unit":"g"},{"name":"Oignons verts","unit":"tiges"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sauce soja","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Œufs","note":"selon le goût"},{"name":"Légumes verts","note":"selon le goût"}]'::jsonb, '["Porter de l''eau à ébullition dans une casserole, cuire les gâteaux de riz. Dans un bol, ajouter de l''eau pour éviter qu''ils ne collent, puis égoutter et réserver.","Ciseler les oignons verts (séparer le blanc du vert). Couper les légumes verts en petits morceaux. Réserver.","(Optionnel) Préparer les œufs brouillés (voir ''Œufs brouillés aux tomates'').","Chauffer la poêle, ajouter 30 ml d''huile de cuisson.","Ajouter le blanc d''oignon vert dans la poêle jusqu''à ce qu''il devienne doré et parfumé. Verser l''huile d''oignon vert dans un bol et réserver.","Réchauffer la poêle, ajouter 20 ml d''huile de cuisson.","Ajouter tous les accompagnements (œufs, légumes verts, etc.) et faire sauter uniformément.","Jeter l''eau des gâteaux de riz, puis ajouter les gâteaux dans la poêle.","Ajouter la sauce soja et le sel, mélanger uniformément.","Éteindre le feu, ajouter l''huile d''oignon vert, mélanger et servir."]'::jsonb, '["Plat principal","Saveur du Minnan","Sauté","Maison","Rapide","Savoureux"]'::jsonb),
  ('howtocook:staple/炒意大利面/炒意大利面', 'fr', 'Spaghetti sautés', 'Féculents', 'Ces spaghetti sautés sont tendres et savoureux, accompagnés de bœuf mariné et de sauce, avec un riche arôme de sauce. C''est un plat principal familial de style occidental. Riche en glucides et protéines, il permet de reconstituer rapidement l''énergie. La recette est simple, même les débutants peuvent la maîtriser facilement. Le processus complet prend environ 30 minutes.', '[{"name":"Spaghetti","unit":"g"},{"name":"Tranches de bœuf mariné","unit":"tranche"},{"name":"Ketchup","unit":"g"},{"name":"Sauce au poivre noir","note":"Choisir l''un ou l''autre"},{"name":"Huile de colza","unit":"ml"},{"name":"Eau","unit":"g"},{"name":"Sel","unit":"g"}]'::jsonb, '["Ajouter 250 g d''eau par personne","Quand l''eau bout, ajouter les pâtes, cuire à feu moyen pendant 15 à 20 minutes (ces pâtes sont généralement assez dures, il est préférable de goûter avant de les retirer ; si le centre est encore un peu dur, continuer la cuisson).","Retirer les pâtes et les déposer dans une assiette pour les réserver.","Chauffer la poêle, verser l''huile de cuisson. Quand l''huile est à température moyenne, ajouter les pâtes et faire sauter pendant une minute (si c''est trop sec, ajouter un peu d''eau).","Ajouter 10 g de ketchup, le bœuf mariné, 2 g de sel, et continuer à faire sauter pendant une minute.","Retirer du feu."]'::jsonb, '["Plat principal","Arôme de sauce","Style occidental","Sauté","Rapide","Familial"]'::jsonb),
  ('howtocook:staple/炒方便面/炒方便面', 'fr', 'Nouilles instantanées sautées', 'Féculents', 'Ces nouilles instantanées sautées ont une texture moelleuse et élastique, salées et savoureuses. C''est un plat principal rapide et fait maison, une amélioration des nouilles bouillies traditionnelles. Accompagnées d''œufs et de saucisse, elles enrichissent les sources de protéines et d''énergie. La méthode est simple, il suffit de rincer les nouilles à l''eau froide pour conserver la texture. Même les débutants peuvent le faire facilement, et le tout prend environ 15 minutes.', '[{"name":"Nouilles instantanées","unit":"paquet"},{"name":"Œufs","unit":"pièce"},{"name":"Saucisse","unit":"pièce"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Retirez l''emballage de la saucisse et coupez-la en petits morceaux de 1 cm de large.","Ajoutez 1200 ml d''eau dans une casserole, en fait suffisamment pour couvrir les nouilles. Portez à ébullition complète, n''ajoutez pas les nouilles avant l''ébullition.","Ajoutez les nouilles instantanées et faites cuire 45 secondes. Pendant la cuisson, remuez pour séparer les nouilles.","Dès que les nouilles sont séparées, éteignez le feu. Ne les faites pas trop cuire !","Prélevez 80 ml d''eau de cuisson chaude et réservez.","Séparez les nouilles de l''eau. Rincez les nouilles à l''eau froide.","Égouttez les nouilles. Ne les laissez pas tremper dans l''eau trop longtemps.","Préparez un petit bol et versez le sachet d''assaisonnement des nouilles.","Ajoutez tout le sachet de légumes.","Ajoutez tout le sachet de sauce.","Ajoutez 50 % à 80 % du sachet de poudre. (Mettre tout le sachet rendra trop salé.)","Versez les 80 ml d''eau de cuisson chaude dans le bol et mélangez bien pour obtenir une sauce.","Prenez le nombre d''œufs calculé et cassez-les dans un petit bol. N''ajoutez pas de sel ! (Les œufs absorberont le sel des autres ingrédients dans la poêle.)","Chauffez la poêle 20 secondes, ajoutez 8 ml d''huile par portion.","Ajoutez le bol d''œufs préparé. Faites sauter environ 20 secondes jusqu''à ce que les œufs soient cuits.","Retirez l''œuf cuit et réservez. Il n''est pas nécessaire de laver la poêle. Il ne reste généralement pas beaucoup d''huile.","Réchauffez la poêle 20 secondes, ajoutez 10 ml d''huile par portion.","Ajoutez la saucisse préparée à l''étape 1. Faites sauter 10 secondes.","Ajoutez les nouilles de l''étape 2. Faites sauter 30 secondes.","Ajoutez la sauce de l''étape 3. Faites sauter 30 secondes.","Ajoutez l''œuf cuit de l''étape 4. Faites sauter 30 secondes.","Éteignez le feu et servez."]'::jsonb, '["Plat principal","Salé et savoureux","Rapide","Fait maison","Sauté"]'::jsonb),
  ('howtocook:staple/炒河粉', 'fr', 'Nouilles de riz sautées', 'Féculents', 'Les nouilles de riz sautées sont un plat classique populaire dans la région du Guangdong. On recherche un wok bien chaud, une texture sèche et parfumée, des nouilles souples et translucides, accompagnées de lanières de viande, de germes de soja et de concombres en julienne, offrant une riche variété de textures. Elles apportent principalement des glucides et des protéines, et l''ajout de légumes complète les vitamines et les fibres alimentaires. Cette recette est de difficulté modérée, même les débutants peuvent l''essayer avec tous les ingrédients préparés, et le processus complet prend environ 30 minutes pour être servi.', '[{"name":"Nouilles de riz","unit":"g","note":""},{"name":"Porc / Bœuf","unit":"","note":"quantité suffisante"},{"name":"Sel","unit":"g","note":""},{"name":"Glutamate monosodique","unit":"g","note":""},{"name":"Sauce soja foncée","unit":"ml","note":""},{"name":"Sauce soja claire","unit":"ml","note":""},{"name":"Cumin en poudre","unit":"g","note":""},{"name":"Assaisonnement pour nouilles de riz","unit":"g","note":""},{"name":"Poivre en poudre","unit":"","note":"quantité suffisante"},{"name":"Concombre","unit":"g","note":""},{"name":"Gluten","unit":"g","note":""},{"name":"Germes de soja","unit":"g","note":""},{"name":"Œufs","unit":"pièce","note":""},{"name":"Gousses d''ail","unit":"pièce","note":""},{"name":"Ciboule","unit":"pièce","note":""},{"name":"Fécule","unit":"","note":"quantité suffisante"},{"name":"Huile de cuisson","unit":"g","note":""}]'::jsonb, '["Hacher finement la ciboule (séparer le blanc du vert), écraser les gousses d''ail, les laisser sur la planche.","Casser les œufs, prélever un peu de blanc dans un bol, mettre le reste dans un autre bol.","Mettre les germes de soja dans une casserole, cuire à feu vif pendant 60 secondes. Les égoutter, les passer sous l''eau froide, les mettre dans une assiette.","Couper le concombre en julienne, le mettre dans une assiette, peut être mélangé avec les germes de soja.","Traiter le gluten, le mettre séparément dans une assiette.","Couper la viande en fines lanières, ajouter la fécule, le blanc d''œuf réservé, le poivre, mélanger dans le sens des aiguilles d''une montre.","Note : Les nouilles de riz achetées en supermarché sont souvent recouvertes d''huile, on peut les rincer à l''eau du robinet. Même chose pour le gluten.","Note : Après avoir rincé le gluten, presser à la main pour en extraire l''excès d''eau (sans trop forcer).","Ajouter de l''huile, chauffer la poêle puis la vider.","Verser la viande préparée, faire sauter jusqu''à ce qu''elle change de couleur, la mettre dans un bol.","Pendant que la poêle est chaude, ajouter 20 g d''huile (les personnes hypertendues peuvent réduire la quantité), ajouter le blanc de ciboule et l''ail, faire revenir jusqu''à ce qu''ils dégagent leur parfum.","Ajouter les nouilles de riz, verser la sauce soja foncée pour colorer, mélanger, puis ajouter la poudre d''assaisonnement pour nouilles, continuer à faire sauter.","Lorsque les nouilles deviennent translucides, ajouter les lanières de viande cuites et le gluten, ajouter la sauce soja claire pour rehausser la saveur, mélanger deux fois.","Ajouter les germes de soja et la julienne de concombre, faire sauter jusqu''à ce que les nouilles soient complètement translucides.","Éteindre le feu !","Parsemer de vert de ciboule pour décorer, soulever la poêle.","Verser dans une assiette, commencer à déguster."]'::jsonb, '["Plat principal","Savoureux","Sauté","Cantonais","Rapide","Accompagne bien le riz"]'::jsonb),
  ('howtocook:staple/炒馍', 'fr', 'Mantou sauté', 'Féculents', 'Le mantou sauté est un plat maison salé, croustillant et parfumé, typique du nord de la Chine. Les dés de mantou sont dorés à la poêle, croustillants à l''extérieur et moelleux à l''intérieur. L''ajout de cumin et de cinq-épices en rehausse la saveur. On peut l''accompagner d''œufs pour les protéines et d''oignons verts pour la fraîcheur, ce qui en fait un repas équilibré. La difficulté est modérée, même les débutants peuvent rapidement maîtriser la recette. Comptez environ 15 minutes pour le préparer et le déguster.', '[{"name":"Mantou","unit":"pièce"},{"name":"Sel","unit":"g"},{"name":"Huile","unit":"ml"},{"name":"Cumin en poudre","unit":"g"},{"name":"Piment en poudre","unit":"g"},{"name":"Cinq-épices","unit":"g"},{"name":"Oignons verts","unit":"tige"},{"name":"Œuf","unit":"pièce"},{"name":"Poivre","note":"selon votre goût"}]'::jsonb, '["Couper les mantous en petits morceaux ou en fines tranches.","Si vous utilisez des œufs, casser les œufs dans un bol et les battre (vous pouvez ajouter 1 g de sel et 1 g de cinq-épices ou les ajouter pendant la cuisson).","Verser les œufs sur les mantous et bien mélanger. Ne pas mettre trop d''œufs.","Chauffer la poêle à feu vif et ajouter l''huile de cuisson (si vous utilisez une poêle en acier inoxydable, vous pouvez d''abord ajouter l''huile et la chauffer jusqu''à ce qu''elle soit chaude).","Ajouter les morceaux de mantou et les faire sauter en remuant bien.","Réduire le feu et faire sauter jusqu''à ce que les morceaux soient dorés.","Ajouter le sel, le poivre et les cinq-épices.","Enfin, ajouter les oignons verts hachés et faire sauter quelques fois.","Éteindre le feu et servir."]'::jsonb, '["Plat principal","Salé et parfumé","Sauté","Style du Nord","Rapide","Fait maison"]'::jsonb),
  ('howtocook:staple/炸酱面', 'fr', 'Nouilles Zhajiang', 'Féculents', 'Les nouilles Zhajiang sont un plat familial traditionnel de Pékin, avec une sauce riche et parfumée et des nouilles fermes, accompagnées de légumes frais, salé-sucré. Les principaux nutriments proviennent des protéines de la viande maigre et des vitamines des légumes, fournissant de l''énergie. La recette est adaptée aux débutants, le temps de préparation est d''environ 30 minutes. Une fois maîtrisée, on peut gagner du temps en préparant les ingrédients et en faisant sauter la sauce en parallèle.', '[{"name":"Viande hachée / dés de porc","unit":"g"},{"name":"Nouilles sèches","unit":"g"},{"name":"Nouilles ordinaires","unit":"g"},{"name":"Ciboule","unit":"g"},{"name":"Ail","unit":"g","note":"au goût"},{"name":"Légumes d''accompagnement","unit":"g"},{"name":"Huile de cuisson","unit":"g"},{"name":"Pâte de haricots fermentés","unit":"g"},{"name":"Pâte de soja sucrée","unit":"g"}]'::jsonb, '["Couper les légumes d''accompagnement en julienne et réserver.","Hacher l''oignon vert. Chauffer l''huile dans une poêle, ajouter l''oignon et la viande, faire sauter jusqu''à ce que la viande soit bien cuite (plus de rose).","Ajouter la pâte de haricots fermentés et la pâte de soja sucrée, continuer à sauter jusqu''à ce que la sauce épaississe légèrement. Retirer et réserver pour obtenir la sauce zhajiang.","Prendre un grand bol, ajouter de l''eau froide et réserver.","Cuire les nouilles jusqu''à ce qu''elles soient al dente (pas de cœur blanc), les transférer dans le bol d''eau froide de l''étape 4.","Égoutter immédiatement et transférer dans un bol propre.","Prendre la sauce de l''étape 3, la verser sur les nouilles et mélanger. Puis ajouter les légumes de l''étape 1 et mélanger à nouveau."]'::jsonb, '["Plat principal","Sauce parfumée","Salé-sucré","Sauce sautée","Pékin","Familial","Rapide"]'::jsonb),
  ('howtocook:staple/烙饼/烙饼', 'fr', 'Galette poêlée', 'Féculents', 'Cette galette maison a des couches distinctes, une croûte croustillante et un intérieur moelleux, avec le parfum de la pâte à l''huile grillée. C''est un plat de base courant dans le nord de la Chine. Il fournit principalement des glucides et de l''énergie, et convient pour accompagner d''autres plats. La préparation demande un peu de technique, surtout pour rouler la pâte à l''huile et abaisser la galette, mais en suivant les étapes, ce n''est pas difficile, même pour un débutant. Du pétrissage à la cuisson, il faut environ 1 heure.', '[{"name":"farine","unit":"g"},{"name":"eau chaude","unit":"ml"},{"name":"eau froide","unit":"ml"},{"name":"huile","note":"Quantité suffisante"},{"name":"poêle électrique","note":"Quantité suffisante"}]'::jsonb, '["Versez 400g de farine dans un bol. Mélangez une moitié avec de l''eau froide et l''autre moitié avec de l''eau chaude, remuez jusqu''à obtenir des grumeaux, puis pétrissez à la main pour former une pâte. Couvrez de film alimentaire et laissez reposer 40 minutes.","10 minutes avant la fin du repos, consultez l''astuce pour la pâte à l''huile (l''huile chaude donne un meilleur résultat).","Ne pétrissez pas la pâte reposée, appuyez légèrement et coupez-la en quatre avec une incision horizontale et une verticale.","Roulez chaque morceau en boule, abaissez-le en un cercle de taille similaire à celle de la poêle électrique. Prenez 1/4 de la pâte à l''huile et étalez-la uniformément sur la surface de la galette.","Coupez le long du rayon de la galette, puis roulez-la en cône à partir du bord extérieur. Pincez bien la pointe du cône pour éviter que la pâte à l''huile ne s''échappe.","Appuyez sur la pointe du cône pour l''aplatir, puis abaissez à nouveau en un cercle de taille similaire à celle de la poêle (environ 3 mm d''épaisseur).","Préchauffez la poêle électrique, badigeonnez d''huile froide (poêle chaude, huile froide). Placez la galette dans la poêle, badigeonnez également le dessus d''huile pour sceller l''humidité, et couvrez.","Faites cuire à feu vif pendant une minute, ouvrez le couvercle, retournez la galette et faites cuire encore une minute.","Répétez l''opération jusqu''à ce que toutes les galettes soient cuites."]'::jsonb, '["Plat principal","Poêlé","Nord","Plat familial","Croustillant et moelleux","En couches"]'::jsonb),
  ('howtocook:staple/烧饼/芝麻烧饼', 'fr', 'Galette au sésame', 'Féculents', 'La galette au sésame est un mets bien connu dans le nord de la Chine. Sa croûte est recouverte de graines de sésame, croustillante et savoureuse, tandis que l''intérieur est feuilleté et moelleux. La farine fournit des glucides, et les graines de sésame sont riches en calcium et en acides gras insaturés. La préparation comprend le pétrissage de la pâte et la confection de la pâte feuilletée, mais les étapes ne sont pas compliquées, même les débutants peuvent suivre. Du début à la fin, il faut environ 40 minutes.', '[{"name":"Farine","unit":"grammes"},{"name":"Farine","unit":"grammes"},{"name":"Levure sèche","unit":"grammes"},{"name":"Sucre blanc","unit":"grammes"},{"name":"Eau tiède (40°C)","unit":"grammes"},{"name":"Huile de cuisson","unit":"grammes"},{"name":"Huile de cuisson","unit":"grammes"},{"name":"Treize épices","unit":"grammes"},{"name":"Sel","unit":"grammes"},{"name":"Graines de sésame blanc","note":"quantité suffisante"}]'::jsonb, '["Pâte : 300 g de farine, 3 g de levure sèche, 3 g de sucre blanc, 180 g d''eau tiède, 20 g d''huile de cuisson. Laisser reposer 10 minutes.","Pâte feuilletée : dans un petit bol, mélanger 30 g de farine, 2 g de sel, 4 g de Treize épices, 20 g d''huile de cuisson. Laisser reposer.","Façonnage : étaler la pâte en rectangle, badigeonner de la pâte feuilletée préparée, rouler en rouleau à partir d''un bord, couper en 7 morceaux. Plier chaque morceau en deux, refermer avec le pouce et l''index. Tremper d''abord dans l''eau puis dans les graines de sésame blanc. Aplatir en petits galettes rondes.","Cuisson : préchauffer une poêle électrique, verser de l''huile froide (couvrir le fond). Placer les galettes dans la poêle, badigeonner le dessus d''un peu d''huile, étaler uniformément, couvrir. Sélectionner le mode galette. Lorsque le signal sonore retentit, sortir du feu."]'::jsonb, '["Plat principal","Croustillant","Cuit à la poêle","Nord","Fait maison","Pâtisserie salée"]'::jsonb),
  ('howtocook:staple/热干面', 'fr', 'Nouilles de Wuhan', 'Féculents', 'Les nouilles de Wuhan sont l''une des collations les plus représentatives de Wuhan, appartenant à la cuisine du Hubei. Les nouilles alcalines sont fermes et lisses, enrobées d''une épaisse sauce au sésame, accompagnées de haricots verts marinés, de radis séchés et de viande hachée, salées et légèrement épicées, avec une saveur riche. Elles fournissent principalement des glucides et des protéines, et la sauce au sésame est également riche en calcium. La préparation est simple et rapide, même les débutants peuvent facilement réussir, il ne faut qu''une dizaine de minutes de la cuisson des nouilles au mélange.', '[{"name":"Nouilles alcalines pour nouilles de Wuhan","unit":"g"},{"name":"Ciboule","unit":"g"},{"name":"Haricots verts marinés","unit":"g"},{"name":"Viande hachée","unit":"g"},{"name":"Eau d''ail","unit":"ml"},{"name":"Bouillon de viande","unit":"ml"},{"name":"Radis séché","unit":"g"},{"name":"Pâte de sésame","unit":"ml"},{"name":"Huile pimentée","unit":"ml"},{"name":"Poivre","unit":"g"},{"name":"Sauce soja","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Bouillon de poulet en poudre","unit":"g"}]'::jsonb, '["Faire bouillir de l''eau, ajouter les nouilles alcalines, les blanchir pendant 25 secondes puis les égoutter.","Saupoudrer de sel, de bouillon de poulet en poudre et de poivre.","Diluer la pâte de sésame avec 90 ml d''eau, bien mélanger, puis ajouter.","Ajouter 5 ml de sauce soja, 30 ml de bouillon de viande et d''eau d''ail.","Ajouter les radis séchés, la viande hachée, les haricots verts marinés et la ciboule.","Bien mélanger et déguster."]'::jsonb, '["Plat principal","Wuhan","Collation","Nouilles mélangées","Rapide","Salé et légèrement épicé","Fait maison"]'::jsonb),
  ('howtocook:staple/煮泡面加蛋', 'fr', 'Nouilles instantanées avec œuf', 'Féculents', 'Les nouilles instantanées avec œuf sont un plat principal rapide et pratique, avec une texture lisse et un bouillon riche, parfait pour calmer la faim à tout moment. Elles fournissent principalement des glucides et des protéines, pour un regain d''énergie rapide. La préparation est très simple : il suffit de faire bouillir de l''eau, cuire les nouilles, ajouter un œuf et cuire. Même un débutant peut s''en sortir facilement, le tout en environ 10 minutes.', '[{"name":"Nouilles instantanées","unit":"paquet"},{"name":"Œuf","unit":"pièce"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Faire chauffer l''eau jusqu''à ébullition (le feu n''a pas besoin d''être précis, utiliser de l''eau chaude est plus rapide)","Mettre le bloc de nouilles dans la casserole","Ajouter les assaisonnements fournis avec les nouilles","Utiliser des baguettes pour remuer légèrement les nouilles, afin de dissoudre les assaisonnements et d''imbiber les nouilles uniformément","Couvrir et attendre environ 1 minute jusqu''à ce que l''eau bout à nouveau","Casser l''œuf et l''ajouter dans la casserole","Attendre environ 3 à 4 minutes, puis servir"]'::jsonb, '["Plat principal","Rapide","Familial","Bouilli","Savoureux","Rassasiant"]'::jsonb),
  ('howtocook:staple/照烧鸡腿饭', 'fr', 'Riz au poulet teriyaki', 'Féculents', 'Le riz au poulet teriyaki est un plat sucré-salé qui accompagne bien le riz. Les cuisses de poulet sont poêlées jusqu''à ce qu''elles soient dorées puis imprégnées d''une sauce riche, tendres et savoureuses. La viande de cuisse de poulet est riche en protéines de qualité, et accompagnée de brocolis et de carottes, elle apporte des fibres et des vitamines. La préparation nécessite un peu de technique pour désosser, mais dans l''ensemble ce n''est pas compliqué, même les débutants peuvent réussir en suivant les étapes. De la préparation à la cuisson, il faut environ 30 minutes pour le servir.', '[{"name":"cuisses de poulet","unit":"g"},{"name":"vin de cuisine","unit":"ml"},{"name":"sauce soja légère","unit":"ml"},{"name":"miel","unit":"ml"},{"name":"poivre noir concassé","unit":"g"},{"name":"poivre noir moulu","unit":"g"},{"name":"sel","unit":"g"},{"name":"brocolis","unit":"g"},{"name":"carottes","unit":"g"},{"name":"sauce soja foncée","unit":"ml"},{"name":"ail","unit":"g"},{"name":"gingembre","unit":"g"},{"name":"huile de cuisson","unit":"ml"},{"name":"eau","unit":"ml"},{"name":"riz","unit":"g"}]'::jsonb, '["Prenez une cuisse de poulet, côté peau vers le bas sur la planche à découper.","Avec la pointe du couteau, incisez délicatement le long de l''os de la cuisse, d''un bout à l''autre.","Avec les doigts ou le dos du couteau, repoussez doucement la chair pour exposer l''os. Si vous rencontrez des tendons, coupez-les avec la pointe du couteau.","Lorsque la chair est complètement séparée, saisissez une extrémité de l''os, tournez délicatement et retirez-le.","Répétez les étapes ci-dessus pour désosser toutes les cuisses de poulet.","Ajoutez du poivre noir moulu, du poivre noir concassé, du sel et des tranches de gingembre aux cuisses désossées. Laissez mariner 5 minutes.","Dans un bol, mélangez le vin de cuisine, la sauce soja légère, le miel, la sauce soja foncée et de l''eau.","Blanchissez les légumes 1 à 2 minutes, puis égouttez.","Faites chauffer une poêle avec 15 ml d''huile, ajoutez l''ail écrasé et faites-le revenir jusqu''à ce qu''il soit parfumé.","Ajoutez les cuisses de poulet et faites-les cuire à feu moyen-doux jusqu''à ce qu''elles soient dorées des deux côtés. Si la poêle semble trop sèche, ajoutez 5 à 10 ml d''huile supplémentaire.","Ajoutez la sauce préparée, couvrez et laissez mijoter à feu moyen-doux (sur une cuisinière à gaz, utilisez un petit feu) pendant 5 à 10 minutes jusqu''à ce que le poulet soit bien cuit et que la sauce épaississe et bouillonne.","Coupez le poulet en morceaux, disposez-le avec les légumes sur le riz, arrosez de la sauce de cuisson et dégustez lentement."]'::jsonb, '["Plat principal","Sucré-salé","Poêlé-mijoté","Japonais","Accompagnement de riz","Rapide"]'::jsonb),
  ('howtocook:staple/蒸卤面', 'fr', 'Nouilles vapeur braisées', 'Féculents', 'C''est un plat de nouilles maison classique de la région du sud du Henan. Il associe viande et légumes, les nouilles absorbent bien la sauce, la texture est molle et ferme, salée et parfumée. La poitrine de porc fournit des protéines de qualité et des graisses, le céleri est riche en fibres alimentaires. La recette est simple à apprendre, même les débutants peuvent la réaliser facilement. La préparation prend environ une heure.', '[{"name":"Poitrine de porc","unit":"g"},{"name":"Nouilles fraîches","unit":"g"},{"name":"Céleri en branches","unit":"branche"},{"name":"Oignon vert","unit":"cm"},{"name":"Gingembre","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Poivron vert","unit":"pièce"},{"name":"Piment rouge sec","unit":"pièce"},{"name":"Poivre du Sichuan","unit":"grain"},{"name":"Sel","unit":"g"},{"name":"Poudre cinq épices","unit":"g"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Huile de cuisson (de préférence huile d''arachide)","note":"quantité suffisante"},{"name":"Vin de cuisine","note":"quantité suffisante"}]'::jsonb, '["Enlever la peau de la poitrine de porc, couper en tranches fines de 2 cm sur 6 cm sur 0,5 cm, réserver","Enlever les feuilles du céleri, couper 2 cm de la base, puis couper en deux dans la longueur et en tronçons de 2 cm, réserver","Peler et hacher l''ail, couper l''oignon vert en fines rondelles de 0,2 cm, couper le gingembre en fine julienne, réserver","Faire chauffer un wok jusqu''à ce qu''il fume, verser 3 ml d''huile de cuisson pour l''enrober, puis jeter l''huile","Ajouter de l''huile de cuisson, ajouter les tranches de porc, l''oignon vert, le gingembre, l''ail et les piments rouges secs, faire sauter 1 minute en remuant constamment et régulièrement","Ajouter le vin de cuisine, la sauce soja claire et la sauce soja foncée, faire sauter encore 1 minute","Ajouter 500 ml d''eau chaude. Couvrir et laisser mijoter 3 minutes","Ajouter le céleri et le poivron vert dans la casserole, assaisonner avec le sel et la poudre cinq épices, couvrir et continuer à mijoter 3 minutes, puis éteindre le feu","Ajouter 1000 ml d''eau dans un cuiseur vapeur, porter à ébullition. Étaler les nouilles à plat sur le panier vapeur, mettre dans le cuiseur et cuire à la vapeur 15 minutes","Sortir les nouilles cuites à la vapeur, les séparer avec des baguettes et les mains (attention, c''est chaud) sur le plan de travail, laisser refroidir à température ambiante","Mettre les nouilles dans la casserole avec les légumes et mélanger : d''une main tenir les baguettes, de l''autre une spatule, soulever les légumes par-dessus les nouilles, mélanger jusqu''à ce que les nouilles soient uniformément colorées","Remettre les nouilles mélangées sur le panier vapeur, cuire à la vapeur encore 10 minutes, puis éteindre le feu"]'::jsonb, '["Plat principal","Salé et parfumé","À la vapeur","Sud du Henan","Maison","Viande et légumes"]'::jsonb),
  ('howtocook:staple/猪油拌饭', 'fr', 'Riz mélangé au saindoux', 'Féculents', 'Ce plat est un riz mélangé simple au parfum de la cuisine familiale du sud de la Chine. Les grains de riz sont enveloppés de saindoux fondu, imprégnés de la saveur salée et umami de la sauce soja et du parfum frais de la ciboule. C''est un choix réconfortant pour de nombreux enfants lorsqu''ils manquent d''appétit. Il fournit principalement des glucides rapides et de l''énergie lipidique, mais il est riche en cholestérol, il ne faut pas en manger trop souvent. Sa préparation est sans difficulté, même ceux qui ne savent pas cuisiner peuvent le faire facilement. Il suffit de quelques minutes pour mélanger un bol de riz chaud et parfumé.', '[{"name":"Riz (de préférence du riz à grain rond)","unit":"grammes"},{"name":"Saindoux","unit":"grammes"},{"name":"Sauce soja claire (de préférence Lee Kum Kee ou Haitian)","unit":"millilitres"},{"name":"Sauce soja foncée","unit":"millilitres"},{"name":"Sauce d''huître (optionnel)","unit":"grammes"},{"name":"Ciboule ciselée (optionnel)","unit":"grammes"},{"name":"Lardons frits (optionnel)","unit":"grammes"}]'::jsonb, '["Déposer le saindoux au fond du bol","Ajouter le riz","Verser la sauce soja et la sauce d''huître","Saupoudrer de ciboule et de lardons frits","Mélanger uniformément"]'::jsonb, '["Plat principal","Salé-umami","Riz mélangé","Rapide","Familial","Sud de la Chine","Accompagnement"]'::jsonb),
  ('howtocook:staple/电饭煲三文鱼炊饭/电饭煲三文鱼炊饭', 'fr', 'Riz au saumon au cuiseur de riz', 'Féculents', 'C''est un plat familial qui fusionne la méthode de cuisson du riz à la japonaise. Le riz absorbe les arômes du beurre et du saumon, offrant une texture riche et savoureuse. Le saumon apporte des protéines de qualité et des acides gras insaturés, et les champignons ajoutent des fibres. La préparation est très simple : il suffit d''utiliser le cuiseur de riz en une seule étape. De la préparation à la cuisson, cela prend environ 45 minutes, idéal pour les débutants.', '[{"name":"Riz","unit":"g"},{"name":"Saumon","unit":"g"},{"name":"Beurre salé","unit":"cuillère à soupe"},{"name":"Eau","note":"Quantité suffisante"},{"name":"Maïs (optionnel)","note":"Quantité suffisante"},{"name":"Champignons enoki (optionnel)","note":"Quantité suffisante"},{"name":"Champignons shiitake (optionnel)","note":"Quantité suffisante"}]'::jsonb, '["Enlever les écailles et les arêtes du saumon","Hacher les champignons enoki et shiitake","Laver le riz trois fois","Mettre le saumon, le riz et le beurre dans le cuiseur de riz","Pour une texture plus riche, ajouter une cuillère à soupe de beurre supplémentaire","Ajouter de l''eau selon les graduations du cuiseur de riz","Régler le cuiseur de riz en mode cuisson du riz et attendre environ 30 à 45 minutes"]'::jsonb, '["Plat principal","Savoureux","Cuiseur de riz","Familial","Rapide"]'::jsonb),
  ('howtocook:staple/空气炸锅照烧鸡饭/空气炸锅照烧鸡饭', 'fr', 'Riz au poulet teriyaki (friteuse à air)', 'Féculents', 'Ce riz au poulet teriyaki de style japonais a une sauce sucrée-salée riche, la surface est légèrement croustillante après cuisson, l''intérieur est tendre et juteux, et il se marie très bien avec du riz. Le poulet et les œufs fournissent des protéines de haute qualité, mais la quantité de sauce soja et de sucre est assez élevée, donc mieux pour un changement occasionnel. La recette est simple : il suffit de mélanger les ingrédients et de les mettre dans la friteuse à air, même les débutants peuvent la réussir facilement. De la préparation à la sortie, cela prend environ 1 heure.', '[{"name":"Poulet","unit":"g"},{"name":"Sauce soja","unit":"ml"},{"name":"Sucre","unit":"g"},{"name":"Vinaigre blanc","unit":"ml"},{"name":"Biscuits Ritz","unit":"pièce"},{"name":"Œuf","unit":"pièce"},{"name":"Riz","note":"quantité suffisante"}]'::jsonb, '["Mélanger la sauce soja, le sucre et le vinaigre, bien remuer la sauce et réserver.","Dans un autre bol, ajouter le poulet, l''œuf, la moitié de la sauce et les biscuits Ritz écrasés. Bien mélanger.","Tapisser le fond du panier de la friteuse à air avec du papier aluminium, ajouter le mélange de galette de viande, verser uniformément le reste de la sauce dessus.","Cuire à 350°F (177°C) pendant 40 minutes. Servir de préférence sur du riz.","Lorsque l''extérieur est doré et croustillant, sortir du four, couper en morceaux et servir dans une assiette."]'::jsonb, '["Plat principal","Sucré-salé","Friteuse à air","Japonais","Accompagnement de riz","Fait maison"]'::jsonb),
  ('howtocook:staple/米饭/煮锅蒸米饭', 'fr', 'Riz cuit à la vapeur à la casserole', 'Féculents', 'C''est un plat de base familial simple et sans prétention. Avec une casserole ordinaire, on peut obtenir un riz doux et moelleux. Le riz blanc fournit principalement des glucides pour un apport énergétique rapide. La préparation est très simple, les débutants n''ont qu''à surveiller la cuisson du début à la fin pour maîtriser facilement, du moment où l''on met le riz à celui où on le sort, cela prend environ 25 minutes.', '[{"name":"Riz du Nord","unit":"ml"},{"name":"Eau","note":"Quantité suffisante"}]'::jsonb, '["Laver le riz","Ajouter le riz et l''eau dans la casserole","Porter à ébullition à feu vif","Remuer le fond pour éviter que ça colle","Couvrir, réduire à feu doux et laisser cuire 10-15 minutes (selon la texture désirée), sans ouvrir le couvercle","Éteindre le feu et laisser reposer 5 minutes","Dégustez :)"]'::jsonb, '["Plat principal","Léger","Moelleux","Cuit","Familial","Rapide"]'::jsonb),
  ('howtocook:staple/米饭/电饭煲蒸米饭', 'fr', 'Riz au cuiseur à riz', 'Féculents', 'Un plat de base connu de tous, au parfum de riz pur et à la texture moelleuse, qui peut être plus ferme ou plus humide selon la quantité d''eau. Riche en glucides, il apporte rapidement de l''énergie et se marie avec une variété de plats. L''opération est extrêmement simple, même les débutants peuvent le faire facilement. Du lavage du riz à la cuisson, cela prend environ quarante minutes.', '[{"name":"Riz du Jiangnan ou riz du nord","unit":"ml"},{"name":"Eau","note":"Quantité suffisante"}]'::jsonb, '["Laver le riz.","Ajouter le riz et l''eau dans le cuiseur à riz.","Brancher le cuiseur à riz et le mettre en mode cuisson. Attendre environ 30 minutes.","Lorsque le cuiseur passe automatiquement en mode maintien au chaud.","Laisser le riz reposer dans le cuiseur pendant 10-15 minutes.","Servir le riz."]'::jsonb, '["Base","Léger","Rapide","Maison"]'::jsonb),
  ('howtocook:staple/红芸豆拌饭', 'fr', 'Riz aux haricots rouges', 'Féculents', 'Ce plat familial du nord de l''Inde est une spécialité traditionnelle du Pendjab et de Delhi. La sauce tomate à l''oignon est riche et épicée, les haricots rouges mijotés sont tendres et savoureux, et servis avec du riz chaud, c''est réconfortant et nourrissant. Les haricots sont riches en protéines, fibres et oligo-éléments, pour un repas équilibré. La recette est simple, même les débutants peuvent la réussir. Comptez environ 40 minutes de préparation, mais les haricots secs doivent tremper 8 heures à l''avance. Une saveur familiale intense, comme chez maman.', '[{"name":"Haricots rouges secs","unit":"g"},{"name":"Oignon","unit":"pièce"},{"name":"Tomate","unit":"pièce"},{"name":"Concentré de tomate","unit":"ml"},{"name":"Gingembre","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Piment vert","unit":"pièce"},{"name":"Huile de cuisson ou ghee","unit":"ml"},{"name":"Feuille de laurier","unit":"feuille"},{"name":"Curcuma en poudre","unit":"g"},{"name":"Piment rouge en poudre","unit":"g"},{"name":"Coriandre moulue","unit":"g"},{"name":"Cumin moulu","unit":"g"},{"name":"Garam masala","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Eau","unit":"ml"},{"name":"Feuilles de coriandre fraîche","unit":"g"},{"name":"Riz","unit":"g"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Faire tremper les haricots rouges secs dans de l''eau froide pendant au moins 8 heures (toute une nuit) ; ils doubleront de volume.","Égoutter les haricots rouges trempés.","À l''autocuiseur : mettre les haricots et 600 ml d''eau, fermer le couvercle, chauffer à feu vif jusqu''à la montée en pression, puis réduire à feu moyen et cuire 15 à 20 minutes, jusqu''à ce que les haricots s''écrasent facilement entre les doigts.","À la casserole ordinaire : mettre les haricots et assez d''eau pour les couvrir, porter à ébullition à feu vif, puis réduire à feu moyen et cuire 60 à 90 minutes, jusqu''à ce qu''ils soient bien tendres.","Après cuisson, réserver l''eau de cuisson des haricots.","Dans une poêle, chauffer 30 ml d''huile de cuisson à feu moyen.","Ajouter 2 feuilles de laurier et les faire frire jusqu''à ce qu''elles dégagent leur parfum (environ 10 secondes).","Ajouter l''oignon émincé et le faire revenir jusqu''à ce qu''il soit brun doré (environ 6 à 8 minutes).","Ajouter le gingembre râpé et l''ail écrasé, faire revenir 1 minute.","Ajouter la tomate coupée en dés et faire revenir jusqu''à ce qu''elle soit complètement fondue et que l''huile se sépare (environ 5 minutes).","Ajouter 3 g de curcuma, 5 g de piment rouge en poudre, 5 g de coriandre moulue, 3 g de cumin moulu et 6 g de sel.","Faire revenir 2 minutes pour que les épices se mélangent à la tomate.","Verser les haricots cuits avec leur eau de cuisson dans la poêle.","Ajouter les piments verts et mélanger.","Porter à ébullition à feu vif, puis réduire à feu doux et laisser mijoter 15 à 20 minutes.","Pendant ce temps, écraser une partie des haricots avec le dos d''une cuillère pour épaissir la sauce.","Ajouter 3 g de garam masala et mélanger.","Éteindre le feu et parsemer de feuilles de coriandre fraîche.","Rincer le riz à l''eau claire.","Mettre le riz dans un cuiseur à riz avec 400 ml d''eau.","Cuire normalement.","Servir le riz dans une assiette.","Verser le curry de haricots rouges sur le riz ou à côté.","Accompagner de salade d''oignons et de quartiers de citron."]'::jsonb, '["Plat principal","Inde du Nord","Mijoté","Épicé","Accompagnement du riz","Familial","Curry"]'::jsonb),
  ('howtocook:staple/老友猪肉粉/老友猪肉粉', 'fr', 'Nouilles de porc Laoyou', 'Féculents', 'Les nouilles de porc Laoyou sont aigres et épicées, fraîches et parfumées. Les nouilles sont lisses, avec la saveur riche caractéristique des haricots noirs fermentés et des pousses de bambou aigres. C''est un goût familial typique de Nanning. Le porc fournit des protéines de qualité, tandis que les nouilles apportent rapidement de l''énergie glucidique. La préparation est de difficulté moyenne : il faut faire tremper les nouilles à l''avance. Une fois que vous maîtrisez la recette, elle peut être servie en environ quarante minutes.', '[{"name":"Nouilles de riz","unit":"g"},{"name":"Porc","unit":"g"},{"name":"Pousses de bambou aigres","unit":"g"},{"name":"Piments hachés","unit":"g"},{"name":"Haricots noirs fermentés","unit":"g"},{"name":"Ail","unit":"g"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sucre blanc","unit":"g"},{"name":"Vinaigre de riz","unit":"ml"},{"name":"Sel","unit":"ml"},{"name":"Huile","unit":"ml"},{"name":"Fécule de maïs","unit":"ml"},{"name":"Poivre moulu","unit":"ml"}]'::jsonb, '["Assaisonnez tout le porc avec du vin de cuisine, du sel, de la sauce soja légère, de la fécule de maïs et du poivre dans un bol, réservez.","Dans une poêle chaude sans huile, mettez tous les pousses de bambou aigres et faites-les sécher à sec. Laissez un peu d''espace au milieu des pousses de bambou séchées.","Ajoutez 10-15 ml d''huile de cuisson, tout l''ail, les piments hachés et les haricots noirs fermentés au milieu des pousses de bambou séchées au milieu des pousses de bambou séchées, poussez le tout au centre et faites revenir jusqu''à ce que les arômes se dégagent.","Ajoutez tout le porc assaisonné, puis ajoutez 10 ml de sauce soja légère et faites sauter une minute.","Ajoutez 5 ml de vinaigre de riz, 10 ml de sauce soja légère et 450 ml d''eau claire, portez à ébullition.","Après ébullition, ajoutez les nouilles trempées dans l''eau tiède, faites cuire encore 3 minutes, puis servez."]'::jsonb, '["Plat principal","Aigre-épicé","Bouilli","Saveur de Nanning","Familial","Nouilles de riz"]'::jsonb),
  ('howtocook:staple/老干妈拌面', 'fr', 'Nouilles à la Lao Gan Ma', 'Féculents', 'Un plat de nouilles fait maison, épicé et appétissant. Les nouilles sont fermes et enrobées de la saveur piquante et fermentée de la Lao Gan Ma, la sauce soja rehausse le goût, simple mais très savoureux. En tant que plat principal, il fournit rapidement des glucides et de l''énergie, et la capsaïcine stimule l''appétit. La préparation est très facile, même les débutants peuvent s''en sortir, de l''ébullition de l''eau à la sortie du plat, il faut environ dix minutes.', '[{"name":"Eau","unit":"litre"},{"name":"Nouilles","unit":"gramme"},{"name":"Lao Gan Ma","unit":"ml"},{"name":"Sauce soja","unit":"ml"}]'::jsonb, '["Verser l''eau dans une casserole et porter à ébullition","Mettre les nouilles uniformément dans la casserole","Pendant la cuisson, remuer pour éviter que les nouilles ne collent","Lorsque vous soulevez une nouille avec des baguettes et qu''elle glisse naturellement, attendez 30 secondes puis éteignez le feu","Mettre les nouilles dans un bol","Ajouter la Lao Gan Ma et la sauce soja selon les quantités indiquées","Mélanger les nouilles, la Lao Gan Ma et la sauce soja dans le bol avec des baguettes","Manger"]'::jsonb, '["Plat principal","Épicé","Nouilles mélangées","Rapide","Fait maison","Appétissant"]'::jsonb),
  ('howtocook:staple/肉蛋盖饭', 'fr', 'Riz au porc et œuf', 'Féculents', 'Ce plat est riche en sauce, salé-sucré, avec de la viande hachée grillée et des œufs tendres, servi sur du riz chaud pour une grande satisfaction. C''est un plat rapide et familial. Riche en protéines de haute qualité et en acides aminés essentiels, il apporte rapidement de l''énergie. La préparation est simple et intuitive, même les débutants peuvent y arriver facilement. De la préparation à la cuisson, il faut environ quinze minutes.', '[{"name":"riz","unit":"g"},{"name":"œuf","unit":"unité"},{"name":"viande hachée","unit":"g"},{"name":"sauce soja foncée","unit":"ml"},{"name":"sauce soja claire","unit":"ml"},{"name":"vinaigre","unit":"ml"},{"name":"huile d''échalote rouge","unit":"g"},{"name":"ciboule","unit":"g"},{"name":"huile","unit":"ml"},{"name":"sucre","unit":"g"}]'::jsonb, '["Cuire le riz, généralement en utilisant la tasse à mesurer offerte avec l''achat du riz, une tasse de riz = 240g","Mettre 30 ml d''huile dans la poêle","Ajouter la viande hachée, régler à feu moyen et faire revenir jusqu''à ce qu''elle soit légèrement dorée des deux côtés","Casser les œufs dans la poêle sans les brouiller, couvrir avec un couvercle","Préparer une sauce dans un bol : mettre les quantités correspondantes de sauce soja foncée, sauce soja claire, vinaigre, sucre, huile d''échalote rouge, et bien mélanger","Ouvrir le couvercle, verser la sauce dans la poêle, attendre trois minutes","Éteindre le feu, déposer la viande et les œufs sur le riz","Vérification de sécurité, commencer à déguster le plat"]'::jsonb, '["Plat principal","Sauce riche","Salé-sucré","Rapide","Accompagne bien le riz","Familial"]'::jsonb),
  ('howtocook:staple/茄子肉煎饼/茄子肉煎饼', 'fr', 'Galettes à l''aubergine et au lard fumé', 'Féculents', 'Cette galette maison allie le goût salé et fumé du lard à la douceur de l''aubergine. La croûte est croustillante et l''intérieur moelleux, un plat de farine de riz au parfum rustique. Riche en glucides et en protéines de qualité, l''aubergine apporte des fibres et des vitamines, un équilibre nutritionnel entre viande et légumes. La difficulté est moyenne, il faut maîtriser la consistance de la pâte et le temps de cuisson, mais les débutants peuvent réussir en suivant les étapes. De la préparation à la sortie du plat, compter environ 30 minutes.', '[{"name":"farine de riz","unit":"g"},{"name":"farine de blé","unit":"g"},{"name":"œuf","unit":"pièce"},{"name":"lard fumé cuit","unit":"g"},{"name":"aubergine","unit":"pièce"},{"name":"huile de cuisson","unit":"ml"},{"name":"sel","unit":"g"}]'::jsonb, '["Éplucher l''aubergine et la couper en tranches. Couper le lard fumé en tranches. Réserver.","Ajouter successivement dans un bol 250 g de farine de riz, 50 g de farine de blé et 1 œuf.","Tout en remuant avec des baguettes, ajouter de l''eau (pour ajuster la consistance) jusqu''à obtenir une pâte qui adhère aux tranches d''aubergine et de lard sans couler. Puis placer toutes les tranches d''aubergine et de lard dans la pâte et bien les enrober.","Verser 10 à 30 ml d''huile de cuisson dans une poêle et chauffer à feu doux.","À l''aide de baguettes ou d''une cuillère, déposer les tranches enrobées de pâte dans la poêle. Faire dorer des deux côtés, puis cuire encore 3 à 6 minutes (ajouter un peu d''huile si nécessaire).","Saupoudrer de sel, mélanger rapidement, puis dresser dans une assiette."]'::jsonb, '["Plat principal","Salé et fumé","Poêlé","Maison","Saveur rustique","Équilibré nutritionnellement"]'::jsonb),
  ('howtocook:staple/葱油拌面', 'fr', 'Nouilles à l''huile d''oignon vert', 'Féculents', 'Les nouilles à l''huile d''oignon vert sont un plat de nouilles domestique classique de Shanghai, réputé pour son arôme unique d''huile d''oignon. La préparation est simple et rapide. Riches en glucides et en lipides, elles fournissent rapidement de l''énergie. Un débutant peut les préparer en seulement 20 minutes, ce qui en fait un dîner rapide idéal pour le quotidien.', '[{"name":"Nouilles sèches","unit":"g"},{"name":"Ciboule","unit":"g"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Sucre blanc","unit":"g"},{"name":"Huile de cuisson","unit":"ml"}]'::jsonb, '["Laver la ciboule et la couper en tronçons (environ 5-7 cm). Les parties blanches et vertes peuvent être séparées.","Dans une poêle, ajouter 100 ml d''huile de cuisson et chauffer à feu moyen. D''abord, ajouter les tronçons blancs et les faire revenir jusqu''à ce qu''ils soient légèrement jaunes.","Ajouter les tronçons verts, réduire à feu doux et continuer à faire revenir.","Maintenir à feu doux et faire revenir patiemment pendant environ 15-20 minutes, jusqu''à ce que les oignons deviennent croustillants et dorés.","Retirer les oignons croustillants (l''huile reste dans la poêle).","Dans l''huile restante dans la poêle, ajouter 60 ml de sauce soja légère, 20 ml de sauce soja foncée et 15 g de sucre blanc. Chauffer à feu doux en remuant pendant environ 1 minute, jusqu''à ce que le sucre soit dissous et que la sauce soit homogène. Éteindre immédiatement. Verser la sauce à l''huile d''oignon dans un récipient, laisser refroidir puis conserver dans un contenant hermétique.","Prendre 80 g de nouilles sèches.","Dans une casserole, ajouter 1000 ml d''eau potable et porter à ébullition à feu vif.","Ajouter les nouilles et cuire selon les instructions sur l''emballage, jusqu''à ce qu''elles soient cuites (généralement 3-8 minutes, se référer aux instructions).","Égoutter les nouilles cuites et les placer dans un bol.","Ajouter 15 ml de la sauce à l''huile d''oignon préparée précédemment dans le bol de nouilles.","(Optionnel) Ajouter les oignons croustillants frits précédemment.","Mélanger rapidement avec des baguettes, puis servir."]'::jsonb, '["Plat principal","Shanghai","Savoureux","Rapide","Fait maison","Nouilles mélangées"]'::jsonb),
  ('howtocook:staple/蛋包饭', 'fr', 'Omelette au riz', 'Féculents', 'Enveloppé d''une peau d''œuf tendre et lisse, le riz sauté à la sauce tomate offre une texture riche, un goût aigre-doux qui ouvre l''appétit. Ce plat familial japonais classique est riche en protéines, glucides et diverses vitamines, équilibré sur le plan nutritionnel. Envelopper l''omelette nécessite un peu de technique, mais la difficulté globale est modérée, les débutants peuvent aussi essayer. De la préparation à la finition, comptez environ 25 minutes.', '[{"name":"Œuf","unit":"pièce"},{"name":"Oignon","unit":"g"},{"name":"Carotte","unit":"g"},{"name":"Maïs et petits pois (optionnel)","unit":"g"},{"name":"Jambon ou blanc de poulet","unit":"g"},{"name":"Riz cuit","unit":"g"},{"name":"Ketchup","unit":"ml"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Lait (optionnel)","unit":"ml"}]'::jsonb, '["Couper l''oignon, la carotte, le jambon ou le blanc de poulet en petits dés, réserver.","Chauffer la poêle, verser 10 ml d''huile de cuisson, attendre 10 secondes.","Ajouter d''abord les dés d''oignon, faire revenir 1 minute, une fois parfumé, ajouter la carotte, le maïs et les petits pois, continuer à faire revenir 2 minutes.","Ajouter le jambon ou le poulet en dés, faire sauter jusqu''à ce qu''il change de couleur.","Ajouter le riz, émietter, puis ajouter 20 ml de ketchup, bien mélanger. Le riz sauté est prêt, réserver.","Battre les œufs, ajouter 10 ml de lait et bien mélanger.","Mettre 5 ml d''huile de cuisson dans la poêle, verser l''œuf battu, incliner doucement la poêle pour que l''œuf recouvre uniformément le fond.","Chauffer à feu doux, lorsque la surface de l''œuf est à moitié cuite, placer le riz sauté au centre.","Avec une spatule, replier l''omelette pour envelopper le riz, formant une forme ovale.","Faire glisser délicatement dans l''assiette, ajuster la forme, éventuellement décorer avec un peu de ketchup sur le dessus."]'::jsonb, '["Plat principal","Aigre-doux","Sauté","Rapide","Familial","Japonais","Appétissant"]'::jsonb),
  ('howtocook:staple/蛋炒饭', 'fr', 'Riz sauté aux œufs', 'Féculents', 'Un riz sauté aux œufs fait maison, avec des filaments d''œufs dorés enveloppant des grains de riz séparés, accompagné de jambon, carottes et concombres, une texture riche, salée et savoureuse. Les œufs fournissent des protéines de qualité, les carottes apportent des vitamines, les glucides fournissent suffisamment d''énergie. Les étapes sont un peu nombreuses, mais un débutant peut réussir en suivant le processus, le tout prend environ 25 minutes.', '[{"name":"Riz froid","unit":"ml"},{"name":"Œufs"},{"name":"Jambon","unit":"pièce(s)"},{"name":"Concombre","unit":"grammes"},{"name":"Carotte","unit":"grammes"},{"name":"Huile","unit":"ml"},{"name":"Sel","unit":"grammes"},{"name":"Poivre","unit":"grammes"},{"name":"Oignon vert","unit":"tige(s)"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Lanières de bœuf Dengying/luncheon/luncheon/lardon/saucisson/viande braisée (optionnel)","note":"Quantité suffisante"}]'::jsonb, '["Émietter le riz refroidi en petits morceaux avec une spatule.","Couper le jambon, les carottes, les concombres, etc. en tranches ou en dés selon vos besoins.","Si vous avez de la viande cuite à la maison, préparez-la pour une meilleure saveur.","Séparer les blancs des jaunes d''œufs, les battre chacun dans un grand bol. Attention, ne pas ajouter de sel à cette étape.","Chauffer la poêle à feu vif, lorsqu''elle fume, ajouter de l''huile, puis verser les blancs d''œufs. Une fois qu''ils sont pris, les retirer et réserver.","S''il reste assez d''huile, ajouter directement les jaunes. Sinon, ajouter de l''huile et attendre qu''elle chauffe à feu vif.","Une fois que les jaunes sont pris, réduire le feu à moyen-doux, ajouter le jambon, la viande cuite, les carottes, les concombres, etc., et faire sauter 10 secondes (jusqu''à ce qu''ils soient parfumés).","Remettre les blancs d''œufs, faire sauter 5 secondes, puis ajouter rapidement le riz et augmenter le feu, en faisant sauter pour que chaque grain de riz soit enrobé d''œuf.","Pendant le sauté, écraser les morceaux de riz. Cette étape peut être longue, une fois que tout le riz est émietté, continuer à sauter jusqu''à ce qu''il soit bien mélangé.","Réduire le feu à doux, ajouter du sel, du poivre, et de la sauce soja légère.","Continuer à sauter uniformément. Quand on voit certains grains de riz sauter dans la poêle, c''est presque prêt.","Enfin, ajouter les oignons verts et faire sauter 10 secondes.","Éteindre le feu, servir dans un bol."]'::jsonb, '["Plat principal","Salé","Fait maison","Rapide","Sauté","Accompagnement du riz"]'::jsonb),
  ('howtocook:staple/螺蛳粉', 'fr', 'Nouilles de riz aux escargots', 'Féculents', 'Les nouilles de riz aux escargots sont une spécialité de Liuzhou, dans le Guangxi. Le bouillon est savoureux et riche, aigre-piquant et rafraîchissant, les nouilles sont molles et élastiques. La saveur combine la fraîcheur du bouillon d''escargots, la fermentation unique des pousses de bambou aigres et le piquant de l''huile de piment, avec des couches distinctes. En tant que plat principal, les nouilles fournissent des glucides, le sachet de chair d''escargot et les garnitures apportent des protéines, et les pousses de bambou aigres aident à ouvrir l''appétit et à la digestion. La préparation est simple : il suffit de cuire les nouilles et d''ajouter les assaisonnements dans l''ordre, très adapté aux débutants. De l''ébullition de l''eau au service, cela prend environ dix minutes, parfait pour un repas rapide.', '[{"name":"Nouilles de riz aux escargots en sachet","unit":"sachet"},{"name":"Eau","unit":"L"},{"name":"Nouilles de riz","note":"quantité suffisante"},{"name":"Sachet de chair d''escargot","note":"quantité suffisante"},{"name":"Sachet de bouillon","note":"quantité suffisante"},{"name":"Sachet de pousses de bambou aigres","note":"quantité suffisante"},{"name":"Sachet de cacahuètes","note":"quantité suffisante"},{"name":"Sachet de feuilles de tofu","note":"quantité suffisante"},{"name":"Sachet de champignons noirs","note":"quantité suffisante"},{"name":"Sachet de vinaigre","note":"quantité suffisante"},{"name":"Huile de piment","note":"quantité suffisante"}]'::jsonb, '["Dans une casserole, ajoutez de l''eau et portez à ébullition.","Ajoutez les nouilles de riz, faites cuire 3-5 minutes en remuant avec des baguettes pour éviter qu''elles ne collent.","Ajoutez le sachet de bouillon selon votre goût.","Ajoutez une partie des sachets de garnitures, comme les champignons noirs, les cacahuètes et les escargots (ces garnitures ont besoin de cuire un peu pour s''imprégner).","Ajoutez le sachet d''assaisonnement selon votre goût.","Mélangez puis égouttez et placez dans un bol.","Ajoutez le reste des sachets de garnitures, comme les pousses de bambou aigres et les feuilles de tofu (ces garnitures ne doivent pas tremper trop longtemps).","Dégustez!"]'::jsonb, '["Plat principal","Aigre-piquant","Savoureux","Rapide","Style Guangxi","Nouilles en bouillon"]'::jsonb),
  ('howtocook:staple/西红柿鸡蛋挂面/西红柿鸡蛋挂面', 'fr', 'Nouilles aux œufs et à la tomate', 'Féculents', 'Les nouilles aux œufs et à la tomate sont un plat de nouilles rapide et familial, aigre-doux et salé, avec une sauce riche et des nouilles fermes. Ce plat est un incontournable du quotidien, influencé par la cuisine du nord. Les œufs fournissent des protéines de qualité, les tomates sont riches en lycopène et en vitamines, et les nouilles apportent des glucides, le tout pour un repas équilibré. La recette est simple, les étapes claires, et elle convient aux débutants. Du début à la fin, comptez environ 20 minutes.', '[{"name":"Nouilles","unit":"g"},{"name":"Tomate","unit":"pièce"},{"name":"Œuf","unit":"pièce"},{"name":"Sel","unit":"g"},{"name":"Ciboule","note":"à volonté"},{"name":"Ail","note":"à volonté"},{"name":"Poivron vert","note":"à volonté"},{"name":"Huile de cuisson","unit":"g"},{"name":"Sauce soja","unit":"g"},{"name":"Sauce d''huître","unit":"g"},{"name":"Bouillon de poulet en granulés","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Huile de sésame","unit":"g"},{"name":"Vinaigre blanc","unit":"g"},{"name":"Eau claire","note":"à volonté"}]'::jsonb, '["Laver et ciseler la ciboule.","Couper les tomates en morceaux. Si vous ne savez pas comment faire, cherchez d''abord sur Internet.","Couper le poivron vert en losanges.","Casser les œufs dans un petit bol et les battre. Si les œufs ont une odeur, ajouter 2 g de vinaigre blanc pour enlever l''odeur.","Chauffer la poêle, verser 15 à 20 g d''huile de cuisson. Pour des œufs brouillés moelleux, il faut plus d''huile, et laisser un peu d''huile au fond pour faire sauter les tomates.","Quand l''huile est chaude (à environ 70 % de sa capacité, à 10 cm au-dessus on sent la chaleur), verser les œufs battus et les brouiller rapidement.","Une fois les œufs cuits et sans liquide, les mettre dans un petit bol. Laisser un peu d''huile au fond de la poêle.","Ajouter la partie blanche de la ciboule et l''ail haché dans l''huile restante, et faire revenir jusqu''à ce qu''ils dégagent leur parfum.","Ajouter les tomates et le poivron vert. Faire sauter jusqu''à ce que les tomates rendent un peu de jus.","Ajouter rapidement 5 g de sauce soja et 2 g de sucre blanc.","Faire sauter une dizaine de secondes, puis ajouter un bol d''eau claire (juste assez pour couvrir les tomates).","Porter à ébullition, puis ajouter les œufs cuits, 5 g de sauce d''huître ou 2 g de bouillon de poulet en granulés pour rehausser la saveur.","Réduire la sauce à feu moyen-doux en remuant pour éviter d''attacher. Réduire jusqu''à ce que la sauce épaississe (voir image), puis ajouter un peu de ciboule ciselée (la partie verte restante) et de l''huile de sésame (facultatif). La garniture est prête.","Inutile de laver la poêle, ajouter directement 500 ml d''eau claire.","Porter à ébullition et ajouter les nouilles. Une fois les nouilles ramollies, ajouter 100 ml d''eau claire.","Après une nouvelle ébullition, si les nouilles flottent, ajouter encore 100 ml d''eau claire.","Après ébullition, vérifier si les nouilles sont translucides sur les bords ; si oui, elles sont cuites.","Égoutter les nouilles et les mettre dans le bol de garniture. Mélanger et déguster."]'::jsonb, '["Repas principal","Familial","Rapide","Aigre-doux","Nouilles","Accompagnement"]'::jsonb),
  ('howtocook:staple/豆角焖面/豆角焖面', 'fr', 'Nouilles étuvées aux haricots verts et poitrine de porc', 'Féculents', 'Les nouilles étuvées aux haricots verts sont un plat de nouilles familial du nord de la Chine. Les nouilles absorbent le bouillon, devenant moelleuses et savoureuses, avec la fraîcheur des haricots verts et le gras des tranches de viande. La poitrine de porc apporte des protéines et des lipides, les haricots verts sont riches en fibres et vitamines, l''association viande-légumes est équilibrée. L''ensemble n''est pas très difficile, mais il faut surveiller le feu et le moment d''ajout du bouillon. Convient aux cuisiniers avec un peu d''expérience, comptez environ 30 minutes pour le servir.', '[{"name":"Nouilles fraîches","unit":"g","note":""},{"name":"Poitrine de porc","unit":"g","note":""},{"name":"Haricots verts","unit":"g","note":""},{"name":"Huile de cuisson","unit":"ml","note":""},{"name":"Sel","unit":"g","note":""},{"name":"Sauce soja claire","unit":"ml","note":""},{"name":"Sauce soja foncée","unit":"ml","note":""},{"name":"Sauce d''huître","unit":"g","note":""},{"name":"Treize épices","unit":"g","note":""},{"name":"Bouillon de poule en poudre","unit":"g","note":""},{"name":"Glutamate monosodique","unit":"g","note":""},{"name":"Oignon vert","unit":"g","note":""},{"name":"Gingembre","unit":"g","note":""},{"name":"Ail","unit":"g","note":""},{"name":"Eau chaude","unit":"ml","note":""}]'::jsonb, '["Coupez les haricots verts en tronçons de 5 à 6 cm.","Coupez l''oignon vert en tronçons de 1 à 2 cm.","Coupez le gingembre en fines lamelles de 1 mm x 1 mm x 3 cm.","Écrasez l''ail sur une planche et hachez-le en grains de 1 mm.","Coupez la poitrine de porc en tranches de 2 mm d''épaisseur.","Chauffez la poêle jusqu''à ce qu''elle soit bien sèche. Placez votre main à 10 cm au-dessus de la poêle, vous devez sentir une chaleur nette.","Ajoutez l''huile de cuisson indiquée, tenez la poêle par le manche, inclinez-la à 5 cm du feu et faites tourner pour que l''huile recouvre les deux tiers de la poêle (du bas vers le haut).","Ajoutez tout le gingembre et tous les tronçons d''oignon vert, faites revenir en remuant 5 secondes (attention aux éclaboussures d''huile, portez des gants ou protégez-vous).","Ajoutez toutes les tranches de viande. Ne remuez pas immédiatement, laissez poser 5 secondes, puis remuez pour que toute la viande soit enrobée d''huile.","Remuez continuellement les tranches de viande jusqu''à ce qu''elles aient toutes changé de couleur. Versez la sauce soja claire préparée le long du bord de la poêle et remuez pour bien répartir.","Ajoutez successivement le sel, la sauce soja foncée, la sauce d''huître, le treize épices, le bouillon de poule en poudre et tous les haricots verts préparés. Remuez pendant 2 minutes.","Ajoutez l''eau chaude préparée.","Quand l''eau bout, utilisez une louche pour retirer la moitié du bouillon de la poêle (attention à ne pas retirer les légumes).","Étalez toutes les nouilles uniformément au-dessus des légumes.","Couvrez et laissez mijoter à feu moyen pendant 5 minutes.","Retirez le couvercle, versez le bouillon réservé sur les nouilles, une louche à la fois, en répartissant uniformément.","Couvrez et laissez mijoter à feu moyen pendant 3 minutes.","Retirez le couvercle, saupoudrez uniformément tout l''ail haché et le glutamate monosodique.","Remuez constamment avec des baguettes pour bien mélanger les nouilles, les légumes et la viande.","Éteignez le feu."]'::jsonb, '["Plat principal","Cuisine familiale du nord","Nouilles étuvées","Salé et parfumé","Rapide"]'::jsonb),
  ('howtocook:staple/酱拌荞麦面/酱拌荞麦面', 'fr', 'Nouilles de sarrasin sauce Lao Gan Ma', 'Féculents', 'Les nouilles de sarrasin sauce Lao Gan Ma sont aigres-douces, rafraîchissantes et glissantes, un plat de nouilles froides maison simple et rapide. Riches en fibres alimentaires et protéines, accompagnées de concombre et carotte pour une texture croquante et des vitamines, l''équilibre nutritionnel est assuré. Il suffit de cuire les nouilles, couper les légumes et mélanger avec Lao Gan Ma, quelques étapes faciles pour les débutants, environ 20 minutes. Meilleur goût après réfrigération.', '[{"name":"Nouilles de sarrasin","unit":"g"},{"name":"Concombre","unit":"pièce"},{"name":"Carotte","unit":"pièce"},{"name":"Lao Gan Ma","unit":"ml"}]'::jsonb, '["Cuire les nouilles de sarrasin dans l''eau froide jusqu''à cuisson, 8 à 10 minutes, puis égoutter et réserver.","Couper le concombre et la carotte en petits bâtonnets.","Mettre les nouilles de sarrasin, le concombre et la carotte dans un plat, ajouter Lao Gan Ma, mélanger."]'::jsonb, '["Plat principal","Froid","Rapide","Maison","Aigre-doux","Légèrement épicé","Rafraîchissant"]'::jsonb),
  ('howtocook:staple/酸辣蕨根粉', 'fr', 'Vermicelles de fougère aigre-piquants', 'Féculents', 'Les vermicelles de fougère aigre-piquants ont une texture lisse et élastique, sont acidulés et épicés pour ouvrir l''appétit. C''est un plat froid familial qui peut aussi être un plat principal. Les vermicelles de fougère sont riches en amidon et en fibres alimentaires, fournissant de l''énergie. Cette recette est très simple, idéale pour les débutants, ne nécessitant que 10 minutes de la préparation à la finition.', '[{"name":"Vermicelles de fougère","note":"quantité suffisante"},{"name":"Huile pimentée","note":"quantité suffisante"},{"name":"Sauce soja","note":"quantité suffisante"},{"name":"Vinaigre aromatique","note":"quantité suffisante"},{"name":"Piments (petits piments)","note":"quantité suffisante"},{"name":"Ail","note":"quantité suffisante"},{"name":"Ciboule","note":"quantité suffisante"},{"name":"Sel","unit":"g"},{"name":"Sucre","unit":"g"}]'::jsonb, '["Ajoutez de l''eau dans une casserole jusqu''à environ 3/5 de sa hauteur, portez à ébullition.","Une fois l''eau bouillante, ajoutez les vermicelles de fougère et faites cuire à feu moyen-doux pendant 8 minutes.","Égouttez.","Selon les proportions, ajoutez la sauce soja, le vinaigre et l''huile pimentée.","Trempez des baguettes et goûtez.","Si vous trouvez que la sauce soja est trop forte, ajoutez le sel préparé.","Si vous pensez que ce n''est pas assez savoureux, ajoutez le sucre préparé.","Mélangez bien jusqu''à ce que la plupart des assaisonnements granulaires soient dissous.","Prenez un bol.","Ajoutez la sauce préparée à l''étape précédente.","Passez les vermicelles de fougère sous l''eau froide, puis mettez-les dans la sauce.","Mélangez bien.","Hachez finement la ciboule, l''ail et les piments, puis saupoudrez sur les vermicelles.","C''est prêt! (｡･∀･)ﾉﾞ"]'::jsonb, '["Plat principal","Aigre-piquant","Salade froide","Rapide","Familial","Appétissant"]'::jsonb),
  ('howtocook:staple/醪糟小汤圆', 'fr', 'Boulettes de riz gluant au vin de riz fermenté', 'Féculents', 'Les boulettes de riz gluant au vin de riz fermenté sont un dessert traditionnel chinois sucré et moelleux. L''acidité légère du vin de riz fermenté se marie avec la douceur du riz gluant, réconfortant l''estomac et l''esprit. Riches en glucides et en vitamines du groupe B, elles fournissent rapidement de l''énergie et favorisent la circulation sanguine. La recette est très simple, idéale pour les débutants. De l''ébullition de l''eau à la mise en plat, il ne faut qu''environ 15 minutes. C''est une soupe sucrée maison facile à réaliser à tout moment.', '[{"name":"Eau","unit":"ml"},{"name":"Petites boulettes de riz gluant","unit":"g"},{"name":"Vin de riz fermenté","unit":"g"},{"name":"Baies de goji","unit":"pièces"},{"name":"Sucre blanc","note":"Quantité suffisante"}]'::jsonb, '["Verser l''eau dans une casserole et porter à ébullition","Ajouter les petites boulettes de riz gluant et cuire 8 minutes","Ajouter le vin de riz fermenté et les baies de goji, puis cuire encore 2 minutes","Verser dans un bol, ajouter du sucre blanc selon le goût personnel et bien mélanger","Déguster"]'::jsonb, '["Plat principal","Sucré et parfumé","Moelleux","Bouilli","Rapide","Fait maison"]'::jsonb),
  ('howtocook:staple/陕西油泼面/陕西油泼面', 'fr', 'Nouilles à l''huile bouillante du Shaanxi', 'Féculents', 'Ce plat de nouilles traditionnel du nord-ouest de la Chine est réputé pour ses nouilles élastiques et sa saveur épicée obtenue en versant de l''huile bouillante. C''est un plat de tous les jours dans les foyers du Shaanxi. Les nouilles sont riches en glucides, accompagnées de légumes verts et de germes de soja, ce qui permet de reconstituer rapidement l''énergie avec un bon équilibre alimentaire. L''ensemble du processus est simple et clair, idéal pour les débutants, et ne nécessite qu''environ 30 minutes de la préparation à l''assiette.', '[{"name":"Nouilles fraîches (de préférence nouilles étirées)","unit":"tige"},{"name":"Sel","unit":"g"},{"name":"Oignon vert","unit":"tige"},{"name":"Ail","unit":"gousse"},{"name":"Poudre de piment sec (ou poudre de piment du Qin)","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Vinaigre de riz noir","unit":"ml"},{"name":"Légumes verts","unit":"g"},{"name":"Germes de soja","unit":"g"},{"name":"Poivre du Sichuan","note":"selon votre goût"},{"name":"Anis étoilé","note":"selon votre goût"},{"name":"Cannelle","note":"selon votre goût"},{"name":"Feuilles de laurier","note":"selon votre goût"},{"name":"Sésame","note":"selon votre goût"}]'::jsonb, '["Pour les nouilles étirées, utilisez un rouleau à pâtisserie (si vous n''en avez pas, vos mains feront l''affaire) pour presser légèrement le haut et le bas, puis saisissez les extrémités gauche et droite et étirez doucement","Coupez l''oignon vert en fines rondelles et hachez l''ail ; réservez","Lavez les légumes verts et les germes de soja (si utilisés)","Dans une casserole, ajoutez suffisamment d''eau, portez à ébullition à feu vif, puis ajoutez 1 g de sel","Ajoutez les nouilles, remuez doucement avec des baguettes pour éviter qu''elles ne collent, faites cuire jusqu''à ce qu''elles remontent à la surface, puis encore 1 à 2 minutes","Dans la dernière minute de cuisson des nouilles, ajoutez les légumes verts et les germes de soja pour les blanchir","Égouttez les nouilles, les légumes verts et les germes de soja, puis placez-les dans un bol","Sur les nouilles, ajoutez successivement la sauce soja légère, le vinaigre de riz noir, l''oignon vert, l''ail haché et la poudre de piment sec (vous pouvez aussi ajouter un peu de sésame)","Dans une poêle, versez l''huile de cuisson, ajoutez le poivre du Sichuan, l''anis étoilé, la cannelle et les feuilles de laurier (si utilisés), faites chauffer à feu doux jusqu''à ce que les épices libèrent leur arôme, puis retirez les épices","Lorsque l''huile atteint 70 % de sa température (commence à fumer légèrement), versez-la rapidement et uniformément sur la poudre de piment dans le bol ; vous devriez entendre un grésillement","Mélangez bien tous les assaisonnements et les nouilles avec des baguettes, puis dégustez"]'::jsonb, '["Plat principal","Shaanxi","Nouilles","Épicé","Rapide","Familial"]'::jsonb),
  ('howtocook:staple/韩式拌饭/韩式拌饭', 'fr', 'Bibimbap coréen', 'Féculents', 'Le Bibimbap coréen est un plat familial coréen coloré et riche en saveurs. La sauce sucrée-épicée enrobe le riz, les légumes, le bœuf et l''œuf coulant, et une fois mélangé, chaque bouchée est satisfaisante. Les légumes variés apportent des vitamines et des fibres, le bœuf et l''œuf fournissent des protéines de qualité, un équilibre nutritionnel. La préparation est simple mais comporte plusieurs étapes de préparation, même un débutant peut le faire calmement. Du début à la table, cela prend environ 45 minutes.', '[{"name":"Riz","unit":"bol"},{"name":"Œuf","unit":"pièce"},{"name":"Rouleaux de bœuf","unit":"rouleau"},{"name":"Pousses de soja","unit":"g"},{"name":"Champignons","unit":"g"},{"name":"Carotte","unit":"pièce"},{"name":"Courgette","unit":"g"},{"name":"Pâte de piment coréenne","unit":"ml"},{"name":"Sprite","unit":"ml"},{"name":"Graines de sésame","unit":"g"},{"name":"Huile de sésame","unit":"ml"},{"name":"Sauce soja","unit":"ml"},{"name":"Sel","note":"quantité suffisante"}]'::jsonb, '["Lavez et coupez les légumes en julienne. Faites-les sauter dans une poêle jusqu''à ce qu''ils soient tendres, puis retirez-les.","Portez de l''eau à ébullition. Blanchissez les rouleaux de bœuf jusqu''à ce qu''ils soient cuits, environ 3 minutes, puis égouttez-les.","Faites cuire un œuf au plat (avec le jaune coulant).","Mettez le riz dans un bol, puis renversez-le dans un grand bol.","Disposez les légumes et les rouleaux de bœuf préparés en cercle sur le riz, placez l''œuf au centre.","Préparez la sauce.","10 ml de pâte de piment coréenne (sucrée-épicée) + 5 ml de sauce soja + 2 bouchons de Sprite (si vous êtes au régime, utilisez du Sprite zero) + 10 g de graines de sésame + 5 ml d''huile de sésame.","Mélangez la sauce ci-dessus. Vous pouvez ajouter plus de sauce soja et de sel.","Versez la sauce préparée sur le plat dressé dans le bol."]'::jsonb, '["Plat principal","Coréen","Sucré-épicé","Fait maison","Accompagne bien le riz","Mélangé"]'::jsonb),
  ('howtocook:staple/韭菜盒子', 'fr', 'Chaussons à la ciboulette', 'Féculents', 'Les chaussons à la ciboulette sont une pâtisserie traditionnelle chinoise, à la croûte dorée et croustillante, avec une garniture juteuse et savoureuse. La ciboulette associée aux crevettes et aux œufs est riche en vitamines et en protéines de qualité. La recette est simple et convient aux débutants : il faut environ 2h30 du pétrissage à la sortie de la poêle.', '[{"name":"ciboulette","unit":"gramme"},{"name":"crevettes décortiquées","unit":"gramme"},{"name":"œuf","unit":"pièce"},{"name":"huile de sésame","unit":"millilitre"},{"name":"sel","unit":"gramme"},{"name":"farine","unit":"gramme"}]'::jsonb, '["Mettez la farine dans un grand bol, ajoutez de l''eau, mélangez jusqu''à obtenir une pâte lisse, laissez reposer 30 minutes.","Lavez et hachez finement la ciboulette, ajoutez les œufs battus et 5g de sel, mélangez bien.","Divisez la pâte en petites portions, étalez-les en cercles fins, garnissez avec le mélange de ciboulette, crevettes et œufs.","Faites chauffer une poêle, ajoutez de l''huile de cuisson, placez les chaussons, faites-les cuire jusqu''à ce qu''ils soient dorés des deux côtés, environ 3-4 minutes.","Dressez sur une assiette, laissez refroidir légèrement et dégustez."]'::jsonb, '["Plat principal","Savoureux","Poêlé","Maison","Pâtisserie chinoise"]'::jsonb),
  ('howtocook:staple/鲜肉烧卖', 'fr', 'Shao Mai à la viande fraîche', 'Féculents', 'C''est une délicatesse raffinée du Jiangnan, avec une peau fine comme du papier et une garniture généreuse et juteuse. En croquant, la saveur de la viande, la fraîcheur des pousses de bambou et le bouillon fondu de la gelée se mélangent, salé avec une touche sucrée, texture tendre et élastique. Le porc et les crevettes fournissent des protéines de qualité, les pousses de bambou d''hiver et les champignons shiitake ajoutent des fibres et des oligo-éléments, la version faible en gras réduit les graisses saturées. Bien que la technique de pliage demande un peu de patience, les étapes sont claires et les débutants peuvent la maîtriser avec de la pratique. De la préparation de la farce à la sortie du cuiseur vapeur, il faut environ une heure.', '[{"name":"Feuilles de shao mai","unit":"g"},{"name":"Viande de porc hachée (3:7 gras/maigre)","unit":"g"},{"name":"Filet de porc ou épaule de porc (version faible en gras)","unit":"g"},{"name":"Gingembre râpé","unit":"g"},{"name":"Oignon vert émincé (parties vertes uniquement)","unit":"g"},{"name":"Sauce soja claire","unit":"mL"},{"name":"Vin de riz","unit":"mL"},{"name":"Sel","unit":"g"},{"name":"Sucre (facultatif)","unit":"g"},{"name":"Poivre blanc moulu (facultatif)","unit":"g"},{"name":"Huile de sésame","unit":"mL"},{"name":"Bouillon","unit":"mL"},{"name":"Cube de bouillon concentré","unit":"g"},{"name":"Pousses de bambou d''hiver (facultatif)","unit":"g"},{"name":"Gelée de peau (facultatif mais recommandé)","unit":"g"},{"name":"Champignons shiitake (facultatif)","unit":"g"},{"name":"Champignons shiitake secs (réhydratés, facultatifs)","unit":"g"},{"name":"Crevettes décortiquées (facultatif)","unit":"g"},{"name":"Épaississant alimentaire composé (version faible en gras)","unit":"g"},{"name":"Fécule de maïs (version faible en gras)","unit":"g"},{"name":"Saindoux (ou graisse de poulet) (version faible en gras)","unit":"g"}]'::jsonb, '["(Version faible en gras) Prendre 10 mL d''eau froide, ajouter l''épaississant alimentaire composé, mélanger pour obtenir une pâte.","(Version faible en gras) Ajouter 25 mL d''eau bouillante, remuer jusqu''à obtenir un gel semi-transparent.","(Version faible en gras) Après refroidissement, incorporer 280 g de viande maigre hachée + 15 g de saindoux fondu (ou graisse de poulet).","Mélanger la viande de porc hachée avec le gingembre râpé et l''oignon vert émincé, ajouter la sauce soja, le vin de riz, le sel, le sucre, le poivre blanc, et remuer dans un sens jusqu''à ce que la farce soit ferme.","Si vous utilisez du bouillon concentré, prendre un cube de bouillon concentré et le mélanger avec 15 mL d''eau chaude, remuer jusqu''à dispersion complète de l''émulsion, puis ajouter 15 mL d''eau à température ambiante.","Ajouter progressivement de l''eau ou du bouillon, continuer à remuer jusqu''à ce que la farce absorbe le liquide et devienne collante. Si la farce semble trop épaisse, ajouter 5 mL d''eau et continuer à remuer.","Ajouter les ingrédients facultatifs (pousses de bambou d''hiver, gelée de peau, champignons shiitake), puis arroser d''huile de sésame et mélanger. Réfrigérer pendant 30 minutes pour que les saveurs se mélangent.","Prendre une feuille de shao mai, déposer environ 20-25 g de farce (ne pas être trop gourmand, sinon elle ne se fermera pas).","Avec le pouce et l''index, refermer doucement les bords de la pâte pour former une forme de ''vase'', en laissant une ouverture sur le dessus.","Avec les doigts, tasser doucement le fond pour assurer la stabilité.","Si vous ajoutez des crevettes, déposer une crevette sur le dessus.","Répéter les étapes de pliage des shao mai jusqu''à épuisement.","Placer dans un panier vapeur en les espaçant pour éviter qu''ils ne collent.","Cuire à la vapeur à feu vif pendant 8 à 10 minutes."]'::jsonb, '["Plat principal","Saveur du Jiangnan","Salé et savoureux","Cuit à la vapeur","Amuse-bouche pour invités","Peau fine et garniture généreuse","Option faible en gras"]'::jsonb),
  ('howtocook:staple/鲣鱼海苔玉米饭/鲣鱼海苔玉米饭', 'fr', 'Riz au thon séché, algue et maïs', 'Féculents', 'C''est un plat japonais simple, savoureux et parfumé. Le riz est bien séparé, mêlant la saveur salée et umami du thon séché, le croustillant des algues et la douceur du maïs. Le thon séché est riche en protéines de haute qualité et en DHA, associé aux minéraux des algues et aux fibres alimentaires du maïs, pour un équilibre nutritionnel. La préparation est très simple, même les débutants peuvent la réaliser facilement. Il ne faut que 5 minutes de travail effectif, et environ 40 minutes au total avec la cuisson du riz.', '[{"name":"Riz","note":"Quantité suffisante"},{"name":"Grains de maïs","unit":"g"},{"name":"Mélange de thon séché et d''algues émiettées","unit":"g"}]'::jsonb, '["Servir le riz dans un bol, ajouter les grains de maïs et mélanger.","Ajouter le mélange de thon séché et d''algues émiettées."]'::jsonb, '["Plat principal","Japonais","Rapide","Savoureux","Maison","Repas simple"]'::jsonb),
  ('howtocook:staple/鹰嘴豆炸饼', 'fr', 'Beignets de pois chiches', 'Féculents', 'Le curry de pois chiches accompagné de pain frit est une spécialité de rue emblématique du nord de l''Inde. Les beignets moelleux avec les pois chiches aux épices offrent une texture riche, à la fois acide, épicée et salée. Les pois chiches sont riches en protéines végétales et en fibres, rassasiants et nutritifs. Les étapes sont un peu nombreuses, mais en suivant le processus, ce n''est pas difficile, adapté à une cuisine maison de niveau intermédiaire. Environ 50 minutes de préparation (les pois chiches doivent être trempés 8 heures à l''avance).', '[{"name":"Pois chiches secs","unit":"g"},{"name":"Oignon","unit":"pièce"},{"name":"Tomate","unit":"pièce"},{"name":"Gingembre","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Piment vert","unit":"pièce"},{"name":"Huile de cuisson (pour le curry)","unit":"ml"},{"name":"Sachet de thé noir (pour colorer les pois chiches)","unit":"pièce"},{"name":"Curcuma en poudre","unit":"g"},{"name":"Piment rouge en poudre","unit":"g"},{"name":"Coriandre moulue","unit":"g"},{"name":"Cumin moulu","unit":"g"},{"name":"Sel (pour le curry)","unit":"g"},{"name":"Garam masala","unit":"g"},{"name":"Poudre de grenade","unit":"g"},{"name":"Jus de citron","unit":"ml"},{"name":"Eau","unit":"ml"},{"name":"Farine tout usage","unit":"g"},{"name":"Yaourt","unit":"ml"},{"name":"Huile de cuisson (pour la pâte)","unit":"ml"},{"name":"Bicarbonate de soude","unit":"g"},{"name":"Sel (pour la pâte)","unit":"g"},{"name":"Eau tiède","unit":"ml"},{"name":"Huile de cuisson (pour la friture)","unit":"ml"},{"name":"Coriandre fraîche","note":"quantité suffisante"},{"name":"Quartiers de citron","note":"quantité suffisante"}]'::jsonb, '["Faire tremper les pois chiches secs dans l''eau claire toute la nuit (au moins 8 heures). Après trempage, le volume doublera environ.","Égoutter les pois chiches trempés.","Les mettre dans une casserole, ajouter 500 ml d''eau et 1 sachet de thé noir (pour la coloration).","Porter à ébullition à feu vif, puis réduire à feu moyen et cuire 25-30 minutes, jusqu''à ce que les pois chiches s''écrasent facilement entre les doigts.","Retirer le sachet de thé et réserver le liquide de cuisson.","Verser 30 ml d''huile de cuisson dans une poêle et chauffer à feu moyen.","Ajouter l''oignon haché et faire revenir jusqu''à ce qu''il soit doré (environ 6-8 minutes).","Ajouter le gingembre et l''ail râpés, faire revenir 1 minute.","Ajouter la tomate hachée, faire revenir jusqu''à ce qu''elle soit complètement fondue et que l''huile se sépare (environ 5 minutes).","Ajouter 3 g de curcuma, 5 g de piment rouge en poudre, 8 g de coriandre moulue, 5 g de cumin moulu, 6 g de sel.","Faire revenir 2 minutes pour libérer les arômes des épices.","Verser les pois chiches cuits avec leur liquide dans la poêle.","Ajouter le piment vert et mélanger.","Porter à ébullition à feu vif, puis réduire à feu doux et laisser mijoter 15-20 minutes, en écrasant quelques pois chiches avec le dos d''une cuillère pour épaissir la sauce.","Ajouter 5 g de garam masala et 3 g de poudre de grenade (ou 15 ml de jus de citron).","Mélanger, puis éteindre le feu et réserver.","Dans un grand bol, mélanger 250 g de farine, 2 g de bicarbonate de soude, 3 g de sel.","Ajouter 60 ml de yaourt et 15 ml d''huile de cuisson.","Ajouter progressivement de l''eau tiède en pétrissant jusqu''à obtenir une pâte lisse et souple (la pâte doit être un peu plus molle qu''une pâte ordinaire).","Couvrir la pâte d''un torchon humide et laisser reposer 30 minutes.","Diviser la pâte en 8 portions égales.","Prendre une portion, huiler légèrement les mains, et étaler en un cercle d''environ 15 cm de diamètre et 3 mm d''épaisseur.","Verser 500 ml d''huile de friture dans une casserole profonde et chauffer à feu moyen-vif jusqu''à environ 180°C.","Glisser délicatement le pain dans l''huile chaude, appuyer légèrement avec une écumoire pour le faire gonfler.","Frire 1-2 minutes, retourner et frire jusqu''à ce que les deux faces soient dorées.","Égoutter et absorber l''excès d''huile avec du papier absorbant.","Réchauffer le curry de pois chiches.","Servir les beignets chauds avec le curry de pois chiches.","Peut être accompagné d''oignons émincés, de piments verts et de quartiers de citron."]'::jsonb, '["Plat principal","Inde du Nord","Rue","Aigre-épicé-salé","Frit","Rassasiant"]'::jsonb),
  ('howtocook:staple/麻油拌面', 'fr', 'Nouilles à l''huile de sésame', 'Féculents', 'La saveur parfumée de l''huile de sésame, associée à la sauce soja foncée et au poivre, donne un goût salé et savoureux. C''est un plat de nouilles simple, économique et rapide. Les nouilles fournissent des glucides, l''huile de sésame contient des acides gras insaturés et de la vitamine E, apportant de l''énergie. Aucune difficulté, même les débutants peuvent le faire, de l''ébullition au mélange en seulement dix minutes.', '[{"name":"eau","unit":"litre"},{"name":"nouilles instantanées","unit":"bloc"},{"name":"huile de sésame","unit":"ml"},{"name":"sauce soja foncée","unit":"g"},{"name":"sel","unit":"g"},{"name":"poivre","unit":"g"},{"name":"sauce soja claire","unit":"g"}]'::jsonb, '["Versez l''eau dans une casserole et portez à ébullition (si vous aimez les nouilles fermes, vous pouvez ajouter 30 g de sel dans l''eau, les nouilles cuites dans de l''eau salée seront plus fermes).","Plongez les nouilles instantanées dans l''eau et faites cuire 3 minutes (ou selon le temps indiqué sur l''emballage).","Lorsque les nouilles commencent à se séparer, remuez-les pour qu''elles cuisent uniformément.","Égouttez les nouilles et versez-les dans un bol.","Ajoutez l''huile de sésame, la sauce soja foncée, le poivre, et éventuellement la sauce soja claire, selon les quantités indiquées ci-dessus.","Mélangez avec des baguettes jusqu''à homogénéité.","Et voilà, des nouilles à l''huile de sésame simples et économiques prêtes !"]'::jsonb, '["Plat principal","Salé et savoureux","Mélangé","Rapide","Maison"]'::jsonb),
  ('howtocook:staple/麻辣减脂荞麦面', 'fr', 'Nouilles de sarrasin épicées minceur', 'Féculents', 'Le bouillon épicé mêle fond de pot-au-feu épicé, beurre de cacahuète et lait, offrant une texture riche et onctueuse avec une saveur relevée. Accompagné de nouilles de sarrasin riches en fibres et de légumes frais, ce plat est peu calorique et rassasiant, idéal pour une période de perte de poids. Pas de difficulté, pas besoin de compétences culinaires, environ 20 minutes du début à la fin.', '[{"name":"Nouilles de sarrasin demi-sèches","unit":"g"},{"name":"Feuilles de chou chinois","unit":"feuille"},{"name":"Feuilles de laitue","unit":"feuille"},{"name":"Beurre de cacahuète","unit":"g"},{"name":"Lait entier","unit":"ml"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Huile de piment","unit":"ml"},{"name":"Vinaigre","unit":"ml"},{"name":"Huile de poivre du Sichuan","unit":"ml"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Laver les feuilles de chou chinois et la laitue, réserver.","Verser 500 ml d''eau dans une casserole, mettre à feu vif, ajouter les nouilles de sarrasin et le chou chinois, attendre l''ébullition.","À ébullition, réduire à feu doux, ajouter le fond de pot-au-feu épicé, le beurre de cacahuète, le lait, la sauce soja claire et l''huile de piment. Cuire 5 minutes après reprise de l''ébullition.","Ajouter la laitue, cuire encore 2 minutes.","Ajouter le vinaigre et l''huile de poivre du Sichuan, éteindre le feu. Déguster directement dans la petite casserole."]'::jsonb, '["Plat principal","Épicé","Savoureux","Rapide","Minceur","Faible en calories","Nouilles bouillies"]'::jsonb),
  ('howtocook:vegetable_dish/上汤娃娃菜/上汤娃娃菜', 'fr', 'Bébé chou chinois au bouillon', 'Plats végétariens', 'Ce bébé chou chinois au bouillon est frais, sucré et savoureux, avec une texture tendre. C''est un plat végétarien familial, particulièrement adapté pendant un régime. Le bébé chou chinois est riche en vitamines et fibres, faible en gras et en calories. L''ajout d''œuf de cent ans et de jambon en conserve rehausse la saveur sans trop alourdir. La difficulté est modérée, les débutants peuvent essayer. De la préparation à la cuisson, cela prend environ 20 minutes.', '[{"name":"Bébé chou chinois","unit":"g"},{"name":"Champignons enoki","unit":"g"},{"name":"Œufs de cent ans","unit":"pièce"},{"name":"Viande de déjeuner (jambon)","unit":"","note":"à votre convenance"},{"name":"Ciboule","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Ail","unit":"g"},{"name":"Sel","note":"à votre convenance"},{"name":"Sucre","note":"à votre convenance"},{"name":"Fécule","note":"à votre convenance"}]'::jsonb, '["Laver le bébé chou chinois, couper en deux dans le sens de la longueur puis en tronçons.","Ciboule: 3g, couper en petits tronçons. Ail: 10g, émincer. Gingembre: 10g, couper en fines lamelles.","Couper les œufs de cent ans en dés, ainsi que le jambon ou la viande de déjeuner en dés (dés de 1 cm).","Laver les champignons enoki et les séparer.","Faire bouillir de l''eau, y plonger le bébé chou chinois pendant dix secondes pour le blanchir, puis égoutter.","Chauffer la poêle à feu vif, ajouter de l''huile, la faire chauffer puis la jeter. Remettre un peu d''huile.","Passer à feu doux, ajouter la ciboule, le gingembre et l''ail, faire revenir jusqu''à ce qu''ils dégagent leur parfum.","Ajouter environ 300g d''eau (juste assez pour couvrir le chou), puis ajouter le bébé chou chinois, les champignons enoki et la viande de déjeuner.","Ajouter les assaisonnements : sauce d''huître, sucre, sel et MSG. Porter à ébullition.","Cuire 3 minutes, puis dresser dans l''assiette : disposer le chou, mettre les œufs de cent ans par-dessus et verser le bouillon.","Bébé chou chinois au bouillon"]'::jsonb, '["Plat végétarien","Léger","Familial","Rapide","Mijoté","Faible en gras","Savoureux"]'::jsonb),
  ('howtocook:vegetable_dish/乾隆白菜/乾隆白菜', 'fr', 'Chou de Qianlong', 'Plats végétariens', 'Le chou de Qianlong est une entrée froide classique de Pékin, à base de cœur de chou chinois déchiré à la main et mélangé à une sauce épaisse de pâte de sésame. Sa saveur aigre-douce et sa texture croquante sont rafraîchissantes et appétissantes. Le chou est riche en vitamines et fibres, tandis que la pâte de sésame apporte des graisses de qualité et du calcium. Aucune cuisson, il suffit de mélanger la sauce et c''est prêt. Idéal pour les débutants, servi en seulement 10 minutes.', '[{"name":"Feuilles tendres de chou chinois","unit":"g"},{"name":"Pâte de sésame","unit":"g"},{"name":"Vinaigre vieilli","unit":"ml"},{"name":"Sucre blanc","unit":"g"},{"name":"Huile de sésame","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Graines de sésame blanc toastées","unit":"g"}]'::jsonb, '["Prendre uniquement les feuilles tendres à l''intérieur du chou chinois (partie jaune), retirer les côtes, et déchirer à la main en morceaux de la taille d''une demi-paume. Ne pas utiliser de couteau (les surfaces déchirées sont rugueuses et retiennent mieux la sauce).","Rincer les feuilles de chou déchirées, puis égoutter soigneusement. L''excès d''eau empêche la sauce d''adhérer.","Dans un bol, ajouter 30 g de pâte de sésame, puis ajouter 45 ml de vinaigre vieilli. Mélanger dans le même sens pour diluer la pâte progressivement jusqu''à ce qu''elle coule en un filet fin. Ne pas mélanger dans les deux sens, car cela ferait ''tourner'' la pâte de sésame.","Ajouter 5 g de sucre blanc à la sauce, bien mélanger. Ajouter 1 g de sel, bien mélanger. Enfin, ajouter 5 ml d''huile de sésame, bien mélanger. Ajouter chaque ingrédient un par un et mélanger après chaque ajout, en vérifiant la consistance.","Verser la sauce uniformément sur les feuilles de chou, puis mélanger délicatement avec les mains pour bien enrober chaque feuille.","Parsemer de graines de sésame blanc toastées, dresser dans une assiette et servir. Si vous avez le temps, laisser reposer 5 minutes pour que les saveurs se mélangent avant de déguster."]'::jsonb, '["Plat végétarien","Saveur pékinoise","Aigre-doux","Entrée froide","Appétissant","Rapide","Fait maison"]'::jsonb),
  ('howtocook:vegetable_dish/凉拌木耳/凉拌木耳', 'fr', 'Salade d''oreilles de bois', 'Plats végétariens', 'Salade d''oreilles de bois, car il y a beaucoup d''aliments secs dans les fournitures distribuées, et les oreilles de bois sont un aliment relativement sain. De plus, la cuisson de cette salade est relativement simple.', '[{"name":"Oreilles de bois séchées","unit":"gramme"},{"name":"Oreilles de bois humides","unit":"gramme"},{"name":"Gousse d''ail","unit":"pièce"},{"name":"Petit piment","unit":"pièce"},{"name":"Sel","unit":"gramme"},{"name":"Sucre","unit":"gramme"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Vinaigre","unit":"ml"},{"name":"Huile de sésame","unit":"ml"},{"name":"Wasabi","unit":"cm"}]'::jsonb, '["Faire tremper les oreilles de bois séchées dans environ 400 ml d''eau pendant 45 minutes. (Si vous utilisez des oreilles de bois humides, sautez cette étape.)","Enlever les parties dures des oreilles de bois trempées (comme sur les images 4, 5, 6) et les laver soigneusement.","Porter de l''eau à ébullition, y mettre les oreilles de bois et les faire cuire à feu vif pendant 1,5 à 2 minutes.","Hacher les gousses d''ail et les petits piments, les mettre dans un bol (de taille moyenne à grande), puis ajouter successivement le sel, le sucre, la sauce soja légère, le vinaigre, l''huile de sésame et le wasabi, dans les quantités indiquées ci-dessus.","Égoutter les oreilles de bois cuites et les ajouter dans le bol de l''étape précédente.","Bien mélanger et servir."]'::jsonb, '["Plat végétarien","Salade","Rapide","Aigre-piquant","Apéritif","Maison"]'::jsonb),
  ('howtocook:vegetable_dish/凉拌油麦菜', 'fr', 'Laitue romaine en salade', 'Plats végétariens', 'Une entrée froide maison rafraîchissante qui coupe la lourdeur. La richesse de la pâte de sésame enrobe le croquant de la laitue romaine, avec des notes aigres-douces, salées et parfumées, très appétissante. La laitue est riche en vitamines et fibres, la pâte de sésame apporte calcium et bonnes graisses, équilibrée. La recette est simple : couper, mélanger, prête en une quinzaine de minutes, idéale pour les débutants et les soirs pressés.', '[{"name":"Laitue romaine","unit":"pièce"},{"name":"Vinaigre","unit":"ml"},{"name":"Sauce soja","unit":"ml"},{"name":"Pâte de sésame","unit":"ml"},{"name":"Huile de sésame","unit":"ml"},{"name":"Sucre blanc","unit":"g"},{"name":"Sauce aux huîtres","unit":"ml"},{"name":"Ail","unit":"tête"},{"name":"Sel","note":"quantité suffisante"}]'::jsonb, '["Écraser l''ail et le hacher finement.","Mettre le vinaigre, la sauce soja, la pâte de sésame, l''huile de sésame, le sucre, la sauce aux huîtres et l''ail haché dans un bol et mélanger uniformément.","Couper la laitue romaine en tronçons de 4 cm maximum.","Mettre la laitue romaine dans un grand saladier, verser la sauce du bol ci-dessus et bien mélanger."]'::jsonb, '["Plat végétarien","Rafraîchissant","Salade","Rapide","Fait maison","Appétissant"]'::jsonb),
  ('howtocook:vegetable_dish/凉拌莴笋/凉拌莴笋', 'fr', 'Laitue asperge marinée', 'Plats végétariens', 'Un petit plat froid maison, croquant et rafraîchissant. La laitue asperge, après marinade, est particulièrement croquante et tendre, avec une légère touche de piquant, très appétissante. Riche en vitamines et fibres alimentaires, peu calorique. Simple à réaliser, idéal pour les débutants. De la préparation à la table, environ vingt minutes. Encore meilleur après un passage au frais.', '[{"name":"Laitue asperge","unit":"pièce"},{"name":"Radis","unit":"pièce"},{"name":"Piment oiseau","unit":"pièce"},{"name":"Gingembre","unit":"tranche"},{"name":"Ail","unit":"gousse"},{"name":"Sel","unit":"g"},{"name":"Huile de cuisson","unit":"ml"}]'::jsonb, '["Éplucher la laitue asperge et la couper en fines lanières. Couper le radis en lanières. Les mettre ensemble dans un grand bol, ajouter du sel et mélanger. Laisser reposer 10 minutes.","Rincer la laitue asperge trempée 1 à 2 fois à l''eau.","Faire bouillir de l''eau dans une casserole, y plonger la laitue asperge, cuire 1 minute, puis égoutter et transférer dans un grand bol.","Faire chauffer de l''huile dans une casserole, ajouter les tranches de gingembre, les gousses d''ail et les piments oiseaux. Faire sauter pendant 30 à 45 secondes, puis verser sur la laitue asperge.","Bien mélanger et servir dans une assiette."]'::jsonb, '["Végétarien","Rafraîchissant","Légèrement épicé","Salade froide","Rapide","Maison","Appétissant"]'::jsonb),
  ('howtocook:vegetable_dish/凉拌豆腐', 'fr', 'Salade de tofu', 'Plats végétariens', 'Cette salade froide est rafraîchissante et délicieuse, riche en protéines végétales et en calcium, faible en gras et saine. Sa préparation est simple et rapide, même un débutant peut la réaliser en seulement 10 minutes.', '[{"name":"tofu","unit":"g"},{"name":"ciboule","unit":"g"},{"name":"ail","unit":"gousse"},{"name":"sauce soja claire","unit":"ml"},{"name":"huile de sésame","unit":"ml"},{"name":"vinaigre","unit":"ml"},{"name":"sucre blanc","unit":"g"},{"name":"huile pimentée","unit":"ml"}]'::jsonb, '["Couper le tofu en petits cubes de 2 cm de côté, réserver.","Ajouter 500 ml d''eau potable dans une casserole et porter à ébullition à feu vif.","Plonger les cubes de tofu et cuire 1 à 2 minutes pour enlever l''odeur de soja et rendre le tofu plus ferme.","Égoutter les cubes de tofu cuits, les égoutter, puis les mettre dans un bol, réserver.","Laver la ciboule, la couper en fines rondelles, réserver.","Peler l''ail et le hacher finement, réserver.","Dans un petit bol propre, ajouter 15 ml de sauce soja claire, 5 ml d''huile de sésame, 5 ml de vinaigre (facultatif), 2 g de sucre blanc (facultatif).","Ajouter l''ail haché.","Mélanger jusqu''à ce que le sucre soit complètement dissous et que la sauce soit homogène.","Verser la sauce préparée uniformément sur les cubes de tofu.","Parsemer de ciboule hachée.","Selon vos goûts, arroser de 5 ml d''huile pimentée (facultatif).","Mélanger délicatement avec des baguettes ou une cuillère, puis servir."]'::jsonb, '["plat végétarien","rafraîchissant","rapide","salade froide","fait maison","faible en gras"]'::jsonb),
  ('howtocook:vegetable_dish/凉拌金针菇', 'fr', 'Champignons enoki en salade', 'Plats végétariens', 'Les champignons enoki en salade sont une entrée froide familiale simple et rapide, avec une texture croquante et lisse, salée-umami et légèrement acidulée. Les champignons enoki sont riches en fibres alimentaires et en plusieurs vitamines, avec un faible apport calorique. La préparation ne nécessite que blanchiment et assaisonnement, idéale pour les débutants et rapide à préparer même en étant pressé. Du début à la fin, il faut environ 10 minutes.', '[{"name":"champignons enoki","unit":"g","note":""},{"name":"oignons verts","unit":"g","note":""},{"name":"ail","unit":"gousse","note":""},{"name":"sauce soja claire","unit":"ml","note":""},{"name":"vinaigre","unit":"ml","note":""},{"name":"sucre blanc","unit":"g","note":""},{"name":"huile de sésame","unit":"ml","note":""},{"name":"huile pimentée","unit":"ml","note":""}]'::jsonb, '["Couper la base des champignons enoki, rincer à l''eau claire, réserver.","Laver les oignons verts, les couper en fines rondelles, réserver.","Peler l''ail, le hacher finement, réserver.","Dans une casserole, ajouter 1000 ml d''eau potable, porter à ébullition à feu vif.","Ajouter les champignons enoki, cuire 1 à 2 minutes jusqu''à ce qu''ils ramollissent.","Égoutter les champignons enoki cuits, les placer dans un grand bol, réserver.","Dans un autre petit bol propre, ajouter 15 ml de sauce soja claire, 10 ml de vinaigre, 3 g de sucre blanc (facultatif), 5 ml d''huile de sésame (facultatif).","Ajouter l''ail haché.","Mélanger bien pour dissoudre le sucre et homogénéiser la sauce.","Verser la sauce préparée uniformément sur les champignons enoki.","Parsemer des oignons verts coupés.","Selon votre goût, arroser de 5 ml d''huile pimentée (facultatif).","Mélanger délicatement avec des baguettes, servir."]'::jsonb, '["végétarien","en salade","familial","rapide","apéritif","rafraîchissant","salé-umami"]'::jsonb),
  ('howtocook:vegetable_dish/凉拌黄瓜', 'fr', 'Salade de concombre', 'Plats végétariens', 'C''est une salade froide maison rafraîchissante et appétissante, avec une texture croquante et une saveur acidulée. Le concombre est riche en eau et en vitamines, ce qui aide à se rafraîchir et à embellir la peau. La préparation est très simple, idéale pour les débutants : il suffit d''écraser, d''assaisonner et de laisser mariner 15 minutes. L''ensemble prend environ 20 minutes.', '[{"name":"concombre","unit":"g"},{"name":"vinaigre"},{"name":"sauce soja"},{"name":"ail","unit":"gousse"},{"name":"sucre blanc","unit":"g"},{"name":"sel"},{"name":"sauce d''huître","unit":"ml"},{"name":"huile de sésame"}]'::jsonb, '["À l''aide d''un couteau, aplatir le concombre en le frappant, puis le couper en morceaux d''environ 3 cm de long.","Mettre les morceaux de concombre dans un bol.","Écraser l''ail et le hacher finement.","Ajouter 5 g de sucre blanc dans le bol, mélanger et laisser mariner 15 minutes (la marinade au sucre donne un meilleur goût et une meilleure couleur, sans flétrir).","Verser successivement le vinaigre, la sauce soja, le sel, la sauce d''huître et l''ail dans le bol, puis mélanger uniformément.","Verser l''huile de sésame dans le bol et mélanger uniformément."]'::jsonb, '["Plat végétarien","Rafraîchissant","Salade froide","Rapide","Maison","Appétissant"]'::jsonb),
  ('howtocook:vegetable_dish/包菜炒鸡蛋粉丝/包菜炒鸡蛋粉丝', 'fr', 'Chou poêlé aux œufs et vermicelles', 'Plats végétariens', 'Le chou poêlé aux œufs et vermicelles est un plat sauté maison savoureux et salé. Les lamelles de chou croquantes et sucrées se mêlent aux vermicelles moelleux et aux œufs tendres, créant une texture riche en couches. Le chou est riche en vitamines et fibres alimentaires, les œufs apportent des protéines de qualité, et la carotte ajoute des nutriments, pour un équilibre entre légumes et protéines. La préparation nécessite de faire tremper les vermicelles à l''avance, les étapes sont nombreuses mais pas compliquées, ce qui représente un défi pour les débutants. De la préparation à la fin, cela prend environ 1 heure 20 minutes.', '[{"name":"Chou","unit":"pièce"},{"name":"Œuf","unit":"pièce"},{"name":"Vermicelle","unit":"paquet"},{"name":"Carotte","unit":"pièce"},{"name":"Huile de colza","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Sauce d''huître","unit":"ml"},{"name":"Oignon vert","unit":"pièce"},{"name":"Ail","unit":"gousse"},{"name":"Piment sec","unit":"pièce"}]'::jsonb, '["Couper la carotte et le chou en lamelles, réserver.","Faire tremper les vermicelles dans l''eau froide pendant 1 heure, puis les mettre dans une casserole avec de l''eau bouillante jusqu''à ce qu''ils soient ramollis, égoutter et réserver.","Casser les œufs dans un bol, ajouter le sel et battre pendant 15 secondes.","Hacher finement l''oignon vert, l''ail et le piment, réserver.","Chauffer l''huile dans la poêle, verser les œufs, les brouiller jusqu''à cuisson, puis les sortir et réserver.","Ajouter de l''huile, mettre l''oignon vert, l''ail et le piment sec, faire revenir 8 secondes.","Ajouter la carotte et les lamelles de chou, faire sauter 30 secondes.","Ajouter les vermicelles.","Ajouter l''assaisonnement : 15 ml de sauce soja claire, 10 ml de sauce soja foncée, 10 ml de sauce d''huître, 2 g de sel.","Ajouter les œufs cuits précédemment, faire sauter environ 15 secondes.","Sortir du feu et dresser."]'::jsonb, '["Plat végétarien","Salé","Sauté","Fait maison","Accompagnement du riz","Rapide"]'::jsonb),
  ('howtocook:vegetable_dish/印度土豆花菜', 'fr', 'Pommes de terre et chou-fleur à l''indienne', 'Plats végétariens', 'Ce plat végétarien indien maison se caractérise par une couleur dorée et sèche, des épices riches, des pommes de terre moelleuses, du chou-fleur légèrement bruni sur les bords. Il est de style nord-indien. Les pommes de terre et le chou-fleur sont riches en fibres et en vitamine C, équilibrés sur le plan nutritionnel. La recette est simple et convient aux débutants. De la préparation à la cuisson, il faut environ 25 minutes.', '[{"name":"Pommes de terre","unit":"pièce"},{"name":"Chou-fleur","unit":"pièce"},{"name":"Oignon","unit":"pièce"},{"name":"Tomate","unit":"pièce"},{"name":"Gingembre","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Piment vert","unit":"pièce"},{"name":"Coriandre","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Graines de cumin","unit":"g"},{"name":"Curcuma en poudre","unit":"g"},{"name":"Piment rouge en poudre","unit":"g"},{"name":"Coriandre en poudre","unit":"g"},{"name":"Garam Masala","unit":"g"},{"name":"Sel","unit":"g"}]'::jsonb, '["Éplucher et couper les pommes de terre en morceaux d''environ 2 cm.","Détacher le chou-fleur en petits bouquets uniformes ; couper les gros bouquets avec un couteau.","Verser 30 ml d''huile de cuisson dans un wok et chauffer à feu moyen.","Lorsque l''huile est chaude, ajouter 3 g de graines de cumin et les faire frire jusqu''à ce qu''elles deviennent foncées et dégagent leur arôme (environ 10 secondes, attention à ne pas brûler).","Ajouter l''oignon haché et faire revenir jusqu''à ce qu''il devienne translucide et légèrement doré (environ 3-4 minutes).","Ajouter le gingembre, l''ail et le piment vert, et faire revenir pendant 1 minute.","Ajouter la tomate hachée et faire revenir jusqu''à ce qu''elle soit ramollie (environ 2-3 minutes).","Ajouter 3 g de curcuma en poudre, 3 g de piment rouge en poudre, 5 g de coriandre en poudre et 5 g de sel.","Faire revenir pendant 1 minute pour bien mélanger les épices avec les légumes.","Ajouter les morceaux de pommes de terre et faire revenir 2 minutes pour les enrober d''épices.","Ajouter les bouquets de chou-fleur et mélanger délicatement.","Couvrir et réduire à feu moyen-doux. Laisser mijoter 12 à 15 minutes en remuant toutes les 3 à 4 minutes pour éviter que ça n''attache.","Lorsque les pommes de terre sont tendres (faciles à transpercer avec une baguette) et que le chou-fleur est légèrement bruni, saupoudrer 3 g de Garam Masala.","Faire revenir pendant 1 minute.","Éteindre le feu, parsemer de feuilles de coriandre et servir."]'::jsonb, '["Végétarien","Inde du Nord","Épicé","Braiser et sauter","Maison","Accompagnement de riz"]'::jsonb),
  ('howtocook:vegetable_dish/印度葫芦丸子', 'fr', 'Boulettes de courge indienne', 'Plats végétariens', 'Ce plat végétarien du nord de l''Inde râpe la courge, la mélange avec de la farine de pois chiche, forme des boulettes, les frit, puis les trempe dans un curry d''oignon et de tomate. L''extérieur est croustillant, l''intérieur moelleux, la sauce est riche et épicée. La courge est rafraîchissante, la farine de pois chiche apporte des protéines végétales et des fibres, ce qui en fait un plat végétarien équilibré et rassasiant. La préparation implique de la friture et de la sauce, un peu d''étapes mais faciles à suivre dans l''ordre, environ 40 minutes au total.', '[{"name":"Courge (calebasse)","unit":"pièce(s)"},{"name":"Farine de pois chiche","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Piment rouge en poudre","unit":"g"},{"name":"Coriandre en poudre","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Oignon","unit":"pièce(s)"},{"name":"Tomate","unit":"pièce(s)"},{"name":"Gingembre","unit":"g"},{"name":"Ail","unit":"gousse(s)"},{"name":"Piment vert","unit":"pièce(s)"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Curcuma en poudre","unit":"g"},{"name":"Piment rouge en poudre","unit":"g"},{"name":"Coriandre en poudre","unit":"g"},{"name":"Cumin en poudre","unit":"g"},{"name":"Garam masala","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Eau","unit":"ml"},{"name":"Coriandre fraîche","unit":"g"}]'::jsonb, '["Peler la courge et la râper finement à l''aide d''une râpe.","Presser à la main l''eau des filaments de courge, le plus possible, sinon les boulettes ne tiendront pas à la friture.","Ajouter aux filaments de courge essorés 80g de farine de pois chiche, 3g de sel, 3g de piment rouge en poudre, 3g de coriandre en poudre.","Mélanger bien à la main, pétrir jusqu''à obtenir une pâte qui ne colle pas aux doigts.","Former des petites boulettes d''environ 3 cm de diamètre, réserver.","Verser 500ml d''huile de cuisson dans une casserole profonde, chauffer à feu moyen jusqu''à environ 170°C (tester avec un petit morceau de pâte qui remonte rapidement et bulle).","Frire les boulettes par lots pendant 4-5 minutes jusqu''à ce qu''elles soient dorées et croustillantes.","Égoutter les boulettes frites sur du papier absorbant, réserver.","Verser 30ml d''huile de cuisson dans une poêle, chauffer à feu moyen 10 secondes.","Ajouter l''oignon haché, faire revenir jusqu''à ce qu''il soit doré (environ 5-7 minutes).","Ajouter le gingembre et l''ail râpés, faire revenir 1 minute jusqu''à ce que les arômes se dégagent.","Ajouter la tomate hachée, faire revenir jusqu''à ce qu''elle soit complètement molle et que l''huile se sépare (environ 5 minutes).","Ajouter 3g de curcuma en poudre, 5g de piment rouge en poudre, 5g de coriandre en poudre, 3g de cumin en poudre, 5g de sel.","Faire revenir 2 minutes pour que les épices se mélangent bien à la tomate.","Ajouter 200ml d''eau, bien mélanger, porter à ébullition puis réduire à feu doux et laisser mijoter 5 minutes.","Déposer délicatement les boulettes frites dans la sauce, laisser mijoter à feu doux 3-5 minutes pour qu''elles absorbent la sauce.","Saupoudrer de 3g de mélange d''épices indien (garam masala) et de piment vert haché.","Éteindre le feu, décorer de feuilles de coriandre fraîche et servir."]'::jsonb, '["Végétarien","Inde du Nord","Épicé","Curry","Plat végétarien","Plat pour invités"]'::jsonb),
  ('howtocook:vegetable_dish/地三鲜/地三鲜', 'fr', 'Trois trésors de la terre', 'Plats végétariens', 'Les Trois trésors de la terre sont un plat familial classique du Nord-Est : l''aubergine est moelleuse, la pomme de terre tendre et parfumée, et le piment vert croquant. La sauce salée et savoureuse accompagne parfaitement le riz. La combinaison d''ingrédients apporte des vitamines et des fibres alimentaires, et la pomme de terre offre une bonne dose de glucides. Ce plat nécessite une friture et un sauté rapide, demandant un certain savoir-faire ; les débutants devront s''exercer un peu. La préparation prend environ 40 minutes.', '[{"name":"Aubergine","unit":"g"},{"name":"Pomme de terre","unit":"g"},{"name":"Piment vert","unit":"pièce"},{"name":"Oignon vert","unit":"g"},{"name":"Gingembre","unit":"g"},{"name":"Ail","unit":"g"},{"name":"Pâte de haricots fermentés (doubanjiang)","unit":"ml"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sucre","unit":"g"},{"name":"Fécule","unit":"g"}]'::jsonb, '["Laver les pommes de terre, l''aubergine et les piments verts.","Éplucher les pommes de terre.","Couper l''aubergine et les pommes de terre en morceaux irréguliers de 15 g chacun.","Déchirer les piments verts à la main en suivant les nervures, en morceaux environ 25% plus grands que ceux de pomme de terre et d''aubergine.","Essuyer autant que possible l''humidité de la surface des piments pour éviter les projections lors de la friture. Utiliser du papier absorbant ou laisser sécher à l''air pendant 30 minutes.","Couper l''oignon vert en petits tronçons de 0,5 cm, prélever 5 g. Hacher l''ail en purée, prélever 15 g et diviser en deux portions de 7,5 g chacune. Hacher le gingembre, prélever 5 g.","Dans un bol vide, mélanger 10 ml de sauce soja légère, 10 g de sucre, 8 g de fécule, et 80 ml d''eau claire. Bien remuer pour obtenir la sauce d''assaisonnement, réserver.","Chauffer la poêle et ajouter 150 ml d''huile.","Ajouter les pommes de terre et les faire frire environ 3-4 minutes, jusqu''à ce qu''elles soient dorées et qu''une baguette les traverse facilement.","Retirer les pommes de terre, laisser l''huile dans la poêle.","Ajouter l''aubergine et la faire frire environ 2-3 minutes, jusqu''à ce qu''elle soit cuite à 70% (molle, bords légèrement brunis et rendant l''excès d''huile).","Retirer l''aubergine, laisser l''huile (il se peut qu''il n''en reste plus).","S''il n''y a plus d''huile liquide dans la poêle, ajouter 15 ml d''huile.","Ajouter les morceaux de piment vert et les faire frire environ 15 secondes, jusqu''à ce que les bords commencent à cloquer, puis retirer immédiatement. Vider l''huile de la poêle.","Remettre la poêle sur le feu et ajouter 15 ml d''huile neuve.","Ajouter 5 g d''oignon vert, 5 g de gingembre et 7,5 g d''ail. Faire revenir à feu moyen-doux jusqu''à ce que les arômes se dégagent.","Ajouter 15 ml de pâte de haricots fermentés (doubanjiang). Passer à feu doux et faire revenir jusqu''à ce que l''huile devienne rouge et que l''arôme de la pâte se libère.","Verser le bol de sauce. Passer immédiatement à feu vif et remuer rapidement pour éviter que cela n''attache ! Après environ 10 secondes, la sauce bouillonnera et épaissira.","Ajouter immédiatement les pommes de terre, l''aubergine et les piments verts préparés.","Faire sauter pendant 20 secondes pour que la sauce épaisse enrobe uniformément les ingrédients.","Éteindre le feu, saupoudrer les 7,5 g d''ail restants. Mélanger et servir."]'::jsonb, '["Plat végétarien","Nord-Est","Familial","Accompagnement du riz","Sauce parfumée","Sauté"]'::jsonb),
  ('howtocook:vegetable_dish/家常日本豆腐', 'fr', 'Tofu japonais maison', 'Plats végétariens', 'Le tofu japonais maison est un plat rapide et facile, croustillant à l''extérieur et tendre à l''intérieur. Une croûte dorée enrobe le tofu soyeux aux œufs, accompagné de poivron vert, carotte et autres légumes. On peut l''assaisonner en version salée-umami ou aigre-douce, pour un goût croustillant et savoureux. Le tofu japonais est principalement à base d''œufs, riche en protéines de qualité, avec du champignon noir et des légumes, pour un repas équilibré. Il faut un peu de technique pour faire frire le tofu, de difficulté modérée, les débutants peuvent essayer. Le tout est prêt en environ 30 minutes.', '[{"name":"Tofu japonais","unit":"g"},{"name":"Poivron vert","unit":"g"},{"name":"Carotte","unit":"g"},{"name":"Jambon","unit":"g"},{"name":"Champignon noir","unit":"g"},{"name":"Fécule de maïs","unit":"g"},{"name":"Oignon","unit":"g"},{"name":"Ail","unit":"g"},{"name":"Huile","unit":"ml"},{"name":"Sauce soja","unit":"ml"},{"name":"Sauce d''huître","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Bouillon de poulet","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Ketchup","unit":"ml"}]'::jsonb, '["Couper la carotte en rondelles, le poivron vert en fines lamelles, hacher l''oignon et l''ail.","Ouvrir le paquet de tofu japonais et le couper en cylindres d''environ 1 cm d''épaisseur.","Mettre la fécule de maïs dans une assiette plate pour préparer l''enrobage.","Poser délicatement le tofu sur la fécule, enrober le dessus, le dessous et les côtés, en évitant de trop en mettre.","Verser 150 ml d''huile dans une poêle, l''huile doit recouvrir la majeure partie du tofu. Quand les bords deviennent dorés, retourner et cuire l''autre côté.","Lorsque les deux côtés sont dorés, les retirer et les réserver dans une assiette propre.","Verser 10-15 ml d''huile dans un wok, ajouter l''oignon et l''ail, faire revenir jusqu''à ce qu''ils soient parfumés, puis ajouter le poivron vert, la carotte, le jambon et le champignon noir.","Ajouter la sauce d''huître, la sauce soja, le sel, le bouillon de poulet, le sucre blanc et le ketchup.","Remuer doucement jusqu''à ce que les couleurs soient uniformes."]'::jsonb, '["Végétarien","Poêlé","Salé-umami","Aigre-doux","Rapide","Accompagnement de riz"]'::jsonb),
  ('howtocook:vegetable_dish/小炒藕丁/小炒藕丁', 'fr', 'Sauté de dés de lotus', 'Plats végétariens', 'Le sauté de dés de lotus est un plat végétarien rapide et familial. Les dés de lotus sont croquants et tendres, avec une saveur salée et umami relevée d''une légère touche piquante, ce qui stimule l''appétit. Le lotus est riche en fibres alimentaires et en vitamines, aide à rafraîchir et à hydrater. Simple à préparer, il suffit de faire attention au blanchiment et à l''assaisonnement, même un débutant peut le réussir facilement. Il faut environ 20 minutes du début à la fin pour le servir.', '[{"name":"poireau chinois","unit":"tronçon"},{"name":"piment Xiaomi","unit":"pièce"},{"name":"racine de lotus","unit":"tronçon"},{"name":"sauce soja claire","unit":"ml"},{"name":"sauce soja foncée","unit":"ml"},{"name":"sauce d''huîtres","unit":"ml"},{"name":"huile de cuisson","unit":"ml"}]'::jsonb, '["Couper le poireau chinois et les piments Xiaomi en petits tronçons, réserver.","Éplucher le lotus, le couper en petits morceaux ne dépassant pas 3 cm, les mettre dans l''eau pour les réserver (pour éviter l''oxydation et le noircissement).","Prendre un wok, y mettre 500 ml d''eau froide, porter à ébullition.","Plonger les dés de lotus dans l''eau bouillante, les blanchir 2 minutes, puis les retirer et les mettre dans une assiette, réserver.","Vider l''eau du wok, le chauffer pour le sécher, ajouter 10-15 ml d''huile de cuisson.","Lorsque l''huile est chaude, ajouter les oignons verts hachés et les piments Xiaomi, les faire revenir jusqu''à ce qu''ils dégagent leur arôme.","Ajouter les dés de lotus préparés dans le wok, les faire sauter à feu vif.","Ajouter la sauce soja claire, la sauce soja foncée et la sauce d''huîtres.","Faire sauter 2 minutes, puis retirer du feu et servir."]'::jsonb, '["Plat végétarien","Salé et umami","Légèrement piquant","Sauté rapide","Familial","Idéal avec du riz"]'::jsonb),
  ('howtocook:vegetable_dish/干锅花菜/干锅花菜', 'fr', 'Chou-fleur à la poêle', 'Plats végétariens', 'Le chou-fleur à la poêle est un plat familial du Hunan, croquant et savoureux, avec du porc grillé parfumé et légèrement épicé. Le chou-fleur est riche en vitamine C et en fibres, associé au porc pour apporter protéines et énergie. La difficulté de préparation est modérée, il faut juste veiller à bien égoutter après blanchiment et à faire revenir le gras du porc. Convient aux débutants ayant quelques bases. De la préparation au service, compter environ 40 minutes.', '[{"name":"chou-fleur","unit":"grammes"},{"name":"poitrine de porc","unit":"grammes"},{"name":"piment","unit":"pièce"},{"name":"sauce soja légère","unit":"ml"},{"name":"sucre blanc","unit":"grammes"},{"name":"ail","unit":"tête"},{"name":"sel","unit":"grammes"},{"name":"huile","unit":"ml"}]'::jsonb, '["Placer les fleurettes de chou-fleur tête en bas dans de l''eau salée légère et laisser tremper 20 minutes. Puis les laver et les séparer en petits bouquets à l''aide d''un petit couteau.","Les blanchir dans l''eau bouillante pendant 1 minute, les sortir et les rincer immédiatement à l''eau froide jusqu''à ce qu''ils soient complètement refroidis. Égoutter et réserver.","Trancher finement la poitrine de porc. Couper l''ail en morceaux et l''écraser avec le plat du couteau. Couper les petits piments rouges en tronçons.","Faire chauffer la poêle avec de l''huile, ajouter le blanc d''oignon vert et faire revenir jusqu''à ce qu''il soit parfumé.","Ajouter les tranches de poitrine de porc dans la poêle, faire sauter à feu moyen jusqu''à ce qu''elles soient colorées de tous les côtés, continuer à faire sauter un moment pour faire fondre une partie de la graisse.","Ajouter les tronçons de piment rouge et le chou-fleur, mélanger quelques fois.","Ajouter 10 ml de sauce soja légère.","Ajouter 5 g de sucre blanc, passer à feu vif et faire sauter sans arrêt pendant 1 minute.","Couper les feuilles d''ail en tronçons, les ajouter dans la poêle, mélanger quelques fois, puis éteindre le feu, couvrir et laisser mijoter 1 minute. C''est prêt."]'::jsonb, '["Légumes","Hunanais","Poêle","Familial","Accompagne le riz","Sec et parfumé"]'::jsonb),
  ('howtocook:vegetable_dish/手撕包菜/手撕包菜', 'fr', 'Chou déchiré', 'Plats végétariens', 'Le chou déchiré est un grand classique de la cuisine du Hunan, aigre-piquant et croquant. Le chou reste tendre et savoureux, la poitrine de porc est parfumée sans être grasse. Il ouvre l''appétit et accompagne parfaitement le riz. Le chou est riche en vitamine C et en fibres, et la poitrine de porc apporte des protéines et de l''énergie. La cuisson nécessite de saisir à feu vif, ce qui peut être un défi pour les débutants, mais en suivant les étapes, vous réussirez. De la préparation à l''assiette, comptez environ 20 minutes.', '[{"name":"chou","unit":"pièce"},{"name":"poitrine de porc","unit":"g"},{"name":"piment de la jungle","unit":"pièce"},{"name":"huile de cuisson","unit":"ml"},{"name":"vin de cuisine","unit":"ml"},{"name":"sauce soja claire","unit":"ml"},{"name":"vinaigre parfumé","unit":"ml"},{"name":"bouillon de poulet","unit":"g"},{"name":"gingembre","unit":"tranche"},{"name":"ail","unit":"gousse"},{"name":"pousses d''ail","unit":"pièce"},{"name":"sel","unit":"g"}]'::jsonb, '["Couper le chou en deux, retirer la partie blanche centrale (voir figure 1)","Déchirer le chou à la main, mettre 2 g de sel dans un bol, laver le chou et égoutter (voir figure 2)","Tranches de gingembre, gousses d''ail, piments de la jungle, pousses d''ail préparés et réservés (voir figure 3)","Trancher la poitrine de porc, laver à l''eau claire et réserver","Ajouter 30 ml d''huile de cuisson dans la poêle, verser le chou et faire sauter à feu vif pendant 1 minute, ajouter 3 g de sel, continuer à faire sauter pendant 2 minutes, puis réserver","Ajouter 30 ml d''huile de cuisson dans la poêle, verser la poitrine de porc, faire sauter à feu vif pendant 1 minute","Ajouter les tranches de gingembre et autres ingrédients, faire sauter 1 minute","Verser le chou et faire sauter, ajouter le vinaigre parfumé, le vin de cuisine, le bouillon de poulet, le vin de cuisine, continuer à faire sauter à feu vif pendant 2 minutes, puis servir"]'::jsonb, '["Légumes","Aigre-piquant","Sauté","Cuisine du Hunan","Accompagne le riz","Fait maison"]'::jsonb),
  ('howtocook:vegetable_dish/拔丝土豆/拔丝土豆', 'fr', 'Pommes de terre caramélisées', 'Plats végétariens', 'Les pommes de terre caramélisées sont un plat classique de la cuisine du Shandong. Elles sont dorées, avec des fils de sucre fins, croustillantes à l''extérieur et moelleuses à l''intérieur, sucrées et parfumées. Les pommes de terre sont riches en glucides et en vitamine C, ce qui permet de reconstituer rapidement l''énergie. Ce plat est assez difficile ; les débutants doivent faire attention au feu de cuisson du sucre pour éviter qu''il ne cristallise ou ne brûle. De la préparation à la cuisson, comptez environ 30 minutes.', '[{"name":"Pommes de terre","unit":"pièce(s)"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Fécule","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Eau","unit":"ml"},{"name":"Graines de sésame","unit":"g"}]'::jsonb, '["Éplucher les pommes de terre et les couper en petits morceaux réguliers. Ajouter la fécule (sans eau) et mélanger pour enrober les pommes de terre.","Chauffer l''huile dans une poêle, ajouter les morceaux de pommes de terre et les faire frire doucement en remuant pendant 5 à 7 minutes, jusqu''à ce qu''une baguette puisse les traverser.","Retirer les pommes de terre et les mettre dans un grand bol.","Ajouter l''eau et le sucre blanc dans la poêle, remuer lentement dans une direction jusqu''à ce que le sucre devienne brun.","Remettre les pommes de terre dans la poêle, faire sauter pendant 30 secondes, puis retirer du feu.","Servir les pommes de terre dans une assiette et saupoudrer de graines de sésame."]'::jsonb, '["Végétarien","Cuisine du Shandong","Caramélisé","Sucré et parfumé","Friture","Maison"]'::jsonb),
  ('howtocook:vegetable_dish/松仁玉米', 'fr', 'Maïs aux pignons de pin', 'Plats végétariens', 'Le maïs aux pignons de pin est un plat familial rapide, croquant et sucré. Les pignons sont croustillants, le maïs est doux et sucré, une saveur domestique typique du nord. L''association maïs et pignons apporte des fibres, des acides gras insaturés et des vitamines. La recette est simple, même les débutants peuvent la réussir. De la préparation à la cuisson, il faut environ quinze minutes.', '[{"name":"Grains de maïs","unit":"g"},{"name":"Pignons de pin grillés","unit":"g"},{"name":"Carotte","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sucre blanc","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Fécule (de maïs)","unit":"g"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Blanchir les grains de maïs et les dés de carotte pendant 1 minute, égoutter et réserver.","Chauffer la poêle avec de l''huile froide, faire revenir les dés de carotte, puis ajouter les grains de maïs et faire sauter.","Ajouter le sucre blanc et le sel, mélanger.","Mélanger l''eau et la fécule pour obtenir une sauce, verser dans la poêle et remuer rapidement pour épaissir légèrement.","Ajouter les pignons de pin grillés et mélanger uniformément.","Servir dans une assiette."]'::jsonb, '["Plat végétarien","Léger","Rapide","Fait maison","Saveur du nord","Sauté"]'::jsonb),
  ('howtocook:vegetable_dish/椒盐玉米/椒盐玉米', 'fr', 'Maïs au poivre et au sel', 'Plats végétariens', 'Une petite collation savoureuse, croustillante à l''extérieur et tendre à l''intérieur, au parfum salé et aromatique, avec la texture sèche typique des restaurants du Sichuan. En croquant, on découvre la douceur naturelle du maïs. Le maïs apporte des glucides et des fibres alimentaires, et avec le sésame, on ajoute de bonnes graisses et de la vitamine E. Cette recette comporte plusieurs étapes mais reste simple, nécessitant un peu de patience pour secouer et enrober de fécule. Elle est adaptée aux débutants. De la décongélation à la sortie du feu, comptez environ 30 minutes.', '[{"name":"Grains de maïs","unit":"g"},{"name":"Fécule","unit":"g"},{"name":"Poivre et sel","unit":"g"},{"name":"Graines de sésame","unit":"g"},{"name":"Huile","note":"Quantité suffisante"},{"name":"Panier en plastique","unit":"pièce"}]'::jsonb, '["Les grains de maïs sont déjà égrenés, il suffit de les décongeler. Faites-les tremper dans de l''eau tiède pendant 15 minutes ou faites-les bouillir dans de l''eau bouillante pendant 5 minutes.","Prenez un panier, appelez-le BoîteA, tapissez-le de papier absorbant, et versez-y les grains de maïs décongelés.","Secouez, secouez, secouez ! Jusqu''à ce que le papier absorbant soit complètement humide.","Prenez un deuxième panier BoîteB, tapissez-le de papier absorbant, et versez tout le maïs de BoîteA dans BoîteB.","Secouez, secouez, secouez ! Jusqu''à ce que le papier absorbant soit complètement humide.","Répétez l''opération plusieurs fois jusqu''à ce qu''il n''y ait plus de gouttes d''eau visibles à la surface du maïs, mais qu''il reste humide.","Versez une grande quantité de fécule, suffisamment pour couvrir complètement les grains de maïs.","Secouez, secouez, secouez ! Jusqu''à ce que la fécule enrobe les grains de maïs.","Allumez le feu - mettez la poêle - versez de l''huile, juste de quoi couvrir le fond, mais pas trop.","Quand l''huile est chaude à 80%, versez les grains de maïs enrobés de fécule.","Faites frire à feu moyen pendant 30 secondes sans remuer, sinon la fécule se détachera.","Remuez doucement pendant 3 minutes, puis retirez du feu.","L''étape la plus importante : saupoudrez de 3 g de poivre et sel, et de graines de sésame !","Le délicieux « maïs au poivre et au sel » est prêt."]'::jsonb, '["Légume","Salé et parfumé","Croustillant","Sichuan","Fait maison","Rapide"]'::jsonb),
  ('howtocook:vegetable_dish/榄菜肉末四季豆/榄菜肉末四季豆', 'fr', 'Haricots verts sautés à la viande hachée et aux olives confites', 'Plats végétariens', 'Les haricots verts sautés à la viande hachée et aux olives confites sont un plat familial typique de la région de Chaoshan, à la fois salé et croustillant, très appétissant avec du riz. Les haricots verts sont riches en fibres alimentaires et en vitamines, associés à la viande hachée pour fournir des protéines de qualité, et les olives confites apportent une saveur umami et salée unique. La recette est claire, même les débutants peuvent la réaliser rapidement, il suffit de bien cuire les haricots verts. De la préparation à la cuisson, environ trente minutes.', '[{"name":"haricots verts","unit":"g"},{"name":"poitrine de porc","unit":"g"},{"name":"olives confites","unit":"g"},{"name":"ail","unit":"g"},{"name":"piment rouge","unit":"g"}]'::jsonb, '["Lavez les haricots verts, retirez les fils, puis coupez-les en petits morceaux de taille uniforme.","Écrasez l''ail et hachez-le finement.","Coupez les piments rouges en petits morceaux de taille uniforme.","Retirez la peau de la poitrine de porc, puis hachez-la finement.","Faites chauffer la poêle, ajoutez 20 ml d''huile pour la lubrifier, puis jetez l''huile chaude. Ajoutez 10 ml d''huile froide : c''est ce qu''on appelle « poêle chaude, huile froide » pour éviter que la viande n''adhère.","Si vous n''avez pas de bouteille d''huile, vous pouvez sauter cette étape : ajoutez directement la viande hachée et faites-la revenir à feu doux pendant deux minutes pour faire fondre la graisse.","Une fois la viande parfumée, ajoutez l''ail, les olives confites et les piments rouges, faites revenir jusqu''à ce que les arômes se dégagent.","Ajoutez les haricots verts et faites-les sauter à feu moyen pendant au moins 5 minutes. Assurez-vous qu''ils sont bien cuits, sinon ils pourraient être toxiques.","Une fois les haricots cuits, versez 2 ml de sauce soja le long du bord de la poêle, puis ajoutez 2 g de sel, 1 g de bouillon de poulet, 1 g de poivre moulu et 0,5 g de sucre.","Mélangez bien les assaisonnements.","Servez et dressez dans une assiette."]'::jsonb, '["légume","salé et savoureux","Chaoshan","appétissant avec du riz","sauté"]'::jsonb),
  ('howtocook:vegetable_dish/水油焖蔬菜', 'fr', 'Légumes étuvés à l''eau et à l''huile', 'Plats végétariens', 'Les légumes étuvés à l''eau et à l''huile sont un accompagnement simple et rapide. En ajoutant quelques gouttes d''huile et des assaisonnements à l''eau bouillante, les légumes feuilles deviennent tendres et brillants, à la fois légers et parfumés. Cette méthode améliore l''absorption des vitamines liposolubles et est plus nutritive que de manger les légumes crus. Peu difficile, elle est idéale pour les débutants ; du lavage à l''assiette, il ne faut qu''environ 10 minutes.', '[{"name":"Légumes à feuilles","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Sauce d''huître","unit":"ml"}]'::jsonb, '["Lavez les légumes.","Ajoutez 150 ml d''eau dans la casserole et portez à ébullition. (L''eau ne doit pas nécessairement recouvrir complètement les légumes.)","Ajoutez 3 g de sel.","(Facultatif) Ajoutez 3 ml de sauce d''huître.","Ajoutez 2 ml d''huile de cuisson.","Ajoutez les légumes, remuez, puis couvrez et laissez étuver 1 minute.","Servez dans un plat."]'::jsonb, '["Légumes","Léger","Étuvé","Rapide","Maison"]'::jsonb),
  ('howtocook:vegetable_dish/油醋爆蛋', 'fr', 'Œufs éclatés à l''huile et au vinaigre', 'Plats végétariens', 'Ce plat de tous les jours, typique du Hunan, est rapide et savoureux. Aigre-doux et épicé, les œufs sont croustillants à l''extérieur et moelleux à l''intérieur, enrobés d''une sauce riche et appétissante. Les œufs apportent des protéines de qualité et de la lécithine, et le vinaigre aromatique stimule l''appétit. La recette est très simple, adaptée aux débutants, et ne prend qu''environ dix minutes de la préparation à l''assiette.', '[{"name":"Œufs","unit":"pièce(s)"},{"name":"Piments oiseaux","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Ciboule","unit":"g"},{"name":"Ail","unit":"g"},{"name":"Vinaigre aromatique","unit":"ml"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Sauce d''huître","unit":"g"},{"name":"Sucre blanc","unit":"g"}]'::jsonb, '["Ne pas battre les œufs, les casser directement dans un bol et réserver.","Couper la ciboule en tronçons de 3 cm.","Mettre les gousses d''ail et les piments oiseaux dans un presse-ail et réduire en purée.","Dans un petit bol, mélanger le vinaigre aromatique, la sauce soja claire, la sauce d''huître, le sucre blanc et l''eau pour obtenir une sauce aigre-douce.","Chauffer l''huile, verser les œufs. Lorsqu''ils sont pris, les couper en gros morceaux. Ajouter la purée d''ail et de piment, puis verser la sauce aigre-douce.","Faire réduire à feu vif. Juste avant de servir, ajouter les tronçons de ciboule."]'::jsonb, '["Plat végétarien","Aigre-doux et épicé","Rapide","Accompagnement de riz","Quotidien","Style hunanais"]'::jsonb),
  ('howtocook:vegetable_dish/洋葱炒鸡蛋/洋葱炒鸡蛋', 'fr', 'Oignons sautés aux œufs', 'Plats végétariens', 'Les oignons sautés aux œufs sont un plat familial savoureux et parfumé, avec des œufs tendres et des oignons sucrés. C''est un accompagnement national. Les œufs sont riches en protéines et en vitamines, les oignons contiennent des fibres et des antioxydants. C''est un plat rapide et équilibré. Très simple, idéal pour les débutants, de la préparation à la cuisson, environ 5 minutes.', '[{"name":"Œufs","unit":"pièce"},{"name":"Oignons","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Ciboule","unit":"tige"},{"name":"Vin de cuisine","unit":"ml"}]'::jsonb, '["Cassez les œufs dans un grand bol, ajoutez les oignons émincés et le sel, puis mélangez pendant 60 secondes.","Faites chauffer l''huile dans une poêle, versez les œufs, faites cuire un côté pendant 30 à 45 secondes, retournez et continuez à faire sauter, répétez pendant 2 à 3 minutes, puis ajoutez le vin de cuisine et retirez du feu.","Dressez les œufs dans une assiette et parsemez de ciboulette."]'::jsonb, '["Plat végétarien","Salé et parfumé","Familial","Rapide","Accompagnement","Sauté"]'::jsonb),
  ('howtocook:vegetable_dish/清炒花菜', 'fr', 'Chou-fleur sauté', 'Plats végétariens', 'Un plat végétarien maison courant, croustillant et rafraîchissant. Riche en vitamine C et en fibres alimentaires. Simple et rapide à préparer, même un débutant peut le réaliser en seulement 15 minutes.', '[{"name":"Chou-fleur","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Sel","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Eau potable","unit":"ml"}]'::jsonb, '["Laver le chou-fleur, le couper en petits bouquets à l''aide d''un couteau ou à la main, trancher les tiges épaisses si nécessaire. Réserver.","Peler l''ail et le couper en lamelles. Réserver.","Ajouter 1000 ml d''eau potable dans une casserole et porter à ébullition à feu vif.","Ajouter les bouquets de chou-fleur et cuire 2 à 3 minutes, jusqu''à ce qu''ils pâlissent et deviennent légèrement tendres.","Égoutter le chou-fleur cuit et réserver.","Chauffer un wok ou une grande poêle, ajouter 15 ml d''huile de cuisson et chauffer à feu vif.","Ajouter les lamelles d''ail et les faire sauter rapidement jusqu''à ce qu''elles soient parfumées.","Ajouter les bouquets de chou-fleur blanchis, réduire à feu moyen-vif et faire sauter rapidement environ 2 minutes, jusqu''à ce qu''ils soient bien chauds.","Ajouter 3 g de sel, mélanger uniformément.","Verser 50 ml d''eau potable le long des bords du wok, couvrir et laisser mijoter 1 minute pour que le chou-fleur soit bien cuit et imprégné des saveurs.","Découvrir, mélanger rapidement et servir."]'::jsonb, '["Légume","Léger","Sauté","Maison","Rapide","Accompagnement"]'::jsonb),
  ('howtocook:vegetable_dish/清蒸南瓜', 'fr', 'Courge cuite à la vapeur', 'Plats végétariens', 'Un plat de légumes cuit à la vapeur qui préserve au maximum le goût sucré naturel et les nutriments de la courge. La texture est moelleuse et sucrée, pouvant être servie en dessert ou en plat principal. La courge est riche en bêta-carotène et en fibres alimentaires, bénéfique pour la vue et la santé intestinale. La préparation est très simple, même les débutants peuvent réussir facilement ; de la découpe à la cuisson, cela ne prend que 15 à 20 minutes.', '[{"name":"Courge","unit":"g"},{"name":"Eau potable","unit":"ml"}]'::jsonb, '["Laver l''extérieur de la courge, retirer la pulpe et les graines.","Couper la courge en tranches d''environ 2 cm d''épaisseur, réserver.","Ajouter 1000 ml d''eau potable dans la casserole du cuiseur vapeur.","Disposer uniformément les tranches de courge dans un plat.","Une fois l''eau du cuiseur vapeur portée à ébullition, placer le plat contenant la courge dans le cuiseur.","Couvrir et cuire à feu vif pendant 15 à 20 minutes, jusqu''à ce que la courge soit tendre et puisse être facilement transpercée avec des baguettes.","Éteindre le feu et retirer délicatement le plat."]'::jsonb, '["Plat végétarien","Léger","À la vapeur","Rapide","Fait maison","Végétalien"]'::jsonb),
  ('howtocook:vegetable_dish/炒滑蛋/炒滑蛋', 'fr', 'Œufs brouillés onctueux', 'Plats végétariens', 'Les œufs brouillés onctueux sont un plat familial classique, tendre et savoureux avec un léger goût de lait. Les œufs sont riches en protéines de haute qualité et en vitamines, nutritifs et faciles à digérer. La recette est très conviviale, même les débutants peuvent la maîtriser facilement. Il faut seulement environ 5 minutes de la préparation à la cuisson, un choix idéal pour un regain d''énergie rapide quand on est pressé.', '[{"name":"Œufs","unit":"pièce(s)"},{"name":"Lait","unit":"ml"},{"name":"Huile de cuisson","unit":"ml"}]'::jsonb, '["Mélanger les œufs avec le lait et 5 ml d''huile de cuisson, réserver.","Chauffer une poêle antiadhésive à feu vif pendant environ 30 secondes, ajouter 5 ml d''huile de cuisson.","Après 30 secondes, réduire le feu à doux et verser le mélange d''œufs.","Laisser reposer dans la poêle pendant 5 secondes, puis pousser lentement les œufs du bord vers le centre avec une spatule.","Faire sauter jusqu''à ce que les œufs soient presque pris, puis éteindre le feu et servir."]'::jsonb, '["Végétarien","Savoureux","Onctueux","Rapide","Familial","Petit-déjeuner"]'::jsonb),
  ('howtocook:vegetable_dish/炒茄子', 'fr', 'Aubergines sautées', 'Plats végétariens', 'Ce plat d''aubergines sautées maison est tendre et savoureux, avec une riche saveur de sauce. L''ajout de badiane (anis étoilé) renforce la saveur. Les aubergines sont riches en fibres alimentaires, vitamine P et potassium, ce qui aide à protéger le système cardiovasculaire. La recette est simple, idéale pour les débutants, cuite à feu vif du début à la fin. Environ vingt minutes de la préparation à la mise en plat.', '[{"name":"Aubergine","unit":"pièce"},{"name":"Badiane (facultatif)","unit":"pièce"},{"name":"Crevettes séchées (facultatif)","unit":"poignée"},{"name":"Oignon vert (facultatif)","unit":"brin"},{"name":"Viande hachée (facultatif)","unit":"g"},{"name":"Sauce soja","unit":"ml"},{"name":"Sucre (facultatif)","unit":"g"},{"name":"Vinaigre (facultatif)","unit":"ml"},{"name":"Huile de colza ou d''arachide","note":"quantité suffisante"}]'::jsonb, '["Laver les aubergines, les couper en deux dans le sens de la longueur. Couper chaque moitié en losanges, puis mettre les morceaux dans un bol.","Laver les oignons verts et les couper en fines rondelles. Les mettre sur une planche à découper.","Couper la badiane (anis étoilé) en morceaux et la mettre sur la planche à découper.","Si vous utilisez de la viande hachée, faites-la revenir dans 10 ml d''huile (15 ml si maigre) à feu moyen jusqu''à ce qu''elle change de couleur (environ 1 minute), puis réservez.","Chauffer la poêle à feu vif jusqu''à ce qu''il n''y ait plus d''eau.","Verser de l''huile de cuisson dans la poêle, deux fois la hauteur du fond (on peut en mettre plus, mais pas moins).","Chauffer l''huile jusqu''à environ 60 % de sa température maximale, puis ajouter les ingrédients optionnels : badiane, crevettes séchées, oignons verts.","Si vous n''avez pas d''ingrédients optionnels, chauffer l''huile jusqu''à 90 %.","Lorsque l''huile atteint 90 % de sa température, verser les aubergines du bol dans la poêle et les faire sauter avec une spatule.","Faire sauter environ 40 secondes, puis suspendre la spatule au-dessus de la poêle, parallèlement à celle-ci, et verser la sauce soja sur la spatule. Compter environ 2,5 spatules par personne (on peut en mettre moins, mais pas trop car c''est salé).","Lorsque les aubergines sont à moitié tendres (environ 1 minute plus tard), remettre la viande hachée précuite et mélanger rapidement.","Si vous souhaitez ajouter du sucre et du vinaigre, les ajouter maintenant.","Continuer à faire sauter.","Lorsque toutes les aubergines ont changé de couleur et sont tendres, les retirer de la poêle."]'::jsonb, '["Plat végétarien","Fait maison","Rapide","Accompagnement de riz","Savoureux","Sauté à feu vif"]'::jsonb),
  ('howtocook:vegetable_dish/炒青菜', 'fr', 'Légumes verts sautés', 'Plats végétariens', 'C''est un plat végétarien maison rafraîchissant et délicieux, avec une texture croquante et tendre, salé et umami avec un arrière-goût sucré. Les légumes verts sont riches en vitamines et fibres alimentaires, ce qui favorise la digestion. La recette est très simple, même les débutants peuvent la maîtriser facilement. De la préparation au service, cela prend environ 10 minutes.', '[{"name":"Légumes verts","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Eau","unit":"ml"},{"name":"Sucre blanc","unit":"g"}]'::jsonb, '["Séparez les légumes verts en petites feuilles, lavez-les à l''eau claire et réservez.","Hachez les gousses d''ail et réservez.","Faites chauffer une poêle à feu moyen-vif, ajoutez 10-15 ml d''huile de cuisson. Attendez 30 secondes pour que l''huile chauffe.","Versez les légumes verts préparés dans la poêle et faites-les sauter jusqu''à ce qu''ils ramollissent (environ 1 minute).","Ajoutez l''ail haché.","Versez la quantité d''eau claire calculée, le niveau doit recouvrir ou presque recouvrir les légumes, ajoutez le sel (2 g), et continuez à faire sauter pendant environ 1 minute.","Enfin, ajoutez le sucre blanc, baissez le feu et chauffez 2 minutes à couvert.","Servez dans une assiette."]'::jsonb, '["Végétarien","Léger","Savoureux","Maison","Rapide","Sauté"]'::jsonb),
  ('howtocook:vegetable_dish/烤茄子/烤茄子', 'fr', 'Aubergines grillées', 'Plats végétariens', 'Les aubergines grillées sont parfumées, croustillantes à l''extérieur et tendres à l''intérieur. Les arômes piquants du cumin et de l''ail se marient parfaitement avec la chair fondante de l''aubergine, reproduisant facilement la saveur des grillades de rue à la maison. Riches en vitamine P et en anthocyanes, les aubergines aident à protéger le système cardiovasculaire et ont des propriétés antioxydantes. La recette nécessite un four, mais les étapes sont claires, et même un débutant peut la réaliser en environ une demi-heure. C''est un plat d''accompagnement rapide et idéal pour un repas en famille.', '[{"name":"Aubergine","unit":"pièce"},{"name":"Huile de cuisson","unit":"millilitre"},{"name":"Sauce soja (claire)","unit":"gramme"},{"name":"Piment rouge","unit":"pièce"},{"name":"Ail","unit":"gousse"},{"name":"Cumin","unit":"gramme"},{"name":"Sel de table","unit":"gramme"}]'::jsonb, '["Mettez la sauce soja, le cumin, le sel, l''ail haché et les piments rouges émincés dans un bol. Mélangez uniformément et réservez.","Lavez l''aubergine et séchez-la avec du papier absorbant.","Piquez 4 à 8 fois un côté de l''aubergine avec une fourchette.","Badigeonnez la surface de l''aubergine avec 15-25 ml d''huile de cuisson.","Préchauffez le four à 200°C (chaleur tournante) pendant 2 minutes.","Placez l''aubergine au milieu ou en haut du four et faites-la cuire 12 à 15 minutes (jusqu''à ce que la peau soit ridée et que vous puissiez enfoncer de 0,3 à 0,5 cm).","Sortez l''aubergine et faites une incision verticale au centre, en laissant 1 à 1,5 cm du haut et du bas.","Insérez un petit couteau ou une fourchette dans l''incision et coupez l''intérieur verticalement.","Écartez légèrement l''incision et versez la sauce préparée à l''étape 1.","Remettez l''aubergine au four à 200°C pendant 4 à 7 minutes.","Sortez l''aubergine et éteignez le four."]'::jsonb, '["Plat végétarien","Ail","Cumin","Grillé","Rapide","Fait maison","Accompagnement"]'::jsonb),
  ('howtocook:vegetable_dish/白灼菜心/白灼菜心', 'fr', 'Cœurs de chou chinois blanchis', 'Plats végétariens', 'Ce plat classique cantonais utilise la technique du blanchiment : une cuisson rapide dans l''eau bouillante préserve la douceur et le croquant des cœurs de chou chinois, notamment les tiges particulièrement rafraîchissantes. Sa saveur est délicate et savoureuse. Riche en vitamine C et en fibres alimentaires, faible en gras et en calories, il est idéal pour ceux qui recherchent une alimentation saine. La préparation est très simple, avec une difficulté estimée à seulement deux étoiles ; même un débutant peut le réaliser en 15 minutes. C''est un choix parfait pour un apport rapide de légumes verts.', '[{"name":"Cœurs de chou chinois frais","unit":"g"},{"name":"Sauce soja","unit":"g"},{"name":"Sauce d''huître","unit":"g"},{"name":"Sel","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Piment oiseau","unit":"pièce"},{"name":"Huile de cuisson","unit":"g"}]'::jsonb, '["Lavez les cœurs de chou chinois et retirez les extrémités dures ou vieilles. Ici, on gratte aussi la partie de la tige avec un couteau pour enlever la couche extérieure dure ; l''intérieur est plus savoureux, mais attention au temps de blanchiment des tiges, sinon elles perdent leur croquant.","Émincez l''ail. Si vous avez un oignon, ajoutez-en un peu.","Préparez la sauce magique : environ 5 g de sauce soja, 5 g de sauce d''huître, ajoutez 3 g de sucre et 100 g d''eau claire (un demi-bol pour obtenir un bol de sauce).","Portez à ébullition 500 ml d''eau avec 5 g de sel et 10 g d''huile de cuisson.","Blanchissez les tiges des cœurs de chou chinois dans l''eau bouillante pendant 1 minute, jusqu''à ce qu''elles deviennent vert foncé. Puis, ajoutez les feuilles et faites cuire encore 1 minute. Égouttez et disposez dans une assiette.","Dans une autre petite casserole, versez la sauce préparée, portez à petite ébullition. Ajoutez la moitié de l''ail émincé, un peu de gingembre en julienne et du piment rouge haché. Pendant la cuisson, on a ajouté un peu d''oignon et d''ail émincés : d''abord, versez un peu d''huile au fond de la casserole, à feu moyen, faites revenir l''ail et l''oignon jusqu''à ce qu''ils dégagent leur parfum, puis ajoutez la sauce et le piment, portez à ébullition.","Laissez la sauce réduire un peu. Après ébullition, attendez environ dix secondes, puis versez-la directement sur les cœurs de chou chinois. N''en mettez pas trop, mais l''ail haché est important, n''en lésinez pas."]'::jsonb, '["Légumes","Cantonais","Blanchi","Léger","Rapide","Familial"]'::jsonb),
  ('howtocook:vegetable_dish/皮蛋豆腐', 'fr', 'Tofu aux œufs de cent ans', 'Plats végétariens', 'Le tofu aux œufs de cent ans est une salade rafraîchissante et apéritive. Les œufs de cent ans sont fermes et tendres, le tofu soyeux fond dans la bouche, et la saveur légèrement salée et acide est particulièrement appétissante avec du riz. Le tofu est riche en protéines végétales de qualité et en calcium, tandis que les œufs de cent ans apportent du fer, de la vitamine A et d''autres nutriments. Ensemble, ils sont faciles à digérer et à assimiler. La préparation est presque sans difficulté, même un débutant peut la réaliser facilement : du début à la mise sur la table, il ne faut qu''environ 5 minutes.', '[{"name":"Œufs de cent ans","unit":"pièce"},{"name":"Tofu soyeux","unit":"boîte"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sucre blanc","unit":"g"},{"name":"Vinaigre (de préférence vinaigre de riz Zhenjiang)","unit":"ml"},{"name":"Huile de sésame (facultatif)","unit":"ml"},{"name":"Huile de piment (facultatif)","unit":"ml"},{"name":"Cacahuètes concassées (facultatif)","unit":"g"},{"name":"Ciboule émincée (facultatif)","unit":"g"},{"name":"Coriandre (facultatif)","unit":"branche"}]'::jsonb, '["Commencez par écaler les œufs de cent ans et coupez-les en quatre quartiers.","Coupez le tofu soyeux en morceaux ou en tranches et disposez-les au milieu.","Mélangez la sauce soja légère, le sucre blanc, le vinaigre, l''huile de sésame et l''huile de piment pour faire une sauce, puis versez-la sur le dessus.","Enfin, saupoudrez éventuellement de cacahuètes concassées, de ciboule et de coriandre."]'::jsonb, '["Plat végétarien","Salade","Rapide","Fait maison","Rafraîchissant","Accompagnement de riz"]'::jsonb),
  ('howtocook:vegetable_dish/糖拌西红柿/糖拌西红柿', 'fr', 'Tomates au sucre', 'Plats végétariens', 'C''est une salade froide maison idéale pour l''été, aigre-douce et rafraîchissante, simple à préparer. Les tomates sont riches en vitamine C, ouvrent l''appétit et sont dégraissantes. Même les débutants peuvent la réaliser facilement. Le processus entier (y compris la réfrigération) prend environ 15 minutes avant de servir.', '[{"name":"Tomates","unit":"Pièce"},{"name":"Sucre blanc","unit":"Gramme"}]'::jsonb, '["Avec un couteau, inciser la peau des tomates en forme de croix.","Insérer une baguette dans le fond de la tomate (le côté opposé à la tige), et la faire tourner au-dessus d''une flamme de gaz pendant 10 secondes (ou l''arroser d''eau bouillante pendant 30 secondes), jusqu''à ce que la peau se détache et se boursoufle.","Retirer complètement la peau des tomates.","Couper chaque tomate en huit morceaux (en suivant les rainures pour conserver plus de jus), retirer la partie dure du sommet (le pédoncule), et réserver.","Une fois toutes les tomates coupées, les disposer en une couche uniforme dans un plat.","Saupoudrer de sucre blanc, puis répéter l''étape précédente jusqu''à avoir placé toutes les tomates.","Placer au réfrigérateur pendant 10 minutes.","Un plat de tomates au sucre est prêt. Nutritif et délicieux, aigre-doux et rafraîchissant, parfait pour se rafraîchir et dégraisser en été."]'::jsonb, '["Végétarien","Aigre-doux","Salade froide","Maison","Rapide","Rafraîchissant"]'::jsonb),
  ('howtocook:vegetable_dish/红烧冬瓜/红烧冬瓜', 'fr', 'Courge celtique braisée', 'Plats végétariens', 'La courge celtique braisée est un plat végétarien maison, rouge et brillant, parfumé et savoureux, avec une texture tendre et fondante. C''est un plat chinois braisé très apprécié. La courge celtique est riche en eau, en fibres et en vitamine C, elle aide à éliminer la chaleur et à diurétique. Avec des assaisonnements simples, ce plat est nutritif et facile à digérer. Cette recette convient aux débutants, les étapes sont claires, il suffit de maîtriser le feu et l''assaisonnement. Le temps de préparation est d''environ 25 minutes.', '[{"name":"Courge celtique","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Vin de cuisine","unit":"ml"},{"name":"Amidon","unit":"g"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Bouillon de poule en poudre","unit":"g"},{"name":"Ciboule","unit":"tige"},{"name":"Gingembre haché","unit":"pièce"},{"name":"Sauce d''huîtres","unit":"ml"}]'::jsonb, '["Peler la courge celtique, couper en petits cubes de côté ne dépassant pas 2 cm","Faire chauffer l''huile dans une poêle, ajouter la courge celtique, remuer doucement et faire frire pendant 2 minutes jusqu''à ce que la surface soit dorée","Retirer la courge celtique et la mettre dans un grand bol pour réserver","Utiliser l''huile restante dans la poêle, ajouter successivement le gingembre haché, la sauce soja légère et la sauce d''huîtres, faire sauter pendant 15 s","Remettre la courge celtique, faire sauter 30 s, puis ajouter de l''eau bouillante pour couvrir la surface de la courge, cuire à feu vif pendant 10 minutes","Ajouter la sauce soja foncée pour colorer, continuer à cuire jusqu''à ce que la courge soit tendre (des baguettes peuvent s''enfoncer facilement)","Ajouter le bouillon de poule en poudre, le vin de cuisine et la ciboule, faire sauter 30 s, puis retirer la courge dans le grand bol","Conserver le jus restant dans la poêle, ajouter la fécule délayée dans l''eau, porter à ébullition puis verser le jus sur la courge"]'::jsonb, '["Plat végétarien","Braisé","Salé et umami","Fait maison","Rapide","Fondant"]'::jsonb),
  ('howtocook:vegetable_dish/红烧茄子', 'fr', 'Aubergines braisées', 'Plats végétariens', 'Les aubergines braisées sont un plat familial salé et savoureux, idéal pour accompagner le riz. Les morceaux d''aubergine tendres et moelleux absorbent la sauce, accompagnés de poivrons verts et de tomates, offrant une saveur aigre-douce et légèrement piquante. L''aubergine est riche en fibres alimentaires et en vitamine P, et les morceaux frits sont parfumés sans être gras. La préparation nécessite de les enrober de pâte, de les frire, puis de les mijoter doucement pour les imprégner de saveur. Bien que les étapes soient un peu nombreuses, les débutants peuvent essayer ; avec une attention aux détails, on peut réussir. De la préparation à la cuisson, cela prend environ 45 minutes.', '[{"name":"ail","unit":"gousse"},{"name":"oignon vert","unit":"pièce"},{"name":"poivron vert","unit":"pièce"},{"name":"oignon","unit":"pièce"},{"name":"tomate","unit":"pièce"},{"name":"aubergine verte","unit":"pièce"},{"name":"sel","note":"à volonté"},{"name":"sauce soja","note":"à volonté"},{"name":"œuf","unit":"pièce"},{"name":"farine","unit":"g"},{"name":"fécule","note":"à volonté"}]'::jsonb, '["Laver l''aubergine verte, le poivron vert, la tomate, l''oignon et l''oignon vert.","Couper l''oignon vert en ciboule de 5 mm de large, éplucher et écraser l''ail, couper la tomate en morceaux de 6 cm³, couper le poivron vert et l''oignon en morceaux de 5 g.","Couper l''aubergine en losanges (d''abord en tranches de 2 cm d''épaisseur, puis en bâtonnets de 2 cm, enfin en morceaux en coupant en diagonale).","Verser la farine dans un bol, ajouter petit à petit un peu d''eau, mélanger jusqu''à obtenir une pâte épaisse et collante.","Ajouter la fécule, ajouter 30 g d''eau, mélanger uniformément.","Casser l''œuf dans le bol, ajouter (farine / 20) g de sel, mélanger uniformément.","Verser les morceaux d''aubergine dans la pâte, mélanger pour que chaque face soit enrobée de pâte.","Chauffer à feu vif, ajouter 500 ml d''huile. Lorsque l''huile commence à fumer, passer à feu doux. Placer les morceaux d''aubergine un par un dans l''huile avec des baguettes. Une fois tous les morceaux ajoutés, passer à feu moyen. Frire jusqu''à ce qu''ils soient dorés, puis les retirer et vider l''huile.","Ajouter 5 g d''huile, mettre l''ail et la ciboule, faire sauter 15 secondes, ajouter les morceaux de poivron vert, faire sauter 30 secondes, ajouter la tomate, faire sauter 30 secondes.","Ajouter les aubergines frites, ajouter de l''eau jusqu''à 0,8 fois la hauteur des ingrédients dans la casserole.","Ajouter la sauce soja et 3 g de sel.","Attendre que la sauce soit épaisse (le niveau d''eau est d''environ 0,2 à 0,3 fois la hauteur des ingrédients restants), découvrir, servir et éteindre le feu."]'::jsonb, '["végétarien","salé","braisé","familial","accompagnement riz","frit"]'::jsonb),
  ('howtocook:vegetable_dish/素炒豆角', 'fr', 'Haricots verts sautés végétariens', 'Plats végétariens', 'C''est un sauté maison à la sauce parfumée, les haricots verts sont tendres et savoureux, légèrement épicés, parfait avec du riz. Riches en fibres alimentaires et en vitamines, ils aident à la digestion. La recette est simple, même les débutants peuvent la réussir, de la préparation à la cuisson environ 20 minutes.', '[{"name":"Haricots verts","unit":"g"},{"name":"Piments rouges","unit":"pièce"},{"name":"Oignon vert","unit":"rondelle"},{"name":"Ail","unit":"gousse"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Sauce soja foncée","unit":"ml"},{"name":"Sauce d''huître","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Huile","unit":"ml"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Hacher l''oignon vert, hacher l''ail, réserver.","Mélanger la sauce soja claire, la sauce soja foncée, la sauce d''huître et le sel pour faire la sauce, réserver.","Couper les piments rouges en rondelles, réserver.","Enlever les fils des haricots verts, couper en biais à 45° en morceaux de 4-10 cm, réserver.","Chauffer l''huile dans une poêle (10-15 ml), lorsqu''elle fume, ajouter l''oignon vert et les piments, faire revenir jusqu''à ce qu''ils dégagent une odeur parfumée.","Ajouter les haricots verts, faire sauter 30 secondes.","Ajouter la sauce, faire sauter à feu vif pendant 2 minutes.","Verser 150 ml d''eau.","Baisser le feu à moyen-doux, couvrir et laisser mijoter 8-10 minutes.","Ajouter l''ail haché, servir."]'::jsonb, '["Plat végétarien","Savoureux","Sauté végétarien","Accompagnement riz","Rapide","Maison"]'::jsonb),
  ('howtocook:vegetable_dish/脆皮豆腐', 'fr', 'Tofu croustillant', 'Plats végétariens', 'Le tofu croustillant est croustillant à l''extérieur et tendre à l''intérieur, avec une sauce salée-sucrée bien équilibrée. C''est un plat rapide et savoureux qui accompagne bien le riz. Le tofu est riche en protéines végétales et en calcium, et l''œuf fournit des protéines de haute qualité, offrant un bon équilibre nutritionnel. La préparation demande de la patience pour obtenir une croûte dorée et croustillante, mais les étapes sont claires, même les débutants peuvent réussir. L''ensemble prend environ 30 minutes.', '[{"name":"Tofu ferme","unit":"pièce"},{"name":"Œuf","unit":"pièce"},{"name":"Sauce soja claire","unit":"g"},{"name":"Sauce soja foncée","unit":"g"},{"name":"Sauce d''huître","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Fécule de maïs","unit":"g"},{"name":"Huile de cuisson","unit":"ml"}]'::jsonb, '["Battre l''œuf pour former une omelette liquide et réserver.","Préparer la sauce (20 g de sauce soja claire + 10 g de sauce huître + 5 g de sauce soja foncée + 10 g de sucre blanc + 10 g de fécule de maïs + 200 ml d''eau).","Couper le tofu ferme en tranches (conseil personnel, pour information : 5 tranches par personne, épaisseur 1,2 cm).","Verser la fécule de maïs dans une assiette. Enrober les tranches de tofu de fécule, puis les tremper dans l''œuf battu, et réserver.","Chauffer la poêle et y verser 18 ml d''huile de cuisson. Attendre 10 secondes pour que l''huile chauffe.","Disposer uniformément les tranches de tofu enrobées d''œuf dans la poêle, couvrir le fond, et faire revenir à feu doux jusqu''à ce qu''elles soient dorées, puis les retourner.","Une fois les deux faces dorées, verser la sauce, en badigeonnant chaque morceau de tofu. Cuire à feu vif pendant 3 minutes jusqu''à ce que la sauce épaississe.","Éteindre le feu."]'::jsonb, '["Plat végétarien","Salé-sucré","Poêlé","Maison","Accompagnement de riz","Rapide"]'::jsonb),
  ('howtocook:vegetable_dish/芹菜拌茶树菇/芹菜拌茶树菇', 'fr', 'Salade de céleri et champignons de saule', 'Plats végétariens', 'C''est une salade fraîche et croquante, où le céleri croquant et la texture moelleuse des champignons de saule se complètent harmonieusement, offrant une riche palette de textures. Riche en vitamines et minéraux, nutritive et appétissante. La préparation est très simple, même un débutant peut la réaliser facilement, il faut environ 30 minutes de la préparation au plat final.', '[{"name":"Champignons de saule Minxing","unit":"bouteille"},{"name":"Céleri","unit":"grammes"},{"name":"Huile de sésame","unit":"ml"},{"name":"Sauce d''huître","unit":"ml"},{"name":"Sauce soja","unit":"ml"},{"name":"Sel de table","unit":"grammes"}]'::jsonb, '["(Si vous utilisez du céleri jeune, sautez cette étape) Faites bouillir une bouilloire d''eau chaude, réservez.","Pour le céleri frais (jeune ou non), retirez les feuilles jaunes, lavez et réservez.","(Si vous utilisez du céleri jeune, sautez cette étape) Séparez les feuilles de céleri et mettez-les dans un bol à part. Coupez les tiges de céleri en lanières de 2-3 mm de large à l''aide d''un couteau. Réservez. Cette étape permet de blanchir le céleri plus rapidement et uniformément, et de le rendre plus croquant.","Coupez le céleri jeune en tronçons de 4 cm, réservez.","(Si vous utilisez du céleri jeune, sautez cette étape) Mettez une casserole sur le feu, versez l''eau chaude de la bouilloire et portez à ébullition.","(Si vous utilisez du céleri jeune, sautez cette étape) Plongez les lanières de céleri dans l''eau bouillante pour les blanchir. Après environ 20 secondes, ajoutez les feuilles de céleri. 5 secondes plus tard, éteignez le feu, égouttez le tout et passez sous l''eau froide. Réservez.","Saupoudrez le céleri blanchi (ou le céleri jeune) avec le sel, l''huile de sésame, la sauce d''huître et la sauce soja. Mélangez bien.","Ajoutez les champignons de saule dans le saladier et mélangez bien.","Dressez dans une assiette.","Dégustez."]'::jsonb, '["Plat végétarien","Salade","Léger","Rapide","Appétissant","Maison"]'::jsonb),
  ('howtocook:vegetable_dish/茄子炖土豆', 'fr', 'Aubergines mijotées avec pommes de terre', 'Plats végétariens', 'Les aubergines mijotées avec pommes de terre sont un plat familial du Nord-Est de la Chine, tendres et savoureuses, avec une légère pointe de piquant du piment et de l''ail, parfait pour accompagner le riz. Les aubergines sont riches en anthocyanes et en fibres alimentaires, les pommes de terre fournissent des glucides et de la vitamine C, et le porc apporte des protéines, ce qui en fait un repas équilibré et rassasiant. La préparation est simple, mais nécessite de maîtriser le feu pour la cuisson et la réduction, ce qui peut être un défi pour les débutants. La difficulté estimée est moyenne. Du début à la fin, il faut environ 45 minutes.', '[{"name":"Aubergine","unit":"pièce"},{"name":"Pomme de terre","unit":"pièce"},{"name":"Viande","unit":"g"},{"name":"Piment vert","unit":"g"},{"name":"Sauce soja","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Eau","note":"quantité suffisante"}]'::jsonb, '["Lavez les aubergines, les pommes de terre et les piments. Pelez l''ail et écrasez-le.","Coupez les aubergines et les pommes de terre en morceaux d''environ 6 cm de côté. Coupez les piments en petits morceaux de 5 g. Coupez la viande en lanières de 3 cm.","Allumez le feu, faites chauffer la poêle, ajoutez 13 ml d''huile.","Quand l''huile commence à fumer légèrement, ajoutez les piments.","Une fois le parfum des piments dégagé, ajoutez immédiatement la viande et faites-la revenir à la spatule pendant 30 secondes.","Ajoutez les pommes de terre et faites revenir 30 secondes.","Ajoutez les aubergines et faites revenir 30 secondes.","Ajoutez la sauce soja et le sel, continuez à remuer pendant 5 minutes.","Ajoutez de l''eau jusqu''à ce que le niveau d''eau atteigne 0,9 fois la hauteur des ingrédients dans la poêle, puis couvrez.","Attendez que le niveau d''eau soit réduit à 0,1 fois la hauteur des ingrédients, puis découvrez, ajoutez l''ail, mélangez bien et éteignez le feu."]'::jsonb, '["Plat de légumes","Nord-Est","Familial","Mijoté","Salé et parfumé","Accompagnement de riz","Légèrement épicé"]'::jsonb),
  ('howtocook:vegetable_dish/莴笋叶煎饼/莴笋叶煎饼', 'fr', 'Galette de feuilles de laitue', 'Plats végétariens', 'La galette de feuilles de laitue est un snack maison simple et rapide, avec une texture croustillante à l''extérieur et tendre à l''intérieur, et une saveur fraîche des feuilles de laitue. Les feuilles de laitue sont riches en vitamines et en fibres alimentaires, associées à des œufs pour compléter les protéines de haute qualité, une nutrition équilibrée. Le processus de fabrication ne nécessite aucune technique complexe, il suffit de mélanger et de faire frire des deux côtés, même les débutants peuvent facilement le maîtriser. Il ne faut qu''environ 10 minutes de la préparation à la cuisson.', '[{"name":"feuilles de laitue","unit":"g"},{"name":"œufs","unit":"pièce"},{"name":"huile de cuisson","unit":"ml"},{"name":"sauce soja légère","unit":"ml"},{"name":"fécule","unit":"g"},{"name":"bouillon de volaille","unit":"g"}]'::jsonb, '["Hacher les feuilles de laitue, ajouter les œufs, la fécule, la sauce soja légère et le bouillon de volaille, mélanger uniformément et réserver.","Chauffer l''huile dans une poêle, verser la pâte de feuilles de laitue et l''étaler uniformément sur la surface de la poêle.","Faire frire le premier côté pendant 120 secondes, puis retourner et faire frire l''autre côté pendant 60 secondes, puis retirer de la poêle."]'::jsonb, '["végétarien","rapide","fait maison","poêlé","léger","nutritif"]'::jsonb),
  ('howtocook:vegetable_dish/菠菜炒鸡蛋/菠菜炒鸡蛋', 'fr', 'Épinards sautés aux œufs', 'Plats végétariens', 'Les épinards sautés aux œufs sont un plat familial rapide, léger et savoureux. Les épinards sont tendres, les œufs sont parfumés, et ce plat est apprécié dans toute la Chine. Les épinards sont riches en fer, acide folique et vitamines, tandis que les œufs fournissent des protéines de haute qualité et de la lécithine, ce qui est bénéfique pour enrichir le sang et renforcer la constitution. La préparation est simple, idéale pour les débutants, et prend environ 15 minutes de la préparation à la cuisson.', '[{"name":"Épinards","unit":"g"},{"name":"Œufs","unit":"pièce"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sel de table","unit":"g"}]'::jsonb, '["Retirer les racines des épinards, les laver, les placer dans un panier et les blanchir.","Casser les œufs dans un bol et les battre.","Chauffer la poêle, ajouter 10 ml d''huile.","Une fois l''huile chaude, verser les œufs battus et les faire sauter à feu moyen pendant 15 secondes, d''abord en formant une omelette, puis la couper en petits morceaux avec une spatule.","Éteindre le feu, mettre les morceaux d''œufs dans une assiette, ne pas laver la poêle.","Rallumer le feu, ajouter 5 ml d''huile. Une fois l''huile chaude, ajouter les épinards et les faire sauter à feu vif pendant 15 secondes, puis ajouter les morceaux d''œufs et mélanger.","Ajouter 5 g de sel et 100 ml d''eau potable, faire sauter à feu vif pendant 10 secondes.","Éteindre le feu, servir dans une assiette."]'::jsonb, '["plat végétarien","léger","savoureux","rapide","familial","sauté"]'::jsonb),
  ('howtocook:vegetable_dish/葱煎豆腐', 'fr', 'Tofu poêlé à la ciboule', 'Plats végétariens', 'Croustillant à l''extérieur et tendre à l''intérieur, riche en arôme de ciboule, salé et légèrement épicé, c''est un plat familial. Le tofu est riche en protéines végétales et en calcium, accompagné de piment vert et de ciboule, équilibré. Difficulté modérée, il faut maîtriser le feu doux pour poêler le tofu. Même un débutant peut réussir en suivant les étapes patiemment. Temps total environ 30 minutes.', '[{"name":"Tofu blanc","note":"quantité suffisante"},{"name":"Ciboule","unit":"pièce"},{"name":"Piment vert","unit":"pièce"},{"name":"Sel","unit":"g"},{"name":"Bouillon de poule","unit":"g"},{"name":"Huile","unit":"ml"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Laver le tofu. Couper en tranches d''environ 5 mm d''épaisseur, disposer dans une assiette.","Laver la ciboule, enlever les racines, couper en fines rondelles, réserver.","Laver le piment, couper en deux, retirer les graines, couper en dés de 1 cm, réserver.","Chauffer la poêle, ajouter 9 ml d''huile.","Une fois l''huile dans la poêle, répartir uniformément sur le fond, disposer le tofu uniformément, cuire à feu doux jusqu''à ce qu''il soit doré, puis retourner.","Lorsque les deux faces sont dorées, transférer dans une assiette et réserver.","Ajouter de l''huile pour couvrir le fond de la poêle, verser le piment et faire sauter à feu vif en écrasant avec la spatule pendant 3 minutes.","Verser le tofu, mélanger, ajouter le sel et le bouillon de poule, faire sauter à feu moyen pendant 1 minute, puis verser 10 ml d''eau et faire réduire à feu vif.","Avant de retirer du feu, saupoudrer de la ciboule réservée, puis servir dans un plat."]'::jsonb, '["Plat végétarien","Salé et légèrement épicé","Poêlé","Familial","Accompagnement de riz","Rapide"]'::jsonb),
  ('howtocook:vegetable_dish/蒜蓉空心菜/蒜蓉空心菜', 'fr', 'Liseron d''eau à l''ail', 'Plats végétariens', 'Le liseron d''eau à l''ail est un plat maison rapide, croquant et rafraîchissant, avec une forte saveur d''ail. Il s''agit d''un plat sauté typique du Sichuan. Le liseron d''eau est riche en fibres alimentaires, vitamines et calcium, ce qui favorise le transit intestinal. La recette est très simple, idéale pour les débutants, de la préparation à la cuisson, cela prend environ 15 minutes.', '[{"name":"Liseron d''eau","unit":"g"},{"name":"Ail haché","unit":"gousse"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Sauce soja légère","unit":"ml"}]'::jsonb, '["Lavez le liseron d''eau, retirez les feuilles abîmées ou les tiges dures, coupez-le uniformément en 2 ou 3 segments (pour éviter qu''il ne soit trop long à faire sauter).","Versez d''abord un peu d''huile dans la poêle, chauffez jusqu''à ce qu''elle fume légèrement, puis inclinez la poêle pour répartir l''huile chaude uniformément sur le fond, puis ajoutez le reste de l''huile (méthode de la poêle chaude et de l''huile froide).","Ajoutez l''ail haché, faites-le revenir à feu doux pendant 10 à 15 secondes pour le faire parfumer.","Ajoutez rapidement le liseron d''eau uniformément, passez à feu vif, avec une spatule dans la main gauche et des baguettes dans la droite, remuez constamment le liseron d''eau jusqu''à ce qu''il ramollisse et devienne vert.","Ensuite, sans utiliser les baguettes, utilisez la spatule pour faire sauter rapidement le liseron d''eau ramolli pendant 15 à 20 secondes, pour qu''il chauffe uniformément, saupoudrez 2 g de sel, 3 g de sucre blanc, 8 ml de sauce soja légère.","Continuez à faire sauter à feu vif pendant 10 secondes, puis servez."]'::jsonb, '["Plat végétarien","À l''ail","Léger","Style sichuannais","Rapide","Maison","Sauté"]'::jsonb),
  ('howtocook:vegetable_dish/蒜蓉西兰花', 'fr', 'Brocoli à l''ail', 'Plats végétariens', 'Ce plat de légumes maison se distingue par son goût prononcé d''ail et son assaisonnement simple. Le brocoli blanchi est tendre ou légèrement croquant, léger et savoureux. Riche en vitamine C, en fibres alimentaires et en antioxydants, c''est un plat végétarien rapide et équilibré. La préparation est facile, même pour les débutants, et prend environ 15 minutes de la préparation à la cuisson.', '[{"name":"Brocoli","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sauce d''huître","unit":"ml"},{"name":"Sucre blanc","unit":"g"}]'::jsonb, '["Coupez le brocoli en petits bouquets et lavez-les.","Épluchez l''ail et hachez-le finement.","Ajoutez 1000 ml d''eau potable dans une casserole et portez à ébullition à feu vif.","Mettez le brocoli dans l''eau bouillante et faites cuire à feu vif pendant 2 à 3 minutes, jusqu''à ce qu''il devienne vert vif et tendre.","Retirez le brocoli cuit, égouttez-le et disposez-le dans une assiette.","Chauffez la poêle avec 10 ml d''huile de cuisson. Une fois l''huile chaude, ajoutez l''ail haché et faites-le revenir à feu doux jusqu''à ce qu''il soit parfumé.","Ajoutez 10 ml de sauce soja légère, 5 ml de sauce d''huître, 2 g de sucre blanc et 30 ml d''eau potable.","Portez la sauce à ébullition.","Versez uniformément la sauce à l''ail chaude sur le brocoli dans l''assiette."]'::jsonb, '["Plat végétarien","Ail","Léger","Rapide","Fait maison"]'::jsonb),
  ('howtocook:vegetable_dish/蒲烧茄子', 'fr', 'Aubergine à la sauce kabayaki', 'Plats végétariens', 'L''aubergine à la sauce kabayaki est un plat maison sucré-salé à la texture fondante. Il s''inspire du style kabayaki japonais mais est cuit à la chinoise, par poêlage. L''aubergine est riche en fibres alimentaires et en vitamines, ce qui aide à rafraîchir la chaleur et à activer la circulation. Difficulté moyenne, un peu de patience pour les débutants, temps de préparation estimé : environ 30 minutes.', '[{"name":"aubergine","unit":"pièce"},{"name":"sauce kabayaki","unit":"portion"},{"name":"miel","unit":"ml"},{"name":"sucre blanc","unit":"ml"},{"name":"sauce soja claire","unit":"ml"},{"name":"sauce soja foncée","unit":"ml"},{"name":"vin de cuisine","unit":"ml"},{"name":"eau","unit":"ml"}]'::jsonb, '["Peler l''aubergine et la couper horizontalement en deux morceaux.","Cuire à la vapeur pendant 5 minutes.","Couper dans le sens de la longueur sans trancher complètement, puis faire 2 à 3 entailles de chaque côté des faces coupées pour pouvoir l''aplatir.","Faire revenir jusqu''à ce que les deux faces soient dorées.","Verser la sauce kabayaki sur l''aubergine jusqu''à ce qu''elle atteigne la moitié de la hauteur.","Faire cuire jusqu''à ce que le dessous soit coloré, puis retourner.","En même temps, réduire la sauce. Si elle ne réduit pas, ajouter une liaison à la fécule de maïs (rapport fécule/eau de 1:4 à 1:10 selon la réduction souhaitée).","Verser le reste de sauce kabayaki sur l''aubergine.","Sortir de la poêle, l''aubergine à la sauce kabayaki est prête."]'::jsonb, '["végétarien","sucré-salé","poêlé","maison","accompagnement de riz","fondant"]'::jsonb),
  ('howtocook:vegetable_dish/虎皮青椒/虎皮青椒', 'fr', 'Poivrons tigrés', 'Plats végétariens', 'Les poivrons tigrés sont un petit plat familial. La peau est légèrement grillée et ridée, la texture tendre et croustillante, avec une saveur salée et umami teintée d''aigre-doux, très appétissant pour accompagner le riz. Les poivrons sont riches en vitamine C et en fibres alimentaires, ce qui aide à renforcer l''immunité et à favoriser la digestion. La préparation est simple et claire, il suffit de maîtriser la pression et le feu, convient aux débutants, et peut être réalisée en environ 15 minutes.', '[{"name":"Poivron vert","unit":"pièce"},{"name":"Ail","unit":"gousse"},{"name":"Huile","unit":"ml"},{"name":"Sucre","unit":"g"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Vinaigre de riz noir","unit":"ml"},{"name":"Sel","unit":"g"}]'::jsonb, '["Retirez les queues des poivrons et rincez-les à l''eau courante.","Coupez les poivrons en longues lamelles ; en moyenne, coupez un poivron dans le sens de la longueur en 3 à 4 morceaux.","Épluchez l''ail et hachez-le finement ; la taille doit être d''environ 2 mm x 2 mm x 2 mm.","Assaisonnement 1 : dans un petit bol, versez 20 ml d''huile et mettez l''ail haché.","Assaisonnement 2 : versez le sucre, la sauce soja claire, le vinaigre et le sel dans un bol, puis mélangez.","Versez l''assaisonnement 1 dans la poêle, chauffez à feu moyen (5/10) et ajoutez les lamelles de poivron sans les superposer ; disposez-les une par une.","Appuyez constamment sur les poivrons avec une spatule et retournez-les au moment opportun.","Faites sauter environ 2 minutes ; lorsque la peau des poivrons commence à rider, versez l''assaisonnement 2.","Augmentez le feu et continuez à sauter pendant 30 secondes, puis retirez du feu et servez dans une assiette."]'::jsonb, '["Légume","Familial","Accompagne le riz","Rapide","Savoureux","Aigre-doux","Sauté"]'::jsonb),
  ('howtocook:vegetable_dish/蚝油三鲜菇/蚝油三鲜菇', 'fr', 'Trois champignons à la sauce d''huître', 'Plats végétariens', 'Les trois champignons à la sauce d''huître sont un plat familial rapide, savoureux et tendre. Les champignons absorbent la sauce d''huître, offrant une texture douce et moelleuse avec une légère touche épicée, rafraîchissante sans être grasse. Riches en protéines végétales, fibres alimentaires et vitamines, accompagnés de brocoli pour un équilibre nutritionnel. La préparation est simple, même les débutants peuvent facilement la maîtriser. De la préparation à la cuisson, il ne faut qu''environ 15 minutes.', '[{"name":"Champignons shiitake","unit":"pièce"},{"name":"Champignons shimeji","unit":"g"},{"name":"Champignons blancs","unit":"g"},{"name":"Petits piments rouges","unit":"pièce"},{"name":"Poivron","unit":"pièce"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Vin de cuisson","unit":"ml"},{"name":"Fécule","unit":"g"},{"name":"Sauce soja","unit":"ml"},{"name":"Bouillon de poule en poudre","unit":"g"},{"name":"Ciboule","unit":"pièce"},{"name":"Gingembre haché","unit":"morceau"},{"name":"Sauce d''huître","unit":"ml"},{"name":"Brocoli","unit":"g"},{"name":"Eau bouillante","unit":"ml"}]'::jsonb, '["Enlever la terre des racines des champignons shimeji et des champignons blancs, puis les séparer en bouquets.","Couper les champignons shiitake en tranches (0,5-1 cm d''épaisseur ; plus épaisses donnent une meilleure texture moelleuse).","Verser la fécule dans un petit bol, ajouter 50 ml d''eau et mélanger jusqu''à dissolution complète (mélange de fécule). Réserver.","Porter l''eau à ébullition, y plonger le brocoli et cuire 3 minutes. Égoutter et réserver dans un bol.","Nettoyer la casserole, porter l''eau à ébullition, ajouter 5 g de sel de cuisine, puis ajouter les champignons shimeji, blancs et shiitake. Cuire 1 minute.","Après 1 minute, les égoutter et les essorer.","Chauffer l''huile dans la poêle. Lorsque l''huile commence à former de petites bulles, ajouter le gingembre haché, les petits piments rouges et le poivron. Faire sauter 30 secondes.","Ajouter les trois champignons, puis ajouter la sauce soja, la sauce d''huître et le bouillon de poule en poudre. Mélanger uniformément, puis ajouter le mélange de fécule.","Cuire à feu moyen jusqu''à ce que la sauce épaississe. Ajouter le vin de cuisson et la ciboule. Retirer du feu et servir.","Disposer le brocoli sur le plat."]'::jsonb, '["plat végétarien","savoureux","légèrement épicé","rapide","familial","qui accompagne bien le riz"]'::jsonb),
  ('howtocook:vegetable_dish/蚝油生菜', 'fr', 'Laitue à la sauce d''huître', 'Plats végétariens', 'La laitue à la sauce d''huître est un plat maison rafraîchissant et savoureux. La laitue croquante est nappée d''une sauce à l''huître et à l''ail, à la fois salée et sucrée. C''est un plat végétarien rapide très courant dans les restaurants cantonais et sichuanais. Riche en vitamines et en fibres alimentaires, il aide à la digestion. La recette est très adaptée aux débutants : du lavage à la cuisson, il ne faut qu''environ 15 minutes.', '[{"name":"Laitue","unit":"tête"},{"name":"Sauce d''huître","unit":"ml"},{"name":"Ail","unit":"gousse"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Sucre blanc","unit":"g"},{"name":"Huile de cuisson","unit":"ml"}]'::jsonb, '["Laver la laitue et retirer les feuilles abîmées.","Chauffer une casserole, y verser 1 L d''eau froide, puis ajouter 2-3 ml d''huile de cuisson et 0,5 g de sel. Porter à ébullition.","Une fois l''eau bouillante, plonger la laitue et blanchir chaque feuille pendant 10 secondes.","Retirer la laitue, égoutter et disposer dans une assiette.","Préparer la sauce : mélanger dans un bol 10 ml de sauce soja légère, 6-8 ml de sauce d''huître, 0,5 g de sel, 1 g de sucre blanc, et ajouter 10-15 ml d''eau froide en remuant.","Remettre le feu, chauffer la casserole avec 5-8 ml d''huile de cuisson, puis ajouter la purée d''ail.","Lorsque l''ail dégage son parfum, verser la sauce préparée. Porter à ébullition puis éteindre immédiatement.","Verser uniformément la sauce de la casserole sur la laitue."]'::jsonb, '["Plat végétarien","Savoureux","Salé-sucré","Rapide","Cantonnais","Cuisine maison","Accompagnement du riz"]'::jsonb),
  ('howtocook:vegetable_dish/西红柿炒鸡蛋', 'fr', 'Tomates brouillées aux œufs', 'Plats végétariens', 'Un plat familial aigre-doux qui ouvre l''appétit, avec des œufs tendres enveloppés de tomates juteuses et fondantes, un classique de la table chinoise. Les œufs fournissent des protéines de qualité, les tomates sont riches en vitamine C et en lycopène, un équilibre nutritionnel facile à absorber. Les étapes sont simples, les ingrédients faciles à trouver, particulièrement adapté aux débutants en cuisine, du début de la préparation au service, environ 15 minutes.', '[{"name":"Tomates","unit":"pièce(s)"},{"name":"Œufs","unit":"pièce(s)"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Sucre (optionnel)","unit":"g"},{"name":"Ciboule hachée (optionnel)","unit":"g"},{"name":"Vinaigre","unit":"ml"},{"name":"Concentré de tomates","unit":"ml"},{"name":"Eau","unit":"ml"}]'::jsonb, '["Lavez les tomates","Optionnel : retirez la peau des tomates","Ébouillantez la peau, puis plongez les tomates dans l''eau froide et pelez-les","Coupez le pédoncule des tomates, coupez-les en petits morceaux de côté ne dépassant pas 4 cm, ce sont les morceaux de tomates","Cassez les œufs dans un bol, ajoutez 1 g de sel, mélangez bien, c''est le mélange d''œufs","Vous pouvez ajouter 1 ml de vinaigre aux œufs, cela enlève l''odeur et rend les œufs plus moelleux","Chauffez la poêle, ajoutez de l''huile de cuisson","Une fois l''huile chaude, versez le mélange d''œufs. Faites sauter jusqu''à ce que les œufs soient solides et légèrement dorés, ce sont les œufs mi-cuits","Éteignez le feu. Mettez les œufs mi-cuits dans une assiette, rallumez le feu","Attention : ne lavez pas la poêle","Ajoutez les morceaux de tomates, écrasez avec la spatule et faites sauter 20 secondes, ou jusqu''à ce que les tomates soient tendres","Ajoutez les œufs mi-cuits dans la poêle, mélangez bien","Vous pouvez ajouter 10 ml de concentré de tomates et 50 ml d''eau pour plus de sauce","Vous pouvez ajouter d''autres viandes cuites et ingrédients","Ajoutez le reste du sel, du sucre (optionnel, si vous préférez une version sucrée), de la ciboule hachée (optionnel), mélangez bien","Éteignez le feu, servez dans une assiette"]'::jsonb, '["Plat végétarien","Aigre-doux","Sauté","Familial","Rapide","Accompagnement de riz"]'::jsonb),
  ('howtocook:vegetable_dish/西红柿豆腐汤羹/西红柿豆腐汤羹', 'fr', 'Soupe de tomates et tofu', 'Plats végétariens', 'Une soupe maison légère et délicieuse, aigre-douce pour ouvrir l''appétit, texture tendre et lisse. Les tomates sont riches en vitamine C et en lycopène, associées aux œufs et au tofu, elles apportent des protéines de haute qualité, une nutrition équilibrée et facile à absorber. La préparation est simple, il suffit de couper, faire sauter et cuire, même un débutant peut facilement la maîtriser, du début à la fin environ 15 minutes.', '[{"name":"Tomate","unit":"pièce"},{"name":"Œuf","unit":"pièce"},{"name":"Tofu","unit":"gramme"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sel","unit":"gramme"},{"name":"Fécule","unit":"gramme"},{"name":"Assaisonnement au poulet","unit":"gramme"},{"name":"Ciboule","unit":"tige"},{"name":"Gingembre","unit":"tranche"},{"name":"Eau bouillante","unit":"ml"}]'::jsonb, '["Couper les tomates en petits dés, casser les œufs dans un bol et les battre, couper le tofu en morceaux et réserver.","Chauffer l''huile dans une casserole, ajouter les tranches de gingembre, après 5 S verser les tomates et faire sauter 30 S.","Ajouter de l''eau bouillante dans la casserole, porter à ébullition, après 60 S verser les œufs battus et les morceaux de tofu.","Une fois l''eau de la soupe à nouveau bouillante, ajouter la fécule délayée dans l''eau, remuer dans une direction 2 tours.","Ajouter l''assaisonnement au poulet, le sel et la ciboule, après 30 S retirer du feu."]'::jsonb, '["Plat végétarien","Léger","Aigre-doux","Maison","Rapide"]'::jsonb),
  ('howtocook:vegetable_dish/西葫芦炒鸡蛋/西葫芦炒鸡蛋', 'fr', 'Courgettes sautées aux œufs', 'Plats végétariens', 'Les courgettes sautées aux œufs sont un plat rapide et savoureux de la cuisine familiale. Les courgettes sont tendres et juteuses, les œufs sont moelleux et parfumés. L''ajout de tomates apporte une touche acidulée et sucrée, ce qui accompagne parfaitement le riz. Les œufs fournissent des protéines de qualité et de la lécithine, tandis que les courgettes sont riches en vitamine C et en fibres alimentaires, offrant un repas équilibré. La préparation est simple et idéale pour les débutants : il ne faut que 15 minutes environ de la préparation au service.', '[{"name":"Courgettes","unit":"g"},{"name":"Œufs","unit":"pièce(s)"},{"name":"Tomates","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sel","unit":"g"}]'::jsonb, '["Lavez les tomates, coupez-les en petits morceaux, réservez.","Lavez les courgettes, coupez-les en losanges d''environ 4 cm de côté, réservez.","Cassez trois œufs dans un bol, battez-les jusqu''à homogénéité, réservez.","Chauffez la poêle, ajoutez 5 ml à 10 ml d''huile de cuisson.","Versez les œufs, faites-les sauter jusqu''à ce qu''ils soient solides, divisez-les en petits morceaux avec une spatule, puis transférez-les dans un bol, réservez.","Ajoutez 5 ml à 10 ml d''huile de cuisson dans la poêle, versez les tomates, faites-les sauter jusqu''à ce qu''elles soient tendres.","Ajoutez les courgettes, mélangez bien, ajoutez 6 g de sel, réduisez le feu et laissez cuire 4 à 5 minutes.","Ajoutez les œufs réservés, faites sauter à feu moyen pendant 15 secondes.","Éteignez le feu, servez dans une assiette."]'::jsonb, '["Végétarien","Léger","Sauté","Fait maison","Rapide","Pour le riz"]'::jsonb),
  ('howtocook:vegetable_dish/话梅煮毛豆/话梅煮毛豆', 'fr', 'Fèves de soja vertes aux prunes salées', 'Plats végétariens', 'Les fèves de soja vertes aux prunes salées sont un petit plat maison aigre-doux et appétissant. La texture est rafraîchissante et moelleuse, avec le parfum naturel de la prune. Les fèves de soja sont riches en protéines végétales et en fibres alimentaires, ce qui aide à fournir de l''énergie et à favoriser la digestion. La recette est très simple, même les débutants peuvent la réaliser facilement, et cela ne prend que 35 à 45 minutes.', '[{"name":"Fèves de soja vertes","unit":"g"},{"name":"Prunes salées","unit":"pièce"},{"name":"Sel de table","unit":"g"}]'::jsonb, '["Ajouter du sel de table à l''eau claire, faire tremper les fèves de soja vertes pendant 15 minutes.","Ajouter de l''eau bouillante, verser les fèves de soja vertes et les prunes salées, faire bouillir pendant 20-30 minutes.","Retirer du feu et déguster."]'::jsonb, '["Plat végétarien","Aigre-doux","Bouilli","Maison","Appétissant","Rapide"]'::jsonb),
  ('howtocook:vegetable_dish/酸辣土豆丝', 'fr', 'Pommes de terre râpées aigres-piquantes', 'Plats végétariens', 'Un plat familial classique aigre-piquant qui ouvre l''appétit, avec une texture croquante et une couleur vive. C''est un sauté rapide très apprécié. Les pommes de terre fournissent des glucides et du potassium, les piments sont riches en vitamine C, ce qui aide à stimuler l''appétit. Les étapes sont simples et claires, très accessibles aux débutants, et il faut environ 20 minutes de la préparation à la cuisson.', '[{"name":"Pommes de terre","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Poivron vert","unit":"pièce"},{"name":"Poivron rouge","unit":"pièce"},{"name":"Piment séché","unit":"pièce"},{"name":"Oignon vert","unit":"tige"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Vinaigre noir","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Huile de cuisson","unit":"ml"}]'::jsonb, '["Éplucher les pommes de terre et les râper (ou utiliser un mandoline).","Laver les pommes de terre râpées à l''eau claire pour enlever l''excès d''amidon, puis les blanchir 10 secondes. Égoutter et réserver.","Couper l''oignon vert en fines rondelles ; écraser l''ail et le hacher (le diviser en deux parts égales) ; couper les piments séchés en petits morceaux ; couper les poivrons vert et rouge en julienne.","Chauffer un wok à feu doux avec de l''huile, ajouter la moitié des oignons verts (la partie blanche), la moitié de l''ail haché et les piments séchés pour les faire revenir.","Ajouter les poivrons vert et rouge, faire sauter quelques fois, puis ajouter les pommes de terre râpées et faire sauter jusqu''à ce qu''elles changent de couleur.","Ajouter 5 ml de sauce soja claire, 10 ml de vinaigre noir, le reste de l''ail haché et 2 g de sel. Mélanger rapidement.","Avant de servir, saupoudrer du reste des oignons verts, mélanger et dresser dans une assiette."]'::jsonb, '["Plat végétarien","Aigre-piquant","Sauté","Familial","Rapide","Accompagnement de riz"]'::jsonb),
  ('howtocook:vegetable_dish/金针菇日本豆腐煲', 'fr', 'Casserole de champignons enoki et tofu japonais', 'Plats végétariens', 'La casserole de champignons enoki et tofu japonais est un plat familial savoureux avec une sauce parfumée. Le tofu est croustillant à l''extérieur et tendre à l''intérieur, tandis que les champignons enoki sont lisses et imprégnés de saveurs. Les champignons enoki sont riches en acides aminés et en fibres alimentaires, et le tofu japonais fournit des protéines de haute qualité, ce qui en fait un plat nutritif et appétissant. Les étapes sont simples, même les débutants peuvent les maîtriser facilement, et la préparation à la cuisson dure environ 30 minutes.', '[{"name":"champignons enoki","unit":"botte"},{"name":"tofu japonais (tamago tofu)","unit":"sachet"},{"name":"piments rouges","unit":"pièce"},{"name":"ail","unit":"gousse"},{"name":"sauce soja légère","unit":"ml"},{"name":"sauce d''huître","unit":"ml"},{"name":"sauce soja foncée","unit":"ml"},{"name":"sucre","unit":"g"},{"name":"huile de cuisson","unit":"ml"},{"name":"sel","note":"quantité suffisante"},{"name":"eau","unit":"ml"}]'::jsonb, '["Couper le tofu en tranches, le faire frire à feu doux jusqu''à ce qu''il soit doré des deux côtés, puis le réserver.","Hacher l''ail en fines miettes ; mélanger la sauce soja légère, la sauce d''huître, la sauce soja foncée, le sucre et 100 ml d''eau pour préparer la sauce, et réserver.","Chauffer la poêle avec de l''huile, une fois chaude, ajouter les piments rouges et l''ail haché pour les faire revenir. Ajouter d''abord les champignons enoki, les faire sauter jusqu''à ce qu''ils soient tendres. Disposer le tofu frit sur les champignons, verser la sauce préparée à l''étape #2, couvrir et laisser mijoter 5 minutes, puis augmenter le feu pour réduire la sauce."]'::jsonb, '["Plat végétarien","Sauce parfumée","Familial","Accompagnement de riz","Frit et mijoté"]'::jsonb),
  ('howtocook:vegetable_dish/金钱蛋', 'fr', 'Œufs dorés', 'Plats végétariens', 'Les œufs dorés sont un plat familial hunanais croustillant à l''extérieur, tendre à l''intérieur, salé et légèrement épicé. Les tranches d''œufs frits dorés ressemblent à des pièces de monnaie, symbole de prospérité. Associés aux piments verts et rouges, ils sont riches en protéines de qualité et en vitamines. La difficulté est moyenne, accessible aux débutants après un peu de pratique. Le plat est prêt en environ 30 minutes.', '[{"name":"Œuf","unit":"pièce"},{"name":"Piment vert long","unit":"g"},{"name":"Piment rouge","unit":"g"},{"name":"Pâte de soja fermentée","unit":"ml"},{"name":"Ail","unit":"g"},{"name":"Ciboule","unit":"g"},{"name":"Fécule de maïs","unit":"g"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sauce soja","unit":"ml"},{"name":"Sauce d''huître","unit":"ml"},{"name":"Sucre","unit":"g"}]'::jsonb, '["Mettre les œufs dans une casserole d''eau froide, porter à ébullition à feu vif, puis réduire à feu doux et cuire 8 minutes.","Rincer à l''eau froide du robinet pour faciliter l''épluchage.","Hacher l''ail (pas plus de 1 mm), couper le piment vert long et le piment rouge en petits dés (environ 2-3 mm).","Couper chaque œuf dur en 4 tranches de taille similaire dans le sens de la largeur.","Si vous utilisez de la fécule, enrober chaque tranche d''œuf de fécule, puis secouer l''excédent.","Verser 25 ml d''huile dans la poêle (20 ml si sans fécule), y déposer les tranches d''œuf.","Faire frire jusqu''à ce qu''elles soient légèrement dorées, puis ajouter 10 ml d''huile (10 ml si sans fécule) et retourner.","Lorsque la deuxième face est dorée, ajouter le piment vert, le piment rouge et l''ail haché, faire sauter environ une minute, puis retourner.","Ajouter la pâte de soja fermentée, faire sauter quelques dizaines de secondes, puis retourner.","Mélanger la sauce soja, la sauce d''huître et le sucre dans un bol, verser dans la poêle, secouer doucement, puis servir."]'::jsonb, '["Plat végétarien","Salé","Légèrement épicé","Frit","Hunanais","Accompagnement du riz"]'::jsonb),
  ('howtocook:vegetable_dish/陕北熬豆角', 'fr', 'Haricots verts mijotés du Shaanbei', 'Plats végétariens', 'C''est un plat mijoté de style fermier du nord-ouest de la Chine, avec des haricots tendres, des pommes de terre fondantes, une sauce tomate riche, acidulée et appétissante. Riche en fibres alimentaires, vitamines et glucides, il est équilibré. La recette est extrêmement simple, les quantités peuvent être ajustées selon les goûts, et il est presque impossible d''échouer, ce qui le rend particulièrement adapté aux débutants. De la préparation à la fin, il faut environ 30 minutes.', '[{"name":"Haricots verts","unit":"g"},{"name":"Pomme de terre","unit":"pièce"},{"name":"Tomate","unit":"pièce"},{"name":"Piment vert torsadé","unit":"pièce"},{"name":"Sel","unit":"g"},{"name":"Sauce soja légère","unit":"ml"},{"name":"Cinq-épices","unit":"g"},{"name":"Sauce aux huîtres","unit":"ml"},{"name":"Oignon vert","unit":"rondelles"},{"name":"Gingembre","unit":"g"},{"name":"Ail","unit":"gousse"},{"name":"Coriandre ciselée","note":"selon le goût"},{"name":"Huile","unit":"ml"}]'::jsonb, '["Émincer l''oignon vert, hacher l''ail, couper le gingembre en filaments. Réserver.","Effiler les haricots et les couper en petits tronçons de 2 à 10 cm. Réserver.","Éplucher les pommes de terre et les couper en petits cubes de 1 cm³. Réserver.","Peler les tomates et les couper en petits cubes de 1 cm³. Réserver.","Épépiner le piment et le couper en lanières de 0,15 cm de large. Réserver.","Chauffer l''huile (10-15 ml) dans une poêle jusqu''à ce qu''elle fume, puis ajouter l''oignon, le gingembre et l''ail. Faire revenir jusqu''à ce que les arômes se dégagent.","Ajouter les haricots et faire revenir jusqu''à ce qu''ils changent de couleur (du vert clair au vert foncé).","Ajouter les cubes de pommes de terre et faire revenir 30 secondes.","Ajouter de l''eau chaude (juste à hauteur des légumes), couvrir et laisser mijoter jusqu''à ce que les pommes de terre soient tendres (vérifier avec une baguette).","Ajouter les dés de tomates, le sel, la sauce soja légère, la sauce aux huîtres, la poudre cinq-épices et le piment. Laisser mijoter jusqu''à ce que les tomates soient réduites en sauce (remuer pour éviter que cela n''accroche).","Ajouter la coriandre ciselée et servir."]'::jsonb, '["Plat végétarien","Fait maison","Accompagnement du riz","Mijoté","Nord-ouest","Rapide"]'::jsonb),
  ('howtocook:vegetable_dish/雷椒皮蛋', 'fr', 'Piments verts et œufs de cent ans pilés', 'Plats végétariens', 'Les piments verts et les œufs de cent ans pilés sont une entrée froide maison au goût rustique mais savoureux. Le fumé des piments verts se marie à la richesse des œufs de cent ans, avec une touche aigre-douce et épicée qui ouvre l''appétit, parfait pour l''été. Les œufs de cent ans sont riches en protéines et minéraux, les piments verts apportent de la vitamine C, et l''ail stimule l''appétit. La recette est simple, même les débutants peuvent la réaliser facilement, environ 15 minutes du début à la fin.', '[{"name":"Œuf de cent ans","unit":"pièce"},{"name":"Piment vert","unit":"pièce"},{"name":"Oignon vert","unit":"cm"},{"name":"Ail","unit":"gousse"},{"name":"Piment oiseau","unit":"pièce"},{"name":"Huile de cuisson","unit":"ml"},{"name":"Sauce soja claire","unit":"ml"},{"name":"Vinaigre noir","unit":"ml"},{"name":"Sucre blanc","unit":"g"},{"name":"Huile de sésame","unit":"ml"}]'::jsonb, '["Laver les piments verts, retirer les queues, les fendre en deux dans le sens de la longueur, enlever les graines à l''intérieur et les aplatir sur une planche à découper. Réserver. (Il est important d''enlever les graines, sinon elles éclateront à la cuisson.)","Couper l''oignon vert en petits tronçons d''un demi-centimètre. Réserver.","Peler les gousses d''ail et les hacher finement. Réserver.","Écaler les œufs de cent ans. Réserver.","Couper les piments oiseaux en petits morceaux de 5 à 10 mm. Réserver.","Chauffer une poêle et ajouter 10 à 20 ml d''huile de cuisson.","Mettre tous les piments verts dans la poêle, réduire à feu doux pour maintenir la température, et les faire griller jusqu''à ce qu''ils soient tendres (vérifier avec une baguette : elle doit s''enfoncer facilement).","Éteindre le feu et mettre les œufs de cent ans et les piments verts dans un petit bol en fer.","Méthode 1 : Si vous avez un rouleau à pâtisserie et que le bruit ne dérange pas les voisins, utilisez une extrémité du rouleau pour pilonner les œufs et les piments dans le bol jusqu''à ce qu''ils soient bien mélangés (option).","Méthode 2 : Déchirer les piments verts à la main en lanières d''environ un demi-centimètre, puis écraser les œufs de cent ans avec une fourchette (option).","Piments oiseaux","Verser la sauce soja claire, le vinaigre noir, le sucre blanc, l''huile de sésame, ainsi que les autres ingrédients non utilisés.","Mélanger uniformément."]'::jsonb, '["Végétarien","Aigre-doux épicé","Salade","Apéritif","Maison","Rapide"]'::jsonb),
  ('howtocook:vegetable_dish/鸡蛋火腿炒黄瓜', 'fr', 'Sauté de concombre aux œufs et jambon', 'Plats végétariens', 'C''est un sauté maison rapide et rafraîchissant, salé et savoureux, avec du concombre croquant, des œufs tendres et du jambon parfumé. C''est un plat familial chinois très populaire. Les œufs apportent des protéines de qualité, le concombre est riche en vitamines et en eau, le jambon ajoute de la saveur, l''ensemble est équilibré. Les étapes de cuisson sont simples et claires, le niveau de difficulté est très faible, idéal pour les débutants en cuisine. De la préparation à la fin, il ne faut qu''environ 10 minutes.', '[{"name":"concombre","unit":"pièce"},{"name":"œuf","unit":"pièce"},{"name":"jambon","unit":"pièce"},{"name":"piment rouge","unit":"pièce"},{"name":"huile de cuisson","unit":"ml"},{"name":"sauce soja légère","unit":"ml"},{"name":"sel","unit":"g"}]'::jsonb, '["Laver le concombre, le couper en demi-rondelles, réserver.","Couper le jambon en demi-rondelles, réserver.","Hacher le piment rouge (facultatif), réserver.","Casser les œufs dans un bol, les battre pour obtenir un mélange d''œufs.","Verser 5 ml d''huile de cuisson dans une poêle chaude.","Une fois l''huile chaude, réduire le feu à doux, verser le mélange d''œufs battus, remuer avec des baguettes, cuire en remuant jusqu''à ce que les œufs soient solides et légèrement dorés (œufs brouillés), puis les retirer et réserver.","Sans laver la poêle, verser 5 ml d''huile de cuisson, ajouter les rondelles de concombre et faire sauter à feu vif pendant 1 minute.","Remettre les œufs brouillés dans la poêle, ajouter 2 g de sel et 3 ml de sauce soja légère, puis immédiatement ajouter les rondelles de jambon et le piment haché (facultatif), mélanger rapidement.","Éteindre le feu, servir dans une assiette."]'::jsonb, '["légume","rafraîchissant","savoureux","sauté","rapide","familial"]'::jsonb),
  ('howtocook:vegetable_dish/鸡蛋羹/微波炉鸡蛋羹', 'fr', 'Œufs vapeur au micro-ondes', 'Plats végétariens', 'Les œufs vapeur au micro-ondes sont un plat simple et rapide de la cuisine familiale, avec une texture tendre et lisse, particulièrement adapté comme en-cas tardif ou repas rapide. Les œufs sont riches en protéines de haute qualité et en diverses vitamines, fournissant les nutriments nécessaires au corps, et les crevettes séchées apportent en plus du calcium. Ce plat est très accessible aux débutants, sans nécessiter de maîtrise du feu, du battage des œufs à l''assaisonnement jusqu''à la sortie du four, le processus complet ne prend qu''environ 10 minutes.', '[{"name":"Œufs","unit":"pièce"},{"name":"Eau","unit":"ml"},{"name":"Sel","unit":"g"},{"name":"Crevettes séchées","unit":"pièce"},{"name":"Ciboule","unit":"g"},{"name":"Huile de sésame","unit":"ml"},{"name":"Sauce soja","note":"à volonté"}]'::jsonb, '["Cassez les œufs dans un bol en céramique allant au micro-ondes et battez-les avec des baguettes.","Ajoutez l''eau et le sel, mélangez bien.","Ajoutez les crevettes séchées dans le bol, mélangez bien pour éviter qu''elles ne s''agglutinent.","Hachez finement la ciboule (morceaux d''environ 0,6 mm de côté, avec une tolérance de ±3 mm) et ajoutez-la dans le bol, mélangez bien.","Placez le bol et son contenu dans le micro-ondes, couvrez la surface d''un film plastique alimentaire ou d''une assiette allant au micro-ondes (attention : ne pas sceller hermétiquement, laisser un espace pour la dilatation) et faites chauffer 2 minutes à 500 W.","Retirez délicatement le film plastique ou le couvercle, puis continuez à chauffer 2 minutes.","Si le micro-ondes n''a pas de plateau tournant, tournez doucement le bol horizontalement de 180 degrés pour assurer une cuisson uniforme.","Ajoutez l''huile de sésame.","Sortez délicatement le bol du micro-ondes (il est vraiment chaud).","Si vous choisissez d''ajouter de la sauce soja, assurez-vous qu''elle coule sur la surface des œufs pour la recouvrir d''une couche très fine.","Savourez joyeusement vos œufs vapeur."]'::jsonb, '["Plat végétarien","Rapide","Familial","Tendre","En-cas tardif","Micro-ondes"]'::jsonb),
  ('howtocook:vegetable_dish/鸡蛋羹/蒸箱鸡蛋羹', 'fr', 'Œufs cuits à la vapeur', 'Plats végétariens', 'Voici une recette rapide de flan d''œufs tendre et lisse, réalisée à l''aide d''un cuiseur vapeur. La texture peut être ajustée : moins d''eau donne une texture ferme, plus d''eau la rend plus tendre. Riche en protéines de qualité et en nutriments, facile à digérer. Niveau de difficulté modéré, les débutants peuvent réussir avec un peu d''attention. Du début à la fin, il faut environ 15 minutes.', '[{"name":"Œuf","unit":"pièce"},{"name":"Sel de table","unit":"gramme"},{"name":"Huile alimentaire","unit":"ml"},{"name":"Sauce soja légère (optionnelle)","unit":"ml"}]'::jsonb, '["Casser un œuf dans un bol et le battre","Ajouter 1,0 à 1,5 fois le volume de l''œuf en eau purifiée à 60°C dans le bol, puis mélanger uniformément","Dans la bonne plage, moins d''eau donne une texture plus ferme, plus d''eau la rend plus tendre","Attention : en dehors de cette plage, trop peu d''eau rend la texture trop ferme, trop d''eau la rend trop liquide","Ajouter 1 g de sel de table","Le sel joue un rôle important pour rehausser la saveur de base et pour la coagulation","Ajouter 5 ml d''huile alimentaire","Filtrer le mélange d''œufs pour enlever les bulles (optionnel, sinon les œufs cuits auront des bulles et ne seront pas beaux)","Vérifier que le réservoir d''eau du cuiseur vapeur est suffisamment rempli (en cas de doute, remplir le bac)","Placer le bol contenant le mélange d''œufs bien battu dans le cuiseur vapeur","Régler à 100°C et cuire à la vapeur pendant 10 minutes","Ouvrir le cuiseur vapeur (attention : de la vapeur s''échappe instantanément, ouvrir lentement)","Sortir le plat (ajouter de la sauce soja légère pour assaisonner)","Déguster"]'::jsonb, '["végétarien","vapeur","rapide","fait maison","tendre et lisse","léger"]'::jsonb),
  ('howtocook:vegetable_dish/鸡蛋羹/鸡蛋羹', 'fr', 'Flan aux œufs', 'Plats végétariens', 'Ce plat est un plat vapeur maison simple et rapide. Sa texture est tendre et lisse comme un flan, salé et savoureux. On le retrouve souvent sur les tables comme petit-déjeuner ou accompagnement. Les œufs fournissent des protéines de qualité et de la lécithine, faciles à digérer. Idéal pour les débutants, quelques étapes simples suffisent pour obtenir un flan aux œufs lisse et délicat. L''ensemble prend environ 15 minutes.', '[{"name":"œufs","unit":"pièce","note":""},{"name":"sel de table","unit":"g","note":""},{"name":"huile de sésame (ou huile de sésame grillé)","unit":"ml","note":""},{"name":"sauce soja légère (ou sauce Soja)","unit":"ml","note":""},{"name":"vinaigre blanc (ou vin de cuisine)","unit":"ml","note":""},{"name":"huile de poivre du Sichuan","unit":"","note":"quantité suffisante"}]'::jsonb, '["Cassez deux œufs dans un bol et battez-les.","Ajoutez 3 g de sel de table.","Le sel joue un rôle important pour relever le goût et favoriser la coagulation.","Ajoutez 2 ml de vinaigre blanc pour enlever l''odeur de poisson des œufs (optionnel).","Vous pouvez aussi utiliser du vinaigre de riz, mais sa couleur peut rendre les œufs légèrement noirs.","Vous pouvez aussi ajouter du vin de cuisine, qui a le même effet désodorisant sans l''acidité du vinaigre.","Ajoutez au bol de l''eau pure à 70°C, en quantité égale à 1 à 1,5 fois le volume des œufs, et mélangez bien.","Avec 1 fois d''eau, les œufs sont plus fermes ; avec 1,5 fois, ils sont plus tendres.","Filtrez le mélange d''œufs pour enlever les mousses (optionnel, sinon les œufs cuits à la vapeur auront des bulles et ne seront pas beaux).","Dans une casserole, ajoutez 300 à 500 ml d''eau claire. Portez à ébullition, puis placez le bol contenant le mélange d''œufs.","Couvrez le bol avec un couvercle, une assiette en fer avec un creux retournée, ou du film plastique pour réduire la vapeur d''eau, afin d''éviter une texture alvéolée.","Étapes de cuisson à la vapeur (choisissez une option)","Cuire à feu moyen pendant 10 minutes. Après 10 minutes, éteignez le feu et laissez reposer 5 minutes.","Cuire à feu vif pendant 5 minutes, en maintenant l''eau en ébullition constante, sinon prolongez le temps. Ouvrez le couvercle toutes les 2 minutes pour libérer la vapeur. Si vous ouvrez trop tard, le flan devient alvéolé ; si vous ouvrez trop tôt ou trop souvent, le temps de cuisson doit être plus long.","Comment savoir si c''est cuit ?","Secouez le bol : le flan ne doit plus être liquide, mais avoir une texture ferme comme un flan. Il est alors prêt à sortir.","Sortez du cuiseur vapeur.","Ajoutez de l''huile de sésame et de la sauce soja légère, puis dégustez.","Vous pouvez aussi remplacer l''huile de sésame par de l''huile de poivre du Sichuan pour un goût plus piquant."]'::jsonb, '["Végétarien","Vapeur","Rapide","Maison","Petit-déjeuner","Savoureux"]'::jsonb),
  ('howtocook:vegetable_dish/鸡蛋花/鸡蛋花', 'fr', 'Fleur d''œuf', 'Plats végétariens', 'Une soupe médicinale maison simple et facile à préparer, avec deux variantes sucrée et salée. La texture est lisse et tendre. C''est un petit remède traditionnel pour apaiser la gorge. Riche en protéines de haute qualité et en lécithine, elle est facile à digérer et à absorber, et peut soulager la sécheresse et les démangeaisons de la gorge. La préparation est très simple : même un débutant peut la réussir après l''avoir vue une fois. De l''ébullition de l''eau à la fin, cela ne prend qu''environ 5 minutes.', '[{"name":"Œufs","unit":"pièce"},{"name":"Eau bouillante","unit":"ml"},{"name":"Sucre blanc","unit":"g"},{"name":"Sel","unit":"g"}]'::jsonb, '["Cassez les œufs dans un bol.","À l''aide de baguettes ou d''un fouet, battez les œufs dans un sens jusqu''à ce que le blanc et le jaune soient complètement mélangés et de couleur uniforme (cela prend environ 1 à 2 minutes).","Ajoutez le sucre ou le sel (selon l''assaisonnement choisi) dans le mélange d''œufs et mélangez légèrement.","Préparez de l''eau bouillante à 100 °C qui vient de bouillir.","Tout en remuant rapidement les œufs dans le bol avec des baguettes, versez l''eau bouillante en un mince filet sur les œufs. Assurez-vous que l''eau bouillante et les œufs sont bien mélangés.","Continuez à remuer un instant jusqu''à ce que les œufs soient complètement cuits par l''eau chaude, formant une fleur d''œuf uniforme de couleur jaune pâle."]'::jsonb, '["Plat végétarien","Sucré et salé","Rapide","Fait maison","Apaisant pour la gorge","Soupe"]'::jsonb)
),
upserted as (
  insert into public.recipe_i18n (recipe_id, lang, name, category, description, ingredients, steps, tags)
  select recipe_id, lang, name, category, description, ingredients, steps, tags from seed
  on conflict (recipe_id, lang) do update set
  name = excluded.name,
  category = excluded.category,
  description = excluded.description,
  ingredients = excluded.ingredients,
  steps = excluded.steps,
  tags = excluded.tags,
  updated_at = now()
  returning recipe_id, lang
)
delete from public.recipe_i18n t
where t.lang in ('en', 'ja', 'fr')
  and t.recipe_id like 'howtocook:%'
  and not exists (select 1 from seed s where s.recipe_id = t.recipe_id and s.lang = t.lang);
